--
-- Name: ensure_row_trigger(text, text); Type: FUNCTION; Schema: audit; Owner: -
--

CREATE FUNCTION audit.ensure_row_trigger(sch text, tbl text) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
  pk_cols text[];
  args text;
  trig_name text;
BEGIN
  SELECT array_agg(a.attname ORDER BY a.attnum) INTO pk_cols
  FROM pg_index i
  JOIN pg_attribute a ON a.attrelid = i.indrelid AND a.attnum = ANY(i.indkey)
  WHERE i.indrelid = format('%I.%I', sch, tbl)::regclass
    AND i.indisprimary;

  IF pk_cols IS NULL THEN
    RAISE NOTICE 'audit: %.% has no PK; skipping row trigger', sch, tbl;
    RETURN;
  END IF;

  trig_name := format('trg_audit_%s', tbl);
  EXECUTE format('DROP TRIGGER IF EXISTS %I ON %I.%I;', trig_name, sch, tbl);

  SELECT string_agg(quote_literal(c), ', ') INTO args FROM unnest(pk_cols) AS c;

  EXECUTE format(
    'CREATE TRIGGER %I
       AFTER INSERT OR UPDATE OR DELETE ON %I.%I
       FOR EACH ROW EXECUTE FUNCTION audit.log_row_change(%s);',
    trig_name, sch, tbl, args
  );
END;
$$;


--
-- Name: install_row_triggers(); Type: FUNCTION; Schema: audit; Owner: -
--

CREATE FUNCTION audit.install_row_triggers() RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE r record;
BEGIN
  FOR r IN
    SELECT n.nspname AS sch, c.relname AS tbl
    FROM pg_class c
    JOIN pg_namespace n ON n.oid = c.relnamespace
    WHERE n.nspname = 'public' AND c.relkind = 'r'
  LOOP
    PERFORM audit.ensure_row_trigger(r.sch, r.tbl);
  END LOOP;
END;
$$;


--
-- Name: log_row_change(); Type: FUNCTION; Schema: audit; Owner: -
--

CREATE FUNCTION audit.log_row_change() RETURNS trigger
    LANGUAGE plpgsql
    AS $_$
DECLARE
  pk_json   jsonb := '{}'::jsonb;
  col_name  text;
  col_val   jsonb;
  i         int;
  src_rec   record;
BEGIN
  src_rec := CASE WHEN TG_OP = 'DELETE' THEN OLD ELSE NEW END;

  IF TG_NARGS > 0 THEN
    FOR i IN 0..TG_NARGS-1 LOOP
      col_name := TG_ARGV[i];
      EXECUTE format('SELECT to_jsonb(($1).%I)', col_name) INTO col_val USING src_rec;
      pk_json := pk_json || jsonb_build_object(col_name, col_val);
    END LOOP;
  END IF;

  IF TG_OP = 'INSERT' THEN
    INSERT INTO audit.row_changes(table_name, op, pk, new_row)
    VALUES (TG_TABLE_NAME, TG_OP, NULLIF(pk_json,'{}'::jsonb), to_jsonb(NEW));
    RETURN NEW;
  ELSIF TG_OP = 'UPDATE' THEN
    INSERT INTO audit.row_changes(table_name, op, pk, old_row, new_row)
    VALUES (TG_TABLE_NAME, TG_OP, NULLIF(pk_json,'{}'::jsonb), to_jsonb(OLD), to_jsonb(NEW));
    RETURN NEW;
  ELSE -- DELETE
    INSERT INTO audit.row_changes(table_name, op, pk, old_row)
    VALUES (TG_TABLE_NAME, TG_OP, NULLIF(pk_json,'{}'::jsonb), to_jsonb(OLD));
    RETURN OLD;
  END IF;
END;
$_$;


--
-- Name: notify_row_change(); Type: FUNCTION; Schema: audit; Owner: -
--

CREATE FUNCTION audit.notify_row_change() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  PERFORM pg_notify('audit_events',
    json_build_object(
      'ts', NEW.changed_at,
      'op', NEW.op,
      'table', NEW.table_name,
      'pk', coalesce(NEW.pk::text,'{}')
    )::text
  );
  RETURN NEW;
END;
$$;


--
-- Name: api_add_eval_groups_v4(uuid, types.i_add_eval_groups_v4_group[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_add_eval_groups_v4(eval_id uuid, groups types.i_add_eval_groups_v4_group[], profile_id uuid) RETURNS TABLE(eval_id uuid, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        eval_id AS eval_id,
        COALESCE(groups, ARRAY[]::types.i_add_eval_groups_v4_group[]) AS groups,
        profile_id AS profile_id
),
user_profile AS (
    SELECT 
        role,
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
-- Create eval_groups entries
link_groups AS (
    INSERT INTO eval_groups (eval_id, group_id, created_at, updated_at)
    SELECT 
        p.eval_id,
        (g).group_id,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN UNNEST(p.groups) AS g
    WHERE (g).group_id IS NOT NULL
    ON CONFLICT (eval_id, group_id) DO UPDATE SET
        updated_at = NOW()
),
-- Create/find rubric_grade_agents entries
create_rubric_grade_agents AS (
    INSERT INTO rubric_grade_agents (rubric_id, grade_agent_id, created_at, updated_at)
    SELECT DISTINCT
        (rga).rubric_id,
        (rga).grade_agent_id,
        NOW(),
        NOW()
    FROM params x
    CROSS JOIN UNNEST(x.groups) AS g
    CROSS JOIN UNNEST((g).rubric_grade_agents) AS rga
    WHERE (rga).rubric_id IS NOT NULL 
      AND (rga).grade_agent_id IS NOT NULL
    ON CONFLICT (rubric_id, grade_agent_id, agent_id) DO UPDATE SET
        updated_at = NOW()
    RETURNING id as rubric_grade_agent_id, rubric_id, grade_agent_id
),
-- Link rubric_grade_agents to groups
link_group_rubric_grade_agents AS (
    INSERT INTO eval_groups_rubric_grade_agents (eval_id, group_id, rubric_grade_agent_id, created_at, updated_at)
    SELECT DISTINCT
        p.eval_id,
        (g).group_id,
        crga.rubric_grade_agent_id,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN UNNEST(p.groups) AS g
    CROSS JOIN UNNEST((g).rubric_grade_agents) AS rga
    JOIN create_rubric_grade_agents crga ON crga.rubric_id = (rga).rubric_id 
        AND crga.grade_agent_id = (rga).grade_agent_id
    WHERE (g).group_id IS NOT NULL
      AND (rga).rubric_id IS NOT NULL 
      AND (rga).grade_agent_id IS NOT NULL
    ON CONFLICT (eval_id, group_id, rubric_grade_agent_id) DO NOTHING
)
SELECT 
    p.eval_id,
    up.actor_name::text as actor_name
FROM params p
CROSS JOIN user_profile up
$$;


--
-- Name: api_add_eval_runs_v4(uuid, types.i_add_eval_runs_v4_run[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_add_eval_runs_v4(eval_id uuid, runs types.i_add_eval_runs_v4_run[], profile_id uuid) RETURNS TABLE(eval_id uuid, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        eval_id AS eval_id,
        COALESCE(runs, ARRAY[]::types.i_add_eval_runs_v4_run[]) AS runs,
        profile_id AS profile_id
),
user_profile AS (
    SELECT 
        role,
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
-- Create eval_runs entries
link_runs AS (
    INSERT INTO eval_runs (eval_id, run_id, completed, created_at, updated_at)
    SELECT 
        p.eval_id,
        (r).run_id,
        false,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN UNNEST(p.runs) AS r
    WHERE (r).run_id IS NOT NULL
    ON CONFLICT (eval_id, run_id) DO UPDATE SET
        completed = false,
        updated_at = NOW()
),
-- Create/find rubric_grade_agents entries
create_rubric_grade_agents AS (
    INSERT INTO rubric_grade_agents (rubric_id, grade_agent_id, created_at, updated_at)
    SELECT DISTINCT
        (rga).rubric_id,
        (rga).grade_agent_id,
        NOW(),
        NOW()
    FROM params x
    CROSS JOIN UNNEST(x.runs) AS r
    CROSS JOIN UNNEST((r).rubric_grade_agents) AS rga
    WHERE (rga).rubric_id IS NOT NULL 
      AND (rga).grade_agent_id IS NOT NULL
    ON CONFLICT (rubric_id, grade_agent_id, agent_id) DO UPDATE SET
        updated_at = NOW()
    RETURNING id as rubric_grade_agent_id, rubric_id, grade_agent_id
),
-- Link rubric_grade_agents to runs
link_run_rubric_grade_agents AS (
    INSERT INTO eval_runs_rubric_grade_agents (eval_id, run_id, rubric_grade_agent_id, created_at, updated_at)
    SELECT DISTINCT
        p.eval_id,
        (r).run_id,
        crga.rubric_grade_agent_id,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN UNNEST(p.runs) AS r
    CROSS JOIN UNNEST((r).rubric_grade_agents) AS rga
    JOIN create_rubric_grade_agents crga ON crga.rubric_id = (rga).rubric_id 
        AND crga.grade_agent_id = (rga).grade_agent_id
    WHERE (r).run_id IS NOT NULL
      AND (rga).rubric_id IS NOT NULL 
      AND (rga).grade_agent_id IS NOT NULL
    ON CONFLICT (eval_id, run_id, rubric_grade_agent_id) DO NOTHING
)
SELECT 
    p.eval_id,
    up.actor_name::text as actor_name
FROM params p
CROSS JOIN user_profile up
$$;


--
-- Name: api_authorize_emulation_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_authorize_emulation_v4(requester_profile_id uuid, target_profile_id uuid) RETURNS TABLE(allowed boolean, reason text, actor_name text)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        requester_profile_id AS requester_profile_id,
        target_profile_id AS target_profile_id
),
self_emulation_check AS (
    -- Check if trying to emulate self (always allowed)
    SELECT 
        CASE 
            WHEN (SELECT requester_profile_id FROM params) = (SELECT target_profile_id FROM params) THEN true
            ELSE false
        END as is_self_emulation
),
requester_role AS (
    -- Get requester's role for permission check
    SELECT role
    FROM profiles p
    WHERE p.id = (SELECT requester_profile_id FROM params)
),
simulatable_profiles AS (
    -- Get simulatable profiles for the requester based on role hierarchy
    SELECT 
        p.id
    FROM profiles p
    CROSS JOIN requester_role rr
    WHERE p.id != (SELECT requester_profile_id FROM params)
      AND CASE 
        WHEN rr.role = 'superadmin'::profile_role THEN true
        WHEN rr.role = 'admin'::profile_role THEN p.role IN ('instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role)
        WHEN rr.role = 'instructional'::profile_role THEN p.role IN ('member'::profile_role, 'guest'::profile_role)
        ELSE false
      END
),
target_in_simulatable AS (
    -- Check if target is in simulatable list
    SELECT EXISTS(
        SELECT 1 
        FROM simulatable_profiles sp
        WHERE sp.id = (SELECT target_profile_id FROM params)
    ) as is_simulatable
),
actor_name_computed AS (
    -- Compute actor_name from requester profile
    SELECT 
        first_name || ' ' || last_name as actor_name
    FROM profiles
    WHERE id = (SELECT requester_profile_id FROM params)
)
SELECT 
    CASE 
        WHEN (SELECT is_self_emulation FROM self_emulation_check) THEN true
        WHEN (SELECT is_simulatable FROM target_in_simulatable) THEN true
        ELSE false
    END as allowed,
    CASE 
        WHEN (SELECT is_self_emulation FROM self_emulation_check) THEN NULL::text
        WHEN (SELECT is_simulatable FROM target_in_simulatable) THEN NULL::text
        ELSE 'You do not have permission to emulate this profile'
    END as reason,
    (SELECT actor_name FROM actor_name_computed) as actor_name
$$;


--
-- Name: api_bulk_archive_attempts_v4(boolean, uuid, uuid[], text, text, uuid[], uuid[], public.profile_role[], text[], text, uuid[], uuid[], uuid[], boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_bulk_archive_attempts_v4(archived boolean, profile_id uuid, attempt_ids uuid[] DEFAULT ARRAY[]::uuid[], start_date text DEFAULT NULL::text, end_date text DEFAULT NULL::text, cohort_ids uuid[] DEFAULT ARRAY[]::uuid[], department_ids uuid[] DEFAULT ARRAY[]::uuid[], roles public.profile_role[] DEFAULT ARRAY[]::public.profile_role[], simulation_filters text[] DEFAULT ARRAY[]::text[], search text DEFAULT NULL::text, profile_ids_filter uuid[] DEFAULT ARRAY[]::uuid[], simulation_ids uuid[] DEFAULT ARRAY[]::uuid[], scenario_ids uuid[] DEFAULT ARRAY[]::uuid[], infinite_mode boolean DEFAULT NULL::boolean) RETURNS TABLE(updated_count bigint, actor_name text, profile_ids_to_invalidate text[])
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_updated_count bigint;
    v_actor_name text;
    v_profile_ids text[];
    v_use_attempt_ids_mode boolean;
BEGIN
    -- Get actor name
    SELECT first_name || ' ' || last_name INTO v_actor_name
    FROM profiles
    WHERE id = profile_id;

    -- Determine mode: use attempt_ids if provided and non-empty
    v_use_attempt_ids_mode := cardinality(attempt_ids) > 0;

    IF v_use_attempt_ids_mode THEN
        -- attempt_ids mode: Archive specific attempts
        WITH update_attempts AS (
            UPDATE simulation_attempts
            SET archived = api_bulk_archive_attempts_v4.archived
            WHERE id = ANY(attempt_ids)
              AND archived != api_bulk_archive_attempts_v4.archived
            RETURNING id
        )
        SELECT COUNT(*)::bigint INTO v_updated_count
        FROM update_attempts;

        -- Get profile IDs to invalidate from attempt_ids
        SELECT COALESCE(
            ARRAY_AGG(DISTINCT ap.profile_id::text) FILTER (WHERE ap.profile_id IS NOT NULL),
            ARRAY[]::text[]
        ) INTO v_profile_ids
        FROM attempt_profiles ap
        WHERE ap.attempt_id = ANY(attempt_ids)
          AND ap.active = true;
    ELSE
        -- filter mode: Use the existing filter-based logic from bulk_archive_attempts_by_filters.sql
        -- This is a complex query, so we'll execute it as a subquery
        WITH 
        roles_param AS (
            SELECT roles AS roles_array
        ),
        history_viewer_role AS (
            SELECT 
                CASE 
                    WHEN profile_id::text IS NULL OR profile_id::text = '' THEN
                        CASE 
                            WHEN 'superadmin'::profile_role = ANY(roles) THEN 'superadmin'::text
                            WHEN 'admin'::profile_role = ANY(roles) THEN 'admin'::text
                            WHEN 'instructional'::profile_role = ANY(roles) THEN 'instructional'::text
                            WHEN 'member'::profile_role = ANY(roles) THEN 'member'::text
                            ELSE 'guest'::text
                        END
                    ELSE COALESCE((SELECT role::text FROM profiles WHERE id = profile_id), 'guest'::text)
                END::profile_role as role
        ),
        expanded_history_cohort_ids AS (
            SELECT DISTINCT cohort_id
            FROM (
                SELECT unnest(cohort_ids) as cohort_id
                WHERE cardinality(cohort_ids) > 0
                UNION
                SELECT cp.cohort_id
                FROM cohort_profiles cp
                WHERE cp.profile_id = profile_id AND (profile_id::text IS NOT NULL AND profile_id::text != '')
            ) combined
        ),
        history_attempts AS (
            SELECT DISTINCT
                sa.id AS attempt_id,
                sa.simulation_id,
                sa.created_at AS attempt_date,
                sa.archived AS is_archived,
                sa.infinite_mode,
                ap.profile_id,
                sim.title AS simulation_name,
                sim.practice_simulation,
                COALESCE(sdd.department_ids, NULL) as department_ids
            FROM simulation_attempts sa
            JOIN attempt_profiles ap ON ap.attempt_id = sa.id AND ap.active = TRUE
            JOIN simulations sim ON sim.id = sa.simulation_id
            JOIN profiles p_attempt ON p_attempt.id = ap.profile_id
            CROSS JOIN history_viewer_role hvr
            LEFT JOIN (
                SELECT 
                    sd.simulation_id,
                    ARRAY_AGG(sd.department_id::text ORDER BY sd.created_at) as department_ids
                FROM simulation_departments sd
                WHERE sd.active = true
                GROUP BY sd.simulation_id
            ) sdd ON sdd.simulation_id = sim.id
            WHERE (start_date IS NULL OR start_date = '' OR sa.created_at >= (NULLIF(start_date, '')::timestamptz))
              AND (end_date IS NULL OR end_date = '' OR sa.created_at <= (NULLIF(end_date, '')::timestamptz))
              AND (
                (cardinality(simulation_filters) = 0) AND sim.practice_simulation = FALSE
                OR
                (cardinality(simulation_filters) > 0 AND (
                  ('general' = ANY(simulation_filters) AND sim.practice_simulation = FALSE) OR
                  ('practice' = ANY(simulation_filters) AND sim.practice_simulation = TRUE) OR
                  ('archived' = ANY(simulation_filters) AND sa.archived = TRUE)
                ))
              )
              AND (
                cardinality(simulation_filters) = 0 OR 'archived' = ANY(simulation_filters) OR sa.archived = FALSE
              )
              AND ((profile_id::text IS NULL OR profile_id::text = '') OR ap.profile_id = profile_id)
              AND (cardinality(department_ids) = 0 OR sdd.department_ids IS NULL OR sdd.department_ids && department_ids::text[])
              AND (
                hvr.role = 'superadmin'::profile_role OR
                (hvr.role = 'admin'::profile_role AND p_attempt.role IN ('admin'::profile_role, 'instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role)) OR
                (hvr.role = 'instructional'::profile_role AND p_attempt.role IN ('instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role)) OR
                (hvr.role = 'member'::profile_role AND p_attempt.role IN ('member'::profile_role, 'guest'::profile_role)) OR
                (hvr.role = 'guest'::profile_role AND p_attempt.role = 'guest'::profile_role)
              )
        ),
        history_attempt_cohorts AS (
            SELECT
                ha.attempt_id,
                COALESCE(ARRAY_AGG(DISTINCT c.id) FILTER (WHERE c.id IS NOT NULL AND cs.simulation_id = ha.simulation_id), ARRAY[]::uuid[]) AS cohort_ids
            FROM history_attempts ha
            LEFT JOIN cohort_profiles cp ON cp.profile_id = ha.profile_id
            LEFT JOIN cohorts c ON c.id = cp.cohort_id AND c.active = TRUE
            LEFT JOIN cohort_simulations cs ON cs.cohort_id = c.id
            WHERE (
                (SELECT COUNT(*) FROM expanded_history_cohort_ids) = 0
                OR c.id IN (SELECT cohort_id FROM expanded_history_cohort_ids)
            )
            GROUP BY ha.attempt_id
        ),
        history_attempts_filtered AS (
            SELECT ha.*
            FROM history_attempts ha
            JOIN history_attempt_cohorts hac ON hac.attempt_id = ha.attempt_id
            WHERE (
                (SELECT COUNT(*) FROM expanded_history_cohort_ids) = 0
                OR cardinality(hac.cohort_ids) > 0
            )
        ),
        history_attempts_with_filters AS (
            SELECT haf.*
            FROM history_attempts_filtered haf
            WHERE 
                (cardinality(profile_ids_filter) = 0 OR haf.profile_id = ANY(profile_ids_filter))
                AND (cardinality(simulation_ids) = 0 OR haf.simulation_id = ANY(simulation_ids))
                AND (infinite_mode IS NULL OR haf.infinite_mode = infinite_mode)
        ),
        attempt_scenario_ids AS (
            SELECT DISTINCT
                ac.attempt_id,
                ARRAY_AGG(DISTINCT sc.scenario_id) FILTER (WHERE sc.scenario_id IS NOT NULL) AS scenario_ids
            FROM attempt_chats ac
            JOIN chats sc ON sc.id = ac.chat_id
            WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_with_filters)
            GROUP BY ac.attempt_id
        ),
        history_attempts_final AS (
            SELECT haf.*
            FROM history_attempts_with_filters haf
            LEFT JOIN attempt_scenario_ids asi ON asi.attempt_id = haf.attempt_id
            WHERE 
                (cardinality(scenario_ids) = 0 OR asi.scenario_ids IS NULL OR asi.scenario_ids && scenario_ids)
        ),
        history_personas AS (
            SELECT
                ac.attempt_id,
                array_agg(DISTINCT sp.persona_id) FILTER (WHERE sp.persona_id IS NOT NULL) AS persona_ids
            FROM attempt_chats ac
            JOIN chats sc ON sc.id = ac.chat_id
            JOIN scenarios scn ON scn.id = sc.scenario_id
            LEFT JOIN scenario_personas sp ON sp.scenario_id = scn.id AND sp.active = TRUE
            WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
            GROUP BY ac.attempt_id
        ),
        final_filtered_attempts AS (
            SELECT haf.attempt_id
            FROM history_attempts_final haf
            LEFT JOIN profiles p ON p.id = haf.profile_id
            LEFT JOIN history_personas hp ON hp.attempt_id = haf.attempt_id
            WHERE 
                (search IS NULL OR search = '' OR
                 LOWER(p.first_name || ' ' || p.last_name) LIKE '%' || LOWER(search) || '%' OR
                 LOWER(haf.simulation_name) LIKE '%' || LOWER(search) || '%' OR
                 EXISTS (
                     SELECT 1
                     FROM unnest(hp.persona_ids) AS pid
                     JOIN personas per ON per.id = pid
                     WHERE LOWER(per.name) LIKE '%' || LOWER(search) || '%'
                 ))
        ),
        filter_update AS (
            UPDATE simulation_attempts
            SET archived = api_bulk_archive_attempts_v4.archived
            WHERE id IN (SELECT attempt_id FROM final_filtered_attempts)
              AND archived != api_bulk_archive_attempts_v4.archived
            RETURNING id
        )
        SELECT COUNT(*)::bigint INTO v_updated_count
        FROM filter_update;

        -- Get profile IDs to invalidate (use current user's profile ID)
        IF profile_id IS NOT NULL THEN
            v_profile_ids := ARRAY[profile_id::text];
        ELSE
            v_profile_ids := ARRAY[]::text[];
        END IF;
    END IF;

    -- Return results
    RETURN QUERY SELECT v_updated_count, v_actor_name, COALESCE(v_profile_ids, ARRAY[]::text[]);
END;
$$;


--
-- Name: api_bulk_create_staff_v4(types.i_bulk_create_staff_v4_profile[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_bulk_create_staff_v4(profiles types.i_bulk_create_staff_v4_profile[], profile_id uuid) RETURNS TABLE(profile_ids uuid[], existing_emails text[], actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        COALESCE(profiles, ARRAY[]::types.i_bulk_create_staff_v4_profile[]) AS profiles,
        profile_id AS profile_id
),
user_profile AS (
    SELECT 
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
profiles_expanded AS (
    -- Expand composite type array into rows with generated profile IDs
    SELECT 
        gen_random_uuid() as profile_id,
        p.first_name,
        p.last_name,
        p.emails,
        COALESCE(p.primary_email_index, 0) as primary_email_index,
        p.role,
        COALESCE(p.department_ids, ARRAY[]::uuid[]) as department_ids,
        p.primary_department_index
    FROM unnest((SELECT profiles FROM params)) as p
),
all_emails_expanded AS (
    -- Extract all emails (primary and additional) with their profile IDs
    SELECT 
        pe.profile_id,
        email_val as email,
        CASE 
            WHEN (idx - 1) = pe.primary_email_index THEN true
            ELSE false
        END as is_primary
    FROM profiles_expanded pe
    CROSS JOIN LATERAL unnest(pe.emails) WITH ORDINALITY AS t(email_val, idx)
),
primary_emails_only AS (
    -- Get primary email for each profile
    SELECT DISTINCT ON (profile_id)
        profile_id,
        email as primary_email
    FROM all_emails_expanded
    WHERE is_primary = true
),
email_check AS (
    -- Check if any emails already exist in profile_emails
    SELECT array_agg(DISTINCT pe.email) as existing_emails
    FROM profile_emails pe
    CROSS JOIN all_emails_expanded aee
    WHERE pe.email = aee.email
       AND pe.active = true
),
profiles_data AS (
    -- Prepare profile data with primary email and primary department
    SELECT 
        pe.profile_id,
        pe.first_name,
        pe.last_name,
        COALESCE(peo.primary_email, '') as primary_email,
        pe.role,
        CASE 
            WHEN pe.primary_department_index IS NOT NULL 
                 AND pe.primary_department_index >= 0 
                 AND pe.primary_department_index < array_length(pe.department_ids, 1)
            THEN pe.department_ids[pe.primary_department_index + 1]  -- PostgreSQL arrays are 1-indexed
            WHEN array_length(pe.department_ids, 1) > 0
            THEN pe.department_ids[1]  -- Default to first department
            ELSE NULL
        END as primary_department_id,
        pe.department_ids as all_department_ids
    FROM profiles_expanded pe
    LEFT JOIN primary_emails_only peo ON peo.profile_id = pe.profile_id
),
profile_insert AS (
    -- Insert all profiles (only if no emails exist)
    INSERT INTO profiles (
        id, first_name, last_name, role, active
    )
    SELECT 
        pd.profile_id,
        pd.first_name,
        pd.last_name,
        pd.role::profile_role,
        true  -- active
    FROM profiles_data pd
    WHERE NOT EXISTS (SELECT 1 FROM email_check WHERE existing_emails IS NOT NULL)
    RETURNING id
),
email_insert AS (
    -- Insert all emails (primary and additional) into profile_emails
    INSERT INTO profile_emails (profile_id, email, is_primary, active)
    SELECT 
        aee.profile_id,
        aee.email,
        aee.is_primary,
        true  -- active
    FROM all_emails_expanded aee
    WHERE EXISTS (SELECT 1 FROM profile_insert pi WHERE pi.id = aee.profile_id)
      AND NOT EXISTS (
          SELECT 1 FROM profile_emails pe 
          WHERE pe.email = aee.email AND pe.active = true
      )
),
department_insert AS (
    -- Insert all department relationships (first one as primary, rest as non-primary)
    INSERT INTO profile_departments (profile_id, department_id, is_primary, active)
    SELECT 
        pd.profile_id,
        dept_id,
        CASE 
            WHEN dept_id = pd.primary_department_id THEN true
            WHEN pd.primary_department_id IS NULL AND (ROW_NUMBER() OVER (PARTITION BY pd.profile_id ORDER BY dept_id) = 1) THEN true
            ELSE false
        END as is_primary,
        true  -- active
    FROM profiles_data pd
    CROSS JOIN unnest(pd.all_department_ids) as dept_id
    WHERE dept_id IS NOT NULL
        AND EXISTS (SELECT 1 FROM profile_insert pi WHERE pi.id = pd.profile_id)
    ON CONFLICT (profile_id, department_id) DO NOTHING
)
-- Return created profile IDs, existing emails, and actor_name
SELECT 
    COALESCE(array_agg(pi.id ORDER BY pi.id), ARRAY[]::uuid[]) as profile_ids,
    COALESCE(ec.existing_emails, ARRAY[]::text[]) as existing_emails,
    up.actor_name::text as actor_name
FROM profile_insert pi
CROSS JOIN email_check ec
CROSS JOIN user_profile up
GROUP BY ec.existing_emails, up.actor_name
$$;


--
-- Name: api_bulk_delete_staff_v4(uuid[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_bulk_delete_staff_v4(profile_ids uuid[], profile_id uuid) RETURNS TABLE(deleted_count integer, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        profile_ids AS profile_ids,
        profile_id AS profile_id
),
user_profile AS (
    SELECT 
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
deletable_profiles AS (
    -- Get list of profiles that can be deleted
    SELECT array_agg(p.id) as deletable_ids
    FROM profiles p
    CROSS JOIN params pr
    WHERE p.id = ANY(pr.profile_ids)
),
profile_delete AS (
    -- Delete profiles
    DELETE FROM profiles p
    WHERE EXISTS (
        SELECT 1 FROM params pr WHERE p.id = ANY(pr.profile_ids)
    )
        AND EXISTS (SELECT 1 FROM deletable_profiles WHERE deletable_ids IS NOT NULL)
    RETURNING p.id
)
-- Return deletion count and actor_name
SELECT 
    COALESCE((SELECT COUNT(*) FROM profile_delete), 0)::int as deleted_count,
    up.actor_name::text as actor_name
FROM deletable_profiles dp
CROSS JOIN user_profile up
$$;


--
-- Name: api_bulk_update_staff_v4(uuid, uuid[], text, boolean, integer, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_bulk_update_staff_v4(profile_id uuid, profile_ids uuid[], role text DEFAULT NULL::text, active boolean DEFAULT NULL::boolean, requests_per_day integer DEFAULT NULL::integer, primary_department_id uuid DEFAULT NULL::uuid) RETURNS TABLE(updated_count integer, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        profile_ids AS profile_ids,
        role AS role,
        active AS active,
        requests_per_day AS requests_per_day,
        primary_department_id AS primary_department_id,
        profile_id AS profile_id
),
user_profile AS (
    SELECT 
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
role_param AS (
    -- Use role to help PostgreSQL infer type (even if NULL)
    SELECT role AS role_value FROM params
),
current_user_role AS (
    -- Get current user's role for validation
    SELECT p.role FROM params x JOIN profiles p ON p.id = x.profile_id
),
profile_validation AS (
    -- Validate each profile and check permissions
    SELECT 
        p.id,
        p.role as current_role,
        cur.role as validator_role,
        rp.role_value,
        -- Check if role assignment is allowed (hierarchy check)
        CASE 
            WHEN rp.role_value IS NULL THEN true  -- Not updating role
            WHEN cur.role = 'superadmin'::profile_role THEN true
            WHEN cur.role = 'admin'::profile_role AND rp.role_value::profile_role IN ('instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role) THEN true
            WHEN cur.role = 'instructional'::profile_role AND rp.role_value::profile_role IN ('member'::profile_role, 'guest'::profile_role) THEN true
            WHEN cur.role = 'member'::profile_role AND rp.role_value::profile_role = 'guest'::profile_role THEN true
            ELSE false
        END as can_assign_role,
        -- Check if role level is acceptable (cannot assign equal or higher role)
        CASE 
            WHEN rp.role_value IS NULL THEN true  -- Not updating role
            WHEN cur.role = 'superadmin'::profile_role THEN true  -- Superadmin can assign any role
            WHEN p.id = (SELECT profile_id FROM params) THEN true  -- Can update own role
            WHEN cur.role = 'superadmin'::profile_role THEN true
            WHEN cur.role = 'admin'::profile_role AND rp.role_value::profile_role IN ('instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role) THEN true
            WHEN cur.role = 'instructional'::profile_role AND rp.role_value::profile_role IN ('member'::profile_role, 'guest'::profile_role) THEN true
            WHEN cur.role = 'member'::profile_role AND rp.role_value::profile_role = 'guest'::profile_role THEN true
            ELSE false
        END as role_level_ok,
        -- All profiles can be edited based on role hierarchy
        true as can_edit_default
    FROM params pr
    CROSS JOIN unnest(pr.profile_ids) as profile_id_val
    CROSS JOIN current_user_role cur
    CROSS JOIN role_param rp
    JOIN profiles p ON p.id = profile_id_val
),
validated_profiles AS (
    -- Filter to only profiles that pass validation
    SELECT id
    FROM profile_validation
    WHERE can_assign_role = true AND role_level_ok = true AND can_edit_default = true
),
profile_update AS (
    -- Update profiles table with dynamic SET clauses
    UPDATE profiles p
    SET 
        role = COALESCE((SELECT CAST(rp.role_value AS profile_role) FROM role_param rp WHERE rp.role_value IS NOT NULL LIMIT 1), p.role),
        active = COALESCE((SELECT active FROM params), p.active),
        updated_at = NOW()
    WHERE p.id IN (SELECT id FROM validated_profiles)
    RETURNING p.id
),
request_limit_update AS (
    -- Update request limits if provided (skip if NULL)
    INSERT INTO profile_request_limits (profile_id, requests_per_day, active)
    SELECT 
        pu.id,
        CASE WHEN (SELECT requests_per_day FROM params) = -1 THEN NULL ELSE (SELECT requests_per_day FROM params) END,  -- -1 means unlimited (NULL)
        true
    FROM profile_update pu
    WHERE (SELECT requests_per_day FROM params) IS NOT NULL  -- Only update if value provided (not skipping)
    ON CONFLICT (profile_id, active) 
    WHERE active = true
    DO UPDATE SET 
        requests_per_day = EXCLUDED.requests_per_day,
        updated_at = NOW()
),
department_update AS (
    -- Update primary department if provided (skip if NULL)
    UPDATE profile_departments
    SET 
        department_id = (SELECT primary_department_id FROM params),
        updated_at = NOW()
    WHERE profile_id IN (SELECT id FROM profile_update)
        AND (SELECT primary_department_id FROM params) IS NOT NULL  -- Only update if value provided (not skipping)
    RETURNING profile_id
)
SELECT 
    COUNT(*)::integer as updated_count,
    up.actor_name::text as actor_name
FROM profile_update pu
CROSS JOIN user_profile up
GROUP BY up.actor_name
$$;


--
-- Name: api_check_login_authorization_v4(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_check_login_authorization_v4(department_id text DEFAULT NULL::text) RETURNS TABLE(guest_login_enabled boolean, active_departments_count bigint, department_auth_providers_count bigint, default_settings_auth_providers_count bigint, departments_without_auth_providers_count bigint, department_exists boolean)
    LANGUAGE sql STABLE
    AS $$
WITH params_normalized AS (
    -- Normalize department_id: convert empty string to NULL
    SELECT 
        CASE 
            WHEN department_id IS NULL OR department_id = '' THEN NULL::uuid
            ELSE department_id::uuid
        END as department_id_uuid
),
default_settings AS (
    -- Get settings with no department links (cross-department/default)
    SELECT s.id as settings_id, s.guest_login_enabled
    FROM settings s
    WHERE s.active = true
      AND NOT EXISTS (
          SELECT 1 FROM department_settings sd 
          WHERE sd.settings_id = s.id AND sd.active = true
      )
    LIMIT 1
),
dept_specific_settings AS (
    -- Get department-specific settings (if department_id provided)
    SELECT s.id as settings_id, s.guest_login_enabled
    FROM settings s
    JOIN department_settings ds ON ds.settings_id = s.id AND ds.active = true
    CROSS JOIN params_normalized pn
    WHERE pn.department_id_uuid IS NOT NULL
      AND ds.department_id = pn.department_id_uuid
      AND s.active = true
    LIMIT 1
),
selected_settings AS (
    -- Priority: department-specific settings, then default, then any active
    SELECT 
        COALESCE(
            (SELECT settings_id FROM dept_specific_settings),
            (SELECT settings_id FROM default_settings),
            (SELECT id FROM settings WHERE active = true LIMIT 1)
        ) as settings_id,
        COALESCE(
            (SELECT guest_login_enabled FROM dept_specific_settings),
            (SELECT guest_login_enabled FROM default_settings),
            false
        ) as guest_login_enabled
),
active_departments_count AS (
    -- Count all active departments
    SELECT COUNT(*) as count
    FROM departments
    WHERE active = true
),
department_exists_check AS (
    -- Check if the specified department exists and is active (if department_id provided)
    SELECT 
        CASE 
            WHEN pn.department_id_uuid IS NOT NULL THEN
                EXISTS(
                    SELECT 1 FROM departments d
                    CROSS JOIN params_normalized pn
                    WHERE d.id = pn.department_id_uuid
                    AND d.active = true
                )
            ELSE false
        END as department_exists
    FROM params_normalized pn
),
department_auth_providers_count AS (
    -- Count auth providers for specific department (if department_id provided)
    SELECT COUNT(DISTINCT a.id) as count
    FROM departments d
    JOIN department_settings ds ON ds.department_id = d.id AND ds.active = true
    JOIN settings s ON s.id = ds.settings_id AND s.active = true
    JOIN setting_auths sa ON sa.settings_id = s.id AND sa.active = true
    JOIN auth a ON a.id = sa.auth_id AND a.active = true
    CROSS JOIN params_normalized pn
    WHERE pn.department_id_uuid IS NOT NULL
      AND d.id = pn.department_id_uuid
      AND d.active = true
),
default_settings_auth_providers_count AS (
    -- Count auth providers for default settings (no department links)
    SELECT COUNT(DISTINCT a.id) as count
    FROM default_settings ds
    JOIN settings s ON s.id = ds.settings_id
    JOIN setting_auths sa ON sa.settings_id = s.id AND sa.active = true
    JOIN auth a ON a.id = sa.auth_id AND a.active = true
),
departments_without_auth_providers_count AS (
    -- Count departments that have no auth providers configured
    SELECT COUNT(DISTINCT d.id) as count
    FROM departments d
    WHERE d.active = true
      AND NOT EXISTS (
          SELECT 1
          FROM department_settings ds
          JOIN settings s ON s.id = ds.settings_id AND s.active = true
          JOIN setting_auths sa ON sa.settings_id = s.id AND sa.active = true
          JOIN auth a ON a.id = sa.auth_id AND a.active = true
          WHERE ds.department_id = d.id
            AND ds.active = true
      )
)
SELECT 
    (SELECT guest_login_enabled FROM selected_settings) as guest_login_enabled,
    (SELECT count FROM active_departments_count) as active_departments_count,
    COALESCE((SELECT count FROM department_auth_providers_count), 0) as department_auth_providers_count,
    COALESCE((SELECT count FROM default_settings_auth_providers_count), 0) as default_settings_auth_providers_count,
    COALESCE((SELECT count FROM departments_without_auth_providers_count), 0) as departments_without_auth_providers_count,
    (SELECT department_exists FROM department_exists_check) as department_exists
LIMIT 1
$$;


--
-- Name: api_check_next_incomplete_scenario_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_check_next_incomplete_scenario_v4(attempt_id uuid) RETURNS TABLE(has_next_scenario boolean, next_scenario_id uuid, next_scenario_position integer)
    LANGUAGE sql STABLE
    AS $$
WITH RECURSIVE attempt_base AS (
    SELECT 
        sa.id as attempt_id,
        sa.simulation_id,
        sa.infinite_mode
    FROM simulation_attempts sa
    WHERE sa.id = attempt_id
),
simulation_scenarios_list AS (
    SELECT 
        ss.scenario_id,
        ss.position
    FROM simulation_scenarios ss
    CROSS JOIN attempt_base ab
    WHERE ss.simulation_id = ab.simulation_id
      AND ss.active = true
    ORDER BY ss.position
),
existing_chats AS (
    SELECT 
        sc.id as chat_id,
        sc.scenario_id as child_scenario_id,
        sc.completed
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    CROSS JOIN attempt_base ab
    WHERE ac.attempt_id = ab.attempt_id
),
-- Recursively map child scenario IDs to root parent IDs  
scenario_ancestors AS (
    SELECT DISTINCT
        ec.child_scenario_id,
        ec.child_scenario_id as ancestor_id,
        0 as depth
    FROM existing_chats ec
    
    UNION ALL
    
    SELECT 
        sa.child_scenario_id,
        COALESCE(
            (SELECT st.parent_id 
             FROM scenario_tree st 
             WHERE st.child_id = sa.ancestor_id 
               AND st.parent_id != st.child_id 
             LIMIT 1),
            sa.ancestor_id
        ) as ancestor_id,
        sa.depth + 1 as depth
    FROM scenario_ancestors sa
    WHERE sa.depth < 100
      AND EXISTS (
          SELECT 1 FROM scenario_tree st 
          WHERE st.child_id = sa.ancestor_id 
            AND st.parent_id != st.child_id
      )
),
root_scenarios AS (
    SELECT DISTINCT
        child_scenario_id,
        ancestor_id as root_scenario_id
    FROM scenario_ancestors
    WHERE depth = (
        SELECT MAX(depth) 
        FROM scenario_ancestors sa2 
        WHERE sa2.child_scenario_id = scenario_ancestors.child_scenario_id
    )
),
-- Map child scenario IDs to root parent IDs for comparison
child_to_parent_mapping AS (
    SELECT DISTINCT
        ec.child_scenario_id,
        COALESCE(rs.root_scenario_id, ec.child_scenario_id) as parent_scenario_id
    FROM existing_chats ec
    LEFT JOIN root_scenarios rs ON rs.child_scenario_id = ec.child_scenario_id
),
-- Get scenarios that already have chats (even without grades) to avoid duplicates
existing_parent_scenario_ids AS (
    SELECT DISTINCT ctp.parent_scenario_id
    FROM child_to_parent_mapping ctp
    JOIN simulation_scenarios_list ssl ON ssl.scenario_id = ctp.parent_scenario_id
),
-- Get parent scenarios that have graded chats (reuse logic from get_scenarios_with_grades.sql)
scenarios_with_grades AS (
    SELECT DISTINCT ss.scenario_id as parent_scenario_id
    FROM simulation_scenarios ss
    CROSS JOIN attempt_base ab
    JOIN attempt_chats ac ON ac.attempt_id = ab.attempt_id
    JOIN chats sc ON sc.id = ac.chat_id
    JOIN grades scg ON EXISTS (
        SELECT 1 FROM runs r_check
        JOIN group_runs gr_check ON gr_check.run_id = r_check.id
        JOIN groups g_check ON g_check.id = gr_check.group_id
        JOIN chat_groups cg_check ON cg_check.group_id = g_check.id
        JOIN chats c_check ON c_check.id = cg_check.chat_id AND c_check.id = sc.id
        WHERE r_check.id = scg.run_id
    )
    JOIN runs r ON r.id = scg.run_id
    JOIN group_runs gr ON gr.run_id = r.id
    JOIN groups g ON g.id = gr.group_id
    JOIN chat_groups cg ON cg.group_id = g.id
    JOIN chats c ON c.id = cg.chat_id AND c.id = sc.id
    LEFT JOIN root_scenarios rs ON rs.child_scenario_id = sc.scenario_id
    WHERE ss.simulation_id = ab.simulation_id
      AND ss.active = true
      AND (
        COALESCE(rs.root_scenario_id, sc.scenario_id) = ss.scenario_id
        OR sc.scenario_id = ss.scenario_id
      )
),
-- Find next scenario that doesn't have a graded chat and doesn't already have a chat
next_scenario_candidate AS (
    SELECT 
        ssl.scenario_id,
        ssl.position
    FROM simulation_scenarios_list ssl
    CROSS JOIN attempt_base ab
    WHERE ssl.scenario_id NOT IN (
        SELECT parent_scenario_id FROM scenarios_with_grades
    )
    AND ssl.scenario_id NOT IN (
        SELECT parent_scenario_id FROM existing_parent_scenario_ids
    )
    ORDER BY ssl.position
    LIMIT 1
),
-- For infinite mode, always find next scenario (cycle through)
infinite_mode_next AS (
    SELECT 
        ssl.scenario_id,
        ssl.position
    FROM simulation_scenarios_list ssl
    CROSS JOIN attempt_base ab
    WHERE ab.infinite_mode = true
    AND EXISTS (SELECT 1 FROM simulation_scenarios_list)
    ORDER BY ssl.position
    LIMIT 1
)
SELECT 
    CASE 
        WHEN EXISTS (SELECT 1 FROM next_scenario_candidate) THEN true
        WHEN EXISTS (SELECT 1 FROM infinite_mode_next) THEN true
        ELSE false
    END as has_next_scenario,
    COALESCE(
        (SELECT scenario_id FROM next_scenario_candidate),
        (SELECT scenario_id FROM infinite_mode_next)
    ) as next_scenario_id,
    COALESCE(
        (SELECT position FROM next_scenario_candidate),
        (SELECT position FROM infinite_mode_next)
    ) as next_scenario_position
$$;


--
-- Name: api_complete_document_creation_v4(uuid, text, text, bigint, text, text, uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_complete_document_creation_v4(parent_document_id uuid, file_path text, mime_type text, file_size bigint, child_name text, child_description text, classify_agent_id uuid, document_agent_id uuid, scenario_id uuid) RETURNS TABLE(child_document_id text, upload_id text)
    LANGUAGE sql
    AS $$
WITH create_child_document AS (
    -- Create child document (not a template)
    INSERT INTO documents (
        id, name, description, active, template, created_at, updated_at,
        classify_agent_id, document_agent_id
    )
    VALUES (gen_random_uuid(), api_complete_document_creation_v4.child_name, api_complete_document_creation_v4.child_description, true, false, NOW(), NOW(), api_complete_document_creation_v4.classify_agent_id, api_complete_document_creation_v4.document_agent_id)
    RETURNING id
),
create_upload AS (
    -- Create upload record
    INSERT INTO uploads (file_path, mime_type, size, created_at, updated_at)
    VALUES (api_complete_document_creation_v4.file_path, api_complete_document_creation_v4.mime_type, api_complete_document_creation_v4.file_size, NOW(), NOW())
    RETURNING id
),
link_document_upload AS (
    -- Link document to upload (regular upload, not template upload)
    INSERT INTO document_uploads (document_id, upload_id, active, created_at, updated_at)
    SELECT ccd.id, cu.id, true, NOW(), NOW()
    FROM create_child_document ccd
    CROSS JOIN create_upload cu
    ON CONFLICT (document_id, upload_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
    RETURNING document_id, upload_id
),
link_document_tree AS (
    -- Link parent→child in document_tree
    INSERT INTO document_tree (parent_id, child_id, active, created_at, updated_at)
    SELECT api_complete_document_creation_v4.parent_document_id, ccd.id, true, NOW(), NOW()
    FROM create_child_document ccd
    ON CONFLICT (parent_id, child_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
    RETURNING child_id
),
copy_document_departments AS (
    -- Copy document_departments from parent to child (for department filtering)
    INSERT INTO document_departments (document_id, department_id, active, created_at, updated_at)
    SELECT 
        ccd.id,
        dd.department_id,
        dd.active,
        NOW(),
        NOW()
    FROM create_child_document ccd
    CROSS JOIN document_departments dd
    WHERE dd.document_id = api_complete_document_creation_v4.parent_document_id AND dd.active = true
    ON CONFLICT (document_id, department_id) DO UPDATE SET
        active = EXCLUDED.active,
        updated_at = NOW()
),
-- NOTE: Child documents are "bare" - we do NOT copy document_fields or parameter_documents 
-- from parent template to avoid collisions in scenarios/videos.
-- We DO copy document_departments for proper department filtering.
-- The child document exists only as a dynamic instance linked to the parent via document_tree
link_scenario AS (
    -- Optionally link to scenario if scenario_id provided
    INSERT INTO scenario_documents (scenario_id, document_id, active, created_at, updated_at)
    SELECT api_complete_document_creation_v4.scenario_id, ccd.id, true, NOW(), NOW()
    FROM create_child_document ccd
    WHERE api_complete_document_creation_v4.scenario_id IS NOT NULL
    ON CONFLICT (scenario_id, document_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
    RETURNING document_id
)
SELECT 
    ccd.id::text as child_document_id,
    cu.id::text as upload_id
FROM create_child_document ccd
CROSS JOIN create_upload cu
CROSS JOIN link_document_upload ldu
CROSS JOIN link_document_tree ldt
LEFT JOIN link_scenario ls ON ls.document_id = ccd.id
$$;


--
-- Name: api_create_agent_v4(text, text, uuid, boolean, public.agent_role, uuid, uuid, text, uuid[], uuid, uuid, uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_agent_v4(name text, description text, model_id uuid, active boolean, role public.agent_role, profile_id uuid, prompt_id uuid DEFAULT NULL::uuid, system_prompt text DEFAULT NULL::text, department_ids uuid[] DEFAULT ARRAY[]::uuid[], model_temperature_level_id uuid DEFAULT NULL::uuid, model_reasoning_level_id uuid DEFAULT NULL::uuid, model_voice_ids uuid[] DEFAULT ARRAY[]::uuid[]) RETURNS TABLE(agent_id text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT
        name AS name,
        description AS description,
        model_id AS model_id,
        active AS active,
        role AS role,
        prompt_id AS prompt_id,
        NULLIF(system_prompt, '') AS system_prompt,
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids,
        model_temperature_level_id AS model_temperature_level_id,
        model_reasoning_level_id AS model_reasoning_level_id,
        COALESCE(model_voice_ids, ARRAY[]::uuid[]) AS model_voice_ids,
        profile_id AS profile_id
),
user_profile AS (
    SELECT 
        p.role,
        p.first_name || ' ' || p.last_name as actor_name
    FROM profiles p
    JOIN params x ON p.id = x.profile_id
),
validate_create_permissions AS (
    -- Validate department permissions for create operation
    SELECT validate_department_create_permissions(
        up.role::text,
        (SELECT department_ids::text[] FROM params)
    ) AS ok
    FROM user_profile up
),
assert_permissions AS (
    -- Ensure permissions are valid before proceeding
    SELECT 1
    FROM validate_create_permissions
    WHERE ok = true
),
actor_profile AS (
    SELECT 
        x.profile_id AS resolved_profile_id,
        up.actor_name
    FROM params x
    CROSS JOIN user_profile up
),
new_agent AS (
    INSERT INTO agents (name, description, model_id, active, role, created_at, updated_at)
    SELECT 
        x.name,
        x.description,
        x.model_id,
        x.active,
        x.role,
        NOW(), 
        NOW()
    FROM params x
    JOIN assert_permissions ap ON TRUE
    RETURNING id::text as agent_id
),
new_prompt AS (
    -- Create prompt only if system_prompt provided and prompt_id not provided
    INSERT INTO prompts (system_prompt, created_at, updated_at)
    SELECT x.system_prompt, NOW(), NOW()
    FROM params x
    WHERE x.prompt_id IS NULL AND x.system_prompt IS NOT NULL
    RETURNING id::text as prompt_id
),
selected_prompt_id AS (
    -- Use provided prompt_id or newly created prompt_id (only return row if prompt exists)
    SELECT COALESCE(
        (SELECT prompt_id::text FROM params),
        (SELECT prompt_id FROM new_prompt LIMIT 1)
    ) as prompt_id
    WHERE (SELECT prompt_id FROM params) IS NOT NULL OR EXISTS (SELECT 1 FROM new_prompt)
),
link_prompt AS (
    -- Link agent to prompt if prompt_id exists
    INSERT INTO agent_prompts (agent_id, prompt_id, active, created_at, updated_at)
    SELECT 
        na.agent_id::uuid,
        sp.prompt_id::uuid,
        true,
        NOW(),
        NOW()
    FROM new_agent na
    CROSS JOIN selected_prompt_id sp
    ON CONFLICT (agent_id, prompt_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
link_departments AS (
    -- Link departments if provided (array is never NULL, but may be empty)
    INSERT INTO agent_departments (agent_id, department_id, active, created_at, updated_at)
    SELECT 
        na.agent_id::uuid,
        dept_id,
        true,
        NOW(),
        NOW()
    FROM new_agent na
    CROSS JOIN params x
    CROSS JOIN UNNEST(x.department_ids) AS dept_id
    ON CONFLICT (agent_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
link_temperature_level AS (
    -- Link temperature level if provided
    INSERT INTO agent_temperature_levels (agent_id, model_temperature_level_id, active, created_at, updated_at)
    SELECT 
        na.agent_id::uuid,
        x.model_temperature_level_id,
        true,
        NOW(),
        NOW()
    FROM new_agent na
    CROSS JOIN params x
    WHERE x.model_temperature_level_id IS NOT NULL
    ON CONFLICT (agent_id, model_temperature_level_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
link_reasoning_level AS (
    -- Link reasoning level if provided
    INSERT INTO agent_reasoning_levels (agent_id, model_reasoning_level_id, active, created_at, updated_at)
    SELECT 
        na.agent_id::uuid,
        x.model_reasoning_level_id,
        true,
        NOW(),
        NOW()
    FROM new_agent na
    CROSS JOIN params x
    WHERE x.model_reasoning_level_id IS NOT NULL
    ON CONFLICT (agent_id, model_reasoning_level_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
link_voices AS (
    -- Link voices if provided (array is never NULL, but may be empty)
    INSERT INTO agent_voices (agent_id, model_voice_id, active, created_at, updated_at)
    SELECT 
        na.agent_id::uuid,
        voice_id,
        true,
        NOW(),
        NOW()
    FROM new_agent na
    CROSS JOIN params x
    CROSS JOIN UNNEST(x.model_voice_ids) AS voice_id
    ON CONFLICT (agent_id, model_voice_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
)
SELECT 
    na.agent_id,
    ap.actor_name
FROM new_agent na
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_create_analysis_v4(text); Type: FUNCTION; Schema: public; Owner: -
