$$;


--
-- Name: api_create_analytics_view_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_analytics_view_v4(profile_id uuid) RETURNS TABLE(actor_name text, success boolean, message text, status text)
    LANGUAGE sql STABLE
    AS $$
WITH actor_profile AS (
    SELECT COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM profiles
    WHERE id = profile_id
)
SELECT 
    COALESCE((SELECT actor_name FROM actor_profile), 'System')::text as actor_name,
    true::boolean as success,
    'Analytics materialized view created successfully'::text as message,
    'success'::text as status;
$$;


--
-- Name: api_create_assistant_message_with_branch_v4(text, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_assistant_message_with_branch_v4(content text, run_id uuid, parent_message_id uuid) RETURNS TABLE(id uuid, created_at timestamp with time zone)
    LANGUAGE sql
    AS $$
WITH assistant_message AS (
    INSERT INTO messages (role, completed, audio, created_at, updated_at)
    VALUES ('assistant'::message_role, true, false, NOW(), NOW())
    RETURNING id, created_at, updated_at
),
insert_content AS (
    INSERT INTO content (content, created_at, updated_at)
    SELECT content, created_at, updated_at
    FROM assistant_message
    RETURNING id as content_id, created_at, updated_at
),
insert_message_content AS (
    INSERT INTO message_content (message_id, content_id, idx, created_at, updated_at)
    SELECT am.id, ic.content_id, 0, ic.created_at, ic.updated_at
    FROM assistant_message am
    CROSS JOIN insert_content ic
),
link_to_run AS (
    INSERT INTO message_runs (message_id, run_id, created_at, updated_at)
    SELECT am.id, run_id, NOW(), NOW()
    FROM assistant_message am
    ON CONFLICT (message_id, run_id) 
    DO UPDATE SET updated_at = NOW()
),
create_branch AS (
    INSERT INTO message_tree (parent_id, child_id, active, created_at, updated_at)
    SELECT parent_message_id, am.id, true, NOW(), NOW()
    FROM assistant_message am
    WHERE parent_message_id IS NOT NULL
    ON CONFLICT (parent_id, child_id) 
    DO UPDATE SET 
        active = true,
        updated_at = NOW()
)
SELECT id, created_at FROM assistant_message
$$;


--
-- Name: api_create_auth_v4(text, text, boolean, text, text, uuid, types.i_create_auth_v4_auth_item[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_auth_v4(name text, description text, active boolean, auth_type text, slug text, profile_id uuid, auth_items types.i_create_auth_v4_auth_item[] DEFAULT ARRAY[]::types.i_create_auth_v4_auth_item[]) RETURNS TABLE(success boolean, auth_id uuid, name text, message text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT
        name AS name,
        description AS description,
        active AS active,
        auth_type AS auth_type,
        COALESCE(NULLIF(slug, ''), lower(replace(name, ' ', '-'))) AS slug,
        profile_id AS profile_id,
        COALESCE(auth_items, ARRAY[]::types.i_create_auth_v4_auth_item[]) AS auth_items
),
actor_profile AS (
    SELECT 
        x.profile_id as resolved_profile_id,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
new_auth AS (
    INSERT INTO auth (
        name,
        description,
        active,
        auth_type,
        slug
    )
    SELECT x.name, x.description, x.active, x.auth_type, x.slug
    FROM params x
    RETURNING id as auth_id
),
items_expanded AS (
    -- Expand composite type array
    SELECT 
        item.name as item_name,
        item.description as item_description,
        COALESCE(item.encrypted, true) as item_encrypted,
        COALESCE(item.position, row_number() OVER ()) as item_position,
        COALESCE(item.active, true) as item_active,
        item.key_id as item_key_id
    FROM params x
    CROSS JOIN LATERAL unnest(x.auth_items) AS item
),
new_items AS (
    -- Create all auth items (without value column - dropped in migration)
    INSERT INTO auth_items (
        auth_id,
        name,
        description,
        encrypted,
        position,
        active
    )
    SELECT 
        na.auth_id,
        ie.item_name,
        ie.item_description,
        ie.item_encrypted,
        ie.item_position,
        ie.item_active
    FROM new_auth na
    CROSS JOIN items_expanded ie
    RETURNING id as item_id, encrypted
),
link_encrypted_keys AS (
    -- NOTE: auth_item_keys table was removed in migration 74
    -- Keys are now linked through settings (setting_auth_keys, setting_provider_keys)
    -- This CTE is kept for compatibility but does nothing
    SELECT 1 WHERE false
)
SELECT 
    true::boolean as success,
    na.auth_id,
    x.name,
    (x.name || ' created successfully')::text as message,
    ap.actor_name
FROM new_auth na
CROSS JOIN actor_profile ap
CROSS JOIN params x
$$;


--
-- Name: api_create_cohort_v4(text, text, boolean, text[], text[], text[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_cohort_v4(title text, description text, active boolean, department_ids text[], profile_ids text[], simulation_ids text[], profile_id uuid) RETURNS TABLE(cohort_id uuid, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT
        title AS title,
        COALESCE(NULLIF(description, ''), '') AS description,
        active AS active,
        COALESCE(department_ids, ARRAY[]::text[]) AS department_ids,
        COALESCE(profile_ids, ARRAY[]::text[]) AS profile_ids,
        COALESCE(simulation_ids, ARRAY[]::text[]) AS simulation_ids,
        profile_id AS profile_id
),
actor_profile AS (
    SELECT 
        x.profile_id AS resolved_profile_id,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
new_cohort AS (
    -- Create cohort
    INSERT INTO cohorts (
        title,
        description,
        active
    )
    SELECT x.title, x.description, x.active
    FROM params x
    RETURNING id
),
link_departments AS (
    -- Link departments if provided (array may be empty)
    INSERT INTO cohort_departments (cohort_id, department_id, active, created_at, updated_at)
    SELECT 
        nc.id,
        dept_id::uuid,
        true,
        NOW(),
        NOW()
    FROM new_cohort nc
    CROSS JOIN params x
    CROSS JOIN UNNEST(x.department_ids) as dept_id
    WHERE COALESCE(array_length(x.department_ids, 1), 0) > 0
    ON CONFLICT (cohort_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
link_profiles AS (
    -- Link profiles if provided (array may be empty)
    INSERT INTO cohort_profiles (cohort_id, profile_id, active)
    SELECT 
        nc.id,
        pid::uuid,
        true
    FROM new_cohort nc
    CROSS JOIN params x
    CROSS JOIN UNNEST(x.profile_ids) as pid
    WHERE COALESCE(array_length(x.profile_ids, 1), 0) > 0
    ON CONFLICT (cohort_id, profile_id) DO UPDATE SET
        active = true
),
simulations_with_order AS (
    -- Prepare simulations with position based on array order
    SELECT 
        simulation_id::uuid,
        ROW_NUMBER() OVER () as position
    FROM params x
    CROSS JOIN UNNEST(x.simulation_ids) as simulation_id
    WHERE COALESCE(array_length(x.simulation_ids, 1), 0) > 0
),
link_simulations AS (
    -- Link simulations with position if provided (array may be empty)
    INSERT INTO cohort_simulations (cohort_id, simulation_id, active, position)
    SELECT 
        nc.id,
        swo.simulation_id,
        true,
        swo.position
    FROM new_cohort nc
    CROSS JOIN simulations_with_order swo
)
-- Return cohort ID and actor name
SELECT 
    nc.id as cohort_id,
    ap.actor_name
FROM new_cohort nc
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_create_department_v4(text, text, boolean, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_department_v4(title text, description text, active boolean, settings_id uuid, profile_id uuid) RETURNS TABLE(department_id uuid, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        title AS title,
        description AS description,
        active AS active,
        settings_id AS settings_id,
        profile_id AS profile_id
),
actor_profile AS (
    SELECT 
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
new_department AS (
    -- Create department
    INSERT INTO departments (
        title,
        description,
        active,
        created_at,
        updated_at
    )
    SELECT title, description, active, NOW(), NOW()
    FROM params
    RETURNING id
),
link_settings AS (
    -- Link settings if provided
    INSERT INTO department_settings (settings_id, department_id, active, created_at, updated_at)
    SELECT 
        settings_id,
        nd.id,
        true,
        NOW(),
        NOW()
    FROM new_department nd
    CROSS JOIN params p
    WHERE p.settings_id IS NOT NULL
    ON CONFLICT (settings_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
)
-- Return department ID and actor name
SELECT 
    nd.id as department_id,
    ap.actor_name::text as actor_name
FROM new_department nd
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_create_document_v4(text, uuid, text, uuid, uuid[], uuid[], uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_document_v4(name text, profile_id uuid, description text DEFAULT ''::text, upload_id uuid DEFAULT NULL::uuid, department_ids uuid[] DEFAULT ARRAY[]::uuid[], parameter_item_ids uuid[] DEFAULT ARRAY[]::uuid[], html_id uuid DEFAULT NULL::uuid, schema_id uuid DEFAULT NULL::uuid) RETURNS TABLE(success boolean, message text, document_id uuid, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        name AS name,
        COALESCE(NULLIF(description, ''), '') AS description,
        upload_id AS upload_id,
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids,
        COALESCE(parameter_item_ids, ARRAY[]::uuid[]) AS field_ids,
        html_id AS html_id,
        schema_id AS schema_id,
        profile_id AS profile_id
),
user_profile AS (
    SELECT 
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
new_document_id AS (
    SELECT gen_random_uuid() as document_id
),
insert_doc AS (
    INSERT INTO documents (
        id, 
        name,
        description,
        active,
        template,
        created_at, 
        updated_at,
        classify_agent_id,
        document_agent_id
    )
    SELECT 
        ndi.document_id,
        p.name,
        p.description,
        true,
        false,  -- template defaults to false - must be explicitly enabled via update
        NOW(), 
        NOW(),
        (SELECT id FROM agents WHERE role = 'classify' AND active = true LIMIT 1),
        (SELECT id FROM agents WHERE role = 'document' AND active = true LIMIT 1)
    FROM params p
    CROSS JOIN new_document_id ndi
    RETURNING id
),
insert_upload AS (
    -- Link regular upload if provided
    INSERT INTO document_uploads (document_id, upload_id, active, created_at, updated_at)
    SELECT ndi.document_id, p.upload_id, true, NOW(), NOW()
    FROM params p
    CROSS JOIN new_document_id ndi
    WHERE p.upload_id IS NOT NULL
    ON CONFLICT (document_id, upload_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
create_template AS (
    -- Create template (just values, no schema/HTML refs) if html_id and schema_id are provided
    INSERT INTO templates (name, created_at, updated_at)
    SELECT 
        p.name as name,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN new_document_id ndi
    WHERE p.html_id IS NOT NULL AND p.schema_id IS NOT NULL
      AND NOT EXISTS (
          SELECT 1 FROM document_templates dt
          WHERE dt.html_id = p.html_id 
            AND dt.schema_id = p.schema_id
      )
    RETURNING id as template_id
),
get_existing_template AS (
    -- Get existing template if it exists (matching html_id and schema_id via document_templates)
    SELECT dt.template_id
    FROM params p
    JOIN document_templates dt ON dt.html_id = p.html_id AND dt.schema_id = p.schema_id
    WHERE p.html_id IS NOT NULL AND p.schema_id IS NOT NULL
    LIMIT 1
),
template_id AS (
    SELECT template_id FROM create_template
    UNION ALL
    SELECT template_id FROM get_existing_template
    WHERE EXISTS (SELECT 1 FROM params WHERE html_id IS NOT NULL AND schema_id IS NOT NULL)
    LIMIT 1
),
link_template_schema AS (
    -- Link template to schema via schema_templates junction table
    INSERT INTO schema_templates (schema_id, template_id, created_at, updated_at)
    SELECT 
        p.schema_id,
        ti.template_id,
        NOW(),
        NOW()
    FROM template_id ti
    CROSS JOIN params p
    WHERE p.schema_id IS NOT NULL
    ON CONFLICT (schema_id, template_id) DO UPDATE SET
        updated_at = NOW()
),
insert_template_link AS (
    -- Link template to document with html_id and schema_id
    INSERT INTO document_templates (document_id, template_id, html_id, schema_id, active, created_at, updated_at)
    SELECT 
        ndi.document_id,
        ti.template_id,
        p.html_id,
        p.schema_id,
        true,
        NOW(),
        NOW()
    FROM template_id ti
    CROSS JOIN new_document_id ndi
    CROSS JOIN params p
    WHERE p.html_id IS NOT NULL AND p.schema_id IS NOT NULL
    ON CONFLICT (document_id, template_id) DO UPDATE SET
        html_id = EXCLUDED.html_id,
        schema_id = EXCLUDED.schema_id,
        active = true,
        updated_at = NOW()
),
insert_depts AS (
    INSERT INTO document_departments (document_id, department_id, active, created_at, updated_at)
    SELECT ndi.document_id, dept_id, true, NOW(), NOW()
    FROM params p
    CROSS JOIN new_document_id ndi
    CROSS JOIN unnest(p.department_ids) as dept_id
    WHERE cardinality(p.department_ids) > 0
    RETURNING document_id
),
insert_fields AS (
    INSERT INTO document_fields (document_id, field_id, active, created_at, updated_at)
    SELECT ndi.document_id, field_id, true, NOW(), NOW()
    FROM params p
    CROSS JOIN new_document_id ndi
    CROSS JOIN unnest(p.field_ids) as field_id
    WHERE cardinality(p.field_ids) > 0
    RETURNING document_id
)
SELECT 
    true::boolean as success,
    'Document created successfully'::text as message,
    ndi.document_id,
    up.actor_name
FROM new_document_id ndi
CROSS JOIN user_profile up
LIMIT 1
$$;


--
-- Name: api_create_eval_grade_v4(uuid, uuid, text, boolean, numeric, numeric, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_eval_grade_v4(run_id uuid, eval_id uuid, description text, passed boolean, score numeric, time_taken numeric, rubric_grade_agent_id uuid) RETURNS TABLE(grade_id text)
    LANGUAGE sql
    AS $$
INSERT INTO grades 
(run_id, rubric_grade_agent_id, description, passed, score, time_taken, created_at)
SELECT 
    run_id,
    rubric_grade_agent_id,
    description,
    passed,
    score,
    time_taken,
    NOW()
WHERE (eval_id IS NOT NULL OR eval_id IS NULL)  -- Use eval_id to help PostgreSQL infer type
RETURNING id::text as grade_id
$$;


--
-- Name: api_create_eval_v4(text, text, uuid[], boolean, uuid[], uuid[], boolean, boolean, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_eval_v4(name text, description text, agent_ids uuid[], use_groups boolean, model_run_ids uuid[], department_ids uuid[], active boolean, dynamic boolean, profile_id uuid) RETURNS TABLE(eval_id uuid, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        name AS name,
        description AS description,
        COALESCE(agent_ids, ARRAY[]::uuid[]) AS agent_ids,
        COALESCE(use_groups, false) AS use_groups,
        model_run_ids AS model_run_ids,
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids,
        COALESCE(active, true) AS active,
        COALESCE(dynamic, false) AS dynamic,
        profile_id AS profile_id
),
user_profile AS (
    SELECT 
        role,
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
validate_create_permissions AS (
    SELECT validate_department_create_permissions(
        up.role::text,
        ARRAY(SELECT dept_id::text FROM UNNEST((SELECT department_ids FROM params)) as dept_id)
    ) as validation_passed
    FROM user_profile up
),
new_eval AS (
    INSERT INTO evals (name, description, use_groups, active, dynamic, created_at, updated_at)
    SELECT name, description, use_groups, active, dynamic, NOW(), NOW()
    FROM params
    RETURNING id as eval_id
),
link_agents AS (
    INSERT INTO eval_agents (eval_id, agent_id, created_at, updated_at)
    SELECT 
        ne.eval_id,
        a_id,
        NOW(),
        NOW()
    FROM new_eval ne
    CROSS JOIN params p
    CROSS JOIN UNNEST(p.agent_ids) as a_id
    WHERE COALESCE(array_length(p.agent_ids, 1), 0) > 0
    ON CONFLICT (eval_id, agent_id) DO UPDATE SET
        updated_at = NOW()
),
link_departments AS (
    INSERT INTO eval_departments (eval_id, department_id, active, created_at, updated_at)
    SELECT 
        ne.eval_id,
        d_id,
        true,
        NOW(),
        NOW()
    FROM new_eval ne
    CROSS JOIN params p
    CROSS JOIN UNNEST(p.department_ids) as d_id
    WHERE COALESCE(array_length(p.department_ids, 1), 0) > 0
    ON CONFLICT (eval_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
link_runs AS (
    INSERT INTO eval_runs (eval_id, run_id, completed, created_at, updated_at)
    SELECT 
        ne.eval_id,
        r_id,
        false,
        NOW(),
        NOW()
    FROM new_eval ne
    CROSS JOIN params p
    CROSS JOIN UNNEST(p.model_run_ids) as r_id
    WHERE COALESCE(array_length(p.model_run_ids, 1), 0) > 0
    ON CONFLICT (eval_id, run_id) DO UPDATE SET
        completed = false,
        updated_at = NOW()
)
SELECT 
    ne.eval_id,
    up.actor_name::text as actor_name
FROM new_eval ne
CROSS JOIN user_profile up
$$;


--
-- Name: api_create_feedback_v4(public.feedback_type, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_feedback_v4(type public.feedback_type, message text, profile_id uuid) RETURNS TABLE(feedback_id uuid, actor_name text)
    LANGUAGE sql
    AS $$
WITH actor_profile AS (
    SELECT 
        profile_id as resolved_profile_id,
        p.first_name || ' ' || p.last_name as actor_name
    FROM profiles p
    WHERE p.id = profile_id
),
new_feedback AS (
    INSERT INTO feedback (type, message, profile_id, created_at)
    VALUES (type, message, profile_id, NOW())
    RETURNING id as feedback_id
)
SELECT 
    nf.feedback_id,
    ap.actor_name
FROM new_feedback nf
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_create_field_v4(text, text, boolean, text[], text[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_field_v4(name text, description text, active boolean, department_ids text[], conditional_parameter_ids text[], profile_id uuid) RETURNS TABLE(field_id uuid, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT
        name AS name,
        COALESCE(NULLIF(description, ''), '') AS description,
        COALESCE(active, true) AS active,
        COALESCE(department_ids, ARRAY[]::text[]) AS department_ids,
        COALESCE(conditional_parameter_ids, ARRAY[]::text[]) AS conditional_parameter_ids,
        profile_id AS profile_id
),
user_profile AS (
    SELECT 
        p.role,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
validate_create_permissions AS (
    -- Validate department permissions for create operation
    SELECT validate_department_create_permissions(
        up.role::text,
        x.department_ids
    ) as validation_passed
    FROM user_profile up
    CROSS JOIN params x
),
actor_profile AS (
    SELECT 
        x.profile_id AS resolved_profile_id,
        up.actor_name
    FROM params x
    CROSS JOIN user_profile up
),
new_field AS (
    INSERT INTO fields (
        name,
        description,
        active
    )
    SELECT x.name, x.description, x.active
    FROM params x
    RETURNING id as field_id
),
link_conditional_parameters AS (
    -- Link field to conditional parameters if provided
    INSERT INTO field_conditional_parameters (field_id, conditional_parameter_id, active, created_at, updated_at)
    SELECT 
        nf.field_id,
        cond_param_id::uuid,
        true,
        NOW(),
        NOW()
    FROM new_field nf
    CROSS JOIN params x
    CROSS JOIN UNNEST(x.conditional_parameter_ids) as cond_param_id
    WHERE COALESCE(array_length(x.conditional_parameter_ids, 1), 0) > 0
    ON CONFLICT (field_id, conditional_parameter_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
link_departments AS (
    -- Link field to departments if provided
    INSERT INTO field_departments (field_id, department_id, active, created_at, updated_at)
    SELECT 
        nf.field_id,
        dept_id::uuid,
        true,
        NOW(),
        NOW()
    FROM new_field nf
    CROSS JOIN params x
    CROSS JOIN UNNEST(x.department_ids) as dept_id
    WHERE COALESCE(array_length(x.department_ids, 1), 0) > 0
    ON CONFLICT (field_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
)
SELECT 
    nf.field_id,
    ap.actor_name
FROM new_field nf
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_create_generation_and_link_v4(uuid, text, text, uuid, boolean, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_generation_and_link_v4(video_id uuid, file_path text, mime_type text, upload_id uuid, active boolean, run_id uuid) RETURNS TABLE(generation_id uuid)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT
        api_create_generation_and_link_v4.video_id as video_id,
        api_create_generation_and_link_v4.file_path as file_path,
        api_create_generation_and_link_v4.mime_type as mime_type,
        api_create_generation_and_link_v4.upload_id as upload_id,
        api_create_generation_and_link_v4.active as active,
        api_create_generation_and_link_v4.run_id as run_id
),
insert_upload AS (
    INSERT INTO uploads (file_path, mime_type, size, created_at, updated_at)
    SELECT file_path, mime_type, 0, NOW(), NOW()
    FROM params
    WHERE upload_id IS NULL
    RETURNING id as new_upload_id
),
final_upload_id AS (
    SELECT COALESCE((SELECT upload_id FROM params), (SELECT new_upload_id FROM insert_upload LIMIT 1)) as upload_id
),
link_upload AS (
    INSERT INTO video_uploads (video_id, upload_id, active, created_at, updated_at)
    SELECT p.video_id, fi.upload_id, p.active, NOW(), NOW()
    FROM params p
    CROSS JOIN final_upload_id fi
    ON CONFLICT (video_id, upload_id)
    DO UPDATE SET active = EXCLUDED.active, updated_at = NOW()
),
mark_video AS (
    UPDATE videos
    SET completed = TRUE,
        updated_at = NOW()
    WHERE id = (SELECT video_id FROM params)
)
SELECT fi.upload_id as generation_id
FROM final_upload_id fi
$$;


--
-- Name: api_create_key_v4(text, text, text, boolean, uuid, uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_key_v4(name text, key text, description text, active boolean, profile_id uuid, department_ids uuid[] DEFAULT ARRAY[]::uuid[]) RETURNS TABLE(key_id uuid, key_masked text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        name AS name,
        key AS key,
        COALESCE(NULLIF(description, ''), '') AS description,
        active AS active,
        profile_id AS profile_id,
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids
),
user_profile AS (
    SELECT 
        p.role,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
validate_create_permissions AS (
    -- Validate department permissions for create operation
    SELECT validate_department_create_permissions(
        up.role::text,
        ARRAY_AGG(did::text)::text[]
    ) as validation_passed
    FROM user_profile up
    CROSS JOIN params x
    CROSS JOIN unnest(x.department_ids) as did
    GROUP BY up.role
),
actor_profile AS (
    SELECT 
        x.profile_id as resolved_profile_id,
        up.actor_name
    FROM params x
    CROSS JOIN user_profile up
),
new_key AS (
    INSERT INTO keys (
        name,
        key,
        description,
        active
    )
    SELECT name, key, description, active FROM params
    RETURNING id as key_id, key
),
link_departments AS (
    -- NOTE: department_keys table was removed in migration 74
    -- Keys are now linked to departments through settings (setting_provider_keys, setting_auth_keys)
    -- This CTE is kept for compatibility but does nothing
    -- TODO: Reimplement department linking through settings if needed
    SELECT 1 WHERE false
)
SELECT 
    nk.key_id::uuid as key_id,
    CASE 
        WHEN LENGTH(nk.key) > 4 THEN LEFT(nk.key, 4) || '****'
        ELSE '****'
    END::text as key_masked,
    ap.actor_name::text as actor_name
FROM new_key nk
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_create_model_v4(uuid, text, text, boolean, text, uuid, uuid[], text, types.i_create_model_v4_temperature_bounds, types.i_create_model_v4_pricing[], text[], text[], text[], text[], text[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_model_v4(provider_id uuid, name text, description text, active boolean, value text, profile_id uuid, department_ids uuid[] DEFAULT ARRAY[]::uuid[], base_url text DEFAULT NULL::text, temperature_bounds types.i_create_model_v4_temperature_bounds DEFAULT NULL::types.i_create_model_v4_temperature_bounds, pricing types.i_create_model_v4_pricing[] DEFAULT ARRAY[]::types.i_create_model_v4_pricing[], input_modalities text[] DEFAULT ARRAY[]::text[], output_modalities text[] DEFAULT ARRAY[]::text[], reasoning_levels text[] DEFAULT ARRAY[]::text[], voices text[] DEFAULT NULL::text[], qualities text[] DEFAULT ARRAY[]::text[]) RETURNS TABLE(model_id uuid, actor_name text)
    LANGUAGE plpgsql
    AS $$
DECLARE
    new_model_id uuid;
    default_voices text[] := ARRAY['alloy', 'ash', 'ballad', 'coral', 'echo', 'fable', 'onyx', 'nova', 'sage', 'shimmer', 'verse'];
    final_input_mods text[];
    final_output_mods text[];
    final_voices text[];
    temp_val float;
BEGIN
    -- Default modalities to text/text if not provided
    IF array_length(input_modalities, 1) IS NULL AND array_length(output_modalities, 1) IS NULL THEN
        final_input_mods := ARRAY['text'];
        final_output_mods := ARRAY['text'];
    ELSE
        final_input_mods := COALESCE(input_modalities, ARRAY[]::text[]);
        final_output_mods := COALESCE(output_modalities, ARRAY[]::text[]);
    END IF;

    -- Default voices to all voices if not provided
    IF voices IS NULL OR array_length(voices, 1) IS NULL THEN
        final_voices := default_voices;
    ELSE
        final_voices := voices;
    END IF;

    -- Validate permissions
    IF NOT validate_department_create_permissions(
        (SELECT role::text FROM profiles WHERE id = profile_id),
        ARRAY(SELECT unnest(department_ids)::text)
    ) THEN
        RAISE EXCEPTION 'Insufficient permissions to create model';
    END IF;

    -- Create model
    INSERT INTO models (provider_id, name, description, active, value)
    VALUES (provider_id, name, description, active, value)
    RETURNING id INTO new_model_id;

    -- Link departments if provided
    IF array_length(department_ids, 1) > 0 THEN
        INSERT INTO model_departments (model_id, department_id, active, created_at, updated_at)
        SELECT new_model_id, dept_id, true, NOW(), NOW()
        FROM UNNEST(department_ids) as dept_id
        ON CONFLICT (model_id, department_id) DO UPDATE SET
            active = true,
            updated_at = NOW();
    END IF;

    -- Create endpoint if base_url is provided
    IF base_url IS NOT NULL AND TRIM(base_url) != '' THEN
        INSERT INTO model_endpoints (model_id, base_url, active, created_at, updated_at)
        VALUES (new_model_id, base_url, true, NOW(), NOW())
        ON CONFLICT (model_id) DO UPDATE SET
            base_url = EXCLUDED.base_url,
            active = true,
            updated_at = NOW();
    END IF;

    -- Handle temperature bounds
    IF temperature_bounds IS NOT NULL THEN
        IF temperature_bounds.bounds_type = 'range' THEN
            INSERT INTO model_temperature_levels (model_id, temperature, is_upper, active)
            VALUES 
                (new_model_id, temperature_bounds.lower_bound, false, true),
                (new_model_id, temperature_bounds.upper_bound, true, true);
        ELSIF temperature_bounds.bounds_type = 'values' AND array_length(temperature_bounds.values_array, 1) > 0 THEN
            INSERT INTO model_temperature_levels (model_id, temperature, is_upper, active)
            SELECT new_model_id, temp_val, false, true
            FROM UNNEST(temperature_bounds.values_array) as temp_val;
        END IF;
    END IF;

    -- Handle pricing
    IF array_length(pricing, 1) > 0 THEN
        INSERT INTO model_pricing (model_id, pricing_type, unit_id, price, active)
        SELECT new_model_id, p.pricing_type::pricing_type, p.unit_id, p.price, true
        FROM UNNEST(pricing) as p;
    END IF;

    -- Handle modalities
    IF array_length(final_input_mods, 1) > 0 THEN
        INSERT INTO model_modalities (model_id, modality, is_input, active)
        SELECT new_model_id, mod::modality_type, true, true
        FROM UNNEST(final_input_mods) as mod;
    END IF;

    IF array_length(final_output_mods, 1) > 0 THEN
        INSERT INTO model_modalities (model_id, modality, is_input, active)
        SELECT new_model_id, mod::modality_type, false, true
        FROM UNNEST(final_output_mods) as mod;
    END IF;

    -- Handle reasoning levels
    IF array_length(reasoning_levels, 1) > 0 THEN
        INSERT INTO model_reasoning_levels (model_id, reasoning_level, active)
        SELECT new_model_id, level::reasoning_effort, true
        FROM UNNEST(reasoning_levels) as level;
    END IF;

    -- Handle voices
    IF array_length(final_voices, 1) > 0 THEN
        INSERT INTO model_voices (model_id, voice, active)
        SELECT new_model_id, voice::voice, true
        FROM UNNEST(final_voices) as voice;
    END IF;

    -- Handle qualities
    IF array_length(qualities, 1) > 0 THEN
        INSERT INTO model_qualities (model_id, quality, active)
        SELECT new_model_id, quality::quality, true
        FROM UNNEST(qualities) as quality;
    END IF;

    -- Return result
    RETURN QUERY
    SELECT 
        new_model_id as model_id,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM profiles p
    WHERE p.id = profile_id;
END;
$$;


--
-- Name: api_create_or_update_profile_v4(uuid, text, text, text[], text, uuid, integer, boolean, uuid[], uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_or_update_profile_v4(profile_id_new uuid, first_name text, last_name text, emails text[], role text, current_profile_id uuid DEFAULT NULL::uuid, primary_email_index integer DEFAULT 0, active boolean DEFAULT true, department_ids uuid[] DEFAULT ARRAY[]::uuid[], cohort_ids uuid[] DEFAULT ARRAY[]::uuid[]) RETURNS TABLE(profile_id uuid, created boolean, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        profile_id_new AS profile_id_new,
        first_name AS first_name,
        last_name AS last_name,
        COALESCE(emails, ARRAY[]::text[]) AS emails,
        COALESCE(primary_email_index, 0) AS primary_email_index,
        role AS role,
        COALESCE(active, true) AS active,
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids,
        COALESCE(cohort_ids, ARRAY[]::uuid[]) AS cohort_ids,
        current_profile_id AS current_profile_id
),
user_profile AS (
    SELECT 
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    LEFT JOIN profiles p ON p.id = x.current_profile_id
    WHERE x.current_profile_id IS NOT NULL
),
current_user_role AS (
    -- Get current user's role for validation (if provided)
    SELECT p.role FROM params x JOIN profiles p ON p.id = x.current_profile_id WHERE x.current_profile_id IS NOT NULL
),
role_validation AS (
    -- Validate role hierarchy: check if current user can assign target role (if current_profile_id provided)
    SELECT 
        CASE 
            WHEN (SELECT current_profile_id FROM params) IS NULL THEN true  -- No validation if no current_profile_id
            WHEN cur.role = 'superadmin'::profile_role AND p_role.role::profile_role IN ('superadmin'::profile_role, 'admin'::profile_role, 'instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role) THEN true
            WHEN cur.role = 'admin'::profile_role AND p_role.role::profile_role IN ('instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role) THEN true
            WHEN cur.role = 'instructional'::profile_role AND p_role.role::profile_role IN ('member'::profile_role, 'guest'::profile_role) THEN true
            WHEN cur.role = 'member'::profile_role AND p_role.role::profile_role = 'guest'::profile_role THEN true
            ELSE false
        END as can_assign
    FROM current_user_role cur
    CROSS JOIN (SELECT role FROM params) p_role
    WHERE EXISTS (SELECT 1 FROM current_user_role)
    UNION ALL
    SELECT true  -- Allow if no current_profile_id provided
    WHERE NOT EXISTS (SELECT 1 FROM current_user_role)
    LIMIT 1
),
primary_email AS (
    SELECT 
        emails[primary_email_index + 1] as email  -- PostgreSQL arrays are 1-indexed
    FROM params
    WHERE array_length(emails, 1) > primary_email_index
),
existing_profile AS (
    -- Find existing profile by primary email in profile_emails table
    SELECT pe.profile_id as id FROM profile_emails pe WHERE pe.email = (SELECT email FROM primary_email) AND pe.active = true LIMIT 1
),
profile_upsert AS (
    -- Insert or update profile (only if role validation passes)
    INSERT INTO profiles (
        id, first_name, last_name, role, active, updated_at
    )
    SELECT
        COALESCE((SELECT id FROM existing_profile LIMIT 1), (SELECT profile_id_new FROM params)),  -- Use existing ID if found, else new UUID
        (SELECT first_name FROM params),
        (SELECT last_name FROM params),
        (SELECT role FROM params)::profile_role,
        (SELECT active FROM params),
        NOW()
    WHERE EXISTS (SELECT 1 FROM role_validation WHERE can_assign = true)
    ON CONFLICT (id) DO UPDATE SET
        first_name = EXCLUDED.first_name,
        last_name = EXCLUDED.last_name,
        role = CASE 
            WHEN EXISTS (SELECT 1 FROM role_validation WHERE can_assign = true) 
            THEN EXCLUDED.role::profile_role
            ELSE profiles.role::profile_role
        END,
        active = EXCLUDED.active,
        updated_at = NOW()
    RETURNING id, NOT EXISTS(SELECT 1 FROM existing_profile) as created
),
email_deactivate_all AS (
    -- Deactivate all existing emails for this profile
    UPDATE profile_emails SET
        active = false,
        updated_at = NOW()
    WHERE profile_id = (SELECT id FROM profile_upsert LIMIT 1)
      AND EXISTS (SELECT 1 FROM profile_upsert)
),
all_emails_data AS (
    -- Prepare all emails with primary flag based on index
    SELECT 
        email,
        CASE WHEN ord = (SELECT primary_email_index + 1 FROM params) THEN true ELSE false END as is_primary
    FROM unnest((SELECT emails FROM params)) WITH ORDINALITY AS e(email, ord)
),
email_upsert AS (
    -- Insert or update all emails
    INSERT INTO profile_emails (profile_id, email, is_primary, active)
    SELECT 
        pu.id,
        aed.email,
        aed.is_primary,
        true
    FROM profile_upsert pu
    CROSS JOIN all_emails_data aed
    WHERE EXISTS (SELECT 1 FROM role_validation WHERE can_assign = true)
    ON CONFLICT (email) DO UPDATE SET
        profile_id = EXCLUDED.profile_id,
        is_primary = EXCLUDED.is_primary,
        active = true,
        updated_at = NOW()
),
dept_cleanup AS (
    -- Delete existing department relationships
    DELETE FROM profile_departments
    WHERE profile_id = (SELECT id FROM profile_upsert LIMIT 1)
      AND EXISTS (SELECT 1 FROM profile_upsert)
),
dept_insert AS (
    -- Insert department relationships (first one as primary)
    INSERT INTO profile_departments (profile_id, department_id, is_primary, active, created_at, updated_at)
    SELECT 
        pu.id,
        dept_id,
        (ROW_NUMBER() OVER (ORDER BY dept_id) = 1) as is_primary,
        true,
        NOW(),
        NOW()
    FROM profile_upsert pu
    CROSS JOIN unnest((SELECT department_ids FROM params)) as dept_id
    WHERE cardinality((SELECT department_ids FROM params)) > 0
      AND EXISTS (SELECT 1 FROM profile_upsert)
    ON CONFLICT (profile_id, department_id) DO UPDATE SET
        is_primary = EXCLUDED.is_primary,
        active = true,
        updated_at = NOW()
),
cohort_cleanup AS (
    -- Delete existing cohort relationships
    DELETE FROM cohort_profiles
    WHERE profile_id = (SELECT id FROM profile_upsert LIMIT 1)
      AND EXISTS (SELECT 1 FROM profile_upsert)
),
cohort_insert AS (
    -- Insert cohort relationships
    INSERT INTO cohort_profiles (cohort_id, profile_id, active)
    SELECT 
        cohort_id,
        pu.id,
        true
    FROM profile_upsert pu
    CROSS JOIN unnest((SELECT cohort_ids FROM params)) as cohort_id
    WHERE cardinality((SELECT cohort_ids FROM params)) > 0
      AND EXISTS (SELECT 1 FROM profile_upsert)
    ON CONFLICT (cohort_id, profile_id) DO UPDATE SET
        active = true
)
SELECT 
    pu.id as profile_id,
    pu.created,
    COALESCE(up.actor_name, 'System')::text as actor_name
FROM profile_upsert pu
CROSS JOIN user_profile up
LIMIT 1
$$;


--
-- Name: api_create_parameter_v4(text, text, boolean, boolean, boolean, boolean, boolean, boolean, text[], types.i_create_parameter_v4_field_connection[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_parameter_v4(name text, description text, active boolean, simulation_parameter boolean, document_parameter boolean, persona_parameter boolean, scenario_parameter boolean, video_parameter boolean, department_ids text[], field_connections types.i_create_parameter_v4_field_connection[], profile_id uuid) RETURNS TABLE(parameter_id uuid, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        name AS name,
        description AS description,
        active AS active,
        simulation_parameter AS simulation_parameter,
        document_parameter AS document_parameter,
        persona_parameter AS persona_parameter,
        scenario_parameter AS scenario_parameter,
        video_parameter AS video_parameter,
        COALESCE(department_ids, ARRAY[]::text[]) AS department_ids,
        COALESCE(field_connections, ARRAY[]::types.i_create_parameter_v4_field_connection[]) AS field_connections,
        profile_id AS profile_id
),
user_profile AS (
    SELECT 
        p.role,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
validate_create_permissions AS (
    -- Validate department permissions for create operation (parameter-level departments)
    SELECT validate_department_create_permissions(
        up.role::text,
        (SELECT department_ids FROM params)
    ) as validation_passed
    FROM user_profile up
),
actor_profile AS (
    SELECT 
        (SELECT profile_id FROM params) as resolved_profile_id,
        up.actor_name
    FROM user_profile up
),
new_parameter AS (
    INSERT INTO parameters (
        name,
        description,
        active,
        simulation_parameter,
        document_parameter,
        persona_parameter,
        scenario_parameter,
        video_parameter
    )
    SELECT name, description, active, simulation_parameter, document_parameter, persona_parameter, scenario_parameter, video_parameter
    FROM params
    RETURNING id as parameter_id
),
field_connections_expanded AS (
    -- Expand composite type array field_connections
    SELECT 
        (x.field_connections[i]).field_id,
        COALESCE((x.field_connections[i])."default", false) as conn_default,
        COALESCE((x.field_connections[i]).active, true) as conn_active,
        i as conn_order
    FROM params x
    CROSS JOIN generate_subscripts(x.field_connections, 1) AS i
    WHERE array_length(x.field_connections, 1) > 0
    AND (x.field_connections[i]).field_id IS NOT NULL
),
ensure_one_default AS (
    -- Ensure exactly one default: if none specified, set first one; if multiple, keep first
    SELECT 
        conn_order,
        CASE 
            WHEN conn_order = (
                SELECT MIN(conn_order) 
                FROM field_connections_expanded 
                WHERE conn_default = true
                LIMIT 1
            ) THEN true
            WHEN (SELECT COUNT(*) FROM field_connections_expanded WHERE conn_default = true) = 0 
                 AND conn_order = (SELECT MIN(conn_order) FROM field_connections_expanded)
            THEN true
            ELSE false
        END as conn_default_fixed
    FROM field_connections_expanded
),
field_connections_fixed AS (
    SELECT 
        fce.field_id,
        COALESCE(eod.conn_default_fixed, false) as conn_default,
        fce.conn_active
    FROM field_connections_expanded fce
    LEFT JOIN ensure_one_default eod ON eod.conn_order = fce.conn_order
),
link_fields_to_parameter AS (
    -- Link existing fields to parameter via parameter_fields junction with default and active flags
    INSERT INTO parameter_fields (parameter_id, field_id, "default", active, created_at, updated_at)
    SELECT 
        np.parameter_id,
        fcf.field_id,
        fcf.conn_default,
        fcf.conn_active,
        NOW(),
        NOW()
    FROM new_parameter np
    CROSS JOIN field_connections_fixed fcf
    WHERE EXISTS (SELECT 1 FROM fields f WHERE f.id = fcf.field_id AND f.active = true)
    ON CONFLICT (parameter_id, field_id) DO UPDATE SET
        active = EXCLUDED.active,
        "default" = EXCLUDED."default",
        updated_at = NOW()
),
link_parameter_departments AS (
    -- Link departments to parameter if provided at parameter level
    INSERT INTO parameter_departments (parameter_id, department_id, active, created_at, updated_at)
    SELECT 
        np.parameter_id,
        dept_id::uuid,
        true,
        NOW(),
        NOW()
    FROM new_parameter np
    CROSS JOIN params x
    CROSS JOIN UNNEST(x.department_ids) as dept_id
    WHERE array_length(x.department_ids, 1) > 0
    ON CONFLICT (parameter_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
)
SELECT 
    np.parameter_id,
    ap.actor_name::text as actor_name
FROM new_parameter np
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_create_persona_v4(text, text, boolean, text, text, text, text[], uuid, text[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_persona_v4(name text, description text, active boolean, color text, icon text, instructions text, department_ids text[], profile_id uuid, example_ids text[]) RETURNS TABLE(persona_id uuid, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT
        name AS name,
        COALESCE(NULLIF(description, ''), '') AS description,
        active AS active,
        color AS color,
        icon AS icon,
        COALESCE(NULLIF(instructions, ''), '') AS instructions,
        COALESCE(department_ids, ARRAY[]::text[]) AS department_ids,
        profile_id AS profile_id,
        COALESCE(example_ids, ARRAY[]::text[]) AS example_ids
),
user_profile AS (
    SELECT 
        p.role,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
validate_create_permissions AS (
    -- Validate department permissions for create operation
    SELECT validate_department_create_permissions(
        up.role::text,
        x.department_ids
    ) as validation_passed
    FROM params x
    CROSS JOIN user_profile up
),
actor_profile AS (
    SELECT 
        x.profile_id,
        up.actor_name
    FROM params x
    CROSS JOIN user_profile up
),
new_persona AS (
    INSERT INTO personas (name, description, active, color, icon, instructions, created_at, updated_at)
    SELECT x.name, x.description, x.active, x.color, x.icon, x.instructions, NOW(), NOW()
    FROM params x
    RETURNING id
),
link_departments AS (
    -- Link departments if provided (array is never NULL, but may be empty)
    INSERT INTO persona_departments (persona_id, department_id, active, created_at, updated_at)
    SELECT 
        np.id,
        dept_id::uuid,
        true,
        NOW(),
        NOW()
    FROM new_persona np
    CROSS JOIN params x
    CROSS JOIN UNNEST(x.department_ids) as dept_id
    WHERE COALESCE(array_length(x.department_ids, 1), 0) > 0
    ON CONFLICT (persona_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
examples_with_index AS (
    -- Prepare examples with their index (skip composite IDs - filtered in Python)
    SELECT 
        ex_text,
        ROW_NUMBER() OVER () - 1 as idx
    FROM params x
    CROSS JOIN UNNEST(x.example_ids) as ex_text
    WHERE COALESCE(array_length(x.example_ids, 1), 0) > 0
),
existing_examples AS (
    -- Find existing examples by text
    SELECT id as example_id, example
    FROM examples
    WHERE example = ANY(SELECT ex_text FROM examples_with_index)
),
new_examples AS (
    -- Create new examples that don't exist yet
    INSERT INTO examples (example, created_at, updated_at)
    SELECT DISTINCT
        ewi.ex_text,
        NOW(),
        NOW()
    FROM examples_with_index ewi
    WHERE NOT EXISTS (
        SELECT 1 FROM existing_examples ee WHERE ee.example = ewi.ex_text
    )
    RETURNING id as example_id, example
),
all_examples AS (
    -- Combine existing and new examples
    SELECT example_id, example FROM existing_examples
    UNION ALL
    SELECT example_id, example FROM new_examples
),
link_examples AS (
    -- Link examples to persona via junction table
    INSERT INTO persona_examples (persona_id, example_id, idx, created_at)
    SELECT 
        np.id,
        ae.example_id,
        ewi.idx,
        NOW()
    FROM new_persona np
    CROSS JOIN examples_with_index ewi
    JOIN all_examples ae ON ae.example = ewi.ex_text
)
SELECT 
    np.id as persona_id,
    ap.actor_name
FROM new_persona np
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_create_profile_v4(uuid, text, text, text[], text, uuid, integer, boolean, uuid[], uuid[], integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_profile_v4(profile_id uuid, first_name text, last_name text, emails text[], role text, current_profile_id uuid DEFAULT NULL::uuid, primary_email_index integer DEFAULT 0, active boolean DEFAULT true, cohort_ids uuid[] DEFAULT ARRAY[]::uuid[], department_ids uuid[] DEFAULT ARRAY[]::uuid[], primary_department_index integer DEFAULT NULL::integer) RETURNS TABLE(profile_id uuid, first_name text, last_name text, email_exists boolean, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        profile_id AS profile_id,
        first_name AS first_name,
        last_name AS last_name,
        COALESCE(emails, ARRAY[]::text[]) AS emails,
        COALESCE(primary_email_index, 0) AS primary_email_index,
        role AS role,
        COALESCE(active, true) AS active,
        COALESCE(cohort_ids, ARRAY[]::uuid[]) AS cohort_ids,
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids,
        primary_department_index AS primary_department_index,
        current_profile_id AS current_profile_id
),
actor_profile AS (
    SELECT 
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.current_profile_id
),
primary_email AS (
    SELECT 
        emails[primary_email_index + 1] as email  -- PostgreSQL arrays are 1-indexed
    FROM params
    WHERE array_length(emails, 1) > primary_email_index
),
email_check AS (
    -- Check if primary email already exists in profile_emails
    SELECT EXISTS(SELECT 1 FROM profile_emails WHERE email = (SELECT email FROM primary_email) AND active = true) as email_exists
    FROM primary_email
),
profile_insert AS (
    -- Insert profile (only if email doesn't exist)
    INSERT INTO profiles (
        id, first_name, last_name, role, active
    )
    SELECT 
        (SELECT profile_id FROM params),
        (SELECT first_name FROM params),
        (SELECT last_name FROM params),
        (SELECT role FROM params)::profile_role,
        (SELECT active FROM params)
    WHERE NOT EXISTS (SELECT 1 FROM email_check WHERE email_exists = true)
    RETURNING id, first_name, last_name
),
all_emails_data AS (
    -- Prepare all emails with primary flag based on index
    SELECT 
        email,
        CASE WHEN ord = (SELECT primary_email_index + 1 FROM params) THEN true ELSE false END as is_primary
    FROM unnest((SELECT emails FROM params)) WITH ORDINALITY AS e(email, ord)
),
email_insert AS (
    -- Insert all emails into profile_emails
    INSERT INTO profile_emails (profile_id, email, is_primary, active)
    SELECT 
        pi.id,
        aed.email,
        aed.is_primary,
        true
    FROM profile_insert pi
    CROSS JOIN all_emails_data aed
    WHERE NOT EXISTS (SELECT 1 FROM email_check WHERE email_exists = true)
    ON CONFLICT (email) DO NOTHING  -- Skip if email already exists (shouldn't happen due to email_check)
),
cohort_insert AS (
    -- Insert cohort relationships if provided and profile was created
    INSERT INTO cohort_profiles (cohort_id, profile_id, active)
    SELECT 
        cohort_id,
        pi.id,
        true
    FROM profile_insert pi
    CROSS JOIN unnest((SELECT cohort_ids FROM params)) as cohort_id
    WHERE array_length((SELECT cohort_ids FROM params), 1) > 0
        AND NOT EXISTS (SELECT 1 FROM email_check WHERE email_exists = true)
    ON CONFLICT (cohort_id, profile_id) DO NOTHING
),
department_insert AS (
    -- Insert department relationships if provided and profile was created (set primary based on index)
    INSERT INTO profile_departments (profile_id, department_id, is_primary, active)
    SELECT 
        pi.id,
        dept.dept_id,
        (dept.ord - 1 = COALESCE((SELECT primary_department_index FROM params), 0)) as is_primary,
        true
    FROM profile_insert pi
    CROSS JOIN unnest((SELECT department_ids FROM params)) WITH ORDINALITY AS dept(dept_id, ord)
    WHERE array_length((SELECT department_ids FROM params), 1) > 0
        AND NOT EXISTS (SELECT 1 FROM email_check WHERE email_exists = true)
    ON CONFLICT (profile_id, department_id) DO NOTHING
)
-- Return profile info and email check result (always returns a row)
SELECT 
    pi.id as profile_id,
    pi.first_name,
    pi.last_name,
    COALESCE(ec.email_exists, false) as email_exists,
    ap.actor_name
FROM email_check ec
CROSS JOIN actor_profile ap
LEFT JOIN profile_insert pi ON true
LIMIT 1
$$;


--
-- Name: api_create_provider_v4(text, text, text, boolean, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_provider_v4(name text, description text, value text, active boolean, base_url text, profile_id uuid) RETURNS TABLE(provider_id uuid, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT
        name AS name,
        description AS description,
        value AS value,
        active AS active,
        NULLIF(TRIM(base_url), '') AS base_url,
        profile_id AS profile_id
),
actor_profile AS (
    SELECT 
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
new_provider AS (
    INSERT INTO providers (
        name,
        description,
        value,
        active
    )
    SELECT 
        x.name,
        x.description,
        x.value,
        x.active
    FROM params x
    RETURNING id as provider_id
),
link_endpoint AS (
    -- Link endpoint if base_url provided
    INSERT INTO provider_endpoints (provider_id, base_url, active, created_at, updated_at)
    SELECT 
        np.provider_id,
        x.base_url,
        true,
        NOW(),
        NOW()
    FROM new_provider np
    CROSS JOIN params x
    WHERE x.base_url IS NOT NULL
    ON CONFLICT (provider_id) DO UPDATE SET
        base_url = EXCLUDED.base_url,
        active = true,
        updated_at = NOW()
)
SELECT 
    np.provider_id,
    ap.actor_name::text as actor_name
FROM new_provider np
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_create_questions_with_options_v4(jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_questions_with_options_v4(questions_json jsonb) RETURNS TABLE(question_id uuid, question_text text, allow_multiple boolean)
    LANGUAGE sql
    AS $$
WITH questions_data AS (
    -- Parse questions from JSON
    SELECT 
        q->>'question_text' as question_text,
        q->>'type' as question_type,
        COALESCE((q->>'allow_multiple')::boolean, false) as allow_multiple,
        q->'options' as options_json
    FROM jsonb_array_elements(questions_json) as q
),
create_questions AS (
    -- Create questions (or get existing if they match exactly)
    INSERT INTO questions (question_text, allow_multiple, active, created_at, updated_at)
    SELECT DISTINCT
        qd.question_text,
        qd.allow_multiple,
        true,
        NOW(),
        NOW()
    FROM questions_data qd
    WHERE qd.question_text IS NOT NULL AND qd.question_text != ''
    ON CONFLICT DO NOTHING
    RETURNING id::uuid as question_id, question_text, allow_multiple
),
get_existing_questions AS (
    -- Get existing questions that match
    SELECT 
        q.id as question_id,
        q.question_text,
        q.allow_multiple
    FROM questions q
    JOIN questions_data qd ON q.question_text = qd.question_text 
        AND q.allow_multiple = qd.allow_multiple
    WHERE q.active = true
),
all_questions AS (
    SELECT * FROM create_questions
    UNION
    SELECT * FROM get_existing_questions
),
options_data AS (
    -- Extract options from questions (only for choice questions)
    SELECT 
        aq.question_id,
        opt->>'option_text' as option_text,
        opt->>'type' as option_type,
        COALESCE((opt->>'is_correct')::boolean, false) as is_correct
    FROM all_questions aq
    JOIN questions_data qd ON aq.question_text = qd.question_text 
        AND aq.allow_multiple = qd.allow_multiple
    CROSS JOIN jsonb_array_elements(qd.options_json) as opt
    WHERE qd.question_type = 'choice' AND qd.options_json IS NOT NULL
),
create_options AS (
    -- Create options (reusable across questions)
    INSERT INTO options (option_text, type, active, created_at, updated_at)
    SELECT DISTINCT
        od.option_text,
        od.option_type::option_type,
        true,
        NOW(),
        NOW()
    FROM options_data od
    WHERE od.option_text IS NOT NULL AND od.option_text != ''
    ON CONFLICT DO NOTHING
    RETURNING id::uuid as option_id, option_text, type
),
get_existing_options AS (
    -- Get existing options that match
    SELECT 
        o.id as option_id,
        o.option_text,
        o.type
    FROM options o
    JOIN options_data od ON o.option_text = od.option_text 
        AND o.type::text = od.option_type
    WHERE o.active = true
),
all_options AS (
    SELECT * FROM create_options
    UNION
    SELECT * FROM get_existing_options
),
link_question_options AS (
    -- Link questions to options via question_options junction table
    INSERT INTO question_options (question_id, option_id, active, created_at, updated_at)
    SELECT DISTINCT
        od.question_id,
        ao.option_id,
        true,
        NOW(),
        NOW()
    FROM options_data od
    JOIN all_options ao ON ao.option_text = od.option_text 
        AND ao.type::text = od.option_type
    ON CONFLICT (question_id, option_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
link_question_answers AS (
    -- Link questions to correct options via question_answers junction table
    INSERT INTO question_answers (question_id, option_id, active, created_at, updated_at)
    SELECT DISTINCT
        od.question_id,
        ao.option_id,
        true,
        NOW(),
        NOW()
    FROM options_data od
    JOIN all_options ao ON ao.option_text = od.option_text 
        AND ao.type::text = od.option_type
    WHERE od.is_correct = true
    ON CONFLICT (question_id, option_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
)
SELECT DISTINCT
    aq.question_id,
    aq.question_text,
    aq.allow_multiple
FROM all_questions aq
ORDER BY aq.question_id
$$;


--
-- Name: api_create_rubric_v4(text, text, boolean, integer, integer, uuid, uuid[], types.i_create_rubric_v4_standard_group[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_rubric_v4(name text, description text, active boolean, points integer, pass_points integer, profile_id uuid, department_ids uuid[] DEFAULT ARRAY[]::uuid[], standard_groups types.i_create_rubric_v4_standard_group[] DEFAULT ARRAY[]::types.i_create_rubric_v4_standard_group[], rubric_agent_id uuid DEFAULT NULL::uuid) RETURNS TABLE(rubric_id uuid, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        name AS name,
        COALESCE(NULLIF(description, ''), '') AS description,
        active AS active,
        points AS points,
        pass_points AS pass_points,
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids,
        COALESCE(standard_groups, ARRAY[]::types.i_create_rubric_v4_standard_group[]) AS standard_groups,
        rubric_agent_id AS rubric_agent_id,
        profile_id AS profile_id
),
user_profile AS (
    SELECT 
        p.role,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
validate_create_permissions AS (
    SELECT validate_department_create_permissions(
        up.role::text,
        ARRAY_AGG(did::text)
    ) as validation_passed
    FROM params x
    CROSS JOIN UNNEST(x.department_ids) as did
    CROSS JOIN user_profile up
    GROUP BY up.role
),
actor_profile AS (
    SELECT 
        x.profile_id as resolved_profile_id,
        up.actor_name
    FROM params x
    CROSS JOIN user_profile up
),
new_rubric AS (
    INSERT INTO rubrics (
        name,
        description,
        active,
        points,
        pass_points,
        rubric_agent_id
    )
    SELECT 
        x.name,
        x.description,
        x.active,
        x.points,
        x.pass_points,
        x.rubric_agent_id
    FROM params x
    RETURNING id as rubric_id
),
link_departments AS (
    INSERT INTO rubric_departments (rubric_id, department_id, active, created_at, updated_at)
    SELECT 
        nr.rubric_id,
        dept_id,
        true,
        NOW(),
        NOW()
    FROM new_rubric nr
    CROSS JOIN params x
    CROSS JOIN UNNEST(x.department_ids) as dept_id
    WHERE array_length(x.department_ids, 1) > 0
    ON CONFLICT (rubric_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
standard_groups_unnested AS (
    SELECT 
        nr.rubric_id,
        (ROW_NUMBER() OVER (PARTITION BY nr.rubric_id ORDER BY ordinality))::int as group_order,
        sg.name,
        COALESCE(NULLIF(sg.short_name, ''), NULL)::text as short_name,
        COALESCE(NULLIF(sg.description, ''), NULL)::text as description,
        sg.points,
        sg.pass_points,
        COALESCE(sg.position, (ROW_NUMBER() OVER (PARTITION BY nr.rubric_id ORDER BY ordinality)))::int as position,
        COALESCE(sg.active, true)::boolean as active,
        sg.standards
    FROM new_rubric nr
    CROSS JOIN params x
    CROSS JOIN UNNEST(x.standard_groups) WITH ORDINALITY as sg
    WHERE array_length(x.standard_groups, 1) > 0
),
-- Create placeholder calls for API-created standard_groups (not created via tool)
placeholder_calls AS (
    INSERT INTO calls (call_id, tool_id, completed, created_at, updated_at)
    SELECT 
        'api_create_rubric_' || sgu.rubric_id::text || '_sg_' || sgu.group_order::text,
        NULL,
        TRUE,
        NOW(),
        NOW()
    FROM standard_groups_unnested sgu
    RETURNING id, call_id
),
calls_with_order AS (
    SELECT 
        ptc.id as tool_call_id,
        (ROW_NUMBER() OVER (ORDER BY ptc.id))::int as rn
    FROM placeholder_calls ptc
),
new_standard_groups AS (
    INSERT INTO standard_groups (
        name,
        short_name,
        description,
        points,
        pass_points,
        active,
        tool_call_id
    )
    SELECT 
        sgu.name,
        sgu.short_name,
        sgu.description,
        sgu.points,
        sgu.pass_points,
        sgu.active,
        tcwo.tool_call_id
    FROM standard_groups_unnested sgu
    JOIN calls_with_order tcwo ON tcwo.rn = sgu.group_order
    RETURNING id, name, short_name, description, points, pass_points, active
),
link_rubric_standard_groups AS (
    INSERT INTO rubric_standard_groups (rubric_id, standard_group_id, position, active, created_at, updated_at)
    SELECT 
        sgu.rubric_id,
        nsg.id as standard_group_id,
        sgu.position,
        sgu.active,
        NOW(),
        NOW()
    FROM new_standard_groups nsg
    JOIN standard_groups_unnested sgu ON 
        sgu.name = nsg.name 
        AND COALESCE(sgu.short_name, '') = COALESCE(nsg.short_name, '')
        AND COALESCE(sgu.description, '') = COALESCE(nsg.description, '')
        AND sgu.points = nsg.points
        AND sgu.pass_points = nsg.pass_points
    ORDER BY sgu.group_order
    ON CONFLICT (rubric_id, standard_group_id) DO UPDATE SET
        position = EXCLUDED.position,
        active = EXCLUDED.active,
        updated_at = NOW()
),
standard_groups_with_order AS (
    SELECT DISTINCT ON (nsg.id)
        nsg.id as standard_group_id,
        sgu.standards
    FROM new_standard_groups nsg
    JOIN standard_groups_unnested sgu ON 
        sgu.name = nsg.name 
        AND COALESCE(sgu.short_name, '') = COALESCE(nsg.short_name, '')
        AND COALESCE(sgu.description, '') = COALESCE(nsg.description, '')
        AND sgu.points = nsg.points
        AND sgu.pass_points = nsg.pass_points
    ORDER BY nsg.id, sgu.group_order
),
standards_unnested AS (
    SELECT 
        sgwo.standard_group_id,
        std.name,
        COALESCE(NULLIF(std.description, ''), NULL)::text as description,
        std.points
    FROM standard_groups_with_order sgwo
    CROSS JOIN UNNEST(sgwo.standards) as std
    WHERE array_length(sgwo.standards, 1) > 0
),
new_standards AS (
    INSERT INTO standards (
        standard_group_id,
        name,
        description,
        points
    )
    SELECT 
        standard_group_id,
        name,
        description,
        points
    FROM standards_unnested
    RETURNING id
)
SELECT 
    nr.rubric_id,
    ap.actor_name
FROM new_rubric nr
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_create_scenario_v4(text, boolean, boolean, boolean, boolean, boolean, boolean, text, text[], text[], types.q_create_scenario_v4_parameter[], uuid, text, uuid, text, text[], text[], text[], text[], uuid[], text[], text[], text, text[], types.q_create_scenario_v4_question_timestamp[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_scenario_v4(name text, active boolean, objectives_enabled boolean, images_enabled boolean, video_enabled boolean, questions_enabled boolean, problem_statement_enabled boolean, problem_statement text, document_ids text[], objective_ids text[], parameters types.q_create_scenario_v4_parameter[], profile_id uuid, description text DEFAULT NULL::text, video_agent_id uuid DEFAULT NULL::uuid, problem_statement_name text DEFAULT NULL::text, problem_statement_versions text[] DEFAULT NULL::text[], department_ids text[] DEFAULT NULL::text[], persona_ids text[] DEFAULT NULL::text[], template_document_ids text[] DEFAULT NULL::text[], upload_ids uuid[] DEFAULT NULL::uuid[], image_names text[] DEFAULT NULL::text[], video_ids text[] DEFAULT NULL::text[], active_video_id text DEFAULT NULL::text, question_ids text[] DEFAULT NULL::text[], question_timestamps types.q_create_scenario_v4_question_timestamp[] DEFAULT ARRAY[]::types.q_create_scenario_v4_question_timestamp[], run_id uuid DEFAULT NULL::uuid) RETURNS TABLE(scenario_id uuid, actor_name text)
    LANGUAGE sql
    AS $$
WITH raw_params AS (
    SELECT
        name AS name,
        description AS description,
        active AS active,
        objectives_enabled AS objectives_enabled,
        images_enabled AS images_enabled,
        video_enabled AS video_enabled,
        questions_enabled AS questions_enabled,
        problem_statement_enabled AS problem_statement_enabled,
        video_agent_id AS video_agent_id,
        problem_statement AS problem_statement,
        problem_statement_name AS problem_statement_name,
        problem_statement_versions AS problem_statement_versions,
        department_ids AS department_ids,
        persona_ids AS persona_ids,
        document_ids AS document_ids,
        template_document_ids AS template_document_ids,
        objective_ids AS objective_ids,
        parameters AS parameters,
        upload_ids AS upload_ids,
        image_names AS image_names,
        video_ids AS video_ids,
        active_video_id AS active_video_id,
        question_ids AS question_ids,
        question_timestamps AS question_timestamps,
        run_id AS run_id,
        profile_id AS profile_id
),
-- Preprocessing: Filter composite objective IDs (those with "_" and length 2 when split)
filtered_objective_ids AS (
    SELECT ARRAY_AGG(obj_id) FILTER (WHERE obj_id IS NOT NULL) as objective_ids
    FROM raw_params rp
    CROSS JOIN UNNEST(COALESCE(rp.objective_ids, ARRAY[]::text[])) as obj_id
    WHERE NOT (obj_id LIKE '%_%' AND array_length(string_to_array(obj_id, '_'), 1) = 2)
),
-- Preprocessing: Extract parameter_item_ids and parameter_ids from parameters composite type array
parameter_preprocessing AS (
    SELECT
        COALESCE(
            ARRAY_AGG(DISTINCT field_id::text) FILTER (WHERE field_id IS NOT NULL),
            ARRAY[]::text[]
        ) as parameter_item_ids,
        COALESCE(
            ARRAY_AGG(DISTINCT param.parameter_id::text) FILTER (WHERE param.parameter_id IS NOT NULL),
            ARRAY[]::text[]
        ) as parameter_ids
    FROM raw_params rp
    CROSS JOIN UNNEST(COALESCE(rp.parameters, ARRAY[]::types.q_create_scenario_v4_parameter[])) as param
    CROSS JOIN UNNEST(COALESCE(param.field_ids, ARRAY[]::uuid[])) as field_id
),
-- Preprocessing: Process problem statement versions (clean, deduplicate, ensure problem_statement included)
processed_problem_statement_versions AS (
    SELECT 
        CASE 
            WHEN rp.problem_statement_versions IS NOT NULL 
                 AND array_length(rp.problem_statement_versions, 1) > 0
            THEN 
                -- Clean and deduplicate versions, ensure problem_statement is included
                COALESCE(
                    ARRAY_AGG(DISTINCT version_text) FILTER (WHERE version_text IS NOT NULL AND version_text != ''),
                    ARRAY[]::text[]
                )
            ELSE 
                -- If no versions provided, use single problem statement if available
                CASE 
                    WHEN rp.problem_statement IS NOT NULL AND rp.problem_statement != ''
                    THEN ARRAY[rp.problem_statement]
                    ELSE ARRAY[]::text[]
                END
        END as problem_statement_versions
    FROM raw_params rp
    CROSS JOIN LATERAL (
        SELECT version_text
        FROM UNNEST(COALESCE(rp.problem_statement_versions, ARRAY[]::text[])) as version_text
        WHERE version_text IS NOT NULL AND trim(version_text) != ''
        UNION ALL
        -- Ensure problem_statement is included if not already in versions
        SELECT rp.problem_statement as version_text
        WHERE rp.problem_statement IS NOT NULL 
          AND rp.problem_statement != ''
          AND (rp.problem_statement_versions IS NULL 
               OR NOT (rp.problem_statement = ANY(rp.problem_statement_versions)))
    ) all_versions
    GROUP BY rp.problem_statement_versions, rp.problem_statement
),
-- Preprocessing: Construct upload_images array from upload_ids and image_names arrays
upload_images_preprocessing AS (
    SELECT
        COALESCE(
            ARRAY_AGG(
                (upload_id, image_name)::types.q_create_scenario_v4_upload_image
                ORDER BY idx
            ),
            '{}'::types.q_create_scenario_v4_upload_image[]
        ) as upload_images
    FROM raw_params rp
    CROSS JOIN LATERAL (
        SELECT 
            upload_id,
            image_name,
            ROW_NUMBER() OVER () - 1 as idx
        FROM UNNEST(
            COALESCE(rp.upload_ids, ARRAY[]::uuid[]),
            COALESCE(rp.image_names, ARRAY[]::text[])
        ) as t(upload_id, image_name)
    ) paired
    WHERE rp.upload_ids IS NOT NULL 
      AND rp.image_names IS NOT NULL
      AND array_length(rp.upload_ids, 1) = array_length(rp.image_names, 1)
      AND array_length(rp.upload_ids, 1) > 0
),
params AS (
    SELECT
        rp.name AS name,
        COALESCE(NULLIF(rp.description, ''), '') AS description,
        rp.active AS active,
        rp.objectives_enabled AS objectives_enabled,
        rp.images_enabled AS images_enabled,
        rp.video_enabled AS video_enabled,
        rp.questions_enabled AS questions_enabled,
        rp.problem_statement_enabled AS problem_statement_enabled,
        rp.video_agent_id AS video_agent_id,
        rp.problem_statement AS problem_statement,
        COALESCE(rp.problem_statement_name, rp.name) AS problem_statement_name,
        COALESCE(ppsv.problem_statement_versions, ARRAY[]::text[]) AS problem_statement_versions,
        COALESCE(rp.department_ids, ARRAY[]::text[]) AS department_ids,
        COALESCE(rp.persona_ids, ARRAY[]::text[]) AS persona_ids,
        COALESCE(rp.document_ids, ARRAY[]::text[]) AS document_ids,
        COALESCE(rp.template_document_ids, ARRAY[]::text[]) AS template_document_ids,
        COALESCE(foi.objective_ids, ARRAY[]::text[]) AS objective_ids,
        COALESCE(pp.parameter_item_ids, ARRAY[]::text[]) AS parameter_item_ids,
        COALESCE(uip.upload_images, ARRAY[]::types.q_create_scenario_v4_upload_image[]) AS upload_images,
        COALESCE(rp.video_ids, ARRAY[]::text[]) AS video_ids,
        rp.active_video_id AS active_video_id,
        COALESCE(rp.question_ids, ARRAY[]::text[]) AS question_ids,
        COALESCE(rp.question_timestamps, ARRAY[]::types.q_create_scenario_v4_question_timestamp[]) AS question_timestamps,
        rp.run_id AS run_id,
        COALESCE(pp.parameter_ids, ARRAY[]::text[]) AS parameter_ids,
        rp.profile_id AS profile_id
    FROM raw_params rp
    CROSS JOIN filtered_objective_ids foi
    CROSS JOIN parameter_preprocessing pp
    CROSS JOIN processed_problem_statement_versions ppsv
    CROSS JOIN upload_images_preprocessing uip
),
user_profile AS (
    SELECT 
        p.role,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
validate_create_permissions AS (
    -- Validate department permissions for create operation
    SELECT validate_department_create_permissions(
        up.role::text,
        (SELECT department_ids FROM params)
    ) as validation_passed
    FROM user_profile up
),
actor_profile AS (
    SELECT 
        (SELECT profile_id FROM params) as resolved_profile_id,
        up.actor_name
    FROM user_profile up
),
new_scenario AS (
    INSERT INTO scenarios (
        name,
        description,
        active,
        objectives_enabled,
        images_enabled,
        video_enabled,
        questions_enabled,
        problem_statement_enabled,
        video_agent_id
    )
    SELECT 
        (SELECT name FROM params), 
        (SELECT description FROM params), 
        (SELECT active FROM params), 
        (SELECT objectives_enabled FROM params), 
        (SELECT images_enabled FROM params), 
        (SELECT video_enabled FROM params), 
        (SELECT questions_enabled FROM params), 
        (SELECT problem_statement_enabled FROM params), 
        (SELECT video_agent_id FROM params)
    RETURNING id
),
link_departments AS (
    -- Link departments if provided
    INSERT INTO scenario_departments (scenario_id, department_id, active, created_at, updated_at)
    SELECT 
        ns.id,
        dept_id::uuid,
        true,
        NOW(),
        NOW()
    FROM new_scenario ns
    CROSS JOIN UNNEST((SELECT department_ids FROM params)) as dept_id
    WHERE COALESCE(array_length((SELECT department_ids FROM params), 1), 0) > 0
    ON CONFLICT (scenario_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
link_scenario_parameters AS (
    -- Link parameters if provided (array is never NULL, but may be empty)
    INSERT INTO scenario_parameters (scenario_id, parameter_id, active, created_at, updated_at)
    SELECT 
        ns.id,
        param_id::uuid,
        true,
        NOW(),
        NOW()
    FROM new_scenario ns
    CROSS JOIN UNNEST((SELECT parameter_ids FROM params)) as param_id
    WHERE COALESCE(array_length((SELECT parameter_ids FROM params), 1), 0) > 0
    ON CONFLICT (scenario_id, parameter_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
link_tree_edge AS (
    -- Insert self-referencing edge in scenario_tree (marks as root)
    INSERT INTO scenario_tree (parent_id, child_id, active)
    SELECT ns.id, ns.id, true
    FROM new_scenario ns
),
problem_statement_versions_data AS (
    -- Prepare problem statement versions
    SELECT DISTINCT version_text
    FROM new_scenario ns
    CROSS JOIN UNNEST((SELECT problem_statement_versions FROM params)) as version_text
    WHERE COALESCE(array_length((SELECT problem_statement_versions FROM params), 1), 0) > 0
    UNION ALL
    -- If no versions provided, use single problem statement
    SELECT (SELECT problem_statement FROM params) as version_text
    FROM new_scenario ns
    WHERE COALESCE(array_length((SELECT problem_statement_versions FROM params), 1), 0) = 0 
      AND (SELECT problem_statement FROM params) IS NOT NULL 
      AND (SELECT problem_statement FROM params) != ''
),
create_problem_statements AS (
    -- Create problem_statement records first (strong entity)
    -- Always create new records (don't reuse) to allow different names for same text
    INSERT INTO problem_statements (name, problem_statement, created_at, updated_at)
    SELECT 
        (SELECT problem_statement_name FROM params) as name,
        psd.version_text,
        NOW(),
        NOW()
    FROM problem_statement_versions_data psd
    RETURNING id as problem_statement_id, problem_statement
),
link_problem_statements AS (
    -- Link problem statements to scenario via junction table
    INSERT INTO scenario_problem_statements (scenario_id, problem_statement_id, active, created_at, updated_at)
    SELECT 
        ns.id,
        cps.problem_statement_id,
        CASE 
            WHEN cps.problem_statement = (SELECT problem_statement FROM params) THEN true
            ELSE false
        END as active,
        NOW(),
        NOW()
    FROM new_scenario ns
    CROSS JOIN create_problem_statements cps
),
link_personas AS (
    -- Link personas if provided
    INSERT INTO scenario_personas (scenario_id, persona_id, active, created_at, updated_at)
    SELECT 
        ns.id,
        persona_id::uuid,
        true,
        NOW(),
        NOW()
    FROM new_scenario ns
    CROSS JOIN UNNEST((SELECT persona_ids FROM params)) as persona_id
    WHERE COALESCE(array_length((SELECT persona_ids FROM params), 1), 0) > 0
    ON CONFLICT (scenario_id, persona_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
link_documents AS (
    -- Link documents (both regular and template documents)
    INSERT INTO scenario_documents (scenario_id, document_id, active, created_at, updated_at)
    SELECT 
        ns.id,
        doc_id::uuid,
        true,
        NOW(),
        NOW()
    FROM new_scenario ns
    CROSS JOIN (
        SELECT doc_id FROM UNNEST((SELECT document_ids FROM params)) as doc_id
        UNION ALL
        SELECT doc_id FROM UNNEST((SELECT template_document_ids FROM params)) as doc_id
    ) all_docs
    WHERE COALESCE(array_length((SELECT document_ids FROM params), 1), 0) > 0 
       OR COALESCE(array_length((SELECT template_document_ids FROM params), 1), 0) > 0
    ON CONFLICT (scenario_id, document_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
objectives_with_index AS (
    -- Prepare objectives with their index (skip composite IDs - filtered in Python)
    SELECT 
        obj_text,
        ROW_NUMBER() OVER () - 1 as idx
    FROM UNNEST((SELECT objective_ids FROM params)) as obj_text
    WHERE COALESCE(array_length((SELECT objective_ids FROM params), 1), 0) > 0
),
existing_objectives AS (
    -- Find existing objectives by text
    SELECT id as objective_id, objective
    FROM objectives
    WHERE objective = ANY(SELECT obj_text FROM objectives_with_index)
),
new_objectives AS (
    -- Create new objectives that don't exist yet
    INSERT INTO objectives (objective, created_at, updated_at)
    SELECT DISTINCT
        owi.obj_text,
        NOW(),
        NOW()
    FROM objectives_with_index owi
    WHERE NOT EXISTS (
        SELECT 1 FROM existing_objectives eo WHERE eo.objective = owi.obj_text
    )
    RETURNING id as objective_id, objective
),
all_objectives AS (
    -- Combine existing and new objectives
    SELECT objective_id, objective FROM existing_objectives
    UNION ALL
    SELECT objective_id, objective FROM new_objectives
),
link_objectives AS (
    -- Link objectives to scenario via junction table
    INSERT INTO scenario_objectives (scenario_id, objective_id, idx, created_at)
    SELECT 
        ns.id,
        ao.objective_id,
        owi.idx,
        NOW()
    FROM new_scenario ns
    CROSS JOIN objectives_with_index owi
    JOIN all_objectives ao ON ao.objective = owi.obj_text
),
link_parameters AS (
    -- Link fields
    INSERT INTO scenario_fields (scenario_id, field_id, active, created_at, updated_at)
    SELECT 
        ns.id,
        field_id::uuid,
        true,
        NOW(),
        NOW()
    FROM new_scenario ns
    CROSS JOIN UNNEST((SELECT parameter_item_ids FROM params)) as field_id
    WHERE COALESCE(array_length((SELECT parameter_item_ids FROM params), 1), 0) > 0
    ON CONFLICT (scenario_id, field_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
create_images AS (
    -- Create images if they don't exist
    INSERT INTO images (name, created_at, updated_at, active)
    SELECT DISTINCT
        img.name,
        NOW(),
        NOW(),
        true
    FROM params x
    CROSS JOIN UNNEST(x.upload_images) as img
    WHERE array_length((SELECT upload_images FROM params), 1) > 0
      AND NOT EXISTS (
          SELECT 1 FROM images i
          JOIN image_uploads iu ON iu.image_id = i.id
          WHERE iu.upload_id = img.upload_id AND i.name = img.name
      )
    RETURNING id as image_id
),
link_image_uploads AS (
    -- Link images to uploads via junction table
    INSERT INTO image_uploads (image_id, upload_id, active, created_at, updated_at)
    SELECT DISTINCT
        ci.image_id,
        img.upload_id,
        true,
        NOW(),
        NOW()
    FROM create_images ci
    CROSS JOIN params x
    CROSS JOIN UNNEST(x.upload_images) as img
    WHERE array_length((SELECT upload_images FROM params), 1) > 0
    ON CONFLICT (image_id, upload_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
    RETURNING image_id, upload_id
),
get_images AS (
    -- Get existing images via image_uploads junction table
    SELECT i.id as image_id, iu.upload_id
    FROM params x
    CROSS JOIN UNNEST(x.upload_images) as img
    JOIN image_uploads iu ON iu.upload_id = img.upload_id
    JOIN images i ON i.id = iu.image_id AND i.name = img.name
    WHERE iu.active = true
),
all_images AS (
    SELECT image_id, upload_id FROM link_image_uploads
    UNION
    SELECT image_id, upload_id FROM get_images
),
link_images AS (
    -- Link images to scenario via junction table
    INSERT INTO scenario_images (scenario_id, image_id, active, created_at, updated_at)
    SELECT 
        ns.id,
        ai.image_id,
        true,
        NOW(),
        NOW()
    FROM new_scenario ns
    CROSS JOIN all_images ai
    WHERE array_length((SELECT upload_images FROM params), 1) > 0
    ON CONFLICT (scenario_id, image_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
link_problem_statements_to_runs AS (
    -- Link problem statements to run via tool_call if run_id provided
    SELECT DISTINCT
        cps.problem_statement_id,
        (SELECT run_id FROM params) as run_id
    FROM create_problem_statements cps
    WHERE (SELECT run_id FROM params) IS NOT NULL
    AND EXISTS (
        SELECT 1 FROM problem_statements ps
        JOIN calls tc ON tc.id = ps.tool_call_id
        JOIN tool_call_runs tcr ON tcr.tool_call_id = tc.id
        WHERE ps.id = cps.problem_statement_id
        AND tcr.run_id = (SELECT run_id FROM params)
    )
),
link_objectives_to_runs AS (
    -- Link objectives to run via tool_call if run_id provided
    SELECT DISTINCT
        ao.objective_id,
        (SELECT run_id FROM params) as run_id
    FROM all_objectives ao
    WHERE (SELECT run_id FROM params) IS NOT NULL
    AND EXISTS (
        SELECT 1 FROM objectives o
        JOIN calls tc ON tc.id = o.tool_call_id
        JOIN tool_call_runs tcr ON tcr.tool_call_id = tc.id
        WHERE o.id = ao.objective_id
        AND tcr.run_id = (SELECT run_id FROM params)
    )
),
link_videos AS (
    -- Link videos to scenario via junction table
    INSERT INTO scenario_videos (scenario_id, video_id, active, created_at, updated_at)
    SELECT 
        ns.id,
        video_id::uuid,
        CASE 
            WHEN video_id::text = (SELECT active_video_id FROM params) THEN true
            ELSE false
        END as active,
        NOW(),
        NOW()
    FROM new_scenario ns
    CROSS JOIN UNNEST((SELECT video_ids FROM params)) as video_id
    WHERE COALESCE(array_length((SELECT video_ids FROM params), 1), 0) > 0
    ON CONFLICT (scenario_id, video_id) DO UPDATE SET
        active = CASE 
            WHEN (scenario_videos.video_id)::text = (SELECT active_video_id FROM params) THEN true
            ELSE false
        END,
        updated_at = NOW()
),
link_questions AS (
    -- Link questions to scenario via junction table
    INSERT INTO scenario_questions (scenario_id, question_id, active, created_at, updated_at)
    SELECT 
        ns.id,
        question_id::uuid,
        true,
        NOW(),
        NOW()
    FROM new_scenario ns
    CROSS JOIN UNNEST((SELECT question_ids FROM params)) as question_id
    WHERE COALESCE(array_length((SELECT question_ids FROM params), 1), 0) > 0
    ON CONFLICT (scenario_id, question_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
link_question_times AS (
    -- Link question times to videos
    INSERT INTO scenario_question_times (scenario_id, question_id, video_id, time, active, created_at, updated_at)
    SELECT 
        ns.id,
        qt.question_id,
        qt.video_id,
        time_val::numeric as time,
        true,
        NOW(),
        NOW()
    FROM new_scenario ns
    CROSS JOIN params x
    CROSS JOIN UNNEST(x.question_timestamps) as qt
    CROSS JOIN UNNEST(COALESCE(qt.timestamps, ARRAY[]::numeric[])) as time_val
    WHERE array_length((SELECT question_timestamps FROM params), 1) > 0
    ON CONFLICT (scenario_id, question_id, video_id, time) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
link_image_departments AS (
    INSERT INTO image_departments (image_id, department_id, active, created_at, updated_at)
    SELECT DISTINCT
        ai.image_id,
        dept_id::uuid,
        true,
        NOW(),
        NOW()
    FROM all_images ai
    CROSS JOIN new_scenario ns
    CROSS JOIN UNNEST((SELECT department_ids FROM params)) as dept_id
    WHERE COALESCE(array_length((SELECT department_ids FROM params), 1), 0) > 0
    ON CONFLICT (image_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
link_video_departments AS (
    INSERT INTO video_departments (video_id, department_id, active, created_at, updated_at)
    SELECT DISTINCT
        vid::uuid as video_id,
        dept_id::uuid,
        true,
        NOW(),
        NOW()
    FROM UNNEST((SELECT video_ids FROM params)) as vid
    CROSS JOIN UNNEST((SELECT department_ids FROM params)) as dept_id
    WHERE COALESCE(array_length((SELECT video_ids FROM params), 1), 0) > 0
    AND COALESCE(array_length((SELECT department_ids FROM params), 1), 0) > 0
    ON CONFLICT (video_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
link_objective_departments AS (
    INSERT INTO objective_departments (objective_id, department_id, active, created_at, updated_at)
    SELECT DISTINCT
        ao.objective_id,
        dept_id::uuid,
        true,
        NOW(),
        NOW()
    FROM all_objectives ao
    CROSS JOIN UNNEST((SELECT department_ids FROM params)) as dept_id
    WHERE COALESCE(array_length((SELECT department_ids FROM params), 1), 0) > 0
    ON CONFLICT (objective_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
link_question_departments AS (
    INSERT INTO question_departments (question_id, department_id, active, created_at, updated_at)
    SELECT DISTINCT
        question_id::uuid,
        dept_id::uuid,
        true,
        NOW(),
        NOW()
    FROM UNNEST((SELECT question_ids FROM params)) as question_id
    CROSS JOIN UNNEST((SELECT department_ids FROM params)) as dept_id
    WHERE COALESCE(array_length((SELECT question_ids FROM params), 1), 0) > 0
    AND COALESCE(array_length((SELECT department_ids FROM params), 1), 0) > 0
    ON CONFLICT (question_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
link_problem_statement_departments AS (
    INSERT INTO problem_statement_departments (problem_statement_id, department_id, active, created_at, updated_at)
    SELECT DISTINCT
        cps.problem_statement_id,
        dept_id::uuid,
        true,
        NOW(),
        NOW()
    FROM create_problem_statements cps
    CROSS JOIN UNNEST((SELECT department_ids FROM params)) as dept_id
    WHERE COALESCE(array_length((SELECT department_ids FROM params), 1), 0) > 0
    ON CONFLICT (problem_statement_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
create_persona_ranges AS (
    INSERT INTO scenario_persona_ranges (scenario_id, min_count, max_count)
    SELECT ns.id, 1, 3
    FROM new_scenario ns
    ON CONFLICT (scenario_id) DO UPDATE SET
        updated_at = NOW()
),
create_document_ranges AS (
    INSERT INTO scenario_document_ranges (scenario_id, min_count, max_count)
    SELECT ns.id, 0, 3
    FROM new_scenario ns
    ON CONFLICT (scenario_id) DO UPDATE SET
        updated_at = NOW()
),
create_parameter_ranges AS (
    INSERT INTO scenario_parameter_ranges (scenario_id, min_count, max_count)
    SELECT ns.id, 0, 3
    FROM new_scenario ns
    ON CONFLICT (scenario_id) DO UPDATE SET
        updated_at = NOW()
),
create_field_ranges AS (
    INSERT INTO scenario_field_ranges (scenario_id, parameter_id, min_count, max_count)
    SELECT 
        ns.id,
        param_id::uuid,
        1,
        3
    FROM new_scenario ns
    CROSS JOIN UNNEST((SELECT parameter_ids FROM params)) as param_id
    WHERE COALESCE(array_length((SELECT parameter_ids FROM params), 1), 0) > 0
    ON CONFLICT (scenario_id, parameter_id) DO UPDATE SET
        updated_at = NOW()
)
SELECT 
    ns.id as scenario_id,
    ap.actor_name::text as actor_name
FROM new_scenario ns
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_create_simulation_chat_v4(timestamp with time zone, text, uuid, uuid, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_simulation_chat_v4(created_at timestamp with time zone, title text, scenario_id uuid, attempt_id uuid, completed boolean) RETURNS TABLE(id uuid, created_at timestamp with time zone, updated_at timestamp with time zone, title text, scenario_id uuid, attempt_id uuid, completed boolean, trace_id text)
    LANGUAGE sql
    AS $$
WITH inserted_chat AS (
    INSERT INTO chats (created_at, title, scenario_id, completed, updated_at)
    VALUES (created_at, title, scenario_id, completed, NOW())
    RETURNING id, created_at, updated_at, title, scenario_id, completed
),
create_group_if_needed AS (
    INSERT INTO groups (created_at, updated_at)
    VALUES (NOW(), NOW())
    RETURNING id as group_id, trace_id
),
create_chat_group_if_needed AS (
    INSERT INTO chat_groups (chat_id, group_id, created_at, updated_at)
    SELECT ic.id, cg.group_id, ic.created_at, ic.updated_at
    FROM inserted_chat ic
    CROSS JOIN create_group_if_needed cg
    ON CONFLICT (chat_id, group_id) DO NOTHING
    RETURNING group_id
),
final_group AS (
    SELECT group_id FROM create_chat_group_if_needed
    LIMIT 1
),
inserted_junction AS (
    INSERT INTO attempt_chats (attempt_id, chat_id, created_at, updated_at)
    SELECT attempt_id, ic.id, ic.created_at, ic.updated_at
    FROM inserted_chat ic
    RETURNING chat_id, attempt_id
)
SELECT 
    ic.id,
    ic.created_at,
    ic.updated_at,
    ic.title,
    ic.scenario_id,
    ij.attempt_id,
    ic.completed,
    g.trace_id
FROM inserted_chat ic
JOIN inserted_junction ij ON ij.chat_id = ic.id
CROSS JOIN final_group fg
JOIN groups g ON g.id = fg.group_id
$$;


--
-- Name: api_create_video_basic_v4(text, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_create_video_basic_v4(name text, length_seconds integer) RETURNS TABLE(id uuid)
    LANGUAGE sql
    AS $$
WITH tool_call AS (
    INSERT INTO calls (call_id, tool_id, completed, created_at, updated_at)
    VALUES (concat('video:', uuidv7()::text), NULL, FALSE, NOW(), NOW())
    RETURNING id
),
insert_video AS (
    INSERT INTO videos (
        name,
        length_seconds,
        active,
        image_enabled,
        completed,
        tool_call_id,
        created_at,
        updated_at
    )
    SELECT name, length_seconds, TRUE, TRUE, FALSE, tool_call.id, NOW(), NOW()
    FROM tool_call
    RETURNING id
)
SELECT id FROM insert_video
$$;


--
-- Name: api_delete_agent_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_delete_agent_v4(agent_id uuid, profile_id uuid) RETURNS TABLE(usage_count bigint, deleted boolean, name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT agent_id AS agent_id,
           profile_id AS profile_id
),
actor_profile AS (
    SELECT 
        x.profile_id,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
agent_info AS (
    SELECT id, name FROM params x JOIN agents ON agents.id = x.agent_id
),
usage_check AS (
    SELECT COUNT(*) as usage_count
    FROM params x
    JOIN agent_departments ON agent_departments.agent_id = x.agent_id AND agent_departments.active = true
),
delete_result AS (
    DELETE FROM agents 
    USING params x
    WHERE agents.id = x.agent_id 
      AND (SELECT usage_count FROM usage_check) = 0
    RETURNING agents.id
)
SELECT 
    (SELECT usage_count FROM usage_check) as usage_count,
    CASE WHEN EXISTS(SELECT 1 FROM delete_result) THEN true ELSE false END as deleted,
    COALESCE(ai.name, 'Unknown') as name,
    ap.actor_name
FROM actor_profile ap
CROSS JOIN agent_info ai
$$;


--
-- Name: api_delete_auth_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_delete_auth_v4(auth_id uuid, profile_id uuid) RETURNS TABLE(auth_exists boolean, success boolean, name text, message text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT auth_id AS auth_id,
           profile_id AS profile_id
),
auth_exists_check AS (
    -- Check if auth exists before deletion
    SELECT EXISTS(
        SELECT 1 FROM auth WHERE id = (SELECT auth_id FROM params)
    )::boolean as auth_exists
),
actor_profile AS (
    SELECT 
        x.profile_id as profile_id,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
auth_info AS (
    SELECT id, name
    FROM params x
    JOIN auth ON auth.id = x.auth_id
),
delete_result AS (
    DELETE FROM auth
    WHERE id = (SELECT auth_id FROM params)
    RETURNING id
)
SELECT 
    aec.auth_exists::boolean as auth_exists,
    aec.auth_exists::boolean as success,
    COALESCE(ai.name, '')::text as name,
    (COALESCE(ai.name, 'Unknown') || ' deleted successfully')::text as message,
    ap.actor_name::text as actor_name
FROM auth_exists_check aec
CROSS JOIN actor_profile ap
LEFT JOIN auth_info ai ON true
$$;


--
-- Name: api_delete_cohort_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_delete_cohort_v4(cohort_id uuid, profile_id uuid) RETURNS TABLE(usage_count bigint, deleted boolean, title text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT
        cohort_id AS cohort_id,
        profile_id AS profile_id
),
actor_profile AS (
    SELECT 
        x.profile_id AS profile_id,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
usage_check AS (
    SELECT COUNT(*) as usage_count
    FROM params x
    JOIN cohort_profiles cp ON cp.cohort_id = x.cohort_id
),
delete_result AS (
    DELETE FROM cohorts c
    USING params x
    CROSS JOIN usage_check uc
    WHERE c.id = x.cohort_id 
      AND uc.usage_count = 0
    RETURNING c.id, c.title
)
SELECT 
    uc.usage_count,
    CASE WHEN EXISTS(SELECT 1 FROM delete_result) THEN true ELSE false END as deleted,
    COALESCE((SELECT title FROM delete_result LIMIT 1), (SELECT title FROM params x JOIN cohorts c ON c.id = x.cohort_id LIMIT 1)) as title,
    ap.actor_name
FROM actor_profile ap
CROSS JOIN usage_check uc
$$;


--
-- Name: api_delete_department_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_delete_department_v4(department_id uuid, profile_id uuid) RETURNS TABLE(department_exists boolean, deleted boolean, total_usage bigint, title text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        department_id AS department_id,
        profile_id AS profile_id
),
department_exists_check AS (
    -- Check if department exists independently of deletion
    SELECT EXISTS(
        SELECT 1 FROM departments WHERE id = (SELECT department_id FROM params)
    )::boolean as department_exists
),
actor_profile AS (
    SELECT 
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
department_info AS (
    -- Check if department exists and get usage counts
    SELECT 
        d.id,
        d.title,
        (SELECT COUNT(*) FROM simulation_departments WHERE department_id = d.id AND active = true) as simulation_count,
        (SELECT COUNT(*) FROM scenario_departments WHERE department_id = d.id AND active = true) as scenario_count,
        (SELECT COUNT(*) FROM persona_departments WHERE department_id = d.id AND active = true) as persona_count,
        (SELECT COUNT(*) FROM document_departments WHERE department_id = d.id AND active = true) as document_count,
        (SELECT COUNT(*) FROM cohort_departments WHERE department_id = d.id AND active = true) as cohort_count
    FROM departments d
    WHERE d.id = (SELECT department_id FROM params)
),
usage_summary AS (
    -- Calculate total usage
    SELECT 
        id,
        title,
        simulation_count,
        scenario_count,
        persona_count,
        document_count,
        cohort_count,
        (simulation_count + scenario_count + persona_count + document_count + cohort_count) as total_usage
    FROM department_info
),
delete_department AS (
    -- Delete department only if it exists and is not in use
    DELETE FROM departments
    WHERE id IN (
        SELECT id FROM usage_summary WHERE total_usage = 0
    )
    RETURNING id
)
-- Return department info and usage counts (even if not deleted, so caller can determine error)
SELECT 
    dec.department_exists::boolean as department_exists,
    CASE WHEN dd.id IS NOT NULL THEN true ELSE false END::boolean as deleted,
    COALESCE(us.total_usage, 0)::bigint as total_usage,
    COALESCE(us.title, '')::text as title,
    ap.actor_name::text as actor_name
FROM department_exists_check dec
CROSS JOIN actor_profile ap
LEFT JOIN usage_summary us ON dec.department_exists = true
LEFT JOIN delete_department dd ON dd.id = us.id AND us.total_usage = 0
$$;


--
-- Name: api_delete_document_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_delete_document_v4(document_id uuid, profile_id uuid) RETURNS TABLE(success boolean, message text, document_id uuid, document_name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT document_id AS document_id,
           profile_id AS profile_id
),
actor_profile AS (
    SELECT 
        p.id as profile_id,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
document_info AS (
    SELECT id, name FROM documents WHERE id = (SELECT document_id FROM params)
),
delete_result AS (
    DELETE FROM documents WHERE id = (SELECT document_id FROM params)
    RETURNING id
)
SELECT 
    true::boolean as success,
    'Document deleted successfully'::text as message,
    di.id as document_id,
    di.name as document_name,
    ap.actor_name
FROM document_info di
CROSS JOIN actor_profile ap
WHERE EXISTS (SELECT 1 FROM delete_result)
LIMIT 1
$$;


--
-- Name: api_delete_eval_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_delete_eval_v4(eval_id uuid, profile_id uuid) RETURNS TABLE(eval_id uuid, eval_name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        eval_id AS eval_id,
        profile_id AS profile_id
),
actor_profile AS (
    SELECT
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
eval_info AS (
    SELECT id as eval_id, name as eval_name 
    FROM params x
    JOIN evals ON evals.id = x.eval_id
),
delete_eval AS (
    DELETE FROM evals
    USING params p
    WHERE evals.id = p.eval_id
    RETURNING evals.id as eval_id
)
SELECT ei.eval_id, ei.eval_name, ap.actor_name::text as actor_name
FROM eval_info ei
CROSS JOIN actor_profile ap
WHERE EXISTS (SELECT 1 FROM delete_eval)
$$;


--
-- Name: api_delete_field_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_delete_field_v4(field_id uuid, profile_id uuid) RETURNS TABLE(field_exists boolean, name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT
        field_id AS field_id,
        profile_id AS profile_id
),
field_exists_check AS (
    -- Check if field exists independently of access control
    SELECT EXISTS(
        SELECT 1 FROM fields WHERE id = (SELECT field_id FROM params)
    )::boolean as field_exists
),
user_profile AS (
    SELECT p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
field_to_delete AS (
    SELECT 
        f.id,
        f.name
    FROM params x
    JOIN fields f ON f.id = x.field_id
),
deleted_field AS (
    -- Delete field (cascade deletes parameter_fields and field_departments)
    DELETE FROM fields
    WHERE id = (SELECT id FROM field_to_delete)
    RETURNING id, (SELECT name FROM field_to_delete) as name
)
SELECT 
    fec.field_exists::boolean as field_exists,
    df.name,
    up.actor_name
FROM field_exists_check fec
CROSS JOIN user_profile up
LEFT JOIN deleted_field df ON fec.field_exists = true
$$;


--
-- Name: api_delete_key_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_delete_key_v4(key_id uuid, profile_id uuid) RETURNS TABLE(key_exists boolean, key_id uuid, name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT key_id AS key_id, profile_id AS profile_id
),
key_exists_check AS (
    SELECT EXISTS(
        SELECT 1 FROM keys WHERE id = (SELECT key_id FROM params)
    )::boolean as key_exists
),
actor_profile AS (
    SELECT 
        p.id as profile_id,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
user_profile AS (
    SELECT role 
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
key_info AS (
    SELECT id, name FROM params x
    JOIN keys k ON k.id = x.key_id
),
department_keys_data AS (
    -- NOTE: department_keys table was removed in migration 74
    SELECT ARRAY[]::text[] as department_ids
),
user_departments AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.active = true
),
check_permissions AS (
    SELECT 
        CASE 
            -- Default keys (no department_ids) can only be deleted by superadmin
            WHEN COALESCE(kdd.department_ids, NULL) IS NULL AND up.role != 'superadmin' THEN false
            WHEN up.role = 'superadmin'::profile_role THEN true
            WHEN up.role = 'admin'::profile_role THEN true
            ELSE false
        END as can_delete
    FROM user_profile up
    CROSS JOIN department_keys_data kdd
    GROUP BY up.role, kdd.department_ids
),
delete_key AS (
    DELETE FROM keys
    WHERE id = (SELECT key_id FROM params)
    AND EXISTS (SELECT 1 FROM check_permissions WHERE can_delete = true)
    RETURNING id
)
SELECT 
    kec.key_exists::boolean as key_exists,
    COALESCE(ki.id, (SELECT key_id FROM params))::uuid as key_id,
    COALESCE(ki.name, '')::text as name,
    ap.actor_name::text as actor_name
FROM key_exists_check kec
CROSS JOIN actor_profile ap
LEFT JOIN key_info ki ON true
LEFT JOIN delete_key dk ON dk.id = ki.id
WHERE kec.key_exists = true
$$;


--
-- Name: api_delete_model_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_delete_model_v4(model_id uuid, profile_id uuid) RETURNS TABLE(model_exists boolean, deleted boolean, name text, actor_name text, personas_usage_count bigint, agents_usage_count bigint)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT model_id AS model_id, profile_id AS profile_id
),
model_exists_check AS (
    SELECT EXISTS(SELECT 1 FROM models WHERE id = (SELECT model_id FROM params))::boolean as model_exists
),
actor_profile AS (
    SELECT 
        (SELECT profile_id FROM params)::uuid as profile_id,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM profiles p
    WHERE p.id = (SELECT profile_id FROM params)::uuid
),
personas_usage_check AS (
    -- Personas are no longer directly linked to models (persona_text_model dropped in migration 44)
    -- So there's no direct usage check needed for personas
    SELECT 0::bigint as usage_count
),
agents_usage_check AS (
    SELECT COUNT(*)::bigint as usage_count
    FROM agents
    WHERE model_id = (SELECT model_id FROM params)
),
model_info AS (
    SELECT name FROM models WHERE id = (SELECT model_id FROM params)
),
delete_result AS (
    DELETE FROM models 
    WHERE id = (SELECT model_id FROM params)
      AND (SELECT usage_count FROM personas_usage_check) = 0
      AND (SELECT usage_count FROM agents_usage_check) = 0
      AND EXISTS(SELECT 1 FROM model_info)
    RETURNING id
)
SELECT 
    mec.model_exists::boolean as model_exists,
    CASE WHEN EXISTS(SELECT 1 FROM delete_result) THEN true ELSE false END::boolean as deleted,
    COALESCE(mi.name, '')::text as name,
    ap.actor_name::text as actor_name,
    (SELECT usage_count FROM personas_usage_check)::bigint as personas_usage_count,
    (SELECT usage_count FROM agents_usage_check)::bigint as agents_usage_count
FROM model_exists_check mec
CROSS JOIN actor_profile ap
LEFT JOIN model_info mi ON true
$$;


--
-- Name: api_delete_parameter_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_delete_parameter_v4(parameter_id uuid, profile_id uuid) RETURNS TABLE(parameter_exists boolean, usage_count bigint, name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        parameter_id AS parameter_id,
        profile_id AS profile_id
),
parameter_exists_check AS (
    -- Check if parameter exists independently of access control
    SELECT EXISTS(
        SELECT 1 FROM parameters WHERE id = (SELECT parameter_id FROM params)
    )::boolean as parameter_exists
),
actor_profile AS (
    SELECT 
        (SELECT profile_id FROM params) as profile_id,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
usage_check AS (
    SELECT COUNT(DISTINCT sf.scenario_id) as usage_count
    FROM params x
    JOIN parameter_fields fp ON fp.parameter_id = x.parameter_id AND fp.active = true
    JOIN scenario_fields sf ON sf.field_id = fp.field_id AND sf.active = true
),
parameter_info AS (
    SELECT 
        p.name,
        COALESCE(uc.usage_count, 0) as usage_count
    FROM params x
    JOIN parameters p ON p.id = x.parameter_id
    CROSS JOIN usage_check uc
),
delete_parameter AS (
    -- Delete parameter (cascade deletes items and parameter_item_departments)
    DELETE FROM parameters
    WHERE id = (SELECT parameter_id FROM params)
        AND (SELECT usage_count FROM usage_check) = 0
    RETURNING name
)
SELECT 
    (SELECT parameter_exists FROM parameter_exists_check)::boolean as parameter_exists,
    COALESCE(pi.usage_count, 0)::bigint as usage_count,
    pi.name::text as name,
    ap.actor_name::text as actor_name
FROM parameter_exists_check pec
CROSS JOIN actor_profile ap
LEFT JOIN parameter_info pi ON pec.parameter_exists = true
LEFT JOIN delete_parameter dp ON dp.name = pi.name AND pec.parameter_exists = true
$$;


--
-- Name: api_delete_persona_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_delete_persona_v4(persona_id uuid, profile_id uuid) RETURNS TABLE(usage_count bigint, name text, deleted boolean, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT persona_id AS persona_id,
           profile_id AS profile_id
),
user_profile AS (
    SELECT 
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
usage_check AS (
    SELECT COUNT(*)::bigint as usage_count
    FROM params x
    JOIN scenario_personas sp ON sp.persona_id = x.persona_id AND sp.active = true
),
persona_info AS (
    SELECT name FROM params x
    JOIN personas p ON p.id = x.persona_id
),
delete_result AS (
    DELETE FROM personas 
    WHERE id = (SELECT persona_id FROM params)
      AND (SELECT usage_count FROM usage_check) = 0
      AND EXISTS(SELECT 1 FROM persona_info)
    RETURNING id
)
SELECT 
    (SELECT usage_count FROM usage_check) as usage_count,
    (SELECT name FROM persona_info) as name,
    CASE WHEN EXISTS(SELECT 1 FROM delete_result) THEN true ELSE false END as deleted,
    (SELECT actor_name FROM user_profile) as actor_name
$$;


--
-- Name: api_delete_profile_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_delete_profile_v4(target_profile_id uuid, current_profile_id uuid) RETURNS TABLE(profile_exists boolean, profile_id uuid, first_name text, last_name text, name text, deleted boolean, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT target_profile_id AS target_profile_id,
           current_profile_id AS current_profile_id
),
profile_exists_check AS (
    -- Check if profile exists independently of deletion
    SELECT EXISTS(SELECT 1 FROM profiles WHERE id = (SELECT target_profile_id FROM params))::boolean as profile_exists
),
actor_profile AS (
    SELECT 
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.current_profile_id
),
profile_check AS (
    -- Check if profile exists and get details
    SELECT 
        id,
        first_name,
        last_name,
        first_name || ' ' || last_name as name
    FROM profiles 
    WHERE id = (SELECT target_profile_id FROM params)
),
profile_delete AS (
    -- Delete profile (only if exists)
    DELETE FROM profiles
    WHERE id = (SELECT target_profile_id FROM params)
        AND EXISTS (SELECT 1 FROM profile_check)
    RETURNING id, first_name, last_name, first_name || ' ' || last_name as name
)
-- Return profile info with deletion status
SELECT 
    pec.profile_exists::boolean as profile_exists,
    pc.id as profile_id,
    pc.first_name,
    pc.last_name,
    pc.name,
    CASE WHEN pd.id IS NOT NULL THEN true ELSE false END as deleted,
    ap.actor_name
FROM profile_exists_check pec
CROSS JOIN actor_profile ap
LEFT JOIN profile_check pc ON pec.profile_exists = true
LEFT JOIN profile_delete pd ON pd.id = pc.id
LIMIT 1
$$;


--
-- Name: api_delete_prompt_v4(uuid, uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_delete_prompt_v4(agent_id uuid, prompt_id uuid, profile_id uuid, department_id uuid DEFAULT NULL::uuid) RETURNS TABLE(prompt_name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        agent_id AS agent_id,
        prompt_id AS prompt_id,
        department_id AS department_id,
        profile_id AS profile_id
),
actor_profile AS (
    SELECT
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
prompt_name_lookup AS (
    SELECT name as prompt_name 
    FROM params x
    JOIN prompts p ON p.id = x.prompt_id
),
prompt_info AS (
    -- Check if this prompt is active (default or department-specific)
    SELECT 
        CASE WHEN EXISTS (
            SELECT 1 FROM agent_prompts 
            WHERE agent_id = (SELECT agent_id FROM params) 
            AND prompt_id = (SELECT prompt_id FROM params) 
            AND active = true
        ) THEN 'default' ELSE 'none' END as default_status,
        CASE WHEN (SELECT department_id FROM params) IS NOT NULL AND EXISTS (
            SELECT 1 FROM agent_department_prompts 
            WHERE agent_id = (SELECT agent_id FROM params) 
            AND prompt_id = (SELECT prompt_id FROM params) 
            AND department_id = (SELECT department_id FROM params) 
            AND active = true
        ) THEN true ELSE false END as is_dept_active
),
latest_default_prompt AS (
    -- Get the latest default prompt (by updated_at) for fallback
    SELECT prompt_id::text
    FROM agent_prompts ap
    JOIN prompts pr ON pr.id = ap.prompt_id
    WHERE ap.agent_id = (SELECT agent_id FROM params)
    AND ap.prompt_id != (SELECT prompt_id FROM params)
    ORDER BY pr.updated_at DESC
    LIMIT 1
),
deactivate_and_fallback AS (
    -- Handle active prompt deactivation and fallback
    UPDATE agent_prompts
    SET active = false, updated_at = NOW()
    WHERE agent_id = (SELECT agent_id FROM params)
    AND prompt_id = (SELECT prompt_id FROM params)
    AND active = true
    AND (SELECT default_status FROM prompt_info) = 'default'
    RETURNING 1
),
activate_latest_default AS (
    -- Activate latest default prompt if we deleted an active default prompt
    UPDATE agent_prompts
    SET active = true, updated_at = NOW()
    WHERE agent_id = (SELECT agent_id FROM params)
    AND prompt_id = (SELECT prompt_id::uuid FROM latest_default_prompt)
    AND EXISTS (SELECT 1 FROM deactivate_and_fallback)
),
deactivate_dept_prompt AS (
    -- Deactivate department-specific prompt link
    UPDATE agent_department_prompts
    SET active = false, updated_at = NOW()
    WHERE agent_id = (SELECT agent_id FROM params)
    AND prompt_id = (SELECT prompt_id FROM params)
    AND ((SELECT department_id FROM params) IS NULL OR department_id = (SELECT department_id FROM params))
    AND active = true
    RETURNING prompt_id
),
delete_agent_prompt_links AS (
    -- Delete default prompt link (if not already deactivated)
    DELETE FROM agent_prompts
    WHERE agent_id = (SELECT agent_id FROM params)
    AND prompt_id = (SELECT prompt_id FROM params)
    AND NOT EXISTS (SELECT 1 FROM deactivate_and_fallback)
),
delete_dept_prompt_links AS (
    -- Delete department-specific prompt links
    -- Delete if already inactive OR if we just deactivated them
    DELETE FROM agent_department_prompts
    WHERE agent_id = (SELECT agent_id FROM params)
    AND prompt_id = (SELECT prompt_id FROM params)
    AND ((SELECT department_id FROM params) IS NULL OR department_id = (SELECT department_id FROM params))
    AND (
        active = false 
        OR EXISTS (SELECT 1 FROM deactivate_dept_prompt)
    )
),
check_other_links AS (
    -- Check if prompt is linked elsewhere (other agents or persona tables)
    SELECT 
        CASE WHEN EXISTS (
            SELECT 1 FROM agent_prompts WHERE prompt_id = (SELECT prompt_id FROM params)
            UNION ALL
            SELECT 1 FROM agent_department_prompts WHERE prompt_id = (SELECT prompt_id FROM params) AND active = true
        ) THEN false ELSE true END as can_delete_prompt
),
deleted_prompt AS (
    -- Delete prompt record if no other links exist
    DELETE FROM prompts
    WHERE id = (SELECT prompt_id FROM params)
    AND (SELECT can_delete_prompt FROM check_other_links) = true
    RETURNING id
)
SELECT 
    COALESCE((SELECT prompt_name FROM prompt_name_lookup), 'Unknown') as prompt_name,
    COALESCE((SELECT actor_name FROM actor_profile), '') as actor_name
FROM params
$$;


--
-- Name: api_delete_provider_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_delete_provider_v4(provider_id uuid, profile_id uuid) RETURNS TABLE(provider_exists boolean, provider_id uuid, name text, actor_name text, deleted boolean)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT provider_id AS provider_id, profile_id AS profile_id
),
provider_exists_check AS (
    -- Check if provider exists independently of access control
    SELECT EXISTS(
        SELECT 1 FROM providers WHERE id = (SELECT provider_id FROM params)
    )::boolean as provider_exists
),
actor_profile AS (
    SELECT 
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
provider_info AS (
    SELECT id, name 
    FROM params x
    JOIN providers ON providers.id = x.provider_id
),
user_profile AS (
    SELECT role 
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
check_usage AS (
    -- Check if provider is used by models
    SELECT EXISTS(
        SELECT 1 FROM models m 
        WHERE m.provider_id = (SELECT provider_id FROM params) AND m.active = true
    ) as is_used
),
check_permissions AS (
    SELECT 
        CASE 
            WHEN cu.is_used THEN false
            WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_delete
    FROM user_profile up
    CROSS JOIN check_usage cu
),
delete_provider AS (
    DELETE FROM providers
    WHERE providers.id = (SELECT provider_id FROM params)
    AND EXISTS (SELECT 1 FROM check_permissions WHERE can_delete = true)
    AND NOT EXISTS (SELECT 1 FROM check_usage WHERE is_used = true)
    RETURNING id
)
SELECT 
    pec.provider_exists::boolean as provider_exists,
    pi.id as provider_id,
    pi.name::text as name,
    ap.actor_name::text as actor_name,
    CASE WHEN EXISTS(SELECT 1 FROM delete_provider) THEN true ELSE false END::boolean as deleted
FROM provider_exists_check pec
LEFT JOIN provider_info pi ON pec.provider_exists = true
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_delete_rubric_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_delete_rubric_v4(rubric_id uuid, profile_id uuid) RETURNS TABLE(rubric_id uuid, name text, usage_count bigint, deleted boolean, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT rubric_id AS rubric_id, profile_id AS profile_id
),
actor_profile AS (
    SELECT
        x.profile_id,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
rubric_info AS (
    SELECT 
        r.id,
        r.name,
        (SELECT COUNT(DISTINCT ss.simulation_id) FROM simulation_scenarios ss 
         JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
         JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
         WHERE rga.rubric_id = r.id AND ss.active = true) as usage_count
    FROM rubrics r
    WHERE r.id = (SELECT rubric_id FROM params)
),
delete_rubric AS (
    DELETE FROM rubrics
    WHERE id IN (
        SELECT id FROM rubric_info WHERE usage_count = 0
    )
    RETURNING id as rubric_id
)
SELECT 
    ri.id as rubric_id,
    ri.name,
    ri.usage_count,
    CASE WHEN dr.rubric_id IS NOT NULL THEN true ELSE false END as deleted,
    ap.actor_name
FROM rubric_info ri
LEFT JOIN delete_rubric dr ON dr.rubric_id = ri.id
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_delete_scenario_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_delete_scenario_v4(scenario_id uuid, profile_id uuid) RETURNS TABLE(scenario_exists boolean, scenario_id uuid, name text, usage_count bigint, deleted boolean, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT scenario_id AS scenario_id, profile_id AS profile_id
),
actor_profile AS (
    SELECT 
        p.id as resolved_profile_id,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
scenario_exists_check AS (
    SELECT EXISTS(
        SELECT 1 FROM scenarios WHERE id = (SELECT scenario_id FROM params)
    )::boolean as scenario_exists
),
scenario_info AS (
    -- Check if scenario exists and get name
    SELECT 
        s.id,
        s.name,
        (SELECT COUNT(*) FROM simulation_scenarios WHERE scenario_id = s.id AND active = true) as usage_count
    FROM scenarios s
    WHERE s.id = (SELECT scenario_id FROM params)
),
delete_scenario AS (
    -- Delete scenario only if it exists and is not in use
    DELETE FROM scenarios
    WHERE id IN (
        SELECT id FROM scenario_info WHERE usage_count = 0
    )
    RETURNING id, name
)
-- Return scenario info (even if not deleted, so caller can determine error)
SELECT 
    sec.scenario_exists::boolean as scenario_exists,
    si.id as scenario_id,
    si.name::text as name,
    si.usage_count::bigint as usage_count,
    CASE WHEN ds.id IS NOT NULL THEN true ELSE false END as deleted,
    ap.actor_name::text as actor_name
FROM scenario_exists_check sec
LEFT JOIN scenario_info si ON sec.scenario_exists = true
LEFT JOIN delete_scenario ds ON ds.id = si.id
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_delete_simulation_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_delete_simulation_v4(simulation_id uuid, profile_id uuid) RETURNS TABLE(deleted boolean, usage_count bigint, title text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT simulation_id AS simulation_id,
           profile_id AS profile_id
),
actor_profile AS (
    SELECT 
        x.profile_id,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
simulation_info AS (
    SELECT 
        s.id,
        s.title,
        (SELECT COUNT(*) FROM cohort_simulations WHERE cohort_simulations.simulation_id = s.id) as usage_count
    FROM params x
    JOIN simulations s ON s.id = x.simulation_id
),
delete_simulation AS (
    DELETE FROM simulations
    WHERE id IN (
        SELECT id FROM simulation_info WHERE usage_count = 0
    )
    RETURNING id
)
SELECT 
    CASE WHEN ds.id IS NOT NULL THEN true ELSE false END as deleted,
    si.usage_count,
    si.title::text as title,
    ap.actor_name::text as actor_name
FROM simulation_info si
LEFT JOIN delete_simulation ds ON ds.id = si.id
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_duplicate_agent_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_duplicate_agent_v4(agent_id uuid, profile_id uuid) RETURNS TABLE(agent_id text, agent_name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT agent_id AS agent_id,
           profile_id AS profile_id
),
actor_profile AS (
    SELECT 
        x.profile_id,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
source_agent AS (
    SELECT 
        a.id as source_id,
        a.name,
        a.description,
        a.model_id,
        a.role,
        ap.prompt_id,
        COALESCE(pr.system_prompt, '') as system_prompt,
        -- Get temperature and reasoning from junction tables
        atl.model_temperature_level_id,
        arl.model_reasoning_level_id
    FROM params x
    JOIN agents a ON a.id = x.agent_id
    LEFT JOIN agent_prompts ap ON ap.agent_id = a.id AND ap.active = true
    LEFT JOIN prompts pr ON pr.id = ap.prompt_id
    LEFT JOIN agent_temperature_levels atl ON atl.agent_id = a.id AND atl.active = true
    LEFT JOIN agent_reasoning_levels arl ON arl.agent_id = a.id AND arl.active = true
),
new_prompt AS (
    INSERT INTO prompts (name, description, system_prompt, created_at, updated_at)
    SELECT 
        COALESCE(pr.name, 'Agent Prompt') || ' Copy',
        COALESCE(pr.description, ''),
        sa.system_prompt, 
        NOW(), 
        NOW()
    FROM source_agent sa
    LEFT JOIN prompts pr ON pr.id = sa.prompt_id
    RETURNING id as prompt_id
),
new_agent AS (
    INSERT INTO agents (name, description, model_id, active, role, created_at, updated_at)
    SELECT 
        sa.name || ' Copy',
        sa.description,
        sa.model_id,
        false,
        sa.role,
        NOW(),
        NOW()
    FROM source_agent sa
    RETURNING id::text as agent_id
),
copy_temperature AS (
    INSERT INTO agent_temperature_levels (agent_id, model_temperature_level_id, active, created_at, updated_at)
    SELECT 
        na.agent_id::uuid,
        sa.model_temperature_level_id,
        true,
        NOW(),
        NOW()
    FROM source_agent sa
    CROSS JOIN new_agent na
    WHERE sa.model_temperature_level_id IS NOT NULL
),
copy_reasoning AS (
    INSERT INTO agent_reasoning_levels (agent_id, model_reasoning_level_id, active, created_at, updated_at)
    SELECT 
        na.agent_id::uuid,
        sa.model_reasoning_level_id,
        true,
        NOW(),
        NOW()
    FROM source_agent sa
    CROSS JOIN new_agent na
    WHERE sa.model_reasoning_level_id IS NOT NULL
),
link_prompt AS (
    INSERT INTO agent_prompts (agent_id, prompt_id, active, created_at, updated_at)
    SELECT na.agent_id::uuid, np.prompt_id, true, NOW(), NOW()
    FROM new_agent na
    CROSS JOIN new_prompt np
),
copy_departments AS (
    INSERT INTO agent_departments (agent_id, department_id, active, created_at, updated_at)
    SELECT 
        na.agent_id::uuid,
        ad.department_id,
        ad.active,
        NOW(),
        NOW()
    FROM source_agent sa
    JOIN agent_departments ad ON ad.agent_id = sa.source_id AND ad.active = true
    CROSS JOIN new_agent na
)
SELECT 
    na.agent_id,
    sa.name as agent_name,
    ap.actor_name
FROM new_agent na
CROSS JOIN source_agent sa
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_duplicate_auth_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_duplicate_auth_v4(auth_id uuid, profile_id uuid) RETURNS TABLE(auth_exists boolean, success boolean, auth_id uuid, original_name text, message text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT auth_id AS auth_id,
           profile_id AS profile_id
),
auth_exists_check AS (
    -- Check if auth exists before duplication
    SELECT EXISTS(
        SELECT 1 FROM auth WHERE id = (SELECT auth_id FROM params)
    )::boolean as auth_exists
),
actor_profile AS (
    SELECT 
        x.profile_id as profile_id,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
source_auth AS (
    SELECT id, name, description, active, auth_type, slug
    FROM params x
    JOIN auth ON auth.id = x.auth_id
),
new_auth AS (
    INSERT INTO auth (
        name,
        description,
        active,
        auth_type,
        slug
    )
    SELECT 
        name || ' (Copy)',
        description,
        active,
        auth_type,
        slug || '-copy'
    FROM source_auth
    RETURNING id as auth_id
),
source_items AS (
    SELECT 
        ai.name,
        ai.description,
        ai.encrypted,
        ai.position,
        ai.active
    FROM source_auth sa
    JOIN auth_items ai ON ai.auth_id = sa.id
),
new_items AS (
    INSERT INTO auth_items (
        auth_id,
        name,
        description,
        encrypted,
        position,
        active
    )
    SELECT 
        na.auth_id,
        si.name,
        si.description,
        si.encrypted,
        si.position,
        si.active
    FROM new_auth na
    CROSS JOIN source_items si
    RETURNING id as item_id
)
SELECT 
    aec.auth_exists::boolean as auth_exists,
    aec.auth_exists::boolean as success,
    na.auth_id,
    sa.name::text as original_name,
    (sa.name || ' duplicated successfully')::text as message,
    ap.actor_name::text as actor_name
FROM auth_exists_check aec
CROSS JOIN actor_profile ap
LEFT JOIN source_auth sa ON true
LEFT JOIN new_auth na ON true
$$;


--
-- Name: api_duplicate_cohort_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_duplicate_cohort_v4(cohort_id uuid, profile_id uuid) RETURNS TABLE(id uuid, title text, original_title text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT
        cohort_id AS cohort_id,
        profile_id AS profile_id
),
actor_profile AS (
    SELECT 
        x.profile_id AS profile_id,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
original_cohort AS (
    -- Get original cohort data
    SELECT 
        id,
        title,
        description
    FROM params x
    JOIN cohorts c ON c.id = x.cohort_id
),
new_cohort AS (
    -- Create duplicate cohort
    INSERT INTO cohorts (
        title,
        description,
        active
    )
    SELECT 
        oc.title || ' Copy',
        oc.description,
        false
    FROM original_cohort oc
    RETURNING id, title, description
),
copy_profiles AS (
    -- Copy profile relationships
    INSERT INTO cohort_profiles (cohort_id, profile_id, active)
    SELECT 
        nc.id,
        cp.profile_id,
        cp.active
    FROM new_cohort nc
    CROSS JOIN original_cohort oc
    JOIN cohort_profiles cp ON cp.cohort_id = oc.id
),
copy_simulations AS (
    -- Copy simulation relationships with position
    INSERT INTO cohort_simulations (cohort_id, simulation_id, active, position)
    SELECT 
        nc.id,
        cs.simulation_id,
        cs.active,
        cs.position
    FROM new_cohort nc
    CROSS JOIN original_cohort oc
    JOIN cohort_simulations cs ON cs.cohort_id = oc.id
),
copy_departments AS (
    -- Copy department relationships
    INSERT INTO cohort_departments (cohort_id, department_id, active, created_at, updated_at)
    SELECT 
        nc.id,
        cd.department_id,
        cd.active,
        NOW(),
        NOW()
    FROM new_cohort nc
    CROSS JOIN original_cohort oc
    JOIN cohort_departments cd ON cd.cohort_id = oc.id AND cd.active = true
)
-- Return new cohort info
SELECT 
    nc.id,
    nc.title,
    oc.title as original_title,
    ap.actor_name
FROM new_cohort nc
CROSS JOIN original_cohort oc
CROSS JOIN actor_profile ap
LIMIT 1
$$;


--
-- Name: api_duplicate_department_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_duplicate_department_v4(department_id uuid, profile_id uuid) RETURNS TABLE(new_department_id uuid, original_title text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        department_id AS department_id,
        profile_id AS profile_id
),
actor_profile AS (
    SELECT 
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
original_dept AS (
    SELECT 
        id,
        title,
        description,
        active
    FROM departments
    WHERE id = (SELECT department_id FROM params)
),
new_dept AS (
    INSERT INTO departments (title, description, active, created_at, updated_at)
    SELECT 
        title || ' Copy',
        description,
        false,
        NOW(),
        NOW()
    FROM original_dept
    RETURNING id
)
SELECT 
    nd.id as new_department_id,
    od.title::text as original_title,
    ap.actor_name::text as actor_name
FROM new_dept nd
CROSS JOIN original_dept od
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_duplicate_field_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_duplicate_field_v4(field_id uuid, profile_id uuid) RETURNS TABLE(field_exists boolean, field_id uuid, field_name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT
        field_id AS field_id,
        profile_id AS profile_id
),
field_exists_check AS (
    -- Check if field exists independently of access control
    SELECT EXISTS(
        SELECT 1 FROM fields WHERE id = (SELECT field_id FROM params)
    )::boolean as field_exists
),
user_profile AS (
    SELECT p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
original_field AS (
    SELECT 
        f.id,
        f.name,
        f.description
    FROM params x
    JOIN fields f ON f.id = x.field_id
),
original_parameters AS (
    SELECT fp.parameter_id
    FROM params x
    JOIN parameter_fields fp ON fp.field_id = x.field_id AND fp.active = true
),
original_departments AS (
    SELECT fd.department_id
    FROM params x
    JOIN field_departments fd ON fd.field_id = x.field_id AND fd.active = true
),
new_field AS (
    INSERT INTO fields (
        name,
        description
    )
    SELECT 
        orig.name || ' (Copy)',
        orig.description
    FROM original_field orig
    RETURNING id as field_id, name as field_name
),
link_parameters AS (
    -- Link new field to same parameters as original
    INSERT INTO parameter_fields (field_id, parameter_id, active, created_at, updated_at)
    SELECT 
        nf.field_id,
        op.parameter_id,
        true,
        NOW(),
        NOW()
    FROM new_field nf
    CROSS JOIN original_parameters op
    ON CONFLICT (field_id, parameter_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
link_departments AS (
    -- Link new field to same departments as original
    INSERT INTO field_departments (field_id, department_id, active, created_at, updated_at)
    SELECT 
        nf.field_id,
        od.department_id,
        true,
        NOW(),
        NOW()
    FROM new_field nf
    CROSS JOIN original_departments od
    ON CONFLICT (field_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
)
SELECT 
    fec.field_exists::boolean as field_exists,
    nf.field_id,
    nf.field_name,
    up.actor_name
FROM field_exists_check fec
CROSS JOIN user_profile up
LEFT JOIN new_field nf ON fec.field_exists = true
$$;


--
-- Name: api_duplicate_model_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_duplicate_model_v4(model_id uuid, profile_id uuid) RETURNS TABLE(model_exists boolean, model_id uuid, original_name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT model_id AS model_id, profile_id AS profile_id
),
model_exists_check AS (
    SELECT EXISTS(SELECT 1 FROM models WHERE id = (SELECT model_id FROM params))::boolean as model_exists
),
actor_profile AS (
    SELECT 
        x.profile_id,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
source_model AS (
    SELECT 
        m.name,
        m.description,
        m.active,
        m.provider_id,
        m.value
    FROM params x
    JOIN models m ON m.id = x.model_id
),
duplicated_model AS (
    INSERT INTO models (
        provider_id,
        name,
        description,
        active,
        value
    )
    SELECT 
        sm.provider_id,
        sm.name,
        sm.description || ' Copy',
        sm.active,
        sm.value
    FROM source_model sm
    CROSS JOIN model_exists_check mec
    WHERE mec.model_exists = true
    RETURNING id
)
SELECT 
    mec.model_exists::boolean as model_exists,
    dm.id as model_id,
    sm.name::text as original_name,
    ap.actor_name::text as actor_name
FROM model_exists_check mec
CROSS JOIN source_model sm
CROSS JOIN duplicated_model dm
CROSS JOIN actor_profile ap
WHERE mec.model_exists = true
LIMIT 1
$$;


--
-- Name: api_duplicate_parameter_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_duplicate_parameter_v4(parameter_id uuid, profile_id uuid) RETURNS TABLE(parameter_id uuid, original_name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        parameter_id AS parameter_id,
        profile_id AS profile_id
),
actor_profile AS (
    SELECT 
        (SELECT profile_id FROM params) as profile_id,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
original_parameter AS (
    SELECT 
        name,
        description,
        COALESCE(simulation_parameter, false) as simulation_parameter,
        COALESCE(document_parameter, false) as document_parameter,
        COALESCE(persona_parameter, false) as persona_parameter,
        COALESCE(scenario_parameter, false) as scenario_parameter,
        COALESCE(video_parameter, false) as video_parameter
    FROM params x
    JOIN parameters ON parameters.id = x.parameter_id
),
new_parameter AS (
    INSERT INTO parameters (
        name,
        description,
        active,
        simulation_parameter,
        document_parameter,
        persona_parameter,
        scenario_parameter,
        video_parameter
    )
    SELECT 
        op.name || ' Copy',
        op.description,
        false,  -- Duplicated parameters are inactive by default
        op.simulation_parameter,
        op.document_parameter,
        op.persona_parameter,
        op.scenario_parameter,
        op.video_parameter
    FROM original_parameter op
    RETURNING id as parameter_id
),
original_fields AS (
    SELECT 
        f.id as original_field_id,
        f.name,
        f.description
    FROM params x
    JOIN parameter_fields fp ON fp.parameter_id = x.parameter_id AND fp.active = true
    JOIN fields f ON f.id = fp.field_id
),
original_field_departments AS (
    SELECT 
        of.original_field_id,
        COALESCE(ARRAY_AGG(fd.department_id::text ORDER BY fd.created_at) FILTER (WHERE fd.department_id IS NOT NULL), NULL) as department_ids
    FROM original_fields of
    LEFT JOIN field_departments fd ON fd.field_id = of.original_field_id AND fd.active = true
    GROUP BY of.original_field_id
),
new_fields AS (
    -- Create all fields (duplicates of original fields)
    INSERT INTO fields (
        name,
        description
    )
    SELECT 
        of.name,
        of.description
    FROM original_fields of
    RETURNING id as field_id, name as field_name
),
new_fields_with_order AS (
    -- Add row numbers to new fields for matching
    SELECT 
        field_id,
        field_name,
        ROW_NUMBER() OVER (ORDER BY field_name) as field_row_num
    FROM new_fields
),
fields_with_depts AS (
    -- Match new fields with original fields and their department arrays
    -- Use ROW_NUMBER to match fields in order since names might not be unique
    SELECT 
        nf.field_id,
        ofd.department_ids
    FROM new_fields_with_order nf
    JOIN (
        SELECT 
            original_field_id,
            name,
            ROW_NUMBER() OVER (ORDER BY name) as field_row_num
        FROM original_fields
    ) of ON of.field_row_num = nf.field_row_num
    LEFT JOIN original_field_departments ofd ON ofd.original_field_id = of.original_field_id
    WHERE ofd.department_ids IS NOT NULL AND array_length(ofd.department_ids, 1) > 0
),
link_fields_to_parameter AS (
    -- Link new fields to new parameter via parameter_fields junction
    INSERT INTO parameter_fields (field_id, parameter_id, active, created_at, updated_at)
    SELECT 
        fwd.field_id,
        np.parameter_id,
        true,
        NOW(),
        NOW()
    FROM new_parameter np
    CROSS JOIN fields_with_depts fwd
    ON CONFLICT (field_id, parameter_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
link_departments AS (
    -- Link departments to fields if they existed on original (only if dept_ids exist)
    INSERT INTO field_departments (field_id, department_id, active, created_at, updated_at)
    SELECT 
        fwd.field_id,
        dept_id::uuid,
        true,
        NOW(),
        NOW()
    FROM fields_with_depts fwd
    CROSS JOIN UNNEST(fwd.department_ids) as dept_id
    WHERE fwd.department_ids IS NOT NULL AND array_length(fwd.department_ids, 1) > 0
    ON CONFLICT (field_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
)
SELECT 
    np.parameter_id,
    op.name::text as original_name,
    ap.actor_name::text as actor_name
FROM new_parameter np
CROSS JOIN original_parameter op
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_duplicate_persona_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_duplicate_persona_v4(persona_id uuid, profile_id uuid) RETURNS TABLE(new_persona_id uuid, original_name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT persona_id AS persona_id,
           profile_id AS profile_id
),
user_profile AS (
    SELECT 
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
original_persona AS (
    SELECT 
        p.id,
        p.name,
        p.description,
        p.color,
        p.icon
    FROM params x
    JOIN personas p ON p.id = x.persona_id
),
original_departments AS (
    -- Get department IDs from original persona
    SELECT department_id
    FROM params x
    JOIN persona_departments pd ON pd.persona_id = x.persona_id AND pd.active = true
),
new_persona AS (
    INSERT INTO personas (
        name,
        description,
        color,
        icon,
        active,
        created_at,
        updated_at
    )
    SELECT 
        op.name || ' Copy',
        COALESCE(op.description, ''),
        op.color,
        op.icon,
        false,
        NOW(),
        NOW()
    FROM original_persona op
    RETURNING id
),
copy_departments AS (
    -- Copy department links from original persona
    INSERT INTO persona_departments (persona_id, department_id, active, created_at, updated_at)
    SELECT 
        np.id,
        od.department_id,
        true,
        NOW(),
        NOW()
    FROM new_persona np
    CROSS JOIN original_departments od
    RETURNING persona_id
)
SELECT 
    (SELECT id FROM new_persona LIMIT 1) as new_persona_id,
    (SELECT name FROM original_persona LIMIT 1) as original_name,
    (SELECT actor_name FROM user_profile LIMIT 1) as actor_name
$$;


--
-- Name: api_duplicate_rubric_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_duplicate_rubric_v4(original_rubric_id uuid, profile_id uuid) RETURNS TABLE(rubric_id uuid, original_name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT original_rubric_id AS original_rubric_id, profile_id AS profile_id
),
actor_profile AS (
    SELECT
        x.profile_id,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
original_rubric AS (
    SELECT 
        id,
        name,
        description,
        points,
        pass_points
    FROM rubrics
    WHERE id = (SELECT original_rubric_id FROM params)
),
original_departments AS (
    SELECT department_id
    FROM rubric_departments
    WHERE rubric_id = (SELECT original_rubric_id FROM params) AND active = true
),
original_groups AS (
    SELECT 
        sg.id,
        sg.name,
        sg.short_name,
        sg.description,
        sg.points,
        sg.pass_points,
        ROW_NUMBER() OVER (ORDER BY rsg.position, sg.name) as group_order
    FROM rubric_standard_groups rsg
    JOIN standard_groups sg ON sg.id = rsg.standard_group_id
    WHERE rsg.rubric_id = (SELECT original_rubric_id FROM params)
      AND rsg.active = true
),
original_standards AS (
    SELECT 
        s.id,
        s.standard_group_id,
        s.name,
        s.description,
        s.points,
        og.group_order
    FROM standards s
    JOIN original_groups og ON s.standard_group_id = og.id
    ORDER BY og.group_order, s.name
),
new_rubric AS (
    INSERT INTO rubrics (
        name,
        description,
        active,
        points,
        pass_points
    )
    SELECT 
        name || ' Copy',
        description,
        false,
        points,
        pass_points
    FROM original_rubric
    RETURNING id as rubric_id
),
link_departments AS (
    INSERT INTO rubric_departments (rubric_id, department_id, active, created_at, updated_at)
    SELECT 
        nr.rubric_id,
        od.department_id,
        true,
        NOW(),
        NOW()
    FROM new_rubric nr
    CROSS JOIN original_departments od
    WHERE EXISTS (SELECT 1 FROM original_departments)
    ON CONFLICT (rubric_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
new_standard_groups AS (
    INSERT INTO standard_groups (
        name,
        short_name,
        description,
        points,
        pass_points
    )
    SELECT 
        og.name,
        og.short_name,
        og.description,
        og.points,
        og.pass_points
    FROM original_groups og
    RETURNING id, name, short_name, description, points, pass_points
),
link_standard_groups AS (
    INSERT INTO rubric_standard_groups (rubric_id, standard_group_id, position, active, created_at, updated_at)
    SELECT 
        nr.rubric_id,
        nsg.id,
        og.group_order,
        true,
        NOW(),
        NOW()
    FROM new_rubric nr
    CROSS JOIN new_standard_groups nsg
    JOIN original_groups og ON 
        og.name = nsg.name
        AND COALESCE(og.short_name, '') = COALESCE(nsg.short_name, '')
        AND COALESCE(og.description, '') = COALESCE(nsg.description, '')
        AND og.points = nsg.points
        AND og.pass_points = nsg.pass_points
),
new_groups_with_order AS (
    SELECT 
        nsg.*,
        og.group_order
    FROM new_standard_groups nsg
    JOIN original_groups og ON 
        og.name = nsg.name
        AND COALESCE(og.short_name, '') = COALESCE(nsg.short_name, '')
        AND COALESCE(og.description, '') = COALESCE(nsg.description, '')
        AND og.points = nsg.points
        AND og.pass_points = nsg.pass_points
),
groups_mapping AS (
    SELECT DISTINCT ON (og.id)
        og.id as old_group_id,
        ngwo.id as new_group_id
    FROM original_groups og
    JOIN new_groups_with_order ngwo ON 
        ngwo.name = og.name
        AND COALESCE(ngwo.short_name, '') = COALESCE(og.short_name, '')
        AND COALESCE(ngwo.description, '') = COALESCE(og.description, '')
        AND ngwo.points = og.points
        AND ngwo.pass_points = og.pass_points
        AND ngwo.group_order = og.group_order
    ORDER BY og.id, ngwo.id
),
new_standards AS (
    INSERT INTO standards (
        standard_group_id,
        name,
        description,
        points
    )
    SELECT 
        gm.new_group_id,
        os.name,
        os.description,
        os.points
    FROM original_standards os
    JOIN groups_mapping gm ON os.standard_group_id = gm.old_group_id
    RETURNING id
)
SELECT 
    nr.rubric_id,
    or_r.name as original_name,
    ap.actor_name
FROM new_rubric nr
CROSS JOIN original_rubric or_r
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_duplicate_scenario_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_duplicate_scenario_v4(scenario_id uuid, profile_id uuid) RETURNS TABLE(scenario_id uuid, scenario_name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT scenario_id AS scenario_id, profile_id AS profile_id
),
actor_profile AS (
    SELECT 
        p.id as resolved_profile_id,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
source_scenario AS (
    SELECT 
        s.id as source_id,
        s.name,
        s.objectives_enabled,
        s.images_enabled,
        ps.problem_statement,
        ps.id as problem_statement_id,
        ps.name as problem_statement_name
    FROM params x
    JOIN scenarios s ON s.id = x.scenario_id
    LEFT JOIN scenario_problem_statements sps_j ON sps_j.scenario_id = s.id AND sps_j.active = true
    LEFT JOIN problem_statements ps ON ps.id = sps_j.problem_statement_id
),
new_scenario AS (
    INSERT INTO scenarios (
        name,
        active,
        objectives_enabled,
        images_enabled,
        created_at,
        updated_at
    )
    SELECT 
        ss.name || ' Copy',
        false,
        ss.objectives_enabled,
        ss.images_enabled,
        NOW(),
        NOW()
    FROM source_scenario ss
    RETURNING id
),
insert_tree_edge AS (
    INSERT INTO scenario_tree (parent_id, child_id, active, created_at, updated_at)
    SELECT ns.id, ns.id, true, NOW(), NOW()
    FROM new_scenario ns
),
create_problem_statements AS (
    -- Create new problem_statement records (reuse if same text exists, but create new for history)
    INSERT INTO problem_statements (name, problem_statement, created_at, updated_at)
    SELECT DISTINCT
        COALESCE(ps.name, ss.name) as name,
        ps.problem_statement,
        NOW(),
        NOW()
    FROM source_scenario ss
    JOIN scenario_problem_statements sps_j ON sps_j.scenario_id = ss.source_id
    JOIN problem_statements ps ON ps.id = sps_j.problem_statement_id
    CROSS JOIN new_scenario ns
    RETURNING id as problem_statement_id, problem_statement
),
link_problem_statements AS (
    -- Link problem statements to new scenario via junction table
    INSERT INTO scenario_problem_statements (scenario_id, problem_statement_id, active, created_at, updated_at)
    SELECT 
        ns.id,
        cps.problem_statement_id,
        sps_j.active,
        NOW(),
        NOW()
    FROM source_scenario ss
    JOIN scenario_problem_statements sps_j ON sps_j.scenario_id = ss.source_id
    JOIN problem_statements ps ON ps.id = sps_j.problem_statement_id
    JOIN create_problem_statements cps ON cps.problem_statement = ps.problem_statement
    CROSS JOIN new_scenario ns
),
copy_personas AS (
    INSERT INTO scenario_personas (scenario_id, persona_id, active, created_at, updated_at)
    SELECT 
        ns.id,
        sp.persona_id,
        sp.active,
        NOW(),
        NOW()
    FROM source_scenario ss
    JOIN scenario_personas sp ON sp.scenario_id = ss.source_id
    CROSS JOIN new_scenario ns
),
copy_documents AS (
    INSERT INTO scenario_documents (scenario_id, document_id, active, created_at, updated_at)
    SELECT 
        ns.id,
        sd.document_id,
        sd.active,
        NOW(),
        NOW()
    FROM source_scenario ss
    JOIN scenario_documents sd ON sd.scenario_id = ss.source_id
    CROSS JOIN new_scenario ns
),
source_objectives AS (
    -- Get objectives from source scenario
    SELECT 
        o.objective,
        so.idx
    FROM source_scenario ss
    JOIN scenario_objectives so ON so.scenario_id = ss.source_id
    JOIN objectives o ON o.id = so.objective_id
),
existing_objectives AS (
    -- Find existing objectives by text
    SELECT id as objective_id, objective
    FROM objectives
    WHERE objective = ANY(SELECT objective FROM source_objectives)
),
new_objectives AS (
    -- Create new objectives that don't exist yet
    INSERT INTO objectives (objective, created_at, updated_at)
    SELECT DISTINCT
        so.objective,
        NOW(),
        NOW()
    FROM source_objectives so
    WHERE NOT EXISTS (
        SELECT 1 FROM existing_objectives eo WHERE eo.objective = so.objective
    )
    RETURNING id as objective_id, objective
),
all_objectives AS (
    -- Combine existing and new objectives
    SELECT objective_id, objective FROM existing_objectives
    UNION ALL
    SELECT objective_id, objective FROM new_objectives
),
link_objectives AS (
    -- Link objectives to new scenario via junction table
    INSERT INTO scenario_objectives (scenario_id, objective_id, idx, created_at)
    SELECT 
        ns.id,
        ao.objective_id,
        so.idx,
        NOW()
    FROM source_objectives so
    JOIN all_objectives ao ON ao.objective = so.objective
    CROSS JOIN new_scenario ns
),
copy_parameters AS (
    INSERT INTO scenario_fields (scenario_id, field_id, active, created_at, updated_at)
    SELECT 
        ns.id,
        sf.field_id,
        sf.active,
        NOW(),
        NOW()
    FROM source_scenario ss
    JOIN scenario_fields sf ON sf.scenario_id = ss.source_id
    CROSS JOIN new_scenario ns
),
copy_departments AS (
    INSERT INTO scenario_departments (scenario_id, department_id, active, created_at, updated_at)
    SELECT 
        ns.id,
        sd.department_id,
        sd.active,
        NOW(),
        NOW()
    FROM source_scenario ss
    JOIN scenario_departments sd ON sd.scenario_id = ss.source_id AND sd.active = true
    CROSS JOIN new_scenario ns
)
SELECT 
    ns.id as scenario_id,
    ss.name::text as scenario_name,
    ap.actor_name::text as actor_name
FROM new_scenario ns
CROSS JOIN source_scenario ss
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_duplicate_simulation_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_duplicate_simulation_v4(simulation_id uuid, profile_id uuid) RETURNS TABLE(simulation_id uuid, simulation_name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT simulation_id AS simulation_id,
           profile_id AS profile_id
),
actor_profile AS (
    SELECT 
        x.profile_id,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
source_simulation AS (
    SELECT 
        s.id as source_id,
        s.title,
        s.description
    FROM params x
    JOIN simulations s ON s.id = x.simulation_id
),
new_simulation AS (
    INSERT INTO simulations (
        title,
        description,
        active,
        practice_simulation,
        created_at,
        updated_at
    )
    SELECT 
        ss.title || ' Copy',
        ss.description,
        false,
        false,
        NOW(),
        NOW()
    FROM source_simulation ss
    RETURNING id as simulation_id
),
copy_scenarios AS (
    INSERT INTO simulation_scenarios (simulation_id, scenario_id, active, position, created_at, updated_at)
    SELECT 
        ns.simulation_id,
        ss.scenario_id,
        ss.active,
        ss.position,
        NOW(),
        NOW()
    FROM source_simulation ssim
    JOIN simulation_scenarios ss ON ss.simulation_id = ssim.source_id
    CROSS JOIN new_simulation ns
),
copy_rubric_grade_agents AS (
    INSERT INTO simulation_scenarios_rubric_grade_agents (simulation_id, scenario_id, rubric_grade_agent_id, created_at, updated_at)
    SELECT 
        ns.simulation_id,
        ssrga.scenario_id,
        ssrga.rubric_grade_agent_id,
        NOW(),
        NOW()
    FROM source_simulation ssim
    JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ssim.source_id
    CROSS JOIN new_simulation ns
    ON CONFLICT (simulation_id, scenario_id, rubric_grade_agent_id) DO NOTHING
),
copy_departments AS (
    INSERT INTO simulation_departments (simulation_id, department_id, active, created_at, updated_at)
    SELECT 
        ns.simulation_id,
        sd.department_id,
        sd.active,
        NOW(),
        NOW()
    FROM source_simulation ssim
    JOIN simulation_departments sd ON sd.simulation_id = ssim.source_id AND sd.active = true
    CROSS JOIN new_simulation ns
)
SELECT 
    ns.simulation_id,
    ss.title::text as simulation_name,
    ap.actor_name::text as actor_name
FROM new_simulation ns
CROSS JOIN source_simulation ss
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_finalize_upload_v4(text, text, bigint, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_finalize_upload_v4(upload_file_path text, content_type text, file_size bigint, profile_id uuid) RETURNS TABLE(upload_id uuid, actor_name text, success boolean, message text, status text)
    LANGUAGE sql
    AS $$
    WITH inserted_upload AS (
        INSERT INTO uploads (file_path, mime_type, size, created_at, updated_at)
        VALUES (upload_file_path, content_type, file_size, NOW(), NOW())
        RETURNING id
    ),
    actor_info AS (
        SELECT 
            first_name || ' ' || last_name as actor_name
        FROM profiles
        WHERE id = profile_id
    )
    SELECT 
        iu.id as upload_id,
        COALESCE(ai.actor_name, '') as actor_name,
        true::boolean as success,
        'Upload finalized successfully'::text as message,
        'success'::text as status
    FROM inserted_upload iu
    CROSS JOIN LATERAL (SELECT actor_name FROM actor_info) ai
$$;


--
-- Name: api_find_practice_simulation_with_persona_v4(uuid, uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_find_practice_simulation_with_persona_v4(persona_id uuid, department_ids uuid[]) RETURNS TABLE(simulation_id text, scenario_id text, simulation_title text, scenario_name text, position_val integer)
    LANGUAGE sql STABLE
    AS $$
WITH practice_simulations AS (
    SELECT DISTINCT
        sim.id as simulation_id,
        sim.title as simulation_title,
        ss.scenario_id,
        ss.position as position_val
    FROM simulations sim
    JOIN simulation_scenarios ss ON ss.simulation_id = sim.id AND ss.active = true
    JOIN scenarios s ON s.id = ss.scenario_id AND s.active = true
    JOIN scenario_personas sp ON sp.scenario_id = s.id AND sp.active = true
    WHERE sim.active = true
      AND sim.practice_simulation = true
      AND sp.persona_id = api_find_practice_simulation_with_persona_v4.persona_id
),
filtered_by_department AS (
    SELECT 
        ps.simulation_id,
        ps.simulation_title,
        ps.scenario_id,
        ps.position_val
    FROM practice_simulations ps
    LEFT JOIN scenario_departments sd ON sd.scenario_id = ps.scenario_id AND sd.active = true
    LEFT JOIN simulation_departments simd ON simd.simulation_id = ps.simulation_id AND simd.active = true
    WHERE 
        -- If no department filter, show all
        (cardinality(api_find_practice_simulation_with_persona_v4.department_ids) = 0)
        -- Or scenario has matching department
        OR EXISTS (
            SELECT 1 FROM scenario_departments sd2 
            WHERE sd2.scenario_id = ps.scenario_id 
            AND sd2.active = true 
            AND sd2.department_id = ANY(api_find_practice_simulation_with_persona_v4.department_ids)
        )
        -- Or scenario has no departments (cross-department)
        OR NOT EXISTS (
            SELECT 1 FROM scenario_departments sd3 
            WHERE sd3.scenario_id = ps.scenario_id 
            AND sd3.active = true
        )
        -- Or simulation has matching department
        OR EXISTS (
            SELECT 1 FROM simulation_departments simd2 
            WHERE simd2.simulation_id = ps.simulation_id 
            AND simd2.active = true 
            AND simd2.department_id = ANY(api_find_practice_simulation_with_persona_v4.department_ids)
        )
        -- Or simulation has no departments (cross-department)
        OR NOT EXISTS (
            SELECT 1 FROM simulation_departments simd3 
            WHERE simd3.simulation_id = ps.simulation_id 
            AND simd3.active = true
        )
    GROUP BY ps.simulation_id, ps.simulation_title, ps.scenario_id, ps.position_val
),
scenario_with_name AS (
    SELECT 
        fbd.simulation_id,
        fbd.simulation_title,
        fbd.scenario_id,
        fbd.position_val,
        s.name as scenario_name
    FROM filtered_by_department fbd
    JOIN scenarios s ON s.id = fbd.scenario_id
)
SELECT 
    simulation_id::text,
    scenario_id::text,
    simulation_title,
    scenario_name,
    position_val as position
FROM scenario_with_name
ORDER BY position_val ASC
LIMIT 1
$$;


--
-- Name: api_get_active_settings_v4(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_active_settings_v4(profile_id text, department_id text DEFAULT ''::text) RETURNS TABLE(settings_id uuid, created_at timestamp with time zone, active boolean, name text, description text, primary_color text, accent text, background text, surface text, success text, warning text, error text, sidebar_background text, sidebar_primary text, chart1 text, chart2 text, chart3 text, chart4 text, chart5 text, guest_login_enabled boolean, success_threshold integer, warning_threshold integer, danger_threshold integer, auth_ids text[], auths types.q_get_settings_detail_v4_auth[], provider_ids text[], providers types.q_get_settings_detail_v4_provider[], default_guest_profile_id uuid, default_account_profile_id uuid)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        profile_id AS profile_id,
        department_id AS department_id
),
default_settings AS (
    -- Get settings with no department links (cross-department/default)
    SELECT s.id as settings_id
    FROM settings s
    WHERE s.active = true
      AND NOT EXISTS (
          SELECT 1 FROM department_settings sd 
          WHERE sd.settings_id = s.id AND sd.active = true
      )
    LIMIT 1
),
is_guest AS (
    -- Check if this is a guest request (empty string)
    SELECT (profile_id = '') as is_guest_flag
    FROM params
),
resolve_profile_id AS (
    -- Resolve profile_id (keep as-is if UUID, null if guest)
    SELECT 
        CASE 
            WHEN (SELECT profile_id FROM params) = '' THEN NULL::uuid
            ELSE (SELECT profile_id::uuid FROM params)
        END as resolved_profile_id
),
resolve_department_id AS (
    -- Resolve department ID: use department_id if provided, otherwise get from profile's primary department
    SELECT 
        CASE 
            -- If department_id is provided and not empty, use it directly
            WHEN (SELECT department_id FROM params) IS NOT NULL AND (SELECT department_id FROM params) != '' THEN (SELECT department_id::uuid FROM params)
            -- Otherwise, try to get from profile's primary department
            ELSE (
                SELECT pd.department_id
                FROM resolve_profile_id rpi
                JOIN profile_departments pd ON pd.profile_id = rpi.resolved_profile_id
                WHERE rpi.resolved_profile_id IS NOT NULL
                  AND pd.is_primary = TRUE 
                  AND pd.active = true
                LIMIT 1
            )
        END as resolved_department_id
),
dept_specific_settings AS (
    -- Get department-specific settings (if resolved_department_id exists)
    SELECT s.id as settings_id
    FROM settings s
    JOIN department_settings sd ON sd.settings_id = s.id
    JOIN resolve_department_id rdi ON sd.department_id = rdi.resolved_department_id
    WHERE rdi.resolved_department_id IS NOT NULL
      AND s.active = true 
      AND sd.active = true
    LIMIT 1
),
selected_settings AS (
    -- Priority: department-specific settings, then default, then any active
    SELECT 
        CASE 
            -- If departmentId is provided or profile has a department, prefer department-specific settings
            WHEN (SELECT resolved_department_id FROM resolve_department_id) IS NOT NULL THEN
                COALESCE(
                    (SELECT settings_id FROM dept_specific_settings),
                    (SELECT settings_id FROM default_settings),
                    (SELECT id FROM settings WHERE active = true LIMIT 1)
                )
            -- For guest requests (no department): return default settings only
            WHEN (SELECT is_guest_flag FROM is_guest) THEN
                COALESCE(
                    (SELECT settings_id FROM default_settings),
                    (SELECT id FROM settings WHERE active = true LIMIT 1)
                )
            -- Fallback: prefer department-specific, then default, then any active
            ELSE
                COALESCE(
                    (SELECT settings_id FROM dept_specific_settings),
                    (SELECT settings_id FROM default_settings),
                    (SELECT id FROM settings WHERE active = true LIMIT 1)
                )
        END as settings_id
),
settings_auths_with_items AS (
    -- Get linked auths for this settings with nested auth_items
    SELECT 
        a.id as auth_id,
        a.name,
        COALESCE(a.description, '') as description,
        a.slug,
        a.active,
        COALESCE(
            ARRAY_AGG(
                (ai.id, ai.name, COALESCE(ai.description, ''), ai.encrypted)::types.q_get_settings_detail_v4_auth_item
                ORDER BY ai.name
            ) FILTER (WHERE ai.id IS NOT NULL),
            '{}'::types.q_get_settings_detail_v4_auth_item[]
        ) as auth_items
    FROM selected_settings ss
    JOIN setting_auths sa ON sa.settings_id = ss.settings_id AND sa.active = true
    JOIN auth a ON a.id = sa.auth_id AND a.active = true
    LEFT JOIN auth_items ai ON ai.auth_id = a.id
    GROUP BY a.id, a.name, a.description, a.slug, a.active
),
settings_auths_data AS (
    -- Aggregate linked auths into array
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (sawi.auth_id, sawi.name, sawi.description, sawi.slug, sawi.active, sawi.auth_items)::types.q_get_settings_detail_v4_auth
                ORDER BY sawi.name
            ),
            '{}'::types.q_get_settings_detail_v4_auth[]
        ) as auths,
        ARRAY_AGG(sawi.auth_id::text ORDER BY sawi.auth_id::text) FILTER (WHERE sawi.auth_id IS NOT NULL) as auth_ids
    FROM settings_auths_with_items sawi
),
settings_providers_data AS (
    -- Get linked providers for this settings
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (p.id, p.name, COALESCE(p.description, ''), p.value, p.active)::types.q_get_settings_detail_v4_provider
                ORDER BY p.name
            ),
            '{}'::types.q_get_settings_detail_v4_provider[]
        ) as providers,
        ARRAY_AGG(p.id::text ORDER BY p.id::text) FILTER (WHERE p.id IS NOT NULL) as provider_ids
    FROM selected_settings ss
    JOIN setting_providers sp ON sp.settings_id = ss.settings_id AND sp.active = true
    JOIN providers p ON p.id = sp.provider_id AND p.active = true
),
settings_default_guest_data AS (
    -- Get default guest account: try selected settings first, fall back to default settings
    SELECT 
        COALESCE(
            (SELECT sdg.profile_id
             FROM selected_settings ss
             JOIN settings_default_guest sdg ON sdg.settings_id = ss.settings_id AND sdg.active = true
             LIMIT 1),
            (SELECT sdg.profile_id
             FROM default_settings ds
             JOIN settings_default_guest sdg ON sdg.settings_id = ds.settings_id AND sdg.active = true
             LIMIT 1)
        ) as default_guest_profile_id
),
settings_default_account_data AS (
    -- Get default account: try selected settings first, fall back to default settings
    SELECT 
        COALESCE(
            (SELECT sda.profile_id
             FROM selected_settings ss
             JOIN settings_default_account sda ON sda.settings_id = ss.settings_id AND sda.active = true
             LIMIT 1),
            (SELECT sda.profile_id
             FROM default_settings ds
             JOIN settings_default_account sda ON sda.settings_id = ds.settings_id AND sda.active = true
             LIMIT 1)
        ) as default_account_profile_id
)
SELECT 
    s.id as settings_id,
    s.created_at,
    s.active,
    s.name,
    s.description,
    s.primary_color,
    s.accent,
    s.background,
    s.surface,
    s.success,
    s.warning,
    s.error,
    s.sidebar_background,
    s.sidebar_primary,
    s.chart1,
    s.chart2,
    s.chart3,
    s.chart4,
    s.chart5,
    s.guest_login_enabled,
    s.success_threshold,
    s.warning_threshold,
    s.danger_threshold,
    COALESCE(sad.auth_ids, ARRAY[]::text[]) as auth_ids,
    COALESCE(sad.auths, '{}'::types.q_get_settings_detail_v4_auth[]) as auths,
    COALESCE(spd.provider_ids, ARRAY[]::text[]) as provider_ids,
    COALESCE(spd.providers, '{}'::types.q_get_settings_detail_v4_provider[]) as providers,
    sdgd.default_guest_profile_id,
    sdad.default_account_profile_id
FROM selected_settings ss
JOIN settings s ON s.id = ss.settings_id
LEFT JOIN settings_auths_data sad ON true
LEFT JOIN settings_providers_data spd ON true
LEFT JOIN settings_default_guest_data sdgd ON true
LEFT JOIN settings_default_account_data sdad ON true
$$;


--
-- Name: api_get_activity_bundle_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_activity_bundle_v4(profile_id uuid) RETURNS TABLE(actor_name text, active_profiles_count bigint, total_feedback_count bigint, total_activity_entries bigint, total_errors_count bigint, chart_data types.q_get_activity_bundle_v4_chart_data_point[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id
),
user_profile AS (
    SELECT 
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
daily_activity AS (
    SELECT 
        DATE(created_at) as date,
        COUNT(*) as activity_count,
        COUNT(*) FILTER (WHERE error = true) as error_count
    FROM activity
    WHERE created_at >= NOW() - INTERVAL '90 days'
    GROUP BY DATE(created_at)
),
daily_feedback AS (
    SELECT 
        DATE(created_at) as date,
        COUNT(*) as feedback_count
    FROM feedback
    WHERE created_at >= NOW() - INTERVAL '90 days'
    GROUP BY DATE(created_at)
),
daily_active_profiles AS (
    SELECT 
        DATE(last_active) as date,
        COUNT(DISTINCT profile_id) as active_profiles_count
    FROM profile_activity
    WHERE last_active >= NOW() - INTERVAL '90 days'
    GROUP BY DATE(last_active)
),
date_series AS (
    SELECT generate_series(
        DATE(NOW() - INTERVAL '90 days'),
        DATE(NOW()),
        '1 day'::interval
    )::date as date
),
combined_daily AS (
    SELECT 
        ds.date,
        COALESCE(da.activity_count, 0) as activity_count,
        COALESCE(da.error_count, 0) as error_count,
        COALESCE(df.feedback_count, 0) as feedback_count,
        COALESCE(dap.active_profiles_count, 0) as active_profiles_count
    FROM date_series ds
    LEFT JOIN daily_activity da ON ds.date = da.date
    LEFT JOIN daily_feedback df ON ds.date = df.date
    LEFT JOIN daily_active_profiles dap ON ds.date = dap.date
    ORDER BY ds.date
)
SELECT 
    up.actor_name::text as actor_name,
    (SELECT COUNT(DISTINCT profile_id) FROM profile_activity)::bigint as active_profiles_count,
    (SELECT COUNT(*) FROM feedback)::bigint as total_feedback_count,
    (SELECT COUNT(*) FROM activity)::bigint as total_activity_entries,
    (SELECT COUNT(*) FROM activity WHERE error = true)::bigint as total_errors_count,
    COALESCE(
        ARRAY_AGG(
            (cd.date, cd.active_profiles_count::integer, cd.feedback_count::integer, cd.activity_count::integer, cd.error_count::integer)::types.q_get_activity_bundle_v4_chart_data_point
            ORDER BY cd.date
        ),
        '{}'::types.q_get_activity_bundle_v4_chart_data_point[]
    ) as chart_data
FROM user_profile up
CROSS JOIN combined_daily cd
GROUP BY up.actor_name
$$;


--
-- Name: api_get_activity_list_v4(uuid, integer, integer, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_activity_list_v4(profile_id uuid, page integer DEFAULT 0, page_size integer DEFAULT 50, search text DEFAULT NULL::text) RETURNS TABLE(actor_name text, activities types.q_get_activity_list_v4_activity[], total_count bigint, page integer, page_size integer, total_pages integer)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        profile_id AS profile_id,
        page AS page,
        page_size AS page_size,
        COALESCE(NULLIF(search, ''), NULL) AS search,
        (page * page_size) AS offset_value
),
user_profile AS (
    SELECT 
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
filtered_activities AS (
    SELECT 
        a.id as activity_id,
        a.created_at,
        a.message,
        a.error,
        COALESCE(p.first_name || ' ' || p.last_name, 'Anonymous') as profile_name,
        p.id as profile_id
    FROM activity a
    LEFT JOIN profiles p ON p.id = a.profile_id
    CROSS JOIN params x
    WHERE (x.search IS NULL OR x.search = '' OR a.message ILIKE '%' || x.search || '%' OR COALESCE(p.first_name || ' ' || p.last_name, 'Anonymous') ILIKE '%' || x.search || '%')
),
activity_count AS (
    SELECT COUNT(*) as total_count
    FROM filtered_activities
),
paginated_activities AS (
    SELECT 
        fa.activity_id,
        fa.created_at,
        fa.message,
        fa.error,
        fa.profile_name,
        fa.profile_id
    FROM filtered_activities fa
    CROSS JOIN params x
    ORDER BY fa.created_at DESC
    LIMIT (SELECT page_size FROM params LIMIT 1)
    OFFSET (SELECT offset_value FROM params LIMIT 1)
)
SELECT 
    up.actor_name::text as actor_name,
    COALESCE(
        ARRAY_AGG(
            (pa.activity_id, pa.created_at, pa.message, pa.error, pa.profile_name, pa.profile_id)::types.q_get_activity_list_v4_activity
            ORDER BY pa.created_at DESC
        ),
        '{}'::types.q_get_activity_list_v4_activity[]
    ) as activities,
    ac.total_count,
    p.page,
    p.page_size,
    CASE 
        WHEN p.page_size > 0 THEN (ac.total_count + p.page_size - 1) / p.page_size
        ELSE 0
    END as total_pages
FROM user_profile up
CROSS JOIN params p
CROSS JOIN activity_count ac
LEFT JOIN paginated_activities pa ON true
GROUP BY up.actor_name, ac.total_count, p.page, p.page_size
$$;


--
-- Name: api_get_agent_detail_v4(uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_agent_detail_v4(agent_id uuid, profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(agent_exists boolean, agent_id text, name text, description text, system_prompt text, prompt_id text, model_id text, active boolean, role text, selected_temperature_level_id text, temperature double precision, selected_reasoning_level_id text, reasoning text, selected_voice_ids text[], valid_voices text[], department_ids text[], valid_department_ids text[], can_edit boolean, temperature_lower double precision, temperature_upper double precision, valid_model_ids text[], actor_name text, departments types.q_get_agent_detail_v4_department[], prompts types.q_get_agent_detail_v4_prompt[], department_prompt_links types.q_get_agent_detail_v4_department_prompt_link[], debug_info types.q_get_agent_detail_v4_debug_info[], models types.q_get_agent_detail_v4_model[], reasoning_options types.q_get_agent_detail_v4_reasoning_option[], temperature_levels types.q_get_agent_detail_v4_temperature_level[], available_voices types.q_get_agent_detail_v4_available_voice[], draft_version integer)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        agent_id AS agent_id,
        profile_id AS profile_id,
        draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'agents'::draft_resource_type
    LIMIT 1
),
agent_exists_check AS (
    -- Check if agent exists independently of access control
    SELECT EXISTS(
        SELECT 1 FROM agents WHERE id = (SELECT agent_id FROM params)
    )::boolean as agent_exists
),
agent_info AS (
    SELECT 
        id::text as agent_id,
        name,
        description,
        model_id::text,
        active,
        role::text
    FROM params x
    JOIN agents ON agents.id = x.agent_id
),
agent_active_prompt AS (
    SELECT 
        ap.agent_id::text as agent_id,
        ap.prompt_id::text as prompt_id,
        pr.system_prompt,
        pr.created_at as prompt_created_at,
        pr.updated_at as prompt_updated_at
    FROM params x
    JOIN agent_prompts ap ON ap.agent_id = x.agent_id AND ap.active = true
    JOIN prompts pr ON pr.id = ap.prompt_id
    LIMIT 1
),
agent_all_prompts AS (
    -- Get all prompts from agent_prompts (default prompts)
    SELECT 
        ap.agent_id::text as agent_id,
        ap.prompt_id::text as prompt_id,
        pr.system_prompt,
        pr.name as prompt_name,
        pr.description as prompt_description,
        pr.created_at as prompt_created_at,
        pr.updated_at as prompt_updated_at
    FROM params x
    JOIN agent_prompts ap ON ap.agent_id = x.agent_id
    JOIN prompts pr ON pr.id = ap.prompt_id
    UNION
    -- Also get all prompts from agent_department_prompts (department-specific prompts)
    SELECT DISTINCT
        adp.agent_id::text as agent_id,
        adp.prompt_id::text as prompt_id,
        pr.system_prompt,
        pr.name as prompt_name,
        pr.description as prompt_description,
        pr.created_at as prompt_created_at,
        pr.updated_at as prompt_updated_at
    FROM params x
    JOIN agent_department_prompts adp ON adp.agent_id = x.agent_id AND adp.active = true
    JOIN prompts pr ON pr.id = adp.prompt_id
),
prompt_departments_data AS (
    SELECT 
        adp.prompt_id::text as prompt_id,
        ARRAY_AGG(adp.department_id::text ORDER BY adp.created_at) as department_ids
    FROM params x
    JOIN agent_department_prompts adp ON adp.agent_id = x.agent_id AND adp.active = true
    GROUP BY adp.prompt_id
),
default_prompt_count AS (
    -- Count default prompts (from agent_prompts, not department-specific)
    -- Always return at least one row with count (0 if no prompts)
    SELECT COALESCE(COUNT(DISTINCT ap.prompt_id), 0)::integer as count
    FROM params x
    JOIN agent_prompts ap ON ap.agent_id = x.agent_id
),
prompt_mapping_data AS (
    SELECT 
        ap.prompt_id::text as prompt_id,
        ap.system_prompt::text as system_prompt,
        COALESCE(ap.prompt_name, '')::text as prompt_name,
        COALESCE(ap.prompt_description, '')::text as prompt_description,
        ap.prompt_created_at::timestamptz as prompt_created_at,
        ap.prompt_updated_at::timestamptz as prompt_updated_at,
        COALESCE(pdd.department_ids, NULL)::text[] as department_ids,
        CASE
            -- Department-specific prompts can always be deleted (fall back to default)
            WHEN pdd.department_ids IS NOT NULL THEN true::boolean
            -- Default prompts can be deleted if there's more than one
            WHEN pdd.department_ids IS NULL AND COALESCE(dpc.count, 0) > 1 THEN true::boolean
            -- Otherwise cannot delete (only one default prompt)
            ELSE false::boolean
        END as can_delete
    FROM agent_all_prompts ap
    LEFT JOIN prompt_departments_data pdd ON pdd.prompt_id = ap.prompt_id
    CROSS JOIN default_prompt_count dpc
),
agent_departments_data AS (
    SELECT 
        ad.agent_id::text as agent_id,
        ARRAY_AGG(ad.department_id::text ORDER BY ad.created_at) as department_ids
    FROM params x
    JOIN agent_departments ad ON ad.agent_id = x.agent_id AND ad.active = true
    GROUP BY ad.agent_id
),
agent_department_prompt_links_data AS (
    SELECT 
        adp.department_id::text as department_id,
        adp.prompt_id::text as prompt_id
    FROM params x
    JOIN agent_department_prompts adp ON adp.agent_id = x.agent_id AND adp.active = true
),
debug_data AS (
    SELECT 
        di.created_at,
        mrm.model_id::text,
        di.content
    FROM params x
    JOIN runs mr ON mr.agent_id = x.agent_id
    JOIN debug_info di ON di.run_id = mr.id
    JOIN run_models mrm ON mrm.run_id = mr.id
    WHERE mrm.active = true
    ORDER BY di.created_at DESC
    LIMIT 100
),
all_models AS (
    SELECT 
        id::text as model_id,
        name,
        COALESCE(description, '') as description,
        active
    FROM models
),
model_modalities_data AS (
    SELECT 
        mm.model_id::text as model_id,
        mm.modality::text as modality,
        mm.is_input::boolean as is_input
    FROM model_modalities mm
    WHERE mm.active = true
),
user_profile AS (
    SELECT 
        role,
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
user_departments AS (
    SELECT DISTINCT d.id, d.title as name, d.description
    FROM params x
    JOIN departments d ON d.active = true
    JOIN profile_departments pd ON pd.department_id = d.id AND pd.profile_id = x.profile_id AND pd.active = true
),
user_has_agent_access AS (
    -- Check if user has access to agent via department links
    SELECT EXISTS(
        SELECT 1 FROM params x
        JOIN agent_departments ad ON ad.agent_id = x.agent_id AND ad.active = true
        JOIN user_departments ud ON ud.id = ad.department_id::uuid
    ) OR EXISTS(
        SELECT 1 FROM params x
        JOIN profiles p ON p.id = x.profile_id AND p.role = 'superadmin'::profile_role
    ) OR (
        -- Default agents (no department links) are accessible to all
        SELECT COUNT(*) FROM params x
        JOIN agent_departments ad ON ad.agent_id = x.agent_id AND ad.active = true
    ) = 0 as has_access
),
valid_departments_data AS (
    SELECT 
        ud.id::text as department_id,
        ud.name::text as department_name,
        COALESCE(ud.description, '')::text as department_description
    FROM user_departments ud
),
valid_department_ids_list AS (
    SELECT array_agg(id::text ORDER BY name) as dept_ids
    FROM user_departments
),
agent_selected_voices AS (
    SELECT 
        av.agent_id::text as agent_id,
        mv.id::text as voice_id,
        mv.voice::text as voice
    FROM agent_voices av
    JOIN model_voices mv ON mv.id = av.model_voice_id
    WHERE av.active = true AND mv.active = true
),
agent_selected_temperature AS (
    SELECT 
        atl.agent_id::text as agent_id,
        atl.model_temperature_level_id::text as selected_temperature_level_id,
        mtl.temperature as selected_temperature
    FROM agent_temperature_levels atl
    JOIN model_temperature_levels mtl ON mtl.id = atl.model_temperature_level_id
    WHERE atl.active = true AND mtl.active = true
),
agent_selected_reasoning AS (
    SELECT 
        arl.agent_id::text as agent_id,
        arl.model_reasoning_level_id::text as selected_reasoning_level_id,
        mrl.reasoning_level::text as selected_reasoning
    FROM agent_reasoning_levels arl
    JOIN model_reasoning_levels mrl ON mrl.id = arl.model_reasoning_level_id
    WHERE arl.active = true AND mrl.active = true
),
model_temperature_levels_data_with_ids AS (
    SELECT 
        mtl.model_id::text as model_id,
        mtl.id::text as temperature_level_id,
        mtl.temperature::text as temperature_value,
        mtl.is_upper::boolean as is_upper
    FROM model_temperature_levels mtl
    WHERE mtl.active = true
),
model_temperature_levels_bounds AS (
    SELECT 
        mtl.model_id::text as model_id,
        MIN(mtl.temperature) FILTER (WHERE mtl.is_upper = false)::float as temperature_lower,
        MAX(mtl.temperature) FILTER (WHERE mtl.is_upper = true)::float as temperature_upper
    FROM model_temperature_levels mtl
    WHERE mtl.active = true
    GROUP BY mtl.model_id
),
model_reasoning_levels_data_with_ids AS (
    SELECT 
        mrl.model_id::text as model_id,
        mrl.id::text as reasoning_level_id,
        mrl.reasoning_level::text as reasoning_level_value
    FROM model_reasoning_levels mrl
    WHERE mrl.active = true
),
model_voices_data_flat AS (
    SELECT 
        mv.model_id::text as model_id,
        mv.id::text as voice_id,
        mv.voice::text as voice_value
    FROM model_voices mv
    WHERE mv.active = true
),
models_agg AS (
    SELECT 
        am.model_id,
        am.name,
        am.description,
        COALESCE((SELECT array_agg(modality::text ORDER BY modality) FROM model_modalities_data WHERE model_id = am.model_id AND is_input = true), ARRAY[]::text[]) as input_modalities,
        COALESCE((SELECT array_agg(modality::text ORDER BY modality) FROM model_modalities_data WHERE model_id = am.model_id AND is_input = false), ARRAY[]::text[]) as output_modalities,
        COALESCE(mtb.temperature_lower, 0.0) as temperature_lower,
        COALESCE(mtb.temperature_upper, 1.0) as temperature_upper,
        COALESCE(
            jsonb_object_agg(
                mtl.temperature_level_id,
                jsonb_build_object('temperature', mtl.temperature_value, 'is_upper', mtl.is_upper)
            ) FILTER (WHERE mtl.temperature_level_id IS NOT NULL),
            '{}'::jsonb
        ) as temperature_levels,
        COALESCE(
            jsonb_object_agg(
                mrl.reasoning_level_id,
                jsonb_build_object('reasoning_level', mrl.reasoning_level_value)
            ) FILTER (WHERE mrl.reasoning_level_id IS NOT NULL),
            '{}'::jsonb
        ) as reasoning_options,
        COALESCE(
            jsonb_object_agg(
                mvf.voice_id,
                jsonb_build_object('voice', mvf.voice_value)
            ) FILTER (WHERE mvf.voice_id IS NOT NULL),
            '{}'::jsonb
        ) as available_voices
    FROM all_models am
    LEFT JOIN model_temperature_levels_bounds mtb ON mtb.model_id = am.model_id
    LEFT JOIN model_temperature_levels_data_with_ids mtl ON mtl.model_id = am.model_id
    LEFT JOIN model_reasoning_levels_data_with_ids mrl ON mrl.model_id = am.model_id
    LEFT JOIN model_voices_data_flat mvf ON mvf.model_id = am.model_id
    GROUP BY am.model_id, am.name, am.description, mtb.temperature_lower, mtb.temperature_upper
)
SELECT 
    -- Agent existence check (always returned)
    aec.agent_exists::boolean as agent_exists,
    -- Top-level agent fields (merged with draft payload if draft_id provided)
    ai.agent_id::text as agent_id,
    COALESCE(
        (SELECT payload->>'name' FROM draft_payload_data),
        ai.name
    )::text as name,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        ai.description
    )::text as description,
    COALESCE(
        (SELECT payload->>'systemPrompt' FROM draft_payload_data),
        (SELECT payload->>'system_prompt' FROM draft_payload_data),
        COALESCE(aap.system_prompt, '')
    )::text as system_prompt,
    COALESCE(
        CASE 
            WHEN (SELECT payload->>'promptId' FROM draft_payload_data) IS NOT NULL THEN
                (SELECT payload->>'promptId' FROM draft_payload_data)
            WHEN (SELECT payload->>'prompt_id' FROM draft_payload_data) IS NOT NULL THEN
                (SELECT payload->>'prompt_id' FROM draft_payload_data)
            ELSE COALESCE(aap.prompt_id, NULL)
        END,
        NULL
    )::text as prompt_id,
    COALESCE(
        (SELECT payload->>'modelId' FROM draft_payload_data),
        (SELECT payload->>'model_id' FROM draft_payload_data),
        ai.model_id
    )::text as model_id,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        ai.active
    )::boolean as active,
    COALESCE(
        (SELECT payload->>'role' FROM draft_payload_data),
        ai.role
    )::text as role,
    -- Selected options from junction tables (merged with draft payload if draft_id provided)
    COALESCE(
        (SELECT payload->>'model_temperature_level_id' FROM draft_payload_data),
        COALESCE(ast.selected_temperature_level_id, '')
    )::text as selected_temperature_level_id,
    COALESCE(ast.selected_temperature, 0.7)::float as temperature,
    COALESCE(
        (SELECT payload->>'model_reasoning_level_id' FROM draft_payload_data),
        COALESCE(asr.selected_reasoning_level_id, '')
    )::text as selected_reasoning_level_id,
    COALESCE(asr.selected_reasoning, '')::text as reasoning,
    COALESCE(
        CASE 
            WHEN (SELECT payload->'model_voice_ids' FROM draft_payload_data) IS NOT NULL AND jsonb_typeof((SELECT payload->'model_voice_ids' FROM draft_payload_data)) = 'array' THEN
                ARRAY(SELECT jsonb_array_elements_text((SELECT payload->'model_voice_ids' FROM draft_payload_data)))::text[]
            ELSE COALESCE((SELECT array_agg(asv2.voice_id::text ORDER BY asv2.voice) FROM agent_selected_voices asv2 WHERE asv2.agent_id = ai.agent_id), ARRAY[]::text[])
        END,
        ARRAY[]::text[]
    )::text[] as selected_voice_ids,
    COALESCE((SELECT array_agg(asv3.voice::text ORDER BY asv3.voice) FROM agent_selected_voices asv3 WHERE asv3.agent_id = ai.agent_id), ARRAY[]::text[])::text[] as valid_voices,
    COALESCE(
        CASE 
            WHEN (SELECT payload->'departmentIds' FROM draft_payload_data) IS NOT NULL AND jsonb_typeof((SELECT payload->'departmentIds' FROM draft_payload_data)) = 'array' THEN
                ARRAY(SELECT jsonb_array_elements_text((SELECT payload->'departmentIds' FROM draft_payload_data)))::text[]
            WHEN (SELECT payload->'department_ids' FROM draft_payload_data) IS NOT NULL AND jsonb_typeof((SELECT payload->'department_ids' FROM draft_payload_data)) = 'array' THEN
                ARRAY(SELECT jsonb_array_elements_text((SELECT payload->'department_ids' FROM draft_payload_data)))::text[]
            ELSE COALESCE(add.department_ids, ARRAY[]::text[])
        END,
        ARRAY[]::text[]
    )::text[] as department_ids,
    COALESCE((SELECT dept_ids FROM valid_department_ids_list LIMIT 1), ARRAY[]::text[])::text[] as valid_department_ids,
    CASE 
        -- Default agents (no department_ids) are read-only for non-superadmin
        WHEN (COALESCE(add.department_ids, ARRAY[]::text[]) = ARRAY[]::text[] AND up.role != 'superadmin') THEN false::boolean
        WHEN up.role = 'superadmin'::profile_role THEN true::boolean
        WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role) AND uhaa.has_access THEN true::boolean
        ELSE false::boolean
    END as can_edit,
    -- Temperature bounds for selected model
    COALESCE((SELECT temperature_lower FROM model_temperature_levels_bounds WHERE model_id = ai.model_id), 0.0)::float as temperature_lower,
    COALESCE((SELECT temperature_upper FROM model_temperature_levels_bounds WHERE model_id = ai.model_id), 1.0)::float as temperature_upper,
    -- Valid model IDs
    COALESCE((SELECT array_agg(model_id::text ORDER BY name) FROM all_models WHERE active = true), ARRAY[]::text[])::text[] as valid_model_ids,
    -- Top-level actor name
    up.actor_name::text as actor_name,
    -- Aggregated arrays
    COALESCE(
        ARRAY_AGG(
            (vdd.department_id, vdd.department_name, vdd.department_description
            )::types.q_get_agent_detail_v4_department
            ORDER BY vdd.department_name
        ) FILTER (WHERE uhaa.has_access = true),
        '{}'::types.q_get_agent_detail_v4_department[]
    ) as departments,
    COALESCE(
        ARRAY_AGG(
            (pmd.prompt_id, pmd.system_prompt, pmd.prompt_name, pmd.prompt_description,
             pmd.prompt_created_at::text, pmd.prompt_updated_at::text,
             COALESCE(pmd.department_ids, ARRAY[]::text[]), pmd.can_delete
            )::types.q_get_agent_detail_v4_prompt
            ORDER BY pmd.prompt_created_at
        ) FILTER (WHERE uhaa.has_access = true),
        '{}'::types.q_get_agent_detail_v4_prompt[]
    ) as prompts,
    COALESCE(
        ARRAY_AGG(
            (adpl.department_id, adpl.prompt_id
            )::types.q_get_agent_detail_v4_department_prompt_link
            ORDER BY adpl.department_id, adpl.prompt_id
        ) FILTER (WHERE uhaa.has_access = true AND adpl.department_id IS NOT NULL),
        '{}'::types.q_get_agent_detail_v4_department_prompt_link[]
    ) as department_prompt_links,
    COALESCE(
        ARRAY_AGG(
            (dd.created_at::text, dd.model_id, dd.content
            )::types.q_get_agent_detail_v4_debug_info
            ORDER BY dd.created_at DESC
        ) FILTER (WHERE uhaa.has_access = true AND dd.created_at IS NOT NULL),
        '{}'::types.q_get_agent_detail_v4_debug_info[]
    ) as debug_info,
    COALESCE(
        ARRAY_AGG(
            (ma.model_id, ma.name, ma.description,
             ma.input_modalities, ma.output_modalities,
             ma.temperature_lower, ma.temperature_upper,
             ma.temperature_levels, ma.reasoning_options, ma.available_voices
            )::types.q_get_agent_detail_v4_model
            ORDER BY ma.name
        ) FILTER (WHERE uhaa.has_access = true),
        '{}'::types.q_get_agent_detail_v4_model[]
    ) as models,
    COALESCE(
        ARRAY_AGG(
            (mrl_selected.reasoning_level_id, mrl_selected.reasoning_level_value
            )::types.q_get_agent_detail_v4_reasoning_option
            ORDER BY mrl_selected.reasoning_level_value
        ) FILTER (WHERE uhaa.has_access = true AND mrl_selected.reasoning_level_id IS NOT NULL),
        '{}'::types.q_get_agent_detail_v4_reasoning_option[]
    ) as reasoning_options,
    COALESCE(
        ARRAY_AGG(
            (mtl_selected.temperature_level_id, mtl_selected.temperature_value, mtl_selected.is_upper
            )::types.q_get_agent_detail_v4_temperature_level
            ORDER BY mtl_selected.temperature_value::float
        ) FILTER (WHERE uhaa.has_access = true AND mtl_selected.temperature_level_id IS NOT NULL),
        '{}'::types.q_get_agent_detail_v4_temperature_level[]
    ) as temperature_levels,
    COALESCE(
        ARRAY_AGG(
            (mvf_selected.voice_id, mvf_selected.voice_value
            )::types.q_get_agent_detail_v4_available_voice
            ORDER BY mvf_selected.voice_value
        ) FILTER (WHERE uhaa.has_access = true AND mvf_selected.voice_id IS NOT NULL),
        '{}'::types.q_get_agent_detail_v4_available_voice[]
    ) as available_voices,
    COALESCE((SELECT draft_version FROM draft_payload_data), 0)::int as draft_version
FROM agent_exists_check aec
CROSS JOIN user_profile up
CROSS JOIN user_has_agent_access uhaa
LEFT JOIN agent_info ai ON ai.agent_id = (SELECT agent_id::text FROM params) AND uhaa.has_access = true
LEFT JOIN agent_active_prompt aap ON aap.agent_id = ai.agent_id AND uhaa.has_access = true
LEFT JOIN agent_departments_data add ON add.agent_id = ai.agent_id AND uhaa.has_access = true
LEFT JOIN agent_selected_temperature ast ON ast.agent_id = ai.agent_id AND uhaa.has_access = true
LEFT JOIN agent_selected_reasoning asr ON asr.agent_id = ai.agent_id AND uhaa.has_access = true
LEFT JOIN valid_departments_data vdd ON uhaa.has_access = true
LEFT JOIN prompt_mapping_data pmd ON uhaa.has_access = true
LEFT JOIN agent_department_prompt_links_data adpl ON uhaa.has_access = true
LEFT JOIN debug_data dd ON uhaa.has_access = true
LEFT JOIN models_agg ma ON uhaa.has_access = true
LEFT JOIN model_reasoning_levels_data_with_ids mrl_selected ON mrl_selected.model_id = ai.model_id AND uhaa.has_access = true
LEFT JOIN model_temperature_levels_data_with_ids mtl_selected ON mtl_selected.model_id = ai.model_id AND uhaa.has_access = true
LEFT JOIN model_voices_data_flat mvf_selected ON mvf_selected.model_id = ai.model_id AND uhaa.has_access = true
GROUP BY aec.agent_exists, ai.agent_id, ai.name, ai.description, aap.system_prompt, aap.prompt_id,
         ai.model_id, ai.active, ai.role, ast.selected_temperature_level_id, ast.selected_temperature,
         asr.selected_reasoning_level_id, asr.selected_reasoning, add.department_ids, up.actor_name,
         up.role, uhaa.has_access
LIMIT 1
$$;


--
-- Name: api_get_agent_model_info_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_agent_model_info_v4(agent_id uuid, profile_id uuid) RETURNS TABLE(model_name text, provider text, base_url text, api_key text)
    LANGUAGE sql STABLE
    AS $$
WITH profile_primary_department AS (
    SELECT pd.department_id
    FROM profile_departments pd
    WHERE pd.profile_id = profile_id
      AND pd.is_primary = TRUE 
      AND pd.active = true
    LIMIT 1
),
default_settings AS (
    SELECT s.id as settings_id
    FROM settings s
    WHERE s.active = true
      AND NOT EXISTS (
          SELECT 1 FROM department_settings sd 
          WHERE sd.settings_id = s.id AND sd.active = true
      )
    LIMIT 1
),
dept_specific_settings AS (
    SELECT s.id as settings_id
    FROM settings s
    JOIN department_settings sd ON sd.settings_id = s.id
    JOIN profile_primary_department ppd ON sd.department_id = ppd.department_id
    WHERE ppd.department_id IS NOT NULL
      AND s.active = true 
      AND sd.active = true
    LIMIT 1
),
settings_with_keys AS (
    SELECT DISTINCT spk.settings_id
    FROM setting_provider_keys spk
    JOIN keys k ON k.id = spk.key_id
    WHERE spk.active = true AND k.active = true
),
dept_specific_settings_with_keys AS (
    SELECT s.id as settings_id
    FROM settings s
    JOIN department_settings sd ON sd.settings_id = s.id
    JOIN profile_primary_department ppd ON sd.department_id = ppd.department_id
    JOIN settings_with_keys swk ON swk.settings_id = s.id
    WHERE ppd.department_id IS NOT NULL
      AND s.active = true AND sd.active = true
    LIMIT 1
),
default_settings_with_keys AS (
    SELECT s.id as settings_id
    FROM settings s
    JOIN settings_with_keys swk ON swk.settings_id = s.id
    WHERE s.active = true
      AND NOT EXISTS (
          SELECT 1 FROM department_settings sd 
          WHERE sd.settings_id = s.id AND sd.active = true
      )
    LIMIT 1
),
active_settings AS (
    SELECT 
        COALESCE(
            (SELECT settings_id FROM dept_specific_settings_with_keys),
            (SELECT settings_id FROM default_settings_with_keys),
            (SELECT settings_id FROM settings_with_keys LIMIT 1),
            (SELECT settings_id FROM dept_specific_settings),
            (SELECT settings_id FROM default_settings),
            (SELECT id FROM settings WHERE active = true LIMIT 1)
        ) as settings_id
)
SELECT 
    m.value as model_name,
    COALESCE(p.value::text, '') as provider,
    COALESCE(me.base_url, '') as base_url,
    k.key as api_key
FROM agents a
INNER JOIN models m ON m.id = a.model_id
LEFT JOIN providers p ON p.id = m.provider_id
LEFT JOIN model_endpoints me ON me.model_id = m.id AND me.active = true
CROSS JOIN active_settings act_s
LEFT JOIN setting_provider_keys spk ON spk.provider_id = p.id 
    AND spk.settings_id = act_s.settings_id 
    AND spk.active = true
LEFT JOIN keys k ON k.id = spk.key_id AND k.active = true
WHERE a.id = agent_id
  AND a.active = true
LIMIT 1
$$;


--
-- Name: api_get_agent_new_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_agent_new_v4(profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(actor_name text, user_role text, primary_department_id text, valid_model_ids text[], valid_department_ids text[], models types.q_get_agent_new_v4_model[], departments types.q_get_agent_new_v4_department[], name text, description text, system_prompt text, prompt_id text, model_id text, active boolean, role text, department_ids text[], model_temperature_level_id text, model_reasoning_level_id text, model_voice_ids text[], draft_version integer)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        profile_id AS profile_id,
        draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'agents'::draft_resource_type
    LIMIT 1
),
user_profile AS (
    SELECT 
        role,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
primary_department_id AS (
    SELECT department_id::text
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id
    WHERE pd.is_primary = TRUE
    LIMIT 1
),
user_departments_for_models AS (
    SELECT DISTINCT pd.department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id
),
valid_models AS (
    SELECT 
        m.id::text as model_id,
        m.name,
        COALESCE(m.description, '') as description,
        m.active
    FROM models m
    LEFT JOIN model_departments md ON md.model_id = m.id AND md.active = true
    WHERE m.active = true
    GROUP BY m.id, m.name, m.description, m.active
    HAVING 
        COUNT(md.model_id) FILTER (WHERE md.department_id IN (SELECT department_id FROM user_departments_for_models)) > 0
        OR NOT EXISTS (SELECT 1 FROM model_departments md2 WHERE md2.model_id = m.id AND md2.active = true)
    ORDER BY m.name
),
model_modalities_data AS (
    SELECT 
        mm.model_id::text as model_id,
        mm.modality::text as modality,
        mm.is_input::boolean as is_input
    FROM model_modalities mm
    WHERE mm.active = true
),
model_temperature_levels_data_with_ids AS (
    SELECT 
        mtl.model_id::text as model_id,
        mtl.id::text as temperature_level_id,
        mtl.temperature::text as temperature_value,
        mtl.is_upper::boolean as is_upper
    FROM model_temperature_levels mtl
    WHERE mtl.active = true
),
model_temperature_levels_bounds AS (
    SELECT 
        mtl.model_id::text as model_id,
        MIN(mtl.temperature) FILTER (WHERE mtl.is_upper = false)::float as temperature_lower,
        MAX(mtl.temperature) FILTER (WHERE mtl.is_upper = true)::float as temperature_upper
    FROM model_temperature_levels mtl
    WHERE mtl.active = true
    GROUP BY mtl.model_id
),
model_reasoning_levels_data_with_ids AS (
    SELECT 
        mrl.model_id::text as model_id,
        mrl.id::text as reasoning_level_id,
        mrl.reasoning_level::text as reasoning_level_value
    FROM model_reasoning_levels mrl
    WHERE mrl.active = true
),
model_voices_data AS (
    SELECT 
        mv.model_id::text as model_id,
        mv.id::text as voice_id,
        mv.voice::text as voice_value
    FROM model_voices mv
    WHERE mv.active = true
),
all_models_with_modalities AS (
    SELECT DISTINCT
        vm.model_id,
        vm.name,
        vm.description,
        vm.active
    FROM valid_models vm
),
user_departments AS (
    SELECT DISTINCT d.id, d.title as name, d.description
    FROM departments d
    JOIN params x ON true
    JOIN profile_departments pd ON pd.department_id = d.id
    WHERE d.active = true
    AND pd.profile_id = x.profile_id
    AND pd.active = true
),
valid_departments_list AS (
    SELECT array_agg(ud.id::text ORDER BY ud.name) as dept_ids
    FROM user_departments ud
),
valid_departments_data AS (
    SELECT 
        ud.id::text as department_id,
        ud.name::text as department_name,
        COALESCE(ud.description, '')::text as department_description
    FROM user_departments ud
),
models_agg AS (
    SELECT 
        amwm.model_id,
        amwm.name,
        amwm.description,
        amwm.active,
        COALESCE(mtb.temperature_lower, 0.0) as temperature_lower,
        COALESCE(mtb.temperature_upper, 1.0) as temperature_upper,
        COALESCE((SELECT array_agg(mmod2.modality::text ORDER BY mmod2.modality) FROM model_modalities_data mmod2 WHERE mmod2.model_id = amwm.model_id AND mmod2.is_input = true), ARRAY[]::text[]) as input_modalities,
        COALESCE((SELECT array_agg(mmod3.modality::text ORDER BY mmod3.modality) FROM model_modalities_data mmod3 WHERE mmod3.model_id = amwm.model_id AND mmod3.is_input = false), ARRAY[]::text[]) as output_modalities,
        COALESCE(
            jsonb_object_agg(
                mtl.temperature_level_id,
                jsonb_build_object('temperature', mtl.temperature_value, 'is_upper', mtl.is_upper)
            ) FILTER (WHERE mtl.temperature_level_id IS NOT NULL),
            '{}'::jsonb
        ) as temperature_levels,
        COALESCE(
            jsonb_object_agg(
                mrl.reasoning_level_id,
                jsonb_build_object('reasoning_level', mrl.reasoning_level_value)
            ) FILTER (WHERE mrl.reasoning_level_id IS NOT NULL),
            '{}'::jsonb
        ) as reasoning_options,
        COALESCE(
            jsonb_object_agg(
                mv.voice_id,
                jsonb_build_object('voice', mv.voice_value)
            ) FILTER (WHERE mv.voice_id IS NOT NULL),
            '{}'::jsonb
        ) as available_voices
    FROM all_models_with_modalities amwm
    LEFT JOIN model_temperature_levels_bounds mtb ON mtb.model_id = amwm.model_id
    LEFT JOIN model_temperature_levels_data_with_ids mtl ON mtl.model_id = amwm.model_id
    LEFT JOIN model_reasoning_levels_data_with_ids mrl ON mrl.model_id = amwm.model_id
    LEFT JOIN model_voices_data mv ON mv.model_id = amwm.model_id
    GROUP BY amwm.model_id, amwm.name, amwm.description, amwm.active, mtb.temperature_lower, mtb.temperature_upper
)
SELECT 
    up.actor_name::text as actor_name,
    up.role::text as user_role,
    pdi.department_id::text as primary_department_id,
    (SELECT array_agg(amwm2.model_id::text ORDER BY amwm2.name) FROM all_models_with_modalities amwm2)::text[] as valid_model_ids,
    COALESCE((SELECT dept_ids FROM valid_departments_list LIMIT 1), ARRAY[]::text[])::text[] as valid_department_ids,
    COALESCE(
        ARRAY_AGG(
            (ma.model_id, ma.name, ma.description, ma.active,
             ma.temperature_lower, ma.temperature_upper,
             ma.input_modalities, ma.output_modalities,
             ma.temperature_levels, ma.reasoning_options, ma.available_voices
            )::types.q_get_agent_new_v4_model
            ORDER BY ma.name
        ),
        '{}'::types.q_get_agent_new_v4_model[]
    ) as models,
    COALESCE(
        ARRAY_AGG(
            (vdd.department_id, vdd.department_name, vdd.department_description
            )::types.q_get_agent_new_v4_department
            ORDER BY vdd.department_name
        ),
        '{}'::types.q_get_agent_new_v4_department[]
    ) as departments,
    -- Default values for new agent (merged with draft payload if draft_id provided)
    COALESCE(
        (SELECT payload->>'name' FROM draft_payload_data),
        'New Agent'::text
    ) as name,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        ''::text
    ) as description,
    COALESCE(
        (SELECT payload->>'systemPrompt' FROM draft_payload_data),
        (SELECT payload->>'system_prompt' FROM draft_payload_data),
        ''::text
    ) as system_prompt,
    COALESCE(
        CASE 
            WHEN (SELECT payload->>'promptId' FROM draft_payload_data) IS NOT NULL THEN
                (SELECT payload->>'promptId' FROM draft_payload_data)
            WHEN (SELECT payload->>'prompt_id' FROM draft_payload_data) IS NOT NULL THEN
                (SELECT payload->>'prompt_id' FROM draft_payload_data)
            ELSE NULL
        END,
        NULL
    )::text as prompt_id,
    COALESCE(
        (SELECT payload->>'modelId' FROM draft_payload_data),
        (SELECT payload->>'model_id' FROM draft_payload_data),
        ''::text
    ) as model_id,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        true::boolean
    ) as active,
    COALESCE(
        (SELECT payload->>'role' FROM draft_payload_data),
        'assistant'::text
    ) as role,
    COALESCE(
        CASE 
            WHEN (SELECT payload->'departmentIds' FROM draft_payload_data) IS NOT NULL AND jsonb_typeof((SELECT payload->'departmentIds' FROM draft_payload_data)) = 'array' THEN
                ARRAY(SELECT jsonb_array_elements_text((SELECT payload->'departmentIds' FROM draft_payload_data)))::text[]
            WHEN (SELECT payload->'department_ids' FROM draft_payload_data) IS NOT NULL AND jsonb_typeof((SELECT payload->'department_ids' FROM draft_payload_data)) = 'array' THEN
                ARRAY(SELECT jsonb_array_elements_text((SELECT payload->'department_ids' FROM draft_payload_data)))::text[]
            ELSE NULL
        END,
        ARRAY[]::text[]
    ) as department_ids,
    COALESCE(
        CASE 
            WHEN (SELECT payload->>'model_temperature_level_id' FROM draft_payload_data) IS NOT NULL THEN
                (SELECT payload->>'model_temperature_level_id' FROM draft_payload_data)
            ELSE NULL
        END,
        NULL
    )::text as model_temperature_level_id,
    COALESCE(
        CASE 
            WHEN (SELECT payload->>'model_reasoning_level_id' FROM draft_payload_data) IS NOT NULL THEN
                (SELECT payload->>'model_reasoning_level_id' FROM draft_payload_data)
            ELSE NULL
        END,
        NULL
    )::text as model_reasoning_level_id,
    COALESCE(
        CASE 
            WHEN (SELECT payload->'model_voice_ids' FROM draft_payload_data) IS NOT NULL AND jsonb_typeof((SELECT payload->'model_voice_ids' FROM draft_payload_data)) = 'array' THEN
                ARRAY(SELECT jsonb_array_elements_text((SELECT payload->'model_voice_ids' FROM draft_payload_data)))::text[]
            ELSE NULL
        END,
        ARRAY[]::text[]
    ) as model_voice_ids,
    COALESCE((SELECT draft_version FROM draft_payload_data), 0)::int as draft_version
FROM user_profile up
CROSS JOIN models_agg ma
CROSS JOIN valid_departments_data vdd
LEFT JOIN primary_department_id pdi ON true
GROUP BY up.actor_name, up.role, pdi.department_id
$$;


--
-- Name: api_get_all_active_departments_v4(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_all_active_departments_v4() RETURNS TABLE(id uuid)
    LANGUAGE sql STABLE
    AS $$
SELECT id FROM departments WHERE active = true
$$;


--
-- Name: api_get_attempt_with_profile_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_attempt_with_profile_v4(attempt_id uuid) RETURNS TABLE(id uuid, simulation_id uuid, created_at timestamp with time zone, infinite_mode boolean, profile_id uuid)
    LANGUAGE sql STABLE
    AS $$
SELECT 
    sa.id,
    sa.simulation_id,
    sa.created_at,
    sa.infinite_mode,
    (SELECT profile_id FROM attempt_profiles WHERE attempt_id = sa.id AND active = true LIMIT 1) as profile_id
FROM simulation_attempts sa
WHERE sa.id = attempt_id
$$;


--
-- Name: api_get_auth_detail_v4(uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_auth_detail_v4(auth_id uuid, profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(auth_exists boolean, name text, description text, active boolean, can_edit boolean, auth_items types.q_get_auth_detail_v4_auth_item[], actor_name text, draft_version integer, auth_item_ids jsonb, auth_item_active_states jsonb, auth_item_encrypted_states jsonb)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        auth_id AS auth_id,
        profile_id AS profile_id,
        draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'auth'::draft_resource_type
    LIMIT 1
),
auth_exists_check AS (
    -- Check if auth exists independently of access control
    SELECT EXISTS(
        SELECT 1 FROM auth WHERE id = (SELECT auth_id FROM params)
    )::boolean as auth_exists
),
user_profile AS (
    SELECT 
        p.role,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
auth_data AS (
    SELECT 
        -- Merge draft payload with auth data (draft takes precedence)
        COALESCE(
            (SELECT payload->>'name' FROM draft_payload_data),
            a.name
        ) as name,
        COALESCE(
            (SELECT payload->>'description' FROM draft_payload_data),
            a.description
        ) as description,
        COALESCE(
            (SELECT (payload->>'active')::boolean FROM draft_payload_data),
            a.active
        ) as active,
        CASE 
            WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_edit
    FROM params x
    JOIN auth a ON a.id = x.auth_id
    CROSS JOIN user_profile up
),
auth_items_data AS (
    -- Get all auth items (values managed separately in settings page)
    SELECT 
        ai.id as auth_item_id,
        ai.name,
        ai.description,
        ai.position,
        ai.active,
        ai.encrypted,
        NULL::text as key_id,
        CASE 
            WHEN ai.encrypted THEN '****'::text
            ELSE ''::text
        END as value_masked
    FROM params x
    JOIN auth_items ai ON ai.auth_id = x.auth_id
    ORDER BY ai.position
)
SELECT 
    aec.auth_exists::boolean as auth_exists,
    ad.name::text as name,
    ad.description::text as description,
    ad.active::boolean as active,
    ad.can_edit::boolean as can_edit,
    COALESCE(
        ARRAY_AGG(
            (aid.auth_item_id, aid.name, aid.description, aid.position, aid.active, aid.value_masked, aid.key_id, aid.encrypted)::types.q_get_auth_detail_v4_auth_item
            ORDER BY aid.position
        ),
        '{}'::types.q_get_auth_detail_v4_auth_item[]
    ) as auth_items,
    up.actor_name::text as actor_name,
    COALESCE((SELECT draft_version FROM draft_payload_data), 0) as draft_version,
    -- Extract auth_item_ids from draft payload if available, otherwise extract from auth_items array
    COALESCE(
        (SELECT payload->'authItemIds' FROM draft_payload_data),
        (SELECT payload->'auth_item_ids' FROM draft_payload_data),
        (SELECT COALESCE(jsonb_agg(aid.auth_item_id::text ORDER BY aid.position), '[]'::jsonb) FROM auth_items_data aid),
        '[]'::jsonb
    ) as auth_item_ids,
    -- Extract auth_item_active_states from draft payload if available, otherwise extract from auth_items array
    COALESCE(
        (SELECT payload->'authItemActiveStates' FROM draft_payload_data),
        (SELECT payload->'auth_item_active_states' FROM draft_payload_data),
        (SELECT COALESCE(jsonb_object_agg(aid.auth_item_id::text, aid.active), '{}'::jsonb) FROM auth_items_data aid),
        '{}'::jsonb
    ) as auth_item_active_states,
    -- Extract auth_item_encrypted_states from draft payload if available, otherwise extract from auth_items array
    COALESCE(
        (SELECT payload->'authItemEncryptedStates' FROM draft_payload_data),
        (SELECT payload->'auth_item_encrypted_states' FROM draft_payload_data),
        (SELECT COALESCE(jsonb_object_agg(aid.auth_item_id::text, aid.encrypted), '{}'::jsonb) FROM auth_items_data aid),
        '{}'::jsonb
    ) as auth_item_encrypted_states
FROM auth_exists_check aec
CROSS JOIN user_profile up
LEFT JOIN auth_data ad ON true
LEFT JOIN auth_items_data aid ON true
GROUP BY aec.auth_exists, ad.name, ad.description, ad.active, ad.can_edit, up.actor_name
$$;


--
-- Name: api_get_auth_items_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_auth_items_v4(auth_id uuid, department_id uuid) RETURNS TABLE(name text, value text, encrypted boolean)
    LANGUAGE sql STABLE
    AS $$
WITH dept_settings AS (
    -- Get department-specific settings if department_id provided
    SELECT DISTINCT s.id as settings_id
    FROM settings s
    JOIN department_settings ds ON ds.settings_id = s.id AND ds.active = true
    WHERE (api_get_auth_items_v4.department_id IS NOT NULL AND ds.department_id = api_get_auth_items_v4.department_id)
      AND s.active = true
),
default_settings AS (
    -- Get default settings (no department links)
    SELECT s.id as settings_id
    FROM settings s
    WHERE s.active = true
      AND NOT EXISTS (
          SELECT 1 FROM department_settings sd 
          WHERE sd.settings_id = s.id AND sd.active = true
      )
    LIMIT 1
),
-- Try department-specific settings first
dept_encrypted_items AS (
    SELECT ai.name, k.key as value, ai.encrypted
    FROM auth_items ai
    JOIN setting_auth_keys sak ON sak.auth_item_id = ai.id AND sak.active = true
    JOIN dept_settings ds ON sak.settings_id = ds.settings_id
    JOIN keys k ON k.id = sak.key_id AND k.active = true
    WHERE ai.auth_id = api_get_auth_items_v4.auth_id AND ai.encrypted = true
),
-- Fall back to default settings if department-specific has no keys
default_encrypted_items AS (
    SELECT ai.name, k.key as value, ai.encrypted
    FROM auth_items ai
    JOIN setting_auth_keys sak ON sak.auth_item_id = ai.id AND sak.active = true
    JOIN default_settings ds ON sak.settings_id = ds.settings_id
    JOIN keys k ON k.id = sak.key_id AND k.active = true
    WHERE ai.auth_id = api_get_auth_items_v4.auth_id 
      AND ai.encrypted = true
      -- Only use default if department-specific didn't have this key
      AND NOT EXISTS (
          SELECT 1 FROM dept_encrypted_items dei 
          WHERE dei.name = ai.name
      )
),
-- Combine encrypted items (dept first, then default fallback)
encrypted_items AS (
    SELECT name, value, encrypted FROM dept_encrypted_items
    UNION ALL
    SELECT name, value, encrypted FROM default_encrypted_items
),
-- Same logic for non-encrypted items
dept_non_encrypted_items AS (
    SELECT ai.name, sav.value, ai.encrypted
    FROM auth_items ai
    JOIN setting_auth_values sav ON sav.auth_item_id = ai.id
    JOIN dept_settings ds ON sav.settings_id = ds.settings_id
    WHERE ai.auth_id = api_get_auth_items_v4.auth_id AND ai.encrypted = false
),
default_non_encrypted_items AS (
    SELECT ai.name, sav.value, ai.encrypted
    FROM auth_items ai
    JOIN setting_auth_values sav ON sav.auth_item_id = ai.id
    JOIN default_settings ds ON sav.settings_id = ds.settings_id
    WHERE ai.auth_id = api_get_auth_items_v4.auth_id 
      AND ai.encrypted = false
      AND NOT EXISTS (
          SELECT 1 FROM dept_non_encrypted_items dni 
          WHERE dni.name = ai.name
      )
),
non_encrypted_items AS (
    SELECT name, value, encrypted FROM dept_non_encrypted_items
    UNION ALL
    SELECT name, value, encrypted FROM default_non_encrypted_items
)
SELECT name, value, encrypted 
FROM encrypted_items
UNION ALL
SELECT name, value, encrypted 
FROM non_encrypted_items
ORDER BY name
$$;


--
-- Name: api_get_auth_list_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_auth_list_v4(profile_id uuid) RETURNS TABLE(actor_name text, auths types.q_get_auth_list_v4_auth[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id
),
user_profile AS (
    SELECT 
        p.role,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
auth_item_counts AS (
    SELECT 
        auth_id,
        COUNT(*) as num_items
    FROM auth_items
    GROUP BY auth_id
),
auth_sample_items AS (
    SELECT 
        ai.auth_id,
        ARRAY_AGG(
            (ai.id, ai.name, ai.description)::types.q_get_auth_list_v4_auth_item
            ORDER BY ai.name
        ) as sample_items
    FROM (
        SELECT id, auth_id, name, description,
               ROW_NUMBER() OVER (PARTITION BY auth_id ORDER BY name) as rn
        FROM auth_items
    ) ai
    WHERE ai.rn <= 3
    GROUP BY ai.auth_id
)
SELECT 
    up.actor_name::text as actor_name,
    COALESCE(
        ARRAY_AGG(
            (a.id, a.name, a.description, a.active, a.updated_at,
             COALESCE(aic.num_items, 0),
             COALESCE(asi.sample_items, '{}'::types.q_get_auth_list_v4_auth_item[]),
             CASE WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true ELSE false END,
             CASE WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true ELSE false END,
             CASE WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true ELSE false END
            )::types.q_get_auth_list_v4_auth
            ORDER BY a.updated_at DESC NULLS LAST
        ),
        '{}'::types.q_get_auth_list_v4_auth[]
    ) as auths
FROM auth a
LEFT JOIN auth_item_counts aic ON aic.auth_id = a.id
LEFT JOIN auth_sample_items asi ON asi.auth_id = a.id
CROSS JOIN user_profile up
GROUP BY up.actor_name, up.role
$$;


--
-- Name: api_get_auth_new_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_auth_new_v4(profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(name text, description text, active boolean, can_edit boolean, auth_items types.q_get_auth_new_v4_auth_item[], actor_name text, draft_version integer, auth_item_ids jsonb, auth_item_active_states jsonb, auth_item_encrypted_states jsonb)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        profile_id AS profile_id,
        draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'auth'::draft_resource_type
    LIMIT 1
),
user_profile AS (
    SELECT 
        p.role,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
auth_data AS (
    SELECT 
        COALESCE(
            (SELECT payload->>'name' FROM draft_payload_data),
            ''::text
        ) as name,
        COALESCE(
            (SELECT payload->>'description' FROM draft_payload_data),
            ''::text
        ) as description,
        COALESCE(
            (SELECT (payload->>'active')::boolean FROM draft_payload_data),
            false::boolean
        ) as active,
        CASE 
            WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_edit
    FROM user_profile up
)
SELECT 
    ad.name::text as name,
    ad.description::text as description,
    ad.active::boolean as active,
    ad.can_edit::boolean as can_edit,
    '{}'::types.q_get_auth_new_v4_auth_item[] as auth_items,
    up.actor_name::text as actor_name,
    COALESCE((SELECT draft_version FROM draft_payload_data), 0) as draft_version,
    -- Extract auth_item_ids from draft payload if available
    COALESCE(
        (SELECT payload->'authItemIds' FROM draft_payload_data),
        (SELECT payload->'auth_item_ids' FROM draft_payload_data),
        '[]'::jsonb
    ) as auth_item_ids,
    -- Extract auth_item_active_states from draft payload if available
    COALESCE(
        (SELECT payload->'authItemActiveStates' FROM draft_payload_data),
        (SELECT payload->'auth_item_active_states' FROM draft_payload_data),
        '{}'::jsonb
    ) as auth_item_active_states,
    -- Extract auth_item_encrypted_states from draft payload if available
    COALESCE(
        (SELECT payload->'authItemEncryptedStates' FROM draft_payload_data),
        (SELECT payload->'auth_item_encrypted_states' FROM draft_payload_data),
        '{}'::jsonb
    ) as auth_item_encrypted_states
FROM auth_data ad
CROSS JOIN user_profile up
$$;


--
-- Name: api_get_auth_providers_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_auth_providers_v4(department_id uuid) RETURNS TABLE(id uuid, slug text, provider_id text, name text)
    LANGUAGE sql STABLE
    AS $$
WITH dept_settings AS (
    -- Get department-specific settings if department_id provided
    SELECT DISTINCT s.id as settings_id
    FROM settings s
    JOIN department_settings ds ON ds.settings_id = s.id AND ds.active = true
    WHERE (api_get_auth_providers_v4.department_id IS NOT NULL AND ds.department_id = api_get_auth_providers_v4.department_id)
      AND s.active = true
    LIMIT 1
),
default_settings AS (
    -- Get default settings (no department links)
    SELECT s.id as settings_id
    FROM settings s
    WHERE s.active = true
      AND NOT EXISTS (
          SELECT 1 FROM department_settings sd 
          WHERE sd.settings_id = s.id AND sd.active = true
      )
    LIMIT 1
),
-- Check if department-specific settings has keys for any provider
dept_settings_has_keys AS (
    SELECT 
        (SELECT settings_id FROM dept_settings LIMIT 1) as settings_id,
        EXISTS (
            SELECT 1 
            FROM setting_auth_keys sak
            JOIN dept_settings ds ON ds.settings_id = sak.settings_id
            WHERE sak.active = true
        ) as has_keys
),
-- Determine which settings to use (settings-based realm selection)
selected_settings AS (
    SELECT 
        CASE 
            -- If department_id is NULL, use default settings (master realm)
            WHEN api_get_auth_providers_v4.department_id IS NULL THEN (SELECT settings_id FROM default_settings)
            -- If department-specific settings has keys, use it
            WHEN (SELECT has_keys FROM dept_settings_has_keys) = true 
                THEN (SELECT settings_id FROM dept_settings LIMIT 1)
            -- Otherwise, fallback to default settings (master realm)
            ELSE (SELECT settings_id FROM default_settings)
        END as settings_id
),
settings_auths AS (
    -- Get auths linked to the selected settings
    SELECT DISTINCT a.id
    FROM auth a
    JOIN setting_auths sa ON sa.auth_id = a.id AND sa.active = true
    JOIN selected_settings ss ON sa.settings_id = ss.settings_id
    WHERE a.active = true
)
-- Return providers for the selected settings
SELECT DISTINCT
    a.id, 
    a.slug, 
    a.auth_type as provider_id, 
    a.name 
FROM auth a
WHERE a.active = true
  AND EXISTS (SELECT 1 FROM settings_auths sa WHERE sa.id = a.id)
ORDER BY a.slug
$$;


--
-- Name: api_get_benchmark_bundle_v4(uuid, uuid[], text, boolean, text, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_benchmark_bundle_v4(profile_id uuid, eval_ids uuid[] DEFAULT ARRAY[]::uuid[], status text DEFAULT NULL::text, archived boolean DEFAULT NULL::boolean, search text DEFAULT NULL::text, page integer DEFAULT 0, page_size integer DEFAULT 20) RETURNS TABLE(actor_name text, evals types.q_get_benchmark_bundle_v4_eval[], attempts types.q_get_benchmark_bundle_v4_eval_attempt[], rubrics types.q_get_benchmark_bundle_v4_rubric[], departments types.q_get_benchmark_bundle_v4_department[], agents types.q_get_benchmark_bundle_v4_agent[], standard_groups types.q_get_benchmark_bundle_v4_standard_group[], standards types.q_get_benchmark_bundle_v4_standard[], rubric_standard_groups types.q_get_benchmark_bundle_v4_rubric_standard_group[], rubric_options types.q_get_benchmark_bundle_v4_rubric_option[], department_options types.q_get_benchmark_bundle_v4_department_option[], agent_options types.q_get_benchmark_bundle_v4_agent_option[], total_count bigint, page integer, page_size integer, total_pages integer)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        profile_id AS profile_id,
        COALESCE(NULLIF(eval_ids, ARRAY[]::uuid[]), NULL::uuid[]) AS eval_ids,
        COALESCE(NULLIF(status, ''), NULL::text) AS status,
        archived AS archived,
        COALESCE(NULLIF(search, ''), NULL::text) AS search,
        COALESCE(page, 0) AS page,
        COALESCE(page_size, 20) AS page_size
),
resolve_profile_id AS (
    SELECT 
        CASE 
            WHEN (SELECT profile_id FROM params)::text IS NULL OR (SELECT profile_id FROM params)::text = '' THEN NULL::uuid
            ELSE (SELECT profile_id FROM params)::uuid
        END as resolved_profile_id
),
actor_profile AS (
    SELECT 
        p.first_name || ' ' || p.last_name as actor_name
    FROM resolve_profile_id rpi
    JOIN profiles p ON p.id = rpi.resolved_profile_id
    WHERE rpi.resolved_profile_id IS NOT NULL
),
user_departments AS (
    SELECT department_id
    FROM profile_departments
    WHERE profile_id = (SELECT resolved_profile_id FROM resolve_profile_id) AND active = true
),
user_profile AS (
    SELECT 
        role,
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM resolve_profile_id rpi
    JOIN profiles p ON p.id = rpi.resolved_profile_id
    WHERE rpi.resolved_profile_id IS NOT NULL
),
eval_status_summary AS (
    SELECT 
        er.eval_id,
        COUNT(*) as total_runs,
        COUNT(*) FILTER (WHERE er.completed = true) as completed_runs,
        COUNT(*) FILTER (WHERE er.completed = false) as pending_runs
    FROM eval_runs er
    GROUP BY er.eval_id
),
eval_data AS (
    SELECT 
        e.id as eval_id,
        e.name,
        e.description,
        -- Get first rubric from junction table (runs or groups based on use_groups)
        (SELECT rga.rubric_id 
         FROM (
             SELECT errga.rubric_grade_agent_id, errga.created_at
             FROM eval_runs_rubric_grade_agents errga
             WHERE errga.eval_id = e.id AND e.use_groups = false
             UNION ALL
             SELECT egga.rubric_grade_agent_id, egga.created_at
             FROM eval_groups_rubric_grade_agents egga
             WHERE egga.eval_id = e.id AND e.use_groups = true
         ) combined
         JOIN rubric_grade_agents rga ON rga.id = combined.rubric_grade_agent_id
         ORDER BY combined.created_at 
         LIMIT 1) as rubric_id,
        e.dynamic,
        e.created_at,
        e.updated_at,
        (SELECT r.name 
         FROM (
             SELECT errga.rubric_grade_agent_id, errga.created_at
             FROM eval_runs_rubric_grade_agents errga
             WHERE errga.eval_id = e.id AND e.use_groups = false
             UNION ALL
             SELECT egga.rubric_grade_agent_id, egga.created_at
             FROM eval_groups_rubric_grade_agents egga
             WHERE egga.eval_id = e.id AND e.use_groups = true
         ) combined
         JOIN rubric_grade_agents rga ON rga.id = combined.rubric_grade_agent_id
         JOIN rubrics r ON r.id = rga.rubric_id
         ORDER BY combined.created_at 
         LIMIT 1) as rubric_name,
        (SELECT r.description 
         FROM (
             SELECT errga.rubric_grade_agent_id, errga.created_at
             FROM eval_runs_rubric_grade_agents errga
             WHERE errga.eval_id = e.id AND e.use_groups = false
             UNION ALL
             SELECT egga.rubric_grade_agent_id, egga.created_at
             FROM eval_groups_rubric_grade_agents egga
             WHERE egga.eval_id = e.id AND e.use_groups = true
         ) combined
         JOIN rubric_grade_agents rga ON rga.id = combined.rubric_grade_agent_id
         JOIN rubrics r ON r.id = rga.rubric_id
         ORDER BY combined.created_at 
         LIMIT 1) as rubric_description,
        COALESCE(ess.total_runs, 0) as total_runs,
        COALESCE(ess.completed_runs, 0) as completed_runs,
        COALESCE(ess.pending_runs, 0) as pending_runs,
        CASE 
            WHEN ess.total_runs IS NULL OR ess.total_runs = 0 THEN 'pending'
            WHEN ess.pending_runs > 0 THEN 'running'
            WHEN ess.completed_runs = ess.total_runs THEN 'completed'
            ELSE 'pending'
        END as status
    FROM evals e
    LEFT JOIN eval_status_summary ess ON ess.eval_id = e.id
),
rubric_departments_data AS (
    SELECT 
        rd.rubric_id,
        ARRAY_AGG(rd.department_id::text ORDER BY rd.created_at) as department_ids
    FROM rubric_departments rd
    WHERE rd.active = true
    GROUP BY rd.rubric_id
),
eval_departments AS (
    SELECT 
        ed.eval_id,
        rdd.department_ids
    FROM eval_data ed
    LEFT JOIN rubric_departments_data rdd ON rdd.rubric_id = ed.rubric_id
),
filtered_evals AS (
    SELECT 
        ed.*,
        edept.department_ids,
        CASE 
            WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_edit,
        CASE 
            WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_delete
    FROM eval_data ed
    LEFT JOIN eval_departments edept ON edept.eval_id = ed.eval_id
    CROSS JOIN user_profile up
    WHERE 
        -- Filter by department access (if rubric has departments, user must have access)
        (
            edept.department_ids IS NULL 
            OR array_length(edept.department_ids, 1) IS NULL
            OR EXISTS (
                SELECT 1 FROM user_departments ud
                WHERE ud.department_id::text = ANY(edept.department_ids)
            )
            OR up.role IN ('admin'::profile_role, 'superadmin'::profile_role)
        )
),
all_rubric_ids AS (
    SELECT DISTINCT rubric_id FROM filtered_evals
),
all_department_ids AS (
    SELECT DISTINCT unnest(department_ids) as department_id
    FROM eval_departments
    WHERE department_ids IS NOT NULL
),
all_agent_ids AS (
    SELECT DISTINCT ea.agent_id::uuid as agent_id
    FROM filtered_evals fe
    JOIN eval_agents ea ON ea.eval_id = fe.eval_id
),
-- Get eval attempts with eval info
attempts_with_eval AS (
    SELECT 
        ea.id as attempt_id,
        ea.created_at as attempt_created_at,
        ea.eval_id,
        ea.archived,
        e.name as eval_name,
        e.description as eval_description,
        -- Get first rubric from junction table (runs or groups based on use_groups)
        (SELECT rga.rubric_id 
         FROM (
             SELECT errga.rubric_grade_agent_id, errga.created_at
             FROM eval_runs_rubric_grade_agents errga
             WHERE errga.eval_id = e.id AND e.use_groups = false
             UNION ALL
             SELECT egga.rubric_grade_agent_id, egga.created_at
             FROM eval_groups_rubric_grade_agents egga
             WHERE egga.eval_id = e.id AND e.use_groups = true
         ) combined
         JOIN rubric_grade_agents rga ON rga.id = combined.rubric_grade_agent_id
         ORDER BY combined.created_at 
         LIMIT 1) as rubric_id,
        (SELECT r.name 
         FROM (
             SELECT errga.rubric_grade_agent_id, errga.created_at
             FROM eval_runs_rubric_grade_agents errga
             WHERE errga.eval_id = e.id AND e.use_groups = false
             UNION ALL
             SELECT egga.rubric_grade_agent_id, egga.created_at
             FROM eval_groups_rubric_grade_agents egga
             WHERE egga.eval_id = e.id AND e.use_groups = true
         ) combined
         JOIN rubric_grade_agents rga ON rga.id = combined.rubric_grade_agent_id
         JOIN rubrics r ON r.id = rga.rubric_id
         ORDER BY combined.created_at 
         LIMIT 1) as rubric_name
    FROM eval_attempts ea
    JOIN evals e ON e.id = ea.eval_id
    CROSS JOIN params p
    WHERE 
        -- Filter by eval_ids if provided
        (p.eval_ids IS NULL OR p.eval_ids = ARRAY[]::uuid[] OR ea.eval_id = ANY(p.eval_ids))
        -- Filter by archived if provided
        AND (p.archived IS NULL OR ea.archived = p.archived)
),
-- Get eval departments for access control (for attempts)
attempt_eval_departments AS (
    SELECT 
        rd.rubric_id as eval_id,
        ARRAY_AGG(rd.department_id::text ORDER BY rd.created_at) as department_ids
    FROM rubric_departments rd
    WHERE rd.active = true
    GROUP BY rd.rubric_id
),
-- Calculate run counts and status for each attempt
attempt_status_summary AS (
    SELECT 
        aea.attempt_id,
        aea.eval_id,
        -- Count runs from eval_runs for this eval
        COUNT(DISTINCT er.run_id) as total_runs,
        -- Count completed runs (where test exists and is completed)
        COUNT(DISTINCT er.run_id) FILTER (
            WHERE EXISTS (
                SELECT 1
                FROM attempt_tests at
                JOIN tests t ON t.id = at.test_id
                WHERE at.attempt_id = aea.attempt_id
                  AND t.trace_id LIKE 'eval_' || aea.attempt_id::text || '_%'
                  AND SPLIT_PART(t.trace_id, '_', 3) = er.run_id::text
                  AND t.completed = true
            )
        ) as completed_runs,
        -- Count pending runs (where test doesn't exist or is not completed)
        COUNT(DISTINCT er.run_id) FILTER (
            WHERE NOT EXISTS (
                SELECT 1
                FROM attempt_tests at
                JOIN tests t ON t.id = at.test_id
                WHERE at.attempt_id = aea.attempt_id
                  AND t.trace_id LIKE 'eval_' || aea.attempt_id::text || '_%'
                  AND SPLIT_PART(t.trace_id, '_', 3) = er.run_id::text
                  AND t.completed = true
            )
        ) as pending_runs
    FROM attempts_with_eval aea
    LEFT JOIN eval_runs er ON er.eval_id = aea.eval_id
    GROUP BY aea.attempt_id, aea.eval_id
),
-- Derive status from run counts
attempts_with_status AS (
    SELECT 
        aea.*,
        COALESCE(ass.total_runs, 0) as total_runs,
        COALESCE(ass.completed_runs, 0) as completed_runs,
        COALESCE(ass.pending_runs, 0) as pending_runs,
        CASE 
            WHEN COALESCE(ass.total_runs, 0) = 0 THEN 'pending'
            WHEN COALESCE(ass.pending_runs, 0) > 0 THEN 'running'
            WHEN COALESCE(ass.completed_runs, 0) = COALESCE(ass.total_runs, 0) AND COALESCE(ass.total_runs, 0) > 0 THEN 'completed'
            ELSE 'pending'
        END as status
    FROM attempts_with_eval aea
    LEFT JOIN attempt_status_summary ass ON ass.attempt_id = aea.attempt_id
),
-- Apply status filter and search if provided
filtered_attempts AS (
    SELECT aas.*
    FROM attempts_with_status aas
    CROSS JOIN params p
    WHERE 
        (p.status IS NULL OR p.status = '' OR aas.status = p.status)
        -- Apply search filter if provided
        AND (
            p.search IS NULL 
            OR p.search = '' 
            OR aas.eval_name ILIKE '%' || p.search || '%'
            OR aas.eval_description ILIKE '%' || p.search || '%'
        )
        -- Apply department access control
        AND (
            NOT EXISTS (SELECT 1 FROM attempt_eval_departments aed WHERE aed.eval_id = aas.eval_id)
            OR EXISTS (
                SELECT 1 
                FROM attempt_eval_departments aed
                JOIN user_departments ud ON ud.department_id::text = ANY(aed.department_ids)
                WHERE aed.eval_id = aas.eval_id
            )
            OR EXISTS (SELECT 1 FROM user_profile WHERE role IN ('admin', 'superadmin'))
        )
),
-- Apply pagination using ROW_NUMBER() to avoid OFFSET variable issue
numbered_attempts AS (
    SELECT 
        fa.*,
        ROW_NUMBER() OVER (ORDER BY fa.attempt_created_at DESC) as rn
    FROM filtered_attempts fa
),
paginated_attempts AS (
    SELECT 
        na.attempt_id,
        na.attempt_created_at,
        na.eval_id,
        na.archived,
        na.eval_name,
        na.eval_description,
        na.rubric_id,
        na.rubric_name,
        na.total_runs,
        na.completed_runs,
        na.pending_runs,
        na.status
    FROM numbered_attempts na
    CROSS JOIN params p
    WHERE na.rn > (p.page * p.page_size) 
      AND na.rn <= ((p.page + 1) * p.page_size)
),
-- Get total count
total_count AS (
    SELECT COUNT(*) as count
    FROM filtered_attempts
),
eval_agents_aggregated AS (
    SELECT 
        ea.eval_id,
        ARRAY_AGG(ea.agent_id::text ORDER BY ea.created_at) as agent_ids
    FROM eval_agents ea
    WHERE ea.eval_id IN (SELECT eval_id FROM filtered_evals)
    GROUP BY ea.eval_id
),
-- Build composite type arrays for evals
evals_array AS (
    SELECT COALESCE(
        ARRAY_AGG(
            (fe.eval_id, fe.name, fe.description, fe.rubric_id, COALESCE(eaa.agent_ids, ARRAY[]::text[]), fe.dynamic,
             fe.rubric_name, fe.rubric_description, fe.total_runs, fe.completed_runs, fe.pending_runs,
             fe.status, fe.created_at, fe.updated_at,
             COALESCE(fe.department_ids, ARRAY[]::text[]),
             fe.can_edit, fe.can_delete
            )::types.q_get_benchmark_bundle_v4_eval
            ORDER BY fe.updated_at DESC NULLS LAST
        ),
        '{}'::types.q_get_benchmark_bundle_v4_eval[]
    ) as evals
    FROM filtered_evals fe
    LEFT JOIN eval_agents_aggregated eaa ON eaa.eval_id = fe.eval_id
),
-- Build composite type arrays for attempts
attempts_array AS (
    SELECT COALESCE(
        ARRAY_AGG(
            (pa.attempt_id, pa.eval_id, pa.eval_name, pa.eval_description, pa.rubric_id, pa.rubric_name,
             pa.attempt_created_at, pa.archived, pa.status, pa.total_runs, pa.completed_runs, pa.pending_runs
            )::types.q_get_benchmark_bundle_v4_eval_attempt
            ORDER BY pa.attempt_created_at DESC
        ),
        '{}'::types.q_get_benchmark_bundle_v4_eval_attempt[]
    ) as attempts
    FROM paginated_attempts pa
),
-- Build composite type arrays for rubrics
rubrics_array AS (
    SELECT COALESCE(
        ARRAY_AGG(
            (r.id, r.name, COALESCE(r.description, ''), r.points, r.pass_points
            )::types.q_get_benchmark_bundle_v4_rubric
            ORDER BY r.name
        ),
        '{}'::types.q_get_benchmark_bundle_v4_rubric[]
    ) as rubrics
    FROM all_rubric_ids ari
    LEFT JOIN rubrics r ON r.id = ari.rubric_id
    WHERE r.id IS NOT NULL
),
-- Build composite type arrays for departments
departments_array AS (
    SELECT COALESCE(
        ARRAY_AGG(
            (d.id, d.title, COALESCE(d.description, '')
            )::types.q_get_benchmark_bundle_v4_department
            ORDER BY d.title
        ),
        '{}'::types.q_get_benchmark_bundle_v4_department[]
    ) as departments
    FROM all_department_ids adi
    LEFT JOIN departments d ON d.id::text = adi.department_id
    WHERE d.active = true AND d.id IS NOT NULL
),
-- Build composite type arrays for agents
agents_array AS (
    SELECT COALESCE(
        ARRAY_AGG(
            (a.id, a.name, COALESCE(a.description, '')
            )::types.q_get_benchmark_bundle_v4_agent
            ORDER BY a.name
        ),
        '{}'::types.q_get_benchmark_bundle_v4_agent[]
    ) as agents
    FROM all_agent_ids aai
    LEFT JOIN agents a ON a.id = aai.agent_id
    WHERE a.active = true AND a.id IS NOT NULL
),
-- Build composite type arrays for standard groups
standard_groups_array AS (
    SELECT COALESCE(
        ARRAY_AGG(
            (sg.id, sg.name, sg.description, sg.points, sg.pass_points
            )::types.q_get_benchmark_bundle_v4_standard_group
            ORDER BY sg.name
        ),
        '{}'::types.q_get_benchmark_bundle_v4_standard_group[]
    ) as standard_groups
    FROM rubric_standard_groups rsg
    JOIN standard_groups sg ON sg.id = rsg.standard_group_id
    WHERE rsg.rubric_id IN (SELECT rubric_id FROM all_rubric_ids)
      AND rsg.active = true
),
-- Build composite type arrays for standards
standards_array AS (
    SELECT COALESCE(
        ARRAY_AGG(
            (st.id, st.name, st.description, st.points
            )::types.q_get_benchmark_bundle_v4_standard
            ORDER BY st.name
        ),
        '{}'::types.q_get_benchmark_bundle_v4_standard[]
    ) as standards
    FROM standards st
    WHERE st.standard_group_id IN (
        SELECT rsg.standard_group_id FROM rubric_standard_groups rsg
        WHERE rsg.rubric_id IN (SELECT rubric_id FROM all_rubric_ids)
          AND rsg.active = true
    )
),
-- Build standard_ids per standard_group first
standard_group_standards AS (
    SELECT 
        rsg.standard_group_id,
        rsg.rubric_id,
        COALESCE(
            ARRAY_AGG(st.id ORDER BY st.id) FILTER (WHERE st.id IS NOT NULL),
            ARRAY[]::uuid[]
        ) as standard_ids
    FROM rubric_standard_groups rsg
    JOIN standard_groups sg ON sg.id = rsg.standard_group_id
    LEFT JOIN standards st ON st.standard_group_id = sg.id
    WHERE rsg.rubric_id IN (SELECT rubric_id FROM all_rubric_ids)
      AND rsg.active = true
    GROUP BY rsg.standard_group_id, rsg.rubric_id
),
-- Build composite type arrays for rubric-standard group relationships
rubric_standard_groups_array AS (
    SELECT COALESCE(
        ARRAY_AGG(
            (sgs.rubric_id, sgs.standard_group_id, sgs.standard_ids
            )::types.q_get_benchmark_bundle_v4_rubric_standard_group
            ORDER BY sgs.rubric_id, sgs.standard_group_id
        ),
        '{}'::types.q_get_benchmark_bundle_v4_rubric_standard_group[]
    ) as rubric_standard_groups
    FROM standard_group_standards sgs
),
-- Build options arrays (for facets)
rubric_options_array AS (
    SELECT COALESCE(
        ARRAY_AGG(
            (r.id::text, r.name
            )::types.q_get_benchmark_bundle_v4_rubric_option
            ORDER BY r.name
        ),
        '{}'::types.q_get_benchmark_bundle_v4_rubric_option[]
    ) as rubric_options
    FROM all_rubric_ids ari
    LEFT JOIN rubrics r ON r.id = ari.rubric_id
    WHERE r.id IS NOT NULL
),
-- Collect all department IDs actually assigned to evals
assigned_department_ids AS (
    SELECT DISTINCT unnest(department_ids) as department_id
    FROM filtered_evals
    WHERE department_ids IS NOT NULL
),
department_options_array AS (
    SELECT COALESCE(
        ARRAY_AGG(
            (d.id::text, d.title
            )::types.q_get_benchmark_bundle_v4_department_option
            ORDER BY d.title
        ),
        '{}'::types.q_get_benchmark_bundle_v4_department_option[]
    ) as department_options
    FROM assigned_department_ids adi
    LEFT JOIN departments d ON d.id::text = adi.department_id
    WHERE d.active = true AND d.id IS NOT NULL
),
-- Collect all agent IDs actually assigned to evals
assigned_agent_ids AS (
    SELECT DISTINCT ea.agent_id::uuid as agent_id
    FROM filtered_evals fe
    JOIN eval_agents ea ON ea.eval_id = fe.eval_id
),
agent_options_array AS (
    SELECT COALESCE(
        ARRAY_AGG(
            (a.id::text, a.name
            )::types.q_get_benchmark_bundle_v4_agent_option
            ORDER BY a.name
        ),
        '{}'::types.q_get_benchmark_bundle_v4_agent_option[]
    ) as agent_options
    FROM assigned_agent_ids aai
    LEFT JOIN agents a ON a.id = aai.agent_id
    WHERE a.active = true AND a.id IS NOT NULL
)
SELECT 
    (SELECT actor_name FROM actor_profile LIMIT 1)::text as actor_name,
    (SELECT evals FROM evals_array) as evals,
    (SELECT attempts FROM attempts_array) as attempts,
    (SELECT rubrics FROM rubrics_array) as rubrics,
    (SELECT departments FROM departments_array) as departments,
    (SELECT agents FROM agents_array) as agents,
    (SELECT standard_groups FROM standard_groups_array) as standard_groups,
    (SELECT standards FROM standards_array) as standards,
    (SELECT rubric_standard_groups FROM rubric_standard_groups_array) as rubric_standard_groups,
    (SELECT rubric_options FROM rubric_options_array) as rubric_options,
    (SELECT department_options FROM department_options_array) as department_options,
    (SELECT agent_options FROM agent_options_array) as agent_options,
    COALESCE((SELECT count FROM total_count), 0)::bigint as total_count,
    p.page::int as page,
    p.page_size::int as page_size,
    CASE 
        WHEN p.page_size > 0 THEN CEIL(COALESCE((SELECT count FROM total_count), 0)::float / p.page_size::float)
        ELSE 0
    END::int as total_pages
FROM params p
$$;


--
-- Name: api_get_certificate_data_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_certificate_data_v4(profile_id uuid) RETURNS TABLE(profile_name text, actor_name text, cohorts types.q_get_certificate_data_v4_cohort[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id
),
profile_info AS (
    SELECT 
        id,
        first_name || ' ' || last_name AS profile_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
-- Get all cohorts the profile belongs to
profile_cohorts AS (
    SELECT DISTINCT
        c.id AS cohort_id,
        c.title AS cohort_title
    FROM params x
    JOIN cohort_profiles cp ON cp.profile_id = x.profile_id
    JOIN cohorts c ON c.id = cp.cohort_id
    WHERE cp.active = TRUE
      AND c.active = TRUE
),
-- Get all simulations for each cohort
cohort_sims AS (
    SELECT DISTINCT
        pc.cohort_id,
        pc.cohort_title,
        s.id AS simulation_id,
        s.title AS simulation_title,
        (SELECT rga.rubric_id FROM simulation_scenarios ss 
         JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
         JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
         WHERE ss.simulation_id = s.id AND ss.active = true 
         ORDER BY ss.position 
         LIMIT 1) as rubric_id
    FROM profile_cohorts pc
    JOIN cohort_simulations cs ON cs.cohort_id = pc.cohort_id
    JOIN simulations s ON s.id = cs.simulation_id
    WHERE cs.active = TRUE
      AND s.active = TRUE
      AND s.practice_simulation = FALSE
),
-- Get expected scenarios per simulation
sim_expected AS (
    SELECT 
        cs.simulation_id,
        COALESCE(COUNT(*), 0) AS expected_scenarios
    FROM cohort_sims cs
    LEFT JOIN simulation_scenarios ss ON ss.simulation_id = cs.simulation_id
    GROUP BY cs.simulation_id
),
-- Get attempt data from analytics (using same pattern as home_overview.sql)
-- Filter analytics for this profile's attempts
filt AS (
    SELECT a.* 
    FROM params x
    JOIN analytics a ON a.profile_id = x.profile_id
    WHERE a.simulation_id IN (SELECT simulation_id FROM cohort_sims)
      AND a.is_practice = FALSE
      AND a.is_archived = FALSE
),
-- Per attempt: sum grade_percent over completed root scenarios
attempt_scores AS (
    SELECT
        ap.attempt_id,
        ap.profile_id,
        ap.simulation_id,
        COALESCE(SUM(ap.grade_percent) FILTER (WHERE ap.completed AND ap.grade_percent IS NOT NULL), 0)::numeric AS sum_completed_pct,
        se.expected_scenarios
    FROM filt ap
    JOIN sim_expected se ON se.simulation_id = ap.simulation_id
    GROUP BY ap.attempt_id, ap.profile_id, ap.simulation_id, se.expected_scenarios
),
-- Average over expected scenarios (missing = 0)
attempt_avg AS (
    SELECT
        attempt_id,
        profile_id,
        simulation_id,
        CASE WHEN expected_scenarios > 0
             THEN (sum_completed_pct / expected_scenarios)
             ELSE 0 END AS avg_pct_over_expected
    FROM attempt_scores
),
-- User-simulation status with best attempt + pass status
user_sim_status AS (
    SELECT
        aa.profile_id,
        aa.simulation_id,
        MAX(aa.avg_pct_over_expected) AS avg_pct_over_expected,
        BOOL_OR(aa.avg_pct_over_expected >= COALESCE(
            (SELECT ROUND(100.0 * r.pass_points::numeric / NULLIF(r.points,0))
             FROM simulations s
             LEFT JOIN simulation_scenarios ss_rubric ON ss_rubric.simulation_id = s.id AND ss_rubric.active = true
             LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga_rubric ON ssrga_rubric.simulation_id = ss_rubric.simulation_id AND ssrga_rubric.scenario_id = ss_rubric.scenario_id
             LEFT JOIN rubric_grade_agents rga_rubric ON rga_rubric.id = ssrga_rubric.rubric_grade_agent_id
             LEFT JOIN rubrics r ON r.id = rga_rubric.rubric_id
             WHERE s.id = aa.simulation_id
             ORDER BY ss_rubric.position
             LIMIT 1), 70
        )) AS passed
    FROM attempt_avg aa
    GROUP BY aa.profile_id, aa.simulation_id
),
-- Combine simulation data with scores and pass status
simulation_results AS (
    SELECT 
        cs.cohort_id,
        cs.cohort_title,
        cs.simulation_id,
        cs.simulation_title,
        COALESCE(ROUND(uss.avg_pct_over_expected::numeric)::int, 0) AS score,
        COALESCE(uss.passed, FALSE) AS passed
    FROM cohort_sims cs
    LEFT JOIN user_sim_status uss ON uss.simulation_id = cs.simulation_id AND uss.profile_id = (SELECT profile_id FROM params)
),
-- Group simulations by cohort using composite types
cohort_simulation_data AS (
    SELECT 
        cohort_id,
        cohort_title,
        COALESCE(
            ARRAY_AGG(
                (sr.simulation_title, sr.score, sr.passed)::types.q_get_certificate_data_v4_simulation
                ORDER BY sr.simulation_title
            ),
            '{}'::types.q_get_certificate_data_v4_simulation[]
        ) AS simulations,
        BOOL_AND(sr.passed) AS cohort_passed
    FROM simulation_results sr
    GROUP BY cohort_id, cohort_title
),
-- Final cohort data with nested composite types
cohort_data AS (
    SELECT 
        cohort_title AS name,
        cohort_passed AS passed,
        simulations
    FROM cohort_simulation_data
)
-- Final result
SELECT 
    pi.profile_name::text as profile_name,
    pi.profile_name::text as actor_name,
    COALESCE(
        (SELECT ARRAY_AGG(
            (cd.name, cd.passed, cd.simulations)::types.q_get_certificate_data_v4_cohort
            ORDER BY cd.name
        )
        FROM cohort_data cd),
        '{}'::types.q_get_certificate_data_v4_cohort[]
    ) AS cohorts
FROM profile_info pi
LIMIT 1
$$;


--
-- Name: api_get_chat_basic_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_chat_basic_v4(chat_id uuid) RETURNS TABLE(id uuid, completed boolean, scenario_id uuid)
    LANGUAGE sql STABLE
    AS $$
SELECT id, completed, scenario_id
FROM chats
WHERE id = chat_id
$$;


--
-- Name: api_get_chat_personas_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_chat_personas_v4(chat_id uuid) RETURNS TABLE(persona_id text, persona_name text)
    LANGUAGE sql STABLE
    AS $$
SELECT 
    p.id::text as persona_id,
    p.name as persona_name
FROM chats c
JOIN scenario_personas sp ON sp.scenario_id = c.scenario_id AND sp.active = true
JOIN personas p ON p.id = sp.persona_id
WHERE c.id = chat_id
  AND p.active = true
ORDER BY p.name
$$;


--
-- Name: api_get_cohort_new_v4(uuid, uuid, text, boolean, uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_cohort_new_v4(profile_id uuid, draft_id uuid DEFAULT NULL::uuid, simulation_search text DEFAULT NULL::text, simulation_show_selected boolean DEFAULT NULL::boolean, current_simulation_ids uuid[] DEFAULT NULL::uuid[]) RETURNS TABLE(title text, description text, department_ids text[], active boolean, can_edit boolean, profile_ids text[], simulation_ids text[], valid_department_ids text[], valid_simulation_ids text[], valid_profile_ids text[], simulations types.q_get_cohort_detail_v4_simulation[], simulations_for_picker types.q_get_cohort_detail_v4_simulation_for_picker[], profiles types.q_get_cohort_new_v4_profile[], staff types.q_get_cohort_new_v4_staff_item[], cohorts types.q_get_cohort_new_v4_cohort[], departments_for_staff types.q_get_cohort_new_v4_department_for_staff[], departments types.q_get_cohort_new_v4_department[], primary_department_id text, actor_name text)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        profile_id AS profile_id,
        draft_id AS draft_id,
        simulation_search AS simulation_search,
        COALESCE(simulation_show_selected, false) AS simulation_show_selected,
        current_simulation_ids AS current_simulation_ids
),
draft_payload_data AS (
    SELECT 
        d.payload
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'cohorts'::draft_resource_type
    LIMIT 1
),
user_departments AS (
    SELECT ARRAY_AGG(DISTINCT pd.department_id) as dept_ids
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id
),
default_cohort AS (
    SELECT c.id
    FROM params x
    JOIN cohorts c ON c.active = true
    LEFT JOIN cohort_departments cd ON cd.cohort_id = c.id AND cd.active = true
    GROUP BY c.id
    HAVING 
        COUNT(cd.cohort_id) FILTER (WHERE cd.department_id = ANY(COALESCE((SELECT dept_ids FROM user_departments), ARRAY[]::uuid[]))) > 0
        OR NOT EXISTS (SELECT 1 FROM cohort_departments cd2 WHERE cd2.cohort_id = c.id AND cd2.active = true)
    ORDER BY c.created_at DESC
    LIMIT 1
),
cohort_departments_data AS (
    SELECT 
        cd.cohort_id,
        ARRAY_AGG(cd.department_id::text ORDER BY cd.created_at) as department_ids
    FROM default_cohort dc
    JOIN cohort_departments cd ON cd.cohort_id = dc.id AND cd.active = true
    GROUP BY cd.cohort_id
),
cohort_data AS (
    SELECT 
        COALESCE((SELECT id FROM default_cohort LIMIT 1), NULL::uuid) as id,
        COALESCE(
            (SELECT payload->>'title' FROM draft_payload_data),
            ''::text
        ) as title,
        COALESCE(
            (SELECT payload->>'description' FROM draft_payload_data),
            ''::text
        ) as description,
        COALESCE(
            (SELECT (payload->>'active')::boolean FROM draft_payload_data),
            true::boolean
        ) as active,
        COALESCE(
            CASE 
                WHEN EXISTS (SELECT 1 FROM draft_payload_data WHERE payload ? 'department_ids') 
                THEN (SELECT ARRAY(SELECT jsonb_array_elements_text(payload->'department_ids')) FROM draft_payload_data)
                ELSE NULL
            END,
            NULL::text[]
        ) as department_ids
    FROM params x
    LEFT JOIN default_cohort dc ON true
    LEFT JOIN cohorts c ON c.id = dc.id
    LEFT JOIN cohort_departments_data cdd ON cdd.cohort_id = c.id
),
cohort_profile_ids AS (
    SELECT cp.profile_id
    FROM default_cohort dc
    JOIN cohort_profiles cp ON cp.cohort_id = dc.id AND cp.active = true
),
draft_simulation_active_states AS (
    -- Extract simulation_active_states from draft payload if it exists
    SELECT 
        key::uuid as simulation_id,
        value::boolean as active
    FROM params x
    CROSS JOIN draft_payload_data dpd
    CROSS JOIN jsonb_each_text(dpd.payload->'simulation_active_states')
    WHERE EXISTS (SELECT 1 FROM draft_payload_data WHERE payload ? 'simulation_active_states')
),
draft_simulation_positions AS (
    -- Extract positions from draft simulation_ids array order (if draft exists)
    SELECT 
        sim_id::uuid as simulation_id,
        ROW_NUMBER() OVER (ORDER BY ordinality) as position
    FROM params x
    CROSS JOIN draft_payload_data dpd
    CROSS JOIN jsonb_array_elements_text(dpd.payload->'simulation_ids') WITH ORDINALITY AS t(sim_id, ordinality)
    WHERE EXISTS (SELECT 1 FROM draft_payload_data WHERE payload ? 'simulation_ids')
),
cohort_simulation_ids AS (
    SELECT cs.simulation_id, cs.active, cs.position
    FROM default_cohort dc
    JOIN cohort_simulations cs ON cs.cohort_id = dc.id
),
-- Build simulation list from draft if it exists, otherwise from default cohort
all_simulation_ids AS (
    -- If draft has simulation_ids, use those; otherwise use default cohort simulations
    SELECT DISTINCT sim_id::uuid as simulation_id
    FROM (
        SELECT sim_id
        FROM params x
        CROSS JOIN draft_payload_data dpd
        CROSS JOIN jsonb_array_elements_text(dpd.payload->'simulation_ids') AS t(sim_id)
        WHERE EXISTS (SELECT 1 FROM draft_payload_data WHERE payload ? 'simulation_ids')
        UNION
        SELECT cs.simulation_id::text as sim_id
        FROM cohort_simulation_ids cs
        WHERE NOT EXISTS (SELECT 1 FROM draft_payload_data WHERE payload ? 'simulation_ids')
    ) combined
),
cohort_simulation_stats AS (
    SELECT 
        asi.simulation_id,
        -- Use draft active state if available, otherwise use default cohort active state, default to true
        COALESCE(
            (SELECT active FROM draft_simulation_active_states WHERE simulation_id = asi.simulation_id),
            (SELECT active FROM cohort_simulation_ids WHERE simulation_id = asi.simulation_id),
            true
        ) as active,
        -- Use draft position if available, otherwise use default cohort position, default to array position
        COALESCE(
            (SELECT position FROM draft_simulation_positions WHERE simulation_id = asi.simulation_id),
            (SELECT position FROM cohort_simulation_ids WHERE simulation_id = asi.simulation_id),
            0
        ) as position,
        s.title as name,
        COALESCE(s.description, '') as description,
        COALESCE(
            (SELECT SUM(stl.time_limit_seconds)
             FROM scenario_time_limits stl
             JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
             WHERE stl.simulation_id = s.id AND stl.active = true AND ss.active = true),
            0
        ) as time_limit,
        COUNT(DISTINCT sa.id) as usage_count,
        COALESCE(
            ROUND(
                100.0 * SUM(CASE WHEN scg.passed = true THEN 1 ELSE 0 END)::numeric 
                / NULLIF(COUNT(scg.id), 0)
            )::int,
            0
        ) as success_rate,
        MAX(sa.created_at) as last_used
    FROM all_simulation_ids asi
    JOIN simulations s ON s.id = asi.simulation_id
    LEFT JOIN simulation_attempts sa ON sa.simulation_id = asi.simulation_id 
    LEFT JOIN attempt_profiles ap ON ap.attempt_id = sa.id AND ap.active = true
    LEFT JOIN cohort_profile_ids cp ON cp.profile_id = ap.profile_id
    LEFT JOIN attempt_chats ac ON ac.attempt_id = sa.id
    LEFT JOIN chats sc ON sc.id = ac.chat_id
    LEFT JOIN grades scg ON EXISTS (
        SELECT 1 FROM runs r_check
        JOIN group_runs gr_check ON gr_check.run_id = r_check.id
        JOIN groups g_check ON g_check.id = gr_check.group_id
        JOIN chat_groups cg_check ON cg_check.group_id = g_check.id
        JOIN chats c_check ON c_check.id = cg_check.chat_id
        WHERE r_check.id = scg.run_id AND c_check.id = sc.id
    )
    LEFT JOIN runs r_cohort_new ON r_cohort_new.id = scg.run_id
    LEFT JOIN LATERAL (
        SELECT DISTINCT c.id AS chat_id
        FROM runs r
        JOIN group_runs gr ON gr.run_id = r.id
        JOIN groups g ON g.id = gr.group_id
        JOIN chat_groups cg ON cg.group_id = g.id
        JOIN chats c ON c.id = cg.chat_id
        WHERE r.id = r_cohort_new.id AND c.id = sc.id
        LIMIT 1
    ) chat_lookup_cohort ON true
    GROUP BY asi.simulation_id, s.id, s.title, s.description
),
valid_departments AS (
    SELECT DISTINCT d.id, d.title as name, d.description
    FROM params x
    JOIN departments d ON true
    JOIN profile_departments pd ON pd.department_id = d.id
    WHERE pd.profile_id = x.profile_id AND d.active = true
),
valid_dept_ids AS (
    SELECT id FROM valid_departments
),
cohort_is_default AS (
    SELECT 
        CASE 
            -- If draft exists and has department_ids, it's not a default cohort
            WHEN EXISTS (SELECT 1 FROM draft_payload_data WHERE payload ? 'department_ids') THEN false
            -- If no draft, check if department_ids from default cohort is NULL
            WHEN COALESCE(cd.department_ids, NULL) IS NULL THEN true
            ELSE false
        END as is_default
    FROM cohort_data cd
),
valid_simulations AS (
    SELECT DISTINCT s.id
    FROM params x
    JOIN simulations s ON s.active = true
    LEFT JOIN simulation_departments sd ON sd.simulation_id = s.id AND sd.active = true
    CROSS JOIN cohort_is_default cid
    GROUP BY s.id, cid.is_default
    HAVING 
        -- For new cohorts (no draft), include all simulations accessible to user's departments
        (cid.is_default = true AND (
            COUNT(sd.simulation_id) FILTER (WHERE sd.department_id IN (SELECT id FROM valid_dept_ids)) > 0
            OR NOT EXISTS (SELECT 1 FROM simulation_departments sd2 WHERE sd2.simulation_id = s.id AND sd2.active = true)
        ))
        OR
        -- For cohorts with department links (from draft), use department filtering
        (cid.is_default = false AND (
            COUNT(sd.simulation_id) FILTER (WHERE sd.department_id IN (SELECT id FROM valid_dept_ids)) > 0
            OR NOT EXISTS (SELECT 1 FROM simulation_departments sd2 WHERE sd2.simulation_id = s.id AND sd2.active = true)
        ))
),
valid_profiles AS (
    SELECT DISTINCT p.id
    FROM params x
    JOIN profiles p ON p.active = true
    LEFT JOIN profile_departments pd ON pd.profile_id = p.id
    CROSS JOIN cohort_is_default cid
    WHERE (
        -- For default cohorts (no department links), include all profiles in the cohort
        (cid.is_default = true AND p.id IN (SELECT profile_id FROM cohort_profile_ids))
        OR
        -- For non-default cohorts, use department filtering
        (cid.is_default = false AND pd.department_id IN (SELECT id FROM valid_dept_ids))
    )
),
cross_dept_simulations AS (
    SELECT DISTINCT s.id::text as simulation_id
    FROM simulations s
    WHERE s.active = true
        AND NOT EXISTS (
            SELECT 1 FROM simulation_departments sd2 
            WHERE sd2.simulation_id = s.id AND sd2.active = true
        )
),
department_simulation_ids AS (
    SELECT 
        d.id as department_id,
        ARRAY_AGG(DISTINCT s.id::text) FILTER (WHERE s.id IS NOT NULL) as simulation_ids
    FROM valid_departments d
    LEFT JOIN simulation_departments sd ON sd.department_id = d.id AND sd.active = true
    LEFT JOIN simulations s ON s.id = sd.simulation_id AND s.active = true
    GROUP BY d.id
),
department_simulation_ids_with_cross AS (
    SELECT 
        dsi.department_id,
        COALESCE(dsi.simulation_ids, ARRAY[]::text[]) || 
        COALESCE(ARRAY(SELECT simulation_id FROM cross_dept_simulations), ARRAY[]::text[]) as simulation_ids
    FROM department_simulation_ids dsi
),
department_profile_ids AS (
    SELECT 
        d.id as department_id,
        ARRAY_AGG(DISTINCT p.id::text) FILTER (WHERE p.id IS NOT NULL) as staff_ids
    FROM valid_departments d
    LEFT JOIN profile_departments pd ON pd.department_id = d.id
    LEFT JOIN profiles p ON p.id = pd.profile_id AND p.active = true
    GROUP BY d.id
),
simulation_mapping_data AS (
    SELECT 
        s.id::text as simulation_id,
        s.title as name,
        COALESCE(s.description, '') as description,
        COALESCE(
            (SELECT SUM(stl.time_limit_seconds)
             FROM scenario_time_limits stl
             JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
             WHERE stl.simulation_id = s.id AND stl.active = true AND ss.active = true),
            0
        ) as time_limit,
        ARRAY[]::text[] as department_ids
    FROM params x
    JOIN simulations s ON s.active = true
    WHERE s.id IN (SELECT id FROM valid_simulations)
),
-- Extract current simulation IDs from draft payload if not provided in params
current_simulation_ids_from_draft AS (
    SELECT 
        CASE 
            WHEN EXISTS (SELECT 1 FROM draft_payload_data WHERE payload ? 'simulation_ids') 
            THEN ARRAY(
                SELECT sim_id::uuid
                FROM draft_payload_data dpd
                CROSS JOIN jsonb_array_elements_text(dpd.payload->'simulation_ids') AS t(sim_id)
            )
            ELSE NULL::uuid[]
        END as simulation_ids
),
-- Combine current_simulation_ids from params or draft
effective_current_simulation_ids AS (
    SELECT 
        COALESCE(
            (SELECT current_simulation_ids FROM params WHERE current_simulation_ids IS NOT NULL AND cardinality(current_simulation_ids) > 0),
            (SELECT simulation_ids FROM current_simulation_ids_from_draft),
            NULL::uuid[]
        ) as simulation_ids
),
-- Filtered simulations_for_picker based on search and show_selected
simulations_for_picker_filtered AS (
    SELECT smd.simulation_id, smd.name, smd.description, smd.time_limit, smd.department_ids
    FROM simulation_mapping_data smd
    CROSS JOIN params p
    CROSS JOIN effective_current_simulation_ids ecsi
    WHERE 
        -- Search filter: if simulation_search provided and not empty, match name or description
        -- Otherwise, return all (no search filter)
        (
            p.simulation_search IS NULL OR 
            p.simulation_search = '' OR
            LOWER(smd.name) LIKE '%' || LOWER(COALESCE(p.simulation_search, '')) || '%' OR
            LOWER(smd.description) LIKE '%' || LOWER(COALESCE(p.simulation_search, '')) || '%'
        )
        -- Show selected filter: if enabled and current_simulation_ids available, only show selected simulations
        AND (
            NOT p.simulation_show_selected OR
            ecsi.simulation_ids IS NULL OR
            cardinality(ecsi.simulation_ids) = 0 OR
            smd.simulation_id::uuid = ANY(ecsi.simulation_ids)
        )
),
profile_mapping_data AS (
    SELECT 
        p.id as profile_id,
        p.first_name || ' ' || p.last_name as name,
        COALESCE((SELECT email FROM profile_emails WHERE profile_id = p.id AND is_primary = true AND active = true LIMIT 1), '') as description
    FROM params x
    JOIN profiles p ON p.id IN (SELECT profile_id FROM cohort_profile_ids)
),
profile_active_cohort_links AS (
    SELECT 
        profile_id,
        COUNT(*) as active_cohort_count
    FROM cohort_profiles
    WHERE active = true
    GROUP BY profile_id
),
profile_all_cohort_links AS (
    SELECT 
        profile_id,
        COUNT(*) as total_cohort_links
    FROM cohort_profiles
    GROUP BY profile_id
),
profile_cohorts AS (
    SELECT 
        cp.profile_id,
        ARRAY_AGG(cp.cohort_id::text ORDER BY c.title) as cohort_ids
    FROM cohort_profiles cp
    JOIN cohorts c ON c.id = cp.cohort_id
    WHERE cp.active = true
    GROUP BY cp.profile_id
),
profile_departments_agg AS (
    SELECT 
        pd.profile_id,
        ARRAY_AGG(pd.department_id::text ORDER BY d.title) as department_ids
    FROM profile_departments pd
    JOIN departments d ON d.id = pd.department_id
    WHERE pd.active = true
    GROUP BY pd.profile_id
),
profile_primary_department AS (
    SELECT 
        pd.profile_id,
        pd.department_id
    FROM profile_departments pd
    WHERE pd.active = true AND pd.is_primary = true
),
recent_runs AS (
    SELECT 
        mrp.profile_id,
        COUNT(*) as run_count
    FROM runs mr
    JOIN run_profiles mrp ON mrp.run_id = mr.id
    WHERE mr.created_at >= NOW() - INTERVAL '24 hours'
    GROUP BY mrp.profile_id
),
profile_total_runs AS (
    SELECT 
        mrp.profile_id,
        COUNT(*) as total_requests
    FROM run_profiles mrp
    GROUP BY mrp.profile_id
),
all_cohort_ids_for_staff AS (
    SELECT DISTINCT unnest(cohort_ids)::uuid as cohort_id
    FROM profile_cohorts
),
all_department_ids_for_staff AS (
    SELECT DISTINCT unnest(department_ids)::uuid as department_id
    FROM profile_departments_agg
),
cohort_mapping_data AS (
    SELECT 
        c.id as cohort_id,
        c.title as name,
        COALESCE(c.description, '') as description
    FROM cohorts c
    WHERE c.id IN (SELECT cohort_id FROM all_cohort_ids_for_staff)
),
department_mapping_for_staff_data AS (
    SELECT 
        d.id::text as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM departments d
    WHERE d.id IN (SELECT department_id FROM all_department_ids_for_staff)
    AND d.active = true
),
user_profile_for_staff AS (
    SELECT role FROM params x JOIN profiles p ON p.id = x.profile_id
),
user_profile_for_cohort AS (
    SELECT 
        role,
        first_name || ' ' || last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
primary_department_id AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.is_primary = TRUE
    LIMIT 1
),
cohort_staff AS (
    SELECT DISTINCT ON (p.id)
        p.id as profile_id,
        p.first_name,
        p.last_name,
        ARRAY_AGG(pe.email ORDER BY pe.is_primary DESC, pe.created_at) FILTER (WHERE pe.active = true) as emails,
        (SELECT email FROM profile_emails WHERE profile_id = p.id AND is_primary = true AND active = true LIMIT 1) as primary_email,
        p.first_name || ' ' || p.last_name as name,
        p.role,
        SUBSTRING(p.first_name FROM 1 FOR 1) || SUBSTRING(p.last_name FROM 1 FOR 1) as initials,
        p.active,
        pa.last_active as lastActive,
        prl.requests_per_day as requests_per_day,
        COALESCE(rr.run_count::int, 0) as requests_in_last_day,
        COALESCE(pc.cohort_ids, ARRAY[]::text[]) as cohort_ids,
        COALESCE(pda.department_ids, ARRAY[]::text[]) as department_ids,
        ppd.department_id as department_id,
        COALESCE(ptr.total_requests, 0) as total_requests,
        COALESCE(pacl.active_cohort_count, 0) as active_cohort_count,
        COALESCE(pacl_all.total_cohort_links, 0) as total_cohort_links,
        CASE 
            WHEN p.id = (SELECT profile_id FROM params) THEN true
            WHEN ups.role = 'superadmin'::profile_role THEN true
            WHEN ups.role = 'admin'::profile_role AND p.role IN ('instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role) THEN true
            WHEN ups.role = 'instructional'::profile_role AND p.role IN ('member'::profile_role, 'guest'::profile_role) THEN true
            WHEN ups.role = 'member'::profile_role AND p.role = 'guest'::profile_role THEN true
            ELSE false
        END as can_edit,
        CASE 
            WHEN p.id = (SELECT profile_id FROM params) THEN false
            WHEN ups.role = 'superadmin'::profile_role THEN true
            WHEN COALESCE(pacl_all.total_cohort_links, 0) > 0 THEN false
            WHEN ups.role = 'admin'::profile_role AND p.role IN ('instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role) THEN true
            WHEN ups.role = 'instructional'::profile_role AND p.role IN ('member'::profile_role, 'guest'::profile_role) THEN true
            WHEN ups.role = 'member'::profile_role AND p.role = 'guest'::profile_role THEN true
            ELSE false
        END as can_delete,
        CASE 
            WHEN p.id = (SELECT profile_id FROM params) THEN false
            WHEN ups.role = 'superadmin'::profile_role THEN true
            WHEN ups.role = 'admin'::profile_role AND p.role IN ('admin'::profile_role, 'instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role) THEN true
            WHEN ups.role = 'instructional'::profile_role AND p.role IN ('instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role) THEN true
            WHEN ups.role = 'member'::profile_role AND p.role IN ('member'::profile_role, 'guest'::profile_role) THEN true
            WHEN ups.role = 'guest'::profile_role AND p.role = 'guest'::profile_role THEN true
            ELSE false
        END as can_remove
    FROM params x
    JOIN profiles p ON true
    JOIN cohort_profile_ids cpi ON cpi.profile_id = p.id
    LEFT JOIN profile_emails pe ON pe.profile_id = p.id AND pe.active = true
    LEFT JOIN profile_cohorts pc ON pc.profile_id = p.id
    LEFT JOIN profile_departments_agg pda ON pda.profile_id = p.id
    LEFT JOIN profile_primary_department ppd ON ppd.profile_id = p.id
    LEFT JOIN profile_total_runs ptr ON ptr.profile_id = p.id
    LEFT JOIN profile_active_cohort_links pacl ON pacl.profile_id = p.id
    LEFT JOIN profile_all_cohort_links pacl_all ON pacl_all.profile_id = p.id
    LEFT JOIN recent_runs rr ON rr.profile_id = p.id
    LEFT JOIN profile_request_limits prl ON prl.profile_id = p.id AND prl.active = true
    LEFT JOIN LATERAL (
        SELECT last_active 
        FROM profile_activity 
        WHERE profile_id = p.id 
        ORDER BY created_at DESC 
        LIMIT 1
    ) pa ON true
    CROSS JOIN user_profile_for_staff ups
    WHERE (
        ups.role = 'superadmin'::profile_role OR
        (ups.role = 'admin'::profile_role AND p.role IN ('admin'::profile_role, 'instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role)) OR
        (ups.role = 'instructional'::profile_role AND p.role IN ('instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role)) OR
        (ups.role = 'member'::profile_role AND p.role IN ('member'::profile_role, 'guest'::profile_role)) OR
        (ups.role = 'guest'::profile_role AND p.role = 'guest'::profile_role)
    )
    GROUP BY p.id, p.first_name, p.last_name, p.role, p.active,
             pa.last_active, prl.requests_per_day,
             pc.cohort_ids, pda.department_ids, ppd.department_id, ptr.total_requests,
             pacl.active_cohort_count, pacl_all.total_cohort_links, rr.run_count, ups.role
    ORDER BY p.id, p.last_name, p.first_name
),
department_mapping_data AS (
    SELECT 
        vd.id as department_id,
        vd.name,
        COALESCE(vd.description, '') as description,
        COALESCE(dsic.simulation_ids, ARRAY[]::text[]) as simulation_ids,
        COALESCE(dpi.staff_ids, ARRAY[]::text[]) as staff_ids
    FROM valid_departments vd
    LEFT JOIN department_simulation_ids_with_cross dsic ON dsic.department_id = vd.id
    LEFT JOIN department_profile_ids dpi ON dpi.department_id = vd.id
)
SELECT 
    cd.title,
    cd.description,
    cd.department_ids,
    cd.active,
    CASE 
        WHEN COALESCE(cd.department_ids, NULL) IS NULL AND upc.role != 'superadmin' THEN false
        WHEN upc.role IN ('admin', 'superadmin') THEN true
        ELSE false
    END as can_edit,
    (SELECT COALESCE(array_agg(profile_id::text), ARRAY[]::text[])
     FROM cohort_profile_ids) as profile_ids,
    CASE 
        -- If draft exists and has simulation_ids, use draft (preserve order with WITH ORDINALITY)
        WHEN EXISTS (SELECT 1 FROM draft_payload_data WHERE payload ? 'simulation_ids') 
        THEN (
            SELECT ARRAY(
                SELECT sim_id 
                FROM draft_payload_data dpd
                CROSS JOIN jsonb_array_elements_text(dpd.payload->'simulation_ids') WITH ORDINALITY AS t(sim_id, ordinality)
                ORDER BY ordinality
            )
        )
        -- Otherwise, return empty array for new cohort (no draft)
        ELSE ARRAY[]::text[]
    END as simulation_ids,
    (SELECT COALESCE(array_agg(id::text), ARRAY[]::text[])
     FROM valid_dept_ids) as valid_department_ids,
    (SELECT COALESCE(array_agg(id::text), ARRAY[]::text[])
     FROM valid_simulations) as valid_simulation_ids,
    (SELECT COALESCE(array_agg(id::text), ARRAY[]::text[])
     FROM valid_profiles) as valid_profile_ids,
    (SELECT COALESCE(
        ARRAY_AGG(
            (css.simulation_id::text, css.name, css.description, css.time_limit, css.active, css.position, css.usage_count, css.success_rate, css.last_used, CASE WHEN css.usage_count = 0 THEN true ELSE false END)::types.q_get_cohort_detail_v4_simulation
            ORDER BY css.position
        ),
        '{}'::types.q_get_cohort_detail_v4_simulation[]
    )
     FROM cohort_simulation_stats css) as simulations,
    (SELECT COALESCE(
        ARRAY_AGG(
            (sfpf.simulation_id, sfpf.name, sfpf.description, sfpf.time_limit, sfpf.department_ids)::types.q_get_cohort_detail_v4_simulation_for_picker
        ),
        '{}'::types.q_get_cohort_detail_v4_simulation_for_picker[]
    )
     FROM simulations_for_picker_filtered sfpf) as simulations_for_picker,
    (SELECT COALESCE(
        ARRAY_AGG(
            (pmd.profile_id, pmd.name, pmd.description)::types.q_get_cohort_new_v4_profile
        ),
        '{}'::types.q_get_cohort_new_v4_profile[]
    )
     FROM profile_mapping_data pmd) as profiles,
    (SELECT COALESCE(
        ARRAY_AGG(
            (cs.profile_id, cs.first_name, cs.last_name, cs.emails, cs.primary_email, cs.name, cs.role, cs.initials, cs.active, cs.lastActive, cs.cohort_ids, cs.department_ids, cs.department_id, cs.requests_per_day, cs.total_requests, cs.requests_in_last_day, cs.can_edit, cs.can_delete, cs.can_remove)::types.q_get_cohort_new_v4_staff_item
            ORDER BY cs.last_name, cs.first_name
        ),
        '{}'::types.q_get_cohort_new_v4_staff_item[]
    )
     FROM cohort_staff cs) as staff,
    (SELECT COALESCE(
        ARRAY_AGG(
            (cmd.cohort_id, cmd.name, cmd.description)::types.q_get_cohort_new_v4_cohort
        ),
        '{}'::types.q_get_cohort_new_v4_cohort[]
    )
     FROM cohort_mapping_data cmd) as cohorts,
    (SELECT COALESCE(
        ARRAY_AGG(
            (dmfsd.department_id, dmfsd.name, dmfsd.description)::types.q_get_cohort_new_v4_department_for_staff
        ),
        '{}'::types.q_get_cohort_new_v4_department_for_staff[]
    )
     FROM department_mapping_for_staff_data dmfsd) as departments_for_staff,
    (SELECT COALESCE(
        ARRAY_AGG(
            (dmd.department_id, dmd.name, dmd.description, dmd.simulation_ids, dmd.staff_ids)::types.q_get_cohort_new_v4_department
        ),
        '{}'::types.q_get_cohort_new_v4_department[]
    )
     FROM department_mapping_data dmd) as departments,
    (SELECT department_id FROM primary_department_id LIMIT 1) as primary_department_id,
    upc.actor_name
FROM cohort_data cd
CROSS JOIN user_profile_for_cohort upc
$$;


--
-- Name: api_get_cohort_search_v4(uuid, uuid, text, uuid[], integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_cohort_search_v4(p_profile_id uuid, p_cohort_id uuid DEFAULT NULL::uuid, p_query text DEFAULT NULL::text, p_dept_ids uuid[] DEFAULT ARRAY[]::uuid[], p_limit_count integer DEFAULT 200) RETURNS TABLE(staff types.q_get_cohort_new_v4_staff_item[], cohorts types.q_get_cohort_search_v4_cohort[], departments types.q_get_cohort_search_v4_department[], actor_name text)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT
        p_profile_id::uuid AS profile_id,
        p_cohort_id::uuid AS cohort_id,
        NULLIF(TRIM(p_query), '')::text AS query,
        (p_dept_ids::uuid[]) AS dept_filter,
        p_limit_count::int AS limit_count
),
user_profile AS (
    SELECT 
        COALESCE((SELECT role FROM params x JOIN profiles p ON p.id = x.profile_id), 'guest') as role,
        COALESCE((SELECT first_name || ' ' || last_name FROM params x JOIN profiles p ON p.id = x.profile_id), 'System') as actor_name
    FROM params
),
user_departments AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.active = true
),
profile_cohorts AS (
    SELECT
        cp.profile_id,
        ARRAY_AGG(cp.cohort_id::text ORDER BY c.title) as cohort_ids
    FROM cohort_profiles cp
    JOIN cohorts c ON c.id = cp.cohort_id
    WHERE cp.active = true
    GROUP BY cp.profile_id
),
profile_departments_agg AS (
    SELECT
        pd.profile_id,
        ARRAY_AGG(pd.department_id::text ORDER BY d.title) as department_ids
    FROM profile_departments pd
    JOIN departments d ON d.id = pd.department_id
    WHERE pd.active = true
    GROUP BY pd.profile_id
),
recent_runs AS (
    SELECT
        rp.profile_id,
        COUNT(*) as run_count
    FROM runs r
    JOIN run_profiles rp ON rp.run_id = r.id AND rp.active = true
    WHERE r.created_at >= NOW() - INTERVAL '24 hours'
    GROUP BY rp.profile_id
),
profile_total_runs AS (
    SELECT
        rp.profile_id,
        COUNT(*) as total_requests
    FROM run_profiles rp
    WHERE rp.active = true
    GROUP BY rp.profile_id
),
all_cohort_ids AS (
    SELECT DISTINCT c.id as cohort_id
    FROM cohorts c
    WHERE c.active = true
),
cohorts_data AS (
    SELECT 
        c.id as cohort_id,
        c.title as name,
        COALESCE(c.description, '') as description
    FROM cohorts c
    WHERE c.id IN (SELECT cohort_id FROM all_cohort_ids)
),
departments_data AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM departments d
    WHERE d.active = true
),
staff_data AS (
    SELECT DISTINCT ON (p.id)
        p.id as profile_id,
        p.first_name,
        p.last_name,
        ARRAY_AGG(pe.email ORDER BY pe.is_primary DESC, pe.created_at) FILTER (WHERE pe.active = true) as emails,
        (SELECT pe.email FROM profile_emails pe WHERE pe.profile_id = p.id AND pe.is_primary = true AND pe.active = true LIMIT 1) as primary_email,
        p.first_name || ' ' || p.last_name as name,
        p.role,
        SUBSTRING(p.first_name FROM 1 FOR 1) || SUBSTRING(p.last_name FROM 1 FOR 1) as initials,
        p.active,
        pa.last_active as last_active,
        COALESCE(pc.cohort_ids, ARRAY[]::text[]) as cohort_ids,
        COALESCE(pda.department_ids, ARRAY[]::text[]) as department_ids,
        (SELECT pd2.department_id FROM profile_departments pd2 WHERE pd2.profile_id = p.id AND pd2.active = true AND pd2.is_primary = true LIMIT 1) as primary_department_id,
        prl.requests_per_day as requests_per_day,
        COALESCE(ptr.total_requests, 0) as total_requests,
        COALESCE(rr.run_count::int, 0) as requests_in_last_day,
        false as can_edit,
        false as can_delete,
        false as can_remove
    FROM params x
    JOIN profiles p ON true
    JOIN profile_departments pd ON pd.profile_id = p.id AND pd.active = true
    LEFT JOIN profile_emails pe ON pe.profile_id = p.id AND pe.active = true
    LEFT JOIN profile_cohorts pc ON pc.profile_id = p.id
    LEFT JOIN profile_departments_agg pda ON pda.profile_id = p.id
    LEFT JOIN profile_total_runs ptr ON ptr.profile_id = p.id
    LEFT JOIN recent_runs rr ON rr.profile_id = p.id
    LEFT JOIN profile_request_limits prl ON prl.profile_id = p.id AND prl.active = true
    LEFT JOIN LATERAL (
        SELECT last_active
        FROM profile_activity
        WHERE profile_id = p.id
        ORDER BY created_at DESC
        LIMIT 1
    ) pa ON true
    CROSS JOIN user_profile up
    WHERE (
        -- Superadmin sees all staff
        up.role = 'superadmin'
        OR
        -- For search, show all staff with active departments
        true
    )
    -- Search query filter (if provided)
    AND (
        x.query IS NULL
        OR (
            p.first_name ILIKE '%' || x.query || '%'
            OR p.last_name ILIKE '%' || x.query || '%'
            OR EXISTS (SELECT 1 FROM profile_emails pe WHERE pe.profile_id = p.id AND pe.active = true AND pe.email ILIKE '%' || x.query || '%')
            OR p.role::text ILIKE '%' || x.query || '%'
            OR (p.first_name || ' ' || p.last_name) ILIKE '%' || x.query || '%'
        )
    )
    -- Cohort exclusion filter (if cohort_id provided)
    AND (
        x.cohort_id IS NULL
        OR NOT EXISTS (SELECT 1 FROM cohort_profiles cp WHERE cp.profile_id = p.id AND cp.cohort_id = x.cohort_id AND cp.active = true)
    )
    -- Department filter (if department_ids provided)
    AND (
        array_length(x.dept_filter, 1) IS NULL
        OR EXISTS (SELECT 1 FROM profile_departments pd_filter WHERE pd_filter.profile_id = p.id AND pd_filter.department_id = ANY(x.dept_filter) AND pd_filter.active = true)
    )
    GROUP BY p.id, p.first_name, p.last_name, p.role, p.active,
             pa.last_active, prl.requests_per_day,
             pc.cohort_ids, pda.department_ids, ptr.total_requests, rr.run_count
    ORDER BY p.id, p.last_name, p.first_name
    LIMIT (SELECT limit_count FROM params LIMIT 1)
)
SELECT 
    -- Aggregate staff separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (sd.profile_id::text, sd.first_name, sd.last_name, sd.emails, sd.primary_email, sd.name, sd.role, sd.initials, sd.active, sd.last_active, sd.cohort_ids, sd.department_ids, sd.primary_department_id, sd.requests_per_day, sd.total_requests, sd.requests_in_last_day, sd.can_edit, sd.can_delete, sd.can_remove)::types.q_get_cohort_new_v4_staff_item
            ORDER BY sd.last_name, sd.first_name
        ) FROM staff_data sd),
        '{}'::types.q_get_cohort_new_v4_staff_item[]
    ) as staff,
    -- Aggregate cohorts separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (cd.cohort_id, cd.name, cd.description)::types.q_get_cohort_search_v4_cohort
            ORDER BY cd.name
        ) FROM cohorts_data cd),
        '{}'::types.q_get_cohort_search_v4_cohort[]
    ) as cohorts,
    -- Aggregate departments separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (dd.department_id, dd.name, dd.description)::types.q_get_cohort_search_v4_department
            ORDER BY dd.name
        ) FROM departments_data dd),
        '{}'::types.q_get_cohort_search_v4_department[]
    ) as departments,
    up.actor_name
FROM user_profile up
$$;


--
-- Name: api_get_create_staff_data_v4(uuid[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_create_staff_data_v4(department_ids uuid[], profile_id uuid) RETURNS TABLE(actor_name text, staff types.q_get_create_staff_data_v4_staff[], cohorts types.q_get_create_staff_data_v4_cohort[], departments types.q_get_create_staff_data_v4_department[], role_options text[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids,
        profile_id AS profile_id
),
user_profile AS (
    SELECT 
        COALESCE((SELECT role FROM profiles WHERE id = (SELECT profile_id FROM params)), 'guest') as role,
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
user_departments AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments ON profile_departments.profile_id = x.profile_id AND profile_departments.active = true
),
profile_cohorts AS (
    SELECT 
        cp.profile_id,
        ARRAY_AGG(cp.cohort_id::text ORDER BY c.title) as cohort_ids
    FROM cohort_profiles cp
    JOIN cohorts c ON c.id = cp.cohort_id
    WHERE cp.active = true
    GROUP BY cp.profile_id
),
profile_departments_agg AS (
    SELECT 
        pd.profile_id,
        ARRAY_AGG(pd.department_id::text ORDER BY d.title) as department_ids
    FROM profile_departments pd
    JOIN departments d ON d.id = pd.department_id
    WHERE pd.active = true
    GROUP BY pd.profile_id
),
profile_primary_department AS (
    SELECT 
        pd.profile_id,
        pd.department_id::text as department_id
    FROM profile_departments pd
    WHERE pd.active = true AND pd.is_primary = true
),
recent_runs AS (
    SELECT 
        mrp.profile_id,
        COUNT(*) as run_count
    FROM runs mr
    JOIN run_profiles mrp ON mrp.run_id = mr.id
    WHERE mr.created_at >= NOW() - INTERVAL '24 hours'
    GROUP BY mrp.profile_id
),
profile_total_runs AS (
    SELECT 
        mrp.profile_id,
        COUNT(*) as total_requests
    FROM run_profiles mrp
    GROUP BY mrp.profile_id
),
all_cohort_ids AS (
    SELECT DISTINCT c.id as cohort_id
    FROM cohorts c
    WHERE c.active = true
),
cohorts_data AS (
    SELECT 
        c.id as cohort_id,
        c.title as name,
        COALESCE(c.description, '') as description
    FROM cohorts c
    WHERE c.id IN (SELECT cohort_id FROM all_cohort_ids)
),
departments_data AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM departments d
    WHERE d.active = true
),
staff_rows AS (
    SELECT DISTINCT ON (p.id)
        p.id as profile_id,
        p.first_name,
        p.last_name,
        COALESCE(
            ARRAY(
                SELECT email FROM (
                    SELECT DISTINCT ON (pe2.email) 
                        pe2.email,
                        pe2.is_primary,
                        pe2.created_at
                    FROM profile_emails pe2 
                    WHERE pe2.profile_id = p.id AND pe2.active = true 
                    ORDER BY pe2.email, pe2.is_primary DESC, pe2.created_at
                ) distinct_emails
                ORDER BY is_primary DESC, created_at
            ),
            ARRAY[]::text[]
        ) as emails,
        (SELECT email FROM profile_emails WHERE profile_id = p.id AND is_primary = true AND active = true LIMIT 1) as primary_email,
        p.first_name || ' ' || p.last_name as name,
        p.role,
        p.active,
        pa.last_active,
        COALESCE(
            ARRAY(SELECT unnest(pc.cohort_ids)::text),
            ARRAY[]::text[]
        ) as cohort_ids,
        COALESCE(
            ARRAY(SELECT unnest(pda.department_ids)::text),
            ARRAY[]::text[]
        ) as department_ids,
        COALESCE(ppd.department_id, '') as primary_department_id,
        prl.requests_per_day,
        COALESCE(ptr.total_requests, 0) as total_requests,
        COALESCE(rr.run_count::int, 0) as requests_in_last_day
    FROM profiles p
    JOIN profile_departments pd ON pd.profile_id = p.id AND pd.active = true
    LEFT JOIN profile_cohorts pc ON pc.profile_id = p.id
    LEFT JOIN profile_departments_agg pda ON pda.profile_id = p.id
    LEFT JOIN profile_primary_department ppd ON ppd.profile_id = p.id
    LEFT JOIN profile_total_runs ptr ON ptr.profile_id = p.id
    LEFT JOIN recent_runs rr ON rr.profile_id = p.id
    LEFT JOIN profile_request_limits prl ON prl.profile_id = p.id AND prl.active = true
    LEFT JOIN LATERAL (
        SELECT last_active 
        FROM profile_activity 
        WHERE profile_id = p.id 
        ORDER BY created_at DESC 
        LIMIT 1
    ) pa ON true
    CROSS JOIN user_profile up
    WHERE (
        -- Superadmin sees all staff
        up.role = 'superadmin'::profile_role
        OR
        -- For create-staff-data, show all staff with active departments
        true
    )
    GROUP BY p.id, p.first_name, p.last_name, p.role, p.active,
             pa.last_active, prl.requests_per_day, pc.cohort_ids, pda.department_ids,
             ppd.department_id, ptr.total_requests, rr.run_count
    ORDER BY p.id, p.last_name, p.first_name
)
SELECT 
    up.actor_name::text as actor_name,
    COALESCE(
        (SELECT ARRAY_AGG(
            (sr.profile_id, sr.first_name, sr.last_name, sr.emails, sr.primary_email, sr.name, sr.role, sr.active, sr.last_active, sr.cohort_ids, sr.department_ids, sr.primary_department_id, sr.requests_per_day, sr.total_requests, sr.requests_in_last_day)::types.q_get_create_staff_data_v4_staff
            ORDER BY sr.last_name, sr.first_name
        )
        FROM staff_rows sr),
        '{}'::types.q_get_create_staff_data_v4_staff[]
    ) as staff,
    COALESCE(
        (SELECT ARRAY_AGG(
            (cd.cohort_id, cd.name, cd.description)::types.q_get_create_staff_data_v4_cohort
            ORDER BY cd.name
        )
        FROM cohorts_data cd),
        '{}'::types.q_get_create_staff_data_v4_cohort[]
    ) as cohorts,
    COALESCE(
        (SELECT ARRAY_AGG(
            (dd.department_id, dd.name, dd.description)::types.q_get_create_staff_data_v4_department
            ORDER BY dd.name
        )
        FROM departments_data dd),
        '{}'::types.q_get_create_staff_data_v4_department[]
    ) as departments,
    ARRAY['superadmin', 'admin', 'instructional', 'member', 'guest']::text[] as role_options
FROM user_profile up
$$;


--
-- Name: api_get_dashboard_bundle_v4(text, text, uuid[], public.profile_role[], text[], uuid[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_dashboard_bundle_v4(start_date text, end_date text, cohort_ids uuid[] DEFAULT ARRAY[]::uuid[], roles public.profile_role[] DEFAULT ARRAY[]::public.profile_role[], simulation_filters text[] DEFAULT ARRAY[]::text[], department_ids uuid[] DEFAULT ARRAY[]::uuid[], profile_id uuid DEFAULT NULL::uuid) RETURNS TABLE(actor_name text, header_metrics types.q_get_dashboard_bundle_v4_header_metrics, primary_metrics types.q_get_dashboard_bundle_v4_primary_metrics, secondary_metrics types.q_get_dashboard_bundle_v4_secondary_metrics, footer_metrics types.q_get_dashboard_bundle_v4_footer_metrics, history types.q_get_dashboard_bundle_v4_attempt_history_row[], insights types.q_get_dashboard_bundle_v4_insights, thresholds types.q_get_dashboard_bundle_v4_thresholds, simulations types.q_get_dashboard_bundle_v4_simulation[], rubrics types.q_get_dashboard_bundle_v4_rubric[], parameters types.q_get_dashboard_bundle_v4_parameter[], fields types.q_get_dashboard_bundle_v4_field[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        start_date::timestamptz AS start_date,
        end_date::timestamptz AS end_date,
        COALESCE(cohort_ids, ARRAY[]::uuid[]) AS cohort_ids,
        COALESCE(roles, ARRAY[]::profile_role[]) AS roles,
        COALESCE(simulation_filters, ARRAY[]::text[]) AS simulation_filters,
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids,
        COALESCE(profile_id, NULL::uuid) AS profile_id
),
-- Get actor name from profile
user_profile AS (
    SELECT 
        COALESCE(
            (SELECT first_name || ' ' || last_name FROM profiles WHERE id = (SELECT profile_id FROM params) LIMIT 1),
            'System'
        ) as actor_name
),
-- Get thresholds from active settings (defaults if no settings found)
settings_thresholds AS (
    SELECT 
        COALESCE(success_threshold, 85) AS success_threshold,
        COALESCE(warning_threshold, 80) AS warning_threshold,
        COALESCE(danger_threshold, 70) AS danger_threshold
    FROM settings
    WHERE active = true
    LIMIT 1
),
-- Filter simulations by cohorts (new filtering order: cohorts → simulations)
-- Gets simulations linked to cohorts + practice simulations without cohorts
filtered_simulation_ids AS (
    SELECT DISTINCT s.id AS simulation_id
    FROM simulations s
    WHERE s.active = TRUE
      AND (
          -- If cohort_ids provided, get simulations linked to those cohorts
                      (cardinality((SELECT cohort_ids FROM params)::uuid[]) > 0 AND EXISTS (
              SELECT 1 
              FROM cohort_simulations cs 
              WHERE cs.simulation_id = s.id 
                            AND cs.cohort_id = ANY((SELECT cohort_ids FROM params)::uuid[])
                AND cs.active = TRUE
          ))
          OR
          -- Always include practice simulations without cohorts
          (s.practice_simulation = TRUE 
           AND NOT EXISTS (
               SELECT 1 
               FROM cohort_simulations cs2 
               WHERE cs2.simulation_id = s.id 
                 AND cs2.active = TRUE
           ))
          OR
          -- If no cohort_ids provided, include all simulations
                      (cardinality((SELECT cohort_ids FROM params)::uuid[]) = 0)
      )
),
filt AS (
    SELECT * FROM analytics a
    WHERE a.attempt_created_at >= (SELECT start_date FROM params)
        AND a.attempt_created_at < (SELECT end_date FROM params)
                    AND ((SELECT simulation_filters FROM params)::text[] IS NULL OR cardinality((SELECT simulation_filters FROM params)::text[]) > 0)
                    AND (
                        (SELECT simulation_filters FROM params)::text[] IS NULL OR (
                            ('general' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_general = TRUE) OR
                            ('practice' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_practice = TRUE) OR
                            ('archived' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_archived = TRUE)
            )
        )
        -- Exclude archived attempts unless 'archived' is explicitly in the filter list
        AND (
                        'archived' = ANY((SELECT simulation_filters FROM params)::text[]) OR a.is_archived = FALSE
        )
        -- Dashboard never filters by profile - always filter by roles
                    AND a.profile_role = ANY((SELECT roles FROM params)::profile_role[])
        -- Filter by simulation_ids from cohorts (new filtering order)
                    AND (cardinality((SELECT cohort_ids FROM params)::uuid[]) = 0 OR a.simulation_id IN (SELECT simulation_id FROM filtered_simulation_ids))
        -- Filter by department_ids (empty array = all departments)
                    AND (cardinality((SELECT department_ids FROM params)::uuid[]) = 0 OR a.department_id = ANY((SELECT department_ids FROM params)::uuid[]))
            ),
            
            -- =====================================================
            -- HEADER METRICS (10 metrics)
            -- =====================================================
            
            -- Attempt normalization for average_score
            per_attempt AS (
                SELECT
                    attempt_id,
                    MIN(attempt_created_at) AS attempt_created_at,
                    (array_agg(profile_id))[1] AS profile_id,
                    COALESCE(MAX(sim_scenario_count), 0) AS expected_from_sim,
                    COUNT(*) FILTER (WHERE completed) AS completed_chats,
                    COUNT(*) FILTER (WHERE completed AND grade_percent IS NOT NULL) AS graded_chats,
                    COUNT(*) AS chats_in_attempt,
                    SUM(grade_percent) FILTER (WHERE grade_percent IS NOT NULL) AS sum_grade_percent
                FROM filt
                GROUP BY attempt_id
            ),
            attempt_norm AS (
                SELECT
                    attempt_id,
                    attempt_created_at,
                    profile_id,
                    GREATEST(expected_from_sim, chats_in_attempt) AS expected,
                    completed_chats,
                    graded_chats,
                    CASE
                        WHEN GREATEST(expected_from_sim, chats_in_attempt) > 0 
                             AND completed_chats > 0 
                             AND completed_chats = graded_chats
                        THEN (sum_grade_percent / GREATEST(expected_from_sim, chats_in_attempt))
                        ELSE NULL
                    END AS norm
                FROM per_attempt
            ),
            
            -- Average Score
            header_avg_score AS (
                SELECT ROUND(AVG(norm))::int AS current_value,
                       COUNT(*) > 0 AS has_data
                FROM attempt_norm WHERE norm IS NOT NULL
            ),
            
            -- Completion Percentage (chat-level aggregation from old stored procedure)
            header_completion AS (
                SELECT ROUND(100.0 * AVG((completed)::int))::int AS current_value,
                       COUNT(*) > 0 AS has_data
                FROM filt
            ),
            
            -- First Attempt Pass Rate (earliest attempt all-time, then filter to window)
            earliest_attempt_all_time AS (
                SELECT DISTINCT ON (a.profile_id, a.simulation_id)
                       a.attempt_id, a.profile_id, a.simulation_id, a.attempt_created_at,
                       a.grade_percent, a.rubric_pass_points, a.rubric_points
                FROM analytics a
                WHERE (
                    -- Match simulation type filters
                    ('general' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_general = TRUE) OR
                    ('practice' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_practice = TRUE) OR
                    ('archived' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_archived = TRUE)
                )
                -- Exclude archived attempts unless 'archived' is explicitly in the filter list
                AND (
                    'archived' = ANY((SELECT simulation_filters FROM params)::text[]) OR a.is_archived = FALSE
                )
                -- Dashboard never filters by profile - always filter by roles
                AND a.profile_role = ANY((SELECT roles FROM params)::profile_role[])
                -- Filter by simulation_ids from cohorts (new filtering order)
                AND (cardinality((SELECT cohort_ids FROM params)::uuid[]) = 0 OR a.simulation_id IN (SELECT simulation_id FROM filtered_simulation_ids))
                -- Filter by department_ids (empty array = all departments)
                AND (cardinality((SELECT department_ids FROM params)::uuid[]) = 0 OR a.department_id = ANY((SELECT department_ids FROM params)::uuid[]))
                ORDER BY a.profile_id, a.simulation_id, a.attempt_created_at
            ),
            first_attempts AS (
                SELECT * FROM earliest_attempt_all_time
                WHERE attempt_created_at >= (SELECT start_date FROM params) AND attempt_created_at < (SELECT end_date FROM params)
            ),
            header_first_pass AS (
                SELECT
                    ROUND(100.0 * COUNT(*) FILTER (WHERE grade_percent >= (rubric_pass_points * 100.0 / NULLIF(rubric_points, 0))) / GREATEST(COUNT(*), 1))::int AS current_value,
                    COUNT(*) > 0 AS has_data
                FROM first_attempts
            ),
            
            -- Highest Score
            header_highest AS (
                SELECT ROUND(MAX(grade_percent))::int AS current_value,
                       COUNT(*) > 0 AS has_data
                FROM filt WHERE grade_percent IS NOT NULL
            ),
            
            -- Messages Per Session
            header_messages AS (
                SELECT ROUND(AVG(num_messages_total))::int AS current_value,
                       COUNT(*) > 0 AS has_data
                FROM filt WHERE num_messages_total IS NOT NULL
            ),
            
            -- Persona Response Times
            persona_times AS (
                SELECT UNNEST(message_time_taken_seconds) AS delta_sec
                FROM filt 
                WHERE cardinality(message_time_taken_seconds) > 0
            ),
            header_persona_times AS (
                SELECT ROUND(AVG(delta_sec))::int AS current_value,
                       COUNT(*) > 0 AS has_data
                FROM persona_times
            ),
            
            -- Session Efficiency (old formula: avgScore * (1 - min(1, avgMinutes/120)))
            user_metrics_for_efficiency AS (
                SELECT
                    AVG(grade_percent) FILTER (WHERE grade_percent IS NOT NULL) AS avg_score,
                    SUM(time_taken_seconds / 60.0) FILTER (WHERE time_taken_seconds IS NOT NULL) AS total_minutes,
                    COUNT(DISTINCT chat_id) AS total_sessions
                FROM filt
            ),
            header_efficiency AS (
                SELECT 
                    GREATEST(0, LEAST(100, ROUND(
                        avg_score * (1.0 - LEAST(1.0, (total_minutes / NULLIF(total_sessions, 0)) / 120.0))
                    )))::int AS current_value,
                    total_sessions > 0 AS has_data
                FROM user_metrics_for_efficiency
            ),
            
            -- Stagnation Rate (grade-stream approach from old stored procedure)
            filtered_chats_for_stagnation AS (
                SELECT DISTINCT chat_id FROM filt WHERE chat_id IS NOT NULL
            ),
            grade_stream AS (
                SELECT
                    sg.id,
                    c_stag.id AS simulation_chat_id,
                    sg.created_at,
                    (sg.score::numeric / NULLIF(r.points, 0)) * 100.0 AS norm
                FROM grades sg
                LEFT JOIN rubric_grade_agents rga ON rga.id = sg.rubric_grade_agent_id
                JOIN runs r_stag ON r_stag.id = sg.run_id
                JOIN group_runs gr_stag ON gr_stag.run_id = r_stag.id
                JOIN groups g_stag ON g_stag.id = gr_stag.group_id
                JOIN chat_groups cg_stag ON cg_stag.group_id = g_stag.id
                JOIN chats c_stag ON c_stag.id = cg_stag.chat_id
                JOIN filtered_chats_for_stagnation fc ON fc.chat_id = c_stag.id
                LEFT JOIN rubrics r ON r.id = rga.rubric_id
                WHERE EXISTS (
                    SELECT 1 FROM runs r_check
                    JOIN group_runs gr_check ON gr_check.run_id = r_check.id
                    JOIN groups g_check ON g_check.id = gr_check.group_id
                    JOIN chat_groups cg_check ON cg_check.group_id = g_check.id
                    JOIN chats c_check ON c_check.id = cg_check.chat_id
                    WHERE r_check.id = sg.run_id
                )
            ),
            ordered_grades AS (
                SELECT *,
                       LAG(norm) OVER (ORDER BY created_at) AS prev_norm
                FROM grade_stream
            ),
            stagnation_flags AS (
                SELECT *,
                       CASE WHEN prev_norm IS NULL THEN NULL
                            WHEN norm <= prev_norm + 0.1 THEN 1 
                            ELSE 0 
                       END AS stagnated
                FROM ordered_grades
                WHERE prev_norm IS NOT NULL
            ),
            header_stagnation AS (
                SELECT ROUND(100.0 * AVG(stagnated))::int AS current_value,
                       COUNT(*) > 0 AS has_data
                FROM stagnation_flags
            ),
            
            -- Time Spent (SUM with 30-minute cap per chat, in minutes)
            header_time AS (
                SELECT ROUND(SUM(LEAST(time_taken_seconds / 60.0, 30.0)))::int AS current_value,
                       COUNT(*) > 0 AS has_data
                FROM filt 
                WHERE time_taken_seconds IS NOT NULL
            ),
            
            -- Total Attempts
            header_attempts AS (
                SELECT COUNT(DISTINCT attempt_id)::int AS current_value,
                       COUNT(*) > 0 AS has_data
                FROM filt
            ),
            
            -- =====================================================
            -- HEADER METRICS TREND DATA (for trend charts)
            -- =====================================================
            
            -- Average Score Trend (using attempt normalization)
            header_avg_score_trend AS (
                SELECT 
                    to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(AVG(norm))::float AS value,
                    COUNT(*)::int AS count
                FROM attempt_norm
                WHERE norm IS NOT NULL
                GROUP BY date
                ORDER BY date
            ),
            
            -- Completion Percentage Trend
            header_completion_trend AS (
                SELECT 
                    to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(100.0 * AVG((completed)::int))::float AS value,
                    COUNT(*)::int AS count
                FROM filt
                GROUP BY date
                ORDER BY date
            ),
            
            -- First Attempt Pass Rate Trend
            header_first_pass_trend AS (
                SELECT 
                    to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(100.0 * COUNT(*) FILTER (WHERE grade_percent >= (rubric_pass_points * 100.0 / NULLIF(rubric_points, 0))) / GREATEST(COUNT(*), 1))::float AS value,
                    COUNT(*)::int AS count
                FROM first_attempts
                GROUP BY date
                ORDER BY date
            ),
            
            -- Highest Score Trend
            header_highest_trend AS (
                SELECT 
                    to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(MAX(grade_percent))::float AS value,
                    COUNT(*)::int AS count
                FROM filt
                WHERE grade_percent IS NOT NULL
                GROUP BY date
                ORDER BY date
            ),
            
            -- Messages Per Session Trend
            header_messages_trend AS (
                SELECT 
                    to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(AVG(num_messages_total))::float AS value,
                    COUNT(*)::int AS count
                FROM filt
                WHERE num_messages_total IS NOT NULL
                GROUP BY date
                ORDER BY date
            ),
            
            -- Persona Response Times Trend
            header_persona_times_trend AS (
                SELECT 
                    to_char(pt.attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(AVG(pt.delta_sec))::float AS value,
                    COUNT(*)::int AS count
                FROM (
                    SELECT attempt_created_at, UNNEST(message_time_taken_seconds) AS delta_sec
                    FROM filt
                    WHERE cardinality(message_time_taken_seconds) > 0
                ) pt
                GROUP BY date
                ORDER BY date
            ),
            
            -- Session Efficiency Trend (user-level aggregation by date)
            user_metrics_for_efficiency_by_date AS (
                SELECT 
                    to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                    profile_id,
                    AVG(grade_percent) FILTER (WHERE grade_percent IS NOT NULL) AS avg_score,
                    SUM(time_taken_seconds / 60.0) FILTER (WHERE time_taken_seconds IS NOT NULL) AS total_minutes,
                    COUNT(DISTINCT chat_id) AS total_sessions
                FROM filt
                GROUP BY date, profile_id
            ),
            header_efficiency_trend AS (
                SELECT 
                    date,
                    ROUND(GREATEST(0, LEAST(100, AVG(
                        avg_score * (1.0 - LEAST(1.0, (total_minutes / NULLIF(total_sessions, 0)) / 120.0))
                    ))))::float AS value,
                    COUNT(*)::int AS count
                FROM user_metrics_for_efficiency_by_date
                WHERE total_sessions > 0
                GROUP BY date
                ORDER BY date
            ),
            
            -- Stagnation Rate Trend
            header_stagnation_trend AS (
                SELECT 
                    to_char(created_at, 'YYYY-MM-DD') AS date,
                    ROUND(100.0 * AVG(stagnated))::float AS value,
                    COUNT(*)::int AS count
                FROM stagnation_flags
                GROUP BY date
                ORDER BY date
            ),
            
            -- Time Spent Trend (with 30-minute cap per chat)
            header_time_trend AS (
                SELECT 
                    to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(AVG(LEAST(30.0, time_taken_seconds / 60.0)))::float AS value,
                    COUNT(*)::int AS count
                FROM filt
                WHERE time_taken_seconds IS NOT NULL
                GROUP BY date
                ORDER BY date
            ),
            
            -- Total Attempts Trend
            header_attempts_trend AS (
                SELECT 
                    to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                    COUNT(DISTINCT attempt_id)::float AS value,
                    COUNT(*)::int AS count
                FROM filt
                GROUP BY date
                ORDER BY date
            ),
            
            -- =====================================================
            -- HEADER METRICS DATA POINTS (for hover tooltips)
            -- =====================================================
            
            -- Average Score Data Points
            header_avg_score_points AS (
                SELECT 
                    COALESCE(an.profile_id::text, '') AS profile_id,
                    to_char(an.attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(an.norm)::int AS value,
                    COALESCE(an.attempt_id::text, '') AS attempt_id,
                    ''::text AS simulation_id,
                    ''::text AS scenario_id
                FROM attempt_norm an
                WHERE an.norm IS NOT NULL
                ORDER BY an.profile_id, an.attempt_created_at
            ),
            
            -- Completion Percentage Data Points
            header_completion_points AS (
                SELECT 
                    f.profile_id::text AS profile_id,
                    to_char(f.attempt_created_at, 'YYYY-MM-DD') AS date,
                    (f.completed::int * 100)::int AS value,
                    f.attempt_id::text AS attempt_id,
                    f.simulation_id::text AS simulation_id,
                    f.scenario_id::text AS scenario_id
                FROM filt f
                ORDER BY f.profile_id, f.attempt_created_at
            ),
            
            -- First Attempt Pass Rate Data Points
            header_first_pass_points AS (
                SELECT 
                    fa.profile_id::text AS profile_id,
                    to_char(fa.attempt_created_at, 'YYYY-MM-DD') AS date,
                    CASE 
                        WHEN fa.grade_percent >= (fa.rubric_pass_points * 100.0 / NULLIF(fa.rubric_points, 0)) THEN 100
                        ELSE 0
                    END::int AS value,
                    fa.attempt_id::text AS attempt_id,
                    fa.simulation_id::text AS simulation_id,
                    NULL::text AS scenario_id
                FROM first_attempts fa
                ORDER BY fa.profile_id, fa.attempt_created_at
            ),
            
            -- Highest Score Data Points
            header_highest_points AS (
                SELECT 
                    f.profile_id::text AS profile_id,
                    to_char(f.attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(f.grade_percent)::int AS value,
                    f.attempt_id::text AS attempt_id,
                    f.simulation_id::text AS simulation_id,
                    f.scenario_id::text AS scenario_id
                FROM filt f
                WHERE f.grade_percent IS NOT NULL
                ORDER BY f.profile_id, f.attempt_created_at
            ),
            
            -- Messages Per Session Data Points
            header_messages_points AS (
                SELECT 
                    f.profile_id::text AS profile_id,
                    to_char(f.attempt_created_at, 'YYYY-MM-DD') AS date,
                    f.num_messages_total::int AS value,
                    f.attempt_id::text AS attempt_id,
                    f.simulation_id::text AS simulation_id,
                    f.scenario_id::text AS scenario_id
                FROM filt f
                WHERE f.num_messages_total IS NOT NULL
                ORDER BY f.profile_id, f.attempt_created_at
            ),
            
            -- Persona Response Times Data Points
            header_persona_times_points AS (
                SELECT 
                    f.profile_id::text AS profile_id,
                    to_char(f.attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(pt.delta_sec)::int AS value,
                    f.attempt_id::text AS attempt_id,
                    f.simulation_id::text AS simulation_id,
                    f.scenario_id::text AS scenario_id
                FROM filt f
                CROSS JOIN LATERAL UNNEST(f.message_time_taken_seconds) AS pt(delta_sec)
                WHERE cardinality(f.message_time_taken_seconds) > 0
                ORDER BY f.profile_id, f.attempt_created_at
            ),
            
            -- Session Efficiency Data Points
            header_efficiency_points AS (
                SELECT 
                    f.profile_id::text AS profile_id,
                    to_char(f.attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(GREATEST(0, LEAST(100, 
                        f.grade_percent * (1.0 - LEAST(1.0, (f.time_taken_seconds / 60.0) / 120.0))
                    )))::int AS value,
                    f.attempt_id::text AS attempt_id,
                    f.simulation_id::text AS simulation_id,
                    f.scenario_id::text AS scenario_id
                FROM filt f
                WHERE f.grade_percent IS NOT NULL AND f.time_taken_seconds IS NOT NULL
                ORDER BY f.profile_id, f.attempt_created_at
            ),
            
            -- Stagnation Rate Data Points
            header_stagnation_points AS (
                SELECT 
                    ''::text AS profile_id,
                    to_char(gs.created_at, 'YYYY-MM-DD') AS date,
                    (sf.stagnated * 100)::int AS value,
                    ''::text AS attempt_id,
                    ''::text AS simulation_id,
                    ''::text AS scenario_id
                FROM stagnation_flags sf
                JOIN grade_stream gs ON gs.id = sf.id
                ORDER BY gs.created_at
            ),
            
            -- Time Spent Data Points
            header_time_points AS (
                SELECT 
                    f.profile_id::text AS profile_id,
                    to_char(f.attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(LEAST(30.0, f.time_taken_seconds / 60.0))::int AS value,
                    f.attempt_id::text AS attempt_id,
                    f.simulation_id::text AS simulation_id,
                    f.scenario_id::text AS scenario_id
                FROM filt f
                WHERE f.time_taken_seconds IS NOT NULL
                ORDER BY f.profile_id, f.attempt_created_at
            ),
            
            -- Total Attempts Data Points
            header_attempts_points AS (
                SELECT 
                    f.profile_id::text AS profile_id,
                    to_char(f.attempt_created_at, 'YYYY-MM-DD') AS date,
                    1::int AS value,
                    f.attempt_id::text AS attempt_id,
                    f.simulation_id::text AS simulation_id,
                    f.scenario_id::text AS scenario_id
                FROM filt f
                WHERE f.attempt_id IS NOT NULL
                ORDER BY f.profile_id, f.attempt_created_at
            ),
            
            -- =====================================================
            -- PRIMARY METRICS
            -- =====================================================
            
            -- Growth Data
            spine AS (
                SELECT generate_series(
                    date_trunc('day', (SELECT start_date FROM params)::timestamptz)::date,
                    (date_trunc('day', (SELECT end_date FROM params)::timestamptz) - interval '1 second')::date,
                    interval '1 day'
                )::date AS d
            ),
            growth_avg_score AS (
                SELECT to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                       AVG(grade_percent)::float AS value
                FROM filt WHERE grade_percent IS NOT NULL
                GROUP BY date
            ),
            growth_pass_rate AS (
                SELECT to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                       (100.0 * COUNT(*) FILTER (WHERE grade_percent >= (rubric_pass_points * 100.0 / NULLIF(rubric_points, 0))) 
                        / NULLIF(COUNT(*), 0))::float AS value
                FROM first_attempts
                GROUP BY date
            ),
            growth_completion_rate AS (
                SELECT to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                       AVG(CASE WHEN expected > 0 THEN (100.0 * completed_chats / expected) ELSE 0 END)::float AS value
                FROM attempt_norm
                GROUP BY date
            ),
            growth_first_attempt_pass_rate AS (
                SELECT to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                       (100.0 * COUNT(*) FILTER (WHERE grade_percent >= (rubric_pass_points * 100.0 / NULLIF(rubric_points, 0))) 
                        / NULLIF(COUNT(*), 0))::float AS value
                FROM first_attempts
                GROUP BY date
            ),
            growth_messages AS (
                SELECT to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                       AVG(num_messages_total)::float AS value
                FROM filt WHERE num_messages_total IS NOT NULL
                GROUP BY date
            ),
            growth_persona_times_daily AS (
                SELECT to_char(pt.attempt_created_at, 'YYYY-MM-DD') AS date,
                       AVG(pt.delta_sec)::float AS value
                FROM (
                    SELECT attempt_created_at, UNNEST(message_time_taken_seconds) AS delta_sec
                    FROM filt WHERE cardinality(message_time_taken_seconds) > 0
                ) pt
                GROUP BY date
            ),
            growth_efficiency AS (
                SELECT 
                    to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                    GREATEST(0, LEAST(100, ROUND(
                        AVG(grade_percent) FILTER (WHERE grade_percent IS NOT NULL) * 
                        (1.0 - LEAST(1.0, (SUM(time_taken_seconds / 60.0) FILTER (WHERE time_taken_seconds IS NOT NULL) / 
                         NULLIF(COUNT(DISTINCT chat_id), 0)) / 120.0))
                    )))::float AS value
                FROM filt 
                WHERE time_taken_seconds > 0 AND grade_percent IS NOT NULL
                GROUP BY date
            ),
            growth_stagnation AS (
                SELECT to_char(created_at, 'YYYY-MM-DD') AS date,
                       (100.0 * AVG(stagnated))::float AS value
                FROM stagnation_flags
                GROUP BY date
            ),
            growth_time_spent AS (
                SELECT to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                       AVG(time_taken_seconds)::float AS value
                FROM filt WHERE time_taken_seconds IS NOT NULL
                GROUP BY date
            ),
            growth_total_attempts AS (
                SELECT to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                       COUNT(DISTINCT attempt_id)::float AS value
                FROM filt
                GROUP BY date
            ),
            growth_chart_dates AS (
                SELECT s.d AS date_val,
                       to_char(s.d, 'YYYY-MM-DD') AS date,
                       ROUND(COALESCE(gas.value, 0))::int AS average_score,
                       ROUND(COALESCE(gcr.value, 0))::int AS completion_rate,
                       ROUND(COALESCE(gfapr.value, 0))::int AS first_attempt_pass_rate,
                       ROUND(COALESCE(ge.value, 0))::int AS session_efficiency,
                       ROUND(COALESCE(gst.value, 0))::int AS stagnation_rate
                FROM spine s
                LEFT JOIN growth_avg_score gas ON gas.date = to_char(s.d, 'YYYY-MM-DD')
                LEFT JOIN growth_completion_rate gcr ON gcr.date = to_char(s.d, 'YYYY-MM-DD')
                LEFT JOIN growth_first_attempt_pass_rate gfapr ON gfapr.date = to_char(s.d, 'YYYY-MM-DD')
                LEFT JOIN growth_efficiency ge ON ge.date = to_char(s.d, 'YYYY-MM-DD')
                LEFT JOIN growth_stagnation gst ON gst.date = to_char(s.d, 'YYYY-MM-DD')
                WHERE gas.value IS NOT NULL 
                   OR gcr.value IS NOT NULL 
                   OR gfapr.value IS NOT NULL 
                   OR ge.value IS NOT NULL 
                   OR gst.value IS NOT NULL
            ),
            growth_window AS (
                SELECT AVG(average_score) FILTER (WHERE date_val >= (SELECT MAX(date_val) FROM growth_chart_dates) - interval '7 days') AS last_avg,
                       AVG(average_score) FILTER (WHERE date_val >= (SELECT MAX(date_val) FROM growth_chart_dates) - interval '14 days' 
                                                        AND date_val < (SELECT MAX(date_val) FROM growth_chart_dates) - interval '7 days') AS prev_avg
                FROM growth_chart_dates
            ),
            
            -- Persona Performance
            persona_agg AS (
                SELECT f.persona_id,
                       p.name,
                       COALESCE(p.color, '#3b82f6') AS color,
                       AVG(f.grade_percent)::float AS avg_score,
                       COUNT(DISTINCT f.chat_id)::int AS sessions,
                       ARRAY_AGG(DISTINCT f.simulation_id::text) AS simulation_ids,
                       CASE
                           WHEN AVG(f.grade_percent)::float >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'
                           WHEN AVG(f.grade_percent)::float >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'
                           ELSE 'danger'
                       END AS status
                FROM filt f
                JOIN personas p ON p.id = f.persona_id
                WHERE f.grade_percent IS NOT NULL AND f.persona_id IS NOT NULL
                GROUP BY f.persona_id, p.name, p.color
            ),
            trend_data_raw AS (
                SELECT
                    f.persona_id,
                    date_trunc('day', f.chat_created_at) AS day,
                    to_char(date_trunc('day', f.chat_created_at), 'YYYY-MM-DD') AS date,
                    EXTRACT(epoch FROM date_trunc('day', f.chat_created_at))::bigint AS timestamp,
                    f.simulation_id,
                    AVG(f.grade_percent)::float AS avg_score
                FROM filt f
                WHERE f.persona_id IS NOT NULL AND f.grade_percent IS NOT NULL
                GROUP BY f.persona_id, date_trunc('day', f.chat_created_at), f.simulation_id
            ),
            persona_trends_agg_converted AS (
                SELECT 
                    persona_id,
                    COALESCE(
                        ARRAY_AGG(
                            (date, COALESCE(avg_score, 0)::float, timestamp, simulation_id::text)::types.q_get_dashboard_bundle_v4_persona_trend_data
                            ORDER BY day
                        ),
                        '{}'::types.q_get_dashboard_bundle_v4_persona_trend_data[]
                    ) AS trends
                FROM trend_data_raw
                GROUP BY persona_id
            ),
            persona_colors_agg_converted AS (
                SELECT ARRAY_AGG(
                    (p.name, COALESCE(p.color, '#3b82f6'))::types.q_get_dashboard_bundle_v4_persona_color
                    ORDER BY p.name
                ) AS colors
                FROM (SELECT DISTINCT persona_id FROM persona_agg) pa
                JOIN personas p ON p.id = pa.persona_id
            ),
            
            -- Rubric Heatmap (FULL IMPLEMENTATION with correlation matrices)
            -- Get all chats that have grades in the date range (not filtered by analytics attempt_created_at)
            filtered_chats AS (
                SELECT DISTINCT c.id AS chat_id
                FROM grades scg
                JOIN runs r ON r.id = scg.run_id
                JOIN group_runs gr ON gr.run_id = r.id
                JOIN grade_groups gg ON gg.group_id = gr.group_id
                JOIN chats c ON c.id = gg.chat_id
                JOIN attempt_chats ac ON ac.chat_id = c.id
                JOIN simulation_attempts sa ON sa.id = ac.attempt_id
                WHERE scg.created_at >= (SELECT start_date FROM params)
                  AND scg.created_at < (SELECT end_date FROM params)
                  -- Apply same filters as filt but on attempt level
                  AND EXISTS (
                      SELECT 1 FROM analytics a
                      WHERE a.chat_id = c.id
                        AND a.profile_role = ANY((SELECT roles FROM params)::profile_role[])
                        AND (cardinality((SELECT department_ids FROM params)::uuid[]) = 0 OR a.department_id = ANY((SELECT department_ids FROM params)::uuid[]))
                        AND (cardinality((SELECT cohort_ids FROM params)::uuid[]) = 0 OR a.simulation_id IN (SELECT simulation_id FROM filtered_simulation_ids))
                        AND ((SELECT simulation_filters FROM params)::text[] IS NULL OR cardinality((SELECT simulation_filters FROM params)::text[]) > 0)
                        AND (
                            (SELECT simulation_filters FROM params)::text[] IS NULL OR (
                                ('general' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_general) OR
                                ('practice' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_practice) OR
                                ('archived' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_archived)
                            )
                        )
                        AND (
                            'archived' = ANY((SELECT simulation_filters FROM params)::text[]) OR a.is_archived = FALSE
                        )
                  )
            ),
            -- Get chat scenario and simulation info for fallback
            chat_scenario_info AS (
                SELECT DISTINCT
                    c.id AS chat_id,
                    c.scenario_id,
                    sa.simulation_id
                FROM chats c
                JOIN attempt_chats ac ON ac.chat_id = c.id
                JOIN simulation_attempts sa ON sa.id = ac.attempt_id
                WHERE c.id IN (SELECT chat_id FROM filtered_chats)
            ),
            -- Get first scenario's rubric per simulation (fallback)
            sim_first_scenario_rubric_heatmap AS (
                SELECT DISTINCT ON (ss.simulation_id)
                    ss.simulation_id,
                    rga.rubric_id
                FROM simulation_scenarios ss
                LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
                LEFT JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
                WHERE ss.active = true
                  AND ss.simulation_id IN (SELECT DISTINCT simulation_id FROM chat_scenario_info)
                ORDER BY ss.simulation_id, ss.position
            ),
            latest_grade_per_chat AS (
                SELECT DISTINCT ON (c.id)
                    scg.id,
                    c.id AS chat_id,
                    COALESCE(
                        rga.rubric_id,
                        rga_fallback_scenario.rubric_id,
                        sfsr.rubric_id
                    ) AS rubric_id
                FROM grades scg
                LEFT JOIN rubric_grade_agents rga ON rga.id = scg.rubric_grade_agent_id
                JOIN runs r ON r.id = scg.run_id
                JOIN group_runs gr ON gr.run_id = r.id
                JOIN grade_groups gg ON gg.group_id = gr.group_id
                JOIN chats c ON c.id = gg.chat_id
                JOIN filtered_chats fc ON fc.chat_id = c.id
                LEFT JOIN chat_scenario_info csi ON csi.chat_id = c.id
                LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga_fallback ON ssrga_fallback.simulation_id = csi.simulation_id
                  AND ssrga_fallback.scenario_id = csi.scenario_id
                  AND rga.rubric_id IS NULL
                LEFT JOIN rubric_grade_agents rga_fallback_scenario ON rga_fallback_scenario.id = ssrga_fallback.rubric_grade_agent_id
                LEFT JOIN sim_first_scenario_rubric_heatmap sfsr ON sfsr.simulation_id = csi.simulation_id
                  AND rga.rubric_id IS NULL
                  AND rga_fallback_scenario.rubric_id IS NULL
                WHERE EXISTS (
                    SELECT 1 FROM runs r_check
                    JOIN group_runs gr_check ON gr_check.run_id = r_check.id
                    JOIN grade_groups gg_check ON gg_check.group_id = gr_check.group_id
                    JOIN chats c_check ON c_check.id = gg_check.chat_id
                    WHERE r_check.id = scg.run_id
                )
                  AND COALESCE(
                      rga.rubric_id,
                      rga_fallback_scenario.rubric_id,
                      sfsr.rubric_id
                  ) IS NOT NULL
                ORDER BY c.id, scg.created_at DESC
            ),
            per_grade_group AS (
                SELECT
                    lg.chat_id,
                    rsg.rubric_id,
                    sg.id AS group_id,
                    sg.name AS group_name,
                    (100.0 * SUM(scf.total)::float8 / NULLIF(sg.points::float8, 0))::float8 AS pct
                FROM latest_grade_per_chat lg
                JOIN feedbacks scf ON scf.grade_id = lg.id
                JOIN standards s ON s.id = scf.standard_id
                JOIN rubric_standard_groups rsg ON rsg.rubric_id = lg.rubric_id AND rsg.active = true
                JOIN standard_groups sg ON sg.id = rsg.standard_group_id AND sg.id = s.standard_group_id
                GROUP BY lg.chat_id, rsg.rubric_id, sg.id, sg.name, sg.points
            ),
            corrs_upper AS (
                SELECT
                    a.rubric_id,
                    a.group_id AS g1,
                    b.group_id AS g2,
                    COUNT(*) FILTER (WHERE a.pct IS NOT NULL AND b.pct IS NOT NULL) AS n,
                    corr(a.pct, b.pct) AS r
                FROM per_grade_group a
                JOIN per_grade_group b
                    ON b.rubric_id = a.rubric_id
                    AND b.chat_id = a.chat_id
                    AND b.group_id >= a.group_id
                GROUP BY a.rubric_id, a.group_id, b.group_id
            ),
            corrs_full AS (
                SELECT rubric_id, g1, g2, n, r FROM corrs_upper
                UNION ALL
                SELECT rubric_id, g2 AS g1, g1 AS g2, n, r
                FROM corrs_upper
                WHERE g1 != g2
            ),
            rubric_groups AS (
                SELECT DISTINCT pgg.rubric_id, sg.id, sg.name, sg.short_name
                FROM per_grade_group pgg
                JOIN rubric_standard_groups rsg ON rsg.rubric_id = pgg.rubric_id AND rsg.standard_group_id = pgg.group_id AND rsg.active = true
                JOIN standard_groups sg ON sg.id = rsg.standard_group_id
            ),
            valid_rubric_ids_list AS (
                SELECT DISTINCT rubric_id FROM rubric_groups
            ),
            enriched_corrs AS (
                SELECT
                    c.rubric_id, c.g1, c.g2, c.n,
                    CASE WHEN c.r = c.r THEN c.r ELSE 0.0 END AS r,
                    NULL AS p_value,
                    CASE
                        WHEN c.n IS NULL OR c.n < 3 THEN 'No Data'
                        WHEN ABS(CASE WHEN c.r = c.r THEN c.r ELSE 0.0 END) >= 0.7 THEN 'Strong'
                        WHEN ABS(CASE WHEN c.r = c.r THEN c.r ELSE 0.0 END) >= 0.4 THEN 'Moderate'
                        WHEN ABS(CASE WHEN c.r = c.r THEN c.r ELSE 0.0 END) > 0.0 THEN 'Weak'
                        ELSE 'No Data'
                    END AS strength,
                    CASE
                        WHEN c.n IS NULL OR c.n < 3 THEN '#e5e7eb'
                        WHEN (CASE WHEN c.r = c.r THEN c.r ELSE 0.0 END) >= 0.0 THEN
                            CASE
                                WHEN ABS(CASE WHEN c.r = c.r THEN c.r ELSE 0.0 END) >= 0.7 THEN '#10b981'
                                WHEN ABS(CASE WHEN c.r = c.r THEN c.r ELSE 0.0 END) >= 0.4 THEN '#34d399'
                                ELSE '#a7f3d0'
                            END
                        ELSE
                            CASE
                                WHEN ABS(CASE WHEN c.r = c.r THEN c.r ELSE 0.0 END) >= 0.7 THEN '#ef4444'
                                WHEN ABS(CASE WHEN c.r = c.r THEN c.r ELSE 0.0 END) >= 0.4 THEN '#f87171'
                                ELSE '#fecaca'
                            END
                    END AS color
                FROM corrs_full c
            ),
            rubric_insights AS (
                SELECT
                    e.rubric_id,
                    CASE
                        WHEN COALESCE(SUM(CASE WHEN e.n >= 3 THEN 1 ELSE 0 END), 0) = 0 THEN NULL
                        ELSE (
                            SELECT 'Top pair: "' || g1.name || '" vs "' || g2.name ||
                                   '" r=' || TO_CHAR(e2.r, 'FM0.00') ||
                                   ' (n=' || e2.n || ')'
                            FROM enriched_corrs e2
                            JOIN rubric_groups g1 ON g1.id = e2.g1 AND g1.rubric_id = e2.rubric_id
                            JOIN rubric_groups g2 ON g2.id = e2.g2 AND g2.rubric_id = e2.rubric_id
                            WHERE e2.rubric_id = e.rubric_id AND e2.n >= 3
                            ORDER BY ABS(e2.r) DESC, e2.n DESC
                            LIMIT 1
                        )
                    END AS txt
                FROM enriched_corrs e
                GROUP BY e.rubric_id
            ),
            rubric_has_data AS (
                SELECT rubric_id,
                    (SUM(CASE WHEN n >= 3 THEN 1 ELSE 0 END) > 0) AS has_data
                FROM enriched_corrs
                GROUP BY rubric_id
            ),
            rubric_avg_correlation AS (
                SELECT 
                    rubric_id,
                    AVG(ABS(r)) AS avg_correlation_strength
                FROM enriched_corrs
                WHERE g1 != g2 AND n >= 3
                GROUP BY rubric_id
            ),
            -- Convert rubric_correlations: convert matrix and standard_groups to composite types
            per_rubric_matrix_converted AS (
                SELECT
                    g1.rubric_id,
                    ROW_NUMBER() OVER (PARTITION BY g1.rubric_id ORDER BY g1.name) - 1 AS row_idx,
                    ARRAY_AGG(
                        (g1.rubric_id::text, COALESCE(e.r, 0.0), e.p_value, COALESCE(e.color, '#e5e7eb'), COALESCE(e.strength, 'No Data'), COALESCE(e.n, 0))::types.q_get_dashboard_bundle_v4_rubric_heatmap_cell
                        ORDER BY g2.name
                    ) AS row_array
                FROM rubric_groups g1
                JOIN rubric_groups g2 ON g2.rubric_id = g1.rubric_id
                LEFT JOIN enriched_corrs e
                    ON e.rubric_id = g1.rubric_id AND e.g1 = g1.id AND e.g2 = g2.id
                GROUP BY g1.rubric_id, g1.id, g1.name
            ),
            matrix_converted AS (
                SELECT 
                    rubric_id,
                    COALESCE(
                        ARRAY_AGG(
                            ROW(row_array)::types.q_get_dashboard_bundle_v4_rubric_heatmap_row
                            ORDER BY row_idx
                        ),
                        ARRAY[]::types.q_get_dashboard_bundle_v4_rubric_heatmap_row[]
                    ) AS matrix
                FROM per_rubric_matrix_converted
                GROUP BY rubric_id
            ),
            sg_converted AS (
                SELECT rubric_id,
                    ARRAY_AGG((id::text, name, short_name, rubric_id::text)::types.q_get_dashboard_bundle_v4_standard_group ORDER BY name) AS standard_groups
                FROM rubric_groups
                GROUP BY rubric_id
            ),
            per_rubric_heatmap_converted AS (
                SELECT
                    r.rubric_id,
                    COALESCE(m.matrix, ARRAY[]::types.q_get_dashboard_bundle_v4_rubric_heatmap_row[]) AS matrix,
                    COALESCE(sg.standard_groups, ARRAY[]::types.q_get_dashboard_bundle_v4_standard_group[]) AS standard_groups,
                    (SELECT txt FROM rubric_insights i WHERE i.rubric_id = r.rubric_id LIMIT 1) AS insights,
                    COALESCE((SELECT h.has_data FROM rubric_has_data h WHERE h.rubric_id = r.rubric_id LIMIT 1), FALSE) AS has_data
                FROM valid_rubric_ids_list r
                LEFT JOIN matrix_converted m ON m.rubric_id = r.rubric_id
                LEFT JOIN sg_converted sg ON sg.rubric_id = r.rubric_id
            ),
            rubric_correlations_converted AS (
                SELECT
                    COALESCE(
                        ARRAY_AGG(
                            (pr.rubric_id::text, pr.standard_groups, pr.matrix, pr.insights, pr.has_data)::types.q_get_dashboard_bundle_v4_rubric_matrix_package
                            ORDER BY pr.rubric_id::text
                        ),
                        '{}'::types.q_get_dashboard_bundle_v4_rubric_matrix_package[]
                    ) AS matrices,
                    COALESCE(
                        ARRAY_AGG(rubric_id::text ORDER BY rubric_id::text),
                        ARRAY[]::text[]
                    ) AS valid_rubric_ids,
                    CASE
                        WHEN (SELECT COUNT(*) FROM rubric_avg_correlation) = 0 THEN 'neutral'::text
                        WHEN (SELECT AVG(avg_correlation_strength * 100) FROM rubric_avg_correlation) >= 
                             (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                        WHEN (SELECT AVG(avg_correlation_strength * 100) FROM rubric_avg_correlation) >= 
                             (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'danger'::text
                    END AS status
                FROM per_rubric_heatmap_converted pr
            ),
            -- Entity Mappings - converted to arrays of composite types
            simulation_ids AS (
                SELECT DISTINCT simulation_id FROM filt WHERE simulation_id IS NOT NULL
            ),
            simulation_with_depts AS (
                SELECT 
                    s.id,
                    s.title,
                    s.description,
                    COALESCE(
                        (SELECT SUM(stl.time_limit_seconds)
                         FROM scenario_time_limits stl
                         JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
                         WHERE stl.simulation_id = s.id AND stl.active = true AND ss.active = true),
                        0
                    ) AS time_limit,
                    COALESCE(
                        ARRAY_AGG(sd.department_id::text ORDER BY sd.created_at) FILTER (WHERE sd.department_id IS NOT NULL),
                        ARRAY[]::text[]
                    ) AS dept_ids
                FROM simulations s
                LEFT JOIN simulation_departments sd ON sd.simulation_id = s.id AND sd.active = true
                WHERE s.id IN (SELECT simulation_id FROM simulation_ids)
                  AND s.active = true
                  AND (
                      cardinality((SELECT department_ids FROM params)::uuid[]) = 0 
                      OR sd.department_id = ANY((SELECT department_ids FROM params)::uuid[])
                      OR NOT EXISTS (SELECT 1 FROM simulation_departments sd2 WHERE sd2.simulation_id = s.id AND sd2.active = true)
                  )
                GROUP BY s.id, s.title, s.description
            ),
            simulations_converted AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (id::text, title, COALESCE(description, ''), time_limit, dept_ids)::types.q_get_dashboard_bundle_v4_simulation
                        ORDER BY title
                    ),
                    '{}'::types.q_get_dashboard_bundle_v4_simulation[]
                ) AS simulations_array
                FROM simulation_with_depts
            ),
            rubric_ids AS (
                SELECT DISTINCT rubric_id FROM filt WHERE rubric_id IS NOT NULL
            ),
            rubrics_converted AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (r.id::text, r.name, COALESCE(r.description, ''))::types.q_get_dashboard_bundle_v4_rubric
                        ORDER BY r.name
                    ),
                    '{}'::types.q_get_dashboard_bundle_v4_rubric[]
                ) AS rubrics_array
                FROM rubrics r
                WHERE r.id IN (SELECT rubric_id FROM rubric_ids)
                  AND r.active = true
            ),
            parameters_converted AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (p.id::text, p.name, COALESCE(p.description, ''), 
                         false, 
                         COALESCE(p.document_parameter, false),
                         COALESCE(p.persona_parameter, false)
                        )::types.q_get_dashboard_bundle_v4_parameter
                        ORDER BY p.name
                    ),
                    '{}'::types.q_get_dashboard_bundle_v4_parameter[]
                ) AS parameters_array
                FROM parameters p
                WHERE p.active = true
                  AND (
                      cardinality((SELECT department_ids FROM params)) = 0 
                      OR EXISTS (
                          SELECT 1 
                          FROM fields f
                          JOIN parameter_fields pf ON pf.field_id = f.id AND pf.active = true
                          JOIN field_departments fd ON fd.field_id = f.id AND fd.active = true
                          WHERE pf.parameter_id = p.id AND fd.department_id = ANY((SELECT department_ids FROM params)::uuid[])
                      )
                      OR NOT EXISTS (
                          SELECT 1 
                          FROM fields f
                          JOIN parameter_fields pf ON pf.field_id = f.id AND pf.active = true
                          JOIN field_departments fd2 ON fd2.field_id = f.id AND fd2.active = true
                          WHERE pf.parameter_id = p.id
                      )
                  )
            ),
            fields_converted AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (f.id::text, f.name, COALESCE(f.description, ''), 
                         pf.parameter_id::text, p.name
                        )::types.q_get_dashboard_bundle_v4_field
                        ORDER BY f.name
                    ),
                    '{}'::types.q_get_dashboard_bundle_v4_field[]
                ) AS fields_array
                FROM fields f
                JOIN parameter_fields pf ON pf.field_id = f.id AND pf.active = true
                JOIN parameters p ON pf.parameter_id = p.id
                LEFT JOIN field_departments fd ON fd.field_id = f.id AND fd.active = true
                WHERE p.active = true
                  AND (
                      cardinality((SELECT department_ids FROM params)::uuid[]) = 0 
                      OR fd.department_id = ANY((SELECT department_ids FROM params)::uuid[])
                      OR NOT EXISTS (SELECT 1 FROM field_departments fd2 WHERE fd2.field_id = f.id AND fd2.active = true)
                  )
            ),
            -- Helper CTEs for header metrics - convert to composite types
            header_avg_score_trend_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((date, value, count)::types.q_get_dashboard_bundle_v4_trend_data ORDER BY date),
                    '{}'::types.q_get_dashboard_bundle_v4_trend_data[]
                ) as trend_data
                FROM header_avg_score_trend
            ),
            header_avg_score_points_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((COALESCE(profile_id, ''), date, value::float, attempt_id, simulation_id, scenario_id, 0)::types.q_get_dashboard_bundle_v4_data_point),
                    '{}'::types.q_get_dashboard_bundle_v4_data_point[]
                ) as data_points
                FROM header_avg_score_points
            ),
            header_avg_score_metric AS (
                SELECT 
                    COALESCE((SELECT has_data FROM header_avg_score), false)::boolean as has_data,
                    'avg'::text as method,
                    COALESCE((SELECT current_value FROM header_avg_score), 0)::int as current_value,
                    CASE
                        WHEN NOT COALESCE((SELECT has_data FROM header_avg_score), false) THEN 'neutral'::text
                        WHEN COALESCE((SELECT current_value FROM header_avg_score), 0) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                        WHEN COALESCE((SELECT current_value FROM header_avg_score), 0) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'danger'::text
                    END as status,
                    NULL::text as trend_analysis,
                    NULL::text as value_field,
                    NULL::text as key_field,
                    (SELECT trend_data FROM header_avg_score_trend_agg LIMIT 1) as trend_data,
                    (SELECT data_points FROM header_avg_score_points_agg LIMIT 1) as data_points
            ),
            header_completion_trend_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((date, value, count)::types.q_get_dashboard_bundle_v4_trend_data ORDER BY date),
                    '{}'::types.q_get_dashboard_bundle_v4_trend_data[]
                ) as trend_data
                FROM header_completion_trend
            ),
            header_completion_points_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((profile_id, date, value::float, attempt_id, simulation_id, scenario_id, 0)::types.q_get_dashboard_bundle_v4_data_point),
                    '{}'::types.q_get_dashboard_bundle_v4_data_point[]
                ) as data_points
                FROM header_completion_points
            ),
            header_completion_metric AS (
                SELECT 
                    COALESCE((SELECT has_data FROM header_completion), false)::boolean as has_data,
                    'avg'::text as method,
                    COALESCE((SELECT current_value FROM header_completion), 0)::int as current_value,
                    CASE
                        WHEN NOT COALESCE((SELECT has_data FROM header_completion), false) THEN 'neutral'::text
                        WHEN COALESCE((SELECT current_value FROM header_completion), 0) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                        WHEN COALESCE((SELECT current_value FROM header_completion), 0) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'danger'::text
                    END as status,
                    NULL::text as trend_analysis,
                    NULL::text as value_field,
                    NULL::text as key_field,
                    (SELECT trend_data FROM header_completion_trend_agg LIMIT 1) as trend_data,
                    (SELECT data_points FROM header_completion_points_agg LIMIT 1) as data_points
            ),
            header_first_pass_trend_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((date, value, count)::types.q_get_dashboard_bundle_v4_trend_data ORDER BY date),
                    '{}'::types.q_get_dashboard_bundle_v4_trend_data[]
                ) as trend_data
                FROM header_first_pass_trend
            ),
            header_first_pass_points_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((profile_id, date, value::float, attempt_id, simulation_id, COALESCE(scenario_id, ''), 0)::types.q_get_dashboard_bundle_v4_data_point),
                    '{}'::types.q_get_dashboard_bundle_v4_data_point[]
                ) as data_points
                FROM header_first_pass_points
            ),
            header_first_pass_metric AS (
                SELECT 
                    COALESCE((SELECT has_data FROM header_first_pass), false)::boolean as has_data,
                    'rate'::text as method,
                    COALESCE((SELECT current_value FROM header_first_pass), 0)::int as current_value,
                    CASE
                        WHEN NOT COALESCE((SELECT has_data FROM header_first_pass), false) THEN 'neutral'::text
                        WHEN COALESCE((SELECT current_value FROM header_first_pass), 0) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                        WHEN COALESCE((SELECT current_value FROM header_first_pass), 0) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'danger'::text
                    END as status,
                    NULL::text as trend_analysis,
                    NULL::text as value_field,
                    NULL::text as key_field,
                    (SELECT trend_data FROM header_first_pass_trend_agg LIMIT 1) as trend_data,
                    (SELECT data_points FROM header_first_pass_points_agg LIMIT 1) as data_points
            ),
            header_highest_trend_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((date, value, count)::types.q_get_dashboard_bundle_v4_trend_data ORDER BY date),
                    '{}'::types.q_get_dashboard_bundle_v4_trend_data[]
                ) as trend_data
                FROM header_highest_trend
            ),
            header_highest_points_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((profile_id, date, value::float, attempt_id, simulation_id, scenario_id, 0)::types.q_get_dashboard_bundle_v4_data_point),
                    '{}'::types.q_get_dashboard_bundle_v4_data_point[]
                ) as data_points
                FROM header_highest_points
            ),
            header_highest_metric AS (
                SELECT 
                    COALESCE((SELECT has_data FROM header_highest), false)::boolean as has_data,
                    'max'::text as method,
                    COALESCE((SELECT current_value FROM header_highest), 0)::int as current_value,
                    CASE
                        WHEN NOT COALESCE((SELECT has_data FROM header_highest), false) THEN 'neutral'::text
                        WHEN COALESCE((SELECT current_value FROM header_highest), 0) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                        WHEN COALESCE((SELECT current_value FROM header_highest), 0) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'danger'::text
                    END as status,
                    NULL::text as trend_analysis,
                    NULL::text as value_field,
                    NULL::text as key_field,
                    (SELECT trend_data FROM header_highest_trend_agg LIMIT 1) as trend_data,
                    (SELECT data_points FROM header_highest_points_agg LIMIT 1) as data_points
            ),
            header_messages_trend_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((date, value, count)::types.q_get_dashboard_bundle_v4_trend_data ORDER BY date),
                    '{}'::types.q_get_dashboard_bundle_v4_trend_data[]
                ) as trend_data
                FROM header_messages_trend
            ),
            header_messages_points_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((profile_id, date, value::float, attempt_id, simulation_id, scenario_id, 0)::types.q_get_dashboard_bundle_v4_data_point),
                    '{}'::types.q_get_dashboard_bundle_v4_data_point[]
                ) as data_points
                FROM header_messages_points
            ),
            header_messages_metric AS (
                SELECT 
                    COALESCE((SELECT has_data FROM header_messages), false)::boolean as has_data,
                    'avg'::text as method,
                    COALESCE((SELECT current_value FROM header_messages), 0)::int as current_value,
                    CASE
                        WHEN NOT COALESCE((SELECT has_data FROM header_messages), false) THEN 'neutral'::text
                        WHEN COALESCE((SELECT current_value FROM header_messages), 0) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                        WHEN COALESCE((SELECT current_value FROM header_messages), 0) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'danger'::text
                    END as status,
                    NULL::text as trend_analysis,
                    NULL::text as value_field,
                    NULL::text as key_field,
                    (SELECT trend_data FROM header_messages_trend_agg LIMIT 1) as trend_data,
                    (SELECT data_points FROM header_messages_points_agg LIMIT 1) as data_points
            ),
            header_persona_times_trend_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((date, value, count)::types.q_get_dashboard_bundle_v4_trend_data ORDER BY date),
                    '{}'::types.q_get_dashboard_bundle_v4_trend_data[]
                ) as trend_data
                FROM header_persona_times_trend
            ),
            header_persona_times_points_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((profile_id, date, value::float, attempt_id, simulation_id, scenario_id, 0)::types.q_get_dashboard_bundle_v4_data_point),
                    '{}'::types.q_get_dashboard_bundle_v4_data_point[]
                ) as data_points
                FROM header_persona_times_points
            ),
            header_persona_times_metric AS (
                SELECT 
                    COALESCE((SELECT has_data FROM header_persona_times), false)::boolean as has_data,
                    'avg'::text as method,
                    COALESCE((SELECT current_value FROM header_persona_times), 0)::int as current_value,
                    CASE
                        WHEN NOT COALESCE((SELECT has_data FROM header_persona_times), false) THEN 'neutral'::text
                        WHEN COALESCE((SELECT current_value FROM header_persona_times), 0) > (SELECT danger_threshold FROM settings_thresholds LIMIT 1) THEN 'danger'::text
                        WHEN COALESCE((SELECT current_value FROM header_persona_times), 0) > (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'success'::text
                    END as status,
                    NULL::text as trend_analysis,
                    NULL::text as value_field,
                    NULL::text as key_field,
                    (SELECT trend_data FROM header_persona_times_trend_agg LIMIT 1) as trend_data,
                    (SELECT data_points FROM header_persona_times_points_agg LIMIT 1) as data_points
            ),
            header_efficiency_trend_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((date, value, count)::types.q_get_dashboard_bundle_v4_trend_data ORDER BY date),
                    '{}'::types.q_get_dashboard_bundle_v4_trend_data[]
                ) as trend_data
                FROM header_efficiency_trend
            ),
            header_efficiency_points_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((profile_id, date, value::float, attempt_id, simulation_id, scenario_id, 0)::types.q_get_dashboard_bundle_v4_data_point),
                    '{}'::types.q_get_dashboard_bundle_v4_data_point[]
                ) as data_points
                FROM header_efficiency_points
            ),
            header_efficiency_metric AS (
                SELECT 
                    COALESCE((SELECT has_data FROM header_efficiency), false)::boolean as has_data,
                    'avg'::text as method,
                    COALESCE((SELECT current_value FROM header_efficiency), 0)::int as current_value,
                    CASE
                        WHEN NOT COALESCE((SELECT has_data FROM header_efficiency), false) THEN 'neutral'::text
                        WHEN COALESCE((SELECT current_value FROM header_efficiency), 0) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                        WHEN COALESCE((SELECT current_value FROM header_efficiency), 0) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'danger'::text
                    END as status,
                    NULL::text as trend_analysis,
                    NULL::text as value_field,
                    NULL::text as key_field,
                    (SELECT trend_data FROM header_efficiency_trend_agg LIMIT 1) as trend_data,
                    (SELECT data_points FROM header_efficiency_points_agg LIMIT 1) as data_points
            ),
            header_stagnation_trend_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((date, value, count)::types.q_get_dashboard_bundle_v4_trend_data ORDER BY date),
                    '{}'::types.q_get_dashboard_bundle_v4_trend_data[]
                ) as trend_data
                FROM header_stagnation_trend
            ),
            header_stagnation_points_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((COALESCE(profile_id, ''), date, value::float, COALESCE(attempt_id, ''), COALESCE(simulation_id, ''), COALESCE(scenario_id, ''), 0)::types.q_get_dashboard_bundle_v4_data_point),
                    '{}'::types.q_get_dashboard_bundle_v4_data_point[]
                ) as data_points
                FROM header_stagnation_points
            ),
            header_stagnation_metric AS (
                SELECT 
                    COALESCE((SELECT has_data FROM header_stagnation), false)::boolean as has_data,
                    'rate'::text as method,
                    COALESCE((SELECT current_value FROM header_stagnation), 0)::int as current_value,
                    CASE
                        WHEN NOT COALESCE((SELECT has_data FROM header_stagnation), false) THEN 'neutral'::text
                        WHEN COALESCE((SELECT current_value FROM header_stagnation), 0) > (SELECT danger_threshold FROM settings_thresholds LIMIT 1) THEN 'danger'::text
                        WHEN COALESCE((SELECT current_value FROM header_stagnation), 0) > (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'success'::text
                    END as status,
                    NULL::text as trend_analysis,
                    NULL::text as value_field,
                    NULL::text as key_field,
                    (SELECT trend_data FROM header_stagnation_trend_agg LIMIT 1) as trend_data,
                    (SELECT data_points FROM header_stagnation_points_agg LIMIT 1) as data_points
            ),
            header_time_trend_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((date, value, count)::types.q_get_dashboard_bundle_v4_trend_data ORDER BY date),
                    '{}'::types.q_get_dashboard_bundle_v4_trend_data[]
                ) as trend_data
                FROM header_time_trend
            ),
            header_time_points_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((profile_id, date, value::float, attempt_id, simulation_id, scenario_id, 0)::types.q_get_dashboard_bundle_v4_data_point),
                    '{}'::types.q_get_dashboard_bundle_v4_data_point[]
                ) as data_points
                FROM header_time_points
            ),
            header_time_metric AS (
                SELECT 
                    COALESCE((SELECT has_data FROM header_time), false)::boolean as has_data,
                    'avg'::text as method,
                    COALESCE((SELECT current_value FROM header_time), 0)::int as current_value,
                    CASE
                        WHEN NOT COALESCE((SELECT has_data FROM header_time), false) THEN 'neutral'::text
                        WHEN COALESCE((SELECT current_value FROM header_time), 0) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                        WHEN COALESCE((SELECT current_value FROM header_time), 0) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'danger'::text
                    END as status,
                    NULL::text as trend_analysis,
                    NULL::text as value_field,
                    NULL::text as key_field,
                    (SELECT trend_data FROM header_time_trend_agg LIMIT 1) as trend_data,
                    (SELECT data_points FROM header_time_points_agg LIMIT 1) as data_points
            ),
            header_attempts_trend_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((date, value, count)::types.q_get_dashboard_bundle_v4_trend_data ORDER BY date),
                    '{}'::types.q_get_dashboard_bundle_v4_trend_data[]
                ) as trend_data
                FROM header_attempts_trend
            ),
            header_attempts_points_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((profile_id, date, value::float, attempt_id, simulation_id, scenario_id, 0)::types.q_get_dashboard_bundle_v4_data_point),
                    '{}'::types.q_get_dashboard_bundle_v4_data_point[]
                ) as data_points
                FROM header_attempts_points
            ),
            header_attempts_metric AS (
                SELECT 
                    COALESCE((SELECT has_data FROM header_attempts), false)::boolean as has_data,
                    'countDistinct'::text as method,
                    COALESCE((SELECT current_value FROM header_attempts), 0)::int as current_value,
                    CASE
                        WHEN NOT COALESCE((SELECT has_data FROM header_attempts), false) THEN 'neutral'::text
                        WHEN COALESCE((SELECT current_value FROM header_attempts), 0) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                        WHEN COALESCE((SELECT current_value FROM header_attempts), 0) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'danger'::text
                    END as status,
                    NULL::text as trend_analysis,
                    NULL::text as value_field,
                    NULL::text as key_field,
                    (SELECT trend_data FROM header_attempts_trend_agg LIMIT 1) as trend_data,
                    (SELECT data_points FROM header_attempts_points_agg LIMIT 1) as data_points
            ),
            header_metrics_combined AS (
                SELECT (
                    (SELECT (has_data, method, current_value, status, trend_analysis, value_field, key_field, trend_data, data_points)::types.q_get_dashboard_bundle_v4_metric_response FROM header_avg_score_metric LIMIT 1),
                    (SELECT (has_data, method, current_value, status, trend_analysis, value_field, key_field, trend_data, data_points)::types.q_get_dashboard_bundle_v4_metric_response FROM header_completion_metric LIMIT 1),
                    (SELECT (has_data, method, current_value, status, trend_analysis, value_field, key_field, trend_data, data_points)::types.q_get_dashboard_bundle_v4_metric_response FROM header_first_pass_metric LIMIT 1),
                    (SELECT (has_data, method, current_value, status, trend_analysis, value_field, key_field, trend_data, data_points)::types.q_get_dashboard_bundle_v4_metric_response FROM header_highest_metric LIMIT 1),
                    (SELECT (has_data, method, current_value, status, trend_analysis, value_field, key_field, trend_data, data_points)::types.q_get_dashboard_bundle_v4_metric_response FROM header_messages_metric LIMIT 1),
                    (SELECT (has_data, method, current_value, status, trend_analysis, value_field, key_field, trend_data, data_points)::types.q_get_dashboard_bundle_v4_metric_response FROM header_persona_times_metric LIMIT 1),
                    (SELECT (has_data, method, current_value, status, trend_analysis, value_field, key_field, trend_data, data_points)::types.q_get_dashboard_bundle_v4_metric_response FROM header_efficiency_metric LIMIT 1),
                    (SELECT (has_data, method, current_value, status, trend_analysis, value_field, key_field, trend_data, data_points)::types.q_get_dashboard_bundle_v4_metric_response FROM header_stagnation_metric LIMIT 1),
                    (SELECT (has_data, method, current_value, status, trend_analysis, value_field, key_field, trend_data, data_points)::types.q_get_dashboard_bundle_v4_metric_response FROM header_time_metric LIMIT 1),
                    (SELECT (has_data, method, current_value, status, trend_analysis, value_field, key_field, trend_data, data_points)::types.q_get_dashboard_bundle_v4_metric_response FROM header_attempts_metric LIMIT 1)
                )::types.q_get_dashboard_bundle_v4_header_metrics as header_metrics
            ),
            -- Primary metrics helper CTEs
            growth_chart_data_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (date, average_score::float, completion_rate::float, first_attempt_pass_rate::float, session_efficiency::float, stagnation_rate::float)::types.q_get_dashboard_bundle_v4_growth_data_point
                        ORDER BY date_val
                    ),
                    '{}'::types.q_get_dashboard_bundle_v4_growth_data_point[]
                ) as chart_data
                FROM growth_chart_dates
            ),
            growth_available_metrics AS (
                SELECT ARRAY[
                    ('averageScore', 'Average Score', '#3b82f6', '%', 'Average score across all attempts', 'percent')::types.q_get_dashboard_bundle_v4_growth_metric,
                    ('completionRate', 'Completion Rate', '#8b5cf6', '%', 'Percentage of scenarios completed', 'percent')::types.q_get_dashboard_bundle_v4_growth_metric,
                    ('firstAttemptPassRate', 'First Attempt Pass Rate', '#06b6d4', '%', 'Pass rate on first attempts', 'percent')::types.q_get_dashboard_bundle_v4_growth_metric,
                    ('sessionEfficiency', 'Session Efficiency', '#84cc16', '%', 'Efficiency index based on score and time (0-100)', 'percent')::types.q_get_dashboard_bundle_v4_growth_metric,
                    ('stagnationRate', 'Stagnation Rate', '#ec4899', '%', 'Percentage of attempts with no improvement', 'percent')::types.q_get_dashboard_bundle_v4_growth_metric
                ] as available_metrics
            ),
            growth_window_averages_combined AS (
                SELECT (
                    ROW((7, (SELECT ROUND(last_avg) FROM growth_window), (SELECT ROUND(prev_avg) FROM growth_window))::types.q_get_dashboard_bundle_v4_growth_window_average)
                )::types.q_get_dashboard_bundle_v4_growth_window_averages as window_averages
            ),
            growth_data_combined AS (
                SELECT (
                    (SELECT chart_data FROM growth_chart_data_agg LIMIT 1),
                    (SELECT available_metrics FROM growth_available_metrics LIMIT 1),
                    (SELECT window_averages FROM growth_window_averages_combined LIMIT 1),
                    CASE
                        WHEN (SELECT last_avg FROM growth_window) IS NULL OR (SELECT prev_avg FROM growth_window) IS NULL THEN 'neutral'::text
                        WHEN (SELECT ROUND(last_avg - prev_avg) FROM growth_window) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                        WHEN (SELECT ROUND(last_avg - prev_avg) FROM growth_window) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'danger'::text
                    END
                )::types.q_get_dashboard_bundle_v4_growth_data_response as growth_data
            ),
            persona_performance_top5 AS (
                SELECT pa.name, pa.avg_score, pa.sessions, pa.color, pa.simulation_ids, 
                       COALESCE(ptc.trends, ARRAY[]::types.q_get_dashboard_bundle_v4_persona_trend_data[]) as trends,
                       pa.status
                FROM persona_agg pa
                LEFT JOIN persona_trends_agg_converted ptc ON ptc.persona_id = pa.persona_id
                ORDER BY pa.avg_score DESC
                LIMIT 5
            ),
            persona_performance_chart_data_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (name, COALESCE(avg_score, 0)::float, sessions, color, simulation_ids, trends, status)::types.q_get_dashboard_bundle_v4_persona_performance_data
                    ),
                    '{}'::types.q_get_dashboard_bundle_v4_persona_performance_data[]
                ) as chart_data
                FROM persona_performance_top5
            ),
            persona_performance_valid_sims AS (
                SELECT COALESCE(
                    ARRAY_AGG(DISTINCT simulation_id::text ORDER BY simulation_id::text),
                    ARRAY[]::text[]
                ) as valid_simulation_ids
                FROM filt
                WHERE simulation_id IS NOT NULL
            ),
            persona_performance_combined AS (
                SELECT (
                    (SELECT chart_data FROM persona_performance_chart_data_agg LIMIT 1),
                    (SELECT valid_simulation_ids FROM persona_performance_valid_sims LIMIT 1),
                    (SELECT colors FROM persona_colors_agg_converted LIMIT 1)
                )::types.q_get_dashboard_bundle_v4_persona_performance_response as persona_performance
            ),
            rubric_heatmap_combined AS (
                SELECT (
                    (SELECT matrices FROM rubric_correlations_converted LIMIT 1),
                    (SELECT valid_rubric_ids FROM rubric_correlations_converted LIMIT 1),
                    (SELECT status FROM rubric_correlations_converted LIMIT 1)
                )::types.q_get_dashboard_bundle_v4_rubric_heatmap_response as rubric_heatmap
            ),
            primary_metrics_combined AS (
                SELECT (
                    (SELECT growth_data FROM growth_data_combined LIMIT 1),
                    (SELECT persona_performance FROM persona_performance_combined LIMIT 1),
                    (SELECT rubric_heatmap FROM rubric_heatmap_combined LIMIT 1)
                )::types.q_get_dashboard_bundle_v4_primary_metrics as primary_metrics
            ),
            -- =====================================================
            -- SECONDARY METRICS
            -- =====================================================
            
            -- Attempt Improvement (ENHANCED with per-simulation facts)
            attempt_first AS (
                SELECT profile_id, simulation_id, attempt_id,
                       MIN(attempt_created_at) AS first_ts
                FROM filt
                GROUP BY profile_id, simulation_id, attempt_id
            ),
            attempt_ord AS (
                SELECT af.*, 
                       ROW_NUMBER() OVER (PARTITION BY af.profile_id, af.simulation_id ORDER BY af.first_ts) AS attempt_no
                FROM attempt_first af
            ),
            attempt_stats AS (
                SELECT
                    ao.profile_id,
                    ao.simulation_id,
                    ao.attempt_id,
                    ao.attempt_no,
                    AVG(f.grade_percent)::float AS avg_grade,
                    AVG(f.time_taken_seconds / 60.0)::float AS avg_time_minutes,
                    MAX((f.passed)::int)::int AS passed_any
                FROM attempt_ord ao
                JOIN filt f ON f.attempt_id = ao.attempt_id
                WHERE f.grade_percent IS NOT NULL
                GROUP BY ao.profile_id, ao.simulation_id, ao.attempt_id, ao.attempt_no
            ),
            multiple_users_attempt_data AS (
                SELECT
                    simulation_id,
                    attempt_no,
                    AVG(avg_grade)::float AS avg_grade,
                    AVG(avg_time_minutes)::float AS avg_time_minutes,
                    (100.0 * AVG(passed_any))::float AS pass_rate
                FROM attempt_stats
                WHERE avg_grade IS NOT NULL
                GROUP BY simulation_id, attempt_no
            ),
            attempt_rows AS (
                SELECT
                    attempt_no,
                    AVG(avg_grade)::float AS avg_grade,
                    AVG(avg_time_minutes)::float AS avg_time_minutes,
                    AVG(pass_rate)::float AS pass_rate
                FROM multiple_users_attempt_data
                WHERE attempt_no <= 5
                GROUP BY attempt_no
            ),
            attempt_improvement_chart_data_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        ('Attempt ' || attempt_no, ROUND(COALESCE(avg_grade, 0))::float, ROUND(COALESCE(avg_time_minutes, 0))::float, ROUND(COALESCE(pass_rate, 0))::float)::types.q_get_dashboard_bundle_v4_attempt_improvement_data
                        ORDER BY attempt_no
                    ),
                    '{}'::types.q_get_dashboard_bundle_v4_attempt_improvement_data[]
                ) as chart_data
                FROM attempt_rows
            ),
            attempt_facts AS (
                SELECT
                    simulation_id::text,
                    attempt_no::int,
                    ROUND(COALESCE(avg_grade, 0))::int AS avg_grade,
                    ROUND(COALESCE(avg_time_minutes, 0))::int AS avg_minutes,
                    ROUND(COALESCE(pass_rate, 0))::int AS pass_rate
                FROM multiple_users_attempt_data
            ),
            attempt_improvement_facts_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (simulation_id, attempt_no, avg_grade::float, avg_minutes::float, pass_rate::float)::types.q_get_dashboard_bundle_v4_attempt_improvement_fact
                        ORDER BY simulation_id, attempt_no
                    ),
                    '{}'::types.q_get_dashboard_bundle_v4_attempt_improvement_fact[]
                ) as facts
                FROM attempt_facts
            ),
            attempt_improvement_valid_sims AS (
                SELECT COALESCE(
                    ARRAY_AGG(DISTINCT simulation_id::text ORDER BY simulation_id::text),
                    ARRAY[]::text[]
                ) as valid_simulation_ids
                FROM filt
                WHERE simulation_id IS NOT NULL
            ),
            attempt_improvement_status AS (
                SELECT CASE
                    WHEN (SELECT COUNT(*) FROM attempt_rows) < 2 THEN 'neutral'::text
                    WHEN (SELECT avg_grade FROM attempt_rows WHERE attempt_no = (SELECT MAX(attempt_no) FROM attempt_rows)) IS NULL 
                         OR (SELECT avg_grade FROM attempt_rows WHERE attempt_no = (SELECT MIN(attempt_no) FROM attempt_rows)) IS NULL THEN 'neutral'::text
                    WHEN (SELECT avg_grade FROM attempt_rows WHERE attempt_no = (SELECT MAX(attempt_no) FROM attempt_rows)) - 
                         (SELECT avg_grade FROM attempt_rows WHERE attempt_no = (SELECT MIN(attempt_no) FROM attempt_rows)) >= 
                         (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                    WHEN (SELECT avg_grade FROM attempt_rows WHERE attempt_no = (SELECT MAX(attempt_no) FROM attempt_rows)) - 
                         (SELECT avg_grade FROM attempt_rows WHERE attempt_no = (SELECT MIN(attempt_no) FROM attempt_rows)) >= 
                         (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                    ELSE 'danger'::text
                END as status
            ),
            attempt_improvement_combined AS (
                SELECT (
                    (SELECT chart_data FROM attempt_improvement_chart_data_agg LIMIT 1),
                    (SELECT facts FROM attempt_improvement_facts_agg LIMIT 1),
                    (SELECT valid_simulation_ids FROM attempt_improvement_valid_sims LIMIT 1),
                    (SELECT status FROM attempt_improvement_status LIMIT 1)
                )::types.q_get_dashboard_bundle_v4_attempt_improvement_response as attempt_improvement
            ),
            
            -- Cohort Performance (FULL IMPLEMENTATION)
            filt_with_cohorts AS (
                SELECT f.*, c_id
                FROM filt f,
                LATERAL unnest(f.cohort_ids) AS c_id
            ),
            cohort_list AS (
                SELECT DISTINCT 
                    c.id, 
                    c.title,
                    ARRAY(
                        SELECT cp.profile_id 
                        FROM cohort_profiles cp
                        JOIN profiles p ON p.id = cp.profile_id
                        WHERE cp.cohort_id = c.id
                            AND cp.active = true
                            AND p.role = ANY((SELECT roles FROM params)::profile_role[])
                    ) AS profile_ids,
                    ARRAY(SELECT cs.simulation_id FROM cohort_simulations cs WHERE cs.cohort_id = c.id AND cs.active = true) AS simulation_ids
                FROM cohorts c
                JOIN (SELECT DISTINCT c_id FROM filt_with_cohorts) fc ON fc.c_id = c.id
            ),
            cohort_attempts AS (
                SELECT
                    fc.c_id AS cohort_id,
                    fc.attempt_id,
                    MAX((fc.passed)::int)::int AS passed_any,
                    AVG(fc.grade_percent)::float AS avg_grade_attempt
                FROM filt_with_cohorts fc
                GROUP BY fc.c_id, fc.attempt_id
            ),
            cohort_agg AS (
                SELECT
                    cl.id AS cohort_id,
                    cl.title AS cohort_name,
                    COALESCE(cardinality(cl.profile_ids), 0) AS total_students_declared,
                    cardinality(cl.profile_ids) AS total_students_seen,
                    COUNT(DISTINCT ca.attempt_id) AS total_attempts,
                    SUM(ca.passed_any)::int AS passed_attempts,
                    (100.0 * AVG(ca.passed_any))::float AS pass_rate_attempts,
                    AVG(ca.avg_grade_attempt)::float AS avg_percentage_score,
                    (SELECT COUNT(*) FROM (
                        SELECT profile_id
                        FROM filt_with_cohorts fc2
                        WHERE fc2.c_id = cl.id
                        GROUP BY profile_id
                        HAVING 
                            COUNT(DISTINCT simulation_id) = cardinality(cl.simulation_ids)
                            AND NOT EXISTS (
                                SELECT 1 
                                FROM (
                                    SELECT 
                                        simulation_id,
                                        MAX(CASE WHEN grade_percent IS NULL THEN 0 ELSE grade_percent END) as best_score
                                    FROM filt_with_cohorts fc3 
                                    WHERE fc3.c_id = cl.id 
                                        AND fc3.profile_id = fc2.profile_id
                                    GROUP BY simulation_id
                                ) sim_bests
                                WHERE sim_bests.best_score < 80.0
                            )
                    ) s) AS passed_students,
                    (SELECT COUNT(*) FROM (
                        SELECT 1
                        FROM filt_with_cohorts fc2
                        WHERE fc2.c_id = cl.id
                        GROUP BY fc2.profile_id
                        HAVING MAX((fc2.passed)::int) = 1
                    ) s) AS passed_at_least_once,
                    cardinality(cl.simulation_ids) AS simulation_count,
                    cardinality(cl.simulation_ids) AS required_simulations
                FROM cohort_list cl
                LEFT JOIN cohort_attempts ca ON ca.cohort_id = cl.id
                GROUP BY cl.id, cl.title, cl.profile_ids, cl.simulation_ids
            ),
            cohort_performance_cohort_data_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (cohort_id::text, cohort_name,
                         ROUND(CASE 
                             WHEN total_students_seen > 0 THEN 
                                 (100.0 * passed_students / total_students_seen)::numeric
                             ELSE 0
                         END, 2)::float,
                         ROUND(COALESCE(avg_percentage_score, 0))::int,
                         GREATEST(total_students_declared, total_students_seen),
                         COALESCE(passed_at_least_once, 0),
                         COALESCE(total_attempts, 0),
                         COALESCE(passed_attempts, 0),
                         COALESCE(simulation_count, 0),
                         COALESCE(required_simulations, 0),
                         CASE
                             WHEN total_students_seen = 0 THEN 'neutral'::text
                             WHEN (100.0 * passed_students / NULLIF(total_students_seen, 0)) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                             WHEN (100.0 * passed_students / NULLIF(total_students_seen, 0)) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                             ELSE 'danger'::text
                         END)::types.q_get_dashboard_bundle_v4_cohort_data
                        ORDER BY cohort_name
                    ),
                    '{}'::types.q_get_dashboard_bundle_v4_cohort_data[]
                ) as cohort_data
                FROM cohort_agg
            ),
            cohort_daily_data AS (
                SELECT
                    to_char(date_trunc('day', fc.attempt_created_at), 'YYYY-MM-DD') AS date,
                    AVG(fc.grade_percent)::float AS avg_score,
                    fc.c_id::text AS cohort_id
                FROM filt_with_cohorts fc
                WHERE fc.grade_percent IS NOT NULL
                GROUP BY fc.c_id, date_trunc('day', fc.attempt_created_at)
            ),
            cohort_performance_daily_data_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (date, ROUND(COALESCE(avg_score, 0))::int, cohort_id)::types.q_get_dashboard_bundle_v4_daily_data
                        ORDER BY cohort_id, date
                    ),
                    '{}'::types.q_get_dashboard_bundle_v4_daily_data[]
                ) as daily_data
                FROM cohort_daily_data
            ),
            cohort_performance_valid_sims AS (
                SELECT COALESCE(
                    ARRAY_AGG(DISTINCT simulation_id::text ORDER BY simulation_id::text),
                    ARRAY[]::text[]
                ) as valid_simulation_ids
                FROM filt
                WHERE simulation_id IS NOT NULL
            ),
            cohort_performance_status AS (
                SELECT CASE
                    WHEN (SELECT COUNT(*) FROM cohort_agg) = 0 THEN 'neutral'::text
                    WHEN (SELECT AVG(
                        CASE 
                            WHEN total_students_seen > 0 THEN 
                                (100.0 * passed_students / total_students_seen)::numeric
                            ELSE 0
                        END
                    ) FROM cohort_agg) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                    WHEN (SELECT AVG(
                        CASE 
                            WHEN total_students_seen > 0 THEN 
                                (100.0 * passed_students / total_students_seen)::numeric
                            ELSE 0
                        END
                    ) FROM cohort_agg) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                    ELSE 'danger'::text
                END as status
            ),
            cohort_performance_combined AS (
                SELECT (
                    (SELECT cohort_data FROM cohort_performance_cohort_data_agg LIMIT 1),
                    (SELECT daily_data FROM cohort_performance_daily_data_agg LIMIT 1),
                    ARRAY[]::types.q_get_dashboard_bundle_v4_cohort_fact[],
                    ARRAY[]::types.q_get_dashboard_bundle_v4_cohort_daily_fact[],
                    (SELECT valid_simulation_ids FROM cohort_performance_valid_sims LIMIT 1),
                    (SELECT status FROM cohort_performance_status LIMIT 1)
                )::types.q_get_dashboard_bundle_v4_cohort_performance_response as cohort_performance
            ),
            
            -- Skill Performance (FULL IMPLEMENTATION with radar charts)
            filt_for_skills AS (
                SELECT chat_id, simulation_id, cohort_ids, profile_cohort_ids, profile_role,
                       is_general, is_practice, is_archived, profile_id, attempt_created_at
                FROM analytics a
                WHERE a.attempt_created_at >= (SELECT start_date FROM params)
                    AND a.attempt_created_at < (SELECT end_date FROM params)
                    AND (cardinality((SELECT cohort_ids FROM params)::uuid[]) = 0 OR a.simulation_id IN (SELECT simulation_id FROM filtered_simulation_ids))
                    AND a.profile_role = ANY((SELECT roles FROM params)::profile_role[])
                    AND (cardinality((SELECT department_ids FROM params)::uuid[]) = 0 OR a.department_id = ANY((SELECT department_ids FROM params)::uuid[]))
                    AND ((SELECT simulation_filters FROM params)::text[] IS NULL OR cardinality((SELECT simulation_filters FROM params)::text[]) > 0)
                    AND (
                        (SELECT simulation_filters FROM params)::text[] IS NULL OR (
                            ('general' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_general) OR
                            ('practice' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_practice) OR
                            ('archived' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_archived)
                        )
                    )
                    AND (
                        'archived' = ANY((SELECT simulation_filters FROM params)::text[]) OR a.is_archived = FALSE
                    )
            ),
            -- Get chat scenario and simulation info for skills fallback
            chat_scenario_info_skills AS (
                SELECT DISTINCT
                    c.id AS chat_id,
                    c.scenario_id,
                    sa.simulation_id
                FROM chats c
                JOIN attempt_chats ac ON ac.chat_id = c.id
                JOIN simulation_attempts sa ON sa.id = ac.attempt_id
                WHERE c.id IN (SELECT chat_id FROM filt_for_skills)
            ),
            -- Get first scenario's rubric per simulation for skills (fallback)
            sim_first_scenario_rubric_skills AS (
                SELECT DISTINCT ON (ss.simulation_id)
                    ss.simulation_id,
                    rga.rubric_id
                FROM simulation_scenarios ss
                LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
                LEFT JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
                WHERE ss.active = true
                  AND ss.simulation_id IN (SELECT DISTINCT simulation_id FROM chat_scenario_info_skills)
                ORDER BY ss.simulation_id, ss.position
            ),
            latest_grade_for_skills AS (
                SELECT DISTINCT ON (c.id, COALESCE(rga.rubric_id, (SELECT rga_fallback.rubric_id FROM rubric_grade_agents rga_fallback WHERE rga_fallback.id = ssrga_fallback.rubric_grade_agent_id), sfsr.rubric_id))
                       scg.id AS grade_id,
                       c.id AS chat_id,
                       COALESCE(
                           rga.rubric_id,
                           (SELECT rga_fallback.rubric_id FROM rubric_grade_agents rga_fallback WHERE rga_fallback.id = ssrga_fallback.rubric_grade_agent_id),
                           sfsr.rubric_id
                       ) AS rubric_id,
                       scg.created_at
                FROM grades scg
                LEFT JOIN rubric_grade_agents rga ON rga.id = scg.rubric_grade_agent_id
                JOIN runs r ON r.id = scg.run_id
                JOIN group_runs gr ON gr.run_id = r.id
                JOIN grade_groups gg ON gg.group_id = gr.group_id
                JOIN chats c ON c.id = gg.chat_id
                LEFT JOIN chat_scenario_info_skills csi ON csi.chat_id = c.id
                LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga_fallback ON ssrga_fallback.simulation_id = csi.simulation_id
                  AND ssrga_fallback.scenario_id = csi.scenario_id
                  AND rga.rubric_id IS NULL
                LEFT JOIN sim_first_scenario_rubric_skills sfsr ON sfsr.simulation_id = csi.simulation_id
                  AND rga.rubric_id IS NULL
                  AND ssrga_fallback.rubric_grade_agent_id IS NULL
                WHERE EXISTS (
                    SELECT 1 FROM runs r_check
                    JOIN group_runs gr_check ON gr_check.run_id = r_check.id
                    JOIN grade_groups gg_check ON gg_check.group_id = gr_check.group_id
                    JOIN chats c_check ON c_check.id = gg_check.chat_id
                    WHERE r_check.id = scg.run_id
                )
                  AND c.id IN (SELECT chat_id FROM filt_for_skills)
                  AND COALESCE(
                      rga.rubric_id,
                      (SELECT rga_fallback.rubric_id FROM rubric_grade_agents rga_fallback WHERE rga_fallback.id = ssrga_fallback.rubric_grade_agent_id),
                      sfsr.rubric_id
                  ) IS NOT NULL
                ORDER BY c.id, COALESCE(rga.rubric_id, (SELECT rga_fallback.rubric_id FROM rubric_grade_agents rga_fallback WHERE rga_fallback.id = ssrga_fallback.rubric_grade_agent_id), sfsr.rubric_id), scg.created_at DESC
            ),
            per_grade_group_skills AS (
                SELECT
                    lg.rubric_id,
                    sg.id AS group_id,
                    sg.name AS group_name,
                    f.simulation_id,
                    lg.grade_id AS grade_id,
                    SUM(scf.total)::float8 AS score,
                    SUM(s.points)::float8 AS points,
                    CASE WHEN sg.points > 0
                         THEN 100.0 * SUM(scf.total)::float8 / sg.points::float8
                         ELSE NULL
                    END AS pct
                FROM latest_grade_for_skills lg
                JOIN filt_for_skills f ON f.chat_id = lg.chat_id
                JOIN feedbacks scf ON scf.grade_id = lg.grade_id
                JOIN standards s ON s.id = scf.standard_id
                JOIN rubric_standard_groups rsg ON rsg.rubric_id = lg.rubric_id AND rsg.active = true
                JOIN standard_groups sg ON sg.id = rsg.standard_group_id AND sg.id = s.standard_group_id
                GROUP BY lg.rubric_id, sg.id, sg.name, f.simulation_id, lg.grade_id, sg.points
            ),
            radar_rows AS (
                SELECT 
                    pgg.rubric_id, 
                    sg.short_name AS group_name,
                    sg.description AS group_description,
                    AVG(pgg.pct)::float8 AS avg_pct
                FROM per_grade_group_skills pgg
                JOIN standard_groups sg ON sg.id = pgg.group_id
                GROUP BY pgg.rubric_id, sg.short_name, sg.description
            ),
            skill_group_stats AS (
                SELECT
                    pgg.rubric_id,
                    sg.id AS group_id,
                    sg.name AS group_name,
                    sg.description AS group_description,
                    pgg.simulation_id,
                    SUM(pgg.score) AS score_sum,
                    SUM(pgg.points) AS points_sum,
                    ROUND(AVG(pgg.pct))::int AS avg_pct
                FROM per_grade_group_skills pgg
                JOIN standard_groups sg ON sg.id = pgg.group_id
                GROUP BY pgg.rubric_id, sg.id, sg.name, sg.description, pgg.simulation_id
            ),
            radar_data_per_rubric AS (
                SELECT
                    rubric_id,
                    COALESCE(
                        ARRAY_AGG(
                            (group_name, group_description, GREATEST(0, LEAST(1, COALESCE(avg_pct, 0) / 100.0))::float, 1.0::float)::types.q_get_dashboard_bundle_v4_skill_radar_data
                            ORDER BY group_name
                        ),
                        '{}'::types.q_get_dashboard_bundle_v4_skill_radar_data[]
                    ) as radar_data
                FROM radar_rows
                GROUP BY rubric_id
            ),
            group_facts_per_rubric AS (
                SELECT
                    rubric_id,
                    COALESCE(
                        ARRAY_AGG(
                            (group_id::text, group_name, group_description, simulation_id::text, COALESCE(score_sum, 0)::float, COALESCE(points_sum, 0)::float, COALESCE(avg_pct, 0)::float)::types.q_get_dashboard_bundle_v4_skill_standard_fact
                            ORDER BY group_name, simulation_id
                        ),
                        '{}'::types.q_get_dashboard_bundle_v4_skill_standard_fact[]
                    ) as group_facts
                FROM skill_group_stats
                GROUP BY rubric_id
            ),
            skill_performance_packages_agg AS (
                SELECT
                    COALESCE(rd.rubric_id, gf.rubric_id) AS rubric_id,
                    COALESCE(rd.radar_data, '{}'::types.q_get_dashboard_bundle_v4_skill_radar_data[]) AS radar_data,
                    COALESCE(gf.group_facts, '{}'::types.q_get_dashboard_bundle_v4_skill_standard_fact[]) AS group_facts
                FROM radar_data_per_rubric rd
                FULL OUTER JOIN group_facts_per_rubric gf ON gf.rubric_id = rd.rubric_id
            ),
            skill_performance_packages_combined AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (rubric_id::text, radar_data, group_facts)::types.q_get_dashboard_bundle_v4_skill_package
                        ORDER BY rubric_id::text
                    ),
                    '{}'::types.q_get_dashboard_bundle_v4_skill_package[]
                ) as packages
                FROM skill_performance_packages_agg
            ),
            skill_performance_valid_rubrics AS (
                SELECT COALESCE(
                    ARRAY_AGG(DISTINCT rubric_id::text ORDER BY rubric_id::text),
                    ARRAY[]::text[]
                ) as valid_rubric_ids
                FROM per_grade_group_skills
            ),
            skill_performance_status AS (
                SELECT CASE
                    WHEN (SELECT COUNT(*) FROM skill_performance_packages_combined) = 0 THEN 'neutral'::text
                    ELSE 'success'::text
                END as status
            ),
            skill_performance_combined AS (
                SELECT (
                    (SELECT packages FROM skill_performance_packages_combined LIMIT 1),
                    (SELECT valid_rubric_ids FROM skill_performance_valid_rubrics LIMIT 1),
                    (SELECT status FROM skill_performance_status LIMIT 1)
                )::types.q_get_dashboard_bundle_v4_skill_performance_response as skill_performance
            ),
            secondary_metrics_combined AS (
                SELECT (
                    (SELECT attempt_improvement FROM attempt_improvement_combined LIMIT 1),
                    (SELECT cohort_performance FROM cohort_performance_combined LIMIT 1),
                    (SELECT skill_performance FROM skill_performance_combined LIMIT 1)
                )::types.q_get_dashboard_bundle_v4_secondary_metrics as secondary_metrics
            ),
            -- =====================================================
            -- FOOTER METRICS
            -- =====================================================
            
            -- Scenario Performance (FULL IMPLEMENTATION with categorical parameters)
            param_ids_categorical AS (
                SELECT id
                FROM parameters
                WHERE active = TRUE
            ),
            cat_map AS (
                SELECT 
                    f.id AS parameter_item_id,
                    fp.parameter_id,
                    s.id AS scenario_id
                FROM fields f
                JOIN parameter_fields fp ON fp.field_id = f.id AND fp.active = true
                JOIN param_ids_categorical p ON p.id = fp.parameter_id
                JOIN scenario_fields sf ON sf.field_id = f.id
                JOIN scenarios s ON s.id = sf.scenario_id
                WHERE s.active = TRUE
            ),
            scenario_seen AS (
                SELECT DISTINCT f.scenario_id
                FROM filt f
                WHERE f.scenario_id IS NOT NULL
            ),
            cat_map_seen AS (
                SELECT cm.parameter_id, cm.parameter_item_id, cm.scenario_id
                FROM cat_map cm
                JOIN scenario_seen ss ON ss.scenario_id = cm.scenario_id
            ),
            attempt_daily_categorical AS (
                SELECT
                    cm.parameter_id,
                    cm.parameter_item_id,
                    to_char(date_trunc('day', f.attempt_created_at), 'YYYY-MM-DD') AS date,
                    EXTRACT(EPOCH FROM date_trunc('day', f.attempt_created_at))::bigint AS timestamp,
                    AVG(f.grade_percent)::float AS avg_score,
                    COUNT(*)::int AS attempts,
                    SUM((f.passed)::int)::int AS passed_attempts
                FROM filt f
                JOIN cat_map_seen cm ON cm.scenario_id = f.scenario_id
                WHERE f.grade_percent IS NOT NULL
                GROUP BY cm.parameter_id, cm.parameter_item_id, date_trunc('day', f.attempt_created_at)
            ),
            scenario_performance_attribute_attempt_facts_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (parameter_id::text, parameter_item_id::text, date, timestamp, avg_score, attempts, passed_attempts)::types.q_get_dashboard_bundle_v4_scenario_attribute_attempt_fact
                        ORDER BY parameter_id, parameter_item_id, date
                    ),
                    '{}'::types.q_get_dashboard_bundle_v4_scenario_attribute_attempt_fact[]
                ) as attribute_attempt_facts
                FROM attempt_daily_categorical
            ),
            scenario_performance_attribute_scenario_facts_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (parameter_id::text, parameter_item_id::text, scenario_id::text)::types.q_get_dashboard_bundle_v4_scenario_attribute_scenario_fact
                        ORDER BY parameter_id, parameter_item_id, scenario_id
                    ),
                    '{}'::types.q_get_dashboard_bundle_v4_scenario_attribute_scenario_fact[]
                ) as attribute_scenario_facts
                FROM cat_map_seen
            ),
            scenario_performance_valid_params AS (
                SELECT COALESCE(
                    ARRAY_AGG(DISTINCT parameter_id::text ORDER BY parameter_id::text),
                    ARRAY[]::text[]
                ) as valid_parameter_ids
                FROM cat_map_seen
            ),
            scenario_performance_status AS (
                SELECT CASE
                    WHEN (SELECT COUNT(*) FROM attempt_daily_categorical) = 0 THEN 'neutral'::text
                    WHEN (SELECT AVG(avg_score) FROM attempt_daily_categorical) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                    WHEN (SELECT AVG(avg_score) FROM attempt_daily_categorical) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                    ELSE 'danger'::text
                END as status
            ),
            scenario_performance_combined AS (
                SELECT (
                    (SELECT valid_parameter_ids FROM scenario_performance_valid_params LIMIT 1),
                    (SELECT attribute_attempt_facts FROM scenario_performance_attribute_attempt_facts_agg LIMIT 1),
                    (SELECT attribute_scenario_facts FROM scenario_performance_attribute_scenario_facts_agg LIMIT 1),
                    (SELECT status FROM scenario_performance_status LIMIT 1)
                )::types.q_get_dashboard_bundle_v4_scenario_performance_response as scenario_performance
            ),
            
            -- Scenario Stats (NUMERICAL PARAMETERS - mostly empty as functionality disabled)
            nums AS (SELECT id FROM parameters WHERE false),
            num_map AS (SELECT NULL::uuid AS scenario_id, NULL::uuid AS parameter_id, NULL::numeric AS level WHERE false),
            num_map_seen AS (
                SELECT nm.*
                FROM num_map nm
                JOIN scenario_seen ss ON ss.scenario_id = nm.scenario_id
            ),
            numeric_attempts AS (
                SELECT
                    nms.parameter_id,
                    nms.level,
                    f.grade_percent::float AS score
                FROM filt f
                JOIN num_map_seen nms ON nms.scenario_id = f.scenario_id
                WHERE f.grade_percent IS NOT NULL
            ),
            numeric_levels AS (
                SELECT
                    parameter_id,
                    CASE 
                        WHEN level = floor(level) THEN level::int::text 
                        ELSE to_char(level, 'FM999D0') 
                    END AS level_label,
                    CASE 
                        WHEN level = floor(level) THEN level::numeric 
                        ELSE round(level::numeric, 1) 
                    END AS level_value,
                    score
                FROM numeric_attempts
            ),
            numeric_agg AS (
                SELECT 
                    parameter_id, 
                    level_label, 
                    level_value,
                    AVG(score)::float AS avg_score,
                    COUNT(*)::int AS attempts
                FROM numeric_levels
                GROUP BY parameter_id, level_label, level_value
            ),
            scenario_stats_numeric_attempt_facts_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (parameter_id::text, level_label, level_value, avg_score, attempts)::types.q_get_dashboard_bundle_v4_numeric_attempt_fact
                        ORDER BY parameter_id, level_value
                    ),
                    '{}'::types.q_get_dashboard_bundle_v4_numeric_attempt_fact[]
                ) as numeric_attempt_facts
                FROM numeric_agg
            ),
            scenario_stats_numeric_scenario_facts_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (nms.parameter_id::text, nms.scenario_id::text, 
                         CASE 
                             WHEN nms.level = floor(nms.level) THEN nms.level::int::text 
                             ELSE to_char(nms.level, 'FM999D0') 
                         END,
                         CASE 
                             WHEN nms.level = floor(nms.level) THEN nms.level::numeric 
                             ELSE round(nms.level::numeric, 1) 
                         END)::types.q_get_dashboard_bundle_v4_numeric_scenario_fact
                        ORDER BY nms.parameter_id, nms.scenario_id, nms.level
                    ),
                    '{}'::types.q_get_dashboard_bundle_v4_numeric_scenario_fact[]
                ) as numeric_scenario_facts
                FROM num_map_seen nms
            ),
            scenario_stats_valid_params AS (
                SELECT COALESCE(
                    ARRAY_AGG(DISTINCT parameter_id::text ORDER BY parameter_id::text),
                    ARRAY[]::text[]
                ) as valid_numeric_parameter_ids
                FROM numeric_levels
            ),
            scenario_stats_status AS (
                SELECT CASE
                    WHEN (SELECT COUNT(*) FROM numeric_agg) = 0 THEN 'neutral'::text
                    WHEN (SELECT AVG(avg_score) FROM numeric_agg) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                    WHEN (SELECT AVG(avg_score) FROM numeric_agg) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                    ELSE 'danger'::text
                END as status
            ),
            scenario_stats_combined AS (
                SELECT (
                    (SELECT valid_numeric_parameter_ids FROM scenario_stats_valid_params LIMIT 1),
                    (SELECT numeric_attempt_facts FROM scenario_stats_numeric_attempt_facts_agg LIMIT 1),
                    (SELECT numeric_scenario_facts FROM scenario_stats_numeric_scenario_facts_agg LIMIT 1),
                    (SELECT status FROM scenario_stats_status LIMIT 1)
                )::types.q_get_dashboard_bundle_v4_scenario_stats_response as scenario_stats
            ),
            
            -- Simulation Performance (existing, keep as-is)
            sim_perf AS (
                SELECT f.simulation_id,
                       f.scenario_id,
                       sc.name AS scenario_name,
                       COALESCE(AVG(f.grade_percent), 0)::float AS avg_score,
                       COALESCE((100.0 * AVG((f.completed OR f.grade_percent IS NOT NULL)::int)), 0)::float AS success_rate,
                       COUNT(*)::int AS total_attempts,
                       SUM((f.completed OR f.grade_percent IS NOT NULL)::int)::int AS completed_attempts
                FROM filt f
                JOIN scenarios sc ON sc.id = f.scenario_id
                WHERE f.simulation_id IS NOT NULL AND f.scenario_id IS NOT NULL
                GROUP BY f.simulation_id, f.scenario_id, sc.name
            ),
            simulation_performance_scenario_facts_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (simulation_id::text, scenario_id::text, scenario_name, avg_score, success_rate, total_attempts, completed_attempts)::types.q_get_dashboard_bundle_v4_scenario_fact
                        ORDER BY simulation_id, scenario_id
                    ),
                    '{}'::types.q_get_dashboard_bundle_v4_scenario_fact[]
                ) as scenario_facts
                FROM sim_perf
            ),
            simulation_performance_valid_sims AS (
                SELECT COALESCE(
                    ARRAY_AGG(DISTINCT simulation_id::text ORDER BY simulation_id::text),
                    ARRAY[]::text[]
                ) as valid_simulation_ids
                FROM sim_perf
            ),
            simulation_performance_status AS (
                SELECT CASE
                    WHEN (SELECT COUNT(*) FROM sim_perf) = 0 THEN 'neutral'::text
                    WHEN (SELECT (0.7 * AVG(avg_score) + 0.3 * AVG(success_rate)) FROM sim_perf) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                    WHEN (SELECT (0.7 * AVG(avg_score) + 0.3 * AVG(success_rate)) FROM sim_perf) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                    ELSE 'danger'::text
                END as status
            ),
            simulation_performance_combined AS (
                SELECT (
                    (SELECT valid_simulation_ids FROM simulation_performance_valid_sims LIMIT 1),
                    (SELECT scenario_facts FROM simulation_performance_scenario_facts_agg LIMIT 1),
                    (SELECT status FROM simulation_performance_status LIMIT 1)
                )::types.q_get_dashboard_bundle_v4_simulation_performance_response as simulation_performance
            ),
            
            -- Simulation Composition (ENHANCED with parameter composition)
            sim_seen AS (
                SELECT DISTINCT f.simulation_id
                FROM filt f
                WHERE f.simulation_id IS NOT NULL
            ),
            scen_seen AS (
                SELECT DISTINCT f.scenario_id
                FROM filt f
                WHERE f.scenario_id IS NOT NULL
            ),
            sim_summary AS (
                SELECT
                    f.simulation_id,
                    AVG(f.grade_percent)::float AS avg_score,
                    (100.0 * AVG((f.passed)::int))::float AS pass_rate,
                    (100.0 * AVG((f.completed OR f.grade_percent IS NOT NULL)::int))::float AS completion_rate,
                    COUNT(*)::int AS attempts
                FROM filt f
                WHERE f.grade_percent IS NOT NULL
                GROUP BY f.simulation_id
            ),
            sim_scenarios_seen AS (
                SELECT 
                    s.id AS simulation_id,
                    COUNT(DISTINCT sc.id)::int AS scenario_count
                FROM simulations s
                JOIN simulation_scenarios ss_link ON ss_link.simulation_id = s.id
                JOIN scenarios sc ON sc.id = ss_link.scenario_id
                JOIN scen_seen ss ON ss.scenario_id = sc.id
                WHERE s.active = TRUE AND sc.active = TRUE
                GROUP BY s.id
            ),
            sim_param_items_seen AS (
                SELECT
                    s.id AS simulation_id,
                    p.id AS parameter_id,
                    f.id AS parameter_item_id,
                    COUNT(a.chat_id)::int AS cnt
                FROM simulations s
                JOIN simulation_scenarios ss_link ON ss_link.simulation_id = s.id
                JOIN scenarios sc ON sc.id = ss_link.scenario_id
                JOIN scen_seen ss ON ss.scenario_id = sc.id
                JOIN scenario_fields sf ON sf.scenario_id = sc.id
                JOIN fields f ON f.id = sf.field_id
                JOIN parameter_fields pf ON pf.field_id = f.id AND pf.active = true
                JOIN parameters p ON p.id = pf.parameter_id
                JOIN analytics a ON a.scenario_id = sc.id
                WHERE s.active = TRUE AND sc.active = TRUE
                GROUP BY s.id, p.id, f.id
            ),
            simulation_facts AS (
                SELECT
                    s.id AS simulation_id,
                    s.title AS simulation_title,
                    COALESCE(ROUND(ss.avg_score), 0)::int AS avg_score,
                    COALESCE(ROUND(ss.pass_rate), 0)::int AS pass_rate,
                    COALESCE(ROUND(ss.completion_rate), 0)::int AS completion_rate,
                    COALESCE(ss.attempts, 0) AS total_attempts,
                    COALESCE(sc_seen.scenario_count, 0) AS scenario_count
                FROM simulations s
                LEFT JOIN sim_summary ss ON ss.simulation_id = s.id
                LEFT JOIN sim_scenarios_seen sc_seen ON sc_seen.simulation_id = s.id
                WHERE s.active = TRUE
                  AND s.id IN (SELECT simulation_id FROM sim_seen)
            ),
            simulation_composition_simulation_facts_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (simulation_id::text, simulation_title, avg_score::float, completion_rate::float, total_attempts, scenario_count)::types.q_get_dashboard_bundle_v4_simulation_fact
                        ORDER BY simulation_id
                    ),
                    '{}'::types.q_get_dashboard_bundle_v4_simulation_fact[]
                ) as simulation_facts
                FROM simulation_facts
            ),
            param_facts_cat AS (
                SELECT
                    simulation_id,
                    parameter_id,
                    parameter_item_id,
                    cnt AS scenario_count
                FROM sim_param_items_seen
            ),
            simulation_composition_param_facts_cat_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (simulation_id::text, parameter_id::text, parameter_item_id::text, scenario_count)::types.q_get_dashboard_bundle_v4_simulation_parameter_fact_categorical
                        ORDER BY simulation_id, parameter_id, parameter_item_id
                    ),
                    '{}'::types.q_get_dashboard_bundle_v4_simulation_parameter_fact_categorical[]
                ) as simulation_parameter_facts_categorical
                FROM param_facts_cat
            ),
            sim_param_nums_seen AS (
                SELECT
                    NULL::uuid AS simulation_id,
                    NULL::uuid AS parameter_id,
                    NULL::numeric AS most_common_level,
                    0::int AS chat_count
                WHERE false
            ),
            sim_param_nums_most_common AS (
                SELECT
                    simulation_id,
                    parameter_id,
                    most_common_level AS avg_level,
                    CASE
                        WHEN most_common_level = floor(most_common_level) 
                        THEN (most_common_level::int)::text
                        ELSE to_char(most_common_level, 'FM999D0')
                    END AS level_label,
                    chat_count AS scenario_count
                FROM sim_param_nums_seen
            ),
            simulation_composition_param_facts_num_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (simulation_id::text, parameter_id::text, avg_level, level_label, scenario_count)::types.q_get_dashboard_bundle_v4_simulation_parameter_fact_numeric
                        ORDER BY simulation_id, parameter_id
                    ),
                    '{}'::types.q_get_dashboard_bundle_v4_simulation_parameter_fact_numeric[]
                ) as simulation_parameter_facts_numeric
                FROM sim_param_nums_most_common
            ),
            simulation_composition_valid_sims AS (
                SELECT COALESCE(
                    ARRAY_AGG(DISTINCT simulation_id::text ORDER BY simulation_id::text),
                    ARRAY[]::text[]
                ) as valid_simulation_ids
                FROM filt
                WHERE simulation_id IS NOT NULL
            ),
            simulation_composition_has_data AS (
                SELECT COUNT(*) > 0 as has_data
                FROM simulation_facts
            ),
            simulation_composition_status AS (
                SELECT CASE
                    WHEN (SELECT COUNT(*) FROM simulation_facts) = 0 THEN 'neutral'::text
                    ELSE 'success'::text
                END as status
            ),
            simulation_composition_combined AS (
                SELECT (
                    (SELECT valid_simulation_ids FROM simulation_composition_valid_sims LIMIT 1),
                    (SELECT simulation_facts FROM simulation_composition_simulation_facts_agg LIMIT 1),
                    (SELECT simulation_parameter_facts_categorical FROM simulation_composition_param_facts_cat_agg LIMIT 1),
                    (SELECT simulation_parameter_facts_numeric FROM simulation_composition_param_facts_num_agg LIMIT 1),
                    (SELECT has_data FROM simulation_composition_has_data LIMIT 1),
                    (SELECT status FROM simulation_composition_status LIMIT 1)
                )::types.q_get_dashboard_bundle_v4_simulation_composition_response as simulation_composition
            ),
            footer_metrics_combined AS (
                SELECT (
                    (SELECT scenario_performance FROM scenario_performance_combined LIMIT 1),
                    (SELECT scenario_stats FROM scenario_stats_combined LIMIT 1),
                    (SELECT simulation_performance FROM simulation_performance_combined LIMIT 1),
                    (SELECT simulation_composition FROM simulation_composition_combined LIMIT 1)
                )::types.q_get_dashboard_bundle_v4_footer_metrics as footer_metrics
            ),
            -- History - placeholder for now (needs conversion from attempt history CTEs)
            history_combined AS (
                SELECT ARRAY[]::types.q_get_dashboard_bundle_v4_attempt_history_row[] as history
            ),
            -- Insights - placeholder for now (needs conversion)
            insights_combined AS (
                SELECT (
                    NULL::text,
                    ARRAY[]::types.q_get_dashboard_bundle_v4_persona_insight[],
                    NULL::text,
                    NULL::text,
                    ARRAY[]::types.q_get_dashboard_bundle_v4_cohort_insight[],
                    NULL::text,
                    NULL::text,
                    NULL::text,
                    NULL::text,
                    NULL::text
                )::types.q_get_dashboard_bundle_v4_insights as insights
            ),
            -- Thresholds
            thresholds_combined AS (
                SELECT COALESCE(
                    (SELECT (success_threshold, warning_threshold, danger_threshold)::types.q_get_dashboard_bundle_v4_thresholds FROM settings_thresholds LIMIT 1),
                    (85, 80, 70)::types.q_get_dashboard_bundle_v4_thresholds
                ) as thresholds
            )
SELECT
    (SELECT actor_name FROM user_profile)::text as actor_name,
    (SELECT header_metrics FROM header_metrics_combined LIMIT 1) as header_metrics,
    (SELECT primary_metrics FROM primary_metrics_combined LIMIT 1) as primary_metrics,
    (SELECT secondary_metrics FROM secondary_metrics_combined LIMIT 1) as secondary_metrics,
    (SELECT footer_metrics FROM footer_metrics_combined LIMIT 1) as footer_metrics,
    (SELECT history FROM history_combined LIMIT 1) as history,
    (SELECT insights FROM insights_combined LIMIT 1) as insights,
    (SELECT thresholds FROM thresholds_combined LIMIT 1) as thresholds,
    (SELECT simulations_array FROM simulations_converted LIMIT 1) as simulations,
    (SELECT rubrics_array FROM rubrics_converted LIMIT 1) as rubrics,
    (SELECT parameters_array FROM parameters_converted LIMIT 1) as parameters,
    (SELECT fields_array FROM fields_converted LIMIT 1) as fields
$$;


--
-- Name: api_get_dashboard_history_v4(text, text, uuid[], uuid[], public.profile_role[], text[], text, uuid[], uuid[], uuid[], boolean, text, text, integer, integer, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_dashboard_history_v4(start_date text, end_date text, cohort_ids uuid[] DEFAULT ARRAY[]::uuid[], department_ids uuid[] DEFAULT ARRAY[]::uuid[], roles public.profile_role[] DEFAULT ARRAY[]::public.profile_role[], simulation_filters text[] DEFAULT ARRAY[]::text[], search text DEFAULT NULL::text, profile_ids uuid[] DEFAULT ARRAY[]::uuid[], simulation_ids uuid[] DEFAULT ARRAY[]::uuid[], scenario_ids uuid[] DEFAULT ARRAY[]::uuid[], infinite_mode boolean DEFAULT NULL::boolean, sort_by text DEFAULT 'date'::text, sort_order text DEFAULT 'desc'::text, page_size integer DEFAULT 20, "offset" integer DEFAULT 0, profile_id uuid DEFAULT NULL::uuid) RETURNS TABLE(data types.q_get_dashboard_history_v4_attempt_history_row[], total_count bigint, archived_count bigint, unarchived_count bigint, profile_options types.q_get_dashboard_history_v4_profile_option[], simulation_options types.q_get_dashboard_history_v4_simulation_option[], scenario_options types.q_get_dashboard_history_v4_scenario_option[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        start_date::timestamptz AS start_date,
        end_date::timestamptz AS end_date,
        COALESCE(cohort_ids, ARRAY[]::uuid[]) AS cohort_ids,
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids,
        COALESCE(roles, ARRAY[]::profile_role[]) AS roles,
        COALESCE(simulation_filters, ARRAY[]::text[])::text[] AS simulation_filters,
        COALESCE(NULLIF(search, ''), NULL) AS search,
        COALESCE(profile_ids, ARRAY[]::uuid[]) AS profile_ids,
        COALESCE(simulation_ids, ARRAY[]::uuid[]) AS simulation_ids,
        COALESCE(scenario_ids, ARRAY[]::uuid[]) AS scenario_ids,
        infinite_mode AS infinite_mode,
        COALESCE(sort_by, 'date') AS sort_by,
        COALESCE(sort_order, 'desc') AS sort_order,
        COALESCE(page_size, 20) AS page_size,
        COALESCE("offset", 0) AS offset_val,
        COALESCE(profile_id, NULL::uuid) AS profile_id
),
-- Expanded cohort list: union of provided cohortIds (dashboard never filters by profile)
expanded_history_cohort_ids AS (
    SELECT DISTINCT cohort_id
    FROM (
        SELECT unnest((SELECT cohort_ids FROM params)) as cohort_id
        WHERE cardinality((SELECT cohort_ids FROM params)) > 0
    ) combined
),
-- Filter attempts by date, cohorts, departments, and roles
history_attempts AS (
    SELECT DISTINCT
        sa.id AS attempt_id,
        sa.simulation_id,
        sa.created_at AS attempt_date,
        sa.archived AS is_archived,
        sa.infinite_mode,
        ap.profile_id,
        sim.title AS simulation_name,
        sim.practice_simulation,
        COALESCE(sdd.department_ids, NULL) as department_ids
    FROM simulation_attempts sa
    JOIN attempt_profiles ap ON ap.attempt_id = sa.id AND ap.active = TRUE
    JOIN simulations sim ON sim.id = sa.simulation_id
    JOIN profiles p_attempt ON p_attempt.id = ap.profile_id
    LEFT JOIN (
        SELECT 
            sd.simulation_id,
            ARRAY_AGG(sd.department_id::text ORDER BY sd.created_at) as department_ids
        FROM simulation_departments sd
        WHERE sd.active = true
        GROUP BY sd.simulation_id
    ) sdd ON sdd.simulation_id = sim.id
    WHERE sa.created_at >= (SELECT start_date FROM params)
      AND sa.created_at <= (SELECT end_date FROM params)
      -- Dashboard never filters by profile - always filter by roles
      AND p_attempt.role = ANY((SELECT roles FROM params)::profile_role[])
      -- Simulation type filtering: general (practice_simulation = FALSE), practice (practice_simulation = TRUE), archived (archived = TRUE)
      -- If no filters provided (NULL or empty), default to general only (matching old behavior: sim.practice_simulation = FALSE)
      AND (
        (cardinality((SELECT simulation_filters FROM params)::text[]) = 0) AND sim.practice_simulation = FALSE
        OR
        (cardinality((SELECT simulation_filters FROM params)::text[]) > 0 AND (
          ('general' = ANY((SELECT simulation_filters FROM params)::text[]) AND sim.practice_simulation = FALSE) OR
          ('practice' = ANY((SELECT simulation_filters FROM params)::text[]) AND sim.practice_simulation = TRUE) OR
          ('archived' = ANY((SELECT simulation_filters FROM params)::text[]) AND sa.archived = TRUE)
        ))
      )
      -- Exclude archived attempts unless 'archived' is explicitly in the filter list
      AND (
        cardinality((SELECT simulation_filters FROM params)::text[]) = 0 OR 'archived' = ANY((SELECT simulation_filters FROM params)::text[]) OR sa.archived = FALSE
      )
      AND (cardinality((SELECT department_ids FROM params)) = 0 OR sdd.department_ids IS NULL OR sdd.department_ids && (SELECT department_ids FROM params)::text[])
),
-- Get cohorts for each attempt's profile (includes inactive links for history)
history_attempt_cohorts AS (
    SELECT
        ha.attempt_id,
        COALESCE(ARRAY_AGG(DISTINCT c.id) FILTER (WHERE c.id IS NOT NULL AND cs.simulation_id = ha.simulation_id), ARRAY[]::uuid[]) AS cohort_ids,
        COALESCE(ARRAY_AGG(DISTINCT c.title) FILTER (WHERE c.id IS NOT NULL AND cs.simulation_id = ha.simulation_id), ARRAY[]::text[]) AS cohort_names
    FROM history_attempts ha
    LEFT JOIN cohort_profiles cp ON cp.profile_id = ha.profile_id
    LEFT JOIN cohorts c ON c.id = cp.cohort_id AND c.active = TRUE
    LEFT JOIN cohort_simulations cs ON cs.cohort_id = c.id
    WHERE (
        -- If no cohort filter, include all attempts
        (SELECT COUNT(*) FROM expanded_history_cohort_ids) = 0
        -- Otherwise, only include cohorts in the expanded list
        OR c.id IN (SELECT cohort_id FROM expanded_history_cohort_ids)
    )
    GROUP BY ha.attempt_id
),
-- Filter attempts by cohort membership (uses expanded cohort list)
history_attempts_filtered AS (
    SELECT ha.*
    FROM history_attempts ha
    JOIN history_attempt_cohorts hac ON hac.attempt_id = ha.attempt_id
    WHERE (
        -- If no cohort filter, include all attempts
        (SELECT COUNT(*) FROM expanded_history_cohort_ids) = 0
        -- Otherwise, only include attempts with matching cohorts
        OR cardinality(hac.cohort_ids) > 0
    )
),
-- Get all unique profile options from filtered attempts (before history-specific filters)
profile_options_cte AS (
    SELECT 
        haf.profile_id,
        p.first_name || ' ' || p.last_name AS profile_name,
        COUNT(DISTINCT haf.attempt_id) AS count
    FROM history_attempts_filtered haf
    JOIN profiles p ON p.id = haf.profile_id
    GROUP BY haf.profile_id, p.first_name, p.last_name
    ORDER BY profile_name
),
-- Get all unique simulation options from filtered attempts (before history-specific filters)
simulation_options_cte AS (
    SELECT 
        haf.simulation_id,
        s.title AS simulation_name,
        COUNT(DISTINCT haf.attempt_id) AS count
    FROM history_attempts_filtered haf
    JOIN simulations s ON s.id = haf.simulation_id
    GROUP BY haf.simulation_id, s.title
    ORDER BY simulation_name
),
-- Get all unique scenario options from filtered attempts (before history-specific filters)
scenario_options_cte AS (
    SELECT 
        sc.scenario_id,
        s.name AS scenario_title,
        COUNT(DISTINCT haf.attempt_id) AS count
    FROM history_attempts_filtered haf
    JOIN attempt_chats ac ON ac.attempt_id = haf.attempt_id
    JOIN chats sc ON sc.id = ac.chat_id
    JOIN scenarios s ON s.id = sc.scenario_id
    WHERE sc.scenario_id IS NOT NULL
    GROUP BY sc.scenario_id, s.name
    ORDER BY scenario_title
),
-- Apply additional filters (profileIds, simulationIds, scenarioIds, infiniteMode)
history_attempts_with_filters AS (
    SELECT haf.*
    FROM history_attempts_filtered haf
    WHERE 
        -- Profile filter
        (cardinality((SELECT profile_ids FROM params)::uuid[]) = 0 OR haf.profile_id = ANY((SELECT profile_ids FROM params)::uuid[]))
        -- Simulation filter
        AND (cardinality((SELECT simulation_ids FROM params)::uuid[]) = 0 OR haf.simulation_id = ANY((SELECT simulation_ids FROM params)::uuid[]))
        -- Infinite mode filter
        AND ((SELECT infinite_mode FROM params) IS NULL OR haf.infinite_mode = (SELECT infinite_mode FROM params))
),
-- Get scenario IDs for each attempt (for scenario filtering)
attempt_scenario_ids AS (
    SELECT DISTINCT
        ac.attempt_id,
        ARRAY_AGG(DISTINCT sc.scenario_id) FILTER (WHERE sc.scenario_id IS NOT NULL) AS scenario_ids
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_with_filters)
    GROUP BY ac.attempt_id
),
-- Apply scenario filter
history_attempts_final AS (
    SELECT haf.*
    FROM history_attempts_with_filters haf
    LEFT JOIN attempt_scenario_ids asi ON asi.attempt_id = haf.attempt_id
    WHERE 
        -- Scenario filter (if any scenario matches, include the attempt)
        (cardinality((SELECT scenario_ids FROM params)) = 0 OR asi.scenario_ids IS NULL OR asi.scenario_ids && (SELECT scenario_ids FROM params))
),
-- Aggregate chats per attempt
history_chat_rollup AS (
    SELECT
        ac.attempt_id,
        COUNT(*) FILTER (WHERE sc.completed) AS completed_chats,
        COUNT(*) FILTER (WHERE sc.completed = FALSE) AS incomplete_chats,
        MIN(sc.created_at) AS first_chat_at,
        MAX(sc.created_at) AS last_activity_at,
        array_agg(DISTINCT sc.scenario_id) FILTER (WHERE sc.scenario_id IS NOT NULL) AS scenario_ids_seen
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
    GROUP BY ac.attempt_id
),
-- Get latest grade per chat
history_chat_grades AS (
    SELECT DISTINCT ON (c.id)
        c.id AS chat_id,
        scg.score,
        rga.rubric_id
    FROM grades scg
    LEFT JOIN rubric_grade_agents rga ON rga.id = scg.rubric_grade_agent_id
    JOIN runs r ON r.id = scg.run_id
    JOIN group_runs gr ON gr.run_id = r.id
    JOIN grade_groups gg ON gg.group_id = gr.group_id
    JOIN chats c ON c.id = gg.chat_id
    WHERE EXISTS (
        SELECT 1 FROM runs r_check
        JOIN group_runs gr_check ON gr_check.run_id = r_check.id
        JOIN grade_groups gg_check ON gg_check.group_id = gr_check.group_id
        JOIN chats c_check ON c_check.id = gg_check.chat_id
        WHERE r_check.id = scg.run_id
    )
      AND c.id IN (
        SELECT sc.id FROM attempt_chats ac
        JOIN chats sc ON sc.id = ac.chat_id
        WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
      )
    ORDER BY c.id, scg.created_at DESC
),
-- Get first scenario's rubric per simulation (fallback when chat scenario doesn't match)
sim_first_scenario_rubric AS (
    SELECT DISTINCT ON (ss.simulation_id)
        ss.simulation_id,
        rga.rubric_id,
        r.points
    FROM simulation_scenarios ss
    LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
    LEFT JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
    LEFT JOIN rubrics r ON r.id = rga.rubric_id
    WHERE ss.active = true
      AND ss.simulation_id IN (SELECT DISTINCT simulation_id FROM history_attempts_final)
    ORDER BY ss.simulation_id, ss.position
),
-- Aggregate grades per attempt
history_grade_rollup AS (
    SELECT
        ac.attempt_id,
        COUNT(*) FILTER (WHERE hcg.score IS NOT NULL) AS completed_with_grade,
        SUM(CASE WHEN hcg.score IS NOT NULL AND COALESCE(r.points, r_fallback_scenario.points, r_fallback_first.points, 0) > 0
            THEN (hcg.score / COALESCE(r.points, r_fallback_scenario.points, r_fallback_first.points, 1)::numeric * 100.0)
            ELSE 0 END) AS sum_grade_percent
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    JOIN simulation_attempts sa ON sa.id = ac.attempt_id
    LEFT JOIN history_chat_grades hcg ON hcg.chat_id = sc.id
    LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga_fallback_scenario ON ssrga_fallback_scenario.simulation_id = sa.simulation_id
      AND ssrga_fallback_scenario.scenario_id = sc.scenario_id
      AND hcg.chat_id IS NOT NULL
      AND hcg.rubric_id IS NULL
    LEFT JOIN rubric_grade_agents rga_fallback_scenario ON rga_fallback_scenario.id = ssrga_fallback_scenario.rubric_grade_agent_id
    LEFT JOIN rubrics r ON r.id = hcg.rubric_id
    LEFT JOIN rubrics r_fallback_scenario ON r_fallback_scenario.id = rga_fallback_scenario.rubric_id
    LEFT JOIN sim_first_scenario_rubric sfsr ON sfsr.simulation_id = sa.simulation_id
      AND hcg.chat_id IS NOT NULL
      AND hcg.rubric_id IS NULL
      AND r_fallback_scenario.points IS NULL
    LEFT JOIN rubrics r_fallback_first ON r_fallback_first.id = sfsr.rubric_id
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
    GROUP BY ac.attempt_id
),
-- Calculate elapsed time per attempt (for infinite mode time limit checks)
history_elapsed_time AS (
    SELECT
        ac.attempt_id,
        COALESCE(
            SUM(
                CASE 
                    WHEN sc.completed AND hcg.chat_id IS NOT NULL THEN
                        (SELECT scg.time_taken FROM grades scg 
                         JOIN runs r ON r.id = scg.run_id
                         JOIN group_runs gr ON gr.run_id = r.id
                         JOIN grade_groups gg ON gg.group_id = gr.group_id
                         JOIN chats c ON c.id = gg.chat_id
                         WHERE c.id = sc.id 
                           AND EXISTS (
                               SELECT 1 FROM runs r_check
                               JOIN group_runs gr_check ON gr_check.run_id = r_check.id
                               JOIN grade_groups gg_check ON gg_check.group_id = gr_check.group_id
                               JOIN chats c_check ON c_check.id = gg_check.chat_id
                               WHERE r_check.id = scg.run_id
                           )
                         ORDER BY scg.created_at DESC LIMIT 1)
                    WHEN sc.completed THEN
                        EXTRACT(EPOCH FROM (
                            (SELECT scg.created_at FROM grades scg 
                             JOIN runs r ON r.id = scg.run_id
                             JOIN group_runs gr ON gr.run_id = r.id
                             JOIN grade_groups gg ON gg.group_id = gr.group_id
                             JOIN chats c ON c.id = gg.chat_id
                             WHERE c.id = sc.id 
                               AND EXISTS (
                                   SELECT 1 FROM runs r_check
                                   JOIN group_runs gr_check ON gr_check.run_id = r_check.id
                                   JOIN grade_groups gg_check ON gg_check.group_id = gr_check.group_id
                                   JOIN chats c_check ON c_check.id = gg_check.chat_id
                                   WHERE r_check.id = scg.run_id
                               )
                             ORDER BY scg.created_at DESC LIMIT 1) - sc.created_at
                        ))::integer
                    ELSE
                        EXTRACT(EPOCH FROM (NOW() - sc.created_at))::integer
                END
            ),
            0
        ) AS elapsed_seconds
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    LEFT JOIN history_chat_grades hcg ON hcg.chat_id = sc.id
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
    GROUP BY ac.attempt_id
),
-- Get personas for each attempt
history_personas AS (
    SELECT
        ac.attempt_id,
        array_agg(DISTINCT sp.persona_id) FILTER (WHERE sp.persona_id IS NOT NULL) AS persona_ids
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    JOIN scenarios scn ON scn.id = sc.scenario_id
    LEFT JOIN scenario_personas sp ON sp.scenario_id = scn.id AND sp.active = TRUE
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
    GROUP BY ac.attempt_id
),
-- Count scenarios per simulation
history_sim_scenario_count AS (
    SELECT
        s.id AS simulation_id,
        COUNT(ss.scenario_id)::int AS scenario_count
    FROM simulations s
    LEFT JOIN simulation_scenarios ss ON ss.simulation_id = s.id
    WHERE s.id IN (SELECT simulation_id FROM history_attempts_final)
    GROUP BY s.id
),
-- Get scenario info
history_scenario_ids AS (
    SELECT
        s.id AS simulation_id,
        ARRAY_AGG(ss.scenario_id ORDER BY ss.position)::uuid[] AS scenario_ids_assigned
    FROM simulations s
    LEFT JOIN simulation_scenarios ss ON ss.simulation_id = s.id
    WHERE s.id IN (SELECT simulation_id FROM history_attempts_final)
    GROUP BY s.id
),
-- Get first scenario_id from each attempt's first chat (for practice scenario retry)
history_first_scenario AS (
    SELECT DISTINCT ON (ac.attempt_id)
        ac.attempt_id,
        sc.scenario_id AS practice_scenario_id
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
    ORDER BY ac.attempt_id, sc.created_at ASC
),
-- Join all history data
attempt_rollup AS (
    SELECT
        haf.attempt_id,
        haf.simulation_id,
        haf.attempt_date,
        haf.is_archived,
        haf.infinite_mode,
        haf.profile_id,
        haf.simulation_name,
        haf.practice_simulation,
        haf.department_ids,
        COALESCE(hcr.first_chat_at, haf.attempt_date) AS first_chat_at,
        COALESCE(hcr.last_activity_at, haf.attempt_date) AS last_activity_at,
        COALESCE(hgr.completed_with_grade, 0) AS completed_with_grade,
        COALESCE(hssc.scenario_count, 0) AS sim_scenario_count,
        COALESCE(hgr.sum_grade_percent, 0) AS sum_grade_percent_zero_fill,
        COALESCE(hp.persona_ids, ARRAY[]::uuid[]) AS persona_ids_distinct,
        COALESCE(hcr.scenario_ids_seen, ARRAY[]::uuid[]) AS leaf_scenarios_seen,
        COALESCE(hcr.incomplete_chats, 0) AS incomplete_chats,
        COALESCE(het.elapsed_seconds, 0) AS elapsed_seconds,
        hfs.practice_scenario_id
    FROM history_attempts_final haf
    LEFT JOIN history_chat_rollup hcr ON hcr.attempt_id = haf.attempt_id
    LEFT JOIN history_grade_rollup hgr ON hgr.attempt_id = haf.attempt_id
    LEFT JOIN history_personas hp ON hp.attempt_id = haf.attempt_id
    LEFT JOIN history_sim_scenario_count hssc ON hssc.simulation_id = haf.simulation_id
    LEFT JOIN history_elapsed_time het ON het.attempt_id = haf.attempt_id
    LEFT JOIN history_first_scenario hfs ON hfs.attempt_id = haf.attempt_id
),
attempt_cohort_ids AS (
    SELECT
        attempt_id,
        cohort_ids AS profile_cohort_ids
    FROM history_attempt_cohorts
    WHERE attempt_id IN (SELECT attempt_id FROM history_attempts_final)
),
-- Get rubric data per simulation (one row per simulation)
simulation_rubrics AS (
    SELECT DISTINCT ON (ss.simulation_id)
        ss.simulation_id,
        r.id AS rubric_id,
        r.points AS rubric_points,
        r.pass_points AS rubric_pass_points
    FROM simulation_scenarios ss
    LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
    LEFT JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
    LEFT JOIN rubrics r ON r.id = rga.rubric_id
    WHERE ss.active = true
      AND ss.simulation_id IN (SELECT DISTINCT simulation_id FROM attempt_rollup)
    ORDER BY ss.simulation_id, ss.position
),
attempt_joined AS (
    SELECT
        ar.*,
        hsi.scenario_ids_assigned,
        sr.rubric_id,
        sr.rubric_points,
        sr.rubric_pass_points,
        CASE
            WHEN sr.rubric_points IS NULL OR sr.rubric_points = 0 THEN NULL
            ELSE ROUND((sr.rubric_pass_points::numeric / sr.rubric_points::numeric) * 100.0)::int
        END AS pass_pct,
        (p.first_name || ' ' || p.last_name) AS profile_name,
        COALESCE(
            (SELECT SUM(stl.time_limit_seconds)
             FROM scenario_time_limits stl
             JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
             WHERE stl.simulation_id = s.id AND stl.active = true AND ss.active = true),
            0
        ) as time_limit_seconds
    FROM attempt_rollup ar
    JOIN simulations s ON s.id = ar.simulation_id
    LEFT JOIN history_scenario_ids hsi ON hsi.simulation_id = ar.simulation_id
    LEFT JOIN simulation_rubrics sr ON sr.simulation_id = s.id
    JOIN profiles p ON p.id = ar.profile_id
),
attempt_cohort_names AS (
    SELECT
        attempt_id,
        cohort_names
    FROM history_attempt_cohorts
    WHERE attempt_id IN (SELECT attempt_id FROM history_attempts_final)
),
final_rows AS (
    SELECT
        aj.attempt_id,
        aj.simulation_id,
        aj.profile_id,
        aj.profile_name,
        aj.simulation_name,
        aj.scenario_ids_assigned,
        aj.is_archived,
        aj.practice_simulation,
        aj.pass_pct,
        aj.infinite_mode,
        aj.attempt_date,
        aj.department_ids,
        aj.practice_scenario_id,
        CASE WHEN aj.infinite_mode THEN NULL ELSE COALESCE(aj.sim_scenario_count, 0) END AS num_scenarios,
        COALESCE(aj.completed_with_grade, 0) AS num_scenarios_completed,
        CASE
            WHEN aj.infinite_mode THEN
                CASE GREATEST(array_length(aj.leaf_scenarios_seen, 1), 0)
                    WHEN 0 THEN NULL
                    ELSE ROUND(aj.sum_grade_percent_zero_fill / GREATEST(array_length(aj.leaf_scenarios_seen, 1), 1))::int
                END
            ELSE
                CASE COALESCE(aj.sim_scenario_count, 0)
                    WHEN 0 THEN NULL
                    ELSE CASE
                            WHEN aj.completed_with_grade = 0 THEN NULL
                            ELSE ROUND(aj.sum_grade_percent_zero_fill / NULLIF(aj.sim_scenario_count, 0))::int
                        END
                END
        END AS score_percent,
        CASE
            WHEN aj.infinite_mode THEN
                CASE GREATEST(array_length(aj.leaf_scenarios_seen, 1), 0)
                    WHEN 0 THEN NULL
                    ELSE CASE
                        WHEN ROUND(aj.sum_grade_percent_zero_fill / GREATEST(array_length(aj.leaf_scenarios_seen, 1), 1))::int >= 80 THEN 'high'
                        WHEN ROUND(aj.sum_grade_percent_zero_fill / GREATEST(array_length(aj.leaf_scenarios_seen, 1), 1))::int >= 70 THEN 'medium'
                        ELSE 'low'
                    END
                END
            ELSE
                CASE COALESCE(aj.sim_scenario_count, 0)
                    WHEN 0 THEN NULL
                    ELSE CASE
                        WHEN aj.completed_with_grade = 0 THEN NULL
                        ELSE CASE
                            WHEN ROUND(aj.sum_grade_percent_zero_fill / NULLIF(aj.sim_scenario_count, 0))::int >= 80 THEN 'high'
                            WHEN ROUND(aj.sum_grade_percent_zero_fill / NULLIF(aj.sim_scenario_count, 0))::int >= 70 THEN 'medium'
                            ELSE 'low'
                        END
                    END
                END
        END AS score_status,
        (NOT aj.is_archived) AS show_view,
        (NOT aj.is_archived) AND (
            (aj.infinite_mode
                AND (
                    -- No time limit OR time limit not exceeded
                    (aj.time_limit_seconds IS NULL OR aj.elapsed_seconds < aj.time_limit_seconds)
                    -- AND there are incomplete chats (pending work)
                    AND aj.incomplete_chats > 0
                ))
            OR
            (NOT aj.infinite_mode
                AND aj.sim_scenario_count IS NOT NULL
                AND COALESCE(aj.completed_with_grade, 0) < aj.sim_scenario_count)
        ) AS show_continue,
        aj.persona_ids_distinct
    FROM attempt_joined aj
),
-- Apply search filter (searches profile name, simulation name, persona names)
final_rows_with_search AS (
    SELECT fr.*
    FROM final_rows fr
    WHERE 
        -- Search filter: if search term provided, search in profile name, simulation name, or persona names
        ((SELECT search FROM params) IS NULL OR (SELECT search FROM params) = '' OR
         LOWER(fr.profile_name) LIKE '%' || LOWER((SELECT search FROM params)) || '%' OR
         LOWER(fr.simulation_name) LIKE '%' || LOWER((SELECT search FROM params)) || '%' OR
         EXISTS (
             SELECT 1
             FROM unnest(fr.persona_ids_distinct) AS pid
             JOIN personas per ON per.id = pid
             WHERE LOWER(per.name) LIKE '%' || LOWER((SELECT search FROM params)) || '%'
         ))
),
persona_labels AS (
    SELECT
        fr.attempt_id,
        COALESCE(ARRAY_AGG(per.name ORDER BY per.name) FILTER (WHERE per.name IS NOT NULL), ARRAY[]::text[]) AS persona_names,
        COALESCE(ARRAY_AGG(per.color ORDER BY per.name) FILTER (WHERE per.color IS NOT NULL), ARRAY[]::text[]) AS persona_colors
    FROM final_rows_with_search fr
    LEFT JOIN LATERAL (
        SELECT DISTINCT per.name, per.color
        FROM unnest(fr.persona_ids_distinct) AS pid
        JOIN personas per ON per.id = pid
    ) per ON TRUE
    GROUP BY fr.attempt_id
),
scenario_names AS (
    SELECT
        fr.attempt_id,
        COALESCE(sn.names, ARRAY[]::text[]) AS names
    FROM final_rows_with_search fr
    LEFT JOIN LATERAL (
        SELECT ARRAY_AGG(s.name ORDER BY s.name) AS names
        FROM unnest(fr.scenario_ids_assigned) sid
        JOIN scenarios s ON s.id = sid
    ) sn ON TRUE
),
-- Get total count before pagination
total_count_cte AS (
    SELECT COUNT(*)::bigint AS total_count
    FROM final_rows_with_search
),
-- Get archived and unarchived counts for filtered set
archive_counts_cte AS (
    SELECT 
        COUNT(*) FILTER (WHERE is_archived = true)::bigint AS archived_count,
        COUNT(*) FILTER (WHERE is_archived = false)::bigint AS unarchived_count
    FROM final_rows_with_search
),
-- Paginated and sorted results
paginated_rows AS (
    SELECT
        fr.attempt_id,
        fr.attempt_date,
        fr.profile_id,
        fr.profile_name,
        fr.simulation_name,
        fr.num_scenarios,
        fr.num_scenarios_completed,
        fr.infinite_mode,
        fr.score_percent,
        fr.score_status,
        fr.simulation_id,
        fr.scenario_ids_assigned,
        fr.is_archived,
        fr.show_view,
        fr.show_continue,
        fr.practice_simulation,
        fr.pass_pct,
        fr.department_ids,
        fr.practice_scenario_id,
        fr.persona_ids_distinct
    FROM final_rows_with_search fr
    ORDER BY 
        CASE 
            WHEN (SELECT sort_by FROM params) = 'date' AND (SELECT sort_order FROM params) = 'desc' THEN fr.attempt_date
        END DESC NULLS LAST,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'date' AND (SELECT sort_order FROM params) = 'asc' THEN fr.attempt_date
        END ASC NULLS LAST,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'simulationName' AND (SELECT sort_order FROM params) = 'desc' THEN fr.simulation_name
        END DESC NULLS LAST,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'simulationName' AND (SELECT sort_order FROM params) = 'asc' THEN fr.simulation_name
        END ASC NULLS LAST,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'score' AND (SELECT sort_order FROM params) = 'desc' THEN COALESCE(fr.score_percent, -1)
        END DESC,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'score' AND (SELECT sort_order FROM params) = 'asc' THEN COALESCE(fr.score_percent, 999999)
        END ASC,
        fr.attempt_id DESC
    LIMIT (SELECT page_size FROM params)
    OFFSET (SELECT offset_val FROM params)
),
-- Convert paginated rows to composite types
data_agg AS (
    SELECT COALESCE(
        ARRAY_AGG(
            (
                pr.attempt_id,
                pr.attempt_date,
                pr.profile_id,
                pr.profile_name,
                pr.simulation_name,
                pr.num_scenarios,
                pr.num_scenarios_completed,
                pr.infinite_mode,
                COALESCE(
                    (SELECT SUM(stl.time_limit_seconds)
                     FROM scenario_time_limits stl
                     JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
                     WHERE stl.simulation_id = pr.simulation_id AND stl.active = true AND ss.active = true),
                    0
                ),
                COALESCE(pl.persona_names, ARRAY[]::text[]),
                COALESCE(pl.persona_colors, ARRAY[]::text[]),
                pr.score_percent,
                pr.score_status,
                pr.simulation_id,
                COALESCE(pr.scenario_ids_assigned, ARRAY[]::uuid[])::text[],
                COALESCE(sn.names, ARRAY[]::text[]),
                pr.is_archived,
                pr.show_view,
                pr.show_continue,
                COALESCE(pr.practice_simulation, false),
                pr.pass_pct,
                pr.department_ids,
                COALESCE(acn.cohort_names, ARRAY[]::text[]),
                pr.practice_scenario_id
            )::types.q_get_dashboard_history_v4_attempt_history_row
            ORDER BY 
                CASE 
                    WHEN (SELECT sort_by FROM params) = 'date' AND (SELECT sort_order FROM params) = 'desc' THEN pr.attempt_date
                END DESC NULLS LAST,
                CASE 
                    WHEN (SELECT sort_by FROM params) = 'date' AND (SELECT sort_order FROM params) = 'asc' THEN pr.attempt_date
                END ASC NULLS LAST,
                CASE 
                    WHEN (SELECT sort_by FROM params) = 'simulationName' AND (SELECT sort_order FROM params) = 'desc' THEN pr.simulation_name
                END DESC NULLS LAST,
                CASE 
                    WHEN (SELECT sort_by FROM params) = 'simulationName' AND (SELECT sort_order FROM params) = 'asc' THEN pr.simulation_name
                END ASC NULLS LAST,
                CASE 
                    WHEN (SELECT sort_by FROM params) = 'score' AND (SELECT sort_order FROM params) = 'desc' THEN COALESCE(pr.score_percent, -1)
                END DESC,
                CASE 
                    WHEN (SELECT sort_by FROM params) = 'score' AND (SELECT sort_order FROM params) = 'asc' THEN COALESCE(pr.score_percent, 999999)
                END ASC,
                pr.attempt_id DESC
        ),
        '{}'::types.q_get_dashboard_history_v4_attempt_history_row[]
    ) AS data
    FROM paginated_rows pr
    LEFT JOIN persona_labels pl ON pl.attempt_id = pr.attempt_id
    LEFT JOIN scenario_names sn ON sn.attempt_id = pr.attempt_id
    LEFT JOIN attempt_cohort_names acn ON acn.attempt_id = pr.attempt_id
),
-- Convert options to composite types
profile_options_agg AS (
    SELECT COALESCE(
        ARRAY_AGG(
            (profile_id::text, profile_name, count)::types.q_get_dashboard_history_v4_profile_option
            ORDER BY profile_name
        ),
        '{}'::types.q_get_dashboard_history_v4_profile_option[]
    ) AS profile_options
    FROM profile_options_cte
),
simulation_options_agg AS (
    SELECT COALESCE(
        ARRAY_AGG(
            (simulation_id::text, simulation_name, count)::types.q_get_dashboard_history_v4_simulation_option
            ORDER BY simulation_name
        ),
        '{}'::types.q_get_dashboard_history_v4_simulation_option[]
    ) AS simulation_options
    FROM simulation_options_cte
),
scenario_options_agg AS (
    SELECT COALESCE(
        ARRAY_AGG(
            (scenario_id::text, scenario_title, count)::types.q_get_dashboard_history_v4_scenario_option
            ORDER BY scenario_title
        ),
        '{}'::types.q_get_dashboard_history_v4_scenario_option[]
    ) AS scenario_options
    FROM scenario_options_cte
)
SELECT
    (SELECT data FROM data_agg LIMIT 1) AS data,
    (SELECT total_count FROM total_count_cte LIMIT 1) AS total_count,
    (SELECT archived_count FROM archive_counts_cte LIMIT 1) AS archived_count,
    (SELECT unarchived_count FROM archive_counts_cte LIMIT 1) AS unarchived_count,
    (SELECT profile_options FROM profile_options_agg LIMIT 1) AS profile_options,
    (SELECT simulation_options FROM simulation_options_agg LIMIT 1) AS simulation_options,
    (SELECT scenario_options FROM scenario_options_agg LIMIT 1) AS scenario_options
$$;


--
-- Name: api_get_default_department_v4(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_default_department_v4() RETURNS TABLE(department_id text)
    LANGUAGE sql STABLE
    AS $$
SELECT sdd.department_id::text
FROM settings s
JOIN settings_default_department sdd ON sdd.settings_id = s.id
WHERE s.active = true
  AND sdd.active = true
LIMIT 1
$$;


--
-- Name: api_get_department_detail_v4(uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_department_detail_v4(department_id uuid, profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(department_exists boolean, department_id uuid, title text, description text, active boolean, can_edit boolean, can_duplicate boolean, can_delete boolean, in_use boolean, staff_count integer, total_price_spent double precision, settings_id uuid, valid_department_ids uuid[], valid_model_ids uuid[], valid_key_ids uuid[], actor_name text, settings types.q_get_department_detail_v4_setting[], cohorts types.q_get_department_detail_v4_cohort[], departments types.q_get_department_detail_v4_department[], models types.q_get_department_detail_v4_model[], keys types.q_get_department_detail_v4_key[], model_keys types.q_get_department_detail_v4_model_key[], draft_version integer)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT department_id AS department_id,
           profile_id AS profile_id,
           draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'departments'::draft_resource_type
    LIMIT 1
),
department_exists_check AS (
    -- Check if department exists independently of access control
    SELECT EXISTS(
        SELECT 1 FROM departments WHERE id = (SELECT department_id FROM params)
    )::boolean as department_exists
),
-- First, find runs for this department (filter first, then calculate costs)
runs_for_department_via_agents AS (
    SELECT DISTINCT mr.id as run_id
    FROM runs mr
    JOIN agent_departments ad ON ad.agent_id = mr.agent_id AND ad.active = true
    WHERE ad.department_id = (SELECT department_id FROM params) AND mr.agent_id IS NOT NULL
),
runs_for_department_via_personas AS (
    SELECT DISTINCT mr.id as run_id
    FROM runs mr
    JOIN run_personas mrp ON mrp.run_id = mr.id AND mrp.active = true
    JOIN persona_departments pd ON pd.persona_id = mrp.persona_id AND pd.active = true
    WHERE pd.department_id = (SELECT department_id FROM params)
),
runs_for_department_via_profiles AS (
    SELECT DISTINCT mr.id as run_id
    FROM runs mr
    JOIN run_profiles mrp ON mrp.run_id = mr.id AND mrp.active = true
    JOIN profile_departments pd ON pd.profile_id = mrp.profile_id AND pd.active = true
    WHERE pd.department_id = (SELECT department_id FROM params)
),
runs_for_department AS (
    SELECT run_id FROM runs_for_department_via_agents
    UNION
    SELECT run_id FROM runs_for_department_via_personas
    UNION
    SELECT run_id FROM runs_for_department_via_profiles
),
-- Calculate costs only for runs in this department (much faster)
model_run_costs AS (
    SELECT 
        rpu.run_id,
        COALESCE(SUM(
            (rpu.count::numeric / u.value::numeric) * mp.price
        ), 0) as cost
    FROM run_pricing_usage rpu
    JOIN runs_for_department rfd ON rfd.run_id = rpu.run_id
    JOIN run_models rm ON rm.run_id = rpu.run_id AND rm.active = true
    JOIN model_pricing mp ON mp.model_id = rm.model_id 
        AND mp.pricing_type = rpu.pricing_type 
        AND mp.unit_id = rpu.unit_id
        AND mp.active = true
    JOIN units u ON u.id = rpu.unit_id
    GROUP BY rpu.run_id
),
department_price_spent AS (
    SELECT 
        (SELECT department_id FROM params) as department_id,
        COALESCE(SUM(mrc.cost), 0) as total_price_spent
    FROM model_run_costs mrc
),
department_staff_count AS (
    SELECT 
        department_id, 
        COUNT(DISTINCT profile_id) as staff_count
    FROM profile_departments
    WHERE department_id = (SELECT department_id FROM params) AND active = true
    GROUP BY department_id
),
department_usage AS (
    SELECT
        (SELECT COUNT(*) FROM profile_departments WHERE department_id = (SELECT department_id FROM params) AND active = true) +
        (SELECT COUNT(*) FROM simulation_departments WHERE department_id = (SELECT department_id FROM params) AND active = true) +
        (SELECT COUNT(*) FROM scenario_departments WHERE department_id = (SELECT department_id FROM params) AND active = true) +
        (SELECT COUNT(*) FROM persona_departments WHERE department_id = (SELECT department_id FROM params) AND active = true) +
        (SELECT COUNT(*) FROM document_departments WHERE department_id = (SELECT department_id FROM params) AND active = true) +
        (SELECT COUNT(*) FROM cohort_departments WHERE department_id = (SELECT department_id FROM params) AND active = true) as total_usage
),
user_profile AS (
    SELECT 
        role,
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
user_department_access AS (
    -- Check if user has access to this department
    SELECT EXISTS(
        SELECT 1 FROM profile_departments pd
        WHERE pd.profile_id = (SELECT profile_id FROM params) AND pd.department_id = (SELECT department_id FROM params) AND pd.active = true
    ) OR EXISTS(
        SELECT 1 FROM profiles p WHERE p.id = (SELECT profile_id FROM params) AND p.role = 'superadmin'
    ) as has_access
),
-- Only get cohorts/departments for the current user's profile (much faster)
user_profile_cohorts AS (
    SELECT 
        ARRAY_AGG(cp.cohort_id ORDER BY c.title) as cohort_ids
    FROM cohort_profiles cp
    JOIN cohorts c ON c.id = cp.cohort_id
    WHERE cp.profile_id = (SELECT profile_id FROM params) AND cp.active = true
),
user_profile_departments AS (
    SELECT 
        ARRAY_AGG(pd.department_id ORDER BY d.title) as department_ids
    FROM profile_departments pd
    JOIN departments d ON d.id = pd.department_id
    WHERE pd.profile_id = (SELECT profile_id FROM params) AND pd.active = true
),
all_cohort_ids AS (
    SELECT DISTINCT unnest(cohort_ids) as cohort_id
    FROM user_profile_cohorts
    WHERE cohort_ids IS NOT NULL AND array_length(cohort_ids, 1) > 0
),
all_department_ids AS (
    SELECT DISTINCT unnest(department_ids) as department_id
    FROM user_profile_departments
    WHERE department_ids IS NOT NULL AND array_length(department_ids, 1) > 0
),
department_current_settings AS (
    -- Get current settings_id for this department (department-specific first, then default)
    SELECT COALESCE(
        -- Department-specific settings for this department
        (SELECT ds.settings_id
         FROM department_settings ds
         WHERE ds.department_id = (SELECT department_id FROM params) AND ds.active = true
         LIMIT 1),
        -- Fallback to default settings (no department links)
        (SELECT s.id
         FROM settings s
         WHERE s.active = true
         AND NOT EXISTS (
             SELECT 1 FROM department_settings ds2 
             WHERE ds2.settings_id = s.id 
             AND ds2.active = true
         )
         ORDER BY s.created_at DESC
         LIMIT 1)
    ) as settings_id
),
settings_departments_data AS (
    -- Get department_ids for each setting
    SELECT 
        ds.settings_id,
        CASE 
            WHEN COUNT(ds.department_id) > 0 THEN ARRAY_AGG(ds.department_id ORDER BY ds.created_at) FILTER (WHERE ds.department_id IS NOT NULL)
            ELSE ARRAY[]::uuid[]
        END as department_ids
    FROM department_settings ds
    WHERE ds.active = true
    GROUP BY ds.settings_id
),
settings_data AS (
    -- Only return department-specific settings for this department + default settings
    SELECT DISTINCT
        s.id as settings_id,
        s.created_at,
        s.active,
        COALESCE(sdd.department_ids, ARRAY[]::uuid[]) as department_ids
    FROM settings s
    LEFT JOIN settings_departments_data sdd ON sdd.settings_id = s.id
    WHERE s.active = true
    AND (
        -- Include department-specific settings for this department
        EXISTS (
            SELECT 1 FROM department_settings ds 
            WHERE ds.settings_id = s.id 
            AND ds.department_id = (SELECT department_id FROM params) 
            AND ds.active = true
        )
        OR
        -- Include default settings (no department links)
        NOT EXISTS (
            SELECT 1 FROM department_settings ds2 
            WHERE ds2.settings_id = s.id 
            AND ds2.active = true
        )
    )
),
cohorts_data AS (
    SELECT DISTINCT
        c.id as cohort_id,
        c.title as name,
        COALESCE(c.description, '') as description
    FROM cohorts c
    WHERE c.id IN (SELECT cohort_id FROM all_cohort_ids)
),
departments_data AS (
    SELECT DISTINCT
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM departments d
    WHERE (d.id = (SELECT department_id FROM params) OR EXISTS (SELECT 1 FROM all_department_ids WHERE department_id = d.id))
    AND d.active = true
),
keys_data AS (
    -- Get all API keys available to this department via settings
    SELECT DISTINCT 
        k.id as key_id, 
        k.name, 
        CASE 
            WHEN LENGTH(k.key) > 4 THEN LEFT(k.key, 4) || '****'
            ELSE '****'
        END as key_masked,
        CASE 
            WHEN LENGTH(k.key) > 4 THEN LEFT(k.key, 4) || '****'
            ELSE '****'
        END as description,
        k.active
    FROM keys k
    JOIN setting_provider_keys spk ON spk.key_id = k.id AND spk.active = true
    JOIN settings s ON s.id = spk.settings_id AND s.active = true
    JOIN department_settings ds ON ds.settings_id = s.id AND ds.active = true
    WHERE k.active = true
    AND ds.department_id = (SELECT department_id FROM params)
    AND ds.active = true
    UNION
    -- Also include all active keys (general access)
    SELECT DISTINCT 
        k.id as key_id, 
        k.name, 
        CASE 
            WHEN LENGTH(k.key) > 4 THEN LEFT(k.key, 4) || '****'
            ELSE '****'
        END as key_masked,
        CASE 
            WHEN LENGTH(k.key) > 4 THEN LEFT(k.key, 4) || '****'
            ELSE '****'
        END as description,
        k.active
    FROM keys k
    WHERE k.active = true
),
-- Get model-key associations using JOIN instead of correlated subquery (much faster)
department_settings_for_model_keys AS (
    SELECT DISTINCT ds.settings_id
    FROM department_settings ds
    WHERE ds.department_id = (SELECT department_id FROM params) AND ds.active = true
),
department_models AS (
    -- Get all models available to this department (default + department-specific)
    SELECT DISTINCT
        m.id as model_id,
        m.name,
        COALESCE(m.description, '') as description,
        m.active,
        m.provider_id
    FROM models m
    LEFT JOIN model_departments md ON md.model_id = m.id AND md.active = true
    WHERE m.active = true
    AND (
        md.department_id = (SELECT department_id FROM params)
        OR NOT EXISTS (SELECT 1 FROM model_departments md2 WHERE md2.model_id = m.id AND md2.active = true)
    )
),
model_key_associations AS (
    SELECT DISTINCT
        dm.model_id,
        spk.key_id
    FROM department_models dm
    LEFT JOIN department_settings_for_model_keys dsfmk ON true
    LEFT JOIN setting_provider_keys spk ON spk.provider_id = dm.provider_id 
        AND spk.settings_id = dsfmk.settings_id 
        AND spk.active = true
    WHERE spk.key_id IS NOT NULL
)
SELECT 
    -- Department existence check (always returned)
    dec.department_exists::boolean as department_exists,
    -- Top-level department fields
    d.id as department_id,
    -- Merge draft payload over existing department data if draft_id provided
    COALESCE(
        (SELECT payload->>'title' FROM draft_payload_data),
        d.title::text
    ) as title,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        d.description::text
    ) as description,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        d.active::boolean
    ) as active,
    CASE 
        WHEN up.role = 'superadmin' THEN true
        WHEN up.role = 'admin' AND uda.has_access THEN true
        ELSE false
    END::boolean as can_edit,
    CASE WHEN up.role = 'superadmin' THEN true ELSE false END::boolean as can_duplicate,
    CASE 
        WHEN up.role = 'superadmin' AND du.total_usage = 0 THEN true
        ELSE false
    END::boolean as can_delete,
    CASE WHEN du.total_usage > 0 THEN true ELSE false END::boolean as in_use,
    COALESCE(dsc.staff_count, 0)::int as staff_count,
    COALESCE(dps.total_price_spent, 0)::float as total_price_spent,
    dcs.settings_id as settings_id,
    COALESCE((SELECT array_agg(department_id ORDER BY name) FROM departments_data), ARRAY[]::uuid[])::uuid[] as valid_department_ids,
    COALESCE((SELECT array_agg(model_id ORDER BY name) FROM department_models), ARRAY[]::uuid[])::uuid[] as valid_model_ids,
    COALESCE((SELECT array_agg(key_id ORDER BY name) FROM keys_data), ARRAY[]::uuid[])::uuid[] as valid_key_ids,
    up.actor_name::text as actor_name,
    -- Aggregated arrays
    COALESCE(
        ARRAY_AGG(
            (sd.settings_id, sd.created_at, sd.active, sd.department_ids)::types.q_get_department_detail_v4_setting
            ORDER BY sd.created_at DESC
        ) FILTER (WHERE uda.has_access = true AND sd.settings_id IS NOT NULL),
        '{}'::types.q_get_department_detail_v4_setting[]
    ) as settings,
    COALESCE(
        ARRAY_AGG(
            (cd.cohort_id, cd.name, cd.description)::types.q_get_department_detail_v4_cohort
            ORDER BY cd.name
        ) FILTER (WHERE uda.has_access = true AND cd.cohort_id IS NOT NULL),
        '{}'::types.q_get_department_detail_v4_cohort[]
    ) as cohorts,
    COALESCE(
        ARRAY_AGG(
            (dd.department_id, dd.name, dd.description)::types.q_get_department_detail_v4_department
            ORDER BY dd.name
        ) FILTER (WHERE uda.has_access = true AND dd.department_id IS NOT NULL),
        '{}'::types.q_get_department_detail_v4_department[]
    ) as departments,
    COALESCE(
        ARRAY_AGG(
            (dm.model_id, dm.name, dm.description)::types.q_get_department_detail_v4_model
            ORDER BY dm.name
        ) FILTER (WHERE uda.has_access = true AND dm.model_id IS NOT NULL),
        '{}'::types.q_get_department_detail_v4_model[]
    ) as models,
    COALESCE(
        ARRAY_AGG(
            (kd.key_id, kd.name, kd.description, kd.key_masked, kd.active)::types.q_get_department_detail_v4_key
            ORDER BY kd.name
        ) FILTER (WHERE uda.has_access = true AND kd.key_id IS NOT NULL),
        '{}'::types.q_get_department_detail_v4_key[]
    ) as keys,
    COALESCE(
        ARRAY_AGG(
            (mka.model_id, mka.key_id)::types.q_get_department_detail_v4_model_key
            ORDER BY mka.model_id, mka.key_id
        ) FILTER (WHERE uda.has_access = true AND mka.model_id IS NOT NULL AND mka.key_id IS NOT NULL),
        '{}'::types.q_get_department_detail_v4_model_key[]
    ) as model_keys,
    COALESCE(
        (SELECT draft_version FROM draft_payload_data),
        0::int
    ) as draft_version
FROM department_exists_check dec
CROSS JOIN user_profile up
CROSS JOIN user_department_access uda
CROSS JOIN department_usage du
LEFT JOIN departments d ON d.id = (SELECT department_id FROM params) AND uda.has_access = true
LEFT JOIN department_price_spent dps ON dps.department_id = d.id AND uda.has_access = true
LEFT JOIN department_staff_count dsc ON dsc.department_id = d.id AND uda.has_access = true
LEFT JOIN department_current_settings dcs ON uda.has_access = true
LEFT JOIN settings_data sd ON uda.has_access = true
LEFT JOIN cohorts_data cd ON uda.has_access = true
LEFT JOIN departments_data dd ON uda.has_access = true
LEFT JOIN department_models dm ON uda.has_access = true
LEFT JOIN keys_data kd ON uda.has_access = true
LEFT JOIN model_key_associations mka ON uda.has_access = true
GROUP BY dec.department_exists, d.id, d.title, d.description, d.active, up.role, uda.has_access, 
         du.total_usage, dsc.staff_count, dps.total_price_spent, dcs.settings_id, up.actor_name
LIMIT 1
$$;


--
-- Name: api_get_department_new_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_department_new_v4(profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(profile_role text, actor_name text, settings types.q_get_department_new_v4_setting[], title text, description text, active boolean, draft_version integer)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id,
           draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'departments'::draft_resource_type
    LIMIT 1
),
user_profile AS (
    SELECT 
        role,
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
settings_departments_data AS (
    -- Get department_ids for each setting
    SELECT 
        ds.settings_id,
        ARRAY_AGG(ds.department_id ORDER BY ds.created_at) as department_ids
    FROM department_settings ds
    WHERE ds.active = true
    GROUP BY ds.settings_id
),
settings_data AS (
    SELECT DISTINCT
        s.id as settings_id,
        s.created_at,
        s.active,
        COALESCE(sdd.department_ids, ARRAY[]::uuid[]) as department_ids
    FROM settings s
    LEFT JOIN settings_departments_data sdd ON sdd.settings_id = s.id
    WHERE s.active = true
)
SELECT 
    up.role::text as profile_role,
    up.actor_name::text as actor_name,
    COALESCE(
        ARRAY_AGG(
            (sd.settings_id, sd.created_at, sd.active, sd.department_ids)::types.q_get_department_new_v4_setting
            ORDER BY sd.created_at DESC
        ),
        '{}'::types.q_get_department_new_v4_setting[]
    ) as settings,
    -- Default values for new department (merged with draft payload if draft_id provided)
    COALESCE(
        (SELECT payload->>'title' FROM draft_payload_data),
        ''::text
    ) as title,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        ''::text
    ) as description,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        true::boolean
    ) as active,
    COALESCE(
        (SELECT draft_version FROM draft_payload_data),
        0::int
    ) as draft_version
FROM user_profile up
CROSS JOIN settings_data sd
GROUP BY up.role, up.actor_name
$$;


--
-- Name: api_get_department_title_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_department_title_v4(department_id uuid) RETURNS TABLE(title text)
    LANGUAGE sql STABLE
    AS $$
SELECT title FROM departments WHERE id = department_id
$$;


--
-- Name: api_get_departments_for_profile_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_departments_for_profile_v4(profile_id uuid) RETURNS TABLE(id uuid)
    LANGUAGE sql STABLE
    AS $$
SELECT DISTINCT d.id
FROM departments d
JOIN profile_departments pd ON pd.department_id = d.id
WHERE pd.profile_id = profile_id AND d.active = true
$$;


--
-- Name: api_get_developer_instruction_v4(public.developer_instruction_type, public.agent_role); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_developer_instruction_v4(instruction_type public.developer_instruction_type, agent_role_val public.agent_role) RETURNS TABLE(developer_instruction_id uuid, type public.developer_instruction_type, template text, active boolean, schema_id uuid)
    LANGUAGE sql STABLE
    AS $$
SELECT
    di.id as developer_instruction_id,
    di.type,
    di.template,
    di.active,
    dis.schema_id
FROM developer_instructions di
JOIN agent_role_developer_instruction_types ardit ON ardit.developer_instruction_type = di.type
LEFT JOIN developer_instruction_schemas dis ON dis.developer_instruction_id = di.id
WHERE di.type = instruction_type
  AND ardit.agent_role = agent_role_val
  AND di.active = true
LIMIT 1
$$;


--
-- Name: api_get_document_detail_v4(uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_document_detail_v4(document_id uuid, profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(document_exists boolean, document_id uuid, name text, description text, active boolean, type text, upload_id uuid, updated_at timestamp with time zone, extension text, scenario_ids uuid[], can_edit boolean, can_delete boolean, document_type_options text[], department_ids text[], valid_department_ids text[], departments types.q_get_document_detail_v4_department[], field_ids uuid[], valid_field_ids text[], fields types.q_get_document_detail_v4_field[], linked_parameter_ids text[], parameters types.q_get_document_detail_v4_parameter[], classify_agent_id uuid, document_agent_id uuid, agents types.q_get_document_detail_v4_agent[], valid_agent_ids text[], template boolean, template_id uuid, schema_id uuid, html_id uuid, template_file_path text, template_html text, templates types.q_get_document_detail_v4_template[], actor_name text, draft_version integer)
    LANGUAGE sql STABLE
    AS $_$
WITH params AS (
    SELECT document_id AS document_id,
           profile_id AS profile_id,
           draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'documents'::draft_resource_type
    LIMIT 1
),
document_exists_check AS (
    -- Check if document exists independently of access control
    SELECT EXISTS(
        SELECT 1 FROM documents WHERE id = (SELECT document_id FROM params)
    )::boolean as document_exists
),
document_data AS (
    SELECT 
        d.id as document_id,
        d.name,
        d.description,
        d.active,
        d.updated_at,
        d.classify_agent_id,
        d.document_agent_id,
        (SELECT ARRAY_AGG(dd.department_id::text) FROM document_departments dd WHERE dd.document_id = d.id AND dd.active = true) as department_ids,
        (SELECT ARRAY_AGG(df.field_id) FROM document_fields df WHERE df.document_id = d.id AND df.active = true) as field_ids,
        (SELECT du.upload_id FROM document_uploads du WHERE du.document_id = d.id AND du.active = true ORDER BY du.created_at DESC LIMIT 1) as upload_id,
        (SELECT dt.html_id FROM document_templates dt WHERE dt.document_id = d.id AND dt.active = true ORDER BY dt.created_at DESC LIMIT 1) as html_id,
        (SELECT dt.schema_id FROM document_templates dt WHERE dt.document_id = d.id AND dt.active = true ORDER BY dt.created_at DESC LIMIT 1) as schema_id,
        (SELECT u.file_path FROM document_uploads du 
         JOIN uploads u ON u.id = du.upload_id 
         WHERE du.document_id = d.id AND du.active = true ORDER BY du.created_at DESC LIMIT 1) as file_path,
        (SELECT u.file_path FROM document_templates dt
         JOIN html h ON h.id = dt.html_id
         JOIN html_uploads hu ON hu.html_id = h.id
         JOIN uploads u ON u.id = hu.upload_id 
         WHERE dt.document_id = d.id AND dt.active = true ORDER BY dt.created_at DESC LIMIT 1) as template_file_path,
        d.template,
        (SELECT ARRAY_AGG(DISTINCT st.parent_id) FROM scenario_documents sd
         JOIN scenario_tree st ON st.child_id = sd.scenario_id AND st.parent_id = st.child_id
         WHERE sd.document_id = d.id AND sd.active = true) as scenario_ids,
        (SELECT COUNT(*) FROM scenario_documents sd WHERE sd.document_id = d.id AND sd.active = true) as active_scenario_count,
        (SELECT COUNT(*) FROM scenario_documents sd WHERE sd.document_id = d.id) as total_scenario_links
    FROM params x
    JOIN documents d ON d.id = x.document_id
),
document_active_template AS (
    SELECT 
        dt.document_id,
        dt.template_id,
        dt.schema_id,
        dt.created_at as template_created_at,
        dt.updated_at as template_updated_at
    FROM params x
    JOIN document_templates dt ON dt.document_id = x.document_id AND dt.active = true
    ORDER BY dt.created_at DESC
    LIMIT 1
),
document_all_templates AS (
    SELECT 
        dt.document_id,
        dt.template_id,
        dt.schema_id,
        dt.active as template_active,
        dt.created_at as template_created_at,
        dt.updated_at as template_updated_at
    FROM params x
    JOIN document_templates dt ON dt.document_id = x.document_id
),
user_profile AS (
    SELECT 
        role,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
user_departments AS (
    SELECT DISTINCT d.id, d.title as name, d.description
    FROM params x
    JOIN departments d ON d.active = true
    JOIN profile_departments pd ON d.id = pd.department_id AND pd.profile_id = x.profile_id AND pd.active = true
),
department_parameter_ids AS (
    SELECT 
        ud.id as department_id,
        COALESCE(ARRAY_AGG(DISTINCT p.id::text) FILTER (WHERE p.id IS NOT NULL), ARRAY[]::text[]) as parameter_ids
    FROM user_departments ud
    LEFT JOIN parameters p ON p.active = true
    LEFT JOIN parameter_fields pf ON pf.parameter_id = p.id AND pf.active = true
    LEFT JOIN field_departments fd ON fd.field_id = pf.field_id AND fd.active = true
    WHERE (fd.department_id = ud.id OR NOT EXISTS (SELECT 1 FROM field_departments fd2 
                                                     JOIN parameter_fields pf2 ON pf2.field_id = fd2.field_id 
                                                     WHERE pf2.parameter_id = p.id AND pf2.active = true AND fd2.active = true))
    GROUP BY ud.id
),
department_data AS (
    SELECT 
        ud.id as department_id,
        ud.name,
        COALESCE(ud.description, '') as description,
        COALESCE(dparami.parameter_ids, ARRAY[]::text[]) as parameter_ids
    FROM user_departments ud
    LEFT JOIN department_parameter_ids dparami ON dparami.department_id = ud.id
),
linked_parameters AS (
    -- Note: parameter_documents junction table removed - parameters no longer directly linked to documents
    -- Return empty result since we can't determine which parameters are linked
    SELECT 
        NULL::uuid as parameter_id,
        NULL::text as parameter_name,
        NULL::text as parameter_description,
        false as persona_parameter,
        false as scenario_parameter,
        false as video_parameter
    WHERE false
),
parameter_data AS (
    SELECT 
        lp.parameter_id,
        lp.parameter_name as name,
        lp.parameter_description as description,
        true as document_parameter,
        lp.persona_parameter,
        lp.scenario_parameter,
        lp.video_parameter
    FROM linked_parameters lp
),
field_data AS (
    SELECT 
        f.id as field_id,
        f.name,
        COALESCE(f.description, '') as description,
        pf.parameter_id,
        p.name as parameter_name
    FROM linked_parameters lp
    JOIN parameter_fields pf ON pf.parameter_id = lp.parameter_id AND pf.active = true
    JOIN fields f ON f.id = pf.field_id AND f.active = true
    JOIN parameters p ON p.id = pf.parameter_id
    CROSS JOIN document_data dd
    LEFT JOIN field_departments fd ON fd.field_id = f.id AND fd.active = true
    WHERE p.active = true
      AND (
          -- Department-based filtering: include if matches department OR has no department restrictions
          (
              (dd.department_ids IS NULL OR array_length(dd.department_ids, 1) = 0)
              AND NOT EXISTS (SELECT 1 FROM field_departments fd2 WHERE fd2.field_id = f.id AND fd2.active = true)
          )
          OR (
              dd.department_ids IS NOT NULL 
              AND array_length(dd.department_ids, 1) > 0
              AND fd.department_id = ANY(SELECT unnest(dd.department_ids)::uuid)
          )
          -- Include fields already assigned to this document even if they don't pass department filter
          OR f.id::text = ANY(COALESCE((SELECT ARRAY_AGG(field_id::text) FROM document_fields df WHERE df.document_id = dd.document_id AND df.active = true), ARRAY[]::text[]))
      )
),
user_departments_for_agents AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.active = true
),
agent_data AS (
    -- Get agents with roles 'classify' or 'document'
    -- Filter by department access: include if has matching department link OR has no department links at all (cross-dept)
    -- Also include agents assigned to this document (classify_agent_id or document_agent_id) even if they don't pass department filter
    SELECT 
        a.id as agent_id,
        a.name,
        COALESCE(a.description, '') as description,
        ARRAY[a.role::text] as roles
    FROM params x
    JOIN agents a ON a.active = true AND a.role IN ('classify'::agent_role, 'document'::agent_role)
    LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
    CROSS JOIN document_data dd
    WHERE (
        -- Department access: has matching department link OR has no department links at all (cross-dept)
        EXISTS (
            SELECT 1 FROM agent_departments ad2 
            WHERE ad2.agent_id = a.id 
            AND ad2.active = true 
            AND ad2.department_id IN (SELECT department_id FROM user_departments_for_agents)
        )
        OR NOT EXISTS (
            SELECT 1 FROM agent_departments ad3 
            WHERE ad3.agent_id = a.id 
            AND ad3.active = true
        )
        -- Include agents assigned to this document even if they don't pass department filter
        OR a.id = dd.classify_agent_id
        OR a.id = dd.document_agent_id
    )
),
valid_field_ids_data AS (
    SELECT 
        dd.document_id,
        COALESCE(
            ARRAY_AGG(DISTINCT f.id::text ORDER BY f.id::text) FILTER (WHERE f.id IS NOT NULL),
            ARRAY[]::text[]
        ) as valid_field_ids
    FROM document_data dd
    LEFT JOIN parameter_fields pf ON pf.parameter_id IN (SELECT id FROM parameters WHERE active = true) AND pf.active = true
    LEFT JOIN fields f ON f.id = pf.field_id AND f.active = true
    LEFT JOIN field_departments fd ON fd.field_id = f.id AND fd.active = true
    WHERE (
        -- If document has no departments, include only cross-department fields
        (dd.department_ids IS NULL OR array_length(dd.department_ids, 1) = 0)
        AND NOT EXISTS (
            SELECT 1 FROM field_departments fd2 
            WHERE fd2.field_id = f.id 
            AND fd2.active = true
        )
    ) OR (
        -- If document has departments, include fields from those departments OR cross-department fields
        dd.department_ids IS NOT NULL 
        AND array_length(dd.department_ids, 1) > 0
        AND (
            fd.department_id = ANY(SELECT unnest(dd.department_ids)::uuid)
            OR NOT EXISTS (
                SELECT 1 FROM field_departments fd2 
                WHERE fd2.field_id = f.id 
                AND fd2.active = true
            )
        )
    )
    GROUP BY dd.document_id
)
SELECT 
    -- Existence check (always returned)
    dec.document_exists::boolean as document_exists,
    -- Document fields
    dd.document_id::uuid as document_id,
    -- Merge draft payload over existing document data if draft_id provided
    COALESCE(
        (SELECT payload->>'name' FROM draft_payload_data),
        dd.name
    )::text as name,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        COALESCE(dd.description, '')
    )::text as description,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        dd.active
    )::boolean as active,
    CASE 
        WHEN dd.file_path IS NOT NULL THEN SUBSTRING(dd.file_path FROM '\\.([^\\.]+)$')
        ELSE ''
    END::text as type,
    dd.upload_id::uuid as upload_id,
    dd.updated_at::timestamptz as updated_at,
    CASE 
        WHEN dd.file_path IS NOT NULL THEN SUBSTRING(dd.file_path FROM '\\.([^\\.]+)$')
        ELSE NULL
    END::text as extension,
    COALESCE(dd.scenario_ids, ARRAY[]::uuid[])::uuid[] as scenario_ids,
    CASE 
        WHEN dd.active_scenario_count > 0 THEN false
        WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) THEN true
        ELSE false
    END::boolean as can_edit,
    CASE 
        WHEN dd.total_scenario_links > 0 THEN false
        WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) THEN true
        ELSE false
    END::boolean as can_delete,
    ARRAY['homework', 'exam', 'lab', 'project']::text[] as document_type_options,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'department_ids' IS NOT NULL AND jsonb_typeof(payload->'department_ids') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'department_ids'))
                ELSE NULL
            END
        FROM draft_payload_data),
        COALESCE(dd.department_ids, ARRAY[]::text[])
    )::text[] as department_ids,
    COALESCE((SELECT ARRAY_AGG(dd2.department_id::text ORDER BY dd2.department_id::text) FROM department_data dd2), ARRAY[]::text[])::text[] as valid_department_ids,
    -- Aggregate departments separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (dd2.department_id, dd2.name, dd2.description, dd2.parameter_ids)::types.q_get_document_detail_v4_department
            ORDER BY dd2.name
        ) FROM department_data dd2),
        '{}'::types.q_get_document_detail_v4_department[]
    ) as departments,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'parameter_item_ids' IS NOT NULL AND jsonb_typeof(payload->'parameter_item_ids') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'parameter_item_ids'))::uuid[]
                ELSE NULL
            END
        FROM draft_payload_data),
        COALESCE(dd.field_ids, ARRAY[]::uuid[])
    )::uuid[] as field_ids,
    COALESCE(vfid.valid_field_ids, ARRAY[]::text[])::text[] as valid_field_ids,
    -- Aggregate fields separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (fd.field_id, fd.name, fd.description, fd.parameter_id, fd.parameter_name)::types.q_get_document_detail_v4_field
            ORDER BY fd.name
        ) FROM field_data fd),
        '{}'::types.q_get_document_detail_v4_field[]
    ) as fields,
    COALESCE((SELECT ARRAY_AGG(pd.parameter_id::text ORDER BY pd.name) FROM parameter_data pd), ARRAY[]::text[])::text[] as linked_parameter_ids,
    -- Aggregate parameters separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (pd.parameter_id, pd.name, pd.description, pd.document_parameter, pd.persona_parameter, pd.scenario_parameter, pd.video_parameter)::types.q_get_document_detail_v4_parameter
            ORDER BY pd.name
        ) FROM parameter_data pd),
        '{}'::types.q_get_document_detail_v4_parameter[]
    ) as parameters,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->>'classify_agent_id' IS NOT NULL AND payload->>'classify_agent_id' != 'null' THEN
                    (payload->>'classify_agent_id')::uuid
                ELSE NULL
            END
        FROM draft_payload_data),
        dd.classify_agent_id
    )::uuid as classify_agent_id,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->>'document_agent_id' IS NOT NULL AND payload->>'document_agent_id' != 'null' THEN
                    (payload->>'document_agent_id')::uuid
                ELSE NULL
            END
        FROM draft_payload_data),
        dd.document_agent_id
    )::uuid as document_agent_id,
    -- Aggregate agents separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (ad.agent_id, ad.name, ad.description, ad.roles)::types.q_get_document_detail_v4_agent
            ORDER BY ad.name
        ) FROM agent_data ad),
        '{}'::types.q_get_document_detail_v4_agent[]
    ) as agents,
    COALESCE((SELECT ARRAY_AGG(ad2.agent_id::text ORDER BY ad2.name) FROM agent_data ad2), ARRAY[]::text[])::text[] as valid_agent_ids,
    dd.template::boolean as template,
    dat.template_id::uuid as template_id,
    dat.schema_id::uuid as schema_id,
    dd.html_id::uuid as html_id,
    dd.template_file_path::text as template_file_path,
    NULL::text as template_html,  -- Will be populated in Python from file system
    -- Aggregate templates separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (dat2.template_id, dat2.schema_id, dat2.template_active, dat2.template_created_at, dat2.template_updated_at)::types.q_get_document_detail_v4_template
            ORDER BY dat2.template_created_at DESC
        ) FROM document_all_templates dat2),
        '{}'::types.q_get_document_detail_v4_template[]
    ) as templates,
    up.actor_name::text as actor_name,
    COALESCE((SELECT draft_version FROM draft_payload_data), 0)::int as draft_version
FROM document_exists_check dec
CROSS JOIN user_profile up
LEFT JOIN document_data dd ON dec.document_exists = true
LEFT JOIN document_active_template dat ON dat.document_id = dd.document_id AND dec.document_exists = true
LEFT JOIN valid_field_ids_data vfid ON vfid.document_id = dd.document_id AND dec.document_exists = true
LIMIT 1
$_$;


--
-- Name: api_get_document_template_info_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_document_template_info_v4(parent_document_id uuid) RETURNS TABLE(file_path text, schema_id uuid, classify_agent_id text, document_agent_id text, name text, description text)
    LANGUAGE sql STABLE
    AS $$
SELECT 
    u.file_path,
    dt.schema_id,
    d.classify_agent_id::text,
    d.document_agent_id::text,
    d.name,
    d.description
FROM documents d
INNER JOIN document_templates dt ON dt.document_id = d.id AND dt.active = true
INNER JOIN html h ON h.id = dt.html_id
INNER JOIN html_uploads hu ON hu.html_id = h.id AND hu.active = true
INNER JOIN uploads u ON u.id = hu.upload_id
WHERE d.id = parent_document_id
ORDER BY dt.created_at DESC
LIMIT 1
$$;


--
-- Name: api_get_document_templates_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_document_templates_v4(document_id uuid) RETURNS TABLE(html_id uuid, template_id uuid, schema_id uuid, active boolean, created_at timestamp with time zone, updated_at timestamp with time zone)
    LANGUAGE sql STABLE
    AS $$
SELECT
    dt.html_id,
    dt.template_id,
    dt.schema_id,
    dt.active,
    dt.created_at,
    dt.updated_at
FROM document_templates dt
WHERE dt.document_id = document_id
ORDER BY dt.created_at DESC
$$;


--
-- Name: api_get_eval_attempt_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_eval_attempt_v4(attempt_id uuid, profile_id uuid) RETURNS TABLE(attempt_exists boolean, actor_name text, attempt types.q_get_eval_attempt_v4_attempt, eval types.q_get_eval_attempt_v4_eval, runs types.q_get_eval_attempt_v4_run[], status_summary types.q_get_eval_attempt_v4_status_summary)
    LANGUAGE sql STABLE
    AS $_$
WITH params AS (
    SELECT 
        attempt_id AS attempt_id,
        profile_id AS profile_id
),
actor_profile AS (
    SELECT
        p.id as profile_id,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
attempt_exists_check AS (
    SELECT EXISTS(
        SELECT 1 FROM eval_attempts WHERE id = (SELECT attempt_id FROM params)
    )::boolean as attempt_exists
),
attempt_data AS (
    SELECT 
        ea.id,
        ea.created_at,
        ea.eval_id,
        ea.archived,
        ea.infinite_mode
    FROM params x
    JOIN eval_attempts ea ON ea.id = x.attempt_id
),
-- Get eval agents for system prompt (use first agent)
eval_agents_data AS (
    SELECT 
        ea.eval_id,
        ARRAY_AGG(ea.agent_id::text ORDER BY ea.created_at) as agent_ids,
        (ARRAY_AGG(ea.agent_id ORDER BY ea.created_at))[1] as first_agent_id
    FROM attempt_data ad
    JOIN eval_agents ea ON ea.eval_id = ad.eval_id
    GROUP BY ea.eval_id
),
-- Get system prompt from eval's first agent (default active prompt)
agent_system_prompt AS (
    SELECT 
        COALESCE(pr.system_prompt, '') as system_prompt
    FROM attempt_data ad
    LEFT JOIN eval_agents_data ead ON ead.eval_id = ad.eval_id
    LEFT JOIN agent_prompts ap ON ap.agent_id = ead.first_agent_id AND ap.active = true
    LEFT JOIN prompts pr ON pr.id = ap.prompt_id
    LIMIT 1
),
eval_info AS (
    SELECT 
        e.id as eval_id,
        e.name as eval_name,
        e.description as eval_description,
        COALESCE(ead.agent_ids, ARRAY[]::text[]) as agent_ids,
        e.dynamic,
        -- Get first rubric and eval_agent from junction table
        -- Get first rubric from runs (when use_groups = false) or groups (when use_groups = true)
        (SELECT rga.rubric_id 
         FROM (
             SELECT errga.rubric_grade_agent_id, errga.created_at
             FROM eval_runs_rubric_grade_agents errga
             WHERE errga.eval_id = e.id AND e.use_groups = false
             UNION ALL
             SELECT egga.rubric_grade_agent_id, egga.created_at
             FROM eval_groups_rubric_grade_agents egga
             WHERE egga.eval_id = e.id AND e.use_groups = true
         ) combined
         JOIN rubric_grade_agents rga ON rga.id = combined.rubric_grade_agent_id
         ORDER BY combined.created_at 
         LIMIT 1) as rubric_id,
        (SELECT r.name 
         FROM (
             SELECT errga.rubric_grade_agent_id, errga.created_at
             FROM eval_runs_rubric_grade_agents errga
             WHERE errga.eval_id = e.id AND e.use_groups = false
             UNION ALL
             SELECT egga.rubric_grade_agent_id, egga.created_at
             FROM eval_groups_rubric_grade_agents egga
             WHERE egga.eval_id = e.id AND e.use_groups = true
         ) combined
         JOIN rubric_grade_agents rga ON rga.id = combined.rubric_grade_agent_id
         JOIN rubrics r ON r.id = rga.rubric_id
         ORDER BY combined.created_at 
         LIMIT 1) as rubric_name,
        (SELECT r.description 
         FROM (
             SELECT errga.rubric_grade_agent_id, errga.created_at
             FROM eval_runs_rubric_grade_agents errga
             WHERE errga.eval_id = e.id AND e.use_groups = false
             UNION ALL
             SELECT egga.rubric_grade_agent_id, egga.created_at
             FROM eval_groups_rubric_grade_agents egga
             WHERE egga.eval_id = e.id AND e.use_groups = true
         ) combined
         JOIN rubric_grade_agents rga ON rga.id = combined.rubric_grade_agent_id
         JOIN rubrics r ON r.id = rga.rubric_id
         ORDER BY combined.created_at 
         LIMIT 1) as rubric_description,
        (SELECT rga.grade_agent_id 
         FROM (
             SELECT errga.rubric_grade_agent_id, errga.created_at
             FROM eval_runs_rubric_grade_agents errga
             WHERE errga.eval_id = e.id AND e.use_groups = false
             UNION ALL
             SELECT egga.rubric_grade_agent_id, egga.created_at
             FROM eval_groups_rubric_grade_agents egga
             WHERE egga.eval_id = e.id AND e.use_groups = true
         ) combined
         JOIN rubric_grade_agents rga ON rga.id = combined.rubric_grade_agent_id
         ORDER BY combined.created_at 
         LIMIT 1) as eval_agent_id
    FROM attempt_data ad
    JOIN evals e ON e.id = ad.eval_id
    LEFT JOIN eval_agents_data ead ON ead.eval_id = e.id
),
-- Get all runs for this eval (from eval_runs)
eval_runs_data AS (
    SELECT 
        er.run_id,
        er.completed as eval_run_completed,
        er.created_at as eval_run_assigned_at,
        er.updated_at as eval_run_updated_at
    FROM attempt_data ad
    JOIN eval_runs er ON er.eval_id = ad.eval_id
),
-- Get tests linked to this attempt via attempt_tests
attempt_tests_data AS (
    SELECT 
        at.test_id,
        at.attempt_id,
        t.run_id as test_run_id,
        t.completed as test_completed,
        t.title as test_title,
        t.created_at as test_created_at,
        t.updated_at as test_updated_at
    FROM attempt_data ad
    JOIN attempt_tests at ON at.attempt_id = ad.id
    JOIN tests t ON t.id = at.test_id
),
-- Map tests to original runs using trace_id
-- trace_id format: "eval_{attempt_id}_{original_run_id}"
tests_to_runs AS (
    SELECT 
        atd.test_id,
        atd.test_completed,
        atd.test_title,
        atd.test_created_at,
        atd.test_updated_at,
        -- Extract original run_id from trace_id (format: eval_{attempt_id}_{run_id})
        -- Keep as text for comparison, cast to uuid only when valid
        CASE 
            WHEN t.trace_id LIKE 'eval_%_%' AND SPLIT_PART(t.trace_id, '_', 3) ~ '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$' THEN
                SPLIT_PART(t.trace_id, '_', 3)::uuid
            ELSE NULL::uuid
        END as original_run_id
    FROM attempt_tests_data atd
    JOIN tests t ON t.id = atd.test_id
    CROSS JOIN attempt_data ad
    WHERE t.trace_id LIKE 'eval_%_%'
      AND SPLIT_PART(t.trace_id, '_', 2) = ad.id::text
),
runs_with_status AS (
    SELECT 
        erd.run_id,
        erd.eval_run_completed,
        erd.eval_run_assigned_at,
        erd.eval_run_updated_at,
        -- Check if test exists for this run
        CASE 
            WHEN EXISTS (
                SELECT 1 
                FROM tests_to_runs ttr
                WHERE ttr.original_run_id = erd.run_id
            ) THEN
                -- Test exists, check if completed
                CASE 
                    WHEN EXISTS (
                        SELECT 1 
                        FROM tests_to_runs ttr2
                        WHERE ttr2.original_run_id = erd.run_id
                          AND ttr2.test_completed = true
                    ) THEN 'completed'
                    ELSE 'in_progress'
                END
            ELSE 'not_started'
        END as status,
        -- Get test_id if exists
        (
            SELECT ttr3.test_id
            FROM tests_to_runs ttr3
            WHERE ttr3.original_run_id = erd.run_id
            LIMIT 1
        ) as test_id
    FROM eval_runs_data erd
),
-- Get run details (model, agent, persona, profile, grade)
runs_with_details AS (
    SELECT 
        rws.run_id,
        rws.status,
        rws.test_id,
        rws.eval_run_completed,
        rws.eval_run_assigned_at,
        rws.eval_run_updated_at,
        -- Run details
        r.created_at as run_created_at,
        -- Model info
        rm.model_id,
        m.name as model_name,
        -- Agent/persona info
        r.agent_id,
        a.name as agent_name,
        rper.persona_id,
        per.name as persona_name,
        -- Profile info
        rp.profile_id,
        p.first_name || ' ' || p.last_name as profile_name,
        -- Grade info (from eval_agent's run, not original run)
        -- Grade is on the eval_agent run (test.run_id), not original run
        (
            SELECT g.score
            FROM grades g
            JOIN test_runs tr ON tr.run_id = g.run_id
            JOIN tests t ON t.id = tr.test_id
            WHERE t.id = rws.test_id
            LIMIT 1
        ) as grade_score,
        (
            SELECT g.passed
            FROM grades g
            JOIN test_runs tr ON tr.run_id = g.run_id
            JOIN tests t ON t.id = tr.test_id
            WHERE t.id = rws.test_id
            LIMIT 1
        ) as grade_passed,
        (
            SELECT g.created_at
            FROM grades g
            JOIN test_runs tr ON tr.run_id = g.run_id
            JOIN tests t ON t.id = tr.test_id
            WHERE t.id = rws.test_id
            LIMIT 1
        ) as grade_created_at
    FROM runs_with_status rws
    JOIN runs r ON r.id = rws.run_id
    LEFT JOIN run_models rm ON rm.run_id = r.id AND rm.active = true
    LEFT JOIN models m ON m.id = rm.model_id
    LEFT JOIN agents a ON a.id = r.agent_id
    LEFT JOIN run_personas rper ON rper.run_id = r.id AND rper.active = true
    LEFT JOIN personas per ON per.id = rper.persona_id
    LEFT JOIN run_profiles rp ON rp.run_id = r.id AND rp.active = true
    LEFT JOIN profiles p ON p.id = rp.profile_id
    ORDER BY rws.eval_run_assigned_at DESC
),
-- Calculate status summary
status_summary AS (
    SELECT 
        COUNT(*) FILTER (WHERE status = 'not_started')::int as not_started,
        COUNT(*) FILTER (WHERE status = 'in_progress')::int as in_progress,
        COUNT(*) FILTER (WHERE status = 'completed')::int as completed,
        COUNT(*)::int as total
    FROM runs_with_status
),
runs_aggregated AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (rwd.run_id, rwd.status, rwd.test_id, rwd.eval_run_completed, rwd.eval_run_assigned_at, rwd.eval_run_updated_at, rwd.run_created_at, rwd.model_id, rwd.model_name, rwd.agent_id, rwd.agent_name, rwd.persona_id, rwd.persona_name, rwd.profile_id, rwd.profile_name, rwd.grade_score, rwd.grade_passed, rwd.grade_created_at)::types.q_get_eval_attempt_v4_run
                ORDER BY rwd.eval_run_assigned_at DESC
            ),
            '{}'::types.q_get_eval_attempt_v4_run[]
        ) as runs
    FROM runs_with_details rwd
)
SELECT 
    aec.attempt_exists,
    ap.actor_name,
    (ad.id, ad.created_at, ad.eval_id, ad.archived, ad.infinite_mode)::types.q_get_eval_attempt_v4_attempt as attempt,
    (ei.eval_id, ei.eval_name, ei.eval_description, ei.agent_ids, ei.dynamic, ei.rubric_id, ei.rubric_name, ei.rubric_description, ei.eval_agent_id, COALESCE(asp.system_prompt, ''))::types.q_get_eval_attempt_v4_eval as eval,
    COALESCE(ra.runs, '{}'::types.q_get_eval_attempt_v4_run[]) as runs,
    (ss.not_started, ss.in_progress, ss.completed, ss.total)::types.q_get_eval_attempt_v4_status_summary as status_summary
FROM attempt_exists_check aec
CROSS JOIN attempt_data ad
CROSS JOIN eval_info ei
CROSS JOIN status_summary ss
CROSS JOIN actor_profile ap
CROSS JOIN agent_system_prompt asp
CROSS JOIN runs_aggregated ra
$_$;


--
-- Name: api_get_eval_detail_v4(uuid, uuid, text, uuid[], integer, integer, uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_eval_detail_v4(eval_id uuid, profile_id uuid, available_model_runs_search text DEFAULT NULL::text, available_model_runs_agent_ids uuid[] DEFAULT ARRAY[]::uuid[], available_model_runs_page integer DEFAULT 1, available_model_runs_page_size integer DEFAULT 50, draft_id uuid DEFAULT NULL::uuid, agent_search text DEFAULT NULL::text, group_search text DEFAULT NULL::text) RETURNS TABLE(eval_exists boolean, actor_name text, eval_id uuid, name text, description text, agent_ids text[], active boolean, dynamic boolean, created_at timestamp with time zone, updated_at timestamp with time zone, department_ids text[], total_runs bigint, completed_runs bigint, pending_runs bigint, status text, model_runs types.q_get_eval_detail_v4_model_run[], departments types.q_get_eval_detail_v4_department[], valid_department_ids text[], eval_agents types.q_get_eval_detail_v4_agent[], valid_eval_agent_ids text[], agents types.q_get_eval_detail_v4_agent[], valid_agent_ids text[], rubrics types.q_get_eval_detail_v4_rubric[], valid_rubric_ids text[], can_edit boolean, can_delete boolean, available_model_runs types.q_get_eval_detail_v4_available_model_run[], available_model_runs_total_count bigint, available_model_runs_page integer, available_model_runs_page_size integer, available_model_runs_total_pages bigint, available_groups types.q_get_eval_detail_v4_available_group[], draft_version integer, rubric_grade_agent_pairs jsonb, rubric_grade_agent_active_states jsonb, rubric_grade_agent_positions jsonb, run_rubric_grade_agents jsonb, group_rubric_grade_agents jsonb)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        eval_id AS eval_id,
        profile_id AS profile_id,
        available_model_runs_search AS available_model_runs_search,
        COALESCE(available_model_runs_agent_ids, ARRAY[]::uuid[]) AS available_model_runs_agent_ids,
        available_model_runs_page AS available_model_runs_page,
        available_model_runs_page_size AS available_model_runs_page_size,
        draft_id AS draft_id,
        COALESCE(NULLIF(agent_search, ''), NULL) AS agent_search,
        COALESCE(NULLIF(group_search, ''), NULL) AS group_search
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'evals'::draft_resource_type
    LIMIT 1
),
eval_exists_check AS (
    SELECT EXISTS(SELECT 1 FROM evals WHERE id = (SELECT eval_id FROM params))::boolean as eval_exists
),
resolve_profile_id AS (
    SELECT 
        CASE 
            WHEN (SELECT profile_id FROM params)::text IS NULL OR (SELECT profile_id FROM params)::text = '' THEN NULL::uuid
            ELSE (SELECT profile_id FROM params)::uuid
        END as resolved_profile_id
),
user_departments AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments ON profile_departments.profile_id = x.profile_id AND profile_departments.active = true
),
eval_data AS (
    SELECT 
        e.id as eval_id,
        e.name,
        e.description,
        e.use_groups,
        e.active,
        e.dynamic,
        e.created_at,
        e.updated_at
    FROM params x
    JOIN evals e ON e.id = x.eval_id
),
eval_agents_data AS (
    SELECT 
        ea.eval_id,
        ARRAY_AGG(ea.agent_id::text ORDER BY ea.created_at) as agent_ids
    FROM params x
    JOIN eval_agents ea ON ea.eval_id = x.eval_id
    GROUP BY ea.eval_id
),
-- Get rubric_grade_agents per run (when use_groups = false)
runs_rubric_grade_agents_data AS (
    SELECT 
        errga.eval_id,
        errga.run_id,
        ARRAY_AGG(
            (rga.id, rga.rubric_id, r.name, rga.grade_agent_id, a.name)::types.q_get_eval_detail_v4_rubric_grade_agent
            ORDER BY r.name
        ) as rubric_grade_agents
    FROM params x
    JOIN evals e ON e.id = x.eval_id AND e.use_groups = false
    JOIN eval_runs_rubric_grade_agents errga ON errga.eval_id = e.id
    JOIN rubric_grade_agents rga ON rga.id = errga.rubric_grade_agent_id
    JOIN rubrics r ON r.id = rga.rubric_id
    JOIN agents a ON a.id = rga.grade_agent_id
    GROUP BY errga.eval_id, errga.run_id
),
-- Get rubric_grade_agents per group (when use_groups = true)
groups_rubric_grade_agents_data AS (
    SELECT 
        egga.eval_id,
        egga.group_id,
        ARRAY_AGG(
            (rga.id, rga.rubric_id, r.name, rga.grade_agent_id, a.name)::types.q_get_eval_detail_v4_rubric_grade_agent
            ORDER BY r.name
        ) as rubric_grade_agents
    FROM params x
    JOIN evals e ON e.id = x.eval_id AND e.use_groups = true
    JOIN eval_groups_rubric_grade_agents egga ON egga.eval_id = e.id
    JOIN rubric_grade_agents rga ON rga.id = egga.rubric_grade_agent_id
    JOIN rubrics r ON r.id = rga.rubric_id
    JOIN agents a ON a.id = rga.grade_agent_id
    GROUP BY egga.eval_id, egga.group_id
),
eval_departments_data AS (
    SELECT 
        ed.eval_id,
        ARRAY_AGG(ed.department_id::text ORDER BY ed.created_at) as department_ids
    FROM params x
    JOIN eval_departments ed ON ed.eval_id = x.eval_id AND ed.active = true
    GROUP BY ed.eval_id
),
eval_status_summary AS (
    SELECT 
        er.eval_id,
        COUNT(*) as total_runs,
        COUNT(*) FILTER (WHERE er.completed = true) as completed_runs,
        COUNT(*) FILTER (WHERE er.completed = false) as pending_runs
    FROM params x
    JOIN eval_runs er ON er.eval_id = x.eval_id
    GROUP BY er.eval_id
),
runs_list AS (
    SELECT 
        er.run_id,
        er.completed,
        er.created_at as assigned_at,
        er.updated_at as status_updated_at,
        r.created_at as model_run_created_at,
        rm.model_id,
        m.name as model_name,
        r.agent_id,
        a.name as agent_name,
        rper.persona_id,
        per.name as persona_name,
        rp.profile_id,
        p.first_name || ' ' || p.last_name as profile_name,
        CASE WHEN g.id IS NOT NULL THEN true ELSE false END as has_grade,
        g.score as grade_score,
        g.passed as grade_passed,
        g.created_at as grade_created_at,
        COALESCE(
            (SELECT ARRAY_AGG(
                (rga.id, rga.rubric_id, r2.name, rga.grade_agent_id, a2.name)::types.q_get_eval_detail_v4_rubric_grade_agent
                ORDER BY r2.name
            )
            FROM eval_runs_rubric_grade_agents errga
            JOIN rubric_grade_agents rga ON rga.id = errga.rubric_grade_agent_id
            JOIN rubrics r2 ON r2.id = rga.rubric_id
            JOIN agents a2 ON a2.id = rga.grade_agent_id
            WHERE errga.eval_id = er.eval_id AND errga.run_id = er.run_id),
            '{}'::types.q_get_eval_detail_v4_rubric_grade_agent[]
        ) as rubric_grade_agents
    FROM params x
    JOIN eval_runs er ON er.eval_id = x.eval_id
    JOIN runs r ON r.id = er.run_id
    LEFT JOIN run_models rm ON rm.run_id = r.id AND rm.active = true
    LEFT JOIN models m ON m.id = rm.model_id
    LEFT JOIN agents a ON a.id = r.agent_id
    LEFT JOIN run_personas rper ON rper.run_id = r.id AND rper.active = true
    LEFT JOIN personas per ON per.id = rper.persona_id
    LEFT JOIN run_profiles rp ON rp.run_id = r.id AND rp.active = true
    LEFT JOIN profiles p ON p.id = rp.profile_id
    LEFT JOIN grades g ON g.run_id = er.run_id 
        AND EXISTS (
            SELECT 1 FROM test_runs tr
            JOIN tests t ON t.id = tr.test_id
            JOIN attempt_tests at ON at.test_id = t.id
            JOIN eval_attempts ea ON ea.id = at.attempt_id
            WHERE tr.run_id = g.run_id AND ea.eval_id = er.eval_id
        )
    ORDER BY er.created_at DESC
),
model_runs_array AS (
    SELECT COALESCE(
        ARRAY_AGG(
            (rl.run_id, rl.completed, rl.assigned_at, rl.status_updated_at,
             rl.model_run_created_at, rl.model_id, rl.model_name,
             rl.agent_id, rl.agent_name, rl.persona_id, rl.persona_name,
             rl.profile_id, rl.profile_name, rl.has_grade,
             rl.grade_score, rl.grade_passed, rl.grade_created_at,
             rl.rubric_grade_agents
            )::types.q_get_eval_detail_v4_model_run
        ),
        '{}'::types.q_get_eval_detail_v4_model_run[]
    ) as model_runs
    FROM runs_list rl
),
user_profile AS (
    SELECT 
        role,
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
valid_departments_for_eval AS (
    SELECT DISTINCT d.id, d.title as name, COALESCE(d.description, '') as description
    FROM params x
    JOIN departments d ON d.active = true
    JOIN profile_departments pd ON pd.department_id = d.id AND pd.profile_id = x.profile_id AND pd.active = true
),
valid_dept_ids AS (
    SELECT ARRAY_AGG(id::text) as ids FROM valid_departments_for_eval
),
departments_array AS (
    SELECT COALESCE(
        ARRAY_AGG((vd.id, vd.name, vd.description)::types.q_get_eval_detail_v4_department),
        '{}'::types.q_get_eval_detail_v4_department[]
    ) as departments
    FROM valid_departments_for_eval vd
),
user_departments_for_agents AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.active = true
),
valid_eval_agents_list AS (
    SELECT 
        a.id,
        a.name,
        COALESCE(a.description, '') as description,
        ARRAY[a.role::text] as roles
    FROM params x
    JOIN agents a ON a.active = true AND a.role = 'grade'::agent_role
    LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
    WHERE 
        (SELECT agent_search FROM params LIMIT 1) IS NULL
        OR LOWER(a.name) LIKE '%' || LOWER((SELECT agent_search FROM params LIMIT 1)) || '%'
        OR LOWER(COALESCE(a.description, '')) LIKE '%' || LOWER((SELECT agent_search FROM params LIMIT 1)) || '%'
    GROUP BY a.id, a.name, a.description, a.role
    HAVING 
        COUNT(ad.agent_id) FILTER (WHERE ad.department_id IN (SELECT department_id FROM user_departments_for_agents)) > 0
        OR NOT EXISTS (SELECT 1 FROM agent_departments ad2 WHERE ad2.agent_id = a.id AND ad2.active = true)
),
eval_agents_array AS (
    SELECT COALESCE(
        ARRAY_AGG((vea.id, vea.name, vea.description, vea.roles)::types.q_get_eval_detail_v4_agent),
        '{}'::types.q_get_eval_detail_v4_agent[]
    ) as eval_agents,
    COALESCE(ARRAY_AGG(vea.id::text ORDER BY vea.name), ARRAY[]::text[]) as eval_agent_ids
    FROM valid_eval_agents_list vea
),
valid_agents_for_eval_list AS (
    SELECT 
        a.id,
        a.name,
        COALESCE(a.description, '') as description,
        ARRAY[a.role::text] as roles
    FROM params x
    JOIN agents a ON a.active = true
    LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
    WHERE 
        (SELECT agent_search FROM params LIMIT 1) IS NULL
        OR LOWER(a.name) LIKE '%' || LOWER((SELECT agent_search FROM params LIMIT 1)) || '%'
        OR LOWER(COALESCE(a.description, '')) LIKE '%' || LOWER((SELECT agent_search FROM params LIMIT 1)) || '%'
    GROUP BY a.id, a.name, a.description, a.role
    HAVING 
        COUNT(ad.agent_id) FILTER (WHERE ad.department_id IN (SELECT department_id FROM user_departments_for_agents)) > 0
        OR NOT EXISTS (SELECT 1 FROM agent_departments ad2 WHERE ad2.agent_id = a.id AND ad2.active = true)
),
agents_array AS (
    SELECT COALESCE(
        ARRAY_AGG((vae.id, vae.name, vae.description, vae.roles)::types.q_get_eval_detail_v4_agent),
        '{}'::types.q_get_eval_detail_v4_agent[]
    ) as agents,
    COALESCE(ARRAY_AGG(vae.id::text ORDER BY vae.name), ARRAY[]::text[]) as agent_ids
    FROM valid_agents_for_eval_list vae
),
user_department_ids_for_rubrics AS (
    SELECT ARRAY_AGG(id) as ids
    FROM params x
    JOIN departments d ON d.active = true
    JOIN profile_departments pd ON d.id = pd.department_id AND pd.profile_id = x.profile_id AND pd.active = true
),
valid_rubrics_data AS (
    SELECT DISTINCT
        r.id,
        r.name,
        COALESCE(r.description, '') as description,
        CASE WHEN r.agent_role IS NULL THEN NULL ELSE r.agent_role::text END as agent_role
    FROM params x
    JOIN rubrics r ON r.active = true
    LEFT JOIN rubric_departments rd ON rd.rubric_id = r.id AND rd.active = true
    CROSS JOIN user_department_ids_for_rubrics udi
    WHERE (
        rd.department_id = ANY(udi.ids)
        OR NOT EXISTS (SELECT 1 FROM rubric_departments rd2 WHERE rd2.rubric_id = r.id AND rd2.active = true)
    )
    UNION
    SELECT DISTINCT
        r2.id,
        r2.name,
        COALESCE(r2.description, '') as description,
        CASE WHEN r2.agent_role IS NULL THEN NULL ELSE r2.agent_role::text END as agent_role
    FROM params x
    JOIN evals e ON e.id = x.eval_id
    LEFT JOIN eval_runs_rubric_grade_agents errga ON errga.eval_id = e.id AND e.use_groups = false
    LEFT JOIN eval_groups_rubric_grade_agents egga ON egga.eval_id = e.id AND e.use_groups = true
    JOIN rubric_grade_agents rga ON rga.id = COALESCE(errga.rubric_grade_agent_id, egga.rubric_grade_agent_id)
    JOIN rubrics r2 ON r2.id = rga.rubric_id
    WHERE r2.active = true
),
rubrics_array AS (
    SELECT COALESCE(
        ARRAY_AGG((vr.id, vr.name, vr.description, vr.agent_role)::types.q_get_eval_detail_v4_rubric),
        '{}'::types.q_get_eval_detail_v4_rubric[]
    ) as rubrics,
    COALESCE(ARRAY_AGG(vr.id::text), ARRAY[]::text[]) as rubric_ids
    FROM valid_rubrics_data vr
),
-- Available model runs query (conditional based on filters)
available_model_runs_params AS (
    SELECT 
        available_model_runs_search,
        available_model_runs_agent_ids,
        available_model_runs_page,
        available_model_runs_page_size
    FROM params
),
profile_role_check AS (
    SELECT 
        (SELECT profile_id FROM params) as raw_profile_id,
        CASE 
            WHEN (SELECT profile_id FROM params) IS NULL THEN NULL::uuid
            WHEN (SELECT role FROM user_profile) IN ('admin', 'superadmin', 'instructional') THEN NULL::uuid
            ELSE (SELECT profile_id FROM params)
        END as effective_profile_id
),
runs_base AS (
    SELECT
        r.id as run_id,
        r.created_at,
        rm.model_id,
        rp.profile_id,
        r.agent_id,
        rper.persona_id
    FROM runs r
    LEFT JOIN run_models rm ON rm.run_id = r.id AND rm.active = true
    LEFT JOIN run_profiles rp ON rp.run_id = r.id AND rp.active = true
    LEFT JOIN run_personas rper ON rper.run_id = r.id AND rper.active = true
    WHERE 
        (SELECT effective_profile_id FROM profile_role_check) IS NULL
        OR rp.profile_id = (SELECT effective_profile_id FROM profile_role_check)
),
runs_with_names AS (
    SELECT
        rb.*,
        m.name as model_name,
        p.first_name || ' ' || p.last_name as profile_name,
        a.name as agent_name,
        per.name as persona_name,
        CASE 
            WHEN rb.agent_id IS NOT NULL THEN 'agent'
            WHEN rb.persona_id IS NOT NULL THEN 'persona'
            ELSE NULL
        END as actor_type
    FROM runs_base rb
    LEFT JOIN models m ON m.id = rb.model_id
    LEFT JOIN profiles p ON p.id = rb.profile_id
    LEFT JOIN agents a ON a.id = rb.agent_id
    LEFT JOIN personas per ON per.id = rb.persona_id
),
runs_filtered AS (
    SELECT *
    FROM runs_with_names rwn
    CROSS JOIN available_model_runs_params amp
    WHERE (
        -- Show all runs when both filters are null/empty (default case)
        (
            (amp.available_model_runs_search IS NULL OR amp.available_model_runs_search = '')
            AND (amp.available_model_runs_agent_ids IS NULL 
                 OR COALESCE(array_length(amp.available_model_runs_agent_ids, 1), 0) = 0)
        )
        OR (
            -- Apply search filter when search term is provided
            amp.available_model_runs_search IS NOT NULL
            AND amp.available_model_runs_search != ''
            AND (
                LOWER(COALESCE(rwn.model_name, '')) LIKE '%' || LOWER(amp.available_model_runs_search) || '%'
                OR LOWER(COALESCE(rwn.agent_name, '')) LIKE '%' || LOWER(amp.available_model_runs_search) || '%'
                OR LOWER(COALESCE(rwn.persona_name, '')) LIKE '%' || LOWER(amp.available_model_runs_search) || '%'
                OR LOWER(COALESCE(rwn.profile_name, '')) LIKE '%' || LOWER(amp.available_model_runs_search) || '%'
            )
            -- If agent_ids filter is also provided, combine filters (run must match search AND be in agent_ids)
            AND (
                amp.available_model_runs_agent_ids IS NULL 
                OR COALESCE(array_length(amp.available_model_runs_agent_ids, 1), 0) = 0
                OR (rwn.agent_id IS NOT NULL AND rwn.agent_id = ANY(amp.available_model_runs_agent_ids))
            )
        )
        OR (
            -- Apply agent_ids filter when agent_ids are provided (without search)
            amp.available_model_runs_agent_ids IS NOT NULL
            AND COALESCE(array_length(amp.available_model_runs_agent_ids, 1), 0) > 0
            AND rwn.agent_id IS NOT NULL 
            AND rwn.agent_id = ANY(amp.available_model_runs_agent_ids)
            -- Only apply agent_ids filter if search is null/empty
            AND (amp.available_model_runs_search IS NULL OR amp.available_model_runs_search = '')
        )
    )
),
paginated_runs AS (
    SELECT
        rf.*,
        COUNT(*) OVER() AS total_count
    FROM runs_filtered rf
    CROSS JOIN available_model_runs_params amp
    ORDER BY rf.created_at DESC
    LIMIT (SELECT available_model_runs_page_size FROM available_model_runs_params LIMIT 1)
    OFFSET (SELECT (available_model_runs_page - 1) * available_model_runs_page_size FROM available_model_runs_params LIMIT 1)
),
available_model_runs_array AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (pr.run_id, pr.created_at, pr.model_id, pr.model_name,
                 pr.profile_id, pr.profile_name, pr.agent_id, pr.agent_name,
                 pr.persona_id, pr.persona_name, pr.actor_type
                )::types.q_get_eval_detail_v4_available_model_run
            ),
            '{}'::types.q_get_eval_detail_v4_available_model_run[]
        ) as available_model_runs,
        COALESCE(MAX(pr.total_count), 0) as total_count,
        MAX(amp.available_model_runs_page) as page,
        MAX(amp.available_model_runs_page_size) as page_size,
        CEIL(COALESCE(MAX(pr.total_count), 0)::float / NULLIF(MAX(amp.available_model_runs_page_size), 0)) as total_pages
    FROM paginated_runs pr
    CROSS JOIN available_model_runs_params amp
),
-- Available groups query (filtered by group_search)
groups_base AS (
    SELECT
        g.id as group_id,
        g.created_at,
        COUNT(gr.run_id) as member_count
    FROM groups g
    LEFT JOIN group_runs gr ON gr.group_id = g.id
    GROUP BY g.id, g.created_at
),
groups_filtered AS (
    SELECT *
    FROM groups_base gb
    CROSS JOIN params x
    WHERE (
        x.group_search IS NULL 
        OR x.group_search = ''
        OR LOWER(gb.group_id::text) LIKE '%' || LOWER(x.group_search) || '%'
        OR LOWER(gb.group_id::text) LIKE '%' || LOWER(REPLACE(x.group_search, '-', '')) || '%'
    )
),
available_groups_array AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (gf.group_id, 
                 'Group ' || SUBSTRING(gf.group_id::text, 1, 8),
                 COALESCE(gf.member_count::text, '0') || ' members',
                 gf.created_at,
                 gf.member_count)::types.q_get_eval_detail_v4_available_group
                ORDER BY gf.created_at DESC
            ),
            '{}'::types.q_get_eval_detail_v4_available_group[]
        ) as available_groups
    FROM groups_filtered gf
)
SELECT 
    eec.eval_exists,
    up.actor_name::text as actor_name,
    ed.eval_id,
    -- Merge draft payload over existing eval data if draft_id provided
    COALESCE(
        (SELECT payload->>'name' FROM draft_payload_data),
        ed.name
    ) as name,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        ed.description
    ) as description,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'agent_ids' IS NOT NULL AND jsonb_typeof(payload->'agent_ids') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'agent_ids'))
                ELSE NULL
            END
        FROM draft_payload_data),
        COALESCE(ead.agent_ids, ARRAY[]::text[])
    ) as agent_ids,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        ed.active
    ) as active,
    COALESCE(
        (SELECT (payload->>'dynamic')::boolean FROM draft_payload_data),
        ed.dynamic
    ) as dynamic,
    ed.created_at,
    ed.updated_at,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'department_ids' IS NOT NULL AND jsonb_typeof(payload->'department_ids') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'department_ids'))
                ELSE NULL
            END
        FROM draft_payload_data),
        COALESCE(edd.department_ids, ARRAY[]::text[])
    ) as department_ids,
    COALESCE(ess.total_runs, 0) as total_runs,
    COALESCE(ess.completed_runs, 0) as completed_runs,
    COALESCE(ess.pending_runs, 0) as pending_runs,
    CASE 
        WHEN ess.total_runs IS NULL OR ess.total_runs = 0 THEN 'pending'
        WHEN ess.pending_runs > 0 THEN 'running'
        WHEN ess.completed_runs = ess.total_runs THEN 'completed'
        ELSE 'pending'
    END as status,
    COALESCE(mra.model_runs, '{}'::types.q_get_eval_detail_v4_model_run[]) as model_runs,
    COALESCE(da.departments, '{}'::types.q_get_eval_detail_v4_department[]) as departments,
    COALESCE((SELECT ids FROM valid_dept_ids), ARRAY[]::text[]) as valid_department_ids,
    COALESCE(eaa.eval_agents, '{}'::types.q_get_eval_detail_v4_agent[]) as eval_agents,
    COALESCE(eaa.eval_agent_ids, ARRAY[]::text[]) as valid_eval_agent_ids,
    COALESCE(aa.agents, '{}'::types.q_get_eval_detail_v4_agent[]) as agents,
    COALESCE(aa.agent_ids, ARRAY[]::text[]) as valid_agent_ids,
    COALESCE(ra.rubrics, '{}'::types.q_get_eval_detail_v4_rubric[]) as rubrics,
    COALESCE(ra.rubric_ids, ARRAY[]::text[]) as valid_rubric_ids,
    CASE WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) THEN true ELSE false END as can_edit,
    CASE WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) THEN true ELSE false END as can_delete,
    COALESCE(amra.available_model_runs, '{}'::types.q_get_eval_detail_v4_available_model_run[]) as available_model_runs,
    COALESCE(amra.total_count, 0) as available_model_runs_total_count,
    COALESCE(amra.page, 1) as available_model_runs_page,
    COALESCE(amra.page_size, 50) as available_model_runs_page_size,
    COALESCE(amra.total_pages, 0) as available_model_runs_total_pages,
    COALESCE(aga.available_groups, '{}'::types.q_get_eval_detail_v4_available_group[]) as available_groups,
    COALESCE((SELECT version FROM draft_payload_data), 0) as draft_version,
    COALESCE(
        (SELECT payload->'rubric_grade_agent_pairs' FROM draft_payload_data),
        '[]'::jsonb
    ) as rubric_grade_agent_pairs,
    COALESCE(
        (SELECT payload->'rubric_grade_agent_active_states' FROM draft_payload_data),
        '{}'::jsonb
    ) as rubric_grade_agent_active_states,
    COALESCE(
        (SELECT payload->'rubric_grade_agent_positions' FROM draft_payload_data),
        '[]'::jsonb
    ) as rubric_grade_agent_positions,
    COALESCE(
        (SELECT payload->'run_rubric_grade_agents' FROM draft_payload_data),
        COALESCE(
            (SELECT jsonb_object_agg(
                errga.run_id::text,
                COALESCE(
                    (SELECT jsonb_agg(
                        jsonb_build_object(
                            'rubric_id', rga.rubric_id::text,
                            'grade_text_agent_id', rga.grade_agent_id::text
                        )
                    )
                    FROM eval_runs_rubric_grade_agents errga2
                    JOIN rubric_grade_agents rga ON rga.id = errga2.rubric_grade_agent_id
                    WHERE errga2.eval_id = ed.eval_id AND errga2.run_id = errga.run_id),
                    '[]'::jsonb
                )
            )
             FROM params x2
             JOIN eval_runs_rubric_grade_agents errga ON errga.eval_id = ed.eval_id
             GROUP BY errga.run_id),
            '{}'::jsonb
        )
    ) as run_rubric_grade_agents,
    COALESCE(
        (SELECT payload->'group_rubric_grade_agents' FROM draft_payload_data),
        COALESCE(
            (SELECT jsonb_object_agg(
                egga.group_id::text,
                COALESCE(
                    (SELECT jsonb_agg(
                        jsonb_build_object(
                            'rubric_id', rga.rubric_id::text,
                            'grade_text_agent_id', rga.grade_agent_id::text
                        )
                    )
                    FROM eval_groups_rubric_grade_agents egga2
                    JOIN rubric_grade_agents rga ON rga.id = egga2.rubric_grade_agent_id
                    WHERE egga2.eval_id = ed.eval_id AND egga2.group_id = egga.group_id),
                    '[]'::jsonb
                )
            )
             FROM params x3
             JOIN eval_groups_rubric_grade_agents egga ON egga.eval_id = ed.eval_id
             GROUP BY egga.group_id),
            '{}'::jsonb
        )
    ) as group_rubric_grade_agents
FROM eval_exists_check eec
CROSS JOIN params
CROSS JOIN eval_data ed
LEFT JOIN eval_agents_data ead ON ead.eval_id = ed.eval_id
LEFT JOIN eval_departments_data edd ON edd.eval_id = ed.eval_id
LEFT JOIN eval_status_summary ess ON ess.eval_id = ed.eval_id
CROSS JOIN model_runs_array mra
CROSS JOIN user_profile up
CROSS JOIN departments_array da
CROSS JOIN eval_agents_array eaa
CROSS JOIN agents_array aa
CROSS JOIN rubrics_array ra
LEFT JOIN available_model_runs_array amra ON (
    (SELECT available_model_runs_search FROM params) IS NOT NULL 
    OR (SELECT available_model_runs_agent_ids FROM params) IS NOT NULL
    OR COALESCE(array_length((SELECT available_model_runs_agent_ids FROM params), 1), 0) > 0
)
CROSS JOIN available_groups_array aga
WHERE 
    -- Filter by department access (if eval has departments, user must have access)
    (
        edd.department_ids IS NULL 
        OR array_length(edd.department_ids, 1) IS NULL
        OR EXISTS (
            SELECT 1 FROM user_departments ud
            WHERE ud.department_id::text = ANY(edd.department_ids)
        )
        OR up.role IN ('admin'::profile_role, 'superadmin'::profile_role)
    )
$$;


--
-- Name: api_get_eval_new_v4(uuid, text, uuid[], integer, integer, uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_eval_new_v4(profile_id uuid, available_model_runs_search text DEFAULT NULL::text, available_model_runs_agent_ids uuid[] DEFAULT ARRAY[]::uuid[], available_model_runs_page integer DEFAULT 1, available_model_runs_page_size integer DEFAULT 50, draft_id uuid DEFAULT NULL::uuid, agent_search text DEFAULT NULL::text, group_search text DEFAULT NULL::text) RETURNS TABLE(actor_name text, eval_id uuid, name text, description text, agent_ids text[], model_run_ids text[], active boolean, dynamic boolean, department_ids text[], valid_department_ids text[], departments types.q_get_eval_detail_v4_department[], eval_agents types.q_get_eval_detail_v4_agent[], valid_eval_agent_ids text[], agents types.q_get_eval_detail_v4_agent[], valid_agent_ids text[], rubrics types.q_get_eval_detail_v4_rubric[], valid_rubric_ids text[], use_groups boolean, can_edit boolean, can_delete boolean, available_model_runs types.q_get_eval_detail_v4_available_model_run[], available_model_runs_total_count bigint, available_model_runs_page integer, available_model_runs_page_size integer, available_model_runs_total_pages bigint, available_groups types.q_get_eval_detail_v4_available_group[], draft_version integer, rubric_grade_agent_pairs jsonb, rubric_grade_agent_active_states jsonb, rubric_grade_agent_positions jsonb, run_rubric_grade_agents jsonb, group_rubric_grade_agents jsonb)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        profile_id AS profile_id,
        available_model_runs_search AS available_model_runs_search,
        COALESCE(available_model_runs_agent_ids, ARRAY[]::uuid[]) AS available_model_runs_agent_ids,
        available_model_runs_page AS available_model_runs_page,
        available_model_runs_page_size AS available_model_runs_page_size,
        draft_id AS draft_id,
        COALESCE(NULLIF(agent_search, ''), NULL) AS agent_search,
        COALESCE(NULLIF(group_search, ''), NULL) AS group_search
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'evals'::draft_resource_type
    LIMIT 1
),
user_profile AS (
    SELECT 
        role,
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
user_departments_for_agents AS (
    SELECT DISTINCT pd.department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.active = true
),
valid_departments_for_eval AS (
    SELECT DISTINCT d.id, d.title as name, COALESCE(d.description, '') as description
    FROM params x
    JOIN departments d ON d.active = true
    JOIN profile_departments pd ON pd.department_id = d.id AND pd.profile_id = x.profile_id AND pd.active = true
),
valid_dept_ids AS (
    SELECT ARRAY_AGG(id::text) as ids FROM valid_departments_for_eval
),
departments_array AS (
    SELECT COALESCE(
        ARRAY_AGG((vd.id, vd.name, vd.description)::types.q_get_eval_detail_v4_department),
        '{}'::types.q_get_eval_detail_v4_department[]
    ) as departments
    FROM valid_departments_for_eval vd
),
valid_eval_agents_list AS (
    SELECT 
        a.id,
        a.name,
        COALESCE(a.description, '') as description,
        ARRAY[a.role::text] as roles
    FROM params x
    JOIN agents a ON a.active = true AND a.role = 'grade'::agent_role
    LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
    GROUP BY a.id, a.name, a.description, a.role
    HAVING 
        COUNT(ad.agent_id) FILTER (WHERE ad.department_id IN (SELECT department_id FROM user_departments_for_agents)) > 0
        OR NOT EXISTS (SELECT 1 FROM agent_departments ad2 WHERE ad2.agent_id = a.id AND ad2.active = true)
),
eval_agents_array AS (
    SELECT COALESCE(
        ARRAY_AGG((vea.id, vea.name, vea.description, vea.roles)::types.q_get_eval_detail_v4_agent),
        '{}'::types.q_get_eval_detail_v4_agent[]
    ) as eval_agents,
    COALESCE(ARRAY_AGG(vea.id::text ORDER BY vea.name), ARRAY[]::text[]) as eval_agent_ids
    FROM valid_eval_agents_list vea
),
valid_agents_for_eval_list AS (
    SELECT 
        a.id,
        a.name,
        COALESCE(a.description, '') as description,
        ARRAY[a.role::text] as roles
    FROM params x
    JOIN agents a ON a.active = true
    LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
    WHERE 
        (SELECT agent_search FROM params LIMIT 1) IS NULL
        OR LOWER(a.name) LIKE '%' || LOWER((SELECT agent_search FROM params LIMIT 1)) || '%'
        OR LOWER(COALESCE(a.description, '')) LIKE '%' || LOWER((SELECT agent_search FROM params LIMIT 1)) || '%'
    GROUP BY a.id, a.name, a.description, a.role
    HAVING 
        COUNT(ad.agent_id) FILTER (WHERE ad.department_id IN (SELECT department_id FROM user_departments_for_agents)) > 0
        OR NOT EXISTS (SELECT 1 FROM agent_departments ad2 WHERE ad2.agent_id = a.id AND ad2.active = true)
),
agents_array AS (
    SELECT COALESCE(
        ARRAY_AGG((vae.id, vae.name, vae.description, vae.roles)::types.q_get_eval_detail_v4_agent),
        '{}'::types.q_get_eval_detail_v4_agent[]
    ) as agents,
    COALESCE(ARRAY_AGG(vae.id::text ORDER BY vae.name), ARRAY[]::text[]) as agent_ids
    FROM valid_agents_for_eval_list vae
),
user_department_ids_for_rubrics AS (
    SELECT ARRAY_AGG(id) as ids
    FROM params x
    JOIN departments d ON d.active = true
    JOIN profile_departments pd ON d.id = pd.department_id AND pd.profile_id = x.profile_id AND pd.active = true
),
valid_rubrics_data AS (
    SELECT DISTINCT
        r.id,
        r.name,
        COALESCE(r.description, '') as description,
        CASE WHEN r.agent_role IS NULL THEN NULL ELSE r.agent_role::text END as agent_role
    FROM params x
    JOIN rubrics r ON r.active = true
    LEFT JOIN rubric_departments rd ON rd.rubric_id = r.id AND rd.active = true
    CROSS JOIN user_department_ids_for_rubrics udi
    WHERE (
        rd.department_id = ANY(udi.ids)
        OR NOT EXISTS (SELECT 1 FROM rubric_departments rd2 WHERE rd2.rubric_id = r.id AND rd2.active = true)
    )
),
rubrics_array AS (
    SELECT COALESCE(
        ARRAY_AGG((vr.id, vr.name, vr.description, vr.agent_role)::types.q_get_eval_detail_v4_rubric),
        '{}'::types.q_get_eval_detail_v4_rubric[]
    ) as rubrics,
    COALESCE(ARRAY_AGG(vr.id::text), ARRAY[]::text[]) as rubric_ids
    FROM valid_rubrics_data vr
),
-- Available model runs query (same as detail endpoint)
available_model_runs_params AS (
    SELECT 
        available_model_runs_search,
        available_model_runs_agent_ids,
        available_model_runs_page,
        available_model_runs_page_size
    FROM params
),
profile_role_check AS (
    SELECT 
        (SELECT profile_id FROM params) as raw_profile_id,
        CASE 
            WHEN (SELECT profile_id FROM params) IS NULL THEN NULL::uuid
            WHEN (SELECT role FROM user_profile) IN ('admin', 'superadmin', 'instructional') THEN NULL::uuid
            ELSE (SELECT profile_id FROM params)
        END as effective_profile_id
),
runs_base AS (
    SELECT
        r.id as run_id,
        r.created_at,
        rm.model_id,
        rp.profile_id,
        r.agent_id,
        rper.persona_id
    FROM runs r
    LEFT JOIN run_models rm ON rm.run_id = r.id AND rm.active = true
    LEFT JOIN run_profiles rp ON rp.run_id = r.id AND rp.active = true
    LEFT JOIN run_personas rper ON rper.run_id = r.id AND rper.active = true
    WHERE 
        (SELECT effective_profile_id FROM profile_role_check) IS NULL
        OR rp.profile_id = (SELECT effective_profile_id FROM profile_role_check)
),
runs_with_names AS (
    SELECT
        rb.*,
        m.name as model_name,
        p.first_name || ' ' || p.last_name as profile_name,
        a.name as agent_name,
        per.name as persona_name,
        CASE 
            WHEN rb.agent_id IS NOT NULL THEN 'agent'
            WHEN rb.persona_id IS NOT NULL THEN 'persona'
            ELSE NULL
        END as actor_type
    FROM runs_base rb
    LEFT JOIN models m ON m.id = rb.model_id
    LEFT JOIN profiles p ON p.id = rb.profile_id
    LEFT JOIN agents a ON a.id = rb.agent_id
    LEFT JOIN personas per ON per.id = rb.persona_id
),
runs_filtered AS (
    SELECT *
    FROM runs_with_names rwn
    CROSS JOIN available_model_runs_params amp
    WHERE (
        -- Show all runs when both filters are null/empty (default case)
        (
            (amp.available_model_runs_search IS NULL OR amp.available_model_runs_search = '')
            AND (amp.available_model_runs_agent_ids IS NULL 
                 OR COALESCE(array_length(amp.available_model_runs_agent_ids, 1), 0) = 0)
        )
        OR (
            -- Apply search filter when search term is provided
            amp.available_model_runs_search IS NOT NULL
            AND amp.available_model_runs_search != ''
            AND (
                LOWER(COALESCE(rwn.model_name, '')) LIKE '%' || LOWER(amp.available_model_runs_search) || '%'
                OR LOWER(COALESCE(rwn.agent_name, '')) LIKE '%' || LOWER(amp.available_model_runs_search) || '%'
                OR LOWER(COALESCE(rwn.persona_name, '')) LIKE '%' || LOWER(amp.available_model_runs_search) || '%'
                OR LOWER(COALESCE(rwn.profile_name, '')) LIKE '%' || LOWER(amp.available_model_runs_search) || '%'
            )
            -- If agent_ids filter is also provided, combine filters (run must match search AND be in agent_ids)
            AND (
                amp.available_model_runs_agent_ids IS NULL 
                OR COALESCE(array_length(amp.available_model_runs_agent_ids, 1), 0) = 0
                OR (rwn.agent_id IS NOT NULL AND rwn.agent_id = ANY(amp.available_model_runs_agent_ids))
            )
        )
        OR (
            -- Apply agent_ids filter when agent_ids are provided (without search)
            amp.available_model_runs_agent_ids IS NOT NULL
            AND COALESCE(array_length(amp.available_model_runs_agent_ids, 1), 0) > 0
            AND rwn.agent_id IS NOT NULL 
            AND rwn.agent_id = ANY(amp.available_model_runs_agent_ids)
            -- Only apply agent_ids filter if search is null/empty
            AND (amp.available_model_runs_search IS NULL OR amp.available_model_runs_search = '')
        )
    )
),
paginated_runs AS (
    SELECT
        rf.*,
        COUNT(*) OVER() AS total_count
    FROM runs_filtered rf
    CROSS JOIN available_model_runs_params amp
    ORDER BY rf.created_at DESC
    LIMIT (SELECT available_model_runs_page_size FROM available_model_runs_params LIMIT 1)
    OFFSET (SELECT (available_model_runs_page - 1) * available_model_runs_page_size FROM available_model_runs_params LIMIT 1)
),
available_model_runs_array AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (pr.run_id, pr.created_at, pr.model_id, pr.model_name,
                 pr.profile_id, pr.profile_name, pr.agent_id, pr.agent_name,
                 pr.persona_id, pr.persona_name, pr.actor_type
                )::types.q_get_eval_detail_v4_available_model_run
            ),
            '{}'::types.q_get_eval_detail_v4_available_model_run[]
        ) as available_model_runs,
        COALESCE(MAX(pr.total_count), 0) as total_count,
        MAX(amp.available_model_runs_page) as page,
        MAX(amp.available_model_runs_page_size) as page_size,
        CEIL(COALESCE(MAX(pr.total_count), 0)::float / NULLIF(MAX(amp.available_model_runs_page_size), 0)) as total_pages
    FROM paginated_runs pr
    CROSS JOIN available_model_runs_params amp
),
-- Available groups query (filtered by group_search)
groups_base AS (
    SELECT
        g.id as group_id,
        g.created_at,
        COUNT(gr.run_id) as member_count
    FROM groups g
    LEFT JOIN group_runs gr ON gr.group_id = g.id
    GROUP BY g.id, g.created_at
),
groups_filtered AS (
    SELECT *
    FROM groups_base gb
    CROSS JOIN params x
    WHERE (
        x.group_search IS NULL 
        OR x.group_search = ''
        OR LOWER(gb.group_id::text) LIKE '%' || LOWER(x.group_search) || '%'
        OR LOWER(gb.group_id::text) LIKE '%' || LOWER(REPLACE(x.group_search, '-', '')) || '%'
    )
),
available_groups_array AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (gf.group_id, 
                 'Group ' || SUBSTRING(gf.group_id::text, 1, 8),
                 COALESCE(gf.member_count::text, '0') || ' members',
                 gf.created_at,
                 gf.member_count)::types.q_get_eval_detail_v4_available_group
                ORDER BY gf.created_at DESC
            ),
            '{}'::types.q_get_eval_detail_v4_available_group[]
        ) as available_groups
    FROM groups_filtered gf
)
SELECT 
    up.actor_name::text as actor_name,
    NULL::uuid as eval_id,
    -- Default values for new eval (merged with draft payload if draft_id provided)
    COALESCE(
        (SELECT payload->>'name' FROM draft_payload_data),
        ''::text
    ) as name,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        ''::text
    ) as description,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'agent_ids' IS NOT NULL AND jsonb_typeof(payload->'agent_ids') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'agent_ids'))
                ELSE NULL
            END
        FROM draft_payload_data),
        ARRAY[]::text[]
    ) as agent_ids,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'model_run_ids' IS NOT NULL AND jsonb_typeof(payload->'model_run_ids') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'model_run_ids'))
                ELSE NULL
            END
        FROM draft_payload_data),
        ARRAY[]::text[]
    ) as model_run_ids,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        true::boolean
    ) as active,
    COALESCE(
        (SELECT (payload->>'dynamic')::boolean FROM draft_payload_data),
        false::boolean
    ) as dynamic,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'department_ids' IS NOT NULL AND jsonb_typeof(payload->'department_ids') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'department_ids'))
                ELSE NULL
            END
        FROM draft_payload_data),
        ARRAY[]::text[]
    ) as department_ids,
    COALESCE((SELECT ids FROM valid_dept_ids), ARRAY[]::text[]) as valid_department_ids,
    COALESCE(da.departments, '{}'::types.q_get_eval_detail_v4_department[]) as departments,
    COALESCE(eaa.eval_agents, '{}'::types.q_get_eval_detail_v4_agent[]) as eval_agents,
    COALESCE(eaa.eval_agent_ids, ARRAY[]::text[]) as valid_eval_agent_ids,
    COALESCE(aa.agents, '{}'::types.q_get_eval_detail_v4_agent[]) as agents,
    COALESCE(aa.agent_ids, ARRAY[]::text[]) as valid_agent_ids,
    COALESCE(ra.rubrics, '{}'::types.q_get_eval_detail_v4_rubric[]) as rubrics,
    COALESCE(ra.rubric_ids, ARRAY[]::text[]) as valid_rubric_ids,
    COALESCE(
        (SELECT (payload->>'use_groups')::boolean FROM draft_payload_data),
        false::boolean
    ) as use_groups,
    CASE WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) THEN true ELSE false END as can_edit,
    CASE WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) THEN true ELSE false END as can_delete,
    COALESCE(amra.available_model_runs, '{}'::types.q_get_eval_detail_v4_available_model_run[]) as available_model_runs,
    COALESCE(amra.total_count, 0) as available_model_runs_total_count,
    COALESCE(amra.page, 1) as available_model_runs_page,
    COALESCE(amra.page_size, 50) as available_model_runs_page_size,
    COALESCE(amra.total_pages, 0) as available_model_runs_total_pages,
    COALESCE(aga.available_groups, '{}'::types.q_get_eval_detail_v4_available_group[]) as available_groups,
    COALESCE((SELECT version FROM draft_payload_data), 0) as draft_version,
    COALESCE(
        (SELECT payload->'rubric_grade_agent_pairs' FROM draft_payload_data),
        '[]'::jsonb
    ) as rubric_grade_agent_pairs,
    COALESCE(
        (SELECT payload->'rubric_grade_agent_active_states' FROM draft_payload_data),
        '{}'::jsonb
    ) as rubric_grade_agent_active_states,
    COALESCE(
        (SELECT payload->'rubric_grade_agent_positions' FROM draft_payload_data),
        '[]'::jsonb
    ) as rubric_grade_agent_positions,
    COALESCE(
        (SELECT payload->'run_rubric_grade_agents' FROM draft_payload_data),
        '{}'::jsonb
    ) as run_rubric_grade_agents,
    COALESCE(
        (SELECT payload->'group_rubric_grade_agents' FROM draft_payload_data),
        '{}'::jsonb
    ) as group_rubric_grade_agents
FROM user_profile up
CROSS JOIN valid_dept_ids vdi
CROSS JOIN departments_array da
CROSS JOIN eval_agents_array eaa
CROSS JOIN agents_array aa
CROSS JOIN rubrics_array ra
LEFT JOIN available_model_runs_array amra ON (
    (SELECT available_model_runs_search FROM params) IS NOT NULL 
    OR (SELECT available_model_runs_agent_ids FROM params) IS NOT NULL
    OR COALESCE(array_length((SELECT available_model_runs_agent_ids FROM params), 1), 0) > 0
)
CROSS JOIN available_groups_array aga
$$;


--
-- Name: api_get_existing_chats_for_attempt_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_existing_chats_for_attempt_v4(attempt_id uuid) RETURNS TABLE(id uuid, completed boolean, scenario_id uuid)
    LANGUAGE sql STABLE
    AS $$
SELECT sc.id, sc.completed, sc.scenario_id
FROM attempt_chats ac
JOIN chats sc ON sc.id = ac.chat_id
WHERE ac.attempt_id = attempt_id
ORDER BY sc.created_at
$$;


--
-- Name: api_get_feedback_list_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_feedback_list_v4(profile_id uuid) RETURNS TABLE(actor_name text, feedback types.q_get_feedback_list_v4_feedback_row[])
    LANGUAGE sql STABLE
    AS $$
WITH actor_profile AS (
    SELECT 
        p.first_name || ' ' || p.last_name as actor_name
    FROM profiles p
    WHERE p.id = profile_id
),
feedback_rows AS (
    SELECT 
        f.id as feedback_id,
        f.type,
        COALESCE(f.message, '') as message,
        f.created_at,
        f.resolved,
        COALESCE(p.first_name || ' ' || p.last_name, 'Anonymous') as author_name,
        COALESCE(
            (SELECT email FROM profile_emails WHERE profile_id = f.profile_id AND is_primary = true AND active = true LIMIT 1),
            ''
        ) as author_email,
        COALESCE(
            ARRAY_AGG(pe.email ORDER BY pe.is_primary DESC, pe.created_at) FILTER (WHERE pe.active = true),
            ARRAY[]::text[]
        ) as author_emails,
        COALESCE(f.profile_id::text, '') as author_profile_id
    FROM feedback f
    LEFT JOIN profiles p ON p.id = f.profile_id
    LEFT JOIN profile_emails pe ON pe.profile_id = f.profile_id AND pe.active = true
    GROUP BY f.id, f.type, f.message, f.created_at, f.resolved, p.first_name, p.last_name, f.profile_id
    ORDER BY f.resolved ASC, f.created_at DESC
)
SELECT 
    COALESCE(ap.actor_name, '') as actor_name,
    COALESCE(
        ARRAY_AGG(
            (fr.feedback_id, fr.type, fr.message, fr.created_at, fr.resolved, fr.author_name, fr.author_email, fr.author_emails, fr.author_profile_id)::types.q_get_feedback_list_v4_feedback_row
        ),
        ARRAY[]::types.q_get_feedback_list_v4_feedback_row[]
    ) as feedback
FROM actor_profile ap
CROSS JOIN feedback_rows fr
GROUP BY ap.actor_name
$$;


--
-- Name: api_get_field_detail_v4(uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_field_detail_v4(field_id uuid, profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(field_exists boolean, field_id uuid, name text, description text, active boolean, department_ids text[], parameter_ids text[], conditional_parameter_ids text[], departments types.q_get_field_detail_v4_department[], valid_department_ids text[], parameters types.q_get_field_detail_v4_parameter[], valid_parameter_ids text[], can_edit boolean, actor_name text, draft_version integer)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT
        field_id AS field_id,
        profile_id AS profile_id,
        draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.version as draft_version,
        d.payload
    FROM params x
    LEFT JOIN drafts d ON d.id = x.draft_id
        AND d.resource_type = 'fields'::draft_resource_type
        AND d.profile_id = x.profile_id
),
field_exists_check AS (
    -- Check if field exists independently of access control
    SELECT EXISTS(
        SELECT 1 FROM fields WHERE id = (SELECT field_id FROM params)
    )::boolean as field_exists
),
user_profile AS (
    SELECT 
        up.id,
        up.role,
        COALESCE(up.first_name || ' ' || up.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles up ON up.id = x.profile_id
),
field_parameters_data AS (
    SELECT 
        pf.field_id,
        ARRAY_AGG(pf.parameter_id::text ORDER BY p.name) as parameter_ids
    FROM params x
    JOIN parameter_fields pf ON pf.field_id = x.field_id AND pf.active = true
    JOIN parameters p ON p.id = pf.parameter_id
    GROUP BY pf.field_id
),
field_conditional_parameters_data AS (
    SELECT 
        fcp.field_id,
        ARRAY_AGG(fcp.conditional_parameter_id::text ORDER BY p.name) as conditional_parameter_ids
    FROM params x
    JOIN field_conditional_parameters fcp ON fcp.field_id = x.field_id AND fcp.active = true
    JOIN parameters p ON p.id = fcp.conditional_parameter_id
    GROUP BY fcp.field_id
),
field_departments_data AS (
    SELECT 
        fd.field_id,
        ARRAY_AGG(fd.department_id::text ORDER BY fd.created_at) as department_ids
    FROM params x
    LEFT JOIN field_departments fd ON fd.field_id = x.field_id AND fd.active = true
    GROUP BY fd.field_id
),
user_departments AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.active = true
),
valid_departments_data AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM departments d
    WHERE d.id IN (SELECT department_id FROM user_departments)
       OR EXISTS (SELECT 1 FROM user_profile WHERE role = 'superadmin'::profile_role)
),
valid_parameters_data AS (
    SELECT 
        p.id as parameter_id,
        p.name,
        COALESCE(p.description, '') as description
    FROM parameters p
    WHERE p.active = true
),
user_has_field_access AS (
    SELECT EXISTS(
        SELECT 1 FROM field_departments fd
        JOIN profile_departments pd ON pd.department_id = fd.department_id
        WHERE fd.field_id = (SELECT field_id FROM params)
        AND fd.active = true
        AND pd.profile_id = (SELECT profile_id FROM params)
        AND pd.active = true
    ) OR EXISTS(
        SELECT 1 FROM params x
        JOIN profiles p ON p.id = x.profile_id
        WHERE p.role = 'superadmin'::profile_role
    ) OR (
        SELECT NOT EXISTS(
            SELECT 1 FROM field_departments fd2
            WHERE fd2.field_id = (SELECT field_id FROM params)
            AND fd2.active = true
        )
    ) as has_access
)
SELECT 
    -- Field existence check (always returned)
    fec.field_exists::boolean as field_exists,
    f.id as field_id,
    -- Merge draft payload with field data (draft takes precedence)
    COALESCE(
        (SELECT payload->>'name' FROM draft_payload_data),
        f.name
    ) as name,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        f.description
    ) as description,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        f.active
    ) as active,
    COALESCE(
        (SELECT ARRAY(SELECT jsonb_array_elements_text(payload->'departmentIds')) FROM draft_payload_data),
        fdd.department_ids,
        NULL
    ) as department_ids,
    COALESCE(fpd.parameter_ids, ARRAY[]::text[]) as parameter_ids,
    COALESCE(
        (SELECT ARRAY(SELECT jsonb_array_elements_text(payload->'conditionalParameterIds')) FROM draft_payload_data),
        fcpd.conditional_parameter_ids,
        ARRAY[]::text[]
    ) as conditional_parameter_ids,
    -- Aggregate departments
    COALESCE(
        (SELECT ARRAY_AGG(
            (vdd.department_id, vdd.name, vdd.description)::types.q_get_field_detail_v4_department
            ORDER BY vdd.name
        ) FROM valid_departments_data vdd),
        '{}'::types.q_get_field_detail_v4_department[]
    ) as departments,
    -- Valid department IDs
    (SELECT COALESCE(array_agg(department_id::text), ARRAY[]::text[])
     FROM valid_departments_data) as valid_department_ids,
    -- Aggregate parameters
    COALESCE(
        (SELECT ARRAY_AGG(
            (vpd.parameter_id, vpd.name, vpd.description)::types.q_get_field_detail_v4_parameter
            ORDER BY vpd.name
        ) FROM valid_parameters_data vpd),
        '{}'::types.q_get_field_detail_v4_parameter[]
    ) as parameters,
    -- Valid parameter IDs
    (SELECT COALESCE(array_agg(parameter_id::text), ARRAY[]::text[])
     FROM valid_parameters_data) as valid_parameter_ids,
    CASE 
        WHEN COALESCE(fdd.department_ids, NULL) IS NULL AND up.role != 'superadmin' THEN false
        WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
        ELSE false
    END as can_edit,
    up.actor_name,
    -- Draft version
    COALESCE((SELECT draft_version FROM draft_payload_data), 0) as draft_version
FROM field_exists_check fec
CROSS JOIN user_profile up
LEFT JOIN params x ON true
LEFT JOIN fields f ON f.id = x.field_id AND f.active = true
LEFT JOIN field_departments_data fdd ON fdd.field_id = f.id
LEFT JOIN field_parameters_data fpd ON fpd.field_id = f.id
LEFT JOIN field_conditional_parameters_data fcpd ON fcpd.field_id = f.id
CROSS JOIN user_has_field_access uha
LEFT JOIN draft_payload_data dpd ON true
WHERE uha.has_access = true OR fec.field_exists = false
$$;


--
-- Name: api_get_field_new_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_field_new_v4(profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(valid_department_ids text[], departments types.q_get_field_new_v4_department[], valid_parameter_ids text[], parameters types.q_get_field_new_v4_parameter[], user_role text, primary_department_id uuid, actor_name text, draft_version integer, name text, description text, active boolean, department_ids text[], conditional_parameter_ids text[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        profile_id AS profile_id,
        draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.version as draft_version,
        d.payload
    FROM params x
    LEFT JOIN drafts d ON d.id = x.draft_id
        AND d.resource_type = 'fields'::draft_resource_type
        AND d.profile_id = x.profile_id
),
user_profile AS (
    SELECT 
        up.id,
        up.role,
        COALESCE(up.first_name || ' ' || up.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles up ON up.id = x.profile_id
),
user_departments AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.active = true
),
valid_departments_data AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM departments d
    WHERE d.id IN (SELECT department_id FROM user_departments)
       OR EXISTS (SELECT 1 FROM user_profile WHERE role = 'superadmin')
),
valid_parameters_data AS (
    SELECT 
        p.id as parameter_id,
        p.name,
        COALESCE(p.description, '') as description
    FROM parameters p
    WHERE p.active = true
),
primary_department_data AS (
    SELECT 
        pd.department_id as primary_department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.active = true
    ORDER BY pd.created_at
    LIMIT 1
)
SELECT 
    -- Valid department IDs
    (SELECT COALESCE(array_agg(department_id::text), ARRAY[]::text[])
     FROM valid_departments_data) as valid_department_ids,
    -- Aggregate departments
    COALESCE(
        (SELECT ARRAY_AGG(
            (vdd.department_id, vdd.name, vdd.description)::types.q_get_field_new_v4_department
            ORDER BY vdd.name
        ) FROM valid_departments_data vdd),
        '{}'::types.q_get_field_new_v4_department[]
    ) as departments,
    -- Valid parameter IDs
    (SELECT COALESCE(array_agg(parameter_id::text), ARRAY[]::text[])
     FROM valid_parameters_data) as valid_parameter_ids,
    -- Aggregate parameters
    COALESCE(
        (SELECT ARRAY_AGG(
            (vpd.parameter_id, vpd.name, vpd.description)::types.q_get_field_new_v4_parameter
            ORDER BY vpd.name
        ) FROM valid_parameters_data vpd),
        '{}'::types.q_get_field_new_v4_parameter[]
    ) as parameters,
    up.role::text as user_role,
    pdd.primary_department_id,
    up.actor_name,
    -- Draft fields
    COALESCE((SELECT draft_version FROM draft_payload_data), 0) as draft_version,
    COALESCE(
        (SELECT payload->>'name' FROM draft_payload_data),
        'New Field'
    ) as name,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        ''
    ) as description,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        true
    ) as active,
    COALESCE(
        (SELECT ARRAY(SELECT jsonb_array_elements_text(payload->'departmentIds')) FROM draft_payload_data),
        ARRAY[]::text[]
    ) as department_ids,
    COALESCE(
        (SELECT ARRAY(SELECT jsonb_array_elements_text(payload->'conditionalParameterIds')) FROM draft_payload_data),
        ARRAY[]::text[]
    ) as conditional_parameter_ids
FROM user_profile up
LEFT JOIN primary_department_data pdd ON true
LEFT JOIN draft_payload_data dpd ON true
$$;


--
-- Name: api_get_group_order_agents_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_group_order_agents_v4(group_id uuid) RETURNS TABLE(agent_id uuid, position_idx integer)
    LANGUAGE sql STABLE
    AS $$
SELECT 
    go.agent_id::uuid,
    go.position_idx
FROM group_order go
WHERE go.group_id = api_get_group_order_agents_v4.group_id
ORDER BY go.position_idx ASC
$$;


--
-- Name: api_get_group_stop_tools_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_group_stop_tools_v4(group_id uuid) RETURNS TABLE(tool_id uuid, position_idx integer)
    LANGUAGE sql STABLE
    AS $$
SELECT 
    gs.tool_id::uuid,
    gs.position_idx
FROM group_stop gs
WHERE gs.group_id = api_get_group_stop_tools_v4.group_id
ORDER BY gs.position_idx ASC
$$;


--
-- Name: api_get_health_bundle_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_health_bundle_v4(profile_id uuid DEFAULT NULL::uuid) RETURNS TABLE(actor_name text, health_kpis types.q_get_health_bundle_v4_health_kpis, metrics types.q_get_health_bundle_v4_metrics_data_point[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id
),
-- Current health status for each service (latest record per service)
current_health AS (
    SELECT DISTINCT ON (service)
        service,
        ok,
        latency_ms,
        error,
        ts
    FROM service_health
    WHERE service IN ('websocket', 'redis', 'tus', 'database', 'keycloak')
    ORDER BY service, ts DESC
),

-- Health trend data for each service (last 7 days, aggregated by hour)
health_trends AS (
    SELECT 
        service,
        date_trunc('hour', ts) as date_hour,
        COUNT(*) FILTER (WHERE ok = true)::float / NULLIF(COUNT(*), 0) * 100.0 as uptime_percent,
        AVG(latency_ms) as avg_latency_ms,
        COUNT(*) as check_count
    FROM service_health
    WHERE service IN ('websocket', 'redis', 'tus', 'database', 'keycloak')
      AND ts >= NOW() - INTERVAL '7 days'
    GROUP BY service, date_hour
    ORDER BY service, date_hour
),

-- Health trend data formatted for each service
websocket_trend AS (
    SELECT 
        to_char(date_hour, 'YYYY-MM-DD HH24:MI:SS') as date,
        ROUND(uptime_percent::numeric, 2)::float as value,
        ROUND(avg_latency_ms::numeric, 2)::float as latency,
        check_count::int as count
    FROM health_trends
    WHERE service = 'websocket'
    ORDER BY date_hour
),

redis_trend AS (
    SELECT 
        to_char(date_hour, 'YYYY-MM-DD HH24:MI:SS') as date,
        ROUND(uptime_percent::numeric, 2)::float as value,
        ROUND(avg_latency_ms::numeric, 2)::float as latency,
        check_count::int as count
    FROM health_trends
    WHERE service = 'redis'
    ORDER BY date_hour
),

document_trend AS (
    SELECT 
        to_char(date_hour, 'YYYY-MM-DD HH24:MI:SS') as date,
        ROUND(uptime_percent::numeric, 2)::float as value,
        ROUND(avg_latency_ms::numeric, 2)::float as latency,
        check_count::int as count
    FROM health_trends
    WHERE service = 'tus'
    ORDER BY date_hour
),

database_trend AS (
    SELECT 
        to_char(date_hour, 'YYYY-MM-DD HH24:MI:SS') as date,
        ROUND(uptime_percent::numeric, 2)::float as value,
        ROUND(avg_latency_ms::numeric, 2)::float as latency,
        check_count::int as count
    FROM health_trends
    WHERE service = 'database'
    ORDER BY date_hour
),

authentication_trend AS (
    SELECT 
        to_char(date_hour, 'YYYY-MM-DD HH24:MI:SS') as date,
        ROUND(uptime_percent::numeric, 2)::float as value,
        ROUND(avg_latency_ms::numeric, 2)::float as latency,
        check_count::int as count
    FROM health_trends
    WHERE service = 'keycloak'
    ORDER BY date_hour
),

-- Build health KPIs with composite types
websocket_kpi AS (
    SELECT 
        COALESCE((SELECT ok FROM current_health WHERE service = 'websocket' LIMIT 1), false) as ok,
        COALESCE(ROUND((SELECT latency_ms FROM current_health WHERE service = 'websocket' LIMIT 1)::numeric, 2)::float, 0.0) as latency_ms,
        COALESCE((SELECT error FROM current_health WHERE service = 'websocket' LIMIT 1), 'No data') as error,
        COALESCE(
            (SELECT ARRAY_AGG(
                (wt.date, wt.value, wt.latency, wt.count)::types.q_get_health_bundle_v4_trend_data
                ORDER BY wt.date
            ) FROM websocket_trend wt),
            '{}'::types.q_get_health_bundle_v4_trend_data[]
        ) as trend
),

redis_kpi AS (
    SELECT 
        COALESCE((SELECT ok FROM current_health WHERE service = 'redis' LIMIT 1), false) as ok,
        COALESCE(ROUND((SELECT latency_ms FROM current_health WHERE service = 'redis' LIMIT 1)::numeric, 2)::float, 0.0) as latency_ms,
        COALESCE((SELECT error FROM current_health WHERE service = 'redis' LIMIT 1), 'No data') as error,
        COALESCE(
            (SELECT ARRAY_AGG(
                (rt.date, rt.value, rt.latency, rt.count)::types.q_get_health_bundle_v4_trend_data
                ORDER BY rt.date
            ) FROM redis_trend rt),
            '{}'::types.q_get_health_bundle_v4_trend_data[]
        ) as trend
),

document_kpi AS (
    SELECT 
        COALESCE((SELECT ok FROM current_health WHERE service = 'tus' LIMIT 1), false) as ok,
        COALESCE(ROUND((SELECT latency_ms FROM current_health WHERE service = 'tus' LIMIT 1)::numeric, 2)::float, 0.0) as latency_ms,
        COALESCE((SELECT error FROM current_health WHERE service = 'tus' LIMIT 1), 'No data') as error,
        COALESCE(
            (SELECT ARRAY_AGG(
                (dt.date, dt.value, dt.latency, dt.count)::types.q_get_health_bundle_v4_trend_data
                ORDER BY dt.date
            ) FROM document_trend dt),
            '{}'::types.q_get_health_bundle_v4_trend_data[]
        ) as trend
),

database_kpi AS (
    SELECT 
        COALESCE((SELECT ok FROM current_health WHERE service = 'database' LIMIT 1), false) as ok,
        COALESCE(ROUND((SELECT latency_ms FROM current_health WHERE service = 'database' LIMIT 1)::numeric, 2)::float, 0.0) as latency_ms,
        COALESCE((SELECT error FROM current_health WHERE service = 'database' LIMIT 1), 'No data') as error,
        COALESCE(
            (SELECT ARRAY_AGG(
                (dbt.date, dbt.value, dbt.latency, dbt.count)::types.q_get_health_bundle_v4_trend_data
                ORDER BY dbt.date
            ) FROM database_trend dbt),
            '{}'::types.q_get_health_bundle_v4_trend_data[]
        ) as trend
),

authentication_kpi AS (
    SELECT 
        COALESCE((SELECT ok FROM current_health WHERE service = 'keycloak' LIMIT 1), false) as ok,
        COALESCE(ROUND((SELECT latency_ms FROM current_health WHERE service = 'keycloak' LIMIT 1)::numeric, 2)::float, 0.0) as latency_ms,
        COALESCE((SELECT error FROM current_health WHERE service = 'keycloak' LIMIT 1), 'No data') as error,
        COALESCE(
            (SELECT ARRAY_AGG(
                (at.date, at.value, at.latency, at.count)::types.q_get_health_bundle_v4_trend_data
                ORDER BY at.date
            ) FROM authentication_trend at),
            '{}'::types.q_get_health_bundle_v4_trend_data[]
        ) as trend
),

-- App metrics time series (last 7 days, aggregated by hour)
metrics_trend AS (
    SELECT 
        date_trunc('hour', ts) as date_hour,
        AVG(cpu_percent) as avg_cpu_percent,
        AVG(avg_latency_ms) as avg_latency_ms,
        AVG(memory_bytes) as avg_memory_bytes,
        MAX(requests_total) as max_requests_total,
        MAX(errors_total) as max_errors_total,
        COUNT(*) as sample_count
    FROM app_metrics
    WHERE ts >= NOW() - INTERVAL '7 days'
    GROUP BY date_hour
    ORDER BY date_hour
),
health_kpis_row AS (
    SELECT 
        (
            (SELECT (ok, latency_ms, error, trend)::types.q_get_health_bundle_v4_health_kpi FROM websocket_kpi LIMIT 1),
            (SELECT (ok, latency_ms, error, trend)::types.q_get_health_bundle_v4_health_kpi FROM redis_kpi LIMIT 1),
            (SELECT (ok, latency_ms, error, trend)::types.q_get_health_bundle_v4_health_kpi FROM document_kpi LIMIT 1),
            (SELECT (ok, latency_ms, error, trend)::types.q_get_health_bundle_v4_health_kpi FROM database_kpi LIMIT 1),
            (SELECT (ok, latency_ms, error, trend)::types.q_get_health_bundle_v4_health_kpi FROM authentication_kpi LIMIT 1)
        )::types.q_get_health_bundle_v4_health_kpis as health_kpis
),
actor_profile AS (
    SELECT COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM profiles
    WHERE id = (SELECT profile_id FROM params)
    LIMIT 1
)
SELECT 
    COALESCE((SELECT actor_name FROM actor_profile), 'System')::text as actor_name,
    (SELECT health_kpis FROM health_kpis_row) as health_kpis,
    COALESCE(
        ARRAY_AGG(
            (
                to_char(mt.date_hour, 'YYYY-MM-DD HH24:MI:SS'),
                ROUND(mt.avg_cpu_percent::numeric, 2)::float,
                ROUND(mt.avg_latency_ms::numeric, 2)::float,
                ROUND(mt.avg_memory_bytes::numeric, 0)::bigint,
                mt.max_requests_total,
                mt.max_errors_total,
                mt.sample_count
            )::types.q_get_health_bundle_v4_metrics_data_point
            ORDER BY mt.date_hour
        ),
        '{}'::types.q_get_health_bundle_v4_metrics_data_point[]
    ) as metrics
FROM metrics_trend mt
$$;


--
-- Name: api_get_home_history_v4(text, text, uuid, uuid[], uuid[], public.profile_role[], text[], text, uuid[], uuid[], uuid[], boolean, text, text, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_home_history_v4(start_date text, end_date text, profile_id uuid, cohort_ids uuid[] DEFAULT ARRAY[]::uuid[], department_ids uuid[] DEFAULT ARRAY[]::uuid[], roles public.profile_role[] DEFAULT ARRAY[]::public.profile_role[], simulation_filters text[] DEFAULT ARRAY[]::text[], search text DEFAULT NULL::text, profile_ids uuid[] DEFAULT ARRAY[]::uuid[], simulation_ids uuid[] DEFAULT ARRAY[]::uuid[], scenario_ids uuid[] DEFAULT ARRAY[]::uuid[], infinite_mode boolean DEFAULT NULL::boolean, sort_by text DEFAULT 'date'::text, sort_order text DEFAULT 'desc'::text, page integer DEFAULT 0, page_size integer DEFAULT 20) RETURNS TABLE(actor_name text, data types.q_get_home_history_v4_attempt_history_row[], total_count integer, page integer, page_size integer, total_pages integer, profile_options types.q_get_home_history_v4_option[], simulation_options types.q_get_home_history_v4_option[], scenario_options types.q_get_home_history_v4_option[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        start_date::timestamptz AS start_date,
        end_date::timestamptz AS end_date,
        profile_id AS profile_id,
        COALESCE(cohort_ids, ARRAY[]::uuid[]) AS cohort_ids,
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids,
        COALESCE(roles, ARRAY[]::profile_role[]) AS roles,
        COALESCE(simulation_filters, ARRAY[]::text[]) AS simulation_filters,
        search AS search,
        COALESCE(profile_ids, ARRAY[]::uuid[]) AS profile_ids,
        COALESCE(simulation_ids, ARRAY[]::uuid[]) AS simulation_ids,
        COALESCE(scenario_ids, ARRAY[]::uuid[]) AS scenario_ids,
        infinite_mode AS infinite_mode,
        COALESCE(sort_by, 'date') AS sort_by,
        COALESCE(sort_order, 'desc') AS sort_order,
        COALESCE(page, 0) AS page,
        COALESCE(page_size, 20) AS page_size,
        (COALESCE(page, 0) * COALESCE(page_size, 20)) AS offset_count
),
resolve_profile_id AS (
    SELECT 
        CASE 
            WHEN (SELECT profile_id FROM params)::text IS NULL OR (SELECT profile_id FROM params)::text = '' THEN NULL::uuid
            ELSE (SELECT profile_id FROM params)::uuid
        END as resolved_profile_id
),
-- Expanded cohort list: union of provided cohortIds + profileId cohorts
expanded_history_cohort_ids AS (
    SELECT DISTINCT cohort_id
    FROM (
        SELECT unnest((SELECT cohort_ids FROM params)) as cohort_id
        WHERE cardinality((SELECT cohort_ids FROM params)) > 0
        UNION
        SELECT cp.cohort_id
        FROM resolve_profile_id rpi
        JOIN cohort_profiles cp ON cp.profile_id = rpi.resolved_profile_id
    ) combined
),
-- Filter attempts by date, profile, cohorts, departments
history_attempts AS (
    SELECT DISTINCT
        sa.id AS attempt_id,
        sa.simulation_id,
        sa.created_at AS attempt_date,
        sa.archived AS is_archived,
        sa.infinite_mode,
        ap.profile_id,
        sim.title AS simulation_name,
        sim.practice_simulation,
        COALESCE(sdd.department_ids, NULL) as department_ids
    FROM params p
    CROSS JOIN simulation_attempts sa
    JOIN attempt_profiles ap ON ap.attempt_id = sa.id AND ap.active = TRUE
    JOIN simulations sim ON sim.id = sa.simulation_id
    JOIN profiles p_attempt ON p_attempt.id = ap.profile_id
    LEFT JOIN (
        SELECT 
            sd.simulation_id,
            ARRAY_AGG(sd.department_id::text ORDER BY sd.created_at) as department_ids
        FROM simulation_departments sd
        WHERE sd.active = true
        GROUP BY sd.simulation_id
    ) sdd ON sdd.simulation_id = sim.id
    CROSS JOIN resolve_profile_id rpi
    WHERE sa.created_at >= p.start_date
      AND sa.created_at <= p.end_date
      -- Profile_id is always non-null for home history - always filter by it
      AND ap.profile_id = rpi.resolved_profile_id
      -- Simulation type filtering: general (practice_simulation = FALSE), practice (practice_simulation = TRUE), archived (archived = TRUE)
      -- If no filters provided (NULL or empty), default to general only (matching old behavior: sim.practice_simulation = FALSE)
      AND (
        (cardinality(p.simulation_filters) = 0) AND sim.practice_simulation = FALSE
        OR
        (cardinality(p.simulation_filters) > 0 AND (
          ('general' = ANY(p.simulation_filters) AND sim.practice_simulation = FALSE) OR
          ('practice' = ANY(p.simulation_filters) AND sim.practice_simulation = TRUE) OR
          ('archived' = ANY(p.simulation_filters) AND sa.archived = TRUE)
        ))
      )
      -- Exclude archived attempts unless 'archived' is explicitly in the filter list
      AND (
        cardinality(p.simulation_filters) = 0 OR 'archived' = ANY(p.simulation_filters) OR sa.archived = FALSE
      )
      AND (cardinality(p.department_ids) = 0 OR sdd.department_ids IS NULL OR sdd.department_ids && p.department_ids::text[])
),
-- Get cohorts for each attempt's profile (includes inactive links for history)
history_attempt_cohorts AS (
    SELECT
        ha.attempt_id,
        COALESCE(ARRAY_AGG(DISTINCT c.id) FILTER (WHERE c.id IS NOT NULL AND cs.simulation_id = ha.simulation_id), ARRAY[]::uuid[]) AS cohort_ids,
        COALESCE(ARRAY_AGG(DISTINCT c.title) FILTER (WHERE c.id IS NOT NULL AND cs.simulation_id = ha.simulation_id), ARRAY[]::text[]) AS cohort_names
    FROM history_attempts ha
    LEFT JOIN cohort_profiles cp ON cp.profile_id = ha.profile_id
    LEFT JOIN cohorts c ON c.id = cp.cohort_id AND c.active = TRUE
    LEFT JOIN cohort_simulations cs ON cs.cohort_id = c.id
    WHERE (
        -- If no cohort filter, include all attempts
        (SELECT COUNT(*) FROM expanded_history_cohort_ids) = 0
        -- Otherwise, only include cohorts in the expanded list
        OR c.id IN (SELECT cohort_id FROM expanded_history_cohort_ids)
    )
    GROUP BY ha.attempt_id
),
-- Filter attempts by cohort membership (uses expanded cohort list)
history_attempts_filtered AS (
    SELECT ha.*
    FROM history_attempts ha
    JOIN history_attempt_cohorts hac ON hac.attempt_id = ha.attempt_id
    WHERE (
        -- If no cohort filter, include all attempts
        (SELECT COUNT(*) FROM expanded_history_cohort_ids) = 0
        -- Otherwise, only include attempts with matching cohorts
        OR cardinality(hac.cohort_ids) > 0
    )
),
-- Get all unique profile options from filtered attempts (before history-specific filters)
profile_options_cte AS (
    SELECT 
        haf.profile_id,
        p.first_name || ' ' || p.last_name AS profile_name,
        COUNT(DISTINCT haf.attempt_id) AS count
    FROM history_attempts_filtered haf
    JOIN profiles p ON p.id = haf.profile_id
    GROUP BY haf.profile_id, p.first_name, p.last_name
    ORDER BY profile_name
),
-- Get all unique simulation options from filtered attempts (before history-specific filters)
simulation_options_cte AS (
    SELECT 
        haf.simulation_id,
        s.title AS simulation_name,
        COUNT(DISTINCT haf.attempt_id) AS count
    FROM history_attempts_filtered haf
    JOIN simulations s ON s.id = haf.simulation_id
    GROUP BY haf.simulation_id, s.title
    ORDER BY simulation_name
),
-- Get all unique scenario options from filtered attempts (before history-specific filters)
scenario_options_cte AS (
    SELECT 
        sc.scenario_id,
        s.name AS scenario_title,
        COUNT(DISTINCT haf.attempt_id) AS count
    FROM history_attempts_filtered haf
    JOIN attempt_chats ac ON ac.attempt_id = haf.attempt_id
    JOIN chats sc ON sc.id = ac.chat_id
    JOIN scenarios s ON s.id = sc.scenario_id
    WHERE sc.scenario_id IS NOT NULL
    GROUP BY sc.scenario_id, s.name
    ORDER BY scenario_title
),
-- Apply additional filters (profileIds, simulationIds, scenarioIds, infiniteMode)
history_attempts_with_filters AS (
    SELECT haf.*
    FROM params p
    CROSS JOIN history_attempts_filtered haf
    WHERE 
        -- Profile filter
        (cardinality(p.profile_ids) = 0 OR haf.profile_id = ANY(p.profile_ids))
        -- Simulation filter
        AND (cardinality(p.simulation_ids) = 0 OR haf.simulation_id = ANY(p.simulation_ids))
        -- Infinite mode filter
        AND (p.infinite_mode IS NULL OR haf.infinite_mode = p.infinite_mode)
),
-- Get scenario IDs for each attempt (for scenario filtering)
attempt_scenario_ids AS (
    SELECT DISTINCT
        ac.attempt_id,
        ARRAY_AGG(DISTINCT sc.scenario_id) FILTER (WHERE sc.scenario_id IS NOT NULL) AS scenario_ids
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_with_filters)
    GROUP BY ac.attempt_id
),
-- Apply scenario filter
history_attempts_final AS (
    SELECT haf.*
    FROM params p
    CROSS JOIN history_attempts_with_filters haf
    LEFT JOIN attempt_scenario_ids asi ON asi.attempt_id = haf.attempt_id
    WHERE 
        -- Scenario filter (if any scenario matches, include the attempt)
        (cardinality(p.scenario_ids) = 0 OR asi.scenario_ids IS NULL OR asi.scenario_ids && p.scenario_ids)
),
-- Aggregate chats per attempt
history_chat_rollup AS (
    SELECT
        ac.attempt_id,
        COUNT(*) FILTER (WHERE sc.completed) AS completed_chats,
        COUNT(*) FILTER (WHERE sc.completed = FALSE) AS incomplete_chats,
        MIN(sc.created_at) AS first_chat_at,
        MAX(sc.created_at) AS last_activity_at,
        array_agg(DISTINCT sc.scenario_id) FILTER (WHERE sc.scenario_id IS NOT NULL) AS scenario_ids_seen
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
    GROUP BY ac.attempt_id
),
-- Get latest grade per chat
history_chat_grades AS (
    SELECT DISTINCT ON (c.id)
        c.id AS chat_id,
        scg.score,
        rga.rubric_id
    FROM grades scg
    LEFT JOIN rubric_grade_agents rga ON rga.id = scg.rubric_grade_agent_id
    JOIN runs r ON r.id = scg.run_id
    JOIN group_runs gr ON gr.run_id = r.id
    JOIN grade_groups gg ON gg.group_id = gr.group_id
    JOIN chats c ON c.id = gg.chat_id
    WHERE EXISTS (
        SELECT 1 FROM runs r_check
        JOIN group_runs gr_check ON gr_check.run_id = r_check.id
        JOIN grade_groups gg_check ON gg_check.group_id = gr_check.group_id
        JOIN chats c_check ON c_check.id = gg_check.chat_id
        WHERE r_check.id = scg.run_id
    )
      AND c.id IN (
        SELECT sc.id FROM attempt_chats ac
        JOIN chats sc ON sc.id = ac.chat_id
        WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
    )
    ORDER BY c.id, scg.created_at DESC
),
-- Get first scenario's rubric per simulation (fallback when chat scenario doesn't match)
sim_first_scenario_rubric AS (
    SELECT DISTINCT ON (ss.simulation_id)
        ss.simulation_id,
        rga.rubric_id,
        r.points
    FROM simulation_scenarios ss
    LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
    LEFT JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
    LEFT JOIN rubrics r ON r.id = rga.rubric_id
    WHERE ss.active = true
      AND ss.simulation_id IN (SELECT DISTINCT simulation_id FROM history_attempts_final)
    ORDER BY ss.simulation_id, ss.position
),
-- Aggregate grades per attempt
history_grade_rollup AS (
    SELECT
        ac.attempt_id,
        COUNT(*) FILTER (WHERE hcg.score IS NOT NULL) AS completed_with_grade,
        SUM(CASE WHEN hcg.score IS NOT NULL AND COALESCE(r.points, r_fallback_scenario.points, r_fallback_first.points, 0) > 0
            THEN (hcg.score / COALESCE(r.points, r_fallback_scenario.points, r_fallback_first.points, 1)::numeric * 100.0)
            ELSE 0 END) AS sum_grade_percent
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    JOIN simulation_attempts sa ON sa.id = ac.attempt_id
    LEFT JOIN history_chat_grades hcg ON hcg.chat_id = sc.id
    LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga_fallback_scenario ON ssrga_fallback_scenario.simulation_id = sa.simulation_id
      AND ssrga_fallback_scenario.scenario_id = sc.scenario_id
      AND hcg.chat_id IS NOT NULL
      AND hcg.rubric_id IS NULL
    LEFT JOIN rubric_grade_agents rga_fallback_scenario ON rga_fallback_scenario.id = ssrga_fallback_scenario.rubric_grade_agent_id
    LEFT JOIN rubrics r ON r.id = hcg.rubric_id
    LEFT JOIN rubrics r_fallback_scenario ON r_fallback_scenario.id = rga_fallback_scenario.rubric_id
    LEFT JOIN sim_first_scenario_rubric sfsr ON sfsr.simulation_id = sa.simulation_id
      AND hcg.chat_id IS NOT NULL
      AND hcg.rubric_id IS NULL
      AND r_fallback_scenario.points IS NULL
    LEFT JOIN rubrics r_fallback_first ON r_fallback_first.id = sfsr.rubric_id
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
    GROUP BY ac.attempt_id
),
-- Calculate elapsed time per attempt (for infinite mode time limit checks)
history_elapsed_time AS (
    SELECT
        ac.attempt_id,
        COALESCE(
            SUM(
                CASE 
                    WHEN sc.completed AND hcg.chat_id IS NOT NULL THEN
                        (SELECT scg.time_taken FROM grades scg 
                         JOIN runs r ON r.id = scg.run_id
                         JOIN group_runs gr ON gr.run_id = r.id
                         JOIN grade_groups gg ON gg.group_id = gr.group_id
                         JOIN chats c ON c.id = gg.chat_id
                         WHERE c.id = sc.id 
                           AND EXISTS (
                               SELECT 1 FROM runs r_check
                               JOIN group_runs gr_check ON gr_check.run_id = r_check.id
                               JOIN grade_groups gg_check ON gg_check.group_id = gr_check.group_id
                               JOIN chats c_check ON c_check.id = gg_check.chat_id
                               WHERE r_check.id = scg.run_id
                           )
                         ORDER BY scg.created_at DESC LIMIT 1)
                    WHEN sc.completed THEN
                        EXTRACT(EPOCH FROM (
                            (SELECT scg.created_at FROM grades scg 
                             JOIN runs r ON r.id = scg.run_id
                             JOIN group_runs gr ON gr.run_id = r.id
                             JOIN grade_groups gg ON gg.group_id = gr.group_id
                             JOIN chats c ON c.id = gg.chat_id
                             WHERE c.id = sc.id 
                               AND EXISTS (
                                   SELECT 1 FROM runs r_check
                                   JOIN group_runs gr_check ON gr_check.run_id = r_check.id
                                   JOIN grade_groups gg_check ON gg_check.group_id = gr_check.group_id
                                   JOIN chats c_check ON c_check.id = gg_check.chat_id
                                   WHERE r_check.id = scg.run_id
                               )
                             ORDER BY scg.created_at DESC LIMIT 1) - sc.created_at
                        ))::integer
                    ELSE
                        EXTRACT(EPOCH FROM (NOW() - sc.created_at))::integer
                END
            ),
            0
        ) AS elapsed_seconds
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    LEFT JOIN history_chat_grades hcg ON hcg.chat_id = sc.id
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
    GROUP BY ac.attempt_id
),
-- Get personas for each attempt
history_personas AS (
    SELECT
        ac.attempt_id,
        array_agg(DISTINCT sp.persona_id) FILTER (WHERE sp.persona_id IS NOT NULL) AS persona_ids
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    JOIN scenarios scn ON scn.id = sc.scenario_id
    LEFT JOIN scenario_personas sp ON sp.scenario_id = scn.id AND sp.active = TRUE
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
    GROUP BY ac.attempt_id
),
-- Count scenarios per simulation
history_sim_scenario_count AS (
    SELECT
        s.id AS simulation_id,
        COUNT(ss.scenario_id)::int AS scenario_count
    FROM simulations s
    LEFT JOIN simulation_scenarios ss ON ss.simulation_id = s.id
    WHERE s.id IN (SELECT simulation_id FROM history_attempts_final)
    GROUP BY s.id
),
-- Get scenario info
history_scenario_ids AS (
    SELECT
        s.id AS simulation_id,
        ARRAY_AGG(ss.scenario_id ORDER BY ss.position)::uuid[] AS scenario_ids_assigned
    FROM simulations s
    LEFT JOIN simulation_scenarios ss ON ss.simulation_id = s.id
    WHERE s.id IN (SELECT simulation_id FROM history_attempts_final)
    GROUP BY s.id
),
-- Get first scenario_id from each attempt's first chat (for practice scenario retry)
history_first_scenario AS (
    SELECT DISTINCT ON (ac.attempt_id)
        ac.attempt_id,
        sc.scenario_id AS practice_scenario_id
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
    ORDER BY ac.attempt_id, sc.created_at ASC
),
-- Join all history data
attempt_rollup AS (
    SELECT
        haf.attempt_id,
        haf.simulation_id,
        haf.attempt_date,
        haf.is_archived,
        haf.infinite_mode,
        haf.profile_id,
        haf.simulation_name,
        haf.practice_simulation,
        haf.department_ids,
        COALESCE(hcr.first_chat_at, haf.attempt_date) AS first_chat_at,
        COALESCE(hcr.last_activity_at, haf.attempt_date) AS last_activity_at,
        COALESCE(hgr.completed_with_grade, 0) AS completed_with_grade,
        COALESCE(hssc.scenario_count, 0) AS sim_scenario_count,
        COALESCE(hgr.sum_grade_percent, 0) AS sum_grade_percent_zero_fill,
        COALESCE(hp.persona_ids, ARRAY[]::uuid[]) AS persona_ids_distinct,
        COALESCE(hcr.scenario_ids_seen, ARRAY[]::uuid[]) AS leaf_scenarios_seen,
        COALESCE(hcr.incomplete_chats, 0) AS incomplete_chats,
        COALESCE(het.elapsed_seconds, 0) AS elapsed_seconds,
        hfs.practice_scenario_id
    FROM history_attempts_final haf
    LEFT JOIN history_chat_rollup hcr ON hcr.attempt_id = haf.attempt_id
    LEFT JOIN history_grade_rollup hgr ON hgr.attempt_id = haf.attempt_id
    LEFT JOIN history_personas hp ON hp.attempt_id = haf.attempt_id
    LEFT JOIN history_sim_scenario_count hssc ON hssc.simulation_id = haf.simulation_id
    LEFT JOIN history_elapsed_time het ON het.attempt_id = haf.attempt_id
    LEFT JOIN history_first_scenario hfs ON hfs.attempt_id = haf.attempt_id
),
attempt_cohort_ids AS (
    SELECT
        attempt_id,
        cohort_ids AS profile_cohort_ids
    FROM history_attempt_cohorts
    WHERE attempt_id IN (SELECT attempt_id FROM history_attempts_final)
),
-- Get rubric data per simulation (one row per simulation)
simulation_rubrics AS (
    SELECT DISTINCT ON (ss.simulation_id)
        ss.simulation_id,
        r.id AS rubric_id,
        r.points AS rubric_points,
        r.pass_points AS rubric_pass_points
    FROM simulation_scenarios ss
    LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
    LEFT JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
    LEFT JOIN rubrics r ON r.id = rga.rubric_id
    WHERE ss.active = true
      AND ss.simulation_id IN (SELECT DISTINCT simulation_id FROM attempt_rollup)
    ORDER BY ss.simulation_id, ss.position
),
attempt_joined AS (
    SELECT
        ar.*,
        hsi.scenario_ids_assigned,
        sr.rubric_id,
        sr.rubric_points,
        sr.rubric_pass_points,
        CASE
            WHEN sr.rubric_points IS NULL OR sr.rubric_points = 0 THEN NULL
            ELSE ROUND((sr.rubric_pass_points::numeric / sr.rubric_points::numeric) * 100.0)::int
        END AS pass_pct,
        (p.first_name || ' ' || p.last_name) AS profile_name,
        COALESCE(
            (SELECT SUM(stl.time_limit_seconds)
             FROM scenario_time_limits stl
             JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
             WHERE stl.simulation_id = s.id AND stl.active = true AND ss.active = true),
            0
        ) as time_limit_seconds
    FROM attempt_rollup ar
    JOIN simulations s ON s.id = ar.simulation_id
    LEFT JOIN history_scenario_ids hsi ON hsi.simulation_id = ar.simulation_id
    LEFT JOIN simulation_rubrics sr ON sr.simulation_id = s.id
    JOIN profiles p ON p.id = ar.profile_id
),
attempt_cohort_names AS (
    SELECT
        attempt_id,
        cohort_names
    FROM history_attempt_cohorts
    WHERE attempt_id IN (SELECT attempt_id FROM history_attempts_final)
),
final_rows AS (
    SELECT
        aj.attempt_id,
        aj.simulation_id,
        aj.profile_id,
        aj.profile_name,
        aj.simulation_name,
        aj.scenario_ids_assigned,
        aj.is_archived,
        aj.practice_simulation,
        aj.pass_pct,
        aj.infinite_mode,
        aj.attempt_date,
        aj.department_ids,
        aj.practice_scenario_id,
        CASE WHEN aj.infinite_mode THEN NULL ELSE COALESCE(aj.sim_scenario_count, 0) END AS num_scenarios,
        COALESCE(aj.completed_with_grade, 0) AS num_scenarios_completed,
        CASE
            WHEN aj.infinite_mode THEN
                CASE GREATEST(array_length(aj.leaf_scenarios_seen, 1), 0)
                    WHEN 0 THEN NULL
                    ELSE ROUND(aj.sum_grade_percent_zero_fill / GREATEST(array_length(aj.leaf_scenarios_seen, 1), 1))::int
                END
            ELSE
                CASE COALESCE(aj.sim_scenario_count, 0)
                    WHEN 0 THEN NULL
                    ELSE CASE
                            WHEN aj.completed_with_grade = 0 THEN NULL
                            ELSE ROUND(aj.sum_grade_percent_zero_fill / NULLIF(aj.sim_scenario_count, 0))::int
                        END
                END
        END AS score_percent,
        CASE
            WHEN aj.infinite_mode THEN
                CASE GREATEST(array_length(aj.leaf_scenarios_seen, 1), 0)
                    WHEN 0 THEN NULL
                    ELSE CASE
                        WHEN ROUND(aj.sum_grade_percent_zero_fill / GREATEST(array_length(aj.leaf_scenarios_seen, 1), 1))::int >= 80 THEN 'high'
                        WHEN ROUND(aj.sum_grade_percent_zero_fill / GREATEST(array_length(aj.leaf_scenarios_seen, 1), 1))::int >= 70 THEN 'medium'
                        ELSE 'low'
                    END
                END
            ELSE
                CASE COALESCE(aj.sim_scenario_count, 0)
                    WHEN 0 THEN NULL
                    ELSE CASE
                        WHEN aj.completed_with_grade = 0 THEN NULL
                        ELSE CASE
                            WHEN ROUND(aj.sum_grade_percent_zero_fill / NULLIF(aj.sim_scenario_count, 0))::int >= 80 THEN 'high'
                            WHEN ROUND(aj.sum_grade_percent_zero_fill / NULLIF(aj.sim_scenario_count, 0))::int >= 70 THEN 'medium'
                            ELSE 'low'
                        END
                    END
                END
        END AS score_status,
        (NOT aj.is_archived) AS show_view,
        (NOT aj.is_archived) AND (
            (aj.infinite_mode
                AND (
                    -- No time limit OR time limit not exceeded
                    (aj.time_limit_seconds IS NULL OR aj.elapsed_seconds < aj.time_limit_seconds)
                    -- AND there are incomplete chats (pending work)
                    AND aj.incomplete_chats > 0
                ))
            OR
            (NOT aj.infinite_mode
                AND aj.sim_scenario_count IS NOT NULL
                AND COALESCE(aj.completed_with_grade, 0) < aj.sim_scenario_count)
        ) AS show_continue,
        aj.persona_ids_distinct
    FROM attempt_joined aj
),
-- Apply search filter (searches profile name, simulation name, persona names)
final_rows_with_search AS (
    SELECT fr.*
    FROM params p
    CROSS JOIN final_rows fr
    WHERE 
        -- Search filter: if search term provided, search in profile name, simulation name, or persona names
        (p.search IS NULL OR p.search = '' OR
         LOWER(fr.profile_name) LIKE '%' || LOWER(p.search) || '%' OR
         LOWER(fr.simulation_name) LIKE '%' || LOWER(p.search) || '%' OR
         EXISTS (
             SELECT 1
             FROM unnest(fr.persona_ids_distinct) AS pid
             JOIN personas per ON per.id = pid
             WHERE LOWER(per.name) LIKE '%' || LOWER(p.search) || '%'
         ))
),
persona_labels AS (
    SELECT
        fr.attempt_id,
        COALESCE(ARRAY_AGG(per.name ORDER BY per.name) FILTER (WHERE per.name IS NOT NULL), ARRAY[]::text[]) AS persona_names,
        COALESCE(ARRAY_AGG(per.color ORDER BY per.name) FILTER (WHERE per.color IS NOT NULL), ARRAY[]::text[]) AS persona_colors
    FROM final_rows_with_search fr
    LEFT JOIN LATERAL (
        SELECT DISTINCT per.name, per.color
        FROM unnest(fr.persona_ids_distinct) AS pid
        JOIN personas per ON per.id = pid
    ) per ON TRUE
    GROUP BY fr.attempt_id
),
scenario_names AS (
    SELECT
        fr.attempt_id,
        COALESCE(sn.names, ARRAY[]::text[]) AS names
    FROM final_rows_with_search fr
    LEFT JOIN LATERAL (
        SELECT ARRAY_AGG(s.name ORDER BY s.name) AS names
        FROM unnest(fr.scenario_ids_assigned) sid
        JOIN scenarios s ON s.id = sid
    ) sn ON TRUE
),
-- Get total count before pagination
total_count_cte AS (
    SELECT COUNT(*)::int AS total_count
    FROM final_rows_with_search
),
-- Paginated and sorted results with row number for ordering
paginated_rows AS (
    SELECT
        fr.attempt_id,
        fr.attempt_date,
        fr.profile_id,
        fr.profile_name,
        fr.simulation_name,
        fr.num_scenarios,
        fr.num_scenarios_completed,
        fr.infinite_mode,
        fr.score_percent,
        fr.score_status,
        fr.simulation_id,
        fr.scenario_ids_assigned,
        fr.is_archived,
        fr.show_view,
        fr.show_continue,
        fr.practice_simulation,
        fr.pass_pct,
        fr.department_ids,
        fr.practice_scenario_id,
        fr.persona_ids_distinct,
        ROW_NUMBER() OVER (
            ORDER BY 
                CASE 
                    WHEN p.sort_by = 'date' AND p.sort_order = 'desc' THEN fr.attempt_date
                END DESC NULLS LAST,
                CASE 
                    WHEN p.sort_by = 'date' AND p.sort_order = 'asc' THEN fr.attempt_date
                END ASC NULLS LAST,
                CASE 
                    WHEN p.sort_by = 'simulationName' AND p.sort_order = 'desc' THEN fr.simulation_name
                END DESC NULLS LAST,
                CASE 
                    WHEN p.sort_by = 'simulationName' AND p.sort_order = 'asc' THEN fr.simulation_name
                END ASC NULLS LAST,
                CASE 
                    WHEN p.sort_by = 'score' AND p.sort_order = 'desc' THEN COALESCE(fr.score_percent, -1)
                END DESC,
                CASE 
                    WHEN p.sort_by = 'score' AND p.sort_order = 'asc' THEN COALESCE(fr.score_percent, 999999)
                END ASC,
                fr.attempt_id DESC
        ) as rn
    FROM params p
    CROSS JOIN final_rows_with_search fr
    ORDER BY 
        CASE 
            WHEN p.sort_by = 'date' AND p.sort_order = 'desc' THEN fr.attempt_date
        END DESC NULLS LAST,
        CASE 
            WHEN p.sort_by = 'date' AND p.sort_order = 'asc' THEN fr.attempt_date
        END ASC NULLS LAST,
        CASE 
            WHEN p.sort_by = 'simulationName' AND p.sort_order = 'desc' THEN fr.simulation_name
        END DESC NULLS LAST,
        CASE 
            WHEN p.sort_by = 'simulationName' AND p.sort_order = 'asc' THEN fr.simulation_name
        END ASC NULLS LAST,
        CASE 
            WHEN p.sort_by = 'score' AND p.sort_order = 'desc' THEN COALESCE(fr.score_percent, -1)
        END DESC,
        CASE 
            WHEN p.sort_by = 'score' AND p.sort_order = 'asc' THEN COALESCE(fr.score_percent, 999999)
        END ASC,
        fr.attempt_id DESC
    LIMIT (SELECT page_size FROM params)
    OFFSET (SELECT offset_count FROM params)
),
-- Build history rows as composite types (preserve order from paginated_rows)
history_rows_agg AS (
    SELECT COALESCE(ARRAY_AGG(
        (pr.attempt_id,
         pr.attempt_date,
         pr.profile_id,
         pr.profile_name,
         pr.simulation_name,
         pr.num_scenarios,
         pr.num_scenarios_completed,
         pr.infinite_mode,
         COALESCE(
            (SELECT SUM(stl.time_limit_seconds)
             FROM scenario_time_limits stl
             JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
             WHERE stl.simulation_id = pr.simulation_id AND stl.active = true AND ss.active = true),
            0
         ),
         COALESCE(pl.persona_names, ARRAY[]::text[]),
         COALESCE(pl.persona_colors, ARRAY[]::text[]),
         pr.score_percent,
         pr.score_status,
         pr.simulation_id,
         COALESCE(pr.scenario_ids_assigned, ARRAY[]::uuid[]),
         COALESCE(sn.names, ARRAY[]::text[]),
         pr.is_archived,
         pr.show_view,
         pr.show_continue,
         COALESCE(pr.practice_simulation, false),
         pr.pass_pct,
         pr.department_ids,
         COALESCE(acn.cohort_names, ARRAY[]::text[]),
         pr.practice_scenario_id
        )::types.q_get_home_history_v4_attempt_history_row
        ORDER BY pr.rn
    ), '{}'::types.q_get_home_history_v4_attempt_history_row[]) as data
    FROM paginated_rows pr
    LEFT JOIN persona_labels pl ON pl.attempt_id = pr.attempt_id
    LEFT JOIN scenario_names sn ON sn.attempt_id = pr.attempt_id
    LEFT JOIN attempt_cohort_names acn ON acn.attempt_id = pr.attempt_id
),
-- Aggregate options
profile_options_agg AS (
    SELECT COALESCE(ARRAY_AGG((poc.profile_id::text, poc.profile_name, poc.count)::types.q_get_home_history_v4_option), '{}'::types.q_get_home_history_v4_option[]) as profile_options
    FROM profile_options_cte poc
),
simulation_options_agg AS (
    SELECT COALESCE(ARRAY_AGG((soc.simulation_id::text, soc.simulation_name, soc.count)::types.q_get_home_history_v4_option), '{}'::types.q_get_home_history_v4_option[]) as simulation_options
    FROM simulation_options_cte soc
),
scenario_options_agg AS (
    SELECT COALESCE(ARRAY_AGG((scoc.scenario_id::text, scoc.scenario_title, scoc.count)::types.q_get_home_history_v4_option), '{}'::types.q_get_home_history_v4_option[]) as scenario_options
    FROM scenario_options_cte scoc
),
user_profile AS (
    SELECT 
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM resolve_profile_id rpi
    JOIN profiles ON profiles.id = rpi.resolved_profile_id
),
-- Calculate page info
page_info AS (
    SELECT 
        (SELECT total_count FROM total_count_cte)::int AS total_count,
        (SELECT page FROM params)::int AS page,
        (SELECT page_size FROM params)::int AS page_size,
        CASE 
            WHEN (SELECT total_count FROM total_count_cte) > 0 
            THEN ((SELECT total_count FROM total_count_cte) + (SELECT page_size FROM params) - 1) / (SELECT page_size FROM params)
            ELSE 0
        END::int AS total_pages
)
SELECT 
    up.actor_name::text as actor_name,
    COALESCE((SELECT data FROM history_rows_agg), '{}'::types.q_get_home_history_v4_attempt_history_row[]) as data,
    pi.total_count,
    pi.page,
    pi.page_size,
    pi.total_pages,
    COALESCE((SELECT profile_options FROM profile_options_agg), '{}'::types.q_get_home_history_v4_option[]) as profile_options,
    COALESCE((SELECT simulation_options FROM simulation_options_agg), '{}'::types.q_get_home_history_v4_option[]) as simulation_options,
    COALESCE((SELECT scenario_options FROM scenario_options_agg), '{}'::types.q_get_home_history_v4_option[]) as scenario_options
FROM user_profile up
CROSS JOIN page_info pi
$$;


--
-- Name: api_get_home_overview_v4(text, text, uuid, uuid[], uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_home_overview_v4(start_date text, end_date text, profile_id uuid, cohort_ids uuid[] DEFAULT ARRAY[]::uuid[], department_ids uuid[] DEFAULT ARRAY[]::uuid[]) RETURNS TABLE(actor_name text, mode text, has_data boolean, items types.q_get_home_overview_v4_simulation_item[], standard_groups types.q_get_home_overview_v4_standard_group[], standards types.q_get_home_overview_v4_standard[], simulations types.q_get_home_overview_v4_simulation[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        start_date::timestamptz AS start_date,
        end_date::timestamptz AS end_date,
        profile_id AS profile_id,
        COALESCE(cohort_ids, ARRAY[]::uuid[]) AS cohort_ids,
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids
),
resolve_profile_id AS (
    SELECT 
        CASE 
            WHEN (SELECT profile_id FROM params)::text IS NULL OR (SELECT profile_id FROM params)::text = '' THEN NULL::uuid
            ELSE (SELECT profile_id FROM params)::uuid
        END as resolved_profile_id
),
-- Filter simulations by cohorts (new filtering order: cohorts → simulations)
-- Gets simulations linked to cohorts + practice simulations without cohorts
filtered_simulation_ids AS (
    SELECT DISTINCT s.id AS simulation_id
    FROM params p
    CROSS JOIN simulations s
    WHERE s.active = TRUE
      AND (
          -- If cohort_ids provided, get simulations linked to those cohorts
          (cardinality(p.cohort_ids) > 0 AND EXISTS (
              SELECT 1 
              FROM cohort_simulations cs 
              WHERE cs.simulation_id = s.id 
                AND cs.cohort_id = ANY(p.cohort_ids)
                AND cs.active = TRUE
          ))
          OR
          -- Always include practice simulations without cohorts
          (s.practice_simulation = TRUE 
           AND NOT EXISTS (
               SELECT 1 
               FROM cohort_simulations cs2 
               WHERE cs2.simulation_id = s.id 
                 AND cs2.active = TRUE
           ))
          OR
          -- If no cohort_ids provided, include all simulations
          (cardinality(p.cohort_ids) = 0)
      )
),
-- Look up profile role if profileId provided and compute role hierarchy
profile_role_lookup AS (
    SELECT 
        CASE 
            WHEN rpi.resolved_profile_id IS NULL THEN 'instructional'
            WHEN (SELECT role FROM profiles WHERE id = rpi.resolved_profile_id) = 'member' THEN 'member'
            ELSE 'instructional'
        END AS mode,
        CASE
            WHEN rpi.resolved_profile_id IS NULL THEN false
            ELSE COALESCE((SELECT role = 'member'::profile_role FROM profiles WHERE id = rpi.resolved_profile_id), false)
        END AS is_member_mode,
        -- Compute role hierarchy array based on profile's role
        CASE
            WHEN rpi.resolved_profile_id IS NULL THEN ARRAY['instructional', 'member', 'guest']::profile_role[]
            WHEN (SELECT role FROM profiles WHERE id = rpi.resolved_profile_id) = 'superadmin' THEN ARRAY['superadmin', 'admin', 'instructional', 'member', 'guest']::profile_role[]
            WHEN (SELECT role FROM profiles WHERE id = rpi.resolved_profile_id) = 'admin' THEN ARRAY['admin', 'instructional', 'member', 'guest']::profile_role[]
            WHEN (SELECT role FROM profiles WHERE id = rpi.resolved_profile_id) = 'instructional' THEN ARRAY['instructional', 'member', 'guest']::profile_role[]
            WHEN (SELECT role FROM profiles WHERE id = rpi.resolved_profile_id) = 'member' THEN ARRAY['member', 'guest']::profile_role[]
            WHEN (SELECT role FROM profiles WHERE id = rpi.resolved_profile_id) = 'guest' THEN ARRAY['guest']::profile_role[]
            ELSE ARRAY['instructional', 'member', 'guest']::profile_role[]  -- Default fallback
        END AS role_hierarchy
    FROM resolve_profile_id rpi
),
-- Filter analytics for items: for member mode include profileId filter
-- Also filter by simulation_ids from cohorts (new filtering order)
filt AS (
    SELECT a.* 
    FROM params p
    CROSS JOIN profile_role_lookup prl
    CROSS JOIN resolve_profile_id rpi
    CROSS JOIN analytics a
    WHERE a.attempt_created_at >= p.start_date 
      AND a.attempt_created_at < p.end_date 
      AND a.is_general = TRUE
      AND (NOT prl.is_member_mode OR a.profile_id = rpi.resolved_profile_id)
      -- Filter by simulation_ids from cohorts (new filtering order)
      AND (cardinality(p.cohort_ids) = 0 OR a.simulation_id IN (SELECT simulation_id FROM filtered_simulation_ids))
),
-- Get cohort-simulation pairs (includes empty cohorts)
cohort_sim AS (
    SELECT c.id AS cohort_id, c.title AS cohort_title, cs.simulation_id
    FROM params p
    CROSS JOIN cohorts c
    JOIN cohort_simulations cs ON cs.cohort_id = c.id AND cs.active = true
    LEFT JOIN cohort_departments cd ON cd.cohort_id = c.id AND cd.active = true
    WHERE (cardinality(p.cohort_ids) = 0 OR c.id = ANY(p.cohort_ids))
    GROUP BY c.id, c.title, cs.simulation_id, p.department_ids
    HAVING 
        (cardinality(p.department_ids) = 0 OR COUNT(cd.cohort_id) FILTER (WHERE cd.department_id = ANY(p.department_ids)) > 0)
        OR (cardinality(p.department_ids) = 0 AND NOT EXISTS (SELECT 1 FROM cohort_departments cd2 WHERE cd2.cohort_id = c.id AND cd2.active = true))
),
-- Expected scenarios per simulation
sim_expected AS (
    SELECT s.id AS simulation_id,
           COALESCE((SELECT COUNT(*)::int FROM simulation_scenarios ss WHERE ss.simulation_id = s.id), 0) AS expected_scenarios
    FROM simulations s
),
-- Per attempt: sum grade_percent over completed root scenarios (one grade per root scenario per attempt)
attempt_scores AS (
    SELECT
        ap.attempt_id,
        ap.profile_id,
        ap.simulation_id,
        COALESCE(SUM(ap.grade_percent) FILTER (WHERE ap.completed AND ap.grade_percent IS NOT NULL), 0)::numeric AS sum_completed_pct,
        se.expected_scenarios
    FROM (
        SELECT DISTINCT ON (ap_inner.attempt_id, ap_inner.scenario_id)
            ap_inner.*
        FROM filt ap_inner
        WHERE ap_inner.completed AND ap_inner.grade_percent IS NOT NULL
        ORDER BY ap_inner.attempt_id, ap_inner.scenario_id, ap_inner.grade_created_at DESC
    ) ap
    JOIN sim_expected se ON se.simulation_id = ap.simulation_id
    GROUP BY ap.attempt_id, ap.profile_id, ap.simulation_id, se.expected_scenarios
),
-- Average over expected scenarios (missing = 0)
attempt_avg AS (
    SELECT
        attempt_id,
        profile_id,
        simulation_id,
        CASE WHEN expected_scenarios > 0
             THEN (sum_completed_pct / expected_scenarios)
             ELSE 0 END AS avg_pct_over_expected
    FROM attempt_scores
),
-- Completed attempts count (includes attempts with or without grades)
completed_attempts_count AS (
    SELECT
        a.profile_id,
        a.simulation_id,
        COUNT(DISTINCT a.attempt_id) AS completed_count
    FROM filt a
    WHERE a.completed = TRUE
    GROUP BY a.profile_id, a.simulation_id
),
-- User-simulation status with best attempt + pass status
user_sim_status AS (
    SELECT
        COALESCE(aa.profile_id, cac.profile_id) AS profile_id,
        COALESCE(aa.simulation_id, cac.simulation_id) AS simulation_id,
        MAX(aa.avg_pct_over_expected) AS avg_pct_over_expected,
        COALESCE(BOOL_OR(aa.avg_pct_over_expected >= COALESCE(
            (SELECT ROUND(100.0 * r.pass_points::numeric / NULLIF(r.points,0))
             FROM simulations s
             LEFT JOIN simulation_scenarios ss_rubric ON ss_rubric.simulation_id = s.id AND ss_rubric.active = true
             LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga_rubric ON ssrga_rubric.simulation_id = ss_rubric.simulation_id AND ssrga_rubric.scenario_id = ss_rubric.scenario_id
             LEFT JOIN rubric_grade_agents rga_rubric ON rga_rubric.id = ssrga_rubric.rubric_grade_agent_id
             LEFT JOIN rubrics r ON r.id = rga_rubric.rubric_id
             WHERE s.id = COALESCE(aa.simulation_id, cac.simulation_id)
             ORDER BY ss_rubric.position
             LIMIT 1), 0
        )), false) AS passed,
        COALESCE(MAX(cac.completed_count), 0) AS chats_completed
    FROM attempt_avg aa
    FULL OUTER JOIN completed_attempts_count cac ON cac.profile_id = aa.profile_id AND cac.simulation_id = aa.simulation_id
    GROUP BY COALESCE(aa.profile_id, cac.profile_id), COALESCE(aa.simulation_id, cac.simulation_id)
),
-- Cohort membership CTE (for non-history queries - only active memberships)
cohort_membership AS (
    SELECT
        cp.profile_id,
        cp.cohort_id,
        cs.simulation_id,
        c.title AS cohort_title,
        prof.role
    FROM params p
    CROSS JOIN cohort_profiles cp
    JOIN cohorts c ON c.id = cp.cohort_id
    JOIN cohort_simulations cs ON cs.cohort_id = c.id
    JOIN profiles prof ON prof.id = cp.profile_id
    LEFT JOIN cohort_departments cd ON cd.cohort_id = c.id AND cd.active = true
    CROSS JOIN profile_role_lookup prl
    CROSS JOIN resolve_profile_id rpi
    WHERE cp.active = true  -- Only active cohort memberships for non-history queries
      AND (cardinality(p.cohort_ids) = 0 OR c.id = ANY(p.cohort_ids))
      AND prof.role = ANY(prl.role_hierarchy)  -- Use computed role hierarchy from profile_role_lookup
      -- When member mode, only include the current member's profile_id
      AND (NOT prl.is_member_mode OR cp.profile_id = rpi.resolved_profile_id)
    GROUP BY cp.profile_id, cp.cohort_id, cs.simulation_id, c.title, prof.role, c.id, p.department_ids
    HAVING 
        (cardinality(p.department_ids) = 0 OR COUNT(cd.cohort_id) FILTER (WHERE cd.department_id = ANY(p.department_ids)) > 0)
        OR (cardinality(p.department_ids) = 0 AND NOT EXISTS (SELECT 1 FROM cohort_departments cd2 WHERE cd2.cohort_id = c.id AND cd2.active = true))
),
-- Simulation metadata
sim_meta AS (
    SELECT DISTINCT
        s.id AS simulation_id,
        s.title,
        s.description,
        COALESCE(
            (SELECT SUM(stl.time_limit_seconds)
             FROM scenario_time_limits stl
             JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
             WHERE stl.simulation_id = s.id AND stl.active = true AND ss.active = true),
            0
        ) as time_limit,
        (SELECT rga.rubric_id FROM simulation_scenarios ss 
         JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
         JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
         WHERE ss.simulation_id = s.id AND ss.active = true 
         ORDER BY ss.position 
         LIMIT 1) as rubric_id,
        COALESCE((SELECT COUNT(*)::int FROM simulation_scenarios ss WHERE ss.simulation_id = s.id), 0) AS num_scenarios,
        COALESCE(r.points, 0) AS rubric_points,
        COALESCE(r.pass_points, 0) AS rubric_pass_points
    FROM simulations s
    LEFT JOIN simulation_scenarios ss_rubric ON ss_rubric.simulation_id = s.id AND ss_rubric.active = true
    LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga_rubric ON ssrga_rubric.simulation_id = ss_rubric.simulation_id AND ssrga_rubric.scenario_id = ss_rubric.scenario_id
    LEFT JOIN rubric_grade_agents rga_rubric ON rga_rubric.id = ssrga_rubric.rubric_grade_agent_id
    LEFT JOIN rubrics r ON r.id = rga_rubric.rubric_id
    WHERE s.id IN (SELECT simulation_id FROM cohort_sim)
),
-- Simulation persona metadata
sim_persona_meta AS (
    SELECT
        sm.simulation_id,
        (ARRAY_AGG(p.color ORDER BY cnt DESC, COALESCE(p.color, '') DESC))[1] AS color,
        (ARRAY_AGG(p.icon ORDER BY cnt DESC, COALESCE(p.icon, '') DESC))[1] AS icon
    FROM (
        SELECT
            s.id AS simulation_id,
            sp.persona_id,
            COUNT(*) AS cnt
        FROM simulations s
        LEFT JOIN simulation_scenarios ss_link ON ss_link.simulation_id = s.id
        LEFT JOIN scenarios sc ON sc.id = ss_link.scenario_id
        LEFT JOIN scenario_personas sp ON sp.scenario_id = sc.id AND sp.active = TRUE
        WHERE s.id IN (SELECT simulation_id FROM sim_meta)
        GROUP BY s.id, sp.persona_id
    ) sm
    LEFT JOIN personas p ON p.id = sm.persona_id
    GROUP BY sm.simulation_id
),
-- Standard groups per simulation (for items) - get from first scenario's rubric
sim_standard_groups AS (
    SELECT DISTINCT ON (ss.simulation_id)
        ss.simulation_id,
        ARRAY_AGG(sg.id::text ORDER BY sg.id) FILTER (WHERE sg.id IS NOT NULL) AS standard_group_ids
    FROM simulation_scenarios ss
    JOIN simulation_scenarios_rubric_grade_agents ssrga_rsg ON ssrga_rsg.simulation_id = ss.simulation_id AND ssrga_rsg.scenario_id = ss.scenario_id
    JOIN rubric_grade_agents rga_rsg ON rga_rsg.id = ssrga_rsg.rubric_grade_agent_id
    JOIN rubric_standard_groups rsg ON rsg.rubric_id = rga_rsg.rubric_id AND rsg.active = true
    JOIN standard_groups sg ON sg.id = rsg.standard_group_id
    WHERE ss.simulation_id IN (SELECT simulation_id FROM sim_meta) AND ss.active = true
    GROUP BY ss.simulation_id, ss.position
    ORDER BY ss.simulation_id, ss.position
),
-- TA VIEW: Primary cohort per simulation for the TA
ta_primary_cohort AS (
    SELECT
        c.id AS cohort_id,
        c.title AS cohort_title,
        cs.simulation_id,
        ROW_NUMBER() OVER (ORDER BY c.id, cs.simulation_id) AS order_idx,
        ROW_NUMBER() OVER (PARTITION BY cs.simulation_id ORDER BY c.id) AS rn
    FROM params p
    CROSS JOIN cohorts c
    JOIN cohort_simulations cs ON cs.cohort_id = c.id
    JOIN cohort_profiles cp ON cp.cohort_id = c.id
        AND cp.profile_id = (SELECT resolved_profile_id FROM resolve_profile_id)
    LEFT JOIN cohort_departments cd ON cd.cohort_id = c.id AND cd.active = true
    WHERE (cardinality(p.cohort_ids) = 0 OR c.id = ANY(p.cohort_ids))
    GROUP BY c.id, c.title, cs.simulation_id, p.department_ids
    HAVING 
        (cardinality(p.department_ids) = 0 OR COUNT(cd.cohort_id) FILTER (WHERE cd.department_id = ANY(p.department_ids)) > 0)
        OR (cardinality(p.department_ids) = 0 AND NOT EXISTS (SELECT 1 FROM cohort_departments cd2 WHERE cd2.cohort_id = c.id AND cd2.active = true))
),
ta_sim_space AS (
    SELECT DISTINCT simulation_id FROM ta_primary_cohort
),
ta_rows AS (
    SELECT
        ('member'::text,
         s.simulation_id,
         s.title,
         s.description,
         s.title,
         s.time_limit,
         s.num_scenarios,
         COALESCE((
            SELECT ROUND(GREATEST(0, LEAST(100, uss.avg_pct_over_expected)))::int
            FROM user_sim_status uss, resolve_profile_id rpi
            WHERE uss.profile_id = rpi.resolved_profile_id
              AND uss.simulation_id = s.simulation_id
         ), NULL)::int,
         COALESCE(ssg.standard_group_ids, ARRAY[]::text[]),
         spm.color,
         spm.icon,
         COALESCE((
            SELECT uss.passed
            FROM user_sim_status uss, resolve_profile_id rpi
            WHERE uss.profile_id = rpi.resolved_profile_id
              AND uss.simulation_id = s.simulation_id
         ), false)::boolean,
         CASE WHEN s.rubric_points > 0
              THEN ROUND(100.0 * s.rubric_pass_points::numeric / s.rubric_points)::int
              ELSE NULL END::int,
         COALESCE((
            SELECT CASE
                      WHEN COALESCE(uss.passed, false) THEN 'passed'
                      WHEN COALESCE(uss.chats_completed, 0) > 0 THEN 'in-progress'
                      ELSE 'not-started'
                    END
            FROM user_sim_status uss, resolve_profile_id rpi
            WHERE uss.profile_id = rpi.resolved_profile_id
              AND uss.simulation_id = s.simulation_id
         ), 'not-started')::text,
         COALESCE((
            SELECT ROUND(GREATEST(0, LEAST(100, uss.avg_pct_over_expected)))::int
            FROM user_sim_status uss, resolve_profile_id rpi
            WHERE uss.profile_id = rpi.resolved_profile_id
              AND uss.simulation_id = s.simulation_id
         ), 0)::int,
         NULL::int,
         NULL::int,
         NULL::int,
         CASE WHEN s.rubric_points > 0
              THEN ROUND(100.0 * s.rubric_pass_points::numeric / s.rubric_points)::int
              ELSE NULL END::int,
         (
            SELECT tpc.cohort_title
            FROM ta_primary_cohort tpc
            WHERE tpc.simulation_id = s.simulation_id AND tpc.rn = 1
         ),
         (
            SELECT CASE
                      WHEN array_length(titles, 1) IS NULL OR array_length(titles, 1) = 0 THEN NULL
                      WHEN array_length(titles, 1) = 1 THEN titles[1]
                      WHEN array_length(titles, 1) = 2 THEN titles[1] || ' and ' || titles[2]
                      ELSE array_to_string(titles[1:array_length(titles,1)-1], ', ')
                           || ', and ' || titles[array_length(titles,1)]
                    END
            FROM (
                SELECT ARRAY_AGG(DISTINCT c.cohort_title ORDER BY c.cohort_title) AS titles
                FROM cohort_membership c, resolve_profile_id rpi
                WHERE c.simulation_id = s.simulation_id
                  AND c.profile_id = rpi.resolved_profile_id
            ) x
         )
        )::types.q_get_home_overview_v4_simulation_item AS item
    FROM sim_meta s
    LEFT JOIN sim_persona_meta spm ON spm.simulation_id = s.simulation_id
    LEFT JOIN sim_standard_groups ssg ON ssg.simulation_id = s.simulation_id
    WHERE EXISTS (SELECT 1 FROM profile_role_lookup prl WHERE prl.is_member_mode)
      AND EXISTS (SELECT 1 FROM ta_sim_space t WHERE t.simulation_id = s.simulation_id)
),
-- INSTRUCTIONAL VIEW: counts across all cohort members
inst_counts AS (
    SELECT
        cs.simulation_id,
        COUNT(DISTINCT cm.profile_id) AS total_members,
        COUNT(DISTINCT CASE WHEN uss.passed THEN cm.profile_id END) AS passed_count,
        COUNT(DISTINCT CASE WHEN (NOT uss.passed) AND uss.chats_completed > 0 THEN cm.profile_id END) AS in_progress_count
    FROM cohort_sim cs
    LEFT JOIN cohort_membership cm ON cm.cohort_id = cs.cohort_id AND cm.simulation_id = cs.simulation_id
    LEFT JOIN user_sim_status uss ON uss.profile_id = cm.profile_id AND uss.simulation_id = cs.simulation_id
    GROUP BY cs.simulation_id
),
inst_cohort_names AS (
    SELECT
        cs.simulation_id,
        ARRAY_AGG(DISTINCT cs.cohort_title ORDER BY cs.cohort_title) AS titles
    FROM cohort_sim cs
    GROUP BY cs.simulation_id
),
inst_rows AS (
    SELECT
        ('instructional'::text,
         s.simulation_id,
         s.title,
         s.description,
         s.title,
         s.time_limit,
         s.num_scenarios,
         NULL::int,
         COALESCE(ssg.standard_group_ids, ARRAY[]::text[]),
         spm.color,
         spm.icon,
         CASE
            WHEN COALESCE(ic.total_members, 0) = 0 THEN true
            WHEN COALESCE(ic.passed_count, 0) = COALESCE(ic.total_members, 0) THEN true
            ELSE false END::boolean,
         CASE WHEN s.rubric_points > 0
              THEN ROUND(100.0 * s.rubric_pass_points::numeric / s.rubric_points)::int
              ELSE NULL END::int,
         CASE
            WHEN COALESCE(ic.total_members, 0) = 0 THEN 'passed'
            WHEN COALESCE(ic.passed_count, 0) = COALESCE(ic.total_members, 0) THEN 'passed'
            WHEN COALESCE(ic.passed_count, 0) > 0 OR COALESCE(ic.in_progress_count, 0) > 0 THEN 'in-progress'
            ELSE 'not-started'
          END::text,
         CASE
            WHEN COALESCE(ic.total_members, 0) > 0
            THEN ROUND(100.0 * (COALESCE(ic.passed_count, 0) + COALESCE(ic.in_progress_count, 0))::numeric / ic.total_members)::int
            ELSE 0
          END::int,
         COALESCE(ic.passed_count, 0)::int,
         COALESCE(ic.in_progress_count, 0)::int,
         GREATEST(COALESCE(ic.total_members, 0) - COALESCE(ic.passed_count, 0) - COALESCE(ic.in_progress_count, 0), 0)::int,
         NULL::int,
         (icn.titles)[1],
         CASE
            WHEN array_length(icn.titles, 1) IS NULL OR array_length(icn.titles, 1) = 0 THEN NULL
            WHEN array_length(icn.titles, 1) = 1 THEN icn.titles[1]
            WHEN array_length(icn.titles, 1) = 2 THEN icn.titles[1] || ' and ' || icn.titles[2]
            ELSE array_to_string(icn.titles[1:array_length(icn.titles,1)-1], ', ')
                 || ', and ' || icn.titles[array_length(icn.titles,1)]
          END
        )::types.q_get_home_overview_v4_simulation_item AS item,
        CASE
            WHEN COALESCE(ic.total_members, 0) = 0 THEN true
            WHEN COALESCE(ic.passed_count, 0) = COALESCE(ic.total_members, 0) THEN true
            ELSE false
        END AS has_passed_bool,
        (icn.titles)[1] AS sort_cohort_name,
        s.title AS sort_title
    FROM sim_meta s
    JOIN inst_counts ic ON ic.simulation_id = s.simulation_id
    LEFT JOIN sim_persona_meta spm ON spm.simulation_id = s.simulation_id
    LEFT JOIN inst_cohort_names icn ON icn.simulation_id = s.simulation_id
    LEFT JOIN sim_standard_groups ssg ON ssg.simulation_id = s.simulation_id
    WHERE NOT EXISTS (SELECT 1 FROM profile_role_lookup prl WHERE prl.is_member_mode)
),
all_rubric_ids AS (
    SELECT DISTINCT rubric_id FROM sim_meta
),
-- Standard groups mapping (as array)
standard_groups_array AS (
    SELECT 
        (sg.id, sg.name, sg.description, sg.points, sg.pass_points)::types.q_get_home_overview_v4_standard_group AS standard_group
    FROM rubric_standard_groups rsg
    JOIN standard_groups sg ON sg.id = rsg.standard_group_id
    WHERE rsg.rubric_id IN (SELECT rubric_id FROM all_rubric_ids) AND rsg.active = true
),
-- Standards mapping (as array)
standards_array AS (
    SELECT 
        (st.id, st.standard_group_id, st.name, st.description, st.points)::types.q_get_home_overview_v4_standard AS standard
    FROM standards st
    WHERE st.standard_group_id IN (
        SELECT rsg.standard_group_id FROM rubric_standard_groups rsg
        WHERE rsg.rubric_id IN (SELECT rubric_id FROM all_rubric_ids) AND rsg.active = true
    )
),
-- Simulation mapping (as array)
simulation_array AS (
    SELECT 
        (sim.id, sim.title, COALESCE(sim.description, ''), 
         COALESCE(
            (SELECT SUM(stl.time_limit_seconds)
             FROM scenario_time_limits stl
             JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
             WHERE stl.simulation_id = sim.id AND stl.active = true AND ss.active = true),
            0
         ),
         COALESCE(sdd.department_ids, ARRAY[]::text[])
        )::types.q_get_home_overview_v4_simulation AS simulation
    FROM simulations sim
    LEFT JOIN (
        SELECT 
            sd.simulation_id,
            ARRAY_AGG(sd.department_id::text ORDER BY sd.created_at) as department_ids
        FROM simulation_departments sd
        WHERE sd.active = true
        GROUP BY sd.simulation_id
    ) sdd ON sdd.simulation_id = sim.id
    WHERE sim.id IN (SELECT DISTINCT simulation_id FROM cohort_sim)
),
user_profile AS (
    SELECT 
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM resolve_profile_id rpi
    JOIN profiles ON profiles.id = rpi.resolved_profile_id
),
-- Aggregate ta items
ta_items_agg AS (
    SELECT COALESCE(ARRAY_AGG(tr.item ORDER BY (SELECT title FROM sim_meta WHERE simulation_id = (tr.item).simulation_id)), '{}'::types.q_get_home_overview_v4_simulation_item[]) as items
    FROM ta_rows tr
),
-- Aggregate inst items
inst_items_agg AS (
    SELECT COALESCE(ARRAY_AGG(ir.item ORDER BY ir.has_passed_bool ASC, ir.sort_cohort_name NULLS LAST, ir.sort_title), '{}'::types.q_get_home_overview_v4_simulation_item[]) as items
    FROM inst_rows ir
),
-- Aggregate mappings separately
standard_groups_agg AS (
    SELECT COALESCE(ARRAY_AGG(DISTINCT standard_group), '{}'::types.q_get_home_overview_v4_standard_group[]) as standard_groups
    FROM standard_groups_array
),
standards_agg AS (
    SELECT COALESCE(ARRAY_AGG(DISTINCT standard), '{}'::types.q_get_home_overview_v4_standard[]) as standards
    FROM standards_array
),
simulations_agg AS (
    SELECT COALESCE(ARRAY_AGG(DISTINCT simulation), '{}'::types.q_get_home_overview_v4_simulation[]) as simulations
    FROM simulation_array
)
SELECT 
    up.actor_name::text as actor_name,
    (SELECT mode FROM profile_role_lookup)::text as mode,
    CASE 
        WHEN (SELECT is_member_mode FROM profile_role_lookup) THEN EXISTS(SELECT 1 FROM ta_rows)
        ELSE EXISTS(SELECT 1 FROM inst_rows)
    END::boolean as has_data,
    CASE
        WHEN (SELECT is_member_mode FROM profile_role_lookup) THEN COALESCE((SELECT items FROM ta_items_agg), '{}'::types.q_get_home_overview_v4_simulation_item[])
        ELSE COALESCE((SELECT items FROM inst_items_agg), '{}'::types.q_get_home_overview_v4_simulation_item[])
    END as items,
    COALESCE((SELECT standard_groups FROM standard_groups_agg), '{}'::types.q_get_home_overview_v4_standard_group[]) as standard_groups,
    COALESCE((SELECT standards FROM standards_agg), '{}'::types.q_get_home_overview_v4_standard[]) as standards,
    COALESCE((SELECT simulations FROM simulations_agg), '{}'::types.q_get_home_overview_v4_simulation[]) as simulations
FROM user_profile up
$$;


--
-- Name: api_get_key_detail_v4(uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_key_detail_v4(key_id uuid, profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(key_exists boolean, key_id uuid, name text, key_masked text, type text, description text, active boolean, created_at timestamp with time zone, updated_at timestamp with time zone, department_ids text[], model_ids text[], valid_department_ids text[], can_edit boolean, departments types.q_get_key_detail_v4_department[], models types.q_get_key_detail_v4_model[], actor_name text, draft_version integer)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT key_id AS key_id, profile_id AS profile_id, draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'keys'::draft_resource_type
    LIMIT 1
),
key_exists_check AS (
    SELECT EXISTS(
        SELECT 1 FROM keys WHERE id = (SELECT key_id FROM params)
    )::boolean as key_exists
),
actor_profile AS (
    SELECT 
        p.id as profile_id,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
key_data AS (
    SELECT 
        k.id as key_id,
        k.name,
        CASE 
            WHEN LENGTH(k.key) > 4 THEN LEFT(k.key, 4) || '****'
            ELSE '****'
        END as key_masked,
        k.description,
        k.active,
        k.created_at,
        k.updated_at
    FROM params x
    JOIN keys k ON k.id = x.key_id
),
-- Get department_ids via setting_provider_keys -> settings -> department_settings
key_departments_data AS (
    SELECT 
        ARRAY_AGG(DISTINCT ds.department_id::text ORDER BY ds.department_id::text) as department_ids
    FROM params x
    JOIN setting_provider_keys spk ON spk.key_id = x.key_id AND spk.active = true
    JOIN settings s ON s.id = spk.settings_id AND s.active = true
    JOIN department_settings ds ON ds.settings_id = s.id AND ds.active = true
),
-- Get model_ids via setting_provider_keys -> providers -> models
key_models_data AS (
    SELECT 
        ARRAY_AGG(m.id::text ORDER BY m.name) as model_ids
    FROM params x
    JOIN setting_provider_keys spk ON spk.key_id = x.key_id AND spk.active = true
    JOIN providers p ON p.id = spk.provider_id
    JOIN models m ON m.provider_id = p.id AND m.active = true
),
valid_depts AS (
    SELECT 
        ARRAY_AGG(d.id::text ORDER BY d.title) as dept_ids
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.active = true
    JOIN departments d ON d.id = pd.department_id AND d.active = true
),
departments_data AS (
    SELECT DISTINCT
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.active = true
    JOIN departments d ON d.id = pd.department_id AND d.active = true
),
models_data AS (
    SELECT DISTINCT
        m.id as model_id,
        m.name,
        COALESCE(m.description, '') as description,
        p.value as provider,
        m.active
    FROM params x
    JOIN setting_provider_keys spk ON spk.key_id = x.key_id AND spk.active = true
    JOIN providers p ON p.id = spk.provider_id
    JOIN models m ON m.provider_id = p.id AND m.active = true
),
profile_data AS (
    SELECT role as user_role 
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
user_has_key_access AS (
    -- Check if user has access to key via setting_provider_keys -> settings -> department_settings
    SELECT EXISTS(
        SELECT 1 FROM params x
        JOIN setting_provider_keys spk ON spk.key_id = x.key_id AND spk.active = true
        JOIN settings s ON s.id = spk.settings_id AND s.active = true
        JOIN department_settings ds ON ds.settings_id = s.id AND ds.active = true
        JOIN profile_departments pd ON pd.department_id = ds.department_id AND pd.active = true
        WHERE pd.profile_id = x.profile_id
    ) OR EXISTS(
        SELECT 1 FROM params x
        JOIN profiles p ON p.id = x.profile_id
        WHERE p.role = 'superadmin'::profile_role
    ) OR (
        -- Default keys (no department links via settings) are accessible to all admins
        NOT EXISTS (
            SELECT 1 FROM params x
            JOIN setting_provider_keys spk ON spk.key_id = x.key_id AND spk.active = true
            JOIN settings s ON s.id = spk.settings_id AND s.active = true
            JOIN department_settings ds ON ds.settings_id = s.id AND ds.active = true
        )
    ) as has_access
)
SELECT 
    kec.key_exists::boolean as key_exists,
    kd.key_id::uuid as key_id,
    COALESCE(
        (SELECT payload->>'name' FROM draft_payload_data),
        kd.name::text
    ) as name,
    kd.key_masked::text as key_masked,
    'api'::text as type,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        kd.description::text
    ) as description,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        kd.active::boolean
    ) as active,
    kd.created_at::timestamptz as created_at,
    kd.updated_at::timestamptz as updated_at,
    COALESCE(kdd.department_ids, ARRAY[]::text[]) as department_ids,
    COALESCE(kmd.model_ids, ARRAY[]::text[]) as model_ids,
    COALESCE(vd.dept_ids, ARRAY[]::text[]) as valid_department_ids,
    CASE 
        -- Default keys (no department_ids via settings) are read-only for non-superadmin
        WHEN (COALESCE(kdd.department_ids, ARRAY[]::text[]) = ARRAY[]::text[] AND pr.user_role != 'superadmin') THEN false
        WHEN pr.user_role = 'superadmin'::profile_role THEN true
        WHEN pr.user_role = 'admin'::profile_role AND uhka.has_access THEN true
        ELSE false
    END::boolean as can_edit,
    COALESCE(
        ARRAY_AGG(
            (dd.department_id, dd.name, dd.description)::types.q_get_key_detail_v4_department
            ORDER BY dd.name
        ) FILTER (WHERE dd.department_id IS NOT NULL),
        '{}'::types.q_get_key_detail_v4_department[]
    ) as departments,
    COALESCE(
        ARRAY_AGG(
            (md.model_id, md.name, md.description, md.provider, md.active)::types.q_get_key_detail_v4_model
            ORDER BY md.name
        ) FILTER (WHERE md.model_id IS NOT NULL),
        '{}'::types.q_get_key_detail_v4_model[]
    ) as models,
    ap.actor_name::text as actor_name,
    COALESCE(
        (SELECT draft_version FROM draft_payload_data),
        0
    )::int as draft_version
FROM key_exists_check kec
CROSS JOIN key_data kd
LEFT JOIN key_departments_data kdd ON true
LEFT JOIN key_models_data kmd ON true
CROSS JOIN valid_depts vd
CROSS JOIN profile_data pr
CROSS JOIN user_has_key_access uhka
CROSS JOIN departments_data dd
CROSS JOIN models_data md
CROSS JOIN actor_profile ap
WHERE uhka.has_access = true
GROUP BY kec.key_exists, kd.key_id, kd.name, kd.key_masked, kd.description, kd.active, 
         kd.created_at, kd.updated_at, kdd.department_ids, kmd.model_ids, vd.dept_ids, 
         pr.user_role, uhka.has_access, ap.actor_name
$$;


--
-- Name: api_get_key_for_decrypt_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_key_for_decrypt_v4(key_id uuid, profile_id uuid) RETURNS TABLE(key text, name text, actor_name text)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT key_id AS key_id, profile_id AS profile_id
),
actor_profile AS (
    SELECT 
        p.id as profile_id,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
)
SELECT 
    k.key::text as key,
    k.name::text as name,
    ap.actor_name::text as actor_name
FROM params x
JOIN keys k ON k.id = x.key_id
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_get_key_id_for_model_default_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_key_id_for_model_default_v4(model_id uuid) RETURNS TABLE(key_id text)
    LANGUAGE sql STABLE
    AS $$
WITH default_settings AS (
    SELECT s.id as settings_id
    FROM settings s
    WHERE s.active = true
      AND NOT EXISTS (
          SELECT 1 FROM department_settings sd 
          WHERE sd.settings_id = s.id AND sd.active = true
      )
    LIMIT 1
),
active_settings AS (
    SELECT 
        COALESCE(
            (SELECT settings_id FROM default_settings),
            (SELECT id FROM settings WHERE active = true LIMIT 1)
        ) as settings_id
)
SELECT spk.key_id::text as key_id
FROM models m
JOIN providers p ON p.id = m.provider_id
CROSS JOIN active_settings act_s
JOIN setting_provider_keys spk ON spk.provider_id = p.id 
    AND spk.settings_id = act_s.settings_id 
    AND spk.active = true
JOIN keys k ON k.id = spk.key_id AND k.active = true
WHERE m.id = model_id
LIMIT 1
$$;


--
-- Name: api_get_key_id_for_model_with_profile_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_key_id_for_model_with_profile_v4(model_id uuid, profile_id uuid) RETURNS TABLE(key_id text)
    LANGUAGE sql STABLE
    AS $$
WITH default_settings AS (
    SELECT s.id as settings_id
    FROM settings s
    WHERE s.active = true
      AND NOT EXISTS (
          SELECT 1 FROM department_settings sd 
          WHERE sd.settings_id = s.id AND sd.active = true
      )
    LIMIT 1
),
profile_primary_department AS (
    SELECT pd.department_id
    FROM profile_departments pd
    WHERE pd.profile_id = profile_id 
      AND pd.is_primary = TRUE 
      AND pd.active = true
    LIMIT 1
),
dept_specific_settings AS (
    SELECT s.id as settings_id
    FROM settings s
    JOIN department_settings sd ON sd.settings_id = s.id
    JOIN profile_primary_department ppd ON sd.department_id = ppd.department_id
    WHERE s.active = true 
      AND sd.active = true
    LIMIT 1
),
active_settings AS (
    SELECT 
        COALESCE(
            (SELECT settings_id FROM dept_specific_settings),
            (SELECT settings_id FROM default_settings),
            (SELECT id FROM settings WHERE active = true LIMIT 1)
        ) as settings_id
)
SELECT spk.key_id::text as key_id
FROM models m
JOIN providers p ON p.id = m.provider_id
CROSS JOIN active_settings act_s
JOIN setting_provider_keys spk ON spk.provider_id = p.id 
    AND spk.settings_id = act_s.settings_id 
    AND spk.active = true
JOIN keys k ON k.id = spk.key_id AND k.active = true
WHERE m.id = model_id
LIMIT 1
$$;


--
-- Name: api_get_key_new_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_key_new_v4(profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(key_id text, name text, key_masked text, description text, active boolean, created_at timestamp with time zone, updated_at timestamp with time zone, department_ids text[], model_ids text[], valid_department_ids text[], can_edit boolean, departments types.q_get_key_new_v4_department[], models types.q_get_key_new_v4_model[], actor_name text, draft_version integer)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id, draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'keys'::draft_resource_type
    LIMIT 1
),
actor_profile AS (
    SELECT 
        p.id as profile_id,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
user_departments AS (
    SELECT DISTINCT pd.department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.active = true
),
valid_depts AS (
    SELECT 
        ARRAY_AGG(d.id::text ORDER BY d.title) as dept_ids
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.active = true
    JOIN departments d ON d.id = pd.department_id AND d.active = true
),
departments_data AS (
    SELECT DISTINCT
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.active = true
    JOIN departments d ON d.id = pd.department_id AND d.active = true
),
profile_data AS (
    SELECT role as user_role 
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
primary_department_id AS (
    SELECT department_id::text
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id
    WHERE pd.is_primary = TRUE AND pd.active = true
    LIMIT 1
)
SELECT 
    ''::text as key_id,
    COALESCE(
        (SELECT payload->>'name' FROM draft_payload_data),
        ''::text
    ) as name,
    '****'::text as key_masked,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        ''::text
    ) as description,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        true::boolean
    ) as active,
    NOW()::timestamptz as created_at,
    NOW()::timestamptz as updated_at,
    -- Set default department_ids based on role
    -- Superadmin: NULL (empty = all departments = default object)
    -- Non-superadmin: [primaryDepartmentId] if available
    CASE 
        WHEN pr.user_role = 'superadmin' THEN NULL::text[]
        WHEN pd.department_id IS NOT NULL THEN ARRAY[pd.department_id]
        ELSE ARRAY[]::text[]
    END as department_ids,
    ARRAY[]::text[] as model_ids,
    COALESCE(vd.dept_ids, ARRAY[]::text[]) as valid_department_ids,
    -- Default keys (empty department_ids) are read-only for non-superadmin
    CASE 
        WHEN pr.user_role = 'superadmin' THEN true
        WHEN pr.user_role = 'admin' AND pd.department_id IS NOT NULL THEN true
        ELSE false
    END::boolean as can_edit,
    COALESCE(
        ARRAY_AGG(
            (dd.department_id, dd.name, dd.description)::types.q_get_key_new_v4_department
            ORDER BY dd.name
        ) FILTER (WHERE dd.department_id IS NOT NULL),
        '{}'::types.q_get_key_new_v4_department[]
    ) as departments,
    '{}'::types.q_get_key_new_v4_model[] as models,
    ap.actor_name::text as actor_name,
    COALESCE(
        (SELECT draft_version FROM draft_payload_data),
        0
    )::int as draft_version
FROM valid_depts vd
CROSS JOIN profile_data pr
LEFT JOIN primary_department_id pd ON true
CROSS JOIN departments_data dd
CROSS JOIN actor_profile ap
GROUP BY pr.user_role, pd.department_id, vd.dept_ids, ap.actor_name
$$;


--
-- Name: api_get_keys_list_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_keys_list_v4(profile_id uuid) RETURNS TABLE(actor_name text, keys types.q_get_keys_list_v4_key[], departments types.q_get_keys_list_v4_department[], models types.q_get_keys_list_v4_model[], department_options types.q_get_keys_list_v4_department_option[], model_options types.q_get_keys_list_v4_model_option[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id
),
user_departments AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments ON profile_departments.profile_id = x.profile_id AND profile_departments.active = true
),
user_profile AS (
    SELECT 
        role,
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
-- Get department_ids via setting_provider_keys -> settings -> department_settings
key_departments_data AS (
    SELECT 
        spk.key_id,
        ARRAY_AGG(DISTINCT ds.department_id::text ORDER BY ds.department_id::text) as department_ids
    FROM setting_provider_keys spk
    JOIN settings s ON s.id = spk.settings_id AND s.active = true
    JOIN department_settings ds ON ds.settings_id = s.id AND ds.active = true
    WHERE spk.active = true
    GROUP BY spk.key_id
),
-- Get model_ids via setting_provider_keys -> providers -> models
key_models_data AS (
    SELECT 
        spk.key_id,
        ARRAY_AGG(m.id::text ORDER BY m.name) as model_ids
    FROM setting_provider_keys spk
    JOIN providers p ON p.id = spk.provider_id
    JOIN models m ON m.provider_id = p.id
    WHERE spk.active = true AND m.active = true
    GROUP BY spk.key_id
),
key_data AS (
    SELECT 
        k.id as key_id,
        k.name,
        CASE 
            WHEN LENGTH(k.key) > 4 THEN LEFT(k.key, 4) || '****'
            ELSE '****'
        END as key_masked,
        k.description,
        k.active,
        k.created_at,
        k.updated_at,
        COALESCE(kdd.department_ids, NULL) as department_ids,
        COALESCE(kmd.model_ids, ARRAY[]::text[]) as model_ids,
        CASE 
            -- Default keys (no department_ids) are read-only for non-superadmin
            WHEN COALESCE(kdd.department_ids, NULL) IS NULL AND up.role != 'superadmin' THEN false
            WHEN up.role = 'superadmin' THEN true
            WHEN up.role = 'admin' AND (
                -- Check if key is linked to settings that are linked to user's departments
                EXISTS (
                    SELECT 1 FROM setting_provider_keys spk
                    JOIN settings s ON s.id = spk.settings_id AND s.active = true
                    JOIN department_settings ds ON ds.settings_id = s.id AND ds.active = true
                    JOIN user_departments ud ON ud.department_id = ds.department_id
                    WHERE spk.key_id = k.id AND spk.active = true
                )
                OR NOT EXISTS (SELECT 1 FROM key_departments_data kdd2 WHERE kdd2.key_id = k.id)
            ) THEN true
            ELSE false
        END as can_edit,
        CASE 
            -- Can't delete if can't edit
            WHEN COALESCE(kdd.department_ids, NULL) IS NULL AND up.role != 'superadmin' THEN false
            WHEN up.role = 'superadmin' THEN true
            WHEN up.role = 'admin' AND (
                EXISTS (
                    SELECT 1 FROM setting_provider_keys spk
                    JOIN settings s ON s.id = spk.settings_id AND s.active = true
                    JOIN department_settings ds ON ds.settings_id = s.id AND ds.active = true
                    JOIN user_departments ud ON ud.department_id = ds.department_id
                    WHERE spk.key_id = k.id AND spk.active = true
                )
                OR NOT EXISTS (SELECT 1 FROM key_departments_data kdd2 WHERE kdd2.key_id = k.id)
            ) THEN true
            ELSE false
        END as can_delete,
        true as can_duplicate
    FROM keys k
    LEFT JOIN key_departments_data kdd ON kdd.key_id = k.id
    LEFT JOIN key_models_data kmd ON kmd.key_id = k.id
    CROSS JOIN user_profile up
    WHERE 
        -- Include keys with matching department links OR default keys (no department links)
        EXISTS (
            SELECT 1 FROM setting_provider_keys spk
            JOIN settings s ON s.id = spk.settings_id AND s.active = true
            JOIN department_settings ds ON ds.settings_id = s.id AND ds.active = true
            JOIN user_departments ud ON ud.department_id = ds.department_id
            WHERE spk.key_id = k.id AND spk.active = true
        )
        OR NOT EXISTS (SELECT 1 FROM key_departments_data kdd2 WHERE kdd2.key_id = k.id)
        OR up.role = 'superadmin'
),
all_department_ids AS (
    SELECT DISTINCT unnest(department_ids)::uuid as department_id
    FROM key_departments_data
    WHERE department_ids IS NOT NULL
    UNION
    SELECT department_id FROM user_departments
),
all_model_ids AS (
    SELECT DISTINCT unnest(model_ids)::uuid as model_id
    FROM key_models_data
    WHERE model_ids IS NOT NULL
),
departments_data AS (
    SELECT DISTINCT
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM departments d
    WHERE d.id IN (SELECT department_id FROM all_department_ids)
),
models_data AS (
    SELECT DISTINCT
        m.id as model_id,
        m.name,
        COALESCE(m.description, '') as description,
        p.value as provider,
        m.active
    FROM models m
    JOIN providers p ON p.id = m.provider_id
    WHERE m.id IN (SELECT model_id FROM all_model_ids)
)
SELECT 
    up.actor_name::text as actor_name,
    COALESCE(
        ARRAY_AGG(
            (kd.key_id, kd.name, kd.key_masked, kd.description, kd.active, kd.created_at, kd.updated_at, 
             kd.department_ids, kd.model_ids, kd.can_edit, kd.can_delete, kd.can_duplicate
            )::types.q_get_keys_list_v4_key
            ORDER BY kd.created_at DESC
        ),
        '{}'::types.q_get_keys_list_v4_key[]
    ) as keys,
    COALESCE(
        ARRAY_AGG(
            (dd.department_id, dd.name, dd.description)::types.q_get_keys_list_v4_department
            ORDER BY dd.name
        ) FILTER (WHERE dd.department_id IS NOT NULL),
        '{}'::types.q_get_keys_list_v4_department[]
    ) as departments,
    COALESCE(
        ARRAY_AGG(
            (md.model_id, md.name, md.description, md.provider, md.active)::types.q_get_keys_list_v4_model
            ORDER BY md.name
        ) FILTER (WHERE md.model_id IS NOT NULL),
        '{}'::types.q_get_keys_list_v4_model[]
    ) as models,
    COALESCE(
        ARRAY_AGG(
            (dd.department_id::text, dd.name)::types.q_get_keys_list_v4_department_option
            ORDER BY dd.name
        ) FILTER (WHERE dd.department_id IS NOT NULL),
        '{}'::types.q_get_keys_list_v4_department_option[]
    ) as department_options,
    COALESCE(
        ARRAY_AGG(
            (md.model_id::text, md.name)::types.q_get_keys_list_v4_model_option
            ORDER BY md.name
        ) FILTER (WHERE md.model_id IS NOT NULL),
        '{}'::types.q_get_keys_list_v4_model_option[]
    ) as model_options
FROM key_data kd
CROSS JOIN user_profile up
CROSS JOIN departments_data dd
CROSS JOIN models_data md
GROUP BY up.actor_name
$$;


--
-- Name: api_get_latest_message_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_latest_message_v4(chat_id uuid) RETURNS TABLE(id uuid, chat_id uuid, role text, content text, created_at timestamp with time zone, completed boolean, updated_at timestamp with time zone)
    LANGUAGE sql STABLE
    AS $$
SELECT 
    m.id,
    c.id AS chat_id,
    m.role,
    cnt.content,
    m.created_at,
    m.completed,
    m.updated_at
FROM chats c
JOIN chat_groups cg ON cg.chat_id = c.id
JOIN groups g ON g.id = cg.group_id
JOIN group_runs gr ON gr.group_id = g.id
JOIN runs r ON r.id = gr.run_id
JOIN message_runs mr ON mr.run_id = r.id
JOIN messages m ON m.id = mr.message_id
LEFT JOIN message_content mc ON mc.message_id = m.id AND mc.idx = 0
        LEFT JOIN content cnt ON cnt.id = mc.content_id
WHERE c.id = chat_id
  AND NOT EXISTS (
      SELECT 1 FROM message_tree mt 
      WHERE mt.parent_id = m.id AND mt.active = true
  )
ORDER BY m.created_at DESC
LIMIT 1
$$;


--
-- Name: api_get_latest_run_for_chat_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_latest_run_for_chat_v4(chat_id uuid) RETURNS TABLE(run_id text)
    LANGUAGE sql STABLE
    AS $$
SELECT gr.run_id::text as run_id
FROM chats c
JOIN chat_groups cg ON cg.chat_id = c.id
JOIN groups g ON g.id = cg.group_id
JOIN group_runs gr ON gr.group_id = g.id
JOIN runs r ON r.id = gr.run_id
WHERE c.id = chat_id
ORDER BY r.created_at DESC
LIMIT 1
$$;


--
-- Name: api_get_leaderboard_bundle_v4(text, text, uuid, text[], uuid[], text[], uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_leaderboard_bundle_v4(start_date text, end_date text, profile_id uuid, roles text[] DEFAULT ARRAY[]::text[], cohort_ids uuid[] DEFAULT ARRAY[]::uuid[], simulation_filters text[] DEFAULT ARRAY['general'::text], department_ids uuid[] DEFAULT ARRAY[]::uuid[]) RETURNS TABLE(actor_name text, data types.q_get_leaderboard_bundle_v4_row[], simulations types.q_get_leaderboard_bundle_v4_simulation[], scenarios types.q_get_leaderboard_bundle_v4_scenario[], primary_color text, accent_color text)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        start_date::timestamptz AS start_date,
        end_date::timestamptz AS end_date,
        profile_id AS profile_id,
        COALESCE(NULLIF(roles, ARRAY[]::text[]), ARRAY[]::text[]) AS roles,
        COALESCE(NULLIF(cohort_ids, ARRAY[]::uuid[]), ARRAY[]::uuid[]) AS cohort_ids,
        COALESCE(NULLIF(simulation_filters, ARRAY[]::text[]), ARRAY['general']::text[]) AS simulation_filters,
        COALESCE(NULLIF(department_ids, ARRAY[]::uuid[]), ARRAY[]::uuid[]) AS department_ids
),
-- Get colors from active settings (defaults if no settings found)
settings_colors AS (
    SELECT 
        COALESCE(primary_color, '#171717') AS primary_color,
        COALESCE(accent, '#f5f5f5') AS accent
    FROM settings
    WHERE active = true
    LIMIT 1
),
-- Get actor name from profile
user_profile AS (
    SELECT 
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
filt AS (
    SELECT * FROM analytics a 
    WHERE a.attempt_created_at >= (SELECT start_date FROM params)
      AND a.attempt_created_at < (SELECT end_date FROM params)
      AND (
          -- Default to general if no filters specified
          cardinality((SELECT simulation_filters FROM params)::text[]) = 0
          OR (
              -- General filter
              ('general' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_general = TRUE) OR
              -- Practice filter
              ('practice' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_practice = TRUE) OR
              -- Archived filter: if general/practice also selected, include archived OR non-general/non-practice
              -- Otherwise, just archived
              ('archived' = ANY((SELECT simulation_filters FROM params)::text[]) AND (
                  (('general' = ANY((SELECT simulation_filters FROM params)::text[]) OR 'practice' = ANY((SELECT simulation_filters FROM params)::text[])) 
                   AND (a.is_archived = TRUE OR (a.is_general = FALSE AND a.is_practice = FALSE)))
                  OR
                  (NOT ('general' = ANY((SELECT simulation_filters FROM params)::text[]) OR 'practice' = ANY((SELECT simulation_filters FROM params)::text[]))
                   AND a.is_archived = TRUE)
              ))
          )
      )
      AND (cardinality((SELECT roles FROM params)::text[]) = 0 OR a.profile_role::text = ANY((SELECT roles FROM params)::text[]))
      AND (cardinality((SELECT cohort_ids FROM params)::uuid[]) = 0 OR a.simulation_id IN (
          SELECT DISTINCT s.id
          FROM simulations s
          WHERE s.active = TRUE
            AND (
                EXISTS (
                    SELECT 1 
                    FROM cohort_simulations cs 
                    WHERE cs.simulation_id = s.id 
                      AND cs.cohort_id = ANY((SELECT cohort_ids FROM params)::uuid[])
                      AND cs.active = TRUE
                )
                OR
                (s.practice_simulation = TRUE 
                 AND NOT EXISTS (
                     SELECT 1 
                     FROM cohort_simulations cs2 
                     WHERE cs2.simulation_id = s.id 
                       AND cs2.active = TRUE
                 ))
            )
      ))
      AND (cardinality((SELECT department_ids FROM params)::uuid[]) = 0 OR a.department_id = ANY((SELECT department_ids FROM params)::uuid[]))
),
profile_stats AS (
    SELECT
        f.profile_id,
        p.first_name,
        p.last_name,
        COUNT(DISTINCT f.attempt_id)::int AS total_attempts,
        MAX(f.grade_percent) FILTER (WHERE f.grade_percent IS NOT NULL) AS highest_score,
        AVG(f.num_messages_total) FILTER (WHERE f.num_messages_total IS NOT NULL) AS avg_messages,
        COALESCE(SUM(LEAST(f.time_taken_seconds / 60.0, 30.0)) FILTER (WHERE f.time_taken_seconds IS NOT NULL), 0.0)::float AS total_time,
        ARRAY_AGG(DISTINCT f.simulation_id) FILTER (WHERE f.simulation_id IS NOT NULL) AS simulation_ids,
        ARRAY_AGG(DISTINCT f.scenario_id) FILTER (WHERE f.scenario_id IS NOT NULL) AS scenario_ids
    FROM filt f
    JOIN profiles p ON f.profile_id = p.id
    GROUP BY f.profile_id, p.first_name, p.last_name
),
-- Persona response times per profile
persona_times AS (
    SELECT
        f.profile_id,
        UNNEST(f.message_time_taken_seconds) AS delta_sec
    FROM filt f
    WHERE cardinality(f.message_time_taken_seconds) > 0
),
persona_per_profile AS (
    SELECT
        profile_id,
        ROUND(AVG(delta_sec))::int AS avg_response_time
    FROM persona_times
    GROUP BY profile_id
),
-- Improvement rate per day per profile
attempt_grades AS (
    SELECT
        simulation_id,
        attempt_id,
        profile_id,
        MIN(chat_created_at) as first_time,
        MAX(grade_percent) as best_grade
    FROM filt
    WHERE grade_percent IS NOT NULL AND attempt_id IS NOT NULL
    GROUP BY simulation_id, attempt_id, profile_id
),
sim_improvement_rates AS (
    SELECT
        profile_id,
        simulation_id,
        CASE
            WHEN COUNT(*) >= 2 THEN
                ROUND(
                    (MAX(best_grade) - MIN(best_grade)) /
                    GREATEST(1.0,
                        EXTRACT(EPOCH FROM (MAX(first_time) - MIN(first_time))) / 86400.0
                    )
                )::int
            ELSE 0
        END AS improvement_rate
    FROM attempt_grades
    GROUP BY profile_id, simulation_id
),
improvement_per_profile AS (
    SELECT
        profile_id,
        MAX(improvement_rate) AS max_improvement_rate
    FROM sim_improvement_rates
    GROUP BY profile_id
),
-- Perfect score count per profile
perfect_per_profile AS (
    SELECT
        profile_id,
        COUNT(*) AS perfect_count
    FROM filt
    WHERE grade_percent >= 100.0
    GROUP BY profile_id
),
-- Quickest pass per profile
quickest_per_profile AS (
    SELECT
        profile_id,
        MIN(time_taken_seconds / 60.0) AS quickest_minutes
    FROM filt
    WHERE passed = TRUE AND time_taken_seconds IS NOT NULL
    GROUP BY profile_id
),
-- Join all metrics together
all_stats AS (
    SELECT
        ps.*,
        COALESCE(pp.avg_response_time, 0) AS persona_response_time,
        COALESCE(ip.max_improvement_rate, 0) AS improvement_rate,
        COALESCE(pf.perfect_count, 0) AS perfect_count,
        COALESCE(qp.quickest_minutes, 0) AS quickest_pass
    FROM profile_stats ps
    LEFT JOIN persona_per_profile pp ON ps.profile_id = pp.profile_id
    LEFT JOIN improvement_per_profile ip ON ps.profile_id = ip.profile_id
    LEFT JOIN perfect_per_profile pf ON ps.profile_id = pf.profile_id
    LEFT JOIN quickest_per_profile qp ON ps.profile_id = qp.profile_id
),
-- Get all unique simulation IDs for mapping
all_simulation_ids AS (
    SELECT DISTINCT unnest(simulation_ids) AS simulation_id
    FROM profile_stats
    WHERE simulation_ids IS NOT NULL
),
simulation_data AS (
    SELECT 
        s.id as simulation_id,
        s.title as name,
        COALESCE(s.description, '') as description,
        COALESCE(
            (SELECT SUM(stl.time_limit_seconds)
             FROM scenario_time_limits stl
             JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
             WHERE stl.simulation_id = s.id AND stl.active = true AND ss.active = true),
            0
        )::int as time_limit,
        COALESCE(
            (SELECT ARRAY_AGG(sd.department_id::text ORDER BY sd.created_at)
             FROM simulation_departments sd
             WHERE sd.simulation_id = s.id AND sd.active = true),
            ARRAY[]::text[]
        ) as department_ids
    FROM all_simulation_ids asi
    LEFT JOIN simulations s ON s.id = asi.simulation_id
    WHERE s.active = true
),
-- Get all unique scenario IDs for mapping
all_scenario_ids AS (
    SELECT DISTINCT unnest(scenario_ids) AS scenario_id
    FROM profile_stats
    WHERE scenario_ids IS NOT NULL
),
scenario_data AS (
    SELECT 
        sc.id as scenario_id,
        sc.name as name,
        COALESCE(
            (SELECT ps.problem_statement 
             FROM scenario_problem_statements sps 
             JOIN problem_statements ps ON ps.id = sps.problem_statement_id 
             WHERE sps.scenario_id = sc.id AND sps.active = true 
             ORDER BY sps.created_at DESC, sps.updated_at DESC 
             LIMIT 1),
            ''
        ) as description
    FROM all_scenario_ids asci
    LEFT JOIN scenarios sc ON sc.id = asci.scenario_id
    WHERE sc.active = true
),
-- Get top 25% of profiles by highest score
ranked_stats AS (
    SELECT 
        *,
        ROW_NUMBER() OVER (ORDER BY highest_score DESC) as rank,
        COUNT(*) OVER () as total_count
    FROM all_stats
),
top_25_percent AS (
    SELECT *
    FROM ranked_stats
    WHERE rank <= GREATEST(1, CEIL(total_count * 0.25)::int)
)
SELECT 
    up.actor_name::text as actor_name,
    COALESCE(
        ARRAY_AGG(
            (t25p.profile_id,
             t25p.first_name,
             t25p.last_name,
             COALESCE(t25p.simulation_ids, ARRAY[]::uuid[]),
             COALESCE(t25p.scenario_ids, ARRAY[]::uuid[]),
             ((true, 'countDistinct', t25p.total_attempts, NULL::text, ARRAY[]::text[], ARRAY[]::text[], ''::text)::types.q_get_leaderboard_bundle_v4_metric,
              (t25p.highest_score IS NOT NULL, 'max', ROUND(COALESCE(t25p.highest_score, 0))::int, NULL::text, ARRAY[]::text[], ARRAY[]::text[], ''::text)::types.q_get_leaderboard_bundle_v4_metric,
              (t25p.avg_messages IS NOT NULL, 'avg', ROUND(COALESCE(t25p.avg_messages, 0))::int, NULL::text, ARRAY[]::text[], ARRAY[]::text[], ''::text)::types.q_get_leaderboard_bundle_v4_metric,
              (t25p.persona_response_time > 0, 'avg', t25p.persona_response_time, NULL::text, ARRAY[]::text[], ARRAY[]::text[], ''::text)::types.q_get_leaderboard_bundle_v4_metric,
              (t25p.total_time IS NOT NULL AND t25p.total_time > 0, 'sum', ROUND(COALESCE(t25p.total_time, 0))::int, NULL::text, ARRAY[]::text[], ARRAY[]::text[], ''::text)::types.q_get_leaderboard_bundle_v4_metric,
              (t25p.improvement_rate > 0, 'slope', t25p.improvement_rate, NULL::text, ARRAY[]::text[], ARRAY[]::text[], ''::text)::types.q_get_leaderboard_bundle_v4_metric,
              (t25p.perfect_count > 0, 'sum', t25p.perfect_count, NULL::text, ARRAY[]::text[], ARRAY[]::text[], ''::text)::types.q_get_leaderboard_bundle_v4_metric,
              (t25p.quickest_pass > 0, 'min', ROUND(t25p.quickest_pass)::int, NULL::text, ARRAY[]::text[], ARRAY[]::text[], ''::text)::types.q_get_leaderboard_bundle_v4_metric)::types.q_get_leaderboard_bundle_v4_metrics
            )::types.q_get_leaderboard_bundle_v4_row
            ORDER BY t25p.highest_score DESC
        ),
        '{}'::types.q_get_leaderboard_bundle_v4_row[]
    ) as data,
    (SELECT COALESCE(
        ARRAY_AGG(
            (sd.simulation_id, sd.name, sd.description, sd.time_limit, sd.department_ids)::types.q_get_leaderboard_bundle_v4_simulation
            ORDER BY sd.name
        ),
        '{}'::types.q_get_leaderboard_bundle_v4_simulation[]
    ) FROM simulation_data sd) as simulations,
    (SELECT COALESCE(
        ARRAY_AGG(
            (scd.scenario_id, scd.name, scd.description)::types.q_get_leaderboard_bundle_v4_scenario
            ORDER BY scd.name
        ),
        '{}'::types.q_get_leaderboard_bundle_v4_scenario[]
    ) FROM scenario_data scd) as scenarios,
    (SELECT primary_color FROM settings_colors LIMIT 1)::text as primary_color,
    (SELECT accent FROM settings_colors LIMIT 1)::text as accent_color
FROM top_25_percent t25p
CROSS JOIN user_profile up
CROSS JOIN settings_colors sc
GROUP BY up.actor_name, sc.primary_color, sc.accent
$$;


--
-- Name: api_get_login_data_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_login_data_v4(department_id uuid DEFAULT NULL::uuid) RETURNS TABLE(providers types.q_get_login_data_v4_provider[], departments types.q_get_login_data_v4_department[], guest_login_enabled boolean, show_default_account boolean, default_department_id text, realm_name text)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT department_id AS department_id
),
-- Get default department from settings_default_department table
default_department_from_settings AS (
    SELECT sdd.department_id
    FROM settings s
    JOIN settings_default_department sdd ON sdd.settings_id = s.id
    WHERE s.active = true AND sdd.active = true
    LIMIT 1
),
-- Get settings for the department (if department_id provided)
-- Note: Include department-specific settings even if inactive (they're linked via department_settings)
dept_settings AS (
    SELECT DISTINCT s.id as settings_id, s.guest_login_enabled
    FROM settings s
    JOIN department_settings ds ON ds.settings_id = s.id
    WHERE ds.active = true
      AND ((SELECT department_id FROM params) IS NULL OR ds.department_id = (SELECT department_id FROM params))
),
-- Get default settings (no department links)
default_settings AS (
    SELECT s.id as settings_id, s.guest_login_enabled
    FROM settings s
    WHERE s.active = true
      AND NOT EXISTS (
          SELECT 1 FROM department_settings ds 
          WHERE ds.settings_id = s.id AND ds.active = true
      )
    LIMIT 1
),
-- Get guest_login_enabled from department-specific settings if department_id provided, otherwise from default settings
active_settings AS (
    SELECT COALESCE(
        CASE 
            WHEN (SELECT department_id FROM params) IS NOT NULL THEN (SELECT guest_login_enabled FROM dept_settings LIMIT 1)
            ELSE NULL
        END,
        (SELECT guest_login_enabled FROM default_settings LIMIT 1),
        true
    ) as guest_login_enabled
),
-- Get auths linked to department settings or default settings
dept_auths AS (
    SELECT DISTINCT a.id
    FROM auth a
    JOIN setting_auths sa ON sa.auth_id = a.id AND sa.active = true
    JOIN dept_settings ds ON ds.settings_id = sa.settings_id
    WHERE a.active = true
),
-- Get auths linked to default settings
default_auths AS (
    SELECT DISTINCT a.id
    FROM auth a
    JOIN setting_auths sa ON sa.auth_id = a.id AND sa.active = true
    JOIN default_settings ds ON ds.settings_id = sa.settings_id
    WHERE a.active = true
),
-- Providers query (always returns at least one row)
providers_data AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (a.slug::text, a.name::text, COALESCE(a.icon_url, '')::text, EXISTS (SELECT 1 FROM default_auths da WHERE da.id = a.id))::types.q_get_login_data_v4_provider
                ORDER BY a.name
            ),
            '{}'::types.q_get_login_data_v4_provider[]
        ) as providers
    FROM auth a
    CROSS JOIN (SELECT guest_login_enabled FROM active_settings LIMIT 1) s
    WHERE a.active = true
      AND (
          -- Include if department_id not provided (show all auths from all settings)
          (SELECT department_id FROM params) IS NULL
          -- OR if department_id is provided, ONLY include department-specific auths (exclude default ones)
          OR (
              (SELECT department_id FROM params) IS NOT NULL
              AND EXISTS (SELECT 1 FROM dept_auths da WHERE da.id = a.id)
          )
      )
),
-- Ensure providers_data always returns a row
providers_with_default AS (
    SELECT providers FROM providers_data
    UNION ALL
    SELECT '{}'::types.q_get_login_data_v4_provider[] WHERE NOT EXISTS (SELECT 1 FROM providers_data)
),
-- Departments query (always returns at least one row)
-- Order: default department first, then alphabetical by title
departments_data AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (id::text, title::text, description::text)::types.q_get_login_data_v4_department
                ORDER BY 
                    -- Default department first (NULLS LAST means non-defaults come after)
                    CASE WHEN id = (SELECT department_id FROM default_department_from_settings LIMIT 1) 
                         THEN 0 ELSE 1 END,
                    -- Then alphabetical by title
                    title
            ),
            '{}'::types.q_get_login_data_v4_department[]
        ) as departments
    FROM departments 
    WHERE active = true
),
-- Ensure departments_data always returns a row
departments_with_default AS (
    SELECT departments FROM departments_data
    UNION ALL
    SELECT '{}'::types.q_get_login_data_v4_department[] WHERE NOT EXISTS (SELECT 1 FROM departments_data)
),
-- Calculate realm name: use settings_id if dept settings has keys, else 'master'
-- Simplified: Check if dept settings has keys, if yes use settings_id, else 'master'
realm_name_calc AS (
    SELECT 
        CASE 
            -- No department → master realm
            WHEN (SELECT department_id FROM params) IS NULL THEN 'master'::text
            -- Check if department-specific settings has keys
            WHEN EXISTS (
                SELECT 1 
                FROM department_settings ds
                JOIN settings s ON s.id = ds.settings_id AND s.active = true
                JOIN setting_auth_keys sak ON sak.settings_id = s.id AND sak.active = true
                WHERE ds.department_id = (SELECT department_id FROM params) AND ds.active = true
            ) THEN (
                -- Department settings has keys → use settings_id as realm
                SELECT s.id::text
                FROM department_settings ds
                JOIN settings s ON s.id = ds.settings_id AND s.active = true
                WHERE ds.department_id = (SELECT department_id FROM params) AND ds.active = true
                LIMIT 1
            )
            -- No keys in dept settings → use master realm
            ELSE 'master'::text
        END as realm_name
),
-- Check department-specific default account (if department_id provided)
dept_default_account_check AS (
    SELECT EXISTS (
        SELECT 1
        FROM settings s
        JOIN department_settings ds ON ds.settings_id = s.id AND ds.active = true
        JOIN settings_default_account sda ON sda.settings_id = s.id AND sda.active = true
        WHERE ds.department_id = (SELECT department_id FROM params)
          AND s.active = true
          AND (SELECT department_id FROM params) IS NOT NULL
    )::boolean as dept_has_default_account
),
-- Check default settings default account (fallback)
default_settings_default_account_check AS (
    SELECT EXISTS (
        SELECT 1
        FROM settings s
        JOIN settings_default_account sda ON sda.settings_id = s.id AND sda.active = true
        WHERE s.active = true
          AND NOT EXISTS (
              SELECT 1 FROM department_settings ds 
              WHERE ds.settings_id = s.id AND ds.active = true
          )
    )::boolean as default_settings_has_default_account
),
-- Calculate show_default_account: show if no providers AND default account exists
show_default_account_calc AS (
    SELECT 
        CASE 
            -- No providers exist
            WHEN array_length((SELECT providers FROM providers_with_default LIMIT 1), 1) IS NULL OR array_length((SELECT providers FROM providers_with_default LIMIT 1), 1) = 0 THEN
                CASE 
                    -- Department-specific: check department settings first, fallback to default settings
                    WHEN (SELECT department_id FROM params) IS NOT NULL THEN
                        COALESCE(
                            (SELECT dept_has_default_account FROM dept_default_account_check),
                            (SELECT default_settings_has_default_account FROM default_settings_default_account_check),
                            false
                        )
                    -- No department: check default settings only
                    ELSE
                        COALESCE(
                            (SELECT default_settings_has_default_account FROM default_settings_default_account_check),
                            false
                        )
                END
            -- Providers exist → don't show default account
            ELSE false
        END::boolean as show_default_account
)
-- Cross join ensures we always get exactly one row
SELECT 
    p.providers as providers,
    d.departments as departments,
    COALESCE((SELECT guest_login_enabled FROM active_settings LIMIT 1), true)::boolean as guest_login_enabled,
    COALESCE((SELECT show_default_account FROM show_default_account_calc LIMIT 1), false)::boolean as show_default_account,
    COALESCE((SELECT department_id::text FROM default_department_from_settings LIMIT 1), NULL)::text as default_department_id,
    (SELECT realm_name FROM realm_name_calc LIMIT 1)::text as realm_name
FROM providers_with_default p
CROSS JOIN departments_with_default d
CROSS JOIN realm_name_calc
CROSS JOIN show_default_account_calc
LIMIT 1
$$;


--
-- Name: api_get_logs_bundle_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_logs_bundle_v4(profile_id uuid DEFAULT NULL::uuid) RETURNS TABLE(actor_name text, health_kpis types.q_get_logs_bundle_v4_health_kpis, metrics types.q_get_logs_bundle_v4_metrics_data_point[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id
),
-- Current health status for each service (latest record per service)
current_health AS (
    SELECT DISTINCT ON (service)
        service,
        ok,
        latency_ms,
        error,
        ts
    FROM service_health
    WHERE service IN ('websocket', 'redis', 'tus', 'database', 'keycloak')
    ORDER BY service, ts DESC
),

-- Health trend data for each service (last 7 days, aggregated by hour)
health_trends AS (
    SELECT 
        service,
        date_trunc('hour', ts) as date_hour,
        COUNT(*) FILTER (WHERE ok = true)::float / NULLIF(COUNT(*), 0) * 100.0 as uptime_percent,
        AVG(latency_ms) as avg_latency_ms,
        COUNT(*) as check_count
    FROM service_health
    WHERE service IN ('websocket', 'redis', 'tus', 'database', 'keycloak')
      AND ts >= NOW() - INTERVAL '7 days'
    GROUP BY service, date_hour
    ORDER BY service, date_hour
),

-- Health trend data formatted for each service
websocket_trend AS (
    SELECT 
        to_char(date_hour, 'YYYY-MM-DD HH24:MI:SS') as date,
        ROUND(uptime_percent::numeric, 2)::float as value,
        ROUND(avg_latency_ms::numeric, 2)::float as latency,
        check_count::int as count
    FROM health_trends
    WHERE service = 'websocket'
    ORDER BY date_hour
),

redis_trend AS (
    SELECT 
        to_char(date_hour, 'YYYY-MM-DD HH24:MI:SS') as date,
        ROUND(uptime_percent::numeric, 2)::float as value,
        ROUND(avg_latency_ms::numeric, 2)::float as latency,
        check_count::int as count
    FROM health_trends
    WHERE service = 'redis'
    ORDER BY date_hour
),

document_trend AS (
    SELECT 
        to_char(date_hour, 'YYYY-MM-DD HH24:MI:SS') as date,
        ROUND(uptime_percent::numeric, 2)::float as value,
        ROUND(avg_latency_ms::numeric, 2)::float as latency,
        check_count::int as count
    FROM health_trends
    WHERE service = 'tus'
    ORDER BY date_hour
),

database_trend AS (
    SELECT 
        to_char(date_hour, 'YYYY-MM-DD HH24:MI:SS') as date,
        ROUND(uptime_percent::numeric, 2)::float as value,
        ROUND(avg_latency_ms::numeric, 2)::float as latency,
        check_count::int as count
    FROM health_trends
    WHERE service = 'database'
    ORDER BY date_hour
),

authentication_trend AS (
    SELECT 
        to_char(date_hour, 'YYYY-MM-DD HH24:MI:SS') as date,
        ROUND(uptime_percent::numeric, 2)::float as value,
        ROUND(avg_latency_ms::numeric, 2)::float as latency,
        check_count::int as count
    FROM health_trends
    WHERE service = 'keycloak'
    ORDER BY date_hour
),

-- Build health KPIs with composite types
websocket_kpi AS (
    SELECT 
        COALESCE((SELECT ok FROM current_health WHERE service = 'websocket' LIMIT 1), false) as ok,
        COALESCE(ROUND((SELECT latency_ms FROM current_health WHERE service = 'websocket' LIMIT 1)::numeric, 2)::float, 0.0) as latency_ms,
        COALESCE((SELECT error FROM current_health WHERE service = 'websocket' LIMIT 1), 'No data') as error,
        COALESCE(
            (SELECT ARRAY_AGG(
                (wt.date, wt.value, wt.latency, wt.count)::types.q_get_logs_bundle_v4_trend_data
                ORDER BY wt.date
            ) FROM websocket_trend wt),
            '{}'::types.q_get_logs_bundle_v4_trend_data[]
        ) as trend
),

redis_kpi AS (
    SELECT 
        COALESCE((SELECT ok FROM current_health WHERE service = 'redis' LIMIT 1), false) as ok,
        COALESCE(ROUND((SELECT latency_ms FROM current_health WHERE service = 'redis' LIMIT 1)::numeric, 2)::float, 0.0) as latency_ms,
        COALESCE((SELECT error FROM current_health WHERE service = 'redis' LIMIT 1), 'No data') as error,
        COALESCE(
            (SELECT ARRAY_AGG(
                (rt.date, rt.value, rt.latency, rt.count)::types.q_get_logs_bundle_v4_trend_data
                ORDER BY rt.date
            ) FROM redis_trend rt),
            '{}'::types.q_get_logs_bundle_v4_trend_data[]
        ) as trend
),

document_kpi AS (
    SELECT 
        COALESCE((SELECT ok FROM current_health WHERE service = 'tus' LIMIT 1), false) as ok,
        COALESCE(ROUND((SELECT latency_ms FROM current_health WHERE service = 'tus' LIMIT 1)::numeric, 2)::float, 0.0) as latency_ms,
        COALESCE((SELECT error FROM current_health WHERE service = 'tus' LIMIT 1), 'No data') as error,
        COALESCE(
            (SELECT ARRAY_AGG(
                (dt.date, dt.value, dt.latency, dt.count)::types.q_get_logs_bundle_v4_trend_data
                ORDER BY dt.date
            ) FROM document_trend dt),
            '{}'::types.q_get_logs_bundle_v4_trend_data[]
        ) as trend
),

database_kpi AS (
    SELECT 
        COALESCE((SELECT ok FROM current_health WHERE service = 'database' LIMIT 1), false) as ok,
        COALESCE(ROUND((SELECT latency_ms FROM current_health WHERE service = 'database' LIMIT 1)::numeric, 2)::float, 0.0) as latency_ms,
        COALESCE((SELECT error FROM current_health WHERE service = 'database' LIMIT 1), 'No data') as error,
        COALESCE(
            (SELECT ARRAY_AGG(
                (dbt.date, dbt.value, dbt.latency, dbt.count)::types.q_get_logs_bundle_v4_trend_data
                ORDER BY dbt.date
            ) FROM database_trend dbt),
            '{}'::types.q_get_logs_bundle_v4_trend_data[]
        ) as trend
),

authentication_kpi AS (
    SELECT 
        COALESCE((SELECT ok FROM current_health WHERE service = 'keycloak' LIMIT 1), false) as ok,
        COALESCE(ROUND((SELECT latency_ms FROM current_health WHERE service = 'keycloak' LIMIT 1)::numeric, 2)::float, 0.0) as latency_ms,
        COALESCE((SELECT error FROM current_health WHERE service = 'keycloak' LIMIT 1), 'No data') as error,
        COALESCE(
            (SELECT ARRAY_AGG(
                (at.date, at.value, at.latency, at.count)::types.q_get_logs_bundle_v4_trend_data
                ORDER BY at.date
            ) FROM authentication_trend at),
            '{}'::types.q_get_logs_bundle_v4_trend_data[]
        ) as trend
),

-- App metrics time series (last 7 days, aggregated by hour)
metrics_trend AS (
    SELECT 
        date_trunc('hour', ts) as date_hour,
        AVG(cpu_percent) as avg_cpu_percent,
        AVG(avg_latency_ms) as avg_latency_ms,
        AVG(memory_bytes) as avg_memory_bytes,
        MAX(requests_total) as max_requests_total,
        MAX(errors_total) as max_errors_total,
        COUNT(*) as sample_count
    FROM app_metrics
    WHERE ts >= NOW() - INTERVAL '7 days'
    GROUP BY date_hour
    ORDER BY date_hour
),
health_kpis_row AS (
    SELECT 
        (
            (SELECT (ok, latency_ms, error, trend)::types.q_get_logs_bundle_v4_health_kpi FROM websocket_kpi LIMIT 1),
            (SELECT (ok, latency_ms, error, trend)::types.q_get_logs_bundle_v4_health_kpi FROM redis_kpi LIMIT 1),
            (SELECT (ok, latency_ms, error, trend)::types.q_get_logs_bundle_v4_health_kpi FROM document_kpi LIMIT 1),
            (SELECT (ok, latency_ms, error, trend)::types.q_get_logs_bundle_v4_health_kpi FROM database_kpi LIMIT 1),
            (SELECT (ok, latency_ms, error, trend)::types.q_get_logs_bundle_v4_health_kpi FROM authentication_kpi LIMIT 1)
        )::types.q_get_logs_bundle_v4_health_kpis as health_kpis
),
actor_profile AS (
    SELECT COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM profiles
    WHERE id = (SELECT profile_id FROM params)
    LIMIT 1
)
SELECT 
    COALESCE((SELECT actor_name FROM actor_profile), 'System')::text as actor_name,
    (SELECT health_kpis FROM health_kpis_row) as health_kpis,
    COALESCE(
        ARRAY_AGG(
            (
                to_char(mt.date_hour, 'YYYY-MM-DD HH24:MI:SS'),
                ROUND(mt.avg_cpu_percent::numeric, 2)::float,
                ROUND(mt.avg_latency_ms::numeric, 2)::float,
                ROUND(mt.avg_memory_bytes::numeric, 0)::bigint,
                mt.max_requests_total,
                mt.max_errors_total,
                mt.sample_count
            )::types.q_get_logs_bundle_v4_metrics_data_point
            ORDER BY mt.date_hour
        ),
        '{}'::types.q_get_logs_bundle_v4_metrics_data_point[]
    ) as metrics
FROM metrics_trend mt
$$;


--
-- Name: api_get_message_created_at_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_message_created_at_v4(message_id uuid) RETURNS TABLE(created_at timestamp with time zone)
    LANGUAGE sql STABLE
    AS $$
SELECT created_at FROM messages WHERE id = message_id
$$;


--
-- Name: api_get_message_id_from_tool_call_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_message_id_from_tool_call_v4(tool_call_id uuid, run_id uuid) RETURNS TABLE(message_id uuid)
    LANGUAGE sql STABLE
    AS $$
SELECT m.id as message_id
FROM calls tc
JOIN tool_call_runs tcr ON tcr.tool_call_id = tc.id
JOIN message_runs mr ON mr.run_id = tcr.run_id
JOIN messages m ON m.id = mr.message_id
WHERE tc.id = api_get_message_id_from_tool_call_v4.tool_call_id
  AND tcr.run_id = api_get_message_id_from_tool_call_v4.run_id
  AND m.role = 'assistant'::message_role
ORDER BY m.created_at DESC
LIMIT 1
$$;


--
-- Name: api_get_messages_count_by_chat_ids_v4(uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_messages_count_by_chat_ids_v4(chat_ids uuid[]) RETURNS TABLE(chat_id uuid, message_count bigint)
    LANGUAGE sql STABLE
    AS $$
SELECT c.id AS chat_id, COUNT(*) as message_count
FROM chats c
JOIN chat_groups cg ON cg.chat_id = c.id
JOIN groups g ON g.id = cg.group_id
JOIN group_runs gr ON gr.group_id = g.id
JOIN runs r ON r.id = gr.run_id
JOIN message_runs mr ON mr.run_id = r.id
JOIN messages m ON m.id = mr.message_id
WHERE c.id = ANY(chat_ids)
GROUP BY c.id
$$;


--
-- Name: api_get_model_detail_v4(uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_model_detail_v4(model_id uuid, profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(model_exists boolean, name text, description text, active boolean, image_model boolean, provider text, provider_id uuid, provider_name text, value text, base_url text, valid_provider_ids uuid[], providers types.q_get_model_detail_v4_provider[], valid_department_ids uuid[], departments types.q_get_model_detail_v4_department[], department_ids uuid[], valid_key_ids uuid[], keys types.q_get_model_detail_v4_key[], default_key_id uuid, temperature_lower double precision, temperature_upper double precision, temperature_values text[], pricing types.q_get_model_detail_v4_pricing[], modalities types.q_get_model_detail_v4_modalities, reasoning_levels text[], voices types.q_get_model_detail_v4_voice[], qualities text[], units types.q_get_model_detail_v4_unit[], actor_name text, draft_version integer)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        model_id AS model_id,
        profile_id AS profile_id,
        draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'models'::draft_resource_type
    LIMIT 1
),
model_exists_check AS (
    SELECT EXISTS(SELECT 1 FROM models WHERE id = (SELECT model_id FROM params))::boolean as model_exists
),
resolve_profile_id AS (
    SELECT 
        CASE 
            WHEN (SELECT profile_id FROM params)::text IS NULL OR (SELECT profile_id FROM params)::text = '' THEN NULL::uuid
            ELSE (SELECT profile_id FROM params)::uuid
        END as resolved_profile_id
),
actor_profile AS (
    SELECT 
        (SELECT profile_id FROM params)::uuid as profile_id,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM profiles p
    WHERE p.id = (SELECT profile_id FROM params)::uuid
),
model_data AS (
    SELECT 
        m.name,
        m.description,
        m.active,
        m.value,
        p.value as provider,
        p.id as provider_id,
        p.name as provider_name
    FROM models m
    JOIN providers p ON p.id = m.provider_id
    WHERE m.id = (SELECT model_id FROM params)
),
-- Determine if model is an image model (has 'image' output modality)
image_model_check AS (
    SELECT 
        CASE WHEN COUNT(*) > 0 THEN true ELSE false END as image_model
    FROM model_modalities
    WHERE model_id = (SELECT model_id FROM params) AND modality = 'image' AND is_input = false AND active = true
),
model_endpoint_data AS (
    SELECT 
        COALESCE(me.base_url, '') as base_url
    FROM models m
    LEFT JOIN model_endpoints me ON me.model_id = m.id AND me.active = true
    WHERE m.id = (SELECT model_id FROM params)
    LIMIT 1
),
model_departments_data AS (
    SELECT 
        md.model_id,
        ARRAY_AGG(md.department_id ORDER BY md.created_at) as department_ids
    FROM model_departments md
    WHERE md.model_id = (SELECT model_id FROM params) AND md.active = true
    GROUP BY md.model_id
),
model_departments_fallback AS (
    SELECT ARRAY[]::uuid[] as department_ids
    WHERE NOT EXISTS (SELECT 1 FROM model_departments_data WHERE model_id = (SELECT model_id FROM params))
),
user_departments AS (
    SELECT DISTINCT pd.department_id
    FROM resolve_profile_id rpi
    JOIN profile_departments pd ON pd.profile_id = rpi.resolved_profile_id
    WHERE pd.active = true
),
user_departments_data AS (
    SELECT DISTINCT d.id, d.title as name, d.description
    FROM departments d
    JOIN resolve_profile_id rpi ON true
    JOIN profile_departments pd ON d.id = pd.department_id
    WHERE d.active = true
    AND pd.profile_id = rpi.resolved_profile_id
    AND pd.active = true
),
providers_data AS (
    SELECT 
        p.id as provider_id,
        p.name,
        COALESCE(p.description, '') as description
    FROM providers p
    WHERE p.active = true
    ORDER BY p.name
),
model_all_keys AS (
    -- Get keys via settings system: settings -> provider -> key
    -- For each department that has this model, get keys from their settings
    SELECT DISTINCT
        spk.key_id,
        k.name,
        k.key,
        k.description,
        k.active,
        ARRAY_AGG(DISTINCT ds.department_id) FILTER (WHERE ds.department_id IS NOT NULL) as department_ids
    FROM models m
    JOIN providers p ON p.id = m.provider_id
    JOIN setting_provider_keys spk ON spk.provider_id = p.id AND spk.active = true
    JOIN keys k ON k.id = spk.key_id AND k.active = true
    JOIN settings s ON s.id = spk.settings_id AND s.active = true
    JOIN department_settings ds ON ds.settings_id = s.id AND ds.active = true
    WHERE m.id = (SELECT model_id FROM params)
    AND ds.active = true
    GROUP BY spk.key_id, k.name, k.key, k.description, k.active
    
    UNION ALL
    
    -- General keys (keys without department links that user has access to)
    SELECT DISTINCT
        k.id as key_id,
        k.name,
        k.key,
        k.description,
        k.active,
        NULL::uuid[] as department_ids
    FROM keys k
    CROSS JOIN resolve_profile_id rpi
    WHERE k.active = true
    AND NOT EXISTS (
        -- Exclude keys already included via setting_provider_keys for this model's provider
        SELECT 1 FROM models m2
        JOIN providers p2 ON p2.id = m2.provider_id
        JOIN setting_provider_keys spk2 ON spk2.provider_id = p2.id AND spk2.key_id = k.id AND spk2.active = true
        WHERE m2.id = (SELECT model_id FROM params)
    )
    AND (
        -- Include keys with no settings links (general keys)
        NOT EXISTS (
            SELECT 1 FROM setting_provider_keys spk3
            WHERE spk3.key_id = k.id AND spk3.active = true
        )
        OR
        -- Include keys with settings links that match user's departments
        EXISTS (
            SELECT 1 FROM setting_provider_keys spk4
            JOIN settings s4 ON s4.id = spk4.settings_id AND s4.active = true
            JOIN department_settings ds4 ON ds4.settings_id = s4.id AND ds4.active = true
            JOIN user_departments ud ON ud.department_id = ds4.department_id
            WHERE spk4.key_id = k.id AND spk4.active = true
        )
        OR
        -- Superadmin can see all keys
        EXISTS (SELECT 1 FROM resolve_profile_id rpi2 JOIN profiles p ON p.id = rpi2.resolved_profile_id WHERE rpi2.resolved_profile_id = rpi.resolved_profile_id AND p.role = 'superadmin'::profile_role)
    )
),
keys_data AS (
    SELECT DISTINCT ON (mak.key_id) 
        mak.key_id,
        mak.name,
        mak.key,
        mak.description,
        mak.active,
        COALESCE(mak.department_ids, ARRAY[]::uuid[]) as department_ids
    FROM model_all_keys mak
    ORDER BY mak.key_id, mak.name
),
model_temperature_data AS (
    SELECT 
        model_id,
        MIN(temperature) FILTER (WHERE is_upper = false) as temperature_lower,
        MAX(temperature) FILTER (WHERE is_upper = true) as temperature_upper,
        ARRAY_AGG(DISTINCT temperature::text ORDER BY temperature::text) FILTER (WHERE is_upper = false) as temperature_values
    FROM model_temperature_levels
    WHERE model_id = (SELECT model_id FROM params) AND active = true
    GROUP BY model_id
),
model_pricing_data AS (
    SELECT 
        mp.pricing_type::text as pricing_type,
        u.id as unit_id,
        u.name as unit_name,
        u.unit_category::text as unit_category,
        mp.price
    FROM model_pricing mp
    JOIN units u ON u.id = mp.unit_id
    WHERE mp.model_id = (SELECT model_id FROM params) AND mp.active = true AND u.active = true
    ORDER BY mp.pricing_type, u.name
),
model_modalities_data AS (
    SELECT 
        ARRAY_AGG(modality::text ORDER BY modality::text) FILTER (WHERE is_input = true) as input_modalities,
        ARRAY_AGG(modality::text ORDER BY modality::text) FILTER (WHERE is_input = false) as output_modalities
    FROM model_modalities
    WHERE model_id = (SELECT model_id FROM params) AND active = true
),
model_reasoning_levels_data AS (
    SELECT 
        ARRAY_AGG(reasoning_level::text ORDER BY 
            CASE reasoning_level
                WHEN 'none' THEN 1
                WHEN 'minimal' THEN 2
                WHEN 'low' THEN 3
                WHEN 'medium' THEN 4
                WHEN 'high' THEN 5
            END
        ) as reasoning_levels
    FROM model_reasoning_levels
    WHERE model_id = (SELECT model_id FROM params) AND active = true
),
model_qualities_data AS (
    SELECT 
        ARRAY_AGG(quality::text ORDER BY 
            CASE quality
                WHEN 'low' THEN 1
                WHEN 'medium' THEN 2
                WHEN 'high' THEN 3
            END
        ) as qualities
    FROM model_qualities
    WHERE model_id = (SELECT model_id FROM params) AND active = true
),
model_voices_data AS (
    SELECT 
        id as voice_id,
        voice::text as voice
    FROM model_voices
    WHERE model_id = (SELECT model_id FROM params) AND active = true
    ORDER BY voice::text
),
all_units_data AS (
    SELECT 
        id as unit_id,
        name,
        unit_category::text as unit_category,
        value
    FROM units
    WHERE active = true
    ORDER BY unit_category, value, name
),
providers_aggregated AS (
    SELECT 
        ARRAY_AGG(pd.provider_id ORDER BY pd.provider_id) as valid_provider_ids,
        ARRAY_AGG((pd.provider_id, pd.name, pd.description)::types.q_get_model_detail_v4_provider ORDER BY pd.name) as providers
    FROM providers_data pd
),
departments_aggregated AS (
    SELECT 
        ARRAY_AGG(udd.id ORDER BY udd.id) as valid_department_ids,
        ARRAY_AGG((udd.id, udd.name, COALESCE(udd.description, ''))::types.q_get_model_detail_v4_department ORDER BY udd.name) as departments
    FROM user_departments_data udd
),
keys_aggregated AS (
    SELECT 
        ARRAY_AGG(kd.key_id ORDER BY kd.key_id) as valid_key_ids,
        ARRAY_AGG(
            (kd.key_id, kd.name, COALESCE(kd.description, ''), 
             CASE 
                 WHEN LENGTH(kd.key) > 4 THEN LEFT(kd.key, 4) || '****'
                 ELSE '****'
             END,
             kd.active,
             kd.department_ids
            )::types.q_get_model_detail_v4_key
            ORDER BY kd.name
        ) as keys
    FROM keys_data kd
),
pricing_aggregated AS (
    SELECT 
        ARRAY_AGG(
            (mpd.pricing_type, mpd.unit_id, mpd.unit_name, mpd.unit_category, mpd.price)::types.q_get_model_detail_v4_pricing
            ORDER BY mpd.pricing_type, mpd.unit_name
        ) as pricing
    FROM model_pricing_data mpd
),
voices_aggregated AS (
    SELECT 
        ARRAY_AGG(
            (mv.voice_id, mv.voice)::types.q_get_model_detail_v4_voice
            ORDER BY mv.voice
        ) as voices
    FROM model_voices_data mv
),
units_aggregated AS (
    SELECT 
        ARRAY_AGG(
            (aud.unit_id, aud.name, aud.unit_category, aud.value)::types.q_get_model_detail_v4_unit
            ORDER BY aud.unit_category, aud.value, aud.name
        ) as units
    FROM all_units_data aud
)
SELECT 
    mec.model_exists::boolean as model_exists,
    -- Merge draft payload over existing model data if draft_id provided
    COALESCE(
        (SELECT payload->>'name' FROM draft_payload_data),
        md.name
    ) as name,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        md.description
    ) as description,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        md.active
    ) as active,
    COALESCE(imc.image_model, false) as image_model,
    md.provider,
    COALESCE(
        (SELECT (payload->>'provider_id')::uuid FROM draft_payload_data),
        md.provider_id
    ) as provider_id,
    md.provider_name,
    COALESCE(
        (SELECT payload->>'value' FROM draft_payload_data),
        md.value
    ) as value,
    COALESCE(
        (SELECT payload->>'base_url' FROM draft_payload_data),
        COALESCE(med.base_url, '')
    ) as base_url,
    COALESCE(pa.valid_provider_ids, ARRAY[]::uuid[]) as valid_provider_ids,
    COALESCE(pa.providers, '{}'::types.q_get_model_detail_v4_provider[]) as providers,
    COALESCE(da.valid_department_ids, ARRAY[]::uuid[]) as valid_department_ids,
    COALESCE(da.departments, '{}'::types.q_get_model_detail_v4_department[]) as departments,
    -- Merge draft payload department_ids over existing model department_ids if draft_id provided
    COALESCE(
        CASE 
            WHEN (SELECT payload->'department_ids' FROM draft_payload_data) IS NOT NULL AND jsonb_typeof((SELECT payload->'department_ids' FROM draft_payload_data)) = 'array' THEN
                ARRAY(SELECT jsonb_array_elements_text((SELECT payload->'department_ids' FROM draft_payload_data)))::uuid[]
            ELSE NULL
        END,
        COALESCE(mdd.department_ids, mdf.department_ids, ARRAY[]::uuid[])
    ) as department_ids,
    COALESCE(ka.valid_key_ids, ARRAY[]::uuid[]) as valid_key_ids,
    COALESCE(ka.keys, '{}'::types.q_get_model_detail_v4_key[]) as keys,
    NULL::uuid as default_key_id,
    -- Merge draft payload temperature_bounds over existing model temperature if draft_id provided
    COALESCE(
        (SELECT (payload->'temperature_bounds'->>'lower')::float FROM draft_payload_data),
        COALESCE(mtd.temperature_lower, 0.0)
    ) as temperature_lower,
    COALESCE(
        (SELECT (payload->'temperature_bounds'->>'upper')::float FROM draft_payload_data),
        COALESCE(mtd.temperature_upper, 1.0)
    ) as temperature_upper,
    COALESCE(mtd.temperature_values, ARRAY[]::text[]) as temperature_values,
    -- Merge draft payload pricing over existing model pricing if draft_id provided
    COALESCE(
        (SELECT 
            ARRAY_AGG(
                (pricing_entry->>'type', 
                 (pricing_entry->>'unit_id')::uuid,
                 u.name,
                 u.unit_category::text,
                 (pricing_entry->>'price')::float
                )::types.q_get_model_detail_v4_pricing
            )
            FROM jsonb_array_elements((SELECT payload->'pricing' FROM draft_payload_data)) AS pricing_entry
            JOIN units u ON u.id = (pricing_entry->>'unit_id')::uuid AND u.active = true
        ),
        COALESCE(pra.pricing, '{}'::types.q_get_model_detail_v4_pricing[])
    ) as pricing,
    -- Merge draft payload modalities over existing model modalities if draft_id provided
    COALESCE(
        (SELECT 
            (
                ARRAY(SELECT jsonb_array_elements_text(payload->'modalities'->'input')),
                ARRAY(SELECT jsonb_array_elements_text(payload->'modalities'->'output'))
            )::types.q_get_model_detail_v4_modalities
            FROM draft_payload_data
        ),
        COALESCE(
            (COALESCE(mmod.input_modalities, ARRAY[]::text[]), COALESCE(mmod.output_modalities, ARRAY[]::text[]))::types.q_get_model_detail_v4_modalities,
            (ARRAY[]::text[], ARRAY[]::text[])::types.q_get_model_detail_v4_modalities
        )
    ) as modalities,
    -- Merge draft payload reasoning_levels over existing model reasoning_levels if draft_id provided
    COALESCE(
        (SELECT ARRAY(SELECT jsonb_array_elements_text(payload->'reasoning_levels')) FROM draft_payload_data),
        COALESCE(mrl.reasoning_levels, ARRAY[]::text[])
    ) as reasoning_levels,
    -- Merge draft payload voices over existing model voices if draft_id provided
    COALESCE(
        (SELECT 
            ARRAY_AGG(
                (gen_random_uuid(), voice_text)::types.q_get_model_detail_v4_voice
            )
            FROM jsonb_array_elements_text((SELECT payload->'voices' FROM draft_payload_data)) AS voice_text
        ),
        COALESCE(va.voices, '{}'::types.q_get_model_detail_v4_voice[])
    ) as voices,
    -- Merge draft payload qualities over existing model qualities if draft_id provided
    COALESCE(
        (SELECT ARRAY(SELECT jsonb_array_elements_text(payload->'qualities')) FROM draft_payload_data),
        COALESCE(mq.qualities, ARRAY[]::text[])
    ) as qualities,
    COALESCE(ua.units, '{}'::types.q_get_model_detail_v4_unit[]) as units,
    ap.actor_name::text as actor_name,
    COALESCE((SELECT draft_version FROM draft_payload_data), 0) as draft_version
FROM model_exists_check mec
CROSS JOIN model_data md
CROSS JOIN actor_profile ap
CROSS JOIN providers_aggregated pa
CROSS JOIN departments_aggregated da
CROSS JOIN keys_aggregated ka
CROSS JOIN pricing_aggregated pra
CROSS JOIN voices_aggregated va
CROSS JOIN units_aggregated ua
LEFT JOIN image_model_check imc ON true
LEFT JOIN model_endpoint_data med ON true
LEFT JOIN model_departments_data mdd ON true
LEFT JOIN model_departments_fallback mdf ON true
LEFT JOIN model_temperature_data mtd ON true
LEFT JOIN model_modalities_data mmod ON true
LEFT JOIN model_reasoning_levels_data mrl ON true
LEFT JOIN model_qualities_data mq ON true
$$;


--
-- Name: api_get_model_new_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_model_new_v4(profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(valid_provider_ids uuid[], providers types.q_get_model_new_v4_provider[], valid_department_ids uuid[], departments types.q_get_model_new_v4_department[], valid_model_ids uuid[], models types.q_get_model_new_v4_model[], valid_key_ids uuid[], keys types.q_get_model_new_v4_key[], units types.q_get_model_new_v4_unit[], user_role text, primary_department_id uuid, actor_name text, draft_version integer)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        profile_id AS profile_id,
        draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'models'::draft_resource_type
    LIMIT 1
),
resolve_profile_id AS (
    SELECT 
        CASE 
            WHEN (SELECT profile_id FROM params)::text IS NULL OR (SELECT profile_id FROM params)::text = '' THEN NULL::uuid
            ELSE (SELECT profile_id FROM params)::uuid
        END as resolved_profile_id
),
actor_profile AS (
    SELECT 
        (SELECT profile_id FROM params)::uuid as profile_id,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM profiles p
    WHERE p.id = (SELECT profile_id FROM params)::uuid
),
user_departments AS (
    SELECT DISTINCT pd.department_id
    FROM resolve_profile_id rpi
    JOIN profile_departments pd ON pd.profile_id = rpi.resolved_profile_id
    WHERE pd.active = true
),
user_departments_data AS (
    SELECT DISTINCT d.id, d.title as name, d.description
    FROM departments d
    JOIN resolve_profile_id rpi ON true
    JOIN profile_departments pd ON d.id = pd.department_id
    WHERE d.active = true
    AND pd.profile_id = rpi.resolved_profile_id
    AND pd.active = true
),
valid_models AS (
    -- Filter models by department: include if has matching department link OR has no department links at all (cross-dept)
    SELECT 
        m.id as model_id,
        m.name,
        COALESCE(m.description, '') as description
    FROM models m
    LEFT JOIN model_departments md ON md.model_id = m.id AND md.active = true
    WHERE m.active = true
    GROUP BY m.id, m.name, m.description
    HAVING 
        COUNT(md.model_id) FILTER (WHERE md.department_id IN (SELECT department_id FROM user_departments)) > 0
        OR NOT EXISTS (SELECT 1 FROM model_departments md2 WHERE md2.model_id = m.id AND md2.active = true)
    ORDER BY m.name
),
valid_keys AS (
    -- Get all active keys (no model-specific filtering for default view)
    SELECT DISTINCT k.id as key_id, k.name, k.key, k.description, k.active
    FROM keys k
    WHERE k.active = true
),
profile_data AS (
    SELECT role as user_role 
    FROM resolve_profile_id rpi
    JOIN profiles p ON p.id = rpi.resolved_profile_id
),
primary_department_id AS (
    SELECT department_id
    FROM resolve_profile_id rpi
    JOIN profile_departments pd ON pd.profile_id = rpi.resolved_profile_id
    WHERE pd.is_primary = TRUE
    LIMIT 1
),
all_units_data AS (
    SELECT 
        id as unit_id,
        name,
        unit_category::text as unit_category,
        value
    FROM units
    WHERE active = true
    ORDER BY unit_category, value, name
),
providers_aggregated AS (
    SELECT 
        ARRAY_AGG(p.id ORDER BY p.name) as valid_provider_ids,
        ARRAY_AGG((p.id, p.name, COALESCE(p.description, ''))::types.q_get_model_new_v4_provider ORDER BY p.name) as providers
    FROM providers p
    WHERE p.active = true
),
departments_aggregated AS (
    SELECT 
        ARRAY_AGG(udd.id ORDER BY udd.id) as valid_department_ids,
        ARRAY_AGG((udd.id, udd.name, COALESCE(udd.description, ''))::types.q_get_model_new_v4_department ORDER BY udd.name) as departments
    FROM user_departments_data udd
),
models_aggregated AS (
    SELECT 
        ARRAY_AGG(vm.model_id ORDER BY vm.name) as valid_model_ids,
        ARRAY_AGG((vm.model_id, vm.name, vm.description)::types.q_get_model_new_v4_model ORDER BY vm.name) as models
    FROM valid_models vm
),
keys_aggregated AS (
    SELECT 
        ARRAY_AGG(vk.key_id ORDER BY vk.key_id) as valid_key_ids,
        ARRAY_AGG(
            (vk.key_id, vk.name, COALESCE(vk.description, ''),
             CASE 
                 WHEN LENGTH(vk.key) > 4 THEN LEFT(vk.key, 4) || '****'
                 ELSE '****'
             END,
             vk.active,
             ARRAY[]::uuid[]
            )::types.q_get_model_new_v4_key
            ORDER BY vk.name
        ) as keys
    FROM valid_keys vk
),
units_aggregated AS (
    SELECT 
        ARRAY_AGG(
            (aud.unit_id, aud.name, aud.unit_category, aud.value)::types.q_get_model_new_v4_unit
            ORDER BY aud.unit_category, aud.value, aud.name
        ) as units
    FROM all_units_data aud
)
SELECT 
    COALESCE(pa.valid_provider_ids, ARRAY[]::uuid[]) as valid_provider_ids,
    COALESCE(pa.providers, '{}'::types.q_get_model_new_v4_provider[]) as providers,
    COALESCE(da.valid_department_ids, ARRAY[]::uuid[]) as valid_department_ids,
    COALESCE(da.departments, '{}'::types.q_get_model_new_v4_department[]) as departments,
    COALESCE(ma.valid_model_ids, ARRAY[]::uuid[]) as valid_model_ids,
    COALESCE(ma.models, '{}'::types.q_get_model_new_v4_model[]) as models,
    COALESCE(ka.valid_key_ids, ARRAY[]::uuid[]) as valid_key_ids,
    COALESCE(ka.keys, '{}'::types.q_get_model_new_v4_key[]) as keys,
    COALESCE(ua.units, '{}'::types.q_get_model_new_v4_unit[]) as units,
    pr.user_role::text as user_role,
    pdi.department_id as primary_department_id,
    ap.actor_name::text as actor_name,
    COALESCE((SELECT draft_version FROM draft_payload_data), 0) as draft_version
FROM providers_aggregated pa
CROSS JOIN departments_aggregated da
CROSS JOIN models_aggregated ma
CROSS JOIN keys_aggregated ka
CROSS JOIN units_aggregated ua
CROSS JOIN profile_data pr
CROSS JOIN actor_profile ap
LEFT JOIN primary_department_id pdi ON true
$$;


--
-- Name: api_get_next_pending_run_or_group_for_benchmark_v4(uuid, uuid, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_next_pending_run_or_group_for_benchmark_v4(attempt_id uuid, eval_id uuid, use_groups boolean) RETURNS TABLE(next_run_id uuid, next_group_id uuid, run_id uuid, group_id uuid)
    LANGUAGE sql STABLE
    AS $$
WITH attempt_data AS (
    SELECT 
        ea.eval_id,
        ea.infinite_mode
    FROM eval_attempts ea
    WHERE ea.id = attempt_id
),
next_run AS (
    SELECT 
        er.run_id::uuid as next_run_id,
        er.run_id::uuid as run_id,
        NULL::uuid as next_group_id,
        NULL::uuid as group_id
    FROM eval_runs er
    CROSS JOIN attempt_data ad
    WHERE er.eval_id = ad.eval_id 
      AND er.completed = false
      AND use_groups = false
    ORDER BY er.created_at ASC
    LIMIT 1
),
next_group AS (
    SELECT 
        NULL::uuid as next_run_id,
        NULL::uuid as run_id,
        eg.group_id::uuid as next_group_id,
        eg.group_id::uuid as group_id
    FROM eval_groups eg
    CROSS JOIN attempt_data ad
    WHERE eg.eval_id = ad.eval_id 
      AND NOT EXISTS (
          SELECT 1 FROM grade_groups gg 
          WHERE gg.group_id = eg.group_id
      )
      AND use_groups = true
    ORDER BY eg.created_at ASC
    LIMIT 1
)
SELECT 
    COALESCE(nr.next_run_id, ng.next_group_id) as next_run_id,
    COALESCE(nr.next_group_id, ng.next_group_id) as next_group_id,
    COALESCE(nr.run_id, ng.run_id) as run_id,
    COALESCE(nr.group_id, ng.group_id) as group_id
FROM next_run nr
FULL OUTER JOIN next_group ng ON true
LIMIT 1
$$;


--
-- Name: api_get_or_create_run_for_chat_v4(uuid, uuid, uuid, uuid, text, uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_or_create_run_for_chat_v4(chat_id uuid, department_id uuid, model_id uuid, entity_id uuid, entity_type text, profile_id uuid DEFAULT NULL::uuid, key_id uuid DEFAULT NULL::uuid, agent_id uuid DEFAULT NULL::uuid) RETURNS TABLE(run_id text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        chat_id as chat_id, 
        department_id as department_id, 
        model_id as model_id, 
        entity_id as entity_id, 
        entity_type as entity_type, 
        profile_id as profile_id, 
        key_id as key_id, 
        agent_id as agent_id
),
-- Get or create group for this chat
chat_group AS (
    -- Try to find existing group via chat_groups junction table
    SELECT cg.group_id
    FROM chat_groups cg
    CROSS JOIN params p
    WHERE cg.chat_id = p.chat_id
    LIMIT 1
),
create_group_if_needed AS (
    -- Create a new group if none exists for this chat
    INSERT INTO groups (created_at, updated_at)
    SELECT NOW(), NOW()
    FROM params p
    WHERE NOT EXISTS (SELECT 1 FROM chat_group)
    RETURNING id as group_id
),
create_chat_group_if_needed AS (
    -- Insert into chat_groups if we created a new group
    INSERT INTO chat_groups (chat_id, group_id, created_at, updated_at)
    SELECT p.chat_id, cg.group_id, NOW(), NOW()
    FROM create_group_if_needed cg
    CROSS JOIN params p
    WHERE NOT EXISTS (SELECT 1 FROM chat_group)
    ON CONFLICT (chat_id, group_id) DO NOTHING
    RETURNING group_id
),
selected_group AS (
    SELECT group_id FROM chat_group
    UNION ALL
    SELECT group_id FROM create_group_if_needed
    UNION ALL
    SELECT group_id FROM create_chat_group_if_needed
),
latest_run AS (
    -- Get the latest run for this chat's group
    SELECT r.id
    FROM selected_group sg
    JOIN group_runs gr ON gr.group_id = sg.group_id
    JOIN runs r ON r.id = gr.run_id
    ORDER BY r.created_at DESC
    LIMIT 1
),
create_run_if_needed AS (
    -- Create a new run if none exists
    INSERT INTO runs (input_tokens, output_tokens, key_id, agent_id)
    SELECT 0, 0, p.key_id, p.agent_id
    FROM params p
    WHERE NOT EXISTS (SELECT 1 FROM latest_run)
    RETURNING id
),
selected_run AS (
    SELECT id FROM latest_run
    UNION ALL
    SELECT id FROM create_run_if_needed
),
link_model AS (
    -- Link model to run if it's a new run
    INSERT INTO run_models (run_id, model_id, active)
    SELECT sr.id, p.model_id, true
    FROM selected_run sr
    CROSS JOIN params p
    WHERE NOT EXISTS (SELECT 1 FROM latest_run)
    AND NOT EXISTS (SELECT 1 FROM run_models rm WHERE rm.run_id = sr.id AND rm.active = true)
    RETURNING run_id
),
link_persona AS (
    INSERT INTO run_personas (run_id, persona_id, active)
    SELECT COALESCE(lm.run_id, sr.id), p.entity_id, true
    FROM selected_run sr
    LEFT JOIN link_model lm ON true
    CROSS JOIN params p
    WHERE NOT EXISTS (SELECT 1 FROM latest_run)
    AND p.entity_type = 'persona'
    AND NOT EXISTS (SELECT 1 FROM run_personas rp WHERE rp.run_id = sr.id AND rp.active = true)
    RETURNING run_id
),
link_profile AS (
    -- Link profile to run if it's a new run and profile_id is provided
    INSERT INTO run_profiles (run_id, profile_id, active)
    SELECT COALESCE(lm.run_id, sr.id), p.profile_id, true
    FROM selected_run sr
    LEFT JOIN link_model lm ON true
    CROSS JOIN params p
    WHERE NOT EXISTS (SELECT 1 FROM latest_run)
    AND p.profile_id IS NOT NULL
    AND NOT EXISTS (SELECT 1 FROM run_profiles rp WHERE rp.run_id = sr.id AND rp.active = true)
    RETURNING run_id
),
link_group AS (
    -- Link run to group if it's a new run
    INSERT INTO group_runs (group_id, run_id, idx, created_at, updated_at)
    SELECT 
        sg.group_id, 
        sr.id, 
        COALESCE((SELECT MAX(idx) FROM group_runs WHERE group_id = sg.group_id), -1) + 1,
        NOW(), 
        NOW()
    FROM selected_run sr
    CROSS JOIN selected_group sg
    WHERE NOT EXISTS (SELECT 1 FROM latest_run)
    AND NOT EXISTS (SELECT 1 FROM group_runs gr WHERE gr.run_id = sr.id AND gr.group_id = sg.group_id)
    RETURNING run_id
)
SELECT sr.id::text as run_id
FROM selected_run sr
LIMIT 1
$$;


--
-- Name: api_get_parameter_detail_v4(uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_parameter_detail_v4(parameter_id uuid, profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(parameter_exists boolean, name text, description text, active boolean, simulation_parameter boolean, document_parameter boolean, persona_parameter boolean, scenario_parameter boolean, video_parameter boolean, department_ids text[], persona_ids text[], document_ids text[], parameter_items types.q_get_parameter_detail_v4_item[], departments types.q_get_parameter_detail_v4_department[], valid_department_ids text[], fields types.q_get_parameter_detail_v4_field[], valid_field_ids text[], field_connections types.q_get_parameter_detail_v4_field_connection[], personas types.q_get_parameter_detail_v4_persona[], valid_persona_ids text[], documents types.q_get_parameter_detail_v4_document[], valid_document_ids text[], can_edit boolean, actor_name text, draft_version integer, field_ids jsonb, field_active_states jsonb, field_default_states jsonb)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT
        parameter_id AS parameter_id,
        profile_id AS profile_id,
        draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'parameters'::draft_resource_type
    LIMIT 1
),
parameter_exists_check AS (
    -- Check if parameter exists independently of access control
    SELECT EXISTS(
        SELECT 1 FROM parameters WHERE id = (SELECT parameter_id FROM params)
    )::boolean as parameter_exists
),
user_profile AS (
    SELECT 
        up.id,
        up.role,
        up.first_name || ' ' || up.last_name as actor_name
    FROM params x
    JOIN profiles up ON up.id = x.profile_id
),
parameter_active_scenario_links AS (
    SELECT 
        pf.parameter_id,
        COUNT(DISTINCT sf.scenario_id) as active_scenario_count
    FROM params x
    JOIN parameter_fields pf ON pf.parameter_id = x.parameter_id AND pf.active = true
    JOIN scenario_fields sf ON sf.field_id = pf.field_id AND sf.active = true
    GROUP BY pf.parameter_id
),
field_departments_data AS (
    SELECT 
        f.id as field_id,
        COALESCE(ARRAY_AGG(fd.department_id::text ORDER BY fd.created_at) FILTER (WHERE fd.department_id IS NOT NULL), ARRAY[]::text[]) as department_ids
    FROM params x
    JOIN parameter_fields pf ON pf.parameter_id = x.parameter_id AND pf.active = true
    JOIN fields f ON f.id = pf.field_id
    LEFT JOIN field_departments fd ON fd.field_id = f.id AND fd.active = true
    GROUP BY f.id
),
parameter_departments_aggregated AS (
    SELECT 
        ARRAY_AGG(DISTINCT dept_id::text ORDER BY dept_id::text) as department_ids
    FROM (
        SELECT pd.department_id as dept_id
        FROM params x
        JOIN parameter_departments pd ON pd.parameter_id = x.parameter_id AND pd.active = true
        UNION
        SELECT fd.department_id as dept_id
        FROM params x
        JOIN parameter_fields pf ON pf.parameter_id = x.parameter_id AND pf.active = true
        JOIN field_departments fd ON fd.field_id = pf.field_id AND fd.active = true
    ) combined_depts
),
user_has_parameter_access AS (
    SELECT EXISTS(
        SELECT 1 FROM parameter_departments pd
        JOIN profile_departments pdp ON pdp.department_id = pd.department_id
        WHERE pd.parameter_id = (SELECT parameter_id FROM params)
        AND pd.active = true
        AND pdp.profile_id = (SELECT profile_id FROM params)
        AND pdp.active = true
    ) OR EXISTS(
        SELECT 1 FROM field_departments fd
        JOIN profile_departments pd ON pd.department_id = fd.department_id
        JOIN parameter_fields pf ON pf.field_id = fd.field_id
        WHERE pf.parameter_id = (SELECT parameter_id FROM params)
        AND pf.active = true
        AND fd.active = true
        AND pd.profile_id = (SELECT profile_id FROM params)
        AND pd.active = true
    ) OR EXISTS(
        SELECT 1 FROM params x
        JOIN profiles p ON p.id = x.profile_id
        WHERE p.role = 'superadmin'::profile_role
    ) OR (
        (SELECT COUNT(*) FROM parameter_departments pd
         WHERE pd.parameter_id = (SELECT parameter_id FROM params)
         AND pd.active = true) = 0
        AND (SELECT COUNT(*) FROM field_departments fd
             JOIN parameter_fields pf ON pf.field_id = fd.field_id
             WHERE pf.parameter_id = (SELECT parameter_id FROM params)
             AND pf.active = true
             AND fd.active = true) = 0
    ) as has_access
),
parameter_data AS (
    SELECT 
        p.name,
        p.description,
        p.active,
        p.simulation_parameter,
        p.document_parameter,
        p.persona_parameter,
        p.scenario_parameter,
        p.video_parameter,
        COALESCE(pda.department_ids, NULL) as department_ids,
        ARRAY[]::text[] as persona_ids,
        ARRAY[]::text[] as document_ids,
        CASE 
            WHEN COALESCE(pasl.active_scenario_count, 0) > 0 THEN false
            WHEN (COALESCE(pda.department_ids, NULL) IS NULL OR array_length(pda.department_ids, 1) = 0) AND up.role != 'superadmin' THEN false
            WHEN up.role = 'superadmin'::profile_role THEN true
            WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role) THEN true
            ELSE false
        END as can_edit
    FROM params x
    JOIN parameters p ON p.id = x.parameter_id
    CROSS JOIN user_profile up
    LEFT JOIN parameter_departments_aggregated pda ON true
    LEFT JOIN parameter_active_scenario_links pasl ON pasl.parameter_id = p.id
    CROSS JOIN user_has_parameter_access uhpa
    WHERE uhpa.has_access = true
),
all_fields_data AS (
    SELECT 
        f.id as field_id,
        COALESCE(ARRAY_AGG(fd.department_id::text ORDER BY fd.created_at) FILTER (WHERE fd.department_id IS NOT NULL), ARRAY[]::text[]) as department_ids
    FROM fields f
    LEFT JOIN field_departments fd ON fd.field_id = f.id AND fd.active = true
    WHERE f.active = true
    GROUP BY f.id
),
all_fields_with_usage AS (
    SELECT 
        f.id,
        f.name,
        f.description,
        COALESCE(COUNT(sf.scenario_id), 0) as usage_count,
        COALESCE(afd.department_ids, ARRAY[]::text[]) as department_ids
    FROM fields f
    LEFT JOIN all_fields_data afd ON afd.field_id = f.id
    LEFT JOIN scenario_fields sf ON sf.field_id = f.id AND sf.active = true
    WHERE f.active = true
    GROUP BY f.id, f.name, f.description, afd.department_ids
),
field_connections_data AS (
    SELECT 
        pf.field_id,
        pf."default",
        pf.active as connection_active
    FROM params x
    JOIN parameter_fields pf ON pf.parameter_id = x.parameter_id AND pf.active = true
),
fields_with_usage AS (
    SELECT 
        f.id,
        f.name,
        f.description,
        COALESCE(fcd."default", false) as "default",
        COALESCE(COUNT(sf.scenario_id), 0) as usage_count,
        COALESCE(fdd.department_ids, ARRAY[]::text[]) as department_ids
    FROM params x
    JOIN parameter_fields pf ON pf.parameter_id = x.parameter_id AND pf.active = true
    JOIN fields f ON f.id = pf.field_id AND f.active = true
    LEFT JOIN field_connections_data fcd ON fcd.field_id = f.id
    LEFT JOIN scenario_fields sf ON sf.field_id = f.id AND sf.active = true
    LEFT JOIN field_departments_data fdd ON fdd.field_id = f.id
    GROUP BY f.id, f.name, f.description, fcd."default", fdd.department_ids
),
parameter_department_ids AS (
    SELECT 
        dept_id as department_id
    FROM parameter_departments_aggregated pda
    CROSS JOIN LATERAL unnest(
        CASE 
            WHEN pda.department_ids IS NOT NULL AND array_length(pda.department_ids, 1) > 0
            THEN pda.department_ids::uuid[]
            ELSE ARRAY[]::uuid[]
        END
    ) AS dept_id
),
filtered_personas AS (
    SELECT DISTINCT p.id, p.name, COALESCE(p.description, '') as description
    FROM personas p
    LEFT JOIN persona_departments pd ON pd.persona_id = p.id AND pd.active = true
    CROSS JOIN parameter_departments_aggregated pda
    WHERE p.active = true
    AND (
        (pda.department_ids IS NULL OR array_length(pda.department_ids, 1) = 0)
        OR (pda.department_ids IS NOT NULL AND pd.department_id = ANY(pda.department_ids::uuid[]))
        OR NOT EXISTS (
            SELECT 1 FROM persona_departments pd2 
            WHERE pd2.persona_id = p.id AND pd2.active = true
        )
    )
),
filtered_documents AS (
    SELECT DISTINCT d.id, d.name, COALESCE(d.description, '') as description
    FROM documents d
    LEFT JOIN document_departments dd ON dd.document_id = d.id AND dd.active = true
    CROSS JOIN parameter_departments_aggregated pda
    WHERE d.active = true
    AND (
        (pda.department_ids IS NULL OR array_length(pda.department_ids, 1) = 0)
        OR (pda.department_ids IS NOT NULL AND dd.department_id = ANY(pda.department_ids::uuid[]))
        OR NOT EXISTS (
            SELECT 1 FROM document_departments dd2 
            WHERE dd2.document_id = d.id AND dd2.active = true
        )
    )
),
valid_depts AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM params x
    JOIN departments d ON d.active = true
    JOIN profile_departments pd ON d.id = pd.department_id AND pd.profile_id = x.profile_id AND pd.active = true
)
SELECT 
    (SELECT parameter_exists FROM parameter_exists_check)::boolean as parameter_exists,
    -- Merge draft payload with parameter data (draft takes precedence)
    COALESCE(
        (SELECT payload->>'name' FROM draft_payload_data),
        pd.name::text
    ) as name,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        pd.description::text
    ) as description,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        pd.active::boolean
    ) as active,
    COALESCE(
        (SELECT (payload->>'simulation_parameter')::boolean FROM draft_payload_data),
        (SELECT (payload->>'simulationParameter')::boolean FROM draft_payload_data),
        pd.simulation_parameter::boolean
    ) as simulation_parameter,
    COALESCE(
        (SELECT (payload->>'document_parameter')::boolean FROM draft_payload_data),
        (SELECT (payload->>'documentParameter')::boolean FROM draft_payload_data),
        pd.document_parameter::boolean
    ) as document_parameter,
    COALESCE(
        (SELECT (payload->>'persona_parameter')::boolean FROM draft_payload_data),
        (SELECT (payload->>'personaParameter')::boolean FROM draft_payload_data),
        pd.persona_parameter::boolean
    ) as persona_parameter,
    COALESCE(
        (SELECT (payload->>'scenario_parameter')::boolean FROM draft_payload_data),
        (SELECT (payload->>'scenarioParameter')::boolean FROM draft_payload_data),
        pd.scenario_parameter::boolean
    ) as scenario_parameter,
    COALESCE(
        (SELECT (payload->>'video_parameter')::boolean FROM draft_payload_data),
        (SELECT (payload->>'videoParameter')::boolean FROM draft_payload_data),
        pd.video_parameter::boolean
    ) as video_parameter,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'department_ids' IS NOT NULL AND jsonb_typeof(payload->'department_ids') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'department_ids'))::text[]
                WHEN payload->'departmentIds' IS NOT NULL AND jsonb_typeof(payload->'departmentIds') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'departmentIds'))::text[]
                ELSE NULL
            END
        FROM draft_payload_data),
        pd.department_ids
    ) as department_ids,
    pd.persona_ids as persona_ids,
    pd.document_ids as document_ids,
    COALESCE(
        (SELECT ARRAY_AGG(
            (fwu.id, fwu.name, fwu.description, fwu."default", fwu.usage_count, fwu.department_ids)::types.q_get_parameter_detail_v4_item
            ORDER BY fwu.name
        ) FROM fields_with_usage fwu),
        '{}'::types.q_get_parameter_detail_v4_item[]
    ) as parameter_items,
    COALESCE(
        (SELECT ARRAY_AGG(
            (vd.department_id, vd.name, vd.description)::types.q_get_parameter_detail_v4_department
            ORDER BY vd.name
        ) FROM valid_depts vd),
        '{}'::types.q_get_parameter_detail_v4_department[]
    ) as departments,
    COALESCE(
        (SELECT ARRAY_AGG(vd.department_id::text ORDER BY vd.department_id)
         FROM valid_depts vd),
        ARRAY[]::text[]
    ) as valid_department_ids,
    COALESCE(
        (SELECT ARRAY_AGG(
            (afwu.id, afwu.name, afwu.description, afwu.usage_count, afwu.department_ids)::types.q_get_parameter_detail_v4_field
            ORDER BY afwu.name
        ) FROM all_fields_with_usage afwu),
        '{}'::types.q_get_parameter_detail_v4_field[]
    ) as fields,
    COALESCE(
        (SELECT ARRAY_AGG(afwu.id::text ORDER BY afwu.id)
         FROM all_fields_with_usage afwu),
        ARRAY[]::text[]
    ) as valid_field_ids,
    COALESCE(
        (SELECT ARRAY_AGG(
            (fcd.field_id, fcd."default", fcd.connection_active)::types.q_get_parameter_detail_v4_field_connection
            ORDER BY fcd.field_id
        ) FROM field_connections_data fcd),
        '{}'::types.q_get_parameter_detail_v4_field_connection[]
    ) as field_connections,
    COALESCE(
        (SELECT ARRAY_AGG(
            (fp.id, fp.name, fp.description)::types.q_get_parameter_detail_v4_persona
            ORDER BY fp.name
        ) FROM filtered_personas fp),
        '{}'::types.q_get_parameter_detail_v4_persona[]
    ) as personas,
    COALESCE(
        (SELECT ARRAY_AGG(fp.id::text ORDER BY fp.id)
         FROM filtered_personas fp),
        ARRAY[]::text[]
    ) as valid_persona_ids,
    COALESCE(
        (SELECT ARRAY_AGG(
            (fd.id, fd.name, fd.description)::types.q_get_parameter_detail_v4_document
            ORDER BY fd.name
        ) FROM filtered_documents fd),
        '{}'::types.q_get_parameter_detail_v4_document[]
    ) as documents,
    COALESCE(
        (SELECT ARRAY_AGG(fd.id::text ORDER BY fd.id)
         FROM filtered_documents fd),
        ARRAY[]::text[]
    ) as valid_document_ids,
    pd.can_edit::boolean as can_edit,
    up.actor_name::text as actor_name,
    -- Draft version (from draft payload if exists)
    COALESCE((SELECT draft_version FROM draft_payload_data), 0) as draft_version,
    -- Extract field_ids from draft payload if available (support both camelCase and snake_case)
    COALESCE(
        (SELECT payload->'fieldIds' FROM draft_payload_data),
        (SELECT payload->'field_ids' FROM draft_payload_data),
        -- Fallback: extract from field_connections if no draft
        (SELECT jsonb_agg(fcd.field_id::text ORDER BY fcd.field_id) FROM field_connections_data fcd),
        '[]'::jsonb
    ) as field_ids,
    -- Extract field_active_states from draft payload if available (support both camelCase and snake_case)
    COALESCE(
        (SELECT payload->'fieldActiveStates' FROM draft_payload_data),
        (SELECT payload->'field_active_states' FROM draft_payload_data),
        -- Fallback: extract from field_connections if no draft
        (SELECT jsonb_object_agg(fcd.field_id::text, fcd.connection_active) FROM field_connections_data fcd),
        '{}'::jsonb
    ) as field_active_states,
    -- Extract field_default_states from draft payload if available (support both camelCase and snake_case)
    COALESCE(
        (SELECT payload->'fieldDefaultStates' FROM draft_payload_data),
        (SELECT payload->'field_default_states' FROM draft_payload_data),
        -- Fallback: extract from field_connections if no draft
        (SELECT jsonb_object_agg(fcd.field_id::text, fcd."default") FROM field_connections_data fcd),
        '{}'::jsonb
    ) as field_default_states
FROM parameter_data pd
CROSS JOIN user_profile up
$$;


--
-- Name: api_get_parameter_new_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_parameter_new_v4(profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(actor_name text, user_role text, primary_department_id text, name text, description text, active boolean, simulation_parameter boolean, document_parameter boolean, persona_parameter boolean, scenario_parameter boolean, video_parameter boolean, department_ids text[], parameter_items types.q_get_parameter_new_v4_item[], departments types.q_get_parameter_new_v4_department[], valid_department_ids text[], fields types.q_get_parameter_new_v4_field[], valid_field_ids text[], field_connections types.q_get_parameter_new_v4_field_connection[], persona_ids text[], personas types.q_get_parameter_new_v4_persona[], valid_persona_ids text[], document_ids text[], documents types.q_get_parameter_new_v4_document[], valid_document_ids text[], can_edit boolean, draft_version integer, field_ids jsonb, field_active_states jsonb, field_default_states jsonb)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        profile_id AS profile_id,
        draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'parameters'::draft_resource_type
    LIMIT 1
),
actor_profile AS (
    SELECT 
        p.id as profile_id,
        p.role,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
user_departments AS (
    SELECT DISTINCT pd.department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id
    WHERE pd.active = true
),
field_departments_for_filter AS (
    SELECT DISTINCT
        fp.parameter_id,
        fd.department_id
    FROM parameter_fields fp
    JOIN field_departments fd ON fd.field_id = fp.field_id
    WHERE fp.active = true AND fd.active = true
),
default_parameter AS (
    SELECT p.id
    FROM parameters p
    LEFT JOIN field_departments_for_filter fdf ON fdf.parameter_id = p.id
    WHERE p.active = true
    GROUP BY p.id
    HAVING 
        -- Include if has matching department link via parameter_departments or field_departments OR has no department links at all (cross-dept)
        COUNT(fdf.parameter_id) FILTER (WHERE fdf.department_id IN (SELECT department_id FROM user_departments)) > 0
        OR NOT EXISTS (
            SELECT 1 FROM parameter_departments pd2 WHERE pd2.parameter_id = p.id AND pd2.active = true
        )
        AND NOT EXISTS (
            SELECT 1 FROM field_departments fd2 
            JOIN parameter_fields fp2 ON fp2.field_id = fd2.field_id 
            WHERE fp2.parameter_id = p.id AND fp2.active = true AND fd2.active = true
        )
    ORDER BY p.created_at DESC
    LIMIT 1
),
parameter_departments_aggregated AS (
    -- Get parameter-level departments (union of parameter_departments and field_departments)
    SELECT 
        ARRAY_AGG(DISTINCT dept_id::text ORDER BY dept_id::text) as department_ids
    FROM (
        -- Parameter-level departments
        SELECT pd.department_id as dept_id
        FROM parameter_departments pd
        JOIN default_parameter dp ON pd.parameter_id = dp.id
        WHERE pd.active = true
        UNION
        -- Field-level departments
        SELECT fd.department_id as dept_id
        FROM parameter_fields fp
        JOIN default_parameter dp ON fp.parameter_id = dp.id
        JOIN field_departments fd ON fd.field_id = fp.field_id AND fd.active = true
        WHERE fp.active = true
    ) combined_depts
),
parameter_data AS (
    SELECT 
        p.name,
        p.description,
        p.active,
        p.simulation_parameter,
        p.document_parameter,
        p.persona_parameter,
        p.scenario_parameter,
        p.video_parameter,
        COALESCE(pda.department_ids, NULL) as department_ids
    FROM parameters p
    JOIN default_parameter dp ON p.id = dp.id
    LEFT JOIN parameter_departments_aggregated pda ON true
),
-- All available fields (not just connected ones)
all_fields_data AS (
    SELECT 
        f.id as field_id,
        COALESCE(ARRAY_AGG(fd.department_id::text ORDER BY fd.created_at) FILTER (WHERE fd.department_id IS NOT NULL), ARRAY[]::text[]) as department_ids
    FROM fields f
    LEFT JOIN field_departments fd ON fd.field_id = f.id AND fd.active = true
    WHERE f.active = true
    GROUP BY f.id
),
all_fields_with_usage AS (
    SELECT 
        f.id,
        f.name,
        f.description,
        COALESCE(COUNT(sf.scenario_id), 0) as usage_count,
        COALESCE(afd.department_ids, ARRAY[]::text[]) as department_ids
    FROM fields f
    LEFT JOIN all_fields_data afd ON afd.field_id = f.id
    LEFT JOIN scenario_fields sf ON sf.field_id = f.id AND sf.active = true
    WHERE f.active = true
    GROUP BY f.id, f.name, f.description, afd.department_ids
),
-- Parameter items from default parameter (fields connected to default parameter)
field_departments_data AS (
    SELECT 
        f.id as parameter_item_id,
        COALESCE(ARRAY_AGG(fd.department_id::text ORDER BY fd.created_at) FILTER (WHERE fd.department_id IS NOT NULL), ARRAY[]::text[]) as department_ids
    FROM fields f
    JOIN parameter_fields fp ON fp.field_id = f.id AND fp.active = true
    JOIN default_parameter dp ON fp.parameter_id = dp.id
    LEFT JOIN field_departments fd ON fd.field_id = f.id AND fd.active = true
    GROUP BY f.id
),
parameter_items_with_usage AS (
    SELECT 
        f.id,
        f.name,
        f.description,
        COALESCE(fp."default", false) as "default",
        COALESCE(COUNT(sf.scenario_id), 0) as usage_count,
        COALESCE(fdd.department_ids, ARRAY[]::text[]) as department_ids
    FROM fields f
    JOIN parameter_fields fp ON fp.field_id = f.id AND fp.active = true
    JOIN default_parameter dp ON fp.parameter_id = dp.id
    LEFT JOIN scenario_fields sf ON sf.field_id = f.id AND sf.active = true
    LEFT JOIN field_departments_data fdd ON fdd.parameter_item_id = f.id
    GROUP BY f.id, f.name, f.description, fp."default", fdd.department_ids
),
-- Valid departments (user's departments)
valid_depts AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id
    JOIN departments d ON d.id = pd.department_id
    WHERE d.active = true
),
primary_department_id AS (
    SELECT department_id::text
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id
    WHERE pd.is_primary = TRUE
    LIMIT 1
),
-- Personas filtered by user's available departments
filtered_personas AS (
    SELECT DISTINCT p.id, p.name, COALESCE(p.description, '') as description
    FROM personas p
    LEFT JOIN persona_departments pd ON pd.persona_id = p.id AND pd.active = true
    CROSS JOIN user_departments ud
    WHERE p.active = true
    AND (
        -- Include if persona is in user's departments
        pd.department_id = ud.department_id
        -- Or if persona has no department restrictions (cross-department persona)
        OR NOT EXISTS (
            SELECT 1 FROM persona_departments pd2 
            WHERE pd2.persona_id = p.id AND pd2.active = true
        )
    )
),
-- Documents filtered by user's available departments
filtered_documents AS (
    SELECT DISTINCT d.id, d.name, COALESCE(d.description, '') as description
    FROM documents d
    LEFT JOIN document_departments dd ON dd.document_id = d.id AND dd.active = true
    CROSS JOIN user_departments ud
    WHERE d.active = true
    AND (
        -- Include if document is in user's departments
        dd.department_id = ud.department_id
        -- Or if document has no department restrictions (cross-department document)
        OR NOT EXISTS (
            SELECT 1 FROM document_departments dd2 
            WHERE dd2.document_id = d.id AND dd2.active = true
        )
    )
)
SELECT 
    ap.actor_name::text as actor_name,
    ap.role::text as user_role,
    COALESCE(pdi.department_id, NULL)::text as primary_department_id,
    -- Default values for new parameter (merged with draft payload if draft_id provided)
    COALESCE(
        (SELECT payload->>'name' FROM draft_payload_data),
        pd.name::text
    ) as name,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        pd.description::text
    ) as description,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        pd.active::boolean
    ) as active,
    COALESCE(
        (SELECT (payload->>'simulation_parameter')::boolean FROM draft_payload_data),
        (SELECT (payload->>'simulationParameter')::boolean FROM draft_payload_data),
        pd.simulation_parameter::boolean
    ) as simulation_parameter,
    COALESCE(
        (SELECT (payload->>'document_parameter')::boolean FROM draft_payload_data),
        (SELECT (payload->>'documentParameter')::boolean FROM draft_payload_data),
        pd.document_parameter::boolean
    ) as document_parameter,
    COALESCE(
        (SELECT (payload->>'persona_parameter')::boolean FROM draft_payload_data),
        (SELECT (payload->>'personaParameter')::boolean FROM draft_payload_data),
        pd.persona_parameter::boolean
    ) as persona_parameter,
    COALESCE(
        (SELECT (payload->>'scenario_parameter')::boolean FROM draft_payload_data),
        (SELECT (payload->>'scenarioParameter')::boolean FROM draft_payload_data),
        pd.scenario_parameter::boolean
    ) as scenario_parameter,
    COALESCE(
        (SELECT (payload->>'video_parameter')::boolean FROM draft_payload_data),
        (SELECT (payload->>'videoParameter')::boolean FROM draft_payload_data),
        pd.video_parameter::boolean
    ) as video_parameter,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'department_ids' IS NOT NULL AND jsonb_typeof(payload->'department_ids') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'department_ids'))::text[]
                WHEN payload->'departmentIds' IS NOT NULL AND jsonb_typeof(payload->'departmentIds') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'departmentIds'))::text[]
                ELSE NULL
            END
        FROM draft_payload_data),
        pd.department_ids
    ) as department_ids,
    -- Parameter items (from default parameter)
    COALESCE(
        (SELECT ARRAY_AGG(
            (piwu.id, piwu.name, piwu.description, piwu."default", piwu.usage_count, piwu.department_ids)::types.q_get_parameter_new_v4_item
            ORDER BY piwu.name
        ) FROM parameter_items_with_usage piwu),
        '{}'::types.q_get_parameter_new_v4_item[]
    ) as parameter_items,
    -- Departments (user's valid departments)
    COALESCE(
        (SELECT ARRAY_AGG(
            (vd.department_id, vd.name, vd.description)::types.q_get_parameter_new_v4_department
            ORDER BY vd.name
        ) FROM valid_depts vd),
        '{}'::types.q_get_parameter_new_v4_department[]
    ) as departments,
    -- Valid department IDs
    COALESCE(
        (SELECT ARRAY_AGG(vd.department_id::text ORDER BY vd.department_id)
         FROM valid_depts vd),
        ARRAY[]::text[]
    ) as valid_department_ids,
    -- Fields (all available fields)
    COALESCE(
        (SELECT ARRAY_AGG(
            (afwu.id, afwu.name, afwu.description, afwu.usage_count, afwu.department_ids)::types.q_get_parameter_new_v4_field
            ORDER BY afwu.name
        ) FROM all_fields_with_usage afwu),
        '{}'::types.q_get_parameter_new_v4_field[]
    ) as fields,
    -- Valid field IDs
    COALESCE(
        (SELECT ARRAY_AGG(afwu.id::text ORDER BY afwu.id)
         FROM all_fields_with_usage afwu),
        ARRAY[]::text[]
    ) as valid_field_ids,
    -- Field connections (empty for new parameter)
    '{}'::types.q_get_parameter_new_v4_field_connection[] as field_connections,
    -- Persona IDs (empty for new)
    ARRAY[]::text[] as persona_ids,
    -- Personas (filtered by user's departments)
    COALESCE(
        (SELECT ARRAY_AGG(
            (fp.id, fp.name, fp.description)::types.q_get_parameter_new_v4_persona
            ORDER BY fp.name
        ) FROM filtered_personas fp),
        '{}'::types.q_get_parameter_new_v4_persona[]
    ) as personas,
    -- Valid persona IDs
    COALESCE(
        (SELECT ARRAY_AGG(fp.id::text ORDER BY fp.id)
         FROM filtered_personas fp),
        ARRAY[]::text[]
    ) as valid_persona_ids,
    -- Document IDs (empty for new)
    ARRAY[]::text[] as document_ids,
    -- Documents (filtered by user's departments)
    COALESCE(
        (SELECT ARRAY_AGG(
            (fd.id, fd.name, fd.description)::types.q_get_parameter_new_v4_document
            ORDER BY fd.name
        ) FROM filtered_documents fd),
        '{}'::types.q_get_parameter_new_v4_document[]
    ) as documents,
    -- Valid document IDs
    COALESCE(
        (SELECT ARRAY_AGG(fd.id::text ORDER BY fd.id)
         FROM filtered_documents fd),
        ARRAY[]::text[]
    ) as valid_document_ids,
    -- Can edit (based on role and default parameter logic)
    CASE 
        WHEN (pd.department_ids IS NULL OR array_length(pd.department_ids, 1) = 0) AND ap.role != 'superadmin' THEN false::boolean
        WHEN ap.role = 'superadmin'::profile_role THEN true::boolean
        WHEN ap.role IN ('admin'::profile_role, 'instructional'::profile_role) THEN true::boolean
        ELSE false::boolean
    END as can_edit,
    -- Draft version (from draft payload if exists)
    COALESCE((SELECT draft_version FROM draft_payload_data), 0) as draft_version,
    -- Extract field_ids from draft payload if available (support both camelCase and snake_case)
    COALESCE(
        (SELECT payload->'fieldIds' FROM draft_payload_data),
        (SELECT payload->'field_ids' FROM draft_payload_data),
        '[]'::jsonb
    ) as field_ids,
    -- Extract field_active_states from draft payload if available (support both camelCase and snake_case)
    COALESCE(
        (SELECT payload->'fieldActiveStates' FROM draft_payload_data),
        (SELECT payload->'field_active_states' FROM draft_payload_data),
        '{}'::jsonb
    ) as field_active_states,
    -- Extract field_default_states from draft payload if available (support both camelCase and snake_case)
    COALESCE(
        (SELECT payload->'fieldDefaultStates' FROM draft_payload_data),
        (SELECT payload->'field_default_states' FROM draft_payload_data),
        '{}'::jsonb
    ) as field_default_states
FROM actor_profile ap
CROSS JOIN parameter_data pd
LEFT JOIN primary_department_id pdi ON true
$$;


--
-- Name: api_get_per_simulation_metrics_v4(text, text, uuid, uuid[], uuid[], public.profile_role[], text[], uuid[], uuid[], uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_per_simulation_metrics_v4(start_date text, end_date text, profile_id uuid, cohort_ids uuid[] DEFAULT ARRAY[]::uuid[], department_ids uuid[] DEFAULT ARRAY[]::uuid[], roles public.profile_role[] DEFAULT ARRAY[]::public.profile_role[], simulation_filters text[] DEFAULT ARRAY[]::text[], profile_ids uuid[] DEFAULT ARRAY[]::uuid[], simulation_ids uuid[] DEFAULT ARRAY[]::uuid[], scenario_ids uuid[] DEFAULT ARRAY[]::uuid[]) RETURNS TABLE(metrics types.q_per_simulation_metrics_v4_metric[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        (start_date::timestamptz) AS start_date,
        (end_date::timestamptz) AS end_date,
        profile_id,
        COALESCE(NULLIF(cohort_ids, ARRAY[]::uuid[]), ARRAY[]::uuid[]) AS cohort_ids,
        COALESCE(NULLIF(department_ids, ARRAY[]::uuid[]), ARRAY[]::uuid[]) AS department_ids,
        COALESCE(NULLIF(roles, ARRAY[]::profile_role[]), ARRAY[]::profile_role[]) AS roles,
        COALESCE(NULLIF(simulation_filters, ARRAY[]::text[]), ARRAY['general']::text[]) AS simulation_filters,
        COALESCE(NULLIF(profile_ids, ARRAY[]::uuid[]), ARRAY[]::uuid[]) AS profile_ids,
        COALESCE(NULLIF(simulation_ids, ARRAY[]::uuid[]), ARRAY[]::uuid[]) AS simulation_ids,
        COALESCE(NULLIF(scenario_ids, ARRAY[]::uuid[]), ARRAY[]::uuid[]) AS scenario_ids
),
filtered_profiles AS (
    SELECT 
        p.id, 
        p.first_name, 
        p.last_name
    FROM profiles p
    WHERE 
        (cardinality((SELECT roles FROM params)::profile_role[]) = 0 OR p.role = ANY((SELECT roles FROM params)::profile_role[]))
        AND (cardinality((SELECT cohort_ids FROM params)::uuid[]) = 0 OR EXISTS (
            SELECT 1 FROM cohort_profiles cp 
            WHERE cp.profile_id = p.id 
              AND cp.cohort_id = ANY((SELECT cohort_ids FROM params)::uuid[]) 
              AND cp.active = true
        ))
        AND (cardinality((SELECT department_ids FROM params)::uuid[]) = 0 OR EXISTS (
            SELECT 1 FROM profile_departments pd 
            WHERE pd.profile_id = p.id 
              AND pd.department_id = ANY((SELECT department_ids FROM params)::uuid[]) 
              AND pd.active = true
        ))
        AND (cardinality((SELECT profile_ids FROM params)::uuid[]) = 0 OR p.id = ANY((SELECT profile_ids FROM params)::uuid[]))
        AND ((SELECT profile_id FROM params) IS NULL OR p.id = (SELECT profile_id FROM params))
),
filt AS (
    SELECT a.* FROM analytics a
    WHERE a.attempt_created_at >= (SELECT start_date FROM params)
      AND a.attempt_created_at < (SELECT end_date FROM params)
      AND a.profile_id IN (SELECT id FROM filtered_profiles)
      AND (
          cardinality((SELECT cohort_ids FROM params)::uuid[]) = 0 OR
          a.simulation_id IN (
              SELECT DISTINCT s.id
              FROM simulations s
              WHERE s.active = TRUE
                AND (
                    EXISTS (
                        SELECT 1 
                        FROM cohort_simulations cs 
                        WHERE cs.simulation_id = s.id 
                          AND cs.cohort_id = ANY((SELECT cohort_ids FROM params)::uuid[])
                          AND cs.active = TRUE
                    )
                    OR
                    (s.practice_simulation = TRUE 
                     AND NOT EXISTS (
                         SELECT 1 
                         FROM cohort_simulations cs2 
                         WHERE cs2.simulation_id = s.id 
                           AND cs2.active = TRUE
                     ))
                )
          )
      )
      AND (cardinality((SELECT profile_ids FROM params)::uuid[]) = 0 OR a.profile_id = ANY((SELECT profile_ids FROM params)::uuid[]))
      AND (cardinality((SELECT simulation_ids FROM params)::uuid[]) = 0 OR a.simulation_id = ANY((SELECT simulation_ids FROM params)::uuid[]))
      AND (cardinality((SELECT scenario_ids FROM params)::uuid[]) = 0 OR a.scenario_id = ANY((SELECT scenario_ids FROM params)::uuid[]))
      AND (
          ('general' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_general = TRUE) OR
          ('practice' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_practice = TRUE) OR
          ('archived' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_archived = TRUE)
      )
      AND ('archived' = ANY((SELECT simulation_filters FROM params)::text[]) OR a.is_archived = FALSE)
),
simulation_metrics_per_profile AS (
    SELECT
        f.profile_id,
        f.simulation_id,
        AVG(f.grade_percent) FILTER (WHERE f.grade_percent IS NOT NULL) AS avg_score,
        MAX(f.grade_percent) FILTER (WHERE f.grade_percent IS NOT NULL) AS highest_score,
        (100.0 * AVG((f.completed)::int))::float AS completion_pct,
        COUNT(f.attempt_id)::int AS total_attempts,
        AVG(f.num_messages_total) AS avg_messages,
        AVG(f.time_taken_seconds / 60.0) AS avg_time_minutes
    FROM filt f
    WHERE f.simulation_id IS NOT NULL
    GROUP BY f.profile_id, f.simulation_id
),
earliest_attempts_all_time AS (
    SELECT DISTINCT ON (a.profile_id, a.simulation_id)
        a.profile_id,
        a.simulation_id,
        a.attempt_created_at,
        a.grade_percent,
        a.rubric_pass_points,
        a.rubric_points
    FROM analytics a
    WHERE a.profile_id IN (SELECT id FROM filtered_profiles)
    ORDER BY a.profile_id, a.simulation_id, a.attempt_created_at
),
filt_date_range AS (
    SELECT 
        MIN(attempt_created_at) AS min_date,
        MAX(attempt_created_at) AS max_date
    FROM filt
    WHERE attempt_created_at IS NOT NULL
),
first_attempts_per_sim AS (
    SELECT
        ea.profile_id,
        ea.simulation_id,
        ea.grade_percent >= (ea.rubric_pass_points * 100.0 / NULLIF(ea.rubric_points, 0)) AS passed
    FROM earliest_attempts_all_time ea
    CROSS JOIN filt_date_range fdr
    WHERE EXISTS (SELECT 1 FROM filt f WHERE f.profile_id = ea.profile_id AND f.simulation_id = ea.simulation_id)
      AND fdr.min_date IS NOT NULL
      AND ea.attempt_created_at >= fdr.min_date
      AND ea.attempt_created_at <= fdr.max_date
),
first_attempt_per_sim_profile AS (
    SELECT
        profile_id,
        simulation_id,
        (100.0 * COUNT(*) FILTER (WHERE passed) / NULLIF(COUNT(*), 0))::float AS pass_rate
    FROM first_attempts_per_sim
    GROUP BY profile_id, simulation_id
)
SELECT 
    COALESCE(
        ARRAY_AGG(
            (sm.profile_id,
             sm.simulation_id,
             COALESCE(sm.avg_score, 0),
             COALESCE(sm.highest_score, 0),
             COALESCE(sm.completion_pct, 0),
             COALESCE(fasp.pass_rate, 0),
             COALESCE(sm.total_attempts, 0),
             COALESCE(sm.avg_messages, 0),
             COALESCE(sm.avg_time_minutes, 0)
            )::types.q_per_simulation_metrics_v4_metric
            ORDER BY sm.profile_id, sm.simulation_id
        ),
        ARRAY[]::types.q_per_simulation_metrics_v4_metric[]
    ) AS metrics
FROM simulation_metrics_per_profile sm
LEFT JOIN first_attempt_per_sim_profile fasp 
    ON fasp.profile_id = sm.profile_id 
    AND fasp.simulation_id = sm.simulation_id
$$;


--
-- Name: api_get_persona_detail_v4(uuid, uuid, text, text, boolean, boolean, text, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_persona_detail_v4(persona_id uuid, profile_id uuid, color_search text DEFAULT NULL::text, icon_search text DEFAULT NULL::text, color_show_selected boolean DEFAULT NULL::boolean, icon_show_selected boolean DEFAULT NULL::boolean, current_color text DEFAULT NULL::text, current_icon text DEFAULT NULL::text, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(persona_exists boolean, name text, description text, department_ids uuid[], active boolean, color text, icon text, instructions text, in_use boolean, scenario_count bigint, can_edit boolean, can_duplicate boolean, can_delete boolean, valid_department_ids uuid[], valid_agent_ids uuid[], valid_parameter_ids uuid[], valid_parameter_item_ids uuid[], linked_parameter_ids uuid[], parameter_field_ids uuid[], example_ids uuid[], actor_name text, departments types.q_get_persona_detail_v4_department[], agents types.q_get_persona_detail_v4_agent[], parameters types.q_get_persona_detail_v4_parameter[], fields types.q_get_persona_detail_v4_field[], examples types.q_get_persona_detail_v4_example[], examples_history types.q_get_persona_detail_v4_example_history_item[], preset_colors types.q_get_persona_detail_v4_color[], suggested_icons text[], valid_icons text[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        persona_id AS persona_id,
        profile_id AS profile_id,
        color_search AS color_search,
        icon_search AS icon_search,
        COALESCE(color_show_selected, false) AS color_show_selected,
        COALESCE(icon_show_selected, false) AS icon_show_selected,
        current_color AS current_color,
        current_icon AS current_icon,
        draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'personas'::draft_resource_type
    LIMIT 1
),
persona_exists_check AS (
    SELECT EXISTS(
        SELECT 1 FROM personas WHERE id = (SELECT persona_id FROM params)
    )::boolean as persona_exists
),
user_profile AS (
    SELECT 
        p.role,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
user_departments AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.active = true
),
persona_departments_data AS (
    SELECT 
        pd.persona_id,
        ARRAY_AGG(pd.department_id ORDER BY pd.created_at) as department_ids
    FROM persona_departments pd
    WHERE pd.persona_id = (SELECT persona_id FROM params) AND pd.active = true
    GROUP BY pd.persona_id
),
persona_department_access_check AS (
    SELECT 
        p.id as persona_id,
        CASE 
            WHEN up.role = 'superadmin'::profile_role THEN true
            WHEN EXISTS (
                SELECT 1 FROM persona_departments pd 
                WHERE pd.persona_id = p.id 
                AND pd.active = true 
                AND pd.department_id IN (SELECT department_id FROM user_departments)
            ) THEN true
            WHEN NOT EXISTS (
                SELECT 1 FROM persona_departments pd3 
                WHERE pd3.persona_id = p.id 
                AND pd3.active = true
            ) THEN true
            ELSE false
        END as has_access
    FROM params x
    JOIN personas p ON p.id = x.persona_id
    CROSS JOIN user_profile up
),
persona_data AS (
    SELECT 
        p.name,
        p.description,
        p.active,
        p.color,
        p.icon,
        p.instructions,
        COALESCE(pdd.department_ids, NULL) as department_ids
    FROM params x
    JOIN personas p ON p.id = x.persona_id
    LEFT JOIN persona_departments_data pdd ON pdd.persona_id = p.id
    INNER JOIN persona_department_access_check pdac ON pdac.persona_id = p.id AND pdac.has_access = true
),
department_mapping_data AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM params x
    JOIN departments d ON d.active = true
    JOIN profile_departments pd ON d.id = pd.department_id AND pd.profile_id = x.profile_id AND pd.active = true
),
valid_department_ids_data AS (
    SELECT ARRAY_AGG(department_id ORDER BY name) as valid_department_ids
    FROM department_mapping_data
),
agent_mapping_data AS (
    SELECT 
        a.id as agent_id,
        a.name,
        COALESCE(a.description, '') as description,
        ARRAY[a.role::text] as roles
    FROM agents a
    WHERE a.active = true
    AND a.role IN ('simulation'::agent_role, 'voice'::agent_role)
    AND (
        EXISTS (
            SELECT 1 FROM agent_departments ad 
            WHERE ad.agent_id = a.id 
            AND ad.active = true 
            AND ad.department_id IN (SELECT department_id FROM user_departments)
        )
        OR NOT EXISTS (
            SELECT 1 FROM agent_departments ad2 
            WHERE ad2.agent_id = a.id 
            AND ad2.active = true
        )
    )
),
valid_agent_ids_data AS (
    SELECT ARRAY_AGG(agent_id) as valid_agent_ids
    FROM agent_mapping_data
),
usage_data AS (
    SELECT COUNT(*) as usage_count
    FROM params x
    JOIN scenario_personas sp ON sp.persona_id = x.persona_id AND sp.active = true
),
parameter_mapping_data AS (
    SELECT 
        p.id as parameter_id,
        p.name,
        COALESCE(p.description, '') as description,
        false as numerical,
        COALESCE(p.document_parameter, false) as document_parameter,
        COALESCE(p.persona_parameter, false) as persona_parameter,
        COALESCE(p.scenario_parameter, false) as scenario_parameter,
        COALESCE(p.video_parameter, false) as video_parameter
    FROM parameters p
    WHERE p.active = true AND p.persona_parameter = true
),
valid_parameter_ids_data AS (
    SELECT ARRAY_AGG(parameter_id ORDER BY name) as valid_parameter_ids
    FROM parameter_mapping_data
),
linked_parameter_ids_data AS (
    SELECT ARRAY[]::uuid[] as linked_parameter_ids
),
field_mapping_data AS (
    SELECT 
        f.id as field_id,
        f.name,
        COALESCE(f.description, '') as description,
        pf.parameter_id,
        p.name as parameter_name
    FROM parameter_mapping_data pmd
    JOIN parameter_fields pf ON pf.parameter_id = pmd.parameter_id AND pf.active = true
    JOIN fields f ON f.id = pf.field_id AND f.active = true
    JOIN parameters p ON p.id = pf.parameter_id
    WHERE p.active = true
),
valid_parameter_item_ids_data AS (
    SELECT ARRAY_AGG(field_id ORDER BY name) as valid_parameter_item_ids
    FROM field_mapping_data
),
parameter_field_ids_data AS (
    SELECT ARRAY[]::uuid[] as parameter_field_ids
),
persona_examples_data AS (
    SELECT 
        ARRAY_AGG(e.id ORDER BY pe.idx) as example_ids
    FROM params x
    JOIN persona_examples pe ON pe.persona_id = x.persona_id
    JOIN examples e ON e.id = pe.example_id
),
example_mapping_data AS (
    SELECT 
        e.id as example_id,
        e.example as name,
        e.example as description
    FROM params x
    JOIN persona_examples pe ON pe.persona_id = x.persona_id
    JOIN examples e ON e.id = pe.example_id
),
accessible_personas AS (
    SELECT DISTINCT p.id as persona_id
    FROM params x
    JOIN personas p ON true
    LEFT JOIN persona_departments pd ON pd.persona_id = p.id AND pd.active = true
    CROSS JOIN user_profile up
    WHERE (
        up.role = 'superadmin'::profile_role
        OR pd.department_id IN (SELECT department_id FROM user_departments)
        OR NOT EXISTS (SELECT 1 FROM persona_departments pd2 WHERE pd2.persona_id = p.id AND pd2.active = true)
    )
),
examples_with_departments AS (
    SELECT 
        e.example,
        COALESCE(
            ARRAY_AGG(DISTINCT pd.department_id::text) FILTER (
                WHERE pd.department_id IS NOT NULL
            ),
            ARRAY[]::text[]
        ) as department_ids
    FROM persona_examples pe
    JOIN examples e ON e.id = pe.example_id
    JOIN accessible_personas ap ON ap.persona_id = pe.persona_id
    LEFT JOIN persona_departments pd ON pd.persona_id = pe.persona_id AND pd.active = true
    WHERE e.example IS NOT NULL AND e.example != ''
    GROUP BY e.example
),
examples_history_data AS (
    SELECT COALESCE(
        (
            SELECT ARRAY_AGG(
                (example, department_ids)::types.q_get_persona_detail_v4_example_history_item
                ORDER BY example
            )
            FROM examples_with_departments
        ),
        '{}'::types.q_get_persona_detail_v4_example_history_item[]
    ) as examples_history
),
permissions_data AS (
    SELECT 
        pd.department_ids,
        ud.usage_count,
        up.role as user_role,
        CASE 
            WHEN pd.department_ids IS NULL AND up.role != 'superadmin' THEN false
            WHEN ud.usage_count > 0 THEN false
            WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_edit,
        true as can_duplicate,
        CASE 
            WHEN pd.department_ids IS NULL AND up.role != 'superadmin' THEN false
            WHEN ud.usage_count > 0 THEN false
            WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_delete
    FROM persona_data pd
    CROSS JOIN usage_data ud
    CROSS JOIN user_profile up
),
-- All preset colors (hardcoded - matches detail.py)
all_preset_colors AS (
    SELECT * FROM (VALUES
        ('#ef4444', 'Red'),
        ('#f97316', 'Orange'),
        ('#f59e0b', 'Amber'),
        ('#eab308', 'Yellow'),
        ('#84cc16', 'Lime'),
        ('#22c55e', 'Green'),
        ('#10b981', 'Emerald'),
        ('#14b8a6', 'Teal'),
        ('#06b6d4', 'Cyan'),
        ('#0ea5e9', 'Sky'),
        ('#3b82f6', 'Blue'),
        ('#6366f1', 'Indigo'),
        ('#8b5cf6', 'Violet'),
        ('#a855f7', 'Purple'),
        ('#d946ef', 'Fuchsia'),
        ('#ec4899', 'Pink'),
        ('#f43f5e', 'Rose')
    ) AS t(hex, name)
),
-- Filtered preset colors based on search and show_selected
preset_colors_filtered AS (
    SELECT apc.hex, apc.name
    FROM all_preset_colors apc
    CROSS JOIN params p
    WHERE 
        -- Search filter: if color_search provided, match name or hex
        (p.color_search IS NULL OR p.color_search = '' OR
         LOWER(apc.name) LIKE '%' || LOWER(p.color_search) || '%' OR
         LOWER(apc.hex) LIKE '%' || LOWER(p.color_search) || '%')
        -- Show selected filter: if enabled and current_color provided, only show current color
        AND (
            NOT p.color_show_selected OR
            p.current_color IS NULL OR
            UPPER(apc.hex) = UPPER(COALESCE(p.current_color, ''))
        )
),
-- All suggested icons (hardcoded - matches detail.py)
all_suggested_icons AS (
    SELECT unnest(ARRAY['Brain', 'User', 'Users', 'Sparkles', 'Zap', 'Heart', 'Star', 'MessageSquare', 'Bot', 'GraduationCap']) AS icon_name
),
-- Filtered suggested icons based on search and show_selected
suggested_icons_filtered AS (
    SELECT asi.icon_name
    FROM all_suggested_icons asi
    CROSS JOIN params p
    WHERE 
        -- Search filter: if icon_search provided, match name
        (p.icon_search IS NULL OR p.icon_search = '' OR
         LOWER(asi.icon_name) LIKE '%' || LOWER(p.icon_search) || '%')
        -- Show selected filter: if enabled and current_icon provided, only show current icon
        AND (
            NOT p.icon_show_selected OR
            p.current_icon IS NULL OR
            LOWER(asi.icon_name) = LOWER(COALESCE(p.current_icon, ''))
        )
),
-- All valid icons (hardcoded - matches detail.py)
all_valid_icons AS (
    SELECT unnest(ARRAY[
        'Brain', 'User', 'Users', 'Sparkles', 'Zap', 'Heart', 'Star', 'MessageSquare', 'Bot', 'GraduationCap',
        'Lightbulb', 'Target', 'Award', 'BookOpen', 'Code', 'Cpu', 'Database', 'FileText', 'Globe',
        'Mail', 'Mic', 'Monitor', 'Phone', 'Radio', 'Search', 'Settings', 'Shield', 'Video', 'Wifi'
    ]) AS icon_name
),
-- Filtered valid icons based on search and show_selected
valid_icons_filtered AS (
    SELECT avi.icon_name
    FROM all_valid_icons avi
    CROSS JOIN params p
    WHERE 
        -- Search filter: if icon_search provided, match name
        (p.icon_search IS NULL OR p.icon_search = '' OR
         LOWER(avi.icon_name) LIKE '%' || LOWER(p.icon_search) || '%')
        -- Show selected filter: if enabled and current_icon provided, only show current icon
        AND (
            NOT p.icon_show_selected OR
            p.current_icon IS NULL OR
            LOWER(avi.icon_name) = LOWER(COALESCE(p.current_icon, ''))
        )
)
SELECT 
    (SELECT persona_exists FROM persona_exists_check) as persona_exists,
    -- Merge draft payload over existing persona data if draft_id provided
    COALESCE(
        (SELECT payload->>'name' FROM draft_payload_data),
        pd.name
    ) as name,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        pd.description
    ) as description,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'department_ids' IS NOT NULL AND jsonb_typeof(payload->'department_ids') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'department_ids'))::uuid[]
                ELSE NULL
            END
        FROM draft_payload_data),
        pd.department_ids
    ) as department_ids,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        pd.active
    ) as active,
    COALESCE(
        (SELECT payload->>'color' FROM draft_payload_data),
        pd.color
    ) as color,
    COALESCE(
        (SELECT payload->>'icon' FROM draft_payload_data),
        pd.icon
    ) as icon,
    COALESCE(
        (SELECT payload->>'instructions' FROM draft_payload_data),
        pd.instructions
    ) as instructions,
    CASE WHEN COALESCE(ud.usage_count, 0) > 0 THEN true ELSE false END as in_use,
    COALESCE(ud.usage_count, 0) as scenario_count,
    perm.can_edit,
    perm.can_duplicate,
    perm.can_delete,
    COALESCE(vdid.valid_department_ids, ARRAY[]::uuid[]) as valid_department_ids,
    COALESCE(vaid.valid_agent_ids, ARRAY[]::uuid[]) as valid_agent_ids,
    COALESCE(vpid.valid_parameter_ids, ARRAY[]::uuid[]) as valid_parameter_ids,
    COALESCE(vpiid.valid_parameter_item_ids, ARRAY[]::uuid[]) as valid_parameter_item_ids,
    COALESCE(lpid.linked_parameter_ids, ARRAY[]::uuid[]) as linked_parameter_ids,
    COALESCE(pfid.parameter_field_ids, ARRAY[]::uuid[]) as parameter_field_ids,
    COALESCE(ped.example_ids, ARRAY[]::uuid[]) as example_ids,
    up.actor_name::text as actor_name,
    -- Aggregate departments separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (dmd.department_id, dmd.name, dmd.description)::types.q_get_persona_detail_v4_department
            ORDER BY dmd.name
        ) FROM department_mapping_data dmd),
        '{}'::types.q_get_persona_detail_v4_department[]
    ) as departments,
    -- Aggregate agents separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (amd.agent_id, amd.name, amd.description, amd.roles)::types.q_get_persona_detail_v4_agent
            ORDER BY amd.name
        ) FROM agent_mapping_data amd),
        '{}'::types.q_get_persona_detail_v4_agent[]
    ) as agents,
    -- Aggregate parameters separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (pmd.parameter_id, pmd.name, pmd.description, pmd.numerical, 
             pmd.document_parameter, pmd.persona_parameter, pmd.scenario_parameter, pmd.video_parameter)::types.q_get_persona_detail_v4_parameter
            ORDER BY pmd.name
        ) FROM parameter_mapping_data pmd),
        '{}'::types.q_get_persona_detail_v4_parameter[]
    ) as parameters,
    -- Aggregate fields separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (fmd.field_id, fmd.name, fmd.description, fmd.parameter_id, fmd.parameter_name)::types.q_get_persona_detail_v4_field
            ORDER BY fmd.name
        ) FROM field_mapping_data fmd),
        '{}'::types.q_get_persona_detail_v4_field[]
    ) as fields,
    -- Aggregate examples separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (emd.example_id, emd.name, emd.description)::types.q_get_persona_detail_v4_example
            ORDER BY emd.name
        ) FROM example_mapping_data emd),
        '{}'::types.q_get_persona_detail_v4_example[]
    ) as examples,
    COALESCE((SELECT examples_history FROM examples_history_data), '{}'::types.q_get_persona_detail_v4_example_history_item[]) as examples_history,
    -- Filtered preset colors (SQL-side filtering)
    COALESCE(
        (SELECT ARRAY_AGG((pcf.hex, pcf.name)::types.q_get_persona_detail_v4_color ORDER BY pcf.name) FROM preset_colors_filtered pcf),
        '{}'::types.q_get_persona_detail_v4_color[]
    ) as preset_colors,
    -- Filtered suggested icons (SQL-side filtering)
    COALESCE(
        (SELECT ARRAY_AGG(sif.icon_name ORDER BY sif.icon_name) FROM suggested_icons_filtered sif),
        '{}'::text[]
    ) as suggested_icons,
    -- Filtered valid icons (SQL-side filtering)
    COALESCE(
        (SELECT ARRAY_AGG(vif.icon_name ORDER BY vif.icon_name) FROM valid_icons_filtered vif),
        '{}'::text[]
    ) as valid_icons
FROM persona_data pd
CROSS JOIN usage_data ud
CROSS JOIN user_profile up
CROSS JOIN permissions_data perm
CROSS JOIN valid_department_ids_data vdid
CROSS JOIN valid_agent_ids_data vaid
CROSS JOIN valid_parameter_ids_data vpid
CROSS JOIN valid_parameter_item_ids_data vpiid
CROSS JOIN linked_parameter_ids_data lpid
CROSS JOIN parameter_field_ids_data pfid
CROSS JOIN persona_examples_data ped
CROSS JOIN examples_history_data ehd
$$;


--
-- Name: api_get_persona_instructions_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_persona_instructions_v4(chat_id uuid) RETURNS TABLE(persona_id text, persona_name text, instructions text)
    LANGUAGE sql STABLE
    AS $$
SELECT 
    p.id::text as persona_id,
    p.name as persona_name,
    COALESCE(p.instructions, '') as instructions
FROM chats c
JOIN scenario_personas sp ON sp.scenario_id = c.scenario_id AND sp.active = true
JOIN personas p ON p.id = sp.persona_id
WHERE c.id = chat_id
  AND p.active = true
ORDER BY p.name
$$;


--
-- Name: api_get_persona_new_v4(uuid, text, text, boolean, boolean, text, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_persona_new_v4(profile_id uuid, color_search text DEFAULT NULL::text, icon_search text DEFAULT NULL::text, color_show_selected boolean DEFAULT NULL::boolean, icon_show_selected boolean DEFAULT NULL::boolean, current_color text DEFAULT NULL::text, current_icon text DEFAULT NULL::text, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(actor_name text, user_role text, primary_department_id uuid, valid_department_ids uuid[], valid_agent_ids uuid[], valid_parameter_ids uuid[], valid_parameter_item_ids uuid[], departments types.q_get_persona_new_v4_department[], agents types.q_get_persona_new_v4_agent[], parameters types.q_get_persona_new_v4_parameter[], fields types.q_get_persona_new_v4_field[], preset_colors types.q_get_persona_new_v4_color[], suggested_icons text[], valid_icons text[], name text, description text, department_ids uuid[], active boolean, color text, icon text, instructions text, in_use boolean, scenario_count integer, can_edit boolean, can_duplicate boolean, can_delete boolean)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        profile_id AS profile_id,
        color_search AS color_search,
        icon_search AS icon_search,
        COALESCE(color_show_selected, false) AS color_show_selected,
        COALESCE(icon_show_selected, false) AS icon_show_selected,
        current_color AS current_color,
        current_icon AS current_icon,
        draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'personas'::draft_resource_type
    LIMIT 1
),
user_profile AS (
    SELECT 
        p.first_name || ' ' || p.last_name as actor_name,
        p.role as user_role
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
user_departments AS (
    SELECT DISTINCT pd.department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.active = true
),
department_mapping_data AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM params x
    JOIN departments d ON d.active = true
    JOIN profile_departments pd ON d.id = pd.department_id AND pd.profile_id = x.profile_id AND pd.active = true
),
valid_department_ids_data AS (
    SELECT ARRAY_AGG(department_id ORDER BY name) as valid_department_ids
    FROM department_mapping_data
),
primary_department_id_data AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.is_primary = TRUE
    LIMIT 1
),
agent_mapping_data AS (
    SELECT 
        a.id as agent_id,
        a.name,
        COALESCE(a.description, '') as description,
        ARRAY[a.role::text] as roles
    FROM params x
    JOIN agents a ON a.active = true AND a.role IN ('simulation'::agent_role, 'voice'::agent_role)
    LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
    GROUP BY a.id, a.name, a.description, a.role
    HAVING 
        COUNT(ad.agent_id) FILTER (WHERE ad.department_id IN (SELECT department_id FROM user_departments)) > 0
        OR NOT EXISTS (SELECT 1 FROM agent_departments ad2 WHERE ad2.agent_id = a.id AND ad2.active = true)
),
valid_agent_ids_data AS (
    SELECT ARRAY_AGG(agent_id ORDER BY name) as valid_agent_ids
    FROM agent_mapping_data
),
parameter_mapping_data AS (
    SELECT 
        p.id as parameter_id,
        p.name,
        COALESCE(p.description, '') as description,
        false as numerical,
        COALESCE(p.document_parameter, false) as document_parameter,
        COALESCE(p.persona_parameter, false) as persona_parameter,
        COALESCE(p.scenario_parameter, false) as scenario_parameter,
        COALESCE(p.video_parameter, false) as video_parameter
    FROM parameters p
    WHERE p.active = true AND p.persona_parameter = true
),
valid_parameter_ids_data AS (
    SELECT ARRAY_AGG(parameter_id ORDER BY name) as valid_parameter_ids
    FROM parameter_mapping_data
),
field_mapping_data AS (
    SELECT 
        f.id as field_id,
        f.name,
        COALESCE(f.description, '') as description,
        pf.parameter_id,
        p.name as parameter_name
    FROM parameter_mapping_data pmd
    JOIN parameter_fields pf ON pf.parameter_id = pmd.parameter_id AND pf.active = true
    JOIN fields f ON f.id = pf.field_id AND f.active = true
    JOIN parameters p ON p.id = pf.parameter_id
    WHERE p.active = true
),
valid_parameter_item_ids_data AS (
    SELECT ARRAY_AGG(field_id ORDER BY name) as valid_parameter_item_ids
    FROM field_mapping_data
),
-- All preset colors (hardcoded)
all_preset_colors AS (
    SELECT * FROM (VALUES
        ('#EF4444', 'Red'),
        ('#F97316', 'Orange'),
        ('#F59E0B', 'Amber'),
        ('#10B981', 'Emerald'),
        ('#3B82F6', 'Blue'),
        ('#6366F1', 'Indigo'),
        ('#8B5CF6', 'Violet'),
        ('#EC4899', 'Pink')
    ) AS t(hex, name)
),
-- Filtered preset colors based on search and show_selected
preset_colors_filtered AS (
    SELECT apc.hex, apc.name
    FROM all_preset_colors apc
    CROSS JOIN params p
    WHERE 
        -- Search filter: if color_search provided, match name or hex
        (p.color_search IS NULL OR p.color_search = '' OR
         LOWER(apc.name) LIKE '%' || LOWER(p.color_search) || '%' OR
         LOWER(apc.hex) LIKE '%' || LOWER(p.color_search) || '%')
        -- Show selected filter: if enabled and current_color provided, only show current color
        AND (
            NOT p.color_show_selected OR
            p.current_color IS NULL OR
            UPPER(apc.hex) = UPPER(COALESCE(p.current_color, ''))
        )
),
-- All suggested icons (hardcoded)
all_suggested_icons AS (
    SELECT unnest(ARRAY['Sparkles', 'Zap', 'Star', 'Heart', 'Users']) AS icon_name
),
-- Filtered suggested icons based on search and show_selected
suggested_icons_filtered AS (
    SELECT asi.icon_name
    FROM all_suggested_icons asi
    CROSS JOIN params p
    WHERE 
        -- Search filter: if icon_search provided, match name
        (p.icon_search IS NULL OR p.icon_search = '' OR
         LOWER(asi.icon_name) LIKE '%' || LOWER(p.icon_search) || '%')
        -- Show selected filter: if enabled and current_icon provided, only show current icon
        AND (
            NOT p.icon_show_selected OR
            p.current_icon IS NULL OR
            LOWER(asi.icon_name) = LOWER(COALESCE(p.current_icon, ''))
        )
),
-- All valid icons (hardcoded)
all_valid_icons AS (
    SELECT unnest(ARRAY[
        'Activity', 'Anchor', 'Award', 'Bell', 'Book', 'Briefcase', 'Calendar', 'Camera',
        'ChevronRight', 'Clock', 'Cloud', 'Code', 'Compass', 'Database', 'FileText', 'Globe',
        'Mail', 'Mic', 'Monitor', 'Phone', 'Radio', 'Search', 'Settings', 'Shield', 'Video', 'Wifi'
    ]) AS icon_name
),
-- Filtered valid icons based on search and show_selected
valid_icons_filtered AS (
    SELECT avi.icon_name
    FROM all_valid_icons avi
    CROSS JOIN params p
    WHERE 
        -- Search filter: if icon_search provided, match name
        (p.icon_search IS NULL OR p.icon_search = '' OR
         LOWER(avi.icon_name) LIKE '%' || LOWER(p.icon_search) || '%')
        -- Show selected filter: if enabled and current_icon provided, only show current icon
        AND (
            NOT p.icon_show_selected OR
            p.current_icon IS NULL OR
            LOWER(avi.icon_name) = LOWER(COALESCE(p.current_icon, ''))
        )
)
SELECT 
    up.actor_name::text as actor_name,
    up.user_role::text as user_role,
    (SELECT department_id FROM primary_department_id_data) as primary_department_id,
    COALESCE(vdid.valid_department_ids, ARRAY[]::uuid[]) as valid_department_ids,
    COALESCE(vaid.valid_agent_ids, ARRAY[]::uuid[]) as valid_agent_ids,
    COALESCE(vpid.valid_parameter_ids, ARRAY[]::uuid[]) as valid_parameter_ids,
    COALESCE(vpiid.valid_parameter_item_ids, ARRAY[]::uuid[]) as valid_parameter_item_ids,
    -- Aggregate departments separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (dmd.department_id, dmd.name, dmd.description)::types.q_get_persona_new_v4_department
            ORDER BY dmd.name
        ) FROM department_mapping_data dmd),
        '{}'::types.q_get_persona_new_v4_department[]
    ) as departments,
    -- Aggregate agents separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (amd.agent_id, amd.name, amd.description, amd.roles)::types.q_get_persona_new_v4_agent
            ORDER BY amd.name
        ) FROM agent_mapping_data amd),
        '{}'::types.q_get_persona_new_v4_agent[]
    ) as agents,
    -- Aggregate parameters separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (pmd.parameter_id, pmd.name, pmd.description, pmd.numerical, 
             pmd.document_parameter, pmd.persona_parameter, pmd.scenario_parameter, pmd.video_parameter)::types.q_get_persona_new_v4_parameter
            ORDER BY pmd.name
        ) FROM parameter_mapping_data pmd),
        '{}'::types.q_get_persona_new_v4_parameter[]
    ) as parameters,
    -- Aggregate fields separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (fmd.field_id, fmd.name, fmd.description, fmd.parameter_id, fmd.parameter_name)::types.q_get_persona_new_v4_field
            ORDER BY fmd.name
        ) FROM field_mapping_data fmd),
        '{}'::types.q_get_persona_new_v4_field[]
    ) as fields,
    -- Filtered preset colors (SQL-side filtering)
    COALESCE(
        (SELECT ARRAY_AGG((pcf.hex, pcf.name)::types.q_get_persona_new_v4_color ORDER BY pcf.name) FROM preset_colors_filtered pcf),
        '{}'::types.q_get_persona_new_v4_color[]
    ) as preset_colors,
    -- Filtered suggested icons (SQL-side filtering)
    COALESCE(
        (SELECT ARRAY_AGG(sif.icon_name ORDER BY sif.icon_name) FROM suggested_icons_filtered sif),
        '{}'::text[]
    ) as suggested_icons,
    -- Filtered valid icons (SQL-side filtering)
    COALESCE(
        (SELECT ARRAY_AGG(vif.icon_name ORDER BY vif.icon_name) FROM valid_icons_filtered vif),
        '{}'::text[]
    ) as valid_icons,
    -- Default values for new persona (merged with draft payload if draft_id provided)
    COALESCE(
        (SELECT payload->>'name' FROM draft_payload_data),
        ''::text
    ) as name,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        ''::text
    ) as description,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'department_ids' IS NOT NULL AND jsonb_typeof(payload->'department_ids') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'department_ids'))::uuid[]
                ELSE NULL
            END
        FROM draft_payload_data),
        CASE 
            WHEN up.user_role = 'superadmin' THEN NULL::uuid[]
            ELSE COALESCE(ARRAY[(SELECT department_id FROM primary_department_id_data)], ARRAY[]::uuid[])
        END
    ) as department_ids,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        true::boolean
    ) as active,
    COALESCE(
        (SELECT payload->>'color' FROM draft_payload_data),
        NULL::text
    ) as color,
    COALESCE(
        (SELECT payload->>'icon' FROM draft_payload_data),
        NULL::text
    ) as icon,
    COALESCE(
        (SELECT payload->>'instructions' FROM draft_payload_data),
        ''::text
    ) as instructions,
    false::boolean as in_use,
    0::int as scenario_count,
    -- can_edit: true for superadmin, or if default_department_ids is not empty
    CASE 
        WHEN up.user_role = 'superadmin' THEN true
        WHEN (SELECT department_id FROM primary_department_id_data) IS NOT NULL THEN true
        ELSE false
    END::boolean as can_edit,
    false::boolean as can_duplicate,
    false::boolean as can_delete
FROM user_profile up
CROSS JOIN valid_department_ids_data vdid
CROSS JOIN valid_agent_ids_data vaid
CROSS JOIN valid_parameter_ids_data vpid
CROSS JOIN valid_parameter_item_ids_data vpiid
$$;


--
-- Name: api_get_practice_history_v4(uuid, uuid[], text, uuid[], uuid[], uuid[], boolean, text, text, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_practice_history_v4(profile_id uuid, department_ids uuid[] DEFAULT ARRAY[]::uuid[], search text DEFAULT NULL::text, profile_ids uuid[] DEFAULT ARRAY[]::uuid[], simulation_ids uuid[] DEFAULT ARRAY[]::uuid[], scenario_ids uuid[] DEFAULT ARRAY[]::uuid[], infinite_mode boolean DEFAULT NULL::boolean, sort_by text DEFAULT 'date'::text, sort_order text DEFAULT 'desc'::text, page_size integer DEFAULT 20, page_offset integer DEFAULT 0) RETURNS TABLE(data types.q_get_practice_history_v4_attempt[], total_count integer, page integer, page_size integer, total_pages integer, profile_options types.q_get_practice_history_v4_profile_option[], simulation_options types.q_get_practice_history_v4_simulation_option[], scenario_options types.q_get_practice_history_v4_scenario_option[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        profile_id AS profile_id,
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids,
        search AS search,
        COALESCE(profile_ids, ARRAY[]::uuid[]) AS profile_ids,
        COALESCE(simulation_ids, ARRAY[]::uuid[]) AS simulation_ids,
        COALESCE(scenario_ids, ARRAY[]::uuid[]) AS scenario_ids,
        infinite_mode AS infinite_mode,
        COALESCE(sort_by, 'date') AS sort_by,
        COALESCE(sort_order, 'desc') AS sort_order,
        COALESCE(page_size, 20) AS page_size,
        COALESCE(page_offset, 0) AS page_offset
),
resolve_profile_id AS (
    -- Resolve profile ID from parameter
    SELECT 
        CASE 
            WHEN (SELECT profile_id FROM params)::text IS NULL OR (SELECT profile_id FROM params)::text = '' THEN NULL::uuid
            ELSE (SELECT profile_id FROM params)::uuid
        END as resolved_profile_id
),
-- Filter attempts by profile and departments (practice simulations only)
history_attempts AS (
    SELECT DISTINCT
        sa.id AS attempt_id,
        sa.simulation_id,
        sa.created_at AS attempt_date,
        sa.archived AS is_archived,
        sa.infinite_mode,
        ap.profile_id,
        sim.title AS simulation_name,
        sim.practice_simulation,
        COALESCE(sdd.department_ids, NULL) as department_ids
    FROM simulation_attempts sa
    JOIN attempt_profiles ap ON ap.attempt_id = sa.id AND ap.active = TRUE
    JOIN simulations sim ON sim.id = sa.simulation_id
    LEFT JOIN (
        SELECT 
            sd.simulation_id,
            ARRAY_AGG(sd.department_id::text ORDER BY sd.created_at) as department_ids
        FROM simulation_departments sd
        WHERE sd.active = true
        GROUP BY sd.simulation_id
    ) sdd ON sdd.simulation_id = sim.id
    WHERE sim.practice_simulation = TRUE
      AND ap.profile_id = (SELECT resolved_profile_id FROM resolve_profile_id)
      AND (cardinality((SELECT department_ids FROM params)::uuid[]) = 0 OR sdd.department_ids IS NULL OR sdd.department_ids && ARRAY(SELECT dept_id::text FROM unnest((SELECT department_ids FROM params)::uuid[]) as dept_id))
),
-- Get cohorts for each attempt's profile
history_attempt_cohorts AS (
    SELECT
        ha.attempt_id,
        COALESCE(ARRAY_AGG(DISTINCT c.title) FILTER (WHERE c.id IS NOT NULL AND cs.simulation_id = ha.simulation_id), ARRAY[]::text[]) AS cohort_names
    FROM history_attempts ha
    LEFT JOIN cohort_profiles cp ON cp.profile_id = ha.profile_id
    LEFT JOIN cohorts c ON c.id = cp.cohort_id AND c.active = TRUE
    LEFT JOIN cohort_simulations cs ON cs.cohort_id = c.id
    GROUP BY ha.attempt_id
),
-- Get all unique profile options from filtered attempts (before history-specific filters)
profile_options_cte AS (
    SELECT 
        ha.profile_id,
        p.first_name || ' ' || p.last_name AS profile_name,
        COUNT(DISTINCT ha.attempt_id) AS count
    FROM history_attempts ha
    JOIN profiles p ON p.id = ha.profile_id
    GROUP BY ha.profile_id, p.first_name, p.last_name
    ORDER BY profile_name
),
-- Get all unique simulation options from filtered attempts (before history-specific filters)
simulation_options_cte AS (
    SELECT 
        ha.simulation_id,
        s.title AS simulation_name,
        COUNT(DISTINCT ha.attempt_id) AS count
    FROM history_attempts ha
    JOIN simulations s ON s.id = ha.simulation_id
    GROUP BY ha.simulation_id, s.title
    ORDER BY simulation_name
),
-- Get all unique scenario options from filtered attempts (before history-specific filters)
scenario_options_cte AS (
    SELECT 
        sc.scenario_id,
        s.name AS scenario_title,
        COUNT(DISTINCT ha.attempt_id) AS count
    FROM history_attempts ha
    JOIN attempt_chats ac ON ac.attempt_id = ha.attempt_id
    JOIN chats sc ON sc.id = ac.chat_id
    JOIN scenarios s ON s.id = sc.scenario_id
    WHERE sc.scenario_id IS NOT NULL
    GROUP BY sc.scenario_id, s.name
    ORDER BY scenario_title
),
-- Apply additional filters (profileIds, simulationIds, scenarioIds, infiniteMode)
history_attempts_with_filters AS (
    SELECT ha.*
    FROM history_attempts ha
    WHERE 
        -- Profile filter
        (cardinality((SELECT profile_ids FROM params)::uuid[]) = 0 OR ha.profile_id = ANY((SELECT profile_ids FROM params)::uuid[]))
        -- Simulation filter
        AND (cardinality((SELECT simulation_ids FROM params)::uuid[]) = 0 OR ha.simulation_id = ANY((SELECT simulation_ids FROM params)::uuid[]))
        -- Infinite mode filter
        AND ((SELECT infinite_mode FROM params) IS NULL OR ha.infinite_mode = (SELECT infinite_mode FROM params))
),
-- Get scenario IDs for each attempt (for scenario filtering)
attempt_scenario_ids AS (
    SELECT DISTINCT
        ac.attempt_id,
        ARRAY_AGG(DISTINCT sc.scenario_id) FILTER (WHERE sc.scenario_id IS NOT NULL) AS scenario_ids
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_with_filters)
    GROUP BY ac.attempt_id
),
-- Apply scenario filter
history_attempts_final AS (
    SELECT haf.*
    FROM history_attempts_with_filters haf
    LEFT JOIN attempt_scenario_ids asi ON asi.attempt_id = haf.attempt_id
    WHERE 
        -- Scenario filter (if any scenario matches, include the attempt)
        (cardinality((SELECT scenario_ids FROM params)::uuid[]) = 0 OR asi.scenario_ids IS NULL OR asi.scenario_ids && (SELECT scenario_ids FROM params)::uuid[])
),
-- Aggregate chats per attempt
history_chat_rollup AS (
    SELECT
        ac.attempt_id,
        COUNT(*) FILTER (WHERE sc.completed) AS completed_chats,
        COUNT(*) FILTER (WHERE sc.completed = FALSE) AS incomplete_chats,
        MIN(sc.created_at) AS first_chat_at,
        MAX(sc.created_at) AS last_activity_at,
        array_agg(DISTINCT sc.scenario_id) FILTER (WHERE sc.scenario_id IS NOT NULL) AS scenario_ids_seen
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
    GROUP BY ac.attempt_id
),
-- Get latest grade per chat
history_chat_grades AS (
    SELECT DISTINCT ON (c.id)
        c.id AS chat_id,
        scg.score,
        rga.rubric_id
    FROM grades scg
    LEFT JOIN rubric_grade_agents rga ON rga.id = scg.rubric_grade_agent_id
    JOIN runs r ON r.id = scg.run_id
    JOIN group_runs gr ON gr.run_id = r.id
    JOIN grade_groups gg ON gg.group_id = gr.group_id
    JOIN chats c ON c.id = gg.chat_id
    WHERE EXISTS (
        SELECT 1 FROM runs r_check
        JOIN group_runs gr_check ON gr_check.run_id = r_check.id
        JOIN grade_groups gg_check ON gg_check.group_id = gr_check.group_id
        JOIN chats c_check ON c_check.id = gg_check.chat_id
        WHERE r_check.id = scg.run_id
    )
      AND c.id IN (
        SELECT sc.id FROM attempt_chats ac
        JOIN chats sc ON sc.id = ac.chat_id
        WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
      )
    ORDER BY c.id, scg.created_at DESC
),
-- Get first scenario's rubric per simulation (fallback when chat scenario doesn't match)
sim_first_scenario_rubric AS (
    SELECT DISTINCT ON (ss.simulation_id)
        ss.simulation_id,
        rga.rubric_id,
        r.points
    FROM simulation_scenarios ss
    LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
    LEFT JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
    LEFT JOIN rubrics r ON r.id = rga.rubric_id
    WHERE ss.active = true
      AND ss.simulation_id IN (SELECT DISTINCT simulation_id FROM history_attempts_final)
    ORDER BY ss.simulation_id, ss.position
),
-- Aggregate grades per attempt
history_grade_rollup AS (
    SELECT
        ac.attempt_id,
        COUNT(*) FILTER (WHERE hcg.score IS NOT NULL) AS completed_with_grade,
        SUM(CASE WHEN hcg.score IS NOT NULL AND COALESCE(r.points, r_fallback_scenario.points, r_fallback_first.points, 0) > 0
            THEN (hcg.score / COALESCE(r.points, r_fallback_scenario.points, r_fallback_first.points, 1)::numeric * 100.0)
            ELSE 0 END) AS sum_grade_percent
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    JOIN simulation_attempts sa ON sa.id = ac.attempt_id
    LEFT JOIN history_chat_grades hcg ON hcg.chat_id = sc.id
    LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga_fallback_scenario ON ssrga_fallback_scenario.simulation_id = sa.simulation_id
      AND ssrga_fallback_scenario.scenario_id = sc.scenario_id
      AND hcg.chat_id IS NOT NULL
      AND hcg.rubric_id IS NULL
    LEFT JOIN rubric_grade_agents rga_fallback_scenario ON rga_fallback_scenario.id = ssrga_fallback_scenario.rubric_grade_agent_id
    LEFT JOIN rubrics r ON r.id = hcg.rubric_id
    LEFT JOIN rubrics r_fallback_scenario ON r_fallback_scenario.id = rga_fallback_scenario.rubric_id
    LEFT JOIN sim_first_scenario_rubric sfsr ON sfsr.simulation_id = sa.simulation_id
      AND hcg.chat_id IS NOT NULL
      AND hcg.rubric_id IS NULL
      AND r_fallback_scenario.points IS NULL
    LEFT JOIN rubrics r_fallback_first ON r_fallback_first.id = sfsr.rubric_id
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
    GROUP BY ac.attempt_id
),
-- Calculate elapsed time per attempt (for infinite mode time limit checks)
history_elapsed_time AS (
    SELECT
        ac.attempt_id,
        COALESCE(
            SUM(
                CASE 
                    WHEN sc.completed AND hcg.chat_id IS NOT NULL THEN
                        (SELECT scg.time_taken FROM grades scg 
                         JOIN runs r ON r.id = scg.run_id
                         JOIN group_runs gr ON gr.run_id = r.id
                         JOIN grade_groups gg ON gg.group_id = gr.group_id
                         JOIN chats c ON c.id = gg.chat_id
                         WHERE c.id = sc.id 
                           AND EXISTS (
                               SELECT 1 FROM runs r_check
                               JOIN group_runs gr_check ON gr_check.run_id = r_check.id
                               JOIN grade_groups gg_check ON gg_check.group_id = gr_check.group_id
                               JOIN chats c_check ON c_check.id = gg_check.chat_id
                               WHERE r_check.id = scg.run_id
                           )
                         ORDER BY scg.created_at DESC LIMIT 1)
                    WHEN sc.completed THEN
                        EXTRACT(EPOCH FROM (
                            (SELECT scg.created_at FROM grades scg 
                             JOIN runs r ON r.id = scg.run_id
                             JOIN group_runs gr ON gr.run_id = r.id
                             JOIN grade_groups gg ON gg.group_id = gr.group_id
                             JOIN chats c ON c.id = gg.chat_id
                             WHERE c.id = sc.id 
                               AND EXISTS (
                                   SELECT 1 FROM runs r_check
                                   JOIN group_runs gr_check ON gr_check.run_id = r_check.id
                                   JOIN grade_groups gg_check ON gg_check.group_id = gr_check.group_id
                                   JOIN chats c_check ON c_check.id = gg_check.chat_id
                                   WHERE r_check.id = scg.run_id
                               )
                             ORDER BY scg.created_at DESC LIMIT 1) - sc.created_at
                        ))::integer
                    ELSE
                        EXTRACT(EPOCH FROM (NOW() - sc.created_at))::integer
                END
            ),
            0
        ) AS elapsed_seconds
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    LEFT JOIN history_chat_grades hcg ON hcg.chat_id = sc.id
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
    GROUP BY ac.attempt_id
),
-- Get personas for each attempt
history_personas AS (
    SELECT
        ac.attempt_id,
        array_agg(DISTINCT sp.persona_id) FILTER (WHERE sp.persona_id IS NOT NULL) AS persona_ids
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    JOIN scenarios scn ON scn.id = sc.scenario_id
    LEFT JOIN scenario_personas sp ON sp.scenario_id = scn.id AND sp.active = TRUE
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
    GROUP BY ac.attempt_id
),
-- Count scenarios per simulation
history_sim_scenario_count AS (
    SELECT
        s.id AS simulation_id,
        COUNT(ss.scenario_id)::int AS scenario_count
    FROM simulations s
    LEFT JOIN simulation_scenarios ss ON ss.simulation_id = s.id
    WHERE s.id IN (SELECT simulation_id FROM history_attempts_final)
    GROUP BY s.id
),
-- Get scenario info
history_scenario_ids AS (
    SELECT
        s.id AS simulation_id,
        ARRAY_AGG(ss.scenario_id ORDER BY ss.position)::uuid[] AS scenario_ids_assigned
    FROM simulations s
    LEFT JOIN simulation_scenarios ss ON ss.simulation_id = s.id
    WHERE s.id IN (SELECT simulation_id FROM history_attempts_final)
    GROUP BY s.id
),
-- Get first scenario_id from each attempt's first chat (for practice scenario retry)
history_first_scenario AS (
    SELECT DISTINCT ON (ac.attempt_id)
        ac.attempt_id,
        sc.scenario_id::text AS practice_scenario_id
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
    ORDER BY ac.attempt_id, sc.created_at ASC
),
-- Join all history data
attempt_rollup AS (
    SELECT
        haf.attempt_id,
        haf.simulation_id,
        haf.attempt_date,
        haf.is_archived,
        haf.infinite_mode,
        haf.profile_id,
        haf.simulation_name,
        haf.practice_simulation,
        haf.department_ids,
        COALESCE(hcr.first_chat_at, haf.attempt_date) AS first_chat_at,
        COALESCE(hcr.last_activity_at, haf.attempt_date) AS last_activity_at,
        COALESCE(hgr.completed_with_grade, 0) AS completed_with_grade,
        COALESCE(hssc.scenario_count, 0) AS sim_scenario_count,
        COALESCE(hgr.sum_grade_percent, 0) AS sum_grade_percent_zero_fill,
        COALESCE(hp.persona_ids, ARRAY[]::uuid[]) AS persona_ids_distinct,
        COALESCE(hcr.scenario_ids_seen, ARRAY[]::uuid[]) AS leaf_scenarios_seen,
        COALESCE(hcr.incomplete_chats, 0) AS incomplete_chats,
        COALESCE(het.elapsed_seconds, 0) AS elapsed_seconds,
        hfs.practice_scenario_id
    FROM history_attempts_final haf
    LEFT JOIN history_chat_rollup hcr ON hcr.attempt_id = haf.attempt_id
    LEFT JOIN history_grade_rollup hgr ON hgr.attempt_id = haf.attempt_id
    LEFT JOIN history_personas hp ON hp.attempt_id = haf.attempt_id
    LEFT JOIN history_sim_scenario_count hssc ON hssc.simulation_id = haf.simulation_id
    LEFT JOIN history_elapsed_time het ON het.attempt_id = haf.attempt_id
    LEFT JOIN history_first_scenario hfs ON hfs.attempt_id = haf.attempt_id
),
-- Get rubric data per simulation (one row per simulation)
simulation_rubrics AS (
    SELECT DISTINCT ON (ss.simulation_id)
        ss.simulation_id,
        r.id AS rubric_id,
        r.points AS rubric_points,
        r.pass_points AS rubric_pass_points
    FROM simulation_scenarios ss
    LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
    LEFT JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
    LEFT JOIN rubrics r ON r.id = rga.rubric_id
    WHERE ss.active = true
      AND ss.simulation_id IN (SELECT DISTINCT simulation_id FROM attempt_rollup)
    ORDER BY ss.simulation_id, ss.position
),
attempt_joined AS (
    SELECT
        ar.*,
        hsi.scenario_ids_assigned,
        sr.rubric_id,
        sr.rubric_points,
        sr.rubric_pass_points,
        CASE
            WHEN sr.rubric_points IS NULL OR sr.rubric_points = 0 THEN NULL
            ELSE ROUND((sr.rubric_pass_points::numeric / sr.rubric_points::numeric) * 100.0)::int
        END AS pass_pct,
        (p.first_name || ' ' || p.last_name) AS profile_name,
        COALESCE(
            (SELECT SUM(stl.time_limit_seconds)
             FROM scenario_time_limits stl
             JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
             WHERE stl.simulation_id = s.id AND stl.active = true AND ss.active = true),
            0
        ) as time_limit_seconds
    FROM attempt_rollup ar
    JOIN simulations s ON s.id = ar.simulation_id
    LEFT JOIN history_scenario_ids hsi ON hsi.simulation_id = ar.simulation_id
    LEFT JOIN simulation_rubrics sr ON sr.simulation_id = s.id
    JOIN profiles p ON p.id = ar.profile_id
),
attempt_cohort_names AS (
    SELECT
        attempt_id,
        cohort_names
    FROM history_attempt_cohorts
    WHERE attempt_id IN (SELECT attempt_id FROM history_attempts_final)
),
final_rows AS (
    SELECT
        aj.attempt_id,
        aj.simulation_id,
        aj.profile_id,
        aj.profile_name,
        aj.simulation_name,
        aj.scenario_ids_assigned,
        aj.is_archived,
        aj.practice_simulation,
        aj.pass_pct,
        aj.infinite_mode,
        aj.attempt_date,
        aj.department_ids,
        aj.practice_scenario_id,
        CASE WHEN aj.infinite_mode THEN NULL ELSE COALESCE(aj.sim_scenario_count, 0) END AS num_scenarios,
        COALESCE(aj.completed_with_grade, 0) AS num_scenarios_completed,
        CASE
            WHEN aj.infinite_mode THEN
                CASE GREATEST(array_length(aj.leaf_scenarios_seen, 1), 0)
                    WHEN 0 THEN NULL
                    ELSE ROUND(aj.sum_grade_percent_zero_fill / GREATEST(array_length(aj.leaf_scenarios_seen, 1), 1))::int
                END
            ELSE
                CASE COALESCE(aj.sim_scenario_count, 0)
                    WHEN 0 THEN NULL
                    ELSE CASE
                            WHEN aj.completed_with_grade = 0 THEN NULL
                            ELSE ROUND(aj.sum_grade_percent_zero_fill / NULLIF(aj.sim_scenario_count, 0))::int
                        END
                END
        END AS score_percent,
        CASE
            WHEN aj.infinite_mode THEN
                CASE GREATEST(array_length(aj.leaf_scenarios_seen, 1), 0)
                    WHEN 0 THEN NULL
                    ELSE CASE
                        WHEN ROUND(aj.sum_grade_percent_zero_fill / GREATEST(array_length(aj.leaf_scenarios_seen, 1), 1))::int >= 80 THEN 'high'
                        WHEN ROUND(aj.sum_grade_percent_zero_fill / GREATEST(array_length(aj.leaf_scenarios_seen, 1), 1))::int >= 70 THEN 'medium'
                        ELSE 'low'
                    END
                END
            ELSE
                CASE COALESCE(aj.sim_scenario_count, 0)
                    WHEN 0 THEN NULL
                    ELSE CASE
                        WHEN aj.completed_with_grade = 0 THEN NULL
                        ELSE CASE
                            WHEN ROUND(aj.sum_grade_percent_zero_fill / NULLIF(aj.sim_scenario_count, 0))::int >= 80 THEN 'high'
                            WHEN ROUND(aj.sum_grade_percent_zero_fill / NULLIF(aj.sim_scenario_count, 0))::int >= 70 THEN 'medium'
                            ELSE 'low'
                        END
                    END
                END
        END AS score_status,
        (NOT aj.is_archived) AS show_view,
        (NOT aj.is_archived) AND (
            (aj.infinite_mode
                AND (
                    -- No time limit OR time limit not exceeded
                    (aj.time_limit_seconds IS NULL OR aj.elapsed_seconds < aj.time_limit_seconds)
                    -- AND there are incomplete chats (pending work)
                    AND aj.incomplete_chats > 0
                ))
            OR
            (NOT aj.infinite_mode
                AND aj.sim_scenario_count IS NOT NULL
                AND COALESCE(aj.completed_with_grade, 0) < aj.sim_scenario_count)
        ) AS show_continue,
        aj.persona_ids_distinct,
        aj.time_limit_seconds
    FROM attempt_joined aj
),
-- Apply search filter (searches profile name, simulation name, persona names)
final_rows_with_search AS (
    SELECT fr.*
    FROM final_rows fr
    WHERE 
        -- Search filter: if search term provided, search in profile name, simulation name, or persona names
        ((SELECT search FROM params) IS NULL OR (SELECT search FROM params) = '' OR
         LOWER(fr.profile_name) LIKE '%' || LOWER((SELECT search FROM params)) || '%' OR
         LOWER(fr.simulation_name) LIKE '%' || LOWER((SELECT search FROM params)) || '%' OR
         EXISTS (
             SELECT 1
             FROM unnest(fr.persona_ids_distinct) AS pid
             JOIN personas per ON per.id = pid
             WHERE LOWER(per.name) LIKE '%' || LOWER((SELECT search FROM params)) || '%'
         ))
),
persona_labels AS (
    SELECT
        fr.attempt_id,
        COALESCE(ARRAY_AGG(per.name ORDER BY per.name) FILTER (WHERE per.name IS NOT NULL), ARRAY[]::text[]) AS persona_names,
        COALESCE(ARRAY_AGG(per.color ORDER BY per.name) FILTER (WHERE per.color IS NOT NULL), ARRAY[]::text[]) AS persona_colors
    FROM final_rows_with_search fr
    LEFT JOIN LATERAL (
        SELECT DISTINCT per.name, per.color
        FROM unnest(fr.persona_ids_distinct) AS pid
        JOIN personas per ON per.id = pid
    ) per ON TRUE
    GROUP BY fr.attempt_id
),
scenario_names AS (
    SELECT
        fr.attempt_id,
        COALESCE(sn.names, ARRAY[]::text[]) AS names
    FROM final_rows_with_search fr
    LEFT JOIN LATERAL (
        SELECT ARRAY_AGG(s.name ORDER BY s.name) AS names
        FROM unnest(fr.scenario_ids_assigned) sid
        JOIN scenarios s ON s.id = sid
    ) sn ON TRUE
),
-- Get total count before pagination
total_count_cte AS (
    SELECT COUNT(*)::int AS total_count
    FROM final_rows_with_search
),
-- Paginated and sorted results
paginated_rows AS (
    SELECT
        fr.attempt_id,
        fr.attempt_date,
        fr.profile_id,
        fr.profile_name,
        fr.simulation_name,
        fr.num_scenarios,
        fr.num_scenarios_completed,
        fr.infinite_mode,
        fr.score_percent,
        fr.score_status,
        fr.simulation_id,
        fr.scenario_ids_assigned,
        fr.is_archived,
        fr.show_view,
        fr.show_continue,
        fr.practice_simulation,
        fr.pass_pct,
        fr.department_ids,
        fr.practice_scenario_id,
        fr.persona_ids_distinct,
        fr.time_limit_seconds,
        -- Computed sort columns for ordering
        CASE 
            WHEN (SELECT sort_by FROM params) = 'date' AND (SELECT sort_order FROM params) = 'desc' THEN fr.attempt_date
            WHEN (SELECT sort_by FROM params) = 'date' AND (SELECT sort_order FROM params) = 'asc' THEN fr.attempt_date
        END AS sort_date,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'simulationName' AND (SELECT sort_order FROM params) = 'desc' THEN fr.simulation_name
            WHEN (SELECT sort_by FROM params) = 'simulationName' AND (SELECT sort_order FROM params) = 'asc' THEN fr.simulation_name
        END AS sort_simulation_name,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'score' AND (SELECT sort_order FROM params) = 'desc' THEN COALESCE(fr.score_percent, -1)
            WHEN (SELECT sort_by FROM params) = 'score' AND (SELECT sort_order FROM params) = 'asc' THEN COALESCE(fr.score_percent, 999999)
        END AS sort_score
    FROM final_rows_with_search fr
    ORDER BY 
        CASE 
            WHEN (SELECT sort_by FROM params) = 'date' AND (SELECT sort_order FROM params) = 'desc' THEN fr.attempt_date
        END DESC NULLS LAST,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'date' AND (SELECT sort_order FROM params) = 'asc' THEN fr.attempt_date
        END ASC NULLS LAST,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'simulationName' AND (SELECT sort_order FROM params) = 'desc' THEN fr.simulation_name
        END DESC NULLS LAST,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'simulationName' AND (SELECT sort_order FROM params) = 'asc' THEN fr.simulation_name
        END ASC NULLS LAST,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'score' AND (SELECT sort_order FROM params) = 'desc' THEN COALESCE(fr.score_percent, -1)
        END DESC,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'score' AND (SELECT sort_order FROM params) = 'asc' THEN COALESCE(fr.score_percent, 999999)
        END ASC,
        fr.attempt_id DESC
    LIMIT (SELECT page_size FROM params)
    OFFSET (SELECT page_offset FROM params)
),
-- Convert paginated rows to composite types
attempts_array AS (
    SELECT 
        (pr.attempt_id,
         pr.attempt_date,
         pr.profile_id,
         pr.profile_name,
         pr.simulation_name,
         pr.num_scenarios,
         pr.num_scenarios_completed,
         pr.infinite_mode,
         pr.time_limit_seconds,
         COALESCE(pl.persona_names, ARRAY[]::text[]),
         COALESCE(pl.persona_colors, ARRAY[]::text[]),
         pr.score_percent,
         pr.score_status,
         pr.simulation_id,
         COALESCE(pr.scenario_ids_assigned, ARRAY[]::uuid[])::text[],
         COALESCE(sn.names, ARRAY[]::text[]),
         pr.is_archived,
         pr.show_view,
         pr.show_continue,
         COALESCE(pr.practice_simulation, false),
         pr.pass_pct,
         pr.department_ids,
         COALESCE(acn.cohort_names, ARRAY[]::text[]),
         pr.practice_scenario_id
        )::types.q_get_practice_history_v4_attempt AS attempt
    FROM paginated_rows pr
    LEFT JOIN persona_labels pl ON pl.attempt_id = pr.attempt_id
    LEFT JOIN scenario_names sn ON sn.attempt_id = pr.attempt_id
    LEFT JOIN attempt_cohort_names acn ON acn.attempt_id = pr.attempt_id
    ORDER BY 
        CASE 
            WHEN (SELECT sort_by FROM params) = 'date' AND (SELECT sort_order FROM params) = 'desc' THEN pr.sort_date
        END DESC NULLS LAST,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'date' AND (SELECT sort_order FROM params) = 'asc' THEN pr.sort_date
        END ASC NULLS LAST,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'simulationName' AND (SELECT sort_order FROM params) = 'desc' THEN pr.sort_simulation_name
        END DESC NULLS LAST,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'simulationName' AND (SELECT sort_order FROM params) = 'asc' THEN pr.sort_simulation_name
        END ASC NULLS LAST,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'score' AND (SELECT sort_order FROM params) = 'desc' THEN pr.sort_score
        END DESC,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'score' AND (SELECT sort_order FROM params) = 'asc' THEN pr.sort_score
        END ASC,
        pr.attempt_id DESC
),
-- Aggregate attempts
attempts_agg AS (
    SELECT COALESCE(ARRAY_AGG(attempt), '{}'::types.q_get_practice_history_v4_attempt[]) as data
    FROM attempts_array
),
-- Convert options to composite types
profile_options_array AS (
    SELECT 
        (poc.profile_id::text, poc.profile_name, poc.count)::types.q_get_practice_history_v4_profile_option AS profile_option
    FROM profile_options_cte poc
),
simulation_options_array AS (
    SELECT 
        (soc.simulation_id::text, soc.simulation_name, soc.count)::types.q_get_practice_history_v4_simulation_option AS simulation_option
    FROM simulation_options_cte soc
),
scenario_options_array AS (
    SELECT 
        (scoc.scenario_id::text, scoc.scenario_title, scoc.count)::types.q_get_practice_history_v4_scenario_option AS scenario_option
    FROM scenario_options_cte scoc
),
-- Aggregate options
profile_options_agg AS (
    SELECT COALESCE(ARRAY_AGG(profile_option), '{}'::types.q_get_practice_history_v4_profile_option[]) as profile_options
    FROM profile_options_array
),
simulation_options_agg AS (
    SELECT COALESCE(ARRAY_AGG(simulation_option), '{}'::types.q_get_practice_history_v4_simulation_option[]) as simulation_options
    FROM simulation_options_array
),
scenario_options_agg AS (
    SELECT COALESCE(ARRAY_AGG(scenario_option), '{}'::types.q_get_practice_history_v4_scenario_option[]) as scenario_options
    FROM scenario_options_array
),
-- Calculate pagination
pagination_calc AS (
    SELECT 
        (SELECT total_count FROM total_count_cte) AS total_count,
        (SELECT page_size FROM params) AS page_size,
        (SELECT page_offset FROM params) AS page_offset
)
SELECT 
    COALESCE((SELECT data FROM attempts_agg), '{}'::types.q_get_practice_history_v4_attempt[]) as data,
    COALESCE((SELECT total_count FROM pagination_calc), 0)::int as total_count,
    CASE 
        WHEN (SELECT page_size FROM params) > 0 
        THEN (SELECT page_offset FROM params) / (SELECT page_size FROM params)
        ELSE 0
    END::int as page,
    (SELECT page_size FROM params)::int as page_size,
    CASE 
        WHEN (SELECT total_count FROM pagination_calc) > 0 AND (SELECT page_size FROM params) > 0
        THEN ((SELECT total_count FROM pagination_calc) + (SELECT page_size FROM params) - 1) / (SELECT page_size FROM params)
        ELSE 0
    END::int as total_pages,
    COALESCE((SELECT profile_options FROM profile_options_agg), '{}'::types.q_get_practice_history_v4_profile_option[]) as profile_options,
    COALESCE((SELECT simulation_options FROM simulation_options_agg), '{}'::types.q_get_practice_history_v4_simulation_option[]) as simulation_options,
    COALESCE((SELECT scenario_options FROM scenario_options_agg), '{}'::types.q_get_practice_history_v4_scenario_option[]) as scenario_options
$$;


--
-- Name: api_get_practice_overview_v4(uuid, uuid[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_practice_overview_v4(profile_id uuid, department_ids uuid[] DEFAULT ARRAY[]::uuid[], draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(actor_name text, mode text, has_data boolean, items types.q_get_practice_overview_v4_practice_simulation[], standard_groups types.q_get_practice_overview_v4_standard_group[], standards types.q_get_practice_overview_v4_standard[], simulations types.q_get_practice_overview_v4_simulation[], personas types.q_get_practice_overview_v4_persona[], scenarios types.q_get_practice_overview_v4_scenario[], parameters types.q_get_practice_overview_v4_parameter[], fields types.q_get_practice_overview_v4_field[], departments types.q_get_practice_overview_v4_department[], valid_department_ids text[], draft_version integer, draft_persona_ids jsonb, draft_parameter_item_ids jsonb, draft_department_ids jsonb)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        profile_id AS profile_id,
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids,
        draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'practice'::draft_resource_type
    LIMIT 1
),
resolve_profile_id AS (
    -- Resolve profile ID from parameter
    SELECT 
        CASE 
            WHEN (SELECT profile_id FROM params)::text IS NULL OR (SELECT profile_id FROM params)::text = '' THEN NULL::uuid
            ELSE (SELECT profile_id FROM params)::uuid
        END as resolved_profile_id
),
-- 1) Simulation meta (practice only)
sim_meta AS (
    SELECT
        s.id AS simulation_id,
        s.title AS simulation_title,
        s.description AS simulation_description,
        COALESCE(
            (SELECT SUM(stl.time_limit_seconds)
             FROM scenario_time_limits stl
             JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
             WHERE stl.simulation_id = s.id AND stl.active = true AND ss.active = true),
            0
        ) AS time_limit,
        (SELECT rga.rubric_id FROM simulation_scenarios ss 
         JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
         JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
         WHERE ss.simulation_id = s.id AND ss.active = true 
         ORDER BY ss.position 
         LIMIT 1) as rubric_id,
        COALESCE((SELECT COUNT(*)::int FROM simulation_scenarios ss WHERE ss.simulation_id = s.id), 0) AS num_scenarios,
        r.points AS rubric_points,
        r.pass_points AS rubric_pass_points,
        s.updated_at
    FROM simulations s
    LEFT JOIN simulation_scenarios ss_rubric ON ss_rubric.simulation_id = s.id AND ss_rubric.active = true
    LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga_rubric ON ssrga_rubric.simulation_id = ss_rubric.simulation_id AND ssrga_rubric.scenario_id = ss_rubric.scenario_id
    LEFT JOIN rubric_grade_agents rga_rubric ON rga_rubric.id = ssrga_rubric.rubric_grade_agent_id
    LEFT JOIN rubrics r ON r.id = rga_rubric.rubric_id
    LEFT JOIN simulation_departments sd ON sd.simulation_id = s.id AND sd.active = true
    WHERE s.active = TRUE
      AND s.practice_simulation = TRUE
    GROUP BY s.id, s.title, s.description, r.points, r.pass_points, s.updated_at, rga_rubric.rubric_id
    HAVING 
        (cardinality((SELECT department_ids FROM params)::uuid[]) = 0 OR COUNT(sd.simulation_id) FILTER (WHERE sd.department_id = ANY((SELECT department_ids FROM params)::uuid[])) > 0)
        OR (cardinality((SELECT department_ids FROM params)) = 0 OR NOT EXISTS (SELECT 1 FROM simulation_departments sd2 WHERE sd2.simulation_id = s.id AND sd2.active = true))
),
-- 2) Persona color/icon
sim_persona_meta AS (
    SELECT
        sm.simulation_id,
        (ARRAY_AGG(p.color ORDER BY cnt DESC, COALESCE(p.color, '') DESC))[1] AS color,
        (ARRAY_AGG(p.icon ORDER BY cnt DESC, COALESCE(p.icon, '') DESC))[1] AS icon
    FROM (
        SELECT
            s.id AS simulation_id,
            sp.persona_id,
            COUNT(*) AS cnt
        FROM simulations s
        LEFT JOIN simulation_scenarios ss_link ON ss_link.simulation_id = s.id
        LEFT JOIN scenarios sc ON sc.id = ss_link.scenario_id
        LEFT JOIN scenario_personas sp ON sp.scenario_id = sc.id AND sp.active = TRUE
        LEFT JOIN simulation_departments sd ON sd.simulation_id = s.id AND sd.active = true
        WHERE s.practice_simulation = TRUE
        GROUP BY s.id, sp.persona_id
        HAVING 
            (cardinality((SELECT department_ids FROM params)::uuid[]) = 0 OR COUNT(sd.simulation_id) FILTER (WHERE sd.department_id = ANY((SELECT department_ids FROM params)::uuid[])) > 0)
            OR (cardinality((SELECT department_ids FROM params)) = 0 OR NOT EXISTS (SELECT 1 FROM simulation_departments sd2 WHERE sd2.simulation_id = s.id AND sd2.active = true))
    ) sm
    LEFT JOIN personas p ON p.id = sm.persona_id
    GROUP BY sm.simulation_id
),
-- 3) All-time analytics slice (lifetime data for this user)
filt_all AS (
    SELECT a.*
    FROM analytics a, resolve_profile_id rpi
    WHERE a.profile_id = rpi.resolved_profile_id
      AND a.is_practice = TRUE
),
-- 4) Per-attempt progression (completed-only average - lifetime)
attempt_progress AS (
    SELECT
        attempt_id,
        profile_id,
        simulation_id,
        COUNT(DISTINCT scenario_id) FILTER (WHERE completed) AS completed_root_scenarios,
        AVG(grade_percent) FILTER (WHERE completed) AS avg_score_completed,
        BOOL_OR(passed) AS any_passed_attempt,
        MAX(chat_created_at) AS last_time
    FROM filt_all
    GROUP BY attempt_id, profile_id, simulation_id
),
-- 5) Latest attempt per (profile, simulation) for completionPct
latest_attempt_per_profile_sim AS (
    SELECT DISTINCT ON (profile_id, simulation_id)
           profile_id, simulation_id, attempt_id,
           completed_root_scenarios, any_passed_attempt, last_time
    FROM attempt_progress
    ORDER BY profile_id, simulation_id, last_time DESC
),
-- 6) Activity by (profile, simulation) - lifetime
activity_by_profile_sim AS (
    SELECT
        profile_id,
        simulation_id,
        COUNT(DISTINCT chat_id) AS chats,
        BOOL_OR(passed) AS any_passed
    FROM filt_all
    GROUP BY profile_id, simulation_id
),
-- 7) Pass threshold
sim_pass_pct AS (
    SELECT DISTINCT ON (s.id)
           s.id AS simulation_id,
           CASE WHEN r.points > 0
                THEN (r.pass_points::numeric / r.points::numeric) * 100.0
                ELSE 70 END AS pass_pct
    FROM simulations s
    LEFT JOIN simulation_scenarios ss_rubric ON ss_rubric.simulation_id = s.id AND ss_rubric.active = true
    LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga_rubric ON ssrga_rubric.simulation_id = ss_rubric.simulation_id AND ssrga_rubric.scenario_id = ss_rubric.scenario_id
    LEFT JOIN rubric_grade_agents rga_rubric ON rga_rubric.id = ssrga_rubric.rubric_grade_agent_id
    LEFT JOIN rubrics r ON r.id = rga_rubric.rubric_id
    LEFT JOIN simulation_departments sd ON sd.simulation_id = s.id AND sd.active = true
    WHERE s.practice_simulation = TRUE
      AND s.active = TRUE
      AND (
          (cardinality((SELECT department_ids FROM params)::uuid[]) = 0 OR sd.department_id = ANY((SELECT department_ids FROM params)::uuid[]))
          OR (cardinality((SELECT department_ids FROM params)) = 0 OR NOT EXISTS (SELECT 1 FROM simulation_departments sd2 WHERE sd2.simulation_id = s.id AND sd2.active = true))
      )
    ORDER BY s.id, s.title, s.description
),
-- 8) Standard groups/standards for rubrics
all_rubric_ids AS (
    SELECT DISTINCT rubric_id FROM sim_meta WHERE rubric_id IS NOT NULL
),
-- Standard groups as array
standard_groups_array AS (
    SELECT 
        (sg.id, sg.name, sg.description, sg.points, sg.pass_points)::types.q_get_practice_overview_v4_standard_group AS standard_group
    FROM rubric_standard_groups rsg
    JOIN standard_groups sg ON sg.id = rsg.standard_group_id
    WHERE rsg.rubric_id IN (SELECT rubric_id FROM all_rubric_ids) AND rsg.active = true
),
-- Standards as array
standards_array AS (
    SELECT 
        (st.id, st.name, st.description, st.points)::types.q_get_practice_overview_v4_standard AS standard
    FROM standards st
    WHERE st.standard_group_id IN (
        SELECT rsg.standard_group_id FROM rubric_standard_groups rsg
        WHERE rsg.rubric_id IN (SELECT rubric_id FROM all_rubric_ids) AND rsg.active = true
    )
),
-- 9) Final items with standard_groups mapping
items_with_standard_groups AS (
    SELECT
        sm.simulation_id,
        sm.simulation_title,
        sm.simulation_description,
        sm.num_scenarios,
        sm.rubric_id,
        sm.rubric_points,
        sm.rubric_pass_points,
        sm.updated_at,
        spm.color,
        spm.icon,
        COALESCE(aps.chats, 0) AS chats,
        COALESCE((
            SELECT ROUND(MAX(ap.avg_score_completed))::int
            FROM attempt_progress ap, resolve_profile_id rpi
            WHERE ap.profile_id = rpi.resolved_profile_id
              AND ap.simulation_id = sm.simulation_id
        ), NULL) AS highest_score,
        COALESCE((
            SELECT MAX(ap.avg_score_completed) >= (
                SELECT pass_pct FROM sim_pass_pct WHERE simulation_id = sm.simulation_id LIMIT 1
            )
            FROM attempt_progress ap, resolve_profile_id rpi
            WHERE ap.profile_id = rpi.resolved_profile_id
              AND ap.simulation_id = sm.simulation_id
        ), false) AS has_passed,
        CASE
            WHEN COALESCE((
                SELECT MAX(ap.avg_score_completed) >= (
                    SELECT pass_pct FROM sim_pass_pct WHERE simulation_id = sm.simulation_id LIMIT 1
                )
                FROM attempt_progress ap, resolve_profile_id rpi
                WHERE ap.profile_id = rpi.resolved_profile_id
                  AND ap.simulation_id = sm.simulation_id
              ), false) THEN 'passed'
            WHEN COALESCE(aps.chats, 0) > 0 THEN 'in-progress'
            ELSE 'not-started'
        END AS status,
        COALESCE((
            SELECT ROUND(100.0 * lap.completed_root_scenarios::numeric / GREATEST(sm.num_scenarios, 1))::int
            FROM latest_attempt_per_profile_sim lap, resolve_profile_id rpi
            WHERE lap.profile_id = rpi.resolved_profile_id
              AND lap.simulation_id = sm.simulation_id
            LIMIT 1
        ), 0) AS completion_pct,
        (
            SELECT MAX(ap.last_time)
            FROM attempt_progress ap, resolve_profile_id rpi
            WHERE ap.profile_id = rpi.resolved_profile_id
              AND ap.simulation_id = sm.simulation_id
        ) AS last_activity_ts,
        -- Get standard_group_ids directly as text array (no JSONB)
        COALESCE((
            SELECT ARRAY_AGG(sg.id::text ORDER BY sg.id)
            FROM rubric_standard_groups rsg
            JOIN standard_groups sg ON sg.id = rsg.standard_group_id
            WHERE rsg.rubric_id = sm.rubric_id AND rsg.active = true
        ), ARRAY[]::text[]) AS standard_groups_ids
    FROM sim_meta sm
    LEFT JOIN sim_persona_meta spm ON spm.simulation_id = sm.simulation_id
    LEFT JOIN activity_by_profile_sim aps
           ON aps.profile_id = (SELECT resolved_profile_id FROM resolve_profile_id)
          AND aps.simulation_id = sm.simulation_id
),
-- Build items with standard_groups array
items_rows AS (
    SELECT
        ('practice'::text,
         iwsg.simulation_id,
         iwsg.simulation_title,
         iwsg.simulation_description,
         iwsg.simulation_title,
         NULL::int,  -- time_limit (not used in practice overview items)
         iwsg.num_scenarios,
         iwsg.highest_score,
         iwsg.rubric_id,
         iwsg.color,
         iwsg.icon,
         iwsg.has_passed,
         CASE
             WHEN iwsg.rubric_points > 0
                 THEN ROUND(100.0 * iwsg.rubric_pass_points::numeric / iwsg.rubric_points)::int
             ELSE NULL
         END::int,
         iwsg.status,
         iwsg.completion_pct,
         NULL::int,  -- passed_count
         NULL::int,  -- in_progress_count
         NULL::int,  -- not_started_count
         NULL::int,  -- pass_pct
         NULL::text,  -- cohort_name
         iwsg.updated_at,
         iwsg.last_activity_ts,
         (iwsg.chats > 0)::boolean,
         -- Use standard_groups_ids array directly (no JSONB conversion)
         COALESCE(iwsg.standard_groups_ids, ARRAY[]::text[])
        )::types.q_get_practice_overview_v4_practice_simulation AS item,
        iwsg.simulation_title AS sort_title,
        iwsg.last_activity_ts AS sort_last_activity
    FROM items_with_standard_groups iwsg
),
-- Simulation data (for simulations array)
simulation_data AS (
    SELECT
        sim.id,
        sim.title,
        sim.description,
        COALESCE(
            (SELECT SUM(stl.time_limit_seconds)
             FROM scenario_time_limits stl
             JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
             WHERE stl.simulation_id = sim.id AND stl.active = true AND ss.active = true),
            0
        ) as time_limit,
        sdd.department_ids
    FROM simulations sim
    LEFT JOIN (
        SELECT 
            sd.simulation_id,
            ARRAY_AGG(sd.department_id::text ORDER BY sd.created_at) as department_ids
        FROM simulation_departments sd
        WHERE sd.active = true
        GROUP BY sd.simulation_id
    ) sdd ON sdd.simulation_id = sim.id
    WHERE sim.active = true
      AND sim.practice_simulation = true
    GROUP BY sim.id, sim.title, sim.description, sdd.department_ids
    HAVING 
        (cardinality((SELECT department_ids FROM params)) = 0 OR sdd.department_ids IS NULL OR sdd.department_ids && (SELECT department_ids FROM params)::text[])
        OR (cardinality((SELECT department_ids FROM params)) = 0 OR NOT EXISTS (SELECT 1 FROM simulation_departments sd2 WHERE sd2.simulation_id = sim.id AND sd2.active = true))
),
-- Simulations as array
simulations_array AS (
    SELECT 
        (sim.id, sim.title, COALESCE(sim.description, ''), sim.time_limit, COALESCE(sim.department_ids, ARRAY[]::text[]))::types.q_get_practice_overview_v4_simulation AS simulation
    FROM simulation_data sim
),
-- Persona data
persona_data AS (
    SELECT
        p.id,
        p.name,
        COALESCE(p.description, '') as description,
        p.color,
        p.icon
    FROM personas p
    LEFT JOIN persona_departments pd ON pd.persona_id = p.id AND pd.active = true
    WHERE p.active = true
    GROUP BY p.id, p.name, p.description, p.color, p.icon
    HAVING 
        (cardinality((SELECT department_ids FROM params)::uuid[]) = 0 OR COUNT(pd.persona_id) FILTER (WHERE pd.department_id = ANY((SELECT department_ids FROM params)::uuid[])) > 0)
        OR (cardinality((SELECT department_ids FROM params)) = 0 OR NOT EXISTS (SELECT 1 FROM persona_departments pd2 WHERE pd2.persona_id = p.id AND pd2.active = true))
),
-- Personas as array
personas_array AS (
    SELECT 
        (p.id, p.name, p.description, COALESCE(p.color, ''), COALESCE(p.icon, ''))::types.q_get_practice_overview_v4_persona AS persona
    FROM persona_data p
),
-- Practice scenario IDs
practice_scenario_ids AS (
    SELECT DISTINCT ss.scenario_id
    FROM simulation_scenarios ss
    JOIN simulations sim ON sim.id = ss.simulation_id
    WHERE sim.active = true
      AND sim.practice_simulation = true
),
-- Scenario persona IDs
scenario_persona_ids AS (
    SELECT 
        sp.scenario_id,
        ARRAY_AGG(sp.persona_id::text ORDER BY sp.persona_id) as persona_ids
    FROM scenario_personas sp
    WHERE sp.active = true
    GROUP BY sp.scenario_id
),
-- Scenario data
scenario_data AS (
    SELECT
        s.id,
        s.name,
        COALESCE(
            (SELECT ps.problem_statement 
             FROM scenario_problem_statements sps
             JOIN problem_statements ps ON ps.id = sps.problem_statement_id
             WHERE sps.scenario_id = s.id AND sps.active = true
             ORDER BY sps.created_at DESC, sps.updated_at DESC
             LIMIT 1), 
            ''
        ) as description,
        COALESCE(spi.persona_ids, ARRAY[]::text[]) as persona_ids
    FROM scenarios s
    JOIN practice_scenario_ids psi ON psi.scenario_id = s.id
    LEFT JOIN scenario_departments sd ON sd.scenario_id = s.id AND sd.active = true
    LEFT JOIN scenario_persona_ids spi ON spi.scenario_id = s.id
    WHERE s.active = true
    GROUP BY s.id, s.name, spi.persona_ids
    HAVING 
        (cardinality((SELECT department_ids FROM params)::uuid[]) = 0 OR COUNT(sd.scenario_id) FILTER (WHERE sd.department_id = ANY((SELECT department_ids FROM params)::uuid[])) > 0)
        OR (cardinality((SELECT department_ids FROM params)) = 0 OR NOT EXISTS (SELECT 1 FROM scenario_departments sd2 WHERE sd2.scenario_id = s.id AND sd2.active = true))
),
-- Scenarios as array
scenarios_array AS (
    SELECT 
        (s.id, s.name, s.description, s.persona_ids)::types.q_get_practice_overview_v4_scenario AS scenario
    FROM scenario_data s
),
-- Parameter data
parameter_data AS (
    SELECT
        par.id,
        par.name,
        COALESCE(par.description, '') as description,
        par.document_parameter,
        par.persona_parameter
    FROM parameters par
    JOIN parameter_fields fp ON fp.parameter_id = par.id AND fp.active = true
    LEFT JOIN field_departments fd ON fd.field_id = fp.field_id AND fd.active = true
    WHERE par.active = true
      AND par.simulation_parameter = true
    GROUP BY par.id, par.name, par.description, par.document_parameter, par.persona_parameter
    HAVING 
        (cardinality((SELECT department_ids FROM params)::uuid[]) = 0 OR COUNT(fd.field_id) FILTER (WHERE fd.department_id = ANY((SELECT department_ids FROM params)::uuid[])) > 0)
        OR (cardinality((SELECT department_ids FROM params)) = 0 OR NOT EXISTS (SELECT 1 FROM field_departments fd2 
                  JOIN parameter_fields fp2 ON fp2.field_id = fd2.field_id 
                  WHERE fp2.parameter_id = par.id AND fp2.active = true))
),
-- Parameters as array
parameters_array AS (
    SELECT 
        (par.id, par.name, par.description, par.document_parameter, par.persona_parameter)::types.q_get_practice_overview_v4_parameter AS parameter
    FROM parameter_data par
),
-- Parameter item data (fields)
parameter_item_data AS (
    SELECT
        f.id,
        f.name,
        COALESCE(f.description, '') as description,
        fp.parameter_id,
        par.name as parameter_name
    FROM fields f
    JOIN parameter_fields fp ON fp.field_id = f.id AND fp.active = true
    JOIN parameters par ON par.id = fp.parameter_id
    LEFT JOIN field_departments fd ON fd.field_id = f.id AND fd.active = true
    WHERE par.active = true
      AND par.simulation_parameter = true
    GROUP BY f.id, f.name, f.description, fp.parameter_id, par.id, par.name
    HAVING 
        (cardinality((SELECT department_ids FROM params)::uuid[]) = 0 OR COUNT(fd.field_id) FILTER (WHERE fd.department_id = ANY((SELECT department_ids FROM params)::uuid[])) > 0)
        OR (cardinality((SELECT department_ids FROM params)) = 0 OR NOT EXISTS (SELECT 1 FROM field_departments fd2 
                  WHERE fd2.field_id = f.id AND fd2.active = true))
),
-- Fields as array
fields_array AS (
    SELECT 
        (pi.id, pi.name, pi.description, pi.parameter_id, pi.parameter_name)::types.q_get_practice_overview_v4_field AS field
    FROM parameter_item_data pi
),
-- Department data
department_data AS (
    SELECT
        d.id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM departments d
    WHERE d.active = true
),
-- Departments as array
departments_array AS (
    SELECT 
        (d.id, d.name, d.description)::types.q_get_practice_overview_v4_department AS department
    FROM department_data d
),
-- Valid department IDs
valid_department_ids_data AS (
    SELECT array_agg(d.id::text ORDER BY d.name) as valid_department_ids
    FROM department_data d
),
-- User profile for actor_name
user_profile AS (
    SELECT 
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM resolve_profile_id rpi
    JOIN profiles ON profiles.id = rpi.resolved_profile_id
),
-- Aggregate items
items_agg AS (
    SELECT COALESCE(
        ARRAY_AGG(ir.item 
            ORDER BY
                (ir.item).simulation_title ILIKE 'general%' DESC,
                ir.sort_last_activity DESC NULLS LAST,
                ir.sort_title
        ),
        '{}'::types.q_get_practice_overview_v4_practice_simulation[]
    ) as items
    FROM items_rows ir
),
-- Aggregate mappings separately
standard_groups_agg AS (
    SELECT COALESCE(ARRAY_AGG(DISTINCT standard_group), '{}'::types.q_get_practice_overview_v4_standard_group[]) as standard_groups
    FROM standard_groups_array
),
standards_agg AS (
    SELECT COALESCE(ARRAY_AGG(DISTINCT standard), '{}'::types.q_get_practice_overview_v4_standard[]) as standards
    FROM standards_array
),
simulations_agg AS (
    SELECT COALESCE(ARRAY_AGG(DISTINCT simulation), '{}'::types.q_get_practice_overview_v4_simulation[]) as simulations
    FROM simulations_array
),
personas_agg AS (
    SELECT COALESCE(ARRAY_AGG(DISTINCT persona), '{}'::types.q_get_practice_overview_v4_persona[]) as personas
    FROM personas_array
),
scenarios_agg AS (
    SELECT COALESCE(ARRAY_AGG(DISTINCT scenario), '{}'::types.q_get_practice_overview_v4_scenario[]) as scenarios
    FROM scenarios_array
),
parameters_agg AS (
    SELECT COALESCE(ARRAY_AGG(DISTINCT parameter), '{}'::types.q_get_practice_overview_v4_parameter[]) as parameters
    FROM parameters_array
),
fields_agg AS (
    SELECT COALESCE(ARRAY_AGG(DISTINCT field), '{}'::types.q_get_practice_overview_v4_field[]) as fields
    FROM fields_array
),
departments_agg AS (
    SELECT COALESCE(ARRAY_AGG(DISTINCT department), '{}'::types.q_get_practice_overview_v4_department[]) as departments
    FROM departments_array
)
SELECT 
    up.actor_name::text as actor_name,
    'practice'::text as mode,
    EXISTS(SELECT 1 FROM items_rows)::boolean as has_data,
    COALESCE((SELECT items FROM items_agg), '{}'::types.q_get_practice_overview_v4_practice_simulation[]) as items,
    COALESCE((SELECT standard_groups FROM standard_groups_agg), '{}'::types.q_get_practice_overview_v4_standard_group[]) as standard_groups,
    COALESCE((SELECT standards FROM standards_agg), '{}'::types.q_get_practice_overview_v4_standard[]) as standards,
    COALESCE((SELECT simulations FROM simulations_agg), '{}'::types.q_get_practice_overview_v4_simulation[]) as simulations,
    COALESCE((SELECT personas FROM personas_agg), '{}'::types.q_get_practice_overview_v4_persona[]) as personas,
    COALESCE((SELECT scenarios FROM scenarios_agg), '{}'::types.q_get_practice_overview_v4_scenario[]) as scenarios,
    COALESCE((SELECT parameters FROM parameters_agg), '{}'::types.q_get_practice_overview_v4_parameter[]) as parameters,
    COALESCE((SELECT fields FROM fields_agg), '{}'::types.q_get_practice_overview_v4_field[]) as fields,
    COALESCE((SELECT departments FROM departments_agg), '{}'::types.q_get_practice_overview_v4_department[]) as departments,
    COALESCE((SELECT valid_department_ids FROM valid_department_ids_data), ARRAY[]::text[]) as valid_department_ids,
    -- Draft version (from draft payload if exists)
    COALESCE((SELECT draft_version FROM draft_payload_data), 0) as draft_version,
    -- Extract personaIds from draft payload if available (support both camelCase and snake_case)
    COALESCE(
        (SELECT payload->'personaIds' FROM draft_payload_data),
        (SELECT payload->'persona_ids' FROM draft_payload_data),
        '[]'::jsonb
    ) as draft_persona_ids,
    -- Extract parameterItemIds from draft payload if available (support both camelCase and snake_case)
    COALESCE(
        (SELECT payload->'parameterItemIds' FROM draft_payload_data),
        (SELECT payload->'parameter_item_ids' FROM draft_payload_data),
        '[]'::jsonb
    ) as draft_parameter_item_ids,
    -- Extract departmentIds from draft payload if available (support both camelCase and snake_case)
    COALESCE(
        (SELECT payload->'departmentIds' FROM draft_payload_data),
        (SELECT payload->'department_ids' FROM draft_payload_data),
        '[]'::jsonb
    ) as draft_department_ids
FROM user_profile up
$$;


--
-- Name: api_get_previous_chat_info_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_previous_chat_info_v4(chat_id uuid) RETURNS TABLE(scenario_id uuid, has_grade boolean)
    LANGUAGE sql STABLE
    AS $$
SELECT sc.scenario_id, c_prev.id IS NOT NULL as has_grade
FROM chats sc
LEFT JOIN grades scg ON EXISTS (
    SELECT 1 FROM runs r_check
    JOIN group_runs gr_check ON gr_check.run_id = r_check.id
    JOIN groups g_check ON g_check.id = gr_check.group_id
    JOIN chat_groups cg_check ON cg_check.group_id = g_check.id
    JOIN chats c_check ON c_check.id = cg_check.chat_id
    WHERE r_check.id = scg.run_id AND c_check.id = sc.id
)
LEFT JOIN runs r_prev ON r_prev.id = scg.run_id
LEFT JOIN group_runs gr_prev ON gr_prev.run_id = r_prev.id
LEFT JOIN groups g_prev ON g_prev.id = gr_prev.group_id
LEFT JOIN chat_groups cg_prev ON cg_prev.group_id = g_prev.id
LEFT JOIN chats c_prev ON c_prev.id = cg_prev.chat_id AND c_prev.id = sc.id
WHERE sc.id = chat_id AND sc.completed = true
$$;


--
-- Name: api_get_pricing_analytics_v4(text, text, uuid[], uuid, text[], uuid[], text[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_pricing_analytics_v4(start_date text, end_date text, department_ids uuid[], profile_id uuid, roles text[], cohort_ids uuid[], simulation_filters text[]) RETURNS TABLE(actor_name text, model_runs types.q_get_pricing_analytics_v4_model_run[], models types.q_get_pricing_analytics_v4_model[], profiles types.q_get_pricing_analytics_v4_profile[], agents types.q_get_pricing_analytics_v4_agent[], personas types.q_get_pricing_analytics_v4_persona[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        COALESCE(NULLIF(start_date, ''), NULL)::timestamptz AS start_date,
        COALESCE(NULLIF(end_date, ''), NULL)::timestamptz AS end_date,
        department_ids AS department_ids,
        profile_id AS profile_id,
        roles AS roles,
        cohort_ids AS cohort_ids,
        simulation_filters AS simulation_filters
),
profile_role_check AS (
    -- Resolve profile_id and check role to determine effective filtering
    SELECT 
        (SELECT profile_id FROM params) as raw_profile_id,
        CASE 
            WHEN (SELECT profile_id FROM params) IS NULL THEN NULL::uuid
            WHEN (SELECT role FROM profiles WHERE id = (SELECT profile_id FROM params)) IN ('admin', 'superadmin', 'instructional') THEN NULL::uuid
            ELSE (SELECT profile_id FROM params)
        END as effective_profile_id
),
user_profile AS (
    SELECT 
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
    WHERE x.profile_id IS NOT NULL
),
runs_base AS (
    SELECT
        mr.id as run_id,
        mr.created_at,
        mr.input_tokens,
        mr.output_tokens,
        mrm.model_id,
        mrp.profile_id,
        mr.agent_id,
        mrper.persona_id,
        sim.practice_simulation,
        sa.archived
    FROM runs mr
    LEFT JOIN run_models mrm ON mrm.run_id = mr.id AND mrm.active = true
    LEFT JOIN run_profiles mrp ON mrp.run_id = mr.id AND mrp.active = true
    LEFT JOIN run_personas mrper ON mrper.run_id = mr.id AND mrper.active = true
    -- Join to simulations via group_runs → groups → chats → attempt_chats → simulation_attempts → simulations
    LEFT JOIN group_runs gr ON gr.run_id = mr.id
    LEFT JOIN groups g ON g.id = gr.group_id
    LEFT JOIN LATERAL (
        SELECT DISTINCT c.id AS chat_id
        FROM groups g2
        JOIN chat_groups cg ON cg.group_id = g2.id
        JOIN chats c ON c.id = cg.chat_id
        WHERE g2.id = g.id
        LIMIT 1
    ) chat_lookup ON true
    LEFT JOIN chats c ON c.id = chat_lookup.chat_id
    LEFT JOIN attempt_chats ac ON ac.chat_id = c.id
    LEFT JOIN simulation_attempts sa ON sa.id = ac.attempt_id
    LEFT JOIN simulations sim ON sim.id = sa.simulation_id
    CROSS JOIN params p
    WHERE 
        -- Date filters (always required)
        mr.created_at >= p.start_date
        AND mr.created_at <= p.end_date
        -- Department filter (via profile_departments join)
        AND (
            p.department_ids IS NULL
            OR COALESCE(array_length(p.department_ids, 1), 0) = 0
            OR EXISTS (
                SELECT 1 FROM run_profiles mrp2
                JOIN profile_departments pd ON pd.profile_id = mrp2.profile_id
                WHERE mrp2.run_id = mr.id
                  AND mrp2.active = true
                  AND pd.department_id = ANY(p.department_ids)
            )
        )
        -- Profile filter (specific user) - only if role is not admin/superadmin/instructional
        AND (
            (SELECT effective_profile_id FROM profile_role_check) IS NULL
            OR mrp.profile_id = (SELECT effective_profile_id FROM profile_role_check)
        )
        -- Role filter (only if no effective profile_id)
        AND (
            (SELECT effective_profile_id FROM profile_role_check) IS NOT NULL
            OR p.roles IS NULL
            OR COALESCE(array_length(p.roles, 1), 0) = 0
            OR mrp.profile_id IN (
                SELECT id FROM profiles WHERE role::text = ANY(p.roles)
            )
        )
        -- Cohort filter (via cohort_profiles)
        AND (
            p.cohort_ids IS NULL
            OR COALESCE(array_length(p.cohort_ids, 1), 0) = 0
            OR mrp.profile_id IN (
                SELECT profile_id FROM cohort_profiles
                WHERE cohort_id = ANY(p.cohort_ids) AND active = true
            )
        )
        -- Simulation type filtering: general (practice_simulation = FALSE), practice (practice_simulation = TRUE), archived (archived = TRUE)
        -- If no filters provided (NULL or empty), include all runs (runs not linked to simulations are included)
        -- If filters provided, only include runs that match the filter OR runs not linked to simulations (treat as "general")
        AND (
            p.simulation_filters IS NULL
            OR COALESCE(array_length(p.simulation_filters, 1), 0) = 0
            OR sim.id IS NULL  -- Runs not linked to simulations are always included
            OR (
                ('general' = ANY(p.simulation_filters) AND sim.practice_simulation = FALSE AND COALESCE(sa.archived, FALSE) = FALSE) OR
                ('practice' = ANY(p.simulation_filters) AND sim.practice_simulation = TRUE AND COALESCE(sa.archived, FALSE) = FALSE) OR
                ('archived' = ANY(p.simulation_filters) AND COALESCE(sa.archived, FALSE) = TRUE)
            )
        )
        -- Exclude archived attempts unless 'archived' is explicitly in the filter list
        AND (
            p.simulation_filters IS NULL
            OR COALESCE(array_length(p.simulation_filters, 1), 0) = 0
            OR 'archived' = ANY(p.simulation_filters)
            OR COALESCE(sa.archived, FALSE) = FALSE
        )
),
-- Calculate run costs using run_pricing_usage (source of truth for pricing)
run_costs AS (
    SELECT 
        rpu.run_id,
        COALESCE(SUM(
            (rpu.count::numeric / u.value::numeric) * mp.price
        ), 0) as run_cost
    FROM run_pricing_usage rpu
    JOIN run_models rm ON rm.run_id = rpu.run_id AND rm.active = true
    JOIN model_pricing mp ON mp.model_id = rm.model_id 
        AND mp.pricing_type = rpu.pricing_type 
        AND mp.unit_id = rpu.unit_id
        AND mp.active = true
    JOIN units u ON u.id = rpu.unit_id
    GROUP BY rpu.run_id
),
runs_with_debug AS (
    SELECT
        mrb.run_id,
        mrb.created_at,
        mrb.input_tokens,
        mrb.output_tokens,
        mrb.model_id,
        mrb.profile_id,
        mrb.agent_id,
        mrb.persona_id,
        COALESCE(rc.run_cost, 0) as run_cost,
        COALESCE(
            ARRAY_AGG(
                (di.id, di.created_at, di.content)::types.q_get_pricing_analytics_v4_debug_info
                ORDER BY di.created_at
            ) FILTER (WHERE di.id IS NOT NULL),
            '{}'::types.q_get_pricing_analytics_v4_debug_info[]
        ) as debug_info
    FROM runs_base mrb
    LEFT JOIN run_costs rc ON rc.run_id = mrb.run_id
    LEFT JOIN debug_info di ON di.run_id = mrb.run_id
    GROUP BY mrb.run_id, mrb.created_at, mrb.input_tokens, mrb.output_tokens, mrb.model_id, mrb.profile_id, mrb.agent_id, mrb.persona_id, rc.run_cost
),
model_pricing_aggregated AS (
    -- Aggregate pricing per model: sum all input/output prices normalized to per-million tokens
    SELECT 
        mrb.model_id,
        COALESCE(SUM(CASE WHEN mp.pricing_type = 'input'::pricing_type THEN mp.price * (1000000.0 / u.value) ELSE 0 END), 0.0) as input_ppm,
        COALESCE(SUM(CASE WHEN mp.pricing_type = 'output'::pricing_type THEN mp.price * (1000000.0 / u.value) ELSE 0 END), 0.0) as output_ppm
    FROM (SELECT DISTINCT model_id FROM runs_base WHERE model_id IS NOT NULL) mrb
    LEFT JOIN model_pricing mp ON mp.model_id = mrb.model_id AND mp.active = true AND mp.pricing_type IN ('input'::pricing_type, 'output'::pricing_type)
    LEFT JOIN units u ON u.id = mp.unit_id
    GROUP BY mrb.model_id
)
SELECT 
    COALESCE((SELECT actor_name FROM user_profile LIMIT 1), 'System')::text as actor_name,
    COALESCE(
        ARRAY_AGG(
            (mrb.run_id, mrb.created_at, mrb.input_tokens, mrb.output_tokens, mrb.model_id, mrb.profile_id, mrb.agent_id, mrb.persona_id, mrb.run_cost, mrb.debug_info)::types.q_get_pricing_analytics_v4_model_run
            ORDER BY mrb.created_at DESC
        ),
        '{}'::types.q_get_pricing_analytics_v4_model_run[]
    ) as model_runs,
    COALESCE(
        ARRAY_AGG(
            DISTINCT (m.id, m.name, COALESCE(m.description, ''), COALESCE(mpa.input_ppm, 0.0), COALESCE(mpa.output_ppm, 0.0))::types.q_get_pricing_analytics_v4_model
        ) FILTER (WHERE m.id IS NOT NULL),
        '{}'::types.q_get_pricing_analytics_v4_model[]
    ) as models,
    COALESCE(
        ARRAY_AGG(
            DISTINCT (p.id, p.first_name || ' ' || p.last_name)::types.q_get_pricing_analytics_v4_profile
        ) FILTER (WHERE p.id IS NOT NULL),
        '{}'::types.q_get_pricing_analytics_v4_profile[]
    ) as profiles,
    COALESCE(
        ARRAY_AGG(
            DISTINCT (a.id, a.name)::types.q_get_pricing_analytics_v4_agent
        ) FILTER (WHERE a.id IS NOT NULL),
        '{}'::types.q_get_pricing_analytics_v4_agent[]
    ) as agents,
    COALESCE(
        ARRAY_AGG(
            DISTINCT (per.id, per.name)::types.q_get_pricing_analytics_v4_persona
        ) FILTER (WHERE per.id IS NOT NULL),
        '{}'::types.q_get_pricing_analytics_v4_persona[]
    ) as personas
FROM runs_with_debug mrb
LEFT JOIN models m ON m.id = mrb.model_id
LEFT JOIN model_pricing_aggregated mpa ON mpa.model_id = m.id
LEFT JOIN profiles p ON p.id = mrb.profile_id
LEFT JOIN agents a ON a.id = mrb.agent_id
LEFT JOIN personas per ON per.id = mrb.persona_id
GROUP BY (SELECT actor_name FROM user_profile LIMIT 1)
$$;


--
-- Name: api_get_pricing_group_detail_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_pricing_group_detail_v4(group_id uuid, profile_id uuid) RETURNS TABLE(group_exists boolean, group_id uuid, actor_name text, runs types.q_get_pricing_group_detail_v4_run_with_messages[], models types.q_get_pricing_group_detail_v4_model[], agents types.q_get_pricing_group_detail_v4_agent[], profiles types.q_get_pricing_group_detail_v4_profile[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        group_id AS group_id,
        profile_id AS profile_id
),
group_exists_check AS (
    SELECT EXISTS(SELECT 1 FROM groups WHERE id = (SELECT group_id FROM params)) as group_exists
),
resolve_profile_id AS (
    SELECT 
        CASE 
            WHEN (SELECT profile_id FROM params) IS NULL THEN NULL::uuid
            ELSE (SELECT profile_id FROM params)
        END as resolved_profile_id
),
user_profile AS (
    SELECT 
        p.role,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    LEFT JOIN profiles p ON p.id = x.profile_id
    WHERE x.profile_id IS NOT NULL
),
group_runs_list AS (
    SELECT 
        gr.run_id
    FROM group_runs gr
    WHERE gr.group_id = (SELECT group_id FROM params)
),
runs_metadata AS (
    SELECT 
        r.id as run_id,
        r.created_at,
        r.input_tokens,
        r.output_tokens,
        r.cached_input_tokens,
        r.key_id,
        r.agent_id,
        rm.model_id,
        rp.profile_id,
        rper.persona_id
    FROM group_runs_list grl
    JOIN runs r ON r.id = grl.run_id
    LEFT JOIN run_models rm ON rm.run_id = r.id AND rm.active = true
    LEFT JOIN run_profiles rp ON rp.run_id = r.id AND rp.active = true
    LEFT JOIN run_personas rper ON rper.run_id = r.id AND rper.active = true
),
-- Get department IDs from runs (via agent or profile)
runs_departments AS (
    SELECT DISTINCT
        d.id as department_id
    FROM runs_metadata rm
    LEFT JOIN agents a ON a.id = rm.agent_id
    LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
    LEFT JOIN departments d ON d.id = ad.department_id AND d.active = true
    WHERE d.id IS NOT NULL
),
-- Check department access
group_access_check AS (
    SELECT 
        CASE 
            WHEN up.role = 'superadmin'::profile_role THEN true
            WHEN EXISTS (
                SELECT 1 FROM runs_departments rd
                JOIN profile_departments pd ON pd.department_id = rd.department_id
                WHERE pd.profile_id = (SELECT resolved_profile_id FROM resolve_profile_id)
                AND pd.active = true
            ) THEN true
            WHEN NOT EXISTS (SELECT 1 FROM runs_departments) THEN true  -- Cross-department resource
            ELSE false
        END as has_access
    FROM user_profile up
),
-- Calculate run costs
run_costs AS (
    SELECT 
        rpu.run_id,
        COALESCE(SUM(
            (rpu.count::numeric / u.value::numeric) * mp.price
        ), 0) as run_cost
    FROM run_pricing_usage rpu
    JOIN run_models rm ON rm.run_id = rpu.run_id AND rm.active = true
    JOIN model_pricing mp ON mp.model_id = rm.model_id 
        AND mp.pricing_type = rpu.pricing_type 
        AND mp.unit_id = rpu.unit_id
        AND mp.active = true
    JOIN units u ON u.id = rpu.unit_id
    JOIN group_runs_list grl ON grl.run_id = rpu.run_id
    GROUP BY rpu.run_id
),
-- Get all messages for each run using message_tree ordering (source of truth)
-- For each run, traverse message_tree to get messages in conversation flow order
run_groups_map AS (
    -- Map each run to its group
    SELECT DISTINCT
        rm.run_id,
        gr.group_id
    FROM runs_metadata rm
    JOIN group_runs gr ON gr.run_id = rm.run_id
),
run_chats_map AS (
    -- Map each run to all chats in its group
    SELECT DISTINCT
        rg.run_id,
        c.id as chat_id
    FROM run_groups_map rg
    JOIN chat_groups cg ON cg.group_id = rg.group_id
    JOIN chats c ON c.id = cg.chat_id
),
-- Find first run (idx = 0) for each group
first_runs_map AS (
    SELECT DISTINCT
        gr.group_id,
        gr.run_id as first_run_id
    FROM group_runs gr
    WHERE gr.idx = 0 AND gr.group_id = (SELECT group_id FROM params)
),
-- Map each run to its previous run (idx - 1) in the same group
previous_runs_map AS (
    SELECT 
        gr_current.group_id,
        gr_current.run_id as current_run_id,
        gr_previous.run_id as previous_run_id
    FROM group_runs gr_current
    JOIN group_runs gr_previous ON gr_previous.group_id = gr_current.group_id
        AND gr_previous.idx = gr_current.idx - 1
    WHERE gr_current.idx > 0 AND gr_current.group_id = (SELECT group_id FROM params)
),
-- Tree traversal for messages: get all messages following conversation flow per run
messages_with_tree AS (
    WITH RECURSIVE message_path AS (
        -- Base case: Include ALL messages from current run
        SELECT 
            m.id, 
            rcm.run_id,
            rcm.chat_id,
            m.role, 
            m.created_at, 
            m.completed, 
            m.updated_at,
            0 as depth,
            m.id as path_root_id,
            gr.idx as run_idx
        FROM run_chats_map rcm
        JOIN run_groups_map rgm ON rgm.run_id = rcm.run_id
        JOIN groups g ON g.id = rgm.group_id
        JOIN group_runs gr ON gr.group_id = g.id AND gr.run_id = rcm.run_id
        JOIN runs r ON r.id = gr.run_id
        JOIN message_runs mr ON mr.run_id = r.id AND mr.run_id = rcm.run_id
        JOIN messages m ON m.id = mr.message_id
        JOIN chat_groups cg ON cg.group_id = g.id
        JOIN chats c ON c.id = cg.chat_id AND c.id = rcm.chat_id
        
        UNION ALL
        
        -- Recursive case: Traverse up the tree following parent links
        SELECT 
            m.id, 
            mp.run_id,
            mp.chat_id,
            m.role, 
            m.created_at, 
            m.completed, 
            m.updated_at,
            mp.depth + 1 as depth,
            mp.path_root_id,
            mp.run_idx
        FROM messages m
        JOIN message_tree mt ON mt.parent_id = m.id AND mt.active = true
        JOIN message_path mp ON mp.id = mt.child_id
        WHERE mp.depth < 50
        AND EXISTS (
            SELECT 1 
            FROM message_runs mr_parent
            JOIN group_runs gr_parent ON gr_parent.run_id = mr_parent.run_id
            JOIN message_runs mr_child ON mr_child.message_id = mt.child_id
            JOIN group_runs gr_child ON gr_child.run_id = mr_child.run_id
            WHERE mr_parent.message_id = m.id
            AND gr_parent.group_id = gr_child.group_id
            AND gr_child.run_id = mp.run_id
            AND (m.role IN ('user'::message_role, 'assistant'::message_role) OR gr_parent.idx = 0)
        )
    ),
    messages_without_parents AS (
        SELECT 
            m.id, 
            rcm.run_id,
            rcm.chat_id,
            m.role, 
            m.created_at, 
            m.completed, 
            m.updated_at,
            0 as depth,
            m.id as path_root_id,
            gr.idx as run_idx
        FROM run_chats_map rcm
        JOIN run_groups_map rgm ON rgm.run_id = rcm.run_id
        JOIN groups g ON g.id = rgm.group_id
        JOIN group_runs gr ON gr.group_id = g.id AND gr.run_id = rcm.run_id
        JOIN runs r ON r.id = gr.run_id
        JOIN message_runs mr ON mr.run_id = r.id AND mr.run_id = rcm.run_id
        JOIN messages m ON m.id = mr.message_id
        JOIN chat_groups cg ON cg.group_id = g.id
        JOIN chats c ON c.id = cg.chat_id AND c.id = rcm.chat_id
        WHERE NOT EXISTS (
            SELECT 1 FROM message_tree mt 
            WHERE mt.child_id = m.id AND mt.active = true
        )
        AND NOT EXISTS (
            SELECT 1 FROM message_path mp 
            WHERE mp.id = m.id AND mp.run_id = rcm.run_id
        )
        
        UNION
        
        SELECT 
            m.id, 
            rcm.run_id,
            rcm.chat_id,
            m.role, 
            m.created_at, 
            m.completed, 
            m.updated_at,
            0 as depth,
            m.id as path_root_id,
            0 as run_idx
        FROM run_chats_map rcm
        JOIN run_groups_map rgm ON rgm.run_id = rcm.run_id
        JOIN groups g ON g.id = rgm.group_id
        JOIN group_runs gr ON gr.group_id = g.id AND gr.run_id = rcm.run_id
        JOIN first_runs_map frm ON frm.group_id = g.id AND frm.first_run_id != rcm.run_id
        JOIN message_runs mr ON mr.run_id = frm.first_run_id
        JOIN messages m ON m.id = mr.message_id AND m.role IN ('system'::message_role, 'developer'::message_role)
        JOIN chat_groups cg ON cg.group_id = g.id
        JOIN chats c ON c.id = cg.chat_id AND c.id = rcm.chat_id
        WHERE NOT EXISTS (
            SELECT 1 FROM message_path mp 
            WHERE mp.id = m.id AND mp.run_id = rcm.run_id
        )
        AND NOT EXISTS (
            SELECT 1 FROM message_runs mr2
            WHERE mr2.message_id = m.id AND mr2.run_id = rcm.run_id
        )
    ),
    all_messages AS (
        SELECT * FROM message_path
        UNION ALL
        SELECT * FROM messages_without_parents
    ),
    message_run_idx AS (
        SELECT DISTINCT ON (am.id, am.run_id)
            am.id,
            am.run_id,
            am.chat_id,
            am.role,
            am.created_at,
            am.completed,
            am.updated_at,
            am.depth,
            COALESCE(
                (SELECT gr.idx FROM message_runs mr2 
                 JOIN group_runs gr ON gr.run_id = mr2.run_id 
                 WHERE mr2.message_id = am.id 
                 ORDER BY gr.idx LIMIT 1),
                am.run_idx
            ) as run_idx
        FROM all_messages am
        ORDER BY am.id, am.run_id, am.run_idx, am.depth ASC
    )
    SELECT 
        mri.id,
        mri.run_id,
        mri.chat_id,
        mri.role,
        mri.created_at,
        mri.completed,
        mri.updated_at,
        mri.depth,
        mri.run_idx
    FROM message_run_idx mri
),
-- Get all content entries for each message
messages_with_content AS (
    SELECT 
        mwt.id,
        mwt.run_id,
        mwt.role,
        mwt.created_at,
        mwt.completed,
        mwt.updated_at,
        mwt.run_idx,
        mwt.depth,
        COALESCE(
            ARRAY_AGG(
                (mc.idx, cnt.content, mc.created_at, mc.updated_at)::types.q_get_pricing_group_detail_v4_content
                ORDER BY mc.idx
            ) FILTER (WHERE mc.idx IS NOT NULL),
            ARRAY[(0, '', mwt.created_at, mwt.updated_at)::types.q_get_pricing_group_detail_v4_content]
        ) as contents
    FROM messages_with_tree mwt
    LEFT JOIN message_content mc ON mc.message_id = mwt.id
    LEFT JOIN content cnt ON cnt.id = mc.content_id
    GROUP BY mwt.id, mwt.run_id, mwt.role, mwt.created_at, mwt.completed, mwt.updated_at, mwt.run_idx, mwt.depth
),
-- Get run idx for each run
runs_with_idx AS (
    SELECT 
        rm.run_id,
        gr.idx as run_idx,
        gr.group_id
    FROM runs_metadata rm
    JOIN group_runs gr ON gr.run_id = rm.run_id
),
-- For each run, find the latest message and traverse up message_tree to get all ancestors
runs_with_messages AS (
    SELECT 
        current_run.run_id,
        current_run.run_idx as current_run_idx,
        COALESCE(
            ARRAY_AGG(
                (ancestor_msg.id, ancestor_msg.role, ancestor_msg.contents, ancestor_msg.created_at, ancestor_msg.updated_at, ancestor_msg.completed, ancestor_msg.run_idx, COALESCE(ancestor_msg.depth, 0))::types.q_get_pricing_group_detail_v4_message
                ORDER BY ancestor_msg.depth ASC
            ) FILTER (WHERE ancestor_msg.id IS NOT NULL),
            '{}'::types.q_get_pricing_group_detail_v4_message[]
        ) as messages
    FROM runs_with_idx current_run
    LEFT JOIN LATERAL (
        SELECT m.id, m.created_at
        FROM message_runs mr
        JOIN messages m ON m.id = mr.message_id
        WHERE mr.run_id = current_run.run_id
        AND m.role IN ('user'::message_role, 'assistant'::message_role)
        ORDER BY 
            CASE WHEN m.role = 'assistant'::message_role THEN 0 ELSE 1 END,
            m.created_at DESC
        LIMIT 1
    ) latest_msg ON true
    LEFT JOIN LATERAL (
        WITH RECURSIVE ancestor_path AS (
            SELECT 
                m.id,
                m.role,
                mwc.contents,
                m.created_at,
                m.updated_at,
                m.completed,
                current_run.run_idx as run_idx,
                0 as depth_from_latest
            FROM messages m
            LEFT JOIN messages_with_content mwc ON mwc.id = m.id AND mwc.run_id = current_run.run_id
            WHERE m.id = latest_msg.id
            
            UNION ALL
            
            SELECT 
                m.id,
                m.role,
                mwc.contents,
                m.created_at,
                m.updated_at,
                m.completed,
                COALESCE(
                    (SELECT gr.idx FROM message_runs mr2 
                     JOIN group_runs gr ON gr.run_id = mr2.run_id 
                     WHERE mr2.message_id = m.id 
                     AND gr.group_id = current_run.group_id
                     ORDER BY gr.idx LIMIT 1),
                    ap.run_idx
                ) as run_idx,
                ap.depth_from_latest + 1 as depth_from_latest
            FROM messages m
            JOIN message_tree mt ON mt.parent_id = m.id AND mt.active = true
            JOIN ancestor_path ap ON ap.id = mt.child_id
            LEFT JOIN messages_with_content mwc ON mwc.id = m.id AND mwc.run_id = current_run.run_id
            WHERE ap.depth_from_latest < 50
            AND EXISTS (
                SELECT 1 
                FROM message_runs mr_parent
                JOIN group_runs gr_parent ON gr_parent.run_id = mr_parent.run_id
                WHERE mr_parent.message_id = m.id
                AND gr_parent.group_id = current_run.group_id
            )
        )
        SELECT 
            ap.id,
            ap.role,
            ap.contents,
            ap.created_at,
            ap.updated_at,
            ap.completed,
            ap.run_idx,
            (MAX(ap.depth_from_latest) OVER () - ap.depth_from_latest)::integer as depth
        FROM ancestor_path ap
    ) ancestor_msg ON true
    GROUP BY current_run.run_id, current_run.run_idx
),
-- Calculate previousContextStartIndex for each run
-- Need to find first message index where run_idx equals current run idx
runs_with_context_index AS (
    SELECT 
        rwm.run_id,
        rwm.current_run_idx,
        rwm.messages,
        CASE 
            WHEN rwm.current_run_idx = 0 THEN NULL::integer
            ELSE (
                SELECT MIN(msg_idx) - 1
                FROM (
                    SELECT 
                        row_number() OVER (ORDER BY 
                            m.depth ASC,
                            CASE 
                                WHEN m.role::message_role = 'system'::message_role THEN 1
                                WHEN m.role::message_role = 'developer'::message_role THEN 2
                                WHEN m.role::message_role = 'user'::message_role THEN 3
                                WHEN m.role::message_role = 'assistant'::message_role THEN 4
                                ELSE 5
                            END,
                            m.run_idx,
                            m.created_at
                        ) as msg_idx,
                        m.run_idx
                    FROM unnest(rwm.messages) m
                ) indexed_msgs
                WHERE indexed_msgs.run_idx = rwm.current_run_idx
            )
        END as previous_context_start_index
    FROM runs_with_messages rwm
),
-- Build run details with messages
runs_detail AS (
    SELECT 
        rm.run_id,
        rm.created_at,
        rm.input_tokens,
        rm.output_tokens,
        rm.cached_input_tokens,
        rm.model_id,
        rm.agent_id,
        rm.profile_id,
        rm.persona_id,
        COALESCE(rc.run_cost, 0) as cost,
        COALESCE(rwci.messages, '{}'::types.q_get_pricing_group_detail_v4_message[]) as messages,
        rwci.previous_context_start_index
    FROM runs_metadata rm
    LEFT JOIN run_costs rc ON rc.run_id = rm.run_id
    LEFT JOIN runs_with_context_index rwci ON rwci.run_id = rm.run_id
)
SELECT 
    (SELECT group_exists FROM group_exists_check)::boolean as group_exists,
    (SELECT group_id FROM params)::uuid as group_id,
    COALESCE((SELECT actor_name FROM user_profile LIMIT 1), 'System')::text as actor_name,
    CASE 
        WHEN (SELECT has_access FROM group_access_check) = false THEN
            '{}'::types.q_get_pricing_group_detail_v4_run_with_messages[]
        ELSE
            COALESCE(
                ARRAY_AGG(
                    (
                        (rd.run_id, rd.created_at, rd.input_tokens, rd.output_tokens, rd.cached_input_tokens, rd.cost, rd.model_id, rd.agent_id, rd.profile_id, rd.persona_id)::types.q_get_pricing_group_detail_v4_run_metadata,
                        rd.messages,
                        rd.previous_context_start_index
                    )::types.q_get_pricing_group_detail_v4_run_with_messages
                    ORDER BY rd.created_at
                ),
                '{}'::types.q_get_pricing_group_detail_v4_run_with_messages[]
            )
    END as runs,
    COALESCE(
        ARRAY_AGG(
            DISTINCT (m.id, m.name, COALESCE(m.description, ''))::types.q_get_pricing_group_detail_v4_model
        ) FILTER (WHERE m.id IS NOT NULL),
        '{}'::types.q_get_pricing_group_detail_v4_model[]
    ) as models,
    COALESCE(
        ARRAY_AGG(
            DISTINCT (a.id, a.name)::types.q_get_pricing_group_detail_v4_agent
        ) FILTER (WHERE a.id IS NOT NULL),
        '{}'::types.q_get_pricing_group_detail_v4_agent[]
    ) as agents,
    COALESCE(
        ARRAY_AGG(
            DISTINCT (p.id, p.first_name || ' ' || p.last_name)::types.q_get_pricing_group_detail_v4_profile
        ) FILTER (WHERE p.id IS NOT NULL),
        '{}'::types.q_get_pricing_group_detail_v4_profile[]
    ) as profiles
FROM runs_detail rd
LEFT JOIN models m ON m.id = rd.model_id
LEFT JOIN agents a ON a.id = rd.agent_id
LEFT JOIN profiles p ON p.id = rd.profile_id
CROSS JOIN group_exists_check gec
CROSS JOIN group_access_check gac
WHERE (SELECT group_exists FROM group_exists_check) = true
GROUP BY (SELECT group_exists FROM group_exists_check), (SELECT group_id FROM params), (SELECT actor_name FROM user_profile LIMIT 1), (SELECT has_access FROM group_access_check)
$$;


--
-- Name: api_get_pricing_runs_v4(text, text, uuid[], uuid, text[], uuid[], text[], text, uuid[], uuid[], uuid[], text, text, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_pricing_runs_v4(start_date text, end_date text, department_ids uuid[], profile_id uuid, roles text[], cohort_ids uuid[], simulation_filters text[], search text, model_ids uuid[], profile_ids uuid[], actor_ids uuid[], sort_by text, sort_order text, limit_count integer, offset_count integer) RETURNS TABLE(actor_name text, group_runs types.q_get_pricing_runs_v4_group_run[], total_count bigint, page integer, page_size integer, total_pages integer, model_options types.q_get_pricing_runs_v4_filter_option[], profile_options types.q_get_pricing_runs_v4_filter_option[], actor_options types.q_get_pricing_runs_v4_filter_option[], models types.q_get_pricing_runs_v4_model[], profiles types.q_get_pricing_runs_v4_profile[], agents types.q_get_pricing_runs_v4_agent[], personas types.q_get_pricing_runs_v4_persona[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        COALESCE(NULLIF(start_date, ''), NULL)::timestamptz AS start_date,
        COALESCE(NULLIF(end_date, ''), NULL)::timestamptz AS end_date,
        department_ids AS department_ids,
        profile_id AS profile_id,
        roles AS roles,
        cohort_ids AS cohort_ids,
        simulation_filters AS simulation_filters,
        search AS search,
        model_ids AS model_ids,
        profile_ids AS profile_ids,
        actor_ids AS actor_ids,
        COALESCE(sort_by, 'created_at') AS sort_by,
        COALESCE(UPPER(sort_order), 'DESC') AS sort_order,
        COALESCE(limit_count, 10) AS limit_count,
        COALESCE(offset_count, 0) AS offset_count
),
resolve_profile_id AS (
    SELECT 
        CASE 
            WHEN (SELECT profile_id FROM params) IS NULL THEN NULL::uuid
            ELSE (SELECT profile_id FROM params)
        END as resolved_profile_id
),
profile_role_check AS (
    -- Resolve profile_id and check role to determine effective filtering
    SELECT 
        (SELECT resolved_profile_id FROM resolve_profile_id) as raw_profile_id,
        CASE 
            WHEN (SELECT resolved_profile_id FROM resolve_profile_id) IS NULL THEN NULL::uuid
            WHEN (SELECT role FROM profiles WHERE id = (SELECT resolved_profile_id FROM resolve_profile_id)) IN ('admin', 'superadmin', 'instructional') THEN NULL::uuid
            ELSE (SELECT resolved_profile_id FROM resolve_profile_id)
        END as effective_profile_id
),
user_profile AS (
    SELECT 
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
    WHERE x.profile_id IS NOT NULL
),
runs_base AS (
    SELECT
        mr.id as run_id,
        mr.created_at,
        mr.input_tokens,
        mr.output_tokens,
        mrm.model_id,
        mrp.profile_id,
        mr.agent_id,
        mrper.persona_id,
        sim.practice_simulation,
        sa.archived,
        gr.group_id
    FROM runs mr
    LEFT JOIN run_models mrm ON mrm.run_id = mr.id AND mrm.active = true
    LEFT JOIN run_profiles mrp ON mrp.run_id = mr.id AND mrp.active = true
    LEFT JOIN run_personas mrper ON mrper.run_id = mr.id AND mrper.active = true
    -- Join to groups via group_runs
    LEFT JOIN group_runs gr ON gr.run_id = mr.id
    LEFT JOIN groups g ON g.id = gr.group_id
    -- Join to simulations via chat_groups → groups → group_runs → runs → chats → attempt_chats → simulation_attempts → simulations
    -- Get chat_id from any chat in this run's group
    LEFT JOIN LATERAL (
        SELECT DISTINCT c.id AS chat_id
        FROM groups g2
        JOIN chat_groups cg ON cg.group_id = g2.id
        JOIN chats c ON c.id = cg.chat_id
        WHERE g2.id = g.id
        LIMIT 1
    ) chat_lookup ON true
    LEFT JOIN chats c ON c.id = chat_lookup.chat_id
    LEFT JOIN attempt_chats ac ON ac.chat_id = c.id
    LEFT JOIN simulation_attempts sa ON sa.id = ac.attempt_id
    LEFT JOIN simulations sim ON sim.id = sa.simulation_id
    CROSS JOIN params p
    WHERE 
        -- Date filters (always required)
        mr.created_at >= p.start_date
        AND mr.created_at <= p.end_date
        -- Department filter (via profile_departments join)
        AND (
            p.department_ids IS NULL
            OR COALESCE(array_length(p.department_ids, 1), 0) = 0
            OR EXISTS (
                SELECT 1 FROM run_profiles mrp2
                JOIN profile_departments pd ON pd.profile_id = mrp2.profile_id
                WHERE mrp2.run_id = mr.id
                  AND mrp2.active = true
                  AND pd.department_id = ANY(p.department_ids)
            )
        )
        -- Profile filter (specific user) - only if role is not admin/superadmin/instructional
        AND (
            (SELECT effective_profile_id FROM profile_role_check) IS NULL
            OR mrp.profile_id = (SELECT effective_profile_id FROM profile_role_check)
        )
        -- Role filter (only if no effective profile_id)
        AND (
            (SELECT effective_profile_id FROM profile_role_check) IS NOT NULL
            OR p.roles IS NULL
            OR COALESCE(array_length(p.roles, 1), 0) = 0
            OR mrp.profile_id IN (
                SELECT id FROM profiles WHERE role::text = ANY(p.roles)
            )
        )
        -- Cohort filter (via cohort_profiles)
        AND (
            p.cohort_ids IS NULL
            OR COALESCE(array_length(p.cohort_ids, 1), 0) = 0
            OR mrp.profile_id IN (
                SELECT cp.profile_id FROM cohort_profiles cp
                WHERE cp.cohort_id = ANY(p.cohort_ids) AND cp.active = true
            )
        )
        -- Simulation type filtering: general (practice_simulation = FALSE), practice (practice_simulation = TRUE), archived (archived = TRUE)
        -- If no filters provided (NULL or empty), include all runs (runs not linked to simulations are included)
        -- If filters provided, only include runs that match the filter OR runs not linked to simulations (treat as "general")
        AND (
            p.simulation_filters IS NULL
            OR COALESCE(array_length(p.simulation_filters, 1), 0) = 0
            OR sim.id IS NULL  -- Runs not linked to simulations are always included
            OR (
                ('general' = ANY(p.simulation_filters) AND sim.practice_simulation = FALSE AND COALESCE(sa.archived, FALSE) = FALSE) OR
                ('practice' = ANY(p.simulation_filters) AND sim.practice_simulation = TRUE AND COALESCE(sa.archived, FALSE) = FALSE) OR
                ('archived' = ANY(p.simulation_filters) AND COALESCE(sa.archived, FALSE) = TRUE)
            )
        )
        -- Exclude archived attempts unless 'archived' is explicitly in the filter list
        AND (
            p.simulation_filters IS NULL
            OR COALESCE(array_length(p.simulation_filters, 1), 0) = 0
            OR 'archived' = ANY(p.simulation_filters)
            OR COALESCE(sa.archived, FALSE) = FALSE
        )
),
runs_with_debug AS (
    SELECT
        mrb.run_id,
        mrb.created_at,
        mrb.input_tokens,
        mrb.output_tokens,
        mrb.model_id,
        mrb.profile_id,
        mrb.agent_id,
        mrb.persona_id,
        mrb.practice_simulation,
        mrb.archived,
        mrb.group_id,
        COALESCE(
            ARRAY_AGG(
                (di.id, di.created_at, di.content)::types.q_get_pricing_runs_v4_debug_info
                ORDER BY di.created_at
            ) FILTER (WHERE di.id IS NOT NULL),
            '{}'::types.q_get_pricing_runs_v4_debug_info[]
        ) as debug_info
    FROM runs_base mrb
    LEFT JOIN debug_info di ON di.run_id = mrb.run_id
    GROUP BY mrb.run_id, mrb.created_at, mrb.input_tokens, mrb.output_tokens, mrb.model_id, mrb.profile_id, mrb.agent_id, mrb.persona_id, mrb.practice_simulation, mrb.archived, mrb.group_id
),
-- Calculate run costs using run_pricing_usage and model_pricing
run_costs AS (
    SELECT 
        rpu.run_id,
        COALESCE(SUM(
            (rpu.count::numeric / u.value::numeric) * mp.price
        ), 0) as run_cost
    FROM run_pricing_usage rpu
    JOIN run_models rm ON rm.run_id = rpu.run_id AND rm.active = true
    JOIN model_pricing mp ON mp.model_id = rm.model_id 
        AND mp.pricing_type = rpu.pricing_type 
        AND mp.unit_id = rpu.unit_id
        AND mp.active = true
    JOIN units u ON u.id = rpu.unit_id
    GROUP BY rpu.run_id
),
-- Join with mappings for search and display
runs_with_names AS (
    SELECT
        mrwd.run_id,
        mrwd.created_at,
        mrwd.input_tokens,
        mrwd.output_tokens,
        mrwd.model_id,
        mrwd.profile_id,
        mrwd.agent_id,
        mrwd.persona_id,
        mrwd.practice_simulation,
        mrwd.archived,
        mrwd.group_id,
        mrwd.debug_info,
        m.name as model_name,
        p.first_name || ' ' || p.last_name as profile_name,
        a.name as agent_name,
        per.name as persona_name,
        COALESCE(rc.run_cost, 0) as run_cost
    FROM runs_with_debug mrwd
    LEFT JOIN models m ON m.id = mrwd.model_id
    LEFT JOIN profiles p ON p.id = mrwd.profile_id
    LEFT JOIN agents a ON a.id = mrwd.agent_id
    LEFT JOIN personas per ON per.id = mrwd.persona_id
    LEFT JOIN run_costs rc ON rc.run_id = mrwd.run_id
),
-- Apply search filter (across model name, agent name, persona name, profile name, debug info)
runs_with_search AS (
    SELECT 
        rwn.run_id,
        rwn.created_at,
        rwn.input_tokens,
        rwn.output_tokens,
        rwn.model_id,
        rwn.profile_id,
        rwn.agent_id,
        rwn.persona_id,
        rwn.practice_simulation,
        rwn.archived,
        rwn.group_id,
        rwn.debug_info,
        rwn.model_name,
        rwn.profile_name,
        rwn.agent_name,
        rwn.persona_name,
        rwn.run_cost
    FROM runs_with_names rwn
    CROSS JOIN params p
    WHERE (
        p.search IS NULL
        OR p.search = ''
        OR LOWER(rwn.model_name) LIKE '%' || LOWER(p.search) || '%'
        OR LOWER(rwn.agent_name) LIKE '%' || LOWER(p.search) || '%'
        OR LOWER(rwn.persona_name) LIKE '%' || LOWER(p.search) || '%'
        OR LOWER(rwn.profile_name) LIKE '%' || LOWER(p.search) || '%'
        OR EXISTS (
            SELECT 1 FROM unnest(rwn.debug_info) AS di
            WHERE LOWER(di.content) LIKE '%' || LOWER(p.search) || '%'
        )
    )
),
-- Apply modelIds, profileIds, actorIds filters
runs_filtered AS (
    SELECT 
        rws.run_id,
        rws.created_at,
        rws.input_tokens,
        rws.output_tokens,
        rws.model_id,
        rws.profile_id,
        rws.agent_id,
        rws.persona_id,
        rws.practice_simulation,
        rws.archived,
        rws.group_id,
        rws.debug_info,
        rws.model_name,
        rws.profile_name,
        rws.agent_name,
        rws.persona_name,
        rws.run_cost
    FROM runs_with_search rws
    CROSS JOIN params p
    WHERE (
        -- Model filter
        (p.model_ids IS NULL OR COALESCE(array_length(p.model_ids, 1), 0) = 0 OR rws.model_id = ANY(p.model_ids))
        -- Profile filter
        AND (p.profile_ids IS NULL OR COALESCE(array_length(p.profile_ids, 1), 0) = 0 OR rws.profile_id = ANY(p.profile_ids))
        -- Actor filter (agent or persona)
        AND (
            p.actor_ids IS NULL 
            OR COALESCE(array_length(p.actor_ids, 1), 0) = 0 
            OR rws.agent_id = ANY(p.actor_ids)
            OR rws.persona_id = ANY(p.actor_ids)
        )
    )
),
-- Group runs by group_id and aggregate
-- Note: Runs without groups are excluded (they would have been in chat_runs before migration)
groups_with_runs AS (
    SELECT
        mrf.group_id,
        COUNT(DISTINCT mrf.run_id) as run_count,
        SUM(mrf.input_tokens) as total_input_tokens,
        SUM(mrf.output_tokens) as total_output_tokens,
        SUM(mrf.run_cost) as total_cost,
        MIN(mrf.created_at) as created_at,  -- Use earliest run's created_at
        -- Aggregate run summaries for display
        ARRAY_AGG(
            (mrf.run_id, mrf.created_at, mrf.input_tokens, mrf.output_tokens, mrf.run_cost, mrf.model_id, mrf.profile_id, mrf.agent_id, mrf.persona_id, mrf.debug_info)::types.q_get_pricing_runs_v4_run_summary
            ORDER BY mrf.created_at
        ) FILTER (WHERE mrf.run_id IS NOT NULL) as runs
    FROM runs_filtered mrf
    WHERE mrf.group_id IS NOT NULL  -- Only include runs that belong to groups
    GROUP BY mrf.group_id
),
-- Get all unique model options from filtered runs (before pagination)
model_options_cte AS (
    SELECT 
        m.id AS model_id,
        m.name AS model_name,
        COUNT(DISTINCT mrf.run_id) AS count
    FROM runs_filtered mrf
    JOIN models m ON m.id = mrf.model_id
    WHERE mrf.model_id IS NOT NULL
    GROUP BY m.id, m.name
    ORDER BY model_name
),
-- Get all unique profile options from filtered runs (before pagination)
profile_options_cte AS (
    SELECT 
        p.id AS profile_id,
        p.first_name || ' ' || p.last_name AS profile_name,
        COUNT(DISTINCT mrf.run_id) AS count
    FROM runs_filtered mrf
    JOIN profiles p ON p.id = mrf.profile_id
    WHERE mrf.profile_id IS NOT NULL
    GROUP BY p.id, p.first_name, p.last_name
    ORDER BY profile_name
),
-- Get all unique actor options (agents + personas) from filtered runs (before pagination)
actor_options_cte AS (
    SELECT 
        COALESCE(a.id, per.id) AS actor_id,
        COALESCE(a.name, per.name) AS actor_name,
        COUNT(DISTINCT mrf.run_id) AS count
    FROM runs_filtered mrf
    LEFT JOIN agents a ON a.id = mrf.agent_id
    LEFT JOIN personas per ON per.id = mrf.persona_id
    WHERE mrf.agent_id IS NOT NULL OR mrf.persona_id IS NOT NULL
    GROUP BY COALESCE(a.id, per.id), COALESCE(a.name, per.name)
    ORDER BY actor_name
),
-- Add pagination and sorting
-- Use CASE statement to handle dynamic sort column (no string replacement needed)
-- Compute sort value based on sort_by parameter, converting all to numeric for consistent ordering
-- For ASC, negate the value so DESC ordering gives ASC result
groups_with_sort AS (
    SELECT
        gwr.*,
        CASE 
            WHEN p.sort_by = 'createdAt' THEN 
                CASE WHEN p.sort_order = 'ASC' THEN -EXTRACT(EPOCH FROM gwr.created_at)::numeric
                     ELSE EXTRACT(EPOCH FROM gwr.created_at)::numeric END
            WHEN p.sort_by = 'inputTokens' THEN 
                CASE WHEN p.sort_order = 'ASC' THEN -gwr.total_input_tokens::numeric
                     ELSE gwr.total_input_tokens::numeric END
            WHEN p.sort_by = 'outputTokens' THEN 
                CASE WHEN p.sort_order = 'ASC' THEN -gwr.total_output_tokens::numeric
                     ELSE gwr.total_output_tokens::numeric END
            WHEN p.sort_by = 'cost' THEN 
                CASE WHEN p.sort_order = 'ASC' THEN -gwr.total_cost
                     ELSE gwr.total_cost END
            WHEN p.sort_by = 'runCount' THEN 
                CASE WHEN p.sort_order = 'ASC' THEN -gwr.run_count::numeric
                     ELSE gwr.run_count::numeric END
            ELSE 
                CASE WHEN p.sort_order = 'ASC' THEN -EXTRACT(EPOCH FROM gwr.created_at)::numeric
                     ELSE EXTRACT(EPOCH FROM gwr.created_at)::numeric END
        END as sort_value
    FROM groups_with_runs gwr
    CROSS JOIN params p
),
paginated_groups AS (
    SELECT
        gws.group_id,
        gws.created_at,
        gws.run_count,
        gws.total_input_tokens,
        gws.total_output_tokens,
        gws.total_cost,
        gws.runs,
        COUNT(*) OVER() AS total_count
    FROM groups_with_sort gws
    ORDER BY gws.sort_value DESC NULLS LAST
    LIMIT (SELECT limit_count FROM params) OFFSET (SELECT offset_count FROM params)
),
-- Build mappings (same as summary endpoint)
model_pricing_aggregated AS (
    -- Aggregate pricing per model: sum all input/output prices normalized to per-million tokens
    SELECT 
        mrf.model_id,
        COALESCE(SUM(CASE WHEN mp.pricing_type = 'input'::pricing_type THEN mp.price * (1000000.0 / u.value) ELSE 0 END), 0.0) as input_ppm,
        COALESCE(SUM(CASE WHEN mp.pricing_type = 'output'::pricing_type THEN mp.price * (1000000.0 / u.value) ELSE 0 END), 0.0) as output_ppm
    FROM (SELECT DISTINCT model_id FROM runs_filtered WHERE model_id IS NOT NULL) mrf
    LEFT JOIN model_pricing mp ON mp.model_id = mrf.model_id AND mp.active = true AND mp.pricing_type IN ('input'::pricing_type, 'output'::pricing_type)
    LEFT JOIN units u ON u.id = mp.unit_id
    GROUP BY mrf.model_id
)
SELECT 
    COALESCE((SELECT actor_name FROM user_profile LIMIT 1), 'System')::text as actor_name,
    COALESCE(
        (SELECT ARRAY_AGG(
            (pg.group_id, pg.created_at, pg.run_count, pg.total_input_tokens, pg.total_output_tokens, pg.total_cost, pg.runs)::types.q_get_pricing_runs_v4_group_run
        ) FROM paginated_groups pg),
        '{}'::types.q_get_pricing_runs_v4_group_run[]
    ) as group_runs,
    COALESCE((SELECT total_count FROM paginated_groups LIMIT 1), 0)::bigint as total_count,
    ((SELECT offset_count FROM params) / NULLIF((SELECT limit_count FROM params), 0))::int as page,
    (SELECT limit_count FROM params)::int as page_size,
    CASE 
        WHEN (SELECT limit_count FROM params) > 0 
        THEN ((COALESCE((SELECT total_count FROM paginated_groups LIMIT 1), 0) + (SELECT limit_count FROM params) - 1) / (SELECT limit_count FROM params))::int
        ELSE 0
    END as total_pages,
    COALESCE(
        (SELECT ARRAY_AGG(
            (moc.model_id::text, moc.model_name, moc.count)::types.q_get_pricing_runs_v4_filter_option
        ) FROM model_options_cte moc),
        '{}'::types.q_get_pricing_runs_v4_filter_option[]
    ) as model_options,
    COALESCE(
        (SELECT ARRAY_AGG(
            (poc.profile_id::text, poc.profile_name, poc.count)::types.q_get_pricing_runs_v4_filter_option
        ) FROM profile_options_cte poc),
        '{}'::types.q_get_pricing_runs_v4_filter_option[]
    ) as profile_options,
    COALESCE(
        (SELECT ARRAY_AGG(
            (aoc.actor_id::text, aoc.actor_name, aoc.count)::types.q_get_pricing_runs_v4_filter_option
        ) FROM actor_options_cte aoc),
        '{}'::types.q_get_pricing_runs_v4_filter_option[]
    ) as actor_options,
    COALESCE(
        (SELECT ARRAY_AGG(
            DISTINCT (m.id, m.name, COALESCE(m.description, ''), COALESCE(mpa.input_ppm, 0.0), COALESCE(mpa.output_ppm, 0.0))::types.q_get_pricing_runs_v4_model
        ) 
        FROM (SELECT DISTINCT model_id FROM runs_filtered WHERE model_id IS NOT NULL) mrf
        JOIN models m ON m.id = mrf.model_id
        LEFT JOIN model_pricing_aggregated mpa ON mpa.model_id = m.id),
        '{}'::types.q_get_pricing_runs_v4_model[]
    ) as models,
    COALESCE(
        (SELECT ARRAY_AGG(
            DISTINCT (p.id, p.first_name || ' ' || p.last_name)::types.q_get_pricing_runs_v4_profile
        )
        FROM (SELECT DISTINCT mrf.profile_id FROM runs_filtered mrf WHERE mrf.profile_id IS NOT NULL) prf
        JOIN profiles p ON p.id = prf.profile_id),
        '{}'::types.q_get_pricing_runs_v4_profile[]
    ) as profiles,
    COALESCE(
        (SELECT ARRAY_AGG(
            DISTINCT (a.id, a.name)::types.q_get_pricing_runs_v4_agent
        )
        FROM (SELECT DISTINCT agent_id FROM runs_filtered WHERE agent_id IS NOT NULL) agt
        JOIN agents a ON a.id = agt.agent_id),
        '{}'::types.q_get_pricing_runs_v4_agent[]
    ) as agents,
    COALESCE(
        (SELECT ARRAY_AGG(
            DISTINCT (per.id, per.name)::types.q_get_pricing_runs_v4_persona
        )
        FROM (SELECT DISTINCT persona_id FROM runs_filtered WHERE persona_id IS NOT NULL) pers
        JOIN personas per ON per.id = pers.persona_id),
        '{}'::types.q_get_pricing_runs_v4_persona[]
    ) as personas
FROM params
LIMIT 1
$$;


--
-- Name: api_get_profile_by_email_v4(text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_profile_by_email_v4(email text, profile_id uuid DEFAULT NULL::uuid) RETURNS TABLE(profile_id uuid, first_name text, last_name text, emails text[], primary_email text, role text, active boolean, req_per_day integer, last_login timestamp with time zone, last_active timestamp with time zone, created_at timestamp with time zone, updated_at timestamp with time zone, primary_department_id uuid, actor_name text)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT email AS email,
           profile_id AS profile_id
),
actor_name_computed AS (
    -- Compute actor_name from profile_id if provided (for audit logging)
    SELECT 
        CASE 
            WHEN (SELECT profile_id FROM params) IS NOT NULL THEN
                (SELECT first_name || ' ' || last_name 
                 FROM profiles 
                 WHERE id = (SELECT profile_id FROM params))
            ELSE NULL
        END as actor_name
),
target_profile AS (
    SELECT 
        p.id,
        p.first_name,
        p.last_name,
        ARRAY_AGG(pe.email ORDER BY pe.is_primary DESC, pe.created_at) FILTER (WHERE pe.active = true) as emails,
        (SELECT email FROM profile_emails WHERE profile_id = p.id AND is_primary = true AND active = true LIMIT 1) as primary_email,
        p.role,
        p.active,
        prl.requests_per_day as req_per_day,
        p.last_login,
        pa.last_active,
        p.created_at,
        p.updated_at,
        pd.department_id as primary_department_id
    FROM profiles p
    JOIN profile_emails pe_match ON pe_match.profile_id = p.id AND pe_match.email = (SELECT email FROM params) AND pe_match.active = true
    LEFT JOIN profile_emails pe ON pe.profile_id = p.id AND pe.active = true
    LEFT JOIN profile_departments pd ON p.id = pd.profile_id AND pd.is_primary = TRUE AND pd.active = true
    LEFT JOIN profile_request_limits prl ON prl.profile_id = p.id AND prl.active = true
    LEFT JOIN LATERAL (
        SELECT last_active 
        FROM profile_activity 
        WHERE profile_id = p.id 
        ORDER BY created_at DESC 
        LIMIT 1
    ) pa ON true
    GROUP BY p.id, p.first_name, p.last_name, p.role, p.active, 
             prl.requests_per_day, p.last_login, pa.last_active, 
             p.created_at, p.updated_at, pd.department_id
)
SELECT 
    tp.id as profile_id,
    tp.first_name,
    tp.last_name,
    COALESCE(tp.emails, ARRAY[]::text[]) as emails,
    tp.primary_email,
    tp.role,
    tp.active,
    tp.req_per_day,
    tp.last_login,
    tp.last_active,
    tp.created_at,
    tp.updated_at,
    tp.primary_department_id,
    anc.actor_name
FROM target_profile tp
CROSS JOIN actor_name_computed anc
LIMIT 1
$$;


--
-- Name: api_get_profile_context_v4(uuid, uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_profile_context_v4(actual_profile_id uuid DEFAULT NULL::uuid, effective_profile_id uuid DEFAULT NULL::uuid, department_id text DEFAULT NULL::text, auth_mode text DEFAULT NULL::text) RETURNS TABLE(is_authorized boolean, guest_login_enabled boolean, active_departments_count bigint, department_auth_providers_count bigint, default_settings_auth_providers_count bigint, departments_without_auth_providers_count bigint, department_exists boolean, actual_id uuid, actual_first_name text, actual_last_name text, actual_emails text[], actual_primary_email text, actual_role text, actual_active boolean, actual_req_per_day integer, actual_last_login timestamp with time zone, actual_last_active timestamp with time zone, actual_created_at timestamp with time zone, actual_updated_at timestamp with time zone, actual_primary_department_id uuid, id uuid, first_name text, last_name text, emails text[], primary_email text, role text, active boolean, req_per_day integer, last_login timestamp with time zone, last_active timestamp with time zone, created_at timestamp with time zone, updated_at timestamp with time zone, primary_department_id uuid, departments types.q_get_profile_context_v4_department[], cohorts types.q_get_profile_context_v4_cohort[], simulations types.q_get_profile_context_v4_simulation[], earliest_attempt_date timestamp with time zone, scoped_roles text[], settings_id text, settings_created_at timestamp with time zone, settings_active boolean, settings_name text, settings_description text, settings_primary_color text, settings_accent text, settings_background text, settings_surface text, settings_success text, settings_warning text, settings_error text, settings_sidebar_background text, settings_sidebar_primary text, settings_chart1 text, settings_chart2 text, settings_chart3 text, settings_chart4 text, settings_chart5 text, settings_guest_login_enabled boolean, settings_success_threshold integer, settings_warning_threshold integer, settings_danger_threshold integer, settings_auth_ids text[], settings_auths types.q_get_profile_context_v4_auth[], settings_provider_ids text[], settings_providers types.q_get_profile_context_v4_provider[], settings_default_guest_profile_id text, settings_default_account_profile_id text, available_sections text[], redirect_path text, department_ids text[], cohort_ids text[], simulation_ids text[], drafts types.q_get_profile_context_v4_draft[], settings_tokens types.q_get_profile_context_v4_theme_tokens, actor_name text)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        actual_profile_id AS actual_profile_id,
        effective_profile_id AS effective_profile_id,
        department_id AS department_id,
        auth_mode AS auth_mode
),
params_normalized AS (
    -- Normalize department_id: convert empty string to NULL
    SELECT 
        CASE 
            WHEN department_id IS NULL OR department_id = '' THEN NULL::uuid
            ELSE department_id::uuid
        END as department_id_uuid
    FROM params
),
-- Authorization check CTEs (merged from check_login_authorization_complete.sql)
default_settings_for_auth AS (
    -- Get settings with no department links (cross-department/default)
    SELECT s.id as settings_id, s.guest_login_enabled
    FROM settings s
    WHERE s.active = true
      AND NOT EXISTS (
          SELECT 1 FROM department_settings sd 
          WHERE sd.settings_id = s.id AND sd.active = true
      )
    LIMIT 1
),
dept_specific_settings_for_auth AS (
    -- Get department-specific settings (if department_id provided)
    SELECT s.id as settings_id, s.guest_login_enabled
    FROM settings s
    JOIN department_settings ds ON ds.settings_id = s.id AND ds.active = true
    CROSS JOIN params_normalized pn
    WHERE pn.department_id_uuid IS NOT NULL
      AND ds.department_id = pn.department_id_uuid
      AND s.active = true
    LIMIT 1
),
selected_settings_for_auth AS (
    -- Priority: department-specific settings, then default, then any active
    SELECT 
        COALESCE(
            (SELECT settings_id FROM dept_specific_settings_for_auth),
            (SELECT settings_id FROM default_settings_for_auth),
            (SELECT id FROM settings WHERE active = true LIMIT 1)
        ) as settings_id,
        COALESCE(
            (SELECT guest_login_enabled FROM dept_specific_settings_for_auth),
            (SELECT guest_login_enabled FROM default_settings_for_auth),
            false
        ) as guest_login_enabled
),
active_departments_count AS (
    -- Count all active departments
    SELECT COUNT(*) as count
    FROM departments
    WHERE active = true
),
department_exists_check AS (
    -- Check if the specified department exists and is active (if department_id provided)
    SELECT 
        CASE 
            WHEN pn.department_id_uuid IS NOT NULL THEN
                EXISTS(
                    SELECT 1 FROM departments d
                    WHERE d.id = pn.department_id_uuid
                    AND d.active = true
                )
            ELSE false
        END as department_exists
    FROM params_normalized pn
),
department_auth_providers_count AS (
    -- Count auth providers for specific department (if department_id provided)
    SELECT COUNT(DISTINCT a.id) as count
    FROM departments d
    JOIN department_settings ds ON ds.department_id = d.id AND ds.active = true
    JOIN settings s ON s.id = ds.settings_id AND s.active = true
    JOIN setting_auths sa ON sa.settings_id = s.id AND sa.active = true
    JOIN auth a ON a.id = sa.auth_id AND a.active = true
    CROSS JOIN params_normalized pn
    WHERE pn.department_id_uuid IS NOT NULL
      AND d.id = pn.department_id_uuid
      AND d.active = true
),
default_settings_auth_providers_count AS (
    -- Count auth providers for default settings (no department links)
    SELECT COUNT(DISTINCT a.id) as count
    FROM default_settings_for_auth ds
    JOIN settings s ON s.id = ds.settings_id
    JOIN setting_auths sa ON sa.settings_id = s.id AND sa.active = true
    JOIN auth a ON a.id = sa.auth_id AND a.active = true
),
departments_without_auth_providers_count AS (
    -- Count departments that have no auth providers configured
    SELECT COUNT(DISTINCT d.id) as count
    FROM departments d
    WHERE d.active = true
      AND NOT EXISTS (
          SELECT 1
          FROM department_settings ds
          JOIN settings s ON s.id = ds.settings_id AND s.active = true
          JOIN setting_auths sa ON sa.settings_id = s.id AND sa.active = true
          JOIN auth a ON a.id = sa.auth_id AND a.active = true
          WHERE ds.department_id = d.id
            AND ds.active = true
      )
),
resolve_profile_from_department AS (
    -- Resolve profile ID from department settings when profile IDs are null
    -- This happens when user is accessing via guest/default-account cookies
    -- department-id can be NULL for default settings (no department-specific settings)
    SELECT 
        CASE 
            -- If both profile IDs are null and we have auth_mode, resolve from settings
            WHEN (SELECT actual_profile_id FROM params) IS NULL 
                 AND (SELECT effective_profile_id FROM params) IS NULL 
                 AND (SELECT auth_mode FROM params) IN ('default-guest', 'default-account') THEN
                COALESCE(
                    -- Try department-specific settings first (only if department_id is provided)
                    CASE 
                        WHEN (SELECT department_id FROM params) IS NOT NULL 
                             AND (SELECT department_id FROM params) != '' THEN
                            CASE 
                                WHEN (SELECT auth_mode FROM params) = 'default-guest' THEN
                                    (SELECT sdg.profile_id
                                     FROM settings s
                                     JOIN department_settings ds ON ds.settings_id = s.id AND ds.active = true
                                     JOIN settings_default_guest sdg ON sdg.settings_id = s.id AND sdg.active = true
                                     WHERE ds.department_id = (SELECT department_id FROM params)::uuid AND s.active = true
                                     LIMIT 1)
                                WHEN (SELECT auth_mode FROM params) = 'default-account' THEN
                                    (SELECT sda.profile_id
                                     FROM settings s
                                     JOIN department_settings ds ON ds.settings_id = s.id AND ds.active = true
                                     JOIN settings_default_account sda ON sda.settings_id = s.id AND sda.active = true
                                     WHERE ds.department_id = (SELECT department_id FROM params)::uuid AND s.active = true
                                     LIMIT 1)
                            END
                        ELSE NULL::uuid
                    END,
                    -- Fallback to default settings (no department links) - always try this
                    CASE 
                        WHEN (SELECT auth_mode FROM params) = 'default-guest' THEN
                            (SELECT sdg.profile_id
                             FROM settings s
                             JOIN settings_default_guest sdg ON sdg.settings_id = s.id AND sdg.active = true
                             WHERE s.active = true
                               AND NOT EXISTS (
                                   SELECT 1 FROM department_settings ds 
                                   WHERE ds.settings_id = s.id AND ds.active = true
                               )
                             LIMIT 1)
                        WHEN (SELECT auth_mode FROM params) = 'default-account' THEN
                            (SELECT sda.profile_id
                             FROM settings s
                             JOIN settings_default_account sda ON sda.settings_id = s.id AND sda.active = true
                             WHERE s.active = true
                               AND NOT EXISTS (
                                   SELECT 1 FROM department_settings ds 
                                   WHERE ds.settings_id = s.id AND ds.active = true
                               )
                             LIMIT 1)
                    END
                )
            ELSE NULL::uuid
        END as resolved_profile_id
),
resolved_profile_ids AS (
    -- Use provided profile IDs if available, otherwise use resolved profile from department
    SELECT 
        COALESCE((SELECT actual_profile_id FROM params), (SELECT resolved_profile_id FROM resolve_profile_from_department)) as actual_profile_id,
        COALESCE((SELECT effective_profile_id FROM params), (SELECT resolved_profile_id FROM resolve_profile_from_department)) as effective_profile_id
),
emulation_validation AS (
    -- Validate emulation is authorized when profiles differ
    SELECT 
        (SELECT actual_profile_id FROM resolved_profile_ids) as resolved_actual_profile_id,
        (SELECT effective_profile_id FROM resolved_profile_ids) as resolved_effective_profile_id,
        CASE 
            WHEN (SELECT actual_profile_id FROM resolved_profile_ids) = (SELECT effective_profile_id FROM resolved_profile_ids) THEN true  -- Same profile, always allowed
            ELSE (
                -- Check if effective profile is in simulatable list based on actual user's role
                SELECT EXISTS (
                    SELECT 1
                    FROM profiles p_actual
                    CROSS JOIN profiles p_effective
                    WHERE p_actual.id = (SELECT actual_profile_id FROM resolved_profile_ids)
                      AND p_effective.id = (SELECT effective_profile_id FROM resolved_profile_ids)
                      AND p_effective.id != p_actual.id
                      AND CASE 
                        WHEN p_actual.role = 'superadmin'::profile_role THEN true
                        WHEN p_actual.role = 'admin'::profile_role THEN p_effective.role IN ('instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role)
                        WHEN p_actual.role = 'instructional'::profile_role THEN p_effective.role IN ('member'::profile_role, 'guest'::profile_role)
                        ELSE false
                      END
                )
            )
        END as is_authorized
),
actual_profile_role AS (
    -- Use actual (logged-in) user's role for emulation permissions
    SELECT role FROM profiles p WHERE p.id = (SELECT actual_profile_id FROM resolved_profile_ids)
),
effective_profile_role AS (
    -- Use effective profile's role for UI permissions filtering
    -- Return NULL role when profile ID is NULL (for settings-only requests)
    SELECT 
        COALESCE(
            (SELECT role FROM profiles p WHERE p.id = (SELECT effective_profile_id FROM resolved_profile_ids) LIMIT 1),
            NULL::profile_role
        ) as role
),
scoped_roles_computed AS (
    -- Compute scoped roles based on effective profile's role
    SELECT 
        CASE 
            WHEN epr.role = 'superadmin'::profile_role THEN ARRAY['superadmin', 'admin', 'instructional', 'member', 'guest']::text[]
            WHEN epr.role = 'admin'::profile_role THEN ARRAY['admin', 'instructional', 'member', 'guest']::text[]
            WHEN epr.role = 'instructional'::profile_role THEN ARRAY['instructional', 'member', 'guest']::text[]
            WHEN epr.role = 'member'::profile_role THEN ARRAY['member']::text[]
            ELSE ARRAY['guest']::text[]
        END as scoped_roles
    FROM effective_profile_role epr
),
actual_profile_data AS (
    -- Fetch the logged-in user's profile
    -- Return NULL values when profile ID is NULL (for settings-only requests)
    SELECT 
        p.id,
        p.first_name,
        p.last_name,
        ARRAY_AGG(pe.email ORDER BY pe.is_primary DESC, pe.created_at) FILTER (WHERE pe.active = true) as emails,
        (SELECT email FROM profile_emails WHERE profile_id = p.id AND is_primary = true AND active = true LIMIT 1) as primary_email,
        p.role,
        p.active,
        COALESCE(prl.requests_per_day, 0) as req_per_day,
        p.last_login,
        pa.last_active,
        p.created_at,
        p.updated_at,
        pd.department_id as primary_department_id
    FROM profiles p
    LEFT JOIN profile_emails pe ON pe.profile_id = p.id AND pe.active = true
    LEFT JOIN profile_departments pd ON p.id = pd.profile_id AND pd.is_primary = TRUE
    LEFT JOIN profile_request_limits prl ON prl.profile_id = p.id AND prl.active = true
    LEFT JOIN LATERAL (
        SELECT last_active 
        FROM profile_activity 
        WHERE profile_id = p.id 
        ORDER BY created_at DESC 
        LIMIT 1
    ) pa ON true
    WHERE p.id = (SELECT actual_profile_id FROM resolved_profile_ids)
    GROUP BY p.id, p.first_name, p.last_name, p.role, p.active, 
             prl.requests_per_day, p.last_login, pa.last_active, 
             p.created_at, p.updated_at, pd.department_id
    UNION ALL
    -- Return single row with NULL values when profile ID is NULL (for settings-only requests)
    SELECT 
        NULL::uuid as id,
        NULL::text as first_name,
        NULL::text as last_name,
        NULL::text[] as emails,
        NULL::text as primary_email,
        NULL::profile_role as role,
        NULL::boolean as active,
        NULL::integer as req_per_day,
        NULL::timestamptz as last_login,
        NULL::timestamptz as last_active,
        NULL::timestamptz as created_at,
        NULL::timestamptz as updated_at,
        NULL::uuid as primary_department_id
    WHERE (SELECT actual_profile_id FROM resolved_profile_ids) IS NULL
),
effective_profile_data AS (
    -- Fetch the profile being viewed (could be same as actual or emulated)
    -- Return NULL values when profile ID is NULL (for settings-only requests)
    SELECT 
        p.id,
        p.first_name,
        p.last_name,
        ARRAY_AGG(pe.email ORDER BY pe.is_primary DESC, pe.created_at) FILTER (WHERE pe.active = true) as emails,
        (SELECT email FROM profile_emails WHERE profile_id = p.id AND is_primary = true AND active = true LIMIT 1) as primary_email,
        p.role,
        p.active,
        COALESCE(prl.requests_per_day, 0) as req_per_day,
        p.last_login,
        pa.last_active,
        p.created_at,
        p.updated_at,
        pd.department_id as primary_department_id
    FROM profiles p
    LEFT JOIN profile_emails pe ON pe.profile_id = p.id AND pe.active = true
    LEFT JOIN profile_departments pd ON p.id = pd.profile_id AND pd.is_primary = TRUE
    LEFT JOIN profile_request_limits prl ON prl.profile_id = p.id AND prl.active = true
    LEFT JOIN LATERAL (
        SELECT last_active 
        FROM profile_activity 
        WHERE profile_id = p.id 
        ORDER BY created_at DESC 
        LIMIT 1
    ) pa ON true
    WHERE p.id = (SELECT effective_profile_id FROM resolved_profile_ids)
    GROUP BY p.id, p.first_name, p.last_name, p.role, p.active, 
             prl.requests_per_day, p.last_login, pa.last_active, 
             p.created_at, p.updated_at, pd.department_id
    UNION ALL
    -- Return single row with NULL values when profile ID is NULL (for settings-only requests)
    SELECT 
        NULL::uuid as id,
        NULL::text as first_name,
        NULL::text as last_name,
        NULL::text[] as emails,
        NULL::text as primary_email,
        NULL::profile_role as role,
        NULL::boolean as active,
        NULL::integer as req_per_day,
        NULL::timestamptz as last_login,
        NULL::timestamptz as last_active,
        NULL::timestamptz as created_at,
        NULL::timestamptz as updated_at,
        NULL::uuid as primary_department_id
    WHERE (SELECT effective_profile_id FROM resolved_profile_ids) IS NULL
),
dept_data AS (
    -- Departments for the effective profile
    SELECT 
        d.id,
        d.title,
        d.description,
        d.active,
        pd.is_primary
    FROM profile_departments pd
    JOIN departments d ON d.id = pd.department_id
    WHERE pd.profile_id = (SELECT effective_profile_id FROM resolved_profile_ids)
      AND pd.active = true
      AND d.active = true
),
cohort_data AS (
    -- Cohorts for the effective profile
    SELECT DISTINCT
        c.id,
        c.title,
        c.description,
        c.active,
        COALESCE(cdd.department_ids, ARRAY[]::text[]) as department_ids
    FROM cohort_profiles pc
    JOIN cohorts c ON c.id = pc.cohort_id
    LEFT JOIN (
        SELECT 
            cd.cohort_id,
            ARRAY_AGG(cd.department_id::text ORDER BY cd.created_at) as department_ids
        FROM cohort_departments cd
        WHERE cd.active = true
        GROUP BY cd.cohort_id
    ) cdd ON cdd.cohort_id = c.id
    WHERE pc.profile_id = (SELECT effective_profile_id FROM resolved_profile_ids)
      AND pc.active = true
      AND c.active = true
),
sim_data AS (
    -- Simulations for the effective profile's cohorts
    SELECT DISTINCT
        s.id,
        s.title,
        s.description,
        COALESCE(sdd.department_ids, ARRAY[]::text[]) as department_ids,
        COALESCE(
            (SELECT SUM(stl.time_limit_seconds)
             FROM scenario_time_limits stl
             JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
             WHERE stl.simulation_id = s.id AND stl.active = true AND ss.active = true),
            0
        ) as time_limit,
        s.active,
        s.practice_simulation
    FROM simulations s
    JOIN cohort_simulations cs ON cs.simulation_id = s.id
    JOIN cohort_data cd ON cd.id = cs.cohort_id
    LEFT JOIN (
        SELECT 
            sd.simulation_id,
            ARRAY_AGG(sd.department_id::text ORDER BY sd.created_at) as department_ids
        FROM simulation_departments sd
        WHERE sd.active = true
        GROUP BY sd.simulation_id
    ) sdd ON sdd.simulation_id = s.id
    WHERE s.active = true
),
departments_aggregated AS (
    -- Aggregate departments into composite type array
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (d.id, d.title, d.description, d.active, d.is_primary)::types.q_get_profile_context_v4_department
                ORDER BY d.is_primary DESC, d.title
            ),
            '{}'::types.q_get_profile_context_v4_department[]
        ) as departments
    FROM dept_data d
),
cohorts_aggregated AS (
    -- Aggregate cohorts into composite type array
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (c.id, c.title, c.description, c.active, c.department_ids)::types.q_get_profile_context_v4_cohort
                ORDER BY c.title
            ),
            '{}'::types.q_get_profile_context_v4_cohort[]
        ) as cohorts
    FROM cohort_data c
),
simulations_aggregated AS (
    -- Aggregate simulations into composite type array
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (s.id, s.title, s.description, s.department_ids, s.time_limit, s.active, s.practice_simulation)::types.q_get_profile_context_v4_simulation
                ORDER BY s.title
            ),
            '{}'::types.q_get_profile_context_v4_simulation[]
        ) as simulations
    FROM sim_data s
),
earliest_attempt AS (
    -- Earliest attempt across all departments the effective profile belongs to
    SELECT MIN(sa.created_at) as earliest
    -- Get all departments for the effective profile
    FROM profile_departments pd_effective
    -- Get all profiles in those departments
    JOIN profile_departments pd_all ON pd_all.department_id = pd_effective.department_id
        AND pd_all.active = true
    -- Get attempts for those profiles
    JOIN attempt_profiles ap ON ap.profile_id = pd_all.profile_id
        AND ap.active = true
    JOIN simulation_attempts sa ON sa.id = ap.attempt_id
    WHERE pd_effective.profile_id = (SELECT effective_profile_id FROM resolved_profile_ids)
      AND pd_effective.active = true
),
settings_resolution AS (
    -- Resolve settings based on effective profile's department OR department_id parameter
    -- Logic: department-specific → default → any active
    -- When no profile exists, use department_id parameter directly
    WITH default_settings AS (
        -- Get settings with no department links (cross-department/default)
        SELECT s.id as settings_id
        FROM settings s
        WHERE s.active = true
          AND NOT EXISTS (
              SELECT 1 FROM department_settings sd 
              WHERE sd.settings_id = s.id AND sd.active = true
          )
        LIMIT 1
    ),
    effective_profile_department AS (
        -- Get effective profile's primary department (if profile exists)
        SELECT pd.department_id
        FROM resolved_profile_ids rpi
        JOIN profile_departments pd ON pd.profile_id = rpi.effective_profile_id
        WHERE rpi.effective_profile_id IS NOT NULL
          AND pd.is_primary = TRUE 
          AND pd.active = true
        LIMIT 1
    ),
    resolved_department_id AS (
        -- Use profile's department if available, otherwise use department_id parameter
        -- Cast department_id from params to UUID to match effective_profile_department type
        SELECT COALESCE(
            (SELECT department_id FROM effective_profile_department),
            (SELECT CASE 
                WHEN department_id IS NOT NULL AND department_id != '' THEN department_id::uuid
                ELSE NULL::uuid
            END FROM params)
        ) as department_id
    ),
    dept_specific_settings AS (
        -- Get department-specific settings (if department exists from profile OR parameter)
        SELECT s.id as settings_id
        FROM settings s
        JOIN department_settings sd ON sd.settings_id = s.id
        CROSS JOIN resolved_department_id rdi
        WHERE rdi.department_id IS NOT NULL
          AND sd.department_id = rdi.department_id
          AND s.active = true 
          AND sd.active = true
        LIMIT 1
    ),
    selected_settings AS (
        -- Priority: department-specific settings, then default, then any active
        SELECT 
            COALESCE(
                (SELECT settings_id FROM dept_specific_settings),
                (SELECT settings_id FROM default_settings),
                (SELECT id FROM settings WHERE active = true LIMIT 1)
            ) as settings_id
    ),
    settings_auths_data AS (
        -- Get linked auths for this settings
        SELECT 
            ARRAY_AGG(a.id::text ORDER BY a.name) as auth_ids,
            COALESCE(
                ARRAY_AGG(
                    (a.id, a.name, COALESCE(a.description, ''), a.slug)::types.q_get_profile_context_v4_auth
                    ORDER BY a.name
                ),
                '{}'::types.q_get_profile_context_v4_auth[]
            ) as auths
        FROM selected_settings ss
        JOIN setting_auths sa ON sa.settings_id = ss.settings_id AND sa.active = true
        JOIN auth a ON a.id = sa.auth_id AND a.active = true
    ),
    settings_providers_data AS (
        -- Get linked providers for this settings
        SELECT 
            ARRAY_AGG(p.id::text ORDER BY p.name) as provider_ids,
            COALESCE(
                ARRAY_AGG(
                    (p.id, p.name, COALESCE(p.description, ''), p.value)::types.q_get_profile_context_v4_provider
                    ORDER BY p.name
                ),
                '{}'::types.q_get_profile_context_v4_provider[]
            ) as providers
        FROM selected_settings ss
        JOIN setting_providers sp ON sp.settings_id = ss.settings_id AND sp.active = true
        JOIN providers p ON p.id = sp.provider_id AND p.active = true
    ),
    settings_default_guest_data AS (
        -- Get default guest account: try selected settings first, fall back to default settings
        SELECT 
            COALESCE(
                (SELECT sdg.profile_id::text
                 FROM selected_settings ss
                 JOIN settings_default_guest sdg ON sdg.settings_id = ss.settings_id AND sdg.active = true
                 LIMIT 1),
                (SELECT sdg.profile_id::text
                 FROM default_settings ds
                 JOIN settings_default_guest sdg ON sdg.settings_id = ds.settings_id AND sdg.active = true
                 LIMIT 1)
            ) as default_guest_profile_id
    ),
    settings_default_account_data AS (
        -- Get default account: try selected settings first, fall back to default settings
        SELECT 
            COALESCE(
                (SELECT sda.profile_id::text
                 FROM selected_settings ss
                 JOIN settings_default_account sda ON sda.settings_id = ss.settings_id AND sda.active = true
                 LIMIT 1),
                (SELECT sda.profile_id::text
                 FROM default_settings ds
                 JOIN settings_default_account sda ON sda.settings_id = ds.settings_id AND sda.active = true
                 LIMIT 1)
            ) as default_account_profile_id
    )
    SELECT 
        s.id::text as settings_id,
        s.created_at as settings_created_at,
        s.active as settings_active,
        s.name as settings_name,
        s.description as settings_description,
        s.primary_color,
        s.accent,
        s.background,
        s.surface,
        s.success,
        s.warning,
        s.error,
        s.sidebar_background,
        s.sidebar_primary,
        s.chart1,
        s.chart2,
        s.chart3,
        s.chart4,
        s.chart5,
        s.guest_login_enabled,
        s.success_threshold,
        s.warning_threshold,
        s.danger_threshold,
        COALESCE(sad.auth_ids, ARRAY[]::text[]) as settings_auth_ids,
        COALESCE(sad.auths, '{}'::types.q_get_profile_context_v4_auth[]) as settings_auths,
        COALESCE(spd.provider_ids, ARRAY[]::text[]) as settings_provider_ids,
        COALESCE(spd.providers, '{}'::types.q_get_profile_context_v4_provider[]) as settings_providers,
        sdgd.default_guest_profile_id,
        sdad.default_account_profile_id
    FROM selected_settings ss
    JOIN settings s ON s.id = ss.settings_id::uuid
    LEFT JOIN settings_auths_data sad ON true
    LEFT JOIN settings_providers_data spd ON true
    LEFT JOIN settings_default_guest_data sdgd ON true
    LEFT JOIN settings_default_account_data sdad ON true
    LIMIT 1
),
actor_name_computed AS (
    -- Compute actor_name from effective_profile_id if available, else actual_profile_id
    -- This is used for audit logging
    -- Return NULL when both profile IDs are NULL (for settings-only requests)
    SELECT 
        COALESCE(
            (SELECT first_name || ' ' || last_name 
             FROM profiles 
             WHERE id = (SELECT effective_profile_id FROM resolved_profile_ids) LIMIT 1),
            (SELECT first_name || ' ' || last_name 
             FROM profiles 
             WHERE id = (SELECT actual_profile_id FROM resolved_profile_ids) LIMIT 1),
            NULL::text
        ) as actor_name
),
available_sections_computed AS (
    -- Compute available sections based on effective profile's role
    -- Returns top-level sections only - sidebar will show all subsections when parent section is available
    -- Return empty array when role is NULL (for settings-only requests)
    SELECT 
        CASE 
            WHEN epr.role IS NULL THEN ARRAY[]::text[]
            WHEN epr.role = 'superadmin'::profile_role THEN ARRAY['home', 'leaderboard', 'practice', 'analytics', 'create', 'management', 'engine', 'system', 'health', 'benchmark', 'settings']::text[]
            WHEN epr.role = 'admin'::profile_role THEN ARRAY['home', 'leaderboard', 'practice', 'analytics', 'create', 'management', 'engine', 'settings']::text[]
            WHEN epr.role = 'instructional'::profile_role THEN ARRAY['home', 'leaderboard', 'practice', 'analytics', 'create']::text[]
            WHEN epr.role = 'member'::profile_role THEN ARRAY['home', 'leaderboard', 'practice']::text[]
            ELSE ARRAY['practice']::text[]  -- guest
        END as available_sections
    FROM effective_profile_role epr
),
redirect_path_computed AS (
    -- Compute redirect path based on effective profile's role
    -- Replicates get_redirect_path_for_role logic
    -- Return NULL when role is NULL (for settings-only requests)
    SELECT 
        CASE 
            WHEN epr.role IS NULL THEN NULL::text
            WHEN epr.role = 'guest'::profile_role THEN '/practice'::text
            WHEN epr.role = 'member'::profile_role THEN '/home'::text
            WHEN epr.role = 'instructional'::profile_role THEN '/analytics/dashboard'::text
            WHEN epr.role = 'admin'::profile_role THEN '/analytics/dashboard'::text
            WHEN epr.role = 'superadmin'::profile_role THEN '/analytics/dashboard'::text
            ELSE '/home'::text
        END as redirect_path
    FROM effective_profile_role epr
),
department_ids_computed AS (
    -- Extract department IDs from dept_data
    SELECT 
        COALESCE(
            ARRAY_AGG(d.id::text ORDER BY d.is_primary DESC, d.title),
            ARRAY[]::text[]
        ) as department_ids
    FROM dept_data d
),
cohort_ids_computed AS (
    -- Extract cohort IDs from cohort_data
    SELECT 
        COALESCE(
            ARRAY_AGG(c.id::text ORDER BY c.title),
            ARRAY[]::text[]
        ) as cohort_ids
    FROM cohort_data c
),
simulation_ids_computed AS (
    -- Extract simulation IDs from sim_data
    SELECT 
        COALESCE(
            ARRAY_AGG(s.id::text ORDER BY s.title),
            ARRAY[]::text[]
        ) as simulation_ids
    FROM sim_data s
),
drafts_data AS (
    -- Get all drafts for effective profile
    SELECT 
        d.id,
        d.resource_type::text as resource_type,
        d.payload,
        d.version,
        d.updated_at
    FROM drafts d
    WHERE d.profile_id = (SELECT effective_profile_id FROM resolved_profile_ids)
),
drafts_aggregated AS (
    -- Aggregate drafts as array of composite types
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (dd.id, dd.resource_type, dd.payload, dd.version, dd.updated_at)::types.q_get_profile_context_v4_draft
                ORDER BY dd.updated_at DESC
            ),
            '{}'::types.q_get_profile_context_v4_draft[]
        ) as drafts
    FROM drafts_data dd
)
SELECT 
    -- Emulation authorization flag
    ev.is_authorized::boolean as is_authorized,
    -- Authorization check fields (for default-account and guest login validation)
    (SELECT guest_login_enabled FROM selected_settings_for_auth) as guest_login_enabled,
    (SELECT count FROM active_departments_count) as active_departments_count,
    COALESCE((SELECT count FROM department_auth_providers_count), 0) as department_auth_providers_count,
    COALESCE((SELECT count FROM default_settings_auth_providers_count), 0) as default_settings_auth_providers_count,
    COALESCE((SELECT count FROM departments_without_auth_providers_count), 0) as departments_without_auth_providers_count,
    (SELECT department_exists FROM department_exists_check) as department_exists,
    -- Actual profile fields (prefixed with actual_)
    apd.id as actual_id,
    apd.first_name as actual_first_name,
    apd.last_name as actual_last_name,
    COALESCE(apd.emails, ARRAY[]::text[]) as actual_emails,
    apd.primary_email as actual_primary_email,
    apd.role as actual_role,
    apd.active as actual_active,
    apd.req_per_day as actual_req_per_day,
    apd.last_login as actual_last_login,
    apd.last_active as actual_last_active,
    apd.created_at as actual_created_at,
    apd.updated_at as actual_updated_at,
    apd.primary_department_id as actual_primary_department_id,
    -- Effective profile fields (unprefixed)
    epd.id,
    epd.first_name,
    epd.last_name,
    COALESCE(epd.emails, ARRAY[]::text[]) as emails,
    epd.primary_email,
    epd.role,
    epd.active,
    epd.req_per_day,
    epd.last_login,
    epd.last_active,
    epd.created_at,
    epd.updated_at,
    epd.primary_department_id,
    -- Context data (based on effective profile) - using composite types
    da.departments as departments,
    ca.cohorts as cohorts,
    sa.simulations as simulations,
    (SELECT earliest FROM earliest_attempt) as earliest_attempt_date,
    (SELECT scoped_roles FROM scoped_roles_computed) as scoped_roles,
    -- Settings data (all fields prefixed with settings_)
    sr.settings_id as settings_id,
    sr.settings_created_at as settings_created_at,
    sr.settings_active as settings_active,
    sr.settings_name as settings_name,
    sr.settings_description as settings_description,
    sr.primary_color as settings_primary_color,
    sr.accent as settings_accent,
    sr.background as settings_background,
    sr.surface as settings_surface,
    sr.success as settings_success,
    sr.warning as settings_warning,
    sr.error as settings_error,
    sr.sidebar_background as settings_sidebar_background,
    sr.sidebar_primary as settings_sidebar_primary,
    sr.chart1 as settings_chart1,
    sr.chart2 as settings_chart2,
    sr.chart3 as settings_chart3,
    sr.chart4 as settings_chart4,
    sr.chart5 as settings_chart5,
    sr.guest_login_enabled as settings_guest_login_enabled,
    sr.success_threshold as settings_success_threshold,
    sr.warning_threshold as settings_warning_threshold,
    sr.danger_threshold as settings_danger_threshold,
    sr.settings_auth_ids as settings_auth_ids,
    sr.settings_auths as settings_auths,
    sr.settings_provider_ids as settings_provider_ids,
    sr.settings_providers as settings_providers,
    sr.default_guest_profile_id as settings_default_guest_profile_id,
    sr.default_account_profile_id as settings_default_account_profile_id,
    -- Computed fields
    (SELECT available_sections FROM available_sections_computed) as available_sections,
    (SELECT redirect_path FROM redirect_path_computed) as redirect_path,
    (SELECT department_ids FROM department_ids_computed) as department_ids,
    (SELECT cohort_ids FROM cohort_ids_computed) as cohort_ids,
    (SELECT simulation_ids FROM simulation_ids_computed) as simulation_ids,
    (SELECT drafts FROM drafts_aggregated) as drafts,
    -- Return empty theme tokens struct for type introspection (Python will override with computed values)
    -- 37 fields: background, foreground, card, card_foreground, popover, popover_foreground, primary_color, primary_foreground, secondary, secondary_foreground, muted, muted_foreground, accent, accent_foreground, destructive, border, input, ring, success, success_foreground, warning, warning_foreground, info, info_foreground, chart1, chart2, chart3, chart4, chart5, sidebar, sidebar_foreground, sidebar_primary, sidebar_primary_foreground, sidebar_accent, sidebar_accent_foreground, sidebar_border, sidebar_ring
    ('', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '')::types.q_get_profile_context_v4_theme_tokens as settings_tokens,
    (SELECT actor_name FROM actor_name_computed) as actor_name
FROM params
CROSS JOIN emulation_validation ev
CROSS JOIN resolved_profile_ids rpi
CROSS JOIN actual_profile_data apd
CROSS JOIN effective_profile_data epd
CROSS JOIN scoped_roles_computed src
CROSS JOIN settings_resolution sr
CROSS JOIN departments_aggregated da
CROSS JOIN cohorts_aggregated ca
CROSS JOIN simulations_aggregated sa
CROSS JOIN actor_name_computed anc
CROSS JOIN available_sections_computed asc_computed
CROSS JOIN redirect_path_computed rpc
CROSS JOIN department_ids_computed dic
CROSS JOIN cohort_ids_computed cic
CROSS JOIN simulation_ids_computed sic
CROSS JOIN drafts_aggregated da_drafts
WHERE (
    -- Standard case: require authorization and profile IDs
    (ev.is_authorized = true 
     AND rpi.actual_profile_id IS NOT NULL 
     AND rpi.effective_profile_id IS NOT NULL)
    OR
    -- Settings-only case: allow NULL profile IDs when department_id is provided (for login page theme)
    (rpi.actual_profile_id IS NULL 
     AND rpi.effective_profile_id IS NULL
     AND params.department_id IS NOT NULL
     AND params.department_id != '')
     -- Note: settings_id check happens in Python code, not here
)
$$;


--
-- Name: api_get_profile_detail_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_profile_detail_v4(target_profile_id uuid, profile_id uuid) RETURNS TABLE(profile_exists boolean, profile_id uuid, first_name text, last_name text, name text, emails text[], primary_email text, role text, active boolean, requests_per_day integer, cohort_ids uuid[], department_ids uuid[], primary_department_id uuid, can_edit boolean, valid_department_ids uuid[], valid_cohort_ids uuid[], departments types.q_get_profile_detail_v4_department[], cohorts types.q_get_profile_detail_v4_cohort[], actor_name text)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT target_profile_id AS target_profile_id,
           profile_id AS profile_id
),
profile_exists_check AS (
    -- Check if profile exists independently of access control
    SELECT EXISTS(
        SELECT 1 FROM profiles WHERE id = (SELECT target_profile_id FROM params)
    )::boolean as profile_exists
),
resolve_current_profile_id AS (
    SELECT profile_id AS resolved_profile_id FROM params
),
current_user_role AS (
    SELECT role FROM resolve_current_profile_id rpi
    JOIN profiles p ON p.id = rpi.resolved_profile_id
),
actor_profile AS (
    SELECT 
        p.first_name || ' ' || p.last_name as actor_name
    FROM resolve_current_profile_id rpi
    JOIN profiles p ON p.id = rpi.resolved_profile_id
    WHERE rpi.resolved_profile_id IS NOT NULL
),
target_profile AS (
    SELECT 
        p.id,
        p.first_name,
        p.last_name,
        ARRAY_AGG(pe.email ORDER BY pe.is_primary DESC, pe.created_at) FILTER (WHERE pe.active = true) as emails,
        (SELECT email FROM profile_emails WHERE profile_id = p.id AND is_primary = true AND active = true LIMIT 1) as primary_email,
        p.role,
        p.active,
        prl.requests_per_day,
        COALESCE(p.first_name || ' ' || p.last_name, '') as name
    FROM profiles p
    LEFT JOIN profile_emails pe ON pe.profile_id = p.id AND pe.active = true
    LEFT JOIN profile_request_limits prl ON prl.profile_id = p.id AND prl.active = true
    WHERE p.id = (SELECT target_profile_id FROM params)
    GROUP BY p.id, p.first_name, p.last_name, p.role, p.active, prl.requests_per_day
),
role_visibility_check AS (
    -- Check if current user can see target profile based on role hierarchy
    SELECT 
        tp.*,
        CASE 
            WHEN cur.role = 'superadmin'::profile_role THEN true
            WHEN cur.role = 'admin'::profile_role AND tp.role IN ('admin'::profile_role, 'instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role) THEN true
            WHEN cur.role = 'instructional'::profile_role AND tp.role IN ('instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role) THEN true
            WHEN cur.role = 'member'::profile_role AND tp.role IN ('member'::profile_role, 'guest'::profile_role) THEN true
            WHEN cur.role = 'guest'::profile_role AND tp.role = 'guest'::profile_role THEN true
            ELSE false
        END as can_see
    FROM target_profile tp
    CROSS JOIN current_user_role cur
),
visible_profile AS (
    SELECT * FROM role_visibility_check WHERE can_see = true
),
target_profile_cohorts AS (
    SELECT 
        ARRAY_AGG(cp.cohort_id ORDER BY c.title) as cohort_ids
    FROM cohort_profiles cp
    JOIN cohorts c ON c.id = cp.cohort_id
    WHERE cp.profile_id = (SELECT target_profile_id FROM params) AND cp.active = true AND c.active = true
),
target_profile_departments AS (
    SELECT 
        ARRAY_AGG(pd.department_id ORDER BY d.title) as department_ids,
        (SELECT department_id FROM profile_departments WHERE profile_id = (SELECT target_profile_id FROM params) AND is_primary = TRUE AND active = true LIMIT 1) as primary_department_id
    FROM profile_departments pd
    JOIN departments d ON d.id = pd.department_id
    WHERE pd.profile_id = (SELECT target_profile_id FROM params) AND pd.active = true AND d.active = true
),
all_cohort_ids AS (
    SELECT DISTINCT c.id as cohort_id
    FROM cohorts c
    WHERE c.active = true
),
all_cohorts_data AS (
    SELECT 
        c.id as cohort_id,
        c.title as name,
        COALESCE(c.description, '') as description
    FROM cohorts c
    WHERE c.id IN (SELECT cohort_id FROM all_cohort_ids)
),
current_user_departments AS (
    SELECT DISTINCT pd.department_id
    FROM resolve_current_profile_id rpi
    JOIN profile_departments pd ON pd.profile_id = rpi.resolved_profile_id AND pd.active = true
),
valid_departments_data AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM resolve_current_profile_id rpi
    LEFT JOIN profile_departments pd ON pd.profile_id = rpi.resolved_profile_id AND pd.active = true
    LEFT JOIN departments d ON d.id = pd.department_id AND d.active = true
    WHERE rpi.resolved_profile_id IS NOT NULL
),
can_edit_check AS (
    SELECT 
        CASE 
            WHEN cur.role = 'superadmin'::profile_role THEN true
            WHEN cur.role = 'admin'::profile_role AND vp.role IN ('admin'::profile_role, 'instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role) THEN true
            WHEN cur.role = 'instructional'::profile_role AND vp.role IN ('instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role) THEN true
            WHEN cur.role = 'member'::profile_role AND vp.role IN ('member'::profile_role, 'guest'::profile_role) THEN true
            ELSE false
        END as can_edit
    FROM visible_profile vp
    CROSS JOIN current_user_role cur
),
valid_departments_agg AS (
    SELECT 
        COALESCE(ARRAY_AGG(vdd.department_id ORDER BY vdd.name) FILTER (WHERE vdd.department_id IS NOT NULL), ARRAY[]::uuid[]) as valid_department_ids,
        COALESCE(
            ARRAY_AGG(
                (vdd.department_id, vdd.name, vdd.description)::types.q_get_profile_detail_v4_department
                ORDER BY vdd.name
            ) FILTER (WHERE vdd.department_id IS NOT NULL),
            '{}'::types.q_get_profile_detail_v4_department[]
        ) as departments
    FROM valid_departments_data vdd
    WHERE vdd.department_id IS NOT NULL
),
all_cohorts_agg AS (
    SELECT 
        COALESCE(ARRAY_AGG(acd.cohort_id ORDER BY acd.name) FILTER (WHERE acd.cohort_id IS NOT NULL), ARRAY[]::uuid[]) as valid_cohort_ids,
        COALESCE(
            ARRAY_AGG(
                (acd.cohort_id, acd.name, acd.description)::types.q_get_profile_detail_v4_cohort
                ORDER BY acd.name
            ) FILTER (WHERE acd.cohort_id IS NOT NULL),
            '{}'::types.q_get_profile_detail_v4_cohort[]
        ) as cohorts
    FROM all_cohorts_data acd
    WHERE acd.cohort_id IS NOT NULL
)
SELECT 
    -- Profile existence check (always returned)
    pec.profile_exists::boolean as profile_exists,
    -- Top-level profile fields
    vp.id as profile_id,
    vp.first_name,
    vp.last_name,
    vp.name,
    COALESCE(vp.emails, ARRAY[]::text[]) as emails,
    vp.primary_email,
    vp.role,
    vp.active,
    vp.requests_per_day,
    COALESCE(tpc.cohort_ids, ARRAY[]::uuid[]) as cohort_ids,
    COALESCE(tpd.department_ids, ARRAY[]::uuid[]) as department_ids,
    tpd.primary_department_id,
    COALESCE(cec.can_edit, false) as can_edit,
    COALESCE(vda.valid_department_ids, ARRAY[]::uuid[]) as valid_department_ids,
    COALESCE(aca.valid_cohort_ids, ARRAY[]::uuid[]) as valid_cohort_ids,
    -- Aggregated arrays of composite types
    COALESCE(vda.departments, '{}'::types.q_get_profile_detail_v4_department[]) as departments,
    COALESCE(aca.cohorts, '{}'::types.q_get_profile_detail_v4_cohort[]) as cohorts,
    -- Actor name
    ap.actor_name
FROM profile_exists_check pec
CROSS JOIN actor_profile ap
CROSS JOIN valid_departments_agg vda
CROSS JOIN all_cohorts_agg aca
LEFT JOIN visible_profile vp ON pec.profile_exists = true
LEFT JOIN target_profile_cohorts tpc ON pec.profile_exists = true
LEFT JOIN target_profile_departments tpd ON pec.profile_exists = true
LEFT JOIN can_edit_check cec ON pec.profile_exists = true
LIMIT 1
$$;


--
-- Name: api_get_profile_new_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_profile_new_v4(profile_id uuid) RETURNS TABLE(first_name text, last_name text, emails text[], role text, requests_per_day integer, primary_department_id uuid, active boolean, can_edit boolean, valid_department_ids uuid[], valid_cohort_ids uuid[], role_options text[], departments types.q_get_profile_new_v4_department[], cohorts types.q_get_profile_new_v4_cohort[], actor_name text)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id
),
resolve_profile_id AS (
    SELECT profile_id AS resolved_profile_id FROM params
),
user_departments AS (
    SELECT DISTINCT pd.department_id
    FROM resolve_profile_id rpi
    JOIN profile_departments pd ON pd.profile_id = rpi.resolved_profile_id AND pd.active = true
),
valid_departments_data AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM departments d
    JOIN resolve_profile_id rpi ON true
    JOIN profile_departments pd ON d.id = pd.department_id
    WHERE pd.profile_id = rpi.resolved_profile_id AND d.active = true
),
all_cohort_ids AS (
    SELECT DISTINCT c.id as cohort_id
    FROM cohorts c
    WHERE c.active = true
),
all_cohorts_data AS (
    SELECT 
        c.id as cohort_id,
        c.title as name,
        COALESCE(c.description, '') as description
    FROM cohorts c
    WHERE c.id IN (SELECT cohort_id FROM all_cohort_ids)
),
profile_data AS (
    SELECT role as user_role 
    FROM resolve_profile_id rpi
    JOIN profiles p ON p.id = rpi.resolved_profile_id
),
primary_department_id AS (
    SELECT department_id
    FROM resolve_profile_id rpi
    JOIN profile_departments pd ON pd.profile_id = rpi.resolved_profile_id
    WHERE pd.is_primary = TRUE AND pd.active = true
    LIMIT 1
),
actor_profile AS (
    SELECT 
        p.first_name || ' ' || p.last_name as actor_name
    FROM resolve_profile_id rpi
    JOIN profiles p ON p.id = rpi.resolved_profile_id
),
valid_departments_agg AS (
    SELECT 
        ARRAY_AGG(vdd.department_id ORDER BY vdd.name) as valid_department_ids,
        COALESCE(
            ARRAY_AGG(
                (vdd.department_id, vdd.name, vdd.description)::types.q_get_profile_new_v4_department
                ORDER BY vdd.name
            ) FILTER (WHERE vdd.department_id IS NOT NULL),
            '{}'::types.q_get_profile_new_v4_department[]
        ) as departments
    FROM valid_departments_data vdd
),
all_cohorts_agg AS (
    SELECT 
        ARRAY_AGG(acd.cohort_id ORDER BY acd.name) as valid_cohort_ids,
        COALESCE(
            ARRAY_AGG(
                (acd.cohort_id, acd.name, acd.description)::types.q_get_profile_new_v4_cohort
                ORDER BY acd.name
            ) FILTER (WHERE acd.cohort_id IS NOT NULL),
            '{}'::types.q_get_profile_new_v4_cohort[]
        ) as cohorts
    FROM all_cohorts_data acd
)
SELECT 
    -- Basic fields (empty defaults for creation)
    ''::text as first_name,
    ''::text as last_name,
    ARRAY['']::text[] as emails,
    'instructional'::text as role,  -- Default role
    NULL::integer as requests_per_day,  -- Unlimited by default
    pdi.department_id as primary_department_id,
    true::boolean as active,
    true::boolean as can_edit,  -- User can always create profile
    -- Metadata
    COALESCE(vda.valid_department_ids, ARRAY[]::uuid[]) as valid_department_ids,
    COALESCE(aca.valid_cohort_ids, ARRAY[]::uuid[]) as valid_cohort_ids,
    ARRAY['superadmin', 'admin', 'instructional', 'member', 'guest']::text[] as role_options,
    -- Mappings (now arrays)
    COALESCE(vda.departments, '{}'::types.q_get_profile_new_v4_department[]) as departments,
    COALESCE(aca.cohorts, '{}'::types.q_get_profile_new_v4_cohort[]) as cohorts,
    -- Actor name
    ap.actor_name
FROM valid_departments_agg vda
CROSS JOIN all_cohorts_agg aca
CROSS JOIN profile_data pr
CROSS JOIN actor_profile ap
LEFT JOIN primary_department_id pdi ON true
LIMIT 1
$$;


--
-- Name: api_get_provider_detail_v4(uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_provider_detail_v4(provider_id uuid, profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(provider_exists boolean, provider_id uuid, name text, description text, value text, active boolean, created_at timestamp with time zone, updated_at timestamp with time zone, base_url text, can_edit boolean, can_delete boolean, actor_name text, draft_version integer)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        provider_id AS provider_id, 
        profile_id AS profile_id,
        draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'providers'::draft_resource_type
    LIMIT 1
),
provider_exists_check AS (
    -- Check if provider exists independently of access control
    SELECT EXISTS(
        SELECT 1 FROM providers WHERE id = (SELECT provider_id FROM params)
    )::boolean as provider_exists
),
actor_profile AS (
    SELECT 
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
provider_data AS (
    SELECT 
        p.id as provider_id,
        p.name,
        p.description,
        p.value,
        p.active,
        p.created_at,
        p.updated_at,
        COALESCE(pe.base_url, '') as base_url
    FROM providers p
    LEFT JOIN provider_endpoints pe ON pe.provider_id = p.id AND pe.active = true
    WHERE p.id = (SELECT provider_id FROM params)
),
user_profile AS (
    SELECT role 
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
check_usage AS (
    -- Check if provider is used by models
    SELECT EXISTS(
        SELECT 1 FROM models m 
        WHERE m.provider_id = (SELECT provider_id FROM params) AND m.active = true
    ) as is_used
)
SELECT 
    pec.provider_exists::boolean as provider_exists,
    pd.provider_id,
    -- Merge draft payload over existing provider data if draft_id provided
    COALESCE(
        (SELECT payload->>'name' FROM draft_payload_data),
        pd.name
    ) as name,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        pd.description
    ) as description,
    COALESCE(
        (SELECT payload->>'value' FROM draft_payload_data),
        pd.value
    ) as value,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        pd.active
    ) as active,
    pd.created_at,
    pd.updated_at,
    pd.base_url,
    CASE 
        WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
        ELSE false
    END as can_edit,
    CASE 
        WHEN cu.is_used THEN false
        WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
        ELSE false
    END as can_delete,
    ap.actor_name::text as actor_name,
    COALESCE((SELECT draft_version FROM draft_payload_data), 0) as draft_version
FROM provider_exists_check pec
LEFT JOIN provider_data pd ON pec.provider_exists = true
CROSS JOIN user_profile up
CROSS JOIN check_usage cu
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_get_provider_new_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_provider_new_v4(profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(provider_id text, name text, description text, value text, active boolean, created_at timestamp with time zone, updated_at timestamp with time zone, base_url text, can_edit boolean, can_delete boolean, actor_name text, draft_version integer)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        profile_id AS profile_id,
        draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'providers'::draft_resource_type
    LIMIT 1
),
actor_profile AS (
    SELECT 
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
user_profile AS (
    SELECT role as user_role 
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
)
SELECT 
    ''::text as provider_id,
    -- Default values for new provider (merged with draft payload if draft_id provided)
    COALESCE(
        (SELECT payload->>'name' FROM draft_payload_data),
        ''::text
    ) as name,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        ''::text
    ) as description,
    COALESCE(
        (SELECT payload->>'value' FROM draft_payload_data),
        ''::text
    ) as value,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        true::boolean
    ) as active,
    NOW()::timestamptz as created_at,
    NOW()::timestamptz as updated_at,
    ''::text as base_url,
    CASE 
        WHEN up.user_role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
        ELSE false
    END::boolean as can_edit,
    CASE 
        WHEN up.user_role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
        ELSE false
    END::boolean as can_delete,
    ap.actor_name::text as actor_name,
    COALESCE((SELECT draft_version FROM draft_payload_data), 0) as draft_version
FROM user_profile up
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_get_randomization_data_v4(uuid[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_randomization_data_v4(department_ids uuid[], scenario_id uuid) RETURNS TABLE(personas types.get_randomization_data_persona_v4[], documents types.get_randomization_data_document_v4[], parameters types.get_randomization_data_parameter_v4[], parameter_items types.get_randomization_data_parameter_item_v4[], document_parameter_items types.get_randomization_data_document_parameter_item_v4[], persona_ids text[], document_ids text[], parameter_item_ids text[])
    LANGUAGE sql STABLE
    AS $$
WITH filtered_personas AS (
    SELECT DISTINCT p.id, p.name, COALESCE(p.description, '') as description
    FROM personas p
    LEFT JOIN persona_departments pd ON pd.persona_id = p.id AND pd.active = true
    WHERE p.active = true
    GROUP BY p.id, p.name, p.description
    HAVING 
        -- If department_ids provided and not empty, filter by departments; otherwise include all
        (COALESCE(array_length(api_get_randomization_data_v4.department_ids, 1), 0) = 0 OR
         COUNT(pd.persona_id) FILTER (WHERE pd.department_id = ANY(api_get_randomization_data_v4.department_ids)) > 0
         OR NOT EXISTS (SELECT 1 FROM persona_departments pd2 WHERE pd2.persona_id = p.id AND pd2.active = true))
),
filtered_documents AS (
    SELECT DISTINCT d.id, d.name, NULL::text as type, u.file_path
    FROM documents d
    INNER JOIN document_uploads du ON du.document_id = d.id AND du.active = true
    INNER JOIN uploads u ON u.id = du.upload_id AND u.file_path IS NOT NULL
    LEFT JOIN document_departments dd ON dd.document_id = d.id AND dd.active = true
    WHERE d.active = true
    GROUP BY d.id, d.name, u.file_path
    HAVING 
        -- If department_ids provided and not empty, filter by departments; otherwise include all
        (COALESCE(array_length(api_get_randomization_data_v4.department_ids, 1), 0) = 0 OR
         COUNT(dd.document_id) FILTER (WHERE dd.department_id = ANY(api_get_randomization_data_v4.department_ids)) > 0
         OR NOT EXISTS (SELECT 1 FROM document_departments dd2 WHERE dd2.document_id = d.id AND dd2.active = true))
),
filtered_parameters AS (
    SELECT DISTINCT 
        p.id, 
        p.name, 
        p.description, 
        p.document_parameter,
        p.persona_parameter
    FROM parameters p
    JOIN parameter_fields fp ON fp.parameter_id = p.id AND fp.active = true
    LEFT JOIN field_departments fd ON fd.field_id = fp.field_id AND fd.active = true
    WHERE p.active = true
    GROUP BY p.id, p.name, p.description, p.document_parameter, p.persona_parameter
    HAVING 
        -- If department_ids provided and not empty, filter by departments; otherwise include all
        (COALESCE(array_length(api_get_randomization_data_v4.department_ids, 1), 0) = 0 OR
         COUNT(fd.field_id) FILTER (WHERE fd.department_id = ANY(api_get_randomization_data_v4.department_ids)) > 0
         OR NOT EXISTS (SELECT 1 FROM field_departments fd2 
                      JOIN parameter_fields fp2 ON fp2.field_id = fd2.field_id 
                      WHERE fp2.parameter_id = p.id AND fp2.active = true AND fd2.active = true))
),
parameter_items_data AS (
    SELECT DISTINCT f.id, f.name, f.description, pf.parameter_id
    FROM fields f
    JOIN parameter_fields pf ON pf.field_id = f.id AND pf.active = true
    JOIN filtered_parameters fp2 ON fp2.id = pf.parameter_id
    LEFT JOIN field_departments fd ON fd.field_id = f.id AND fd.active = true
    WHERE f.active = true
    GROUP BY f.id, f.name, f.description, pf.parameter_id
    HAVING 
        -- If department_ids provided and not empty, filter by departments; otherwise include all
        (COALESCE(array_length(api_get_randomization_data_v4.department_ids, 1), 0) = 0 OR
         COUNT(fd.field_id) FILTER (WHERE fd.department_id = ANY(api_get_randomization_data_v4.department_ids)) > 0
         OR NOT EXISTS (SELECT 1 FROM field_departments fd2 WHERE fd2.field_id = f.id AND fd2.active = true))
),
document_parameter_items_junction AS (
    SELECT DISTINCT df.document_id, df.field_id as parameter_item_id
    FROM document_fields df
    JOIN filtered_documents fd ON fd.id = df.document_id
    JOIN parameter_items_data pid ON pid.id = df.field_id
    WHERE df.active = true
),
scenario_persona_links AS (
    SELECT ARRAY_AGG(persona_id::text ORDER BY persona_id) as persona_ids
    FROM scenario_personas
    WHERE scenario_id = api_get_randomization_data_v4.scenario_id AND active = true
),
scenario_document_links AS (
    SELECT ARRAY_AGG(document_id::text ORDER BY document_id) as document_ids
    FROM scenario_documents
    WHERE scenario_id = api_get_randomization_data_v4.scenario_id AND active = true
),
scenario_parameter_item_links AS (
    SELECT ARRAY_AGG(field_id::text ORDER BY field_id) as parameter_item_ids
    FROM scenario_fields
    WHERE scenario_id = api_get_randomization_data_v4.scenario_id AND active = true
),
personas_agg AS (
    SELECT COALESCE(
        ARRAY_AGG(ROW(fp.id, fp.name, fp.description)::types.get_randomization_data_persona_v4 ORDER BY fp.id),
        ARRAY[]::types.get_randomization_data_persona_v4[]
    ) as personas
    FROM filtered_personas fp
),
documents_agg AS (
    SELECT COALESCE(
        ARRAY_AGG(ROW(fd.id, fd.name, fd.type, fd.file_path)::types.get_randomization_data_document_v4 ORDER BY fd.id),
        ARRAY[]::types.get_randomization_data_document_v4[]
    ) as documents
    FROM filtered_documents fd
),
parameters_agg AS (
    SELECT COALESCE(
        ARRAY_AGG(ROW(fp2.id, fp2.name, fp2.description, fp2.document_parameter, fp2.persona_parameter)::types.get_randomization_data_parameter_v4 ORDER BY fp2.id),
        ARRAY[]::types.get_randomization_data_parameter_v4[]
    ) as parameters
    FROM filtered_parameters fp2
),
parameter_items_agg AS (
    SELECT COALESCE(
        ARRAY_AGG(ROW(pid.id, pid.name, pid.description, pid.parameter_id)::types.get_randomization_data_parameter_item_v4 ORDER BY pid.id),
        ARRAY[]::types.get_randomization_data_parameter_item_v4[]
    ) as parameter_items
    FROM parameter_items_data pid
),
document_parameter_items_agg AS (
    SELECT COALESCE(
        ARRAY_AGG(ROW(dpi.document_id, dpi.parameter_item_id)::types.get_randomization_data_document_parameter_item_v4 ORDER BY dpi.document_id, dpi.parameter_item_id),
        ARRAY[]::types.get_randomization_data_document_parameter_item_v4[]
    ) as document_parameter_items
    FROM document_parameter_items_junction dpi
)
SELECT 
    pa.personas,
    da.documents,
    pra.parameters,
    pia.parameter_items,
    dpia.document_parameter_items,
    COALESCE((SELECT persona_ids FROM scenario_persona_links), ARRAY[]::text[]) as persona_ids,
    COALESCE((SELECT document_ids FROM scenario_document_links), ARRAY[]::text[]) as document_ids,
    COALESCE((SELECT parameter_item_ids FROM scenario_parameter_item_links), ARRAY[]::text[]) as parameter_item_ids
FROM personas_agg pa
CROSS JOIN documents_agg da
CROSS JOIN parameters_agg pra
CROSS JOIN parameter_items_agg pia
CROSS JOIN document_parameter_items_agg dpia
$$;


--
-- Name: api_get_randomization_ranges_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_randomization_ranges_v4(scenario_id uuid) RETURNS TABLE(persona_min integer, persona_max integer, document_min integer, document_max integer, parameter_min integer, parameter_max integer, field_ranges_json jsonb)
    LANGUAGE sql STABLE
    AS $$
SELECT 
    COALESCE(
        (SELECT min_count FROM scenario_persona_ranges WHERE scenario_id = api_get_randomization_ranges_v4.scenario_id),
        1
    ) as persona_min,
    COALESCE(
        (SELECT max_count FROM scenario_persona_ranges WHERE scenario_id = api_get_randomization_ranges_v4.scenario_id),
        3
    ) as persona_max,
    COALESCE(
        (SELECT min_count FROM scenario_document_ranges WHERE scenario_id = api_get_randomization_ranges_v4.scenario_id),
        0
    ) as document_min,
    COALESCE(
        (SELECT max_count FROM scenario_document_ranges WHERE scenario_id = api_get_randomization_ranges_v4.scenario_id),
        3
    ) as document_max,
    COALESCE(
        (SELECT min_count FROM scenario_parameter_ranges WHERE scenario_id = api_get_randomization_ranges_v4.scenario_id),
        0
    ) as parameter_min,
    COALESCE(
        (SELECT max_count FROM scenario_parameter_ranges WHERE scenario_id = api_get_randomization_ranges_v4.scenario_id),
        3
    ) as parameter_max,
    COALESCE(
        (
            SELECT jsonb_object_agg(
                parameter_id::text,
                jsonb_build_object(
                    'min', min_count,
                    'max', max_count
                )
            )
            FROM scenario_field_ranges
            WHERE scenario_id = api_get_randomization_ranges_v4.scenario_id
        ),
        '{}'::jsonb
    ) as field_ranges_json
$$;


--
-- Name: api_get_realm_name_for_department_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_realm_name_for_department_v4(department_id uuid) RETURNS TABLE(realm_name text)
    LANGUAGE sql STABLE
    AS $$
SELECT 
    CASE 
        -- No department → master realm
        WHEN department_id IS NULL THEN 'master'::text
        -- Check if department-specific settings has keys
        WHEN EXISTS (
            SELECT 1 
            FROM department_settings ds
            JOIN settings s ON s.id = ds.settings_id AND s.active = true
            JOIN setting_auth_keys sak ON sak.settings_id = s.id AND sak.active = true
            WHERE ds.department_id = api_get_realm_name_for_department_v4.department_id AND ds.active = true
        ) THEN (
            -- Department settings has keys → use settings_id as realm
            SELECT s.id::text
            FROM department_settings ds
            JOIN settings s ON s.id = ds.settings_id AND s.active = true
            WHERE ds.department_id = api_get_realm_name_for_department_v4.department_id AND ds.active = true
            LIMIT 1
        )
        -- No keys in dept settings → use master realm
        ELSE 'master'::text
    END as realm_name
$$;


--
-- Name: api_get_reports_bundle_v4(text, text, uuid, uuid[], uuid[], public.profile_role[], text[], uuid[], uuid[], uuid[], text, text, text, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_reports_bundle_v4(start_date text, end_date text, profile_id uuid, cohort_ids uuid[] DEFAULT ARRAY[]::uuid[], department_ids uuid[] DEFAULT ARRAY[]::uuid[], roles public.profile_role[] DEFAULT ARRAY[]::public.profile_role[], simulation_filters text[] DEFAULT NULL::text[], profile_ids uuid[] DEFAULT ARRAY[]::uuid[], simulation_ids uuid[] DEFAULT ARRAY[]::uuid[], scenario_ids uuid[] DEFAULT ARRAY[]::uuid[], search text DEFAULT NULL::text, sort_by text DEFAULT 'averageScore'::text, sort_order text DEFAULT 'desc'::text, page integer DEFAULT 0, page_size integer DEFAULT 100) RETURNS TABLE(actor_name text, data types.q_reports_bundle_v4_profile[], total_count bigint, page integer, page_size integer, total_pages bigint, profile_options types.q_reports_bundle_v4_filter_option[], simulation_options types.q_reports_bundle_v4_filter_option[], scenario_options types.q_reports_bundle_v4_filter_option[], scenarios types.q_reports_bundle_v4_scenario[], simulations types.q_reports_bundle_v4_simulation[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        (start_date::timestamptz) AS start_date,
        (end_date::timestamptz) AS end_date,
        profile_id AS profile_id,
        COALESCE(cohort_ids, ARRAY[]::uuid[]) AS cohort_ids,
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids,
        COALESCE(roles, ARRAY[]::profile_role[]) AS roles,
        CASE 
            WHEN simulation_filters IS NULL OR cardinality(simulation_filters) = 0 
            THEN ARRAY['general']::text[]
            ELSE simulation_filters
        END AS simulation_filters,
        COALESCE(profile_ids, ARRAY[]::uuid[]) AS profile_ids,
        COALESCE(simulation_ids, ARRAY[]::uuid[]) AS simulation_ids,
        COALESCE(scenario_ids, ARRAY[]::uuid[]) AS scenario_ids,
        COALESCE(NULLIF(search, ''), NULL) AS search,
        COALESCE(NULLIF(sort_by, ''), 'averageScore') AS sort_by,
        COALESCE(NULLIF(UPPER(sort_order), ''), 'DESC') AS sort_order,
        GREATEST(0, COALESCE(page, 0)) AS page,
        GREATEST(1, COALESCE(page_size, 100)) AS page_size
),
-- Get actor name from profile
user_profile AS (
    SELECT 
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
-- Get thresholds from active settings
settings_thresholds AS (
    SELECT 
        COALESCE(success_threshold, 85) AS success_threshold,
        COALESCE(warning_threshold, 80) AS warning_threshold,
        COALESCE(danger_threshold, 70) AS danger_threshold
    FROM settings
    WHERE active = true
    LIMIT 1
),
-- Start from profiles to include all matching profiles, even without attempts
filtered_profiles AS (
    SELECT 
        p.id, 
        p.first_name, 
        p.last_name, 
        ARRAY_AGG(pe.email ORDER BY pe.is_primary DESC, pe.created_at) FILTER (WHERE pe.active = true) as emails,
        (SELECT email FROM profile_emails WHERE profile_id = p.id AND is_primary = true AND active = true LIMIT 1) as primary_email,
        p.role,
        p.created_at
    FROM profiles p
    LEFT JOIN profile_emails pe ON pe.profile_id = p.id AND pe.active = true
    WHERE 
        (cardinality((SELECT roles FROM params)::profile_role[]) = 0 OR p.role = ANY((SELECT roles FROM params)::profile_role[]))
        AND (cardinality((SELECT cohort_ids FROM params)::uuid[]) = 0 OR EXISTS (
            SELECT 1 FROM cohort_profiles cp 
            WHERE cp.profile_id = p.id 
              AND cp.cohort_id = ANY((SELECT cohort_ids FROM params)::uuid[]) 
              AND cp.active = true
        ))
        AND (cardinality((SELECT department_ids FROM params)::uuid[]) = 0 OR EXISTS (
            SELECT 1 FROM profile_departments pd 
            WHERE pd.profile_id = p.id 
              AND pd.department_id = ANY((SELECT department_ids FROM params)::uuid[]) 
              AND pd.active = true
        ))
        AND (cardinality((SELECT profile_ids FROM params)::uuid[]) = 0 OR p.id = ANY((SELECT profile_ids FROM params)::uuid[]))
        AND ((SELECT search FROM params) IS NULL OR 
             p.first_name ILIKE '%' || (SELECT search FROM params) || '%' OR 
             p.last_name ILIKE '%' || (SELECT search FROM params) || '%')
    GROUP BY p.id, p.first_name, p.last_name, p.role, p.created_at
),
filt AS (
    SELECT a.* FROM analytics a
    WHERE a.attempt_created_at >= (SELECT start_date FROM params)
      AND a.attempt_created_at < (SELECT end_date FROM params)
      AND a.profile_id IN (SELECT id FROM filtered_profiles)
      AND (
          cardinality((SELECT cohort_ids FROM params)::uuid[]) = 0 OR
          a.simulation_id IN (
              SELECT DISTINCT s.id
              FROM simulations s
              WHERE s.active = TRUE
                AND (
                    EXISTS (
                        SELECT 1 
                        FROM cohort_simulations cs 
                        WHERE cs.simulation_id = s.id 
                          AND cs.cohort_id = ANY((SELECT cohort_ids FROM params)::uuid[])
                          AND cs.active = TRUE
                    )
                    OR
                    (s.practice_simulation = TRUE 
                     AND NOT EXISTS (
                         SELECT 1 
                         FROM cohort_simulations cs2 
                         WHERE cs2.simulation_id = s.id 
                           AND cs2.active = TRUE
                     ))
                )
          )
      )
      AND (cardinality((SELECT profile_ids FROM params)::uuid[]) = 0 OR a.profile_id = ANY((SELECT profile_ids FROM params)::uuid[]))
      AND (cardinality((SELECT simulation_ids FROM params)::uuid[]) = 0 OR a.simulation_id = ANY((SELECT simulation_ids FROM params)::uuid[]))
      AND (cardinality((SELECT scenario_ids FROM params)::uuid[]) = 0 OR a.scenario_id = ANY((SELECT scenario_ids FROM params)::uuid[]))
      AND (
          ('general' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_general = TRUE) OR
          ('practice' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_practice = TRUE) OR
          ('archived' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_archived = TRUE)
      )
      AND ('archived' = ANY((SELECT simulation_filters FROM params)::text[]) OR a.is_archived = FALSE)
),
profile_metrics AS (
    SELECT
        fp.id AS profile_id,
        fp.first_name,
        fp.last_name,
        fp.emails,
        fp.primary_email,
        fp.role,
        fp.created_at,
        AVG(f.grade_percent) FILTER (WHERE f.grade_percent IS NOT NULL) AS avg_score,
        MAX(f.grade_percent) FILTER (WHERE f.grade_percent IS NOT NULL) AS highest_score,
        COUNT(DISTINCT f.attempt_id)::int AS total_attempts,
        AVG(f.num_messages_total) FILTER (WHERE f.num_messages_total IS NOT NULL) AS avg_messages,
        AVG(f.time_taken_seconds / 60.0) FILTER (WHERE f.time_taken_seconds IS NOT NULL) AS avg_time_minutes
    FROM filtered_profiles fp
    LEFT JOIN filt f ON f.profile_id = fp.id
    GROUP BY fp.id, fp.first_name, fp.last_name, fp.emails, fp.primary_email, fp.role, fp.created_at
),
total_time_per_profile AS (
    SELECT
        f.profile_id,
        SUM(LEAST(f.time_taken_seconds / 60.0, 30.0))::float AS total_time_minutes
    FROM filt f
    WHERE f.time_taken_seconds IS NOT NULL
    GROUP BY f.profile_id
),
completion_per_profile AS (
    SELECT
        fp.id AS profile_id,
        (100.0 * AVG((f.completed)::int))::float AS completion_pct
    FROM filtered_profiles fp
    LEFT JOIN filt f ON f.profile_id = fp.id
    GROUP BY fp.id
    HAVING COUNT(f.attempt_id) > 0
),
earliest_attempts_all_time AS (
    SELECT DISTINCT ON (a.profile_id, a.simulation_id)
        a.profile_id,
        a.simulation_id,
        a.attempt_created_at,
        a.grade_percent,
        a.rubric_pass_points,
        a.rubric_points
    FROM analytics a
    WHERE a.profile_id IN (SELECT id FROM filtered_profiles)
    ORDER BY a.profile_id, a.simulation_id, a.attempt_created_at
),
filt_date_range AS (
    SELECT 
        MIN(attempt_created_at) AS min_date,
        MAX(attempt_created_at) AS max_date
    FROM filt
    WHERE attempt_created_at IS NOT NULL
),
first_attempts AS (
    SELECT
        ea.profile_id,
        ea.grade_percent >= (ea.rubric_pass_points * 100.0 / NULLIF(ea.rubric_points, 0)) AS passed
    FROM earliest_attempts_all_time ea
    CROSS JOIN filt_date_range fdr
    WHERE EXISTS (SELECT 1 FROM filt f WHERE f.profile_id = ea.profile_id)
      AND fdr.min_date IS NOT NULL
      AND ea.attempt_created_at >= fdr.min_date
      AND ea.attempt_created_at <= fdr.max_date
),
first_attempt_per_profile AS (
    SELECT
        profile_id,
        (100.0 * COUNT(*) FILTER (WHERE passed) / NULLIF(COUNT(*), 0))::float AS pass_rate
    FROM first_attempts
    GROUP BY profile_id
),
persona_times AS (
    SELECT
        f.profile_id,
        UNNEST(f.message_time_taken_seconds) AS delta_sec
    FROM filt f
    WHERE cardinality(f.message_time_taken_seconds) > 0
),
persona_per_profile AS (
    SELECT
        profile_id,
        AVG(delta_sec)::float AS avg_response_time
    FROM persona_times
    GROUP BY profile_id
),
efficiency_metrics_per_profile AS (
    SELECT
        f.profile_id,
        AVG(f.grade_percent) FILTER (WHERE f.grade_percent IS NOT NULL) AS avg_score,
        SUM(f.time_taken_seconds / 60.0) FILTER (WHERE f.time_taken_seconds IS NOT NULL) AS total_minutes,
        COUNT(DISTINCT f.chat_id) AS total_sessions
    FROM filt f
    GROUP BY f.profile_id
),
efficiency_per_profile AS (
    SELECT
        profile_id,
        GREATEST(0, LEAST(100, 
            avg_score * (1.0 - LEAST(1.0, (total_minutes / NULLIF(total_sessions, 0)) / 120.0))
        ))::float AS efficiency
    FROM efficiency_metrics_per_profile
    WHERE total_sessions > 0
),
profile_chats AS (
    SELECT DISTINCT profile_id, chat_id 
    FROM filt 
    WHERE chat_id IS NOT NULL
),
-- Get chat scenario and simulation info for bundle fallback
chat_scenario_info_bundle AS (
    SELECT DISTINCT
        c.id AS chat_id,
        c.scenario_id,
        sa.simulation_id
    FROM chats c
    JOIN attempt_chats ac ON ac.chat_id = c.id
    JOIN simulation_attempts sa ON sa.id = ac.attempt_id
    WHERE c.id IN (SELECT chat_id FROM profile_chats)
),
-- Get first scenario's rubric per simulation for bundle (fallback)
sim_first_scenario_rubric_bundle AS (
    SELECT DISTINCT ON (ss.simulation_id)
        ss.simulation_id,
        rga.rubric_id,
        r.points
    FROM simulation_scenarios ss
    LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
    LEFT JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
    LEFT JOIN rubrics r ON r.id = rga.rubric_id
    WHERE ss.active = true
      AND ss.simulation_id IN (SELECT DISTINCT simulation_id FROM chat_scenario_info_bundle)
    ORDER BY ss.simulation_id, ss.position
),
grade_stream_per_profile AS (
    SELECT
        pc.profile_id,
        sg.id,
        c_bundle.id AS simulation_chat_id,
        sg.created_at,
        (sg.score::numeric / NULLIF(COALESCE(r.points, r_fallback_scenario.points, r_fallback_first.points, 0), 0)) * 100.0 AS norm
    FROM grades sg
    LEFT JOIN rubric_grade_agents rga ON rga.id = sg.rubric_grade_agent_id
    JOIN runs r_bundle ON r_bundle.id = sg.run_id
    JOIN group_runs gr_bundle ON gr_bundle.run_id = r_bundle.id
    JOIN grade_groups gg_bundle ON gg_bundle.group_id = gr_bundle.group_id
    JOIN chats c_bundle ON c_bundle.id = gg_bundle.chat_id
    JOIN profile_chats pc ON pc.chat_id = c_bundle.id
    LEFT JOIN chat_scenario_info_bundle csi ON csi.chat_id = c_bundle.id
    LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga_fallback ON ssrga_fallback.simulation_id = csi.simulation_id
      AND ssrga_fallback.scenario_id = csi.scenario_id
      AND rga.rubric_id IS NULL
    LEFT JOIN rubric_grade_agents rga_fallback_scenario ON rga_fallback_scenario.id = ssrga_fallback.rubric_grade_agent_id
    LEFT JOIN rubrics r ON r.id = rga.rubric_id
    LEFT JOIN rubrics r_fallback_scenario ON r_fallback_scenario.id = rga_fallback_scenario.rubric_id
    LEFT JOIN sim_first_scenario_rubric_bundle sfsr ON sfsr.simulation_id = csi.simulation_id
      AND rga.rubric_id IS NULL
      AND r_fallback_scenario.points IS NULL
    LEFT JOIN rubrics r_fallback_first ON r_fallback_first.id = sfsr.rubric_id
    WHERE EXISTS (
        SELECT 1 FROM runs r_check
        JOIN group_runs gr_check ON gr_check.run_id = r_check.id
        JOIN grade_groups gg_check ON gg_check.group_id = gr_check.group_id
        JOIN chats c_check ON c_check.id = gg_check.chat_id
        WHERE r_check.id = sg.run_id
    )
      AND COALESCE(r.points, r_fallback_scenario.points, r_fallback_first.points, 0) > 0
),
ordered_grades_per_profile AS (
    SELECT *,
           LAG(norm) OVER (PARTITION BY profile_id ORDER BY created_at) AS prev_norm
    FROM grade_stream_per_profile
),
stagnation_flags_per_profile AS (
    SELECT
        profile_id,
        CASE WHEN prev_norm IS NULL THEN NULL
             WHEN norm <= prev_norm + 0.1 THEN 1 
             ELSE 0 
        END AS stagnated
    FROM ordered_grades_per_profile
    WHERE prev_norm IS NOT NULL
),
stagnation_per_profile AS (
    SELECT
        profile_id,
        (100.0 * AVG(stagnated))::float AS stagnation_rate
    FROM stagnation_flags_per_profile
    GROUP BY profile_id
),
-- Convert data points from JSONB to composite types
avg_score_data_points AS (
    SELECT
        f.profile_id,
        COALESCE(
            ARRAY_AGG(
                (f.profile_id::text, 
                 to_char(f.attempt_created_at, 'YYYY-MM-DD'),
                 f.grade_percent,
                 f.simulation_id::text,
                 f.scenario_id::text,
                 NULL::text
                )::types.q_reports_bundle_v4_data_point
                ORDER BY f.attempt_created_at
            ),
            ARRAY[]::types.q_reports_bundle_v4_data_point[]
        ) AS data_points
    FROM filt f
    WHERE f.grade_percent IS NOT NULL
    GROUP BY f.profile_id
),
completion_data_points AS (
    SELECT
        f.profile_id,
        COALESCE(
            ARRAY_AGG(
                (f.profile_id::text,
                 to_char(f.chat_created_at, 'YYYY-MM-DD'),
                 (f.completed)::int::numeric,
                 f.simulation_id::text,
                 f.scenario_id::text,
                 NULL::text
                )::types.q_reports_bundle_v4_data_point
                ORDER BY f.chat_created_at
            ),
            ARRAY[]::types.q_reports_bundle_v4_data_point[]
        ) AS data_points
    FROM filt f
    GROUP BY f.profile_id
),
first_attempt_data_points AS (
    SELECT
        fa.profile_id,
        COALESCE(
            ARRAY_AGG(
                (fa.profile_id::text,
                 to_char(ea.attempt_created_at, 'YYYY-MM-DD'),
                 (fa.passed)::int::numeric,
                 ea.simulation_id::text,
                 NULL::text,
                 NULL::text
                )::types.q_reports_bundle_v4_data_point
                ORDER BY ea.attempt_created_at
            ),
            ARRAY[]::types.q_reports_bundle_v4_data_point[]
        ) AS data_points
    FROM first_attempts fa
    JOIN earliest_attempts_all_time ea ON ea.profile_id = fa.profile_id
    GROUP BY fa.profile_id
),
highest_score_data_points AS (
    SELECT
        f.profile_id,
        COALESCE(
            ARRAY_AGG(
                (f.profile_id::text,
                 to_char(f.attempt_created_at, 'YYYY-MM-DD'),
                 f.grade_percent,
                 f.simulation_id::text,
                 f.scenario_id::text,
                 NULL::text
                )::types.q_reports_bundle_v4_data_point
                ORDER BY f.attempt_created_at
            ),
            ARRAY[]::types.q_reports_bundle_v4_data_point[]
        ) AS data_points
    FROM filt f
    WHERE f.grade_percent IS NOT NULL
    GROUP BY f.profile_id
),
messages_data_points AS (
    SELECT
        f.profile_id,
        COALESCE(
            ARRAY_AGG(
                (f.profile_id::text,
                 to_char(f.attempt_created_at, 'YYYY-MM-DD'),
                 f.num_messages_total::numeric,
                 f.simulation_id::text,
                 f.scenario_id::text,
                 NULL::text
                )::types.q_reports_bundle_v4_data_point
                ORDER BY f.attempt_created_at
            ),
            ARRAY[]::types.q_reports_bundle_v4_data_point[]
        ) AS data_points
    FROM filt f
    WHERE f.num_messages_total IS NOT NULL
    GROUP BY f.profile_id
),
persona_time_data_points AS (
    SELECT
        pt.profile_id,
        COALESCE(
            ARRAY_AGG(
                (pt.profile_id::text,
                 NULL::text,
                 pt.delta_sec,
                 NULL::text,
                 NULL::text,
                 NULL::text
                )::types.q_reports_bundle_v4_data_point
            ),
            ARRAY[]::types.q_reports_bundle_v4_data_point[]
        ) AS data_points
    FROM persona_times pt
    GROUP BY pt.profile_id
),
time_spent_data_points AS (
    SELECT
        f.profile_id,
        COALESCE(
            ARRAY_AGG(
                (f.profile_id::text,
                 to_char(f.chat_created_at, 'YYYY-MM-DD'),
                 LEAST(f.time_taken_seconds / 60.0, 30.0),
                 f.simulation_id::text,
                 f.scenario_id::text,
                 f.attempt_id::text
                )::types.q_reports_bundle_v4_data_point
                ORDER BY f.chat_created_at
            ),
            ARRAY[]::types.q_reports_bundle_v4_data_point[]
        ) AS data_points
    FROM filt f
    WHERE f.time_taken_seconds IS NOT NULL
    GROUP BY f.profile_id
),
total_attempts_data_points AS (
    SELECT
        profile_id,
        COALESCE(
            ARRAY_AGG(
                (profile_id::text,
                 NULL::text,
                 NULL::numeric,
                 simulation_id::text,
                 NULL::text,
                 attempt_id::text
                )::types.q_reports_bundle_v4_data_point
            ),
            ARRAY[]::types.q_reports_bundle_v4_data_point[]
        ) AS data_points
    FROM (
        SELECT DISTINCT profile_id, attempt_id, simulation_id
        FROM filt
    ) sub
    GROUP BY profile_id
),
efficiency_data_points AS (
    SELECT
        profile_id,
        COALESCE(
            ARRAY_AGG(
                (profile_id::text,
                 NULL::text,
                 ROUND(GREATEST(0, LEAST(100, 
                     avg_score * (1.0 - LEAST(1.0, (total_minutes / NULLIF(total_sessions, 0)) / 120.0))
                 )))::numeric,
                 NULL::text,
                 NULL::text,
                 NULL::text
                )::types.q_reports_bundle_v4_data_point
            ),
            ARRAY[]::types.q_reports_bundle_v4_data_point[]
        ) AS data_points
    FROM efficiency_metrics_per_profile
    GROUP BY profile_id
),
stagnation_data_points AS (
    SELECT
        sf.profile_id,
        COALESCE(
            ARRAY_AGG(
                (sf.profile_id::text,
                 NULL::text,
                 sf.stagnated::numeric,
                 NULL::text,
                 NULL::text,
                 NULL::text
                )::types.q_reports_bundle_v4_data_point
            ),
            ARRAY[]::types.q_reports_bundle_v4_data_point[]
        ) AS data_points
    FROM stagnation_flags_per_profile sf
    GROUP BY sf.profile_id
),
profile_simulation_ids AS (
    SELECT
        f.profile_id,
        ARRAY_AGG(DISTINCT f.simulation_id::text) FILTER (WHERE f.simulation_id IS NOT NULL) AS simulation_ids
    FROM filt f
    GROUP BY f.profile_id
),
scenario_root_mapping AS (
    WITH RECURSIVE scenario_ancestors AS (
        SELECT DISTINCT
            f.scenario_id as child_scenario_id,
            f.scenario_id as ancestor_id,
            0 as depth
        FROM filt f
        WHERE f.scenario_id IS NOT NULL
        
        UNION ALL
        
        SELECT 
            sa.child_scenario_id,
            COALESCE(
                (SELECT st.parent_id 
                 FROM scenario_tree st 
                 WHERE st.child_id = sa.ancestor_id 
                   AND st.parent_id != st.child_id 
                 LIMIT 1),
                sa.ancestor_id
            ) as ancestor_id,
            sa.depth + 1 as depth
        FROM scenario_ancestors sa
        WHERE sa.depth < 100
          AND EXISTS (
              SELECT 1 FROM scenario_tree st 
              WHERE st.child_id = sa.ancestor_id 
                AND st.parent_id != st.child_id
          )
    )
    SELECT DISTINCT
        child_scenario_id,
        ancestor_id as root_scenario_id
    FROM scenario_ancestors
    WHERE depth = (
        SELECT MAX(depth) 
        FROM scenario_ancestors sa2 
        WHERE sa2.child_scenario_id = scenario_ancestors.child_scenario_id
    )
),
profile_scenario_ids AS (
    SELECT
        f.profile_id,
        ARRAY_AGG(DISTINCT COALESCE(
            (SELECT srm.root_scenario_id::text 
             FROM scenario_root_mapping srm 
             WHERE srm.child_scenario_id = f.scenario_id),
            f.scenario_id::text
        )) FILTER (WHERE f.scenario_id IS NOT NULL) AS scenario_ids
    FROM filt f
    GROUP BY f.profile_id
),
all_metrics AS (
    SELECT
        pm.*,
        COALESCE(tt.total_time_minutes, 0) AS total_time_minutes,
        COALESCE(cp.completion_pct, 0) AS completion_pct,
        COALESCE(fa.pass_rate, 0) AS first_attempt_pass_rate,
        COALESCE(pp.avg_response_time, 0) AS persona_response_time,
        COALESCE(ep.efficiency, 0) AS session_efficiency,
        COALESCE(sp.stagnation_rate, 0) AS stagnation_rate,
        COALESCE(asdp.data_points, ARRAY[]::types.q_reports_bundle_v4_data_point[]) AS avg_score_points,
        COALESCE(cdp.data_points, ARRAY[]::types.q_reports_bundle_v4_data_point[]) AS completion_points,
        COALESCE(fadp.data_points, ARRAY[]::types.q_reports_bundle_v4_data_point[]) AS first_attempt_points,
        COALESCE(hsdp.data_points, ARRAY[]::types.q_reports_bundle_v4_data_point[]) AS highest_score_points,
        COALESCE(mdp.data_points, ARRAY[]::types.q_reports_bundle_v4_data_point[]) AS messages_points,
        COALESCE(ptdp.data_points, ARRAY[]::types.q_reports_bundle_v4_data_point[]) AS persona_time_points,
        COALESCE(tsdp.data_points, ARRAY[]::types.q_reports_bundle_v4_data_point[]) AS time_spent_points,
        COALESCE(tadp.data_points, ARRAY[]::types.q_reports_bundle_v4_data_point[]) AS total_attempts_points,
        COALESCE(edp.data_points, ARRAY[]::types.q_reports_bundle_v4_data_point[]) AS efficiency_points,
        COALESCE(sdp.data_points, ARRAY[]::types.q_reports_bundle_v4_data_point[]) AS stagnation_points,
        COALESCE(psi.simulation_ids, ARRAY[]::text[]) AS simulation_ids,
        COALESCE(psc.scenario_ids, ARRAY[]::text[]) AS scenario_ids
    FROM profile_metrics pm
    LEFT JOIN total_time_per_profile tt ON pm.profile_id = tt.profile_id
    LEFT JOIN completion_per_profile cp ON pm.profile_id = cp.profile_id
    LEFT JOIN first_attempt_per_profile fa ON pm.profile_id = fa.profile_id
    LEFT JOIN persona_per_profile pp ON pm.profile_id = pp.profile_id
    LEFT JOIN efficiency_per_profile ep ON pm.profile_id = ep.profile_id
    LEFT JOIN stagnation_per_profile sp ON pm.profile_id = sp.profile_id
    LEFT JOIN avg_score_data_points asdp ON pm.profile_id = asdp.profile_id
    LEFT JOIN completion_data_points cdp ON pm.profile_id = cdp.profile_id
    LEFT JOIN first_attempt_data_points fadp ON pm.profile_id = fadp.profile_id
    LEFT JOIN highest_score_data_points hsdp ON pm.profile_id = hsdp.profile_id
    LEFT JOIN messages_data_points mdp ON pm.profile_id = mdp.profile_id
    LEFT JOIN persona_time_data_points ptdp ON pm.profile_id = ptdp.profile_id
    LEFT JOIN time_spent_data_points tsdp ON pm.profile_id = tsdp.profile_id
    LEFT JOIN total_attempts_data_points tadp ON pm.profile_id = tadp.profile_id
    LEFT JOIN efficiency_data_points edp ON pm.profile_id = edp.profile_id
    LEFT JOIN stagnation_data_points sdp ON pm.profile_id = sdp.profile_id
    LEFT JOIN profile_simulation_ids psi ON pm.profile_id = psi.profile_id
    LEFT JOIN profile_scenario_ids psc ON pm.profile_id = psc.profile_id
),
profile_options_cte AS (
    SELECT 
        am.profile_id,
        am.first_name || ' ' || am.last_name AS profile_name,
        COUNT(*) AS count
    FROM all_metrics am
    GROUP BY am.profile_id, am.first_name, am.last_name
    ORDER BY profile_name
),
simulation_options_cte AS (
    SELECT 
        sim.id AS simulation_id,
        sim.title AS simulation_name,
        COUNT(DISTINCT am.profile_id) AS count
    FROM all_metrics am
    CROSS JOIN LATERAL UNNEST(am.simulation_ids) AS sim_id
    JOIN simulations sim ON sim.id::text = sim_id
    WHERE sim.active = true
    GROUP BY sim.id, sim.title
    ORDER BY simulation_name
),
scenario_options_cte AS (
    SELECT 
        s.id AS scenario_id,
        s.name AS scenario_title,
        COUNT(DISTINCT am.profile_id) AS count
    FROM all_metrics am
    CROSS JOIN LATERAL UNNEST(am.scenario_ids) AS scen_id
    JOIN scenarios s ON s.id::text = scen_id
    WHERE s.active = true
    GROUP BY s.id, s.name
    ORDER BY scenario_title
),
-- Calculate total count before pagination
total_count_before_pagination AS (
    SELECT COUNT(*)::bigint AS total_count
    FROM all_metrics
),
paginated_metrics AS (
    SELECT
        am.*,
        (SELECT total_count FROM total_count_before_pagination) AS total_count
    FROM all_metrics am
    ORDER BY 
        -- Numeric sorting (DESC)
        CASE 
            WHEN (SELECT sort_by FROM params) = 'averageScore' AND (SELECT sort_order FROM params) = 'DESC' THEN am.avg_score::numeric
            WHEN (SELECT sort_by FROM params) = 'highestScore' AND (SELECT sort_order FROM params) = 'DESC' THEN am.highest_score::numeric
            WHEN (SELECT sort_by FROM params) = 'completionPercentage' AND (SELECT sort_order FROM params) = 'DESC' THEN am.completion_pct::numeric
            WHEN (SELECT sort_by FROM params) = 'firstAttemptPassRate' AND (SELECT sort_order FROM params) = 'DESC' THEN am.first_attempt_pass_rate::numeric
            WHEN (SELECT sort_by FROM params) = 'messagesPerSession' AND (SELECT sort_order FROM params) = 'DESC' THEN am.avg_messages::numeric
            WHEN (SELECT sort_by FROM params) = 'personaResponseTimes' AND (SELECT sort_order FROM params) = 'DESC' THEN am.persona_response_time::numeric
            WHEN (SELECT sort_by FROM params) = 'sessionEfficiency' AND (SELECT sort_order FROM params) = 'DESC' THEN am.session_efficiency::numeric
            WHEN (SELECT sort_by FROM params) = 'stagnationRate' AND (SELECT sort_order FROM params) = 'DESC' THEN am.stagnation_rate::numeric
            WHEN (SELECT sort_by FROM params) = 'timeSpent' AND (SELECT sort_order FROM params) = 'DESC' THEN am.total_time_minutes::numeric
            WHEN (SELECT sort_by FROM params) = 'totalAttempts' AND (SELECT sort_order FROM params) = 'DESC' THEN am.total_attempts::numeric
        END DESC NULLS LAST,
        -- Numeric sorting (ASC)
        CASE 
            WHEN (SELECT sort_by FROM params) = 'averageScore' AND (SELECT sort_order FROM params) = 'ASC' THEN am.avg_score::numeric
            WHEN (SELECT sort_by FROM params) = 'highestScore' AND (SELECT sort_order FROM params) = 'ASC' THEN am.highest_score::numeric
            WHEN (SELECT sort_by FROM params) = 'completionPercentage' AND (SELECT sort_order FROM params) = 'ASC' THEN am.completion_pct::numeric
            WHEN (SELECT sort_by FROM params) = 'firstAttemptPassRate' AND (SELECT sort_order FROM params) = 'ASC' THEN am.first_attempt_pass_rate::numeric
            WHEN (SELECT sort_by FROM params) = 'messagesPerSession' AND (SELECT sort_order FROM params) = 'ASC' THEN am.avg_messages::numeric
            WHEN (SELECT sort_by FROM params) = 'personaResponseTimes' AND (SELECT sort_order FROM params) = 'ASC' THEN am.persona_response_time::numeric
            WHEN (SELECT sort_by FROM params) = 'sessionEfficiency' AND (SELECT sort_order FROM params) = 'ASC' THEN am.session_efficiency::numeric
            WHEN (SELECT sort_by FROM params) = 'stagnationRate' AND (SELECT sort_order FROM params) = 'ASC' THEN am.stagnation_rate::numeric
            WHEN (SELECT sort_by FROM params) = 'timeSpent' AND (SELECT sort_order FROM params) = 'ASC' THEN am.total_time_minutes::numeric
            WHEN (SELECT sort_by FROM params) = 'totalAttempts' AND (SELECT sort_order FROM params) = 'ASC' THEN am.total_attempts::numeric
        END ASC NULLS LAST,
        -- Text sorting (profileName)
        CASE 
            WHEN (SELECT sort_by FROM params) = 'profileName' AND (SELECT sort_order FROM params) = 'DESC' THEN LOWER(am.first_name || ' ' || am.last_name)
        END DESC NULLS LAST,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'profileName' AND (SELECT sort_order FROM params) = 'ASC' THEN LOWER(am.first_name || ' ' || am.last_name)
        END ASC NULLS LAST,
        am.profile_id
    LIMIT (SELECT page_size FROM params)
    OFFSET (SELECT page * page_size FROM params)
),
-- Build metrics with composite types
profiles_with_metrics AS (
    SELECT
        pm.profile_id,
        pm.first_name,
        pm.last_name,
        pm.emails,
        pm.primary_email,
        pm.role,
        pm.simulation_ids,
        pm.scenario_ids,
        -- Build average_score metric
        (
            (pm.avg_score IS NOT NULL AND pm.avg_score > 0),
            'avg',
            ROUND(COALESCE(pm.avg_score, 0))::int,
            pm.avg_score_points,
            (
                ROUND(COALESCE(pm.avg_score, 0))::int,  -- mean
                ROUND(COALESCE(pm.avg_score, 0))::int,  -- median
                ROUND(COALESCE(pm.avg_score, 0))::int,  -- mode
                0,  -- count
                0,  -- completed
                0,  -- total
                0,  -- percent
                ARRAY[]::int[],  -- top
                0,  -- mean_seconds
                0,  -- median_seconds
                0,  -- samples
                0,  -- avg_score_percent
                0,  -- avg_minutes
                0,  -- efficiency
                0,  -- tracked
                0,  -- stagnant
                0,  -- rate_percent
                0,  -- total_minutes
                0::numeric,  -- total_hours
                0,  -- attempts
                0,  -- unique_simulations
                0   -- per_simulation_mean
            )::types.q_reports_bundle_v4_hover,
            CASE
                WHEN pm.avg_score IS NULL OR pm.avg_score = 0 THEN 'neutral'
                WHEN ROUND(pm.avg_score) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'
                WHEN ROUND(pm.avg_score) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'
                ELSE 'danger'
            END
        )::types.q_reports_bundle_v4_metric AS average_score,
        -- Build completion_percentage metric
        (
            (pm.completion_pct IS NOT NULL AND pm.completion_pct > 0),
            'rate',
            ROUND(COALESCE(pm.completion_pct, 0))::int,
            pm.completion_points,
            (
                0,  -- mean
                0,  -- median
                0,  -- mode
                0,  -- count
                ROUND(COALESCE(pm.completion_pct, 0))::int,  -- completed
                0,  -- total
                ROUND(COALESCE(pm.completion_pct, 0))::int,  -- percent
                ARRAY[]::int[],  -- top
                0,  -- mean_seconds
                0,  -- median_seconds
                0,  -- samples
                0,  -- avg_score_percent
                0,  -- avg_minutes
                0,  -- efficiency
                0,  -- tracked
                0,  -- stagnant
                0,  -- rate_percent
                0,  -- total_minutes
                0::numeric,  -- total_hours
                0,  -- attempts
                0,  -- unique_simulations
                0   -- per_simulation_mean
            )::types.q_reports_bundle_v4_hover,
            CASE
                WHEN pm.completion_pct IS NULL OR pm.completion_pct = 0 THEN 'neutral'
                WHEN ROUND(pm.completion_pct) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'
                WHEN ROUND(pm.completion_pct) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'
                ELSE 'danger'
            END
        )::types.q_reports_bundle_v4_metric AS completion_percentage,
        -- Build first_attempt_pass_rate metric
        (
            (pm.first_attempt_pass_rate IS NOT NULL AND pm.first_attempt_pass_rate > 0),
            'rate',
            ROUND(COALESCE(pm.first_attempt_pass_rate, 0))::int,
            pm.first_attempt_points,
            (
                0,  -- mean
                0,  -- median
                0,  -- mode
                0,  -- count
                0,  -- completed
                0,  -- total
                ROUND(COALESCE(pm.first_attempt_pass_rate, 0))::int,  -- percent
                ARRAY[]::int[],  -- top
                0,  -- mean_seconds
                0,  -- median_seconds
                0,  -- samples
                0,  -- avg_score_percent
                0,  -- avg_minutes
                0,  -- efficiency
                0,  -- tracked
                0,  -- stagnant
                0,  -- rate_percent
                0,  -- total_minutes
                0::numeric,  -- total_hours
                0,  -- attempts
                0,  -- unique_simulations
                0   -- per_simulation_mean
            )::types.q_reports_bundle_v4_hover,
            CASE
                WHEN pm.first_attempt_pass_rate IS NULL OR pm.first_attempt_pass_rate = 0 THEN 'neutral'
                WHEN ROUND(pm.first_attempt_pass_rate) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'
                WHEN ROUND(pm.first_attempt_pass_rate) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'
                ELSE 'danger'
            END
        )::types.q_reports_bundle_v4_metric AS first_attempt_pass_rate,
        -- Build highest_score metric
        (
            (pm.highest_score IS NOT NULL AND pm.highest_score > 0),
            'max',
            ROUND(COALESCE(pm.highest_score, 0))::int,
            pm.highest_score_points,
            (
                0,  -- mean
                0,  -- median
                0,  -- mode
                0,  -- count
                0,  -- completed
                0,  -- total
                0,  -- percent
                ARRAY[ROUND(COALESCE(pm.highest_score, 0))::int],  -- top
                0,  -- mean_seconds
                0,  -- median_seconds
                0,  -- samples
                0,  -- avg_score_percent
                0,  -- avg_minutes
                0,  -- efficiency
                0,  -- tracked
                0,  -- stagnant
                0,  -- rate_percent
                0,  -- total_minutes
                0::numeric,  -- total_hours
                0,  -- attempts
                0,  -- unique_simulations
                0   -- per_simulation_mean
            )::types.q_reports_bundle_v4_hover,
            CASE
                WHEN pm.highest_score IS NULL OR pm.highest_score = 0 THEN 'neutral'
                WHEN ROUND(pm.highest_score) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'
                WHEN ROUND(pm.highest_score) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'
                ELSE 'danger'
            END
        )::types.q_reports_bundle_v4_metric AS highest_score,
        -- Build messages_per_session metric
        (
            (pm.avg_messages IS NOT NULL AND pm.avg_messages > 0),
            'avg',
            ROUND(COALESCE(pm.avg_messages, 0))::int,
            pm.messages_points,
            (
                ROUND(COALESCE(pm.avg_messages, 0))::int,  -- mean
                ROUND(COALESCE(pm.avg_messages, 0))::int,  -- median
                0,  -- mode
                pm.total_attempts,  -- count
                0,  -- completed
                0,  -- total
                0,  -- percent
                ARRAY[]::int[],  -- top
                0,  -- mean_seconds
                0,  -- median_seconds
                0,  -- samples
                0,  -- avg_score_percent
                0,  -- avg_minutes
                0,  -- efficiency
                0,  -- tracked
                0,  -- stagnant
                0,  -- rate_percent
                0,  -- total_minutes
                0::numeric,  -- total_hours
                0,  -- attempts
                0,  -- unique_simulations
                0   -- per_simulation_mean
            )::types.q_reports_bundle_v4_hover,
            CASE
                WHEN pm.avg_messages IS NULL OR pm.avg_messages = 0 THEN 'neutral'
                WHEN ROUND(pm.avg_messages) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'
                WHEN ROUND(pm.avg_messages) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'
                ELSE 'danger'
            END
        )::types.q_reports_bundle_v4_metric AS messages_per_session,
        -- Build persona_response_times metric
        (
            (pm.persona_response_time IS NOT NULL AND pm.persona_response_time > 0),
            'avg',
            ROUND(COALESCE(pm.persona_response_time, 0))::int,
            pm.persona_time_points,
            (
                0,  -- mean
                0,  -- median
                0,  -- mode
                0,  -- count
                0,  -- completed
                0,  -- total
                0,  -- percent
                ARRAY[]::int[],  -- top
                ROUND(COALESCE(pm.persona_response_time, 0))::int,  -- mean_seconds
                ROUND(COALESCE(pm.persona_response_time, 0))::int,  -- median_seconds
                0,  -- samples
                0,  -- avg_score_percent
                0,  -- avg_minutes
                0,  -- efficiency
                0,  -- tracked
                0,  -- stagnant
                0,  -- rate_percent
                0,  -- total_minutes
                0::numeric,  -- total_hours
                0,  -- attempts
                0,  -- unique_simulations
                0   -- per_simulation_mean
            )::types.q_reports_bundle_v4_hover,
            CASE
                WHEN pm.persona_response_time IS NULL OR pm.persona_response_time = 0 THEN 'neutral'
                WHEN ROUND(pm.persona_response_time) > (SELECT danger_threshold FROM settings_thresholds LIMIT 1) THEN 'danger'
                WHEN ROUND(pm.persona_response_time) > (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'
                ELSE 'success'
            END
        )::types.q_reports_bundle_v4_metric AS persona_response_times,
        -- Build session_efficiency metric
        (
            (pm.session_efficiency > 0),
            'avg',
            ROUND(COALESCE(pm.session_efficiency, 0))::int,
            pm.efficiency_points,
            (
                0,  -- mean
                0,  -- median
                0,  -- mode
                0,  -- count
                0,  -- completed
                0,  -- total
                0,  -- percent
                ARRAY[]::int[],  -- top
                0,  -- mean_seconds
                0,  -- median_seconds
                0,  -- samples
                0,  -- avg_score_percent
                0,  -- avg_minutes
                ROUND(COALESCE(pm.session_efficiency, 0))::int,  -- efficiency
                0,  -- tracked
                0,  -- stagnant
                0,  -- rate_percent
                0,  -- total_minutes
                0::numeric,  -- total_hours
                0,  -- attempts
                0,  -- unique_simulations
                0   -- per_simulation_mean
            )::types.q_reports_bundle_v4_hover,
            CASE
                WHEN pm.session_efficiency IS NULL OR pm.session_efficiency = 0 THEN 'neutral'
                WHEN ROUND(pm.session_efficiency) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'
                WHEN ROUND(pm.session_efficiency) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'
                ELSE 'danger'
            END
        )::types.q_reports_bundle_v4_metric AS session_efficiency,
        -- Build stagnation_rate metric
        (
            (pm.stagnation_rate > 0),
            'rate',
            ROUND(COALESCE(pm.stagnation_rate, 0))::int,
            pm.stagnation_points,
            (
                0,  -- mean
                0,  -- median
                0,  -- mode
                0,  -- count
                0,  -- completed
                0,  -- total
                0,  -- percent
                ARRAY[]::int[],  -- top
                0,  -- mean_seconds
                0,  -- median_seconds
                0,  -- samples
                0,  -- avg_score_percent
                0,  -- avg_minutes
                0,  -- efficiency
                0,  -- tracked
                0,  -- stagnant
                ROUND(COALESCE(pm.stagnation_rate, 0))::int,  -- rate_percent
                0,  -- total_minutes
                0::numeric,  -- total_hours
                0,  -- attempts
                0,  -- unique_simulations
                0   -- per_simulation_mean
            )::types.q_reports_bundle_v4_hover,
            CASE
                WHEN pm.stagnation_rate IS NULL OR pm.stagnation_rate = 0 THEN 'neutral'
                WHEN ROUND(pm.stagnation_rate) > (SELECT danger_threshold FROM settings_thresholds LIMIT 1) THEN 'danger'
                WHEN ROUND(pm.stagnation_rate) > (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'
                ELSE 'success'
            END
        )::types.q_reports_bundle_v4_metric AS stagnation_rate,
        -- Build time_spent metric
        (
            (pm.total_time_minutes IS NOT NULL AND pm.total_time_minutes > 0),
            'sum',
            ROUND(COALESCE(pm.total_time_minutes, 0))::int,
            pm.time_spent_points,
            (
                0,  -- mean
                0,  -- median
                0,  -- mode
                0,  -- count
                0,  -- completed
                0,  -- total
                0,  -- percent
                ARRAY[]::int[],  -- top
                0,  -- mean_seconds
                0,  -- median_seconds
                0,  -- samples
                0,  -- avg_score_percent
                0,  -- avg_minutes
                0,  -- efficiency
                0,  -- tracked
                0,  -- stagnant
                0,  -- rate_percent
                ROUND(COALESCE(pm.total_time_minutes, 0))::int,  -- total_minutes
                ROUND(COALESCE(pm.total_time_minutes, 0)::numeric / 60.0, 1),  -- total_hours
                0,  -- attempts
                0,  -- unique_simulations
                0   -- per_simulation_mean
            )::types.q_reports_bundle_v4_hover,
            CASE
                WHEN pm.total_time_minutes IS NULL OR pm.total_time_minutes = 0 THEN 'neutral'
                WHEN ROUND(pm.total_time_minutes) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'
                WHEN ROUND(pm.total_time_minutes) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'
                ELSE 'danger'
            END
        )::types.q_reports_bundle_v4_metric AS time_spent,
        -- Build total_attempts metric
        (
            true,
            'countDistinct',
            COALESCE(pm.total_attempts, 0),
            pm.total_attempts_points,
            (
                0,  -- mean
                0,  -- median
                0,  -- mode
                0,  -- count
                0,  -- completed
                0,  -- total
                0,  -- percent
                ARRAY[]::int[],  -- top
                0,  -- mean_seconds
                0,  -- median_seconds
                0,  -- samples
                0,  -- avg_score_percent
                0,  -- avg_minutes
                0,  -- efficiency
                0,  -- tracked
                0,  -- stagnant
                0,  -- rate_percent
                0,  -- total_minutes
                0::numeric,  -- total_hours
                COALESCE(pm.total_attempts, 0),  -- attempts
                0,  -- unique_simulations
                0   -- per_simulation_mean
            )::types.q_reports_bundle_v4_hover,
            CASE
                WHEN pm.total_attempts IS NULL OR pm.total_attempts = 0 THEN 'neutral'
                WHEN pm.total_attempts >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'
                WHEN pm.total_attempts >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'
                ELSE 'danger'
            END
        )::types.q_reports_bundle_v4_metric AS total_attempts
    FROM paginated_metrics pm
),
-- Build profile metrics composite type
profiles_with_profile_metrics AS (
    SELECT
        pwm.profile_id,
        pwm.first_name,
        pwm.last_name,
        pwm.emails,
        pwm.primary_email,
        pwm.role,
        pwm.simulation_ids,
        pwm.scenario_ids,
        (
            pwm.average_score,
            pwm.completion_percentage,
            pwm.first_attempt_pass_rate,
            pwm.highest_score,
            pwm.messages_per_session,
            pwm.persona_response_times,
            pwm.session_efficiency,
            pwm.stagnation_rate,
            pwm.time_spent,
            pwm.total_attempts
        )::types.q_reports_bundle_v4_profile_metrics AS metrics
    FROM profiles_with_metrics pwm
),
-- Build final profile array
profiles_final AS (
    SELECT
        ARRAY_AGG(
            (pwm.profile_id,
             pwm.first_name,
             pwm.last_name,
             pwm.emails,
             pwm.primary_email,
             pwm.role,
             pwm.simulation_ids,
             pwm.scenario_ids,
             pwm.metrics
            )::types.q_reports_bundle_v4_profile
            ORDER BY pwm.profile_id
        ) AS profiles_array
    FROM profiles_with_profile_metrics pwm
),
-- Build filter options (separate CTEs to avoid cartesian product)
profile_options_final AS (
    SELECT
        COALESCE(
            ARRAY_AGG(
                (poc.profile_id::text,
                 poc.profile_name,
                 poc.count
                )::types.q_reports_bundle_v4_filter_option
                ORDER BY poc.profile_name
            ),
            ARRAY[]::types.q_reports_bundle_v4_filter_option[]
        ) AS profile_options_array
    FROM profile_options_cte poc
),
simulation_options_final AS (
    SELECT
        COALESCE(
            ARRAY_AGG(
                (soc.simulation_id::text,
                 soc.simulation_name,
                 soc.count
                )::types.q_reports_bundle_v4_filter_option
                ORDER BY soc.simulation_name
            ),
            ARRAY[]::types.q_reports_bundle_v4_filter_option[]
        ) AS simulation_options_array
    FROM simulation_options_cte soc
),
scenario_options_final AS (
    SELECT
        COALESCE(
            ARRAY_AGG(
                (scoc.scenario_id::text,
                 scoc.scenario_title,
                 scoc.count
                )::types.q_reports_bundle_v4_filter_option
                ORDER BY scoc.scenario_title
            ),
            ARRAY[]::types.q_reports_bundle_v4_filter_option[]
        ) AS scenario_options_array
    FROM scenario_options_cte scoc
),
-- Build scenario and simulation arrays (not mappings)
scenarios_final AS (
    SELECT
        COALESCE(
            ARRAY_AGG(
                (s.id,
                 s.name,
                 COALESCE(
                     (SELECT ps.problem_statement 
                      FROM scenario_problem_statements sps
                      JOIN problem_statements ps ON ps.id = sps.problem_statement_id
                      WHERE sps.scenario_id = s.id AND sps.active = true
                      ORDER BY sps.created_at DESC, sps.updated_at DESC
                      LIMIT 1), 
                     ''
                 )
                )::types.q_reports_bundle_v4_scenario
                ORDER BY s.name
            ),
            ARRAY[]::types.q_reports_bundle_v4_scenario[]
        ) AS scenarios_array
    FROM scenarios s
    JOIN scenario_tree st_root ON st_root.parent_id = s.id AND st_root.child_id = s.id
    WHERE s.active = true
      AND EXISTS (
          SELECT 1 FROM filt f
          WHERE f.scenario_id IS NOT NULL
            AND (
                EXISTS (
                    SELECT 1 FROM scenario_tree st
                    WHERE st.child_id = f.scenario_id
                      AND st.parent_id = s.id
                )
                OR f.scenario_id = s.id
            )
      )
),
simulations_final AS (
    SELECT
        COALESCE(
            ARRAY_AGG(
                (sim.id,
                 sim.title,
                 COALESCE(sim.description, ''),
                 (SELECT rga.rubric_id FROM simulation_scenarios ss 
                  JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
                  JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
                  WHERE ss.simulation_id = sim.id AND ss.active = true 
                  ORDER BY ss.position 
                  LIMIT 1),
                 (SELECT r.points FROM simulation_scenarios ss 
                  JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
                  JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
                  JOIN rubrics r ON r.id = rga.rubric_id
                  WHERE ss.simulation_id = sim.id AND ss.active = true 
                  ORDER BY ss.position 
                  LIMIT 1),
                 (SELECT r.pass_points FROM simulation_scenarios ss 
                  JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
                  JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
                  JOIN rubrics r ON r.id = rga.rubric_id
                  WHERE ss.simulation_id = sim.id AND ss.active = true 
                  ORDER BY ss.position 
                  LIMIT 1)
                )::types.q_reports_bundle_v4_simulation
                ORDER BY sim.title
            ),
            ARRAY[]::types.q_reports_bundle_v4_simulation[]
        ) AS simulations_array
    FROM simulations sim
    WHERE sim.active = true
      AND sim.id IN (SELECT DISTINCT simulation_id FROM filt WHERE simulation_id IS NOT NULL)
),
total_count_cte AS (
    SELECT total_count FROM total_count_before_pagination
)
SELECT
    (SELECT actor_name FROM user_profile)::text as actor_name,
    COALESCE((SELECT profiles_array FROM profiles_final), ARRAY[]::types.q_reports_bundle_v4_profile[]) as data,
    COALESCE((SELECT total_count FROM total_count_cte), 0)::bigint as total_count,
    (SELECT page FROM params)::int as page,
    (SELECT page_size FROM params)::int as page_size,
    CASE 
        WHEN (SELECT page_size FROM params) > 0 
        THEN ((COALESCE((SELECT total_count FROM total_count_cte), 0) + (SELECT page_size FROM params) - 1) / (SELECT page_size FROM params))::bigint
        ELSE 0::bigint
    END as total_pages,
    COALESCE((SELECT profile_options_array FROM profile_options_final), ARRAY[]::types.q_reports_bundle_v4_filter_option[]) as profile_options,
    COALESCE((SELECT simulation_options_array FROM simulation_options_final), ARRAY[]::types.q_reports_bundle_v4_filter_option[]) as simulation_options,
    COALESCE((SELECT scenario_options_array FROM scenario_options_final), ARRAY[]::types.q_reports_bundle_v4_filter_option[]) as scenario_options,
    COALESCE((SELECT scenarios_array FROM scenarios_final), ARRAY[]::types.q_reports_bundle_v4_scenario[]) as scenarios,
    COALESCE((SELECT simulations_array FROM simulations_final), ARRAY[]::types.q_reports_bundle_v4_simulation[]) as simulations
$$;


--
-- Name: api_get_reports_history_v4(text, text, uuid, uuid[], uuid[], public.profile_role[], text[], text, uuid[], uuid[], uuid[], boolean, text, text, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_reports_history_v4(start_date text, end_date text, profile_id uuid, cohort_ids uuid[] DEFAULT ARRAY[]::uuid[], department_ids uuid[] DEFAULT ARRAY[]::uuid[], roles public.profile_role[] DEFAULT ARRAY[]::public.profile_role[], simulation_filters text[] DEFAULT ARRAY[]::text[], search text DEFAULT NULL::text, profile_ids uuid[] DEFAULT ARRAY[]::uuid[], simulation_ids uuid[] DEFAULT ARRAY[]::uuid[], scenario_ids uuid[] DEFAULT ARRAY[]::uuid[], infinite_mode boolean DEFAULT NULL::boolean, sort_by text DEFAULT 'date'::text, sort_order text DEFAULT 'desc'::text, page integer DEFAULT 0, page_size integer DEFAULT 20) RETURNS TABLE(actor_name text, data types.q_reports_history_v4_attempt_history_row[], total_count bigint, archived_count bigint, unarchived_count bigint, page integer, page_size integer, total_pages bigint, profile_options types.q_reports_history_v4_filter_option[], simulation_options types.q_reports_history_v4_filter_option[], scenario_options types.q_reports_history_v4_filter_option[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        (start_date::timestamptz) AS start_date,
        (end_date::timestamptz) AS end_date,
        profile_id AS profile_id,
        COALESCE(cohort_ids, ARRAY[]::uuid[]) AS cohort_ids,
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids,
        COALESCE(roles, ARRAY[]::profile_role[]) AS roles,
        COALESCE(NULLIF(simulation_filters, ARRAY[]::text[]), ARRAY['general']::text[]) AS simulation_filters,
        COALESCE(NULLIF(search, ''), NULL) AS search,
        COALESCE(profile_ids, ARRAY[]::uuid[]) AS profile_ids,
        COALESCE(simulation_ids, ARRAY[]::uuid[]) AS simulation_ids,
        COALESCE(scenario_ids, ARRAY[]::uuid[]) AS scenario_ids,
        infinite_mode AS infinite_mode,
        COALESCE(NULLIF(sort_by, ''), 'date') AS sort_by,
        COALESCE(NULLIF(UPPER(sort_order), ''), 'DESC') AS sort_order,
        GREATEST(0, COALESCE(page, 0)) AS page,
        GREATEST(1, COALESCE(page_size, 20)) AS page_size,
        GREATEST(0, COALESCE(page, 0) * GREATEST(1, COALESCE(page_size, 20))) AS offset_val
),
-- Get actor name from profile
user_profile AS (
    SELECT 
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
-- Expanded cohort list: union of provided cohortIds + profileId cohorts (reports always filters by profile)
expanded_history_cohort_ids AS (
    SELECT DISTINCT cohort_id
    FROM (
        SELECT unnest((SELECT cohort_ids FROM params)::uuid[]) as cohort_id
        WHERE cardinality((SELECT cohort_ids FROM params)::uuid[]) > 0
        UNION
        SELECT cp.cohort_id
        FROM params p
        JOIN cohort_profiles cp ON cp.profile_id = p.profile_id
    ) combined
),
-- Filter attempts by date, profile, cohorts, departments
history_attempts AS (
    SELECT DISTINCT
        sa.id AS attempt_id,
        sa.simulation_id,
        sa.created_at AS attempt_date,
        sa.archived AS is_archived,
        sa.infinite_mode,
        ap.profile_id,
        sim.title AS simulation_name,
        sim.practice_simulation,
        COALESCE(sdd.department_ids, NULL) as department_ids
    FROM simulation_attempts sa
    JOIN attempt_profiles ap ON ap.attempt_id = sa.id AND ap.active = TRUE
    JOIN simulations sim ON sim.id = sa.simulation_id
    JOIN profiles p_attempt ON p_attempt.id = ap.profile_id
    LEFT JOIN (
        SELECT 
            sd.simulation_id,
            ARRAY_AGG(sd.department_id::text ORDER BY sd.created_at) as department_ids
        FROM simulation_departments sd
        WHERE sd.active = true
        GROUP BY sd.simulation_id
    ) sdd ON sdd.simulation_id = sim.id
    CROSS JOIN params p
    WHERE sa.created_at >= (SELECT start_date FROM params)
      AND sa.created_at <= (SELECT end_date FROM params)
      -- Reports always filters by profile_id (required parameter)
      AND ap.profile_id = (SELECT profile_id FROM params)
      -- Simulation type filtering: general (practice_simulation = FALSE), practice (practice_simulation = TRUE), archived (archived = TRUE)
      -- If no filters provided (NULL or empty), default to general only (matching old behavior: sim.practice_simulation = FALSE)
      AND (
        (cardinality((SELECT simulation_filters FROM params)::text[]) = 0) AND sim.practice_simulation = FALSE
        OR
        (cardinality((SELECT simulation_filters FROM params)::text[]) > 0 AND (
          ('general' = ANY((SELECT simulation_filters FROM params)::text[]) AND sim.practice_simulation = FALSE) OR
          ('practice' = ANY((SELECT simulation_filters FROM params)::text[]) AND sim.practice_simulation = TRUE) OR
          ('archived' = ANY((SELECT simulation_filters FROM params)::text[]) AND sa.archived = TRUE)
        ))
      )
      -- Exclude archived attempts unless 'archived' is explicitly in the filter list
      AND (
        cardinality((SELECT simulation_filters FROM params)::text[]) = 0 OR 'archived' = ANY((SELECT simulation_filters FROM params)::text[]) OR sa.archived = FALSE
      )
      AND (cardinality((SELECT department_ids FROM params)::uuid[]) = 0 OR sdd.department_ids IS NULL OR sdd.department_ids && (SELECT department_ids FROM params)::text[])
),
-- Get cohorts for each attempt's profile (includes inactive links for history)
history_attempt_cohorts AS (
    SELECT
        ha.attempt_id,
        COALESCE(ARRAY_AGG(DISTINCT c.id) FILTER (WHERE c.id IS NOT NULL AND cs.simulation_id = ha.simulation_id), ARRAY[]::uuid[]) AS cohort_ids,
        COALESCE(ARRAY_AGG(DISTINCT c.title) FILTER (WHERE c.id IS NOT NULL AND cs.simulation_id = ha.simulation_id), ARRAY[]::text[]) AS cohort_names
    FROM history_attempts ha
    LEFT JOIN cohort_profiles cp ON cp.profile_id = ha.profile_id
    LEFT JOIN cohorts c ON c.id = cp.cohort_id AND c.active = TRUE
    LEFT JOIN cohort_simulations cs ON cs.cohort_id = c.id
    WHERE (
        -- If no cohort filter, include all attempts
        (SELECT COUNT(*) FROM expanded_history_cohort_ids) = 0
        -- Otherwise, only include cohorts in the expanded list
        OR c.id IN (SELECT cohort_id FROM expanded_history_cohort_ids)
    )
    GROUP BY ha.attempt_id
),
-- Filter attempts by cohort membership (uses expanded cohort list)
history_attempts_filtered AS (
    SELECT ha.*
    FROM history_attempts ha
    JOIN history_attempt_cohorts hac ON hac.attempt_id = ha.attempt_id
    WHERE (
        -- If no cohort filter, include all attempts
        (SELECT COUNT(*) FROM expanded_history_cohort_ids) = 0
        -- Otherwise, only include attempts with matching cohorts
        OR cardinality(hac.cohort_ids) > 0
    )
),
-- Get all unique profile options from filtered attempts (before history-specific filters)
profile_options_cte AS (
    SELECT 
        haf.profile_id,
        p.first_name || ' ' || p.last_name AS profile_name,
        COUNT(DISTINCT haf.attempt_id) AS count
    FROM history_attempts_filtered haf
    JOIN profiles p ON p.id = haf.profile_id
    GROUP BY haf.profile_id, p.first_name, p.last_name
    ORDER BY profile_name
),
-- Get all unique simulation options from filtered attempts (before history-specific filters)
simulation_options_cte AS (
    SELECT 
        haf.simulation_id,
        s.title AS simulation_name,
        COUNT(DISTINCT haf.attempt_id) AS count
    FROM history_attempts_filtered haf
    JOIN simulations s ON s.id = haf.simulation_id
    GROUP BY haf.simulation_id, s.title
    ORDER BY simulation_name
),
-- Get all unique scenario options from filtered attempts (before history-specific filters)
scenario_options_cte AS (
    SELECT 
        sc.scenario_id,
        s.name AS scenario_title,
        COUNT(DISTINCT haf.attempt_id) AS count
    FROM history_attempts_filtered haf
    JOIN attempt_chats ac ON ac.attempt_id = haf.attempt_id
    JOIN chats sc ON sc.id = ac.chat_id
    JOIN scenarios s ON s.id = sc.scenario_id
    WHERE sc.scenario_id IS NOT NULL
    GROUP BY sc.scenario_id, s.name
    ORDER BY scenario_title
),
-- Apply additional filters (profileIds, simulationIds, scenarioIds, infiniteMode)
history_attempts_with_filters AS (
    SELECT haf.*
    FROM history_attempts_filtered haf
    WHERE 
        -- Profile filter
        (cardinality((SELECT profile_ids FROM params)::uuid[]) = 0 OR haf.profile_id = ANY((SELECT profile_ids FROM params)::uuid[]))
        -- Simulation filter
        AND (cardinality((SELECT simulation_ids FROM params)::uuid[]) = 0 OR haf.simulation_id = ANY((SELECT simulation_ids FROM params)::uuid[]))
        -- Infinite mode filter
        AND ((SELECT infinite_mode FROM params) IS NULL OR haf.infinite_mode = (SELECT infinite_mode FROM params))
),
-- Get scenario IDs for each attempt (for scenario filtering)
attempt_scenario_ids AS (
    SELECT DISTINCT
        ac.attempt_id,
        ARRAY_AGG(DISTINCT sc.scenario_id) FILTER (WHERE sc.scenario_id IS NOT NULL) AS scenario_ids
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_with_filters)
    GROUP BY ac.attempt_id
),
-- Apply scenario filter
history_attempts_final AS (
    SELECT haf.*
    FROM history_attempts_with_filters haf
    LEFT JOIN attempt_scenario_ids asi ON asi.attempt_id = haf.attempt_id
    WHERE 
        -- Scenario filter (if any scenario matches, include the attempt)
        (cardinality((SELECT scenario_ids FROM params)) = 0 OR asi.scenario_ids IS NULL OR asi.scenario_ids && (SELECT scenario_ids FROM params))
),
-- Aggregate chats per attempt
history_chat_rollup AS (
    SELECT
        ac.attempt_id,
        COUNT(*) FILTER (WHERE sc.completed) AS completed_chats,
        COUNT(*) FILTER (WHERE sc.completed = FALSE) AS incomplete_chats,
        MIN(sc.created_at) AS first_chat_at,
        MAX(sc.created_at) AS last_activity_at,
        array_agg(DISTINCT sc.scenario_id) FILTER (WHERE sc.scenario_id IS NOT NULL) AS scenario_ids_seen
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
    GROUP BY ac.attempt_id
),
-- Get latest grade per chat
history_chat_grades AS (
    SELECT DISTINCT ON (c.id)
        c.id AS chat_id,
        scg.score,
        rga.rubric_id
    FROM grades scg
    LEFT JOIN rubric_grade_agents rga ON rga.id = scg.rubric_grade_agent_id
    JOIN runs r ON r.id = scg.run_id
    JOIN group_runs gr ON gr.run_id = r.id
    JOIN grade_groups gg ON gg.group_id = gr.group_id
    JOIN chats c ON c.id = gg.chat_id
    WHERE EXISTS (
        SELECT 1 FROM runs r_check
        JOIN group_runs gr_check ON gr_check.run_id = r_check.id
        JOIN grade_groups gg_check ON gg_check.group_id = gr_check.group_id
        JOIN chats c_check ON c_check.id = gg_check.chat_id
        WHERE r_check.id = scg.run_id
    )
      AND c.id IN (
        SELECT sc.id FROM attempt_chats ac
        JOIN chats sc ON sc.id = ac.chat_id
        WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
    )
    ORDER BY c.id, scg.created_at DESC
),
-- Get first scenario's rubric per simulation (fallback when chat scenario doesn't match)
sim_first_scenario_rubric AS (
    SELECT DISTINCT ON (ss.simulation_id)
        ss.simulation_id,
        rga.rubric_id,
        r.points
    FROM simulation_scenarios ss
    LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
    LEFT JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
    LEFT JOIN rubrics r ON r.id = rga.rubric_id
    WHERE ss.active = true
      AND ss.simulation_id IN (SELECT DISTINCT simulation_id FROM history_attempts_final)
    ORDER BY ss.simulation_id, ss.position
),
-- Aggregate grades per attempt
history_grade_rollup AS (
    SELECT
        ac.attempt_id,
        COUNT(*) FILTER (WHERE hcg.score IS NOT NULL) AS completed_with_grade,
        SUM(CASE WHEN hcg.score IS NOT NULL AND COALESCE(r.points, r_fallback_scenario.points, r_fallback_first.points, 0) > 0
            THEN (hcg.score / COALESCE(r.points, r_fallback_scenario.points, r_fallback_first.points, 1)::numeric * 100.0)
            ELSE 0 END) AS sum_grade_percent
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    JOIN simulation_attempts sa ON sa.id = ac.attempt_id
    LEFT JOIN history_chat_grades hcg ON hcg.chat_id = sc.id
    LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga_fallback_scenario ON ssrga_fallback_scenario.simulation_id = sa.simulation_id
      AND ssrga_fallback_scenario.scenario_id = sc.scenario_id
      AND hcg.chat_id IS NOT NULL
      AND hcg.rubric_id IS NULL
    LEFT JOIN rubric_grade_agents rga_fallback_scenario ON rga_fallback_scenario.id = ssrga_fallback_scenario.rubric_grade_agent_id
    LEFT JOIN rubrics r ON r.id = hcg.rubric_id
    LEFT JOIN rubrics r_fallback_scenario ON r_fallback_scenario.id = rga_fallback_scenario.rubric_id
    LEFT JOIN sim_first_scenario_rubric sfsr ON sfsr.simulation_id = sa.simulation_id
      AND hcg.chat_id IS NOT NULL
      AND hcg.rubric_id IS NULL
      AND r_fallback_scenario.points IS NULL
    LEFT JOIN rubrics r_fallback_first ON r_fallback_first.id = sfsr.rubric_id
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
    GROUP BY ac.attempt_id
),
-- Calculate elapsed time per attempt (for infinite mode time limit checks)
history_elapsed_time AS (
    SELECT
        ac.attempt_id,
        COALESCE(
            SUM(
                CASE 
                    WHEN sc.completed AND hcg.chat_id IS NOT NULL THEN
                        (SELECT scg.time_taken FROM grades scg 
                         JOIN runs r ON r.id = scg.run_id
                         JOIN group_runs gr ON gr.run_id = r.id
                         JOIN grade_groups gg ON gg.group_id = gr.group_id
                         JOIN chats c ON c.id = gg.chat_id
                         WHERE c.id = sc.id 
                           AND EXISTS (
                               SELECT 1 FROM runs r_check
                               JOIN group_runs gr_check ON gr_check.run_id = r_check.id
                               JOIN grade_groups gg_check ON gg_check.group_id = gr_check.group_id
                               JOIN chats c_check ON c_check.id = gg_check.chat_id
                               WHERE r_check.id = scg.run_id
                           )
                         ORDER BY scg.created_at DESC LIMIT 1)
                    WHEN sc.completed THEN
                        EXTRACT(EPOCH FROM (
                            (SELECT scg.created_at FROM grades scg 
                             JOIN runs r ON r.id = scg.run_id
                             JOIN group_runs gr ON gr.run_id = r.id
                             JOIN grade_groups gg ON gg.group_id = gr.group_id
                             JOIN chats c ON c.id = gg.chat_id
                             WHERE c.id = sc.id 
                               AND EXISTS (
                                   SELECT 1 FROM runs r_check
                                   JOIN group_runs gr_check ON gr_check.run_id = r_check.id
                                   JOIN grade_groups gg_check ON gg_check.group_id = gr_check.group_id
                                   JOIN chats c_check ON c_check.id = gg_check.chat_id
                                   WHERE r_check.id = scg.run_id
                               )
                             ORDER BY scg.created_at DESC LIMIT 1) - sc.created_at
                        ))::integer
                    ELSE
                        EXTRACT(EPOCH FROM (NOW() - sc.created_at))::integer
                END
            ),
            0
        ) AS elapsed_seconds
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    LEFT JOIN history_chat_grades hcg ON hcg.chat_id = sc.id
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
    GROUP BY ac.attempt_id
),
-- Get personas for each attempt
history_personas AS (
    SELECT
        ac.attempt_id,
        array_agg(DISTINCT sp.persona_id) FILTER (WHERE sp.persona_id IS NOT NULL) AS persona_ids
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    JOIN scenarios scn ON scn.id = sc.scenario_id
    LEFT JOIN scenario_personas sp ON sp.scenario_id = scn.id AND sp.active = TRUE
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
    GROUP BY ac.attempt_id
),
-- Count scenarios per simulation
history_sim_scenario_count AS (
    SELECT
        s.id AS simulation_id,
        COUNT(ss.scenario_id)::int AS scenario_count
    FROM simulations s
    LEFT JOIN simulation_scenarios ss ON ss.simulation_id = s.id
    WHERE s.id IN (SELECT simulation_id FROM history_attempts_final)
    GROUP BY s.id
),
-- Get scenario info
history_scenario_ids AS (
    SELECT
        s.id AS simulation_id,
        ARRAY_AGG(ss.scenario_id ORDER BY ss.position)::uuid[] AS scenario_ids_assigned
    FROM simulations s
    LEFT JOIN simulation_scenarios ss ON ss.simulation_id = s.id
    WHERE s.id IN (SELECT simulation_id FROM history_attempts_final)
    GROUP BY s.id
),
-- Get first scenario_id from each attempt's first chat (for practice scenario retry)
history_first_scenario AS (
    SELECT DISTINCT ON (ac.attempt_id)
        ac.attempt_id,
        sc.scenario_id AS practice_scenario_id
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    WHERE ac.attempt_id IN (SELECT attempt_id FROM history_attempts_final)
    ORDER BY ac.attempt_id, sc.created_at ASC
),
-- Join all history data
attempt_rollup AS (
    SELECT
        haf.attempt_id,
        haf.simulation_id,
        haf.attempt_date,
        haf.is_archived,
        haf.infinite_mode,
        haf.profile_id,
        haf.simulation_name,
        haf.practice_simulation,
        haf.department_ids,
        COALESCE(hcr.first_chat_at, haf.attempt_date) AS first_chat_at,
        COALESCE(hcr.last_activity_at, haf.attempt_date) AS last_activity_at,
        COALESCE(hgr.completed_with_grade, 0) AS completed_with_grade,
        COALESCE(hssc.scenario_count, 0) AS sim_scenario_count,
        COALESCE(hgr.sum_grade_percent, 0) AS sum_grade_percent_zero_fill,
        COALESCE(hp.persona_ids, ARRAY[]::uuid[]) AS persona_ids_distinct,
        COALESCE(hcr.scenario_ids_seen, ARRAY[]::uuid[]) AS leaf_scenarios_seen,
        COALESCE(hcr.incomplete_chats, 0) AS incomplete_chats,
        COALESCE(het.elapsed_seconds, 0) AS elapsed_seconds,
        hfs.practice_scenario_id
    FROM history_attempts_final haf
    LEFT JOIN history_chat_rollup hcr ON hcr.attempt_id = haf.attempt_id
    LEFT JOIN history_grade_rollup hgr ON hgr.attempt_id = haf.attempt_id
    LEFT JOIN history_personas hp ON hp.attempt_id = haf.attempt_id
    LEFT JOIN history_sim_scenario_count hssc ON hssc.simulation_id = haf.simulation_id
    LEFT JOIN history_elapsed_time het ON het.attempt_id = haf.attempt_id
    LEFT JOIN history_first_scenario hfs ON hfs.attempt_id = haf.attempt_id
),
attempt_cohort_ids AS (
    SELECT
        attempt_id,
        cohort_ids AS profile_cohort_ids
    FROM history_attempt_cohorts
    WHERE attempt_id IN (SELECT attempt_id FROM history_attempts_final)
),
-- Get rubric data per simulation (one row per simulation)
simulation_rubrics AS (
    SELECT DISTINCT ON (ss.simulation_id)
        ss.simulation_id,
        r.id AS rubric_id,
        r.points AS rubric_points,
        r.pass_points AS rubric_pass_points
    FROM simulation_scenarios ss
    LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
    LEFT JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
    LEFT JOIN rubrics r ON r.id = rga.rubric_id
    WHERE ss.active = true
      AND ss.simulation_id IN (SELECT DISTINCT simulation_id FROM attempt_rollup)
    ORDER BY ss.simulation_id, ss.position
),
attempt_joined AS (
    SELECT
        ar.*,
        hsi.scenario_ids_assigned,
        sr.rubric_id,
        sr.rubric_points,
        sr.rubric_pass_points,
        CASE
            WHEN sr.rubric_points IS NULL OR sr.rubric_points = 0 THEN NULL
            ELSE ROUND((sr.rubric_pass_points::numeric / sr.rubric_points::numeric) * 100.0)::int
        END AS pass_pct,
        (p.first_name || ' ' || p.last_name) AS profile_name,
        COALESCE(
            (SELECT SUM(stl.time_limit_seconds)
             FROM scenario_time_limits stl
             JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
             WHERE stl.simulation_id = s.id AND stl.active = true AND ss.active = true),
            0
        ) as time_limit_seconds
    FROM attempt_rollup ar
    JOIN simulations s ON s.id = ar.simulation_id
    LEFT JOIN history_scenario_ids hsi ON hsi.simulation_id = ar.simulation_id
    LEFT JOIN simulation_rubrics sr ON sr.simulation_id = s.id
    JOIN profiles p ON p.id = ar.profile_id
),
attempt_cohort_names AS (
    SELECT
        attempt_id,
        cohort_names
    FROM history_attempt_cohorts
    WHERE attempt_id IN (SELECT attempt_id FROM history_attempts_final)
),
final_rows AS (
    SELECT
        aj.attempt_id,
        aj.simulation_id,
        aj.profile_id,
        aj.profile_name,
        aj.simulation_name,
        aj.scenario_ids_assigned,
        aj.is_archived,
        aj.practice_simulation,
        aj.pass_pct,
        aj.infinite_mode,
        aj.attempt_date,
        aj.department_ids,
        aj.practice_scenario_id,
        CASE WHEN aj.infinite_mode THEN NULL ELSE COALESCE(aj.sim_scenario_count, 0) END AS num_scenarios,
        COALESCE(aj.completed_with_grade, 0) AS num_scenarios_completed,
        CASE
            WHEN aj.infinite_mode THEN
                CASE GREATEST(array_length(aj.leaf_scenarios_seen, 1), 0)
                    WHEN 0 THEN NULL
                    ELSE ROUND(aj.sum_grade_percent_zero_fill / GREATEST(array_length(aj.leaf_scenarios_seen, 1), 1))::int
                END
            ELSE
                CASE COALESCE(aj.sim_scenario_count, 0)
                    WHEN 0 THEN NULL
                    ELSE CASE
                            WHEN aj.completed_with_grade = 0 THEN NULL
                            ELSE ROUND(aj.sum_grade_percent_zero_fill / NULLIF(aj.sim_scenario_count, 0))::int
                        END
                END
        END AS score,
        CASE
            WHEN aj.infinite_mode THEN
                CASE GREATEST(array_length(aj.leaf_scenarios_seen, 1), 0)
                    WHEN 0 THEN NULL
                    ELSE CASE
                        WHEN ROUND(aj.sum_grade_percent_zero_fill / GREATEST(array_length(aj.leaf_scenarios_seen, 1), 1))::int >= 80 THEN 'high'
                        WHEN ROUND(aj.sum_grade_percent_zero_fill / GREATEST(array_length(aj.leaf_scenarios_seen, 1), 1))::int >= 70 THEN 'medium'
                        ELSE 'low'
                    END
                END
            ELSE
                CASE COALESCE(aj.sim_scenario_count, 0)
                    WHEN 0 THEN NULL
                    ELSE CASE
                        WHEN aj.completed_with_grade = 0 THEN NULL
                        ELSE CASE
                            WHEN ROUND(aj.sum_grade_percent_zero_fill / NULLIF(aj.sim_scenario_count, 0))::int >= 80 THEN 'high'
                            WHEN ROUND(aj.sum_grade_percent_zero_fill / NULLIF(aj.sim_scenario_count, 0))::int >= 70 THEN 'medium'
                            ELSE 'low'
                        END
                    END
                END
        END AS score_status,
        (NOT aj.is_archived) AS show_view,
        (NOT aj.is_archived) AND (
            (aj.infinite_mode
                AND (
                    -- No time limit OR time limit not exceeded
                    (aj.time_limit_seconds IS NULL OR aj.elapsed_seconds < aj.time_limit_seconds)
                    -- AND there are incomplete chats (pending work)
                    AND aj.incomplete_chats > 0
                ))
            OR
            (NOT aj.infinite_mode
                AND aj.sim_scenario_count IS NOT NULL
                AND COALESCE(aj.completed_with_grade, 0) < aj.sim_scenario_count)
        ) AS show_continue,
        aj.persona_ids_distinct
    FROM attempt_joined aj
),
-- Apply search filter (searches profile name, simulation name, persona names)
final_rows_with_search AS (
    SELECT fr.*
    FROM final_rows fr
    WHERE 
        -- Search filter: if search term provided, search in profile name, simulation name, or persona names
        ((SELECT search FROM params) IS NULL OR (SELECT search FROM params) = '' OR
         LOWER(fr.profile_name) LIKE '%' || LOWER((SELECT search FROM params)) || '%' OR
         LOWER(fr.simulation_name) LIKE '%' || LOWER((SELECT search FROM params)) || '%' OR
         EXISTS (
             SELECT 1
             FROM unnest(fr.persona_ids_distinct) AS pid
             JOIN personas per ON per.id = pid
             WHERE LOWER(per.name) LIKE '%' || LOWER((SELECT search FROM params)) || '%'
         ))
),
persona_labels AS (
    SELECT
        fr.attempt_id,
        COALESCE(ARRAY_AGG(per.name ORDER BY per.name) FILTER (WHERE per.name IS NOT NULL), ARRAY[]::text[]) AS persona_names,
        COALESCE(ARRAY_AGG(per.color ORDER BY per.name) FILTER (WHERE per.color IS NOT NULL), ARRAY[]::text[]) AS persona_colors
    FROM final_rows_with_search fr
    LEFT JOIN LATERAL (
        SELECT DISTINCT per.name, per.color
        FROM unnest(fr.persona_ids_distinct) AS pid
        JOIN personas per ON per.id = pid
    ) per ON TRUE
    GROUP BY fr.attempt_id
),
scenario_names AS (
    SELECT
        fr.attempt_id,
        COALESCE(sn.names, ARRAY[]::text[]) AS names
    FROM final_rows_with_search fr
    LEFT JOIN LATERAL (
        SELECT ARRAY_AGG(s.name ORDER BY s.name) AS names
        FROM unnest(fr.scenario_ids_assigned) sid
        JOIN scenarios s ON s.id = sid
    ) sn ON TRUE
),
-- Get total count before pagination
total_count_cte AS (
    SELECT COUNT(*)::bigint AS total_count
    FROM final_rows_with_search
),
-- Get archived and unarchived counts for filtered set
archive_counts_cte AS (
    SELECT 
        COUNT(*) FILTER (WHERE is_archived = true)::bigint AS archived_count,
        COUNT(*) FILTER (WHERE is_archived = false)::bigint AS unarchived_count
    FROM final_rows_with_search
),
-- Paginated and sorted results
paginated_rows AS (
    SELECT
        fr.attempt_id,
        fr.attempt_date,
        fr.profile_id,
        fr.profile_name,
        fr.simulation_name,
        fr.num_scenarios,
        fr.num_scenarios_completed,
        fr.infinite_mode,
        fr.score,
        fr.score_status,
        fr.simulation_id,
        fr.scenario_ids_assigned,
        fr.is_archived,
        fr.show_view,
        fr.show_continue,
        fr.practice_simulation,
        fr.pass_pct,
        fr.department_ids,
        fr.practice_scenario_id,
        fr.persona_ids_distinct
    FROM final_rows_with_search fr
    ORDER BY 
        CASE 
            WHEN (SELECT sort_by FROM params) = 'date' AND (SELECT sort_order FROM params) = 'desc' THEN fr.attempt_date
        END DESC NULLS LAST,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'date' AND (SELECT sort_order FROM params) = 'asc' THEN fr.attempt_date
        END ASC NULLS LAST,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'simulationName' AND (SELECT sort_order FROM params) = 'desc' THEN fr.simulation_name
        END DESC NULLS LAST,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'simulationName' AND (SELECT sort_order FROM params) = 'asc' THEN fr.simulation_name
        END ASC NULLS LAST,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'score' AND (SELECT sort_order FROM params) = 'desc' THEN COALESCE(fr.score, -1)
        END DESC,
        CASE 
            WHEN (SELECT sort_by FROM params) = 'score' AND (SELECT sort_order FROM params) = 'asc' THEN COALESCE(fr.score, 999999)
        END ASC,
        fr.attempt_id DESC
    LIMIT (SELECT page_size FROM params)
    OFFSET (SELECT offset_val FROM params)
),
-- Convert paginated rows to composite types
data_agg AS (
    SELECT COALESCE(
        ARRAY_AGG(
            (
                pr.attempt_id,
                pr.attempt_date,
                pr.profile_id,
                pr.profile_name,
                pr.simulation_name,
                pr.num_scenarios,
                pr.num_scenarios_completed,
                pr.infinite_mode,
                COALESCE(
                    (SELECT SUM(stl.time_limit_seconds)
                     FROM scenario_time_limits stl
                     JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
                     WHERE stl.simulation_id = pr.simulation_id AND stl.active = true AND ss.active = true),
                    0
                ),
                COALESCE(pl.persona_names, ARRAY[]::text[]),
                COALESCE(pl.persona_colors, ARRAY[]::text[]),
                pr.score,
                pr.score_status,
                pr.simulation_id,
                COALESCE(pr.scenario_ids_assigned, ARRAY[]::uuid[])::text[],
                COALESCE(sn.names, ARRAY[]::text[]),
                pr.is_archived,
                pr.show_view,
                pr.show_continue,
                COALESCE(pr.practice_simulation, false),
                pr.pass_pct,
                pr.department_ids,
                COALESCE(acn.cohort_names, ARRAY[]::text[]),
                pr.practice_scenario_id
            )::types.q_reports_history_v4_attempt_history_row
            ORDER BY 
                CASE 
                    WHEN (SELECT sort_by FROM params) = 'date' AND (SELECT sort_order FROM params) = 'desc' THEN pr.attempt_date
                END DESC NULLS LAST,
                CASE 
                    WHEN (SELECT sort_by FROM params) = 'date' AND (SELECT sort_order FROM params) = 'asc' THEN pr.attempt_date
                END ASC NULLS LAST,
                CASE 
                    WHEN (SELECT sort_by FROM params) = 'simulationName' AND (SELECT sort_order FROM params) = 'desc' THEN pr.simulation_name
                END DESC NULLS LAST,
                CASE 
                    WHEN (SELECT sort_by FROM params) = 'simulationName' AND (SELECT sort_order FROM params) = 'asc' THEN pr.simulation_name
                END ASC NULLS LAST,
                CASE 
                    WHEN (SELECT sort_by FROM params) = 'score' AND (SELECT sort_order FROM params) = 'desc' THEN COALESCE(pr.score, -1)
                END DESC,
                CASE 
                    WHEN (SELECT sort_by FROM params) = 'score' AND (SELECT sort_order FROM params) = 'asc' THEN COALESCE(pr.score, 999999)
                END ASC,
                pr.attempt_id DESC
        ),
        ARRAY[]::types.q_reports_history_v4_attempt_history_row[]
    ) AS data
    FROM paginated_rows pr
    LEFT JOIN persona_labels pl ON pl.attempt_id = pr.attempt_id
    LEFT JOIN scenario_names sn ON sn.attempt_id = pr.attempt_id
    LEFT JOIN attempt_cohort_names acn ON acn.attempt_id = pr.attempt_id
),
-- Convert options to composite types
profile_options_agg AS (
    SELECT COALESCE(
        ARRAY_AGG(
            (profile_id::text, profile_name, count)::types.q_reports_history_v4_filter_option
            ORDER BY profile_name
        ),
        ARRAY[]::types.q_reports_history_v4_filter_option[]
    ) AS profile_options
    FROM profile_options_cte
),
simulation_options_agg AS (
    SELECT COALESCE(
        ARRAY_AGG(
            (simulation_id::text, simulation_name, count)::types.q_reports_history_v4_filter_option
            ORDER BY simulation_name
        ),
        ARRAY[]::types.q_reports_history_v4_filter_option[]
    ) AS simulation_options
    FROM simulation_options_cte
),
scenario_options_agg AS (
    SELECT COALESCE(
        ARRAY_AGG(
            (scenario_id::text, scenario_title, count)::types.q_reports_history_v4_filter_option
            ORDER BY scenario_title
        ),
        ARRAY[]::types.q_reports_history_v4_filter_option[]
    ) AS scenario_options
    FROM scenario_options_cte
)
SELECT
    (SELECT actor_name FROM user_profile)::text AS actor_name,
    COALESCE((SELECT data FROM data_agg LIMIT 1), ARRAY[]::types.q_reports_history_v4_attempt_history_row[]) AS data,
    COALESCE((SELECT total_count FROM total_count_cte LIMIT 1), 0)::bigint AS total_count,
    COALESCE((SELECT archived_count FROM archive_counts_cte LIMIT 1), 0)::bigint AS archived_count,
    COALESCE((SELECT unarchived_count FROM archive_counts_cte LIMIT 1), 0)::bigint AS unarchived_count,
    (SELECT page FROM params)::int AS page,
    (SELECT page_size FROM params)::int AS page_size,
    CASE 
        WHEN (SELECT page_size FROM params) > 0 
        THEN ((COALESCE((SELECT total_count FROM total_count_cte LIMIT 1), 0) + (SELECT page_size FROM params) - 1) / (SELECT page_size FROM params))::bigint
        ELSE 0::bigint
    END AS total_pages,
    COALESCE((SELECT profile_options FROM profile_options_agg LIMIT 1), ARRAY[]::types.q_reports_history_v4_filter_option[]) AS profile_options,
    COALESCE((SELECT simulation_options FROM simulation_options_agg LIMIT 1), ARRAY[]::types.q_reports_history_v4_filter_option[]) AS simulation_options,
    COALESCE((SELECT scenario_options FROM scenario_options_agg LIMIT 1), ARRAY[]::types.q_reports_history_v4_filter_option[]) AS scenario_options
$$;


--
-- Name: api_get_reports_overview_v4(text, text, uuid, uuid[], public.profile_role[], text[], uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_reports_overview_v4(start_date text, end_date text, profile_id uuid, cohort_ids uuid[] DEFAULT ARRAY[]::uuid[], roles public.profile_role[] DEFAULT ARRAY[]::public.profile_role[], simulation_filters text[] DEFAULT ARRAY[]::text[], department_ids uuid[] DEFAULT ARRAY[]::uuid[]) RETURNS TABLE(actor_name text, header_metrics types.q_reports_overview_v4_header_metrics, primary_metrics types.q_reports_overview_v4_primary_metrics, secondary_metrics types.q_reports_overview_v4_secondary_metrics, footer_metrics types.q_reports_overview_v4_footer_metrics, history types.q_reports_overview_v4_attempt_history_row[], insights types.q_reports_overview_v4_insights, thresholds types.q_reports_overview_v4_thresholds, simulations types.q_reports_overview_v4_simulation[], rubrics types.q_reports_overview_v4_rubric[], parameters types.q_reports_overview_v4_parameter[], fields types.q_reports_overview_v4_field[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        (start_date::timestamptz) AS start_date,
        (end_date::timestamptz) AS end_date,
        profile_id AS profile_id,
        COALESCE(cohort_ids, ARRAY[]::uuid[]) AS cohort_ids,
        COALESCE(roles, ARRAY[]::profile_role[]) AS roles,
        COALESCE(NULLIF(simulation_filters, ARRAY[]::text[]), ARRAY['general']::text[]) AS simulation_filters,
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids
),
-- Get actor name from profile
user_profile AS (
    SELECT 
        COALESCE(
            (SELECT first_name || ' ' || last_name FROM profiles WHERE id = (SELECT profile_id FROM params) LIMIT 1),
            'System'
        ) as actor_name
),
-- Get thresholds from active settings (defaults if no settings found)
settings_thresholds AS (
    SELECT 
        COALESCE(success_threshold, 85) AS success_threshold,
        COALESCE(warning_threshold, 80) AS warning_threshold,
        COALESCE(danger_threshold, 70) AS danger_threshold
    FROM settings
    WHERE active = true
    LIMIT 1
),
-- Filter simulations by cohorts (new filtering order: cohorts → simulations)
-- Gets simulations linked to cohorts + practice simulations without cohorts
filtered_simulation_ids AS (
    SELECT DISTINCT s.id AS simulation_id
    FROM simulations s
    WHERE s.active = TRUE
      AND (
          -- If cohort_ids provided, get simulations linked to those cohorts
                      (cardinality((SELECT cohort_ids FROM params)::uuid[]) > 0 AND EXISTS (
              SELECT 1 
              FROM cohort_simulations cs 
              WHERE cs.simulation_id = s.id 
                            AND cs.cohort_id = ANY((SELECT cohort_ids FROM params)::uuid[])
                AND cs.active = TRUE
          ))
          OR
          -- Always include practice simulations without cohorts
          (s.practice_simulation = TRUE 
           AND NOT EXISTS (
               SELECT 1 
               FROM cohort_simulations cs2 
               WHERE cs2.simulation_id = s.id 
                 AND cs2.active = TRUE
           ))
          OR
          -- If no cohort_ids provided, include all simulations
                      (cardinality((SELECT cohort_ids FROM params)::uuid[]) = 0)
      )
),
filt AS (
    SELECT * FROM analytics a
    WHERE a.attempt_created_at >= (SELECT start_date FROM params)
        AND a.attempt_created_at < (SELECT end_date FROM params)
                    AND ((SELECT simulation_filters FROM params)::text[] IS NULL OR cardinality((SELECT simulation_filters FROM params)::text[]) > 0)
                    AND (
                        (SELECT simulation_filters FROM params)::text[] IS NULL OR (
                            ('general' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_general = TRUE) OR
                            ('practice' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_practice = TRUE) OR
                            ('archived' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_archived = TRUE)
            )
        )
        -- Exclude archived attempts unless 'archived' is explicitly in the filter list
        AND (
                        'archived' = ANY((SELECT simulation_filters FROM params)::text[]) OR a.is_archived = FALSE
        )
        -- Reports always filters by profile_id (required parameter)
                    AND a.profile_id = (SELECT profile_id FROM params)
        -- Filter by simulation_ids from cohorts (new filtering order)
                    AND (cardinality((SELECT cohort_ids FROM params)::uuid[]) = 0 OR a.simulation_id IN (SELECT simulation_id FROM filtered_simulation_ids))
        -- Filter by department_ids (empty array = all departments)
                    AND (cardinality((SELECT department_ids FROM params)::uuid[]) = 0 OR a.department_id = ANY((SELECT department_ids FROM params)::uuid[]))
            ),
            
            -- =====================================================
            -- HEADER METRICS (10 metrics)
            -- =====================================================
            
            -- Attempt normalization for average_score
            per_attempt AS (
                SELECT
                    attempt_id,
                    MIN(attempt_created_at) AS attempt_created_at,
                    (array_agg(profile_id))[1] AS profile_id,
                    COALESCE(MAX(sim_scenario_count), 0) AS expected_from_sim,
                    COUNT(*) FILTER (WHERE completed) AS completed_chats,
                    COUNT(*) FILTER (WHERE completed AND grade_percent IS NOT NULL) AS graded_chats,
                    COUNT(*) AS chats_in_attempt,
                    SUM(grade_percent) FILTER (WHERE grade_percent IS NOT NULL) AS sum_grade_percent
                FROM filt
                GROUP BY attempt_id
            ),
            attempt_norm AS (
                SELECT
                    attempt_id,
                    attempt_created_at,
                    profile_id,
                    GREATEST(expected_from_sim, chats_in_attempt) AS expected,
                    completed_chats,
                    graded_chats,
                    CASE
                        WHEN GREATEST(expected_from_sim, chats_in_attempt) > 0 
                             AND completed_chats > 0 
                             AND completed_chats = graded_chats
                        THEN (sum_grade_percent / GREATEST(expected_from_sim, chats_in_attempt))
                        ELSE NULL
                    END AS norm
                FROM per_attempt
            ),
            
            -- Average Score
            header_avg_score AS (
                SELECT ROUND(AVG(norm))::int AS current_value,
                       COUNT(*) > 0 AS has_data
                FROM attempt_norm WHERE norm IS NOT NULL
            ),
            
            -- Completion Percentage (chat-level aggregation from old stored procedure)
            header_completion AS (
                SELECT ROUND(100.0 * AVG((completed)::int))::int AS current_value,
                       COUNT(*) > 0 AS has_data
                FROM filt
            ),
            
            -- First Attempt Pass Rate (earliest attempt all-time, then filter to window)
            earliest_attempt_all_time AS (
                SELECT DISTINCT ON (a.profile_id, a.simulation_id)
                       a.attempt_id, a.profile_id, a.simulation_id, a.attempt_created_at,
                       a.grade_percent, a.rubric_pass_points, a.rubric_points
                FROM analytics a
                WHERE (
                    -- Match simulation type filters
                    ('general' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_general = TRUE) OR
                    ('practice' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_practice = TRUE) OR
                    ('archived' = ANY((SELECT simulation_filters FROM params)::text[]) AND a.is_archived = TRUE)
                )
                -- Exclude archived attempts unless 'archived' is explicitly in the filter list
                AND (
                    'archived' = ANY((SELECT simulation_filters FROM params)::text[]) OR a.is_archived = FALSE
                )
                -- Dashboard never filters by profile - always filter by roles
                AND a.profile_id = (SELECT profile_id FROM params)
                -- Filter by simulation_ids from cohorts (new filtering order)
                AND (cardinality((SELECT cohort_ids FROM params)::uuid[]) = 0 OR a.simulation_id IN (SELECT simulation_id FROM filtered_simulation_ids))
                -- Filter by department_ids (empty array = all departments)
                AND (cardinality((SELECT department_ids FROM params)::uuid[]) = 0 OR a.department_id = ANY((SELECT department_ids FROM params)::uuid[]))
                ORDER BY a.profile_id, a.simulation_id, a.attempt_created_at
            ),
            first_attempts AS (
                SELECT * FROM earliest_attempt_all_time
                WHERE attempt_created_at >= (SELECT start_date FROM params) AND attempt_created_at < (SELECT end_date FROM params)
            ),
            header_first_pass AS (
                SELECT
                    ROUND(100.0 * COUNT(*) FILTER (WHERE grade_percent >= (rubric_pass_points * 100.0 / NULLIF(rubric_points, 0))) / GREATEST(COUNT(*), 1))::int AS current_value,
                    COUNT(*) > 0 AS has_data
                FROM first_attempts
            ),
            
            -- Highest Score
            header_highest AS (
                SELECT ROUND(MAX(grade_percent))::int AS current_value,
                       COUNT(*) > 0 AS has_data
                FROM filt WHERE grade_percent IS NOT NULL
            ),
            
            -- Messages Per Session
            header_messages AS (
                SELECT ROUND(AVG(num_messages_total))::int AS current_value,
                       COUNT(*) > 0 AS has_data
                FROM filt WHERE num_messages_total IS NOT NULL
            ),
            
            -- Persona Response Times
            persona_times AS (
                SELECT UNNEST(message_time_taken_seconds) AS delta_sec
                FROM filt 
                WHERE cardinality(message_time_taken_seconds) > 0
            ),
            header_persona_times AS (
                SELECT ROUND(AVG(delta_sec))::int AS current_value,
                       COUNT(*) > 0 AS has_data
                FROM persona_times
            ),
            
            -- Session Efficiency (old formula: avgScore * (1 - min(1, avgMinutes/120)))
            user_metrics_for_efficiency AS (
                SELECT
                    AVG(grade_percent) FILTER (WHERE grade_percent IS NOT NULL) AS avg_score,
                    SUM(time_taken_seconds / 60.0) FILTER (WHERE time_taken_seconds IS NOT NULL) AS total_minutes,
                    COUNT(DISTINCT chat_id) AS total_sessions
                FROM filt
            ),
            header_efficiency AS (
                SELECT 
                    GREATEST(0, LEAST(100, ROUND(
                        avg_score * (1.0 - LEAST(1.0, (total_minutes / NULLIF(total_sessions, 0)) / 120.0))
                    )))::int AS current_value,
                    total_sessions > 0 AS has_data
                FROM user_metrics_for_efficiency
            ),
            
            -- Stagnation Rate (grade-stream approach from old stored procedure)
            filtered_chats_for_stagnation AS (
                SELECT DISTINCT chat_id FROM filt WHERE chat_id IS NOT NULL
            ),
            -- Get chat scenario and simulation info for stagnation fallback
            chat_scenario_info_stagnation AS (
                SELECT DISTINCT
                    c.id AS chat_id,
                    c.scenario_id,
                    sa.simulation_id
                FROM chats c
                JOIN attempt_chats ac ON ac.chat_id = c.id
                JOIN simulation_attempts sa ON sa.id = ac.attempt_id
                WHERE c.id IN (SELECT chat_id FROM filtered_chats_for_stagnation)
            ),
            -- Get first scenario's rubric per simulation for stagnation (fallback)
            sim_first_scenario_rubric_stagnation AS (
                SELECT DISTINCT ON (ss.simulation_id)
                    ss.simulation_id,
                    rga.rubric_id,
                    r.points
                FROM simulation_scenarios ss
                LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
                LEFT JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
                LEFT JOIN rubrics r ON r.id = rga.rubric_id
                WHERE ss.active = true
                  AND ss.simulation_id IN (SELECT DISTINCT simulation_id FROM chat_scenario_info_stagnation)
                ORDER BY ss.simulation_id, ss.position
            ),
            grade_stream AS (
                SELECT
                    sg.id,
                    c_stag.id AS simulation_chat_id,
                    sg.created_at,
                    (sg.score::numeric / NULLIF(COALESCE(r.points, r_fallback_scenario.points, r_fallback_first.points, 0), 0)) * 100.0 AS norm
                FROM grades sg
                LEFT JOIN rubric_grade_agents rga ON rga.id = sg.rubric_grade_agent_id
                JOIN runs r_stag ON r_stag.id = sg.run_id
                JOIN group_runs gr_stag ON gr_stag.run_id = r_stag.id
                JOIN grade_groups gg_stag ON gg_stag.group_id = gr_stag.group_id
                JOIN chats c_stag ON c_stag.id = gg_stag.chat_id
                JOIN filtered_chats_for_stagnation fc ON fc.chat_id = c_stag.id
                LEFT JOIN chat_scenario_info_stagnation csi ON csi.chat_id = c_stag.id
                LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga_fallback ON ssrga_fallback.simulation_id = csi.simulation_id
                  AND ssrga_fallback.scenario_id = csi.scenario_id
                  AND rga.rubric_id IS NULL
                LEFT JOIN rubric_grade_agents rga_fallback_scenario ON rga_fallback_scenario.id = ssrga_fallback.rubric_grade_agent_id
                LEFT JOIN rubrics r ON r.id = rga.rubric_id
                LEFT JOIN rubrics r_fallback_scenario ON r_fallback_scenario.id = rga_fallback_scenario.rubric_id
                LEFT JOIN sim_first_scenario_rubric_stagnation sfsr ON sfsr.simulation_id = csi.simulation_id
                  AND rga.rubric_id IS NULL
                  AND r_fallback_scenario.points IS NULL
                LEFT JOIN rubrics r_fallback_first ON r_fallback_first.id = sfsr.rubric_id
                WHERE EXISTS (
                    SELECT 1 FROM runs r_check
                    JOIN group_runs gr_check ON gr_check.run_id = r_check.id
                    JOIN grade_groups gg_check ON gg_check.group_id = gr_check.group_id
                    JOIN chats c_check ON c_check.id = gg_check.chat_id
                    WHERE r_check.id = sg.run_id
                )
                  AND COALESCE(r.points, r_fallback_scenario.points, r_fallback_first.points, 0) > 0
            ),
            ordered_grades AS (
                SELECT *,
                       LAG(norm) OVER (ORDER BY created_at) AS prev_norm
                FROM grade_stream
            ),
            stagnation_flags AS (
                SELECT *,
                       CASE WHEN prev_norm IS NULL THEN NULL
                            WHEN norm <= prev_norm + 0.1 THEN 1 
                            ELSE 0 
                       END AS stagnated
                FROM ordered_grades
                WHERE prev_norm IS NOT NULL
            ),
            header_stagnation AS (
                SELECT ROUND(100.0 * AVG(stagnated))::int AS current_value,
                       COUNT(*) > 0 AS has_data
                FROM stagnation_flags
            ),
            
            -- Time Spent (SUM with 30-minute cap per chat, in minutes)
            header_time AS (
                SELECT ROUND(SUM(LEAST(time_taken_seconds / 60.0, 30.0)))::int AS current_value,
                       COUNT(*) > 0 AS has_data
                FROM filt 
                WHERE time_taken_seconds IS NOT NULL
            ),
            
            -- Total Attempts
            header_attempts AS (
                SELECT COUNT(DISTINCT attempt_id)::int AS current_value,
                       COUNT(*) > 0 AS has_data
                FROM filt
            ),
            
            -- =====================================================
            -- HEADER METRICS TREND DATA (for trend charts)
            -- =====================================================
            
            -- Average Score Trend (using attempt normalization)
            header_avg_score_trend AS (
                SELECT 
                    to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(AVG(norm))::float AS value,
                    COUNT(*)::int AS count
                FROM attempt_norm
                WHERE norm IS NOT NULL
                GROUP BY date
                ORDER BY date
            ),
            
            -- Completion Percentage Trend
            header_completion_trend AS (
                SELECT 
                    to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(100.0 * AVG((completed)::int))::float AS value,
                    COUNT(*)::int AS count
                FROM filt
                GROUP BY date
                ORDER BY date
            ),
            
            -- First Attempt Pass Rate Trend
            header_first_pass_trend AS (
                SELECT 
                    to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(100.0 * COUNT(*) FILTER (WHERE grade_percent >= (rubric_pass_points * 100.0 / NULLIF(rubric_points, 0))) / GREATEST(COUNT(*), 1))::float AS value,
                    COUNT(*)::int AS count
                FROM first_attempts
                GROUP BY date
                ORDER BY date
            ),
            
            -- Highest Score Trend
            header_highest_trend AS (
                SELECT 
                    to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(MAX(grade_percent))::float AS value,
                    COUNT(*)::int AS count
                FROM filt
                WHERE grade_percent IS NOT NULL
                GROUP BY date
                ORDER BY date
            ),
            
            -- Messages Per Session Trend
            header_messages_trend AS (
                SELECT 
                    to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(AVG(num_messages_total))::float AS value,
                    COUNT(*)::int AS count
                FROM filt
                WHERE num_messages_total IS NOT NULL
                GROUP BY date
                ORDER BY date
            ),
            
            -- Persona Response Times Trend
            header_persona_times_trend AS (
                SELECT 
                    to_char(pt.attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(AVG(pt.delta_sec))::float AS value,
                    COUNT(*)::int AS count
                FROM (
                    SELECT attempt_created_at, UNNEST(message_time_taken_seconds) AS delta_sec
                    FROM filt
                    WHERE cardinality(message_time_taken_seconds) > 0
                ) pt
                GROUP BY date
                ORDER BY date
            ),
            
            -- Session Efficiency Trend (user-level aggregation by date)
            user_metrics_for_efficiency_by_date AS (
                SELECT 
                    to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                    profile_id,
                    AVG(grade_percent) FILTER (WHERE grade_percent IS NOT NULL) AS avg_score,
                    SUM(time_taken_seconds / 60.0) FILTER (WHERE time_taken_seconds IS NOT NULL) AS total_minutes,
                    COUNT(DISTINCT chat_id) AS total_sessions
                FROM filt
                GROUP BY date, profile_id
            ),
            header_efficiency_trend AS (
                SELECT 
                    date,
                    ROUND(GREATEST(0, LEAST(100, AVG(
                        avg_score * (1.0 - LEAST(1.0, (total_minutes / NULLIF(total_sessions, 0)) / 120.0))
                    ))))::float AS value,
                    COUNT(*)::int AS count
                FROM user_metrics_for_efficiency_by_date
                WHERE total_sessions > 0
                GROUP BY date
                ORDER BY date
            ),
            
            -- Stagnation Rate Trend
            header_stagnation_trend AS (
                SELECT 
                    to_char(created_at, 'YYYY-MM-DD') AS date,
                    ROUND(100.0 * AVG(stagnated))::float AS value,
                    COUNT(*)::int AS count
                FROM stagnation_flags
                GROUP BY date
                ORDER BY date
            ),
            
            -- Time Spent Trend (with 30-minute cap per chat)
            header_time_trend AS (
                SELECT 
                    to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(AVG(LEAST(30.0, time_taken_seconds / 60.0)))::float AS value,
                    COUNT(*)::int AS count
                FROM filt
                WHERE time_taken_seconds IS NOT NULL
                GROUP BY date
                ORDER BY date
            ),
            
            -- Total Attempts Trend
            header_attempts_trend AS (
                SELECT 
                    to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                    COUNT(DISTINCT attempt_id)::float AS value,
                    COUNT(*)::int AS count
                FROM filt
                GROUP BY date
                ORDER BY date
            ),
            
            -- =====================================================
            -- HEADER METRICS DATA POINTS (for hover tooltips)
            -- =====================================================
            
            -- Average Score Data Points
            header_avg_score_points AS (
                SELECT 
                    COALESCE(an.profile_id::text, '') AS profile_id,
                    to_char(an.attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(an.norm)::int AS value,
                    COALESCE(an.attempt_id::text, '') AS attempt_id,
                    ''::text AS simulation_id,
                    ''::text AS scenario_id
                FROM attempt_norm an
                WHERE an.norm IS NOT NULL
                ORDER BY an.profile_id, an.attempt_created_at
            ),
            
            -- Completion Percentage Data Points
            header_completion_points AS (
                SELECT 
                    f.profile_id::text AS profile_id,
                    to_char(f.attempt_created_at, 'YYYY-MM-DD') AS date,
                    (f.completed::int * 100)::int AS value,
                    f.attempt_id::text AS attempt_id,
                    f.simulation_id::text AS simulation_id,
                    f.scenario_id::text AS scenario_id
                FROM filt f
                ORDER BY f.profile_id, f.attempt_created_at
            ),
            
            -- First Attempt Pass Rate Data Points
            header_first_pass_points AS (
                SELECT 
                    fa.profile_id::text AS profile_id,
                    to_char(fa.attempt_created_at, 'YYYY-MM-DD') AS date,
                    CASE 
                        WHEN fa.grade_percent >= (fa.rubric_pass_points * 100.0 / NULLIF(fa.rubric_points, 0)) THEN 100
                        ELSE 0
                    END::int AS value,
                    fa.attempt_id::text AS attempt_id,
                    fa.simulation_id::text AS simulation_id,
                    NULL::text AS scenario_id
                FROM first_attempts fa
                ORDER BY fa.profile_id, fa.attempt_created_at
            ),
            
            -- Highest Score Data Points
            header_highest_points AS (
                SELECT 
                    f.profile_id::text AS profile_id,
                    to_char(f.attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(f.grade_percent)::int AS value,
                    f.attempt_id::text AS attempt_id,
                    f.simulation_id::text AS simulation_id,
                    f.scenario_id::text AS scenario_id
                FROM filt f
                WHERE f.grade_percent IS NOT NULL
                ORDER BY f.profile_id, f.attempt_created_at
            ),
            
            -- Messages Per Session Data Points
            header_messages_points AS (
                SELECT 
                    f.profile_id::text AS profile_id,
                    to_char(f.attempt_created_at, 'YYYY-MM-DD') AS date,
                    f.num_messages_total::int AS value,
                    f.attempt_id::text AS attempt_id,
                    f.simulation_id::text AS simulation_id,
                    f.scenario_id::text AS scenario_id
                FROM filt f
                WHERE f.num_messages_total IS NOT NULL
                ORDER BY f.profile_id, f.attempt_created_at
            ),
            
            -- Persona Response Times Data Points
            header_persona_times_points AS (
                SELECT 
                    f.profile_id::text AS profile_id,
                    to_char(f.attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(pt.delta_sec)::int AS value,
                    f.attempt_id::text AS attempt_id,
                    f.simulation_id::text AS simulation_id,
                    f.scenario_id::text AS scenario_id
                FROM filt f
                CROSS JOIN LATERAL UNNEST(f.message_time_taken_seconds) AS pt(delta_sec)
                WHERE cardinality(f.message_time_taken_seconds) > 0
                ORDER BY f.profile_id, f.attempt_created_at
            ),
            
            -- Session Efficiency Data Points
            header_efficiency_points AS (
                SELECT 
                    f.profile_id::text AS profile_id,
                    to_char(f.attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(GREATEST(0, LEAST(100, 
                        f.grade_percent * (1.0 - LEAST(1.0, (f.time_taken_seconds / 60.0) / 120.0))
                    )))::int AS value,
                    f.attempt_id::text AS attempt_id,
                    f.simulation_id::text AS simulation_id,
                    f.scenario_id::text AS scenario_id
                FROM filt f
                WHERE f.grade_percent IS NOT NULL AND f.time_taken_seconds IS NOT NULL
                ORDER BY f.profile_id, f.attempt_created_at
            ),
            
            -- Stagnation Rate Data Points
            header_stagnation_points AS (
                SELECT 
                    ''::text AS profile_id,
                    to_char(gs.created_at, 'YYYY-MM-DD') AS date,
                    (sf.stagnated * 100)::int AS value,
                    ''::text AS attempt_id,
                    ''::text AS simulation_id,
                    ''::text AS scenario_id
                FROM stagnation_flags sf
                JOIN grade_stream gs ON gs.id = sf.id
                ORDER BY gs.created_at
            ),
            
            -- Time Spent Data Points
            header_time_points AS (
                SELECT 
                    f.profile_id::text AS profile_id,
                    to_char(f.attempt_created_at, 'YYYY-MM-DD') AS date,
                    ROUND(LEAST(30.0, f.time_taken_seconds / 60.0))::int AS value,
                    f.attempt_id::text AS attempt_id,
                    f.simulation_id::text AS simulation_id,
                    f.scenario_id::text AS scenario_id
                FROM filt f
                WHERE f.time_taken_seconds IS NOT NULL
                ORDER BY f.profile_id, f.attempt_created_at
            ),
            
            -- Total Attempts Data Points
            header_attempts_points AS (
                SELECT 
                    f.profile_id::text AS profile_id,
                    to_char(f.attempt_created_at, 'YYYY-MM-DD') AS date,
                    1::int AS value,
                    f.attempt_id::text AS attempt_id,
                    f.simulation_id::text AS simulation_id,
                    f.scenario_id::text AS scenario_id
                FROM filt f
                WHERE f.attempt_id IS NOT NULL
                ORDER BY f.profile_id, f.attempt_created_at
            ),
            
            -- =====================================================
            -- PRIMARY METRICS
            -- =====================================================
            
            -- Growth Data
            spine AS (
                SELECT generate_series(
                    date_trunc('day', (SELECT start_date FROM params)::timestamptz)::date,
                    (date_trunc('day', (SELECT end_date FROM params)::timestamptz) - interval '1 second')::date,
                    interval '1 day'
                )::date AS d
            ),
            growth_avg_score AS (
                SELECT to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                       AVG(grade_percent)::float AS value
                FROM filt WHERE grade_percent IS NOT NULL
                GROUP BY date
            ),
            growth_pass_rate AS (
                SELECT to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                       (100.0 * COUNT(*) FILTER (WHERE grade_percent >= (rubric_pass_points * 100.0 / NULLIF(rubric_points, 0))) 
                        / NULLIF(COUNT(*), 0))::float AS value
                FROM first_attempts
                GROUP BY date
            ),
            growth_completion_rate AS (
                SELECT to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                       AVG(CASE WHEN expected > 0 THEN (100.0 * completed_chats / expected) ELSE 0 END)::float AS value
                FROM attempt_norm
                GROUP BY date
            ),
            growth_first_attempt_pass_rate AS (
                SELECT to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                       (100.0 * COUNT(*) FILTER (WHERE grade_percent >= (rubric_pass_points * 100.0 / NULLIF(rubric_points, 0))) 
                        / NULLIF(COUNT(*), 0))::float AS value
                FROM first_attempts
                GROUP BY date
            ),
            growth_messages AS (
                SELECT to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                       AVG(num_messages_total)::float AS value
                FROM filt WHERE num_messages_total IS NOT NULL
                GROUP BY date
            ),
            growth_persona_times_daily AS (
                SELECT to_char(pt.attempt_created_at, 'YYYY-MM-DD') AS date,
                       AVG(pt.delta_sec)::float AS value
                FROM (
                    SELECT attempt_created_at, UNNEST(message_time_taken_seconds) AS delta_sec
                    FROM filt WHERE cardinality(message_time_taken_seconds) > 0
                ) pt
                GROUP BY date
            ),
            growth_efficiency AS (
                SELECT 
                    to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                    GREATEST(0, LEAST(100, ROUND(
                        AVG(grade_percent) FILTER (WHERE grade_percent IS NOT NULL) * 
                        (1.0 - LEAST(1.0, (SUM(time_taken_seconds / 60.0) FILTER (WHERE time_taken_seconds IS NOT NULL) / 
                         NULLIF(COUNT(DISTINCT chat_id), 0)) / 120.0))
                    )))::float AS value
                FROM filt 
                WHERE time_taken_seconds > 0 AND grade_percent IS NOT NULL
                GROUP BY date
            ),
            growth_stagnation AS (
                SELECT to_char(created_at, 'YYYY-MM-DD') AS date,
                       (100.0 * AVG(stagnated))::float AS value
                FROM stagnation_flags
                GROUP BY date
            ),
            growth_time_spent AS (
                SELECT to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                       AVG(time_taken_seconds)::float AS value
                FROM filt WHERE time_taken_seconds IS NOT NULL
                GROUP BY date
            ),
            growth_total_attempts AS (
                SELECT to_char(attempt_created_at, 'YYYY-MM-DD') AS date,
                       COUNT(DISTINCT attempt_id)::float AS value
                FROM filt
                GROUP BY date
            ),
            growth_chart_dates AS (
                SELECT s.d AS date_val,
                       to_char(s.d, 'YYYY-MM-DD') AS date,
                       ROUND(COALESCE(gas.value, 0))::int AS average_score,
                       ROUND(COALESCE(gcr.value, 0))::int AS completion_rate,
                       ROUND(COALESCE(gfapr.value, 0))::int AS first_attempt_pass_rate,
                       ROUND(COALESCE(ge.value, 0))::int AS session_efficiency,
                       ROUND(COALESCE(gst.value, 0))::int AS stagnation_rate
                FROM spine s
                LEFT JOIN growth_avg_score gas ON gas.date = to_char(s.d, 'YYYY-MM-DD')
                LEFT JOIN growth_completion_rate gcr ON gcr.date = to_char(s.d, 'YYYY-MM-DD')
                LEFT JOIN growth_first_attempt_pass_rate gfapr ON gfapr.date = to_char(s.d, 'YYYY-MM-DD')
                LEFT JOIN growth_efficiency ge ON ge.date = to_char(s.d, 'YYYY-MM-DD')
                LEFT JOIN growth_stagnation gst ON gst.date = to_char(s.d, 'YYYY-MM-DD')
                WHERE gas.value IS NOT NULL 
                   OR gcr.value IS NOT NULL 
                   OR gfapr.value IS NOT NULL 
                   OR ge.value IS NOT NULL 
                   OR gst.value IS NOT NULL
            ),
            growth_window AS (
                SELECT AVG(average_score) FILTER (WHERE date_val >= (SELECT MAX(date_val) FROM growth_chart_dates) - interval '7 days') AS last_avg,
                       AVG(average_score) FILTER (WHERE date_val >= (SELECT MAX(date_val) FROM growth_chart_dates) - interval '14 days' 
                                                        AND date_val < (SELECT MAX(date_val) FROM growth_chart_dates) - interval '7 days') AS prev_avg
                FROM growth_chart_dates
            ),
            
            -- Persona Performance
            persona_agg AS (
                SELECT f.persona_id,
                       p.name,
                       COALESCE(p.color, '#3b82f6') AS color,
                       AVG(f.grade_percent)::float AS avg_score,
                       COUNT(DISTINCT f.chat_id)::int AS sessions,
                       ARRAY_AGG(DISTINCT f.simulation_id::text) AS simulation_ids,
                       CASE
                           WHEN AVG(f.grade_percent)::float >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'
                           WHEN AVG(f.grade_percent)::float >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'
                           ELSE 'danger'
                       END AS status
                FROM filt f
                JOIN personas p ON p.id = f.persona_id
                WHERE f.grade_percent IS NOT NULL AND f.persona_id IS NOT NULL
                GROUP BY f.persona_id, p.name, p.color
            ),
            trend_data_raw AS (
                SELECT
                    f.persona_id,
                    date_trunc('day', f.chat_created_at) AS day,
                    to_char(date_trunc('day', f.chat_created_at), 'YYYY-MM-DD') AS date,
                    EXTRACT(epoch FROM date_trunc('day', f.chat_created_at))::bigint AS timestamp,
                    f.simulation_id,
                    AVG(f.grade_percent)::float AS avg_score
                FROM filt f
                WHERE f.persona_id IS NOT NULL AND f.grade_percent IS NOT NULL
                GROUP BY f.persona_id, date_trunc('day', f.chat_created_at), f.simulation_id
            ),
            persona_trends_agg_converted AS (
                SELECT 
                    persona_id,
                    COALESCE(
                        ARRAY_AGG(
                            (date, COALESCE(avg_score, 0)::float, timestamp, simulation_id::text)::types.q_reports_overview_v4_persona_trend_data
                            ORDER BY day
                        ),
                        '{}'::types.q_reports_overview_v4_persona_trend_data[]
                    ) AS trends
                FROM trend_data_raw
                GROUP BY persona_id
            ),
            persona_colors_agg_converted AS (
                SELECT ARRAY_AGG(
                    (p.name, COALESCE(p.color, '#3b82f6'))::types.q_reports_overview_v4_persona_color
                    ORDER BY p.name
                ) AS colors
                FROM (SELECT DISTINCT persona_id FROM persona_agg) pa
                JOIN personas p ON p.id = pa.persona_id
            ),
            
            -- Rubric Heatmap (FULL IMPLEMENTATION with correlation matrices)
            filtered_chats AS (
                SELECT DISTINCT chat_id
                FROM filt
                WHERE chat_id IS NOT NULL
            ),
            -- Get chat scenario and simulation info for fallback
            chat_scenario_info_overview AS (
                SELECT DISTINCT
                    c.id AS chat_id,
                    c.scenario_id,
                    sa.simulation_id
                FROM chats c
                JOIN attempt_chats ac ON ac.chat_id = c.id
                JOIN simulation_attempts sa ON sa.id = ac.attempt_id
                WHERE c.id IN (SELECT chat_id FROM filtered_chats)
            ),
            -- Get first scenario's rubric per simulation (fallback)
            sim_first_scenario_rubric_overview AS (
                SELECT DISTINCT ON (ss.simulation_id)
                    ss.simulation_id,
                    rga.rubric_id
                FROM simulation_scenarios ss
                LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
                LEFT JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
                WHERE ss.active = true
                  AND ss.simulation_id IN (SELECT DISTINCT simulation_id FROM chat_scenario_info_overview)
                ORDER BY ss.simulation_id, ss.position
            ),
            latest_grade_per_chat AS (
                SELECT DISTINCT ON (c.id)
                    scg.id,
                    c.id AS chat_id,
                    COALESCE(
                        rga.rubric_id,
                        rga_fallback_scenario.rubric_id,
                        sfsr.rubric_id
                    ) AS rubric_id
                FROM grades scg
                LEFT JOIN rubric_grade_agents rga ON rga.id = scg.rubric_grade_agent_id
                JOIN runs r ON r.id = scg.run_id
                JOIN group_runs gr ON gr.run_id = r.id
                JOIN grade_groups gg ON gg.group_id = gr.group_id
                JOIN chats c ON c.id = gg.chat_id
                JOIN filtered_chats fc ON fc.chat_id = c.id
                LEFT JOIN chat_scenario_info_overview csi ON csi.chat_id = c.id
                LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga_fallback ON ssrga_fallback.simulation_id = csi.simulation_id
                  AND ssrga_fallback.scenario_id = csi.scenario_id
                  AND rga.rubric_id IS NULL
                LEFT JOIN rubric_grade_agents rga_fallback_scenario ON rga_fallback_scenario.id = ssrga_fallback.rubric_grade_agent_id
                LEFT JOIN sim_first_scenario_rubric_overview sfsr ON sfsr.simulation_id = csi.simulation_id
                  AND rga.rubric_id IS NULL
                  AND rga_fallback_scenario.rubric_id IS NULL
                WHERE EXISTS (
                    SELECT 1 FROM runs r_check
                    JOIN group_runs gr_check ON gr_check.run_id = r_check.id
                    JOIN grade_groups gg_check ON gg_check.group_id = gr_check.group_id
                    JOIN chats c_check ON c_check.id = gg_check.chat_id
                    WHERE r_check.id = scg.run_id
                )
                  AND COALESCE(
                      rga.rubric_id,
                      rga_fallback_scenario.rubric_id,
                      sfsr.rubric_id
                  ) IS NOT NULL
                ORDER BY c.id, scg.created_at DESC
            ),
            per_grade_group AS (
                SELECT
                    lg.chat_id,
                    rsg.rubric_id,
                    sg.id AS group_id,
                    sg.name AS group_name,
                    (100.0 * SUM(scf.total)::float8 / NULLIF(sg.points::float8, 0))::float8 AS pct
                FROM latest_grade_per_chat lg
                JOIN feedbacks scf ON scf.grade_id = lg.id
                JOIN standards s ON s.id = scf.standard_id
                JOIN rubric_standard_groups rsg ON rsg.rubric_id = lg.rubric_id AND rsg.active = true
                JOIN standard_groups sg ON sg.id = rsg.standard_group_id AND sg.id = s.standard_group_id
                GROUP BY lg.chat_id, rsg.rubric_id, sg.id, sg.name, sg.points
            ),
            corrs_upper AS (
                SELECT
                    a.rubric_id,
                    a.group_id AS g1,
                    b.group_id AS g2,
                    COUNT(*) FILTER (WHERE a.pct IS NOT NULL AND b.pct IS NOT NULL) AS n,
                    corr(a.pct, b.pct) AS r
                FROM per_grade_group a
                JOIN per_grade_group b
                    ON b.rubric_id = a.rubric_id
                    AND b.chat_id = a.chat_id
                    AND b.group_id >= a.group_id
                GROUP BY a.rubric_id, a.group_id, b.group_id
            ),
            corrs_full AS (
                SELECT rubric_id, g1, g2, n, r FROM corrs_upper
                UNION ALL
                SELECT rubric_id, g2 AS g1, g1 AS g2, n, r
                FROM corrs_upper
                WHERE g1 != g2
            ),
            rubric_groups AS (
                SELECT DISTINCT pgg.rubric_id, sg.id, sg.name, sg.short_name
                FROM per_grade_group pgg
                JOIN rubric_standard_groups rsg ON rsg.rubric_id = pgg.rubric_id AND rsg.standard_group_id = pgg.group_id AND rsg.active = true
                JOIN standard_groups sg ON sg.id = rsg.standard_group_id
            ),
            valid_rubric_ids_list AS (
                SELECT DISTINCT rubric_id FROM rubric_groups
            ),
            enriched_corrs AS (
                SELECT
                    c.rubric_id, c.g1, c.g2, c.n,
                    CASE WHEN c.r = c.r THEN c.r ELSE 0.0 END AS r,
                    NULL AS p_value,
                    CASE
                        WHEN c.n IS NULL OR c.n < 3 THEN 'No Data'
                        WHEN ABS(CASE WHEN c.r = c.r THEN c.r ELSE 0.0 END) >= 0.7 THEN 'Strong'
                        WHEN ABS(CASE WHEN c.r = c.r THEN c.r ELSE 0.0 END) >= 0.4 THEN 'Moderate'
                        WHEN ABS(CASE WHEN c.r = c.r THEN c.r ELSE 0.0 END) > 0.0 THEN 'Weak'
                        ELSE 'No Data'
                    END AS strength,
                    CASE
                        WHEN c.n IS NULL OR c.n < 3 THEN '#e5e7eb'
                        WHEN (CASE WHEN c.r = c.r THEN c.r ELSE 0.0 END) >= 0.0 THEN
                            CASE
                                WHEN ABS(CASE WHEN c.r = c.r THEN c.r ELSE 0.0 END) >= 0.7 THEN '#10b981'
                                WHEN ABS(CASE WHEN c.r = c.r THEN c.r ELSE 0.0 END) >= 0.4 THEN '#34d399'
                                ELSE '#a7f3d0'
                            END
                        ELSE
                            CASE
                                WHEN ABS(CASE WHEN c.r = c.r THEN c.r ELSE 0.0 END) >= 0.7 THEN '#ef4444'
                                WHEN ABS(CASE WHEN c.r = c.r THEN c.r ELSE 0.0 END) >= 0.4 THEN '#f87171'
                                ELSE '#fecaca'
                            END
                    END AS color
                FROM corrs_full c
            ),
            rubric_insights AS (
                SELECT
                    e.rubric_id,
                    CASE
                        WHEN COALESCE(SUM(CASE WHEN e.n >= 3 THEN 1 ELSE 0 END), 0) = 0 THEN NULL
                        ELSE (
                            SELECT 'Top pair: "' || g1.name || '" vs "' || g2.name ||
                                   '" r=' || TO_CHAR(e2.r, 'FM0.00') ||
                                   ' (n=' || e2.n || ')'
                            FROM enriched_corrs e2
                            JOIN rubric_groups g1 ON g1.id = e2.g1 AND g1.rubric_id = e2.rubric_id
                            JOIN rubric_groups g2 ON g2.id = e2.g2 AND g2.rubric_id = e2.rubric_id
                            WHERE e2.rubric_id = e.rubric_id AND e2.n >= 3
                            ORDER BY ABS(e2.r) DESC, e2.n DESC
                            LIMIT 1
                        )
                    END AS txt
                FROM enriched_corrs e
                GROUP BY e.rubric_id
            ),
            rubric_has_data AS (
                SELECT rubric_id,
                    (SUM(CASE WHEN n >= 3 THEN 1 ELSE 0 END) > 0) AS has_data
                FROM enriched_corrs
                GROUP BY rubric_id
            ),
            rubric_avg_correlation AS (
                SELECT 
                    rubric_id,
                    AVG(ABS(r)) AS avg_correlation_strength
                FROM enriched_corrs
                WHERE g1 != g2 AND n >= 3
                GROUP BY rubric_id
            ),
            -- Convert rubric_correlations: convert matrix and standard_groups to composite types
            per_rubric_matrix_converted AS (
                SELECT
                    g1.rubric_id,
                    ROW_NUMBER() OVER (PARTITION BY g1.rubric_id ORDER BY g1.name) - 1 AS row_idx,
                    ARRAY_AGG(
                        (g1.rubric_id::text, COALESCE(e.r, 0.0), e.p_value, COALESCE(e.color, '#e5e7eb'), COALESCE(e.strength, 'No Data'), COALESCE(e.n, 0))::types.q_reports_overview_v4_rubric_heatmap_cell
                        ORDER BY g2.name
                    ) AS row_array
                FROM rubric_groups g1
                JOIN rubric_groups g2 ON g2.rubric_id = g1.rubric_id
                LEFT JOIN enriched_corrs e
                    ON e.rubric_id = g1.rubric_id AND e.g1 = g1.id AND e.g2 = g2.id
                GROUP BY g1.rubric_id, g1.id, g1.name
            ),
            matrix_converted AS (
                SELECT rubric_id, ARRAY_AGG(row_array ORDER BY row_idx) AS matrix
                FROM per_rubric_matrix_converted
                GROUP BY rubric_id
            ),
            sg_converted AS (
                SELECT rubric_id,
                    ARRAY_AGG((id::text, name, short_name, rubric_id::text)::types.q_reports_overview_v4_standard_group ORDER BY name) AS standard_groups
                FROM rubric_groups
                GROUP BY rubric_id
            ),
            per_rubric_heatmap_converted AS (
                SELECT
                    r.rubric_id,
                    COALESCE(m.matrix, ARRAY[]::types.q_reports_overview_v4_rubric_heatmap_cell[][]) AS matrix,
                    COALESCE(sg.standard_groups, ARRAY[]::types.q_reports_overview_v4_standard_group[]) AS standard_groups,
                    (SELECT txt FROM rubric_insights i WHERE i.rubric_id = r.rubric_id LIMIT 1) AS insights,
                    COALESCE((SELECT h.has_data FROM rubric_has_data h WHERE h.rubric_id = r.rubric_id LIMIT 1), FALSE) AS has_data
                FROM valid_rubric_ids_list r
                LEFT JOIN matrix_converted m ON m.rubric_id = r.rubric_id
                LEFT JOIN sg_converted sg ON sg.rubric_id = r.rubric_id
            ),
            rubric_correlations_converted AS (
                SELECT
                    COALESCE(
                        ARRAY_AGG(
                            (pr.rubric_id::text, pr.standard_groups, pr.matrix, pr.insights, pr.has_data)::types.q_reports_overview_v4_rubric_matrix_package
                            ORDER BY pr.rubric_id::text
                        ),
                        '{}'::types.q_reports_overview_v4_rubric_matrix_package[]
                    ) AS matrices,
                    COALESCE(
                        ARRAY_AGG(rubric_id::text ORDER BY rubric_id::text),
                        ARRAY[]::text[]
                    ) AS valid_rubric_ids,
                    CASE
                        WHEN (SELECT COUNT(*) FROM rubric_avg_correlation) = 0 THEN 'neutral'::text
                        WHEN (SELECT AVG(avg_correlation_strength * 100) FROM rubric_avg_correlation) >= 
                             (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                        WHEN (SELECT AVG(avg_correlation_strength * 100) FROM rubric_avg_correlation) >= 
                             (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'danger'::text
                    END AS status
                FROM per_rubric_heatmap_converted pr
            ),
            -- Entity Mappings - converted to arrays of composite types
            simulation_ids AS (
                SELECT DISTINCT simulation_id FROM filt WHERE simulation_id IS NOT NULL
            ),
            simulation_with_depts AS (
                SELECT 
                    s.id,
                    s.title,
                    s.description,
                    COALESCE(
                        (SELECT SUM(stl.time_limit_seconds)
                         FROM scenario_time_limits stl
                         JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
                         WHERE stl.simulation_id = s.id AND stl.active = true AND ss.active = true),
                        0
                    ) AS time_limit,
                    COALESCE(
                        ARRAY_AGG(sd.department_id::text ORDER BY sd.created_at) FILTER (WHERE sd.department_id IS NOT NULL),
                        ARRAY[]::text[]
                    ) AS dept_ids
                FROM simulations s
                LEFT JOIN simulation_departments sd ON sd.simulation_id = s.id AND sd.active = true
                WHERE s.id IN (SELECT simulation_id FROM simulation_ids)
                  AND s.active = true
                  AND (
                      cardinality((SELECT department_ids FROM params)::uuid[]) = 0 
                      OR sd.department_id = ANY((SELECT department_ids FROM params)::uuid[])
                      OR NOT EXISTS (SELECT 1 FROM simulation_departments sd2 WHERE sd2.simulation_id = s.id AND sd2.active = true)
                  )
                GROUP BY s.id, s.title, s.description
            ),
            simulations_converted AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (id::text, title, COALESCE(description, ''), time_limit, dept_ids)::types.q_reports_overview_v4_simulation
                        ORDER BY title
                    ),
                    '{}'::types.q_reports_overview_v4_simulation[]
                ) AS simulations_array
                FROM simulation_with_depts
            ),
            rubric_ids AS (
                SELECT DISTINCT rubric_id FROM filt WHERE rubric_id IS NOT NULL
            ),
            rubrics_converted AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (r.id::text, r.name, COALESCE(r.description, ''))::types.q_reports_overview_v4_rubric
                        ORDER BY r.name
                    ),
                    '{}'::types.q_reports_overview_v4_rubric[]
                ) AS rubrics_array
                FROM rubrics r
                WHERE r.id IN (SELECT rubric_id FROM rubric_ids)
                  AND r.active = true
            ),
            parameters_converted AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (p.id::text, p.name, COALESCE(p.description, ''), 
                         false, 
                         COALESCE(p.document_parameter, false),
                         COALESCE(p.persona_parameter, false)
                        )::types.q_reports_overview_v4_parameter
                        ORDER BY p.name
                    ),
                    '{}'::types.q_reports_overview_v4_parameter[]
                ) AS parameters_array
                FROM parameters p
                WHERE p.active = true
                  AND (
                      cardinality((SELECT department_ids FROM params)) = 0 
                      OR EXISTS (
                          SELECT 1 
                          FROM fields f
                          JOIN parameter_fields pf ON pf.field_id = f.id AND pf.active = true
                          JOIN field_departments fd ON fd.field_id = f.id AND fd.active = true
                          WHERE pf.parameter_id = p.id AND fd.department_id = ANY((SELECT department_ids FROM params)::uuid[])
                      )
                      OR NOT EXISTS (
                          SELECT 1 
                          FROM fields f
                          JOIN parameter_fields pf ON pf.field_id = f.id AND pf.active = true
                          JOIN field_departments fd2 ON fd2.field_id = f.id AND fd2.active = true
                          WHERE pf.parameter_id = p.id
                      )
                  )
            ),
            fields_converted AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (f.id::text, f.name, COALESCE(f.description, ''), 
                         pf.parameter_id::text, p.name
                        )::types.q_reports_overview_v4_field
                        ORDER BY f.name
                    ),
                    '{}'::types.q_reports_overview_v4_field[]
                ) AS fields_array
                FROM fields f
                JOIN parameter_fields pf ON pf.field_id = f.id AND pf.active = true
                JOIN parameters p ON pf.parameter_id = p.id
                LEFT JOIN field_departments fd ON fd.field_id = f.id AND fd.active = true
                WHERE p.active = true
                  AND (
                      cardinality((SELECT department_ids FROM params)::uuid[]) = 0 
                      OR fd.department_id = ANY((SELECT department_ids FROM params)::uuid[])
                      OR NOT EXISTS (SELECT 1 FROM field_departments fd2 WHERE fd2.field_id = f.id AND fd2.active = true)
                  )
            ),
            -- Helper CTEs for header metrics - convert to composite types
            header_avg_score_trend_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((date, value, count)::types.q_reports_overview_v4_trend_data ORDER BY date),
                    '{}'::types.q_reports_overview_v4_trend_data[]
                ) as trend_data
                FROM header_avg_score_trend
            ),
            header_avg_score_points_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((COALESCE(profile_id, ''), date, value::float, attempt_id, simulation_id, scenario_id, 0)::types.q_reports_overview_v4_data_point),
                    '{}'::types.q_reports_overview_v4_data_point[]
                ) as data_points
                FROM header_avg_score_points
            ),
            header_avg_score_metric AS (
                SELECT 
                    COALESCE((SELECT has_data FROM header_avg_score), false)::boolean as has_data,
                    'avg'::text as method,
                    COALESCE((SELECT current_value FROM header_avg_score), 0)::int as current_value,
                    CASE
                        WHEN NOT COALESCE((SELECT has_data FROM header_avg_score), false) THEN 'neutral'::text
                        WHEN COALESCE((SELECT current_value FROM header_avg_score), 0) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                        WHEN COALESCE((SELECT current_value FROM header_avg_score), 0) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'danger'::text
                    END as status,
                    NULL::text as trend_analysis,
                    NULL::text as value_field,
                    NULL::text as key_field,
                    (SELECT trend_data FROM header_avg_score_trend_agg LIMIT 1) as trend_data,
                    (SELECT data_points FROM header_avg_score_points_agg LIMIT 1) as data_points
            ),
            header_completion_trend_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((date, value, count)::types.q_reports_overview_v4_trend_data ORDER BY date),
                    '{}'::types.q_reports_overview_v4_trend_data[]
                ) as trend_data
                FROM header_completion_trend
            ),
            header_completion_points_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((profile_id, date, value::float, attempt_id, simulation_id, scenario_id, 0)::types.q_reports_overview_v4_data_point),
                    '{}'::types.q_reports_overview_v4_data_point[]
                ) as data_points
                FROM header_completion_points
            ),
            header_completion_metric AS (
                SELECT 
                    COALESCE((SELECT has_data FROM header_completion), false)::boolean as has_data,
                    'avg'::text as method,
                    COALESCE((SELECT current_value FROM header_completion), 0)::int as current_value,
                    CASE
                        WHEN NOT COALESCE((SELECT has_data FROM header_completion), false) THEN 'neutral'::text
                        WHEN COALESCE((SELECT current_value FROM header_completion), 0) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                        WHEN COALESCE((SELECT current_value FROM header_completion), 0) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'danger'::text
                    END as status,
                    NULL::text as trend_analysis,
                    NULL::text as value_field,
                    NULL::text as key_field,
                    (SELECT trend_data FROM header_completion_trend_agg LIMIT 1) as trend_data,
                    (SELECT data_points FROM header_completion_points_agg LIMIT 1) as data_points
            ),
            header_first_pass_trend_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((date, value, count)::types.q_reports_overview_v4_trend_data ORDER BY date),
                    '{}'::types.q_reports_overview_v4_trend_data[]
                ) as trend_data
                FROM header_first_pass_trend
            ),
            header_first_pass_points_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((profile_id, date, value::float, attempt_id, simulation_id, COALESCE(scenario_id, ''), 0)::types.q_reports_overview_v4_data_point),
                    '{}'::types.q_reports_overview_v4_data_point[]
                ) as data_points
                FROM header_first_pass_points
            ),
            header_first_pass_metric AS (
                SELECT 
                    COALESCE((SELECT has_data FROM header_first_pass), false)::boolean as has_data,
                    'rate'::text as method,
                    COALESCE((SELECT current_value FROM header_first_pass), 0)::int as current_value,
                    CASE
                        WHEN NOT COALESCE((SELECT has_data FROM header_first_pass), false) THEN 'neutral'::text
                        WHEN COALESCE((SELECT current_value FROM header_first_pass), 0) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                        WHEN COALESCE((SELECT current_value FROM header_first_pass), 0) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'danger'::text
                    END as status,
                    NULL::text as trend_analysis,
                    NULL::text as value_field,
                    NULL::text as key_field,
                    (SELECT trend_data FROM header_first_pass_trend_agg LIMIT 1) as trend_data,
                    (SELECT data_points FROM header_first_pass_points_agg LIMIT 1) as data_points
            ),
            header_highest_trend_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((date, value, count)::types.q_reports_overview_v4_trend_data ORDER BY date),
                    '{}'::types.q_reports_overview_v4_trend_data[]
                ) as trend_data
                FROM header_highest_trend
            ),
            header_highest_points_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((profile_id, date, value::float, attempt_id, simulation_id, scenario_id, 0)::types.q_reports_overview_v4_data_point),
                    '{}'::types.q_reports_overview_v4_data_point[]
                ) as data_points
                FROM header_highest_points
            ),
            header_highest_metric AS (
                SELECT 
                    COALESCE((SELECT has_data FROM header_highest), false)::boolean as has_data,
                    'max'::text as method,
                    COALESCE((SELECT current_value FROM header_highest), 0)::int as current_value,
                    CASE
                        WHEN NOT COALESCE((SELECT has_data FROM header_highest), false) THEN 'neutral'::text
                        WHEN COALESCE((SELECT current_value FROM header_highest), 0) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                        WHEN COALESCE((SELECT current_value FROM header_highest), 0) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'danger'::text
                    END as status,
                    NULL::text as trend_analysis,
                    NULL::text as value_field,
                    NULL::text as key_field,
                    (SELECT trend_data FROM header_highest_trend_agg LIMIT 1) as trend_data,
                    (SELECT data_points FROM header_highest_points_agg LIMIT 1) as data_points
            ),
            header_messages_trend_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((date, value, count)::types.q_reports_overview_v4_trend_data ORDER BY date),
                    '{}'::types.q_reports_overview_v4_trend_data[]
                ) as trend_data
                FROM header_messages_trend
            ),
            header_messages_points_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((profile_id, date, value::float, attempt_id, simulation_id, scenario_id, 0)::types.q_reports_overview_v4_data_point),
                    '{}'::types.q_reports_overview_v4_data_point[]
                ) as data_points
                FROM header_messages_points
            ),
            header_messages_metric AS (
                SELECT 
                    COALESCE((SELECT has_data FROM header_messages), false)::boolean as has_data,
                    'avg'::text as method,
                    COALESCE((SELECT current_value FROM header_messages), 0)::int as current_value,
                    CASE
                        WHEN NOT COALESCE((SELECT has_data FROM header_messages), false) THEN 'neutral'::text
                        WHEN COALESCE((SELECT current_value FROM header_messages), 0) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                        WHEN COALESCE((SELECT current_value FROM header_messages), 0) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'danger'::text
                    END as status,
                    NULL::text as trend_analysis,
                    NULL::text as value_field,
                    NULL::text as key_field,
                    (SELECT trend_data FROM header_messages_trend_agg LIMIT 1) as trend_data,
                    (SELECT data_points FROM header_messages_points_agg LIMIT 1) as data_points
            ),
            header_persona_times_trend_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((date, value, count)::types.q_reports_overview_v4_trend_data ORDER BY date),
                    '{}'::types.q_reports_overview_v4_trend_data[]
                ) as trend_data
                FROM header_persona_times_trend
            ),
            header_persona_times_points_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((profile_id, date, value::float, attempt_id, simulation_id, scenario_id, 0)::types.q_reports_overview_v4_data_point),
                    '{}'::types.q_reports_overview_v4_data_point[]
                ) as data_points
                FROM header_persona_times_points
            ),
            header_persona_times_metric AS (
                SELECT 
                    COALESCE((SELECT has_data FROM header_persona_times), false)::boolean as has_data,
                    'avg'::text as method,
                    COALESCE((SELECT current_value FROM header_persona_times), 0)::int as current_value,
                    CASE
                        WHEN NOT COALESCE((SELECT has_data FROM header_persona_times), false) THEN 'neutral'::text
                        WHEN COALESCE((SELECT current_value FROM header_persona_times), 0) > (SELECT danger_threshold FROM settings_thresholds LIMIT 1) THEN 'danger'::text
                        WHEN COALESCE((SELECT current_value FROM header_persona_times), 0) > (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'success'::text
                    END as status,
                    NULL::text as trend_analysis,
                    NULL::text as value_field,
                    NULL::text as key_field,
                    (SELECT trend_data FROM header_persona_times_trend_agg LIMIT 1) as trend_data,
                    (SELECT data_points FROM header_persona_times_points_agg LIMIT 1) as data_points
            ),
            header_efficiency_trend_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((date, value, count)::types.q_reports_overview_v4_trend_data ORDER BY date),
                    '{}'::types.q_reports_overview_v4_trend_data[]
                ) as trend_data
                FROM header_efficiency_trend
            ),
            header_efficiency_points_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((profile_id, date, value::float, attempt_id, simulation_id, scenario_id, 0)::types.q_reports_overview_v4_data_point),
                    '{}'::types.q_reports_overview_v4_data_point[]
                ) as data_points
                FROM header_efficiency_points
            ),
            header_efficiency_metric AS (
                SELECT 
                    COALESCE((SELECT has_data FROM header_efficiency), false)::boolean as has_data,
                    'avg'::text as method,
                    COALESCE((SELECT current_value FROM header_efficiency), 0)::int as current_value,
                    CASE
                        WHEN NOT COALESCE((SELECT has_data FROM header_efficiency), false) THEN 'neutral'::text
                        WHEN COALESCE((SELECT current_value FROM header_efficiency), 0) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                        WHEN COALESCE((SELECT current_value FROM header_efficiency), 0) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'danger'::text
                    END as status,
                    NULL::text as trend_analysis,
                    NULL::text as value_field,
                    NULL::text as key_field,
                    (SELECT trend_data FROM header_efficiency_trend_agg LIMIT 1) as trend_data,
                    (SELECT data_points FROM header_efficiency_points_agg LIMIT 1) as data_points
            ),
            header_stagnation_trend_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((date, value, count)::types.q_reports_overview_v4_trend_data ORDER BY date),
                    '{}'::types.q_reports_overview_v4_trend_data[]
                ) as trend_data
                FROM header_stagnation_trend
            ),
            header_stagnation_points_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((COALESCE(profile_id, ''), date, value::float, COALESCE(attempt_id, ''), COALESCE(simulation_id, ''), COALESCE(scenario_id, ''), 0)::types.q_reports_overview_v4_data_point),
                    '{}'::types.q_reports_overview_v4_data_point[]
                ) as data_points
                FROM header_stagnation_points
            ),
            header_stagnation_metric AS (
                SELECT 
                    COALESCE((SELECT has_data FROM header_stagnation), false)::boolean as has_data,
                    'rate'::text as method,
                    COALESCE((SELECT current_value FROM header_stagnation), 0)::int as current_value,
                    CASE
                        WHEN NOT COALESCE((SELECT has_data FROM header_stagnation), false) THEN 'neutral'::text
                        WHEN COALESCE((SELECT current_value FROM header_stagnation), 0) > (SELECT danger_threshold FROM settings_thresholds LIMIT 1) THEN 'danger'::text
                        WHEN COALESCE((SELECT current_value FROM header_stagnation), 0) > (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'success'::text
                    END as status,
                    NULL::text as trend_analysis,
                    NULL::text as value_field,
                    NULL::text as key_field,
                    (SELECT trend_data FROM header_stagnation_trend_agg LIMIT 1) as trend_data,
                    (SELECT data_points FROM header_stagnation_points_agg LIMIT 1) as data_points
            ),
            header_time_trend_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((date, value, count)::types.q_reports_overview_v4_trend_data ORDER BY date),
                    '{}'::types.q_reports_overview_v4_trend_data[]
                ) as trend_data
                FROM header_time_trend
            ),
            header_time_points_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((profile_id, date, value::float, attempt_id, simulation_id, scenario_id, 0)::types.q_reports_overview_v4_data_point),
                    '{}'::types.q_reports_overview_v4_data_point[]
                ) as data_points
                FROM header_time_points
            ),
            header_time_metric AS (
                SELECT 
                    COALESCE((SELECT has_data FROM header_time), false)::boolean as has_data,
                    'avg'::text as method,
                    COALESCE((SELECT current_value FROM header_time), 0)::int as current_value,
                    CASE
                        WHEN NOT COALESCE((SELECT has_data FROM header_time), false) THEN 'neutral'::text
                        WHEN COALESCE((SELECT current_value FROM header_time), 0) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                        WHEN COALESCE((SELECT current_value FROM header_time), 0) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'danger'::text
                    END as status,
                    NULL::text as trend_analysis,
                    NULL::text as value_field,
                    NULL::text as key_field,
                    (SELECT trend_data FROM header_time_trend_agg LIMIT 1) as trend_data,
                    (SELECT data_points FROM header_time_points_agg LIMIT 1) as data_points
            ),
            header_attempts_trend_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((date, value, count)::types.q_reports_overview_v4_trend_data ORDER BY date),
                    '{}'::types.q_reports_overview_v4_trend_data[]
                ) as trend_data
                FROM header_attempts_trend
            ),
            header_attempts_points_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG((profile_id, date, value::float, attempt_id, simulation_id, scenario_id, 0)::types.q_reports_overview_v4_data_point),
                    '{}'::types.q_reports_overview_v4_data_point[]
                ) as data_points
                FROM header_attempts_points
            ),
            header_attempts_metric AS (
                SELECT 
                    COALESCE((SELECT has_data FROM header_attempts), false)::boolean as has_data,
                    'countDistinct'::text as method,
                    COALESCE((SELECT current_value FROM header_attempts), 0)::int as current_value,
                    CASE
                        WHEN NOT COALESCE((SELECT has_data FROM header_attempts), false) THEN 'neutral'::text
                        WHEN COALESCE((SELECT current_value FROM header_attempts), 0) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                        WHEN COALESCE((SELECT current_value FROM header_attempts), 0) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'danger'::text
                    END as status,
                    NULL::text as trend_analysis,
                    NULL::text as value_field,
                    NULL::text as key_field,
                    (SELECT trend_data FROM header_attempts_trend_agg LIMIT 1) as trend_data,
                    (SELECT data_points FROM header_attempts_points_agg LIMIT 1) as data_points
            ),
            header_metrics_combined AS (
                SELECT (
                    (SELECT (has_data, method, current_value, status, trend_analysis, value_field, key_field, trend_data, data_points)::types.q_reports_overview_v4_metric_response FROM header_avg_score_metric LIMIT 1),
                    (SELECT (has_data, method, current_value, status, trend_analysis, value_field, key_field, trend_data, data_points)::types.q_reports_overview_v4_metric_response FROM header_completion_metric LIMIT 1),
                    (SELECT (has_data, method, current_value, status, trend_analysis, value_field, key_field, trend_data, data_points)::types.q_reports_overview_v4_metric_response FROM header_first_pass_metric LIMIT 1),
                    (SELECT (has_data, method, current_value, status, trend_analysis, value_field, key_field, trend_data, data_points)::types.q_reports_overview_v4_metric_response FROM header_highest_metric LIMIT 1),
                    (SELECT (has_data, method, current_value, status, trend_analysis, value_field, key_field, trend_data, data_points)::types.q_reports_overview_v4_metric_response FROM header_messages_metric LIMIT 1),
                    (SELECT (has_data, method, current_value, status, trend_analysis, value_field, key_field, trend_data, data_points)::types.q_reports_overview_v4_metric_response FROM header_persona_times_metric LIMIT 1),
                    (SELECT (has_data, method, current_value, status, trend_analysis, value_field, key_field, trend_data, data_points)::types.q_reports_overview_v4_metric_response FROM header_efficiency_metric LIMIT 1),
                    (SELECT (has_data, method, current_value, status, trend_analysis, value_field, key_field, trend_data, data_points)::types.q_reports_overview_v4_metric_response FROM header_stagnation_metric LIMIT 1),
                    (SELECT (has_data, method, current_value, status, trend_analysis, value_field, key_field, trend_data, data_points)::types.q_reports_overview_v4_metric_response FROM header_time_metric LIMIT 1),
                    (SELECT (has_data, method, current_value, status, trend_analysis, value_field, key_field, trend_data, data_points)::types.q_reports_overview_v4_metric_response FROM header_attempts_metric LIMIT 1)
                )::types.q_reports_overview_v4_header_metrics as header_metrics
            ),
            -- Primary metrics helper CTEs
            growth_chart_data_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (date, average_score::float, completion_rate::float, first_attempt_pass_rate::float, session_efficiency::float, stagnation_rate::float)::types.q_reports_overview_v4_growth_data_point
                        ORDER BY date_val
                    ),
                    '{}'::types.q_reports_overview_v4_growth_data_point[]
                ) as chart_data
                FROM growth_chart_dates
            ),
            growth_available_metrics AS (
                SELECT ARRAY[
                    ('averageScore', 'Average Score', '#3b82f6', '%', 'Average score across all attempts', 'percent')::types.q_reports_overview_v4_growth_metric,
                    ('completionRate', 'Completion Rate', '#8b5cf6', '%', 'Percentage of scenarios completed', 'percent')::types.q_reports_overview_v4_growth_metric,
                    ('firstAttemptPassRate', 'First Attempt Pass Rate', '#06b6d4', '%', 'Pass rate on first attempts', 'percent')::types.q_reports_overview_v4_growth_metric,
                    ('sessionEfficiency', 'Session Efficiency', '#84cc16', '%', 'Efficiency index based on score and time (0-100)', 'percent')::types.q_reports_overview_v4_growth_metric,
                    ('stagnationRate', 'Stagnation Rate', '#ec4899', '%', 'Percentage of attempts with no improvement', 'percent')::types.q_reports_overview_v4_growth_metric
                ] as available_metrics
            ),
            growth_window_averages_combined AS (
                SELECT (
                    ROW((7, (SELECT ROUND(last_avg) FROM growth_window), (SELECT ROUND(prev_avg) FROM growth_window))::types.q_reports_overview_v4_growth_window_average)
                )::types.q_reports_overview_v4_growth_window_averages as window_averages
            ),
            growth_data_combined AS (
                SELECT (
                    (SELECT chart_data FROM growth_chart_data_agg LIMIT 1),
                    (SELECT available_metrics FROM growth_available_metrics LIMIT 1),
                    (SELECT window_averages FROM growth_window_averages_combined LIMIT 1),
                    CASE
                        WHEN (SELECT last_avg FROM growth_window) IS NULL OR (SELECT prev_avg FROM growth_window) IS NULL THEN 'neutral'::text
                        WHEN (SELECT ROUND(last_avg - prev_avg) FROM growth_window) >= (SELECT success_threshold FROM settings_thresholds LIMIT 1) THEN 'success'::text
                        WHEN (SELECT ROUND(last_avg - prev_avg) FROM growth_window) >= (SELECT warning_threshold FROM settings_thresholds LIMIT 1) THEN 'warning'::text
                        ELSE 'danger'::text
                    END
                )::types.q_reports_overview_v4_growth_data_response as growth_data
            ),
            persona_performance_top5 AS (
                SELECT pa.name, pa.avg_score, pa.sessions, pa.color, pa.simulation_ids, 
                       COALESCE(ptc.trends, ARRAY[]::types.q_reports_overview_v4_persona_trend_data[]) as trends,
                       pa.status
                FROM persona_agg pa
                LEFT JOIN persona_trends_agg_converted ptc ON ptc.persona_id = pa.persona_id
                ORDER BY pa.avg_score DESC
                LIMIT 5
            ),
            persona_performance_chart_data_agg AS (
                SELECT COALESCE(
                    ARRAY_AGG(
                        (name, COALESCE(avg_score, 0)::float, sessions, color, simulation_ids, trends, status)::types.q_reports_overview_v4_persona_performance_data
                    ),
                    '{}'::types.q_reports_overview_v4_persona_performance_data[]
                ) as chart_data
                FROM persona_performance_top5
            ),
            persona_performance_valid_sims AS (
                SELECT COALESCE(
                    ARRAY_AGG(DISTINCT simulation_id::text ORDER BY simulation_id::text),
                    ARRAY[]::text[]
                ) as valid_simulation_ids
                FROM filt
                WHERE simulation_id IS NOT NULL
            ),
            persona_performance_combined AS (
                SELECT (
                    (SELECT chart_data FROM persona_performance_chart_data_agg LIMIT 1),
                    (SELECT valid_simulation_ids FROM persona_performance_valid_sims LIMIT 1),
                    (SELECT colors FROM persona_colors_agg_converted LIMIT 1)
                )::types.q_reports_overview_v4_persona_performance_response as persona_performance
            ),
            rubric_heatmap_combined AS (
                SELECT (
                    (SELECT matrices FROM rubric_correlations_converted LIMIT 1),
                    (SELECT valid_rubric_ids FROM rubric_correlations_converted LIMIT 1),
                    (SELECT status FROM rubric_correlations_converted LIMIT 1)
                )::types.q_reports_overview_v4_rubric_heatmap_response as rubric_heatmap
            ),
            primary_metrics_combined AS (
                SELECT (
                    (SELECT growth_data FROM growth_data_combined LIMIT 1),
                    (SELECT persona_performance FROM persona_performance_combined LIMIT 1),
                    (SELECT rubric_heatmap FROM rubric_heatmap_combined LIMIT 1)
                )::types.q_reports_overview_v4_primary_metrics as primary_metrics
            ),
            -- Secondary metrics - placeholder for now (needs full conversion)
            secondary_metrics_combined AS (
                SELECT NULL::types.q_reports_overview_v4_secondary_metrics as secondary_metrics
            ),
            -- Footer metrics - placeholder for now (needs full conversion)
            footer_metrics_combined AS (
                SELECT NULL::types.q_reports_overview_v4_footer_metrics as footer_metrics
            ),
            -- History - placeholder for now (needs conversion from attempt history CTEs)
            history_combined AS (
                SELECT ARRAY[]::types.q_reports_overview_v4_attempt_history_row[] as history
            ),
            -- Insights - placeholder for now (needs conversion)
            insights_combined AS (
                SELECT (
                    NULL::text,
                    ARRAY[]::types.q_reports_overview_v4_persona_insight[],
                    NULL::text,
                    NULL::text,
                    ARRAY[]::types.q_reports_overview_v4_cohort_insight[],
                    NULL::text,
                    NULL::text,
                    NULL::text,
                    NULL::text,
                    NULL::text
                )::types.q_reports_overview_v4_insights as insights
            ),
            -- Thresholds
            thresholds_combined AS (
                SELECT COALESCE(
                    (SELECT (success_threshold, warning_threshold, danger_threshold)::types.q_reports_overview_v4_thresholds FROM settings_thresholds LIMIT 1),
                    (85, 80, 70)::types.q_reports_overview_v4_thresholds
                ) as thresholds
            )
SELECT
    (SELECT actor_name FROM user_profile)::text as actor_name,
    (SELECT header_metrics FROM header_metrics_combined LIMIT 1) as header_metrics,
    (SELECT primary_metrics FROM primary_metrics_combined LIMIT 1) as primary_metrics,
    (SELECT secondary_metrics FROM secondary_metrics_combined LIMIT 1) as secondary_metrics,
    (SELECT footer_metrics FROM footer_metrics_combined LIMIT 1) as footer_metrics,
    (SELECT history FROM history_combined LIMIT 1) as history,
    (SELECT insights FROM insights_combined LIMIT 1) as insights,
    (SELECT thresholds FROM thresholds_combined LIMIT 1) as thresholds,
    (SELECT simulations_array FROM simulations_converted LIMIT 1) as simulations,
    (SELECT rubrics_array FROM rubrics_converted LIMIT 1) as rubrics,
    (SELECT parameters_array FROM parameters_converted LIMIT 1) as parameters,
    (SELECT fields_array FROM fields_converted LIMIT 1) as fields
$$;


--
-- Name: api_get_root_scenario_id_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_root_scenario_id_v4(scenario_id uuid) RETURNS TABLE(root_scenario_id uuid)
    LANGUAGE sql STABLE
    AS $$
WITH RECURSIVE scenario_ancestors AS (
    -- Base case: start with the given scenario
    SELECT 
        scenario_id as scenario_id,
        COALESCE(
            (SELECT parent_id 
             FROM scenario_tree 
             WHERE child_id = scenario_id AND parent_id != child_id 
             LIMIT 1),
            scenario_id
        ) as ancestor_id,
        0 as depth
    UNION ALL
    -- Recursive case: traverse up the tree
    SELECT 
        sa.scenario_id,
        COALESCE(
            (SELECT st.parent_id 
             FROM scenario_tree st 
             WHERE st.child_id = sa.ancestor_id 
               AND st.parent_id != st.child_id 
             LIMIT 1),
            sa.ancestor_id
        ) as ancestor_id,
        sa.depth + 1 as depth
    FROM scenario_ancestors sa
    WHERE sa.depth < 100  -- Safety limit
      AND EXISTS (
          SELECT 1 FROM scenario_tree st 
          WHERE st.child_id = sa.ancestor_id 
            AND st.parent_id != st.child_id
      )
)
SELECT ancestor_id as root_scenario_id
FROM scenario_ancestors
WHERE depth = (SELECT MAX(depth) FROM scenario_ancestors)
LIMIT 1
$$;


--
-- Name: api_get_rubric_detail_v4(uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_rubric_detail_v4(rubric_id uuid, profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(rubric_exists boolean, rubric_id uuid, name text, description text, department_ids text[], valid_department_ids text[], points integer, pass_points integer, active boolean, can_edit boolean, rubric_agent_id uuid, valid_agent_ids text[], actor_name text, standard_group_ids uuid[], standard_groups types.q_get_rubric_detail_v4_standard_group[], standards types.q_get_rubric_detail_v4_standard[], departments types.q_get_rubric_detail_v4_department[], agents types.q_get_rubric_detail_v4_agent[], draft_version integer, draft_standard_groups jsonb, draft_standards jsonb, draft_grid_cells jsonb)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT rubric_id AS rubric_id, profile_id AS profile_id, draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'rubrics'::draft_resource_type
    LIMIT 1
),
rubric_exists_check AS (
    SELECT EXISTS(
        SELECT 1 FROM rubrics WHERE id = (SELECT rubric_id FROM params)
    )::boolean as rubric_exists
),
rubric_data AS (
    SELECT 
        r.id as rubric_id,
        r.name,
        r.description,
        r.active,
        r.points,
        r.pass_points,
        r.rubric_agent_id
    FROM rubrics r
    WHERE r.id = (SELECT rubric_id FROM params)
),
rubric_departments_data AS (
    SELECT 
        ARRAY_AGG(rd.department_id::text ORDER BY rd.created_at) as department_ids
    FROM rubric_departments rd
    WHERE rd.rubric_id = (SELECT rubric_id FROM params) AND rd.active = true
),
user_departments AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments ON profile_departments.profile_id = x.profile_id AND profile_departments.active = true
),
valid_depts AS (
    SELECT 
        array_agg(d.id::text ORDER BY d.title) as dept_ids
    FROM departments d
    JOIN params x ON true
    JOIN profile_departments pd ON d.id = pd.department_id
    WHERE pd.profile_id = x.profile_id AND d.active = true
),
user_profile AS (
    SELECT 
        role as user_role,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
profile_data AS (
    SELECT user_role FROM user_profile
),
user_has_rubric_access AS (
    SELECT EXISTS(
        SELECT 1 FROM rubric_departments rd
        JOIN params x ON true
        JOIN profile_departments pd ON pd.department_id = rd.department_id
        WHERE rd.rubric_id = x.rubric_id AND rd.active = true
        AND pd.profile_id = x.profile_id AND pd.active = true
    ) OR EXISTS(
        SELECT 1 FROM params x
        JOIN profiles p ON p.id = x.profile_id
        WHERE p.role = 'superadmin'
    ) OR (
        SELECT COUNT(*) FROM rubric_departments rd
        WHERE rd.rubric_id = (SELECT rubric_id FROM params) AND rd.active = true
    ) = 0 as has_access
),
user_departments_for_agents AS (
    SELECT DISTINCT pd.department_id
    FROM profile_departments pd
    JOIN params x ON pd.profile_id = x.profile_id
    WHERE pd.active = true
),
standard_groups_data AS (
    SELECT 
        sg.id as standard_group_id,
        sg.name,
        sg.description,
        sg.points,
        sg.pass_points,
        rsg.position,
        rsg.active,
        ARRAY_AGG(s.id ORDER BY s.name) as standard_ids
    FROM rubric_standard_groups rsg
    JOIN standard_groups sg ON sg.id = rsg.standard_group_id
    LEFT JOIN standards s ON s.standard_group_id = sg.id
    WHERE rsg.rubric_id = (SELECT rubric_id FROM params) AND rsg.active = true
    GROUP BY sg.id, sg.name, sg.description, sg.points, sg.pass_points, rsg.position, rsg.active
),
standard_groups_aggregated AS (
    SELECT 
        ARRAY_AGG(sg.standard_group_id ORDER BY sg.position, sg.name) as standard_group_ids,
        COALESCE(
            ARRAY_AGG(
                (sg.standard_group_id, sg.name, COALESCE(sg.description, ''), sg.points, sg.pass_points, sg.position, sg.active, COALESCE(sg.standard_ids, ARRAY[]::uuid[]))::types.q_get_rubric_detail_v4_standard_group
                ORDER BY sg.position, sg.name
            ),
            '{}'::types.q_get_rubric_detail_v4_standard_group[]
        ) as standard_groups
    FROM standard_groups_data sg
),
standards_distinct AS (
    SELECT DISTINCT ON (s.id)
        s.id, s.name, COALESCE(s.description, '') as description, s.points
    FROM standards s
    WHERE s.standard_group_id IN (SELECT standard_group_id FROM standard_groups_data)
    ORDER BY s.id, s.name
),
standards_aggregated AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (sd.id, sd.name, sd.description, sd.points)::types.q_get_rubric_detail_v4_standard
                ORDER BY sd.name
            ),
            '{}'::types.q_get_rubric_detail_v4_standard[]
        ) as standards
    FROM standards_distinct sd
),
departments_distinct AS (
    SELECT DISTINCT ON (d.id)
        d.id, d.title, COALESCE(d.description, '') as description
    FROM departments d
    WHERE d.id IN (SELECT department_id FROM user_departments)
    ORDER BY d.id, d.title
),
departments_aggregated AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (dd.id, dd.title, dd.description)::types.q_get_rubric_detail_v4_department
                ORDER BY dd.title
            ),
            '{}'::types.q_get_rubric_detail_v4_department[]
        ) as departments
    FROM departments_distinct dd
),
valid_agents_data AS (
    SELECT 
        a.id as agent_id,
        a.name,
        a.description,
        ARRAY[a.role::text] as roles
    FROM agents a
    LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
    CROSS JOIN rubric_data rd
    WHERE a.active = true 
    AND a.role = 'rubric'
    AND (
        EXISTS (
            SELECT 1 FROM agent_departments ad2 
            WHERE ad2.agent_id = a.id 
            AND ad2.active = true 
            AND ad2.department_id IN (SELECT department_id FROM user_departments_for_agents)
        )
        OR NOT EXISTS (
            SELECT 1 FROM agent_departments ad3 
            WHERE ad3.agent_id = a.id 
            AND ad3.active = true
        )
        OR a.id::text = rd.rubric_agent_id::text
    )
),
agents_aggregated AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(a.agent_id::text ORDER BY a.name),
            ARRAY[]::text[]
        ) as valid_agent_ids,
        COALESCE(
            ARRAY_AGG(
                (a.agent_id, a.name, COALESCE(a.description, ''), a.roles)::types.q_get_rubric_detail_v4_agent
                ORDER BY a.name
            ),
            '{}'::types.q_get_rubric_detail_v4_agent[]
        ) as agents
    FROM valid_agents_data a
)
SELECT 
    rec.rubric_exists,
    rd.rubric_id,
    -- Merge draft payload with rubric data (draft takes precedence)
    COALESCE(
        (SELECT payload->>'name' FROM draft_payload_data),
        rd.name::text
    ) as name,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        rd.description::text
    ) as description,
    COALESCE(rdd.department_ids, ARRAY[]::text[]) as department_ids,
    COALESCE(vd.dept_ids, ARRAY[]::text[]) as valid_department_ids,
    rd.points,
    rd.pass_points,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        rd.active::boolean
    ) as active,
    CASE 
        WHEN (COALESCE(rdd.department_ids, ARRAY[]::text[]) = ARRAY[]::text[] AND pr.user_role != 'superadmin') THEN false
        WHEN pr.user_role = 'superadmin' THEN true
        WHEN pr.user_role IN ('admin', 'instructional') AND uhra.has_access THEN true
        ELSE false
    END as can_edit,
    COALESCE(
        (SELECT (payload->>'rubricAgentId')::uuid FROM draft_payload_data),
        (SELECT (payload->>'rubric_agent_id')::uuid FROM draft_payload_data),
        rd.rubric_agent_id
    ) as rubric_agent_id,
    COALESCE(aa.valid_agent_ids, ARRAY[]::text[]) as valid_agent_ids,
    up.actor_name,
    COALESCE(sga.standard_group_ids, ARRAY[]::uuid[]) as standard_group_ids,
    sga.standard_groups,
    sta.standards,
    da.departments,
    aa.agents,
    -- Draft version (from draft payload if exists)
    COALESCE((SELECT draft_version FROM draft_payload_data), 0) as draft_version,
    -- Extract standardGroups from draft payload if available (support both camelCase and snake_case)
    COALESCE(
        (SELECT payload->'standardGroups' FROM draft_payload_data),
        (SELECT payload->'standard_groups' FROM draft_payload_data),
        '[]'::jsonb
    ) as draft_standard_groups,
    -- Extract standards from draft payload if available (support both camelCase and snake_case)
    COALESCE(
        (SELECT payload->'standards' FROM draft_payload_data),
        (SELECT payload->'standards' FROM draft_payload_data),
        '[]'::jsonb
    ) as draft_standards,
    -- Extract gridCells from draft payload if available (support both camelCase and snake_case)
    COALESCE(
        (SELECT payload->'gridCells' FROM draft_payload_data),
        (SELECT payload->'grid_cells' FROM draft_payload_data),
        '{}'::jsonb
    ) as draft_grid_cells
FROM rubric_exists_check rec
CROSS JOIN rubric_data rd
LEFT JOIN rubric_departments_data rdd ON true
CROSS JOIN valid_depts vd
CROSS JOIN profile_data pr
CROSS JOIN user_profile up
CROSS JOIN standard_groups_aggregated sga
CROSS JOIN standards_aggregated sta
CROSS JOIN departments_aggregated da
CROSS JOIN user_has_rubric_access uhra
CROSS JOIN agents_aggregated aa
LEFT JOIN draft_payload_data ON true
WHERE uhra.has_access = true OR rec.rubric_exists = false
$$;


--
-- Name: api_get_rubric_grade_agent_for_run_or_group_v4(uuid, boolean, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_rubric_grade_agent_for_run_or_group_v4(eval_id uuid, use_groups boolean, run_id uuid DEFAULT NULL::uuid, group_id uuid DEFAULT NULL::uuid) RETURNS TABLE(rubric_grade_agent_id uuid)
    LANGUAGE sql STABLE
    AS $$
WITH run_rubric AS (
    SELECT 
        errga.rubric_grade_agent_id::uuid as rubric_grade_agent_id
    FROM eval_runs_rubric_grade_agents errga
    WHERE errga.eval_id = eval_id 
      AND errga.run_id = run_id
      AND use_groups = false
    ORDER BY errga.created_at ASC
    LIMIT 1
),
group_rubric AS (
    SELECT 
        egga.rubric_grade_agent_id::uuid as rubric_grade_agent_id
    FROM eval_groups_rubric_grade_agents egga
    WHERE egga.eval_id = eval_id 
      AND egga.group_id = group_id
      AND use_groups = true
    ORDER BY egga.created_at ASC
    LIMIT 1
)
SELECT 
    COALESCE(rr.rubric_grade_agent_id, gr.rubric_grade_agent_id) as rubric_grade_agent_id
FROM run_rubric rr
FULL OUTER JOIN group_rubric gr ON true
$$;


--
-- Name: api_get_rubric_new_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_rubric_new_v4(profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(name text, description text, department_ids text[], valid_department_ids text[], points integer, pass_points integer, active boolean, can_edit boolean, rubric_agent_id uuid, valid_agent_ids text[], actor_name text, user_role text, primary_department_id uuid, standard_group_ids uuid[], standard_groups types.q_get_rubric_new_v4_standard_group[], standards types.q_get_rubric_new_v4_standard[], departments types.q_get_rubric_new_v4_department[], agents types.q_get_rubric_new_v4_agent[], draft_version integer, draft_standard_groups jsonb, draft_standards jsonb, draft_grid_cells jsonb)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id, draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'rubrics'::draft_resource_type
    LIMIT 1
),
user_profile AS (
    SELECT 
        role as user_role,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
user_departments AS (
    SELECT DISTINCT pd.department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id
    WHERE pd.active = true
),
default_rubric AS (
    SELECT r.id
    FROM rubrics r
    LEFT JOIN rubric_departments rd ON rd.rubric_id = r.id AND rd.active = true
    WHERE r.active = true
    GROUP BY r.id
    HAVING 
        COUNT(rd.rubric_id) FILTER (WHERE rd.department_id IN (SELECT department_id FROM user_departments)) > 0
        OR NOT EXISTS (SELECT 1 FROM rubric_departments rd2 WHERE rd2.rubric_id = r.id AND rd2.active = true)
    ORDER BY r.created_at DESC
    LIMIT 1
),
rubric_data AS (
    SELECT 
        ''::text as name,
        ''::text as description,
        r.active,
        r.points,
        r.pass_points
    FROM rubrics r
    JOIN default_rubric dr ON r.id = dr.id
),
rubric_departments_data AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(rd.department_id::text ORDER BY rd.created_at) FILTER (WHERE rd.department_id IS NOT NULL),
            ARRAY[]::text[]
        ) as department_ids
    FROM default_rubric dr
    LEFT JOIN rubric_departments rd ON rd.rubric_id = dr.id AND rd.active = true
    GROUP BY dr.id
),
valid_depts AS (
    SELECT 
        array_agg(d.id::text ORDER BY d.title) as dept_ids
    FROM departments d
    JOIN params x ON true
    JOIN profile_departments pd ON d.id = pd.department_id
    WHERE pd.profile_id = x.profile_id AND d.active = true
),
primary_department_id AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id
    WHERE pd.is_primary = TRUE
    LIMIT 1
),
user_departments_for_agents AS (
    SELECT DISTINCT pd.department_id
    FROM profile_departments pd
    JOIN params x ON pd.profile_id = x.profile_id
    WHERE pd.active = true
),
standard_groups_data AS (
    SELECT 
        sg.id as standard_group_id,
        sg.name,
        sg.description,
        sg.points,
        sg.pass_points,
        rsg.position,
        rsg.active,
        ARRAY_AGG(s.id ORDER BY s.name) as standard_ids
    FROM default_rubric dr
    JOIN rubric_standard_groups rsg ON rsg.rubric_id = dr.id AND rsg.active = true
    JOIN standard_groups sg ON sg.id = rsg.standard_group_id
    LEFT JOIN standards s ON s.standard_group_id = sg.id
    GROUP BY sg.id, sg.name, sg.description, sg.points, sg.pass_points, rsg.position, rsg.active
),
standard_groups_aggregated AS (
    SELECT 
        ARRAY_AGG(sg.standard_group_id ORDER BY sg.position, sg.name) as standard_group_ids,
        COALESCE(
            ARRAY_AGG(
                (sg.standard_group_id, sg.name, COALESCE(sg.description, ''), sg.points, sg.pass_points, sg.position, sg.active, COALESCE(sg.standard_ids, ARRAY[]::uuid[]))::types.q_get_rubric_new_v4_standard_group
                ORDER BY sg.position, sg.name
            ),
            '{}'::types.q_get_rubric_new_v4_standard_group[]
        ) as standard_groups
    FROM standard_groups_data sg
),
standards_distinct AS (
    SELECT DISTINCT ON (s.id)
        s.id, s.name, COALESCE(s.description, '') as description, s.points
    FROM standards s
    WHERE s.standard_group_id IN (SELECT standard_group_id FROM standard_groups_data)
    ORDER BY s.id, s.name
),
standards_aggregated AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (sd.id, sd.name, sd.description, sd.points)::types.q_get_rubric_new_v4_standard
                ORDER BY sd.name
            ),
            '{}'::types.q_get_rubric_new_v4_standard[]
        ) as standards
    FROM standards_distinct sd
),
departments_distinct AS (
    SELECT DISTINCT ON (d.id)
        d.id, d.title, COALESCE(d.description, '') as description
    FROM departments d
    WHERE d.id IN (SELECT department_id FROM user_departments)
    ORDER BY d.id, d.title
),
departments_aggregated AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (dd.id, dd.title, dd.description)::types.q_get_rubric_new_v4_department
                ORDER BY dd.title
            ),
            '{}'::types.q_get_rubric_new_v4_department[]
        ) as departments
    FROM departments_distinct dd
),
valid_agents_data AS (
    SELECT 
        a.id as agent_id,
        a.name,
        a.description,
        ARRAY[a.role::text] as roles
    FROM agents a
    LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
    WHERE a.active = true 
    AND a.role = 'rubric'
    AND (
        EXISTS (
            SELECT 1 FROM agent_departments ad2 
            WHERE ad2.agent_id = a.id 
            AND ad2.active = true 
            AND ad2.department_id IN (SELECT department_id FROM user_departments_for_agents)
        )
        OR NOT EXISTS (
            SELECT 1 FROM agent_departments ad3 
            WHERE ad3.agent_id = a.id 
            AND ad3.active = true
        )
    )
),
agents_aggregated AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(a.agent_id::text ORDER BY a.name),
            ARRAY[]::text[]
        ) as valid_agent_ids,
        COALESCE(
            ARRAY_AGG(
                (a.agent_id, a.name, COALESCE(a.description, ''), a.roles)::types.q_get_rubric_new_v4_agent
                ORDER BY a.name
            ),
            '{}'::types.q_get_rubric_new_v4_agent[]
        ) as agents
    FROM valid_agents_data a
)
SELECT 
    -- Merge draft payload with rubric data (draft takes precedence)
    COALESCE(
        (SELECT payload->>'name' FROM draft_payload_data),
        rd.name::text
    ) as name,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        rd.description::text
    ) as description,
    COALESCE(rdd.department_ids, ARRAY[]::text[]) as department_ids,
    COALESCE(vd.dept_ids, ARRAY[]::text[]) as valid_department_ids,
    rd.points,
    rd.pass_points,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        rd.active::boolean
    ) as active,
    CASE 
        WHEN up.user_role = 'superadmin' THEN true
        WHEN up.user_role IN ('admin', 'instructional') THEN true
        ELSE false
    END as can_edit,
    COALESCE(
        (SELECT (payload->>'rubricAgentId')::uuid FROM draft_payload_data),
        (SELECT (payload->>'rubric_agent_id')::uuid FROM draft_payload_data),
        NULL::uuid
    ) as rubric_agent_id,
    COALESCE(aa.valid_agent_ids, ARRAY[]::text[]) as valid_agent_ids,
    up.actor_name,
    up.user_role,
    pdi.department_id as primary_department_id,
    COALESCE(sga.standard_group_ids, ARRAY[]::uuid[]) as standard_group_ids,
    sga.standard_groups,
    sta.standards,
    da.departments,
    aa.agents,
    -- Draft version (from draft payload if exists)
    COALESCE((SELECT draft_version FROM draft_payload_data), 0) as draft_version,
    -- Extract standardGroups from draft payload if available (support both camelCase and snake_case)
    COALESCE(
        (SELECT payload->'standardGroups' FROM draft_payload_data),
        (SELECT payload->'standard_groups' FROM draft_payload_data),
        '[]'::jsonb
    ) as draft_standard_groups,
    -- Extract standards from draft payload if available (support both camelCase and snake_case)
    COALESCE(
        (SELECT payload->'standards' FROM draft_payload_data),
        (SELECT payload->'standards' FROM draft_payload_data),
        '[]'::jsonb
    ) as draft_standards,
    -- Extract gridCells from draft payload if available (support both camelCase and snake_case)
    COALESCE(
        (SELECT payload->'gridCells' FROM draft_payload_data),
        (SELECT payload->'grid_cells' FROM draft_payload_data),
        '{}'::jsonb
    ) as draft_grid_cells
FROM rubric_data rd
LEFT JOIN rubric_departments_data rdd ON true
CROSS JOIN valid_depts vd
CROSS JOIN user_profile up
CROSS JOIN standard_groups_aggregated sga
CROSS JOIN standards_aggregated sta
CROSS JOIN departments_aggregated da
LEFT JOIN primary_department_id pdi ON true
CROSS JOIN agents_aggregated aa
LEFT JOIN draft_payload_data ON true
$$;


--
-- Name: api_get_rubrics_list_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_rubrics_list_v4(profile_id uuid) RETURNS TABLE(actor_name text, rubrics types.q_get_rubrics_list_v4_rubric[], standard_groups types.q_get_rubrics_list_v4_standard_group[], standards types.q_get_rubrics_list_v4_standard[], departments types.q_get_rubrics_list_v4_department[], simulations types.q_get_rubrics_list_v4_simulation[], simulation_options types.q_get_rubrics_list_v4_simulation[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id
),
user_departments AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments ON profile_departments.profile_id = x.profile_id AND profile_departments.active = true
),
rubric_active_simulation_links AS (
    SELECT 
        rga.rubric_id,
        COUNT(DISTINCT ss.simulation_id) as active_simulation_count
    FROM simulation_scenarios ss
    JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
    JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
    JOIN simulations s ON s.id = ss.simulation_id
    WHERE ss.active = true AND s.active = true AND rga.rubric_id IS NOT NULL
    GROUP BY rga.rubric_id
),
rubric_all_simulation_links AS (
    SELECT 
        rga.rubric_id,
        COUNT(DISTINCT ss.simulation_id) as total_simulation_links
    FROM simulation_scenarios ss
    JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
    JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
    WHERE rga.rubric_id IS NOT NULL
    GROUP BY rga.rubric_id
),
simulation_department_access_for_rubrics AS (
    -- Pre-compute which simulations the user has access to (for filtering rubric_simulations_data)
    SELECT 
        s.id as simulation_id,
        CASE 
            -- Include if has matching department link OR has no department links at all (cross-dept)
            WHEN COUNT(sd.simulation_id) FILTER (WHERE sd.department_id IN (SELECT department_id FROM user_departments)) > 0 THEN true
            WHEN NOT EXISTS (SELECT 1 FROM simulation_departments sd2 WHERE sd2.simulation_id = s.id AND sd2.active = true) THEN true
            ELSE false
        END as has_access
    FROM simulations s
    LEFT JOIN simulation_departments sd ON sd.simulation_id = s.id AND sd.active = true
    WHERE s.active = true
    GROUP BY s.id
),
rubric_simulations_distinct AS (
    SELECT DISTINCT ON (rga.rubric_id, s.id)
        rga.rubric_id,
        s.id as simulation_id,
        s.title as simulation_title
    FROM simulations s
    INNER JOIN simulation_department_access_for_rubrics sdar ON sdar.simulation_id = s.id AND sdar.has_access = true
    INNER JOIN simulation_scenarios ss ON ss.simulation_id = s.id AND ss.active = true
    INNER JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
    INNER JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
    WHERE s.active = true AND rga.rubric_id IS NOT NULL
    ORDER BY rga.rubric_id, s.id, s.title
),
rubric_simulations_data AS (
    SELECT 
        rsd.rubric_id,
        ARRAY_AGG(DISTINCT rsd.simulation_id::text ORDER BY rsd.simulation_id::text) as simulation_ids
    FROM rubric_simulations_distinct rsd
    GROUP BY rsd.rubric_id
),
rubric_departments_data AS (
    SELECT 
        rd.rubric_id,
        ARRAY_AGG(rd.department_id::text ORDER BY rd.created_at) as department_ids
    FROM rubric_departments rd
    WHERE rd.active = true
    GROUP BY rd.rubric_id
),
user_profile AS (
    SELECT 
        role,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
rubric_data AS (
    SELECT 
        r.id as rubric_id,
        r.name,
        r.description,
        r.points,
        r.pass_points as pass_points,
        COALESCE(rdd.department_ids, NULL) as department_ids,
        COALESCE(rsd.simulation_ids, ARRAY[]::text[]) as simulation_ids,
        COALESCE(rasl.active_simulation_count, 0) as active_simulation_count,
        COALESCE(rasl_all.total_simulation_links, 0) as total_simulation_links,
        CASE 
            WHEN COALESCE(rasl.active_simulation_count, 0) > 0 THEN false
            WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_edit,
        CASE 
            WHEN COALESCE(rasl_all.total_simulation_links, 0) > 0 THEN false
            WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_delete,
        CASE 
            WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_duplicate
    FROM rubrics r
    LEFT JOIN rubric_departments rd ON rd.rubric_id = r.id AND rd.active = true
    LEFT JOIN rubric_departments_data rdd ON rdd.rubric_id = r.id
    LEFT JOIN rubric_simulations_data rsd ON rsd.rubric_id = r.id
    LEFT JOIN rubric_active_simulation_links rasl ON rasl.rubric_id = r.id
    LEFT JOIN rubric_all_simulation_links rasl_all ON rasl_all.rubric_id = r.id
    CROSS JOIN user_profile up
    GROUP BY r.id, r.name, r.description, r.points, r.pass_points, rdd.department_ids, rsd.simulation_ids, rasl.active_simulation_count, rasl_all.total_simulation_links, up.role
    HAVING 
        COUNT(rd.rubric_id) FILTER (WHERE rd.department_id IN (SELECT department_id FROM user_departments)) > 0
        OR NOT EXISTS (SELECT 1 FROM rubric_departments rd2 WHERE rd2.rubric_id = r.id AND rd2.active = true)
),
all_rubric_ids AS (
    SELECT DISTINCT rubric_id FROM rubric_data
),
rubric_standard_group_ids AS (
    SELECT 
        rsg.rubric_id,
        ARRAY_AGG(rsg.standard_group_id ORDER BY rsg.position, sg.name) as standard_group_ids
    FROM rubric_standard_groups rsg
    JOIN standard_groups sg ON sg.id = rsg.standard_group_id
    WHERE rsg.rubric_id IN (SELECT rubric_id FROM all_rubric_ids) AND rsg.active = true
    GROUP BY rsg.rubric_id
),
all_standard_group_ids AS (
    SELECT DISTINCT rsg.standard_group_id
    FROM rubric_standard_groups rsg
    WHERE rsg.rubric_id IN (SELECT rubric_id FROM all_rubric_ids) AND rsg.active = true
),
all_standard_ids AS (
    SELECT DISTINCT s.id as standard_id
    FROM standards s
    WHERE s.standard_group_id IN (SELECT standard_group_id FROM all_standard_group_ids)
),
all_department_ids AS (
    SELECT DISTINCT unnest(department_ids)::uuid as department_id
    FROM rubric_departments_data
    WHERE department_ids IS NOT NULL
),
all_simulation_ids AS (
    SELECT DISTINCT unnest(simulation_ids)::uuid as simulation_id
    FROM rubric_simulations_data
    WHERE simulation_ids IS NOT NULL
),
-- Collect all assigned simulation IDs and department IDs from rubric_data for filtering
assigned_simulation_ids AS (
    SELECT DISTINCT unnest(simulation_ids)::uuid as simulation_id
    FROM rubric_data
    WHERE simulation_ids IS NOT NULL AND COALESCE(array_length(simulation_ids, 1), 0) > 0
),
assigned_department_ids AS (
    SELECT DISTINCT unnest(department_ids)::uuid as department_id
    FROM rubric_data
    WHERE department_ids IS NOT NULL AND COALESCE(array_length(department_ids, 1), 0) > 0
),
standard_groups_distinct AS (
    SELECT DISTINCT ON (sg.id)
        sg.id, rsg.rubric_id, sg.name, COALESCE(sg.description, '') as description, sg.points, sg.pass_points, rsg.position
    FROM rubric_standard_groups rsg
    JOIN standard_groups sg ON sg.id = rsg.standard_group_id
    WHERE rsg.rubric_id IN (SELECT rubric_id FROM all_rubric_ids) AND rsg.active = true
    ORDER BY sg.id, rsg.rubric_id, rsg.position, sg.name
),
standard_groups_aggregated AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (sgd.id, sgd.rubric_id, sgd.name, sgd.description, sgd.points, sgd.pass_points)::types.q_get_rubrics_list_v4_standard_group
                ORDER BY sgd.rubric_id, sgd.position, sgd.name
            ),
            '{}'::types.q_get_rubrics_list_v4_standard_group[]
        ) as standard_groups
    FROM standard_groups_distinct sgd
),
standards_distinct AS (
    SELECT DISTINCT ON (s.id)
        s.id, s.standard_group_id, s.name, COALESCE(s.description, '') as description, s.points
    FROM standards s
    WHERE s.standard_group_id IN (SELECT standard_group_id FROM all_standard_group_ids)
    ORDER BY s.id, s.standard_group_id, s.name
),
standards_aggregated AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (sd.id, sd.standard_group_id, sd.name, sd.description, sd.points)::types.q_get_rubrics_list_v4_standard
                ORDER BY sd.standard_group_id, sd.name
            ),
            '{}'::types.q_get_rubrics_list_v4_standard[]
        ) as standards
    FROM standards_distinct sd
),
departments_distinct AS (
    SELECT DISTINCT ON (d.id)
        d.id, d.title, COALESCE(d.description, '') as description
    FROM departments d
    WHERE d.id IN (SELECT department_id FROM assigned_department_ids)
    ORDER BY d.id, d.title
),
departments_aggregated AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (dd.id, dd.title, dd.description)::types.q_get_rubrics_list_v4_department
                ORDER BY dd.title
            ),
            '{}'::types.q_get_rubrics_list_v4_department[]
        ) as departments
    FROM departments_distinct dd
),
simulations_with_time_limit AS (
    SELECT DISTINCT ON (s.id)
        s.id, 
        s.title, 
        COALESCE(s.description, '') as description,
        COALESCE(
            (SELECT SUM(stl.time_limit_seconds)
             FROM scenario_time_limits stl
             JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
             WHERE stl.simulation_id = s.id AND stl.active = true AND ss.active = true),
            0
        )::int as time_limit
    FROM simulations s
    INNER JOIN simulation_department_access_for_rubrics sdar ON sdar.simulation_id = s.id AND sdar.has_access = true
    WHERE s.active = true 
      AND s.id IN (SELECT simulation_id FROM all_simulation_ids)
    ORDER BY s.id, s.title
),
simulations_aggregated AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (swtl.id, swtl.title, swtl.description, swtl.time_limit)::types.q_get_rubrics_list_v4_simulation
                ORDER BY swtl.title
            ),
            '{}'::types.q_get_rubrics_list_v4_simulation[]
        ) as simulations
    FROM simulations_with_time_limit swtl
),
-- Filter simulation_options to only include assigned simulations (with disambiguation for duplicate names)
simulation_name_counts AS (
    SELECT s.title, COUNT(*) as count
    FROM simulations s
    WHERE s.id IN (SELECT simulation_id FROM assigned_simulation_ids)
    GROUP BY s.title
),
simulation_options_with_disambiguation AS (
    SELECT DISTINCT ON (s.id)
        s.id,
        CASE 
            WHEN snc.count > 1 THEN s.title || ' (' || RIGHT(s.id::text, 8) || ')'
            ELSE s.title
        END as name,
        COALESCE(s.description, '') as description,
        COALESCE(
            (SELECT SUM(stl.time_limit_seconds)
             FROM scenario_time_limits stl
             JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
             WHERE stl.simulation_id = s.id AND stl.active = true AND ss.active = true),
            0
        )::int as time_limit
    FROM simulations s
    INNER JOIN simulation_department_access_for_rubrics sdar ON sdar.simulation_id = s.id AND sdar.has_access = true
    LEFT JOIN simulation_name_counts snc ON snc.title = s.title
    WHERE s.active = true 
      AND s.id IN (SELECT simulation_id FROM assigned_simulation_ids)
    ORDER BY s.id, s.title
),
simulation_options_aggregated AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (sod.id, sod.name, sod.description, sod.time_limit)::types.q_get_rubrics_list_v4_simulation
                ORDER BY sod.name
            ),
            '{}'::types.q_get_rubrics_list_v4_simulation[]
        ) as simulation_options
    FROM simulation_options_with_disambiguation sod
)
SELECT 
    up.actor_name::text as actor_name,
    COALESCE(
        ARRAY_AGG(
            (rd.rubric_id,
             rd.name,
             rd.description,
             rd.points,
             rd.pass_points,
             CASE WHEN rd.points > 0 THEN ROUND((rd.pass_points::numeric / rd.points::numeric) * 100) ELSE 0 END::int,
             rd.department_ids,
             rd.simulation_ids,
             rd.active_simulation_count,
             rd.total_simulation_links,
             rd.can_edit,
             rd.can_delete,
             rd.can_duplicate,
             COALESCE(rsgi.standard_group_ids, ARRAY[]::uuid[])
            )::types.q_get_rubrics_list_v4_rubric
            ORDER BY rd.name
        ),
        '{}'::types.q_get_rubrics_list_v4_rubric[]
    ) as rubrics,
    sga.standard_groups,
    sta.standards,
    da.departments,
    sima.simulations,
    soa.simulation_options
FROM rubric_data rd
CROSS JOIN user_profile up
LEFT JOIN rubric_standard_group_ids rsgi ON rsgi.rubric_id = rd.rubric_id
CROSS JOIN standard_groups_aggregated sga
CROSS JOIN standards_aggregated sta
CROSS JOIN departments_aggregated da
CROSS JOIN simulations_aggregated sima
CROSS JOIN simulation_options_aggregated soa
GROUP BY up.actor_name, sga.standard_groups, sta.standards, da.departments, sima.simulations, soa.simulation_options
$$;


--
-- Name: api_get_scenario_by_id_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_scenario_by_id_v4(scenario_id uuid) RETURNS TABLE(id uuid, name text, description text, root_scenario_id uuid, parent_scenario_id uuid, created_at timestamp with time zone, updated_at timestamp with time zone, active boolean, profile_id uuid, department_id uuid)
    LANGUAGE sql STABLE
    AS $$
SELECT 
    s.id,
    s.name,
    s.description,
    (SELECT st.parent_id FROM scenario_tree st WHERE st.child_id = s.id AND st.parent_id != s.id LIMIT 1) as root_scenario_id,
    (SELECT st.parent_id FROM scenario_tree st WHERE st.child_id = s.id AND st.parent_id != s.id LIMIT 1) as parent_scenario_id,
    s.created_at,
    s.updated_at,
    s.active,
    NULL::uuid as profile_id,
    (SELECT sd.department_id FROM scenario_departments sd WHERE sd.scenario_id = s.id AND sd.active = true LIMIT 1) as department_id
FROM scenarios s
WHERE s.id = api_get_scenario_by_id_v4.scenario_id
$$;


--
-- Name: api_get_scenario_departments_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_scenario_departments_v4(scenario_id uuid) RETURNS TABLE(department_id uuid)
    LANGUAGE sql STABLE
    AS $$
SELECT sd.department_id
FROM scenario_departments sd
WHERE sd.scenario_id = scenario_id 
  AND sd.active = true
$$;


--
-- Name: api_get_scenario_detail_v4(uuid, uuid, boolean, boolean, uuid[], uuid[], uuid[], boolean, uuid[], uuid[], uuid[], uuid[], uuid[], text, text, text, boolean, boolean, boolean, types.q_get_scenario_detail_v4_field_param_filter[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_scenario_detail_v4(scenario_id uuid, profile_id uuid, use_image boolean DEFAULT NULL::boolean, use_objectives boolean DEFAULT NULL::boolean, document_ids uuid[] DEFAULT NULL::uuid[], problem_statement_ids uuid[] DEFAULT NULL::uuid[], template_document_ids uuid[] DEFAULT NULL::uuid[], use_video boolean DEFAULT NULL::boolean, filter_department_ids uuid[] DEFAULT NULL::uuid[], filter_persona_ids uuid[] DEFAULT NULL::uuid[], filter_document_ids uuid[] DEFAULT NULL::uuid[], filter_parameter_ids uuid[] DEFAULT NULL::uuid[], filter_field_ids uuid[] DEFAULT NULL::uuid[], persona_search text DEFAULT NULL::text, document_search text DEFAULT NULL::text, parameter_search text DEFAULT NULL::text, persona_show_selected boolean DEFAULT NULL::boolean, document_show_selected boolean DEFAULT NULL::boolean, parameter_show_selected boolean DEFAULT NULL::boolean, field_show_selected_by_param types.q_get_scenario_detail_v4_field_param_filter[] DEFAULT ARRAY[]::types.q_get_scenario_detail_v4_field_param_filter[], draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(scenario_exists boolean, scenario_id uuid, name text, description text, problem_statement text, problem_statement_id text, active boolean, generated boolean, department_ids text[], parent_scenario_id uuid, hints_enabled boolean, objectives_enabled boolean, image_input_enabled boolean, persona_ids text[], document_ids text[], objective_ids text[], simulation_ids text[], valid_persona_ids text[], valid_document_ids text[], valid_department_ids uuid[], active_usage_count bigint, user_role text, actor_name text, parameter_ids text[], valid_parameter_ids text[], valid_field_ids text[], question_ids text[], persona_range_min integer, persona_range_max integer, document_range_min integer, document_range_max integer, parameter_range_min integer, parameter_range_max integer, video_enabled boolean, questions_enabled boolean, problem_statement_enabled boolean, scenario_agent_id text, image_agent_id text, video_agent_id text, valid_agent_ids text[], can_edit boolean, can_duplicate boolean, can_delete boolean, field_ranges types.q_get_scenario_detail_v4_field_range[], personas types.q_get_scenario_detail_v4_persona[], documents types.q_get_scenario_detail_v4_document[], parameters types.q_get_scenario_detail_v4_parameter[], fields types.q_get_scenario_detail_v4_field[], departments types.q_get_scenario_detail_v4_department[], agents types.q_get_scenario_detail_v4_agent[], simulations types.q_get_scenario_detail_v4_simulation[], objectives types.q_get_scenario_detail_v4_objective[], problem_statements types.q_get_scenario_detail_v4_problem_statement[], scenario_images types.q_get_scenario_detail_v4_scenario_image[], scenario_videos types.q_get_scenario_detail_v4_scenario_video[], questions types.q_get_scenario_detail_v4_question[], objectives_history types.q_get_scenario_detail_v4_objective_with_departments[], document_details types.q_get_scenario_detail_v4_document_detail[], parameters_detail types.q_get_scenario_detail_v4_parameter_detail[], draft_version integer, draft_field_show_selected jsonb, draft_field_ranges jsonb, draft_randomize_parameter_items jsonb)
    LANGUAGE sql STABLE
    AS $_$
WITH params AS (
    SELECT 
        scenario_id AS scenario_id,
        profile_id AS profile_id,
        COALESCE(use_image, false) AS use_image,
        COALESCE(use_objectives, false) AS use_objectives,
        COALESCE(document_ids, ARRAY[]::uuid[]) AS document_ids,
        COALESCE(problem_statement_ids, ARRAY[]::uuid[]) AS problem_statement_ids,
        COALESCE(template_document_ids, ARRAY[]::uuid[]) AS template_document_ids,
        COALESCE(use_video, false) AS use_video,
        -- Filter parameters
        COALESCE(filter_department_ids, ARRAY[]::uuid[]) AS filter_department_ids,
        COALESCE(filter_persona_ids, ARRAY[]::uuid[]) AS filter_persona_ids,
        COALESCE(filter_document_ids, ARRAY[]::uuid[]) AS filter_document_ids,
        COALESCE(filter_parameter_ids, ARRAY[]::uuid[]) AS filter_parameter_ids,
        COALESCE(filter_field_ids, ARRAY[]::uuid[]) AS filter_field_ids,
        -- Search parameters
        COALESCE(NULLIF(persona_search, ''), NULL) AS persona_search,
        COALESCE(NULLIF(document_search, ''), NULL) AS document_search,
        COALESCE(NULLIF(parameter_search, ''), NULL) AS parameter_search,
        -- Show selected filters
        COALESCE(persona_show_selected, false) AS persona_show_selected,
        COALESCE(document_show_selected, false) AS document_show_selected,
        COALESCE(parameter_show_selected, false) AS parameter_show_selected,
        COALESCE(field_show_selected_by_param, ARRAY[]::types.q_get_scenario_detail_v4_field_param_filter[]) AS field_show_selected_by_param,
        draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'scenarios'::draft_resource_type
    LIMIT 1
),
scenario_exists_check AS (
    -- Check if scenario exists independently of access control
    SELECT EXISTS(
        SELECT 1 FROM scenarios WHERE id = (SELECT scenario_id FROM params LIMIT 1)
    )::boolean as scenario_exists
),
resolve_profile_id AS (
    -- Resolve profile ID from parameter
    SELECT 
        CASE 
            WHEN (SELECT profile_id FROM params)::text IS NULL OR (SELECT profile_id FROM params)::text = '' THEN NULL::uuid
            ELSE (SELECT profile_id FROM params)::uuid
        END as resolved_profile_id
),
-- profile_id is always a UUID (required in request body)
user_profile AS (
    SELECT 
        role,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM profiles p
    WHERE p.id = (SELECT profile_id FROM params LIMIT 1)
),
user_departments AS (
    SELECT ARRAY_AGG(DISTINCT pd.department_id) as dept_ids
    FROM resolve_profile_id rpi
    JOIN profile_departments pd ON pd.profile_id = rpi.resolved_profile_id
    JOIN departments d ON d.id = pd.department_id
    WHERE pd.active = true AND d.active = true
),
user_departments_rows AS (
    SELECT DISTINCT pd.department_id as id
    FROM resolve_profile_id rpi
    JOIN profile_departments pd ON pd.profile_id = rpi.resolved_profile_id
    JOIN departments d ON d.id = pd.department_id
    WHERE pd.active = true AND d.active = true
),
scenario_departments_data AS (
    SELECT 
        sd.scenario_id,
        ARRAY_AGG(sd.department_id::text ORDER BY sd.created_at) as department_ids
    FROM scenario_departments sd
    WHERE sd.scenario_id = (SELECT scenario_id FROM params LIMIT 1) AND sd.active = true
    GROUP BY sd.scenario_id
),
scenario_active_problem_statement AS (
    SELECT 
        sps.scenario_id,
        ps.id::text as problem_statement_id,
        ps.name,
        ps.problem_statement,
        ps.created_at as problem_statement_created_at,
        ps.updated_at as problem_statement_updated_at
    FROM scenario_problem_statements sps
    JOIN problem_statements ps ON ps.id = sps.problem_statement_id
    WHERE sps.scenario_id = (SELECT scenario_id FROM params LIMIT 1) AND sps.active = true
    LIMIT 1
),
scenario_all_problem_statements AS (
    SELECT 
        sps.scenario_id,
        ps.id::text as problem_statement_id,
        ps.id as problem_statement_id_uuid,
        ps.name,
        ps.problem_statement,
        ps.created_at as problem_statement_created_at,
        ps.updated_at as problem_statement_updated_at
    FROM scenario_problem_statements sps
    JOIN problem_statements ps ON ps.id = sps.problem_statement_id
    WHERE sps.scenario_id = (SELECT scenario_id FROM params)
),
problem_statements_array AS (
    -- Problem statements from scenario (sorted first)
    SELECT 
        sps.problem_statement_id_uuid as problem_statement_id,
        sps.name,
        sps.problem_statement,
        sps.problem_statement_created_at as created_at,
        sps.problem_statement_updated_at as updated_at,
        0 as sort_order
    FROM scenario_all_problem_statements sps
    UNION ALL
    -- ALL other problem statements matching departments
    SELECT 
        ps.id as problem_statement_id,
        ps.name,
        ps.problem_statement,
        ps.created_at,
        ps.updated_at,
        1 as sort_order
    FROM problem_statements ps
    LEFT JOIN problem_statement_departments psd_dept ON psd_dept.problem_statement_id = ps.id AND psd_dept.active = true
    WHERE (
        psd_dept.department_id IN (SELECT id FROM user_departments_rows)
        OR NOT EXISTS (SELECT 1 FROM problem_statement_departments psd2 WHERE psd2.problem_statement_id = ps.id AND psd2.active = true)
    )
    AND NOT EXISTS (
        SELECT 1
        FROM scenario_all_problem_statements saps
        WHERE saps.problem_statement_id_uuid = ps.id
    )
),
scenario_department_access_check AS (
    SELECT 
        s.id as scenario_id,
        CASE 
            WHEN up.role = 'superadmin'::profile_role THEN true
            WHEN EXISTS (
                SELECT 1 FROM scenario_departments sd 
                WHERE sd.scenario_id = s.id 
                AND sd.active = true 
                AND sd.department_id IN (SELECT department_id FROM resolve_profile_id rpi JOIN profile_departments pd ON pd.profile_id = rpi.resolved_profile_id WHERE pd.active = true)
            ) THEN true
            WHEN NOT EXISTS (
                SELECT 1 FROM scenario_departments sd2 
                WHERE sd2.scenario_id = s.id 
                AND sd2.active = true
            ) THEN true  -- Cross-department resource
            ELSE false
        END as has_access
    FROM scenarios s
    CROSS JOIN user_profile up
    WHERE s.id = (SELECT scenario_id FROM params LIMIT 1)
),
scenario_core AS (
    SELECT 
        s.id,
        s.name,
        s.description,
        COALESCE(saps.problem_statement, '') as problem_statement,
        COALESCE(saps.problem_statement_id, NULL) as problem_statement_id,
        s.active,
        s.generated,
        st.parent_id as parent_scenario_id,
        COALESCE(sdd.department_ids, NULL) as department_ids,
        s.objectives_enabled,
        s.images_enabled,
        s.video_enabled,
        s.questions_enabled,
        s.problem_statement_enabled,
        s.scenario_agent_id::text,
        s.image_agent_id::text,
        s.video_agent_id::text
    FROM scenarios s
    LEFT JOIN scenario_tree st ON st.child_id = s.id AND st.parent_id != st.parent_id
    LEFT JOIN scenario_active_problem_statement saps ON saps.scenario_id = s.id
    LEFT JOIN scenario_departments_data sdd ON sdd.scenario_id = s.id
    INNER JOIN scenario_department_access_check sdac ON sdac.scenario_id = s.id AND sdac.has_access = true
    WHERE s.id = (SELECT scenario_id FROM params LIMIT 1)
),
scenario_simulation_attributes AS (
    SELECT DISTINCT ON (ss.scenario_id)
        ss.scenario_id,
        ss.hints_enabled
    FROM simulation_scenarios ss
    WHERE ss.scenario_id = (SELECT scenario_id FROM params LIMIT 1) AND ss.active = true
    ORDER BY ss.scenario_id, ss.position
    LIMIT 1
),
scenario_personas_agg AS (
    SELECT ARRAY_AGG(persona_id::text ORDER BY persona_id) as persona_ids
    FROM scenario_personas
    WHERE scenario_id = (SELECT scenario_id FROM params LIMIT 1) AND active = true
),
scenario_documents_agg AS (
    SELECT ARRAY_AGG(document_id::text ORDER BY document_id) as document_ids
    FROM scenario_documents
    WHERE scenario_id = (SELECT scenario_id FROM params LIMIT 1) AND active = true
),
scenario_videos_array AS (
    SELECT 
        v.id,
        v.name,
        v.length_seconds,
        v.completed,
        v.active,
        v.image_enabled,
        u.file_path,
        u.mime_type,
        u.id as upload_id,
        CASE WHEN sv.scenario_id IS NOT NULL THEN 0 ELSE 1 END as sort_order,
        v.created_at
    FROM videos v
    LEFT JOIN video_uploads vu ON vu.video_id = v.id AND vu.active = true
    LEFT JOIN uploads u ON u.id = vu.upload_id
    LEFT JOIN video_departments vd_dept ON vd_dept.video_id = v.id AND vd_dept.active = true
    LEFT JOIN scenario_videos sv ON sv.video_id = v.id AND sv.scenario_id = (SELECT scenario_id FROM params) AND sv.active = true
    WHERE v.active = true
    AND (
        vd_dept.department_id IN (SELECT id FROM user_departments_rows)
        OR NOT EXISTS (SELECT 1 FROM video_departments vd2 WHERE vd2.video_id = v.id AND vd2.active = true)
    )
),
scenario_questions_array AS (
    SELECT 
        q.id,
        q.question_text,
        q.allow_multiple,
        COALESCE(sq.active, q.active) as active,
        CASE WHEN sq.scenario_id IS NOT NULL THEN 0 ELSE 1 END as sort_order,
        q.created_at
    FROM questions q
    LEFT JOIN question_departments qd_dept ON qd_dept.question_id = q.id AND qd_dept.active = true
    LEFT JOIN scenario_questions sq ON sq.question_id = q.id AND sq.scenario_id = (SELECT scenario_id FROM params) AND sq.active = true
    WHERE q.active = true
    AND (
        qd_dept.department_id IN (SELECT id FROM user_departments_rows)
        OR NOT EXISTS (SELECT 1 FROM question_departments qd2 WHERE qd2.question_id = q.id AND qd2.active = true)
    )
),
question_options_array AS (
    SELECT 
        q.id as question_id,
        opt.id,
        opt.option_text,
        opt.type::text,
        EXISTS(
            SELECT 1 FROM question_answers qa 
            WHERE qa.question_id = q.id AND qa.option_id = opt.id AND qa.active = true
        ) as is_correct
    FROM scenario_questions_array q
    JOIN question_options qopt ON qopt.question_id = q.id AND qopt.active = true
    JOIN options opt ON opt.id = qopt.option_id AND opt.active = true
),
question_times_array AS (
    SELECT 
        sqt.question_id,
        sqt.time
    FROM scenario_question_times sqt
    WHERE sqt.scenario_id = (SELECT scenario_id FROM params) 
    AND sqt.active = true
),
scenario_images_array AS (
    SELECT 
        COALESCE(iu.upload_id, i.id) as upload_id,
        i.name,
        u.file_path,
        u.mime_type,
        i.active,
        i.created_at,
        i.updated_at,
        CASE WHEN si.scenario_id IS NOT NULL THEN 0 ELSE 1 END as sort_order
    FROM images i
    LEFT JOIN image_uploads iu ON iu.image_id = i.id AND iu.active = true
    LEFT JOIN uploads u ON u.id = iu.upload_id
    LEFT JOIN image_departments id_dept ON id_dept.image_id = i.id AND id_dept.active = true
    LEFT JOIN scenario_images si ON si.image_id = i.id AND si.scenario_id = (SELECT scenario_id FROM params) AND si.active = true
    WHERE i.active = true
    AND (
        id_dept.department_id IN (SELECT id FROM user_departments_rows)
        OR NOT EXISTS (SELECT 1 FROM image_departments id2 WHERE id2.image_id = i.id AND id2.active = true)
    )
),
scenario_objectives_array AS (
    SELECT 
        o.id as objective_id,
        o.objective as name,
        o.objective as description,
        CASE WHEN so.scenario_id IS NOT NULL THEN 0 ELSE 1 END as sort_order,
        COALESCE(so.idx, 999999) as idx,
        o.created_at
    FROM objectives o
    LEFT JOIN objective_departments od_dept ON od_dept.objective_id = o.id AND od_dept.active = true
    LEFT JOIN scenario_objectives so ON so.objective_id = o.id AND so.scenario_id = (SELECT scenario_id FROM params)
    WHERE (
        od_dept.department_id IN (SELECT id FROM user_departments_rows)
        OR NOT EXISTS (SELECT 1 FROM objective_departments od2 WHERE od2.objective_id = o.id AND od2.active = true)
    )
),
scenario_simulations_agg AS (
    SELECT 
        COALESCE(ARRAY_AGG(DISTINCT simulation_id::text), ARRAY[]::text[]) as simulation_ids,
        COUNT(DISTINCT CASE WHEN s.active THEN simulation_id END) as active_usage_count
    FROM simulation_scenarios ss
    JOIN simulations s ON s.id = ss.simulation_id
    WHERE ss.scenario_id = (SELECT scenario_id FROM params LIMIT 1) AND ss.active = true
),
all_parameters_data AS (
    SELECT 
        p.id as param_id,
        COALESCE((
            SELECT ARRAY_AGG(sf2.field_id ORDER BY sf2.field_id)
            FROM scenario_fields sf2
            JOIN parameter_fields fp2 ON fp2.field_id = sf2.field_id AND fp2.active = true
            WHERE sf2.scenario_id = (SELECT scenario_id FROM params LIMIT 1) AND fp2.parameter_id = p.id::uuid AND sf2.active = true
        ), ARRAY[]::uuid[]) as selected_items,
        COALESCE((
            SELECT ARRAY_AGG(id ORDER BY id)
            FROM (
                SELECT f3.id
                FROM fields f3
                JOIN parameter_fields fp3 ON fp3.field_id = f3.id AND fp3.active = true
                LEFT JOIN field_departments fd3 ON fd3.field_id = f3.id AND fd3.active = true
                CROSS JOIN user_departments ud3
                WHERE fp3.parameter_id = p.id::uuid
                GROUP BY f3.id
                HAVING 
                    COUNT(fd3.field_id) FILTER (WHERE fd3.department_id = ANY(ud3.dept_ids)) > 0
                    OR NOT EXISTS (SELECT 1 FROM field_departments fd4 WHERE fd4.field_id = f3.id AND fd4.active = true)
                UNION
                SELECT sf2.field_id as id
                FROM scenario_fields sf2
                JOIN parameter_fields fp2 ON fp2.field_id = sf2.field_id AND fp2.active = true
                WHERE sf2.scenario_id = (SELECT scenario_id FROM params LIMIT 1) AND fp2.parameter_id = p.id::uuid AND sf2.active = true
            ) combined_items
        ), ARRAY[]::uuid[]) as valid_items
    FROM parameters p
    JOIN parameter_fields fp ON fp.parameter_id = p.id AND fp.active = true
    LEFT JOIN field_departments fd ON fd.field_id = fp.field_id AND fd.active = true
    CROSS JOIN user_departments ud
    WHERE p.active = true
    GROUP BY p.id
    HAVING 
        COUNT(fd.field_id) FILTER (WHERE fd.department_id = ANY(ud.dept_ids)) > 0
        OR NOT EXISTS (SELECT 1 FROM field_departments fd2 
                      JOIN parameter_fields fp2 ON fp2.field_id = fd2.field_id 
                      WHERE fp2.parameter_id = p.id AND fd2.active = true)
),
valid_personas_filtered AS (
    SELECT DISTINCT
        p.id,
        p.name,
        COALESCE(p.description, '') as description,
        p.color,
        p.icon,
        false as image_model  -- No longer checking via persona agents
    FROM personas p
    LEFT JOIN persona_departments pd ON pd.persona_id = p.id AND pd.active = true
    CROSS JOIN user_departments ud
    WHERE p.active = true
    GROUP BY p.id, p.name, p.description, p.color, p.icon
    HAVING 
        (
            COUNT(pd.persona_id) FILTER (WHERE pd.department_id = ANY(ud.dept_ids)) > 0
            OR NOT EXISTS (SELECT 1 FROM persona_departments pd2 WHERE pd2.persona_id = p.id AND pd2.active = true)
        )
        AND (
            CASE 
                WHEN (SELECT use_video FROM params) = true THEN
                    -- Include video_parameter OR general parameters
                    EXISTS (
                        SELECT 1 
                        FROM persona_fields pf
                        JOIN parameter_fields pfield ON pfield.field_id = pf.field_id
                        JOIN parameters param ON param.id = pfield.parameter_id
                        WHERE pf.persona_id = p.id
                        AND pf.active = true
                        AND pfield.active = true
                        AND param.active = true
                        AND param.video_parameter = true
                    )
                    OR EXISTS (
                        SELECT 1 
                        FROM persona_fields pf
                        JOIN field_conditional_parameters fcp ON fcp.field_id = pf.field_id
                        JOIN parameters cp ON cp.id = fcp.conditional_parameter_id
                        WHERE pf.persona_id = p.id
                        AND pf.active = true
                        AND fcp.active = true
                        AND cp.video_parameter = true
                    )
                    OR EXISTS (
                        SELECT 1 
                        FROM persona_fields pf
                        JOIN parameter_fields pfield ON pfield.field_id = pf.field_id
                        JOIN parameters param ON param.id = pfield.parameter_id
                        WHERE pf.persona_id = p.id
                        AND pf.active = true
                        AND pfield.active = true
                        AND param.active = true
                        AND param.video_parameter = false
                        AND param.scenario_parameter = false
                    )
                ELSE
                    -- Include scenario_parameter OR general parameters
                    EXISTS (
                        SELECT 1 
                        FROM persona_fields pf
                        JOIN parameter_fields pfield ON pfield.field_id = pf.field_id
                        JOIN parameters param ON param.id = pfield.parameter_id
                        WHERE pf.persona_id = p.id
                        AND pf.active = true
                        AND pfield.active = true
                        AND param.active = true
                        AND param.scenario_parameter = true
                    )
                    OR EXISTS (
                        SELECT 1 
                        FROM persona_fields pf
                        JOIN field_conditional_parameters fcp ON fcp.field_id = pf.field_id
                        JOIN parameters cp ON cp.id = fcp.conditional_parameter_id
                        WHERE pf.persona_id = p.id
                        AND pf.active = true
                        AND fcp.active = true
                        AND cp.scenario_parameter = true
                    )
                    OR EXISTS (
                        SELECT 1 
                        FROM persona_fields pf
                        JOIN parameter_fields pfield ON pfield.field_id = pf.field_id
                        JOIN parameters param ON param.id = pfield.parameter_id
                        WHERE pf.persona_id = p.id
                        AND pf.active = true
                        AND pfield.active = true
                        AND param.active = true
                        AND param.video_parameter = false
                        AND param.scenario_parameter = false
                    )
            END
        )
        -- Filter by selected departments
        AND (
            (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM persona_departments pd_filter
                WHERE pd_filter.persona_id = p.id
                AND pd_filter.active = true
                AND pd_filter.department_id = ANY((SELECT filter_department_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Filter by selected parameters (persona must have fields from selected parameters)
        AND (
            (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM persona_fields pf_filter
                JOIN parameter_fields pfield_filter ON pfield_filter.field_id = pf_filter.field_id
                WHERE pf_filter.persona_id = p.id
                AND pf_filter.active = true
                AND pfield_filter.active = true
                AND pfield_filter.parameter_id = ANY((SELECT filter_parameter_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Filter by selected fields (persona must have selected fields)
        AND (
            (SELECT array_length(filter_field_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_field_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM persona_fields pf_field_filter
                WHERE pf_field_filter.persona_id = p.id
                AND pf_field_filter.active = true
                AND pf_field_filter.field_id = ANY((SELECT filter_field_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Search filter
        AND (
            (SELECT persona_search FROM params LIMIT 1) IS NULL
            OR LOWER(p.name) LIKE '%' || LOWER((SELECT persona_search FROM params LIMIT 1)) || '%'
            OR LOWER(COALESCE(p.description, '')) LIKE '%' || LOWER((SELECT persona_search FROM params LIMIT 1)) || '%'
        )
        -- Show selected filter
        AND (
            (SELECT persona_show_selected FROM params LIMIT 1) = false
            OR (SELECT array_length(filter_persona_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_persona_ids, 1) FROM params LIMIT 1) = 0
            OR p.id = ANY((SELECT filter_persona_ids FROM params LIMIT 1)::uuid[])
        )
),
persona_data_base AS (
    SELECT 
        p.id,
        p.name,
        p.description,
        p.color,
        p.icon,
        p.image_model
    FROM valid_personas_filtered p
    UNION
    SELECT DISTINCT
        p2.id,
        p2.name,
        COALESCE(p2.description, '') as description,
        p2.color,
        p2.icon,
        false as image_model  -- No longer checking via persona agents
    FROM scenario_personas_agg spa
    CROSS JOIN LATERAL unnest(spa.persona_ids) as persona_id
    JOIN personas p2 ON p2.id = persona_id::uuid
    WHERE p2.active = true
),
persona_data AS (
    SELECT DISTINCT
        pdb.id,
        pdb.name,
        pdb.description,
        pdb.color,
        pdb.icon,
        pdb.image_model
    FROM persona_data_base pdb
    WHERE
        -- Filter by selected departments (already filtered in valid_personas_filtered, but apply again for UNION results)
        (
            (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM persona_departments pd_filter
                WHERE pd_filter.persona_id = pdb.id
                AND pd_filter.active = true
                AND pd_filter.department_id = ANY((SELECT filter_department_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Filter by selected parameters
        AND (
            (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM persona_fields pf_filter
                JOIN parameter_fields pfield_filter ON pfield_filter.field_id = pf_filter.field_id
                WHERE pf_filter.persona_id = pdb.id
                AND pf_filter.active = true
                AND pfield_filter.active = true
                AND pfield_filter.parameter_id = ANY((SELECT filter_parameter_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Filter by selected fields
        AND (
            (SELECT array_length(filter_field_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_field_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM persona_fields pf_field_filter
                WHERE pf_field_filter.persona_id = pdb.id
                AND pf_field_filter.active = true
                AND pf_field_filter.field_id = ANY((SELECT filter_field_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Search filter
        AND (
            (SELECT persona_search FROM params LIMIT 1) IS NULL
            OR LOWER(pdb.name) LIKE '%' || LOWER((SELECT persona_search FROM params LIMIT 1)) || '%'
            OR LOWER(COALESCE(pdb.description, '')) LIKE '%' || LOWER((SELECT persona_search FROM params LIMIT 1)) || '%'
        )
        -- Show selected filter
        AND (
            (SELECT persona_show_selected FROM params LIMIT 1) = false
            OR (SELECT array_length(filter_persona_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_persona_ids, 1) FROM params LIMIT 1) = 0
            OR pdb.id = ANY((SELECT filter_persona_ids FROM params LIMIT 1)::uuid[])
        )
),
-- Persona parameter relationships: via fields (persona_fields → parameter_fields) and persona_parameter flag
persona_parameter_relationships AS (
    SELECT DISTINCT
        p.id as persona_id,
        param.id as parameter_id
    FROM persona_data p
    CROSS JOIN parameters param
    WHERE param.active = true
    AND param.persona_parameter = true
    AND (
        EXISTS (
            SELECT 1 FROM persona_fields pf
            JOIN parameter_fields pfield ON pfield.field_id = pf.field_id
            WHERE pf.persona_id = p.id
            AND pfield.parameter_id = param.id
            AND pf.active = true
            AND pfield.active = true
        )
    )
),
persona_fields_agg AS (
    SELECT 
        pf.persona_id,
        ARRAY_AGG(pf.field_id ORDER BY pf.field_id) as field_ids
    FROM persona_fields pf
    WHERE pf.persona_id IN (SELECT id FROM persona_data) AND pf.active = true
    GROUP BY pf.persona_id
),
persona_parameter_ids_agg AS (
    SELECT 
        ppr.persona_id,
        ARRAY_AGG(ppr.parameter_id ORDER BY ppr.parameter_id) as parameter_ids
    FROM persona_parameter_relationships ppr
    GROUP BY ppr.persona_id
),
persona_examples_data AS (
    SELECT DISTINCT ON (pe.persona_id)
        pe.persona_id,
        e.example
    FROM persona_examples pe
    JOIN examples e ON e.id = pe.example_id
    WHERE pe.persona_id IN (SELECT id FROM persona_data)
    ORDER BY pe.persona_id, pe.idx
),
valid_personas_array AS (
    SELECT 
        p.id as persona_id,
        p.name,
        p.description,
        p.color,
        p.icon,
        COALESCE(p.image_model, false) as image_model,
        COALESCE(ppia.parameter_ids, ARRAY[]::uuid[]) as parameter_ids,
        COALESCE(pfa.field_ids, ARRAY[]::uuid[]) as field_ids,
        ped.example
    FROM persona_data p
    LEFT JOIN persona_parameter_ids_agg ppia ON ppia.persona_id = p.id
    LEFT JOIN persona_fields_agg pfa ON pfa.persona_id = p.id
    LEFT JOIN persona_examples_data ped ON ped.persona_id = p.id
),
valid_documents_filtered AS (
    SELECT DISTINCT
        d.id,
        d.name,
        ''::text as description,
        u.file_path,
        u.mime_type
    FROM documents d
    LEFT JOIN document_uploads du ON du.document_id = d.id AND du.active = true
    LEFT JOIN uploads u ON u.id = du.upload_id
    LEFT JOIN document_departments dd ON dd.document_id = d.id AND dd.active = true
    CROSS JOIN user_departments ud
    WHERE d.active = true
    GROUP BY d.id, d.name, u.file_path, u.mime_type
    HAVING 
        (
            COUNT(dd.document_id) FILTER (WHERE dd.department_id = ANY(ud.dept_ids)) > 0
            OR NOT EXISTS (SELECT 1 FROM document_departments dd2 WHERE dd2.document_id = d.id AND dd2.active = true)
        )
        AND (
            CASE 
                WHEN (SELECT use_video FROM params) = true THEN
                    EXISTS (
                        SELECT 1 
                        FROM document_fields df
                        JOIN parameter_fields pfield ON pfield.field_id = df.field_id
                        JOIN parameters param ON param.id = pfield.parameter_id
                        WHERE df.document_id = d.id
                        AND df.active = true
                        AND pfield.active = true
                        AND param.active = true
                        AND param.video_parameter = true
                    )
                    OR EXISTS (
                        SELECT 1 
                        FROM document_fields df
                        JOIN field_conditional_parameters fcp ON fcp.field_id = df.field_id
                        JOIN parameters cp ON cp.id = fcp.conditional_parameter_id
                        WHERE df.document_id = d.id
                        AND df.active = true
                        AND fcp.active = true
                        AND cp.video_parameter = true
                    )
                ELSE
                    EXISTS (
                        SELECT 1 
                        FROM document_fields df
                        JOIN parameter_fields pfield ON pfield.field_id = df.field_id
                        JOIN parameters param ON param.id = pfield.parameter_id
                        WHERE df.document_id = d.id
                        AND df.active = true
                        AND pfield.active = true
                        AND param.active = true
                        AND param.scenario_parameter = true
                    )
                    OR EXISTS (
                        SELECT 1 
                        FROM document_fields df
                        JOIN field_conditional_parameters fcp ON fcp.field_id = df.field_id
                        JOIN parameters cp ON cp.id = fcp.conditional_parameter_id
                        WHERE df.document_id = d.id
                        AND df.active = true
                        AND fcp.active = true
                        AND cp.scenario_parameter = true
                    )
                    OR EXISTS (
                        SELECT 1 
                        FROM document_fields df
                        JOIN parameter_fields pfield ON pfield.field_id = df.field_id
                        JOIN parameters param ON param.id = pfield.parameter_id
                        WHERE df.document_id = d.id
                        AND df.active = true
                        AND pfield.active = true
                        AND param.active = true
                        AND param.video_parameter = false
                        AND param.scenario_parameter = false
                    )
            END
        )
        -- Filter by selected departments
        AND (
            (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM document_departments dd_filter
                WHERE dd_filter.document_id = d.id
                AND dd_filter.active = true
                AND dd_filter.department_id = ANY((SELECT filter_department_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Filter by selected parameters (document must have fields from selected parameters)
        AND (
            (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM document_fields df_filter
                JOIN parameter_fields pfield_filter ON pfield_filter.field_id = df_filter.field_id
                WHERE df_filter.document_id = d.id
                AND df_filter.active = true
                AND pfield_filter.active = true
                AND pfield_filter.parameter_id = ANY((SELECT filter_parameter_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Filter by selected fields (document must have selected fields)
        AND (
            (SELECT array_length(filter_field_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_field_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM document_fields df_field_filter
                WHERE df_field_filter.document_id = d.id
                AND df_field_filter.active = true
                AND df_field_filter.field_id = ANY((SELECT filter_field_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Search filter
        AND (
            (SELECT document_search FROM params LIMIT 1) IS NULL
            OR LOWER(d.name) LIKE '%' || LOWER((SELECT document_search FROM params LIMIT 1)) || '%'
            OR LOWER(COALESCE(d.description, '')) LIKE '%' || LOWER((SELECT document_search FROM params LIMIT 1)) || '%'
        )
        -- Show selected filter
        AND (
            (SELECT document_show_selected FROM params LIMIT 1) = false
            OR (SELECT array_length(filter_document_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_document_ids, 1) FROM params LIMIT 1) = 0
            OR d.id = ANY((SELECT filter_document_ids FROM params LIMIT 1)::uuid[])
        )
),
document_data_base AS (
    SELECT 
        d.id,
        d.name,
        d.description,
        d.file_path,
        d.mime_type
    FROM valid_documents_filtered d
    UNION
    SELECT DISTINCT
        d2.id,
        d2.name,
        ''::text as description,
        u2.file_path,
        u2.mime_type
    FROM scenario_documents_agg sda
    CROSS JOIN LATERAL unnest(sda.document_ids) as doc_id
    JOIN documents d2 ON d2.id = doc_id::uuid
    LEFT JOIN document_uploads du2 ON du2.document_id = d2.id AND du2.active = true
    LEFT JOIN uploads u2 ON u2.id = du2.upload_id
    WHERE d2.active = true
    UNION
    SELECT DISTINCT
        d3.id,
        d3.name,
        ''::text as description,
        u3.file_path,
        u3.mime_type
    FROM documents d3
    LEFT JOIN document_uploads du3 ON du3.document_id = d3.id AND du3.active = true
    LEFT JOIN uploads u3 ON u3.id = du3.upload_id
    WHERE d3.active = true
    AND (SELECT document_ids FROM params LIMIT 1) IS NOT NULL
    AND array_length((SELECT document_ids FROM params LIMIT 1), 1) > 0
    AND d3.id = ANY((SELECT document_ids FROM params LIMIT 1)::uuid[])
    AND (
        CASE 
            WHEN (SELECT use_video FROM params) = true THEN
                EXISTS (
                    SELECT 1 
                    FROM document_fields df
                    JOIN parameter_fields pfield ON pfield.field_id = df.field_id
                    JOIN parameters param ON param.id = pfield.parameter_id
                    WHERE df.document_id = d3.id
                    AND df.active = true
                    AND pfield.active = true
                    AND param.active = true
                    AND param.video_parameter = true
                )
                OR EXISTS (
                    SELECT 1 
                    FROM document_fields df
                    JOIN field_conditional_parameters fcp ON fcp.field_id = df.field_id
                    JOIN parameters cp ON cp.id = fcp.conditional_parameter_id
                    WHERE df.document_id = d3.id
                    AND df.active = true
                    AND fcp.active = true
                    AND cp.video_parameter = true
                )
            ELSE
                EXISTS (
                    SELECT 1 
                    FROM document_fields df
                    JOIN parameter_fields pfield ON pfield.field_id = df.field_id
                    JOIN parameters param ON param.id = pfield.parameter_id
                    WHERE df.document_id = d3.id
                    AND df.active = true
                    AND pfield.active = true
                    AND param.active = true
                    AND param.scenario_parameter = true
                )
                OR EXISTS (
                    SELECT 1 
                    FROM document_fields df
                    JOIN field_conditional_parameters fcp ON fcp.field_id = df.field_id
                    JOIN parameters cp ON cp.id = fcp.conditional_parameter_id
                    WHERE df.document_id = d3.id
                    AND df.active = true
                    AND fcp.active = true
                    AND cp.scenario_parameter = true
                )
                OR EXISTS (
                    SELECT 1 
                    FROM document_fields df
                    JOIN parameter_fields pfield ON pfield.field_id = df.field_id
                    JOIN parameters param ON param.id = pfield.parameter_id
                    WHERE df.document_id = d3.id
                    AND df.active = true
                    AND pfield.active = true
                    AND param.active = true
                    AND param.video_parameter = false
                    AND param.scenario_parameter = false
                )
        END
    )
),
document_data AS (
    SELECT DISTINCT
        ddb.id,
        ddb.name,
        ddb.description,
        ddb.file_path,
        ddb.mime_type
    FROM document_data_base ddb
    WHERE
        -- Filter by selected departments
        (
            (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM document_departments dd_filter
                WHERE dd_filter.document_id = ddb.id
                AND dd_filter.active = true
                AND dd_filter.department_id = ANY((SELECT filter_department_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Filter by selected parameters
        AND (
            (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM document_fields df_filter
                JOIN parameter_fields pfield_filter ON pfield_filter.field_id = df_filter.field_id
                WHERE df_filter.document_id = ddb.id
                AND df_filter.active = true
                AND pfield_filter.active = true
                AND pfield_filter.parameter_id = ANY((SELECT filter_parameter_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Filter by selected fields
        AND (
            (SELECT array_length(filter_field_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_field_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM document_fields df_field_filter
                WHERE df_field_filter.document_id = ddb.id
                AND df_field_filter.active = true
                AND df_field_filter.field_id = ANY((SELECT filter_field_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Search filter
        AND (
            (SELECT document_search FROM params LIMIT 1) IS NULL
            OR LOWER(ddb.name) LIKE '%' || LOWER((SELECT document_search FROM params LIMIT 1)) || '%'
            OR LOWER(COALESCE(ddb.description, '')) LIKE '%' || LOWER((SELECT document_search FROM params LIMIT 1)) || '%'
        )
        -- Show selected filter
        AND (
            (SELECT document_show_selected FROM params LIMIT 1) = false
            OR (SELECT array_length(filter_document_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_document_ids, 1) FROM params LIMIT 1) = 0
            OR ddb.id = ANY((SELECT filter_document_ids FROM params LIMIT 1)::uuid[])
        )
),
document_parameter_relationships AS (
    SELECT DISTINCT
        d.id as document_id,
        param.id as parameter_id
    FROM document_data d
    CROSS JOIN parameters param
    WHERE param.active = true
    AND param.document_parameter = true
    AND (
        EXISTS (
            SELECT 1 FROM document_fields df
            JOIN parameter_fields pfield ON pfield.field_id = df.field_id
            WHERE df.document_id = d.id
            AND pfield.parameter_id = param.id
            AND df.active = true
            AND pfield.active = true
        )
    )
),
document_fields_agg AS (
    SELECT 
        df.document_id,
        ARRAY_AGG(df.field_id ORDER BY df.field_id) as field_ids
    FROM document_fields df
    WHERE df.document_id IN (SELECT id FROM document_data) AND df.active = true
    GROUP BY df.document_id
),
document_parameter_ids_agg AS (
    SELECT 
        dpr.document_id,
        ARRAY_AGG(dpr.parameter_id ORDER BY dpr.parameter_id) as parameter_ids
    FROM document_parameter_relationships dpr
    GROUP BY dpr.document_id
),
document_parent_ids AS (
    SELECT DISTINCT ON (dt.child_id)
        dt.child_id as document_id,
        dt.parent_id
    FROM document_tree dt
    WHERE dt.child_id IN (SELECT id FROM document_data) AND dt.active = true
),
valid_documents_array AS (
    SELECT 
        d.id as document_id,
        d.name,
        d.description,
        d.file_path,
        d.mime_type,
        COALESCE(dpia.parameter_ids, ARRAY[]::uuid[]) as parameter_ids,
        COALESCE(dfa.field_ids, ARRAY[]::uuid[]) as field_ids,
        dpi.parent_id as parent_document_id
    FROM document_data d
    LEFT JOIN document_parameter_ids_agg dpia ON dpia.document_id = d.id
    LEFT JOIN document_fields_agg dfa ON dfa.document_id = d.id
    LEFT JOIN document_parent_ids dpi ON dpi.document_id = d.id
),
scenario_documents_array AS (
    SELECT 
        d.id as document_id,
        d.name,
        ''::text as description,
        u.file_path,
        u.mime_type,
        ARRAY[]::uuid[] as parameter_ids,
        ARRAY[]::uuid[] as field_ids,
        NULL::uuid as parent_document_id
    FROM scenario_documents sd
    JOIN documents d ON d.id = sd.document_id
    LEFT JOIN document_uploads du ON du.document_id = d.id AND du.active = true
    LEFT JOIN uploads u ON u.id = du.upload_id
    WHERE sd.scenario_id = (SELECT scenario_id FROM params LIMIT 1) AND sd.active = true AND d.active = true
),
all_documents_array AS (
    SELECT * FROM valid_documents_array
    UNION
    SELECT * FROM scenario_documents_array
),
document_details_array AS (
    SELECT 
        dd.id as document_id,
        d.name,
        d.updated_at,
        CASE WHEN dd.file_path IS NOT NULL THEN SUBSTRING(dd.file_path FROM '\\.([^\\.]+)$') ELSE NULL END as extension,
        COALESCE((
            SELECT ARRAY_AGG(sd2.scenario_id ORDER BY sd2.scenario_id)
            FROM scenario_documents sd2
            WHERE sd2.document_id = dd.id AND sd2.active = true
        ), ARRAY[]::uuid[]) as scenario_ids,
        true as can_edit,
        true as can_delete,
        d.active,
        COALESCE((
            SELECT ARRAY_AGG(dd2.department_id ORDER BY dd2.department_id)
            FROM document_departments dd2
            WHERE dd2.document_id = dd.id AND dd2.active = true
        ), NULL::uuid[]) as department_ids,
        dd.file_path,
        dd.mime_type,
        (SELECT du.upload_id FROM document_uploads du WHERE du.document_id = dd.id AND du.active = true ORDER BY du.created_at DESC LIMIT 1) as upload_id,
        COALESCE((
            SELECT ARRAY_AGG(df.field_id ORDER BY df.field_id)
            FROM document_fields df
            WHERE df.document_id = dd.id AND df.active = true
        ), ARRAY[]::uuid[]) as field_ids,
        CASE 
            WHEN d.template = true THEN true
            WHEN EXISTS(
                SELECT 1 FROM document_templates dt2 
                WHERE dt2.document_id = dd.id AND dt2.active = true
            ) THEN true
            ELSE false
        END as is_template,
        (SELECT dt.parent_id FROM document_tree dt WHERE dt.child_id = dd.id AND dt.active = true LIMIT 1) as parent_document_id
    FROM document_data dd
    JOIN documents d ON d.id = dd.id
),
simulation_data AS (
    SELECT 
        s.id as simulation_id,
        s.title as name,
        COALESCE(s.description, '') as description,
        COALESCE(
            (SELECT SUM(stl.time_limit_seconds)
             FROM scenario_time_limits stl
             JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
             WHERE stl.simulation_id = s.id AND stl.active = true AND ss.active = true),
            0
        ) as time_limit,
        COALESCE((
            SELECT ARRAY_AGG(sd.department_id ORDER BY sd.created_at)
            FROM simulation_departments sd
            WHERE sd.simulation_id = s.id AND sd.active = true
        ), NULL::uuid[]) as department_ids
    FROM simulations s
    WHERE s.id = ANY(
        COALESCE((SELECT ARRAY_AGG(sim_id::uuid) FROM (SELECT unnest(simulation_ids) as sim_id FROM scenario_simulations_agg) t), ARRAY[]::uuid[])
    )
),
linked_scenario_parameters AS (
    SELECT DISTINCT
        p.id,
        p.name,
        COALESCE(p.description, '') as description,
        p.document_parameter,
        p.persona_parameter,
        p.scenario_parameter,
        p.video_parameter
    FROM scenario_parameters sp
    JOIN parameters p ON p.id = sp.parameter_id
    WHERE sp.scenario_id = (SELECT scenario_id FROM params)
    AND sp.active = true
    AND p.active = true
),
parameter_data_for_mapping AS (
    SELECT DISTINCT 
        p.id,
        p.name,
        COALESCE(p.description, '') as description,
        p.document_parameter,
        p.persona_parameter,
        p.scenario_parameter,
        p.video_parameter
    FROM parameters p
    JOIN parameter_fields fp ON fp.parameter_id = p.id AND fp.active = true
    LEFT JOIN field_departments fd ON fd.field_id = fp.field_id AND fd.active = true
    CROSS JOIN user_departments ud
    WHERE p.active = true
    AND p.scenario_parameter = true
    GROUP BY p.id, p.name, p.description, p.document_parameter, p.persona_parameter, p.scenario_parameter, p.video_parameter
    HAVING 
        COUNT(fd.field_id) FILTER (WHERE fd.department_id = ANY(ud.dept_ids)) > 0
        OR NOT EXISTS (SELECT 1 FROM field_departments fd2 
                      JOIN parameter_fields fp2 ON fp2.field_id = fd2.field_id 
                      WHERE fp2.parameter_id = p.id AND fp2.active = true)
        -- Filter by selected departments
        AND (
            (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM parameter_fields pf_dept_filter
                JOIN field_departments fd_dept_filter ON fd_dept_filter.field_id = pf_dept_filter.field_id
                WHERE pf_dept_filter.parameter_id = p.id
                AND pf_dept_filter.active = true
                AND fd_dept_filter.active = true
                AND fd_dept_filter.department_id = ANY((SELECT filter_department_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Search filter
        AND (
            (SELECT parameter_search FROM params LIMIT 1) IS NULL
            OR LOWER(p.name) LIKE '%' || LOWER((SELECT parameter_search FROM params LIMIT 1)) || '%'
            OR LOWER(COALESCE(p.description, '')) LIKE '%' || LOWER((SELECT parameter_search FROM params LIMIT 1)) || '%'
        )
        -- Show selected filter
        AND (
            (SELECT parameter_show_selected FROM params LIMIT 1) = false
            OR (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) = 0
            OR p.id = ANY((SELECT filter_parameter_ids FROM params LIMIT 1)::uuid[])
        )
    ORDER BY p.name
),
all_parameters_array_base AS (
    SELECT * FROM linked_scenario_parameters
    UNION
    SELECT * FROM parameter_data_for_mapping
),
all_parameters_array AS (
    SELECT DISTINCT
        apab.id,
        apab.name,
        apab.description,
        apab.document_parameter,
        apab.persona_parameter,
        apab.scenario_parameter,
        apab.video_parameter
    FROM all_parameters_array_base apab
    WHERE
        -- Filter by selected departments
        (
            (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM parameter_fields pf_dept_filter
                JOIN field_departments fd_dept_filter ON fd_dept_filter.field_id = pf_dept_filter.field_id
                WHERE pf_dept_filter.parameter_id = apab.id
                AND pf_dept_filter.active = true
                AND fd_dept_filter.active = true
                AND fd_dept_filter.department_id = ANY((SELECT filter_department_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Search filter
        AND (
            (SELECT parameter_search FROM params LIMIT 1) IS NULL
            OR LOWER(apab.name) LIKE '%' || LOWER((SELECT parameter_search FROM params LIMIT 1)) || '%'
            OR LOWER(COALESCE(apab.description, '')) LIKE '%' || LOWER((SELECT parameter_search FROM params LIMIT 1)) || '%'
        )
        -- Show selected filter
        AND (
            (SELECT parameter_show_selected FROM params LIMIT 1) = false
            OR (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) = 0
            OR apab.id = ANY((SELECT filter_parameter_ids FROM params LIMIT 1)::uuid[])
        )
),
field_conditional_parameters_data AS (
    SELECT 
        fcp.field_id,
        ARRAY_AGG(fcp.conditional_parameter_id ORDER BY fcp.conditional_parameter_id) as conditional_parameter_ids
    FROM field_conditional_parameters fcp
    WHERE fcp.active = true
    GROUP BY fcp.field_id
),
parameter_item_data AS (
    SELECT 
        f.id,
        f.name,
        COALESCE(f.description, '') as description,
        pf.parameter_id,
        p.name as parameter_name
    FROM fields f
    JOIN parameter_fields pf ON pf.field_id = f.id AND pf.active = true
    JOIN parameters p ON p.id = pf.parameter_id
    LEFT JOIN field_departments fd ON fd.field_id = f.id AND fd.active = true
    CROSS JOIN user_departments ud
    WHERE p.active = true AND f.active = true
    GROUP BY f.id, f.name, f.description, pf.parameter_id, p.id, p.name
    HAVING 
        COUNT(fd.field_id) FILTER (WHERE fd.department_id = ANY(ud.dept_ids)) > 0
        OR NOT EXISTS (SELECT 1 FROM field_departments fd2 WHERE fd2.field_id = f.id AND fd2.active = true)
        -- Filter by selected departments
        AND (
            (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM field_departments fd_dept_filter
                WHERE fd_dept_filter.field_id = f.id
                AND fd_dept_filter.active = true
                AND fd_dept_filter.department_id = ANY((SELECT filter_department_ids FROM params LIMIT 1)::uuid[])
            )
            OR NOT EXISTS (SELECT 1 FROM field_departments fd_no_dept WHERE fd_no_dept.field_id = f.id AND fd_no_dept.active = true)
        )
        -- Filter by selected parameters (field must belong to selected parameter)
        AND (
            (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) = 0
            OR pf.parameter_id = ANY((SELECT filter_parameter_ids FROM params LIMIT 1)::uuid[])
        )
        -- Filter by selected fields
        AND (
            (SELECT array_length(filter_field_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_field_ids, 1) FROM params LIMIT 1) = 0
            OR f.id = ANY((SELECT filter_field_ids FROM params LIMIT 1)::uuid[])
        )
        -- Filter by selected personas (field must be linked to selected personas)
        AND (
            (SELECT array_length(filter_persona_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_persona_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM persona_fields pf_persona_filter
                WHERE pf_persona_filter.field_id = f.id
                AND pf_persona_filter.active = true
                AND pf_persona_filter.persona_id = ANY((SELECT filter_persona_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Filter by selected documents (field must be linked to selected documents)
        AND (
            (SELECT array_length(filter_document_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_document_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM document_fields df_doc_filter
                WHERE df_doc_filter.field_id = f.id
                AND df_doc_filter.active = true
                AND df_doc_filter.document_id = ANY((SELECT filter_document_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Per-parameter show_selected filter
        AND (
            array_length((SELECT field_show_selected_by_param FROM params LIMIT 1), 1) IS NULL
            OR NOT EXISTS (
                SELECT 1 FROM UNNEST((SELECT field_show_selected_by_param FROM params LIMIT 1)) as fp_filter
                WHERE fp_filter.parameter_id = pf.parameter_id AND fp_filter.show_selected = true
            )
            OR f.id = ANY((SELECT filter_field_ids FROM params LIMIT 1)::uuid[])
        )
    ORDER BY p.name, f.name
),
scenario_fields_data AS (
    SELECT 
        f.id,
        f.name,
        COALESCE(f.description, '') as description,
        fp.parameter_id,
        p.name as parameter_name
    FROM scenario_fields sf
    JOIN fields f ON f.id = sf.field_id
    JOIN parameter_fields fp ON fp.field_id = f.id AND fp.active = true
    JOIN parameters p ON p.id = fp.parameter_id
    WHERE sf.scenario_id = (SELECT scenario_id FROM params) AND sf.active = true AND p.active = true
),
all_fields_array_base AS (
    SELECT 
        pi.id as field_id,
        pi.name,
        pi.description,
        pi.parameter_id,
        pi.parameter_name,
        COALESCE(fcpd.conditional_parameter_ids, ARRAY[]::uuid[]) as conditional_parameter_ids
    FROM parameter_item_data pi
    LEFT JOIN field_conditional_parameters_data fcpd ON fcpd.field_id = pi.id
    UNION
    SELECT 
        sf.id as field_id,
        sf.name,
        sf.description,
        sf.parameter_id,
        sf.parameter_name,
        ARRAY[]::uuid[] as conditional_parameter_ids
    FROM scenario_fields_data sf
    WHERE NOT EXISTS (
        SELECT 1 FROM parameter_item_data pi2 WHERE pi2.id = sf.id
    )
),
all_fields_array AS (
    SELECT DISTINCT
        afab.field_id,
        afab.name,
        afab.description,
        afab.parameter_id,
        afab.parameter_name,
        afab.conditional_parameter_ids
    FROM all_fields_array_base afab
    WHERE
        -- Filter by selected departments
        (
            (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM field_departments fd_dept_filter
                WHERE fd_dept_filter.field_id = afab.field_id
                AND fd_dept_filter.active = true
                AND fd_dept_filter.department_id = ANY((SELECT filter_department_ids FROM params LIMIT 1)::uuid[])
            )
            OR NOT EXISTS (SELECT 1 FROM field_departments fd_no_dept WHERE fd_no_dept.field_id = afab.field_id AND fd_no_dept.active = true)
        )
        -- Filter by selected parameters
        AND (
            (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) = 0
            OR afab.parameter_id = ANY((SELECT filter_parameter_ids FROM params LIMIT 1)::uuid[])
        )
        -- Filter by selected fields
        AND (
            (SELECT array_length(filter_field_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_field_ids, 1) FROM params LIMIT 1) = 0
            OR afab.field_id = ANY((SELECT filter_field_ids FROM params LIMIT 1)::uuid[])
        )
        -- Filter by selected personas
        AND (
            (SELECT array_length(filter_persona_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_persona_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM persona_fields pf_persona_filter
                WHERE pf_persona_filter.field_id = afab.field_id
                AND pf_persona_filter.active = true
                AND pf_persona_filter.persona_id = ANY((SELECT filter_persona_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Filter by selected documents
        AND (
            (SELECT array_length(filter_document_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_document_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM document_fields df_doc_filter
                WHERE df_doc_filter.field_id = afab.field_id
                AND df_doc_filter.active = true
                AND df_doc_filter.document_id = ANY((SELECT filter_document_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Per-parameter show_selected filter
        AND (
            array_length((SELECT field_show_selected_by_param FROM params LIMIT 1), 1) IS NULL
            OR NOT EXISTS (
                SELECT 1 FROM UNNEST((SELECT field_show_selected_by_param FROM params LIMIT 1)) as fp_filter
                WHERE fp_filter.parameter_id = afab.parameter_id AND fp_filter.show_selected = true
            )
            OR afab.field_id = ANY((SELECT filter_field_ids FROM params LIMIT 1)::uuid[])
        )
),
department_persona_ids AS (
    SELECT 
        d.id as department_id,
        COALESCE(ARRAY_AGG(p.id ORDER BY p.id) FILTER (WHERE p.id IS NOT NULL), ARRAY[]::uuid[]) as persona_ids
    FROM departments d
    CROSS JOIN user_departments ud
    LEFT JOIN personas p ON p.active = true
    LEFT JOIN persona_departments pd ON pd.persona_id = p.id AND pd.active = true
    WHERE d.id = ANY(ud.dept_ids)
    AND (
        pd.department_id = d.id 
        OR NOT EXISTS (SELECT 1 FROM persona_departments pd2 WHERE pd2.persona_id = p.id AND pd2.active = true)
    )
    AND (
        pd.department_id = ANY(ud.dept_ids)
        OR NOT EXISTS (SELECT 1 FROM persona_departments pd3 WHERE pd3.persona_id = p.id AND pd3.active = true)
    )
    GROUP BY d.id
),
department_document_ids AS (
    SELECT 
        d.id as department_id,
        COALESCE(ARRAY_AGG(doc.id ORDER BY doc.id) FILTER (WHERE doc.id IS NOT NULL), ARRAY[]::uuid[]) as document_ids
    FROM departments d
    CROSS JOIN user_departments ud
    LEFT JOIN documents doc ON doc.active = true
    LEFT JOIN document_departments dd ON dd.document_id = doc.id AND dd.active = true
    WHERE d.id = ANY(ud.dept_ids)
    AND (dd.department_id = d.id OR NOT EXISTS (SELECT 1 FROM document_departments dd2 WHERE dd2.document_id = doc.id AND dd2.active = true))
    GROUP BY d.id
),
department_parameter_ids AS (
    SELECT 
        d.id as department_id,
        COALESCE(ARRAY_AGG(DISTINCT p.id) FILTER (WHERE p.id IS NOT NULL), ARRAY[]::uuid[]) as parameter_ids
    FROM departments d
    CROSS JOIN user_departments ud
    LEFT JOIN parameters p ON p.active = true
    LEFT JOIN parameter_fields fp ON fp.parameter_id = p.id AND fp.active = true
    LEFT JOIN field_departments fd ON fd.field_id = fp.field_id AND fd.active = true
    WHERE d.id = ANY(ud.dept_ids)
    AND (fd.department_id = d.id OR NOT EXISTS (SELECT 1 FROM field_departments fd2 
                                                 JOIN parameter_fields fp2 ON fp2.field_id = fd2.field_id 
                                                 WHERE fp2.parameter_id = p.id AND fp2.active = true AND fd2.active = true))
    GROUP BY d.id
),
department_field_ids AS (
    SELECT 
        d.id as department_id,
        COALESCE(ARRAY_AGG(f.id ORDER BY f.id) FILTER (WHERE f.id IS NOT NULL), ARRAY[]::uuid[]) as field_ids
    FROM departments d
    CROSS JOIN user_departments ud
    LEFT JOIN fields f ON true
    LEFT JOIN parameter_fields fp ON fp.field_id = f.id AND fp.active = true
    LEFT JOIN parameters p ON p.id = fp.parameter_id AND p.active = true
    LEFT JOIN field_departments fd ON fd.field_id = f.id AND fd.active = true
    WHERE d.id = ANY(ud.dept_ids)
    AND p.id IS NOT NULL
    AND (
        fd.department_id = d.id 
        OR NOT EXISTS (SELECT 1 FROM field_departments fd2 WHERE fd2.field_id = f.id AND fd2.active = true)
    )
    AND (
        fd.department_id = ANY(ud.dept_ids)
        OR NOT EXISTS (SELECT 1 FROM field_departments fd3 WHERE fd3.field_id = f.id AND fd3.active = true)
    )
    GROUP BY d.id
),
scenario_departments_array AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description,
        ARRAY[]::uuid[] as persona_ids,
        ARRAY[]::uuid[] as document_ids,
        ARRAY[]::uuid[] as parameter_ids,
        ARRAY[]::uuid[] as field_ids
    FROM scenario_departments sd
    JOIN departments d ON d.id = sd.department_id
    WHERE sd.scenario_id = (SELECT scenario_id FROM params LIMIT 1) AND sd.active = true AND d.active = true
),
all_departments_array AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description,
        COALESCE(dpi.persona_ids, ARRAY[]::uuid[]) as persona_ids,
        COALESCE(ddi.document_ids, ARRAY[]::uuid[]) as document_ids,
        COALESCE(dparami.parameter_ids, ARRAY[]::uuid[]) as parameter_ids,
        COALESCE(dfi.field_ids, ARRAY[]::uuid[]) as field_ids
    FROM departments d
    CROSS JOIN user_departments ud
    LEFT JOIN department_persona_ids dpi ON dpi.department_id = d.id
    LEFT JOIN department_document_ids ddi ON ddi.department_id = d.id
    LEFT JOIN department_parameter_ids dparami ON dparami.department_id = d.id
    LEFT JOIN department_field_ids dfi ON dfi.department_id = d.id
    WHERE d.id = ANY(ud.dept_ids)
    UNION
    SELECT * FROM scenario_departments_array
),
accessible_scenarios AS (
    SELECT DISTINCT s.id as scenario_id
    FROM scenarios s
    LEFT JOIN scenario_departments sd ON sd.scenario_id = s.id AND sd.active = true
    CROSS JOIN user_departments ud
    WHERE s.active = true
    AND (
        sd.department_id = ANY(ud.dept_ids)
        OR NOT EXISTS (SELECT 1 FROM scenario_departments sd2 WHERE sd2.scenario_id = s.id AND sd2.active = true)
    )
),
objectives_with_departments_array AS (
    SELECT
        o.objective,
        COALESCE(
            (
                SELECT ARRAY_AGG(DISTINCT dept_id ORDER BY dept_id)
                FROM (
                    SELECT DISTINCT sd.department_id as dept_id
                    FROM scenario_objectives so2
                    JOIN objectives o2 ON o2.id = so2.objective_id
                    JOIN accessible_scenarios acs2 ON acs2.scenario_id = so2.scenario_id
                    LEFT JOIN scenario_departments sd ON sd.scenario_id = so2.scenario_id AND sd.active = true
                    WHERE o2.objective = o.objective
                        AND o2.objective IS NOT NULL 
                        AND o2.objective != ''
                        AND sd.department_id IS NOT NULL
                ) dept_list
            ),
            ARRAY[]::uuid[]
        ) as department_ids
    FROM scenario_objectives so
    JOIN objectives o ON o.id = so.objective_id
    JOIN accessible_scenarios acs ON acs.scenario_id = so.scenario_id
    WHERE o.objective IS NOT NULL AND o.objective != ''
    GROUP BY o.objective
),
user_departments_for_agents AS (
    SELECT department_id
    FROM resolve_profile_id rpi
    JOIN profile_departments pd ON pd.profile_id = rpi.resolved_profile_id
    WHERE pd.active = true
),
expected_agent_role AS (
    SELECT 'scenario'::agent_role as role
),
scenario_persona_ranges_data AS (
    SELECT 
        COALESCE(spr.min_count, 1) as persona_min,
        COALESCE(spr.max_count, 3) as persona_max
    FROM scenario_core sc
    LEFT JOIN scenario_persona_ranges spr ON spr.scenario_id = sc.id
),
scenario_document_ranges_data AS (
    SELECT 
        COALESCE(sdr.min_count, 0) as document_min,
        COALESCE(sdr.max_count, 3) as document_max
    FROM scenario_core sc
    LEFT JOIN scenario_document_ranges sdr ON sdr.scenario_id = sc.id
),
scenario_parameter_ranges_data AS (
    SELECT 
        COALESCE(spr.min_count, 0) as parameter_min,
        COALESCE(spr.max_count, 3) as parameter_max
    FROM scenario_core sc
    LEFT JOIN scenario_parameter_ranges spr ON spr.scenario_id = sc.id
),
scenario_field_ranges_data AS (
    SELECT 
        sc.id as scenario_id,
        COALESCE(
            ARRAY_AGG((sfr.parameter_id, sfr.min_count, sfr.max_count)::types.q_get_scenario_detail_v4_field_range ORDER BY sfr.parameter_id),
            ARRAY[]::types.q_get_scenario_detail_v4_field_range[]
        ) as field_ranges
    FROM scenario_core sc
    LEFT JOIN scenario_field_ranges sfr ON sfr.scenario_id = sc.id
    GROUP BY sc.id
),
valid_agents_array AS (
    SELECT 
        a.id as agent_id,
        a.name,
        COALESCE(a.description, '') as description,
        ARRAY[a.role::text] as roles
    FROM agents a
    LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
    CROSS JOIN expected_agent_role ear
    WHERE a.active = true 
    AND (
        a.role = ear.role
        OR a.role = 'scenario'::agent_role
        OR a.role = 'image'
    )
    GROUP BY a.id, a.name, a.description, a.role, ear.role
    HAVING 
        COUNT(ad.agent_id) FILTER (WHERE ad.department_id IN (SELECT department_id FROM user_departments_for_agents)) > 0
        OR NOT EXISTS (SELECT 1 FROM agent_departments ad2 WHERE ad2.agent_id = a.id AND ad2.active = true)
)
SELECT 
    (SELECT scenario_exists FROM scenario_exists_check) as scenario_exists,
    sc.id as scenario_id,
    -- Merge draft payload over existing scenario data if draft_id provided
    COALESCE(
        (SELECT payload->>'name' FROM draft_payload_data),
        sc.name
    ) as name,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        sc.description
    ) as description,
    COALESCE(
        (SELECT payload->>'problem_statement' FROM draft_payload_data),
        sc.problem_statement
    ) as problem_statement,
    sc.problem_statement_id,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        sc.active
    ) as active,
    sc.generated,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'department_ids' IS NOT NULL AND jsonb_typeof(payload->'department_ids') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'department_ids'))
                ELSE NULL
            END
        FROM draft_payload_data),
        sc.department_ids
    ) as department_ids,
    sc.parent_scenario_id,
    COALESCE(ssa_attr.hints_enabled, false) as hints_enabled,
    COALESCE(
        (SELECT (payload->>'use_objectives')::boolean FROM draft_payload_data),
        sc.objectives_enabled
    ) as objectives_enabled,
    COALESCE(
        (SELECT (payload->>'use_image')::boolean FROM draft_payload_data),
        sc.images_enabled
    ) as image_input_enabled,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'persona_ids' IS NOT NULL AND jsonb_typeof(payload->'persona_ids') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'persona_ids'))
                ELSE NULL
            END
        FROM draft_payload_data),
        COALESCE(spa.persona_ids, ARRAY[]::text[])
    ) as persona_ids,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'document_ids' IS NOT NULL AND jsonb_typeof(payload->'document_ids') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'document_ids'))
                ELSE NULL
            END
        FROM draft_payload_data),
        COALESCE(sd.document_ids, ARRAY[]::text[])
    ) as document_ids,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'objective_ids' IS NOT NULL AND jsonb_typeof(payload->'objective_ids') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'objective_ids'))
                ELSE NULL
            END
        FROM draft_payload_data),
        COALESCE((
            SELECT ARRAY_AGG(objective_id::text ORDER BY sort_order, idx, created_at DESC)
            FROM scenario_objectives_array
        ), ARRAY[]::text[])
    ) as objective_ids,
    COALESCE(ssa.simulation_ids, ARRAY[]::text[]) as simulation_ids,
    COALESCE((
        SELECT ARRAY_AGG(persona_id::text ORDER BY name)
        FROM valid_personas_array
    ), ARRAY[]::text[]) as valid_persona_ids,
    COALESCE((
        SELECT ARRAY_AGG(document_id::text ORDER BY name)
        FROM all_documents_array
    ), ARRAY[]::text[]) as valid_document_ids,
    (SELECT dept_ids FROM user_departments) as valid_department_ids,
    COALESCE(ssa.active_usage_count, 0) as active_usage_count,
    up.role as user_role,
    up.actor_name,
    COALESCE((
        SELECT ARRAY_AGG(id::text ORDER BY name)
        FROM all_parameters_array
    ), ARRAY[]::text[]) as parameter_ids,
    COALESCE((
        SELECT ARRAY_AGG(id::text ORDER BY name)
        FROM all_parameters_array
    ), ARRAY[]::text[]) as valid_parameter_ids,
    COALESCE((
        SELECT ARRAY_AGG(field_id::text ORDER BY parameter_name, name)
        FROM all_fields_array
    ), ARRAY[]::text[]) as valid_field_ids,
    COALESCE((
        SELECT ARRAY_AGG(id::text ORDER BY sort_order, created_at DESC)
        FROM scenario_questions_array
    ), ARRAY[]::text[]) as question_ids,
    COALESCE((SELECT persona_min FROM scenario_persona_ranges_data), 1) as persona_range_min,
    COALESCE((SELECT persona_max FROM scenario_persona_ranges_data), 3) as persona_range_max,
    COALESCE((SELECT document_min FROM scenario_document_ranges_data), 0) as document_range_min,
    COALESCE((SELECT document_max FROM scenario_document_ranges_data), 3) as document_range_max,
    COALESCE((SELECT parameter_min FROM scenario_parameter_ranges_data), 0) as parameter_range_min,
    COALESCE((SELECT parameter_max FROM scenario_parameter_ranges_data), 3) as parameter_range_max,
    sc.video_enabled,
    sc.questions_enabled,
    sc.problem_statement_enabled,
    sc.scenario_agent_id,
    sc.image_agent_id,
    sc.video_agent_id,
    COALESCE((
        SELECT ARRAY_AGG(agent_id::text ORDER BY name)
        FROM valid_agents_array
    ), ARRAY[]::text[]) as valid_agent_ids,
    -- Computed permissions
    CASE 
        WHEN COALESCE(ssa.active_usage_count, 0) > 0 THEN false
        WHEN sc.generated = true THEN false
        WHEN (COALESCE(sc.department_ids, ARRAY[]::text[]) = ARRAY[]::text[] AND up.role != 'superadmin') THEN false
        ELSE true
    END as can_edit,
    true as can_duplicate,
    CASE 
        WHEN COALESCE(ssa.active_usage_count, 0) > 0 THEN false
        WHEN sc.generated = true THEN false
        WHEN (COALESCE(sc.department_ids, ARRAY[]::text[]) = ARRAY[]::text[] AND up.role != 'superadmin') THEN false
        WHEN up.role != 'superadmin' THEN false
        ELSE true
    END as can_delete,
    COALESCE(sfrd.field_ranges, ARRAY[]::types.q_get_scenario_detail_v4_field_range[]) as field_ranges,
    -- Arrays of composite types (built from subqueries)
    COALESCE((
        SELECT ARRAY_AGG(ROW(vpa.persona_id, vpa.name, vpa.description, vpa.color, vpa.icon, vpa.image_model, vpa.parameter_ids, vpa.field_ids, vpa.example)::types.q_get_scenario_detail_v4_persona ORDER BY vpa.name)
        FROM valid_personas_array vpa
    ), '{}'::types.q_get_scenario_detail_v4_persona[]) as personas,
    COALESCE((
        SELECT ARRAY_AGG((ada.document_id, ada.name, ada.description, ada.file_path, ada.mime_type, ada.parameter_ids, ada.field_ids, ada.parent_document_id)::types.q_get_scenario_detail_v4_document ORDER BY ada.name)
        FROM all_documents_array ada
    ), '{}'::types.q_get_scenario_detail_v4_document[]) as documents,
    COALESCE((
        SELECT ARRAY_AGG(ROW(apa.id, apa.name, apa.description, apa.document_parameter, apa.persona_parameter, apa.scenario_parameter, apa.video_parameter)::types.q_get_scenario_detail_v4_parameter ORDER BY apa.name)
        FROM all_parameters_array apa
    ), '{}'::types.q_get_scenario_detail_v4_parameter[]) as parameters,
    COALESCE((
        SELECT ARRAY_AGG((afa.field_id, afa.name, afa.description, afa.parameter_id, afa.parameter_name, afa.conditional_parameter_ids)::types.q_get_scenario_detail_v4_field ORDER BY afa.parameter_name, afa.name)
        FROM all_fields_array afa
    ), '{}'::types.q_get_scenario_detail_v4_field[]) as fields,
    COALESCE((
        SELECT ARRAY_AGG((ada2.department_id, ada2.name, ada2.description, ada2.persona_ids, ada2.document_ids, ada2.parameter_ids, ada2.field_ids)::types.q_get_scenario_detail_v4_department ORDER BY ada2.name)
        FROM all_departments_array ada2
    ), '{}'::types.q_get_scenario_detail_v4_department[]) as departments,
    COALESCE((
        SELECT ARRAY_AGG((vaa.agent_id, vaa.name, vaa.description, vaa.roles)::types.q_get_scenario_detail_v4_agent ORDER BY vaa.name)
        FROM valid_agents_array vaa
    ), '{}'::types.q_get_scenario_detail_v4_agent[]) as agents,
    COALESCE((
        SELECT ARRAY_AGG((sda.simulation_id, sda.name, sda.description, sda.time_limit, sda.department_ids)::types.q_get_scenario_detail_v4_simulation ORDER BY sda.name)
        FROM simulation_data sda
    ), '{}'::types.q_get_scenario_detail_v4_simulation[]) as simulations,
    COALESCE((
        SELECT ARRAY_AGG((soa.objective_id, soa.name, soa.description)::types.q_get_scenario_detail_v4_objective ORDER BY soa.sort_order, soa.idx, soa.created_at DESC)
        FROM scenario_objectives_array soa
    ), '{}'::types.q_get_scenario_detail_v4_objective[]) as objectives,
    COALESCE((
        SELECT ARRAY_AGG((psa.problem_statement_id, psa.name, psa.problem_statement, psa.created_at, psa.updated_at)::types.q_get_scenario_detail_v4_problem_statement ORDER BY psa.sort_order, psa.problem_statement_id)
        FROM problem_statements_array psa
    ), '{}'::types.q_get_scenario_detail_v4_problem_statement[]) as problem_statements,
    COALESCE((
        SELECT ARRAY_AGG((sia.upload_id, sia.name, sia.file_path, sia.mime_type, sia.active, sia.created_at, sia.updated_at)::types.q_get_scenario_detail_v4_scenario_image ORDER BY sia.sort_order, sia.created_at DESC)
        FROM scenario_images_array sia
    ), '{}'::types.q_get_scenario_detail_v4_scenario_image[]) as scenario_images,
    COALESCE((
        SELECT ARRAY_AGG((sva.id, sva.name, sva.length_seconds, sva.completed, sva.active, sva.image_enabled, sva.file_path, sva.mime_type, sva.upload_id)::types.q_get_scenario_detail_v4_scenario_video ORDER BY sva.sort_order, sva.created_at DESC)
        FROM scenario_videos_array sva
    ), '{}'::types.q_get_scenario_detail_v4_scenario_video[]) as scenario_videos,
    COALESCE((
        SELECT ARRAY_AGG(
            ROW(
                sqa.id,
                sqa.question_text,
                sqa.allow_multiple,
                sqa.active,
                COALESCE((
                    SELECT ARRAY_AGG(ROW(qoa.id, qoa.option_text, qoa.type, qoa.is_correct)::types.q_get_scenario_detail_v4_question_option ORDER BY qoa.id)
                    FROM question_options_array qoa
                    WHERE qoa.question_id = sqa.id
                ), '{}'::types.q_get_scenario_detail_v4_question_option[]),
                COALESCE((
                    SELECT ARRAY_AGG(qta.time ORDER BY qta.time)
                    FROM question_times_array qta
                    WHERE qta.question_id = sqa.id
                ), ARRAY[]::integer[])
            )::types.q_get_scenario_detail_v4_question
            ORDER BY sqa.sort_order, sqa.created_at DESC
        )
        FROM scenario_questions_array sqa
    ), '{}'::types.q_get_scenario_detail_v4_question[]) as questions,
    COALESCE((
        SELECT ARRAY_AGG((owda.objective, owda.department_ids)::types.q_get_scenario_detail_v4_objective_with_departments ORDER BY owda.objective)
        FROM objectives_with_departments_array owda
    ), '{}'::types.q_get_scenario_detail_v4_objective_with_departments[]) as objectives_history,
    COALESCE((
        SELECT ARRAY_AGG((dda.document_id, dda.name, dda.updated_at, dda.extension, dda.scenario_ids, dda.can_edit, dda.can_delete, dda.active, dda.department_ids, dda.file_path, dda.mime_type, dda.upload_id, dda.field_ids, dda.is_template, dda.parent_document_id)::types.q_get_scenario_detail_v4_document_detail ORDER BY dda.name)
        FROM document_details_array dda
    ), '{}'::types.q_get_scenario_detail_v4_document_detail[]) as document_details,
    COALESCE((
        SELECT ARRAY_AGG((apd.param_id, apd.selected_items, apd.valid_items)::types.q_get_scenario_detail_v4_parameter_detail ORDER BY apd.param_id)
        FROM all_parameters_data apd
    ), '{}'::types.q_get_scenario_detail_v4_parameter_detail[]) as parameters_detail,
    COALESCE((SELECT draft_version FROM draft_payload_data), 0) as draft_version,
    -- Extract nested objects from draft payload if available
    COALESCE(
        (SELECT payload->'fieldShowSelected' FROM draft_payload_data),
        (SELECT payload->'field_show_selected' FROM draft_payload_data),
        '{}'::jsonb
    ) as draft_field_show_selected,
    COALESCE(
        (SELECT payload->'fieldRanges' FROM draft_payload_data),
        (SELECT payload->'field_ranges' FROM draft_payload_data),
        '{}'::jsonb
    ) as draft_field_ranges,
    COALESCE(
        (SELECT payload->'randomizeParameterItems' FROM draft_payload_data),
        (SELECT payload->'randomize_parameter_items' FROM draft_payload_data),
        '{}'::jsonb
    ) as draft_randomize_parameter_items
FROM scenario_core sc
CROSS JOIN user_profile up
LEFT JOIN scenario_simulation_attributes ssa_attr ON ssa_attr.scenario_id = sc.id
LEFT JOIN scenario_personas_agg spa ON true
LEFT JOIN scenario_documents_agg sd ON true
LEFT JOIN scenario_simulations_agg ssa ON true
LEFT JOIN scenario_field_ranges_data sfrd ON sfrd.scenario_id = sc.id
$_$;


--
-- Name: api_get_scenario_ids_for_regeneration_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_scenario_ids_for_regeneration_v4(scenario_id uuid) RETURNS TABLE(persona_id uuid, scenario_agent_id text, document_ids json, parameter_item_ids json)
    LANGUAGE sql STABLE
    AS $$
SELECT 
    (SELECT rp.persona_id FROM scenario_personas rp WHERE rp.scenario_id = s.id AND rp.active = true LIMIT 1) as persona_id,
    s.scenario_agent_id::text as scenario_agent_id,
    COALESCE(
        json_agg(DISTINCT sd.document_id::text) FILTER (WHERE sd.document_id IS NOT NULL),
        '[]'::json
    ) as document_ids,
    COALESCE(
        json_agg(DISTINCT sf.field_id::text) FILTER (WHERE sf.field_id IS NOT NULL),
        '[]'::json
    ) as parameter_item_ids
FROM scenarios s
LEFT JOIN scenario_documents sd ON sd.scenario_id = s.id AND sd.active = true
LEFT JOIN scenario_fields sf ON sf.scenario_id = s.id AND sf.active = true
WHERE s.id = api_get_scenario_ids_for_regeneration_v4.scenario_id
GROUP BY s.id, s.scenario_agent_id
$$;


--
-- Name: api_get_scenario_images_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_scenario_images_v4(scenario_id uuid) RETURNS TABLE(image_id uuid, active boolean)
    LANGUAGE sql STABLE
    AS $$
SELECT 
    si.image_id,
    si.active
FROM scenario_images si
WHERE si.scenario_id = scenario_id
  AND si.active = true
$$;


--
-- Name: api_get_scenario_new_v4(uuid, boolean, boolean, uuid[], uuid[], uuid[], uuid[], uuid[], boolean, uuid[], uuid[], uuid[], uuid[], uuid[], text, text, text, boolean, boolean, boolean, types.q_get_scenario_new_v4_field_param_filter[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_scenario_new_v4(profile_id uuid, use_image boolean DEFAULT NULL::boolean, use_objectives boolean DEFAULT NULL::boolean, document_ids uuid[] DEFAULT NULL::uuid[], problem_statement_ids uuid[] DEFAULT NULL::uuid[], template_document_ids uuid[] DEFAULT NULL::uuid[], objective_ids uuid[] DEFAULT NULL::uuid[], image_ids uuid[] DEFAULT NULL::uuid[], use_video boolean DEFAULT NULL::boolean, filter_department_ids uuid[] DEFAULT NULL::uuid[], filter_persona_ids uuid[] DEFAULT NULL::uuid[], filter_document_ids uuid[] DEFAULT NULL::uuid[], filter_parameter_ids uuid[] DEFAULT NULL::uuid[], filter_field_ids uuid[] DEFAULT NULL::uuid[], persona_search text DEFAULT NULL::text, document_search text DEFAULT NULL::text, parameter_search text DEFAULT NULL::text, persona_show_selected boolean DEFAULT NULL::boolean, document_show_selected boolean DEFAULT NULL::boolean, parameter_show_selected boolean DEFAULT NULL::boolean, field_show_selected_by_param types.q_get_scenario_new_v4_field_param_filter[] DEFAULT ARRAY[]::types.q_get_scenario_new_v4_field_param_filter[], draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(actor_name text, user_role text, department_ids text[], valid_persona_ids text[], valid_document_ids text[], valid_parameter_ids text[], valid_field_ids text[], primary_department_id text, scenario_agent_id text, image_agent_id text, video_agent_id text, valid_agent_ids text[], selected_template_document_ids text[], video_enabled boolean, questions_enabled boolean, persona_range_min integer, persona_range_max integer, document_range_min integer, document_range_max integer, parameter_range_min integer, parameter_range_max integer, question_ids text[], departments types.q_get_scenario_new_v4_department[], personas types.q_get_scenario_new_v4_persona[], documents types.q_get_scenario_new_v4_document[], parameters types.q_get_scenario_new_v4_parameter[], fields types.q_get_scenario_new_v4_field[], agents types.q_get_scenario_new_v4_agent[], objectives types.q_get_scenario_new_v4_objective[], problem_statements types.q_get_scenario_new_v4_problem_statement[], scenario_images types.q_get_scenario_new_v4_scenario_image[], scenario_videos types.q_get_scenario_new_v4_scenario_video[], questions types.q_get_scenario_new_v4_question[], objectives_history types.q_get_scenario_new_v4_objective_with_departments[], document_details types.q_get_scenario_new_v4_document_detail[], parameters_detail types.q_get_scenario_new_v4_parameter_detail[], draft_version integer, draft_field_show_selected jsonb, draft_field_ranges jsonb, draft_randomize_parameter_items jsonb)
    LANGUAGE sql STABLE
    AS $_$
WITH params AS (
    SELECT 
        profile_id AS profile_id,
        COALESCE(use_image, false) AS use_image,
        COALESCE(use_objectives, false) AS use_objectives,
        COALESCE(document_ids, ARRAY[]::uuid[]) AS document_ids,
        COALESCE(problem_statement_ids, ARRAY[]::uuid[]) AS problem_statement_ids,
        COALESCE(template_document_ids, ARRAY[]::uuid[]) AS template_document_ids,
        COALESCE(objective_ids, ARRAY[]::uuid[]) AS objective_ids,
        COALESCE(image_ids, ARRAY[]::uuid[]) AS image_ids,
        COALESCE(use_video, false) AS use_video,
        -- Filter parameters
        COALESCE(filter_department_ids, ARRAY[]::uuid[]) AS filter_department_ids,
        COALESCE(filter_persona_ids, ARRAY[]::uuid[]) AS filter_persona_ids,
        COALESCE(filter_document_ids, ARRAY[]::uuid[]) AS filter_document_ids,
        COALESCE(filter_parameter_ids, ARRAY[]::uuid[]) AS filter_parameter_ids,
        COALESCE(filter_field_ids, ARRAY[]::uuid[]) AS filter_field_ids,
        -- Search parameters
        COALESCE(NULLIF(persona_search, ''), NULL) AS persona_search,
        COALESCE(NULLIF(document_search, ''), NULL) AS document_search,
        COALESCE(NULLIF(parameter_search, ''), NULL) AS parameter_search,
        -- Show selected filters
        COALESCE(persona_show_selected, false) AS persona_show_selected,
        COALESCE(document_show_selected, false) AS document_show_selected,
        COALESCE(parameter_show_selected, false) AS parameter_show_selected,
        COALESCE(field_show_selected_by_param, ARRAY[]::types.q_get_scenario_new_v4_field_param_filter[]) AS field_show_selected_by_param,
        draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'scenarios'::draft_resource_type
    LIMIT 1
),
params_single AS (
    SELECT * FROM params LIMIT 1
),
extracted_params AS (
    SELECT 
        ps.document_ids::uuid[] as document_ids,
        ps.problem_statement_ids::uuid[] as problem_statement_ids,
        ps.template_document_ids::uuid[] as template_document_ids,
        ps.objective_ids::uuid[] as objective_ids,
        ps.image_ids::uuid[] as image_ids,
        ps.use_video::boolean as use_video,
        ps.profile_id::uuid as profile_id
    FROM params_single ps
),
user_profile AS (
    SELECT 
        first_name || ' ' || last_name as actor_name,
        role as user_role
    FROM profiles WHERE id = (SELECT profile_id FROM extracted_params)
),
user_departments AS (
    SELECT DISTINCT d.id
    FROM departments d
    JOIN profile_departments pd ON pd.department_id = d.id
    CROSS JOIN params p
    WHERE pd.profile_id = p.profile_id AND pd.active = true AND d.active = true
),
department_persona_ids AS (
    SELECT 
        d.id as department_id,
        COALESCE(ARRAY_AGG(p.id ORDER BY p.id) FILTER (WHERE p.id IS NOT NULL), ARRAY[]::uuid[]) as persona_ids
    FROM departments d
    INNER JOIN user_departments ud ON d.id = ud.id
    LEFT JOIN personas p ON p.active = true
    LEFT JOIN persona_departments pd ON pd.persona_id = p.id AND pd.active = true
    WHERE (
        pd.department_id = d.id 
        OR NOT EXISTS (SELECT 1 FROM persona_departments pd2 WHERE pd2.persona_id = p.id AND pd2.active = true)
    )
    GROUP BY d.id
),
department_document_ids AS (
    SELECT 
        d.id as department_id,
        COALESCE(ARRAY_AGG(doc.id ORDER BY doc.id) FILTER (WHERE doc.id IS NOT NULL), ARRAY[]::uuid[]) as document_ids
    FROM departments d
    INNER JOIN user_departments ud ON d.id = ud.id
    LEFT JOIN documents doc ON doc.active = true
    LEFT JOIN document_departments dd ON dd.document_id = doc.id AND dd.active = true
    WHERE (dd.department_id = d.id OR NOT EXISTS (SELECT 1 FROM document_departments dd2 WHERE dd2.document_id = doc.id AND dd2.active = true))
    GROUP BY d.id
),
department_parameter_ids AS (
    SELECT 
        d.id as department_id,
        COALESCE(ARRAY_AGG(DISTINCT p.id) FILTER (WHERE p.id IS NOT NULL), ARRAY[]::uuid[]) as parameter_ids
    FROM departments d
    INNER JOIN user_departments ud ON d.id = ud.id
    LEFT JOIN parameters p ON p.active = true
    LEFT JOIN parameter_fields pf ON pf.parameter_id = p.id AND pf.active = true
    LEFT JOIN field_departments fd ON fd.field_id = pf.field_id AND fd.active = true
    WHERE (fd.department_id = d.id OR NOT EXISTS (SELECT 1 FROM field_departments fd2 
                                                 JOIN parameter_fields pf2 ON pf2.field_id = fd2.field_id 
                                                 WHERE pf2.parameter_id = p.id AND pf2.active = true AND fd2.active = true))
    GROUP BY d.id
),
department_field_ids AS (
    SELECT 
        d.id as department_id,
        COALESCE(ARRAY_AGG(f.id ORDER BY f.id) FILTER (WHERE f.id IS NOT NULL), ARRAY[]::uuid[]) as field_ids
    FROM departments d
    INNER JOIN user_departments ud ON d.id = ud.id
    LEFT JOIN fields f ON true
    LEFT JOIN field_departments fd ON fd.field_id = f.id AND fd.active = true
    WHERE (
        fd.department_id = d.id 
        OR NOT EXISTS (SELECT 1 FROM field_departments fd2 WHERE fd2.field_id = f.id AND fd2.active = true)
    )
    GROUP BY d.id
),
all_departments_array AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description,
        COALESCE(dpi.persona_ids, ARRAY[]::uuid[]) as persona_ids,
        COALESCE(ddi.document_ids, ARRAY[]::uuid[]) as document_ids,
        COALESCE(dparami.parameter_ids, ARRAY[]::uuid[]) as parameter_ids,
        COALESCE(dfi.field_ids, ARRAY[]::uuid[]) as field_ids
    FROM departments d
    INNER JOIN user_departments ud ON d.id = ud.id
    LEFT JOIN department_persona_ids dpi ON dpi.department_id = d.id
    LEFT JOIN department_document_ids ddi ON ddi.department_id = d.id
    LEFT JOIN department_parameter_ids dparami ON dparami.department_id = d.id
    LEFT JOIN department_field_ids dfi ON dfi.department_id = d.id
),
persona_data AS (
    SELECT 
        p.id,
        p.name,
        COALESCE(p.description, '') as description,
        p.color,
        p.icon,
        false as image_model
    FROM personas p
    LEFT JOIN persona_departments pd ON pd.persona_id = p.id AND pd.active = true
    WHERE p.active = true
    GROUP BY p.id, p.name, p.description, p.color, p.icon
    HAVING 
        (
            COUNT(pd.persona_id) FILTER (WHERE pd.department_id IN (SELECT id FROM user_departments)) > 0
            OR NOT EXISTS (SELECT 1 FROM persona_departments pd2 WHERE pd2.persona_id = p.id AND pd2.active = true)
        )
        AND (
            CASE 
                WHEN (SELECT use_video FROM extracted_params) = true THEN
                    EXISTS (
                        SELECT 1 
                        FROM persona_fields pf
                        JOIN parameter_fields pfield ON pfield.field_id = pf.field_id
                        JOIN parameters param ON param.id = pfield.parameter_id
                        WHERE pf.persona_id = p.id
                        AND pf.active = true
                        AND pfield.active = true
                        AND param.active = true
                        AND param.video_parameter = true
                    )
                    OR EXISTS (
                        SELECT 1 
                        FROM persona_fields pf
                        JOIN field_conditional_parameters fcp ON fcp.field_id = pf.field_id
                        JOIN parameters cp ON cp.id = fcp.conditional_parameter_id
                        WHERE pf.persona_id = p.id
                        AND pf.active = true
                        AND fcp.active = true
                        AND cp.video_parameter = true
                    )
                    OR EXISTS (
                        SELECT 1 
                        FROM persona_fields pf
                        JOIN parameter_fields pfield ON pfield.field_id = pf.field_id
                        JOIN parameters param ON param.id = pfield.parameter_id
                        WHERE pf.persona_id = p.id
                        AND pf.active = true
                        AND pfield.active = true
                        AND param.active = true
                        AND param.video_parameter = false
                        AND param.scenario_parameter = false
                    )
                ELSE
                    EXISTS (
                        SELECT 1 
                        FROM persona_fields pf
                        JOIN parameter_fields pfield ON pfield.field_id = pf.field_id
                        JOIN parameters param ON param.id = pfield.parameter_id
                        WHERE pf.persona_id = p.id
                        AND pf.active = true
                        AND pfield.active = true
                        AND param.active = true
                        AND param.scenario_parameter = true
                    )
                    OR EXISTS (
                        SELECT 1 
                        FROM persona_fields pf
                        JOIN field_conditional_parameters fcp ON fcp.field_id = pf.field_id
                        JOIN parameters cp ON cp.id = fcp.conditional_parameter_id
                        WHERE pf.persona_id = p.id
                        AND pf.active = true
                        AND fcp.active = true
                        AND cp.scenario_parameter = true
                    )
                    OR EXISTS (
                        SELECT 1 
                        FROM persona_fields pf
                        JOIN parameter_fields pfield ON pfield.field_id = pf.field_id
                        JOIN parameters param ON param.id = pfield.parameter_id
                        WHERE pf.persona_id = p.id
                        AND pf.active = true
                        AND pfield.active = true
                        AND param.active = true
                        AND param.video_parameter = false
                        AND param.scenario_parameter = false
                    )
            END
        )
        -- Filter by selected departments
        AND (
            (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM persona_departments pd_filter
                WHERE pd_filter.persona_id = p.id
                AND pd_filter.active = true
                AND pd_filter.department_id = ANY((SELECT filter_department_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Filter by selected parameters (persona must have fields from selected parameters)
        AND (
            (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM persona_fields pf_filter
                JOIN parameter_fields pfield_filter ON pfield_filter.field_id = pf_filter.field_id
                WHERE pf_filter.persona_id = p.id
                AND pf_filter.active = true
                AND pfield_filter.active = true
                AND pfield_filter.parameter_id = ANY((SELECT filter_parameter_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Filter by selected fields (persona must have selected fields)
        AND (
            (SELECT array_length(filter_field_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_field_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM persona_fields pf_field_filter
                WHERE pf_field_filter.persona_id = p.id
                AND pf_field_filter.active = true
                AND pf_field_filter.field_id = ANY((SELECT filter_field_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Search filter
        AND (
            (SELECT persona_search FROM params LIMIT 1) IS NULL
            OR LOWER(p.name) LIKE '%' || LOWER((SELECT persona_search FROM params LIMIT 1)) || '%'
            OR LOWER(COALESCE(p.description, '')) LIKE '%' || LOWER((SELECT persona_search FROM params LIMIT 1)) || '%'
        )
        -- Show selected filter
        AND (
            (SELECT persona_show_selected FROM params LIMIT 1) = false
            OR (SELECT array_length(filter_persona_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_persona_ids, 1) FROM params LIMIT 1) = 0
            OR p.id = ANY((SELECT filter_persona_ids FROM params LIMIT 1)::uuid[])
        )
    ORDER BY p.name
),
persona_parameter_relationships AS (
    SELECT DISTINCT
        p.id as persona_id,
        param.id as parameter_id
    FROM persona_data p
    CROSS JOIN parameters param
    WHERE param.active = true
    AND param.persona_parameter = true
    AND (
        EXISTS (
            SELECT 1 FROM persona_fields pf
            JOIN parameter_fields pfield ON pfield.field_id = pf.field_id
            WHERE pf.persona_id = p.id
            AND pfield.parameter_id = param.id
            AND pf.active = true
            AND pfield.active = true
        )
    )
),
persona_fields_data AS (
    SELECT 
        pf.persona_id,
        ARRAY_AGG(pf.field_id ORDER BY pf.field_id) as field_ids
    FROM persona_fields pf
    WHERE pf.active = true
    GROUP BY pf.persona_id
),
persona_examples_data AS (
    SELECT DISTINCT ON (pe.persona_id)
        pe.persona_id,
        e.example
    FROM persona_examples pe
    JOIN examples e ON e.id = pe.example_id
    WHERE pe.persona_id IN (SELECT id FROM persona_data)
    ORDER BY pe.persona_id, pe.idx
),
all_personas_array AS (
    SELECT 
        p.id as persona_id,
        p.name,
        p.description,
        p.color,
        p.icon,
        p.image_model,
        COALESCE((
            SELECT ARRAY_AGG(ppr.parameter_id ORDER BY ppr.parameter_id)
            FROM persona_parameter_relationships ppr
            WHERE ppr.persona_id = p.id
        ), ARRAY[]::uuid[]) as parameter_ids,
        COALESCE(pfd.field_ids, ARRAY[]::uuid[]) as field_ids,
        ped.example
    FROM persona_data p
    LEFT JOIN persona_fields_data pfd ON pfd.persona_id = p.id
    LEFT JOIN persona_examples_data ped ON ped.persona_id = p.id
),
document_data_base AS (
    SELECT 
        d.id,
        d.name,
        ''::text as description
    FROM documents d
    LEFT JOIN document_departments dd ON dd.document_id = d.id AND dd.active = true
    WHERE d.active = true
    GROUP BY d.id, d.name
    HAVING 
        (
            COUNT(dd.document_id) FILTER (WHERE dd.department_id IN (SELECT id FROM user_departments)) > 0
            OR NOT EXISTS (SELECT 1 FROM document_departments dd2 WHERE dd2.document_id = d.id AND dd2.active = true)
        )
        AND (
            CASE 
                WHEN (SELECT use_video FROM extracted_params) = true THEN
                    EXISTS (
                        SELECT 1 
                        FROM document_fields df
                        JOIN parameter_fields pfield ON pfield.field_id = df.field_id
                        JOIN parameters param ON param.id = pfield.parameter_id
                        WHERE df.document_id = d.id
                        AND df.active = true
                        AND pfield.active = true
                        AND param.active = true
                        AND param.video_parameter = true
                    )
                    OR EXISTS (
                        SELECT 1 
                        FROM document_fields df
                        JOIN field_conditional_parameters fcp ON fcp.field_id = df.field_id
                        JOIN parameters cp ON cp.id = fcp.conditional_parameter_id
                        WHERE df.document_id = d.id
                        AND df.active = true
                        AND fcp.active = true
                        AND cp.video_parameter = true
                    )
                ELSE
                    EXISTS (
                        SELECT 1 
                        FROM document_fields df
                        JOIN parameter_fields pfield ON pfield.field_id = df.field_id
                        JOIN parameters param ON param.id = pfield.parameter_id
                        WHERE df.document_id = d.id
                        AND df.active = true
                        AND pfield.active = true
                        AND param.active = true
                        AND param.scenario_parameter = true
                    )
                    OR EXISTS (
                        SELECT 1 
                        FROM document_fields df
                        JOIN field_conditional_parameters fcp ON fcp.field_id = df.field_id
                        JOIN parameters cp ON cp.id = fcp.conditional_parameter_id
                        WHERE df.document_id = d.id
                        AND df.active = true
                        AND fcp.active = true
                        AND cp.scenario_parameter = true
                    )
                    OR EXISTS (
                        SELECT 1 
                        FROM document_fields df
                        JOIN parameter_fields pfield ON pfield.field_id = df.field_id
                        JOIN parameters param ON param.id = pfield.parameter_id
                        WHERE df.document_id = d.id
                        AND df.active = true
                        AND pfield.active = true
                        AND param.active = true
                        AND param.video_parameter = false
                        AND param.scenario_parameter = false
                    )
            END
        )
    UNION
    SELECT DISTINCT
        d.id,
        d.name,
        ''::text as description
    FROM documents d
    WHERE d.active = true
    AND (SELECT document_ids FROM extracted_params LIMIT 1) IS NOT NULL
    AND array_length((SELECT document_ids FROM extracted_params LIMIT 1), 1) > 0
            AND d.id IN (SELECT unnest((SELECT document_ids FROM extracted_params LIMIT 1)::uuid[]))
    AND (
        CASE 
            WHEN (SELECT use_video FROM params LIMIT 1) = true THEN
                EXISTS (
                    SELECT 1 
                    FROM document_fields df
                    JOIN parameter_fields pfield ON pfield.field_id = df.field_id
                    JOIN parameters param ON param.id = pfield.parameter_id
                    WHERE df.document_id = d.id
                    AND df.active = true
                    AND pfield.active = true
                    AND param.active = true
                    AND param.video_parameter = true
                )
                OR EXISTS (
                    SELECT 1 
                    FROM document_fields df
                    JOIN field_conditional_parameters fcp ON fcp.field_id = df.field_id
                    JOIN parameters cp ON cp.id = fcp.conditional_parameter_id
                    WHERE df.document_id = d.id
                    AND df.active = true
                    AND fcp.active = true
                    AND cp.video_parameter = true
                )
            ELSE
                EXISTS (
                    SELECT 1 
                    FROM document_fields df
                    JOIN parameter_fields pfield ON pfield.field_id = df.field_id
                    JOIN parameters param ON param.id = pfield.parameter_id
                    WHERE df.document_id = d.id
                    AND df.active = true
                    AND pfield.active = true
                    AND param.active = true
                    AND param.scenario_parameter = true
                )
                OR EXISTS (
                    SELECT 1 
                    FROM document_fields df
                    JOIN field_conditional_parameters fcp ON fcp.field_id = df.field_id
                    JOIN parameters cp ON cp.id = fcp.conditional_parameter_id
                    WHERE df.document_id = d.id
                    AND df.active = true
                    AND fcp.active = true
                    AND cp.scenario_parameter = true
                )
                OR EXISTS (
                    SELECT 1 
                    FROM document_fields df
                    JOIN parameter_fields pfield ON pfield.field_id = df.field_id
                    JOIN parameters param ON param.id = pfield.parameter_id
                    WHERE df.document_id = d.id
                    AND df.active = true
                    AND pfield.active = true
                    AND param.active = true
                    AND param.video_parameter = false
                    AND param.scenario_parameter = false
                )
        END
    )
    UNION
    SELECT DISTINCT
        d.id,
        d.name,
        ''::text as description
    FROM documents d
    WHERE d.active = true
    AND (SELECT template_document_ids FROM extracted_params LIMIT 1) IS NOT NULL
    AND array_length((SELECT template_document_ids FROM extracted_params LIMIT 1), 1) > 0
    AND d.id IN (SELECT unnest((SELECT template_document_ids FROM extracted_params LIMIT 1)::uuid[]))
    AND (
        CASE 
            WHEN (SELECT use_video FROM params LIMIT 1) = true THEN
                EXISTS (
                    SELECT 1 
                    FROM document_fields df
                    JOIN parameter_fields pfield ON pfield.field_id = df.field_id
                    JOIN parameters param ON param.id = pfield.parameter_id
                    WHERE df.document_id = d.id
                    AND df.active = true
                    AND pfield.active = true
                    AND param.active = true
                    AND param.video_parameter = true
                )
                OR EXISTS (
                    SELECT 1 
                    FROM document_fields df
                    JOIN field_conditional_parameters fcp ON fcp.field_id = df.field_id
                    JOIN parameters cp ON cp.id = fcp.conditional_parameter_id
                    WHERE df.document_id = d.id
                    AND df.active = true
                    AND fcp.active = true
                    AND cp.video_parameter = true
                )
            ELSE
                EXISTS (
                    SELECT 1 
                    FROM document_fields df
                    JOIN parameter_fields pfield ON pfield.field_id = df.field_id
                    JOIN parameters param ON param.id = pfield.parameter_id
                    WHERE df.document_id = d.id
                    AND df.active = true
                    AND pfield.active = true
                    AND param.active = true
                    AND param.scenario_parameter = true
                )
                OR EXISTS (
                    SELECT 1 
                    FROM document_fields df
                    JOIN field_conditional_parameters fcp ON fcp.field_id = df.field_id
                    JOIN parameters cp ON cp.id = fcp.conditional_parameter_id
                    WHERE df.document_id = d.id
                    AND df.active = true
                    AND fcp.active = true
                    AND cp.scenario_parameter = true
                )
                OR EXISTS (
                    SELECT 1 
                    FROM document_fields df
                    JOIN parameter_fields pfield ON pfield.field_id = df.field_id
                    JOIN parameters param ON param.id = pfield.parameter_id
                    WHERE df.document_id = d.id
                    AND df.active = true
                    AND pfield.active = true
                    AND param.active = true
                    AND param.video_parameter = false
                    AND param.scenario_parameter = false
                )
        END
    )
),
document_data AS (
    SELECT DISTINCT
        ddb.id,
        ddb.name,
        ddb.description
    FROM document_data_base ddb
    WHERE
        -- Filter by selected departments
        (
            (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM document_departments dd_filter
                WHERE dd_filter.document_id = ddb.id
                AND dd_filter.active = true
                AND dd_filter.department_id = ANY((SELECT filter_department_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Filter by selected parameters (document must have fields from selected parameters)
        AND (
            (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM document_fields df_filter
                JOIN parameter_fields pfield_filter ON pfield_filter.field_id = df_filter.field_id
                WHERE df_filter.document_id = ddb.id
                AND df_filter.active = true
                AND pfield_filter.active = true
                AND pfield_filter.parameter_id = ANY((SELECT filter_parameter_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Filter by selected fields (document must have selected fields)
        AND (
            (SELECT array_length(filter_field_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_field_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM document_fields df_field_filter
                WHERE df_field_filter.document_id = ddb.id
                AND df_field_filter.active = true
                AND df_field_filter.field_id = ANY((SELECT filter_field_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Search filter
        AND (
            (SELECT document_search FROM params LIMIT 1) IS NULL
            OR LOWER(ddb.name) LIKE '%' || LOWER((SELECT document_search FROM params LIMIT 1)) || '%'
            OR LOWER(COALESCE(ddb.description, '')) LIKE '%' || LOWER((SELECT document_search FROM params LIMIT 1)) || '%'
        )
        -- Show selected filter
        AND (
            (SELECT document_show_selected FROM params LIMIT 1) = false
            OR (SELECT array_length(filter_document_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_document_ids, 1) FROM params LIMIT 1) = 0
            OR ddb.id = ANY((SELECT filter_document_ids FROM params LIMIT 1)::uuid[])
        )
    ORDER BY ddb.name
),
document_parameter_relationships AS (
    SELECT DISTINCT
        d.id as document_id,
        param.id as parameter_id
    FROM document_data d
    CROSS JOIN parameters param
    WHERE param.active = true
    AND param.document_parameter = true
    AND (
        EXISTS (
            SELECT 1 FROM document_fields df
            JOIN parameter_fields pfield ON pfield.field_id = df.field_id
            WHERE df.document_id = d.id
            AND pfield.parameter_id = param.id
            AND df.active = true
            AND pfield.active = true
        )
    )
),
document_fields_data AS (
    SELECT 
        df.document_id,
        ARRAY_AGG(df.field_id ORDER BY df.field_id) as field_ids
    FROM document_fields df
    WHERE df.active = true
    GROUP BY df.document_id
),
document_tree_data AS (
    SELECT DISTINCT ON (dt.child_id)
        dt.child_id as document_id,
        dt.parent_id
    FROM document_tree dt
    WHERE dt.active = true
    ORDER BY dt.child_id, dt.created_at DESC
),
all_documents_array AS (
    SELECT 
        d.id as document_id,
        d.name,
        d.description,
        COALESCE(u.file_path, template_u.file_path) as file_path,
        COALESCE(u.mime_type, template_u.mime_type) as mime_type,
        COALESCE((
            SELECT ARRAY_AGG(dpr.parameter_id ORDER BY dpr.parameter_id)
            FROM document_parameter_relationships dpr
            WHERE dpr.document_id = d.id
        ), ARRAY[]::uuid[]) as parameter_ids,
        COALESCE(dfd.field_ids, ARRAY[]::uuid[]) as field_ids,
        dtd.parent_id as parent_document_id
    FROM document_data d
    LEFT JOIN document_uploads du ON du.document_id = d.id AND du.active = true
    LEFT JOIN uploads u ON u.id = du.upload_id
    LEFT JOIN document_templates dt ON dt.document_id = d.id AND dt.active = true
    LEFT JOIN html h ON h.id = dt.html_id
    LEFT JOIN html_uploads hu ON hu.html_id = h.id AND hu.active = true
    LEFT JOIN uploads template_u ON template_u.id = hu.upload_id
    LEFT JOIN document_fields_data dfd ON dfd.document_id = d.id
    LEFT JOIN document_tree_data dtd ON dtd.document_id = d.id
),
available_scenario_parameters AS (
    SELECT DISTINCT
        p.id,
        p.name,
        COALESCE(p.description, '') as description,
        p.document_parameter,
        p.persona_parameter,
        p.scenario_parameter,
        p.video_parameter,
        false as numerical
    FROM parameters p
    WHERE p.active = true
    AND p.scenario_parameter = true
    AND (
        EXISTS (
            SELECT 1 FROM parameter_fields pf
            JOIN fields f ON f.id = pf.field_id
            LEFT JOIN field_departments fd ON fd.field_id = f.id AND fd.active = true
            WHERE pf.parameter_id = p.id
            AND pf.active = true
            AND f.active = true
            AND (
                fd.department_id IN (SELECT id FROM user_departments)
                OR NOT EXISTS (SELECT 1 FROM field_departments fd2 WHERE fd2.field_id = f.id AND fd2.active = true)
            )
        )
    )
),
parameter_data AS (
    SELECT DISTINCT 
        p.id,
        p.name,
        COALESCE(p.description, '') as description,
        p.document_parameter,
        p.persona_parameter
    FROM parameters p
    JOIN parameter_fields pf ON pf.parameter_id = p.id AND pf.active = true
    LEFT JOIN field_departments fd ON fd.field_id = pf.field_id AND fd.active = true
    CROSS JOIN user_departments ud
    WHERE p.active = true
    GROUP BY p.id, p.name, p.description, p.document_parameter, p.persona_parameter
    HAVING 
        COUNT(fd.field_id) FILTER (WHERE fd.department_id IN (SELECT id FROM user_departments)) > 0
        OR NOT EXISTS (SELECT 1 FROM field_departments fd2 
                      JOIN parameter_fields pf2 ON pf2.field_id = fd2.field_id 
                      WHERE pf2.parameter_id = p.id AND pf2.active = true)
        -- Filter by selected departments
        AND (
            (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM parameter_fields pf_dept_filter
                JOIN field_departments fd_dept_filter ON fd_dept_filter.field_id = pf_dept_filter.field_id
                WHERE pf_dept_filter.parameter_id = p.id
                AND pf_dept_filter.active = true
                AND fd_dept_filter.active = true
                AND fd_dept_filter.department_id = ANY((SELECT filter_department_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Search filter
        AND (
            (SELECT parameter_search FROM params LIMIT 1) IS NULL
            OR LOWER(p.name) LIKE '%' || LOWER((SELECT parameter_search FROM params LIMIT 1)) || '%'
            OR LOWER(COALESCE(p.description, '')) LIKE '%' || LOWER((SELECT parameter_search FROM params LIMIT 1)) || '%'
        )
        -- Show selected filter
        AND (
            (SELECT parameter_show_selected FROM params LIMIT 1) = false
            OR (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) = 0
            OR p.id = ANY((SELECT filter_parameter_ids FROM params LIMIT 1)::uuid[])
        )
    ORDER BY p.name
),
all_parameters_array AS (
    SELECT 
        p.id as parameter_id,
        p.name,
        p.description,
        p.document_parameter,
        p.persona_parameter,
        p.scenario_parameter,
        p.video_parameter,
        p.numerical
    FROM available_scenario_parameters p
),
parameter_item_data AS (
    SELECT 
        f.id,
        f.name,
        COALESCE(f.description, '') as description,
        pf.parameter_id,
        p.name as parameter_name
    FROM fields f
    JOIN parameter_fields pf ON pf.field_id = f.id AND pf.active = true
    JOIN parameters p ON p.id = pf.parameter_id
    LEFT JOIN field_departments fd ON fd.field_id = f.id AND fd.active = true
    WHERE p.active = true AND f.active = true
    GROUP BY f.id, f.name, f.description, pf.parameter_id, p.id, p.name
    HAVING 
        COUNT(fd.field_id) FILTER (WHERE fd.department_id IN (SELECT id FROM user_departments)) > 0
        OR NOT EXISTS (SELECT 1 FROM field_departments fd2 WHERE fd2.field_id = f.id AND fd2.active = true)
        -- Filter by selected departments
        AND (
            (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_department_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM field_departments fd_dept_filter
                WHERE fd_dept_filter.field_id = f.id
                AND fd_dept_filter.active = true
                AND fd_dept_filter.department_id = ANY((SELECT filter_department_ids FROM params LIMIT 1)::uuid[])
            )
            OR NOT EXISTS (SELECT 1 FROM field_departments fd_no_dept WHERE fd_no_dept.field_id = f.id AND fd_no_dept.active = true)
        )
        -- Filter by selected parameters (field must belong to selected parameter)
        AND (
            (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_parameter_ids, 1) FROM params LIMIT 1) = 0
            OR pf.parameter_id = ANY((SELECT filter_parameter_ids FROM params LIMIT 1)::uuid[])
        )
        -- Filter by selected fields
        AND (
            (SELECT array_length(filter_field_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_field_ids, 1) FROM params LIMIT 1) = 0
            OR f.id = ANY((SELECT filter_field_ids FROM params LIMIT 1)::uuid[])
        )
        -- Filter by selected personas (field must be linked to selected personas)
        AND (
            (SELECT array_length(filter_persona_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_persona_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM persona_fields pf_persona_filter
                WHERE pf_persona_filter.field_id = f.id
                AND pf_persona_filter.active = true
                AND pf_persona_filter.persona_id = ANY((SELECT filter_persona_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Filter by selected documents (field must be linked to selected documents)
        AND (
            (SELECT array_length(filter_document_ids, 1) FROM params LIMIT 1) IS NULL
            OR (SELECT array_length(filter_document_ids, 1) FROM params LIMIT 1) = 0
            OR EXISTS (
                SELECT 1 FROM document_fields df_doc_filter
                WHERE df_doc_filter.field_id = f.id
                AND df_doc_filter.active = true
                AND df_doc_filter.document_id = ANY((SELECT filter_document_ids FROM params LIMIT 1)::uuid[])
            )
        )
        -- Per-parameter show_selected filter (check if field_show_selected_by_param has this parameter set to true)
        AND (
            array_length((SELECT field_show_selected_by_param FROM params LIMIT 1), 1) IS NULL
            OR NOT EXISTS (
                SELECT 1 FROM UNNEST((SELECT field_show_selected_by_param FROM params LIMIT 1)) as fp_filter
                WHERE fp_filter.parameter_id = pf.parameter_id AND fp_filter.show_selected = true
            )
            OR f.id = ANY((SELECT filter_field_ids FROM params LIMIT 1)::uuid[])
        )
    ORDER BY p.name, f.name
),
field_conditional_parameters_data AS (
    SELECT 
        fcp.field_id,
        ARRAY_AGG(fcp.conditional_parameter_id ORDER BY fcp.conditional_parameter_id) as conditional_parameter_ids
    FROM field_conditional_parameters fcp
    WHERE fcp.active = true
    GROUP BY fcp.field_id
),
all_fields_array AS (
    SELECT 
        pi.id as field_id,
        pi.name,
        pi.description,
        pi.parameter_id,
        pi.parameter_name,
        COALESCE(fcpd.conditional_parameter_ids, ARRAY[]::uuid[]) as conditional_parameter_ids
    FROM parameter_item_data pi
    LEFT JOIN field_conditional_parameters_data fcpd ON fcpd.field_id = pi.id
),
all_parameters_detail_array AS (
    SELECT 
        pd.id as param_id,
        ARRAY[]::uuid[] as selected_items,
        COALESCE((
            SELECT ARRAY_AGG(f.id ORDER BY f.id)
            FROM fields f
            JOIN parameter_fields pf ON pf.field_id = f.id AND pf.active = true
            WHERE pf.parameter_id = pd.id AND f.active = true
        ), ARRAY[]::uuid[]) as valid_items
    FROM parameter_data pd
),
primary_department_id AS (
    SELECT department_id::text
    FROM profile_departments
    WHERE profile_id = (SELECT profile_id FROM extracted_params LIMIT 1) AND is_primary = TRUE
    LIMIT 1
),
first_user_department AS (
    SELECT ud.id
    FROM user_departments ud
    ORDER BY ud.id
    LIMIT 1
),
resolved_department_for_agents AS (
    SELECT COALESCE(
        (SELECT pd.department_id FROM profile_departments pd WHERE pd.profile_id = (SELECT profile_id FROM extracted_params LIMIT 1) AND pd.is_primary = TRUE LIMIT 1),
        (SELECT id FROM first_user_department)
    ) as department_id
),
expected_agent_role AS (
    SELECT 'scenario'::agent_role as role
),
default_scenario_agent AS (
    SELECT a.id::text as agent_id
    FROM agents a
    LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
    CROSS JOIN resolved_department_for_agents rdfa
    CROSS JOIN expected_agent_role ear
    WHERE a.role = ear.role
    AND a.active = true
    AND (
        ad.department_id = rdfa.department_id
        OR NOT EXISTS (SELECT 1 FROM agent_departments ad2 WHERE ad2.agent_id = a.id AND ad2.active = true)
    )
    ORDER BY 
        CASE WHEN ad.department_id = rdfa.department_id THEN 0 ELSE 1 END
    LIMIT 1
),
default_image_agent AS (
    SELECT a.id::text as agent_id
    FROM agents a
    LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
    CROSS JOIN resolved_department_for_agents rdfa
    WHERE a.role = 'image'
    AND a.active = true
    AND (
        ad.department_id = rdfa.department_id
        OR NOT EXISTS (SELECT 1 FROM agent_departments ad2 WHERE ad2.agent_id = a.id AND ad2.active = true)
    )
    ORDER BY 
        CASE WHEN ad.department_id = rdfa.department_id THEN 0 ELSE 1 END
    LIMIT 1
),
default_video_agent AS (
    SELECT a.id::text as agent_id
    FROM agents a
    LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
    CROSS JOIN resolved_department_for_agents rdfa
    WHERE a.role = 'video'
    AND a.active = true
    AND (
        ad.department_id = rdfa.department_id
        OR NOT EXISTS (SELECT 1 FROM agent_departments ad2 WHERE ad2.agent_id = a.id AND ad2.active = true)
    )
    ORDER BY 
        CASE WHEN ad.department_id = rdfa.department_id THEN 0 ELSE 1 END
    LIMIT 1
),
agent_filtered AS (
    SELECT a.id, a.name, a.description, a.role
    FROM agents a
    LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
    CROSS JOIN expected_agent_role ear
    WHERE a.active = true 
    AND (
        a.role = ear.role
        OR a.role = 'image'
        OR a.role = 'video'
    )
    GROUP BY a.id, a.name, a.description, a.role, ear.role
    HAVING 
        COUNT(ad.agent_id) FILTER (WHERE ad.department_id IN (SELECT id FROM user_departments)) > 0
        OR NOT EXISTS (SELECT 1 FROM agent_departments ad2 WHERE ad2.agent_id = a.id AND ad2.active = true)
),
all_agents_array AS (
    SELECT 
        af.id as agent_id,
        af.name,
        COALESCE(af.description, '') as description,
        ARRAY[af.role::text] as roles
    FROM agent_filtered af
),
accessible_scenarios_default AS (
    SELECT DISTINCT s.id as scenario_id
    FROM scenarios s
    LEFT JOIN scenario_departments sd ON sd.scenario_id = s.id AND sd.active = true
    WHERE s.active = true
    AND (
        sd.department_id IN (SELECT id FROM user_departments)
        OR NOT EXISTS (SELECT 1 FROM scenario_departments sd2 WHERE sd2.scenario_id = s.id AND sd2.active = true)
    )
),
objectives_with_departments_default AS (
    SELECT
        o.objective,
        COALESCE((
            SELECT ARRAY_AGG(DISTINCT dept_id ORDER BY dept_id)
            FROM (
                SELECT DISTINCT sd.department_id as dept_id
                FROM scenario_objectives so2
                JOIN objectives o2 ON o2.id = so2.objective_id
                JOIN accessible_scenarios_default acs2 ON acs2.scenario_id = so2.scenario_id
                LEFT JOIN scenario_departments sd ON sd.scenario_id = so2.scenario_id AND sd.active = true
                WHERE o2.objective = o.objective
                    AND o2.objective IS NOT NULL 
                    AND o2.objective != ''
                    AND sd.department_id IS NOT NULL
            ) dept_list
        ), ARRAY[]::uuid[]) as department_ids
    FROM scenario_objectives so
    JOIN objectives o ON o.id = so.objective_id
    JOIN accessible_scenarios_default acs ON acs.scenario_id = so.scenario_id
    WHERE o.objective IS NOT NULL AND o.objective != ''
    GROUP BY o.objective
),
all_objectives_array AS (
    SELECT 
        o.id as objective_id,
        o.objective as name,
        o.objective as description
    FROM objectives o
    LEFT JOIN objective_departments od_dept ON od_dept.objective_id = o.id AND od_dept.active = true
    WHERE (
        ((SELECT objective_ids FROM extracted_params LIMIT 1) IS NOT NULL AND array_length((SELECT objective_ids FROM extracted_params LIMIT 1), 1) > 0 AND o.id = ANY((SELECT objective_ids FROM extracted_params LIMIT 1)::uuid[]))
        OR ((SELECT objective_ids FROM extracted_params LIMIT 1) IS NULL OR array_length((SELECT objective_ids FROM extracted_params LIMIT 1), 1) = 0)
    )
    AND (
        od_dept.department_id IN (SELECT id FROM user_departments)
        OR NOT EXISTS (SELECT 1 FROM objective_departments od2 WHERE od2.objective_id = o.id AND od2.active = true)
    )
),
all_problem_statements_array AS (
    SELECT 
        ps.id as problem_statement_id,
        ps.name,
        ps.problem_statement,
        ps.created_at,
        ps.updated_at
    FROM problem_statements ps
    LEFT JOIN problem_statement_departments psd_dept ON psd_dept.problem_statement_id = ps.id AND psd_dept.active = true
    WHERE (
        psd_dept.department_id IN (SELECT id FROM user_departments)
        OR NOT EXISTS (SELECT 1 FROM problem_statement_departments psd2 WHERE psd2.problem_statement_id = ps.id AND psd2.active = true)
    )
    AND (
        ((SELECT problem_statement_ids FROM extracted_params LIMIT 1) IS NULL OR array_length((SELECT problem_statement_ids FROM extracted_params LIMIT 1), 1) = 0)
        OR ps.id IN (SELECT unnest((SELECT problem_statement_ids FROM extracted_params LIMIT 1)::uuid[]))
    )
),
all_scenario_images_array AS (
    SELECT 
        COALESCE(iu.upload_id, i.id) as upload_id,
        i.name,
        u.file_path,
        u.mime_type,
        i.active,
        i.created_at,
        i.updated_at
    FROM images i
    LEFT JOIN image_uploads iu ON iu.image_id = i.id AND iu.active = true
    LEFT JOIN uploads u ON u.id = iu.upload_id
    LEFT JOIN image_departments id_dept ON id_dept.image_id = i.id AND id_dept.active = true
    WHERE i.active = true
    AND (
        id_dept.department_id IN (SELECT id FROM user_departments)
        OR NOT EXISTS (SELECT 1 FROM image_departments id2 WHERE id2.image_id = i.id AND id2.active = true)
    )
    ORDER BY i.created_at DESC
),
all_scenario_videos_array AS (
    SELECT 
        v.id,
        v.name,
        v.length_seconds,
        v.completed,
        v.active,
        v.image_enabled,
        u.file_path,
        u.mime_type,
        u.id as upload_id
    FROM videos v
    LEFT JOIN video_uploads vu ON vu.video_id = v.id AND vu.active = true
    LEFT JOIN uploads u ON u.id = vu.upload_id
    LEFT JOIN video_departments vd_dept ON vd_dept.video_id = v.id AND vd_dept.active = true
    WHERE v.active = true
    AND (
        vd_dept.department_id IN (SELECT id FROM user_departments)
        OR NOT EXISTS (SELECT 1 FROM video_departments vd2 WHERE vd2.video_id = v.id AND vd2.active = true)
    )
    ORDER BY v.created_at DESC
),
all_document_details_array AS (
    SELECT 
        d.id as document_id,
        d.name,
        d.updated_at,
        CASE 
            WHEN u.file_path IS NOT NULL THEN SUBSTRING(u.file_path FROM '\\.([^\\.]+)$')
            WHEN template_u.file_path IS NOT NULL THEN SUBSTRING(template_u.file_path FROM '\\.([^\\.]+)$')
            ELSE NULL 
        END as extension,
        ARRAY[]::uuid[] as scenario_ids,
        true as can_edit,
        true as can_delete,
        d.active,
        COALESCE((
            SELECT ARRAY_AGG(DISTINCT dd.department_id)
            FROM document_departments dd
            WHERE dd.document_id = d.id AND dd.active = true
        ), ARRAY[]::uuid[]) as department_ids,
        COALESCE(u.file_path, template_u.file_path) as file_path,
        COALESCE(u.mime_type, template_u.mime_type) as mime_type,
        COALESCE(u.id, template_u.id) as upload_id,
        dt.html_id as html_id,
        COALESCE((
            SELECT ARRAY_AGG(df.field_id)
            FROM document_fields df
            WHERE df.document_id = d.id AND df.active = true
        ), ARRAY[]::uuid[]) as field_ids,
        CASE 
            WHEN d.template = true THEN true
            WHEN EXISTS(
                SELECT 1 FROM document_templates dt2 
                WHERE dt2.document_id = d.id AND dt2.active = true
            ) THEN true
            ELSE false
        END as is_template,
        dtd.parent_id as parent_document_id
    FROM documents d
    LEFT JOIN document_uploads du ON du.document_id = d.id AND du.active = true
    LEFT JOIN uploads u ON u.id = du.upload_id
    LEFT JOIN document_templates dt ON dt.document_id = d.id AND dt.active = true
    LEFT JOIN html h ON h.id = dt.html_id
    LEFT JOIN html_uploads hu ON hu.html_id = h.id AND hu.active = true
    LEFT JOIN uploads template_u ON template_u.id = hu.upload_id
    LEFT JOIN document_tree_data dtd ON dtd.document_id = d.id
    WHERE (
        d.id IN (SELECT id FROM document_data)
        OR (
            (SELECT document_ids FROM params_single) IS NOT NULL
            AND array_length((SELECT document_ids FROM params_single), 1) > 0
            AND d.id IN (SELECT unnest((SELECT document_ids FROM params_single)::uuid[]))
        )
        OR (
            (SELECT document_ids FROM params_single) IS NOT NULL
            AND array_length((SELECT document_ids FROM params_single), 1) > 0
            AND EXISTS (
                SELECT 1 FROM document_tree dtree
                WHERE dtree.child_id = d.id
                AND dtree.parent_id IN (SELECT unnest((SELECT document_ids FROM params_single)::uuid[]))
                AND dtree.active = true
            )
        )
    )
    AND d.active = true
    ORDER BY d.name
)
SELECT 
    up.actor_name::text as actor_name,
    up.user_role::text as user_role,
    COALESCE(
        (SELECT ARRAY_AGG(id::text ORDER BY id) FROM user_departments),
        ARRAY[]::text[]
    ) as department_ids,
    COALESCE(
        (SELECT ARRAY_AGG(id::text) FROM persona_data),
        ARRAY[]::text[]
    ) as valid_persona_ids,
    COALESCE(
        (SELECT ARRAY_AGG(id::text) FROM document_data),
        ARRAY[]::text[]
    ) as valid_document_ids,
    COALESCE(
        (SELECT ARRAY_AGG(parameter_id::text ORDER BY name) FROM all_parameters_array),
        ARRAY[]::text[]
    ) as valid_parameter_ids,
    COALESCE(
        (SELECT ARRAY_AGG(field_id::text ORDER BY parameter_name, name) FROM all_fields_array),
        ARRAY[]::text[]
    ) as valid_field_ids,
    (SELECT department_id FROM primary_department_id) as primary_department_id,
    COALESCE((SELECT agent_id FROM default_scenario_agent), '') as scenario_agent_id,
    COALESCE((SELECT agent_id FROM default_image_agent), '') as image_agent_id,
    COALESCE((SELECT agent_id FROM default_video_agent), '') as video_agent_id,
    COALESCE((SELECT ARRAY_AGG(agent_id::text ORDER BY name) FROM all_agents_array), ARRAY[]::text[]) as valid_agent_ids,
    COALESCE(
        (SELECT ARRAY_AGG(d.id::text)
         FROM documents d
         WHERE d.active = true
         AND (SELECT template_document_ids FROM extracted_params) IS NOT NULL
         AND array_length((SELECT template_document_ids FROM extracted_params), 1) > 0
         AND d.id IN (SELECT unnest((SELECT template_document_ids FROM extracted_params LIMIT 1)::uuid[]))
         AND d.id IN (SELECT id FROM document_data)),
        ARRAY[]::text[]
    ) as selected_template_document_ids,
    false as video_enabled,
    false as questions_enabled,
    1 as persona_range_min,
    3 as persona_range_max,
    0 as document_range_min,
    3 as document_range_max,
    0 as parameter_range_min,
    3 as parameter_range_max,
    ARRAY[]::text[] as question_ids,
    -- Arrays of composite types (aggregated from subqueries)
    COALESCE(
        (SELECT ARRAY_AGG((ada.department_id, ada.name, ada.description, ada.persona_ids, ada.document_ids, ada.parameter_ids, ada.field_ids)::types.q_get_scenario_new_v4_department ORDER BY ada.name) FROM all_departments_array ada),
        '{}'::types.q_get_scenario_new_v4_department[]
    ) as departments,
    COALESCE(
        (SELECT ARRAY_AGG((apa.persona_id, apa.name, apa.description, apa.color, apa.icon, apa.image_model, apa.parameter_ids, apa.field_ids, apa.example)::types.q_get_scenario_new_v4_persona ORDER BY apa.name) FROM all_personas_array apa),
        '{}'::types.q_get_scenario_new_v4_persona[]
    ) as personas,
    COALESCE(
        (SELECT ARRAY_AGG((ada2.document_id, ada2.name, ada2.description, ada2.file_path, ada2.mime_type, ada2.parameter_ids, ada2.field_ids, ada2.parent_document_id)::types.q_get_scenario_new_v4_document ORDER BY ada2.name) FROM all_documents_array ada2),
        '{}'::types.q_get_scenario_new_v4_document[]
    ) as documents,
    COALESCE(
        (SELECT ARRAY_AGG((aparam.parameter_id, aparam.name, aparam.description, aparam.document_parameter, aparam.persona_parameter, aparam.scenario_parameter, aparam.video_parameter, aparam.numerical)::types.q_get_scenario_new_v4_parameter ORDER BY aparam.name) FROM all_parameters_array aparam),
        '{}'::types.q_get_scenario_new_v4_parameter[]
    ) as parameters,
    COALESCE(
        (SELECT ARRAY_AGG((afa.field_id, afa.name, afa.description, afa.parameter_id, afa.parameter_name, afa.conditional_parameter_ids)::types.q_get_scenario_new_v4_field ORDER BY afa.parameter_name, afa.name) FROM all_fields_array afa),
        '{}'::types.q_get_scenario_new_v4_field[]
    ) as fields,
    COALESCE(
        (SELECT ARRAY_AGG((aag.agent_id, aag.name, aag.description, aag.roles)::types.q_get_scenario_new_v4_agent ORDER BY aag.name) FROM all_agents_array aag),
        '{}'::types.q_get_scenario_new_v4_agent[]
    ) as agents,
    COALESCE(
        (SELECT ARRAY_AGG((aoa.objective_id, aoa.name, aoa.description)::types.q_get_scenario_new_v4_objective ORDER BY aoa.name) FROM all_objectives_array aoa),
        '{}'::types.q_get_scenario_new_v4_objective[]
    ) as objectives,
    COALESCE(
        (SELECT ARRAY_AGG((aps.problem_statement_id, aps.name, aps.problem_statement, aps.created_at, aps.updated_at)::types.q_get_scenario_new_v4_problem_statement ORDER BY aps.name) FROM all_problem_statements_array aps),
        '{}'::types.q_get_scenario_new_v4_problem_statement[]
    ) as problem_statements,
    COALESCE(
        (SELECT ARRAY_AGG((asi.upload_id, asi.name, asi.file_path, asi.mime_type, asi.active, asi.created_at, asi.updated_at)::types.q_get_scenario_new_v4_scenario_image ORDER BY asi.created_at DESC) FROM all_scenario_images_array asi),
        '{}'::types.q_get_scenario_new_v4_scenario_image[]
    ) as scenario_images,
    COALESCE(
        (SELECT ARRAY_AGG((asv.id, asv.name, asv.length_seconds, asv.completed, asv.active, asv.image_enabled, asv.file_path, asv.mime_type, asv.upload_id)::types.q_get_scenario_new_v4_scenario_video ORDER BY asv.id) FROM all_scenario_videos_array asv),
        '{}'::types.q_get_scenario_new_v4_scenario_video[]
    ) as scenario_videos,
    COALESCE(
        ARRAY[]::types.q_get_scenario_new_v4_question[],
        '{}'::types.q_get_scenario_new_v4_question[]
    ) as questions,
    COALESCE(
        (SELECT ARRAY_AGG((owd.objective, owd.department_ids)::types.q_get_scenario_new_v4_objective_with_departments ORDER BY owd.objective) FROM objectives_with_departments_default owd),
        '{}'::types.q_get_scenario_new_v4_objective_with_departments[]
    ) as objectives_history,
    COALESCE(
        (SELECT ARRAY_AGG((add.document_id, add.name, add.updated_at, add.extension, add.scenario_ids, add.can_edit, add.can_delete, add.active, add.department_ids, add.file_path, add.mime_type, add.upload_id, add.field_ids, add.is_template, add.parent_document_id)::types.q_get_scenario_new_v4_document_detail ORDER BY add.name) FROM all_document_details_array add),
        '{}'::types.q_get_scenario_new_v4_document_detail[]
    ) as document_details,
    COALESCE(
        (SELECT ARRAY_AGG((apd.param_id, apd.selected_items, apd.valid_items)::types.q_get_scenario_new_v4_parameter_detail ORDER BY apd.param_id) FROM all_parameters_detail_array apd),
        '{}'::types.q_get_scenario_new_v4_parameter_detail[]
    ) as parameters_detail,
    COALESCE((SELECT draft_version FROM draft_payload_data), 0) as draft_version,
    -- Extract nested objects from draft payload if available
    COALESCE(
        (SELECT payload->'fieldShowSelected' FROM draft_payload_data),
        (SELECT payload->'field_show_selected' FROM draft_payload_data),
        '{}'::jsonb
    ) as draft_field_show_selected,
    COALESCE(
        (SELECT payload->'fieldRanges' FROM draft_payload_data),
        (SELECT payload->'field_ranges' FROM draft_payload_data),
        '{}'::jsonb
    ) as draft_field_ranges,
    COALESCE(
        (SELECT payload->'randomizeParameterItems' FROM draft_payload_data),
        (SELECT payload->'randomize_parameter_items' FROM draft_payload_data),
        '{}'::jsonb
    ) as draft_randomize_parameter_items
FROM user_profile up
$_$;


--
-- Name: api_get_scenario_objectives_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_scenario_objectives_v4(scenario_id uuid) RETURNS TABLE(objective_id uuid, idx integer)
    LANGUAGE sql STABLE
    AS $$
SELECT 
    so.objective_id,
    so.idx
FROM scenario_objectives so
WHERE so.scenario_id = scenario_id
ORDER BY so.idx
$$;


--
-- Name: api_get_scenario_problem_statement_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_scenario_problem_statement_v4(scenario_id uuid) RETURNS TABLE(problem_statement_id uuid, problem_statement text)
    LANGUAGE sql STABLE
    AS $$
SELECT 
    ps.id as problem_statement_id,
    ps.problem_statement
FROM scenario_problem_statements sps
JOIN problem_statements ps ON ps.id = sps.problem_statement_id
WHERE sps.scenario_id = scenario_id
  AND sps.active = true
ORDER BY sps.created_at DESC
LIMIT 1
$$;


--
-- Name: api_get_scenario_questions_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_scenario_questions_v4(scenario_id uuid) RETURNS TABLE(question_id uuid, active boolean)
    LANGUAGE sql STABLE
    AS $$
SELECT 
    sq.question_id,
    sq.active
FROM scenario_questions sq
WHERE sq.scenario_id = scenario_id
  AND sq.active = true
$$;


--
-- Name: api_get_scenario_videos_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_scenario_videos_v4(scenario_id uuid) RETURNS TABLE(video_id uuid, active boolean)
    LANGUAGE sql STABLE
    AS $$
SELECT 
    sv.video_id,
    sv.active
FROM scenario_videos sv
WHERE sv.scenario_id = scenario_id
  AND sv.active = true
$$;


--
-- Name: api_get_scenarios_with_grades_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_scenarios_with_grades_v4(attempt_id uuid) RETURNS TABLE(parent_scenario_id uuid)
    LANGUAGE sql STABLE
    AS $$
WITH RECURSIVE scenario_ancestors AS (
    -- Base case: start with each chat's scenario
    SELECT DISTINCT
        sc.scenario_id as child_scenario_id,
        sc.scenario_id as ancestor_id,
        0 as depth
    FROM attempt_chats ac
    JOIN chats sc ON sc.id = ac.chat_id
    JOIN grades scg ON EXISTS (
        SELECT 1 FROM runs r_check
        JOIN group_runs gr_check ON gr_check.run_id = r_check.id
        JOIN groups g_check ON g_check.id = gr_check.group_id
        JOIN chat_groups cg_check ON cg_check.group_id = g_check.id
        JOIN chats c_check ON c_check.id = cg_check.chat_id
        WHERE r_check.id = scg.run_id AND c_check.id = sc.id
    )
    JOIN runs r_scen1 ON r_scen1.id = scg.run_id
    JOIN group_runs gr_scen1 ON gr_scen1.run_id = r_scen1.id
    JOIN groups g_scen1 ON g_scen1.id = gr_scen1.group_id
    JOIN chat_groups cg_scen1 ON cg_scen1.group_id = g_scen1.id
    JOIN chats c_scen1 ON c_scen1.id = cg_scen1.chat_id AND c_scen1.id = sc.id
    WHERE ac.attempt_id = attempt_id
    
    UNION ALL
    
    -- Recursive case: traverse up the tree
    SELECT 
        sa.child_scenario_id,
        COALESCE(
            (SELECT st.parent_id 
             FROM scenario_tree st 
             WHERE st.child_id = sa.ancestor_id 
               AND st.parent_id != st.child_id 
             LIMIT 1),
            sa.ancestor_id
        ) as ancestor_id,
        sa.depth + 1 as depth
    FROM scenario_ancestors sa
    WHERE sa.depth < 100  -- Safety limit
      AND EXISTS (
          SELECT 1 FROM scenario_tree st 
          WHERE st.child_id = sa.ancestor_id 
            AND st.parent_id != st.child_id
      )
),
root_scenarios AS (
    -- Find the root scenario for each child (topmost ancestor)
    SELECT DISTINCT
        child_scenario_id,
        ancestor_id as root_scenario_id
    FROM scenario_ancestors
    WHERE depth = (
        SELECT MAX(depth) 
        FROM scenario_ancestors sa2 
        WHERE sa2.child_scenario_id = scenario_ancestors.child_scenario_id
    )
)
SELECT DISTINCT ss.scenario_id as parent_scenario_id
FROM simulation_scenarios ss
JOIN simulation_attempts sa ON sa.simulation_id = ss.simulation_id
JOIN attempt_chats ac ON ac.attempt_id = sa.id
JOIN chats sc ON sc.id = ac.chat_id
JOIN grades scg ON EXISTS (
    SELECT 1 FROM runs r_check
    JOIN group_runs gr_check ON gr_check.run_id = r_check.id
    JOIN groups g_check ON g_check.id = gr_check.group_id
    JOIN chat_groups cg_check ON cg_check.group_id = g_check.id
    JOIN chats c_check ON c_check.id = cg_check.chat_id AND c_check.id = sc.id
    WHERE r_check.id = scg.run_id
)
JOIN runs r_scen2 ON r_scen2.id = scg.run_id
JOIN group_runs gr_scen2 ON gr_scen2.run_id = r_scen2.id
JOIN groups g_scen2 ON g_scen2.id = gr_scen2.group_id
JOIN chat_groups cg_scen2 ON cg_scen2.group_id = g_scen2.id
JOIN chats c_scen2 ON c_scen2.id = cg_scen2.chat_id AND c_scen2.id = sc.id
LEFT JOIN root_scenarios rs ON rs.child_scenario_id = sc.scenario_id
WHERE sa.id = attempt_id
  AND (
    -- Case 1: Root scenario matches the parent scenario from simulation_scenarios
    COALESCE(rs.root_scenario_id, sc.scenario_id) = ss.scenario_id
    -- Case 2: Child scenario IS the parent scenario (no child variant)
    OR sc.scenario_id = ss.scenario_id
  )
$$;


--
-- Name: api_get_schema_with_fields_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_schema_with_fields_v4(schema_id uuid) RETURNS TABLE(schema_id uuid, field_id uuid, field_name text, field_type public.schema_field_type, required boolean, "position" integer, item_schema_id uuid)
    LANGUAGE sql STABLE
    AS $_$
SELECT
    s.id as schema_id,
    sf.id as field_id,
    sf.name as field_name,
    sf.field_type,
    sf.required,
    sf."position",
    sfi.item_schema_id
FROM schemas s
JOIN schema_fields sf ON sf.schema_id = s.id
LEFT JOIN schema_field_items sfi ON sfi.schema_field_id = sf.id
WHERE s.id = $1
ORDER BY sf."position", sf.name
$_$;


--
-- Name: api_get_settings_detail_v4(uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_settings_detail_v4(settings_id uuid, profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(settings_exists boolean, settings_id uuid, created_at timestamp with time zone, active boolean, name text, description text, primary_color text, accent text, background text, surface text, success text, warning text, error text, sidebar_background text, sidebar_primary text, chart1 text, chart2 text, chart3 text, chart4 text, chart5 text, guest_login_enabled boolean, success_threshold integer, warning_threshold integer, danger_threshold integer, auth_ids text[], auths types.q_get_settings_detail_v4_auth[], provider_ids text[], providers types.q_get_settings_detail_v4_provider[], provider_keys types.q_get_settings_detail_v4_provider_key[], auth_keys types.q_get_settings_detail_v4_auth_key[], auth_values types.q_get_settings_detail_v4_auth_value[], all_providers types.q_get_settings_detail_v4_provider[], all_auths types.q_get_settings_detail_v4_auth[], default_admin_profile_id uuid, default_admin_name text, default_guest_profile_id uuid, default_guest_name text, department_ids text[], actor_name text, draft_version integer, provider_key_mapping jsonb, auth_key_mapping jsonb, provider_enabled jsonb, auth_enabled jsonb, auth_value_mapping jsonb)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        settings_id AS settings_id, 
        profile_id AS profile_id,
        draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'settings'::draft_resource_type
    LIMIT 1
),
settings_exists_check AS (
    SELECT EXISTS(
        SELECT 1 FROM settings WHERE id = (SELECT settings_id FROM params)
    )::boolean as settings_exists
),
user_profile AS (
    SELECT 
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
settings_auths_with_items AS (
    -- Get linked auths for this settings with nested auth_items
    SELECT 
        a.id as auth_id,
        a.name,
        COALESCE(a.description, '') as description,
        a.slug,
        a.active,
        COALESCE(
            ARRAY_AGG(
                (ai.id, ai.name, COALESCE(ai.description, ''), ai.encrypted)::types.q_get_settings_detail_v4_auth_item
                ORDER BY ai.name
            ) FILTER (WHERE ai.id IS NOT NULL),
            '{}'::types.q_get_settings_detail_v4_auth_item[]
        ) as auth_items
    FROM settings s
    JOIN setting_auths sa ON sa.settings_id = s.id AND sa.active = true
    JOIN auth a ON a.id = sa.auth_id AND a.active = true
    LEFT JOIN auth_items ai ON ai.auth_id = a.id
    WHERE s.id = (SELECT settings_id FROM params)
    GROUP BY a.id, a.name, a.description, a.slug, a.active
),
settings_auths_data AS (
    -- Aggregate linked auths into array
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (sawi.auth_id, sawi.name, sawi.description, sawi.slug, sawi.active, sawi.auth_items)::types.q_get_settings_detail_v4_auth
                ORDER BY sawi.name
            ),
            '{}'::types.q_get_settings_detail_v4_auth[]
        ) as auths,
        ARRAY_AGG(sawi.auth_id::text ORDER BY sawi.auth_id::text) FILTER (WHERE sawi.auth_id IS NOT NULL) as auth_ids
    FROM settings_auths_with_items sawi
),
settings_providers_data AS (
    -- Get linked providers for this settings
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (p.id, p.name, COALESCE(p.description, ''), p.value, p.active)::types.q_get_settings_detail_v4_provider
                ORDER BY p.name
            ),
            '{}'::types.q_get_settings_detail_v4_provider[]
        ) as providers,
        ARRAY_AGG(p.id::text ORDER BY p.id::text) FILTER (WHERE p.id IS NOT NULL) as provider_ids
    FROM settings s
    JOIN setting_providers sp ON sp.settings_id = s.id AND sp.active = true
    JOIN providers p ON p.id = sp.provider_id AND p.active = true
    WHERE s.id = (SELECT settings_id FROM params)
),
all_providers_data AS (
    -- Get ALL providers (not just linked ones)
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (p.id, p.name, COALESCE(p.description, ''), p.value, p.active)::types.q_get_settings_detail_v4_provider
                ORDER BY p.name
            ),
            '{}'::types.q_get_settings_detail_v4_provider[]
        ) as all_providers
    FROM providers p
    WHERE p.active = true
),
all_auths_with_items AS (
    -- Get ALL auths (not just linked ones) with nested auth_items
    SELECT 
        a.id as auth_id,
        a.name,
        COALESCE(a.description, '') as description,
        a.slug,
        a.active,
        COALESCE(
            ARRAY_AGG(
                (ai.id, ai.name, COALESCE(ai.description, ''), ai.encrypted)::types.q_get_settings_detail_v4_auth_item
                ORDER BY ai.name
            ) FILTER (WHERE ai.id IS NOT NULL),
            '{}'::types.q_get_settings_detail_v4_auth_item[]
        ) as auth_items
    FROM auth a
    LEFT JOIN auth_items ai ON ai.auth_id = a.id
    WHERE a.active = true
    GROUP BY a.id, a.name, a.description, a.slug, a.active
),
all_auths_data AS (
    -- Aggregate all auths into array
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (aawi.auth_id, aawi.name, aawi.description, aawi.slug, aawi.active, aawi.auth_items)::types.q_get_settings_detail_v4_auth
                ORDER BY aawi.name
            ),
            '{}'::types.q_get_settings_detail_v4_auth[]
        ) as all_auths
    FROM all_auths_with_items aawi
),
settings_provider_keys_data AS (
    -- Get provider key mappings for this settings
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (spk.provider_id, spk.key_id)::types.q_get_settings_detail_v4_provider_key
                ORDER BY spk.provider_id
            ),
            '{}'::types.q_get_settings_detail_v4_provider_key[]
        ) as provider_keys
    FROM setting_provider_keys spk
    WHERE spk.settings_id = (SELECT settings_id FROM params) AND spk.active = true
),
settings_auth_keys_grouped AS (
    -- Get auth key mappings grouped by auth_id
    SELECT 
        sak.auth_id,
        COALESCE(
            ARRAY_AGG(
                (sak.auth_item_id, sak.key_id)::types.q_get_settings_detail_v4_auth_key_item
                ORDER BY sak.auth_item_id
            ) FILTER (WHERE sak.auth_item_id IS NOT NULL),
            '{}'::types.q_get_settings_detail_v4_auth_key_item[]
        ) as items
    FROM setting_auth_keys sak
    WHERE sak.settings_id = (SELECT settings_id FROM params) AND sak.active = true
    GROUP BY sak.auth_id
),
settings_auth_keys_data AS (
    -- Aggregate auth keys into array
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (sakg.auth_id, sakg.items)::types.q_get_settings_detail_v4_auth_key
                ORDER BY sakg.auth_id
            ),
            '{}'::types.q_get_settings_detail_v4_auth_key[]
        ) as auth_keys
    FROM settings_auth_keys_grouped sakg
),
settings_auth_values_grouped AS (
    -- Get auth value mappings grouped by auth_id
    SELECT 
        sav.auth_id,
        COALESCE(
            ARRAY_AGG(
                (sav.auth_item_id, sav.value)::types.q_get_settings_detail_v4_auth_value_item
                ORDER BY sav.auth_item_id
            ) FILTER (WHERE sav.auth_item_id IS NOT NULL),
            '{}'::types.q_get_settings_detail_v4_auth_value_item[]
        ) as items
    FROM setting_auth_values sav
    WHERE sav.settings_id = (SELECT settings_id FROM params)
    GROUP BY sav.auth_id
),
settings_auth_values_data AS (
    -- Aggregate auth values into array
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (savg.auth_id, savg.items)::types.q_get_settings_detail_v4_auth_value
                ORDER BY savg.auth_id
            ),
            '{}'::types.q_get_settings_detail_v4_auth_value[]
        ) as auth_values
    FROM settings_auth_values_grouped savg
),
settings_default_account_data AS (
    -- Get default admin/superadmin account for this settings
    SELECT 
        sda.profile_id as default_admin_profile_id,
        p.first_name || ' ' || p.last_name as default_admin_name
    FROM settings_default_account sda
    JOIN profiles p ON p.id = sda.profile_id
    WHERE sda.settings_id = (SELECT settings_id FROM params) AND sda.active = true
    LIMIT 1
),
settings_default_guest_data AS (
    -- Get default guest account for this settings
    SELECT 
        sdg.profile_id as default_guest_profile_id,
        p.first_name || ' ' || p.last_name as default_guest_name
    FROM settings_default_guest sdg
    JOIN profiles p ON p.id = sdg.profile_id
    WHERE sdg.settings_id = (SELECT settings_id FROM params) AND sdg.active = true
    LIMIT 1
),
settings_departments_data AS (
    -- Get linked departments for this settings
    SELECT 
        ARRAY_AGG(ds.department_id::text ORDER BY ds.created_at) as department_ids
    FROM department_settings ds
    WHERE ds.settings_id = (SELECT settings_id FROM params) AND ds.active = true
)
SELECT 
    sec.settings_exists::boolean as settings_exists,
    s.id as settings_id,
    s.created_at,
    -- Merge draft payload over existing settings data if draft_id provided
    COALESCE(
        (SELECT payload->>'active' FROM draft_payload_data),
        s.active::text,
        'true'
    )::boolean as active,
    COALESCE(
        (SELECT payload->>'name' FROM draft_payload_data),
        s.name,
        ''
    ) as name,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        s.description,
        ''
    ) as description,
    COALESCE(
        (SELECT payload->>'primary_color' FROM draft_payload_data),
        (SELECT payload->>'primaryColor' FROM draft_payload_data),
        s.primary_color,
        '#171717'
    ) as primary_color,
    COALESCE(
        (SELECT payload->>'accent' FROM draft_payload_data),
        s.accent,
        '#f5f5f5'
    ) as accent,
    COALESCE(
        (SELECT payload->>'background' FROM draft_payload_data),
        s.background,
        '#ffffff'
    ) as background,
    COALESCE(
        (SELECT payload->>'surface' FROM draft_payload_data),
        s.surface,
        '#ffffff'
    ) as surface,
    COALESCE(
        (SELECT payload->>'success' FROM draft_payload_data),
        s.success,
        '#009e34'
    ) as success,
    COALESCE(
        (SELECT payload->>'warning' FROM draft_payload_data),
        s.warning,
        '#ea8100'
    ) as warning,
    COALESCE(
        (SELECT payload->>'error' FROM draft_payload_data),
        s.error,
        '#e7000b'
    ) as error,
    COALESCE(
        (SELECT payload->>'sidebar_background' FROM draft_payload_data),
        (SELECT payload->>'sidebarBackground' FROM draft_payload_data),
        s.sidebar_background,
        '#fafafa'
    ) as sidebar_background,
    COALESCE(
        (SELECT payload->>'sidebar_primary' FROM draft_payload_data),
        (SELECT payload->>'sidebarPrimary' FROM draft_payload_data),
        s.sidebar_primary,
        '#171717'
    ) as sidebar_primary,
    COALESCE(
        (SELECT payload->>'chart1' FROM draft_payload_data),
        s.chart1,
        '#f54900'
    ) as chart1,
    COALESCE(
        (SELECT payload->>'chart2' FROM draft_payload_data),
        s.chart2,
        '#009689'
    ) as chart2,
    COALESCE(
        (SELECT payload->>'chart3' FROM draft_payload_data),
        s.chart3,
        '#104e64'
    ) as chart3,
    COALESCE(
        (SELECT payload->>'chart4' FROM draft_payload_data),
        s.chart4,
        '#ffb900'
    ) as chart4,
    COALESCE(
        (SELECT payload->>'chart5' FROM draft_payload_data),
        s.chart5,
        '#fe9a00'
    ) as chart5,
    COALESCE(
        (SELECT (payload->>'guest_login_enabled')::boolean FROM draft_payload_data),
        (SELECT (payload->>'guestLoginEnabled')::boolean FROM draft_payload_data),
        s.guest_login_enabled,
        true
    ) as guest_login_enabled,
    COALESCE(
        (SELECT (payload->>'success_threshold')::integer FROM draft_payload_data),
        (SELECT (payload->>'successThreshold')::integer FROM draft_payload_data),
        s.success_threshold,
        85
    ) as success_threshold,
    COALESCE(
        (SELECT (payload->>'warning_threshold')::integer FROM draft_payload_data),
        (SELECT (payload->>'warningThreshold')::integer FROM draft_payload_data),
        s.warning_threshold,
        80
    ) as warning_threshold,
    COALESCE(
        (SELECT (payload->>'danger_threshold')::integer FROM draft_payload_data),
        (SELECT (payload->>'dangerThreshold')::integer FROM draft_payload_data),
        s.danger_threshold,
        70
    ) as danger_threshold,
    COALESCE(sad.auth_ids, ARRAY[]::text[]) as auth_ids,
    COALESCE(sad.auths, '{}'::types.q_get_settings_detail_v4_auth[]) as auths,
    COALESCE(spd.provider_ids, ARRAY[]::text[]) as provider_ids,
    COALESCE(spd.providers, '{}'::types.q_get_settings_detail_v4_provider[]) as providers,
    COALESCE(spkd.provider_keys, '{}'::types.q_get_settings_detail_v4_provider_key[]) as provider_keys,
    COALESCE(sakd.auth_keys, '{}'::types.q_get_settings_detail_v4_auth_key[]) as auth_keys,
    COALESCE(savd.auth_values, '{}'::types.q_get_settings_detail_v4_auth_value[]) as auth_values,
    COALESCE(apd.all_providers, '{}'::types.q_get_settings_detail_v4_provider[]) as all_providers,
    COALESCE(aad.all_auths, '{}'::types.q_get_settings_detail_v4_auth[]) as all_auths,
    COALESCE(
        (SELECT (payload->>'default_admin_profile_id')::uuid FROM draft_payload_data),
        (SELECT (payload->>'defaultAdminProfileId')::uuid FROM draft_payload_data),
        sdad.default_admin_profile_id
    ) as default_admin_profile_id,
    sdad.default_admin_name,
    COALESCE(
        (SELECT (payload->>'default_guest_profile_id')::uuid FROM draft_payload_data),
        (SELECT (payload->>'defaultGuestProfileId')::uuid FROM draft_payload_data),
        sdgd.default_guest_profile_id
    ) as default_guest_profile_id,
    sdgd.default_guest_name,
    COALESCE(
        CASE 
            WHEN (SELECT payload->'department_ids' FROM draft_payload_data) IS NOT NULL AND jsonb_typeof((SELECT payload->'department_ids' FROM draft_payload_data)) = 'array' THEN
                ARRAY(SELECT jsonb_array_elements_text((SELECT payload->'department_ids' FROM draft_payload_data)))
            WHEN (SELECT payload->'departmentIds' FROM draft_payload_data) IS NOT NULL AND jsonb_typeof((SELECT payload->'departmentIds' FROM draft_payload_data)) = 'array' THEN
                ARRAY(SELECT jsonb_array_elements_text((SELECT payload->'departmentIds' FROM draft_payload_data)))
            ELSE NULL
        END,
        COALESCE(sdd.department_ids, ARRAY[]::text[])
    ) as department_ids,
    up.actor_name,
    COALESCE((SELECT draft_version FROM draft_payload_data), 0) as draft_version,
    -- Extract draft mappings (support both camelCase and snake_case)
    COALESCE(
        (SELECT payload->'provider_key_mapping' FROM draft_payload_data),
        (SELECT payload->'providerKeyMapping' FROM draft_payload_data),
        '{}'::jsonb
    ) as provider_key_mapping,
    COALESCE(
        (SELECT payload->'auth_key_mapping' FROM draft_payload_data),
        (SELECT payload->'authKeyMapping' FROM draft_payload_data),
        '{}'::jsonb
    ) as auth_key_mapping,
    COALESCE(
        (SELECT payload->'provider_enabled' FROM draft_payload_data),
        (SELECT payload->'providerEnabled' FROM draft_payload_data),
        '{}'::jsonb
    ) as provider_enabled,
    COALESCE(
        (SELECT payload->'auth_enabled' FROM draft_payload_data),
        (SELECT payload->'authEnabled' FROM draft_payload_data),
        '{}'::jsonb
    ) as auth_enabled,
    COALESCE(
        (SELECT payload->'auth_value_mapping' FROM draft_payload_data),
        (SELECT payload->'authValueMapping' FROM draft_payload_data),
        '{}'::jsonb
    ) as auth_value_mapping
FROM settings_exists_check sec
CROSS JOIN params p
LEFT JOIN settings s ON s.id = p.settings_id
LEFT JOIN settings_auths_data sad ON true
LEFT JOIN settings_providers_data spd ON true
LEFT JOIN settings_provider_keys_data spkd ON true
LEFT JOIN settings_auth_keys_data sakd ON true
LEFT JOIN settings_auth_values_data savd ON true
LEFT JOIN all_providers_data apd ON true
LEFT JOIN all_auths_data aad ON true
LEFT JOIN settings_default_account_data sdad ON true
LEFT JOIN settings_default_guest_data sdgd ON true
LEFT JOIN settings_departments_data sdd ON true
CROSS JOIN user_profile up
$$;


--
-- Name: api_get_settings_list_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_settings_list_v4(profile_id uuid) RETURNS TABLE(actor_name text, settings types.q_get_settings_list_v4_setting[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id
),
actor_profile AS (
    SELECT 
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
settings_departments_data AS (
    SELECT 
        ds.settings_id,
        ARRAY_AGG(ds.department_id::text ORDER BY ds.created_at) as department_ids
    FROM department_settings ds
    WHERE ds.active = true
    GROUP BY ds.settings_id
)
SELECT 
    ap.actor_name::text as actor_name,
    COALESCE(
        ARRAY_AGG(
            (s.id, s.created_at, s.active, s.name, s.description,
             COALESCE(sdd.department_ids, ARRAY[]::text[])
            )::types.q_get_settings_list_v4_setting
            ORDER BY s.created_at DESC
        ),
        '{}'::types.q_get_settings_list_v4_setting[]
    ) as settings
FROM settings s
CROSS JOIN actor_profile ap
LEFT JOIN settings_departments_data sdd ON sdd.settings_id = s.id
WHERE s.active = true  -- Only return active settings
GROUP BY ap.actor_name
$$;


--
-- Name: api_get_simulation_attempt_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_simulation_attempt_v4(attempt_id uuid, profile_id uuid) RETURNS TABLE(attempt_exists boolean, actor_name text, access_denied boolean, attempt types.q_get_simulation_attempt_v4_attempt, simulation types.q_get_simulation_attempt_v4_simulation, attempt_profiles types.q_get_simulation_attempt_v4_attempt_profile[], chats types.q_get_simulation_attempt_v4_chat_data[], scenario_documents types.q_get_simulation_attempt_v4_scenario_document[], aggregated_results types.q_get_simulation_attempt_v4_aggregated_results, timer types.q_get_simulation_attempt_v4_timer, current_chat_index integer, expected_chat_count integer, is_single_chat_attempt boolean, is_last_attempt boolean, show_results boolean, should_show_controls boolean, remaining_scenarios_count integer, is_last_remaining_scenario boolean, can_pick_multiple_alternatives boolean, is_active boolean, rubric_structure types.q_get_simulation_attempt_v4_rubric_structure, all_simulation_scenarios types.q_get_simulation_attempt_v4_all_simulation_scenario[], available_continuation_options types.q_get_simulation_attempt_v4_available_continuation_options)
    LANGUAGE sql STABLE
    AS $_$
WITH params AS (
    SELECT 
        attempt_id AS attempt_id,
        profile_id AS profile_id
),
attempt_exists_check AS (
    SELECT EXISTS(
        SELECT 1 FROM simulation_attempts WHERE id = (SELECT attempt_id FROM params)
    )::boolean as attempt_exists
),
actor_profile AS (
    SELECT
        p.id as profile_id,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
attempt_base AS (
    SELECT 
        sa.id,
        sa.created_at,
        sa.simulation_id,
        sa.infinite_mode,
        sa.archived,
        s.id as sim_id,
        s.title as sim_title,
        s.description as sim_description,
        (SELECT department_id FROM simulation_departments sd WHERE sd.simulation_id = s.id AND sd.active = true ORDER BY sd.created_at LIMIT 1) as sim_department_id,
        s.active as sim_active,
        s.practice_simulation as sim_practice_simulation,
        COALESCE(
            (SELECT SUM(stl.time_limit_seconds)::int
             FROM scenario_time_limits stl
             JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
             WHERE stl.simulation_id = s.id AND stl.active = true AND ss.active = true),
            0
        )::int as sim_time_limit,
        (SELECT rga.rubric_id FROM simulation_scenarios ss 
         JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
         JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
         WHERE ss.simulation_id = s.id AND ss.active = true 
         ORDER BY ss.position 
         LIMIT 1) as sim_rubric_id,
        s.created_at as sim_created_at,
        s.updated_at as sim_updated_at
    FROM params x
    JOIN simulation_attempts sa ON sa.id = x.attempt_id
    JOIN simulations s ON s.id = sa.simulation_id
),
attempt_profiles_data AS (
    SELECT COALESCE(
        ARRAY_AGG(
            (ap.profile_id, ap.attempt_id, ap.active)::types.q_get_simulation_attempt_v4_attempt_profile
            ORDER BY ap.created_at
        ),
        '{}'::types.q_get_simulation_attempt_v4_attempt_profile[]
    ) as attempt_profiles
    FROM params x
    JOIN attempt_profiles ap ON ap.attempt_id = x.attempt_id
),
current_attempt_profile AS (
    SELECT ap.profile_id
    FROM params x
    JOIN attempt_profiles ap ON ap.attempt_id = x.attempt_id AND ap.active = true
    LIMIT 1
),
-- Role-based access control: check if viewing profile's role is higher than current user's role
role_check AS (
    SELECT 
        CASE 
            WHEN cap.profile_id IS NOT NULL AND x.profile_id IS NOT NULL THEN
                CASE 
                    WHEN attempt_role_level > current_role_level THEN true
                    ELSE false
                END
            ELSE false
        END as access_denied,
        attempt_role::text as attempt_profile_role,
        current_role::text as current_user_role
    FROM params x
    CROSS JOIN current_attempt_profile cap
    CROSS JOIN LATERAL (
        SELECT role::text as attempt_role,
            CASE 
                WHEN role::text = 'superadmin' THEN 5
                WHEN role::text = 'admin' THEN 4
                WHEN role::text = 'instructional' THEN 3
                WHEN role::text = 'member' THEN 2
                ELSE 1
            END as attempt_role_level
        FROM profiles
        WHERE id = cap.profile_id
    ) attempt_profile_role_info
    CROSS JOIN LATERAL (
        SELECT role::text as current_role,
            CASE 
                WHEN role::text = 'superadmin' THEN 5
                WHEN role::text = 'admin' THEN 4
                WHEN role::text = 'instructional' THEN 3
                WHEN role::text = 'member' THEN 2
                ELSE 1
            END as current_role_level
        FROM profiles
        WHERE id = x.profile_id
    ) current_user_role_info
),
simulation_scenarios_list AS (
    SELECT ss.scenario_id, ss.position
    FROM params x
    JOIN attempt_base ab ON ab.id = x.attempt_id
    JOIN simulation_scenarios ss ON ss.simulation_id = ab.simulation_id AND ss.active = true
    ORDER BY ss.position
),
chat_ids_list AS (
    SELECT array_agg(id) as chat_ids
    FROM (
        SELECT sc.id
        FROM params x
        JOIN attempt_chats ac ON ac.attempt_id = x.attempt_id
        JOIN chats sc ON sc.id = ac.chat_id
        ORDER BY sc.created_at
    ) chats_base
),
scenario_ids_list AS (
    SELECT array_agg(DISTINCT scenario_id) as scenario_ids
    FROM (
        SELECT sc.scenario_id
        FROM params x
        JOIN attempt_chats ac ON ac.attempt_id = x.attempt_id
        JOIN chats sc ON sc.id = ac.chat_id
    ) chats_base
),
chats_base AS (
    SELECT 
        sc.id,
        sc.created_at,
        sc.updated_at,
        sc.title,
        sc.scenario_id,
        ac.attempt_id,
        sc.completed,
        g.trace_id,
        COALESCE(
            (SELECT array_agg(DISTINCT sd.document_id::text)
             FROM scenario_documents sd
             WHERE sd.scenario_id = sc.scenario_id AND sd.active = true),
            ARRAY[]::text[]
        ) as document_ids
    FROM params x
    JOIN attempt_chats ac ON ac.attempt_id = x.attempt_id
    JOIN chats sc ON sc.id = ac.chat_id
    LEFT JOIN chat_groups cg ON cg.chat_id = sc.id
    LEFT JOIN groups g ON g.id = cg.group_id
    ORDER BY sc.created_at
),
-- Get scenario videos and questions (videos now accessed through scenarios)
scenario_videos_with_questions AS (
    SELECT 
        sv.scenario_id,
        v.id as video_id,
        v.name as video_title,
        v.length_seconds,
        vu.upload_id,
        COALESCE(
            (SELECT ARRAY_AGG(
                (q.id, q.question_text, 'choice'::text, q.allow_multiple,
                 COALESCE(
                     (SELECT ARRAY_AGG(sqt.time ORDER BY sqt.time)
                      FROM scenario_question_times sqt
                      WHERE sqt.scenario_id = sv.scenario_id 
                        AND sqt.question_id = q.id 
                        AND sqt.video_id = v.id
                        AND sqt.active = true),
                     ARRAY[]::int[]
                 ),
                 COALESCE(
                     (SELECT ARRAY_AGG(
                         (o.id, o.option_text, o.type::text, CASE WHEN qa.option_id IS NOT NULL THEN true ELSE false END)::types.q_get_simulation_attempt_v4_option
                         ORDER BY o.id
                     )
                     FROM question_options qo
                     JOIN options o ON o.id = qo.option_id AND o.active = true
                     LEFT JOIN question_answers qa ON qa.question_id = q.id AND qa.option_id = o.id AND qa.active = true
                     WHERE qo.question_id = q.id AND qo.active = true),
                     '{}'::types.q_get_simulation_attempt_v4_option[]
                 )
                )::types.q_get_simulation_attempt_v4_question
                ORDER BY sq.created_at
            )
            FROM scenario_questions sq
            JOIN questions q ON q.id = sq.question_id
            WHERE sq.scenario_id = sv.scenario_id AND sq.active = true AND q.active = true),
            '{}'::types.q_get_simulation_attempt_v4_question[]
        ) as questions
    FROM scenario_videos sv
    JOIN videos v ON v.id = sv.video_id
    LEFT JOIN video_uploads vu ON vu.video_id = v.id AND vu.active = true
    WHERE sv.active = true AND v.active = true
),
-- Note: Quizzes are deprecated - questions are now handled directly through scenarios
attempt_quizzes_data AS (
    SELECT 
        q.id as quiz_id,
        q.video_id,
        q.completed as quiz_completed,
        q.created_at as quiz_created_at,
        q.updated_at as quiz_updated_at
    FROM params x
    JOIN attempt_quizzes aq ON aq.attempt_id = x.attempt_id
    JOIN quizzes q ON q.id = aq.quiz_id
),
quiz_responses_data AS (
    SELECT 
        qr.quiz_id,
        qr.question_id,
        qr.option_id,
        qr.completed as response_completed,
        qr.created_at as response_created_at
    FROM quiz_responses qr
    WHERE qr.quiz_id IN (SELECT quiz_id FROM attempt_quizzes_data)
),
quiz_responses_grouped AS (
    SELECT 
        qr.quiz_id,
        COALESCE(
            ARRAY_AGG(
                (qr.question_id, qr.option_id, qr.response_completed, qr.response_created_at)::types.q_get_simulation_attempt_v4_quiz_response
                ORDER BY qr.response_created_at
            ),
            '{}'::types.q_get_simulation_attempt_v4_quiz_response[]
        ) as responses
    FROM quiz_responses_data qr
    GROUP BY qr.quiz_id
),
simulation_root_scenarios_list AS (
    SELECT DISTINCT
        ss.scenario_id as root_scenario_id,
        ss.position
    FROM params x
    JOIN attempt_base ab ON ab.id = x.attempt_id
    JOIN simulation_scenarios ss ON ss.simulation_id = ab.simulation_id AND ss.active = true
    ORDER BY ss.position
),
-- Recursively map all child scenarios to their root parent scenarios
scenario_root_mapping AS (
    WITH RECURSIVE scenario_ancestors AS (
        SELECT DISTINCT
            sc.scenario_id as child_scenario_id,
            sc.scenario_id as ancestor_id,
            0 as depth
        FROM params x
        JOIN chats sc ON EXISTS (
            SELECT 1 FROM attempt_chats ac WHERE ac.chat_id = sc.id AND ac.attempt_id = x.attempt_id
        )
        
        UNION ALL
        
        SELECT 
            sa.child_scenario_id,
            COALESCE(
                (SELECT st.parent_id 
                 FROM scenario_tree st 
                 WHERE st.child_id = sa.ancestor_id 
                   AND st.parent_id != st.child_id 
                 LIMIT 1),
                sa.ancestor_id
            ) as ancestor_id,
            sa.depth + 1 as depth
        FROM scenario_ancestors sa
        WHERE sa.depth < 100
          AND EXISTS (
              SELECT 1 FROM scenario_tree st 
              WHERE st.child_id = sa.ancestor_id 
                AND st.parent_id != st.child_id
          )
    )
    SELECT DISTINCT
        child_scenario_id,
        ancestor_id as root_scenario_id
    FROM scenario_ancestors
    WHERE depth = (
        SELECT MAX(depth) 
        FROM scenario_ancestors sa2 
        WHERE sa2.child_scenario_id = scenario_ancestors.child_scenario_id
    )
),
-- Recursively map previous chat scenarios to their root parent scenarios
previous_chat_scenario_root_mapping AS (
    WITH RECURSIVE scenario_ancestors AS (
        SELECT DISTINCT
            sc.scenario_id as child_scenario_id,
            sc.scenario_id as ancestor_id,
            0 as depth
        FROM params x
        CROSS JOIN current_attempt_profile cap
        JOIN chats sc ON EXISTS (
            SELECT 1 FROM attempt_chats ac2
            JOIN simulation_attempts sa2 ON sa2.id = ac2.attempt_id
            JOIN attempt_profiles ap2 ON ap2.attempt_id = sa2.id AND ap2.active = true
            WHERE ac2.chat_id = sc.id
              AND ap2.profile_id = cap.profile_id
              AND sc.completed = true
              AND EXISTS (
                  SELECT 1 FROM grades scg 
                  JOIN runs r ON r.id = scg.run_id
                  JOIN group_runs gr ON gr.run_id = r.id
                  JOIN groups g ON g.id = gr.group_id
                  JOIN chat_groups cg ON cg.group_id = g.id
                  JOIN chats c ON c.id = cg.chat_id
                  WHERE c.id = sc.id 
                    AND EXISTS (
                        SELECT 1 FROM runs r_check
                        JOIN group_runs gr_check ON gr_check.run_id = r_check.id
                        JOIN groups g_check ON g_check.id = gr_check.group_id
                        JOIN chat_groups cg_check ON cg_check.group_id = g_check.id
                        JOIN chats c_check ON c_check.id = cg_check.chat_id
                        WHERE r_check.id = scg.run_id
                    )
              )
              AND ac2.attempt_id != x.attempt_id
        )
        
        UNION ALL
        
        SELECT 
            sa.child_scenario_id,
            COALESCE(
                (SELECT st.parent_id 
                 FROM scenario_tree st 
                 WHERE st.child_id = sa.ancestor_id 
                   AND st.parent_id != st.child_id 
                 LIMIT 1),
                sa.ancestor_id
            ) as ancestor_id,
            sa.depth + 1 as depth
        FROM scenario_ancestors sa
        WHERE sa.depth < 100
          AND EXISTS (
              SELECT 1 FROM scenario_tree st 
              WHERE st.child_id = sa.ancestor_id 
                AND st.parent_id != st.child_id
          )
    )
    SELECT DISTINCT
        child_scenario_id,
        ancestor_id as root_scenario_id
    FROM scenario_ancestors
    WHERE depth = (
        SELECT MAX(depth) 
        FROM scenario_ancestors sa2 
        WHERE sa2.child_scenario_id = scenario_ancestors.child_scenario_id
    )
),
-- Find previous completed chats from other attempts by same profile
previous_chats_with_grades AS (
    SELECT DISTINCT ON (sc.id)
        sc.id as chat_id,
        sc.scenario_id as child_scenario_id,
        COALESCE(
            (SELECT pcsrm.root_scenario_id 
             FROM previous_chat_scenario_root_mapping pcsrm 
             WHERE pcsrm.child_scenario_id = sc.scenario_id),
            sc.scenario_id
        ) as parent_scenario_id,
        ac2.attempt_id,
        sa2.simulation_id,
        sc.title,
        sc.created_at,
        scg.score,
        scg.passed,
        scg.time_taken
    FROM params x
    CROSS JOIN current_attempt_profile cap
    CROSS JOIN simulation_scenarios_list ssl
    CROSS JOIN attempt_base ab
    JOIN chats sc ON EXISTS (
        SELECT 1 FROM attempt_chats ac2
        JOIN simulation_attempts sa2 ON sa2.id = ac2.attempt_id
        JOIN attempt_profiles ap2 ON ap2.attempt_id = sa2.id AND ap2.active = true
        WHERE ac2.chat_id = sc.id
          AND ap2.profile_id = cap.profile_id
          AND sc.completed = true
          AND EXISTS (
              SELECT 1 FROM grades scg 
              JOIN runs r ON r.id = scg.run_id
              JOIN group_runs gr ON gr.run_id = r.id
              JOIN groups g ON g.id = gr.group_id
              JOIN chat_groups cg ON cg.group_id = g.id
              JOIN chats c ON c.id = cg.chat_id
              WHERE c.id = sc.id
          )
          AND ac2.attempt_id != x.attempt_id
          AND ab.sim_practice_simulation = false
    )
    JOIN attempt_chats ac2 ON EXISTS (
        SELECT 1 FROM chats c_check WHERE c_check.id = sc.id
    ) AND EXISTS (
        SELECT 1 FROM simulation_attempts sa_check WHERE sa_check.id = ac2.attempt_id
    )
    JOIN simulation_attempts sa2 ON sa2.id = ac2.attempt_id
    JOIN attempt_profiles ap2 ON ap2.attempt_id = sa2.id AND ap2.active = true
    LEFT JOIN grades scg ON EXISTS (
        SELECT 1 FROM runs r_check
        JOIN group_runs gr_check ON gr_check.run_id = r_check.id
        JOIN groups g_check ON g_check.id = gr_check.group_id
        JOIN chat_groups cg_check ON cg_check.group_id = g_check.id
        JOIN chats c_check ON c_check.id = cg_check.chat_id
        WHERE r_check.id = scg.run_id AND c_check.id = sc.id
    )
    WHERE ap2.profile_id = cap.profile_id
      AND sc.completed = true
      AND COALESCE(
            (SELECT pcsrm.root_scenario_id 
             FROM previous_chat_scenario_root_mapping pcsrm 
             WHERE pcsrm.child_scenario_id = sc.scenario_id),
            sc.scenario_id
        ) = ssl.scenario_id
      AND ac2.attempt_id != x.attempt_id
      AND ab.sim_practice_simulation = false
    ORDER BY sc.id, scg.created_at DESC NULLS LAST
),
previous_attempt_time_aggregation AS (
    SELECT 
        ac.attempt_id,
        COALESCE(SUM(scg.time_taken), 0)::integer as total_time_taken
    FROM previous_chats_with_grades pwg
    JOIN attempt_chats ac ON ac.attempt_id = pwg.attempt_id
    JOIN chats sc ON sc.id = ac.chat_id
    JOIN grades scg ON EXISTS (
        SELECT 1 FROM runs r_check
        JOIN group_runs gr_check ON gr_check.run_id = r_check.id
        JOIN groups g_check ON g_check.id = gr_check.group_id
        JOIN chat_groups cg_check ON cg_check.group_id = g_check.id
        JOIN chats c_check ON c_check.id = cg_check.chat_id
        WHERE r_check.id = scg.run_id AND c_check.id = sc.id
    )
    WHERE sc.completed = true
    GROUP BY ac.attempt_id
),
previous_attempt_rubric_points AS (
    SELECT DISTINCT ON (sa.simulation_id)
        sa.simulation_id,
        COALESCE(r.points, 0)::integer as total_points
    FROM previous_chats_with_grades pwg
    JOIN simulation_attempts sa ON sa.id = pwg.attempt_id
    JOIN simulations s ON s.id = sa.simulation_id
    LEFT JOIN simulation_scenarios ss_rubric ON ss_rubric.simulation_id = s.id AND ss_rubric.active = true
    LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga_rubric ON ssrga_rubric.simulation_id = ss_rubric.simulation_id AND ssrga_rubric.scenario_id = ss_rubric.scenario_id
    LEFT JOIN rubric_grade_agents rga_rubric ON rga_rubric.id = ssrga_rubric.rubric_grade_agent_id
    LEFT JOIN rubrics r ON r.id = rga_rubric.rubric_id
    ORDER BY sa.simulation_id
),
previous_chats_for_scenarios AS (
    SELECT 
        pwg.parent_scenario_id as scenario_id,
        COALESCE(
            ARRAY_AGG(
                (pwg.chat_id, pwg.attempt_id, pwg.score::float, pwg.passed, pwg.created_at, pwg.title, 
                 COALESCE(pwg.time_taken, 0)::float, 
                 COALESCE(parp.total_points, 0)::float,
                 CASE 
                     WHEN pwg.score IS NOT NULL AND parp.total_points > 0 THEN
                         ROUND((pwg.score::numeric / parp.total_points::numeric) * 100.0)::float
                     ELSE NULL::float
                 END
                )::types.q_get_simulation_attempt_v4_previous_chat
                ORDER BY pwg.created_at DESC
            ),
            '{}'::types.q_get_simulation_attempt_v4_previous_chat[]
        ) as previous_chats
    FROM previous_chats_with_grades pwg
    LEFT JOIN previous_attempt_time_aggregation pat ON pat.attempt_id = pwg.attempt_id
    LEFT JOIN previous_attempt_rubric_points parp ON parp.simulation_id = pwg.simulation_id
    GROUP BY pwg.parent_scenario_id
),
scenario_background_images_for_simulation AS (
    SELECT DISTINCT ON (si.scenario_id)
        si.scenario_id,
        iu.upload_id as background_image_upload_id
    FROM params x
    JOIN attempt_base ab ON ab.id = x.attempt_id
    JOIN scenario_images si ON EXISTS (
        SELECT 1 FROM simulation_scenarios ss 
        WHERE ss.simulation_id = ab.simulation_id 
          AND ss.scenario_id = si.scenario_id 
          AND ss.active = true
    )
    JOIN images i ON i.id = si.image_id AND i.active = true
    LEFT JOIN image_uploads iu ON iu.image_id = i.id AND iu.active = true
    WHERE si.active = true
      AND iu.upload_id IS NOT NULL
    ORDER BY si.scenario_id, si.created_at ASC
),
all_simulation_scenarios_with_previous_chats AS (
    SELECT 
        ssl.scenario_id,
        ssl.position,
        (s.id, s.name, COALESCE(ps.problem_statement, ''),
         COALESCE((SELECT department_id FROM scenario_departments sd WHERE sd.scenario_id = s.id AND sd.active = true ORDER BY sd.created_at LIMIT 1), NULL::uuid),
         s.active,
         sp.persona_id,
         p.name,
         p.icon,
         p.color,
         s.created_at,
         s.updated_at,
         s.generated,
         false,
         COALESCE(ss.copy_paste_allowed, false),
         COALESCE(ss.text_enabled, true),
         COALESCE(ss.audio_enabled, false),
         COALESCE(ss.show_problem_statement, true),
         COALESCE(ss.show_objectives, true),
         COALESCE(ss.show_images, true),
         sbi.background_image_upload_id,
         COALESCE(
             (SELECT ARRAY_AGG(o.objective ORDER BY so.idx)
              FROM scenario_objectives so
              JOIN objectives o ON o.id = so.objective_id
              WHERE so.scenario_id = s.id),
             ARRAY[]::text[]
         )
        )::types.q_get_simulation_attempt_v4_scenario as scenario_data,
        COALESCE(pcf.previous_chats, '{}'::types.q_get_simulation_attempt_v4_previous_chat[]) as previous_chats
    FROM simulation_scenarios_list ssl
    LEFT JOIN simulation_scenarios ss ON ss.scenario_id = ssl.scenario_id AND ss.simulation_id = (SELECT simulation_id FROM attempt_base)
    LEFT JOIN scenarios s ON s.id = ssl.scenario_id
    LEFT JOIN scenario_problem_statements sps ON sps.scenario_id = s.id AND sps.active = true
    LEFT JOIN problem_statements ps ON ps.id = sps.problem_statement_id
    LEFT JOIN scenario_personas sp ON sp.scenario_id = s.id AND sp.active = true
    LEFT JOIN personas p ON p.id = sp.persona_id
    LEFT JOIN scenario_background_images_for_simulation sbi ON sbi.scenario_id = s.id
    LEFT JOIN previous_chats_for_scenarios pcf ON pcf.scenario_id = ssl.scenario_id
    ORDER BY ssl.position
),
scenario_background_images_for_chats AS (
    SELECT DISTINCT ON (si.scenario_id)
        si.scenario_id,
        iu.upload_id as background_image_upload_id
    FROM scenario_images si
    JOIN images i ON i.id = si.image_id AND i.active = true
    LEFT JOIN image_uploads iu ON iu.image_id = i.id AND iu.active = true
    CROSS JOIN scenario_ids_list sil
    WHERE si.scenario_id = ANY(sil.scenario_ids) 
      AND si.active = true
      AND iu.upload_id IS NOT NULL
    ORDER BY si.scenario_id, si.created_at ASC
),
scenarios_data AS (
    SELECT 
        s.id,
        (s.id, s.name, COALESCE(ps.problem_statement, ''),
         COALESCE((SELECT department_id FROM scenario_departments sd WHERE sd.scenario_id = s.id AND sd.active = true ORDER BY sd.created_at LIMIT 1), NULL::uuid),
         s.active,
         sp.persona_id,
         p.name,
         p.icon,
         p.color,
         s.created_at,
         s.updated_at,
         s.generated,
         false,
         COALESCE(ss.copy_paste_allowed, false),
         COALESCE(ss.text_enabled, true),
         COALESCE(ss.audio_enabled, false),
         COALESCE(ss.show_problem_statement, true),
         COALESCE(ss.show_objectives, true),
         COALESCE(ss.show_images, true),
         sbi.background_image_upload_id,
         COALESCE(
             (SELECT ARRAY_AGG(o.objective ORDER BY so.idx)
              FROM scenario_objectives so
              JOIN objectives o ON o.id = so.objective_id
              WHERE so.scenario_id = s.id),
             ARRAY[]::text[]
         )
        )::types.q_get_simulation_attempt_v4_scenario as scenario_data,
        COALESCE(ss.hints_enabled, false) as hints_enabled,
        COALESCE(s.objectives_enabled, true) as objectives_enabled,
        COALESCE(s.images_enabled, false) as image_input_enabled,
        COALESCE(ss.copy_paste_allowed, false) as copy_paste_allowed
    FROM scenarios s
    CROSS JOIN scenario_ids_list sil
    CROSS JOIN attempt_base ab
    LEFT JOIN simulation_scenarios ss ON ss.scenario_id = s.id AND ss.simulation_id = ab.simulation_id
    LEFT JOIN scenario_problem_statements sps ON sps.scenario_id = s.id AND sps.active = true
    LEFT JOIN problem_statements ps ON ps.id = sps.problem_statement_id
    LEFT JOIN scenario_personas sp ON sp.scenario_id = s.id AND sp.active = true
    LEFT JOIN personas p ON p.id = sp.persona_id
    LEFT JOIN scenario_background_images_for_chats sbi ON sbi.scenario_id = s.id
    WHERE s.id = ANY(sil.scenario_ids)
),
simulation_flags AS (
    SELECT 
        COALESCE((SELECT ss.hints_enabled FROM simulation_scenarios ss JOIN chats_base cb ON ss.scenario_id = cb.scenario_id CROSS JOIN attempt_base ab WHERE ss.simulation_id = ab.simulation_id ORDER BY cb.created_at LIMIT 1), false) as hints_enabled,
        COALESCE((SELECT s.objectives_enabled FROM simulation_scenarios ss JOIN chats_base cb ON ss.scenario_id = cb.scenario_id JOIN scenarios s ON s.id = ss.scenario_id CROSS JOIN attempt_base ab WHERE ss.simulation_id = ab.simulation_id ORDER BY cb.created_at LIMIT 1), true) as objectives_enabled,
        COALESCE((SELECT s.images_enabled FROM simulation_scenarios ss JOIN chats_base cb ON ss.scenario_id = cb.scenario_id JOIN scenarios s ON s.id = ss.scenario_id CROSS JOIN attempt_base ab WHERE ss.simulation_id = ab.simulation_id ORDER BY cb.created_at LIMIT 1), false) as image_input_enabled,
        COALESCE((SELECT ss.copy_paste_allowed FROM simulation_scenarios ss JOIN chats_base cb ON ss.scenario_id = cb.scenario_id CROSS JOIN attempt_base ab WHERE ss.simulation_id = ab.simulation_id ORDER BY cb.created_at LIMIT 1), false) as copy_paste_allowed
),
-- Tree traversal for messages: get all messages following conversation flow
messages_with_tree AS (
    WITH RECURSIVE message_path AS (
        SELECT 
            m.id, 
            c.id AS chat_id, 
            CASE WHEN m.role = 'user'::message_role THEN 'query' ELSE 'response' END as type, 
            cnt.content, 
            m.created_at, 
            m.completed, 
            m.updated_at,
            mp_persona.persona_id,
            0 as depth,
            m.id as path_root_id
        FROM chats c
        JOIN chat_groups cg ON cg.chat_id = c.id
        JOIN groups g ON g.id = cg.group_id
        JOIN group_runs gr ON gr.group_id = g.id
        JOIN runs r ON r.id = gr.run_id
        JOIN message_runs mr ON mr.run_id = r.id
        JOIN messages m ON m.id = mr.message_id
        LEFT JOIN message_content mc ON mc.message_id = m.id AND mc.idx = 0
        LEFT JOIN content cnt ON cnt.id = mc.content_id
        LEFT JOIN message_personas mp_persona ON mp_persona.message_id = m.id
        CROSS JOIN chat_ids_list cil
        WHERE c.id = ANY(cil.chat_ids)
          AND m.role IN ('user'::message_role, 'assistant'::message_role)
          AND NOT EXISTS (
              SELECT 1 FROM message_tree mt 
              WHERE mt.parent_id = m.id AND mt.active = true
          )
        
        UNION ALL
        
        SELECT 
            m.id, 
            mp.chat_id, 
            CASE WHEN m.role = 'user'::message_role THEN 'query' ELSE 'response' END as type, 
            cnt.content, 
            m.created_at, 
            m.completed, 
            m.updated_at,
            mp_persona.persona_id,
            mp.depth + 1 as depth,
            mp.path_root_id
        FROM messages m
        LEFT JOIN message_content mc ON mc.message_id = m.id AND mc.idx = 0
        LEFT JOIN content cnt ON cnt.id = mc.content_id
        JOIN message_tree mt ON mt.parent_id = m.id AND mt.active = true
        JOIN message_path mp ON mp.id = mt.child_id
        JOIN message_runs mr ON mr.message_id = m.id
        JOIN runs r ON r.id = mr.run_id
        JOIN group_runs gr ON gr.run_id = r.id
        JOIN groups g ON g.id = gr.group_id
        JOIN chat_groups cg ON cg.group_id = g.id
        JOIN chats c ON c.id = cg.chat_id
        LEFT JOIN message_personas mp_persona ON mp_persona.message_id = m.id
        CROSS JOIN chat_ids_list cil
        WHERE mp.depth < 1000
          AND m.role IN ('user'::message_role, 'assistant'::message_role)
          AND c.id = mp.chat_id
          AND c.id = ANY(cil.chat_ids)
    ),
    messages_without_parents AS (
        SELECT 
            m.id, 
            c.id AS chat_id, 
            CASE WHEN m.role = 'user'::message_role THEN 'query' ELSE 'response' END as type, 
            cnt.content, 
            m.created_at, 
            m.completed, 
            m.updated_at,
            mp_persona.persona_id,
            -1 as depth,
            m.id as path_root_id
        FROM chats c
        JOIN chat_groups cg ON cg.chat_id = c.id
        JOIN groups g ON g.id = cg.group_id
        JOIN group_runs gr ON gr.group_id = g.id
        JOIN runs r ON r.id = gr.run_id
        JOIN message_runs mr ON mr.run_id = r.id
        JOIN messages m ON m.id = mr.message_id
        LEFT JOIN message_content mc ON mc.message_id = m.id AND mc.idx = 0
        LEFT JOIN content cnt ON cnt.id = mc.content_id
        LEFT JOIN message_personas mp_persona ON mp_persona.message_id = m.id
        CROSS JOIN chat_ids_list cil
        WHERE c.id = ANY(cil.chat_ids)
          AND m.role IN ('user'::message_role, 'assistant'::message_role)
          AND NOT EXISTS (
              SELECT 1 FROM message_tree mt 
              WHERE mt.child_id = m.id AND mt.active = true
          )
          AND NOT EXISTS (
              SELECT 1 FROM message_path mp 
              WHERE mp.id = m.id
          )
    ),
    all_messages AS (
        SELECT * FROM message_path
        UNION ALL
        SELECT * FROM messages_without_parents
    )
    SELECT DISTINCT ON (id, chat_id)
        id,
        chat_id,
        type,
        content,
        created_at,
        completed,
        updated_at,
        persona_id
    FROM all_messages
    ORDER BY id, chat_id, created_at
),
grades_data AS (
    SELECT DISTINCT ON (c.id)
        c.id as chat_id,
        (scg.id, scg.created_at, c.id, rga.rubric_id, scg.description, scg.passed, scg.score, scg.time_taken)::types.q_get_simulation_attempt_v4_grade as grade
    FROM params x
    JOIN chats c ON EXISTS (
        SELECT 1 FROM chat_groups cg2
        JOIN groups g2 ON g2.id = cg2.group_id
        JOIN group_runs gr2 ON gr2.group_id = g2.id
        JOIN runs r2 ON r2.id = gr2.run_id
        WHERE cg2.chat_id = c.id
    )
    CROSS JOIN chat_ids_list cil
    JOIN chat_groups cg ON cg.chat_id = c.id
    JOIN groups g ON g.id = cg.group_id
    JOIN group_runs gr ON gr.group_id = g.id
    JOIN runs r ON r.id = gr.run_id
    JOIN grades scg ON scg.run_id = r.id
    LEFT JOIN rubric_grade_agents rga ON rga.id = scg.rubric_grade_agent_id
    WHERE EXISTS (
        SELECT 1 FROM runs r_check
        JOIN group_runs gr_check ON gr_check.run_id = r_check.id
        JOIN groups g_check ON g_check.id = gr_check.group_id
        JOIN chat_groups cg_check ON cg_check.group_id = g_check.id
        JOIN chats c_check ON c_check.id = cg_check.chat_id
        WHERE r_check.id = scg.run_id AND c_check.id = c.id
    )
      AND c.id = ANY(cil.chat_ids)
    ORDER BY c.id, scg.created_at DESC
),
message_feedbacks_data AS (
    -- Strengths with highlights
    SELECT 
        mfs.message_id,
        mfs.grade_id,
        (mfs.id, mfs.name, mfs.description,
         '{}'::types.q_get_simulation_attempt_v4_message_feedback_replace[],
         COALESCE(
             (SELECT ARRAY_AGG((mfh.section)::types.q_get_simulation_attempt_v4_message_feedback_highlight ORDER BY mfh.idx)
                        FROM message_feedback_highlight mfh
                        WHERE mfh.message_feedback_id = mfs.id),
             '{}'::types.q_get_simulation_attempt_v4_message_feedback_highlight[]
         )
        )::types.q_get_simulation_attempt_v4_message_feedback as feedback_data
    FROM message_feedback_strengths mfs
    WHERE mfs.grade_id IN (SELECT (gd.grade).id FROM grades_data gd)
    UNION ALL
    -- Improvements with replaces
    SELECT 
        mfi.message_id,
        mfi.grade_id,
        (mfi.id, mfi.name, mfi.description,
         COALESCE(
             (SELECT ARRAY_AGG((mfr.section, mfr.replace)::types.q_get_simulation_attempt_v4_message_feedback_replace ORDER BY mfr.idx)
                        FROM message_feedback_replace mfr
                        WHERE mfr.message_feedback_id = mfi.id),
             '{}'::types.q_get_simulation_attempt_v4_message_feedback_replace[]
         ),
         '{}'::types.q_get_simulation_attempt_v4_message_feedback_highlight[]
        )::types.q_get_simulation_attempt_v4_message_feedback as feedback_data
    FROM message_feedback_improvements mfi
    WHERE mfi.grade_id IN (SELECT (gd.grade).id FROM grades_data gd)
),
message_feedbacks_grouped AS (
    SELECT 
        mfd.message_id,
        COALESCE(
            ARRAY_AGG(mfd.feedback_data ORDER BY (mfd.feedback_data).id),
            '{}'::types.q_get_simulation_attempt_v4_message_feedback[]
        ) as feedbacks
    FROM message_feedbacks_data mfd
    GROUP BY mfd.message_id
),
messages_grouped AS (
    SELECT 
        mwt.chat_id,
        COALESCE(
            ARRAY_AGG(
                (mwt.id, mwt.created_at, mwt.updated_at, mwt.chat_id, mwt.content, mwt.type, mwt.completed, mwt.persona_id,
                 COALESCE(mfg.feedbacks, '{}'::types.q_get_simulation_attempt_v4_message_feedback[])
                )::types.q_get_simulation_attempt_v4_message
                ORDER BY mwt.created_at
            ),
            '{}'::types.q_get_simulation_attempt_v4_message[]
        ) as messages
    FROM messages_with_tree mwt
    LEFT JOIN message_feedbacks_grouped mfg ON mfg.message_id = mwt.id
    GROUP BY mwt.chat_id
),
personas_per_chat AS (
    SELECT 
        cb.id as chat_id,
        COALESCE(
            ARRAY_AGG((p.id, p.name, p.icon, p.color)::types.q_get_simulation_attempt_v4_persona ORDER BY p.name)
            FILTER (WHERE p.id IS NOT NULL),
            '{}'::types.q_get_simulation_attempt_v4_persona[]
        ) as personas
    FROM chats_base cb
    LEFT JOIN scenario_personas sp ON sp.scenario_id = cb.scenario_id AND sp.active = true
    LEFT JOIN personas p ON p.id = sp.persona_id AND p.active = true
    GROUP BY cb.id
),
hints_data AS (
    SELECT 
        c.id AS chat_id,
        COALESCE(
            ARRAY_AGG(
                (m.id,
                 COALESCE(
                     (SELECT ARRAY_AGG(
                         (sh.simulation_message_id, sh.hint, sh.idx, sh.created_at)::types.q_get_simulation_attempt_v4_hint
                         ORDER BY sh.idx
                     )
                     FROM simulation_hints sh
                     WHERE sh.simulation_message_id = m.id),
                     '{}'::types.q_get_simulation_attempt_v4_hint[]
                 )
                )::types.q_get_simulation_attempt_v4_hints_by_message
            ) FILTER (WHERE m.role = 'assistant'::message_role),
            '{}'::types.q_get_simulation_attempt_v4_hints_by_message[]
        ) as hints
    FROM params x
    CROSS JOIN attempt_base ab
    JOIN chats c ON EXISTS (
        SELECT 1 FROM chat_groups cg
        JOIN groups g ON g.id = cg.group_id
        JOIN group_runs gr ON gr.group_id = g.id
        JOIN runs r ON r.id = gr.run_id
        JOIN message_runs mr ON mr.run_id = r.id
        WHERE cg.chat_id = c.id
    )
    JOIN chat_groups cg ON cg.chat_id = c.id
    JOIN groups g ON g.id = cg.group_id
    JOIN group_runs gr ON gr.group_id = g.id
    JOIN runs r ON r.id = gr.run_id
    JOIN message_runs mr ON mr.run_id = r.id
    JOIN messages m ON m.id = mr.message_id
    CROSS JOIN chat_ids_list cil
    WHERE c.id = ANY(cil.chat_ids)
      AND m.role IN ('user'::message_role, 'assistant'::message_role)
      AND ab.sim_practice_simulation = true
    GROUP BY c.id
),
feedbacks_grouped AS (
    SELECT 
        scf.grade_id as grade_id,
        COALESCE(
            ARRAY_AGG(
                (scf.id, scf.created_at, scf.standard_id, scf.grade_id, scf.total::float, scf.feedback)::types.q_get_simulation_attempt_v4_feedback
            ),
            '{}'::types.q_get_simulation_attempt_v4_feedback[]
        ) as feedbacks
    FROM feedbacks scf
    WHERE scf.grade_id IN (
        SELECT (gd.grade).id FROM grades_data gd
    )
    GROUP BY scf.grade_id
),
rubric_standard_groups AS (
    SELECT 
        sg.id,
        sg.name,
        sg.short_name,
        sg.points,
        sg.pass_points,
        sg.description,
        rsg.rubric_id
    FROM attempt_base ab
    JOIN rubric_standard_groups rsg ON rsg.rubric_id = ab.sim_rubric_id AND rsg.active = true
    JOIN standard_groups sg ON sg.id = rsg.standard_group_id
    WHERE ab.sim_rubric_id IS NOT NULL
),
rubric_standards_grouped AS (
    SELECT 
        s.standard_group_id,
        array_agg(s.id::text) as standard_ids,
        ARRAY_AGG(
            (s.id, s.name, s.points, s.standard_group_id)::types.q_get_simulation_attempt_v4_standard
        ) as standards_list
    FROM standards s
    WHERE s.standard_group_id IN (SELECT id FROM rubric_standard_groups)
    GROUP BY s.standard_group_id
),
standards_mapping_merged AS (
    SELECT 
        ARRAY_AGG(
            (s.id, s.name, COALESCE(s.description, ''), s.points)::types.q_get_simulation_attempt_v4_standard_mapping
        ) as standards_mapping
    FROM standards s
    WHERE s.standard_group_id IN (SELECT id FROM rubric_standard_groups)
),
rubric_structure_complete AS (
    SELECT 
        CASE 
            WHEN EXISTS (SELECT 1 FROM rubric_standard_groups) THEN
                (COALESCE(
                    (SELECT ARRAY_AGG(
                        (rsg.id, rsgroup.standard_ids)::types.q_get_simulation_attempt_v4_standard_group_standards
                    )
                    FROM rubric_standard_groups rsg
                    LEFT JOIN rubric_standards_grouped rsgroup ON rsgroup.standard_group_id = rsg.id),
                    '{}'::types.q_get_simulation_attempt_v4_standard_group_standards[]
                ),
                COALESCE(
                    (SELECT ARRAY_AGG(
                        (rsg.id, rsg.name, COALESCE(rsg.description, ''), rsg.points, rsg.pass_points)::types.q_get_simulation_attempt_v4_standard_group_mapping
                    )
                    FROM rubric_standard_groups rsg),
                    '{}'::types.q_get_simulation_attempt_v4_standard_group_mapping[]
                ),
                COALESCE(smm.standards_mapping, '{}'::types.q_get_simulation_attempt_v4_standard_mapping[])
                )::types.q_get_simulation_attempt_v4_rubric_structure
            ELSE NULL
        END as rubric_structure
    FROM standards_mapping_merged smm
),
scenario_documents_data AS (
    SELECT COALESCE(
        ARRAY_AGG(DISTINCT
            (d.id, d.name, ''::text, d.updated_at,
             COALESCE(SUBSTRING(u.file_path FROM '\\.([^\\.]+)$'), ''),
             COALESCE(
                 (SELECT array_agg(DISTINCT st.parent_id::text)
                  FROM scenario_documents sd2
                  JOIN scenario_tree st ON st.child_id = sd2.scenario_id AND st.parent_id = st.child_id
                  WHERE sd2.document_id = d.id AND sd2.active = true),
                 ARRAY[]::text[]
             ),
             false,
             false,
             d.active,
             COALESCE(
                 (SELECT array_agg(dd.department_id::text ORDER BY dd.created_at)
                  FROM document_departments dd 
                  WHERE dd.document_id = d.id AND dd.active = true),
                 NULL::text[]
             ),
             u.file_path,
             u.mime_type,
             du.upload_id,
             COALESCE(
                 (SELECT array_agg(DISTINCT df.field_id::text)
                  FROM document_fields df
                  WHERE df.document_id = d.id AND df.active = true),
                 ARRAY[]::text[]
             )
            )::types.q_get_simulation_attempt_v4_scenario_document
        ),
        '{}'::types.q_get_simulation_attempt_v4_scenario_document[]
    ) as scenario_documents
    FROM documents d
    LEFT JOIN document_uploads du ON du.document_id = d.id AND du.active = true
    LEFT JOIN uploads u ON u.id = du.upload_id
    JOIN scenario_documents sd ON sd.document_id = d.id
    CROSS JOIN scenario_ids_list sil
    WHERE sd.scenario_id = ANY(sil.scenario_ids) AND d.active = true
),
skill_scores_per_chat AS (
    SELECT 
        gd.chat_id,
        rsg.id as group_id,
        rsg.name as group_name,
        rsg.short_name,
        AVG(fb.total) as avg_score,
        MAX(std.points) as max_points,
        string_agg(COALESCE(fb.feedback, ''), '; ') as feedbacks_text
    FROM grades_data gd
    LEFT JOIN feedbacks_grouped fg ON fg.grade_id = (gd.grade).id
    CROSS JOIN rubric_standard_groups rsg
    JOIN rubric_standards_grouped rsgroup ON rsgroup.standard_group_id = rsg.id
    CROSS JOIN LATERAL unnest(rsgroup.standards_list) std
    CROSS JOIN LATERAL unnest(COALESCE(fg.feedbacks, '{}'::types.q_get_simulation_attempt_v4_feedback[])) fb
    WHERE fb.standard_id = std.id
    GROUP BY gd.chat_id, rsg.id, rsg.name, rsg.short_name
),
dynamic_rubric_per_chat AS (
    SELECT 
        gd.chat_id,
        CASE 
            WHEN gd.grade IS NOT NULL AND EXISTS (SELECT 1 FROM rubric_standard_groups) THEN
                (gd.chat_id,
                 (gd.grade).score::float,
                 (gd.grade).passed,
                 (gd.grade).time_taken::float,
                 COALESCE(
                     (SELECT ARRAY_AGG(
                         (sspc.group_name, ROUND((sspc.avg_score / sspc.max_points) * 5)::float)::types.q_get_simulation_attempt_v4_skill_score
                     )
                     FROM skill_scores_per_chat sspc
                     WHERE sspc.chat_id = gd.chat_id),
                     '{}'::types.q_get_simulation_attempt_v4_skill_score[]
                 ),
                 COALESCE(
                     (SELECT ARRAY_AGG(
                         (sspc.short_name, sspc.feedbacks_text)::types.q_get_simulation_attempt_v4_skill_feedback
                     )
                     FROM skill_scores_per_chat sspc
                     WHERE sspc.chat_id = gd.chat_id),
                     '{}'::types.q_get_simulation_attempt_v4_skill_feedback[]
                 ),
                 COALESCE(
                     (SELECT r.points FROM rubrics r 
                      CROSS JOIN attempt_base ab 
                      WHERE r.id = ab.sim_rubric_id),
                     0
                 )::float
                )::types.q_get_simulation_attempt_v4_dynamic_rubric
            ELSE NULL
        END as dynamic_rubric
    FROM grades_data gd
),
max_scores_per_group_chat AS (
    SELECT 
        gd.chat_id,
        s.standard_group_id,
        MAX(fb.total) as max_score,
        rsg.pass_points
    FROM grades_data gd
    LEFT JOIN feedbacks_grouped fg ON fg.grade_id = (gd.grade).id
    CROSS JOIN LATERAL unnest(COALESCE(fg.feedbacks, '{}'::types.q_get_simulation_attempt_v4_feedback[])) fb
    JOIN standards s ON s.id = fb.standard_id
    JOIN rubric_standard_groups rsg ON rsg.id = s.standard_group_id
    GROUP BY gd.chat_id, s.standard_group_id, rsg.pass_points
),
grading_state_per_chat AS (
    SELECT 
        gd.chat_id,
        CASE 
            WHEN gd.grade IS NOT NULL AND EXISTS (SELECT 1 FROM rubric_standard_groups) THEN
                (                COALESCE(
                    (SELECT ARRAY_AGG(
                        (fb.standard_id, true)::types.q_get_simulation_attempt_v4_standard_achievement
                    )
                    FROM feedbacks_grouped fg2
                    CROSS JOIN LATERAL unnest(COALESCE(fg2.feedbacks, '{}'::types.q_get_simulation_attempt_v4_feedback[])) fb
                    WHERE fg2.grade_id = (gd.grade).id),
                    '{}'::types.q_get_simulation_attempt_v4_standard_achievement[]
                ),
                COALESCE(
                    (SELECT ARRAY_AGG(
                        (fb.standard_id, (fb.total >= mspgc.pass_points)::boolean)::types.q_get_simulation_attempt_v4_standard_pass
                    )
                    FROM feedbacks_grouped fg3
                    CROSS JOIN LATERAL unnest(COALESCE(fg3.feedbacks, '{}'::types.q_get_simulation_attempt_v4_feedback[])) fb
                    JOIN standards s ON s.id = fb.standard_id
                    LEFT JOIN max_scores_per_group_chat mspgc 
                        ON mspgc.chat_id = gd.chat_id 
                        AND mspgc.standard_group_id = s.standard_group_id
                    WHERE fg3.grade_id = (gd.grade).id),
                    '{}'::types.q_get_simulation_attempt_v4_standard_pass[]
                ),
                COALESCE((gd.grade).description, ''),
                COALESCE(
                    (SELECT ARRAY_AGG(
                        (fb.standard_id, fb.feedback)::types.q_get_simulation_attempt_v4_standard_feedback
                    )
                    FROM feedbacks_grouped fg4
                    CROSS JOIN LATERAL unnest(COALESCE(fg4.feedbacks, '{}'::types.q_get_simulation_attempt_v4_feedback[])) fb
                    WHERE fg4.grade_id = (gd.grade).id),
                    '{}'::types.q_get_simulation_attempt_v4_standard_feedback[]
                )
                )::types.q_get_simulation_attempt_v4_grading_state
            ELSE NULL
        END as grading_state
    FROM grades_data gd
),
chats_with_all_data AS (
    SELECT 
        cb.id as chat_id,
        COALESCE(
            (SELECT srm.root_scenario_id 
             FROM scenario_root_mapping srm 
             WHERE srm.child_scenario_id = cb.scenario_id),
            cb.scenario_id
        ) as parent_scenario_id,
        ((cb.id, cb.created_at, cb.updated_at, cb.title, cb.scenario_id,
          COALESCE(
              (SELECT srm.root_scenario_id 
               FROM scenario_root_mapping srm 
               WHERE srm.child_scenario_id = cb.scenario_id),
              cb.scenario_id
          ),
          cb.attempt_id, cb.completed,
          CASE 
              WHEN cb.completed AND gd.grade IS NOT NULL 
              THEN (gd.grade).created_at
              ELSE NULL 
          END,
          cb.trace_id, cb.document_ids)::types.q_get_simulation_attempt_v4_chat,
         sd.scenario_data,
         COALESCE(mg.messages, '{}'::types.q_get_simulation_attempt_v4_message[]),
         COALESCE(hd.hints, '{}'::types.q_get_simulation_attempt_v4_hints_by_message[]),
         gd.grade,
         COALESCE(gspc.grading_state, NULL::types.q_get_simulation_attempt_v4_grading_state),
         drpc.dynamic_rubric,
         COALESCE(
             (SELECT previous_chats 
              FROM previous_chats_for_scenarios pcf2 
              WHERE pcf2.scenario_id = COALESCE(
                  (SELECT srm.root_scenario_id 
                   FROM scenario_root_mapping srm 
                   WHERE srm.child_scenario_id = cb.scenario_id),
                  cb.scenario_id
              )),
             '{}'::types.q_get_simulation_attempt_v4_previous_chat[]
         ),
         COALESCE(ppc.personas, '{}'::types.q_get_simulation_attempt_v4_persona[]),
         'scenario'::text,
         NULL::types.q_get_simulation_attempt_v4_video,
         NULL::types.q_get_simulation_attempt_v4_quiz
        )::types.q_get_simulation_attempt_v4_chat_data as chat_data,
        cb.completed,
        cb.created_at,
        gd.grade
    FROM chats_base cb
    LEFT JOIN scenarios_data sd ON sd.id = cb.scenario_id
    LEFT JOIN messages_grouped mg ON mg.chat_id = cb.id
    LEFT JOIN hints_data hd ON hd.chat_id = cb.id
    LEFT JOIN grades_data gd ON gd.chat_id = cb.id
    LEFT JOIN grading_state_per_chat gspc ON gspc.chat_id = cb.id
    LEFT JOIN dynamic_rubric_per_chat drpc ON drpc.chat_id = cb.id
    LEFT JOIN personas_per_chat ppc ON ppc.chat_id = cb.id
),
chats_with_positions AS (
    SELECT 
        cwad.chat_id,
        cwad.chat_data,
        cwad.completed,
        cwad.created_at,
        cwad.grade,
        COALESCE(
            (SELECT ss.position
             FROM simulation_scenarios ss
             CROSS JOIN attempt_base ab
             WHERE ss.simulation_id = ab.simulation_id 
               AND ss.scenario_id = (cwad.chat_data).scenario.id
               AND ss.active = true
             LIMIT 1),
            (SELECT ROW_NUMBER() OVER (ORDER BY cwad.created_at) FROM chats_with_all_data LIMIT 1)
        ) as position,
        'scenario'::text as content_type
    FROM chats_with_all_data cwad
),
unified_content AS (
    SELECT 
        chat_id::text as content_id,
        chat_data,
        completed,
        created_at,
        grade,
        position,
        'scenario'::text as content_type
    FROM chats_with_positions
),
aggregated_results_data AS (
    SELECT 
        CASE 
            WHEN COUNT(*) FILTER (WHERE completed = true AND grade IS NOT NULL) > 0 THEN
                (COALESCE(SUM((grade).score::numeric) FILTER (WHERE completed = true AND grade IS NOT NULL), 0)::float,
                 COALESCE(
                     (SELECT r.points FROM rubrics r 
                      CROSS JOIN attempt_base ab 
                      WHERE r.id = ab.sim_rubric_id) * COUNT(*) FILTER (WHERE completed = true AND grade IS NOT NULL),
                     0
                 )::float,
                 CASE 
                     WHEN (SELECT r.points FROM rubrics r 
                           CROSS JOIN attempt_base ab 
                           WHERE r.id = ab.sim_rubric_id) > 0 
                        AND COUNT(*) FILTER (WHERE completed = true AND grade IS NOT NULL) > 0 THEN
                         ROUND(
                             (SUM((grade).score::numeric) FILTER (WHERE completed = true AND grade IS NOT NULL)::numeric / 
                              ((SELECT r.points FROM rubrics r 
                                CROSS JOIN attempt_base ab 
                                WHERE r.id = ab.sim_rubric_id) * COUNT(*) FILTER (WHERE completed = true AND grade IS NOT NULL))::numeric) * 100.0,
                             1
                         )::float
                     ELSE 0.0
                 END,
                 BOOL_AND((grade).passed) FILTER (WHERE completed = true AND grade IS NOT NULL),
                 COUNT(*) FILTER (WHERE completed = true AND grade IS NOT NULL)::int,
                 COUNT(*)::int
                )::types.q_get_simulation_attempt_v4_aggregated_results
            ELSE NULL
        END as aggregated_results
    FROM unified_content
    CROSS JOIN attempt_base ab
),
elapsed_time_calc AS (
    SELECT 
        COALESCE(
            SUM(
                CASE 
                    WHEN uc.completed AND uc.grade IS NOT NULL THEN
                        (uc.grade).time_taken::integer
                    WHEN uc.completed THEN
                        EXTRACT(EPOCH FROM (
                            (uc.grade).created_at - uc.created_at
                        ))::integer
                    ELSE
                        EXTRACT(EPOCH FROM (NOW() - uc.created_at))::integer
                END
            ),
            0
        ) as total_elapsed
    FROM unified_content uc
),
timer_data AS (
    SELECT 
        (etc.total_elapsed::int,
         CASE 
             WHEN ab.sim_time_limit IS NOT NULL THEN
                 (ab.sim_time_limit * 60)::int
             ELSE NULL
         END,
         CASE 
             WHEN ab.infinite_mode AND ab.sim_time_limit IS NOT NULL THEN
                 (GREATEST((ab.sim_time_limit * 60) - etc.total_elapsed, 0) <= 0)
             WHEN ab.sim_time_limit IS NOT NULL THEN
                 ((ab.sim_time_limit * 60) - etc.total_elapsed < 0)
             ELSE false
         END,
         CASE 
             WHEN ab.sim_time_limit IS NOT NULL THEN
                 CASE 
                     WHEN ab.infinite_mode THEN
                         CONCAT(
                             FLOOR(GREATEST((ab.sim_time_limit * 60) - etc.total_elapsed, 0) / 3600)::text, 'h ',
                             FLOOR((GREATEST((ab.sim_time_limit * 60) - etc.total_elapsed, 0) % 3600) / 60)::text, 'm ',
                             (GREATEST((ab.sim_time_limit * 60) - etc.total_elapsed, 0) % 60)::text, 's'
                         )
                     ELSE
                         CONCAT(
                             FLOOR(GREATEST((ab.sim_time_limit * 60) - etc.total_elapsed, 0) / 3600)::text, 'h ',
                             FLOOR((GREATEST((ab.sim_time_limit * 60) - etc.total_elapsed, 0) % 3600) / 60)::text, 'm ',
                             (GREATEST((ab.sim_time_limit * 60) - etc.total_elapsed, 0) % 60)::text, 's'
                         )
                 END
             ELSE ''
         END
        )::types.q_get_simulation_attempt_v4_timer as timer
    FROM attempt_base ab
    CROSS JOIN elapsed_time_calc etc
),
simulation_scenario_count AS (
    SELECT 
        COUNT(*)::integer as total_scenarios
    FROM params x
    JOIN attempt_base ab ON ab.id = x.attempt_id
    JOIN simulation_scenarios ss ON ss.simulation_id = ab.simulation_id AND ss.active = true
),
scenarios_with_completed_chats AS (
    SELECT DISTINCT ss.scenario_id as parent_scenario_id
    FROM params x
    JOIN attempt_base ab ON ab.id = x.attempt_id
    JOIN simulation_scenarios ss ON ss.simulation_id = ab.simulation_id AND ss.active = true
    JOIN attempt_chats ac ON ac.attempt_id = ab.id
    JOIN chats sc ON sc.id = ac.chat_id
    JOIN grades scg ON EXISTS (
        SELECT 1 FROM runs r_check
        JOIN group_runs gr_check ON gr_check.run_id = r_check.id
        JOIN groups g_check ON g_check.id = gr_check.group_id
        JOIN chat_groups cg_check ON cg_check.group_id = g_check.id
        JOIN chats c_check ON c_check.id = cg_check.chat_id
        WHERE r_check.id = scg.run_id AND c_check.id = sc.id
    )
    WHERE COALESCE(
            (SELECT srm.root_scenario_id 
             FROM scenario_root_mapping srm 
             WHERE srm.child_scenario_id = sc.scenario_id),
            sc.scenario_id
        ) = ss.scenario_id
       OR sc.scenario_id = ss.scenario_id
),
total_content_count AS (
    SELECT 
        (SELECT COUNT(*) FROM simulation_scenarios_list) as total_count
),
metadata_computed AS (
    SELECT 
        COALESCE(
            (SELECT row_num - 1
             FROM (
                 SELECT 
                     content_id,
                     completed,
                     ROW_NUMBER() OVER (ORDER BY position, created_at) as row_num
                 FROM unified_content
             ) ranked
             WHERE completed = false
             ORDER BY row_num
             LIMIT 1),
            0
        ) as current_chat_index,
        COALESCE((SELECT total_count FROM total_content_count), COUNT(*)::integer) as expected_chat_count,
        COUNT(*) = 1 as is_single_chat_attempt,
        CASE 
            WHEN (SELECT infinite_mode FROM attempt_base) THEN false
            WHEN (SELECT total_count FROM total_content_count) > 0 THEN
                COALESCE(
                    (SELECT row_num - 1
                     FROM (
                         SELECT 
                             content_id,
                             completed,
                             ROW_NUMBER() OVER (ORDER BY position, created_at) as row_num
                         FROM unified_content
                     ) ranked
                     WHERE completed = false
                     ORDER BY row_num
                     LIMIT 1),
                    0
                ) = (SELECT total_count FROM total_content_count) - 1
            ELSE
                COALESCE(
                    (SELECT row_num - 1
                     FROM (
                         SELECT 
                             content_id,
                             completed,
                             ROW_NUMBER() OVER (ORDER BY position, created_at) as row_num
                         FROM unified_content
                     ) ranked
                     WHERE completed = false
                     ORDER BY row_num
                     LIMIT 1),
                    0
                ) = COUNT(*) - 1
        END as is_last_attempt,
        COALESCE(BOOL_AND(completed), false) as show_results,
        CASE 
            WHEN (SELECT COUNT(*) FROM simulation_root_scenarios_list) = 0 THEN false
            ELSE COALESCE((
                SELECT 
                    (SELECT COUNT(DISTINCT srsl.root_scenario_id) FROM simulation_root_scenarios_list srsl
                     LEFT JOIN scenarios_with_completed_chats swcc ON swcc.parent_scenario_id = srsl.root_scenario_id
                     WHERE swcc.parent_scenario_id IS NULL)
            ) > 0, true)
        END as should_show_controls,
        COALESCE((
            SELECT 
                (SELECT COUNT(DISTINCT srsl.root_scenario_id) FROM simulation_root_scenarios_list srsl
                 LEFT JOIN scenarios_with_completed_chats swcc ON swcc.parent_scenario_id = srsl.root_scenario_id
                 WHERE swcc.parent_scenario_id IS NULL)
        ), 0)::integer as remaining_scenarios_count,
        COALESCE((
            SELECT 
                (SELECT COUNT(DISTINCT srsl.root_scenario_id) FROM simulation_root_scenarios_list srsl
                 LEFT JOIN scenarios_with_completed_chats swcc ON swcc.parent_scenario_id = srsl.root_scenario_id
                 WHERE swcc.parent_scenario_id IS NULL)
        ), 0) = 1 as is_last_remaining_scenario,
        NOT (SELECT sim_practice_simulation FROM attempt_base) as can_pick_multiple_alternatives
    FROM unified_content
),
available_continuation_options AS (
    WITH current_scenario_position AS (
        SELECT COALESCE(
            (SELECT ss.position
             FROM simulation_scenarios ss
             CROSS JOIN attempt_base ab
             JOIN unified_content uc ON uc.content_type = 'scenario'
             WHERE ss.simulation_id = ab.simulation_id
               AND ss.scenario_id = (uc.chat_data).scenario.id
               AND ss.active = true
               AND uc.completed = false
             ORDER BY uc.position, uc.created_at
             LIMIT 1),
            1
        ) as current_position
    ),
    valid_next_scenarios AS (
        SELECT 
            ssl.scenario_id,
            ssl.position,
            (asswpc.scenario_data).name as scenario_name,
            asswpc.previous_chats
        FROM simulation_scenarios_list ssl
        CROSS JOIN attempt_base ab
        CROSS JOIN current_scenario_position csp
        JOIN all_simulation_scenarios_with_previous_chats asswpc 
            ON asswpc.scenario_id = ssl.scenario_id
        WHERE ssl.position >= csp.current_position
          AND ab.sim_practice_simulation = false
          AND array_length(COALESCE(asswpc.previous_chats, '{}'::types.q_get_simulation_attempt_v4_previous_chat[]), 1) > 0
        ORDER BY ssl.position
    ),
    scenario_options_expanded AS (
        SELECT 
            vns.scenario_id,
            vns.position,
            vns.scenario_name,
            pc.chat_id as previous_chat_id,
            COALESCE((SELECT title FROM chats WHERE id = pc.chat_id), 'Previous attempt') as title,
            pc.score,
            pc.percentage,
            pc.time_taken
        FROM valid_next_scenarios vns
        CROSS JOIN LATERAL unnest(COALESCE(vns.previous_chats, '{}'::types.q_get_simulation_attempt_v4_previous_chat[])) pc
    )
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (soe.scenario_id, soe.position, soe.scenario_name, soe.previous_chat_id, soe.title, soe.score, soe.percentage, soe.time_taken)::types.q_get_simulation_attempt_v4_continuation_option
                ORDER BY soe.position, soe.score DESC NULLS LAST
            ),
            '{}'::types.q_get_simulation_attempt_v4_continuation_option[]
        ) as next_sequential_options,
        CASE WHEN COUNT(*) > 0 THEN true ELSE false END as has_options
    FROM scenario_options_expanded soe
)
SELECT 
    aec.attempt_exists,
    ap.actor_name,
    COALESCE(rc.access_denied, false) as access_denied,
    (ab.id, ab.created_at, ab.simulation_id, ab.infinite_mode, ab.archived, cap.profile_id)::types.q_get_simulation_attempt_v4_attempt as attempt,
    (ab.sim_id, ab.sim_title, ab.sim_description, ab.sim_department_id, ab.sim_active, false, ab.sim_practice_simulation, 
     sf.hints_enabled, sf.objectives_enabled, false, false, sf.image_input_enabled, sf.copy_paste_allowed, 
     ab.sim_time_limit, ab.sim_rubric_id, ab.sim_created_at, ab.sim_updated_at)::types.q_get_simulation_attempt_v4_simulation as simulation,
    COALESCE(apd.attempt_profiles, '{}'::types.q_get_simulation_attempt_v4_attempt_profile[]) as attempt_profiles,
    COALESCE(
        (SELECT ARRAY_AGG(uc.chat_data ORDER BY uc.position, uc.created_at)
         FROM unified_content uc),
        '{}'::types.q_get_simulation_attempt_v4_chat_data[]
    ) as chats,
    COALESCE(sdd.scenario_documents, '{}'::types.q_get_simulation_attempt_v4_scenario_document[]) as scenario_documents,
    ard.aggregated_results,
    td.timer,
    md.current_chat_index,
    md.expected_chat_count,
    md.is_single_chat_attempt,
    md.is_last_attempt,
    md.show_results,
    md.should_show_controls,
    md.remaining_scenarios_count,
    md.is_last_remaining_scenario,
    md.can_pick_multiple_alternatives,
    NOT (COALESCE((td.timer).exceeded, false) OR md.show_results) as is_active,
    rsc.rubric_structure,
    COALESCE(
        (SELECT ARRAY_AGG(
            ((asswpc.scenario_data).id, (asswpc.scenario_data).name, (asswpc.scenario_data).problem_statement,
             (asswpc.scenario_data).department_id, (asswpc.scenario_data).active, (asswpc.scenario_data).persona_id,
             (asswpc.scenario_data).persona_name, (asswpc.scenario_data).persona_icon, (asswpc.scenario_data).persona_color,
             (asswpc.scenario_data).created_at, (asswpc.scenario_data).updated_at, (asswpc.scenario_data).generated,
             (asswpc.scenario_data).default_scenario, (asswpc.scenario_data).copy_paste_allowed,
             (asswpc.scenario_data).text_enabled, (asswpc.scenario_data).audio_enabled,
             (asswpc.scenario_data).show_problem_statement, (asswpc.scenario_data).show_objectives,
             (asswpc.scenario_data).show_images, (asswpc.scenario_data).background_image,
             (asswpc.scenario_data).objectives, asswpc.previous_chats)::types.q_get_simulation_attempt_v4_all_simulation_scenario
            ORDER BY asswpc.position
        )
        FROM all_simulation_scenarios_with_previous_chats asswpc),
        '{}'::types.q_get_simulation_attempt_v4_all_simulation_scenario[]
    ) as all_simulation_scenarios,
    COALESCE(
        (SELECT (aco.next_sequential_options, aco.has_options)::types.q_get_simulation_attempt_v4_available_continuation_options
         FROM available_continuation_options aco),
        (ARRAY[]::types.q_get_simulation_attempt_v4_continuation_option[], false)::types.q_get_simulation_attempt_v4_available_continuation_options
    ) as available_continuation_options
FROM attempt_exists_check aec
CROSS JOIN attempt_base ab 
CROSS JOIN attempt_profiles_data apd
CROSS JOIN actor_profile ap
CROSS JOIN current_attempt_profile cap
CROSS JOIN simulation_flags sf
CROSS JOIN scenario_documents_data sdd
CROSS JOIN aggregated_results_data ard
CROSS JOIN timer_data td
CROSS JOIN metadata_computed md
LEFT JOIN rubric_structure_complete rsc ON true
LEFT JOIN role_check rc ON true
$_$;


--
-- Name: api_get_simulation_by_id_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_simulation_by_id_v4(simulation_id uuid) RETURNS TABLE(id uuid, title text, description text, active boolean, practice_simulation boolean, rubric_id uuid)
    LANGUAGE sql STABLE
    AS $$
SELECT 
    s.id,
    s.title,
    s.description,
    s.active,
    s.practice_simulation,
    (SELECT ssrga.rubric_grade_agent_id FROM simulation_scenarios_rubric_grade_agents ssrga 
     JOIN simulation_scenarios ss ON ss.simulation_id = ssrga.simulation_id AND ss.scenario_id = ssrga.scenario_id
     WHERE ss.simulation_id = s.id AND ss.active = true 
     ORDER BY ss.position LIMIT 1) as rubric_id
FROM simulations s
WHERE s.id = api_get_simulation_by_id_v4.simulation_id
$$;


--
-- Name: api_get_simulation_detail_v4(uuid, uuid, uuid, text, boolean, uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_simulation_detail_v4(simulation_id uuid, profile_id uuid, draft_id uuid DEFAULT NULL::uuid, scenario_search text DEFAULT NULL::text, scenario_show_selected boolean DEFAULT NULL::boolean, filter_scenario_ids uuid[] DEFAULT NULL::uuid[]) RETURNS TABLE(simulation_exists boolean, actor_name text, simulation_id uuid, name text, description text, department_ids uuid[], valid_department_ids uuid[], time_limit integer, rubric_id uuid, valid_rubric_ids uuid[], scenario_ids uuid[], valid_scenario_ids uuid[], active boolean, practice_simulation boolean, hint_agent_id uuid, simulation_text_agent_id uuid, simulation_voice_agent_id uuid, can_edit boolean, can_duplicate boolean, can_delete boolean, in_use boolean, cohort_count bigint, scenarios types.q_get_simulation_detail_v4_scenario[], parameters types.q_get_simulation_detail_v4_parameter_item[], parameter_items types.q_get_simulation_detail_v4_parameter_item_detail[], scenarios_full types.q_get_simulation_detail_v4_scenario_full[], rubrics types.q_get_simulation_detail_v4_rubric[], departments types.q_get_simulation_detail_v4_department[], parameters_full types.q_get_simulation_detail_v4_parameter[], fields types.q_get_simulation_detail_v4_field[], agents types.q_get_simulation_detail_v4_agent[], valid_agent_ids uuid[], draft_version integer, scenario_active_states jsonb, scenario_settings jsonb)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        simulation_id AS simulation_id,
        profile_id AS profile_id,
        draft_id AS draft_id,
        COALESCE(NULLIF(scenario_search, ''), NULL) AS scenario_search,
        COALESCE(scenario_show_selected, false) AS scenario_show_selected,
        COALESCE(filter_scenario_ids, ARRAY[]::uuid[]) AS filter_scenario_ids
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version,
        CASE 
            WHEN d.payload->'scenarioIds' IS NOT NULL AND jsonb_typeof(d.payload->'scenarioIds') = 'array' THEN
                ARRAY(SELECT jsonb_array_elements_text(d.payload->'scenarioIds'))::uuid[]
            WHEN d.payload->'scenario_ids' IS NOT NULL AND jsonb_typeof(d.payload->'scenario_ids') = 'array' THEN
                ARRAY(SELECT jsonb_array_elements_text(d.payload->'scenario_ids'))::uuid[]
            ELSE ARRAY[]::uuid[]
        END as draft_scenario_ids
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'simulations'::draft_resource_type
    LIMIT 1
),
scenario_filter_ids AS (
    SELECT 
        CASE 
            WHEN (SELECT scenario_show_selected FROM params LIMIT 1) = true 
                AND (SELECT draft_scenario_ids FROM draft_payload_data LIMIT 1) IS NOT NULL
                AND array_length((SELECT draft_scenario_ids FROM draft_payload_data LIMIT 1), 1) > 0
            THEN (SELECT draft_scenario_ids FROM draft_payload_data LIMIT 1)
            WHEN (SELECT array_length(filter_scenario_ids, 1) FROM params LIMIT 1) > 0
            THEN (SELECT filter_scenario_ids FROM params LIMIT 1)
            ELSE ARRAY[]::uuid[]
        END as ids
),
resolve_profile_id AS (
    SELECT 
        CASE 
            WHEN (SELECT profile_id FROM params)::text IS NULL OR (SELECT profile_id FROM params)::text = '' THEN NULL::uuid
            ELSE (SELECT profile_id FROM params)::uuid
        END as resolved_profile_id
),
user_context AS (
    SELECT 
        role,
        p.first_name || ' ' || p.last_name as actor_name
    FROM resolve_profile_id rpi
    JOIN profiles p ON p.id = rpi.resolved_profile_id
),
simulation_exists_check AS (
    SELECT EXISTS(
        SELECT 1 FROM simulations WHERE id = (SELECT simulation_id FROM params)
    )::boolean as simulation_exists
),
simulation_departments_data AS (
    SELECT 
        sd.simulation_id,
        ARRAY_AGG(sd.department_id ORDER BY sd.created_at) as department_ids
    FROM simulation_departments sd
    WHERE sd.simulation_id = (SELECT simulation_id FROM params) AND sd.active = true
    GROUP BY sd.simulation_id
),
simulation_department_access_check AS (
    SELECT 
        s.id as simulation_id,
        CASE 
            WHEN uc.role = 'superadmin'::profile_role THEN true
            WHEN EXISTS (
                SELECT 1 FROM simulation_departments sd 
                WHERE sd.simulation_id = s.id 
                AND sd.active = true 
                AND sd.department_id IN (SELECT department_id FROM resolve_profile_id rpi JOIN profile_departments pd ON pd.profile_id = rpi.resolved_profile_id WHERE pd.active = true)
            ) THEN true
            WHEN NOT EXISTS (
                SELECT 1 FROM simulation_departments sd2 
                WHERE sd2.simulation_id = s.id 
                AND sd2.active = true
            ) THEN true
            ELSE false
        END as has_access
    FROM simulations s
    CROSS JOIN user_context uc
    WHERE s.id = (SELECT simulation_id FROM params)
),
simulation_base AS (
    SELECT 
        s.id,
        s.title,
        s.description,
        s.active,
        s.practice_simulation,
        s.hint_agent_id,
        s.simulation_text_agent_id,
        s.simulation_voice_agent_id,
        (SELECT rga.rubric_id FROM simulation_scenarios ss 
         JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss.simulation_id AND ssrga.scenario_id = ss.scenario_id
         JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
         WHERE ss.simulation_id = s.id AND ss.active = true 
         ORDER BY ss.position 
         LIMIT 1) as rubric_id,
        COALESCE(
            (SELECT SUM(stl.time_limit_seconds)
             FROM scenario_time_limits stl
             JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
             WHERE stl.simulation_id = s.id AND stl.active = true AND ss.active = true),
            0
        ) as time_limit,
        COALESCE(sdd.department_ids, NULL) as department_ids
    FROM simulations s
    LEFT JOIN simulation_departments_data sdd ON sdd.simulation_id = s.id
    INNER JOIN simulation_department_access_check sdac ON sdac.simulation_id = s.id AND sdac.has_access = true
    WHERE s.id = (SELECT simulation_id FROM params)
),
cohort_usage AS (
    SELECT 
        COUNT(*) FILTER (WHERE cs.active = true) as active_cohort_count,
        COUNT(*) as total_cohort_links
    FROM cohort_simulations cs
    WHERE cs.simulation_id = (SELECT simulation_id FROM params)
),
user_departments AS (
    SELECT DISTINCT d.id, d.title as name, d.description
    FROM departments d
    JOIN resolve_profile_id rpi ON true
    JOIN profile_departments pd ON pd.department_id = d.id
    WHERE pd.profile_id = rpi.resolved_profile_id AND d.active = true
),
user_department_ids AS (
    SELECT ARRAY_AGG(id) as ids
    FROM user_departments
),
simulation_scenarios_base AS (
    SELECT 
        ss.simulation_id,
        s.id as scenario_id,
        s.name,
        COALESCE(s.description, '') as description,
        ss.active,
        (ss.position = 1) as default_scenario,
        ss.position,
        ss.hints_enabled,
        ss.copy_paste_allowed,
        ss.audio_enabled,
        ss.text_enabled,
        -- rubric_id removed from simulation_scenarios - now in rubric_grade_agents array
        stl.time_limit_seconds,
        COALESCE(
            (SELECT ARRAY_AGG(DISTINCT sf.field_id)
             FROM scenario_fields sf
             WHERE sf.scenario_id = s.id AND sf.active = true),
            ARRAY[]::uuid[]
        ) as parameter_item_ids
    FROM scenarios s
    JOIN simulation_scenarios ss ON ss.scenario_id = s.id
    LEFT JOIN scenario_time_limits stl ON stl.simulation_id = ss.simulation_id AND stl.scenario_id = ss.scenario_id AND stl.active = true
    WHERE ss.simulation_id = (SELECT simulation_id FROM params)
    ORDER BY ss.position
),
scenario_statistics AS (
    SELECT 
        ss.scenario_id,
        COALESCE(
            (SELECT st.parent_id 
             FROM scenario_tree st 
             WHERE st.child_id = ss.scenario_id 
               AND st.parent_id = st.child_id 
             LIMIT 1),
            ss.scenario_id
        ) as root_scenario_id,
        COUNT(DISTINCT sc.id) as usage_count,
        CASE 
            WHEN COUNT(DISTINCT CASE WHEN sc.completed = true THEN sc.id END) > 0 
            THEN ROUND(
                (COUNT(DISTINCT CASE WHEN sc.completed = true AND scg.passed = true THEN sc.id END)::numeric / 
                 COUNT(DISTINCT CASE WHEN sc.completed = true THEN sc.id END)::numeric) * 100
            )
            ELSE 0 
        END as success_rate,
        MAX(sc.created_at) as last_used_date
    FROM simulation_scenarios ss
    LEFT JOIN chats sc ON (
        sc.scenario_id IN (
            SELECT st2.child_id 
            FROM scenario_tree st2 
            WHERE st2.parent_id = COALESCE(
                (SELECT st3.parent_id 
                 FROM scenario_tree st3 
                 WHERE st3.child_id = ss.scenario_id 
                   AND st3.parent_id = st3.child_id),
                ss.scenario_id
            )
        )
        OR sc.scenario_id = ss.scenario_id
    )
    LEFT JOIN grades scg ON EXISTS (
        SELECT 1 FROM runs r_check
        JOIN group_runs gr_check ON gr_check.run_id = r_check.id
        JOIN groups g_check ON g_check.id = gr_check.group_id
        JOIN chat_groups cg_check ON cg_check.group_id = g_check.id
        JOIN chats c_check ON c_check.id = cg_check.chat_id
        WHERE r_check.id = scg.run_id AND c_check.id = sc.id
    )
    LEFT JOIN runs r_detail ON r_detail.id = scg.run_id
    LEFT JOIN LATERAL (
        SELECT DISTINCT c.id AS chat_id
        FROM runs r
        JOIN group_runs gr ON gr.run_id = r.id
        JOIN groups g ON g.id = gr.group_id
        JOIN chat_groups cg ON cg.group_id = g.id
        JOIN chats c ON c.id = cg.chat_id
        WHERE r.id = r_detail.id AND c.id = sc.id
        LIMIT 1
    ) chat_lookup_detail ON true
    WHERE ss.simulation_id = (SELECT simulation_id FROM params)
    GROUP BY ss.scenario_id
),
scenario_rubric_grade_agents_data AS (
    SELECT 
        ssrga.scenario_id,
        ARRAY_AGG(
            (ssrga.rubric_grade_agent_id, rga.rubric_id, r.name, 
             rga.grade_agent_id, a_text.name,
             rgav.audio_agent_id, a_voice.name)::types.q_get_simulation_detail_v4_rubric_grade_agent
            ORDER BY r.name
        ) as rubric_grade_agents
    FROM simulation_scenarios_base ssb
    JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ssb.simulation_id AND ssrga.scenario_id = ssb.scenario_id
    JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
    JOIN rubrics r ON r.id = rga.rubric_id
    JOIN agents a_text ON a_text.id = rga.grade_agent_id
    LEFT JOIN rubric_grade_agents_audio rgav ON rgav.rubric_grade_agent_id = rga.id
    LEFT JOIN agents a_voice ON a_voice.id = rgav.audio_agent_id
    GROUP BY ssrga.scenario_id
),
scenarios_data AS (
    SELECT 
        ARRAY_AGG(
            (sb.scenario_id, sb.name, sb.description, sb.active, sb.position,
             sb.parameter_item_ids, sb.hints_enabled, sb.copy_paste_allowed,
             sb.audio_enabled, sb.text_enabled, sb.time_limit_seconds,
             COALESCE(stats.usage_count, 0), COALESCE(stats.success_rate, 0),
             stats.last_used_date, COALESCE(stats.usage_count, 0) = 0,
             CASE 
                 WHEN sb.scenario_id IS NOT NULL AND EXISTS (
                     SELECT 1 FROM scenario_videos sv 
                     WHERE sv.scenario_id = sb.scenario_id 
                     AND sv.active = true
                 ) THEN true 
                 ELSE false 
             END,
             COALESCE(srgad.rubric_grade_agents, '{}'::types.q_get_simulation_detail_v4_rubric_grade_agent[])
            )::types.q_get_simulation_detail_v4_scenario
            ORDER BY sb.position
        ) as scenarios,
        ARRAY_AGG(sb.scenario_id) as scenario_ids
    FROM simulation_scenarios_base sb
    LEFT JOIN scenario_statistics stats ON stats.scenario_id = sb.scenario_id
    LEFT JOIN scenario_rubric_grade_agents_data srgad ON srgad.scenario_id = sb.scenario_id
),
valid_scenarios_list AS (
    SELECT DISTINCT
        s.id,
        s.name,
        COALESCE(s.description, '') as description
    FROM scenarios s
    CROSS JOIN user_department_ids udi
    JOIN scenario_tree st ON st.parent_id = s.id AND st.child_id = s.id
    LEFT JOIN scenario_departments sd ON sd.scenario_id = s.id AND sd.active = true
    WHERE s.active = true
      AND (
          sd.department_id = ANY(udi.ids)
          OR NOT EXISTS (SELECT 1 FROM scenario_departments sd2 WHERE sd2.scenario_id = s.id AND sd2.active = true)
      )
    UNION
    SELECT DISTINCT
        COALESCE(
            (SELECT st2.parent_id 
             FROM scenario_tree st2 
             WHERE st2.child_id = ssb.scenario_id 
               AND st2.parent_id = st2.child_id 
             LIMIT 1),
            ssb.scenario_id
        ) as id,
        s2.name,
        COALESCE(s2.description, '') as description
    FROM simulation_scenarios_base ssb
    JOIN scenarios s2 ON s2.id = COALESCE(
        (SELECT st3.parent_id 
         FROM scenario_tree st3 
         WHERE st3.child_id = ssb.scenario_id 
           AND st3.parent_id = st3.child_id 
         LIMIT 1),
        ssb.scenario_id
    )
    WHERE s2.active = true
),
valid_scenarios AS (
    SELECT ARRAY_AGG(id::text) as ids
    FROM valid_scenarios_list
),
valid_rubrics_data AS (
    SELECT DISTINCT
        r.id,
        r.name,
        COALESCE(r.description, '') as description
    FROM rubrics r
    LEFT JOIN rubric_departments rd ON rd.rubric_id = r.id AND rd.active = true
    CROSS JOIN user_department_ids udi
    WHERE r.active = true
      AND (
          rd.department_id = ANY(udi.ids)
          OR NOT EXISTS (SELECT 1 FROM rubric_departments rd2 WHERE rd2.rubric_id = r.id AND rd2.active = true)
      )
    UNION
    SELECT DISTINCT
        r2.id,
        r2.name,
        COALESCE(r2.description, '') as description
    FROM simulation_base sb
    LEFT JOIN simulation_scenarios_rubric_grade_agents ssrga_sb ON ssrga_sb.simulation_id = sb.id
    LEFT JOIN rubric_grade_agents rga_sb ON rga_sb.id = ssrga_sb.rubric_grade_agent_id
    JOIN rubrics r2 ON r2.id = rga_sb.rubric_id
    WHERE rga_sb.rubric_id IS NOT NULL AND r2.active = true
    UNION
    SELECT DISTINCT
        r3.id,
        r3.name,
        COALESCE(r3.description, '') as description
    FROM simulation_scenarios_base ssb
    JOIN simulation_scenarios_rubric_grade_agents ssrga_ssb ON ssrga_ssb.simulation_id = ssb.simulation_id AND ssrga_ssb.scenario_id = ssb.scenario_id
    JOIN rubric_grade_agents rga_ssb ON rga_ssb.id = ssrga_ssb.rubric_grade_agent_id
    JOIN rubrics r3 ON r3.id = rga_ssb.rubric_id
    WHERE rga_ssb.rubric_id IS NOT NULL AND r3.active = true
),
rubrics_data AS (
    SELECT 
        ARRAY_AGG(
            (vr.id, vr.name, vr.description)::types.q_get_simulation_detail_v4_rubric
            ORDER BY vr.name
        ) as rubrics,
        ARRAY_AGG(vr.id::text) as rubric_ids
    FROM valid_rubrics_data vr
),
parameters_data AS (
    SELECT DISTINCT
        p.id,
        p.name,
        COALESCE(p.description, '') as description,
        p.document_parameter,
        p.persona_parameter
    FROM parameters p
    JOIN parameter_fields fp ON fp.parameter_id = p.id AND fp.active = true
    LEFT JOIN field_departments fd ON fd.field_id = fp.field_id AND fd.active = true
    CROSS JOIN user_department_ids udi
    WHERE p.active = true
    GROUP BY p.id, p.name, p.description, p.document_parameter, p.persona_parameter
    HAVING 
        COUNT(fd.field_id) FILTER (WHERE fd.department_id = ANY(udi.ids)) > 0
        OR NOT EXISTS (SELECT 1 FROM field_departments fd2 
                      JOIN parameter_fields fp2 ON fp2.field_id = fd2.field_id 
                      WHERE fp2.parameter_id = p.id AND fp2.active = true AND fd2.active = true)
),
parameters_full_data AS (
    SELECT 
        ARRAY_AGG(
            (pd.id, pd.name, pd.description, pd.document_parameter, pd.persona_parameter)::types.q_get_simulation_detail_v4_parameter
            ORDER BY pd.name
        ) as parameters
    FROM parameters_data pd
),
parameter_items_data AS (
    SELECT 
        f.id,
        fp.parameter_id,
        f.name,
        COALESCE(f.description, '') as description,
        p.name as parameter_name
    FROM fields f
    JOIN parameter_fields fp ON fp.field_id = f.id AND fp.active = true
    JOIN parameters p ON p.id = fp.parameter_id
    WHERE p.id IN (SELECT id FROM parameters_data)
),
parameter_items_list_data AS (
    SELECT 
        ARRAY_AGG(
            (pid.id, pid.parameter_id, pid.name, pid.description)::types.q_get_simulation_detail_v4_parameter_item
            ORDER BY pid.name
        ) as parameter_items,
        ARRAY_AGG(
            (pid.id, pid.name, pid.description, pid.parameter_id)::types.q_get_simulation_detail_v4_parameter_item_detail
            ORDER BY pid.name
        ) as parameter_item_details
    FROM parameter_items_data pid
),
fields_data AS (
    SELECT 
        ARRAY_AGG(
            (pid.id, pid.name, pid.description, pid.parameter_id, pid.parameter_name)::types.q_get_simulation_detail_v4_field
            ORDER BY pid.name
        ) as fields
    FROM parameter_items_data pid
),
scenario_persona_data AS (
    SELECT 
        sp.scenario_id,
        sp.persona_id,
        p.name as persona_name,
        COALESCE(p.description, '') as persona_description,
        p.color as persona_color,
        p.icon as persona_icon,
        false as image_model
    FROM scenario_personas sp
    JOIN personas p ON p.id = sp.persona_id
    WHERE sp.scenario_id IN (SELECT id FROM valid_scenarios_list)
      AND sp.active = true
),
scenario_persona_mapping AS (
    SELECT 
        spd.scenario_id,
        ARRAY_AGG(
            (spd.persona_id, spd.persona_name, spd.persona_description, spd.persona_color, spd.persona_icon, spd.image_model)::types.q_get_simulation_detail_v4_persona
            ORDER BY spd.persona_name
        ) as personas
    FROM scenario_persona_data spd
    GROUP BY spd.scenario_id
),
scenario_documents_data AS (
    SELECT 
        sd.scenario_id,
        ARRAY_AGG(sd.document_id) as document_ids
    FROM scenario_documents sd
    WHERE sd.scenario_id IN (SELECT id FROM valid_scenarios_list)
      AND sd.active = true
    GROUP BY sd.scenario_id
),
scenario_document_mapping AS (
    SELECT 
        sdd.scenario_id,
        ARRAY_AGG(
            (d.id, d.name, ''::text)::types.q_get_simulation_detail_v4_document
            ORDER BY d.name
        ) as documents
    FROM scenario_documents_data sdd
    JOIN documents d ON d.id = ANY(sdd.document_ids)
    GROUP BY sdd.scenario_id
),
scenario_parameter_items_data AS (
    SELECT 
        sf.scenario_id,
        ARRAY_AGG(DISTINCT sf.field_id) as parameter_item_ids
    FROM scenario_fields sf
    WHERE sf.scenario_id IN (SELECT id FROM valid_scenarios_list)
      AND sf.active = true
    GROUP BY sf.scenario_id
),
scenario_field_mapping AS (
    SELECT 
        spid.scenario_id,
        ARRAY_AGG(
            (pid.id, pid.name, pid.description, pid.parameter_id, pid.parameter_name)::types.q_get_simulation_detail_v4_field
            ORDER BY pid.name
        ) as fields
    FROM scenario_parameter_items_data spid
    JOIN parameter_items_data pid ON pid.id = ANY(spid.parameter_item_ids)
    GROUP BY spid.scenario_id
),
scenarios_full_data AS (
    SELECT 
        ARRAY_AGG(
            (vsl.id, vsl.name, vsl.description,
             COALESCE(
                 (SELECT ARRAY_AGG(spd.persona_id) FROM scenario_persona_data spd WHERE spd.scenario_id = vsl.id),
                 ARRAY[]::uuid[]
             ),
             COALESCE(spm.personas, ARRAY[]::types.q_get_simulation_detail_v4_persona[]),
             COALESCE(sdm.documents, ARRAY[]::types.q_get_simulation_detail_v4_document[]),
             COALESCE(sfm.fields, ARRAY[]::types.q_get_simulation_detail_v4_field[]),
             COALESCE(
                 (SELECT spid.parameter_item_ids FROM scenario_parameter_items_data spid WHERE spid.scenario_id = vsl.id),
                 ARRAY[]::uuid[]
             ),
             COALESCE(
                 (SELECT sdd.document_ids FROM scenario_documents_data sdd WHERE sdd.scenario_id = vsl.id),
                 ARRAY[]::uuid[]
             )
            )::types.q_get_simulation_detail_v4_scenario_full
            ORDER BY vsl.name
        ) as scenarios_full
    FROM valid_scenarios_list vsl
    LEFT JOIN scenario_persona_mapping spm ON spm.scenario_id = vsl.id
    LEFT JOIN scenario_document_mapping sdm ON sdm.scenario_id = vsl.id
    LEFT JOIN scenario_field_mapping sfm ON sfm.scenario_id = vsl.id
    WHERE
        -- Search filter
        (
            (SELECT scenario_search FROM params LIMIT 1) IS NULL
            OR LOWER(vsl.name) LIKE '%' || LOWER((SELECT scenario_search FROM params LIMIT 1)) || '%'
            OR LOWER(COALESCE(vsl.description, '')) LIKE '%' || LOWER((SELECT scenario_search FROM params LIMIT 1)) || '%'
        )
        -- Show selected filter (use scenario_filter_ids which comes from draft payload or filter_scenario_ids param)
        AND (
            (SELECT scenario_show_selected FROM params LIMIT 1) = false
            OR (SELECT array_length(ids, 1) FROM scenario_filter_ids LIMIT 1) IS NULL
            OR (SELECT array_length(ids, 1) FROM scenario_filter_ids LIMIT 1) = 0
            OR vsl.id = ANY((SELECT ids FROM scenario_filter_ids LIMIT 1)::uuid[])
        )
),
department_scenario_ids AS (
    SELECT 
        ud.id as department_id,
        COALESCE(ARRAY_AGG(DISTINCT s.id ORDER BY s.id) FILTER (WHERE s.id IS NOT NULL), ARRAY[]::uuid[]) as scenario_ids
    FROM user_departments ud
    LEFT JOIN scenarios s ON s.active = true
    INNER JOIN scenario_tree st ON st.parent_id = s.id AND st.child_id = s.id
    LEFT JOIN scenario_departments sd ON sd.scenario_id = s.id AND sd.active = true
    WHERE (sd.department_id = ud.id OR NOT EXISTS (SELECT 1 FROM scenario_departments sd2 WHERE sd2.scenario_id = s.id AND sd2.active = true))
    GROUP BY ud.id
),
department_rubric_ids AS (
    SELECT 
        ud.id as department_id,
        COALESCE(ARRAY_AGG(DISTINCT r.id ORDER BY r.id) FILTER (WHERE r.id IS NOT NULL), ARRAY[]::uuid[]) as rubric_ids
    FROM user_departments ud
    LEFT JOIN rubrics r ON r.active = true
    LEFT JOIN rubric_departments rd ON rd.rubric_id = r.id AND rd.active = true
    WHERE (rd.department_id = ud.id OR NOT EXISTS (SELECT 1 FROM rubric_departments rd2 WHERE rd2.rubric_id = r.id AND rd2.active = true))
    GROUP BY ud.id
),
department_cohort_ids AS (
    SELECT 
        ud.id as department_id,
        COALESCE(ARRAY_AGG(DISTINCT c.id ORDER BY c.id) FILTER (WHERE c.id IS NOT NULL), ARRAY[]::uuid[]) as cohort_ids
    FROM user_departments ud
    LEFT JOIN cohorts c ON c.active = true
    LEFT JOIN cohort_departments cd ON cd.cohort_id = c.id AND cd.active = true
    WHERE (cd.department_id = ud.id OR NOT EXISTS (SELECT 1 FROM cohort_departments cd2 WHERE cd2.cohort_id = c.id AND cd2.active = true))
    GROUP BY ud.id
),
departments_data AS (
    SELECT 
        ARRAY_AGG(
            (ud.id, ud.name, ud.description,
             COALESCE(dsci.scenario_ids, ARRAY[]::uuid[]),
             COALESCE(dri.rubric_ids, ARRAY[]::uuid[]),
             COALESCE(dci.cohort_ids, ARRAY[]::uuid[])
            )::types.q_get_simulation_detail_v4_department
            ORDER BY ud.name
        ) as departments,
        ARRAY_AGG(DISTINCT ud.id::text) as department_ids
    FROM user_departments ud
    LEFT JOIN department_scenario_ids dsci ON dsci.department_id = ud.id
    LEFT JOIN department_rubric_ids dri ON dri.department_id = ud.id
    LEFT JOIN department_cohort_ids dci ON dci.department_id = ud.id
),
user_departments_for_agents AS (
    SELECT department_id
    FROM resolve_profile_id rpi
    JOIN profile_departments pd ON pd.profile_id = rpi.resolved_profile_id
    WHERE pd.active = true
),
selected_agents_from_simulation AS (
    SELECT DISTINCT a.id, a.name, a.description, a.role
    FROM simulation_base sb
    JOIN agents a ON (
        (a.id = sb.hint_agent_id AND a.role = 'hint'::agent_role)
        OR (a.id = sb.simulation_text_agent_id AND a.role = 'simulation'::agent_role)
        OR (a.id = sb.simulation_voice_agent_id AND a.role = 'voice'::agent_role)
    )
    WHERE a.active = true
      AND (
          sb.hint_agent_id IS NOT NULL
          OR sb.simulation_text_agent_id IS NOT NULL
          OR sb.simulation_voice_agent_id IS NOT NULL
      )
    UNION
    -- Get grade agents from junction tables
    SELECT DISTINCT a.id, a.name, a.description, a.role
    FROM simulation_base sb
    JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = sb.id
    JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
    JOIN agents a ON a.id = rga.grade_agent_id AND a.role IN ('grade'::agent_role)
    WHERE a.active = true
    UNION
    SELECT DISTINCT a.id, a.name, a.description, a.role
    FROM simulation_base sb
    JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = sb.id
    JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
    JOIN rubric_grade_agents_audio rgav ON rgav.rubric_grade_agent_id = rga.id
    JOIN agents a ON a.id = rgav.audio_agent_id AND a.role IN ('audio'::agent_role)
    WHERE a.active = true
    UNION
    -- Get rubric agents (member role) from rubrics.rubric_agent_id
    SELECT DISTINCT a.id, a.name, a.description, a.role
    FROM simulation_base sb
    JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = sb.id
    JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
    JOIN rubrics r ON r.id = rga.rubric_id
    JOIN agents a ON a.id = r.rubric_agent_id AND a.role = 'member'::agent_role
    WHERE a.active = true AND r.rubric_agent_id IS NOT NULL
),
agents_data AS (
    SELECT 
        ARRAY_AGG(
            (filtered_agents.id, filtered_agents.name, COALESCE(filtered_agents.description, ''), ARRAY[filtered_agents.role::text])::types.q_get_simulation_detail_v4_agent
            ORDER BY filtered_agents.name
        ) as agents,
        ARRAY_AGG(filtered_agents.id ORDER BY filtered_agents.name) as agent_ids
    FROM (
        SELECT DISTINCT a.id, a.name, a.description, a.role
        FROM agents a
        LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
        WHERE a.active = true 
        AND a.role IN ('hint'::agent_role, 'grade'::agent_role, 'audio'::agent_role, 'simulation'::agent_role, 'voice'::agent_role, 'member'::agent_role)
        GROUP BY a.id, a.name, a.description, a.role
        HAVING 
            COUNT(ad.agent_id) FILTER (WHERE ad.department_id IN (SELECT department_id FROM user_departments_for_agents)) > 0
            OR NOT EXISTS (SELECT 1 FROM agent_departments ad2 WHERE ad2.agent_id = a.id AND ad2.active = true)
        UNION
        SELECT DISTINCT sas.id, sas.name, sas.description, sas.role
        FROM selected_agents_from_simulation sas
    ) filtered_agents
),
-- Auto-select default agents when there's only one option for each role (for new simulations or when simulation doesn't have agent set)
valid_hint_agents AS (
    SELECT DISTINCT a.id
    FROM agents a
    LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
    WHERE a.active = true 
    AND a.role = 'hint'::agent_role
    GROUP BY a.id
    HAVING 
        COUNT(ad.agent_id) FILTER (WHERE ad.department_id IN (SELECT department_id FROM user_departments_for_agents)) > 0
        OR NOT EXISTS (SELECT 1 FROM agent_departments ad2 WHERE ad2.agent_id = a.id AND ad2.active = true)
),
valid_simulation_agents AS (
    SELECT DISTINCT a.id
    FROM agents a
    LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
    WHERE a.active = true 
    AND a.role = 'simulation'::agent_role
    GROUP BY a.id
    HAVING 
        COUNT(ad.agent_id) FILTER (WHERE ad.department_id IN (SELECT department_id FROM user_departments_for_agents)) > 0
        OR NOT EXISTS (SELECT 1 FROM agent_departments ad2 WHERE ad2.agent_id = a.id AND ad2.active = true)
),
valid_voice_agents AS (
    SELECT DISTINCT a.id
    FROM agents a
    LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
    WHERE a.active = true 
    AND a.role = 'voice'::agent_role
    GROUP BY a.id
    HAVING 
        COUNT(ad.agent_id) FILTER (WHERE ad.department_id IN (SELECT department_id FROM user_departments_for_agents)) > 0
        OR NOT EXISTS (SELECT 1 FROM agent_departments ad2 WHERE ad2.agent_id = a.id AND ad2.active = true)
),
default_hint_agent AS (
    SELECT id FROM valid_hint_agents
    WHERE (SELECT COUNT(*) FROM valid_hint_agents) = 1
    LIMIT 1
),
default_simulation_agent AS (
    SELECT id FROM valid_simulation_agents
    WHERE (SELECT COUNT(*) FROM valid_simulation_agents) = 1
    LIMIT 1
),
default_voice_agent AS (
    SELECT id FROM valid_voice_agents
    WHERE (SELECT COUNT(*) FROM valid_voice_agents) = 1
    LIMIT 1
)
SELECT 
    (SELECT simulation_exists FROM simulation_exists_check) as simulation_exists,
    uc.actor_name::text as actor_name,
    sb.id as simulation_id,
    -- Merge draft payload over existing simulation data if draft_id provided
    COALESCE(
        (SELECT payload->>'title' FROM draft_payload_data),
        sb.title
    ) as name,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        sb.description
    ) as description,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'departmentIds' IS NOT NULL AND jsonb_typeof(payload->'departmentIds') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'departmentIds'))::uuid[]
                WHEN payload->'department_ids' IS NOT NULL AND jsonb_typeof(payload->'department_ids') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'department_ids'))::uuid[]
                ELSE NULL
            END
        FROM draft_payload_data),
        sb.department_ids
    ) as department_ids,
    COALESCE(dd.department_ids::uuid[], ARRAY[]::uuid[]) as valid_department_ids,
    sb.time_limit,
    sb.rubric_id,
    COALESCE(rd.rubric_ids::uuid[], ARRAY[]::uuid[]) as valid_rubric_ids,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'scenarioIds' IS NOT NULL AND jsonb_typeof(payload->'scenarioIds') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'scenarioIds'))::uuid[]
                WHEN payload->'scenario_ids' IS NOT NULL AND jsonb_typeof(payload->'scenario_ids') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'scenario_ids'))::uuid[]
                ELSE NULL
            END
        FROM draft_payload_data),
        COALESCE(sd.scenario_ids::uuid[], ARRAY[]::uuid[])
    ) as scenario_ids,
    COALESCE(vs.ids::uuid[], ARRAY[]::uuid[]) as valid_scenario_ids,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        sb.active
    ) as active,
    COALESCE(
        (SELECT (payload->>'practiceSimulation')::boolean FROM draft_payload_data),
        (SELECT (payload->>'practice_simulation')::boolean FROM draft_payload_data),
        sb.practice_simulation
    ) as practice_simulation,
    -- Auto-select agents: draft payload -> simulation value -> default from SQL (if only one option) -> NULL
    COALESCE(
        (SELECT (payload->>'hint_agent_id')::uuid FROM draft_payload_data),
        sb.hint_agent_id,
        (SELECT id FROM default_hint_agent),
        NULL::uuid
    ) as hint_agent_id,
    COALESCE(
        (SELECT (payload->>'simulation_text_agent_id')::uuid FROM draft_payload_data),
        sb.simulation_text_agent_id,
        (SELECT id FROM default_simulation_agent),
        NULL::uuid
    ) as simulation_text_agent_id,
    COALESCE(
        (SELECT (payload->>'simulation_voice_agent_id')::uuid FROM draft_payload_data),
        sb.simulation_voice_agent_id,
        (SELECT id FROM default_voice_agent),
        NULL::uuid
    ) as simulation_voice_agent_id,
    CASE 
        WHEN COALESCE(sb.department_ids, NULL) IS NULL AND uc.role != 'superadmin' THEN false
        WHEN uc.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) THEN true
        ELSE false
    END as can_edit,
    CASE 
        WHEN uc.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) THEN true
        ELSE false
    END as can_duplicate,
    CASE 
        WHEN COALESCE(sb.department_ids, NULL) IS NULL AND uc.role != 'superadmin' THEN false
        WHEN sb.practice_simulation = true THEN false
        WHEN cu.total_cohort_links > 0 THEN false
        WHEN uc.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) THEN true
        ELSE false
    END as can_delete,
    CASE WHEN cu.total_cohort_links > 0 THEN true ELSE false END as in_use,
    COALESCE(cu.total_cohort_links, 0) as cohort_count,
    COALESCE(sd.scenarios, ARRAY[]::types.q_get_simulation_detail_v4_scenario[]) as scenarios,
    COALESCE(pild.parameter_items, ARRAY[]::types.q_get_simulation_detail_v4_parameter_item[]) as parameters,
    COALESCE(pild.parameter_item_details, ARRAY[]::types.q_get_simulation_detail_v4_parameter_item_detail[]) as parameter_items,
    COALESCE(sfd.scenarios_full, ARRAY[]::types.q_get_simulation_detail_v4_scenario_full[]) as scenarios_full,
    COALESCE(rd.rubrics, ARRAY[]::types.q_get_simulation_detail_v4_rubric[]) as rubrics,
    COALESCE(dd.departments, ARRAY[]::types.q_get_simulation_detail_v4_department[]) as departments,
    COALESCE(pfd.parameters, ARRAY[]::types.q_get_simulation_detail_v4_parameter[]) as parameters_full,
    COALESCE(fd.fields, ARRAY[]::types.q_get_simulation_detail_v4_field[]) as fields,
    COALESCE(ad.agents, ARRAY[]::types.q_get_simulation_detail_v4_agent[]) as agents,
    COALESCE(ad.agent_ids, ARRAY[]::uuid[]) as valid_agent_ids,
    COALESCE((SELECT draft_version FROM draft_payload_data), 0) as draft_version,
    -- Extract scenarioActiveStates and scenarioSettings from draft payload if available
    COALESCE(
        (SELECT payload->'scenarioActiveStates' FROM draft_payload_data),
        (SELECT payload->'scenario_active_states' FROM draft_payload_data),
        '{}'::jsonb
    ) as scenario_active_states,
    COALESCE(
        (SELECT payload->'scenarioSettings' FROM draft_payload_data),
        (SELECT payload->'scenario_settings' FROM draft_payload_data),
        '{}'::jsonb
    ) as scenario_settings
FROM simulation_base sb
CROSS JOIN user_context uc
CROSS JOIN cohort_usage cu
CROSS JOIN scenarios_data sd
CROSS JOIN valid_scenarios vs
CROSS JOIN rubrics_data rd
CROSS JOIN parameters_full_data pfd
CROSS JOIN fields_data fd
CROSS JOIN parameter_items_list_data pild
CROSS JOIN scenarios_full_data sfd
CROSS JOIN departments_data dd
CROSS JOIN agents_data ad
$$;


--
-- Name: api_get_simulation_metadata_for_chat_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_simulation_metadata_for_chat_v4(chat_id uuid) RETURNS TABLE(simulation_id text, attempt_id text, practice_simulation boolean)
    LANGUAGE sql STABLE
    AS $$
SELECT 
    sa.simulation_id::text,
    sa.id::text as attempt_id,
    s.practice_simulation
FROM chats sc
JOIN attempt_chats ac ON ac.chat_id = sc.id
INNER JOIN simulation_attempts sa ON sa.id = ac.attempt_id
INNER JOIN simulations s ON s.id = sa.simulation_id
WHERE sc.id = chat_id
$$;


--
-- Name: api_get_simulation_new_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_simulation_new_v4(profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(actor_name text, name text, description text, department_ids uuid[], valid_department_ids uuid[], time_limit integer, rubric_id uuid, valid_rubric_ids uuid[], scenario_ids uuid[], valid_scenario_ids uuid[], video_ids uuid[], valid_video_ids uuid[], active boolean, practice_simulation boolean, hint_agent_id uuid, simulation_text_agent_id uuid, simulation_voice_agent_id uuid, member_agent_id uuid, can_edit boolean, can_duplicate boolean, can_delete boolean, in_use boolean, cohort_count bigint, scenarios types.q_get_simulation_new_v4_scenario[], videos types.q_get_simulation_new_v4_video[], parameters types.q_get_simulation_new_v4_parameter_item[], parameter_items types.q_get_simulation_new_v4_parameter_item_detail[], scenarios_full types.q_get_simulation_new_v4_scenario_full[], rubrics types.q_get_simulation_new_v4_rubric[], departments types.q_get_simulation_new_v4_department[], parameters_full types.q_get_simulation_new_v4_parameter[], fields types.q_get_simulation_new_v4_field[], agents types.q_get_simulation_new_v4_agent[], valid_agent_ids uuid[], primary_department_id uuid, draft_version integer, scenario_active_states jsonb, scenario_settings jsonb)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        profile_id AS profile_id,
        draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'simulations'::draft_resource_type
    LIMIT 1
),
user_departments AS (
    SELECT DISTINCT pd.department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.active = true
),
user_profile AS (
    SELECT 
        role,
        first_name || ' ' || last_name as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
primary_department_id AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.is_primary = TRUE
    LIMIT 1
),
cohort_usage AS (
    SELECT 
        0 as active_cohort_count,
        0 as total_cohort_links
),
user_department_ids AS (
    SELECT ARRAY_AGG(id) as ids
    FROM departments d
    JOIN params x ON true
    JOIN profile_departments pd ON d.id = pd.department_id
    WHERE pd.profile_id = x.profile_id AND d.active = true
),
valid_scenarios_list AS (
    SELECT DISTINCT
        s.id,
        s.name,
        COALESCE(ps.problem_statement, '') as description
    FROM scenarios s
    LEFT JOIN scenario_problem_statements sps ON sps.scenario_id = s.id AND sps.active = true
    LEFT JOIN problem_statements ps ON ps.id = sps.problem_statement_id
    LEFT JOIN scenario_departments sd ON sd.scenario_id = s.id AND sd.active = true
    CROSS JOIN user_department_ids udi
    JOIN scenario_tree st ON st.parent_id = s.id AND st.child_id = s.id
    WHERE s.active = true
      AND (
          sd.department_id = ANY(udi.ids)
          OR NOT EXISTS (SELECT 1 FROM scenario_departments sd2 WHERE sd2.scenario_id = s.id AND sd2.active = true)
      )
),
valid_scenarios AS (
    SELECT ARRAY_AGG(id::text) as ids
    FROM valid_scenarios_list
),
valid_videos_list AS (
    SELECT DISTINCT
        v.id,
        v.name,
        v.length_seconds
    FROM videos v
    JOIN scenario_videos sv ON sv.video_id = v.id AND sv.active = true
    JOIN valid_scenarios_list vsl ON vsl.id = sv.scenario_id
    WHERE v.active = true
),
valid_videos AS (
    SELECT ARRAY_AGG(id::text) as ids
    FROM valid_videos_list
),
videos_data AS (
    SELECT 
        ARRAY_AGG(
            (vvl.id, vvl.name, ''::text, vvl.length_seconds)::types.q_get_simulation_new_v4_video
            ORDER BY vvl.name
        ) as videos
    FROM valid_videos_list vvl
),
valid_rubrics_data AS (
    SELECT DISTINCT
        r.id,
        r.name,
        COALESCE(r.description, '') as description
    FROM rubrics r
    LEFT JOIN rubric_departments rd ON rd.rubric_id = r.id AND rd.active = true
    CROSS JOIN user_department_ids udi
    WHERE r.active = true
      AND r.agent_role = 'member'::agent_role
      AND (
          rd.department_id = ANY(udi.ids)
          OR NOT EXISTS (SELECT 1 FROM rubric_departments rd2 WHERE rd2.rubric_id = r.id AND rd2.active = true)
      )
),
rubrics_data AS (
    SELECT 
        ARRAY_AGG(
            (vr.id, vr.name, vr.description)::types.q_get_simulation_new_v4_rubric
            ORDER BY vr.name
        ) as rubrics,
        ARRAY_AGG(vr.id::text) as rubric_ids
    FROM valid_rubrics_data vr
),
parameters_data AS (
    SELECT DISTINCT
        p.id,
        p.name,
        COALESCE(p.description, '') as description,
        p.document_parameter,
        p.persona_parameter
    FROM parameters p
    JOIN parameter_fields fp ON fp.parameter_id = p.id AND fp.active = true
    LEFT JOIN field_departments fd ON fd.field_id = fp.field_id AND fd.active = true
    CROSS JOIN user_department_ids udi
    WHERE p.active = true
    GROUP BY p.id, p.name, p.description, p.document_parameter, p.persona_parameter
    HAVING 
        COUNT(fd.field_id) FILTER (WHERE fd.department_id = ANY(udi.ids)) > 0
        OR NOT EXISTS (SELECT 1 FROM field_departments fd2 
                      JOIN parameter_fields fp2 ON fp2.field_id = fd2.field_id 
                      WHERE fp2.parameter_id = p.id AND fp2.active = true AND fd2.active = true)
),
parameters_full_data AS (
    SELECT 
        ARRAY_AGG(
            (pd.id, pd.name, pd.description, pd.document_parameter, pd.persona_parameter)::types.q_get_simulation_new_v4_parameter
            ORDER BY pd.name
        ) as parameters
    FROM parameters_data pd
),
parameter_items_data AS (
    SELECT 
        f.id,
        fp.parameter_id,
        f.name,
        COALESCE(f.description, '') as description,
        p.name as parameter_name
    FROM fields f
    JOIN parameter_fields fp ON fp.field_id = f.id AND fp.active = true
    JOIN parameters p ON p.id = fp.parameter_id
    WHERE p.id IN (SELECT id FROM parameters_data)
),
parameter_items_list_data AS (
    SELECT 
        ARRAY_AGG(
            (pid.id, pid.parameter_id, pid.name, pid.description)::types.q_get_simulation_new_v4_parameter_item
            ORDER BY pid.name
        ) as parameter_items,
        ARRAY_AGG(
            (pid.id, pid.name, pid.description, pid.parameter_id)::types.q_get_simulation_new_v4_parameter_item_detail
            ORDER BY pid.name
        ) as parameter_item_details
    FROM parameter_items_data pid
),
fields_data AS (
    SELECT 
        ARRAY_AGG(
            (pid.id, pid.name, pid.description, pid.parameter_id, pid.parameter_name)::types.q_get_simulation_new_v4_field
            ORDER BY pid.name
        ) as fields
    FROM parameter_items_data pid
),
scenario_persona_data AS (
    SELECT 
        sp.scenario_id,
        sp.persona_id,
        p.name as persona_name,
        COALESCE(p.description, '') as persona_description,
        p.color as persona_color,
        p.icon as persona_icon,
        false as image_model
    FROM scenario_personas sp
    JOIN personas p ON p.id = sp.persona_id
    WHERE sp.scenario_id IN (SELECT id FROM valid_scenarios_list)
      AND sp.active = true
),
scenario_persona_mapping AS (
    SELECT 
        spd.scenario_id,
        ARRAY_AGG(
            (spd.persona_id, spd.persona_name, spd.persona_description, spd.persona_color, spd.persona_icon, spd.image_model)::types.q_get_simulation_new_v4_persona
            ORDER BY spd.persona_name
        ) as personas
    FROM scenario_persona_data spd
    GROUP BY spd.scenario_id
),
scenario_documents_data AS (
    SELECT 
        sd.scenario_id,
        ARRAY_AGG(sd.document_id) as document_ids
    FROM scenario_documents sd
    WHERE sd.scenario_id IN (SELECT id FROM valid_scenarios_list)
      AND sd.active = true
    GROUP BY sd.scenario_id
),
scenario_document_mapping AS (
    SELECT 
        sdd.scenario_id,
        ARRAY_AGG(
            (d.id, d.name, ''::text)::types.q_get_simulation_new_v4_document
            ORDER BY d.name
        ) as documents
    FROM scenario_documents_data sdd
    JOIN documents d ON d.id = ANY(sdd.document_ids)
    GROUP BY sdd.scenario_id
),
scenario_parameter_items_data AS (
    SELECT 
        sf.scenario_id,
        ARRAY_AGG(DISTINCT sf.field_id) as parameter_item_ids
    FROM scenario_fields sf
    WHERE sf.scenario_id IN (SELECT id FROM valid_scenarios_list)
      AND sf.active = true
    GROUP BY sf.scenario_id
),
scenario_field_mapping AS (
    SELECT 
        spid.scenario_id,
        ARRAY_AGG(
            (pid.id, pid.name, pid.description, pid.parameter_id, pid.parameter_name)::types.q_get_simulation_new_v4_field
            ORDER BY pid.name
        ) as fields
    FROM scenario_parameter_items_data spid
    JOIN parameter_items_data pid ON pid.id = ANY(spid.parameter_item_ids)
    GROUP BY spid.scenario_id
),
scenarios_full_data AS (
    SELECT 
        ARRAY_AGG(
            (vsl.id, vsl.name, vsl.description,
             COALESCE(
                 (SELECT ARRAY_AGG(spd.persona_id) FROM scenario_persona_data spd WHERE spd.scenario_id = vsl.id),
                 ARRAY[]::uuid[]
             ),
             COALESCE(spm.personas, ARRAY[]::types.q_get_simulation_new_v4_persona[]),
             COALESCE(sdm.documents, ARRAY[]::types.q_get_simulation_new_v4_document[]),
             COALESCE(sfm.fields, ARRAY[]::types.q_get_simulation_new_v4_field[]),
             COALESCE(
                 (SELECT spid.parameter_item_ids FROM scenario_parameter_items_data spid WHERE spid.scenario_id = vsl.id),
                 ARRAY[]::uuid[]
             ),
             COALESCE(
                 (SELECT sdd.document_ids FROM scenario_documents_data sdd WHERE sdd.scenario_id = vsl.id),
                 ARRAY[]::uuid[]
             )
            )::types.q_get_simulation_new_v4_scenario_full
            ORDER BY vsl.name
        ) as scenarios_full
    FROM valid_scenarios_list vsl
    LEFT JOIN scenario_persona_mapping spm ON spm.scenario_id = vsl.id
    LEFT JOIN scenario_document_mapping sdm ON sdm.scenario_id = vsl.id
    LEFT JOIN scenario_field_mapping sfm ON sfm.scenario_id = vsl.id
),
user_departments_for_mapping AS (
    SELECT DISTINCT d.id, d.title as name, d.description
    FROM departments d
    JOIN params x ON true
    JOIN profile_departments pd ON d.id = pd.department_id
    WHERE pd.profile_id = x.profile_id AND d.active = true
),
department_scenario_ids_default AS (
    SELECT 
        ud.id as department_id,
        COALESCE(ARRAY_AGG(DISTINCT s.id ORDER BY s.id) FILTER (WHERE s.id IS NOT NULL), ARRAY[]::uuid[]) as scenario_ids
    FROM user_departments_for_mapping ud
    LEFT JOIN scenarios s ON s.active = true
    INNER JOIN scenario_tree st ON st.parent_id = s.id AND st.child_id = s.id
    LEFT JOIN scenario_departments sd ON sd.scenario_id = s.id AND sd.active = true
    WHERE (sd.department_id = ud.id OR NOT EXISTS (SELECT 1 FROM scenario_departments sd2 WHERE sd2.scenario_id = s.id AND sd2.active = true))
    GROUP BY ud.id
),
department_rubric_ids_default AS (
    SELECT 
        ud.id as department_id,
        COALESCE(ARRAY_AGG(DISTINCT r.id ORDER BY r.id) FILTER (WHERE r.id IS NOT NULL), ARRAY[]::uuid[]) as rubric_ids
    FROM user_departments_for_mapping ud
    LEFT JOIN rubrics r ON r.active = true AND r.agent_role = 'member'::agent_role
    LEFT JOIN rubric_departments rd ON rd.rubric_id = r.id AND rd.active = true
    WHERE (rd.department_id = ud.id OR NOT EXISTS (SELECT 1 FROM rubric_departments rd2 WHERE rd2.rubric_id = r.id AND rd2.active = true))
    GROUP BY ud.id
),
departments_data AS (
    SELECT 
        ARRAY_AGG(
            (ud.id, ud.name, ud.description,
             COALESCE(dsci.scenario_ids, ARRAY[]::uuid[]),
             COALESCE(dri.rubric_ids, ARRAY[]::uuid[]),
             ARRAY[]::uuid[]
            )::types.q_get_simulation_new_v4_department
            ORDER BY ud.name
        ) as departments,
        ARRAY_AGG(DISTINCT ud.id::text) as department_ids
    FROM user_departments_for_mapping ud
    LEFT JOIN department_scenario_ids_default dsci ON dsci.department_id = ud.id
    LEFT JOIN department_rubric_ids_default dri ON dri.department_id = ud.id
),
user_departments_for_agents AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id
    WHERE pd.active = true
),
agents_data AS (
    SELECT 
        ARRAY_AGG(
            (filtered_agents.id, filtered_agents.name, COALESCE(filtered_agents.description, ''), ARRAY[filtered_agents.role::text])::types.q_get_simulation_new_v4_agent
            ORDER BY filtered_agents.name
        ) as agents,
        ARRAY_AGG(filtered_agents.id ORDER BY filtered_agents.name) as agent_ids
    FROM (
        SELECT DISTINCT a.id, a.name, a.description, a.role
        FROM agents a
        LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
        WHERE a.active = true 
        AND a.role IN ('hint'::agent_role, 'grade'::agent_role, 'audio'::agent_role, 'simulation'::agent_role, 'voice'::agent_role, 'member'::agent_role)
        GROUP BY a.id, a.name, a.description, a.role
        HAVING 
            COUNT(ad.agent_id) FILTER (WHERE ad.department_id IN (SELECT department_id FROM user_departments_for_agents)) > 0
            OR NOT EXISTS (SELECT 1 FROM agent_departments ad2 WHERE ad2.agent_id = a.id AND ad2.active = true)
        UNION
        -- Get rubric agents (member role) from rubrics.rubric_agent_id
        SELECT DISTINCT a.id, a.name, a.description, a.role
        FROM rubrics r
        JOIN agents a ON a.id = r.rubric_agent_id AND a.role = 'member'::agent_role
        WHERE a.active = true AND r.rubric_agent_id IS NOT NULL
    ) filtered_agents
),
-- Auto-select default agents when there's only one option for each role
valid_hint_agents AS (
    SELECT DISTINCT a.id
    FROM agents a
    LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
    WHERE a.active = true 
    AND a.role = 'hint'::agent_role
    GROUP BY a.id
    HAVING 
        COUNT(ad.agent_id) FILTER (WHERE ad.department_id IN (SELECT department_id FROM user_departments_for_agents)) > 0
        OR NOT EXISTS (SELECT 1 FROM agent_departments ad2 WHERE ad2.agent_id = a.id AND ad2.active = true)
),
valid_simulation_agents AS (
    SELECT DISTINCT a.id
    FROM agents a
    LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
    WHERE a.active = true 
    AND a.role = 'simulation'::agent_role
    GROUP BY a.id
    HAVING 
        COUNT(ad.agent_id) FILTER (WHERE ad.department_id IN (SELECT department_id FROM user_departments_for_agents)) > 0
        OR NOT EXISTS (SELECT 1 FROM agent_departments ad2 WHERE ad2.agent_id = a.id AND ad2.active = true)
),
valid_voice_agents AS (
    SELECT DISTINCT a.id
    FROM agents a
    LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
    WHERE a.active = true 
    AND a.role = 'voice'::agent_role
    GROUP BY a.id
    HAVING 
        COUNT(ad.agent_id) FILTER (WHERE ad.department_id IN (SELECT department_id FROM user_departments_for_agents)) > 0
        OR NOT EXISTS (SELECT 1 FROM agent_departments ad2 WHERE ad2.agent_id = a.id AND ad2.active = true)
),
valid_member_agents AS (
    SELECT DISTINCT a.id
    FROM agents a
    LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
    WHERE a.active = true 
    AND a.role = 'member'::agent_role
    GROUP BY a.id
    HAVING 
        COUNT(ad.agent_id) FILTER (WHERE ad.department_id IN (SELECT department_id FROM user_departments_for_agents)) > 0
        OR NOT EXISTS (SELECT 1 FROM agent_departments ad2 WHERE ad2.agent_id = a.id AND ad2.active = true)
    UNION
    -- Get rubric agents (member role) from rubrics.rubric_agent_id
    SELECT DISTINCT a.id
    FROM rubrics r
    JOIN agents a ON a.id = r.rubric_agent_id AND a.role = 'member'::agent_role
    WHERE a.active = true 
    AND r.active = true
    AND r.rubric_agent_id IS NOT NULL
),
default_hint_agent AS (
    SELECT id FROM valid_hint_agents
    WHERE (SELECT COUNT(*) FROM valid_hint_agents) = 1
    LIMIT 1
),
default_simulation_agent AS (
    SELECT id FROM valid_simulation_agents
    WHERE (SELECT COUNT(*) FROM valid_simulation_agents) = 1
    LIMIT 1
),
default_voice_agent AS (
    SELECT id FROM valid_voice_agents
    WHERE (SELECT COUNT(*) FROM valid_voice_agents) = 1
    LIMIT 1
),
default_member_agent AS (
    SELECT id FROM valid_member_agents
    WHERE (SELECT COUNT(*) FROM valid_member_agents) = 1
    LIMIT 1
)
SELECT 
    up.actor_name::text as actor_name,
    -- Default values for new simulation (merged with draft payload if draft_id provided)
    COALESCE(
        (SELECT payload->>'title' FROM draft_payload_data),
        ''::text
    ) as name,
    COALESCE(
        (SELECT payload->>'description' FROM draft_payload_data),
        ''::text
    ) as description,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'departmentIds' IS NOT NULL AND jsonb_typeof(payload->'departmentIds') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'departmentIds'))::uuid[]
                WHEN payload->'department_ids' IS NOT NULL AND jsonb_typeof(payload->'department_ids') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'department_ids'))::uuid[]
                ELSE NULL
            END
        FROM draft_payload_data),
        CASE 
            WHEN up.role = 'superadmin'::profile_role THEN NULL::uuid[]
            ELSE COALESCE(ARRAY[pdi.department_id], ARRAY[]::uuid[])
        END
    ) as department_ids,
    COALESCE(dd.department_ids::uuid[], ARRAY[]::uuid[]) as valid_department_ids,
    0 as time_limit,
    NULL::uuid as rubric_id,
    COALESCE(rd.rubric_ids::uuid[], ARRAY[]::uuid[]) as valid_rubric_ids,
    -- Extract scenario_ids from draft payload if available
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'scenarioIds' IS NOT NULL AND jsonb_typeof(payload->'scenarioIds') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'scenarioIds'))::uuid[]
                WHEN payload->'scenario_ids' IS NOT NULL AND jsonb_typeof(payload->'scenario_ids') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'scenario_ids'))::uuid[]
                ELSE NULL
            END
        FROM draft_payload_data),
        ARRAY[]::uuid[]
    ) as scenario_ids,
    COALESCE(vs.ids::uuid[], ARRAY[]::uuid[]) as valid_scenario_ids,
    ARRAY[]::uuid[] as video_ids,
    COALESCE(vv.ids::uuid[], ARRAY[]::uuid[]) as valid_video_ids,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        true
    ) as active,
    COALESCE(
        (SELECT (payload->>'practiceSimulation')::boolean FROM draft_payload_data),
        (SELECT (payload->>'practice_simulation')::boolean FROM draft_payload_data),
        false
    ) as practice_simulation,
    -- Auto-select agents: draft payload -> default from SQL (if only one option) -> NULL
    COALESCE(
        (SELECT (payload->>'hint_agent_id')::uuid FROM draft_payload_data),
        (SELECT id FROM default_hint_agent),
        NULL::uuid
    ) as hint_agent_id,
    COALESCE(
        (SELECT (payload->>'simulation_text_agent_id')::uuid FROM draft_payload_data),
        (SELECT id FROM default_simulation_agent),
        NULL::uuid
    ) as simulation_text_agent_id,
    COALESCE(
        (SELECT (payload->>'simulation_voice_agent_id')::uuid FROM draft_payload_data),
        (SELECT id FROM default_voice_agent),
        NULL::uuid
    ) as simulation_voice_agent_id,
    -- Auto-select member agent: draft payload -> default from SQL (if only one option) -> NULL
    COALESCE(
        (SELECT (payload->>'member_agent_id')::uuid FROM draft_payload_data),
        (SELECT id FROM default_member_agent),
        NULL::uuid
    ) as member_agent_id,
    CASE 
        WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) THEN true
        ELSE false
    END as can_edit,
    CASE 
        WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) THEN true
        ELSE false
    END as can_duplicate,
    false as can_delete,
    false as in_use,
    0::bigint as cohort_count,
    ARRAY[]::types.q_get_simulation_new_v4_scenario[] as scenarios,
    COALESCE(vd.videos, ARRAY[]::types.q_get_simulation_new_v4_video[]) as videos,
    COALESCE(pild.parameter_items, ARRAY[]::types.q_get_simulation_new_v4_parameter_item[]) as parameters,
    COALESCE(pild.parameter_item_details, ARRAY[]::types.q_get_simulation_new_v4_parameter_item_detail[]) as parameter_items,
    COALESCE(sfd.scenarios_full, ARRAY[]::types.q_get_simulation_new_v4_scenario_full[]) as scenarios_full,
    COALESCE(rd.rubrics, ARRAY[]::types.q_get_simulation_new_v4_rubric[]) as rubrics,
    COALESCE(dd.departments, ARRAY[]::types.q_get_simulation_new_v4_department[]) as departments,
    COALESCE(pfd.parameters, ARRAY[]::types.q_get_simulation_new_v4_parameter[]) as parameters_full,
    COALESCE(fd.fields, ARRAY[]::types.q_get_simulation_new_v4_field[]) as fields,
    COALESCE(ad.agents, ARRAY[]::types.q_get_simulation_new_v4_agent[]) as agents,
    COALESCE(ad.agent_ids, ARRAY[]::uuid[]) as valid_agent_ids,
    pdi.department_id as primary_department_id,
    COALESCE((SELECT draft_version FROM draft_payload_data), 0) as draft_version,
    -- Extract scenarioActiveStates and scenarioSettings from draft payload if available
    COALESCE(
        (SELECT payload->'scenarioActiveStates' FROM draft_payload_data),
        (SELECT payload->'scenario_active_states' FROM draft_payload_data),
        '{}'::jsonb
    ) as scenario_active_states,
    COALESCE(
        (SELECT payload->'scenarioSettings' FROM draft_payload_data),
        (SELECT payload->'scenario_settings' FROM draft_payload_data),
        '{}'::jsonb
    ) as scenario_settings
FROM user_profile up
CROSS JOIN cohort_usage cu
CROSS JOIN valid_scenarios vs
CROSS JOIN valid_videos vv
CROSS JOIN rubrics_data rd
CROSS JOIN parameters_full_data pfd
CROSS JOIN fields_data fd
CROSS JOIN parameter_items_list_data pild
CROSS JOIN scenarios_full_data sfd
CROSS JOIN departments_data dd
CROSS JOIN agents_data ad
CROSS JOIN videos_data vd
LEFT JOIN primary_department_id pdi ON true
$$;


--
-- Name: api_get_simulation_run_context_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_simulation_run_context_v4(chat_id uuid) RETURNS TABLE(chat_id text, chat_title text, trace_id text, attempt_id text, simulation_id text, scenario_id text, department_id text, problem_statement text, persona_id text, persona_name text, system_prompt text, temperature double precision, reasoning text, model_id text, model_name text, provider text, base_url text, api_key text, custom_model text, provider_id text, provider_name text, agent_id text, voice_system_prompt text, voice_temperature double precision, voice_reasoning text, voice_model_id text, voice_model_name text, voice_provider text, voice_base_url text, voice_api_key text, voice_custom_model text, voice_provider_name text, voice_agent_id text, image_input_enabled boolean, copy_paste_allowed boolean, profile_id text, req_per_day integer, runs_today_count bigint, earliest_run_created_at timestamp with time zone, documents json)
    LANGUAGE sql STABLE
    AS $$
WITH scenario_dept AS (
    SELECT 
        s.id as scenario_id,
        (SELECT sd.department_id FROM scenario_departments sd 
         WHERE sd.scenario_id = s.id AND sd.active = true LIMIT 1) as department_id
    FROM chats sc
    JOIN attempt_chats ac ON ac.chat_id = sc.id
    INNER JOIN simulation_attempts sa ON sa.id = ac.attempt_id
    INNER JOIN scenarios s ON s.id = sc.scenario_id
    WHERE sc.id = chat_id
),
profile_dept AS (
    -- Get first department from profile's accessible departments
    SELECT d.id as department_id
    FROM departments d
    JOIN profile_departments pd ON pd.department_id = d.id
    JOIN attempt_profiles ap ON ap.profile_id = pd.profile_id
    JOIN attempt_chats ac ON ac.attempt_id = ap.attempt_id
    WHERE ac.chat_id = chat_id 
      AND ap.active = true 
      AND d.active = true
    LIMIT 1
),
any_active_dept AS (
    -- Get any active department as last resort
    SELECT id as department_id
    FROM departments
    WHERE active = true
    LIMIT 1
),
resolved_dept AS (
    -- Resolve department_id with fallback: scenario -> profile -> any active
    SELECT COALESCE(
        (SELECT department_id FROM scenario_dept),
        (SELECT department_id FROM profile_dept),
        (SELECT department_id FROM any_active_dept)
    ) as department_id
),
profile_rate_limit AS (
    -- Get rate limit for the profile (via attempt_profiles)
    SELECT 
        prl.requests_per_day as req_per_day
    FROM profiles p
    LEFT JOIN profile_request_limits prl ON prl.profile_id = p.id AND prl.active = true
    WHERE p.id = (SELECT ap.profile_id FROM attempt_profiles ap 
                  JOIN attempt_chats ac ON ac.attempt_id = ap.attempt_id 
                  WHERE ac.chat_id = chat_id AND ap.active = true LIMIT 1)
),
runs_today AS (
    -- Count model runs for this profile since start of day
    SELECT 
        COUNT(*)::bigint as runs_today_count,
        MIN(mr.created_at) as earliest_run_created_at
    FROM runs mr
    JOIN run_profiles mrp ON mrp.run_id = mr.id
    WHERE mrp.profile_id = (SELECT ap.profile_id FROM attempt_profiles ap 
                            JOIN attempt_chats ac ON ac.attempt_id = ap.attempt_id 
                            WHERE ac.chat_id = chat_id AND ap.active = true LIMIT 1)
      AND mrp.active = true
      AND mr.created_at >= date_trunc('day', NOW() AT TIME ZONE 'UTC') AT TIME ZONE 'UTC'
),
profile_from_attempt AS (
    -- Get profile_id from attempt_profiles for settings resolution
    SELECT ap.profile_id
    FROM attempt_profiles ap 
    JOIN attempt_chats ac ON ac.attempt_id = ap.attempt_id 
    WHERE ac.chat_id = chat_id AND ap.active = true
    LIMIT 1
),
-- Get active settings for profile (for key lookup via setting_provider_keys)
default_settings AS (
    -- Get settings with no department links (cross-department/default)
    SELECT s.id as settings_id
    FROM settings s
    WHERE s.active = true
      AND NOT EXISTS (
          SELECT 1 FROM department_settings sd 
          WHERE sd.settings_id = s.id AND sd.active = true
      )
    LIMIT 1
),
profile_primary_department AS (
    -- Get profile's primary department ID
    SELECT pd.department_id
    FROM profile_from_attempt pfa
    JOIN profile_departments pd ON pd.profile_id = pfa.profile_id
    WHERE pd.is_primary = TRUE 
      AND pd.active = true
    LIMIT 1
),
dept_specific_settings AS (
    -- Get department-specific settings (if primary_department_id exists)
    SELECT s.id as settings_id
    FROM settings s
    JOIN department_settings sd ON sd.settings_id = s.id
    JOIN profile_primary_department ppd ON sd.department_id = ppd.department_id
    WHERE s.active = true 
      AND sd.active = true
    LIMIT 1
),
settings_with_keys AS (
    -- Settings that have at least one active provider key
    SELECT DISTINCT spk.settings_id
    FROM setting_provider_keys spk
    JOIN keys k ON k.id = spk.key_id
    WHERE spk.active = true AND k.active = true
),
dept_specific_settings_with_keys AS (
    -- Department-specific settings that have keys
    SELECT s.id as settings_id
    FROM settings s
    JOIN department_settings sd ON sd.settings_id = s.id
    JOIN profile_primary_department ppd ON sd.department_id = ppd.department_id
    JOIN settings_with_keys swk ON swk.settings_id = s.id
    WHERE s.active = true AND sd.active = true
    LIMIT 1
),
default_settings_with_keys AS (
    -- Default settings that have keys
    SELECT s.id as settings_id
    FROM settings s
    JOIN settings_with_keys swk ON swk.settings_id = s.id
    WHERE s.active = true
      AND NOT EXISTS (
          SELECT 1 FROM department_settings sd 
          WHERE sd.settings_id = s.id AND sd.active = true
      )
    LIMIT 1
),
active_settings AS (
    -- Prefer department-specific with keys, then default with keys, then any with keys, then fallback
    -- Only use department-specific/default settings if they have keys, otherwise prefer any settings with keys
    SELECT 
        COALESCE(
            (SELECT settings_id FROM dept_specific_settings_with_keys),
            (SELECT settings_id FROM default_settings_with_keys),
            (SELECT settings_id FROM settings_with_keys LIMIT 1),  -- Any with keys
            (SELECT settings_id FROM dept_specific_settings),  -- Original fallback (no keys available)
            (SELECT settings_id FROM default_settings),  -- Original fallback (no keys available)
            (SELECT id FROM settings WHERE active = true LIMIT 1)  -- Last resort
        ) as settings_id
)
SELECT 
    -- Chat data
    sc.id::text as chat_id,
    sc.title as chat_title,
    (SELECT g.trace_id FROM groups g JOIN chat_groups cg ON cg.group_id = g.id WHERE cg.chat_id = sc.id LIMIT 1) as trace_id,
    
    -- Attempt data
    sa.id::text as attempt_id,
    sa.simulation_id::text,
    
    -- Scenario data
    s.id::text as scenario_id,
    (SELECT department_id::text FROM resolved_dept) as department_id,
    ps.problem_statement,
    
    -- Persona data (via scenario_personas junction - first persona for orchestrator)
    p.id::text as persona_id,
    p.name as persona_name,
    
    -- Text agent/model data (backward compatibility - existing fields)
    COALESCE(
        COALESCE(pr_prompt_dept.system_prompt, pr_prompt_default.system_prompt),
        ''
    ) as system_prompt,
    COALESCE(mtl.temperature, 0.0) as temperature,
    mrl.reasoning_level as reasoning,
    m.id::text as model_id,
    m.value as model_name,
    COALESCE(p_prov.value::text, '') as provider,
    COALESCE(me.base_url, '') as base_url,
    k.key as api_key,
    CASE WHEN me.base_url IS NOT NULL AND me.base_url != '' THEN m.value ELSE NULL END as custom_model,
    NULL::text as provider_id,
    COALESCE(p_prov.value::text, '') as provider_name,
    a.id::text as agent_id,
    
    -- Voice agent/model data (prefixed with voice_*)
    COALESCE(
        COALESCE(pr_prompt_voice_dept.system_prompt, pr_prompt_voice_default.system_prompt),
        ''
    ) as voice_system_prompt,
    COALESCE(mtl_voice.temperature, 0.0) as voice_temperature,
    mrl_voice.reasoning_level as voice_reasoning,
    m_voice.id::text as voice_model_id,
    m_voice.value as voice_model_name,
    COALESCE(p_voice.value::text, '') as voice_provider,
    COALESCE(me_voice.base_url, '') as voice_base_url,
    k_voice.key as voice_api_key,
    CASE WHEN me_voice.base_url IS NOT NULL AND me_voice.base_url != '' THEN m_voice.value ELSE NULL END as voice_custom_model,
    COALESCE(p_voice.value::text, '') as voice_provider_name,
    a_voice.id::text as voice_agent_id,
    
    -- Scenario settings (flags moved from scenarios to simulation_scenarios)
    COALESCE(s.images_enabled, false) as image_input_enabled,
    COALESCE(ss.copy_paste_allowed, false) as copy_paste_allowed,
    
    -- Profile data (via attempt_profiles junction)
    ap.profile_id::text as profile_id,
    
    -- Rate limit data
    prl.req_per_day,
    COALESCE(rt.runs_today_count, 0::bigint) as runs_today_count,
    rt.earliest_run_created_at,
    
    -- Documents data (aggregated as JSON array with full document info)
    COALESCE(
        json_agg(
            json_build_object(
                'id', d.id::text,
                'name', d.name,
                'file_path', u.file_path,
                'mime_type', u.mime_type
            )
            ORDER BY d.id
        ) FILTER (WHERE d.id IS NOT NULL AND sd.active = true),
        '[]'::json
    ) as documents

FROM chats sc
JOIN attempt_chats ac ON ac.chat_id = sc.id
INNER JOIN simulation_attempts sa ON sa.id = ac.attempt_id
INNER JOIN scenarios s ON s.id = sc.scenario_id
LEFT JOIN simulation_scenarios ss ON ss.simulation_id = sa.simulation_id AND ss.scenario_id = s.id
LEFT JOIN scenario_problem_statements sps ON sps.scenario_id = s.id AND sps.active = true
LEFT JOIN problem_statements ps ON ps.id = sps.problem_statement_id
INNER JOIN simulations sim ON sim.id = sa.simulation_id
-- Get first persona for orchestrator (ensures single row for orchestrator config)
LEFT JOIN (
    SELECT DISTINCT ON (sp.scenario_id) 
        sp.scenario_id,
        sp.persona_id,
        p.name as persona_name
    FROM scenario_personas sp
    JOIN personas p ON p.id = sp.persona_id
    WHERE sp.active = true AND p.active = true
    ORDER BY sp.scenario_id, p.name
) first_persona ON first_persona.scenario_id = s.id
LEFT JOIN personas p ON p.id = first_persona.persona_id

-- Text agent joins (use simulation agent instead of persona agent)
LEFT JOIN agents a ON a.id = sim.simulation_text_agent_id AND a.active = true
LEFT JOIN models m ON m.id = a.model_id
LEFT JOIN agent_temperature_levels atl ON atl.agent_id = a.id AND atl.active = true
LEFT JOIN model_temperature_levels mtl ON mtl.id = atl.model_temperature_level_id AND mtl.active = true AND mtl.model_id = m.id
LEFT JOIN agent_reasoning_levels arl ON arl.agent_id = a.id AND arl.active = true
LEFT JOIN model_reasoning_levels mrl ON mrl.id = arl.model_reasoning_level_id AND mrl.active = true AND mrl.model_id = m.id
LEFT JOIN agent_department_prompts adp_prompt ON adp_prompt.agent_id = a.id 
    AND adp_prompt.department_id = (SELECT department_id FROM resolved_dept)
    AND adp_prompt.active = true
LEFT JOIN prompts pr_prompt_dept ON pr_prompt_dept.id = adp_prompt.prompt_id
LEFT JOIN agent_prompts ap_default ON ap_default.agent_id = a.id AND ap_default.active = true
LEFT JOIN prompts pr_prompt_default ON pr_prompt_default.id = ap_default.prompt_id
LEFT JOIN model_endpoints me ON me.model_id = m.id AND me.active = true
-- Get keys via settings system: provider -> active settings -> setting_provider_keys
LEFT JOIN providers p_prov ON p_prov.id = m.provider_id
CROSS JOIN active_settings act_s
LEFT JOIN setting_provider_keys spk ON spk.provider_id = p_prov.id 
    AND spk.settings_id = act_s.settings_id 
    AND spk.active = true
LEFT JOIN keys k ON k.id = spk.key_id AND k.active = true

-- Voice agent joins (use simulation agent instead of persona agent)
LEFT JOIN agents a_voice ON a_voice.id = sim.simulation_voice_agent_id AND a_voice.active = true
LEFT JOIN models m_voice ON m_voice.id = a_voice.model_id
LEFT JOIN agent_temperature_levels atl_voice ON atl_voice.agent_id = a_voice.id AND atl_voice.active = true
LEFT JOIN model_temperature_levels mtl_voice ON mtl_voice.id = atl_voice.model_temperature_level_id AND mtl_voice.active = true AND mtl_voice.model_id = m_voice.id
LEFT JOIN agent_reasoning_levels arl_voice ON arl_voice.agent_id = a_voice.id AND arl_voice.active = true
LEFT JOIN model_reasoning_levels mrl_voice ON mrl_voice.id = arl_voice.model_reasoning_level_id AND mrl_voice.active = true AND mrl_voice.model_id = m_voice.id
LEFT JOIN agent_department_prompts adp_prompt_voice ON adp_prompt_voice.agent_id = a_voice.id 
    AND adp_prompt_voice.department_id = (SELECT department_id FROM resolved_dept)
    AND adp_prompt_voice.active = true
LEFT JOIN prompts pr_prompt_voice_dept ON pr_prompt_voice_dept.id = adp_prompt_voice.prompt_id
LEFT JOIN agent_prompts ap_voice_default ON ap_voice_default.agent_id = a_voice.id AND ap_voice_default.active = true
LEFT JOIN prompts pr_prompt_voice_default ON pr_prompt_voice_default.id = ap_voice_default.prompt_id
LEFT JOIN model_endpoints me_voice ON me_voice.model_id = m_voice.id AND me_voice.active = true
-- Get voice keys via settings system: provider -> active settings -> setting_provider_keys
LEFT JOIN providers p_voice ON p_voice.id = m_voice.provider_id
CROSS JOIN active_settings act_s_voice
LEFT JOIN setting_provider_keys spk_voice ON spk_voice.provider_id = p_voice.id 
    AND spk_voice.settings_id = act_s_voice.settings_id 
    AND spk_voice.active = true
LEFT JOIN keys k_voice ON k_voice.id = spk_voice.key_id AND k_voice.active = true
LEFT JOIN attempt_profiles ap ON ap.attempt_id = sa.id AND ap.active = true
LEFT JOIN scenario_documents sd ON sd.scenario_id = s.id
LEFT JOIN documents d ON d.id = sd.document_id
LEFT JOIN document_uploads du ON du.document_id = d.id AND du.active = true
LEFT JOIN uploads u ON u.id = du.upload_id
CROSS JOIN profile_rate_limit prl
CROSS JOIN runs_today rt
CROSS JOIN resolved_dept
WHERE sc.id = chat_id
GROUP BY sc.id, sc.title,
         sa.id, sa.simulation_id,
         s.id, ps.problem_statement,
         first_persona.persona_id, first_persona.persona_name,
         p.id, p.name, 
         -- Text agent fields
         pr_prompt_dept.system_prompt, pr_prompt_default.system_prompt, COALESCE(mtl.temperature, 0.0), mrl.reasoning_level,
         m.id, m.value, p_prov.value, k.key, me.base_url, a.id, act_s.settings_id,
         -- Voice agent fields
         pr_prompt_voice_dept.system_prompt, pr_prompt_voice_default.system_prompt, COALESCE(mtl_voice.temperature, 0.0), mrl_voice.reasoning_level,
         m_voice.id, m_voice.value, p_voice.value, k_voice.key, me_voice.base_url, a_voice.id, act_s_voice.settings_id,
         -- Other fields
         s.images_enabled, ss.copy_paste_allowed,
         ap.profile_id,
         prl.req_per_day, rt.runs_today_count, rt.earliest_run_created_at
$$;


--
-- Name: api_get_simulation_scenarios_ordered_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_simulation_scenarios_ordered_v4(simulation_id uuid) RETURNS TABLE(scenario_id uuid, position_val integer)
    LANGUAGE sql STABLE
    AS $$
SELECT ss.scenario_id, ss.position as position_val
FROM simulation_scenarios ss
WHERE ss.simulation_id = api_get_simulation_scenarios_ordered_v4.simulation_id
ORDER BY ss.position
$$;


--
-- Name: api_get_staff_detail_v4(uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_staff_detail_v4(target_profile_id uuid, profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(staff_exists boolean, actor_name text, profile_id uuid, first_name text, last_name text, name text, emails text[], primary_email text, role text, active boolean, requests_per_day integer, cohort_ids text[], department_ids text[], primary_department_id text, can_edit boolean, valid_department_ids text[], valid_cohort_ids text[], cohorts types.q_get_staff_detail_v4_cohort[], departments types.q_get_staff_detail_v4_department[], primary_email_index integer, primary_department_index integer, draft_version integer)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT target_profile_id AS target_profile_id, profile_id AS current_profile_id, draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.current_profile_id
    AND d.resource_type = 'staff'::draft_resource_type
    LIMIT 1
),
resolve_current_profile_id AS (
    SELECT current_profile_id AS resolved_profile_id FROM params
),
current_user_role AS (
    SELECT role FROM resolve_current_profile_id rpi
    JOIN profiles p ON p.id = rpi.resolved_profile_id
),
actor_profile AS (
    SELECT 
        p.first_name || ' ' || p.last_name as actor_name
    FROM resolve_current_profile_id rpi
    JOIN profiles p ON p.id = rpi.resolved_profile_id
    WHERE rpi.resolved_profile_id IS NOT NULL
),
target_profile AS (
    SELECT 
        p.id,
        p.first_name,
        p.last_name,
        ARRAY_AGG(pe.email ORDER BY pe.is_primary DESC, pe.created_at) FILTER (WHERE pe.active = true) as emails,
        (SELECT email FROM profile_emails WHERE profile_id = p.id AND is_primary = true AND active = true LIMIT 1) as primary_email,
        p.role,
        p.active,
        prl.requests_per_day,
        COALESCE(p.first_name || ' ' || p.last_name, '') as name
    FROM profiles p
    LEFT JOIN profile_emails pe ON pe.profile_id = p.id AND pe.active = true
    LEFT JOIN profile_request_limits prl ON prl.profile_id = p.id AND prl.active = true
    WHERE p.id = (SELECT target_profile_id FROM params)
    GROUP BY p.id, p.first_name, p.last_name, p.role, p.active, prl.requests_per_day
),
staff_exists_check AS (
    SELECT EXISTS(
        SELECT 1 FROM profiles WHERE id = (SELECT target_profile_id FROM params)
    )::boolean as staff_exists
),
role_visibility_check AS (
    -- Check if current user can see target profile based on role hierarchy
    SELECT 
        tp.*,
        CASE 
            WHEN cur.role = 'superadmin'::profile_role THEN true
            WHEN cur.role = 'admin'::profile_role AND tp.role IN ('admin'::profile_role, 'instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role) THEN true
            WHEN cur.role = 'instructional'::profile_role AND tp.role IN ('instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role) THEN true
            WHEN cur.role = 'member'::profile_role AND tp.role IN ('member'::profile_role, 'guest'::profile_role) THEN true
            WHEN cur.role = 'guest'::profile_role AND tp.role = 'guest'::profile_role THEN true
            ELSE false
        END as can_see
    FROM target_profile tp
    CROSS JOIN current_user_role cur
),
visible_profile AS (
    SELECT * FROM role_visibility_check WHERE can_see = true
),
current_user_departments AS (
    SELECT DISTINCT pd.department_id
    FROM resolve_current_profile_id rpi
    JOIN profile_departments pd ON pd.profile_id = rpi.resolved_profile_id
),
target_profile_cohorts AS (
    SELECT 
        ARRAY_AGG(cp.cohort_id::text ORDER BY c.title) as cohort_ids
    FROM cohort_profiles cp
    JOIN cohorts c ON c.id = cp.cohort_id
    WHERE cp.profile_id = (SELECT target_profile_id FROM params) AND cp.active = true AND c.active = true
),
target_profile_departments AS (
    SELECT 
        ARRAY_AGG(pd.department_id::text ORDER BY d.title) as department_ids,
        (SELECT department_id::text FROM profile_departments WHERE profile_id = (SELECT target_profile_id FROM params) AND is_primary = TRUE AND active = true LIMIT 1) as primary_department_id
    FROM profile_departments pd
    JOIN departments d ON d.id = pd.department_id
    WHERE pd.profile_id = (SELECT target_profile_id FROM params) AND pd.active = true AND d.active = true
),
all_cohort_ids AS (
    SELECT DISTINCT c.id as cohort_id
    FROM cohorts c
    WHERE c.active = true
),
cohorts_data AS (
    SELECT 
        c.id as cohort_id,
        c.title as name,
        COALESCE(c.description, '') as description
    FROM cohorts c
    WHERE c.id IN (SELECT cohort_id FROM all_cohort_ids)
),
departments_data AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM resolve_current_profile_id rpi
    LEFT JOIN profile_departments pd ON pd.profile_id = rpi.resolved_profile_id AND pd.active = true
    LEFT JOIN departments d ON d.id = pd.department_id AND d.active = true
    WHERE rpi.resolved_profile_id IS NOT NULL AND d.id IS NOT NULL
),
can_edit_check AS (
    SELECT 
        CASE 
            WHEN cur.role = 'superadmin'::profile_role THEN true
            WHEN cur.role = 'admin'::profile_role AND vp.role IN ('admin'::profile_role, 'instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role) THEN true
            WHEN cur.role = 'instructional'::profile_role AND vp.role IN ('instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role) THEN true
            WHEN cur.role = 'member'::profile_role AND vp.role IN ('member'::profile_role, 'guest'::profile_role) THEN true
            ELSE false
        END as can_edit
    FROM visible_profile vp
    CROSS JOIN current_user_role cur
)
SELECT 
    sec.staff_exists::boolean as staff_exists,
    COALESCE(ap.actor_name, '')::text as actor_name,
    vp.id as profile_id,
    -- Merge draft payload with existing staff data (draft takes precedence)
    COALESCE(
        (SELECT payload->>'firstName' FROM draft_payload_data),
        vp.first_name::text
    ) as first_name,
    COALESCE(
        (SELECT payload->>'lastName' FROM draft_payload_data),
        vp.last_name::text
    ) as last_name,
    COALESCE(
        (SELECT payload->>'firstName' FROM draft_payload_data) || ' ' || 
        COALESCE((SELECT payload->>'lastName' FROM draft_payload_data), ''),
        vp.name::text
    ) as name,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'emails' IS NOT NULL AND jsonb_typeof(payload->'emails') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'emails'))::text[]
                ELSE NULL
            END
        FROM draft_payload_data),
        COALESCE(vp.emails, ARRAY[]::text[])
    ) as emails,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'emails' IS NOT NULL AND jsonb_typeof(payload->'emails') = 'array' AND
                     (payload->>'primaryEmailIndex') IS NOT NULL THEN
                    (ARRAY(SELECT jsonb_array_elements_text(payload->'emails'))::text[])[
                        COALESCE((payload->>'primaryEmailIndex')::integer, 0) + 1
                    ]
                ELSE NULL
            END
        FROM draft_payload_data),
        vp.primary_email::text
    ) as primary_email,
    COALESCE(
        (SELECT payload->>'role' FROM draft_payload_data),
        vp.role::text
    ) as role,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        vp.active::boolean
    ) as active,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->>'reqPerDay' IS NOT NULL AND payload->>'reqPerDay' != '' THEN
                    (payload->>'reqPerDay')::integer
                ELSE NULL
            END
        FROM draft_payload_data),
        vp.requests_per_day::integer
    ) as requests_per_day,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'cohortIds' IS NOT NULL AND jsonb_typeof(payload->'cohortIds') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'cohortIds'))::text[]
                ELSE NULL
            END
        FROM draft_payload_data),
        COALESCE(tpc.cohort_ids, ARRAY[]::text[])
    ) as cohort_ids,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'departmentIds' IS NOT NULL AND jsonb_typeof(payload->'departmentIds') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'departmentIds'))::text[]
                ELSE NULL
            END
        FROM draft_payload_data),
        COALESCE(tpd.department_ids, ARRAY[]::text[])
    ) as department_ids,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'departmentIds' IS NOT NULL AND jsonb_typeof(payload->'departmentIds') = 'array' AND
                     (payload->>'primaryDepartmentIndex') IS NOT NULL THEN
                    (ARRAY(SELECT jsonb_array_elements_text(payload->'departmentIds'))::text[])[
                        COALESCE((payload->>'primaryDepartmentIndex')::integer, 0) + 1
                    ]
                ELSE NULL
            END
        FROM draft_payload_data),
        tpd.primary_department_id::text
    ) as primary_department_id,
    COALESCE(cec.can_edit, false)::boolean as can_edit,
    COALESCE(
        (SELECT array_agg(dd.department_id::text ORDER BY dd.name)
         FROM departments_data dd),
        ARRAY[]::text[]
    ) as valid_department_ids,
    COALESCE(
        (SELECT array_agg(cd.cohort_id::text ORDER BY cd.name)
         FROM cohorts_data cd),
        ARRAY[]::text[]
    ) as valid_cohort_ids,
    COALESCE(
        (SELECT ARRAY_AGG(
            (cd.cohort_id, cd.name, cd.description)::types.q_get_staff_detail_v4_cohort
            ORDER BY cd.name
        )
        FROM cohorts_data cd),
        '{}'::types.q_get_staff_detail_v4_cohort[]
    ) as cohorts,
    COALESCE(
        (SELECT ARRAY_AGG(
            (dd.department_id, dd.name, dd.description)::types.q_get_staff_detail_v4_department
            ORDER BY dd.name
        )
        FROM departments_data dd),
        '{}'::types.q_get_staff_detail_v4_department[]
    ) as departments,
    COALESCE(
        (SELECT (payload->>'primaryEmailIndex')::integer FROM draft_payload_data),
        CASE 
            WHEN vp.emails IS NOT NULL AND vp.primary_email IS NOT NULL THEN
                array_position(vp.emails, vp.primary_email) - 1
            ELSE NULL
        END::integer
    ) as primary_email_index,
    COALESCE(
        (SELECT (payload->>'primaryDepartmentIndex')::integer FROM draft_payload_data),
        CASE 
            WHEN tpd.department_ids IS NOT NULL AND tpd.primary_department_id IS NOT NULL THEN
                array_position(tpd.department_ids, tpd.primary_department_id) - 1
            ELSE NULL
        END::integer
    ) as primary_department_index,
    COALESCE(
        (SELECT draft_version FROM draft_payload_data),
        0::int
    ) as draft_version
FROM staff_exists_check sec
LEFT JOIN visible_profile vp ON true
LEFT JOIN can_edit_check cec ON true
LEFT JOIN actor_profile ap ON true
LEFT JOIN target_profile_cohorts tpc ON true
LEFT JOIN target_profile_departments tpd ON true
$$;


--
-- Name: api_get_staff_new_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_get_staff_new_v4(profile_id uuid, draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(actor_name text, user_role text, primary_department_id text, valid_department_ids text[], valid_cohort_ids text[], role_options text[], cohorts types.q_get_staff_new_v4_cohort[], departments types.q_get_staff_new_v4_department[], first_name text, last_name text, emails text[], primary_email_index integer, role text, requests_per_day integer, requests_per_day_enabled boolean, cohort_ids text[], department_ids text[], primary_department_index integer, active boolean, draft_version integer)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id, draft_id AS draft_id
),
draft_payload_data AS (
    SELECT 
        d.payload,
        d.version as draft_version
    FROM params x
    JOIN drafts d ON d.id = x.draft_id
    WHERE x.draft_id IS NOT NULL
    AND d.profile_id = x.profile_id
    AND d.resource_type = 'staff'::draft_resource_type
    LIMIT 1
),
resolve_profile_id AS (
    SELECT profile_id AS resolved_profile_id FROM params
),
user_departments AS (
    SELECT DISTINCT pd.department_id
    FROM resolve_profile_id rpi
    JOIN profile_departments pd ON pd.profile_id = rpi.resolved_profile_id
),
departments_data AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM departments d
    JOIN resolve_profile_id rpi ON true
    JOIN profile_departments pd ON d.id = pd.department_id
    WHERE pd.profile_id = rpi.resolved_profile_id AND d.active = true
),
all_cohort_ids AS (
    SELECT DISTINCT c.id as cohort_id
    FROM cohorts c
    WHERE c.active = true
),
cohorts_data AS (
    SELECT 
        c.id as cohort_id,
        c.title as name,
        COALESCE(c.description, '') as description
    FROM cohorts c
    WHERE c.id IN (SELECT cohort_id FROM all_cohort_ids)
),
profile_data AS (
    SELECT 
        role as user_role,
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM resolve_profile_id rpi
    JOIN profiles p ON p.id = rpi.resolved_profile_id
),
primary_department_id AS (
    SELECT department_id::text
    FROM resolve_profile_id rpi
    JOIN profile_departments pd ON pd.profile_id = rpi.resolved_profile_id
    WHERE pd.is_primary = TRUE
    LIMIT 1
)
SELECT 
    pd.actor_name::text as actor_name,
    pd.user_role::text as user_role,
    pdi.department_id::text as primary_department_id,
    COALESCE(
        (SELECT array_agg(dd.department_id::text ORDER BY dd.name)
         FROM departments_data dd),
        ARRAY[]::text[]
    ) as valid_department_ids,
    COALESCE(
        (SELECT array_agg(cd.cohort_id::text ORDER BY cd.name)
         FROM cohorts_data cd),
        ARRAY[]::text[]
    ) as valid_cohort_ids,
    ARRAY['superadmin', 'admin', 'instructional', 'member', 'guest']::text[] as role_options,
    COALESCE(
        (SELECT ARRAY_AGG(
            (cd.cohort_id, cd.name, cd.description)::types.q_get_staff_new_v4_cohort
            ORDER BY cd.name
        )
        FROM cohorts_data cd),
        '{}'::types.q_get_staff_new_v4_cohort[]
    ) as cohorts,
    COALESCE(
        (SELECT ARRAY_AGG(
            (dd.department_id, dd.name, dd.description)::types.q_get_staff_new_v4_department
            ORDER BY dd.name
        )
        FROM departments_data dd),
        '{}'::types.q_get_staff_new_v4_department[]
    ) as departments,
    -- Default values for new staff (merged with draft payload if draft_id provided)
    COALESCE(
        (SELECT payload->>'firstName' FROM draft_payload_data),
        ''::text
    ) as first_name,
    COALESCE(
        (SELECT payload->>'lastName' FROM draft_payload_data),
        ''::text
    ) as last_name,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'emails' IS NOT NULL AND jsonb_typeof(payload->'emails') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'emails'))::text[]
                ELSE NULL
            END
        FROM draft_payload_data),
        ARRAY[]::text[]
    ) as emails,
    COALESCE(
        (SELECT (payload->>'primaryEmailIndex')::integer FROM draft_payload_data),
        NULL::integer
    ) as primary_email_index,
    COALESCE(
        (SELECT payload->>'role' FROM draft_payload_data),
        'instructional'::text
    ) as role,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->>'reqPerDay' IS NOT NULL AND payload->>'reqPerDay' != '' THEN
                    (payload->>'reqPerDay')::integer
                ELSE NULL
            END
        FROM draft_payload_data),
        NULL::integer
    ) as requests_per_day,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->>'reqPerDay' IS NOT NULL AND payload->>'reqPerDay' != '' THEN true
                ELSE false
            END
        FROM draft_payload_data),
        false::boolean
    ) as requests_per_day_enabled,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'cohortIds' IS NOT NULL AND jsonb_typeof(payload->'cohortIds') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'cohortIds'))::text[]
                ELSE NULL
            END
        FROM draft_payload_data),
        ARRAY[]::text[]
    ) as cohort_ids,
    COALESCE(
        (SELECT 
            CASE 
                WHEN payload->'departmentIds' IS NOT NULL AND jsonb_typeof(payload->'departmentIds') = 'array' THEN
                    ARRAY(SELECT jsonb_array_elements_text(payload->'departmentIds'))::text[]
                ELSE NULL
            END
        FROM draft_payload_data),
        ARRAY[]::text[]
    ) as department_ids,
    COALESCE(
        (SELECT (payload->>'primaryDepartmentIndex')::integer FROM draft_payload_data),
        NULL::integer
    ) as primary_department_index,
    COALESCE(
        (SELECT (payload->>'active')::boolean FROM draft_payload_data),
        true::boolean
    ) as active,
    COALESCE(
        (SELECT draft_version FROM draft_payload_data),
        0::int
    ) as draft_version
FROM profile_data pd
LEFT JOIN primary_department_id pdi ON true
$$;


