CREATE FUNCTION public.api_insert_document_tree_v4(parent_id uuid, child_id uuid, active boolean) RETURNS TABLE(parent_id uuid, child_id uuid, active boolean, created_at timestamp with time zone, updated_at timestamp with time zone)
    LANGUAGE sql
    AS $$
