--
-- Name: api_insert_scenario_image_link_v4(uuid, uuid, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_insert_scenario_image_link_v4(scenario_id uuid, image_id uuid, active boolean DEFAULT true) RETURNS TABLE(scenario_id uuid, image_id uuid, active boolean, created_at timestamp with time zone, updated_at timestamp with time zone)
    LANGUAGE sql
    AS $$
INSERT INTO scenario_images (scenario_id, image_id, active, created_at, updated_at)
VALUES (api_insert_scenario_image_link_v4.scenario_id, api_insert_scenario_image_link_v4.image_id, COALESCE(api_insert_scenario_image_link_v4.active, true), NOW(), NOW())
ON CONFLICT (scenario_id, image_id) DO UPDATE SET
    active = EXCLUDED.active,
    updated_at = NOW()
RETURNING scenario_id, image_id, active, created_at, updated_at
$$;


