--
-- Name: api_leave_cohort_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_leave_cohort_v4(cohort_id uuid, profile_id uuid) RETURNS TABLE(cohort_title text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT
        cohort_id AS cohort_id,
        profile_id AS profile_id
),
actor_profile AS (
    SELECT 
        x.profile_id AS profile_id,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
cohort_info AS (
    SELECT id, title FROM params x JOIN cohorts c ON c.id = x.cohort_id
),
update_result AS (
    UPDATE cohort_profiles
    SET active = false, updated_at = NOW()
    FROM params x
    WHERE cohort_profiles.cohort_id = x.cohort_id 
      AND cohort_profiles.profile_id = x.profile_id
    RETURNING cohort_profiles.cohort_id
)
SELECT 
    ci.title as cohort_title,
    ap.actor_name
FROM cohort_info ci
CROSS JOIN actor_profile ap
WHERE EXISTS (SELECT 1 FROM update_result)
$$;


