--
-- Name: api_link_system_developer_messages_to_run_v4(uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_link_system_developer_messages_to_run_v4(run_id uuid, department_id uuid DEFAULT NULL::uuid, chat_id uuid DEFAULT NULL::uuid) RETURNS TABLE(system_message_id uuid, developer_message_id uuid)
    LANGUAGE sql
    AS $$
WITH run_info AS (
    SELECT 
        r.id as run_id,
        r.agent_id,
        (SELECT rp.persona_id FROM run_personas rp WHERE rp.run_id = r.id AND rp.active = true LIMIT 1) as persona_id,
        COALESCE(
            department_id,
            -- Try to get department from chat
            (SELECT sd.department_id FROM runs r2
             JOIN group_runs gr ON gr.run_id = r2.id
             JOIN groups g ON g.id = gr.group_id
             JOIN chat_groups cg ON cg.group_id = g.id
             JOIN chats c ON c.id = cg.chat_id
             JOIN scenario_departments sd ON sd.scenario_id = c.scenario_id AND sd.active = true
             WHERE r2.id = r.id LIMIT 1),
            -- Try to get department from profile
            (SELECT pd.department_id FROM run_profiles rpf
             JOIN profile_departments pd ON pd.profile_id = rpf.profile_id AND pd.active = true
             WHERE rpf.run_id = r.id AND rpf.active = true LIMIT 1),
            -- Fallback to any active department
            (SELECT id FROM departments WHERE active = true LIMIT 1)
        ) as department_id
    FROM runs r
    WHERE r.id = run_id
),
-- Get system prompt for persona runs
-- System prompt comes from the agent (department-specific or default), then persona instructions are appended
persona_system_prompt AS (
    SELECT 
        CASE 
            WHEN p.instructions IS NOT NULL AND p.instructions != '' THEN
                COALESCE(pr_dept.system_prompt, pr_default.system_prompt) || E'\n\n' || p.instructions
            ELSE
                COALESCE(pr_dept.system_prompt, pr_default.system_prompt)
        END as system_prompt
    FROM run_info ri
    JOIN run_personas rp ON rp.run_id = ri.run_id AND rp.active = true
    JOIN personas p ON p.id = rp.persona_id
    JOIN agents a ON a.id = ri.agent_id
    LEFT JOIN agent_department_prompts adp ON adp.agent_id = a.id 
        AND adp.department_id = ri.department_id
        AND adp.active = true
    LEFT JOIN prompts pr_dept ON pr_dept.id = adp.prompt_id
    LEFT JOIN agent_prompts ap ON ap.agent_id = a.id AND ap.active = true
    LEFT JOIN prompts pr_default ON pr_default.id = ap.prompt_id
    WHERE ri.persona_id IS NOT NULL
    AND COALESCE(pr_dept.system_prompt, pr_default.system_prompt) IS NOT NULL
    AND COALESCE(pr_dept.system_prompt, pr_default.system_prompt) != ''
),
-- Get system prompt for agent runs
agent_system_prompt AS (
    SELECT 
        COALESCE(pr_dept.system_prompt, pr_default.system_prompt) as system_prompt
    FROM run_info ri
    JOIN agents a ON a.id = ri.agent_id
    LEFT JOIN agent_department_prompts adp ON adp.agent_id = a.id 
        AND adp.department_id = ri.department_id
        AND adp.active = true
    LEFT JOIN prompts pr_dept ON pr_dept.id = adp.prompt_id
    LEFT JOIN agent_prompts ap ON ap.agent_id = a.id AND ap.active = true
    LEFT JOIN prompts pr_default ON pr_default.id = ap.prompt_id
    WHERE ri.agent_id IS NOT NULL
    AND ri.persona_id IS NULL
    AND COALESCE(pr_dept.system_prompt, pr_default.system_prompt) IS NOT NULL
    AND COALESCE(pr_dept.system_prompt, pr_default.system_prompt) != ''
),
-- Get or create system message with MD5 deduplication
system_message_content AS (
    SELECT system_prompt as content FROM persona_system_prompt
    UNION ALL
    SELECT system_prompt as content FROM agent_system_prompt
),
system_message_hash AS (
    SELECT DISTINCT message_content_hash(smc.content, 'system') as hash, smc.content
    FROM system_message_content smc
),
existing_system_message AS (
    SELECT m.id as system_message_id
    FROM messages m
    JOIN message_content mc ON mc.message_id = m.id AND mc.idx = 0
        JOIN content cnt ON cnt.id = mc.content_id
    JOIN system_message_hash smh ON message_content_hash(cnt.content, 'system') = smh.hash
    WHERE m.role = 'system'
    LIMIT 1
),
new_system_message AS (
    INSERT INTO messages (role, completed, audio, created_at, updated_at)
    SELECT 'system'::message_role, false, false, NOW(), NOW()
    FROM system_message_content smc
    WHERE NOT EXISTS (SELECT 1 FROM existing_system_message)
    RETURNING id as system_message_id, created_at, updated_at
),
-- Create synthetic tool call for new system messages
system_tool_call AS (
    INSERT INTO calls (call_id, tool_id, completed, created_at, updated_at)
    SELECT 'link_sys_dev_system_' || nsm.system_message_id::text, NULL, true, nsm.created_at, nsm.updated_at
    FROM new_system_message nsm
    WHERE NOT EXISTS (SELECT 1 FROM existing_system_message)
    RETURNING id as tool_call_id, created_at, updated_at
),
-- Get existing tool_call_id for existing system messages
existing_system_tool_call AS (
    SELECT DISTINCT cnt.tool_call_id
    FROM existing_system_message esm
    JOIN message_content mc ON mc.message_id = esm.system_message_id AND mc.idx = 0
    JOIN content cnt ON cnt.id = mc.content_id
    LIMIT 1
),
-- Combine new and existing tool calls
system_tool_call_id AS (
    SELECT tool_call_id FROM system_tool_call
    UNION ALL
    SELECT tool_call_id FROM existing_system_tool_call
),
insert_system_content_step1 AS (
    INSERT INTO content (content, tool_call_id, created_at, updated_at)
    SELECT smc.content, stc.tool_call_id, nsm.created_at, nsm.updated_at
    FROM new_system_message nsm
    CROSS JOIN system_message_content smc
    CROSS JOIN system_tool_call_id stc
    WHERE NOT EXISTS (SELECT 1 FROM existing_system_message)
    RETURNING id as content_id, created_at, updated_at
),
insert_system_content AS (
    INSERT INTO message_content (message_id, content_id, idx, created_at, updated_at)
    SELECT nsm.system_message_id, ic.content_id, 0, ic.created_at, ic.updated_at
    FROM new_system_message nsm
    CROSS JOIN system_message_content smc
    CROSS JOIN system_tool_call_id stc
    CROSS JOIN insert_system_content_step1 ic
    WHERE NOT EXISTS (SELECT 1 FROM existing_system_message)
),
system_message AS (
    SELECT system_message_id FROM existing_system_message
    UNION ALL
    SELECT system_message_id FROM new_system_message
),
-- Link system message to run
link_system AS (
    INSERT INTO message_runs (message_id, run_id, created_at, updated_at)
    SELECT sm.system_message_id, run_id, NOW(), NOW()
    FROM system_message sm
    ON CONFLICT (message_id, run_id) DO UPDATE SET updated_at = NOW()
    RETURNING message_id as system_message_id
),
-- Get scenario developer message (for simulation runs with chat_id)
-- Use developer_instructions table for scenario_statement type
scenario_developer_template AS (
    SELECT di.template
    FROM run_info ri
    JOIN agents a ON a.id = ri.agent_id
    JOIN agent_role_developer_instruction_types ardit ON ardit.agent_role = a.role
    JOIN developer_instructions di ON di.type = ardit.developer_instruction_type
    WHERE ardit.developer_instruction_type = 'scenario_statement'::developer_instruction_type
    LIMIT 1
),
scenario_developer_content AS (
    SELECT DISTINCT
        -- Use template from developer_instructions if available, otherwise fallback to hardcoded
        COALESCE(
            REPLACE(sdt.template, '{{ problem_statement }}', ps.problem_statement),
            'The following is the scenario for the chat: ' || ps.problem_statement
        ) as content
    FROM run_info ri
    JOIN group_runs gr ON gr.run_id = ri.run_id
    JOIN groups g ON g.id = gr.group_id
    JOIN chat_groups cg ON cg.group_id = g.id
    JOIN chats c ON c.id = cg.chat_id
    JOIN scenario_problem_statements sps ON sps.scenario_id = c.scenario_id AND sps.active = true
    JOIN problem_statements ps ON ps.id = sps.problem_statement_id
    CROSS JOIN LATERAL (SELECT template FROM scenario_developer_template LIMIT 1) sdt
    WHERE chat_id IS NOT NULL
    AND c.id = chat_id
    AND ps.problem_statement IS NOT NULL 
    AND ps.problem_statement != ''
),
-- Get or create developer message for scenario with MD5 deduplication
scenario_developer_hash AS (
    SELECT DISTINCT message_content_hash(sdc.content, 'developer') as hash, sdc.content
    FROM scenario_developer_content sdc
),
existing_scenario_developer_message AS (
    SELECT m.id as developer_message_id
    FROM messages m
    JOIN message_content mc ON mc.message_id = m.id AND mc.idx = 0
        JOIN content cnt ON cnt.id = mc.content_id
    JOIN scenario_developer_hash sdh ON message_content_hash(cnt.content, 'developer') = sdh.hash
    WHERE m.role = 'developer'
    LIMIT 1
),
new_scenario_developer_message AS (
    INSERT INTO messages (role, completed, audio, created_at, updated_at)
    SELECT 'developer'::message_role, false, false, NOW(), NOW()
    FROM scenario_developer_content sdc
    WHERE NOT EXISTS (SELECT 1 FROM existing_scenario_developer_message)
    RETURNING id as developer_message_id, created_at, updated_at
),
-- Create synthetic tool call for new developer messages
developer_tool_call AS (
    INSERT INTO calls (call_id, tool_id, completed, created_at, updated_at)
    SELECT 'link_sys_dev_developer_' || nsdm.developer_message_id::text, NULL, true, nsdm.created_at, nsdm.updated_at
    FROM new_scenario_developer_message nsdm
    WHERE NOT EXISTS (SELECT 1 FROM existing_scenario_developer_message)
    RETURNING id as tool_call_id, created_at, updated_at
),
-- Get existing tool_call_id for existing developer messages
existing_developer_tool_call AS (
    SELECT DISTINCT cnt.tool_call_id
    FROM existing_scenario_developer_message esdm
    JOIN message_content mc ON mc.message_id = esdm.developer_message_id AND mc.idx = 0
    JOIN content cnt ON cnt.id = mc.content_id
    LIMIT 1
),
-- Combine new and existing tool calls
developer_tool_call_id AS (
    SELECT tool_call_id FROM developer_tool_call
    UNION ALL
    SELECT tool_call_id FROM existing_developer_tool_call
),
insert_scenario_developer_content_step1 AS (
    INSERT INTO content (content, tool_call_id, created_at, updated_at)
    SELECT sdc.content, dtc.tool_call_id, nsdm.created_at, nsdm.updated_at
    FROM new_scenario_developer_message nsdm
    CROSS JOIN scenario_developer_content sdc
    CROSS JOIN developer_tool_call_id dtc
    WHERE NOT EXISTS (SELECT 1 FROM existing_scenario_developer_message)
    RETURNING id as content_id, created_at, updated_at
),
insert_scenario_developer_content AS (
    INSERT INTO message_content (message_id, content_id, idx, created_at, updated_at)
    SELECT nsdm.developer_message_id, ic.content_id, 0, ic.created_at, ic.updated_at
    FROM new_scenario_developer_message nsdm
    CROSS JOIN scenario_developer_content sdc
    CROSS JOIN developer_tool_call_id dtc
    CROSS JOIN insert_scenario_developer_content_step1 ic
    WHERE NOT EXISTS (SELECT 1 FROM existing_scenario_developer_message)
),
scenario_developer_message AS (
    SELECT developer_message_id FROM existing_scenario_developer_message
    UNION ALL
    SELECT developer_message_id FROM new_scenario_developer_message
),
-- Link developer message to run
link_developer AS (
    INSERT INTO message_runs (message_id, run_id, created_at, updated_at)
    SELECT sdm.developer_message_id, run_id, NOW(), NOW()
    FROM scenario_developer_message sdm
    ON CONFLICT (message_id, run_id) DO UPDATE SET updated_at = NOW()
    RETURNING message_id as developer_message_id
),
-- Link system → developer in message_tree (if both exist)
link_system_to_developer AS (
    INSERT INTO message_tree (parent_id, child_id, active, created_at, updated_at)
    SELECT DISTINCT
        ls.system_message_id as parent_id,
        ld.developer_message_id as child_id,
        true as active,
        NOW() as created_at,
        NOW() as updated_at
    FROM link_system ls
    JOIN link_developer ld ON true
    WHERE NOT EXISTS (
        SELECT 1 FROM message_tree mt 
        WHERE mt.parent_id = ls.system_message_id 
        AND mt.child_id = ld.developer_message_id 
        AND mt.active = true
    )
)
SELECT 
    (SELECT system_message_id FROM link_system LIMIT 1) as system_message_id,
    (SELECT developer_message_id FROM link_developer LIMIT 1) as developer_message_id
$$;


--
-- Name: api_link_video_to_scenario_v4(uuid, uuid, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_link_video_to_scenario_v4(scenario_id uuid, video_id uuid, active boolean) RETURNS TABLE(video_id text)
    LANGUAGE sql
    AS $$
WITH link_video AS (
    UPDATE scenario_videos
    SET active = false, updated_at = NOW()
    WHERE scenario_id = api_link_video_to_scenario_v4.scenario_id AND active = true
),
insert_video AS (
    INSERT INTO scenario_videos (scenario_id, video_id, active, created_at, updated_at)
    VALUES (scenario_id, video_id, active, NOW(), NOW())
    ON CONFLICT (scenario_id, video_id) DO UPDATE SET
        active = EXCLUDED.active,
        updated_at = NOW()
    RETURNING video_id::text
)
SELECT video_id FROM insert_video
$$;


--
-- Name: api_list_agents_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_list_agents_v4(profile_id uuid) RETURNS TABLE(actor_name text, agents types.q_list_agents_v4_agent[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id
),
user_departments AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments ON profile_departments.profile_id = x.profile_id AND profile_departments.active = true
),
user_profile AS (
    SELECT 
        role,
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
agent_department_links AS (
    SELECT 
        agent_id,
        COUNT(*) as total_links
    FROM agent_departments
    WHERE active = true
    GROUP BY agent_id
),
agent_departments_data AS (
    SELECT 
        ad.agent_id,
        ARRAY_AGG(ad.department_id::text ORDER BY ad.created_at) as department_ids
    FROM agent_departments ad
    WHERE ad.active = true
    GROUP BY ad.agent_id
),
filtered_agents AS (
    SELECT 
        a.id,
        a.name,
        a.description,
        a.model_id,
        a.role,
        a.updated_at
    FROM agents a
    LEFT JOIN agent_departments ad ON ad.agent_id = a.id AND ad.active = true
    GROUP BY a.id, a.name, a.description, a.model_id, a.role, a.updated_at
    HAVING 
        -- Include if has matching department link OR has no department links at all (cross-dept)
        COUNT(ad.agent_id) FILTER (WHERE ad.department_id IN (SELECT department_id FROM user_departments)) > 0
        OR NOT EXISTS (SELECT 1 FROM agent_departments ad2 WHERE ad2.agent_id = a.id AND ad2.active = true)
)
SELECT 
    up.actor_name::text as actor_name,
    COALESCE(
        ARRAY_AGG(
            (fa.id, fa.name, fa.description, 
             COALESCE(mrl.reasoning_level::text, ''),
             COALESCE(mtl.temperature, 0.0),
             fa.model_id, fa.role, fa.updated_at,
             COALESCE(addd.department_ids, ARRAY[]::text[]),
             CASE WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true ELSE false END,
             true,
             CASE 
                 WHEN COALESCE(adl.total_links, 0) > 0 THEN false
                 WHEN up.role = 'superadmin'::profile_role THEN true
                 ELSE false
             END,
             m.name,
             COALESCE(m.description, ''),
             up.actor_name
            )::types.q_list_agents_v4_agent
            ORDER BY fa.name
        ),
        '{}'::types.q_list_agents_v4_agent[]
    ) as agents
FROM filtered_agents fa
CROSS JOIN user_profile up
LEFT JOIN agent_department_links adl ON adl.agent_id = fa.id
LEFT JOIN agent_departments_data addd ON addd.agent_id = fa.id
-- Join temperature from junction table
LEFT JOIN agent_temperature_levels atl ON atl.agent_id = fa.id AND atl.active = true
LEFT JOIN model_temperature_levels mtl ON mtl.id = atl.model_temperature_level_id AND mtl.active = true
-- Join reasoning from junction table
LEFT JOIN agent_reasoning_levels arl ON arl.agent_id = fa.id AND arl.active = true
LEFT JOIN model_reasoning_levels mrl ON mrl.id = arl.model_reasoning_level_id AND mrl.active = true
LEFT JOIN models m ON m.id = fa.model_id
GROUP BY up.actor_name, up.role
$$;


--
-- Name: api_list_cohorts_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_list_cohorts_v4(profile_id uuid) RETURNS TABLE(actor_name text, cohorts types.q_list_cohorts_v4_cohort[], profiles types.q_list_cohorts_v4_profile[], simulations types.q_list_cohorts_v4_simulation[], scenarios types.q_list_cohorts_v4_scenario[], simulation_scenario_mapping jsonb, departments types.q_list_cohorts_v4_department[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id
),
user_departments AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.active = true
),
user_profile AS (
    SELECT 
        role,
        first_name || ' ' || last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
cohort_profiles_agg AS (
    SELECT 
        cp.cohort_id,
        ARRAY_AGG(cp.profile_id ORDER BY p.last_name, p.first_name) as profile_ids
    FROM cohort_profiles cp
    JOIN profiles p ON p.id = cp.profile_id
    WHERE cp.active = true
    GROUP BY cp.cohort_id
),
cohort_profiles_role_filtered AS (
    SELECT 
        cp.cohort_id,
        ARRAY_AGG(cp.profile_id) FILTER (
            WHERE 
                (up.role = 'superadmin'::profile_role) OR
                (up.role = 'admin'::profile_role AND p.role IN ('admin'::profile_role, 'instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role)) OR
                (up.role = 'instructional'::profile_role AND p.role IN ('instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role)) OR
                (up.role = 'member'::profile_role AND p.role IN ('member'::profile_role, 'guest'::profile_role)) OR
                (up.role = 'guest'::profile_role AND p.role = 'guest'::profile_role)
        ) as profile_ids
    FROM cohort_profiles cp
    JOIN profiles p ON p.id = cp.profile_id
    CROSS JOIN user_profile up
    WHERE cp.active = true
    GROUP BY cp.cohort_id
),
cohort_simulations_agg AS (
    SELECT 
        cs.cohort_id,
        ARRAY_AGG(cs.simulation_id ORDER BY s.title) as simulation_ids
    FROM cohort_simulations cs
    JOIN simulations s ON s.id = cs.simulation_id
    WHERE cs.active = true
    GROUP BY cs.cohort_id
),
cohort_usage AS (
    SELECT DISTINCT cp.cohort_id, COUNT(DISTINCT ap.attempt_id) as usage_count
    FROM cohort_profiles cp
    JOIN attempt_profiles ap ON ap.profile_id = cp.profile_id
    WHERE cp.active = true
    GROUP BY cp.cohort_id
),
cohort_departments_data AS (
    SELECT 
        cd.cohort_id,
        ARRAY_AGG(cd.department_id::text ORDER BY cd.created_at) as department_ids
    FROM cohort_departments cd
    WHERE cd.active = true
    GROUP BY cd.cohort_id
),
user_in_cohort AS (
    SELECT cohort_id
    FROM params x
    JOIN cohort_profiles cp ON cp.profile_id = x.profile_id AND cp.active = true
),
all_profile_ids AS (
    SELECT DISTINCT unnest(profile_ids) as profile_id
    FROM cohort_profiles_agg
),
all_simulation_ids AS (
    SELECT DISTINCT unnest(simulation_ids) as simulation_id
    FROM cohort_simulations_agg
),
simulation_scenarios_agg AS (
    SELECT 
        ss.simulation_id,
        ARRAY_AGG(ss.scenario_id ORDER BY sc.name) as scenario_ids
    FROM simulation_scenarios ss
    JOIN scenarios sc ON sc.id = ss.scenario_id
    WHERE ss.simulation_id IN (SELECT simulation_id FROM all_simulation_ids)
      AND ss.active = true
    GROUP BY ss.simulation_id
),
all_scenario_ids AS (
    SELECT DISTINCT unnest(scenario_ids) as scenario_id
    FROM simulation_scenarios_agg
),
scenario_personas_agg AS (
    SELECT 
        sp.scenario_id,
        ARRAY_AGG(sp.persona_id::text ORDER BY sp.persona_id) as persona_ids
    FROM scenario_personas sp
    WHERE sp.scenario_id IN (SELECT scenario_id FROM all_scenario_ids)
      AND sp.active = true
    GROUP BY sp.scenario_id
),
all_persona_ids AS (
    SELECT DISTINCT unnest(persona_ids)::uuid as persona_id
    FROM scenario_personas_agg
    WHERE persona_ids IS NOT NULL
),
persona_mapping_data AS (
    SELECT COALESCE(
        jsonb_object_agg(
            p.id::text,
            jsonb_build_object(
                'name', p.name,
                'description', COALESCE(p.description, ''),
                'color', p.color,
                'icon', p.icon,
                'image_model', false
            )
        ) FILTER (WHERE p.id IS NOT NULL),
        '{}'::jsonb
    ) as mapping
    FROM all_persona_ids api
    LEFT JOIN personas p ON p.id = api.persona_id
),
scenario_mapping_data AS (
    SELECT 
        s.id::text as scenario_id,
        s.name,
        COALESCE(ps.problem_statement, '') as description,
        s.active,
        COALESCE(spa.persona_ids, ARRAY[]::text[]) as persona_ids,
        pm.mapping as persona_mapping
    FROM all_scenario_ids asi
    LEFT JOIN scenarios s ON s.id = asi.scenario_id
    LEFT JOIN scenario_problem_statements sps ON sps.scenario_id = s.id AND sps.active = true
    LEFT JOIN problem_statements ps ON ps.id = sps.problem_statement_id
    LEFT JOIN scenario_personas_agg spa ON spa.scenario_id = s.id
    LEFT JOIN scenario_tree st ON st.parent_id = s.id AND st.child_id = s.id
    CROSS JOIN persona_mapping_data pm
    WHERE s.id IS NOT NULL AND st.parent_id IS NOT NULL
),
all_department_ids AS (
    SELECT DISTINCT unnest(department_ids)::uuid as department_id
    FROM cohort_departments_data
    WHERE department_ids IS NOT NULL
    UNION
    SELECT department_id FROM user_departments
),
department_mapping_data AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM departments d
    WHERE d.id IN (SELECT department_id FROM all_department_ids)
),
cohorts_data AS (
    SELECT 
        c.id as cohort_id,
        c.title as name,
        c.description,
        c.active,
        c.updated_at,
        COALESCE(cdd.department_ids, NULL) as department_ids,
        COALESCE(cp.profile_ids, ARRAY[]::uuid[]) as profile_ids,
        COALESCE(cs.simulation_ids, ARRAY[]::uuid[]) as simulation_ids,
        COALESCE(cu.usage_count, 0) as usage_count,
        COALESCE(array_length(cprf.profile_ids, 1), 0) as num_members,
        CASE 
            WHEN COALESCE(cdd.department_ids, NULL) IS NULL AND up.role != 'superadmin' THEN false
            WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_edit,
        CASE 
            WHEN COALESCE(cdd.department_ids, NULL) IS NULL AND up.role != 'superadmin' THEN false
            WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) AND COALESCE(cu.usage_count, 0) = 0 THEN true
            ELSE false
        END as can_delete,
        true as can_duplicate,
        CASE
            WHEN uic.cohort_id IS NOT NULL THEN true
            ELSE false
        END as can_leave
    FROM params x
    JOIN cohorts c ON true
    LEFT JOIN cohort_departments cd ON cd.cohort_id = c.id AND cd.active = true
    LEFT JOIN cohort_departments_data cdd ON cdd.cohort_id = c.id
    LEFT JOIN cohort_profiles_agg cp ON cp.cohort_id = c.id
    LEFT JOIN cohort_profiles_role_filtered cprf ON cprf.cohort_id = c.id
    LEFT JOIN cohort_simulations_agg cs ON cs.cohort_id = c.id
    LEFT JOIN cohort_usage cu ON cu.cohort_id = c.id
    LEFT JOIN user_in_cohort uic ON uic.cohort_id = c.id
    CROSS JOIN user_profile up
    WHERE (
        (up.role = 'instructional'::profile_role AND uic.cohort_id IS NOT NULL)
        OR
        up.role != 'instructional'
    )
    GROUP BY c.id, c.title, c.description, c.active, c.updated_at,
             cdd.department_ids, cp.profile_ids, cprf.profile_ids, cs.simulation_ids, cu.usage_count, up.role, uic.cohort_id
    HAVING 
        COUNT(cd.cohort_id) FILTER (WHERE cd.department_id IN (SELECT department_id FROM user_departments)) > 0
        OR NOT EXISTS (SELECT 1 FROM cohort_departments cd2 WHERE cd2.cohort_id = c.id AND cd2.active = true)
),
profile_mapping_data AS (
    SELECT 
        p.id as profile_id,
        p.first_name || ' ' || p.last_name as name,
        COALESCE((SELECT email FROM profile_emails WHERE profile_id = p.id AND is_primary = true AND active = true LIMIT 1), '') as description
    FROM profiles p
    WHERE p.id IN (SELECT profile_id FROM all_profile_ids)
),
simulation_mapping_data AS (
    SELECT 
        s.id as simulation_id,
        s.title as name,
        COALESCE(s.description, '') as description,
        COALESCE(
            (SELECT SUM(stl.time_limit_seconds)
             FROM scenario_time_limits stl
             JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
             WHERE stl.simulation_id = s.id AND stl.active = true AND ss.active = true),
            0
        ) as time_limit,
        COALESCE(sdd.department_ids, ARRAY[]::text[]) as department_ids,
        COALESCE(ssa.scenario_ids, ARRAY[]::uuid[])::text[] as scenario_ids
    FROM simulations s
    LEFT JOIN (
        SELECT 
            sd.simulation_id,
            ARRAY_AGG(sd.department_id::text ORDER BY sd.created_at) as department_ids
        FROM simulation_departments sd
        WHERE sd.active = true
        GROUP BY sd.simulation_id
    ) sdd ON sdd.simulation_id = s.id
    LEFT JOIN simulation_scenarios_agg ssa ON ssa.simulation_id = s.id
    WHERE s.id IN (SELECT simulation_id FROM all_simulation_ids)
),
simulation_scenario_mapping_data AS (
    SELECT 
        ssa.simulation_id::text,
        ssa.scenario_ids::text[]
    FROM simulation_scenarios_agg ssa
),
-- Build facet options with disambiguation
profile_options_data AS (
    SELECT 
        pid.profile_id,
        pmd.name,
        CASE 
            WHEN (SELECT COUNT(*) FROM profile_mapping_data pmd2 WHERE pmd2.name = pmd.name) > 1 
            THEN pmd.name || ' (' || SUBSTRING(pid.profile_id::text FROM LENGTH(pid.profile_id::text) - 7) || ')'
            ELSE pmd.name
        END as label
    FROM all_profile_ids pid
    JOIN profile_mapping_data pmd ON pmd.profile_id = pid.profile_id
),
simulation_options_data AS (
    SELECT 
        sid.simulation_id,
        smd.name,
        CASE 
            WHEN (SELECT COUNT(*) FROM simulation_mapping_data smd2 WHERE smd2.name = smd.name) > 1 
            THEN smd.name || ' (' || SUBSTRING(sid.simulation_id::text FROM LENGTH(sid.simulation_id::text) - 7) || ')'
            ELSE smd.name
        END as label
    FROM all_simulation_ids sid
    JOIN simulation_mapping_data smd ON smd.simulation_id = sid.simulation_id
),
department_options_data AS (
    SELECT 
        did.department_id,
        dmd.name as label
    FROM all_department_ids did
    JOIN department_mapping_data dmd ON dmd.department_id = did.department_id
    WHERE did.department_id IN (SELECT department_id FROM user_departments)
)
SELECT 
    up.actor_name,
    -- Aggregate cohorts separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (cd.cohort_id, cd.name, cd.description, cd.active, cd.department_ids, 
             ARRAY(SELECT unnest(cd.profile_ids)::text), 
             ARRAY(SELECT unnest(cd.simulation_ids)::text),
             cd.usage_count, cd.num_members, cd.can_edit, cd.can_delete, cd.can_duplicate, cd.can_leave, cd.updated_at)::types.q_list_cohorts_v4_cohort
            ORDER BY cd.updated_at DESC NULLS LAST
        ) FROM cohorts_data cd),
        '{}'::types.q_list_cohorts_v4_cohort[]
    ) as cohorts,
    -- Aggregate profiles separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (pmd.profile_id, pmd.name, pmd.description)::types.q_list_cohorts_v4_profile
            ORDER BY pmd.name
        ) FROM profile_mapping_data pmd),
        '{}'::types.q_list_cohorts_v4_profile[]
    ) as profiles,
    -- Aggregate simulations separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (smd.simulation_id, smd.name, smd.description, smd.time_limit, smd.department_ids, smd.scenario_ids)::types.q_list_cohorts_v4_simulation
            ORDER BY smd.name
        ) FROM simulation_mapping_data smd),
        '{}'::types.q_list_cohorts_v4_simulation[]
    ) as simulations,
    -- Aggregate scenarios separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (smd2.scenario_id, smd2.name, smd2.description, smd2.active, smd2.persona_ids, smd2.persona_mapping)::types.q_list_cohorts_v4_scenario
            ORDER BY smd2.name
        ) FROM scenario_mapping_data smd2),
        '{}'::types.q_list_cohorts_v4_scenario[]
    ) as scenarios,
    -- Aggregate simulation_scenario_mapping separately
    COALESCE(
        (SELECT jsonb_object_agg(
            ssmd.simulation_id,
            ssmd.scenario_ids
        ) FROM simulation_scenario_mapping_data ssmd),
        '{}'::jsonb
    ) as simulation_scenario_mapping,
    -- Aggregate departments separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (dmd.department_id, dmd.name, dmd.description)::types.q_list_cohorts_v4_department
            ORDER BY dmd.name
        ) FROM department_mapping_data dmd),
        '{}'::types.q_list_cohorts_v4_department[]
    ) as departments
FROM user_profile up
$$;


--
-- Name: api_list_departments_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_list_departments_v4(profile_id uuid) RETURNS TABLE(actor_name text, departments types.q_list_departments_v4_department[], cohorts types.q_list_departments_v4_cohort[], profiles types.q_list_departments_v4_profile[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id
),
user_departments AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments ON profile_departments.profile_id = x.profile_id AND profile_departments.active = true
),
user_profile AS (
    SELECT 
        role,
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
model_run_costs AS (
    SELECT 
        rpu.run_id,
        COALESCE(SUM(
            (rpu.count::numeric / u.value::numeric) * mp.price
        ), 0) as cost
    FROM run_pricing_usage rpu
    JOIN run_models rm ON rm.run_id = rpu.run_id AND rm.active = true
    JOIN model_pricing mp ON mp.model_id = rm.model_id 
        AND mp.pricing_type = rpu.pricing_type 
        AND mp.unit_id = rpu.unit_id
        AND mp.active = true
    JOIN units u ON u.id = rpu.unit_id
    GROUP BY rpu.run_id
),
model_run_departments_via_agents AS (
    SELECT DISTINCT
        mrc.run_id,
        ad.department_id
    FROM model_run_costs mrc
    JOIN runs mr ON mr.id = mrc.run_id
    JOIN agent_departments ad ON ad.agent_id = mr.agent_id AND ad.active = true
    WHERE mr.agent_id IS NOT NULL
    AND ad.department_id IN (SELECT department_id FROM user_departments)
),
model_run_departments_via_personas AS (
    SELECT DISTINCT
        mrc.run_id,
        pd.department_id
    FROM model_run_costs mrc
    JOIN run_personas mrp ON mrp.run_id = mrc.run_id AND mrp.active = true
    JOIN persona_departments pd ON pd.persona_id = mrp.persona_id AND pd.active = true
    WHERE pd.department_id IN (SELECT department_id FROM user_departments)
),
model_run_departments_via_profiles AS (
    SELECT DISTINCT
        mrc.run_id,
        pd.department_id
    FROM model_run_costs mrc
    JOIN run_profiles mrp ON mrp.run_id = mrc.run_id AND mrp.active = true
    JOIN profile_departments pd ON pd.profile_id = mrp.profile_id AND pd.active = true
    WHERE pd.department_id IN (SELECT department_id FROM user_departments)
),
model_run_departments AS (
    SELECT run_id, department_id FROM model_run_departments_via_agents
    UNION
    SELECT run_id, department_id FROM model_run_departments_via_personas
    UNION
    SELECT run_id, department_id FROM model_run_departments_via_profiles
),
department_price_spent AS (
    SELECT 
        mrd.department_id,
        SUM(mrc.cost) as total_price_spent
    FROM model_run_costs mrc
    JOIN model_run_departments mrd ON mrd.run_id = mrc.run_id
    GROUP BY mrd.department_id
),
department_staff_count AS (
    SELECT 
        department_id, 
        COUNT(DISTINCT profile_id) as staff_count
    FROM profile_departments
    WHERE department_id IN (SELECT department_id FROM user_departments)
    GROUP BY department_id
),
department_cohorts_data AS (
    SELECT 
        cd.department_id,
        ARRAY_AGG(cd.cohort_id ORDER BY cd.created_at) as cohort_ids
    FROM cohort_departments cd
    WHERE cd.department_id IN (SELECT department_id FROM user_departments) AND cd.active = true
    GROUP BY cd.department_id
),
department_profiles_data AS (
    SELECT 
        pd.department_id,
        ARRAY_AGG(pd.profile_id ORDER BY p.last_name, p.first_name) as profile_ids
    FROM profile_departments pd
    JOIN profiles p ON p.id = pd.profile_id
    WHERE pd.department_id IN (SELECT department_id FROM user_departments) AND pd.active = true
    GROUP BY pd.department_id
),
department_all_cohort_links AS (
    SELECT 
        cd.department_id,
        COUNT(*) as total_cohort_links
    FROM cohort_departments cd
    WHERE cd.department_id IN (SELECT department_id FROM user_departments) AND cd.active = true
    GROUP BY cd.department_id
),
department_profiles_would_orphan AS (
    SELECT 
        pd.department_id,
        COUNT(*) as profiles_with_only_this_dept
    FROM profile_departments pd
    WHERE pd.department_id IN (SELECT department_id FROM user_departments)
    AND NOT EXISTS (
        SELECT 1 FROM profile_departments pd2 
        WHERE pd2.profile_id = pd.profile_id 
        AND pd2.department_id != pd.department_id
    )
    GROUP BY pd.department_id
),
all_cohort_ids AS (
    SELECT DISTINCT unnest(cohort_ids) as cohort_id
    FROM department_cohorts_data
    WHERE cohort_ids IS NOT NULL
),
all_profile_ids_raw AS (
    SELECT DISTINCT unnest(profile_ids) as profile_id
    FROM department_profiles_data
    WHERE profile_ids IS NOT NULL
),
-- Role-based filtering: filter profiles based on role hierarchy
profile_roles AS (
    SELECT 
        p.id as profile_id,
        p.role
    FROM profiles p
    WHERE p.id IN (SELECT profile_id FROM all_profile_ids_raw)
),
filtered_profile_ids AS (
    SELECT 
        pr.profile_id
    FROM params x
    CROSS JOIN user_profile up
    JOIN profile_roles pr ON pr.profile_id IN (SELECT profile_id FROM all_profile_ids_raw)
    WHERE 
        -- superadmin can see all
        up.role = 'superadmin'::profile_role
        OR
        -- admin can see admin, instructional, member, guest
        (up.role = 'admin'::profile_role AND pr.role IN ('admin'::profile_role, 'instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role))
        OR
        -- instructional can see instructional, member, guest
        (up.role = 'instructional'::profile_role AND pr.role IN ('instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role))
        OR
        -- member can see member, guest
        (up.role = 'member'::profile_role AND pr.role IN ('member'::profile_role, 'guest'::profile_role))
        OR
        -- guest can only see guest
        (up.role = 'guest'::profile_role AND pr.role = 'guest'::profile_role)
),
department_profiles_filtered_data AS (
    SELECT 
        pd.department_id,
        ARRAY_AGG(pd.profile_id ORDER BY p.last_name, p.first_name) FILTER (WHERE pd.profile_id IN (SELECT profile_id FROM filtered_profile_ids)) as profile_ids,
        COUNT(DISTINCT pd.profile_id) FILTER (WHERE pd.profile_id IN (SELECT profile_id FROM filtered_profile_ids)) as staff_count
    FROM profile_departments pd
    JOIN profiles p ON p.id = pd.profile_id
    WHERE pd.department_id IN (SELECT department_id FROM user_departments) AND pd.active = true
    GROUP BY pd.department_id
),
departments_data AS (
    SELECT 
        d.id,
        d.title,
        d.description,
        d.active,
        d.updated_at,
        COALESCE(dps.total_price_spent, 0) as total_price_spent,
        COALESCE(dpf.staff_count, 0) as staff_count,
        COALESCE(dcd.cohort_ids, ARRAY[]::uuid[]) as cohort_ids,
        COALESCE(dpf.profile_ids, ARRAY[]::uuid[]) as profile_ids,
        CASE 
            WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_edit,
        CASE 
            WHEN COALESCE(dacl.total_cohort_links, 0) > 0 THEN false
            WHEN COALESCE(dpwo.profiles_with_only_this_dept, 0) > 0 THEN false
            WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_delete,
        CASE 
            WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_duplicate
    FROM departments d
    JOIN user_departments ud ON ud.department_id = d.id
    CROSS JOIN user_profile up
    LEFT JOIN department_price_spent dps ON dps.department_id = d.id
    LEFT JOIN department_profiles_filtered_data dpf ON dpf.department_id = d.id
    LEFT JOIN department_cohorts_data dcd ON dcd.department_id = d.id
    LEFT JOIN department_all_cohort_links dacl ON dacl.department_id = d.id
    LEFT JOIN department_profiles_would_orphan dpwo ON dpwo.department_id = d.id
    -- Only include departments with staff_count > 0 (after role filtering)
    WHERE COALESCE(dpf.staff_count, 0) > 0
),
cohorts_data AS (
    SELECT DISTINCT
        c.id as cohort_id,
        c.title as name,
        COALESCE(c.description, '') as description
    FROM cohorts c
    WHERE c.id IN (SELECT cohort_id FROM all_cohort_ids)
),
profiles_data AS (
    SELECT DISTINCT
        p.id as profile_id,
        COALESCE(p.first_name || ' ' || p.last_name, '') as name,
        COALESCE((SELECT email FROM profile_emails WHERE profile_id = p.id AND is_primary = true AND active = true LIMIT 1), '') as description
    FROM profiles p
    WHERE p.id IN (SELECT profile_id FROM filtered_profile_ids)
),
departments_agg AS (
    SELECT 
        up.actor_name,
        COALESCE(
            ARRAY_AGG(
                (dd.id, dd.title, dd.description, dd.active, dd.updated_at,
                 dd.total_price_spent, dd.staff_count, dd.cohort_ids, dd.profile_ids,
                 dd.can_edit, dd.can_delete, dd.can_duplicate)::types.q_list_departments_v4_department
                ORDER BY dd.title
            ),
            '{}'::types.q_list_departments_v4_department[]
        ) as departments
    FROM user_profile up
    CROSS JOIN departments_data dd
    GROUP BY up.actor_name
),
cohorts_agg AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (cd.cohort_id, cd.name, cd.description)::types.q_list_departments_v4_cohort
                ORDER BY cd.name
            ),
            '{}'::types.q_list_departments_v4_cohort[]
        ) as cohorts
    FROM (
        SELECT DISTINCT cohort_id, name, description
        FROM cohorts_data
    ) cd
),
profiles_agg AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (pd.profile_id, pd.name, pd.description)::types.q_list_departments_v4_profile
                ORDER BY pd.name
            ),
            '{}'::types.q_list_departments_v4_profile[]
        ) as profiles
    FROM (
        SELECT DISTINCT profile_id, name, description
        FROM profiles_data
    ) pd
)
SELECT 
    da.actor_name::text as actor_name,
    da.departments,
    ca.cohorts,
    pa.profiles
FROM departments_agg da
CROSS JOIN cohorts_agg ca
CROSS JOIN profiles_agg pa
$$;


--
-- Name: api_list_documents_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_list_documents_v4(profile_id uuid) RETURNS TABLE(actor_name text, documents types.q_list_documents_v4_document[], scenarios types.q_list_documents_v4_scenario[], fields types.q_list_documents_v4_field[], departments types.q_list_documents_v4_department[], parameters types.q_list_documents_v4_parameter[], scenario_options types.q_list_documents_v4_scenario_option[], department_options types.q_list_documents_v4_department_option[], valid_department_ids text[], document_type_options text[])
    LANGUAGE sql STABLE
    AS $_$
WITH params AS (
    SELECT profile_id AS profile_id
),
user_departments AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments ON profile_departments.profile_id = x.profile_id AND profile_departments.active = true
),
document_active_scenario_links AS (
    SELECT 
        sd.document_id,
        COUNT(*) as active_scenario_count
    FROM scenario_documents sd
    WHERE sd.active = true
    GROUP BY sd.document_id
),
document_all_scenario_links AS (
    SELECT 
        sd.document_id,
        COUNT(*) as total_scenario_links
    FROM scenario_documents sd
    GROUP BY sd.document_id
),
document_scenarios AS (
    SELECT 
        sd.document_id,
        ARRAY_AGG(DISTINCT st.parent_id) as scenario_ids
    FROM scenario_documents sd
    JOIN scenario_tree st ON st.child_id = sd.scenario_id AND st.parent_id = st.child_id
    WHERE sd.active = true
    GROUP BY sd.document_id
),
document_fields_cte AS (
    SELECT 
        df.document_id,
        ARRAY_AGG(df.field_id) as field_ids
    FROM document_fields df
    WHERE df.active = true
    GROUP BY df.document_id
),
document_departments_data AS (
    SELECT 
        dd.document_id,
        ARRAY_AGG(dd.department_id::text ORDER BY dd.created_at) as department_ids
    FROM document_departments dd
    WHERE dd.active = true
    GROUP BY dd.document_id
),
document_data AS (
    SELECT 
        d.id as document_id,
        d.name,
        d.updated_at,
        du.upload_id,
        d.active,
        CASE 
            WHEN u.file_path IS NOT NULL THEN SUBSTRING(u.file_path FROM '\\.([^\\.]+)$')
            ELSE NULL
        END as extension,
        COALESCE(ddd.department_ids, NULL) as department_ids,
        COALESCE(ds.scenario_ids, ARRAY[]::uuid[]) as scenario_ids,
        COALESCE(dfc.field_ids, ARRAY[]::uuid[]) as field_ids,
        COALESCE(dasl.active_scenario_count, 0) as active_scenario_count,
        COALESCE(dasl_all.total_scenario_links, 0) as total_scenario_links
    FROM documents d
    LEFT JOIN document_uploads du ON du.document_id = d.id AND du.active = true
    LEFT JOIN uploads u ON u.id = du.upload_id
    LEFT JOIN document_departments dd ON dd.document_id = d.id AND dd.active = true
    LEFT JOIN document_departments_data ddd ON ddd.document_id = d.id
    LEFT JOIN document_scenarios ds ON ds.document_id = d.id
    LEFT JOIN document_fields_cte dfc ON dfc.document_id = d.id
    LEFT JOIN document_active_scenario_links dasl ON dasl.document_id = d.id
    LEFT JOIN document_all_scenario_links dasl_all ON dasl_all.document_id = d.id
    GROUP BY d.id, d.name, d.updated_at, du.upload_id, u.file_path, d.active, 
             ddd.department_ids, ds.scenario_ids, dfc.field_ids, dasl.active_scenario_count, dasl_all.total_scenario_links
    HAVING 
        COUNT(dd.document_id) FILTER (WHERE dd.department_id IN (SELECT department_id FROM user_departments)) > 0
        OR NOT EXISTS (SELECT 1 FROM document_departments dd2 WHERE dd2.document_id = d.id AND dd2.active = true)
),
user_profile AS (
    SELECT 
        role,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
all_scenario_ids AS (
    SELECT DISTINCT unnest(scenario_ids) as scenario_id
    FROM document_data
),
scenario_data AS (
    SELECT 
        s.id as scenario_id,
        s.name,
        COALESCE(ps.problem_statement, '') as description,
        s.active
    FROM all_scenario_ids asi
    LEFT JOIN scenarios s ON s.id = asi.scenario_id
    LEFT JOIN scenario_problem_statements sps ON sps.scenario_id = s.id AND sps.active = true
    LEFT JOIN problem_statements ps ON ps.id = sps.problem_statement_id
    LEFT JOIN scenario_tree st ON st.parent_id = s.id AND st.child_id = s.id
    WHERE s.id IS NOT NULL AND st.parent_id IS NOT NULL
),
field_data AS (
    SELECT DISTINCT
        f.id as field_id,
        f.name,
        f.description,
        pf.parameter_id,
        p.name as parameter_name
    FROM fields f
    JOIN parameter_fields pf ON pf.field_id = f.id AND pf.active = true
    JOIN parameters p ON p.id = pf.parameter_id
    LEFT JOIN field_departments fd ON fd.field_id = f.id AND fd.active = true
    WHERE p.active = true AND f.active = true
    GROUP BY f.id, f.name, f.description, pf.parameter_id, p.name
    HAVING 
        COUNT(fd.field_id) FILTER (WHERE fd.department_id IN (SELECT department_id FROM user_departments)) > 0
        OR NOT EXISTS (SELECT 1 FROM field_departments fd2 WHERE fd2.field_id = f.id AND fd2.active = true)
),
department_parameter_ids AS (
    SELECT 
        d.id as department_id,
        COALESCE(ARRAY_AGG(DISTINCT p.id::text) FILTER (WHERE p.id IS NOT NULL), ARRAY[]::text[]) as parameter_ids
    FROM departments d
    LEFT JOIN parameters p ON p.active = true
    LEFT JOIN parameter_fields pf ON pf.parameter_id = p.id AND pf.active = true
    LEFT JOIN field_departments fd ON fd.field_id = pf.field_id AND fd.active = true
    WHERE d.id IN (SELECT department_id FROM user_departments)
    AND (fd.department_id = d.id OR NOT EXISTS (SELECT 1 FROM field_departments fd2 
                                                 JOIN parameter_fields fp2 ON fp2.field_id = fd2.field_id 
                                                 WHERE fp2.parameter_id = p.id AND fp2.active = true AND fd2.active = true))
    GROUP BY d.id
),
cross_department_items AS (
    -- Fields with no department restrictions (available to all)
    SELECT DISTINCT f.id
    FROM fields f
    JOIN parameter_fields pf ON pf.field_id = f.id AND pf.active = true
    JOIN parameters p ON p.id = pf.parameter_id AND p.active = true
    WHERE NOT EXISTS (
        SELECT 1 FROM field_departments fd 
        WHERE fd.field_id = f.id 
        AND fd.active = true
    )
),
department_field_ids AS (
    SELECT 
        d.id as department_id,
        COALESCE(ARRAY_AGG(f.id::text ORDER BY f.id) FILTER (WHERE f.id IS NOT NULL), ARRAY[]::text[]) as field_ids
    FROM departments d
    LEFT JOIN (
        -- Fields assigned to this specific department
        SELECT DISTINCT fd.department_id, f.id
        FROM field_departments fd
        JOIN fields f ON f.id = fd.field_id
        JOIN parameter_fields pf ON pf.field_id = f.id AND pf.active = true
        JOIN parameters p ON p.id = pf.parameter_id AND p.active = true
        WHERE fd.active = true
        UNION
        -- Cross-department fields (available to all user departments)
        SELECT DISTINCT ud.department_id, cdi.id
        FROM user_departments ud
        CROSS JOIN cross_department_items cdi
    ) f_dept ON f_dept.department_id = d.id
    LEFT JOIN fields f ON f.id = f_dept.id
    WHERE d.id IN (SELECT department_id FROM user_departments)
    GROUP BY d.id
),
department_data AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description,
        COALESCE(dparami.parameter_ids, ARRAY[]::text[]) as parameter_ids,
        COALESCE(dparamitems.field_ids, ARRAY[]::text[]) as field_ids
    FROM departments d
    LEFT JOIN department_parameter_ids dparami ON dparami.department_id = d.id
    LEFT JOIN department_field_ids dparamitems ON dparamitems.department_id = d.id
    WHERE d.id IN (SELECT department_id FROM user_departments)
),
parameter_data AS (
    SELECT DISTINCT 
        p.id as parameter_id,
        p.name,
        COALESCE(p.description, '') as description,
        p.document_parameter,
        p.persona_parameter,
        CASE WHEN EXISTS (SELECT 1 FROM scenario_parameters sp WHERE sp.parameter_id = p.id AND sp.active = true) THEN true ELSE false END as scenario_parameter,
        p.video_parameter as video_parameter
    FROM parameters p
    JOIN parameter_fields pf ON pf.parameter_id = p.id AND pf.active = true
    LEFT JOIN field_departments fd ON fd.field_id = pf.field_id AND fd.active = true
    WHERE p.active = true
    GROUP BY p.id, p.name, p.description, p.document_parameter, p.persona_parameter, p.video_parameter
    HAVING 
        COUNT(fd.field_id) FILTER (WHERE fd.department_id IN (SELECT department_id FROM user_departments)) > 0
        OR NOT EXISTS (SELECT 1 FROM field_departments fd2 
                      JOIN parameter_fields pf2 ON pf2.field_id = fd2.field_id 
                      WHERE pf2.parameter_id = p.id AND pf2.active = true AND fd2.active = true)
    ORDER BY p.name
),
document_valid_fields AS (
    SELECT 
        dd.document_id,
        COALESCE(
            ARRAY_AGG(DISTINCT f.id::text ORDER BY f.id::text) FILTER (WHERE f.id IS NOT NULL),
            ARRAY[]::text[]
        ) as valid_field_ids
    FROM document_data dd
    LEFT JOIN parameter_fields pf ON pf.parameter_id IN (SELECT id FROM parameters WHERE active = true) AND pf.active = true
    LEFT JOIN fields f ON f.id = pf.field_id AND f.active = true
    LEFT JOIN field_departments fd ON fd.field_id = f.id AND fd.active = true
    WHERE (
        -- If document has no departments, include only cross-department fields
        (dd.department_ids IS NULL OR array_length(dd.department_ids, 1) = 0)
        AND NOT EXISTS (
            SELECT 1 FROM field_departments fd2 
            WHERE fd2.field_id = f.id 
            AND fd2.active = true
        )
    ) OR (
        -- If document has departments, include fields from those departments OR cross-department fields
        dd.department_ids IS NOT NULL 
        AND array_length(dd.department_ids, 1) > 0
        AND (
            fd.department_id = ANY(SELECT unnest(dd.department_ids)::uuid)
            OR NOT EXISTS (
                SELECT 1 FROM field_departments fd2 
                WHERE fd2.field_id = f.id 
                AND fd2.active = true
            )
        )
    )
    GROUP BY dd.document_id
),
scenario_options_data AS (
    SELECT 
        sd.scenario_id,
        sd.name,
        CASE 
            WHEN (SELECT COUNT(*) FROM scenario_data sd2 WHERE sd2.name = sd.name) > 1 
            THEN sd.name || ' (' || SUBSTRING(sd.scenario_id::text FROM LENGTH(sd.scenario_id::text) - 7) || ')'
            ELSE sd.name
        END as label
    FROM scenario_data sd
),
department_options_data AS (
    SELECT 
        dd.department_id,
        dd.name as label
    FROM department_data dd
)
SELECT 
    up.actor_name::text as actor_name,
    -- Aggregate documents separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (dd.document_id, dd.name, dd.updated_at, dd.upload_id, dd.active, dd.extension,
             COALESCE(dd.department_ids, ARRAY[]::text[]), dd.scenario_ids, dd.field_ids,
             COALESCE(dvf.valid_field_ids, ARRAY[]::text[]), dd.active_scenario_count, dd.total_scenario_links,
             CASE 
                 WHEN dd.active_scenario_count > 0 THEN false
                 WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) THEN true
                 ELSE false
             END,
             CASE 
                 WHEN dd.total_scenario_links > 0 THEN false
                 WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) THEN true
                 ELSE false
             END
            )::types.q_list_documents_v4_document
            ORDER BY dd.updated_at DESC
        ) FROM document_data dd
        LEFT JOIN document_valid_fields dvf ON dvf.document_id = dd.document_id),
        '{}'::types.q_list_documents_v4_document[]
    ) as documents,
    -- Aggregate scenarios separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (sd.scenario_id, sd.name, sd.description, sd.active)::types.q_list_documents_v4_scenario
            ORDER BY sd.name
        ) FROM scenario_data sd),
        '{}'::types.q_list_documents_v4_scenario[]
    ) as scenarios,
    -- Aggregate fields separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (fd.field_id, fd.name, fd.description, fd.parameter_id, fd.parameter_name)::types.q_list_documents_v4_field
            ORDER BY fd.name
        ) FROM field_data fd),
        '{}'::types.q_list_documents_v4_field[]
    ) as fields,
    -- Aggregate departments separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (dd2.department_id, dd2.name, dd2.description, dd2.parameter_ids, dd2.field_ids)::types.q_list_documents_v4_department
            ORDER BY dd2.name
        ) FROM department_data dd2),
        '{}'::types.q_list_documents_v4_department[]
    ) as departments,
    -- Aggregate parameters separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (pd.parameter_id, pd.name, pd.description, pd.document_parameter, pd.persona_parameter, pd.scenario_parameter, pd.video_parameter)::types.q_list_documents_v4_parameter
            ORDER BY pd.name
        ) FROM parameter_data pd),
        '{}'::types.q_list_documents_v4_parameter[]
    ) as parameters,
    -- Scenario options (composite type array)
    COALESCE(
        (SELECT ARRAY_AGG(
            (sod.scenario_id::text, sod.label)::types.q_list_documents_v4_scenario_option
            ORDER BY sod.label
        ) FROM scenario_options_data sod),
        '{}'::types.q_list_documents_v4_scenario_option[]
    ) as scenario_options,
    -- Department options (composite type array)
    COALESCE(
        (SELECT ARRAY_AGG(
            (dod.department_id::text, dod.label)::types.q_list_documents_v4_department_option
            ORDER BY dod.label
        ) FROM department_options_data dod),
        '{}'::types.q_list_documents_v4_department_option[]
    ) as department_options,
    -- Valid department IDs
    COALESCE(
        (SELECT ARRAY_AGG(dd2.department_id::text ORDER BY dd2.department_id::text) FROM department_data dd2),
        ARRAY[]::text[]
    ) as valid_department_ids,
    -- Document type options (hardcoded)
    ARRAY['homework', 'project', 'quiz', 'midterm', 'lab', 'lecture', 'syllabus']::text[] as document_type_options
FROM user_profile up
$_$;


--
-- Name: api_list_evals_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_list_evals_v4(profile_id uuid) RETURNS TABLE(actor_name text, evals types.q_list_evals_v4_eval[], rubrics types.q_list_evals_v4_rubric[], departments types.q_list_evals_v4_department[], agents types.q_list_evals_v4_agent[], standard_groups types.q_list_evals_v4_standard_group[], standards types.q_list_evals_v4_standard[], rubric_standard_groups types.q_list_evals_v4_rubric_standard_group[], rubric_options types.q_list_evals_v4_option[], department_options types.q_list_evals_v4_option[], agent_options types.q_list_evals_v4_option[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id
),
user_departments AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments ON profile_departments.profile_id = x.profile_id AND profile_departments.active = true
),
user_profile AS (
    SELECT 
        role,
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
eval_status_summary AS (
    SELECT 
        er.eval_id,
        COUNT(*) as total_runs,
        COUNT(*) FILTER (WHERE er.completed = true) as completed_runs,
        COUNT(*) FILTER (WHERE er.completed = false) as pending_runs
    FROM eval_runs er
    GROUP BY er.eval_id
),
eval_data AS (
    SELECT 
        e.id as eval_id,
        e.name,
        e.description,
        e.use_groups,
        e.dynamic,
        e.created_at,
        e.updated_at,
        -- Get first rubric from junction table for display (from runs or groups based on use_groups)
        (SELECT rga.rubric_id 
         FROM (
             SELECT errga.rubric_grade_agent_id, errga.created_at
             FROM eval_runs_rubric_grade_agents errga
             WHERE errga.eval_id = e.id AND e.use_groups = false
             UNION ALL
             SELECT egga.rubric_grade_agent_id, egga.created_at
             FROM eval_groups_rubric_grade_agents egga
             WHERE egga.eval_id = e.id AND e.use_groups = true
         ) combined
         JOIN rubric_grade_agents rga ON rga.id = combined.rubric_grade_agent_id
         ORDER BY combined.created_at 
         LIMIT 1) as rubric_id,
        (SELECT r.name 
         FROM (
             SELECT errga.rubric_grade_agent_id, errga.created_at
             FROM eval_runs_rubric_grade_agents errga
             WHERE errga.eval_id = e.id AND e.use_groups = false
             UNION ALL
             SELECT egga.rubric_grade_agent_id, egga.created_at
             FROM eval_groups_rubric_grade_agents egga
             WHERE egga.eval_id = e.id AND e.use_groups = true
         ) combined
         JOIN rubric_grade_agents rga ON rga.id = combined.rubric_grade_agent_id
         JOIN rubrics r ON r.id = rga.rubric_id
         ORDER BY combined.created_at 
         LIMIT 1) as rubric_name,
        (SELECT r.description 
         FROM (
             SELECT errga.rubric_grade_agent_id, errga.created_at
             FROM eval_runs_rubric_grade_agents errga
             WHERE errga.eval_id = e.id AND e.use_groups = false
             UNION ALL
             SELECT egga.rubric_grade_agent_id, egga.created_at
             FROM eval_groups_rubric_grade_agents egga
             WHERE egga.eval_id = e.id AND e.use_groups = true
         ) combined
         JOIN rubric_grade_agents rga ON rga.id = combined.rubric_grade_agent_id
         JOIN rubrics r ON r.id = rga.rubric_id
         ORDER BY combined.created_at 
         LIMIT 1) as rubric_description,
        COALESCE(ess.total_runs, 0) as total_runs,
        COALESCE(ess.completed_runs, 0) as completed_runs,
        COALESCE(ess.pending_runs, 0) as pending_runs,
        CASE 
            WHEN ess.total_runs IS NULL OR ess.total_runs = 0 THEN 'pending'
            WHEN ess.pending_runs > 0 THEN 'running'
            WHEN ess.completed_runs = ess.total_runs THEN 'completed'
            ELSE 'pending'
        END as status
    FROM evals e
    LEFT JOIN eval_status_summary ess ON ess.eval_id = e.id
),
rubric_departments_data AS (
    SELECT 
        rd.rubric_id,
        ARRAY_AGG(rd.department_id::text ORDER BY rd.created_at) as department_ids
    FROM rubric_departments rd
    WHERE rd.active = true
    GROUP BY rd.rubric_id
),
eval_departments AS (
    SELECT 
        ed.eval_id,
        COALESCE(rdd.department_ids, ARRAY[]::text[]) as department_ids
    FROM eval_data ed
    LEFT JOIN rubric_departments_data rdd ON rdd.rubric_id = ed.rubric_id
),
filtered_evals AS (
    SELECT 
        ed.*,
        edept.department_ids
    FROM eval_data ed
    LEFT JOIN eval_departments edept ON edept.eval_id = ed.eval_id
    CROSS JOIN user_profile up
    WHERE 
        -- Filter by department access (if rubric has departments, user must have access)
        (
            edept.department_ids IS NULL 
            OR array_length(edept.department_ids, 1) IS NULL
            OR EXISTS (
                SELECT 1 FROM user_departments ud
                WHERE ud.department_id::text = ANY(edept.department_ids)
            )
            OR up.role IN ('admin'::profile_role, 'superadmin'::profile_role)
        )
),
eval_agents_aggregated AS (
    SELECT 
        ea.eval_id,
        ARRAY_AGG(ea.agent_id::text ORDER BY ea.created_at) as agent_ids
    FROM eval_agents ea
    WHERE ea.eval_id IN (SELECT eval_id FROM filtered_evals)
    GROUP BY ea.eval_id
),
evals_aggregated AS (
    SELECT 
        ARRAY_AGG(
            (fe.eval_id, fe.name, fe.description, COALESCE(eaa.agent_ids, ARRAY[]::text[]), fe.use_groups,
             fe.rubric_id, fe.rubric_name, fe.rubric_description, fe.total_runs, fe.completed_runs,
             fe.pending_runs, fe.status, fe.created_at, fe.updated_at,
             fe.department_ids,
             CASE WHEN (SELECT role FROM user_profile) IN ('admin', 'instructional', 'superadmin') THEN true ELSE false END,
             CASE WHEN (SELECT role FROM user_profile) IN ('admin', 'instructional', 'superadmin') THEN true ELSE false END
            )::types.q_list_evals_v4_eval
            ORDER BY fe.updated_at DESC NULLS LAST
        ) as evals_array
    FROM filtered_evals fe
    LEFT JOIN eval_agents_aggregated eaa ON eaa.eval_id = fe.eval_id
),
all_rubric_ids AS (
    SELECT DISTINCT rga.rubric_id 
    FROM filtered_evals fe
    LEFT JOIN eval_runs_rubric_grade_agents errga ON errga.eval_id = fe.eval_id AND fe.use_groups = false
    LEFT JOIN eval_groups_rubric_grade_agents egga ON egga.eval_id = fe.eval_id AND fe.use_groups = true
    JOIN rubric_grade_agents rga ON rga.id = COALESCE(errga.rubric_grade_agent_id, egga.rubric_grade_agent_id)
),
all_department_ids AS (
    SELECT DISTINCT unnest(department_ids) as department_id
    FROM eval_departments
    WHERE department_ids IS NOT NULL AND array_length(department_ids, 1) > 0
),
all_agent_ids AS (
    SELECT DISTINCT agent_id
    FROM eval_agents ea
    JOIN filtered_evals fe ON fe.eval_id = ea.eval_id
    WHERE agent_id IS NOT NULL
),
all_standard_group_ids AS (
    SELECT DISTINCT rsg.standard_group_id
    FROM rubric_standard_groups rsg
    WHERE rsg.rubric_id IN (SELECT rubric_id FROM all_rubric_ids)
      AND rsg.active = true
),
all_standard_ids AS (
    SELECT DISTINCT st.id as standard_id
    FROM standards st
    WHERE st.standard_group_id IN (
        SELECT standard_group_id FROM all_standard_group_ids
    )
)
SELECT 
    up.actor_name::text as actor_name,
    -- Evals array
    COALESCE(ea.evals_array, '{}'::types.q_list_evals_v4_eval[]) as evals,
    -- Rubrics array
    COALESCE(
        (SELECT ARRAY_AGG((r.id, r.name, COALESCE(r.description, ''), r.points, r.pass_points)::types.q_list_evals_v4_rubric)
         FROM all_rubric_ids ari
         JOIN rubrics r ON r.id = ari.rubric_id),
        '{}'::types.q_list_evals_v4_rubric[]
    ) as rubrics,
    -- Departments array
    COALESCE(
        (SELECT ARRAY_AGG((d.id, d.title, COALESCE(d.description, ''))::types.q_list_evals_v4_department)
         FROM all_department_ids adi
         JOIN departments d ON d.id::text = adi.department_id
         WHERE d.active = true),
        '{}'::types.q_list_evals_v4_department[]
    ) as departments,
    -- Agents array
    COALESCE(
        (SELECT ARRAY_AGG((a.id, a.name, COALESCE(a.description, ''))::types.q_list_evals_v4_agent)
         FROM all_agent_ids aai
         JOIN agents a ON a.id = aai.agent_id
         WHERE a.active = true),
        '{}'::types.q_list_evals_v4_agent[]
    ) as agents,
    -- Standard groups array
    COALESCE(
        (SELECT ARRAY_AGG((sg.id, sg.name, sg.description, sg.points, sg.pass_points)::types.q_list_evals_v4_standard_group)
         FROM all_standard_group_ids asgi
         JOIN standard_groups sg ON sg.id = asgi.standard_group_id),
        '{}'::types.q_list_evals_v4_standard_group[]
    ) as standard_groups,
    -- Standards array
    COALESCE(
        (SELECT ARRAY_AGG((st.id, st.name, st.description, st.points)::types.q_list_evals_v4_standard)
         FROM all_standard_ids asi
         JOIN standards st ON st.id = asi.standard_id),
        '{}'::types.q_list_evals_v4_standard[]
    ) as standards,
    -- Rubric standard groups array (mapping structure)
    COALESCE(
        (SELECT ARRAY_AGG(
            (rsg.rubric_id, rsg.standard_group_id,
             COALESCE(
                 (SELECT ARRAY_AGG(st.id)
                  FROM standards st
                  WHERE st.standard_group_id = rsg.standard_group_id),
                 ARRAY[]::uuid[]
             )
            )::types.q_list_evals_v4_rubric_standard_group
         )
         FROM all_standard_group_ids asgi
         JOIN rubric_standard_groups rsg ON rsg.standard_group_id = asgi.standard_group_id AND rsg.active = true),
        '{}'::types.q_list_evals_v4_rubric_standard_group[]
    ) as rubric_standard_groups,
    -- Rubric options array
    COALESCE(
        (SELECT ARRAY_AGG((r.id::text, r.name)::types.q_list_evals_v4_option)
         FROM all_rubric_ids ari
         JOIN rubrics r ON r.id = ari.rubric_id),
        '{}'::types.q_list_evals_v4_option[]
    ) as rubric_options,
    -- Department options array (only departments assigned to evals)
    COALESCE(
        (SELECT ARRAY_AGG((d.id::text, d.title)::types.q_list_evals_v4_option)
         FROM all_department_ids adi
         JOIN departments d ON d.id::text = adi.department_id
         WHERE d.active = true),
        '{}'::types.q_list_evals_v4_option[]
    ) as department_options,
    -- Agent options array (only agents assigned to evals)
    COALESCE(
        (SELECT ARRAY_AGG((a.id::text, a.name)::types.q_list_evals_v4_option)
         FROM all_agent_ids aai
         JOIN agents a ON a.id = aai.agent_id
         WHERE a.active = true),
        '{}'::types.q_list_evals_v4_option[]
    ) as agent_options
FROM user_profile up
CROSS JOIN evals_aggregated ea
$$;


--
-- Name: api_list_fields_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_list_fields_v4(profile_id uuid) RETURNS TABLE(actor_name text, fields types.q_list_fields_v4_field[], parameters types.q_list_fields_v4_parameter[], departments types.q_list_fields_v4_department[], parameter_options types.q_list_fields_v4_option[], department_options types.q_list_fields_v4_option[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id
),
user_departments AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.active = true
),
user_profile AS (
    SELECT 
        role,
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
field_parameters_agg AS (
    SELECT 
        pf.field_id,
        ARRAY_AGG(pf.parameter_id::text ORDER BY p.name) as parameter_ids
    FROM parameter_fields pf
    JOIN parameters p ON p.id = pf.parameter_id
    WHERE pf.active = true
    GROUP BY pf.field_id
),
field_departments_data AS (
    SELECT 
        fd.field_id,
        ARRAY_AGG(fd.department_id::text ORDER BY fd.created_at) as department_ids
    FROM field_departments fd
    WHERE fd.active = true
    GROUP BY fd.field_id
),
field_conditional_parameters_agg AS (
    SELECT 
        fcp.field_id,
        ARRAY_AGG(fcp.conditional_parameter_id::text ORDER BY p.name) as conditional_parameter_ids
    FROM field_conditional_parameters fcp
    JOIN parameters p ON p.id = fcp.conditional_parameter_id
    WHERE fcp.active = true
    GROUP BY fcp.field_id
),
fields_data AS (
    SELECT 
        f.id as field_id,
        f.name,
        f.description,
        f.active,
        f.created_at,
        f.updated_at,
        COALESCE(fdd.department_ids, NULL) as department_ids,
        COALESCE(fpa.parameter_ids, ARRAY[]::text[]) as parameter_ids,
        COALESCE(fcpa.conditional_parameter_ids, ARRAY[]::text[]) as conditional_parameter_ids,
        CASE 
            WHEN COALESCE(fdd.department_ids, NULL) IS NULL AND up.role != 'superadmin' THEN false
            WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_edit,
        CASE 
            WHEN COALESCE(fdd.department_ids, NULL) IS NULL AND up.role != 'superadmin' THEN false
            WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_delete,
        true as can_duplicate
    FROM params x
    JOIN fields f ON f.active = true
    LEFT JOIN field_departments_data fdd ON fdd.field_id = f.id
    LEFT JOIN field_parameters_agg fpa ON fpa.field_id = f.id
    LEFT JOIN field_conditional_parameters_agg fcpa ON fcpa.field_id = f.id
    CROSS JOIN user_profile up
    WHERE (
        -- Include fields with no departments (cross-department)
        NOT EXISTS (SELECT 1 FROM field_departments fd2 WHERE fd2.field_id = f.id AND fd2.active = true)
        OR
        -- Include fields in user's departments
        EXISTS (
            SELECT 1 FROM field_departments fd
            WHERE fd.field_id = f.id 
            AND fd.department_id IN (SELECT department_id FROM user_departments)
            AND fd.active = true
        )
    )
    GROUP BY f.id, f.name, f.description, f.active, f.created_at, f.updated_at, fdd.department_ids, fpa.parameter_ids, fcpa.conditional_parameter_ids, up.role
),
assigned_parameter_ids AS (
    SELECT DISTINCT unnest(parameter_ids)::text as parameter_id
    FROM fields_data
    WHERE parameter_ids IS NOT NULL
),
assigned_department_ids AS (
    SELECT DISTINCT unnest(department_ids)::text as department_id
    FROM fields_data
    WHERE department_ids IS NOT NULL
),
all_parameter_ids AS (
    SELECT DISTINCT unnest(parameter_ids)::uuid as parameter_id
    FROM field_parameters_agg
),
parameter_data AS (
    SELECT 
        p.id as parameter_id,
        p.name,
        COALESCE(p.description, '') as description
    FROM all_parameter_ids api
    JOIN parameters p ON p.id = api.parameter_id
),
parameter_options_data AS (
    SELECT 
        ARRAY_AGG(
            (p.parameter_id::text,
             CASE 
                 WHEN (SELECT COUNT(*) FROM parameter_data pd2 WHERE pd2.name = p.name) > 1 
                 THEN p.name || ' (' || SUBSTRING(p.parameter_id::text FROM LENGTH(p.parameter_id::text) - 7) || ')'
                 ELSE p.name
             END)::types.q_list_fields_v4_option
            ORDER BY p.name
        ) FILTER (WHERE p.parameter_id IN (SELECT parameter_id::uuid FROM assigned_parameter_ids)) as options
    FROM parameter_data p
),
all_department_ids AS (
    SELECT DISTINCT unnest(department_ids)::uuid as department_id
    FROM field_departments_data
    WHERE department_ids IS NOT NULL
    UNION
    SELECT department_id FROM user_departments
),
department_data AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM all_department_ids adi
    JOIN departments d ON d.id = adi.department_id
),
department_options_data AS (
    SELECT 
        ARRAY_AGG(
            (d.department_id::text, d.name)::types.q_list_fields_v4_option
            ORDER BY d.name
        ) FILTER (WHERE d.department_id::text IN (SELECT department_id FROM assigned_department_ids) AND d.department_id IN (SELECT department_id FROM user_departments)) as options
    FROM department_data d
)
SELECT 
    up.actor_name,
    -- Aggregate fields
    COALESCE(
        (SELECT ARRAY_AGG(
            (fd.field_id, fd.name, fd.description, fd.active, fd.created_at, fd.updated_at, fd.department_ids, fd.parameter_ids, fd.conditional_parameter_ids, fd.can_edit, fd.can_delete, fd.can_duplicate)::types.q_list_fields_v4_field
            ORDER BY fd.name
        ) FROM fields_data fd),
        '{}'::types.q_list_fields_v4_field[]
    ) as fields,
    -- Aggregate parameters
    COALESCE(
        (SELECT ARRAY_AGG(
            (pd.parameter_id, pd.name, pd.description)::types.q_list_fields_v4_parameter
            ORDER BY pd.name
        ) FROM parameter_data pd),
        '{}'::types.q_list_fields_v4_parameter[]
    ) as parameters,
    -- Aggregate departments
    COALESCE(
        (SELECT ARRAY_AGG(
            (dd.department_id, dd.name, dd.description)::types.q_list_fields_v4_department
            ORDER BY dd.name
        ) FROM department_data dd),
        '{}'::types.q_list_fields_v4_department[]
    ) as departments,
    -- Parameter options (for UI filtering)
    COALESCE((SELECT options FROM parameter_options_data), '{}'::types.q_list_fields_v4_option[]) as parameter_options,
    -- Department options (for UI filtering)
    COALESCE((SELECT options FROM department_options_data), '{}'::types.q_list_fields_v4_option[]) as department_options
FROM user_profile up
$$;


--
-- Name: api_list_models_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_list_models_v4(profile_id uuid) RETURNS TABLE(actor_name text, models types.q_list_models_v4_model[], provider_options types.q_list_models_v4_provider_option[], status_options types.q_list_models_v4_status_option[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id
),
user_profile AS (
    SELECT 
        role,
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
-- Pre-aggregate simulation usage counts for all models
-- Simulations are linked to models via simulation_text_agent_id/simulation_voice_agent_id -> agents -> model_id
simulation_usage AS (
    SELECT 
        a.model_id,
        COUNT(*) as usage_count
    FROM (
        SELECT sim.simulation_text_agent_id as agent_id
        FROM simulations sim
        WHERE sim.simulation_text_agent_id IS NOT NULL
        UNION ALL
        SELECT sim.simulation_voice_agent_id as agent_id
        FROM simulations sim
        WHERE sim.simulation_voice_agent_id IS NOT NULL
    ) combined_agents
    JOIN agents a ON a.id = combined_agents.agent_id AND a.active = true
    GROUP BY a.model_id
),
-- Pre-aggregate agent usage counts for all models
agent_usage AS (
    SELECT 
        model_id,
        COUNT(*) as usage_count
    FROM agents
    GROUP BY model_id
),
-- Determine if model is an image model (has 'image' output modality)
image_model_check AS (
    SELECT 
        model_id,
        CASE WHEN COUNT(*) > 0 THEN true ELSE false END as image_model
    FROM model_modalities
    WHERE modality = 'image' AND is_input = false AND active = true
    GROUP BY model_id
),
models_with_usage AS (
    SELECT 
        m.id as model_id,
        m.name,
        m.description,
        m.active,
        COALESCE(imc.image_model, false) as image_model,
        m.updated_at,
        p.value as provider,
        p.id as provider_id,
        p.name as provider_name,
        COALESCE(me.base_url, '') as base_url,
        COALESCE(su.usage_count, 0) as simulation_usage_count,
        COALESCE(au.usage_count, 0) as agent_usage_count
    FROM models m
    JOIN providers p ON p.id = m.provider_id
    LEFT JOIN model_endpoints me ON me.model_id = m.id AND me.active = true
    LEFT JOIN simulation_usage su ON su.model_id = m.id
    LEFT JOIN agent_usage au ON au.model_id = m.id
    LEFT JOIN image_model_check imc ON imc.model_id = m.id
),
provider_options_data AS (
    SELECT 
        value,
        name as label
    FROM providers
    WHERE active = true
    ORDER BY name
),
models_aggregated AS (
    SELECT 
        up.actor_name,
        COALESCE(
            ARRAY_AGG(
                (mwu.model_id, mwu.name, mwu.description, mwu.active, mwu.image_model, mwu.updated_at,
                 mwu.provider, mwu.provider_id, mwu.provider_name, mwu.base_url,
                 CASE 
                     WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
                     ELSE false
                 END,
                 CASE 
                     WHEN (mwu.simulation_usage_count + mwu.agent_usage_count) = 0 THEN true
                     ELSE false
                 END
                )::types.q_list_models_v4_model
                ORDER BY mwu.updated_at DESC
            ),
            '{}'::types.q_list_models_v4_model[]
        ) as models
    FROM models_with_usage mwu
    CROSS JOIN user_profile up
    GROUP BY up.actor_name
),
provider_options_aggregated AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (value, label)::types.q_list_models_v4_provider_option
                ORDER BY label
            ),
            '{}'::types.q_list_models_v4_provider_option[]
        ) as provider_options
    FROM provider_options_data
)
SELECT 
    ma.actor_name::text as actor_name,
    ma.models,
    poa.provider_options,
    ARRAY[
        ('true', 'Active')::types.q_list_models_v4_status_option,
        ('false', 'Inactive')::types.q_list_models_v4_status_option
    ] as status_options
FROM models_aggregated ma
CROSS JOIN provider_options_aggregated poa
$$;


--
-- Name: api_list_parameters_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_list_parameters_v4(profile_id uuid) RETURNS TABLE(actor_name text, parameters types.q_list_parameters_v4_parameter[], scenarios types.q_list_parameters_v4_scenario[], departments types.q_list_parameters_v4_department[], documents types.q_list_parameters_v4_document[], scenario_options types.q_list_parameters_v4_scenario_option[], document_options types.q_list_parameters_v4_document_option[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id
),
user_departments AS (
    SELECT pd.department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.active = true
),
user_profile AS (
    SELECT 
        role,
        first_name || ' ' || last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
parameter_active_scenario_links AS (
    SELECT 
        fp.parameter_id,
        COUNT(DISTINCT sf.scenario_id) as active_scenario_count
    FROM parameter_fields fp
    JOIN scenario_fields sf ON sf.field_id = fp.field_id
    WHERE fp.active = true AND sf.active = true
    GROUP BY fp.parameter_id
),
parameter_all_scenario_links AS (
    SELECT 
        fp.parameter_id,
        COUNT(DISTINCT sf.scenario_id) as total_scenario_links
    FROM parameter_fields fp
    JOIN scenario_fields sf ON sf.field_id = fp.field_id
    WHERE fp.active = true
    GROUP BY fp.parameter_id
),
scenario_parameters_data AS (
    SELECT 
        sp.parameter_id,
        ARRAY_AGG(DISTINCT st.parent_id::text ORDER BY st.parent_id::text) as scenario_ids,
        COUNT(DISTINCT st.parent_id) as num_scenarios
    FROM scenario_parameters sp
    JOIN scenarios s ON s.id = sp.scenario_id
    JOIN scenario_tree st ON st.child_id = s.id AND st.parent_id = st.child_id
    WHERE sp.active = true AND s.active = true
    GROUP BY sp.parameter_id
),
parameter_item_counts AS (
    SELECT 
        fp.parameter_id,
        COUNT(*) as num_items
    FROM parameter_fields fp
    WHERE fp.active = true
    GROUP BY fp.parameter_id
),
parameter_sample_items_data AS (
    SELECT 
        fp_sub.parameter_id,
        fp_sub.field_id,
        fp_sub.name,
        fp_sub.description
    FROM (
        SELECT f.id as field_id, fp.parameter_id, f.name, f.description,
               ROW_NUMBER() OVER (PARTITION BY fp.parameter_id ORDER BY f.name) as rn
        FROM parameter_fields fp
        JOIN fields f ON f.id = fp.field_id
        WHERE fp.active = true
    ) fp_sub
    WHERE fp_sub.rn <= 3
),
parameter_item_departments_data AS (
    SELECT 
        combined.parameter_id,
        ARRAY_AGG(DISTINCT combined.department_id::text ORDER BY combined.department_id::text) as department_ids
    FROM (
        SELECT pd.parameter_id, pd.department_id
        FROM parameter_departments pd
        WHERE pd.active = true
        UNION
        SELECT fp.parameter_id, fd.department_id
        FROM parameter_fields fp
        JOIN field_departments fd ON fd.field_id = fp.field_id
        WHERE fp.active = true AND fd.active = true
    ) combined
    GROUP BY combined.parameter_id
),
parameter_item_departments_for_filter AS (
    SELECT DISTINCT
        combined.parameter_id,
        combined.department_id
    FROM (
        SELECT pd.parameter_id, pd.department_id
        FROM parameter_departments pd
        WHERE pd.active = true
        UNION
        SELECT fp.parameter_id, fd.department_id
        FROM parameter_fields fp
        JOIN field_departments fd ON fd.field_id = fp.field_id
        WHERE fp.active = true AND fd.active = true
    ) combined
),
parameter_documents AS (
    SELECT 
        fp.parameter_id,
        ARRAY_AGG(DISTINCT df.document_id::text ORDER BY df.document_id::text) as document_ids
    FROM parameter_fields fp
    JOIN document_fields df ON df.field_id = fp.field_id
    WHERE fp.active = true AND df.active = true
    GROUP BY fp.parameter_id
),
filtered_parameters AS (
    SELECT 
        p.id,
        p.name,
        p.description,
        p.active,
        p.updated_at
    FROM parameters p
    LEFT JOIN parameter_item_departments_for_filter pidf ON pidf.parameter_id = p.id
    GROUP BY p.id, p.name, p.description, p.active, p.updated_at
    HAVING 
        COUNT(pidf.parameter_id) FILTER (WHERE pidf.department_id IN (SELECT department_id FROM user_departments)) > 0
        OR NOT EXISTS (
            SELECT 1 FROM parameter_departments pd2 WHERE pd2.parameter_id = p.id AND pd2.active = true
        )
        AND NOT EXISTS (
            SELECT 1 FROM field_departments fd2 
            JOIN parameter_fields fp2 ON fp2.field_id = fd2.field_id 
            WHERE fp2.parameter_id = p.id AND fp2.active = true AND fd2.active = true
        )
),
all_department_ids AS (
    SELECT DISTINCT unnest(department_ids)::uuid as department_id
    FROM parameter_item_departments_data
    WHERE department_ids IS NOT NULL
    UNION
    SELECT ud.department_id FROM user_departments ud
),
all_scenario_ids AS (
    SELECT DISTINCT unnest(scenario_ids)::uuid as scenario_id
    FROM scenario_parameters_data
    WHERE scenario_ids IS NOT NULL
),
all_document_ids AS (
    SELECT DISTINCT unnest(document_ids)::uuid as document_id
    FROM parameter_documents
    WHERE document_ids IS NOT NULL
),
scenarios_data AS (
    SELECT 
        s.id as scenario_id,
        s.name,
        COALESCE(ps.problem_statement, '') as description,
        s.active
    FROM all_scenario_ids asi
    LEFT JOIN scenarios s ON s.id = asi.scenario_id
    LEFT JOIN scenario_problem_statements sps ON sps.scenario_id = s.id AND sps.active = true
    LEFT JOIN problem_statements ps ON ps.id = sps.problem_statement_id
    WHERE s.id IS NOT NULL
),
departments_data AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM departments d
    WHERE d.id IN (SELECT department_id FROM all_department_ids)
),
documents_data AS (
    SELECT 
        doc.id as document_id,
        doc.name,
        COALESCE(doc.description, '') as description
    FROM documents doc
    WHERE doc.id IN (SELECT document_id FROM all_document_ids)
),
-- Collect scenario IDs, document IDs, and department IDs actually assigned to parameters
assigned_scenario_ids AS (
    SELECT DISTINCT unnest(spd.scenario_ids)::uuid as scenario_id
    FROM filtered_parameters fp
    LEFT JOIN scenario_parameters_data spd ON spd.parameter_id = fp.id
    WHERE spd.scenario_ids IS NOT NULL
),
assigned_document_ids AS (
    SELECT DISTINCT unnest(pd.document_ids)::uuid as document_id
    FROM filtered_parameters fp
    LEFT JOIN parameter_documents pd ON pd.parameter_id = fp.id
    WHERE pd.document_ids IS NOT NULL
),
assigned_department_ids AS (
    SELECT DISTINCT unnest(pidd.department_ids)::uuid as department_id
    FROM filtered_parameters fp
    LEFT JOIN parameter_item_departments_data pidd ON pidd.parameter_id = fp.id
    WHERE pidd.department_ids IS NOT NULL
),
-- Filter scenarios to only include those assigned to parameters AND in user's departments
scenario_ids_in_user_depts AS (
    SELECT DISTINCT sd.scenario_id::text
    FROM scenario_departments sd
    WHERE sd.scenario_id IN (SELECT scenario_id FROM assigned_scenario_ids)
    AND sd.department_id IN (SELECT department_id FROM user_departments)
    AND sd.active = true
    UNION
    SELECT DISTINCT s.id::text
    FROM scenarios s
    WHERE s.id IN (SELECT scenario_id FROM assigned_scenario_ids)
    AND NOT EXISTS (
        SELECT 1 FROM scenario_departments sd2 
        WHERE sd2.scenario_id = s.id AND sd2.active = true
    )
),
-- Filter documents to only include those assigned to parameters AND in user's departments
document_ids_in_user_depts AS (
    SELECT DISTINCT dd.document_id::text
    FROM document_departments dd
    WHERE dd.document_id IN (SELECT document_id FROM assigned_document_ids)
    AND dd.department_id IN (SELECT department_id FROM user_departments)
    AND dd.active = true
    UNION
    SELECT DISTINCT d.id::text
    FROM documents d
    WHERE d.id IN (SELECT document_id FROM assigned_document_ids)
    AND NOT EXISTS (
        SELECT 1 FROM document_departments dd2 
        WHERE dd2.document_id = d.id AND dd2.active = true
    )
),
-- Build scenario options with disambiguation
scenario_names_count AS (
    SELECT 
        name,
        COUNT(*) as name_count
    FROM scenarios_data
    GROUP BY name
),
scenario_options_data AS (
    SELECT 
        sd.scenario_id::text as value,
        CASE 
            WHEN snc.name_count > 1 THEN sd.name || ' (' || SUBSTRING(sd.scenario_id::text FROM LENGTH(sd.scenario_id::text) - 7) || ')'
            ELSE sd.name
        END as label
    FROM scenarios_data sd
    JOIN scenario_names_count snc ON snc.name = sd.name
    WHERE sd.scenario_id::text IN (SELECT scenario_id FROM scenario_ids_in_user_depts)
),
-- Build document options with disambiguation
document_names_count AS (
    SELECT 
        name,
        COUNT(*) as name_count
    FROM documents_data
    GROUP BY name
),
document_options_data AS (
    SELECT 
        dd.document_id::text as value,
        CASE 
            WHEN dnc.name_count > 1 THEN dd.name || ' (' || SUBSTRING(dd.document_id::text FROM LENGTH(dd.document_id::text) - 7) || ')'
            ELSE dd.name
        END as label
    FROM documents_data dd
    JOIN document_names_count dnc ON dnc.name = dd.name
    WHERE dd.document_id::text IN (SELECT document_id FROM document_ids_in_user_depts)
),
-- Filter departments to only include those assigned to parameters AND in user's departments
filtered_departments_data AS (
    SELECT 
        d.department_id,
        d.name,
        d.description
    FROM departments_data d
    WHERE d.department_id IN (SELECT department_id FROM assigned_department_ids)
    AND d.department_id IN (SELECT department_id FROM user_departments)
),
parameters_data AS (
    SELECT 
        fp.id as parameter_id,
        fp.name,
        fp.description,
        fp.active,
        fp.updated_at,
        COALESCE(pidd.department_ids, NULL) as department_ids,
        COALESCE(spd.scenario_ids, ARRAY[]::text[]) as scenario_ids,
        COALESCE(pd.document_ids, ARRAY[]::text[]) as document_ids,
        COALESCE(pic.num_items, 0) as num_items,
        COALESCE(
            (SELECT ARRAY_AGG((psi.field_id, psi.name, psi.description)::types.q_list_parameters_v4_sample_item ORDER BY psi.name)
             FROM parameter_sample_items_data psi
             WHERE psi.parameter_id = fp.id),
            '{}'::types.q_list_parameters_v4_sample_item[]
        ) as sample_items,
        CASE 
            WHEN COALESCE(pasl.active_scenario_count, 0) > 0 THEN false
            WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_edit,
        CASE 
            WHEN COALESCE(pasl_all.total_scenario_links, 0) > 0 THEN false
            WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_delete,
        CASE 
            WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_duplicate
    FROM filtered_parameters fp
    CROSS JOIN user_profile up
    LEFT JOIN parameter_item_departments_data pidd ON pidd.parameter_id = fp.id
    LEFT JOIN scenario_parameters_data spd ON spd.parameter_id = fp.id
    LEFT JOIN parameter_documents pd ON pd.parameter_id = fp.id
    LEFT JOIN parameter_item_counts pic ON pic.parameter_id = fp.id
    LEFT JOIN parameter_active_scenario_links pasl ON pasl.parameter_id = fp.id
    LEFT JOIN parameter_all_scenario_links pasl_all ON pasl_all.parameter_id = fp.id
)
SELECT 
    up.actor_name::text as actor_name,
    -- Aggregate parameters separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (pd.parameter_id, pd.name, pd.description, pd.active, pd.updated_at,
             pd.department_ids, pd.scenario_ids, pd.document_ids, pd.num_items,
             pd.sample_items, pd.can_edit, pd.can_delete, pd.can_duplicate
            )::types.q_list_parameters_v4_parameter
            ORDER BY pd.updated_at DESC NULLS LAST
        ) FROM parameters_data pd),
        '{}'::types.q_list_parameters_v4_parameter[]
    ) as parameters,
    -- Aggregate scenarios separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (sd.scenario_id, sd.name, sd.description, sd.active)::types.q_list_parameters_v4_scenario
            ORDER BY sd.name
        ) FROM scenarios_data sd),
        '{}'::types.q_list_parameters_v4_scenario[]
    ) as scenarios,
    -- Aggregate departments separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (fdd.department_id, fdd.name, fdd.description)::types.q_list_parameters_v4_department
            ORDER BY fdd.name
        ) FROM filtered_departments_data fdd),
        '{}'::types.q_list_parameters_v4_department[]
    ) as departments,
    -- Aggregate documents separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (dd.document_id, dd.name, dd.description)::types.q_list_parameters_v4_document
            ORDER BY dd.name
        ) FROM documents_data dd),
        '{}'::types.q_list_parameters_v4_document[]
    ) as documents,
    -- Aggregate scenario options separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (sod.value, sod.label)::types.q_list_parameters_v4_scenario_option
            ORDER BY sod.label
        ) FROM scenario_options_data sod),
        '{}'::types.q_list_parameters_v4_scenario_option[]
    ) as scenario_options,
    -- Aggregate document options separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (dod.value, dod.label)::types.q_list_parameters_v4_document_option
            ORDER BY dod.label
        ) FROM document_options_data dod),
        '{}'::types.q_list_parameters_v4_document_option[]
    ) as document_options
FROM user_profile up
$$;


--
-- Name: api_list_personas_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_list_personas_v4(profile_id uuid) RETURNS TABLE(actor_name text, personas types.q_list_personas_v4_persona[], scenarios types.q_list_personas_v4_scenario[], agents types.q_list_personas_v4_agent[], departments types.q_list_personas_v4_department[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id
),
user_departments AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments ON profile_departments.profile_id = x.profile_id AND profile_departments.active = true
),
user_profile AS (
    SELECT 
        role,
        first_name || ' ' || last_name as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
persona_active_scenario_links AS (
    SELECT 
        sp.persona_id,
        COUNT(*) as active_scenario_count
    FROM scenario_personas sp
    WHERE sp.active = true
    GROUP BY sp.persona_id
),
persona_all_scenario_links AS (
    SELECT 
        sp.persona_id,
        COUNT(*) as total_scenario_links
    FROM scenario_personas sp
    GROUP BY sp.persona_id
),
persona_scenarios AS (
    SELECT 
        sp.persona_id,
        ARRAY_AGG(DISTINCT st.parent_id) as scenario_ids,
        COUNT(DISTINCT st.parent_id) as num_scenarios
    FROM scenario_personas sp
    JOIN scenario_tree st ON st.child_id = sp.scenario_id
    WHERE sp.active = true AND st.parent_id = st.child_id
    GROUP BY sp.persona_id
),
persona_departments_data AS (
    SELECT 
        pd.persona_id,
        ARRAY_AGG(pd.department_id::text ORDER BY pd.created_at) as department_ids
    FROM persona_departments pd
    WHERE pd.active = true
    GROUP BY pd.persona_id
),
persona_data_base AS (
    SELECT 
        p.id as persona_id,
        p.name as persona_name,
        p.description,
        p.color,
        p.icon,
        NULL::uuid as agent_id,
        NULL::uuid as model_id,
        NULL::text as reasoning,
        NULL::numeric as temperature,
        p.active,
        p.updated_at,
        COALESCE(pdd.department_ids, NULL) as department_ids,
        COALESCE(ps.scenario_ids, ARRAY[]::uuid[]) as scenario_ids,
        COALESCE(ps.num_scenarios, 0) as num_scenarios,
        COALESCE(pasl.active_scenario_count, 0) as active_scenario_count,
        COALESCE(pasl_all.total_scenario_links, 0) as total_scenario_links,
        CASE WHEN COUNT(pd.persona_id) > 0 THEN true ELSE false END as has_dept_links
    FROM personas p
    LEFT JOIN persona_scenarios ps ON ps.persona_id = p.id
    LEFT JOIN persona_active_scenario_links pasl ON pasl.persona_id = p.id
    LEFT JOIN persona_all_scenario_links pasl_all ON pasl_all.persona_id = p.id
    LEFT JOIN persona_departments_data pdd ON pdd.persona_id = p.id
    LEFT JOIN persona_departments pd ON pd.persona_id = p.id AND pd.active = true AND pd.department_id IN (SELECT department_id FROM user_departments)
    GROUP BY p.id, p.name, p.description, p.color, p.icon, p.active, p.updated_at, 
             pdd.department_ids, ps.scenario_ids, ps.num_scenarios, pasl.active_scenario_count, pasl_all.total_scenario_links
    HAVING COUNT(pd.persona_id) > 0 OR NOT EXISTS (
        SELECT 1 FROM persona_departments pd2 WHERE pd2.persona_id = p.id AND pd2.active = true
    )
),
persona_data AS (
    SELECT 
        pdb.*,
        CASE 
            WHEN pdb.active_scenario_count > 0 THEN false
            WHEN NOT pdb.has_dept_links AND up.role != 'superadmin' THEN false
            WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_edit,
        CASE 
            WHEN NOT pdb.has_dept_links AND up.role != 'superadmin' THEN false
            WHEN pdb.total_scenario_links > 0 THEN false
            WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_delete
    FROM persona_data_base pdb
    CROSS JOIN user_profile up
),
all_scenario_ids AS (
    SELECT DISTINCT unnest(scenario_ids) as scenario_id
    FROM persona_data
),
scenario_department_check AS (
    SELECT DISTINCT sd.scenario_id::text
    FROM scenario_departments sd
    WHERE sd.scenario_id::text = ANY(SELECT scenario_id::text FROM all_scenario_ids)
    AND sd.department_id::text = ANY(SELECT department_id::text FROM user_departments)
    AND sd.active = true
    UNION
    SELECT DISTINCT s.id::text
    FROM scenarios s
    WHERE s.id::text = ANY(SELECT scenario_id::text FROM all_scenario_ids)
    AND NOT EXISTS (
        SELECT 1 FROM scenario_departments sd2 
        WHERE sd2.scenario_id = s.id AND sd2.active = true
    )
),
valid_scenario_ids AS (
    SELECT scenario_id::uuid
    FROM scenario_department_check
),
scenario_mapping_data AS (
    SELECT 
        s.id as scenario_id,
        s.name,
        COALESCE(ps.problem_statement, '') as description,
        s.active,
        ARRAY[]::uuid[] as persona_ids,
        ARRAY[]::uuid[] as document_ids,
        ARRAY[]::uuid[] as parameter_item_ids
    FROM all_scenario_ids asi
    JOIN scenarios s ON s.id = asi.scenario_id
    LEFT JOIN scenario_problem_statements sps ON sps.scenario_id = s.id AND sps.active = true
    LEFT JOIN problem_statements ps ON ps.id = sps.problem_statement_id
    LEFT JOIN scenario_tree st ON st.parent_id = s.id AND st.child_id = s.id
),
department_mapping_data AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM departments d
    WHERE d.id IN (SELECT department_id FROM user_departments)
),
assigned_agent_ids AS (
    SELECT DISTINCT agent_id
    FROM persona_data
    WHERE agent_id IS NOT NULL
),
agent_mapping_data AS (
    SELECT 
        a.id as agent_id,
        a.name,
        COALESCE(a.description, '') as description,
        ARRAY[a.role::text] as roles
    FROM agents a
    WHERE a.id IN (SELECT agent_id FROM assigned_agent_ids)
    AND a.active = true
)
SELECT 
    up.actor_name::text as actor_name,
    -- Aggregate personas separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (pd.persona_id, pd.persona_name, pd.description, pd.color, pd.icon,
             pd.department_ids, pd.scenario_ids, pd.agent_id, NULL::text,
             pd.model_id, NULL::text, pd.reasoning, 
             COALESCE(pd.temperature, 0.0), 
             CASE WHEN pd.temperature IS NOT NULL THEN TO_CHAR(pd.temperature, 'FM0.00') ELSE '0.00' END,
             pd.active, NOT pd.active, pd.num_scenarios,
             pd.can_edit,
             true,
             pd.can_delete,
             pd.updated_at
            )::types.q_list_personas_v4_persona
            ORDER BY pd.updated_at DESC NULLS LAST
        ) FROM persona_data pd),
        '{}'::types.q_list_personas_v4_persona[]
    ) as personas,
    -- Aggregate scenarios separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (smd.scenario_id, smd.name, smd.description, smd.active, smd.persona_ids, 
             smd.document_ids, smd.parameter_item_ids)::types.q_list_personas_v4_scenario
            ORDER BY smd.name
        ) FROM scenario_mapping_data smd),
        '{}'::types.q_list_personas_v4_scenario[]
    ) as scenarios,
    -- Aggregate agents separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (amd.agent_id, amd.name, amd.description, amd.roles)::types.q_list_personas_v4_agent
            ORDER BY amd.name
        ) FROM agent_mapping_data amd),
        '{}'::types.q_list_personas_v4_agent[]
    ) as agents,
    -- Aggregate departments separately
    COALESCE(
        (SELECT ARRAY_AGG(
            (dmd.department_id, dmd.name, dmd.description)::types.q_list_personas_v4_department
            ORDER BY dmd.name
        ) FROM department_mapping_data dmd),
        '{}'::types.q_list_personas_v4_department[]
    ) as departments
FROM user_profile up
$$;


--
-- Name: api_list_providers_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_list_providers_v4(profile_id uuid) RETURNS TABLE(actor_name text, providers types.q_list_providers_v4_provider[], provider_options types.q_list_providers_v4_provider_option[], status_options types.q_list_providers_v4_status_option[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id
),
user_profile AS (
    SELECT 
        p.role,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
provider_data AS (
    SELECT 
        p.id as provider_id,
        p.name,
        p.description,
        p.value,
        p.active,
        p.created_at,
        p.updated_at,
        COALESCE(pe.base_url, '') as base_url,
        CASE 
            WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_edit,
        CASE 
            -- Check if provider is used by models
            WHEN EXISTS (SELECT 1 FROM models m WHERE m.provider_id = p.id AND m.active = true) THEN false
            WHEN up.role IN ('admin'::profile_role, 'superadmin'::profile_role) THEN true
            ELSE false
        END as can_delete,
        true as can_duplicate
    FROM providers p
    LEFT JOIN provider_endpoints pe ON pe.provider_id = p.id AND pe.active = true
    CROSS JOIN user_profile up
),
providers_agg AS (
    SELECT 
        (SELECT actor_name FROM user_profile LIMIT 1)::text as actor_name,
        COALESCE(
            ARRAY_AGG(
                (pd.provider_id, pd.name, pd.description, pd.value, pd.active, pd.created_at, pd.updated_at, pd.base_url, pd.can_edit, pd.can_delete, pd.can_duplicate)::types.q_list_providers_v4_provider
                ORDER BY pd.created_at DESC
            ),
            '{}'::types.q_list_providers_v4_provider[]
        ) as providers
    FROM provider_data pd
),
provider_options_agg AS (
    SELECT 
        COALESCE(
            ARRAY_AGG(
                (p.value, p.name)::types.q_list_providers_v4_provider_option
                ORDER BY p.name
            ) FILTER (WHERE p.active = true),
            '{}'::types.q_list_providers_v4_provider_option[]
        ) as provider_options
    FROM providers p
    WHERE p.active = true
)
SELECT 
    pa.actor_name,
    pa.providers,
    poa.provider_options,
    ARRAY[
        ('true', 'Active')::types.q_list_providers_v4_status_option,
        ('false', 'Inactive')::types.q_list_providers_v4_status_option
    ]::types.q_list_providers_v4_status_option[] as status_options
FROM providers_agg pa
CROSS JOIN provider_options_agg poa
$$;


--
-- Name: api_list_scenarios_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_list_scenarios_v4(profile_id uuid) RETURNS TABLE(actor_name text, scenarios types.q_list_scenarios_v4_scenario[], objectives types.q_list_scenarios_v4_objective[], fields types.q_list_scenarios_v4_field[], cohorts types.q_list_scenarios_v4_cohort[], personas types.q_list_scenarios_v4_persona[], simulations types.q_list_scenarios_v4_simulation[], departments types.q_list_scenarios_v4_department[], persona_options types.q_list_scenarios_v4_option[], simulation_options types.q_list_scenarios_v4_option[], department_options types.q_list_scenarios_v4_option[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id
),
user_departments AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments ON profile_departments.profile_id = x.profile_id AND profile_departments.active = true
),
scenario_objectives AS (
    SELECT 
        so.scenario_id,
        ARRAY_AGG(o.id::text ORDER BY so.idx) as objective_ids
    FROM scenario_objectives so
    JOIN objectives o ON o.id = so.objective_id
    GROUP BY so.scenario_id
),
scenario_parameters AS (
    SELECT 
        sf.scenario_id,
        ARRAY_AGG(DISTINCT sf.field_id::text) as parameter_item_ids
    FROM scenario_fields sf
    WHERE sf.active = true
    GROUP BY sf.scenario_id
),
scenario_simulations AS (
    SELECT 
        ss.scenario_id,
        ARRAY_AGG(DISTINCT ss.simulation_id::text) as simulation_ids,
        COUNT(DISTINCT ss.simulation_id) as num_simulations
    FROM simulation_scenarios ss
    WHERE ss.active = true
    GROUP BY ss.scenario_id
),
scenario_all_simulation_links AS (
    SELECT 
        ss.scenario_id,
        COUNT(*) as total_links
    FROM simulation_scenarios ss
    GROUP BY ss.scenario_id
),
scenario_cohorts AS (
    SELECT DISTINCT
        ss.scenario_id,
        ARRAY_AGG(DISTINCT cs.cohort_id::text) as cohort_ids
    FROM simulation_scenarios ss
    JOIN cohort_simulations cs ON cs.simulation_id = ss.simulation_id
    WHERE ss.active = true AND cs.active = true
    GROUP BY ss.scenario_id
),
scenario_personas_agg AS (
    SELECT 
        sp.scenario_id,
        ARRAY_AGG(sp.persona_id::text ORDER BY sp.persona_id) as persona_ids
    FROM scenario_personas sp
    WHERE sp.active = true
    GROUP BY sp.scenario_id
),
user_profile AS (
    SELECT 
        role,
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
scenario_departments_data AS (
    SELECT 
        sd.scenario_id,
        ARRAY_AGG(sd.department_id::text ORDER BY sd.created_at) as department_ids
    FROM scenario_departments sd
    WHERE sd.active = true
    GROUP BY sd.scenario_id
),
scenario_attributes AS (
    SELECT DISTINCT ON (ss.scenario_id)
        ss.scenario_id,
        ss.hints_enabled,
        s.objectives_enabled,
        s.images_enabled as image_input_enabled
    FROM simulation_scenarios ss
    JOIN scenarios s ON s.id = ss.scenario_id
    WHERE ss.active = true
    ORDER BY ss.scenario_id, ss.position
),
scenario_data AS (
    SELECT 
        s.id as scenario_id,
        s.name as title,
        s.description,
        COALESCE(ps.problem_statement, '') as problem_statement,
        s.active,
        s.generated,
        s.updated_at,
        st.parent_id as parent_scenario_id,
        COALESCE(so.objective_ids, ARRAY[]::text[]) as objective_ids,
        COALESCE(spa.persona_ids, ARRAY[]::text[]) as persona_ids,
        COALESCE(spar.parameter_item_ids, ARRAY[]::text[]) as parameter_item_ids,
        COALESCE(ss.simulation_ids, ARRAY[]::text[]) as simulation_ids,
        COALESCE(ss.num_simulations, 0) as num_simulations,
        COALESCE(sc.cohort_ids, ARRAY[]::text[]) as cohort_ids,
        COALESCE(sdd.department_ids, NULL) as department_ids,
        COALESCE(sa.hints_enabled, false) as hints_enabled,
        COALESCE(sa.objectives_enabled, true) as objectives_enabled,
        COALESCE(sa.image_input_enabled, false) as image_input_enabled,
        CASE WHEN COUNT(sd.scenario_id) > 0 THEN true ELSE false END as has_dept_links,
        CASE 
            WHEN COALESCE(sdd.department_ids, NULL) IS NULL AND up.role != 'superadmin' THEN false
            WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) 
                 AND COALESCE(ss.num_simulations, 0) = 0 
            THEN true
            ELSE false
        END as can_edit,
        CASE 
            -- Can't delete if can't edit (stricter than can_edit)
            WHEN COALESCE(sdd.department_ids, NULL) IS NULL AND up.role != 'superadmin' THEN false
            WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) 
                 AND COALESCE(sal.total_links, 0) = 0 
            THEN true
            ELSE false
        END as can_delete,
        true as can_duplicate
    FROM scenarios s
    -- Only include root scenarios (parent_id = child_id in scenario_tree)
    JOIN scenario_tree root_check ON root_check.parent_id = s.id AND root_check.child_id = s.id
    LEFT JOIN scenario_departments sd ON sd.scenario_id = s.id AND sd.active = true
    LEFT JOIN scenario_departments_data sdd ON sdd.scenario_id = s.id
    LEFT JOIN scenario_tree st ON st.child_id = s.id AND st.parent_id != st.child_id
    LEFT JOIN scenario_problem_statements sps_j ON sps_j.scenario_id = s.id AND sps_j.active = true
    LEFT JOIN problem_statements ps ON ps.id = sps_j.problem_statement_id
    LEFT JOIN scenario_objectives so ON so.scenario_id = s.id
    LEFT JOIN scenario_parameters spar ON spar.scenario_id = s.id
    LEFT JOIN scenario_simulations ss ON ss.scenario_id = s.id
    LEFT JOIN scenario_all_simulation_links sal ON sal.scenario_id = s.id
    LEFT JOIN scenario_cohorts sc ON sc.scenario_id = s.id
    LEFT JOIN scenario_personas_agg spa ON spa.scenario_id = s.id
    LEFT JOIN scenario_attributes sa ON sa.scenario_id = s.id
    CROSS JOIN user_profile up
    GROUP BY s.id, s.name, s.description, ps.problem_statement, s.active, s.generated, s.updated_at, st.parent_id, 
             so.objective_ids, spa.persona_ids, spar.parameter_item_ids, ss.simulation_ids, ss.num_simulations, 
             sc.cohort_ids, sdd.department_ids, sal.total_links, up.role,
             sa.hints_enabled, sa.objectives_enabled, sa.image_input_enabled
    HAVING 
        -- Include if has matching department link OR has no department links at all (cross-dept)
        COUNT(sd.scenario_id) FILTER (WHERE sd.department_id IN (SELECT department_id FROM user_departments)) > 0
        OR NOT EXISTS (SELECT 1 FROM scenario_departments sd2 WHERE sd2.scenario_id = s.id AND sd2.active = true)
),
all_parameter_item_ids AS (
    SELECT DISTINCT unnest(parameter_item_ids) as parameter_item_id
    FROM scenario_data
),
all_cohort_ids AS (
    SELECT DISTINCT unnest(cohort_ids) as cohort_id
    FROM scenario_data
    WHERE cohort_ids IS NOT NULL
),
all_persona_ids AS (
    SELECT DISTINCT unnest(persona_ids)::uuid as persona_id
    FROM scenario_data
    WHERE persona_ids IS NOT NULL
),
all_simulation_ids AS (
    SELECT DISTINCT unnest(simulation_ids) as simulation_id
    FROM scenario_data
),
all_department_ids AS (
    SELECT DISTINCT unnest(department_ids) as department_id
    FROM scenario_data
    WHERE department_ids IS NOT NULL
)
SELECT 
    up.actor_name::text as actor_name,
    COALESCE(
        ARRAY_AGG(
            (sd.scenario_id, sd.title, sd.problem_statement, sd.active, sd.generated, 
             sd.parent_scenario_id, sd.department_ids, sd.objective_ids, sd.persona_ids, 
             sd.parameter_item_ids, sd.simulation_ids, sd.num_simulations, sd.can_edit, 
             sd.can_delete, sd.can_duplicate, sd.cohort_ids, sd.updated_at)::types.q_list_scenarios_v4_scenario
            ORDER BY sd.updated_at DESC NULLS LAST
        ),
        '{}'::types.q_list_scenarios_v4_scenario[]
    ) as scenarios,
    COALESCE(
        (SELECT ARRAY_AGG((o.id::text, o.objective, COALESCE(o.objective, ''))::types.q_list_scenarios_v4_objective)
         FROM objectives o
         WHERE o.id::text IN (SELECT DISTINCT unnest(sd.objective_ids) FROM scenario_data sd)),
        '{}'::types.q_list_scenarios_v4_objective[]
    ) as objectives,
    COALESCE(
        (SELECT ARRAY_AGG((f.id::text, f.name, COALESCE(f.description, ''), fp.parameter_id::text, p.name)::types.q_list_scenarios_v4_field)
         FROM fields f
         JOIN parameter_fields fp ON fp.field_id = f.id AND fp.active = true
         JOIN parameters p ON p.id = fp.parameter_id
         WHERE f.id::text IN (SELECT parameter_item_id FROM all_parameter_item_ids)),
        '{}'::types.q_list_scenarios_v4_field[]
    ) as fields,
    COALESCE(
        (SELECT ARRAY_AGG((c.id::text, c.title, COALESCE(c.description, ''))::types.q_list_scenarios_v4_cohort)
         FROM cohorts c
         WHERE c.id::text IN (SELECT cohort_id FROM all_cohort_ids)),
        '{}'::types.q_list_scenarios_v4_cohort[]
    ) as cohorts,
    COALESCE(
        (SELECT ARRAY_AGG((p.id::text, p.name, COALESCE(p.description, ''), p.color, p.icon, false)::types.q_list_scenarios_v4_persona)
         FROM personas p
         WHERE p.id IN (SELECT persona_id FROM all_persona_ids)),
        '{}'::types.q_list_scenarios_v4_persona[]
    ) as personas,
    COALESCE(
        (SELECT ARRAY_AGG(
            (s.id::text, s.title, COALESCE(s.description, ''), 
             COALESCE(
                 (SELECT SUM(stl.time_limit_seconds)
                  FROM scenario_time_limits stl
                  JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
                  WHERE stl.simulation_id = s.id AND stl.active = true AND ss.active = true),
                 0
             ),
             (SELECT ARRAY_AGG(sd.department_id::text ORDER BY sd.created_at)
              FROM simulation_departments sd
              WHERE sd.simulation_id = s.id AND sd.active = true)
            )::types.q_list_scenarios_v4_simulation
         )
         FROM all_simulation_ids asi
         LEFT JOIN simulations s ON s.id::text = asi.simulation_id),
        '{}'::types.q_list_scenarios_v4_simulation[]
    ) as simulations,
    COALESCE(
        (SELECT ARRAY_AGG((d.id::text, d.title, COALESCE(d.description, ''))::types.q_list_scenarios_v4_department)
         FROM departments d
         WHERE d.id::text IN (SELECT department_id FROM all_department_ids)
           AND d.id IN (SELECT department_id FROM user_departments)),
        '{}'::types.q_list_scenarios_v4_department[]
    ) as departments,
    -- Options arrays for UI (composite types)
    COALESCE(
        (SELECT ARRAY_AGG((p.id::text, p.name)::types.q_list_scenarios_v4_option ORDER BY p.name)
         FROM personas p
         WHERE p.id IN (SELECT persona_id FROM all_persona_ids)),
        '{}'::types.q_list_scenarios_v4_option[]
    ) as persona_options,
    COALESCE(
        (SELECT ARRAY_AGG((s.id::text, s.title)::types.q_list_scenarios_v4_option ORDER BY s.title)
         FROM all_simulation_ids asi
         LEFT JOIN simulations s ON s.id::text = asi.simulation_id),
        '{}'::types.q_list_scenarios_v4_option[]
    ) as simulation_options,
    COALESCE(
        (SELECT ARRAY_AGG((d.id::text, d.title)::types.q_list_scenarios_v4_option ORDER BY d.title)
         FROM departments d
         WHERE d.id::text IN (SELECT department_id FROM all_department_ids)
           AND d.id IN (SELECT department_id FROM user_departments)
           AND d.id::text IN (SELECT DISTINCT unnest(department_ids) FROM scenario_data WHERE department_ids IS NOT NULL)),
        '{}'::types.q_list_scenarios_v4_option[]
    ) as department_options
FROM scenario_data sd
CROSS JOIN user_profile up
GROUP BY up.actor_name
$$;


--
-- Name: api_list_simulations_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_list_simulations_v4(profile_id uuid) RETURNS TABLE(actor_name text, simulations types.q_list_simulations_v4_simulation[], scenarios types.q_list_simulations_v4_scenario[], rubrics types.q_list_simulations_v4_rubric[], departments types.q_list_simulations_v4_department[], cohorts types.q_list_simulations_v4_cohort[], rubric_options types.q_list_simulations_v4_option[], cohort_options types.q_list_simulations_v4_option[], department_options types.q_list_simulations_v4_option[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id
),
user_departments AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments ON profile_departments.profile_id = x.profile_id AND profile_departments.active = true
),
user_profile AS (
    SELECT 
        role,
        first_name || ' ' || last_name as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
simulation_scenarios_data AS (
    SELECT 
        ss.simulation_id,
        ARRAY_AGG(ss.scenario_id ORDER BY sc.name) as scenario_ids,
        COUNT(ss.scenario_id) as num_scenarios
    FROM simulation_scenarios ss
    JOIN scenarios sc ON sc.id = ss.scenario_id
    WHERE ss.active = true
    GROUP BY ss.simulation_id
),
simulation_attempts AS (
    SELECT 
        sa.simulation_id,
        COUNT(*) as attempt_count
    FROM simulation_attempts sa
    GROUP BY sa.simulation_id
),
simulation_active_cohort_links AS (
    SELECT 
        cs.simulation_id,
        COUNT(*) as active_cohort_count
    FROM cohort_simulations cs
    WHERE cs.active = true
    GROUP BY cs.simulation_id
),
simulation_all_cohort_links AS (
    SELECT 
        cs.simulation_id,
        COUNT(*) as total_cohort_links,
        COUNT(DISTINCT cs.cohort_id) as num_cohorts
    FROM cohort_simulations cs
    GROUP BY cs.simulation_id
),
simulation_cohorts_data AS (
    SELECT 
        cs.simulation_id,
        ARRAY_AGG(cs.cohort_id::text ORDER BY c.title) as cohort_ids
    FROM cohort_simulations cs
    JOIN cohorts c ON c.id = cs.cohort_id
    WHERE cs.active = true
    GROUP BY cs.simulation_id
),
simulation_departments_data AS (
    SELECT 
        sd.simulation_id,
        ARRAY_AGG(sd.department_id::text ORDER BY sd.created_at) as department_ids
    FROM simulation_departments sd
    WHERE sd.active = true
    GROUP BY sd.simulation_id
),
simulation_data AS (
    SELECT 
        s.id as simulation_id,
        s.title as name,
        s.description,
        COALESCE(
            (SELECT SUM(stl.time_limit_seconds)
             FROM scenario_time_limits stl
             JOIN simulation_scenarios ss ON ss.simulation_id = stl.simulation_id AND ss.scenario_id = stl.scenario_id
             WHERE stl.simulation_id = s.id AND stl.active = true AND ss.active = true),
            0
        ) as time_limit,
        s.active,
        s.practice_simulation,
        (SELECT rga.rubric_id FROM simulation_scenarios ss_rubric 
         JOIN simulation_scenarios_rubric_grade_agents ssrga ON ssrga.simulation_id = ss_rubric.simulation_id AND ssrga.scenario_id = ss_rubric.scenario_id
         JOIN rubric_grade_agents rga ON rga.id = ssrga.rubric_grade_agent_id
         WHERE ss_rubric.simulation_id = s.id AND ss_rubric.active = true 
         ORDER BY ss_rubric.position 
         LIMIT 1) as rubric_id,
        s.updated_at,
        COALESCE(sdd.department_ids, NULL) as department_ids,
        COALESCE(ssd.scenario_ids, ARRAY[]::uuid[]) as scenario_ids,
        COALESCE(ssd.num_scenarios, 0) as num_scenarios,
        COALESCE(sa.attempt_count, 0) as attempt_count,
        COALESCE(sacl.active_cohort_count, 0) as active_cohort_count,
        COALESCE(salcl.total_cohort_links, 0) as total_cohort_links,
        COALESCE(salcl.num_cohorts, 0) as num_cohorts,
        COALESCE(scd.cohort_ids, ARRAY[]::text[]) as cohort_ids
    FROM simulations s
    LEFT JOIN simulation_departments sd ON sd.simulation_id = s.id AND sd.active = true
    LEFT JOIN simulation_departments_data sdd ON sdd.simulation_id = s.id
    LEFT JOIN simulation_scenarios_data ssd ON ssd.simulation_id = s.id
    LEFT JOIN simulation_attempts sa ON sa.simulation_id = s.id
    LEFT JOIN simulation_active_cohort_links sacl ON sacl.simulation_id = s.id
    LEFT JOIN simulation_all_cohort_links salcl ON salcl.simulation_id = s.id
    LEFT JOIN simulation_cohorts_data scd ON scd.simulation_id = s.id
    GROUP BY s.id, s.title, s.description, s.active, s.practice_simulation, 
             s.updated_at, sdd.department_ids, ssd.scenario_ids, ssd.num_scenarios, sa.attempt_count, 
             sacl.active_cohort_count, salcl.total_cohort_links, salcl.num_cohorts, scd.cohort_ids
    HAVING 
        -- Include if has matching department link OR has no department links at all (cross-dept)
        COUNT(sd.simulation_id) FILTER (WHERE sd.department_id IN (SELECT department_id FROM user_departments)) > 0
        OR NOT EXISTS (SELECT 1 FROM simulation_departments sd2 WHERE sd2.simulation_id = s.id AND sd2.active = true)
),
all_scenario_ids AS (
    SELECT DISTINCT unnest(scenario_ids) as scenario_id
    FROM simulation_data
),
scenario_personas_agg AS (
    SELECT 
        sp.scenario_id,
        ARRAY_AGG(sp.persona_id::text ORDER BY sp.persona_id) as persona_ids
    FROM scenario_personas sp
    WHERE sp.scenario_id IN (SELECT scenario_id FROM all_scenario_ids)
      AND sp.active = true
    GROUP BY sp.scenario_id
),
all_persona_ids AS (
    SELECT DISTINCT unnest(persona_ids)::uuid as persona_id
    FROM scenario_personas_agg
    WHERE persona_ids IS NOT NULL
),
image_model_check AS (
    SELECT 
        model_id,
        CASE WHEN COUNT(*) > 0 THEN true ELSE false END as image_model
    FROM model_modalities
    WHERE modality = 'image' AND is_input = false AND active = true
    GROUP BY model_id
),
persona_data AS (
    SELECT 
        p.id as persona_id,
        p.name,
        COALESCE(p.description, '') as description,
        p.color,
        p.icon,
        false as image_model
    FROM all_persona_ids api
    JOIN personas p ON p.id = api.persona_id
),
scenario_base_data AS (
    SELECT 
        s.id as scenario_id,
        s.name,
        COALESCE(ps.problem_statement, '') as description,
        s.active,
        COALESCE(spa.persona_ids, ARRAY[]::text[]) as persona_ids,
        ARRAY[]::text[] as parameter_item_ids,
        ARRAY[]::text[] as document_ids
    FROM all_scenario_ids asi
    JOIN scenarios s ON s.id = asi.scenario_id
    LEFT JOIN scenario_problem_statements sps ON sps.scenario_id = s.id AND sps.active = true
    LEFT JOIN problem_statements ps ON ps.id = sps.problem_statement_id
    LEFT JOIN scenario_personas_agg spa ON spa.scenario_id = s.id
    LEFT JOIN scenario_tree st ON st.parent_id = s.id AND st.child_id = s.id
    WHERE st.parent_id IS NOT NULL
),
scenario_persona_mapping AS (
    SELECT 
        sp.scenario_id,
        ARRAY_AGG(
            (pd.persona_id, pd.name, pd.description, pd.color, pd.icon, pd.image_model)::types.q_list_simulations_v4_persona
            ORDER BY pd.name
        ) as personas
    FROM scenario_base_data sbd
    JOIN scenario_personas sp ON sp.scenario_id = sbd.scenario_id AND sp.active = true
    JOIN persona_data pd ON pd.persona_id = sp.persona_id
    GROUP BY sp.scenario_id
),
all_rubric_ids AS (
    SELECT DISTINCT rubric_id
    FROM simulation_data
    WHERE rubric_id IS NOT NULL
),
rubric_data AS (
    SELECT 
        r.id as rubric_id,
        r.name,
        COALESCE(r.description, '') as description
    FROM all_rubric_ids ari
    JOIN rubrics r ON r.id = ari.rubric_id
),
all_cohort_ids AS (
    SELECT DISTINCT unnest(cohort_ids) as cohort_id
    FROM simulation_cohorts_data
    WHERE cohort_ids IS NOT NULL
),
cohort_data AS (
    SELECT 
        c.id as cohort_id,
        c.title as name,
        COALESCE(c.description, '') as description
    FROM all_cohort_ids aci
    JOIN cohorts c ON c.id = aci.cohort_id::uuid
),
department_data AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM departments d
    WHERE d.id IN (SELECT department_id FROM user_departments)
)
SELECT 
    up.actor_name::text as actor_name,
    -- Aggregate simulations
    COALESCE(
        (SELECT ARRAY_AGG(
            (simd.simulation_id, simd.name, simd.description, simd.department_ids, simd.time_limit,
             simd.active, simd.practice_simulation,
             CASE 
                 WHEN COALESCE(simd.department_ids, NULL) IS NULL AND up.role != 'superadmin' THEN false
                 WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) THEN true
                 ELSE false
             END,
             CASE 
                 WHEN COALESCE(simd.department_ids, NULL) IS NULL AND up.role != 'superadmin' THEN false
                 WHEN simd.practice_simulation = true THEN false
                 WHEN simd.total_cohort_links > 0 THEN false
                 WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) THEN true
                 ELSE false
             END,
             CASE 
                 WHEN up.role IN ('admin'::profile_role, 'instructional'::profile_role, 'superadmin'::profile_role) THEN true
                 ELSE false
             END,
             simd.scenario_ids, simd.rubric_id, simd.num_cohorts, simd.cohort_ids, simd.updated_at
            )::types.q_list_simulations_v4_simulation
            ORDER BY simd.updated_at DESC NULLS LAST
        ) FROM simulation_data simd),
        '{}'::types.q_list_simulations_v4_simulation[]
    ) as simulations,
    -- Aggregate scenarios
    COALESCE(
        (SELECT ARRAY_AGG(
            (sbd.scenario_id, sbd.name, sbd.description, sbd.active, sbd.persona_ids,
             COALESCE(spm.personas, ARRAY[]::types.q_list_simulations_v4_persona[]),
             ARRAY[]::types.q_list_simulations_v4_document[],
             ARRAY[]::types.q_list_simulations_v4_field[],
             sbd.parameter_item_ids,
             sbd.document_ids
            )::types.q_list_simulations_v4_scenario
            ORDER BY sbd.name
        ) FROM scenario_base_data sbd
        LEFT JOIN scenario_persona_mapping spm ON spm.scenario_id = sbd.scenario_id),
        '{}'::types.q_list_simulations_v4_scenario[]
    ) as scenarios,
    -- Aggregate rubrics
    COALESCE(
        (SELECT ARRAY_AGG(
            (rd.rubric_id, rd.name, rd.description)::types.q_list_simulations_v4_rubric
            ORDER BY rd.name
        ) FROM rubric_data rd),
        '{}'::types.q_list_simulations_v4_rubric[]
    ) as rubrics,
    -- Aggregate departments
    COALESCE(
        (SELECT ARRAY_AGG(
            (dd.department_id, dd.name, dd.description)::types.q_list_simulations_v4_department
            ORDER BY dd.name
        ) FROM department_data dd),
        '{}'::types.q_list_simulations_v4_department[]
    ) as departments,
    -- Aggregate cohorts
    COALESCE(
        (SELECT ARRAY_AGG(
            (cd.cohort_id, cd.name, cd.description)::types.q_list_simulations_v4_cohort
            ORDER BY cd.name
        ) FROM cohort_data cd),
        '{}'::types.q_list_simulations_v4_cohort[]
    ) as cohorts,
    -- Rubric options
    COALESCE(
        (SELECT ARRAY_AGG(
            (rd.rubric_id::text, rd.name)::types.q_list_simulations_v4_option
            ORDER BY rd.name
        ) FROM rubric_data rd),
        '{}'::types.q_list_simulations_v4_option[]
    ) as rubric_options,
    -- Cohort options
    COALESCE(
        (SELECT ARRAY_AGG(
            (cd.cohort_id::text, cd.name)::types.q_list_simulations_v4_option
            ORDER BY cd.name
        ) FROM cohort_data cd),
        '{}'::types.q_list_simulations_v4_option[]
    ) as cohort_options,
    -- Department options
    COALESCE(
        (SELECT ARRAY_AGG(
            (dd.department_id::text, dd.name)::types.q_list_simulations_v4_option
            ORDER BY dd.name
        ) FROM department_data dd),
        '{}'::types.q_list_simulations_v4_option[]
    ) as department_options
FROM user_profile up
$$;


--
-- Name: api_list_staff_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_list_staff_v4(profile_id uuid) RETURNS TABLE(actor_name text, current_user_role text, staff types.q_list_staff_v4_staff[], cohorts types.q_list_staff_v4_cohort[], departments types.q_list_staff_v4_department[], trend_data_active types.q_list_staff_v4_trend_data[], trend_data_admin types.q_list_staff_v4_trend_data[], trend_data_instructional types.q_list_staff_v4_trend_data[], trend_data_member types.q_list_staff_v4_trend_data[], trend_data_total_requests types.q_list_staff_v4_trend_data[], valid_department_ids text[], role_options text[], cohort_options text[], last_active_options text[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT profile_id AS profile_id
),
user_departments AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments ON profile_departments.profile_id = x.profile_id AND profile_departments.active = true
),
profile_active_cohort_links AS (
    SELECT 
        profile_id,
        COUNT(*) as active_cohort_count
    FROM cohort_profiles
    WHERE active = true
    GROUP BY profile_id
),
profile_all_cohort_links AS (
    SELECT 
        profile_id,
        COUNT(*) as total_cohort_links
    FROM cohort_profiles
    GROUP BY profile_id
),
profile_cohorts AS (
    SELECT 
        cp.profile_id,
        ARRAY_AGG(cp.cohort_id::text ORDER BY c.title) as cohort_ids
    FROM cohort_profiles cp
    JOIN cohorts c ON c.id = cp.cohort_id
    WHERE cp.active = true
    GROUP BY cp.profile_id
),
profile_departments_agg AS (
    SELECT 
        pd.profile_id,
        ARRAY_AGG(pd.department_id::text ORDER BY d.title) as department_ids
    FROM profile_departments pd
    JOIN departments d ON d.id = pd.department_id
    WHERE pd.active = true
    GROUP BY pd.profile_id
),
profile_primary_department AS (
    SELECT 
        pd.profile_id,
        pd.department_id::text as department_id
    FROM profile_departments pd
    WHERE pd.active = true AND pd.is_primary = true
),
valid_department_ids_data AS (
    SELECT array_agg(d.id::text ORDER BY d.title) as valid_department_ids
    FROM departments d
    WHERE d.active = true
),
recent_runs AS (
    SELECT 
        mrp.profile_id,
        COUNT(*) as run_count
    FROM runs mr
    JOIN run_profiles mrp ON mrp.run_id = mr.id
    WHERE mr.created_at >= NOW() - INTERVAL '24 hours'
    GROUP BY mrp.profile_id
),
profile_total_runs AS (
    SELECT 
        mrp.profile_id,
        COUNT(*) as total_requests
    FROM run_profiles mrp
    GROUP BY mrp.profile_id
),
user_profile AS (
    SELECT 
        role,
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
all_cohort_ids AS (
    SELECT DISTINCT unnest(cohort_ids)::uuid as cohort_id
    FROM profile_cohorts
),
all_department_ids AS (
    SELECT DISTINCT unnest(department_ids)::uuid as department_id
    FROM profile_departments_agg
),
cohorts_data AS (
    SELECT 
        c.id as cohort_id,
        c.title as name,
        COALESCE(c.description, '') as description
    FROM cohorts c
    WHERE c.id IN (SELECT cohort_id FROM all_cohort_ids)
),
departments_data AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM departments d
    WHERE (d.id IN (SELECT department_id FROM user_departments) OR d.id IN (SELECT department_id FROM all_department_ids))
    AND d.active = true
),
-- Trend data CTEs
active_users_count AS (
    SELECT COUNT(DISTINCT p.id) as count
    FROM profiles p
    JOIN profile_departments pd ON pd.profile_id = p.id AND pd.active = true
    WHERE pd.department_id IN (SELECT department_id FROM user_departments)
    AND p.active = true
),
admin_users_by_date AS (
    SELECT 
        DATE(p.created_at) as date,
        COUNT(DISTINCT p.id) as count
    FROM profiles p
    JOIN profile_departments pd ON pd.profile_id = p.id AND pd.active = true
    WHERE pd.department_id IN (SELECT department_id FROM user_departments)
    AND p.role IN ('admin'::profile_role, 'superadmin'::profile_role)
    GROUP BY DATE(p.created_at)
),
admin_users_cumulative AS (
    SELECT 
        date,
        SUM(count) OVER (ORDER BY date) as cumulative_count,
        count as daily_count
    FROM admin_users_by_date
),
instructional_users_by_date AS (
    SELECT 
        DATE(p.created_at) as date,
        COUNT(DISTINCT p.id) as count
    FROM profiles p
    JOIN profile_departments pd ON pd.profile_id = p.id AND pd.active = true
    WHERE pd.department_id IN (SELECT department_id FROM user_departments)
    AND p.role = 'instructional'::profile_role
    GROUP BY DATE(p.created_at)
),
instructional_users_cumulative AS (
    SELECT 
        date,
        SUM(count) OVER (ORDER BY date) as cumulative_count,
        count as daily_count
    FROM instructional_users_by_date
),
member_users_by_date AS (
    SELECT 
        DATE(p.created_at) as date,
        COUNT(DISTINCT p.id) as count
    FROM profiles p
    JOIN profile_departments pd ON pd.profile_id = p.id AND pd.active = true
    WHERE pd.department_id IN (SELECT department_id FROM user_departments)
    AND p.role = 'member'::profile_role
    GROUP BY DATE(p.created_at)
),
member_users_cumulative AS (
    SELECT 
        date,
        SUM(count) OVER (ORDER BY date) as cumulative_count,
        count as daily_count
    FROM member_users_by_date
),
total_requests_by_date AS (
    SELECT 
        DATE(mr.created_at) as date,
        COUNT(*) as count
    FROM runs mr
    JOIN run_profiles mrp ON mrp.run_id = mr.id
    JOIN profile_departments pd ON pd.profile_id = mrp.profile_id AND pd.active = true
    WHERE pd.department_id IN (SELECT department_id FROM user_departments)
    GROUP BY DATE(mr.created_at)
),
total_requests_cumulative AS (
    SELECT 
        date,
        SUM(count) OVER (ORDER BY date) as cumulative_count,
        count as daily_count
    FROM total_requests_by_date
),
earliest_date AS (
    SELECT MIN(DATE(p.created_at)) as date
    FROM profiles p
    JOIN profile_departments pd ON pd.profile_id = p.id AND pd.active = true
    WHERE pd.department_id IN (SELECT department_id FROM user_departments)
),
staff_rows AS (
    SELECT DISTINCT ON (p.id)
        p.id as profile_id,
        p.first_name,
        p.last_name,
        COALESCE(
            ARRAY(
                SELECT email FROM (
                    SELECT DISTINCT ON (pe2.email) 
                        pe2.email,
                        pe2.is_primary,
                        pe2.created_at
                    FROM profile_emails pe2 
                    WHERE pe2.profile_id = p.id AND pe2.active = true 
                    ORDER BY pe2.email, pe2.is_primary DESC, pe2.created_at
                ) distinct_emails
                ORDER BY is_primary DESC, created_at
            ),
            ARRAY[]::text[]
        ) as emails,
        (SELECT email FROM profile_emails WHERE profile_id = p.id AND is_primary = true AND active = true LIMIT 1) as primary_email,
        p.first_name || ' ' || p.last_name as name,
        p.role,
        SUBSTRING(p.first_name FROM 1 FOR 1) || SUBSTRING(p.last_name FROM 1 FOR 1) as initials,
        p.active,
        pa.last_active,
        prl.requests_per_day,
        COALESCE(rr.run_count::int, 0) as requests_in_last_day,
        COALESCE(pc.cohort_ids, ARRAY[]::text[]) as cohort_ids,
        COALESCE(
            ARRAY(SELECT unnest(pda.department_ids)::text),
            ARRAY[]::text[]
        ) as department_ids,
        COALESCE(ppd.department_id, '') as primary_department_id,
        COALESCE(ptr.total_requests, 0) as total_requests,
        COALESCE(pacl.active_cohort_count, 0) as active_cohort_count,
        COALESCE(pacl_all.total_cohort_links, 0) as total_cohort_links,
        up.role as current_user_role_for_permissions
    FROM profiles p
    LEFT JOIN profile_departments pd ON pd.profile_id = p.id AND pd.active = true
    LEFT JOIN profile_emails pe ON pe.profile_id = p.id AND pe.active = true
    LEFT JOIN profile_cohorts pc ON pc.profile_id = p.id
    LEFT JOIN profile_departments_agg pda ON pda.profile_id = p.id
    LEFT JOIN profile_primary_department ppd ON ppd.profile_id = p.id
    LEFT JOIN profile_total_runs ptr ON ptr.profile_id = p.id
    LEFT JOIN profile_active_cohort_links pacl ON pacl.profile_id = p.id
    LEFT JOIN profile_all_cohort_links pacl_all ON pacl_all.profile_id = p.id
    LEFT JOIN recent_runs rr ON rr.profile_id = p.id
    LEFT JOIN profile_request_limits prl ON prl.profile_id = p.id AND prl.active = true
    LEFT JOIN LATERAL (
        SELECT last_active 
        FROM profile_activity 
        WHERE profile_id = p.id 
        ORDER BY created_at DESC 
        LIMIT 1
    ) pa ON true
    CROSS JOIN user_profile up
    WHERE (
        -- Superadmins see all profiles (bypass department filter)
        up.role = 'superadmin'::profile_role 
        -- Non-superadmins only see profiles that share departments with them
        OR pd.department_id IN (SELECT department_id FROM user_departments)
    )
    AND (
        up.role = 'superadmin'::profile_role OR
        (up.role = 'admin'::profile_role AND p.role IN ('admin'::profile_role, 'instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role)) OR
        (up.role = 'instructional'::profile_role AND p.role IN ('instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role)) OR
        (up.role = 'member'::profile_role AND p.role IN ('member'::profile_role, 'guest'::profile_role)) OR
        (up.role = 'guest' AND p.role = 'guest')
    )
    GROUP BY p.id, p.first_name, p.last_name, p.role, p.active, 
             pa.last_active, prl.requests_per_day,
             pc.cohort_ids, pda.department_ids, ppd.department_id, ptr.total_requests,
             pacl.active_cohort_count, pacl_all.total_cohort_links, rr.run_count, up.role
    ORDER BY p.id, p.last_name, p.first_name
)
SELECT 
    up.actor_name::text as actor_name,
    up.role::text as current_user_role,
    COALESCE(
        (SELECT ARRAY_AGG(
            (sr.profile_id, sr.first_name, sr.last_name, sr.emails, sr.primary_email, sr.name, sr.role, sr.initials, sr.active, sr.last_active, sr.cohort_ids, sr.department_ids, sr.primary_department_id, sr.requests_per_day, sr.total_requests, sr.requests_in_last_day,
             CASE 
                 -- Always allow editing self
                 WHEN sr.profile_id = (SELECT profile_id FROM params) THEN true
                 -- Superadmin has no restrictions
                 WHEN sr.current_user_role_for_permissions = 'superadmin' THEN true
                 -- Role hierarchy: can only edit roles lower than current role
                 WHEN sr.current_user_role_for_permissions = 'admin' AND sr.role IN ('instructional', 'member', 'guest') THEN true
                 WHEN sr.current_user_role_for_permissions = 'instructional' AND sr.role IN ('member', 'guest') THEN true
                 WHEN sr.current_user_role_for_permissions = 'member' AND sr.role = 'guest' THEN true
                 ELSE false
             END,
             CASE 
                 -- Cannot delete ourselves
                 WHEN sr.profile_id = (SELECT profile_id FROM params) THEN false
                 -- Superadmin has no restrictions (except self)
                 WHEN sr.current_user_role_for_permissions = 'superadmin' THEN true
                 -- Cannot delete profiles with cohort links (prevent orphaned data)
                 WHEN sr.total_cohort_links > 0 THEN false
                 -- Role hierarchy: can only delete roles lower than current role
                 WHEN sr.current_user_role_for_permissions = 'admin' AND sr.role IN ('instructional', 'member', 'guest') THEN true
                 WHEN sr.current_user_role_for_permissions = 'instructional' AND sr.role IN ('member', 'guest') THEN true
                 WHEN sr.current_user_role_for_permissions = 'member' AND sr.role = 'guest' THEN true
                 ELSE false
             END
            )::types.q_list_staff_v4_staff
            ORDER BY sr.last_name, sr.first_name
        )
        FROM staff_rows sr),
        '{}'::types.q_list_staff_v4_staff[]
    ) as staff,
    COALESCE(
        (SELECT ARRAY_AGG(
            (cd.cohort_id, cd.name, cd.description)::types.q_list_staff_v4_cohort
            ORDER BY cd.name
        )
        FROM cohorts_data cd),
        '{}'::types.q_list_staff_v4_cohort[]
    ) as cohorts,
    COALESCE(
        (SELECT ARRAY_AGG(
            (dd.department_id, dd.name, dd.description)::types.q_list_staff_v4_department
            ORDER BY dd.name
        )
        FROM departments_data dd),
        '{}'::types.q_list_staff_v4_department[]
    ) as departments,
    COALESCE(
        (SELECT ARRAY_AGG(
            (active_trend.date, active_trend.count::double precision, 0)::types.q_list_staff_v4_trend_data
            ORDER BY active_trend.date
        )
        FROM (
            SELECT 
                COALESCE((SELECT date FROM earliest_date), CURRENT_DATE) as date,
                (SELECT count FROM active_users_count) as count
            UNION ALL
            SELECT CURRENT_DATE as date, (SELECT count FROM active_users_count) as count
        ) active_trend),
        '{}'::types.q_list_staff_v4_trend_data[]
    ) as trend_data_active,
    COALESCE(
        (SELECT ARRAY_AGG(
            (auc.date, auc.cumulative_count::double precision, auc.daily_count)::types.q_list_staff_v4_trend_data
            ORDER BY auc.date
        )
        FROM admin_users_cumulative auc),
        '{}'::types.q_list_staff_v4_trend_data[]
    ) as trend_data_admin,
    COALESCE(
        (SELECT ARRAY_AGG(
            (iuc.date, iuc.cumulative_count::double precision, iuc.daily_count)::types.q_list_staff_v4_trend_data
            ORDER BY iuc.date
        )
        FROM instructional_users_cumulative iuc),
        '{}'::types.q_list_staff_v4_trend_data[]
    ) as trend_data_instructional,
    COALESCE(
        (SELECT ARRAY_AGG(
            (muc.date, muc.cumulative_count::double precision, muc.daily_count)::types.q_list_staff_v4_trend_data
            ORDER BY muc.date
        )
        FROM member_users_cumulative muc),
        '{}'::types.q_list_staff_v4_trend_data[]
    ) as trend_data_member,
    COALESCE(
        (SELECT ARRAY_AGG(
            (trc.date, trc.cumulative_count::double precision, trc.daily_count)::types.q_list_staff_v4_trend_data
            ORDER BY trc.date
        )
        FROM total_requests_cumulative trc),
        '{}'::types.q_list_staff_v4_trend_data[]
    ) as trend_data_total_requests,
    COALESCE(vdid.valid_department_ids, ARRAY[]::text[]) as valid_department_ids,
    CASE 
        WHEN up.role = 'superadmin' THEN ARRAY['superadmin', 'admin', 'instructional', 'member', 'guest']::text[]
        WHEN up.role = 'admin' THEN ARRAY['admin', 'instructional', 'member', 'guest']::text[]
        ELSE ARRAY['instructional', 'member', 'guest']::text[]
    END as role_options,
    COALESCE(
        (SELECT ARRAY_AGG(cd.name ORDER BY cd.name)
         FROM cohorts_data cd),
        ARRAY[]::text[]
    ) as cohort_options,
    ARRAY['recent', 'moderate', 'old', 'never']::text[] as last_active_options
FROM user_profile up
CROSS JOIN valid_department_ids_data vdid
$$;


--
-- Name: api_log_run_v4(uuid, integer, integer, integer, integer, integer, integer, integer, uuid, text[], text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_log_run_v4(run_id uuid, input_text_tokens integer, input_audio_tokens integer, input_image_tokens integer, output_text_tokens integer, output_audio_tokens integer, cached_text_tokens integer, cached_audio_tokens integer, department_id uuid DEFAULT NULL::uuid, developer_contents text[] DEFAULT ARRAY[]::text[], assistant_output text DEFAULT NULL::text) RETURNS TABLE(success integer)
    LANGUAGE sql
    AS $$
-- Complete log_run handler: token updates + message logging in single transaction
-- All parameters are cast exactly once in params CTE for reliable type introspection
WITH params AS (
    SELECT api_log_run_v4.run_id AS run_id,
           api_log_run_v4.department_id AS department_id,
           api_log_run_v4.input_text_tokens AS input_text_tokens,
           api_log_run_v4.input_audio_tokens AS input_audio_tokens,
           api_log_run_v4.input_image_tokens AS input_image_tokens,
           api_log_run_v4.output_text_tokens AS output_text_tokens,
           api_log_run_v4.output_audio_tokens AS output_audio_tokens,
           api_log_run_v4.cached_text_tokens AS cached_text_tokens,
           api_log_run_v4.cached_audio_tokens AS cached_audio_tokens,
           COALESCE(api_log_run_v4.developer_contents, ARRAY[]::text[]) AS developer_contents,
           NULLIF(api_log_run_v4.assistant_output, '') AS assistant_output
),
run_info AS (
    SELECT 
        r.id as run_id,
        r.agent_id,
        (SELECT rp.persona_id FROM run_personas rp WHERE rp.run_id = r.id AND rp.active = true LIMIT 1) as persona_id,
        COALESCE(
            x.department_id,
            -- Try to get department from chat
            (SELECT sd.department_id FROM runs r2
             JOIN group_runs gr ON gr.run_id = r2.id
             JOIN groups g ON g.id = gr.group_id
             JOIN chat_groups cg ON cg.group_id = g.id
             JOIN chats c ON c.id = cg.chat_id
             JOIN scenario_departments sd ON sd.scenario_id = c.scenario_id AND sd.active = true
             WHERE r2.id = x.run_id LIMIT 1),
            -- Try to get department from profile
            (SELECT pd.department_id FROM run_profiles rpf
             JOIN profile_departments pd ON pd.profile_id = rpf.profile_id AND pd.active = true
             WHERE rpf.run_id = x.run_id AND rpf.active = true LIMIT 1),
            -- Fallback to any active department
            (SELECT id FROM departments WHERE active = true LIMIT 1)
        ) as department_id
    FROM params x
    JOIN runs r ON r.id = x.run_id
),
-- Token update: handle both text-only and audio/image/text scenarios
has_audio_or_image AS (
    SELECT 
        COALESCE(x.input_audio_tokens, 0) > 0 OR COALESCE(x.input_image_tokens, 0) > 0 OR COALESCE(x.output_audio_tokens, 0) > 0 OR COALESCE(x.cached_audio_tokens, 0) > 0 as has_audio_image
    FROM params x
),
update_run AS (
    UPDATE runs 
    SET 
        input_tokens = CASE 
            WHEN (SELECT has_audio_image FROM has_audio_or_image) THEN
                COALESCE(x.input_text_tokens, 0) + COALESCE(x.input_audio_tokens, 0) + COALESCE(x.input_image_tokens, 0)
            ELSE
                COALESCE(x.input_text_tokens, 0)
        END,
        output_tokens = CASE 
            WHEN (SELECT has_audio_image FROM has_audio_or_image) THEN
                COALESCE(x.output_text_tokens, 0) + COALESCE(x.output_audio_tokens, 0)
            ELSE
                COALESCE(x.output_text_tokens, 0)
        END,
        cached_input_tokens = CASE 
            WHEN (SELECT has_audio_image FROM has_audio_or_image) THEN
                COALESCE(x.cached_text_tokens, 0) + COALESCE(x.cached_audio_tokens, 0)
            ELSE
                COALESCE(x.cached_text_tokens, 0)
        END
    FROM params x
    WHERE runs.id = x.run_id
    RETURNING id, input_tokens, output_tokens, cached_input_tokens
),
-- Get unit IDs for pricing
million_text_unit AS (
    SELECT id FROM units 
    WHERE name = 'million_text' AND unit_category = 'tokens' AND active = true 
    LIMIT 1
),
million_audio_unit AS (
    SELECT id FROM units 
    WHERE name = 'million_audio' AND unit_category = 'tokens' AND active = true 
    LIMIT 1
),
million_image_unit AS (
    SELECT id FROM units 
    WHERE name = 'million_image' AND unit_category = 'tokens' AND active = true 
    LIMIT 1
),
-- Upsert pricing usage (conditional based on token types)
upsert_input_text_usage AS (
    INSERT INTO run_pricing_usage (run_id, pricing_type, unit_id, count, updated_at)
    SELECT 
        ur.id,
        'input'::pricing_type,
        mtu.id,
        x.input_text_tokens,
        now()
    FROM params x
    CROSS JOIN update_run ur
    CROSS JOIN million_text_unit mtu
    WHERE x.input_text_tokens > 0 AND mtu.id IS NOT NULL
    ON CONFLICT (run_id, pricing_type, unit_id) 
    DO UPDATE SET 
        count = EXCLUDED.count,
        updated_at = now()
),
upsert_input_audio_usage AS (
    INSERT INTO run_pricing_usage (run_id, pricing_type, unit_id, count, updated_at)
    SELECT 
        ur.id,
        'input'::pricing_type,
        mau.id,
        x.input_audio_tokens,
        now()
    FROM params x
    CROSS JOIN update_run ur
    CROSS JOIN million_audio_unit mau
    WHERE COALESCE(x.input_audio_tokens, 0) > 0 AND mau.id IS NOT NULL
    ON CONFLICT (run_id, pricing_type, unit_id) 
    DO UPDATE SET 
        count = EXCLUDED.count,
        updated_at = now()
),
upsert_input_image_usage AS (
    INSERT INTO run_pricing_usage (run_id, pricing_type, unit_id, count, updated_at)
    SELECT 
        ur.id,
        'input'::pricing_type,
        miu.id,
        x.input_image_tokens,
        now()
    FROM params x
    CROSS JOIN update_run ur
    CROSS JOIN million_image_unit miu
    WHERE COALESCE(x.input_image_tokens, 0) > 0 AND miu.id IS NOT NULL
    ON CONFLICT (run_id, pricing_type, unit_id) 
    DO UPDATE SET 
        count = EXCLUDED.count,
        updated_at = now()
),
upsert_output_text_usage AS (
    INSERT INTO run_pricing_usage (run_id, pricing_type, unit_id, count, updated_at)
    SELECT 
        ur.id,
        'output'::pricing_type,
        mtu.id,
        x.output_text_tokens,
        now()
    FROM params x
    CROSS JOIN update_run ur
    CROSS JOIN million_text_unit mtu
    WHERE x.output_text_tokens > 0 AND mtu.id IS NOT NULL
    ON CONFLICT (run_id, pricing_type, unit_id) 
    DO UPDATE SET 
        count = EXCLUDED.count,
        updated_at = now()
),
upsert_output_audio_usage AS (
    INSERT INTO run_pricing_usage (run_id, pricing_type, unit_id, count, updated_at)
    SELECT 
        ur.id,
        'output'::pricing_type,
        mau.id,
        x.output_audio_tokens,
        now()
    FROM params x
    CROSS JOIN update_run ur
    CROSS JOIN million_audio_unit mau
    WHERE COALESCE(x.output_audio_tokens, 0) > 0 AND mau.id IS NOT NULL
    ON CONFLICT (run_id, pricing_type, unit_id) 
    DO UPDATE SET 
        count = EXCLUDED.count,
        updated_at = now()
),
upsert_cached_text_usage AS (
    INSERT INTO run_pricing_usage (run_id, pricing_type, unit_id, count, updated_at)
    SELECT 
        ur.id,
        'cached'::pricing_type,
        mtu.id,
        x.cached_text_tokens,
        now()
    FROM params x
    CROSS JOIN update_run ur
    CROSS JOIN million_text_unit mtu
    WHERE COALESCE(x.cached_text_tokens, 0) > 0 AND mtu.id IS NOT NULL
    ON CONFLICT (run_id, pricing_type, unit_id) 
    DO UPDATE SET 
        count = EXCLUDED.count,
        updated_at = now()
),
upsert_cached_audio_usage AS (
    INSERT INTO run_pricing_usage (run_id, pricing_type, unit_id, count, updated_at)
    SELECT 
        ur.id,
        'cached'::pricing_type,
        mau.id,
        x.cached_audio_tokens,
        now()
    FROM params x
    CROSS JOIN update_run ur
    CROSS JOIN million_audio_unit mau
    WHERE COALESCE(x.cached_audio_tokens, 0) > 0 AND mau.id IS NOT NULL
    ON CONFLICT (run_id, pricing_type, unit_id) 
    DO UPDATE SET 
        count = EXCLUDED.count,
        updated_at = now()
),
-- Get system prompt for persona runs
persona_system_prompt AS (
    SELECT 
        CASE 
            WHEN p.instructions IS NOT NULL AND p.instructions != '' THEN
                COALESCE(pr_dept.system_prompt, pr_default.system_prompt) || E'\n\n' || p.instructions
            ELSE
                COALESCE(pr_dept.system_prompt, pr_default.system_prompt)
        END as system_prompt
    FROM run_info ri
    JOIN run_personas rp ON rp.run_id = ri.run_id AND rp.active = true
    JOIN personas p ON p.id = rp.persona_id
    JOIN agents a ON a.id = ri.agent_id
    LEFT JOIN agent_department_prompts adp ON adp.agent_id = a.id 
        AND adp.department_id = ri.department_id
        AND adp.active = true
    LEFT JOIN prompts pr_dept ON pr_dept.id = adp.prompt_id
    LEFT JOIN agent_prompts ap ON ap.agent_id = a.id AND ap.active = true
    LEFT JOIN prompts pr_default ON pr_default.id = ap.prompt_id
    WHERE ri.persona_id IS NOT NULL
    AND COALESCE(pr_dept.system_prompt, pr_default.system_prompt) IS NOT NULL
    AND COALESCE(pr_dept.system_prompt, pr_default.system_prompt) != ''
),
-- Get system prompt for agent runs
agent_system_prompt AS (
    SELECT 
        COALESCE(pr_dept.system_prompt, pr_default.system_prompt) as system_prompt
    FROM run_info ri
    JOIN agents a ON a.id = ri.agent_id
    LEFT JOIN agent_department_prompts adp ON adp.agent_id = a.id 
        AND adp.department_id = ri.department_id
        AND adp.active = true
    LEFT JOIN prompts pr_dept ON pr_dept.id = adp.prompt_id
    LEFT JOIN agent_prompts ap ON ap.agent_id = a.id AND ap.active = true
    LEFT JOIN prompts pr_default ON pr_default.id = ap.prompt_id
    WHERE ri.agent_id IS NOT NULL
    AND ri.persona_id IS NULL
    AND COALESCE(pr_dept.system_prompt, pr_default.system_prompt) IS NOT NULL
    AND COALESCE(pr_dept.system_prompt, pr_default.system_prompt) != ''
),
-- Get or create system message with MD5 deduplication
system_message_content AS (
    SELECT system_prompt as content FROM persona_system_prompt
    UNION ALL
    SELECT system_prompt as content FROM agent_system_prompt
),
system_message_hash AS (
    SELECT DISTINCT message_content_hash(smc.content, 'system') as hash, smc.content
    FROM system_message_content smc
),
existing_system_message AS (
    SELECT m.id as system_message_id
    FROM messages m
    JOIN message_content mc ON mc.message_id = m.id AND mc.idx = 0
        JOIN content cnt ON cnt.id = mc.content_id
    JOIN system_message_hash smh ON message_content_hash(cnt.content, 'system') = smh.hash
    WHERE m.role = 'system'
    LIMIT 1
),
new_system_message AS (
    INSERT INTO messages (role, completed, audio, created_at, updated_at)
    SELECT 'system'::message_role, false, false, NOW(), NOW()
    FROM system_message_content smc
    WHERE NOT EXISTS (SELECT 1 FROM existing_system_message)
    RETURNING id as system_message_id, created_at, updated_at
),
-- Get prompt tool_id for prompt agent
get_prompt_tool_id AS (
    SELECT id as tool_id
    FROM tools
    WHERE name = 'prompt' AND agent_role = 'prompt'::agent_role AND active = true
    LIMIT 1
),
system_tool_call AS (
    INSERT INTO calls (call_id, tool_id, completed, created_at, updated_at)
    SELECT 'log_run_system_' || nsm.system_message_id::text, gpt.tool_id, true, nsm.created_at, nsm.updated_at
    FROM new_system_message nsm
    CROSS JOIN get_prompt_tool_id gpt
    WHERE NOT EXISTS (SELECT 1 FROM existing_system_message)
    RETURNING id as tool_call_id, created_at, updated_at
),
existing_system_tool_call AS (
    SELECT DISTINCT cnt.tool_call_id
    FROM existing_system_message esm
    JOIN message_content mc ON mc.message_id = esm.system_message_id AND mc.idx = 0
    JOIN content cnt ON cnt.id = mc.content_id
    LIMIT 1
),
system_tool_call_id AS (
    SELECT tool_call_id FROM system_tool_call
    UNION ALL
    SELECT tool_call_id FROM existing_system_tool_call
),
insert_system_content_step1 AS (
    INSERT INTO content (content, tool_call_id, created_at, updated_at)
    SELECT smc.content, stc.tool_call_id, nsm.created_at, nsm.updated_at
    FROM new_system_message nsm
    CROSS JOIN system_message_content smc
    CROSS JOIN system_tool_call_id stc
    WHERE NOT EXISTS (SELECT 1 FROM existing_system_message)
    RETURNING id as content_id, content, tool_call_id, created_at, updated_at
),
insert_system_content AS (
    INSERT INTO message_content (message_id, content_id, idx, created_at, updated_at)
    SELECT nsm.system_message_id, ic.content_id, 0, ic.created_at, ic.updated_at
    FROM new_system_message nsm
    CROSS JOIN system_message_content smc
    CROSS JOIN system_tool_call_id stc
    JOIN insert_system_content_step1 ic ON ic.content = smc.content
        AND ic.tool_call_id = stc.tool_call_id
    WHERE NOT EXISTS (SELECT 1 FROM existing_system_message)
),
system_message AS (
    SELECT system_message_id FROM existing_system_message
    UNION ALL
    SELECT system_message_id FROM new_system_message
),
-- Link system message to run
link_system AS (
    INSERT INTO message_runs (message_id, run_id, created_at, updated_at)
    SELECT sm.system_message_id, x.run_id, NOW(), NOW()
    FROM params x
    CROSS JOIN system_message sm
    ON CONFLICT (message_id, run_id) DO UPDATE SET updated_at = NOW()
    RETURNING message_id as system_message_id
),
-- Process developer messages from array (preserve order for parent selection)
developer_contents_array AS (
    SELECT 
        t.content,
        t.idx
    FROM params x
    CROSS JOIN unnest(x.developer_contents) WITH ORDINALITY AS t(content, idx)
    WHERE x.developer_contents IS NOT NULL AND array_length(x.developer_contents, 1) > 0
),
developer_contents_filtered AS (
    SELECT 
        trim(t.content) as content,
        MIN(t.idx) as first_idx
    FROM developer_contents_array t
    WHERE trim(t.content) != ''
    GROUP BY trim(t.content)
),
-- Get or create developer messages with MD5 deduplication
developer_messages_processed AS (
    SELECT 
        dcf.content,
        dcf.first_idx,
        message_content_hash(dcf.content, 'developer') as hash
    FROM developer_contents_filtered dcf
),
existing_developer_messages_with_rn AS (
    SELECT 
        dmp.content,
        dmp.first_idx,
        m.id as message_id,
        ROW_NUMBER() OVER (PARTITION BY dmp.content ORDER BY m.created_at ASC) as rn
    FROM developer_messages_processed dmp
    JOIN messages m ON m.role = 'developer'
    JOIN message_content mc ON mc.message_id = m.id AND mc.idx = 0
        JOIN content cnt ON cnt.id = mc.content_id
        AND message_content_hash(cnt.content, 'developer') = dmp.hash
),
existing_developer_messages AS (
    SELECT 
        content,
        first_idx,
        message_id
    FROM existing_developer_messages_with_rn
    WHERE rn = 1
),
new_developer_messages AS (
    INSERT INTO messages (role, completed, audio, created_at, updated_at)
    SELECT 'developer'::message_role, false, false, NOW(), NOW()
    FROM developer_messages_processed dmp
    WHERE NOT EXISTS (
        SELECT 1 FROM existing_developer_messages edm 
        WHERE edm.content = dmp.content
    )
    RETURNING id as message_id, created_at, updated_at
),
-- Get instruct tool_id for prompt agent
get_instruct_tool_id AS (
    SELECT id as tool_id
    FROM tools
    WHERE name = 'instruct' AND agent_role = 'prompt'::agent_role AND active = true
    LIMIT 1
),
developer_calls_with_rn AS (
    INSERT INTO calls (call_id, tool_id, completed, created_at, updated_at)
    SELECT 
        'log_run_developer_' || ndm.message_id::text, 
        git.tool_id, 
        true, 
        ndm.created_at, 
        ndm.updated_at
    FROM new_developer_messages ndm
    CROSS JOIN get_instruct_tool_id git
    RETURNING id as tool_call_id, created_at, updated_at
),
developer_calls_ordered AS (
    SELECT 
        tool_call_id,
        created_at,
        ROW_NUMBER() OVER (ORDER BY created_at) as rn
    FROM developer_calls_with_rn
),
developer_messages_ordered AS (
    SELECT 
        message_id,
        created_at,
        updated_at,
        ROW_NUMBER() OVER (ORDER BY created_at) as rn
    FROM new_developer_messages
),
developer_message_with_tool_call AS (
    SELECT 
        dmo.message_id,
        dmo.created_at,
        dmo.updated_at,
        dtco.tool_call_id
    FROM developer_messages_ordered dmo
    JOIN developer_calls_ordered dtco ON dtco.rn = dmo.rn
),
existing_developer_calls AS (
    SELECT edm.message_id, cnt.tool_call_id
    FROM existing_developer_messages edm
    JOIN message_content mc ON mc.message_id = edm.message_id AND mc.idx = 0
    JOIN content cnt ON cnt.id = mc.content_id
),
all_developer_calls AS (
    SELECT message_id, tool_call_id FROM developer_message_with_tool_call
    UNION ALL
    SELECT message_id, tool_call_id FROM existing_developer_calls
),
insert_developer_content_step1 AS (
    INSERT INTO content (content, tool_call_id, created_at, updated_at)
    SELECT 
        dmp.content, 
        adtcm.tool_call_id, 
        dmtc.created_at,
        dmtc.updated_at
    FROM all_developer_calls adtcm
    JOIN developer_message_with_tool_call dmtc ON dmtc.message_id = adtcm.message_id
    JOIN developer_messages_processed dmp ON EXISTS (
        SELECT 1 FROM new_developer_messages ndm 
        WHERE ndm.message_id = adtcm.message_id
    )
    WHERE NOT EXISTS (
        SELECT 1 FROM existing_developer_messages edm 
        JOIN message_content mc2 ON mc2.message_id = edm.message_id AND mc2.idx = 0
        JOIN content cnt2 ON cnt2.id = mc2.content_id
        WHERE cnt2.content = dmp.content
    )
    RETURNING id as content_id, created_at, updated_at
),
insert_developer_content AS (
    INSERT INTO message_content (message_id, content_id, idx, created_at, updated_at)
    SELECT 
        adtcm.message_id,
        ic.content_id,
        0,
        ic.created_at,
        ic.updated_at
    FROM all_developer_calls adtcm
    JOIN developer_message_with_tool_call dmtc ON dmtc.message_id = adtcm.message_id
    JOIN developer_messages_processed dmp ON EXISTS (
        SELECT 1 FROM new_developer_messages ndm 
        WHERE ndm.message_id = adtcm.message_id
    )
    CROSS JOIN insert_developer_content_step1 ic
    WHERE NOT EXISTS (
        SELECT 1 FROM existing_developer_messages edm 
        JOIN message_content mc2 ON mc2.message_id = edm.message_id AND mc2.idx = 0
        JOIN content cnt2 ON cnt2.id = mc2.content_id
        WHERE cnt2.content = dmp.content
    )
),
all_developer_messages AS (
    SELECT message_id, content, first_idx FROM existing_developer_messages
    UNION ALL
    SELECT ndm.message_id, dmp.content, dmp.first_idx 
    FROM developer_messages_processed dmp
    JOIN new_developer_messages ndm ON NOT EXISTS (
        SELECT 1 FROM existing_developer_messages edm 
        WHERE edm.content = dmp.content
    )
),
-- Link developer messages to run (preserve order for parent selection)
link_developers AS (
    INSERT INTO message_runs (message_id, run_id, created_at, updated_at)
    SELECT adm.message_id, x.run_id, NOW(), NOW()
    FROM params x
    CROSS JOIN all_developer_messages adm
    ORDER BY adm.first_idx
    ON CONFLICT (message_id, run_id) 
    DO UPDATE SET updated_at = NOW()
    RETURNING message_id as developer_message_id
),
-- Link system → developer in message_tree (if both exist)
link_system_to_developer AS (
    INSERT INTO message_tree (parent_id, child_id, active, created_at, updated_at)
    SELECT DISTINCT
        ls.system_message_id as parent_id,
        ld.developer_message_id as child_id,
        true as active,
        NOW() as created_at,
        NOW() as updated_at
    FROM link_system ls
    CROSS JOIN link_developers ld
    WHERE NOT EXISTS (
        SELECT 1 FROM message_tree mt 
        WHERE mt.parent_id = ls.system_message_id 
        AND mt.child_id = ld.developer_message_id 
        AND mt.active = true
    )
),
-- Create assistant message if output provided
assistant_message AS (
    INSERT INTO messages (role, completed, audio, created_at, updated_at)
    SELECT 'assistant'::message_role, true, false, NOW(), NOW()
    FROM params x
    WHERE x.assistant_output IS NOT NULL AND trim(x.assistant_output) != ''
    RETURNING id as assistant_message_id, created_at, updated_at
),
assistant_tool_call AS (
    INSERT INTO calls (call_id, tool_id, completed, created_at, updated_at)
    SELECT 'log_run_assistant_' || am.assistant_message_id::text, NULL, true, am.created_at, am.updated_at
    FROM params x
    CROSS JOIN assistant_message am
    WHERE x.assistant_output IS NOT NULL AND trim(x.assistant_output) != ''
    RETURNING id as tool_call_id, created_at, updated_at
),
insert_assistant_content_step1 AS (
    INSERT INTO content (content, tool_call_id, created_at, updated_at)
    SELECT trim(x.assistant_output), atc.tool_call_id, am.created_at, am.updated_at
    FROM params x
    CROSS JOIN assistant_message am
    CROSS JOIN assistant_tool_call atc
    WHERE x.assistant_output IS NOT NULL AND trim(x.assistant_output) != ''
    RETURNING id as content_id, created_at, updated_at
),
insert_assistant_content AS (
    INSERT INTO message_content (message_id, content_id, idx, created_at, updated_at)
    SELECT am.assistant_message_id, ic.content_id, 0, ic.created_at, ic.updated_at
    FROM params x
    CROSS JOIN assistant_message am
    CROSS JOIN assistant_tool_call atc
    CROSS JOIN insert_assistant_content_step1 ic
    WHERE x.assistant_output IS NOT NULL AND trim(x.assistant_output) != ''
),
link_assistant AS (
    INSERT INTO message_runs (message_id, run_id, created_at, updated_at)
    SELECT am.assistant_message_id, x.run_id, NOW(), NOW()
    FROM params x
    CROSS JOIN assistant_message am
    ON CONFLICT (message_id, run_id) 
    DO UPDATE SET updated_at = NOW()
),
-- Determine parent for assistant message (last developer if exists, otherwise system)
-- Note: link_developers returns rows in insertion order, so last row is the last developer message
assistant_parent AS (
    SELECT 
        COALESCE(
            (SELECT developer_message_id FROM link_developers ORDER BY developer_message_id DESC LIMIT 1),
            (SELECT system_message_id FROM link_system LIMIT 1)
        ) as parent_message_id
),
-- Create message_tree branch for assistant
create_assistant_branch AS (
    INSERT INTO message_tree (parent_id, child_id, active, created_at, updated_at)
    SELECT 
        ap.parent_message_id,
        am.assistant_message_id,
        true,
        NOW(),
        NOW()
    FROM assistant_message am
    CROSS JOIN assistant_parent ap
    WHERE ap.parent_message_id IS NOT NULL
    AND NOT EXISTS (
        SELECT 1 FROM message_tree mt 
        WHERE mt.parent_id = ap.parent_message_id 
        AND mt.child_id = am.assistant_message_id 
        AND mt.active = true
    )
    ON CONFLICT (parent_id, child_id) 
    DO UPDATE SET 
        active = true,
        updated_at = NOW()
)
SELECT 1 AS success
$$;


--
-- Name: api_patch_agent_draft_v4(uuid, text, integer, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_patch_agent_draft_v4(profile_id uuid, patch text, expected_version integer, input_draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(draft_id uuid, new_version integer, draft_exists boolean)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_draft_id uuid;
    v_new_version int;
    v_profile_id uuid := profile_id;  -- Store function parameter in local variable to avoid ambiguity
    v_patch jsonb := patch::jsonb;  -- Cast text to jsonb at the start
BEGIN
    -- If input_draft_id provided, try to patch existing draft
    IF input_draft_id IS NOT NULL THEN
        UPDATE drafts
        SET
            payload = drafts.payload || v_patch,
            version = drafts.version + 1,
            updated_at = now()
        WHERE
            drafts.id = input_draft_id
            AND drafts.profile_id = v_profile_id
            AND drafts.version = expected_version
        RETURNING drafts.id, drafts.version INTO v_draft_id, v_new_version;
        
        -- If update succeeded, return result
        IF v_draft_id IS NOT NULL THEN
            RETURN QUERY SELECT v_draft_id, v_new_version, true;
            RETURN;
        END IF;
    END IF;
    
    -- If no input_draft_id or update failed (version mismatch), create new draft
    WITH defaults AS (
        SELECT jsonb_build_object(
            'name', 'New Agent',
            'description', '',
            'systemPrompt', '',
            'promptId', null,
            'modelId', '',
            'active', true,
            'role', 'assistant',
            'departmentIds', jsonb_build_array(),
            'model_temperature_level_id', null,
            'model_reasoning_level_id', null,
            'model_voice_ids', jsonb_build_array()
        ) AS d
    ),
    payload AS (
        SELECT (d || v_patch) AS p
        FROM defaults
    ),
    params AS (
        SELECT v_profile_id AS p_profile_id
    )
    INSERT INTO drafts(resource_type, profile_id, payload)
    SELECT 'agents'::draft_resource_type, p_profile_id, p
    FROM payload, params
    RETURNING id, version INTO v_draft_id, v_new_version;
    
    RETURN QUERY SELECT v_draft_id, v_new_version, false;
END;
$$;


