            'hint_agent_id', NULL,
            'simulation_text_agent_id', NULL,
            'simulation_voice_agent_id', NULL,
            'member_agent_id', NULL
        ) AS d
    ),
    payload AS (
        SELECT (d || v_patch) AS p
        FROM defaults
    ),
    params AS (
        SELECT v_profile_id AS p_profile_id
    )
    INSERT INTO drafts(resource_type, profile_id, payload)
    SELECT 'simulations'::draft_resource_type, p_profile_id, p
    FROM payload, params
    RETURNING id, version INTO v_draft_id, v_new_version;
    
    RETURN QUERY SELECT v_draft_id, v_new_version, false;
END;
$$;


--
-- Name: api_patch_staff_draft_v4(uuid, text, integer, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_patch_staff_draft_v4(profile_id uuid, patch text, expected_version integer, input_draft_id uuid DEFAULT NULL::uuid) RETURNS TABLE(draft_id uuid, new_version integer, draft_exists boolean)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_draft_id uuid;
    v_new_version int;
    v_profile_id uuid := profile_id;  -- Store function parameter in local variable to avoid ambiguity
    v_patch jsonb := patch::jsonb;  -- Cast text to jsonb at the start
BEGIN
    -- If input_draft_id provided, try to patch existing draft
    IF input_draft_id IS NOT NULL THEN
        UPDATE drafts
        SET
            payload = drafts.payload || v_patch,
            version = drafts.version + 1,
            updated_at = now()
        WHERE
            drafts.id = input_draft_id
            AND drafts.profile_id = v_profile_id
            AND drafts.version = expected_version
        RETURNING drafts.id, drafts.version INTO v_draft_id, v_new_version;
        
        -- If update succeeded, return result
        IF v_draft_id IS NOT NULL THEN
            RETURN QUERY SELECT v_draft_id, v_new_version, true;
            RETURN;
        END IF;
    END IF;
    
    -- If no input_draft_id or update failed (version mismatch), create new draft
    WITH defaults AS (
        SELECT jsonb_build_object(
            'firstName', '',
            'lastName', '',
            'emails', jsonb_build_array(),
            'primaryEmailIndex', NULL,
            'role', 'instructional',
            'reqPerDay', NULL,
            'requestsPerDayEnabled', false,
            'cohortIds', jsonb_build_array(),
            'departmentIds', jsonb_build_array(),
            'primaryDepartmentIndex', NULL,
            'active', true
        ) AS d
    ),
    payload AS (
        SELECT (d || v_patch) AS p
        FROM defaults
    ),
    params AS (
        SELECT v_profile_id AS p_profile_id
    )
    INSERT INTO drafts(resource_type, profile_id, payload)
    SELECT 'staff'::draft_resource_type, p_profile_id, p
    FROM payload, params
    RETURNING id, version INTO v_draft_id, v_new_version;
    
    RETURN QUERY SELECT v_draft_id, v_new_version, false;
END;
$$;


--
-- Name: api_process_csv_v4(text, types.i_process_csv_v4_column_mapping[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_process_csv_v4(csv_content text, column_mappings types.i_process_csv_v4_column_mapping[], profile_id uuid) RETURNS TABLE(success boolean, headers text[], rows types.q_process_csv_v4_processed_row[], actor_name text)
    LANGUAGE sql STABLE
    AS $$
-- Function accepts csv_content and column_mappings from frontend
-- CSV parsing happens in Python, then Python constructs full response
-- This function provides actor_name - Python will merge parsed data with actor_name
WITH params AS (
    SELECT 
        csv_content AS csv_content,
        COALESCE(column_mappings, ARRAY[]::types.i_process_csv_v4_column_mapping[]) AS column_mappings,
        profile_id AS profile_id
),
user_profile AS (
    SELECT 
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
)
SELECT 
    true::boolean as success,
    ARRAY[]::text[] as headers,  -- Populated by Python after parsing
    ARRAY[]::types.q_process_csv_v4_processed_row[] as rows,  -- Populated by Python after parsing
    up.actor_name::text as actor_name
FROM params p
CROSS JOIN user_profile up
$$;


--
-- Name: api_randomize_scenario_v4(uuid, uuid, text, uuid[], uuid[], uuid[], uuid[], uuid[], integer, integer, integer, integer, integer, integer, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_randomize_scenario_v4(scenario_id uuid, profile_id uuid, randomize_type text, department_ids uuid[], persona_ids uuid[], document_ids uuid[], parameter_ids uuid[], field_ids uuid[], persona_min integer, persona_max integer, document_min integer, document_max integer, parameter_selection_min integer, parameter_selection_max integer, field_ranges_json jsonb) RETURNS TABLE(randomized_persona_ids uuid[], randomized_document_ids uuid[], randomized_parameter_ids uuid[], randomized_field_ids uuid[])
    LANGUAGE plpgsql
    AS $$
DECLARE
    -- Valid IDs (will be populated from filtering)
    valid_persona_ids uuid[];
    valid_document_ids uuid[];
    valid_parameter_ids uuid[];
    valid_field_ids uuid[];
    
    -- Ranges from database or defaults
    allowed_persona_min integer;
    allowed_persona_max integer;
    allowed_document_min integer;
    allowed_document_max integer;
    allowed_parameter_min integer;
    allowed_parameter_max integer;
    
    -- Validated and capped ranges
    final_persona_min integer;
    final_persona_max integer;
    final_document_min integer;
    final_document_max integer;
    final_parameter_min integer;
    final_parameter_max integer;
    
    -- Counts for capping
    max_valid_personas integer;
    max_valid_documents integer;
    max_valid_parameters integer;
    
    -- Randomization results
    randomized_persona_ids uuid[];
    randomized_document_ids uuid[];
    randomized_parameter_ids uuid[];
    randomized_field_ids uuid[];
    
    -- Random count
    random_count integer;
    capped_max integer;
    
    -- Field randomization variables
    param_id uuid;
    param_range jsonb;
    param_min_val integer;
    param_max_val integer;
    valid_items_for_param uuid[];
    max_valid_items integer;
    randomized_items uuid[];
BEGIN
    -- Initialize result arrays as NULL
    randomized_persona_ids := NULL;
    randomized_document_ids := NULL;
    randomized_parameter_ids := NULL;
    randomized_field_ids := NULL;
    
    -- Get user's accessible departments
    WITH user_departments AS (
        SELECT DISTINCT d.id
        FROM departments d
        JOIN profile_departments pd ON pd.department_id = d.id
        WHERE pd.profile_id = api_randomize_scenario_v4.profile_id 
          AND pd.active = true 
          AND d.active = true
    ),
    -- Get valid persona IDs (filtered by departments if provided)
    filtered_personas AS (
        SELECT DISTINCT p.id
        FROM personas p
        LEFT JOIN persona_departments pd ON pd.persona_id = p.id AND pd.active = true
        WHERE p.active = true
        AND (
            -- If department_ids provided, filter by them
            (COALESCE(array_length(api_randomize_scenario_v4.department_ids, 1), 0) = 0 
             OR EXISTS (
                 SELECT 1 FROM user_departments ud 
                 WHERE ud.id = ANY(api_randomize_scenario_v4.department_ids)
                 AND (pd.department_id = ud.id OR NOT EXISTS (
                     SELECT 1 FROM persona_departments pd2 
                     WHERE pd2.persona_id = p.id AND pd2.active = true
                 ))
             ))
            -- Or if no department filter, include all accessible
            OR (COALESCE(array_length(api_randomize_scenario_v4.department_ids, 1), 0) = 0
                AND (pd.department_id IN (SELECT id FROM user_departments)
                     OR NOT EXISTS (
                         SELECT 1 FROM persona_departments pd2 
                         WHERE pd2.persona_id = p.id AND pd2.active = true
                     )))
        )
        -- Filter by provided persona_ids if any
        AND (COALESCE(array_length(api_randomize_scenario_v4.persona_ids, 1), 0) = 0
             OR p.id = ANY(api_randomize_scenario_v4.persona_ids))
    ),
    -- Get valid document IDs
    filtered_documents AS (
        SELECT DISTINCT d.id
        FROM documents d
        INNER JOIN document_uploads du ON du.document_id = d.id AND du.active = true
        LEFT JOIN document_departments dd ON dd.document_id = d.id AND dd.active = true
        WHERE d.active = true
        AND (
            COALESCE(array_length(api_randomize_scenario_v4.department_ids, 1), 0) = 0
            OR EXISTS (
                SELECT 1 FROM user_departments ud 
                WHERE ud.id = ANY(api_randomize_scenario_v4.department_ids)
                AND (dd.department_id = ud.id OR NOT EXISTS (
                    SELECT 1 FROM document_departments dd2 
                    WHERE dd2.document_id = d.id AND dd2.active = true
                ))
            )
            OR (COALESCE(array_length(api_randomize_scenario_v4.department_ids, 1), 0) = 0
                AND (dd.department_id IN (SELECT id FROM user_departments)
                     OR NOT EXISTS (
                         SELECT 1 FROM document_departments dd2 
                         WHERE dd2.document_id = d.id AND dd2.active = true
                     )))
        )
        AND (COALESCE(array_length(api_randomize_scenario_v4.document_ids, 1), 0) = 0
             OR d.id = ANY(api_randomize_scenario_v4.document_ids))
    ),
    -- Get valid parameter IDs
    filtered_parameters AS (
        SELECT DISTINCT p.id
        FROM parameters p
        JOIN parameter_fields pf ON pf.parameter_id = p.id AND pf.active = true
        LEFT JOIN field_departments fd ON fd.field_id = pf.field_id AND fd.active = true
        WHERE p.active = true
        AND (
            COALESCE(array_length(api_randomize_scenario_v4.department_ids, 1), 0) = 0
            OR EXISTS (
                SELECT 1 FROM user_departments ud 
                WHERE ud.id = ANY(api_randomize_scenario_v4.department_ids)
                AND (fd.department_id = ud.id OR NOT EXISTS (
                    SELECT 1 FROM field_departments fd2 
                    JOIN parameter_fields pf2 ON pf2.field_id = fd2.field_id 
                    WHERE pf2.parameter_id = p.id AND pf2.active = true AND fd2.active = true
                ))
            )
            OR (COALESCE(array_length(api_randomize_scenario_v4.department_ids, 1), 0) = 0
                AND (fd.department_id IN (SELECT id FROM user_departments)
                     OR NOT EXISTS (
                         SELECT 1 FROM field_departments fd2 
                         JOIN parameter_fields pf2 ON pf2.field_id = fd2.field_id 
                         WHERE pf2.parameter_id = p.id AND pf2.active = true AND fd2.active = true
                     )))
        )
        AND (COALESCE(array_length(api_randomize_scenario_v4.parameter_ids, 1), 0) = 0
             OR p.id = ANY(api_randomize_scenario_v4.parameter_ids))
    ),
    -- Get valid field IDs (filtered by departments and parameters)
    filtered_fields AS (
        SELECT DISTINCT f.id
        FROM fields f
        JOIN parameter_fields pf ON pf.field_id = f.id AND pf.active = true
        LEFT JOIN field_departments fd ON fd.field_id = f.id AND fd.active = true
        WHERE f.active = true
        AND (
            COALESCE(array_length(api_randomize_scenario_v4.department_ids, 1), 0) = 0
            OR EXISTS (
                SELECT 1 FROM user_departments ud 
                WHERE ud.id = ANY(api_randomize_scenario_v4.department_ids)
                AND (fd.department_id = ud.id OR NOT EXISTS (
                    SELECT 1 FROM field_departments fd2 
                    WHERE fd2.field_id = f.id AND fd2.active = true
                ))
            )
            OR (COALESCE(array_length(api_randomize_scenario_v4.department_ids, 1), 0) = 0
                AND (fd.department_id IN (SELECT id FROM user_departments)
                     OR NOT EXISTS (
                         SELECT 1 FROM field_departments fd2 
                         WHERE fd2.field_id = f.id AND fd2.active = true
                     )))
        )
        AND (COALESCE(array_length(api_randomize_scenario_v4.field_ids, 1), 0) = 0
             OR f.id = ANY(api_randomize_scenario_v4.field_ids))
        AND (COALESCE(array_length(api_randomize_scenario_v4.parameter_ids, 1), 0) = 0
             OR pf.parameter_id = ANY(api_randomize_scenario_v4.parameter_ids))
    )
    SELECT 
        (SELECT ARRAY_AGG(id ORDER BY id) FROM filtered_personas),
        (SELECT ARRAY_AGG(id ORDER BY id) FROM filtered_documents),
        (SELECT ARRAY_AGG(id ORDER BY id) FROM filtered_parameters),
        (SELECT ARRAY_AGG(id ORDER BY id) FROM filtered_fields)
    INTO 
        valid_persona_ids,
        valid_document_ids,
        valid_parameter_ids,
        valid_field_ids;
    
    -- Handle NULL arrays (no results)
    valid_persona_ids := COALESCE(valid_persona_ids, ARRAY[]::uuid[]);
    valid_document_ids := COALESCE(valid_document_ids, ARRAY[]::uuid[]);
    valid_parameter_ids := COALESCE(valid_parameter_ids, ARRAY[]::uuid[]);
    valid_field_ids := COALESCE(valid_field_ids, ARRAY[]::uuid[]);
    
    -- Get ranges from database (scenario-specific or defaults)
    SELECT 
        COALESCE((SELECT min_count FROM scenario_persona_ranges WHERE scenario_id = api_randomize_scenario_v4.scenario_id), 1),
        COALESCE((SELECT max_count FROM scenario_persona_ranges WHERE scenario_id = api_randomize_scenario_v4.scenario_id), 3),
        COALESCE((SELECT min_count FROM scenario_document_ranges WHERE scenario_id = api_randomize_scenario_v4.scenario_id), 0),
        COALESCE((SELECT max_count FROM scenario_document_ranges WHERE scenario_id = api_randomize_scenario_v4.scenario_id), 3),
        COALESCE((SELECT min_count FROM scenario_parameter_ranges WHERE scenario_id = api_randomize_scenario_v4.scenario_id), 0),
        COALESCE((SELECT max_count FROM scenario_parameter_ranges WHERE scenario_id = api_randomize_scenario_v4.scenario_id), 3)
    INTO 
        allowed_persona_min,
        allowed_persona_max,
        allowed_document_min,
        allowed_document_max,
        allowed_parameter_min,
        allowed_parameter_max;
    
    -- Validate and cap persona ranges
    final_persona_min := COALESCE(api_randomize_scenario_v4.persona_min, allowed_persona_min);
    final_persona_max := COALESCE(api_randomize_scenario_v4.persona_max, allowed_persona_min);
    final_persona_min := GREATEST(allowed_persona_min, LEAST(final_persona_min, allowed_persona_max));
    final_persona_max := GREATEST(allowed_persona_min, LEAST(final_persona_max, allowed_persona_max));
    final_persona_min := LEAST(final_persona_min, final_persona_max);
    
    -- Validate and cap document ranges
    final_document_min := COALESCE(api_randomize_scenario_v4.document_min, allowed_document_min);
    final_document_max := COALESCE(api_randomize_scenario_v4.document_max, allowed_document_min);
    final_document_min := GREATEST(allowed_document_min, LEAST(final_document_min, allowed_document_max));
    final_document_max := GREATEST(allowed_document_min, LEAST(final_document_max, allowed_document_max));
    final_document_min := LEAST(final_document_min, final_document_max);
    
    -- Validate and cap parameter ranges
    final_parameter_min := COALESCE(api_randomize_scenario_v4.parameter_selection_min, allowed_parameter_min);
    final_parameter_max := COALESCE(api_randomize_scenario_v4.parameter_selection_max, allowed_parameter_max);
    final_parameter_min := GREATEST(allowed_parameter_min, LEAST(final_parameter_min, allowed_parameter_max));
    final_parameter_max := GREATEST(allowed_parameter_min, LEAST(final_parameter_max, allowed_parameter_max));
    final_parameter_min := LEAST(final_parameter_min, final_parameter_max);
    
    -- Get counts for capping
    max_valid_personas := array_length(valid_persona_ids, 1);
    max_valid_documents := array_length(valid_document_ids, 1);
    max_valid_parameters := array_length(valid_parameter_ids, 1);
    
    -- Handle NULL counts
    max_valid_personas := COALESCE(max_valid_personas, 0);
    max_valid_documents := COALESCE(max_valid_documents, 0);
    max_valid_parameters := COALESCE(max_valid_parameters, 0);
    
    -- Perform randomization based on randomize_type
    IF randomize_type = 'all' THEN
        -- Randomize personas
        IF max_valid_personas > 0 THEN
            capped_max := LEAST(final_persona_max, max_valid_personas);
            random_count := LEAST(capped_max, GREATEST(final_persona_min, 
                final_persona_min + FLOOR(RANDOM() * (capped_max - final_persona_min + 1))::integer));
            SELECT ARRAY_AGG(id ORDER BY random())
            INTO randomized_persona_ids
            FROM unnest(valid_persona_ids) AS id
            LIMIT random_count;
        END IF;
        
        -- Randomize documents
        IF max_valid_documents > 0 THEN
            capped_max := LEAST(final_document_max, max_valid_documents);
            random_count := LEAST(capped_max, GREATEST(final_document_min,
                final_document_min + FLOOR(RANDOM() * (capped_max - final_document_min + 1))::integer));
            SELECT ARRAY_AGG(id ORDER BY random())
            INTO randomized_document_ids
            FROM unnest(valid_document_ids) AS id
            LIMIT random_count;
        END IF;
        
        -- Randomize parameters
        IF max_valid_parameters > 0 THEN
            capped_max := LEAST(final_parameter_max, max_valid_parameters);
            random_count := LEAST(capped_max, GREATEST(final_parameter_min,
                final_parameter_min + FLOOR(RANDOM() * (capped_max - final_parameter_min + 1))::integer));
            SELECT ARRAY_AGG(id ORDER BY random())
            INTO randomized_parameter_ids
            FROM unnest(valid_parameter_ids) AS id
            LIMIT random_count;
        END IF;
        
        -- Randomize all fields (for all valid parameters)
        randomized_items := ARRAY[]::uuid[];
        FOR param_id IN SELECT unnest(valid_parameter_ids)
        LOOP
            -- Get range for this parameter (from field_ranges_json or defaults)
            param_range := field_ranges_json -> param_id::text;
            IF param_range IS NULL THEN
                -- Use defaults if not in JSON
                param_min_val := 1;
                param_max_val := 1;
            ELSE
                param_min_val := COALESCE((param_range->>'min')::integer, 1);
                param_max_val := COALESCE((param_range->>'max')::integer, 1);
            END IF;
            param_max_val := LEAST(param_max_val, 3);
            param_min_val := LEAST(param_min_val, param_max_val);
            
            -- Get valid fields for this parameter
            SELECT ARRAY_AGG(f.id)
            INTO valid_items_for_param
            FROM fields f
            JOIN parameter_fields pf ON pf.field_id = f.id AND pf.active = true
            WHERE f.active = true
              AND pf.parameter_id = param_id
              AND f.id = ANY(valid_field_ids);
            
            IF valid_items_for_param IS NOT NULL AND array_length(valid_items_for_param, 1) > 0 THEN
                max_valid_items := array_length(valid_items_for_param, 1);
                capped_max := LEAST(param_max_val, max_valid_items);
                random_count := LEAST(capped_max, GREATEST(param_min_val,
                    param_min_val + FLOOR(RANDOM() * (capped_max - param_min_val + 1))::integer));
                
                -- Get randomized fields for this parameter
                SELECT ARRAY_AGG(id ORDER BY random())
                INTO valid_items_for_param
                FROM unnest(valid_items_for_param) AS id
                LIMIT random_count;
                
                -- Accumulate into randomized_items
                randomized_items := randomized_items || valid_items_for_param;
            END IF;
        END LOOP;
        
        IF array_length(randomized_items, 1) > 0 THEN
            randomized_field_ids := randomized_items;
        END IF;
        
    ELSIF randomize_type = 'persona' THEN
        -- Randomize personas only
        IF max_valid_personas > 0 THEN
            capped_max := LEAST(final_persona_max, max_valid_personas);
            random_count := LEAST(capped_max, GREATEST(final_persona_min,
                final_persona_min + FLOOR(RANDOM() * (capped_max - final_persona_min + 1))::integer));
            SELECT ARRAY_AGG(id ORDER BY random())
            INTO randomized_persona_ids
            FROM unnest(valid_persona_ids) AS id
            LIMIT random_count;
        END IF;
        
    ELSIF randomize_type = 'document' THEN
        -- Randomize documents only
        IF max_valid_documents > 0 THEN
            capped_max := LEAST(final_document_max, max_valid_documents);
            random_count := LEAST(capped_max, GREATEST(final_document_min,
                final_document_min + FLOOR(RANDOM() * (capped_max - final_document_min + 1))::integer));
            SELECT ARRAY_AGG(id ORDER BY random())
            INTO randomized_document_ids
            FROM unnest(valid_document_ids) AS id
            LIMIT random_count;
        END IF;
        
    ELSIF randomize_type = 'parameters' THEN
        -- Randomize parameters only
        IF max_valid_parameters > 0 THEN
            capped_max := LEAST(final_parameter_max, max_valid_parameters);
            random_count := LEAST(capped_max, GREATEST(final_parameter_min,
                final_parameter_min + FLOOR(RANDOM() * (capped_max - final_parameter_min + 1))::integer));
            SELECT ARRAY_AGG(id ORDER BY random())
            INTO randomized_parameter_ids
            FROM unnest(valid_parameter_ids) AS id
            LIMIT random_count;
        END IF;
        
    ELSIF randomize_type LIKE 'parameter_%' THEN
        -- Randomize fields for specific parameter
        param_id := (regexp_replace(randomize_type, '^parameter_', ''))::uuid;
        
        -- Get range for this parameter (from field_ranges_json or defaults)
        param_range := field_ranges_json -> param_id::text;
        IF param_range IS NULL THEN
            -- Use defaults if not in JSON
            param_min_val := 1;
            param_max_val := 1;
        ELSE
            param_min_val := COALESCE((param_range->>'min')::integer, 1);
            param_max_val := COALESCE((param_range->>'max')::integer, 1);
        END IF;
        param_max_val := LEAST(param_max_val, 3);
        param_min_val := LEAST(param_min_val, param_max_val);
        
        -- Get valid fields for this parameter
        SELECT ARRAY_AGG(f.id)
        INTO valid_items_for_param
        FROM fields f
        JOIN parameter_fields pf ON pf.field_id = f.id AND pf.active = true
        WHERE f.active = true
          AND pf.parameter_id = param_id
          AND f.id = ANY(valid_field_ids);
        
        IF valid_items_for_param IS NOT NULL AND array_length(valid_items_for_param, 1) > 0 THEN
            max_valid_items := array_length(valid_items_for_param, 1);
            capped_max := LEAST(param_max_val, max_valid_items);
            random_count := LEAST(capped_max, GREATEST(param_min_val,
                param_min_val + FLOOR(RANDOM() * (capped_max - param_min_val + 1))::integer));
            
            SELECT ARRAY_AGG(id ORDER BY random())
            INTO randomized_field_ids
            FROM unnest(valid_items_for_param) AS id
            LIMIT random_count;
        END IF;
    END IF;
    
    -- Return results (NULL arrays if no randomization occurred)
    RETURN QUERY SELECT 
        randomized_persona_ids,
        randomized_document_ids,
        randomized_parameter_ids,
        randomized_field_ids;
END;
$$;


--
-- Name: api_refresh_analytics_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_refresh_analytics_v4(profile_id uuid) RETURNS TABLE(actor_name text, success boolean, message text, status text)
    LANGUAGE plpgsql
    AS $$
DECLARE
    actor_name_val text;
BEGIN
    -- Refresh the materialized view
    REFRESH MATERIALIZED VIEW CONCURRENTLY analytics;
    
    -- Get actor_name from profile
    SELECT COALESCE(first_name || ' ' || last_name, 'System') INTO actor_name_val
    FROM profiles
    WHERE id = profile_id;
    
    -- Return response
    RETURN QUERY SELECT
        COALESCE(actor_name_val, 'System')::text as actor_name,
        true::boolean as success,
        'Analytics materialized view refreshed successfully'::text as message,
        'success'::text as status;
END $$;


--
-- Name: api_render_template_v4(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_render_template_v4(document_id uuid, profile_id uuid) RETURNS TABLE(document_name text, actor_name text, file_path text, schema_id uuid, settings_primary_color text, settings_accent text, settings_background text, settings_surface text, settings_success text, settings_warning text, settings_error text, settings_sidebar_background text, settings_sidebar_primary text, settings_chart1 text, settings_chart2 text, settings_chart3 text, settings_chart4 text, settings_chart5 text)
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT document_id AS document_id,
           profile_id AS profile_id
),
actor_profile AS (
    SELECT 
        p.id as profile_id,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
-- Settings resolution (same logic as get_active_settings_complete.sql)
default_settings AS (
    -- Get settings with no department links (cross-department/default)
    SELECT s.id as settings_id
    FROM settings s
    WHERE s.active = true
      AND NOT EXISTS (
          SELECT 1 FROM department_settings sd 
          WHERE sd.settings_id = s.id AND sd.active = true
      )
    LIMIT 1
),
resolve_department_id AS (
    -- Get profile's primary department
    SELECT 
        pd.department_id as resolved_department_id
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id
    WHERE pd.is_primary = TRUE 
      AND pd.active = true
    LIMIT 1
),
dept_specific_settings AS (
    -- Get department-specific settings (if profile has a department)
    SELECT s.id as settings_id
    FROM settings s
    JOIN department_settings sd ON sd.settings_id = s.id
    JOIN resolve_department_id rdi ON sd.department_id = rdi.resolved_department_id
    WHERE rdi.resolved_department_id IS NOT NULL
      AND s.active = true 
      AND sd.active = true
    LIMIT 1
),
selected_settings AS (
    -- Priority: department-specific settings, then default, then any active
    SELECT 
        COALESCE(
            (SELECT settings_id FROM dept_specific_settings),
            (SELECT settings_id FROM default_settings),
            (SELECT id FROM settings WHERE active = true LIMIT 1)
        ) as settings_id
)
SELECT 
    d.name::text as document_name,
    ap.actor_name::text as actor_name,
    u.file_path::text as file_path,
    dt.schema_id,
    -- Settings fields
    s.primary_color::text as settings_primary_color,
    s.accent::text as settings_accent,
    s.background::text as settings_background,
    s.surface::text as settings_surface,
    s.success::text as settings_success,
    s.warning::text as settings_warning,
    s.error::text as settings_error,
    s.sidebar_background::text as settings_sidebar_background,
    s.sidebar_primary::text as settings_sidebar_primary,
    s.chart1::text as settings_chart1,
    s.chart2::text as settings_chart2,
    s.chart3::text as settings_chart3,
    s.chart4::text as settings_chart4,
    s.chart5::text as settings_chart5
FROM params x
JOIN documents d ON d.id = x.document_id
INNER JOIN document_templates dt ON dt.document_id = d.id AND dt.active = true
INNER JOIN html h ON h.id = dt.html_id
INNER JOIN html_uploads hu ON hu.html_id = h.id AND hu.active = true
INNER JOIN uploads u ON u.id = hu.upload_id
CROSS JOIN actor_profile ap
CROSS JOIN selected_settings ss
LEFT JOIN settings s ON s.id = ss.settings_id
ORDER BY dt.created_at DESC
LIMIT 1
$$;


--
-- Name: api_resolve_feedback_v4(uuid, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_resolve_feedback_v4(feedback_id uuid, resolved boolean) RETURNS TABLE(id uuid, resolved boolean)
    LANGUAGE sql
    AS $$
UPDATE feedback
SET resolved = api_resolve_feedback_v4.resolved
WHERE id = feedback_id
RETURNING id, resolved
$$;


--
-- Name: api_save_question_timestamps_v4(uuid, uuid, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_save_question_timestamps_v4(scenario_id uuid, video_id uuid, question_timestamps jsonb) RETURNS TABLE(inserted_count integer)
    LANGUAGE sql
    AS $$
WITH deactivate_timestamps AS (
    UPDATE scenario_question_times
    SET active = false, updated_at = NOW()
    WHERE scenario_id = api_save_question_timestamps_v4.scenario_id 
      AND video_id = api_save_question_timestamps_v4.video_id
),
insert_timestamps AS (
    INSERT INTO scenario_question_times (scenario_id, question_id, video_id, time, active, created_at, updated_at)
    SELECT 
        scenario_id,
        (q_entry.key)::uuid,
        video_id,
        time_val::integer,
        true,
        NOW(),
        NOW()
    FROM jsonb_each(COALESCE(question_timestamps, '{}'::jsonb)) as q_entry
    CROSS JOIN jsonb_array_elements_text(q_entry.value) as time_val
    WHERE question_timestamps IS NOT NULL
    AND jsonb_typeof(question_timestamps) = 'object'
    ON CONFLICT (scenario_id, question_id, video_id, time) DO UPDATE SET
        active = true,
        updated_at = NOW()
    RETURNING 1
)
SELECT COUNT(*)::int as inserted_count FROM insert_timestamps
$$;


--
-- Name: api_search_simulatable_profiles_v4(uuid, integer, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_search_simulatable_profiles_v4(profile_id uuid, limit_count integer, query text) RETURNS TABLE(actor_name text, profiles types.q_search_simulatable_profiles_v4_profile[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        profile_id AS profile_id,
        limit_count AS limit_count,
        query AS query
),
requester_profile AS (
    SELECT 
        role,
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM profiles p
    WHERE p.id = (SELECT profile_id FROM params)
),
requester_role AS (
    SELECT role FROM requester_profile
),
simulatable_data AS (
    SELECT 
        p.id,
        p.first_name,
        p.last_name,
        ARRAY_AGG(pe.email ORDER BY pe.is_primary DESC, pe.created_at) FILTER (WHERE pe.active = true) as emails,
        (SELECT email FROM profile_emails WHERE profile_id = p.id AND is_primary = true AND active = true LIMIT 1) as primary_email,
        p.role,
        p.active,
        COALESCE(prl.requests_per_day, 0) as req_per_day,
        p.last_login,
        pa.last_active,
        p.created_at,
        p.updated_at,
        pd.department_id as primary_department_id
    FROM profiles p
    CROSS JOIN requester_role rr
    LEFT JOIN profile_emails pe ON pe.profile_id = p.id AND pe.active = true
    LEFT JOIN profile_departments pd ON p.id = pd.profile_id AND pd.is_primary = TRUE
    LEFT JOIN profile_request_limits prl ON prl.profile_id = p.id AND prl.active = true
    LEFT JOIN LATERAL (
        SELECT last_active 
        FROM profile_activity 
        WHERE profile_id = p.id 
        ORDER BY created_at DESC 
        LIMIT 1
    ) pa ON true
    WHERE p.id != (SELECT profile_id FROM params)
      AND CASE 
        WHEN rr.role = 'superadmin'::profile_role THEN true
        WHEN rr.role = 'admin'::profile_role THEN p.role IN ('instructional'::profile_role, 'member'::profile_role, 'guest'::profile_role)
        WHEN rr.role = 'instructional'::profile_role THEN p.role IN ('member'::profile_role, 'guest'::profile_role)
        ELSE false
      END
      AND ((SELECT query FROM params) IS NULL OR (SELECT query FROM params) = '' OR (p.first_name ILIKE '%' || (SELECT query FROM params) || '%' OR p.last_name ILIKE '%' || (SELECT query FROM params) || '%' OR EXISTS (SELECT 1 FROM profile_emails pe WHERE pe.profile_id = p.id AND pe.active = true AND pe.email ILIKE '%' || (SELECT query FROM params) || '%') OR p.role::text ILIKE '%' || (SELECT query FROM params) || '%' OR (p.first_name || ' ' || p.last_name) ILIKE '%' || (SELECT query FROM params) || '%'))
    GROUP BY p.id, p.first_name, p.last_name, p.role, p.active, 
             prl.requests_per_day, p.last_login, pa.last_active, 
             p.created_at, p.updated_at, pd.department_id
    ORDER BY p.first_name, p.last_name
    LIMIT (SELECT limit_count FROM params)
)
SELECT 
    (SELECT actor_name FROM requester_profile)::text as actor_name,
    COALESCE(
        ARRAY_AGG(
            (sp.id, sp.first_name, sp.last_name, COALESCE(sp.emails, ARRAY[]::text[]), sp.primary_email, sp.role, sp.active, sp.req_per_day, sp.last_login, sp.last_active, sp.created_at, sp.updated_at, sp.primary_department_id)::types.q_search_simulatable_profiles_v4_profile
            ORDER BY sp.first_name, sp.last_name
        ),
        '{}'::types.q_search_simulatable_profiles_v4_profile[]
    ) as profiles
FROM simulatable_data sp
$$;


--
-- Name: api_search_staff_v4(text, uuid, uuid[], uuid[], integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_search_staff_v4(query text, profile_id uuid, cohort_ids uuid[], department_ids uuid[], limit_count integer DEFAULT 200) RETURNS TABLE(actor_name text, staff types.q_search_staff_v4_staff[], cohorts types.q_search_staff_v4_cohort[], departments types.q_search_staff_v4_department[])
    LANGUAGE sql STABLE
    AS $$
WITH params AS (
    SELECT 
        COALESCE(NULLIF(TRIM(query), ''), NULL) AS query,
        profile_id AS profile_id,
        COALESCE(cohort_ids, ARRAY[]::uuid[]) AS cohort_ids,
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids,
        COALESCE(limit_count, 200) AS limit_count
),
user_profile AS (
    SELECT 
        COALESCE((SELECT role FROM profiles WHERE id = (SELECT profile_id FROM params)), 'guest') as role,
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
user_departments AS (
    SELECT department_id
    FROM params x
    JOIN profile_departments ON profile_departments.profile_id = x.profile_id AND profile_departments.active = true
),
profile_cohorts AS (
    SELECT
        cp.profile_id,
        ARRAY_AGG(cp.cohort_id::text ORDER BY c.title) as cohort_ids
    FROM cohort_profiles cp
    JOIN cohorts c ON c.id = cp.cohort_id
    WHERE cp.active = true
    GROUP BY cp.profile_id
),
profile_departments_agg AS (
    SELECT
        pd.profile_id,
        ARRAY_AGG(pd.department_id::text ORDER BY d.title) as department_ids
    FROM profile_departments pd
    JOIN departments d ON d.id = pd.department_id
    WHERE pd.active = true
    GROUP BY pd.profile_id
),
recent_runs AS (
    SELECT
        rp.profile_id,
        COUNT(*) as run_count
    FROM runs r
    JOIN run_profiles rp ON rp.run_id = r.id AND rp.active = true
    WHERE r.created_at >= NOW() - INTERVAL '24 hours'
    GROUP BY rp.profile_id
),
profile_total_runs AS (
    SELECT
        rp.profile_id,
        COUNT(*) as total_requests
    FROM run_profiles rp
    WHERE rp.active = true
    GROUP BY rp.profile_id
),
all_cohort_ids AS (
    SELECT DISTINCT c.id as cohort_id
    FROM cohorts c
    WHERE c.active = true
),
cohorts_data AS (
    SELECT 
        c.id as cohort_id,
        c.title as name,
        COALESCE(c.description, '') as description
    FROM cohorts c
    WHERE c.id IN (SELECT cohort_id FROM all_cohort_ids)
),
departments_data AS (
    SELECT 
        d.id as department_id,
        d.title as name,
        COALESCE(d.description, '') as description
    FROM departments d
    WHERE d.active = true
),
staff_rows AS (
    SELECT DISTINCT ON (p.id)
        p.id as profile_id,
        p.first_name,
        p.last_name,
        COALESCE(
            ARRAY(
                SELECT email FROM (
                    SELECT DISTINCT ON (pe2.email) 
                        pe2.email,
                        pe2.is_primary,
                        pe2.created_at
                    FROM profile_emails pe2 
                    WHERE pe2.profile_id = p.id AND pe2.active = true 
                    ORDER BY pe2.email, pe2.is_primary DESC, pe2.created_at
                ) distinct_emails
                ORDER BY is_primary DESC, created_at
            ),
            ARRAY[]::text[]
        ) as emails,
        (SELECT email FROM profile_emails WHERE profile_id = p.id AND is_primary = true AND active = true LIMIT 1) as primary_email,
        p.first_name || ' ' || p.last_name as name,
        p.role,
        SUBSTRING(p.first_name FROM 1 FOR 1) || SUBSTRING(p.last_name FROM 1 FOR 1) as initials,
        p.active,
        pa.last_active,
        COALESCE(
            ARRAY(SELECT unnest(pc.cohort_ids)::text),
            ARRAY[]::text[]
        ) as cohort_ids,
        COALESCE(
            ARRAY(SELECT unnest(pda.department_ids)::text),
            ARRAY[]::text[]
        ) as department_ids,
        COALESCE((SELECT pd2.department_id::text FROM profile_departments pd2 WHERE pd2.profile_id = p.id AND pd2.active = true AND pd2.is_primary = true LIMIT 1), '') as primary_department_id,
        prl.requests_per_day,
        COALESCE(ptr.total_requests, 0) as total_requests,
        COALESCE(rr.run_count::int, 0) as requests_in_last_day
    FROM profiles p
    JOIN profile_departments pd ON pd.profile_id = p.id AND pd.active = true
    LEFT JOIN profile_emails pe ON pe.profile_id = p.id AND pe.active = true
    LEFT JOIN profile_cohorts pc ON pc.profile_id = p.id
    LEFT JOIN profile_departments_agg pda ON pda.profile_id = p.id
    LEFT JOIN profile_total_runs ptr ON ptr.profile_id = p.id
    LEFT JOIN recent_runs rr ON rr.profile_id = p.id
    LEFT JOIN profile_request_limits prl ON prl.profile_id = p.id AND prl.active = true
    LEFT JOIN LATERAL (
        SELECT last_active
        FROM profile_activity
        WHERE profile_id = p.id
        ORDER BY created_at DESC
        LIMIT 1
    ) pa ON true
    CROSS JOIN user_profile up
    WHERE (
        -- Superadmin sees all staff
        up.role = 'superadmin'::profile_role
        OR
        -- For search, show all staff with active departments
        true
    )
    AND (
        -- Search query filter (if provided)
        (SELECT query FROM params) IS NULL
        OR (
            p.first_name ILIKE '%' || (SELECT query FROM params) || '%'
            OR p.last_name ILIKE '%' || (SELECT query FROM params) || '%'
            OR EXISTS (
                SELECT 1 FROM profile_emails pe_search 
                WHERE pe_search.profile_id = p.id 
                AND pe_search.active = true 
                AND pe_search.email ILIKE '%' || (SELECT query FROM params) || '%'
            )
            OR p.role::text ILIKE '%' || (SELECT query FROM params) || '%'
            OR (p.first_name || ' ' || p.last_name) ILIKE '%' || (SELECT query FROM params) || '%'
        )
    )
    AND (
        -- Cohort exclusion filter (if provided)
        (SELECT array_length(cohort_ids, 1) FROM params) IS NULL
        OR (SELECT array_length(cohort_ids, 1) FROM params) = 0
        OR NOT EXISTS (
            SELECT 1 FROM cohort_profiles cp_exclude 
            WHERE cp_exclude.profile_id = p.id 
            AND cp_exclude.cohort_id = ANY((SELECT cohort_ids FROM params)::uuid[])
            AND cp_exclude.active = true
        )
    )
    AND (
        -- Department exclusion filter (if provided)
        (SELECT array_length(department_ids, 1) FROM params) IS NULL
        OR (SELECT array_length(department_ids, 1) FROM params) = 0
        OR NOT EXISTS (
            SELECT 1 FROM profile_departments pd_exclude 
            WHERE pd_exclude.profile_id = p.id 
            AND pd_exclude.department_id = ANY((SELECT department_ids FROM params)::uuid[])
            AND pd_exclude.active = true
        )
    )
    GROUP BY p.id, p.first_name, p.last_name, p.role, p.active,
             pa.last_active, prl.requests_per_day, pc.cohort_ids, pda.department_ids,
             ptr.total_requests, rr.run_count
    ORDER BY p.id, p.last_name, p.first_name
    LIMIT (SELECT limit_count FROM params)
)
SELECT 
    up.actor_name::text as actor_name,
    COALESCE(
        (SELECT ARRAY_AGG(
            (sr.profile_id, sr.first_name, sr.last_name, sr.emails, sr.primary_email, sr.name, sr.role, sr.initials, sr.active, sr.last_active, sr.cohort_ids, sr.department_ids, sr.primary_department_id, sr.requests_per_day, sr.total_requests, sr.requests_in_last_day, false, false)::types.q_search_staff_v4_staff
            ORDER BY sr.last_name, sr.first_name
        )
        FROM staff_rows sr),
        '{}'::types.q_search_staff_v4_staff[]
    ) as staff,
    COALESCE(
        (SELECT ARRAY_AGG(
            (cd.cohort_id, cd.name, cd.description)::types.q_search_staff_v4_cohort
            ORDER BY cd.name
        )
        FROM cohorts_data cd),
        '{}'::types.q_search_staff_v4_cohort[]
    ) as cohorts,
    COALESCE(
        (SELECT ARRAY_AGG(
            (dd.department_id, dd.name, dd.description)::types.q_search_staff_v4_department
            ORDER BY dd.name
        )
        FROM departments_data dd),
        '{}'::types.q_search_staff_v4_department[]
    ) as departments
FROM user_profile up
$$;


--
-- Name: api_simulation_text_stop_run_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_simulation_text_stop_run_v4(chat_id uuid) RETURNS TABLE(success boolean, cancelled_message_id uuid, final_content text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT api_simulation_text_stop_run_v4.chat_id as chat_id
),
latest_message AS (
    SELECT
        m.id,
        COALESCE(cnt.content, '') as content
    FROM chats c
    JOIN chat_groups cg ON cg.chat_id = c.id
    JOIN groups g ON g.id = cg.group_id
    JOIN group_runs gr ON gr.group_id = g.id
    JOIN runs r ON r.id = gr.run_id
    JOIN message_runs mr ON mr.run_id = r.id
    JOIN messages m ON m.id = mr.message_id
    LEFT JOIN message_content mc ON mc.message_id = m.id AND mc.idx = 0
        LEFT JOIN content cnt ON cnt.id = mc.content_id
    WHERE c.id = (SELECT chat_id FROM params)
      AND NOT EXISTS (
          SELECT 1 FROM message_tree mt
          WHERE mt.parent_id = m.id AND mt.active = true
      )
    ORDER BY m.created_at DESC
    LIMIT 1
),
update_message AS (
    UPDATE messages
    SET completed = TRUE,
        updated_at = NOW()
    WHERE id = (SELECT id FROM latest_message)
    RETURNING id
)
SELECT
    (SELECT id FROM update_message) IS NOT NULL as success,
    (SELECT id FROM update_message) as cancelled_message_id,
    (SELECT content FROM latest_message) as final_content
$$;


--
-- Name: api_start_benchmark_attempt_v4(uuid, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_start_benchmark_attempt_v4(eval_id uuid, infinite_mode boolean) RETURNS TABLE(attempt_id text, eval_id text, agent_ids text[], dynamic boolean, infinite_mode boolean, use_groups boolean, pending_run_ids uuid[], pending_group_ids uuid[])
    LANGUAGE sql
    AS $$
WITH new_attempt AS (
    INSERT INTO eval_attempts (eval_id, created_at, infinite_mode)
    VALUES (api_start_benchmark_attempt_v4.eval_id, NOW(), COALESCE(api_start_benchmark_attempt_v4.infinite_mode, false))
    RETURNING id as attempt_id, infinite_mode
),
eval_data AS (
    SELECT 
        e.id as eval_id,
        e.dynamic,
        e.use_groups
    FROM evals e
    WHERE e.id = api_start_benchmark_attempt_v4.eval_id
),
eval_agents_data AS (
    SELECT 
        ARRAY_AGG(ea.agent_id::text ORDER BY ea.created_at) as agent_ids
    FROM eval_agents ea
    WHERE ea.eval_id = api_start_benchmark_attempt_v4.eval_id
),
pending_runs AS (
    SELECT ARRAY_AGG(er.run_id::uuid) FILTER (WHERE er.completed = false) as pending_run_ids
    FROM eval_runs er
    WHERE er.eval_id = api_start_benchmark_attempt_v4.eval_id AND er.completed = false
),
pending_groups AS (
    SELECT ARRAY_AGG(eg.group_id::uuid) FILTER (WHERE NOT EXISTS (SELECT 1 FROM grade_groups gg WHERE gg.group_id = eg.group_id)) as pending_group_ids
    FROM eval_groups eg
    WHERE eg.eval_id = api_start_benchmark_attempt_v4.eval_id
      AND NOT EXISTS (SELECT 1 FROM grade_groups gg WHERE gg.group_id = eg.group_id)
)
SELECT 
    na.attempt_id::text,
    ed.eval_id::text,
    COALESCE(ead.agent_ids, ARRAY[]::text[]) as agent_ids,
    ed.dynamic,
    na.infinite_mode,
    ed.use_groups,
    COALESCE(pr.pending_run_ids, ARRAY[]::uuid[]) as pending_run_ids,
    COALESCE(pg.pending_group_ids, ARRAY[]::uuid[]) as pending_group_ids
FROM new_attempt na
CROSS JOIN eval_data ed
LEFT JOIN eval_agents_data ead ON true
LEFT JOIN pending_runs pr ON true
LEFT JOIN pending_groups pg ON true
$$;


--
-- Name: api_text_complete_finalize_v4(uuid, uuid, uuid, text, uuid, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_text_complete_finalize_v4(chat_id uuid, run_id uuid, tool_call_id uuid, call_id text, message_id uuid, final_content text, persona_id uuid) RETURNS TABLE(message_id text, final_content text, completed boolean)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        api_text_complete_finalize_v4.chat_id as chat_id,
        api_text_complete_finalize_v4.run_id as run_id,
        api_text_complete_finalize_v4.tool_call_id as tool_call_id,
        api_text_complete_finalize_v4.call_id as call_id,
        api_text_complete_finalize_v4.message_id as message_id,
        api_text_complete_finalize_v4.final_content as final_content,
        api_text_complete_finalize_v4.persona_id as persona_id
),
-- Get tool call if tool_call_id or call_id provided
get_tool_call AS (
    SELECT tc.id as tool_call_id
    FROM params p
    JOIN calls tc ON (
        (p.tool_call_id IS NOT NULL AND tc.id = p.tool_call_id)
        OR (p.call_id IS NOT NULL AND tc.call_id = p.call_id)
    )
    LIMIT 1
),
-- Finalize tool call
finalize_tool_call AS (
    UPDATE calls
    SET completed = true,
        updated_at = NOW()
    FROM get_tool_call gtc
    WHERE calls.id = gtc.tool_call_id
    RETURNING id as tool_call_id
),
-- Get message from tool_call or use provided message_id
get_message_from_tool_call AS (
    SELECT DISTINCT ON (m.id) m.id as message_id
    FROM get_tool_call gtc
    JOIN tool_call_runs tcr ON tcr.tool_call_id = gtc.tool_call_id
    JOIN message_runs mr ON mr.run_id = tcr.run_id
    JOIN messages m ON m.id = mr.message_id
    WHERE m.role = 'assistant'::message_role
    ORDER BY m.id, m.created_at DESC
    LIMIT 1
),
selected_message AS (
    SELECT message_id FROM get_message_from_tool_call
    WHERE EXISTS (SELECT 1 FROM get_tool_call)
    UNION ALL
    SELECT message_id FROM params
    WHERE message_id IS NOT NULL
),
-- Update message content with final content
update_message_content_final AS (
    UPDATE content
    SET content = p.final_content,
        updated_at = NOW()
    FROM params p,
         message_content mc
    WHERE mc.content_id = content.id
      AND mc.message_id = (SELECT message_id FROM selected_message LIMIT 1)
      AND mc.idx = 0
),
-- Mark message as completed
complete_message AS (
    UPDATE messages
    SET completed = true,
        updated_at = NOW()
    WHERE id = (SELECT message_id FROM selected_message LIMIT 1)
    RETURNING id as message_id, completed
),
-- Link message to persona if provided
link_message_to_persona AS (
    INSERT INTO message_personas (message_id, persona_id, created_at, updated_at)
    SELECT 
        (SELECT message_id FROM selected_message LIMIT 1),
        p.persona_id,
        NOW(),
        NOW()
    FROM params p
    WHERE p.persona_id IS NOT NULL
      AND NOT EXISTS (
          SELECT 1 FROM message_personas mp 
          WHERE mp.message_id = (SELECT message_id FROM selected_message LIMIT 1)
          AND mp.persona_id = p.persona_id
      )
)
SELECT 
    (SELECT message_id FROM selected_message LIMIT 1)::text as message_id,
    (SELECT final_content FROM params LIMIT 1) as final_content,
    (SELECT completed FROM complete_message LIMIT 1) as completed
$$;


--
-- Name: api_update_agent_v4(uuid, text, text, uuid, boolean, public.agent_role, uuid, uuid, text, text[], text[], uuid, uuid, text[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_update_agent_v4(agent_id uuid, name text, description text, model_id uuid, active boolean, role public.agent_role, profile_id uuid, prompt_id uuid DEFAULT NULL::uuid, system_prompt text DEFAULT NULL::text, department_ids text[] DEFAULT ARRAY[]::text[], department_ids_for_prompt text[] DEFAULT ARRAY[]::text[], model_temperature_level_id uuid DEFAULT NULL::uuid, model_reasoning_level_id uuid DEFAULT NULL::uuid, model_voice_ids text[] DEFAULT ARRAY[]::text[]) RETURNS TABLE(agent_id text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT
        agent_id AS agent_id,
        name AS name,
        description AS description,
        model_id AS model_id,
        active AS active,
        role AS role,
        prompt_id AS prompt_id,
        NULLIF(system_prompt, '') AS system_prompt,
        COALESCE(department_ids, ARRAY[]::text[]) AS department_ids,
        COALESCE(department_ids_for_prompt, ARRAY[]::text[]) AS department_ids_for_prompt,
        model_temperature_level_id AS model_temperature_level_id,
        model_reasoning_level_id AS model_reasoning_level_id,
        COALESCE(model_voice_ids, ARRAY[]::text[]) AS model_voice_ids,
        profile_id AS profile_id
),
user_profile AS (
    SELECT 
        p.role,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
object_current_departments AS (
    -- Get agent's current active department links
    SELECT COALESCE(ARRAY_AGG(department_id::text), ARRAY[]::text[]) as department_ids
    FROM params x
    JOIN agent_departments ON agent_departments.agent_id = x.agent_id AND agent_departments.active = true
),
user_departments AS (
    -- Get user's departments
    SELECT COALESCE(ARRAY_AGG(department_id::text), ARRAY[]::text[]) as department_ids
    FROM params x
    JOIN profile_departments ON profile_departments.profile_id = x.profile_id AND profile_departments.active = true
),
validate_update_permissions AS (
    -- Validate department permissions for update operation
    SELECT validate_department_update_permissions(
        up.role::text,
        ocd.department_ids,
        ud.department_ids
    ) as validation_passed
    FROM user_profile up
    CROSS JOIN object_current_departments ocd
    CROSS JOIN user_departments ud
),
actor_profile AS (
    SELECT 
        x.profile_id as resolved_profile_id,
        up.actor_name
    FROM params x
    CROSS JOIN user_profile up
),
update_agent AS (
    UPDATE agents
    SET 
        name = x.name,
        description = x.description,
        model_id = x.model_id,
        active = x.active,
        role = x.role,
        updated_at = NOW()
    FROM params x
    WHERE agents.id = x.agent_id
    RETURNING agents.id::text as agent_id
),
new_prompt AS (
    -- Create prompt only if system_prompt provided and prompt_id not provided
    INSERT INTO prompts (system_prompt, created_at, updated_at)
    SELECT x.system_prompt, NOW(), NOW()
    FROM params x
    WHERE x.prompt_id IS NULL AND x.system_prompt IS NOT NULL AND x.system_prompt != ''
    RETURNING id::text as prompt_id
),
selected_prompt_id AS (
    -- Use provided prompt_id or newly created prompt_id (only return row if prompt exists)
    SELECT COALESCE(
        x.prompt_id::text,
        (SELECT prompt_id FROM new_prompt LIMIT 1)
    ) as prompt_id
    FROM params x
    WHERE x.prompt_id IS NOT NULL OR EXISTS (SELECT 1 FROM new_prompt)
),
deactivate_department_prompts AS (
    -- Deactivate existing department-specific prompts for departments in the array
    UPDATE agent_department_prompts
    SET active = false, updated_at = NOW()
    FROM params x
    WHERE agent_department_prompts.agent_id = x.agent_id 
    AND agent_department_prompts.department_id = ANY(SELECT dept_id::uuid FROM UNNEST(x.department_ids_for_prompt) as dept_id)
    AND agent_department_prompts.active = true
    RETURNING agent_department_prompts.agent_id
),
handle_department_prompts AS (
    -- Handle department-specific prompts for all departments in array (never create default prompts)
    INSERT INTO agent_department_prompts (agent_id, department_id, prompt_id, active, created_at, updated_at)
    SELECT x.agent_id, dept_id::uuid, sp.prompt_id::uuid, true, NOW(), NOW()
    FROM params x
    CROSS JOIN selected_prompt_id sp
    CROSS JOIN UNNEST(x.department_ids_for_prompt) as dept_id
    WHERE COALESCE(array_length(x.department_ids_for_prompt, 1), 0) > 0 AND sp.prompt_id IS NOT NULL
    ON CONFLICT (agent_id, department_id, prompt_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
get_default_prompt_content AS (
    -- Get the default prompt content for comparison (for pruning)
    SELECT pr.system_prompt
    FROM params x
    JOIN agent_prompts ap ON ap.agent_id = x.agent_id AND ap.active = true
    JOIN prompts pr ON pr.id = ap.prompt_id
    LIMIT 1
),
prune_duplicate_prompts AS (
    -- Prune department-specific prompts that match the default prompt content
    DELETE FROM agent_department_prompts adp
    USING params x
    WHERE adp.agent_id = x.agent_id
    AND adp.department_id = ANY(SELECT dept_id::uuid FROM UNNEST(x.department_ids_for_prompt) as dept_id)
    AND EXISTS (
        SELECT 1 FROM get_default_prompt_content gdc
        JOIN selected_prompt_id sp ON sp.prompt_id IS NOT NULL
        JOIN prompts pr ON pr.id = sp.prompt_id::uuid
        WHERE pr.system_prompt = gdc.system_prompt
    )
    RETURNING adp.agent_id
),
replace_departments AS (
    -- Delete all existing department links
    DELETE FROM agent_departments
    USING params x
    WHERE agent_departments.agent_id = x.agent_id
),
link_departments AS (
    -- Insert new department links if provided (array is never NULL, but may be empty)
    INSERT INTO agent_departments (agent_id, department_id, active, created_at, updated_at)
    SELECT 
        x.agent_id,
        dept_id::uuid,
        true,
        NOW(),
        NOW()
    FROM params x
    CROSS JOIN UNNEST(x.department_ids) as dept_id
    WHERE COALESCE(array_length(x.department_ids, 1), 0) > 0
    ON CONFLICT (agent_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
deactivate_temperature_levels AS (
    -- Deactivate existing temperature levels if model_temperature_level_id is provided
    UPDATE agent_temperature_levels
    SET active = false, updated_at = NOW()
    FROM params x
    WHERE agent_temperature_levels.agent_id = x.agent_id
    AND x.model_temperature_level_id IS NOT NULL
    RETURNING agent_temperature_levels.agent_id
),
update_temperature_level AS (
    -- Insert or update temperature level if model_temperature_level_id is provided
    INSERT INTO agent_temperature_levels (agent_id, model_temperature_level_id, active, created_at, updated_at)
    SELECT x.agent_id, x.model_temperature_level_id, true, NOW(), NOW()
    FROM params x
    WHERE x.model_temperature_level_id IS NOT NULL
    ON CONFLICT (agent_id, model_temperature_level_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
    RETURNING agent_temperature_levels.agent_id
),
deactivate_reasoning_levels AS (
    -- Deactivate existing reasoning levels if model_reasoning_level_id is provided
    UPDATE agent_reasoning_levels
    SET active = false, updated_at = NOW()
    FROM params x
    WHERE agent_reasoning_levels.agent_id = x.agent_id
    AND x.model_reasoning_level_id IS NOT NULL
    RETURNING agent_reasoning_levels.agent_id
),
update_reasoning_level AS (
    -- Insert or update reasoning level if model_reasoning_level_id is provided
    INSERT INTO agent_reasoning_levels (agent_id, model_reasoning_level_id, active, created_at, updated_at)
    SELECT x.agent_id, x.model_reasoning_level_id, true, NOW(), NOW()
    FROM params x
    WHERE x.model_reasoning_level_id IS NOT NULL
    ON CONFLICT (agent_id, model_reasoning_level_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
    RETURNING agent_reasoning_levels.agent_id
),
deactivate_voices AS (
    -- Deactivate existing voices if model_voice_ids is provided
    UPDATE agent_voices
    SET active = false, updated_at = NOW()
    FROM params x
    WHERE agent_voices.agent_id = x.agent_id
    AND COALESCE(array_length(x.model_voice_ids, 1), 0) > 0
    RETURNING agent_voices.agent_id
),
update_voices AS (
    -- Insert or update voices if model_voice_ids is provided
    INSERT INTO agent_voices (agent_id, model_voice_id, active, created_at, updated_at)
    SELECT x.agent_id, voice_id::uuid, true, NOW(), NOW()
    FROM params x
    CROSS JOIN UNNEST(x.model_voice_ids) as voice_id
    WHERE COALESCE(array_length(x.model_voice_ids, 1), 0) > 0
    ON CONFLICT (agent_id, model_voice_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
    RETURNING agent_voices.agent_id
)
SELECT 
    ua.agent_id,
    ap.actor_name
FROM update_agent ua
CROSS JOIN actor_profile ap
CROSS JOIN validate_update_permissions vup
WHERE vup.validation_passed = true
$$;


--
-- Name: api_update_auth_v4(uuid, text, text, boolean, text, text, uuid, types.i_update_auth_v4_auth_item[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_update_auth_v4(auth_id uuid, name text, description text, active boolean, auth_type text, slug text, profile_id uuid, auth_items types.i_update_auth_v4_auth_item[] DEFAULT ARRAY[]::types.i_update_auth_v4_auth_item[]) RETURNS TABLE(auth_exists boolean, success boolean, name text, message text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT
        auth_id AS auth_id,
        name AS name,
        description AS description,
        active AS active,
        auth_type AS auth_type,
        COALESCE(NULLIF(slug, ''), lower(replace(name, ' ', '-'))) AS slug,
        profile_id AS profile_id,
        COALESCE(auth_items, ARRAY[]::types.i_update_auth_v4_auth_item[]) AS auth_items
),
auth_exists_check AS (
    -- Check if auth exists independently of access control
    SELECT EXISTS(
        SELECT 1 FROM auth WHERE id = (SELECT auth_id FROM params)
    )::boolean as auth_exists
),
actor_profile AS (
    SELECT 
        x.profile_id as profile_id,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
auth_id_resolved AS (
    SELECT x.auth_id as auth_id
    FROM params x
),
delete_existing_keys AS (
    -- NOTE: auth_item_keys table was removed in migration 74
    -- Keys are now linked through settings (setting_auth_keys, setting_provider_keys)
    -- This CTE is kept for compatibility but does nothing
    SELECT 1 WHERE false
),
delete_existing_values AS (
    -- NOTE: auth_item_values table was removed in migration 74
    -- Values are now managed through settings (setting_auth_values)
    -- This CTE is kept for compatibility but does nothing
    SELECT 1 WHERE false
),
delete_existing_items AS (
    -- Delete all existing auth items (cascade will handle keys/values)
    DELETE FROM auth_items
    WHERE auth_id = (SELECT auth_id FROM auth_id_resolved)
    RETURNING id
),
update_auth AS (
    -- Update auth entry
    UPDATE auth
    SET 
        name = (SELECT name FROM params),
        description = (SELECT description FROM params),
        active = (SELECT active FROM params),
        auth_type = (SELECT auth_type FROM params),
        slug = (SELECT slug FROM params),
        updated_at = NOW()
    WHERE id = (SELECT auth_id FROM auth_id_resolved)
    RETURNING id as auth_id
),
items_expanded AS (
    -- Expand composite type array
    SELECT 
        item.name as item_name,
        item.description as item_description,
        COALESCE(item.encrypted, true) as item_encrypted,
        COALESCE(item.position, row_number() OVER ()) as item_position,
        COALESCE(item.active, true) as item_active,
        item.key_id as item_key_id
    FROM params x
    CROSS JOIN LATERAL unnest(x.auth_items) AS item
),
new_items AS (
    -- Create all auth items (without value column - dropped in migration)
    INSERT INTO auth_items (
        auth_id,
        name,
        description,
        encrypted,
        position,
        active
    )
    SELECT 
        ua.auth_id,
        ie.item_name,
        ie.item_description,
        ie.item_encrypted,
        ie.item_position,
        ie.item_active
    FROM update_auth ua
    CROSS JOIN items_expanded ie
    RETURNING id as item_id, encrypted
),
link_encrypted_keys AS (
    -- NOTE: auth_item_keys table was removed in migration 74
    -- Keys are now linked through settings (setting_auth_keys, setting_provider_keys)
    -- This CTE is kept for compatibility but does nothing
    SELECT 1 WHERE false
)
SELECT 
    aec.auth_exists::boolean as auth_exists,
    aec.auth_exists::boolean as success,
    x.name::text as name,
    (x.name || ' updated successfully')::text as message,
    ap.actor_name::text as actor_name
FROM auth_exists_check aec
CROSS JOIN actor_profile ap
CROSS JOIN params x
$$;


--
-- Name: api_update_chat_completed_v4(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_update_chat_completed_v4(chat_id uuid) RETURNS TABLE(id uuid, completed boolean)
    LANGUAGE sql
    AS $$
UPDATE chats 
SET completed = true 
WHERE id = chat_id
RETURNING id, completed
$$;


--
-- Name: api_update_chat_created_at_v4(timestamp with time zone, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_update_chat_created_at_v4(created_at timestamp with time zone, chat_id uuid) RETURNS TABLE(chat_id text)
    LANGUAGE sql
    AS $$
WITH chat_exists AS (
    -- Check if chat exists
    SELECT id
    FROM chats
    WHERE chats.id = api_update_chat_created_at_v4.chat_id
),
update_chat AS (
    -- Update the createdAt timestamp only if chat exists
    UPDATE chats
    SET created_at = api_update_chat_created_at_v4.created_at,
        updated_at = NOW()
    WHERE id IN (SELECT id FROM chat_exists)
    RETURNING id::text as chat_id
)
SELECT chat_id FROM update_chat
$$;


--
-- Name: api_update_cohort_v4(uuid, text, text, boolean, text[], text[], text[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_update_cohort_v4(cohort_id uuid, title text, description text, active boolean, department_ids text[], profile_ids text[], simulation_ids text[], profile_id uuid) RETURNS TABLE(id text, title text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT
        cohort_id AS cohort_id,
        title AS title,
        COALESCE(NULLIF(description, ''), '') AS description,
        active AS active,
        COALESCE(department_ids, ARRAY[]::text[]) AS department_ids,
        COALESCE(profile_ids, ARRAY[]::text[]) AS profile_ids,
        COALESCE(simulation_ids, ARRAY[]::text[]) AS simulation_ids,
        profile_id AS profile_id
),
actor_profile AS (
    SELECT 
        x.profile_id AS profile_id,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
cohort_update AS (
    -- Update cohort
    UPDATE cohorts c SET
        title = x.title,
        description = x.description,
        active = x.active,
        updated_at = NOW()
    FROM params x
    WHERE c.id = x.cohort_id
    RETURNING c.id, c.title
),
delete_departments AS (
    -- Delete existing department relationships
    DELETE FROM cohort_departments cd
    USING params x
    WHERE cd.cohort_id = x.cohort_id
),
link_departments AS (
    -- Link new departments if provided
    INSERT INTO cohort_departments (cohort_id, department_id, active, created_at, updated_at)
    SELECT 
        cu.id,
        dept_id::uuid,
        true,
        NOW(),
        NOW()
    FROM cohort_update cu
    CROSS JOIN params x
    CROSS JOIN UNNEST(x.department_ids) as dept_id
    WHERE COALESCE(array_length(x.department_ids, 1), 0) > 0
    ON CONFLICT (cohort_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
deactivate_profiles AS (
    -- Deactivate existing profile relationships not in the new list
    UPDATE cohort_profiles cp
    SET active = false, updated_at = NOW()
    FROM params x
    WHERE cp.cohort_id = x.cohort_id
      AND COALESCE(array_length(x.profile_ids, 1), 0) > 0
      AND cp.profile_id NOT IN (
          SELECT pid::uuid
          FROM UNNEST(x.profile_ids) as pid
      )
),
link_profiles AS (
    -- Link new profiles if provided
    INSERT INTO cohort_profiles (cohort_id, profile_id, active)
    SELECT 
        cu.id,
        pid::uuid,
        true
    FROM cohort_update cu
    CROSS JOIN params x
    CROSS JOIN UNNEST(x.profile_ids) as pid
    WHERE COALESCE(array_length(x.profile_ids, 1), 0) > 0
    ON CONFLICT (cohort_id, profile_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
replace_simulations AS (
    -- Delete all existing simulation links to reset positions
    DELETE FROM cohort_simulations cs
    USING params x
    WHERE cs.cohort_id = x.cohort_id
),
simulations_with_order AS (
    -- Prepare simulations with position based on array order
    SELECT 
        simulation_id::uuid,
        ROW_NUMBER() OVER () as position
    FROM params x
    CROSS JOIN UNNEST(x.simulation_ids) as simulation_id
    WHERE COALESCE(array_length(x.simulation_ids, 1), 0) > 0
),
link_simulations AS (
    -- Link simulations with position if provided
    INSERT INTO cohort_simulations (cohort_id, simulation_id, active, position)
    SELECT 
        cu.id,
        swo.simulation_id,
        true,
        swo.position
    FROM cohort_update cu
    CROSS JOIN simulations_with_order swo
)
-- Return cohort ID, title, and actor name
SELECT 
    cu.id::text as id,
    cu.title,
    ap.actor_name
FROM cohort_update cu
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_update_department_v4(uuid, text, text, boolean, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_update_department_v4(department_id uuid, title text, description text, active boolean, settings_id uuid, profile_id uuid) RETURNS TABLE(department_id uuid, title text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        department_id AS department_id,
        title AS title,
        description AS description,
        active AS active,
        settings_id AS settings_id,
        profile_id AS profile_id
),
actor_profile AS (
    SELECT 
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
department_update AS (
    -- Update department
    UPDATE departments SET
        title = (SELECT title FROM params),
        description = (SELECT description FROM params),
        active = (SELECT active FROM params),
        updated_at = NOW()
    WHERE id = (SELECT department_id FROM params)
    RETURNING id, title
),
remove_existing_settings AS (
    -- Remove existing settings link if settings_id is null or different
    DELETE FROM department_settings
    WHERE department_id = (SELECT department_id FROM params)
      AND (
          (SELECT settings_id FROM params) IS NULL 
          OR settings_id != (SELECT settings_id FROM params)
      )
),
link_settings AS (
    -- Link settings if provided
    INSERT INTO department_settings (settings_id, department_id, active, created_at, updated_at)
    SELECT 
        settings_id,
        du.id,
        true,
        NOW(),
        NOW()
    FROM department_update du
    CROSS JOIN params p
    WHERE p.settings_id IS NOT NULL
    ON CONFLICT (settings_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
)
-- Return updated department info
SELECT 
    du.id as department_id,
    du.title::text as title,
    ap.actor_name::text as actor_name
FROM department_update du
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_update_document_v4(uuid, uuid, text, text, boolean, boolean, uuid, text[], uuid, uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_update_document_v4(document_id uuid, profile_id uuid, name text DEFAULT NULL::text, description text DEFAULT NULL::text, active boolean DEFAULT NULL::boolean, template boolean DEFAULT NULL::boolean, department_id uuid DEFAULT NULL::uuid, field_ids text[] DEFAULT ARRAY[]::text[], classify_agent_id uuid DEFAULT NULL::uuid, document_agent_id uuid DEFAULT NULL::uuid, html_id uuid DEFAULT NULL::uuid, schema_id uuid DEFAULT NULL::uuid) RETURNS TABLE(success boolean, message text, document_id uuid, document_name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        document_id AS document_id,
        profile_id AS profile_id,
        name AS name,
        description AS description,
        active AS active,
        template AS template,
        department_id AS department_id,
        COALESCE(field_ids, ARRAY[]::text[]) AS field_ids,
        classify_agent_id AS classify_agent_id,
        document_agent_id AS document_agent_id,
        html_id AS html_id,
        schema_id AS schema_id
),
actor_profile AS (
    SELECT 
        p.id as profile_id,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
update_document AS (
    UPDATE documents d
    SET 
        name = COALESCE((SELECT name FROM params), d.name),
        description = COALESCE((SELECT description FROM params), d.description),
        active = COALESCE((SELECT active FROM params), d.active),
        template = COALESCE((SELECT template FROM params), d.template),
        classify_agent_id = COALESCE((SELECT classify_agent_id FROM params), d.classify_agent_id),
        document_agent_id = COALESCE((SELECT document_agent_id FROM params), d.document_agent_id),
        updated_at = NOW()
    FROM params p
    WHERE d.id = p.document_id
    RETURNING d.id
),
create_template AS (
    -- Create template (just values, no schema/HTML refs) if html_id and schema_id are provided
    INSERT INTO templates (name, created_at, updated_at)
    SELECT 
        COALESCE((SELECT name FROM documents WHERE id = (SELECT document_id FROM params)), 'Template'),
        NOW(),
        NOW()
    FROM params p
    WHERE p.html_id IS NOT NULL AND p.schema_id IS NOT NULL
      AND NOT EXISTS (
          SELECT 1 FROM document_templates dt
          WHERE dt.html_id = p.html_id 
            AND dt.schema_id = p.schema_id
      )
    RETURNING id as template_id
),
get_existing_template AS (
    -- Get existing template if it exists (matching html_id and schema_id via document_templates)
    SELECT dt.template_id
    FROM params p
    JOIN document_templates dt ON dt.html_id = p.html_id AND dt.schema_id = p.schema_id
    WHERE p.html_id IS NOT NULL AND p.schema_id IS NOT NULL
    LIMIT 1
),
template_id AS (
    SELECT template_id FROM create_template
    UNION ALL
    SELECT template_id FROM get_existing_template
    WHERE EXISTS (SELECT 1 FROM params WHERE html_id IS NOT NULL AND schema_id IS NOT NULL)
    LIMIT 1
),
link_template_schema AS (
    -- Link template to schema via schema_templates junction table
    INSERT INTO schema_templates (schema_id, template_id, created_at, updated_at)
    SELECT 
        p.schema_id,
        ti.template_id,
        NOW(),
        NOW()
    FROM template_id ti
    CROSS JOIN params p
    WHERE p.schema_id IS NOT NULL
    ON CONFLICT (schema_id, template_id) DO UPDATE SET
        updated_at = NOW()
),
deactivate_previous_templates AS (
    -- Deactivate all previous templates if new one is provided
    UPDATE document_templates
    SET active = false, updated_at = NOW()
    WHERE document_id = (SELECT document_id FROM params)
      AND active = true
      AND (SELECT html_id FROM params) IS NOT NULL
),
update_template_link AS (
    -- Update or insert template link with html_id and schema_id
    INSERT INTO document_templates (document_id, template_id, html_id, schema_id, active, created_at, updated_at)
    SELECT 
        p.document_id,
        ti.template_id,
        p.html_id,
        p.schema_id,
        true,
        NOW(),
        NOW()
    FROM template_id ti
    CROSS JOIN params p
    WHERE p.html_id IS NOT NULL AND p.schema_id IS NOT NULL
    ON CONFLICT (document_id, template_id) DO UPDATE SET
        html_id = EXCLUDED.html_id,
        schema_id = EXCLUDED.schema_id,
        active = true,
        updated_at = NOW()
),
delete_template_link AS (
    -- Delete template link if html_id is NULL (removing template)
    DELETE FROM document_templates 
    WHERE document_id = (SELECT document_id FROM params)
    AND (SELECT html_id FROM params) IS NULL
),
replace_departments AS (
    -- Delete all existing department links
    DELETE FROM document_departments 
    WHERE document_id = (SELECT document_id FROM params)
),
link_department AS (
    -- Insert new department link if provided
    INSERT INTO document_departments (document_id, department_id, active, created_at, updated_at)
    SELECT p.document_id, p.department_id, true, NOW(), NOW()
    FROM params p
    WHERE p.department_id IS NOT NULL
    ON CONFLICT (document_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
replace_fields AS (
    -- Delete all existing field links
    DELETE FROM document_fields 
    WHERE document_id = (SELECT document_id FROM params)
),
link_fields AS (
    -- Insert new field links if provided (array is never NULL, but may be empty)
    INSERT INTO document_fields (document_id, field_id, active, created_at, updated_at)
    SELECT 
        p.document_id,
        field_id::uuid,
        true,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN unnest(p.field_ids) as field_id
    WHERE COALESCE(array_length(p.field_ids, 1), 0) > 0
    ON CONFLICT (document_id, field_id) DO UPDATE SET
        active = EXCLUDED.active,
        updated_at = NOW()
)
SELECT 
    true::boolean as success,
    'Document updated successfully'::text as message,
    ud.id as document_id,
    COALESCE((SELECT name FROM documents WHERE id = ud.id), 'Unknown')::text as document_name,
    ap.actor_name::text as actor_name
FROM update_document ud
CROSS JOIN actor_profile ap
LIMIT 1
$$;


--
-- Name: api_update_eval_v4(uuid, text, text, uuid[], boolean, uuid[], uuid[], boolean, boolean, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_update_eval_v4(eval_id uuid, name text, description text, agent_ids uuid[], use_groups boolean, model_run_ids uuid[], department_ids uuid[], active boolean, dynamic boolean, profile_id uuid) RETURNS TABLE(eval_id uuid, eval_name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        eval_id AS eval_id,
        name AS name,
        description AS description,
        COALESCE(agent_ids, ARRAY[]::uuid[]) AS agent_ids,
        use_groups AS use_groups,
        COALESCE(model_run_ids, ARRAY[]::uuid[]) AS model_run_ids,
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids,
        active AS active,
        dynamic AS dynamic,
        profile_id AS profile_id
),
user_profile AS (
    SELECT
        role,
        COALESCE(first_name || ' ' || last_name, 'System') as actor_name
    FROM params x
    JOIN profiles ON profiles.id = x.profile_id
),
object_current_departments AS (
    SELECT COALESCE(ARRAY_AGG(department_id::text), ARRAY[]::text[]) as department_ids
    FROM params x
    JOIN eval_departments ON eval_departments.eval_id = x.eval_id AND eval_departments.active = true
),
user_departments AS (
    SELECT COALESCE(ARRAY_AGG(department_id::text), ARRAY[]::text[]) as department_ids
    FROM params x
    JOIN profile_departments ON profile_departments.profile_id = x.profile_id AND profile_departments.active = true
),
validate_update_permissions AS (
    SELECT validate_department_update_permissions(
        up.role::text,
        ocd.department_ids,
        ud.department_ids
    ) as validation_passed
    FROM user_profile up
    CROSS JOIN object_current_departments ocd
    CROSS JOIN user_departments ud
),
update_eval AS (
    UPDATE evals SET
        name = p.name,
        description = p.description,
        use_groups = COALESCE(p.use_groups, evals.use_groups),
        active = COALESCE(p.active, evals.active),
        dynamic = COALESCE(p.dynamic, evals.dynamic),
        updated_at = NOW()
    FROM params p
    WHERE evals.id = p.eval_id
    RETURNING evals.id as eval_id, evals.name as eval_name
),
remove_existing_agent_links AS (
    DELETE FROM eval_agents
    USING params p
    WHERE eval_agents.eval_id = p.eval_id
    AND COALESCE(array_length(p.agent_ids, 1), 0) > 0
),
add_new_agent_links AS (
    INSERT INTO eval_agents (eval_id, agent_id, created_at, updated_at)
    SELECT 
        p.eval_id,
        a_id,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN UNNEST(p.agent_ids) as a_id
    WHERE COALESCE(array_length(p.agent_ids, 1), 0) > 0
    ON CONFLICT (eval_id, agent_id) DO UPDATE SET
        updated_at = NOW()
),
remove_existing_dept_links AS (
    DELETE FROM eval_departments
    USING params p
    WHERE eval_departments.eval_id = p.eval_id
    AND COALESCE(array_length(p.department_ids, 1), 0) > 0
),
add_new_dept_links AS (
    INSERT INTO eval_departments (eval_id, department_id, active, created_at, updated_at)
    SELECT 
        p.eval_id,
        d_id,
        true,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN UNNEST(p.department_ids) as d_id
    WHERE COALESCE(array_length(p.department_ids, 1), 0) > 0
    ON CONFLICT (eval_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
remove_existing_links AS (
    DELETE FROM eval_runs
    USING params p
    WHERE eval_runs.eval_id = p.eval_id
    AND COALESCE(array_length(p.model_run_ids, 1), 0) > 0
),
add_new_links AS (
    INSERT INTO eval_runs (eval_id, run_id, completed, created_at, updated_at)
    SELECT 
        p.eval_id,
        r_id,
        false,
        NOW(),
        NOW()
    FROM params p
    CROSS JOIN UNNEST(p.model_run_ids) as r_id
    WHERE COALESCE(array_length(p.model_run_ids, 1), 0) > 0
    ON CONFLICT (eval_id, run_id) DO UPDATE SET
        updated_at = NOW()
)
SELECT ue.eval_id, ue.eval_name, up.actor_name::text as actor_name
FROM update_eval ue
CROSS JOIN user_profile up
$$;


--
-- Name: api_update_field_v4(uuid, text, text, boolean, text[], text[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_update_field_v4(field_id uuid, name text, description text, active boolean, department_ids text[], conditional_parameter_ids text[], profile_id uuid) RETURNS TABLE(field_exists boolean, field_id uuid, field_name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT
        field_id AS field_id,
        name AS name,
        COALESCE(NULLIF(description, ''), '') AS description,
        COALESCE(active, true) AS active,
        COALESCE(department_ids, ARRAY[]::text[]) AS department_ids,
        COALESCE(conditional_parameter_ids, ARRAY[]::text[]) AS conditional_parameter_ids,
        profile_id AS profile_id
),
field_exists_check AS (
    -- Check if field exists independently of access control
    SELECT EXISTS(
        SELECT 1 FROM fields WHERE id = (SELECT field_id FROM params)
    )::boolean as field_exists
),
user_profile AS (
    SELECT 
        p.role,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
object_current_departments AS (
    -- Get field's current active department links
    SELECT COALESCE(ARRAY_AGG(department_id::text), ARRAY[]::text[]) as department_ids
    FROM field_departments
    WHERE field_id = (SELECT field_id FROM params) AND active = true
),
user_departments AS (
    -- Get user's departments
    SELECT COALESCE(ARRAY_AGG(department_id::text), ARRAY[]::text[]) as department_ids
    FROM profile_departments
    WHERE profile_id = (SELECT profile_id FROM params) AND active = true
),
validate_update_permissions AS (
    -- Validate department permissions for update operation
    SELECT validate_department_update_permissions(
        up.role::text,
        ocd.department_ids,
        ud.department_ids
    ) as validation_passed
    FROM user_profile up
    CROSS JOIN object_current_departments ocd
    CROSS JOIN user_departments ud
),
update_field AS (
    UPDATE fields SET
        name = (SELECT name FROM params),
        description = (SELECT description FROM params),
        active = (SELECT active FROM params),
        updated_at = NOW()
    WHERE id = (SELECT field_id FROM params)
    RETURNING id as field_id, (SELECT name FROM params) as field_name
),
delete_existing_conditional_parameters AS (
    -- Delete all existing conditional parameter links (soft delete)
    UPDATE field_conditional_parameters 
    SET active = false, updated_at = NOW()
    WHERE field_id = (SELECT field_id FROM params)
),
link_conditional_parameters AS (
    -- Link field to conditional parameters if provided
    INSERT INTO field_conditional_parameters (field_id, conditional_parameter_id, active, created_at, updated_at)
    SELECT 
        (SELECT field_id FROM params),
        cond_param_id::uuid,
        true,
        NOW(),
        NOW()
    FROM params x
    CROSS JOIN UNNEST(x.conditional_parameter_ids) as cond_param_id
    WHERE COALESCE(array_length(x.conditional_parameter_ids, 1), 0) > 0
    ON CONFLICT (field_id, conditional_parameter_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
delete_existing_departments AS (
    -- Delete all existing department links
    DELETE FROM field_departments 
    WHERE field_id = (SELECT field_id FROM params)
),
link_departments AS (
    -- Link field to departments if provided
    INSERT INTO field_departments (field_id, department_id, active, created_at, updated_at)
    SELECT 
        (SELECT field_id FROM params),
        dept_id::uuid,
        true,
        NOW(),
        NOW()
    FROM params x
    CROSS JOIN UNNEST(x.department_ids) as dept_id
    WHERE COALESCE(array_length(x.department_ids, 1), 0) > 0
    ON CONFLICT (field_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
)
SELECT 
    fec.field_exists::boolean as field_exists,
    uf.field_id,
    uf.field_name,
    up.actor_name
FROM field_exists_check fec
CROSS JOIN user_profile up
LEFT JOIN update_field uf ON fec.field_exists = true
$$;


--
-- Name: api_update_image_completed_v4(uuid, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_update_image_completed_v4(image_id uuid, completed boolean) RETURNS TABLE(id uuid, completed boolean, updated_at timestamp with time zone)
    LANGUAGE sql
    AS $$
UPDATE images
SET completed = api_update_image_completed_v4.completed,
    updated_at = NOW()
WHERE id = image_id
RETURNING id, completed, updated_at
$$;


--
-- Name: api_update_key_v4(uuid, text, text, text, boolean, uuid, uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_update_key_v4(key_id uuid, name text, key text, description text, active boolean, profile_id uuid, department_ids uuid[] DEFAULT ARRAY[]::uuid[]) RETURNS TABLE(key_id uuid, key_masked text, key_name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        key_id AS key_id,
        name AS name,
        key AS key,
        COALESCE(NULLIF(description, ''), '') AS description,
        active AS active,
        profile_id AS profile_id,
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids
),
user_profile AS (
    SELECT
        p.role,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
object_current_departments AS (
    -- NOTE: department_keys table was removed in migration 74
    -- Keys are now linked to departments through settings
    -- Use department_ids from params to help PostgreSQL infer type
    SELECT x.department_ids::text[] as department_ids
    FROM params x
),
user_departments AS (
    -- Get user's departments
    SELECT COALESCE(ARRAY_AGG(department_id::text), ARRAY[]::text[]) as department_ids
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.active = true
),
validate_update_permissions AS (
    -- Validate department permissions for update operation
    SELECT validate_department_update_permissions(
        up.role::text,
        ocd.department_ids,
        ud.department_ids
    ) as validation_passed
    FROM user_profile up
    CROSS JOIN object_current_departments ocd
    CROSS JOIN user_departments ud
),
actor_profile AS (
    SELECT
        x.profile_id as profile_id,
        up.actor_name
    FROM params x
    CROSS JOIN user_profile up
),
update_key AS (
    UPDATE keys
    SET 
        name = x.name,
        key = x.key,
        description = x.description,
        active = x.active,
        updated_at = NOW()
    FROM params x
    WHERE keys.id = x.key_id
    RETURNING keys.id as key_id, keys.key, keys.name as key_name
),
replace_departments AS (
    -- NOTE: department_keys table was removed in migration 74
    SELECT 1 WHERE false
),
link_departments AS (
    -- NOTE: department_keys table was removed in migration 74
    -- Keys are now linked to departments through settings
    SELECT 1 WHERE false
)
SELECT 
    uk.key_id::uuid as key_id,
    CASE 
        WHEN LENGTH(uk.key) > 4 THEN LEFT(uk.key, 4) || '****'
        ELSE '****'
    END::text as key_masked,
    uk.key_name::text as key_name,
    ap.actor_name::text as actor_name
FROM update_key uk
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_update_model_v4(uuid, uuid, text, text, boolean, text, uuid, uuid[], text, types.i_update_model_v4_temperature_bounds, types.i_update_model_v4_pricing[], text[], text[], text[], text[], text[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_update_model_v4(model_id uuid, provider_id uuid, name text, description text, active boolean, value text, profile_id uuid, department_ids uuid[] DEFAULT ARRAY[]::uuid[], base_url text DEFAULT NULL::text, temperature_bounds types.i_update_model_v4_temperature_bounds DEFAULT NULL::types.i_update_model_v4_temperature_bounds, pricing types.i_update_model_v4_pricing[] DEFAULT ARRAY[]::types.i_update_model_v4_pricing[], input_modalities text[] DEFAULT ARRAY[]::text[], output_modalities text[] DEFAULT ARRAY[]::text[], reasoning_levels text[] DEFAULT ARRAY[]::text[], voices text[] DEFAULT NULL::text[], qualities text[] DEFAULT ARRAY[]::text[]) RETURNS TABLE(model_exists boolean, model_name text, actor_name text)
    LANGUAGE plpgsql
    AS $$
DECLARE
    model_exists_check boolean;
    final_input_mods text[];
    final_output_mods text[];
    default_voices text[] := ARRAY['alloy', 'ash', 'ballad', 'coral', 'echo', 'fable', 'onyx', 'nova', 'sage', 'shimmer', 'verse'];
    final_voices text[];
    temp_val float;
    updated_model_name text;
BEGIN
    -- Check if model exists
    SELECT EXISTS(SELECT 1 FROM models WHERE id = model_id) INTO model_exists_check;
    
    IF NOT model_exists_check THEN
        RETURN QUERY SELECT false::boolean, ''::text, ''::text;
        RETURN;
    END IF;

    -- Validate permissions
    IF NOT validate_department_update_permissions(
        (SELECT role::text FROM profiles WHERE id = profile_id),
        ARRAY(SELECT department_id::text FROM model_departments WHERE model_id = api_update_model_v4.model_id AND active = true),
        ARRAY(SELECT department_id::text FROM profile_departments WHERE profile_id = api_update_model_v4.profile_id AND active = true)
    ) THEN
        RAISE EXCEPTION 'Insufficient permissions to update model';
    END IF;

    -- Update model
    UPDATE models SET
        provider_id = api_update_model_v4.provider_id,
        name = api_update_model_v4.name,
        description = api_update_model_v4.description,
        active = api_update_model_v4.active,
        value = api_update_model_v4.value,
        updated_at = NOW()
    WHERE id = api_update_model_v4.model_id
    RETURNING name INTO updated_model_name;

    -- Deactivate all existing department links
    UPDATE model_departments
    SET active = false, updated_at = NOW()
    WHERE model_id = api_update_model_v4.model_id AND active = true;

    -- Link departments if provided
    IF array_length(department_ids, 1) > 0 THEN
        INSERT INTO model_departments (model_id, department_id, active, created_at, updated_at)
        SELECT api_update_model_v4.model_id, dept_id, true, NOW(), NOW()
        FROM UNNEST(department_ids) as dept_id
        ON CONFLICT (model_id, department_id) DO UPDATE SET
            active = true,
            updated_at = NOW();
    END IF;

    -- Update endpoint if base_url is provided
    IF base_url IS NOT NULL AND TRIM(base_url) != '' THEN
        INSERT INTO model_endpoints (model_id, base_url, active, created_at, updated_at)
        VALUES (api_update_model_v4.model_id, base_url, true, NOW(), NOW())
        ON CONFLICT (model_id) DO UPDATE SET
            base_url = EXCLUDED.base_url,
            active = true,
            updated_at = NOW();
    ELSE
        -- Deactivate endpoint if base_url is null or empty
        UPDATE model_endpoints
        SET active = false, updated_at = NOW()
        WHERE model_id = api_update_model_v4.model_id;
    END IF;

    -- Handle temperature bounds
    IF temperature_bounds IS NOT NULL THEN
        -- Deactivate existing temperature levels
        UPDATE model_temperature_levels SET active = false, updated_at = NOW()
        WHERE model_id = api_update_model_v4.model_id;

        IF temperature_bounds.bounds_type = 'range' THEN
            INSERT INTO model_temperature_levels (model_id, temperature, is_upper, active)
            VALUES 
                (api_update_model_v4.model_id, temperature_bounds.lower_bound, false, true),
                (api_update_model_v4.model_id, temperature_bounds.upper_bound, true, true)
            ON CONFLICT (model_id, temperature, is_upper) DO UPDATE SET active = true, updated_at = NOW();
        ELSIF temperature_bounds.bounds_type = 'values' AND array_length(temperature_bounds.values_array, 1) > 0 THEN
            INSERT INTO model_temperature_levels (model_id, temperature, is_upper, active)
            SELECT api_update_model_v4.model_id, temp_val, false, true
            FROM UNNEST(temperature_bounds.values_array) as temp_val
            ON CONFLICT (model_id, temperature, is_upper) DO UPDATE SET active = true, updated_at = NOW();
        END IF;
    END IF;

    -- Handle pricing
    IF array_length(pricing, 1) > 0 THEN
        -- Deactivate existing pricing
        UPDATE model_pricing SET active = false, updated_at = NOW()
        WHERE model_id = api_update_model_v4.model_id;

        -- Insert new pricing entries
        INSERT INTO model_pricing (model_id, pricing_type, unit_id, price, active)
        SELECT api_update_model_v4.model_id, p.pricing_type::pricing_type, p.unit_id, p.price, true
        FROM UNNEST(pricing) as p
        ON CONFLICT (model_id, pricing_type, unit_id) DO UPDATE SET
            price = EXCLUDED.price,
            active = true,
            updated_at = NOW();
    END IF;

    -- Default modalities to text/text if not provided
    IF array_length(input_modalities, 1) IS NULL AND array_length(output_modalities, 1) IS NULL THEN
        final_input_mods := ARRAY['text'];
        final_output_mods := ARRAY['text'];
    ELSE
        final_input_mods := COALESCE(input_modalities, ARRAY[]::text[]);
        final_output_mods := COALESCE(output_modalities, ARRAY[]::text[]);
    END IF;

    -- Handle modalities
    -- Deactivate existing modalities
    UPDATE model_modalities SET active = false, updated_at = NOW()
    WHERE model_id = api_update_model_v4.model_id;

    IF array_length(final_input_mods, 1) > 0 THEN
        INSERT INTO model_modalities (model_id, modality, is_input, active)
        SELECT api_update_model_v4.model_id, mod::modality_type, true, true
        FROM UNNEST(final_input_mods) as mod
        ON CONFLICT (model_id, modality, is_input) DO UPDATE SET active = true, updated_at = NOW();
    END IF;

    IF array_length(final_output_mods, 1) > 0 THEN
        INSERT INTO model_modalities (model_id, modality, is_input, active)
        SELECT api_update_model_v4.model_id, mod::modality_type, false, true
        FROM UNNEST(final_output_mods) as mod
        ON CONFLICT (model_id, modality, is_input) DO UPDATE SET active = true, updated_at = NOW();
    END IF;

    -- Handle reasoning levels
    IF array_length(reasoning_levels, 1) > 0 THEN
        -- Deactivate existing reasoning levels
        UPDATE model_reasoning_levels SET active = false, updated_at = NOW()
        WHERE model_id = api_update_model_v4.model_id;

        -- Insert new reasoning levels
        INSERT INTO model_reasoning_levels (model_id, reasoning_level, active)
        SELECT api_update_model_v4.model_id, level::reasoning_effort, true
        FROM UNNEST(reasoning_levels) as level
        ON CONFLICT (model_id, reasoning_level) DO UPDATE SET active = true, updated_at = NOW();
    END IF;

    -- Default voices to all voices if not provided
    IF voices IS NULL OR array_length(voices, 1) IS NULL THEN
        final_voices := default_voices;
    ELSE
        final_voices := voices;
    END IF;

    -- Handle voices
    -- Always deactivate existing voices first
    UPDATE model_voices SET active = false, updated_at = NOW()
    WHERE model_id = api_update_model_v4.model_id;

    IF array_length(final_voices, 1) > 0 THEN
        INSERT INTO model_voices (model_id, voice, active)
        SELECT api_update_model_v4.model_id, voice::voice, true
        FROM UNNEST(final_voices) as voice
        ON CONFLICT (model_id, voice) DO UPDATE SET active = true, updated_at = NOW();
    END IF;

    -- Handle qualities
    IF array_length(qualities, 1) > 0 THEN
        -- Deactivate existing qualities
        UPDATE model_qualities SET active = false, updated_at = NOW()
        WHERE model_id = api_update_model_v4.model_id;

        -- Insert new qualities
        INSERT INTO model_qualities (model_id, quality, active)
        SELECT api_update_model_v4.model_id, quality::quality, true
        FROM UNNEST(qualities) as quality
        ON CONFLICT (model_id, quality) DO UPDATE SET active = true, updated_at = NOW();
    END IF;

    -- Return result
    RETURN QUERY
    SELECT 
        true::boolean as model_exists,
        updated_model_name as model_name,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM profiles p
    WHERE p.id = profile_id;
END;
$$;


--
-- Name: api_update_parameter_v4(uuid, text, text, boolean, boolean, boolean, boolean, boolean, boolean, text[], types.i_update_parameter_v4_field_connection[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_update_parameter_v4(parameter_id uuid, name text, description text, active boolean, simulation_parameter boolean, document_parameter boolean, persona_parameter boolean, scenario_parameter boolean, video_parameter boolean, department_ids text[], field_connections types.i_update_parameter_v4_field_connection[], profile_id uuid) RETURNS TABLE(parameter_exists boolean, parameter_id uuid, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        parameter_id AS parameter_id,
        name AS name,
        description AS description,
        active AS active,
        simulation_parameter AS simulation_parameter,
        document_parameter AS document_parameter,
        persona_parameter AS persona_parameter,
        scenario_parameter AS scenario_parameter,
        video_parameter AS video_parameter,
        COALESCE(department_ids, ARRAY[]::text[]) AS department_ids,
        COALESCE(field_connections, ARRAY[]::types.i_update_parameter_v4_field_connection[]) AS field_connections,
        profile_id AS profile_id
),
parameter_exists_check AS (
    -- Check if parameter exists independently of access control
    SELECT EXISTS(
        SELECT 1 FROM parameters WHERE id = (SELECT parameter_id FROM params)
    )::boolean as parameter_exists
),
user_profile AS (
    SELECT 
        p.role,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
object_current_departments AS (
    -- Get parameter's current active department links
    SELECT COALESCE(ARRAY_AGG(department_id::text), ARRAY[]::text[]) as department_ids
    FROM params x
    JOIN parameter_departments ON parameter_departments.parameter_id = x.parameter_id AND parameter_departments.active = true
),
user_departments AS (
    -- Get user's departments
    SELECT COALESCE(ARRAY_AGG(department_id::text), ARRAY[]::text[]) as department_ids
    FROM params x
    JOIN profile_departments ON profile_departments.profile_id = x.profile_id AND profile_departments.active = true
),
validate_update_permissions AS (
    -- Validate department permissions for update operation
    SELECT validate_department_update_permissions(
        up.role::text,
        ocd.department_ids,
        ud.department_ids
    ) as validation_passed
    FROM user_profile up
    CROSS JOIN object_current_departments ocd
    CROSS JOIN user_departments ud
),
actor_profile AS (
    SELECT 
        (SELECT profile_id FROM params) as profile_id,
        up.actor_name
    FROM user_profile up
),
update_parameter AS (
    UPDATE parameters SET
        name = (SELECT name FROM params),
        description = (SELECT description FROM params),
        active = (SELECT active FROM params),
        simulation_parameter = (SELECT simulation_parameter FROM params),
        document_parameter = (SELECT document_parameter FROM params),
        persona_parameter = (SELECT persona_parameter FROM params),
        scenario_parameter = (SELECT scenario_parameter FROM params),
        video_parameter = (SELECT video_parameter FROM params),
        updated_at = NOW()
    WHERE id = (SELECT parameter_id FROM params)
    RETURNING id as parameter_id
),
delete_existing_field_links AS (
    -- Soft delete all existing parameter_fields links (set active = false)
    UPDATE parameter_fields 
    SET active = false, updated_at = NOW()
    WHERE parameter_id = (SELECT parameter_id FROM params)
),
field_connections_expanded AS (
    -- Expand composite type array field_connections
    SELECT 
        (x.field_connections[i]).field_id,
        COALESCE((x.field_connections[i])."default", false) as conn_default,
        COALESCE((x.field_connections[i]).active, true) as conn_active,
        i as conn_order
    FROM params x
    CROSS JOIN generate_subscripts(x.field_connections, 1) AS i
    WHERE array_length(x.field_connections, 1) > 0
    AND (x.field_connections[i]).field_id IS NOT NULL
),
ensure_one_default AS (
    -- Ensure exactly one default: if none specified, set first one; if multiple, keep first
    SELECT 
        conn_order,
        CASE 
            WHEN conn_order = (
                SELECT MIN(conn_order) 
                FROM field_connections_expanded 
                WHERE conn_default = true
                LIMIT 1
            ) THEN true
            WHEN (SELECT COUNT(*) FROM field_connections_expanded WHERE conn_default = true) = 0 
                 AND conn_order = (SELECT MIN(conn_order) FROM field_connections_expanded)
            THEN true
            ELSE false
        END as conn_default_fixed
    FROM field_connections_expanded
),
field_connections_fixed AS (
    SELECT 
        fce.field_id,
        COALESCE(eod.conn_default_fixed, false) as conn_default,
        fce.conn_active
    FROM field_connections_expanded fce
    LEFT JOIN ensure_one_default eod ON eod.conn_order = fce.conn_order
),
link_fields_to_parameter AS (
    -- Link existing fields to parameter via parameter_fields junction with default and active flags
    INSERT INTO parameter_fields (parameter_id, field_id, "default", active, created_at, updated_at)
    SELECT 
        (SELECT parameter_id FROM params),
        fcf.field_id,
        fcf.conn_default,
        fcf.conn_active,
        NOW(),
        NOW()
    FROM field_connections_fixed fcf
    WHERE EXISTS (SELECT 1 FROM fields f WHERE f.id = fcf.field_id AND f.active = true)
    ON CONFLICT (parameter_id, field_id) DO UPDATE SET
        active = EXCLUDED.active,
        "default" = EXCLUDED."default",
        updated_at = NOW()
),
delete_existing_parameter_departments AS (
    -- Delete all existing parameter_departments links
    DELETE FROM parameter_departments 
    WHERE parameter_id = (SELECT parameter_id FROM params)
),
link_parameter_departments AS (
    -- Link departments to parameter if provided at parameter level
    INSERT INTO parameter_departments (parameter_id, department_id, active, created_at, updated_at)
    SELECT 
        (SELECT parameter_id FROM params),
        dept_id::uuid,
        true,
        NOW(),
        NOW()
    FROM params x
    CROSS JOIN UNNEST(x.department_ids) as dept_id
    WHERE array_length(x.department_ids, 1) > 0
    ON CONFLICT (parameter_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
)
SELECT 
    (SELECT parameter_exists FROM parameter_exists_check)::boolean as parameter_exists,
    COALESCE(up.parameter_id, (SELECT parameter_id FROM params))::uuid as parameter_id,
    ap.actor_name::text as actor_name
FROM parameter_exists_check pec
CROSS JOIN actor_profile ap
LEFT JOIN update_parameter up ON pec.parameter_exists = true
$$;


--
-- Name: api_update_persona_v4(uuid, text, text, boolean, text, text, text, text[], uuid, text[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_update_persona_v4(persona_id uuid, name text, description text, active boolean, color text, icon text, instructions text, department_ids text[], profile_id uuid, example_ids text[]) RETURNS TABLE(persona_id uuid, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT
        persona_id AS persona_id,
        name AS name,
        COALESCE(NULLIF(description, ''), '') AS description,
        active AS active,
        color AS color,
        icon AS icon,
        COALESCE(NULLIF(instructions, ''), '') AS instructions,
        COALESCE(department_ids, ARRAY[]::text[]) AS department_ids,
        profile_id AS profile_id,
        COALESCE(example_ids, ARRAY[]::text[]) AS example_ids
),
user_profile AS (
    SELECT 
        p.role,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
object_current_departments AS (
    -- Get persona's current active department links
    SELECT COALESCE(ARRAY_AGG(department_id::text), ARRAY[]::text[]) as department_ids
    FROM persona_departments
    WHERE persona_id = (SELECT persona_id FROM params) AND active = true
),
user_departments AS (
    -- Get user's departments
    SELECT COALESCE(ARRAY_AGG(department_id::text), ARRAY[]::text[]) as department_ids
    FROM profile_departments
    WHERE profile_id = (SELECT profile_id FROM params) AND active = true
),
validate_update_permissions AS (
    -- Validate department permissions for update operation
    SELECT validate_department_update_permissions(
        up.role::text,
        ocd.department_ids,
        ud.department_ids
    ) as validation_passed
    FROM user_profile up
    CROSS JOIN object_current_departments ocd
    CROSS JOIN user_departments ud
),
actor_profile AS (
    SELECT 
        x.profile_id,
        up.actor_name
    FROM params x
    CROSS JOIN user_profile up
),
update_persona AS (
    UPDATE personas
    SET 
        name = x.name,
        description = x.description,
        active = x.active,
        color = x.color,
        icon = x.icon,
        instructions = x.instructions,
        updated_at = NOW()
    FROM params x
    WHERE id = x.persona_id
    RETURNING id
),
replace_departments AS (
    -- Delete all existing department links
    DELETE FROM persona_departments WHERE persona_id = (SELECT persona_id FROM params)
),
link_departments AS (
    -- Insert new department links if provided (array is never NULL, but may be empty)
    INSERT INTO persona_departments (persona_id, department_id, active, created_at, updated_at)
    SELECT 
        x.persona_id,
        dept_id::uuid,
        true,
        NOW(),
        NOW()
    FROM params x
    CROSS JOIN UNNEST(x.department_ids) as dept_id
    WHERE COALESCE(array_length(x.department_ids, 1), 0) > 0
    ON CONFLICT (persona_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
replace_examples AS (
    -- Delete all existing example links
    DELETE FROM persona_examples 
    WHERE persona_id = (SELECT persona_id FROM params)
),
examples_with_index AS (
    -- Prepare examples with their index
    SELECT 
        ex_text,
        ROW_NUMBER() OVER () - 1 as idx
    FROM params x
    CROSS JOIN UNNEST(x.example_ids) as ex_text
    WHERE EXISTS (SELECT 1 FROM update_persona)
      AND COALESCE(array_length(x.example_ids, 1), 0) > 0
),
existing_examples AS (
    -- Find existing examples by text
    SELECT id as example_id, example
    FROM examples
    WHERE example = ANY(SELECT ex_text FROM examples_with_index)
),
new_examples AS (
    -- Create new examples that don't exist yet
    INSERT INTO examples (example, created_at, updated_at)
    SELECT DISTINCT
        ewi.ex_text,
        NOW(),
        NOW()
    FROM examples_with_index ewi
    WHERE NOT EXISTS (
        SELECT 1 FROM existing_examples ee WHERE ee.example = ewi.ex_text
    )
    RETURNING id as example_id, example
),
all_examples AS (
    -- Combine existing and new examples
    SELECT example_id, example FROM existing_examples
    UNION ALL
    SELECT example_id, example FROM new_examples
),
insert_examples AS (
    -- Link examples to persona via junction table
    INSERT INTO persona_examples (persona_id, example_id, idx, created_at)
    SELECT 
        x.persona_id,
        ae.example_id,
        ewi.idx,
        NOW()
    FROM params x
    CROSS JOIN examples_with_index ewi
    JOIN all_examples ae ON ae.example = ewi.ex_text
)
SELECT 
    up.id as persona_id,
    ap.actor_name
FROM update_persona up
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_update_profile_v4(uuid, uuid, text, text, timestamp with time zone, text, boolean, timestamp with time zone, integer, text[], integer, uuid[], uuid[], integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_update_profile_v4(target_profile_id uuid, profile_id uuid, first_name text DEFAULT NULL::text, last_name text DEFAULT NULL::text, last_login timestamp with time zone DEFAULT NULL::timestamp with time zone, role text DEFAULT NULL::text, active boolean DEFAULT NULL::boolean, last_active timestamp with time zone DEFAULT NULL::timestamp with time zone, requests_per_day integer DEFAULT NULL::integer, emails text[] DEFAULT NULL::text[], primary_email_index integer DEFAULT NULL::integer, cohort_ids uuid[] DEFAULT NULL::uuid[], department_ids uuid[] DEFAULT NULL::uuid[], primary_department_index integer DEFAULT NULL::integer) RETURNS TABLE(profile_exists boolean, profile_id uuid, first_name text, last_name text, name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        target_profile_id AS target_profile_id,
        first_name AS first_name,
        last_name AS last_name,
        last_login AS last_login,
        role AS role,
        active AS active,
        last_active AS last_active,
        requests_per_day AS requests_per_day,
        emails AS emails,
        primary_email_index AS primary_email_index,
        cohort_ids AS cohort_ids,
        department_ids AS department_ids,
        primary_department_index AS primary_department_index,
        profile_id AS profile_id
),
profile_exists_check AS (
    -- Check if profile exists
    SELECT EXISTS(SELECT 1 FROM profiles WHERE id = (SELECT target_profile_id FROM params))::boolean as profile_exists
),
actor_profile AS (
    SELECT 
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
profile_update AS (
    -- Update profile fields (only update non-NULL parameters, keep existing values for NULL)
    UPDATE profiles
    SET 
        first_name = COALESCE((SELECT first_name FROM params), first_name),
        last_name = COALESCE((SELECT last_name FROM params), last_name),
        last_login = COALESCE((SELECT last_login FROM params), last_login),
        role = COALESCE((SELECT role FROM params)::profile_role, role),
        active = COALESCE((SELECT active FROM params), active),
        updated_at = NOW()
    WHERE id = (SELECT target_profile_id FROM params)
      AND EXISTS (SELECT 1 FROM profile_exists_check WHERE profile_exists = true)
    RETURNING 
        id,
        first_name,
        last_name,
        first_name || ' ' || last_name as name
),
insert_activity AS (
    -- Insert into profile_activity if last_active is provided
    INSERT INTO profile_activity (profile_id, last_active)
    SELECT 
        pu.id,
        (SELECT last_active FROM params)
    FROM profile_update pu
    WHERE (SELECT last_active FROM params) IS NOT NULL
),
request_limit_upsert AS (
    -- Upsert request limit if provided
    INSERT INTO profile_request_limits (profile_id, requests_per_day, active)
    SELECT 
        pu.id,
        (SELECT requests_per_day FROM params),
        true
    FROM profile_update pu
    WHERE (SELECT requests_per_day FROM params) IS NOT NULL
      AND EXISTS (SELECT 1 FROM profile_update)
    ON CONFLICT (profile_id)
    DO UPDATE SET 
        requests_per_day = EXCLUDED.requests_per_day,
        active = true,
        updated_at = NOW()
),
email_update AS (
    -- Update emails if emails array is provided (comprehensive update)
    -- First deactivate all existing emails
    UPDATE profile_emails SET
        active = false,
        is_primary = false,
        updated_at = NOW()
    WHERE profile_id = (SELECT target_profile_id FROM params)
      AND EXISTS (SELECT 1 FROM profile_update)
      AND (SELECT emails FROM params) IS NOT NULL
),
all_emails_data AS (
    -- Prepare all emails with primary flag based on index
    SELECT 
        email,
        CASE WHEN ord = COALESCE((SELECT primary_email_index FROM params), 0) + 1 THEN true ELSE false END as is_primary
    FROM unnest((SELECT emails FROM params)) WITH ORDINALITY AS e(email, ord)
    WHERE (SELECT emails FROM params) IS NOT NULL
),
email_insert AS (
    -- Insert/update all emails
    INSERT INTO profile_emails (profile_id, email, is_primary, active)
    SELECT 
        pu.id,
        aed.email,
        aed.is_primary,
        true
    FROM profile_update pu
    CROSS JOIN all_emails_data aed
    WHERE (SELECT emails FROM params) IS NOT NULL
      AND EXISTS (SELECT 1 FROM profile_update)
    ON CONFLICT (email) DO UPDATE SET
        profile_id = EXCLUDED.profile_id,
        is_primary = EXCLUDED.is_primary,
        active = true,
        updated_at = NOW()
),
cohort_deactivate AS (
    -- Deactivate existing cohort relationships not in the new list (or all if empty array)
    UPDATE cohort_profiles SET
        active = false,
        updated_at = NOW()
    WHERE profile_id = (SELECT target_profile_id FROM params)
      AND EXISTS (SELECT 1 FROM profile_update)
      AND (SELECT cohort_ids FROM params) IS NOT NULL
      AND (
          array_length((SELECT cohort_ids FROM params), 1) IS NULL
          OR cohort_id NOT IN (SELECT unnest((SELECT cohort_ids FROM params)))
      )
),
cohort_insert AS (
    -- Insert or activate cohort relationships
    INSERT INTO cohort_profiles (cohort_id, profile_id, active)
    SELECT 
        cohort_id,
        pu.id,
        true
    FROM profile_update pu
    CROSS JOIN unnest((SELECT cohort_ids FROM params)) as cohort_id
    WHERE (SELECT cohort_ids FROM params) IS NOT NULL
      AND array_length((SELECT cohort_ids FROM params), 1) > 0
      AND EXISTS (SELECT 1 FROM profile_update)
    ON CONFLICT (cohort_id, profile_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
department_deactivate_all AS (
    -- Deactivate all existing department relationships (or all if empty array)
    UPDATE profile_departments SET
        active = false,
        is_primary = false,
        updated_at = NOW()
    WHERE profile_id = (SELECT target_profile_id FROM params)
      AND EXISTS (SELECT 1 FROM profile_update)
      AND (SELECT department_ids FROM params) IS NOT NULL
      AND (
          array_length((SELECT department_ids FROM params), 1) IS NULL
          OR department_id NOT IN (SELECT unnest((SELECT department_ids FROM params)))
      )
),
department_insert AS (
    -- Insert or update department relationships (set primary based on index)
    INSERT INTO profile_departments (profile_id, department_id, is_primary, active)
    SELECT 
        pu.id,
        dept.dept_id,
        (dept.ord - 1 = COALESCE((SELECT primary_department_index FROM params), 0)) as is_primary,
        true
    FROM profile_update pu
    CROSS JOIN unnest((SELECT department_ids FROM params)) WITH ORDINALITY AS dept(dept_id, ord)
    WHERE (SELECT department_ids FROM params) IS NOT NULL
      AND array_length((SELECT department_ids FROM params), 1) > 0
      AND EXISTS (SELECT 1 FROM profile_update)
    ON CONFLICT (profile_id, department_id) DO UPDATE SET
        is_primary = EXCLUDED.is_primary,
        active = true,
        updated_at = NOW()
)
-- Return profile info (always returns a row if profile exists)
SELECT 
    pec.profile_exists::boolean as profile_exists,
    pu.id as profile_id,
    pu.first_name,
    pu.last_name,
    pu.name,
    ap.actor_name
FROM profile_exists_check pec
CROSS JOIN actor_profile ap
LEFT JOIN profile_update pu ON pec.profile_exists = true
LIMIT 1
$$;


--
-- Name: api_update_provider_v4(uuid, text, text, text, boolean, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_update_provider_v4(provider_id uuid, name text, description text, value text, active boolean, base_url text, profile_id uuid) RETURNS TABLE(provider_exists boolean, provider_id uuid, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT
        provider_id AS provider_id,
        name AS name,
        description AS description,
        value AS value,
        active AS active,
        NULLIF(TRIM(base_url), '') AS base_url,
        profile_id AS profile_id
),
provider_exists_check AS (
    -- Check if provider exists independently of access control
    SELECT EXISTS(
        SELECT 1 FROM providers WHERE id = (SELECT provider_id FROM params)
    )::boolean as provider_exists
),
actor_profile AS (
    SELECT 
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
update_provider AS (
    UPDATE providers
    SET 
        name = x.name,
        description = x.description,
        value = x.value,
        active = x.active,
        updated_at = NOW()
    FROM params x
    WHERE id = x.provider_id
    RETURNING id as provider_id
),
update_endpoint AS (
    -- Update or create endpoint if base_url provided
    INSERT INTO provider_endpoints (provider_id, base_url, active, created_at, updated_at)
    SELECT 
        x.provider_id,
        x.base_url,
        true,
        NOW(),
        NOW()
    FROM params x
    WHERE x.base_url IS NOT NULL
    ON CONFLICT (provider_id) DO UPDATE SET
        base_url = EXCLUDED.base_url,
        active = true,
        updated_at = NOW()
),
delete_endpoint AS (
    -- Delete endpoint if base_url is empty/null
    UPDATE provider_endpoints
    SET active = false, updated_at = NOW()
    FROM params x
    WHERE provider_endpoints.provider_id = x.provider_id
    AND x.base_url IS NULL
)
SELECT 
    pec.provider_exists::boolean as provider_exists,
    up.provider_id,
    ap.actor_name::text as actor_name
FROM provider_exists_check pec
LEFT JOIN update_provider up ON pec.provider_exists = true
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_update_rubric_v4(uuid, text, text, boolean, integer, integer, uuid, uuid[], types.i_update_rubric_v4_standard_group[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_update_rubric_v4(rubric_id uuid, name text, description text, active boolean, points integer, pass_points integer, profile_id uuid, department_ids uuid[] DEFAULT ARRAY[]::uuid[], standard_groups types.i_update_rubric_v4_standard_group[] DEFAULT ARRAY[]::types.i_update_rubric_v4_standard_group[], rubric_agent_id uuid DEFAULT NULL::uuid) RETURNS TABLE(rubric_id uuid, rubric_name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        rubric_id AS rubric_id,
        name AS name,
        COALESCE(NULLIF(description, ''), '') AS description,
        active AS active,
        points AS points,
        pass_points AS pass_points,
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids,
        COALESCE(standard_groups, ARRAY[]::types.i_update_rubric_v4_standard_group[]) AS standard_groups,
        rubric_agent_id AS rubric_agent_id,
        profile_id AS profile_id
),
user_profile AS (
    SELECT
        p.role,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
object_current_departments AS (
    SELECT COALESCE(ARRAY_AGG(department_id::text), ARRAY[]::text[]) as department_ids
    FROM rubric_departments
    WHERE rubric_id = (SELECT rubric_id FROM params) AND active = true
),
user_departments AS (
    SELECT COALESCE(ARRAY_AGG(department_id::text), ARRAY[]::text[]) as department_ids
    FROM profile_departments
    WHERE profile_id = (SELECT profile_id FROM params) AND active = true
),
validate_update_permissions AS (
    SELECT validate_department_update_permissions(
        up.role::text,
        ocd.department_ids,
        ud.department_ids
    ) as validation_passed
    FROM user_profile up
    CROSS JOIN object_current_departments ocd
    CROSS JOIN user_departments ud
),
actor_profile AS (
    SELECT
        x.profile_id,
        up.actor_name
    FROM params x
    CROSS JOIN user_profile up
),
update_rubric AS (
    UPDATE rubrics r SET
        name = x.name,
        description = x.description,
        active = x.active,
        points = x.points,
        pass_points = x.pass_points,
        rubric_agent_id = x.rubric_agent_id,
        updated_at = NOW()
    FROM params x
    WHERE r.id = x.rubric_id
    RETURNING r.id as rubric_id, r.name as rubric_name
),
replace_departments AS (
    UPDATE rubric_departments 
    SET active = false, updated_at = NOW()
    WHERE rubric_id = (SELECT rubric_id FROM params) AND active = true
),
link_departments AS (
    INSERT INTO rubric_departments (rubric_id, department_id, active, created_at, updated_at)
    SELECT 
        x.rubric_id,
        dept_id,
        true,
        NOW(),
        NOW()
    FROM params x
    CROSS JOIN UNNEST(x.department_ids) as dept_id
    WHERE array_length(x.department_ids, 1) > 0
    ON CONFLICT (rubric_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
-- Deactivate existing standard_group links instead of deleting standard_groups
deactivate_rubric_standard_groups AS (
    UPDATE rubric_standard_groups 
    SET active = false, updated_at = NOW()
    WHERE rubric_id = (SELECT rubric_id FROM params) AND active = true
),
standard_groups_unnested AS (
    SELECT 
        x.rubric_id,
        (ROW_NUMBER() OVER (PARTITION BY x.rubric_id ORDER BY ordinality))::int as group_order,
        sg.name,
        COALESCE(NULLIF(sg.short_name, ''), NULL)::text as short_name,
        COALESCE(NULLIF(sg.description, ''), NULL)::text as description,
        sg.points,
        sg.pass_points,
        COALESCE(sg.position, (ROW_NUMBER() OVER (PARTITION BY x.rubric_id ORDER BY ordinality)))::int as position,
        COALESCE(sg.active, true)::boolean as active,
        sg.standards
    FROM params x
    CROSS JOIN UNNEST(x.standard_groups) WITH ORDINALITY as sg
    WHERE array_length(x.standard_groups, 1) > 0
),
-- Create placeholder calls for API-updated standard_groups (not created via tool)
placeholder_calls AS (
    INSERT INTO calls (call_id, tool_id, completed, created_at, updated_at)
    SELECT 
        'api_update_rubric_' || sgu.rubric_id::text || '_sg_' || sgu.group_order::text,
        NULL,
        TRUE,
        NOW(),
        NOW()
    FROM standard_groups_unnested sgu
    RETURNING id, call_id
),
calls_with_order AS (
    SELECT 
        ptc.id as tool_call_id,
        (ROW_NUMBER() OVER (ORDER BY ptc.id))::int as rn
    FROM placeholder_calls ptc
),
new_standard_groups AS (
    INSERT INTO standard_groups (
        name,
        short_name,
        description,
        points,
        pass_points,
        active,
        tool_call_id
    )
    SELECT 
        sgu.name,
        sgu.short_name,
        sgu.description,
        sgu.points,
        sgu.pass_points,
        sgu.active,
        tcwo.tool_call_id
    FROM standard_groups_unnested sgu
    JOIN calls_with_order tcwo ON tcwo.rn = sgu.group_order
    RETURNING id, name, short_name, description, points, pass_points, active
),
link_rubric_standard_groups AS (
    INSERT INTO rubric_standard_groups (rubric_id, standard_group_id, position, active, created_at, updated_at)
    SELECT 
        sgu.rubric_id,
        nsg.id as standard_group_id,
        sgu.position,
        sgu.active,
        NOW(),
        NOW()
    FROM new_standard_groups nsg
    JOIN standard_groups_unnested sgu ON 
        sgu.name = nsg.name 
        AND COALESCE(sgu.short_name, '') = COALESCE(nsg.short_name, '')
        AND COALESCE(sgu.description, '') = COALESCE(nsg.description, '')
        AND sgu.points = nsg.points
        AND sgu.pass_points = nsg.pass_points
    ORDER BY sgu.group_order
    ON CONFLICT (rubric_id, standard_group_id) DO UPDATE SET
        position = EXCLUDED.position,
        active = EXCLUDED.active,
        updated_at = NOW()
),
standard_groups_with_order AS (
    SELECT DISTINCT ON (nsg.id)
        nsg.id as standard_group_id,
        sgu.standards
    FROM new_standard_groups nsg
    JOIN standard_groups_unnested sgu ON 
        sgu.name = nsg.name 
        AND COALESCE(sgu.short_name, '') = COALESCE(nsg.short_name, '')
        AND COALESCE(sgu.description, '') = COALESCE(nsg.description, '')
        AND sgu.points = nsg.points
        AND sgu.pass_points = nsg.pass_points
    ORDER BY nsg.id, sgu.group_order
),
standards_unnested AS (
    SELECT 
        sgwo.standard_group_id,
        std.name,
        COALESCE(NULLIF(std.description, ''), NULL)::text as description,
        std.points
    FROM standard_groups_with_order sgwo
    CROSS JOIN UNNEST(sgwo.standards) as std
    WHERE array_length(sgwo.standards, 1) > 0
),
new_standards AS (
    INSERT INTO standards (
        standard_group_id,
        name,
        description,
        points
    )
    SELECT 
        standard_group_id,
        name,
        description,
        points
    FROM standards_unnested
    RETURNING id
)
SELECT ur.rubric_id, ur.rubric_name, ap.actor_name
FROM update_rubric ur
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_update_scenario_name_v4(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_update_scenario_name_v4(scenario_id uuid, name text) RETURNS TABLE(scenario_id uuid, name text)
    LANGUAGE sql
    AS $$
UPDATE scenarios
SET name = api_update_scenario_name_v4.name,
    updated_at = NOW()
WHERE id = scenario_id
RETURNING id as scenario_id, name
$$;


--
-- Name: api_update_scenario_v4(uuid, text, boolean, boolean, boolean, boolean, boolean, boolean, text, text[], text[], types.q_update_scenario_v4_parameter[], uuid, text, uuid, text, text[], text[], text[], uuid[], text[], text[], text, text[], types.q_update_scenario_v4_question_timestamp[], uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_update_scenario_v4(scenario_id uuid, name text, active boolean, objectives_enabled boolean, images_enabled boolean, video_enabled boolean, questions_enabled boolean, problem_statement_enabled boolean, problem_statement text, document_ids text[], objective_ids text[], parameters types.q_update_scenario_v4_parameter[], profile_id uuid, description text DEFAULT NULL::text, video_agent_id uuid DEFAULT NULL::uuid, problem_statement_name text DEFAULT NULL::text, department_ids text[] DEFAULT NULL::text[], persona_ids text[] DEFAULT NULL::text[], template_document_ids text[] DEFAULT NULL::text[], upload_ids uuid[] DEFAULT NULL::uuid[], image_names text[] DEFAULT NULL::text[], video_ids text[] DEFAULT NULL::text[], active_video_id text DEFAULT NULL::text, question_ids text[] DEFAULT NULL::text[], question_timestamps types.q_update_scenario_v4_question_timestamp[] DEFAULT ARRAY[]::types.q_update_scenario_v4_question_timestamp[], scenario_agent_id uuid DEFAULT NULL::uuid, image_agent_id uuid DEFAULT NULL::uuid) RETURNS TABLE(scenario_exists boolean, scenario_id uuid, name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH raw_params AS (
    SELECT
        scenario_id AS scenario_id,
        name AS name,
        description AS description,
        active AS active,
        objectives_enabled AS objectives_enabled,
        images_enabled AS images_enabled,
        video_enabled AS video_enabled,
        questions_enabled AS questions_enabled,
        problem_statement_enabled AS problem_statement_enabled,
        video_agent_id AS video_agent_id,
        problem_statement AS problem_statement,
        problem_statement_name AS problem_statement_name,
        department_ids AS department_ids,
        persona_ids AS persona_ids,
        document_ids AS document_ids,
        template_document_ids AS template_document_ids,
        objective_ids AS objective_ids,
        parameters AS parameters,
        upload_ids AS upload_ids,
        image_names AS image_names,
        scenario_agent_id AS scenario_agent_id,
        image_agent_id AS image_agent_id,
        video_ids AS video_ids,
        active_video_id AS active_video_id,
        question_ids AS question_ids,
        question_timestamps AS question_timestamps,
        profile_id AS profile_id
),
-- Preprocessing: Filter composite objective IDs (those with "_" and length 2 when split)
filtered_objective_ids AS (
    SELECT ARRAY_AGG(obj_id) FILTER (WHERE obj_id IS NOT NULL) as objective_ids
    FROM raw_params rp
    CROSS JOIN UNNEST(COALESCE(rp.objective_ids, ARRAY[]::text[])) as obj_id
    WHERE NOT (obj_id LIKE '%_%' AND array_length(string_to_array(obj_id, '_'), 1) = 2)
),
-- Preprocessing: Extract parameter_item_ids and parameter_ids from parameters composite type array
parameter_preprocessing AS (
    SELECT
        COALESCE(
            ARRAY_AGG(DISTINCT field_id::text) FILTER (WHERE field_id IS NOT NULL),
            ARRAY[]::text[]
        ) as parameter_item_ids,
        COALESCE(
            ARRAY_AGG(DISTINCT param.parameter_id::text) FILTER (WHERE param.parameter_id IS NOT NULL),
            ARRAY[]::text[]
        ) as parameter_ids
    FROM raw_params rp
    CROSS JOIN UNNEST(COALESCE(rp.parameters, ARRAY[]::types.q_update_scenario_v4_parameter[])) as param
    CROSS JOIN UNNEST(COALESCE(param.field_ids, ARRAY[]::uuid[])) as field_id
),
-- Preprocessing: Construct upload_images array from upload_ids and image_names arrays
upload_images_preprocessing AS (
    SELECT
        COALESCE(
            ARRAY_AGG(
                (upload_id, image_name)::types.q_update_scenario_v4_upload_image
                ORDER BY idx
            ),
            '{}'::types.q_update_scenario_v4_upload_image[]
        ) as upload_images
    FROM raw_params rp
    CROSS JOIN LATERAL (
        SELECT 
            upload_id,
            image_name,
            ROW_NUMBER() OVER () - 1 as idx
        FROM UNNEST(
            COALESCE(rp.upload_ids, ARRAY[]::uuid[]),
            COALESCE(rp.image_names, ARRAY[]::text[])
        ) as t(upload_id, image_name)
    ) paired
    WHERE rp.upload_ids IS NOT NULL 
      AND rp.image_names IS NOT NULL
      AND array_length(rp.upload_ids, 1) = array_length(rp.image_names, 1)
      AND array_length(rp.upload_ids, 1) > 0
),
params AS (
    SELECT
        rp.scenario_id AS scenario_id,
        rp.name AS name,
        COALESCE(NULLIF(rp.description, ''), '') AS description,
        rp.active AS active,
        rp.objectives_enabled AS objectives_enabled,
        rp.images_enabled AS images_enabled,
        rp.video_enabled AS video_enabled,
        rp.questions_enabled AS questions_enabled,
        rp.problem_statement_enabled AS problem_statement_enabled,
        rp.video_agent_id AS video_agent_id,
        rp.problem_statement AS problem_statement,
        COALESCE(rp.problem_statement_name, rp.name) AS problem_statement_name,
        COALESCE(rp.department_ids, ARRAY[]::text[]) AS department_ids,
        COALESCE(rp.persona_ids, ARRAY[]::text[]) AS persona_ids,
        COALESCE(rp.document_ids, ARRAY[]::text[]) AS document_ids,
        COALESCE(rp.template_document_ids, ARRAY[]::text[]) AS template_document_ids,
        COALESCE(foi.objective_ids, ARRAY[]::text[]) AS objective_ids,
        COALESCE(pp.parameter_item_ids, ARRAY[]::text[]) AS parameter_item_ids,
        COALESCE(uip.upload_images, ARRAY[]::types.q_update_scenario_v4_upload_image[]) AS upload_images,
        rp.scenario_agent_id AS scenario_agent_id,
        rp.image_agent_id AS image_agent_id,
        COALESCE(pp.parameter_ids, ARRAY[]::text[]) AS parameter_ids,
        COALESCE(rp.video_ids, ARRAY[]::text[]) AS video_ids,
        rp.active_video_id AS active_video_id,
        COALESCE(rp.question_ids, ARRAY[]::text[]) AS question_ids,
        COALESCE(rp.question_timestamps, ARRAY[]::types.q_update_scenario_v4_question_timestamp[]) AS question_timestamps,
        rp.profile_id AS profile_id
    FROM raw_params rp
    CROSS JOIN filtered_objective_ids foi
    CROSS JOIN parameter_preprocessing pp
    CROSS JOIN upload_images_preprocessing uip
),
user_profile AS (
    SELECT 
        p.role,
        COALESCE(p.first_name || ' ' || p.last_name, 'System') as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
object_current_departments AS (
    -- Get scenario's current active department links
    SELECT COALESCE(ARRAY_AGG(department_id::text), ARRAY[]::text[]) as department_ids
    FROM scenario_departments
    WHERE scenario_id = (SELECT scenario_id FROM params) AND active = true
),
user_departments AS (
    -- Get user's departments
    SELECT COALESCE(ARRAY_AGG(department_id::text), ARRAY[]::text[]) as department_ids
    FROM profile_departments
    WHERE profile_id = (SELECT profile_id FROM params) AND active = true
),
validate_update_permissions AS (
    -- Validate department permissions for update operation
    SELECT validate_department_update_permissions(
        up.role::text,
        ocd.department_ids,
        ud.department_ids
    ) as validation_passed
    FROM user_profile up
    CROSS JOIN object_current_departments ocd
    CROSS JOIN user_departments ud
),
actor_profile AS (
    SELECT 
        (SELECT profile_id FROM params) as resolved_profile_id,
        up.actor_name
    FROM user_profile up
),
scenario_exists_check AS (
    -- Check if scenario exists
    SELECT EXISTS(
        SELECT 1 FROM scenarios WHERE id = (SELECT scenario_id FROM params)
    )::boolean as scenario_exists
),
scenario_exists AS (
    -- Get scenario info if exists
    SELECT id, name
    FROM scenarios
    WHERE id = (SELECT scenario_id FROM params)
),
update_scenario AS (
    -- Update scenario basic fields
    UPDATE scenarios
    SET 
        name = (SELECT name FROM params),
        description = (SELECT description FROM params),
        active = (SELECT active FROM params),
        objectives_enabled = (SELECT objectives_enabled FROM params),
        images_enabled = (SELECT images_enabled FROM params),
        video_enabled = (SELECT video_enabled FROM params),
        questions_enabled = (SELECT questions_enabled FROM params),
        problem_statement_enabled = (SELECT problem_statement_enabled FROM params),
        video_agent_id = COALESCE((SELECT video_agent_id FROM params), video_agent_id),
        scenario_agent_id = COALESCE((SELECT scenario_agent_id FROM params), scenario_agent_id),
        image_agent_id = COALESCE((SELECT image_agent_id FROM params), image_agent_id),
        updated_at = NOW()
    WHERE id IN (SELECT id FROM scenario_exists)
    RETURNING id as scenario_id, name
),
deactivate_problem_statements AS (
    -- Deactivate all existing problem statement links (preserve history)
    UPDATE scenario_problem_statements
    SET active = false, updated_at = NOW()
    WHERE scenario_id = (SELECT scenario_id FROM params) AND active = true
    RETURNING problem_statement_id
),
create_problem_statement AS (
    -- Create new problem_statement record (strong entity)
    INSERT INTO problem_statements (name, problem_statement, created_at, updated_at)
    SELECT 
        (SELECT problem_statement_name FROM params) as name,
        (SELECT problem_statement FROM params),
        NOW(),
        NOW()
    WHERE EXISTS (SELECT 1 FROM scenario_exists) 
      AND (SELECT problem_statement_name FROM params) IS NOT NULL 
      AND (SELECT problem_statement_name FROM params) != ''
    RETURNING id as problem_statement_id
),
link_problem_statement AS (
    -- Link new problem statement to scenario via junction table
    INSERT INTO scenario_problem_statements (scenario_id, problem_statement_id, active, created_at, updated_at)
    SELECT 
        (SELECT scenario_id FROM params),
        cps.problem_statement_id,
        true,
        NOW(),
        NOW()
    FROM create_problem_statement cps
    WHERE EXISTS (SELECT 1 FROM scenario_exists)
),
replace_departments AS (
    -- Delete all existing department links
    DELETE FROM scenario_departments 
    WHERE scenario_id = (SELECT scenario_id FROM params)
),
insert_departments AS (
    -- Insert new department links
    INSERT INTO scenario_departments (scenario_id, department_id, active, created_at, updated_at)
    SELECT 
        (SELECT scenario_id FROM params),
        dept_id::uuid,
        true,
        NOW(),
        NOW()
    FROM UNNEST((SELECT department_ids FROM params)) as dept_id
    WHERE EXISTS (SELECT 1 FROM scenario_exists)
      AND COALESCE(array_length((SELECT department_ids FROM params), 1), 0) > 0
    ON CONFLICT (scenario_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
replace_personas AS (
    -- Delete all existing persona links
    DELETE FROM scenario_personas 
    WHERE scenario_id = (SELECT scenario_id FROM params)
),
insert_personas AS (
    -- Insert new persona links
    INSERT INTO scenario_personas (scenario_id, persona_id, active, created_at, updated_at)
    SELECT 
        (SELECT scenario_id FROM params),
        persona_id::uuid,
        true,
        NOW(),
        NOW()
    FROM UNNEST((SELECT persona_ids FROM params)) as persona_id
    WHERE EXISTS (SELECT 1 FROM scenario_exists)
      AND COALESCE(array_length((SELECT persona_ids FROM params), 1), 0) > 0
    ON CONFLICT (scenario_id, persona_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
replace_documents AS (
    -- Delete all existing document links
    DELETE FROM scenario_documents 
    WHERE scenario_id = (SELECT scenario_id FROM params)
),
insert_documents AS (
    -- Insert new document links (both regular and template documents)
    INSERT INTO scenario_documents (scenario_id, document_id, active, created_at, updated_at)
    SELECT 
        (SELECT scenario_id FROM params),
        doc_id::uuid,
        true,
        NOW(),
        NOW()
    FROM (
        SELECT doc_id FROM UNNEST((SELECT document_ids FROM params)) as doc_id
        UNION ALL
        SELECT doc_id FROM UNNEST((SELECT template_document_ids FROM params)) as doc_id
    ) all_docs
    WHERE EXISTS (SELECT 1 FROM scenario_exists)
      AND (COALESCE(array_length((SELECT document_ids FROM params), 1), 0) > 0 
           OR COALESCE(array_length((SELECT template_document_ids FROM params), 1), 0) > 0)
    ON CONFLICT (scenario_id, document_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
replace_objectives AS (
    -- Delete all existing objective links
    DELETE FROM scenario_objectives 
    WHERE scenario_id = (SELECT scenario_id FROM params)
),
objectives_with_index AS (
    -- Prepare objectives with their index
    SELECT 
        obj_text,
        ROW_NUMBER() OVER () - 1 as idx
    FROM UNNEST((SELECT objective_ids FROM params)) as obj_text
    WHERE EXISTS (SELECT 1 FROM scenario_exists)
      AND COALESCE(array_length((SELECT objective_ids FROM params), 1), 0) > 0
),
existing_objectives AS (
    -- Find existing objectives by text
    SELECT id as objective_id, objective
    FROM objectives
    WHERE objective = ANY(SELECT obj_text FROM objectives_with_index)
),
new_objectives AS (
    -- Create new objectives that don't exist yet
    INSERT INTO objectives (objective, created_at, updated_at)
    SELECT DISTINCT
        owi.obj_text,
        NOW(),
        NOW()
    FROM objectives_with_index owi
    WHERE NOT EXISTS (
        SELECT 1 FROM existing_objectives eo WHERE eo.objective = owi.obj_text
    )
    RETURNING id as objective_id, objective
),
all_objectives AS (
    -- Combine existing and new objectives
    SELECT objective_id, objective FROM existing_objectives
    UNION ALL
    SELECT objective_id, objective FROM new_objectives
),
insert_objectives AS (
    -- Link objectives to scenario via junction table
    INSERT INTO scenario_objectives (scenario_id, objective_id, idx, created_at)
    SELECT 
        (SELECT scenario_id FROM params),
        ao.objective_id,
        owi.idx,
        NOW()
    FROM objectives_with_index owi
    JOIN all_objectives ao ON ao.objective = owi.obj_text
),
replace_parameters AS (
    -- Delete all existing field links
    DELETE FROM scenario_fields 
    WHERE scenario_id = (SELECT scenario_id FROM params)
),
insert_parameters AS (
    -- Insert new field links
    INSERT INTO scenario_fields (scenario_id, field_id, active, created_at, updated_at)
    SELECT 
        (SELECT scenario_id FROM params),
        field_id::uuid,
        true,
        NOW(),
        NOW()
    FROM UNNEST((SELECT parameter_item_ids FROM params)) as field_id
    WHERE EXISTS (SELECT 1 FROM scenario_exists)
      AND COALESCE(array_length((SELECT parameter_item_ids FROM params), 1), 0) > 0
    ON CONFLICT (scenario_id, field_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
delete_old_images AS (
    -- Delete old scenario image links (junction table entries)
    DELETE FROM scenario_images
    WHERE scenario_id = (SELECT scenario_id FROM params)
),
create_images AS (
    -- Create images if they don't exist
    INSERT INTO images (name, created_at, updated_at, active)
    SELECT DISTINCT
        img.name,
        NOW(),
        NOW(),
        true
    FROM params x
    CROSS JOIN UNNEST(x.upload_images) as img
    WHERE EXISTS (SELECT 1 FROM scenario_exists)
      AND array_length((SELECT upload_images FROM params), 1) > 0
      AND NOT EXISTS (
          SELECT 1 FROM images i
          JOIN image_uploads iu ON iu.image_id = i.id
          WHERE iu.upload_id = img.upload_id AND i.name = img.name
      )
    RETURNING id as image_id
),
link_image_uploads AS (
    -- Link images to uploads via junction table
    INSERT INTO image_uploads (image_id, upload_id, active, created_at, updated_at)
    SELECT DISTINCT
        ci.image_id,
        img.upload_id,
        true,
        NOW(),
        NOW()
    FROM create_images ci
    CROSS JOIN params x
    CROSS JOIN UNNEST(x.upload_images) as img
    WHERE EXISTS (SELECT 1 FROM scenario_exists)
      AND array_length((SELECT upload_images FROM params), 1) > 0
    ON CONFLICT (image_id, upload_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
get_images AS (
    -- Get existing images via image_uploads junction table
    SELECT i.id as image_id
    FROM params x
    CROSS JOIN UNNEST(x.upload_images) as img
    JOIN image_uploads iu ON iu.upload_id = img.upload_id
    JOIN images i ON i.id = iu.image_id AND i.name = img.name
    WHERE EXISTS (SELECT 1 FROM scenario_exists)
      AND iu.active = true
),
all_images AS (
    SELECT image_id FROM create_images
    UNION
    SELECT image_id FROM get_images
),
link_images AS (
    -- Link images to scenario via junction table
    INSERT INTO scenario_images (scenario_id, image_id, active, created_at, updated_at)
    SELECT 
        (SELECT scenario_id FROM params),
        ai.image_id,
        true,
        NOW(),
        NOW()
    FROM all_images ai
    WHERE EXISTS (SELECT 1 FROM scenario_exists)
      AND array_length((SELECT upload_images FROM params), 1) > 0
    ON CONFLICT (scenario_id, image_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
deactivate_scenario_parameters AS (
    -- Soft-delete removed parameters (set active = false for parameters not in new list)
    UPDATE scenario_parameters
    SET active = false, updated_at = NOW()
    WHERE scenario_id = (SELECT scenario_id FROM params)
    AND active = true
    AND (
        COALESCE(array_length((SELECT parameter_ids FROM params), 1), 0) = 0
        OR parameter_id NOT IN (SELECT unnest((SELECT parameter_ids FROM params))::uuid)
    )
),
link_scenario_parameters AS (
    -- Insert or reactivate parameter links if provided (array is never NULL, but may be empty)
    INSERT INTO scenario_parameters (scenario_id, parameter_id, active, created_at, updated_at)
    SELECT 
        (SELECT scenario_id FROM params),
        param_id::uuid,
        true,
        NOW(),
        NOW()
    FROM UNNEST((SELECT parameter_ids FROM params)) as param_id
    WHERE COALESCE(array_length((SELECT parameter_ids FROM params), 1), 0) > 0
    ON CONFLICT (scenario_id, parameter_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
-- Update department links for content items based on scenario's departments
-- Get all content items currently linked to this scenario (after all updates)
scenario_content_images AS (
    SELECT DISTINCT image_id
    FROM scenario_images
    WHERE scenario_id = (SELECT scenario_id FROM params)
),
scenario_content_objectives AS (
    SELECT DISTINCT objective_id
    FROM scenario_objectives
    WHERE scenario_id = (SELECT scenario_id FROM params)
),
scenario_content_problem_statements AS (
    SELECT DISTINCT problem_statement_id
    FROM scenario_problem_statements
    WHERE scenario_id = (SELECT scenario_id FROM params) AND active = true
),
scenario_content_videos AS (
    SELECT DISTINCT video_id
    FROM scenario_videos
    WHERE scenario_id = (SELECT scenario_id FROM params)
),
scenario_content_questions AS (
    SELECT DISTINCT question_id
    FROM scenario_questions
    WHERE scenario_id = (SELECT scenario_id FROM params) AND active = true
),
-- Replace department links for images
replace_image_departments AS (
    DELETE FROM image_departments
    WHERE image_id IN (SELECT image_id FROM scenario_content_images)
),
link_image_departments AS (
    INSERT INTO image_departments (image_id, department_id, active, created_at, updated_at)
    SELECT DISTINCT
        sci.image_id,
        dept_id::uuid,
        true,
        NOW(),
        NOW()
    FROM scenario_content_images sci
    CROSS JOIN UNNEST((SELECT department_ids FROM params)) as dept_id
    WHERE COALESCE(array_length((SELECT department_ids FROM params), 1), 0) > 0
    ON CONFLICT (image_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
-- Replace department links for videos
replace_video_departments AS (
    DELETE FROM video_departments
    WHERE video_id IN (SELECT video_id FROM scenario_content_videos)
),
link_video_departments AS (
    INSERT INTO video_departments (video_id, department_id, active, created_at, updated_at)
    SELECT DISTINCT
        scv.video_id,
        dept_id::uuid,
        true,
        NOW(),
        NOW()
    FROM scenario_content_videos scv
    CROSS JOIN UNNEST((SELECT department_ids FROM params)) as dept_id
    WHERE COALESCE(array_length((SELECT department_ids FROM params), 1), 0) > 0
    ON CONFLICT (video_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
-- Replace department links for objectives
replace_objective_departments AS (
    DELETE FROM objective_departments
    WHERE objective_id IN (SELECT objective_id FROM scenario_content_objectives)
),
link_objective_departments AS (
    INSERT INTO objective_departments (objective_id, department_id, active, created_at, updated_at)
    SELECT DISTINCT
        sco.objective_id,
        dept_id::uuid,
        true,
        NOW(),
        NOW()
    FROM scenario_content_objectives sco
    CROSS JOIN UNNEST((SELECT department_ids FROM params)) as dept_id
    WHERE COALESCE(array_length((SELECT department_ids FROM params), 1), 0) > 0
    ON CONFLICT (objective_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
-- Replace department links for questions
replace_question_departments AS (
    DELETE FROM question_departments
    WHERE question_id IN (SELECT question_id FROM scenario_content_questions)
),
link_question_departments AS (
    INSERT INTO question_departments (question_id, department_id, active, created_at, updated_at)
    SELECT DISTINCT
        scq.question_id,
        dept_id::uuid,
        true,
        NOW(),
        NOW()
    FROM scenario_content_questions scq
    CROSS JOIN UNNEST((SELECT department_ids FROM params)) as dept_id
    WHERE COALESCE(array_length((SELECT department_ids FROM params), 1), 0) > 0
    ON CONFLICT (question_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
-- Replace department links for problem statements
replace_problem_statement_departments AS (
    DELETE FROM problem_statement_departments
    WHERE problem_statement_id IN (SELECT problem_statement_id FROM scenario_content_problem_statements)
),
link_problem_statement_departments AS (
    INSERT INTO problem_statement_departments (problem_statement_id, department_id, active, created_at, updated_at)
    SELECT DISTINCT
        scps.problem_statement_id,
        dept_id::uuid,
        true,
        NOW(),
        NOW()
    FROM scenario_content_problem_statements scps
    CROSS JOIN UNNEST((SELECT department_ids FROM params)) as dept_id
    WHERE COALESCE(array_length((SELECT department_ids FROM params), 1), 0) > 0
    ON CONFLICT (problem_statement_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
-- Update/create randomization ranges for scenario
-- Upsert persona ranges (create if not exists, update if exists)
upsert_persona_ranges AS (
    INSERT INTO scenario_persona_ranges (scenario_id, min_count, max_count)
    SELECT us.scenario_id, 1, 3
    FROM update_scenario us
    ON CONFLICT (scenario_id) DO UPDATE SET
        updated_at = NOW()
),
upsert_document_ranges AS (
    INSERT INTO scenario_document_ranges (scenario_id, min_count, max_count)
    SELECT us.scenario_id, 0, 3
    FROM update_scenario us
    ON CONFLICT (scenario_id) DO UPDATE SET
        updated_at = NOW()
),
upsert_parameter_ranges AS (
    INSERT INTO scenario_parameter_ranges (scenario_id, min_count, max_count)
    SELECT us.scenario_id, 0, 3
    FROM update_scenario us
    ON CONFLICT (scenario_id) DO UPDATE SET
        updated_at = NOW()
),
upsert_field_ranges AS (
    -- Upsert field ranges for each parameter linked to the scenario
    INSERT INTO scenario_field_ranges (scenario_id, parameter_id, min_count, max_count)
    SELECT 
        us.scenario_id,
        param_id::uuid,
        1,  -- default min
        3   -- default max
    FROM update_scenario us
    CROSS JOIN UNNEST((SELECT parameter_ids FROM params)) as param_id
    WHERE COALESCE(array_length((SELECT parameter_ids FROM params), 1), 0) > 0
    ON CONFLICT (scenario_id, parameter_id) DO UPDATE SET
        updated_at = NOW()
)
SELECT 
    sec.scenario_exists::boolean as scenario_exists,
    us.scenario_id::uuid as scenario_id,
    us.name::text as name,
    ap.actor_name::text as actor_name
FROM scenario_exists_check sec
LEFT JOIN update_scenario us ON sec.scenario_exists = true
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_update_settings_v4(text, text, text, text, text, text, text, text, text, text, text, text, text, text, text, text, boolean, integer, integer, integer, uuid, types.i_update_settings_v4_provider_key[], types.i_update_settings_v4_auth_key[], uuid, uuid, types.i_update_settings_v4_provider_enabled[], types.i_update_settings_v4_auth_enabled[], types.i_update_settings_v4_auth_value[], uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_update_settings_v4(name text, description text, primary_color text, accent text, background text, surface text, success text, warning text, error text, sidebar_background text, sidebar_primary text, chart1 text, chart2 text, chart3 text, chart4 text, chart5 text, guest_login_enabled boolean, success_threshold integer, warning_threshold integer, danger_threshold integer, profile_id uuid, provider_keys types.i_update_settings_v4_provider_key[] DEFAULT ARRAY[]::types.i_update_settings_v4_provider_key[], auth_keys types.i_update_settings_v4_auth_key[] DEFAULT ARRAY[]::types.i_update_settings_v4_auth_key[], default_admin_profile_id uuid DEFAULT NULL::uuid, default_guest_profile_id uuid DEFAULT NULL::uuid, provider_enabled types.i_update_settings_v4_provider_enabled[] DEFAULT ARRAY[]::types.i_update_settings_v4_provider_enabled[], auth_enabled types.i_update_settings_v4_auth_enabled[] DEFAULT ARRAY[]::types.i_update_settings_v4_auth_enabled[], auth_values types.i_update_settings_v4_auth_value[] DEFAULT ARRAY[]::types.i_update_settings_v4_auth_value[], department_ids uuid[] DEFAULT ARRAY[]::uuid[]) RETURNS TABLE(settings_id uuid, settings_name text, actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        name AS name,
        description AS description,
        primary_color AS primary_color,
        accent AS accent,
        background AS background,
        surface AS surface,
        success AS success,
        warning AS warning,
        error AS error,
        sidebar_background AS sidebar_background,
        sidebar_primary AS sidebar_primary,
        chart1 AS chart1,
        chart2 AS chart2,
        chart3 AS chart3,
        chart4 AS chart4,
        chart5 AS chart5,
        guest_login_enabled AS guest_login_enabled,
        success_threshold AS success_threshold,
        warning_threshold AS warning_threshold,
        danger_threshold AS danger_threshold,
        profile_id AS profile_id,
        provider_keys AS provider_keys,
        auth_keys AS auth_keys,
        default_admin_profile_id AS default_admin_profile_id,
        default_guest_profile_id AS default_guest_profile_id,
        provider_enabled AS provider_enabled,
        auth_enabled AS auth_enabled,
        auth_values AS auth_values,
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids
),
actor_profile AS (
    SELECT
        p.id as profile_id,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
old_settings_id AS (
    -- Capture old settings ID before deactivating
    SELECT id as old_id FROM settings WHERE active = true LIMIT 1
),
deactivate_current AS (
    -- Deactivate the current active settings row
    UPDATE settings
    SET active = false
    WHERE active = true
),
insert_new AS (
    -- Insert new active settings row
    INSERT INTO settings (
        active,
        name,
        description,
        primary_color,
        accent,
        background,
        surface,
        success,
        warning,
        error,
        sidebar_background,
        sidebar_primary,
        chart1,
        chart2,
        chart3,
        chart4,
        chart5,
        guest_login_enabled,
        success_threshold,
        warning_threshold,
        danger_threshold
    )
    SELECT 
        true,
        name,
        description,
        primary_color,
        accent,
        background,
        surface,
        success,
        warning,
        error,
        sidebar_background,
        sidebar_primary,
        chart1,
        chart2,
        chart3,
        chart4,
        chart5,
        guest_login_enabled,
        success_threshold,
        warning_threshold,
        danger_threshold
    FROM params
    RETURNING id as settings_id, name as settings_name
),
manage_setting_providers AS (
    -- Manage provider links based on provider_enabled array
    INSERT INTO setting_providers (settings_id, provider_id, active, created_at, updated_at)
    SELECT 
        (SELECT settings_id FROM insert_new LIMIT 1),
        pe.provider_id,
        pe.enabled,
        NOW(),
        NOW()
    FROM params x
    CROSS JOIN UNNEST(x.provider_enabled) AS pe
    WHERE array_length(x.provider_enabled, 1) > 0
    ON CONFLICT (settings_id, provider_id) DO UPDATE SET
        active = EXCLUDED.active,
        updated_at = NOW()
),
copy_setting_providers_fallback AS (
    -- Fallback: Copy setting_providers links from old settings to new (if provider_enabled not provided)
    INSERT INTO setting_providers (settings_id, provider_id, active, created_at, updated_at)
    SELECT 
        (SELECT settings_id FROM insert_new LIMIT 1),
        sp.provider_id,
        sp.active,
        NOW(),
        NOW()
    FROM old_settings_id osi
    CROSS JOIN setting_providers sp
    JOIN params x ON array_length(x.provider_enabled, 1) IS NULL
    WHERE sp.settings_id = osi.old_id AND sp.active = true
      AND NOT EXISTS (
          SELECT 1 FROM params x2
          CROSS JOIN UNNEST(x2.provider_enabled) AS pe
          WHERE pe.provider_id = sp.provider_id
      )
    ON CONFLICT (settings_id, provider_id) DO UPDATE SET
        active = COALESCE(EXCLUDED.active, setting_providers.active),
        updated_at = NOW()
),
manage_setting_auths AS (
    -- Manage auth links based on auth_enabled array
    INSERT INTO setting_auths (settings_id, auth_id, active, created_at, updated_at)
    SELECT 
        (SELECT settings_id FROM insert_new LIMIT 1),
        ae.auth_id,
        ae.enabled,
        NOW(),
        NOW()
    FROM params x
    CROSS JOIN UNNEST(x.auth_enabled) AS ae
    WHERE array_length(x.auth_enabled, 1) > 0
    ON CONFLICT (settings_id, auth_id) DO UPDATE SET
        active = EXCLUDED.active,
        updated_at = NOW()
),
copy_setting_auths_fallback AS (
    -- Fallback: Copy setting_auths links from old settings to new (if auth_enabled not provided)
    INSERT INTO setting_auths (settings_id, auth_id, active, created_at, updated_at)
    SELECT 
        (SELECT settings_id FROM insert_new LIMIT 1),
        sa.auth_id,
        sa.active,
        NOW(),
        NOW()
    FROM old_settings_id osi
    CROSS JOIN setting_auths sa
    JOIN params x ON array_length(x.auth_enabled, 1) IS NULL
    WHERE sa.settings_id = osi.old_id AND sa.active = true
      AND NOT EXISTS (
          SELECT 1 FROM params x2
          CROSS JOIN UNNEST(x2.auth_enabled) AS ae
          WHERE ae.auth_id = sa.auth_id
      )
    ON CONFLICT (settings_id, auth_id) DO UPDATE SET
        active = COALESCE(EXCLUDED.active, setting_auths.active),
        updated_at = NOW()
),
manage_setting_auth_values AS (
    -- Manage auth values based on auth_values array (for non-encrypted items)
    INSERT INTO setting_auth_values (settings_id, auth_id, auth_item_id, value, created_at, updated_at)
    SELECT 
        (SELECT settings_id FROM insert_new LIMIT 1),
        av.auth_id,
        avi.auth_item_id,
        avi.value,
        NOW(),
        NOW()
    FROM params x
    CROSS JOIN UNNEST(x.auth_values) AS av
    CROSS JOIN UNNEST(av.items) AS avi
    WHERE array_length(x.auth_values, 1) > 0
    ON CONFLICT (settings_id, auth_id, auth_item_id) DO UPDATE SET
        value = EXCLUDED.value,
        updated_at = NOW()
),
copy_setting_auth_values_fallback AS (
    -- Fallback: Copy setting_auth_values from old settings to new (if auth_values not provided)
    INSERT INTO setting_auth_values (settings_id, auth_id, auth_item_id, value, created_at, updated_at)
    SELECT 
        (SELECT settings_id FROM insert_new LIMIT 1),
        sav.auth_id,
        sav.auth_item_id,
        sav.value,
        NOW(),
        NOW()
    FROM old_settings_id osi
    CROSS JOIN setting_auth_values sav
    JOIN params x ON array_length(x.auth_values, 1) IS NULL
    WHERE sav.settings_id = osi.old_id
    ON CONFLICT (settings_id, auth_id, auth_item_id) DO UPDATE SET
        value = EXCLUDED.value,
        updated_at = NOW()
),
copy_setting_default_account AS (
    -- Copy default admin account from old settings to new (if not provided)
    INSERT INTO settings_default_account (settings_id, profile_id, active, created_at, updated_at)
    SELECT 
        (SELECT settings_id FROM insert_new LIMIT 1),
        sda.profile_id,
        CASE WHEN (SELECT default_admin_profile_id FROM params) IS NULL THEN sda.active ELSE false END,
        NOW(),
        NOW()
    FROM old_settings_id osi
    CROSS JOIN settings_default_account sda
    JOIN params x ON x.default_admin_profile_id IS NULL
    WHERE sda.settings_id = osi.old_id AND sda.active = true
    ON CONFLICT (settings_id, profile_id) DO UPDATE SET
        active = EXCLUDED.active,
        updated_at = NOW()
),
copy_setting_default_guest AS (
    -- Copy default guest account from old settings to new (if not provided)
    INSERT INTO settings_default_guest (settings_id, profile_id, active, created_at, updated_at)
    SELECT 
        (SELECT settings_id FROM insert_new LIMIT 1),
        sdg.profile_id,
        CASE WHEN (SELECT default_guest_profile_id FROM params) IS NULL THEN sdg.active ELSE false END,
        NOW(),
        NOW()
    FROM old_settings_id osi
    CROSS JOIN settings_default_guest sdg
    JOIN params x ON x.default_guest_profile_id IS NULL
    WHERE sdg.settings_id = osi.old_id AND sdg.active = true
    ON CONFLICT (settings_id, profile_id) DO UPDATE SET
        active = EXCLUDED.active,
        updated_at = NOW()
),
apply_default_admin_account AS (
    -- Apply new default admin account (deactivate old, activate new)
    UPDATE settings_default_account
    SET active = false, updated_at = NOW()
    WHERE settings_id = (SELECT settings_id FROM insert_new LIMIT 1)
      AND (SELECT default_admin_profile_id FROM params) IS NOT NULL
),
insert_default_admin_account AS (
    -- Insert new default admin account
    INSERT INTO settings_default_account (settings_id, profile_id, active, created_at, updated_at)
    SELECT 
        (SELECT settings_id FROM insert_new LIMIT 1),
        default_admin_profile_id,
        true,
        NOW(),
        NOW()
    FROM params
    WHERE default_admin_profile_id IS NOT NULL
    ON CONFLICT (settings_id, profile_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
apply_default_guest_account AS (
    -- Apply new default guest account (deactivate old, activate new)
    UPDATE settings_default_guest
    SET active = false, updated_at = NOW()
    WHERE settings_id = (SELECT settings_id FROM insert_new LIMIT 1)
      AND (SELECT default_guest_profile_id FROM params) IS NOT NULL
),
insert_default_guest_account AS (
    -- Insert new default guest account
    INSERT INTO settings_default_guest (settings_id, profile_id, active, created_at, updated_at)
    SELECT 
        (SELECT settings_id FROM insert_new LIMIT 1),
        default_guest_profile_id,
        true,
        NOW(),
        NOW()
    FROM params
    WHERE default_guest_profile_id IS NOT NULL
    ON CONFLICT (settings_id, profile_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
apply_provider_keys AS (
    -- Apply new provider key mappings
    -- First deactivate all existing provider keys for this settings
    UPDATE setting_provider_keys
    SET active = false, updated_at = NOW()
    WHERE settings_id = (SELECT settings_id FROM insert_new LIMIT 1)
),
insert_provider_keys AS (
    -- Insert new provider key mappings
    INSERT INTO setting_provider_keys (settings_id, provider_id, key_id, active, created_at, updated_at)
    SELECT 
        (SELECT settings_id FROM insert_new LIMIT 1),
        pk.provider_id,
        pk.key_id,
        true,
        NOW(),
        NOW()
    FROM params x
    CROSS JOIN UNNEST(x.provider_keys) AS pk
    WHERE array_length(x.provider_keys, 1) > 0
    ON CONFLICT (settings_id, provider_id, key_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
apply_auth_keys AS (
    -- Apply new auth key mappings (auth_id -> auth_item_id -> key_id)
    -- First deactivate all existing auth keys for this settings
    UPDATE setting_auth_keys
    SET active = false, updated_at = NOW()
    WHERE settings_id = (SELECT settings_id FROM insert_new LIMIT 1)
),
insert_auth_keys AS (
    -- Insert new auth key mappings
    INSERT INTO setting_auth_keys (settings_id, auth_id, auth_item_id, key_id, active, created_at, updated_at)
    SELECT 
        (SELECT settings_id FROM insert_new LIMIT 1),
        ak.auth_id,
        aki.auth_item_id,
        aki.key_id,
        true,
        NOW(),
        NOW()
    FROM params x
    CROSS JOIN UNNEST(x.auth_keys) AS ak
    CROSS JOIN UNNEST(ak.items) AS aki
    WHERE array_length(x.auth_keys, 1) > 0
    ON CONFLICT (settings_id, auth_id, auth_item_id, key_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
copy_department_settings AS (
    -- Copy department_settings links from old settings to new (if department_ids not provided)
    INSERT INTO department_settings (settings_id, department_id, active, created_at, updated_at)
    SELECT 
        (SELECT settings_id FROM insert_new LIMIT 1),
        ds.department_id,
        ds.active,
        NOW(),
        NOW()
    FROM old_settings_id osi
    CROSS JOIN department_settings ds
    JOIN params x ON array_length(x.department_ids, 1) IS NULL
    WHERE ds.settings_id = osi.old_id AND ds.active = true
    ON CONFLICT (settings_id, department_id) DO UPDATE SET
        active = EXCLUDED.active,
        updated_at = NOW()
),
replace_department_settings AS (
    -- Deactivate all existing department_settings links for the new settings
    UPDATE department_settings
    SET active = false, updated_at = NOW()
    WHERE settings_id = (SELECT settings_id FROM insert_new LIMIT 1)
      AND (SELECT array_length(department_ids, 1) FROM params) IS NOT NULL
),
link_department_settings AS (
    -- Insert new department_settings links based on department_ids array
    -- Empty array = global settings (no links), non-empty = department-specific
    INSERT INTO department_settings (settings_id, department_id, active, created_at, updated_at)
    SELECT 
        (SELECT settings_id FROM insert_new LIMIT 1),
        dept_id,
        true,
        NOW(),
        NOW()
    FROM params x
    CROSS JOIN UNNEST(x.department_ids) AS dept_id
    WHERE array_length(x.department_ids, 1) > 0
    ON CONFLICT (settings_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
)
SELECT 
    in_new.settings_id,
    in_new.settings_name,
    ap.actor_name
FROM insert_new in_new
CROSS JOIN actor_profile ap
$$;


--
-- Name: api_update_simulation_v4(uuid, text, text, boolean, boolean, uuid[], uuid[], boolean[], uuid[], boolean[], boolean[], integer[], boolean[], boolean[], types.i_create_simulation_v4_scenario_rubric_grade_agent[], boolean[], boolean[], boolean[], uuid, uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.api_update_simulation_v4(simulation_id uuid, title text, description text, active boolean, practice_simulation boolean, department_ids uuid[], scenario_ids uuid[], scenario_active_flags boolean[], video_ids uuid[], video_active_flags boolean[], scenario_hints_enabled boolean[], scenario_time_limit_seconds integer[], scenario_audio_enabled boolean[], scenario_text_enabled boolean[], scenario_rubric_grade_agents types.i_create_simulation_v4_scenario_rubric_grade_agent[], video_show_problem_statement boolean[], video_show_objectives boolean[], video_show_image boolean[], hint_agent_id uuid, simulation_text_agent_id uuid, simulation_voice_agent_id uuid, profile_id uuid) RETURNS TABLE(actor_name text)
    LANGUAGE sql
    AS $$
WITH params AS (
    SELECT 
        simulation_id AS simulation_id,
        title AS title,
        description AS description,
        active AS active,
        practice_simulation AS practice_simulation,
        COALESCE(department_ids, ARRAY[]::uuid[]) AS department_ids,
        COALESCE(scenario_ids, ARRAY[]::uuid[]) AS scenario_ids,
        COALESCE(scenario_active_flags, ARRAY[]::boolean[]) AS scenario_active_flags,
        COALESCE(video_ids, ARRAY[]::uuid[]) AS video_ids,
        COALESCE(video_active_flags, ARRAY[]::boolean[]) AS video_active_flags,
        COALESCE(scenario_hints_enabled, ARRAY[]::boolean[]) AS scenario_hints_enabled,
        COALESCE(scenario_time_limit_seconds, ARRAY[]::int[]) AS scenario_time_limit_seconds,
        COALESCE(scenario_audio_enabled, ARRAY[]::boolean[]) AS scenario_audio_enabled,
        COALESCE(scenario_text_enabled, ARRAY[]::boolean[]) AS scenario_text_enabled,
        COALESCE(scenario_rubric_grade_agents, ARRAY[]::types.i_create_simulation_v4_scenario_rubric_grade_agent[]) AS scenario_rubric_grade_agents,
        COALESCE(video_show_problem_statement, ARRAY[]::boolean[]) AS video_show_problem_statement,
        COALESCE(video_show_objectives, ARRAY[]::boolean[]) AS video_show_objectives,
        COALESCE(video_show_image, ARRAY[]::boolean[]) AS video_show_image,
        hint_agent_id AS hint_agent_id,
        simulation_text_agent_id AS simulation_text_agent_id,
        simulation_voice_agent_id AS simulation_voice_agent_id,
        profile_id AS profile_id
),
user_profile AS (
    SELECT 
        p.role,
        p.first_name || ' ' || p.last_name as actor_name
    FROM params x
    JOIN profiles p ON p.id = x.profile_id
),
object_current_departments AS (
    SELECT COALESCE(ARRAY_AGG(department_id::text), ARRAY[]::text[]) as department_ids
    FROM params x
    JOIN simulation_departments sd ON sd.simulation_id = x.simulation_id AND sd.active = true
),
user_departments AS (
    SELECT COALESCE(ARRAY_AGG(department_id::text), ARRAY[]::text[]) as department_ids
    FROM params x
    JOIN profile_departments pd ON pd.profile_id = x.profile_id AND pd.active = true
),
validate_update_permissions AS (
    SELECT validate_department_update_permissions(
        up.role::text,
        ocd.department_ids,
        ud.department_ids
    ) as validation_passed
    FROM user_profile up
    CROSS JOIN object_current_departments ocd
    CROSS JOIN user_departments ud
),
assert_permissions AS (
    SELECT 1
    FROM validate_update_permissions
    WHERE validation_passed = true
),
actor_profile AS (
    SELECT 
        x.profile_id,
        up.actor_name
    FROM params x
    CROSS JOIN user_profile up
),
update_simulation AS (
    UPDATE simulations SET
        title = x.title,
        description = x.description,
        active = x.active,
        practice_simulation = x.practice_simulation,
        hint_agent_id = COALESCE(x.hint_agent_id, simulations.hint_agent_id),
        simulation_text_agent_id = COALESCE(x.simulation_text_agent_id, simulations.simulation_text_agent_id),
        simulation_voice_agent_id = x.simulation_voice_agent_id,
        updated_at = NOW()
    FROM params x
    JOIN assert_permissions ap ON TRUE
    WHERE simulations.id = x.simulation_id
    RETURNING simulations.id as simulation_id
),
replace_time_limits AS (
    DELETE FROM scenario_time_limits 
    WHERE simulation_id IN (SELECT simulation_id FROM params)
),
replace_departments AS (
    UPDATE simulation_departments 
    SET active = false, updated_at = NOW()
    WHERE simulation_id IN (SELECT simulation_id FROM params) AND active = true
),
link_departments AS (
    INSERT INTO simulation_departments (simulation_id, department_id, active, created_at, updated_at)
    SELECT 
        x.simulation_id,
        dept_id,
        true,
        NOW(),
        NOW()
    FROM params x
    CROSS JOIN UNNEST(x.department_ids) as dept_id
    WHERE array_length(x.department_ids, 1) > 0
    ON CONFLICT (simulation_id, department_id) DO UPDATE SET
        active = true,
        updated_at = NOW()
),
replace_scenarios AS (
    DELETE FROM simulation_scenarios 
    WHERE simulation_id IN (SELECT simulation_id FROM params)
),
scenarios_data AS (
    SELECT DISTINCT
        scenario_id,
        active_flag,
        hints_enabled,
        audio_enabled,
        text_enabled,
        time_limit_seconds,
        row_num
    FROM (
        SELECT 
            scenario_id,
            active_flag,
            COALESCE(hints_enabled, false) as hints_enabled,
            COALESCE(audio_enabled, false) as audio_enabled,
            COALESCE(text_enabled, true) as text_enabled,
            time_limit_seconds,
            ROW_NUMBER() OVER () as row_num
        FROM params x
        CROSS JOIN UNNEST(
            x.scenario_ids, 
            x.scenario_active_flags, 
            x.scenario_hints_enabled,
            x.scenario_audio_enabled,
            x.scenario_text_enabled,
            x.scenario_time_limit_seconds
        ) AS t(scenario_id, active_flag, hints_enabled, audio_enabled, text_enabled, time_limit_seconds)
    ) sub
),
scenarios_with_order AS (
    SELECT 
        scenario_id,
        active_flag,
        hints_enabled,
        audio_enabled,
        text_enabled,
        time_limit_seconds,
        ROW_NUMBER() OVER (
            ORDER BY active_flag DESC, row_num
        ) as position
    FROM scenarios_data
    WHERE EXISTS (SELECT 1 FROM params x WHERE array_length(x.scenario_ids, 1) > 0)
),
link_time_limits AS (
    INSERT INTO scenario_time_limits (simulation_id, scenario_id, time_limit_seconds, active, created_at, updated_at)
    SELECT 
        x.simulation_id,
        swo.scenario_id,
        swo.time_limit_seconds,
        true,
        NOW(),
        NOW()
    FROM params x
    CROSS JOIN scenarios_with_order swo
    WHERE swo.time_limit_seconds IS NOT NULL 
      AND swo.time_limit_seconds > 0
      AND swo.active_flag = true
),
scenario_count AS (
    SELECT COALESCE(MAX(position), 0) as max_position
    FROM scenarios_with_order
),
videos_data AS (
    SELECT 
        video_id,
        active_flag,
        show_problem_statement,
        show_objectives,
        show_image,
        row_num
    FROM (
        SELECT 
            video_id,
            active_flag,
            COALESCE(show_problem_statement, true) as show_problem_statement,
            COALESCE(show_objectives, true) as show_objectives,
            COALESCE(show_image, true) as show_image,
            ROW_NUMBER() OVER () as row_num
        FROM params x
        CROSS JOIN UNNEST(
            x.video_ids, 
            x.video_active_flags, 
            x.video_show_problem_statement,
            x.video_show_objectives,
            x.video_show_image
        ) AS t(video_id, active_flag, show_problem_statement, show_objectives, show_image)
    ) sub
),
videos_with_order AS (
    SELECT 
        vd.video_id,
        vd.active_flag,
        vd.show_problem_statement,
        vd.show_objectives,
        vd.show_image,
        sc.max_position + ROW_NUMBER() OVER (
            ORDER BY vd.active_flag DESC, vd.row_num
        ) as position
    FROM videos_data vd
    CROSS JOIN scenario_count sc
    WHERE EXISTS (SELECT 1 FROM params x WHERE array_length(x.video_ids, 1) > 0)
),
link_scenarios AS (
    INSERT INTO simulation_scenarios (simulation_id, scenario_id, active, position, hints_enabled, audio_enabled, text_enabled, created_at, updated_at)
    SELECT 
        x.simulation_id,
        swo.scenario_id,
        swo.active_flag,
        swo.position,
        swo.hints_enabled,
        swo.audio_enabled,
        swo.text_enabled,
        NOW(),
        NOW()
    FROM params x
    CROSS JOIN scenarios_with_order swo
),
remove_existing_rubric_grade_agents AS (
    DELETE FROM simulation_scenarios_rubric_grade_agents
    WHERE simulation_id IN (SELECT simulation_id FROM params)
),
-- Create/find rubric_grade_agents entries
create_rubric_grade_agents AS (
    INSERT INTO rubric_grade_agents (rubric_id, grade_agent_id, created_at, updated_at)
    SELECT DISTINCT
        (srga).rubric_id,
        (srga).grade_agent_id,
        NOW(),
        NOW()
    FROM params x
    CROSS JOIN UNNEST(x.scenario_rubric_grade_agents) AS srga
    WHERE (srga).rubric_id IS NOT NULL 
      AND (srga).grade_agent_id IS NOT NULL
    ON CONFLICT (rubric_id, grade_agent_id, agent_id) DO UPDATE SET
        updated_at = NOW()
    RETURNING id as rubric_grade_agent_id, rubric_id, grade_agent_id
),
-- Link audio agents if provided
link_audio_agents AS (
    INSERT INTO rubric_grade_agents_audio (rubric_grade_agent_id, audio_agent_id, created_at, updated_at)
    SELECT DISTINCT
        crga.rubric_grade_agent_id,
        (srga).audio_agent_id,
        NOW(),
        NOW()
    FROM params x
    CROSS JOIN UNNEST(x.scenario_rubric_grade_agents) AS srga
    JOIN create_rubric_grade_agents crga ON crga.rubric_id = (srga).rubric_id 
        AND crga.grade_agent_id = (srga).grade_agent_id
    WHERE (srga).audio_agent_id IS NOT NULL
    ON CONFLICT (rubric_grade_agent_id, audio_agent_id) DO NOTHING
),
link_scenario_rubric_grade_agents AS (
    INSERT INTO simulation_scenarios_rubric_grade_agents (simulation_id, scenario_id, rubric_grade_agent_id, created_at, updated_at)
    SELECT DISTINCT
        x.simulation_id,
        (srga).scenario_id,
        crga.rubric_grade_agent_id,
        NOW(),
        NOW()
    FROM params x
    CROSS JOIN UNNEST(x.scenario_rubric_grade_agents) AS srga
    JOIN create_rubric_grade_agents crga ON crga.rubric_id = (srga).rubric_id 
        AND crga.grade_agent_id = (srga).grade_agent_id
    WHERE EXISTS (
        SELECT 1 FROM scenarios_with_order swo 
        WHERE swo.scenario_id = (srga).scenario_id
    )
      AND (srga).rubric_id IS NOT NULL 
      AND (srga).grade_agent_id IS NOT NULL
    ON CONFLICT (simulation_id, scenario_id, rubric_grade_agent_id) DO NOTHING
)
SELECT 
    ap.actor_name::text as actor_name
FROM update_simulation us
CROSS JOIN actor_profile ap
$$;


