--
-- Name: socket_rubric_generation_progress_v4(uuid, text, uuid, uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.socket_rubric_generation_progress_v4(profile_id uuid, progress_type text, rubric_id uuid DEFAULT NULL::uuid, group_id uuid DEFAULT NULL::uuid, message text DEFAULT NULL::text, tool_name text DEFAULT NULL::text) RETURNS TABLE(type text, message text, tool_name text, trace_id text)
    LANGUAGE sql
    AS $$
-- No-op: Just returns progress info (no database operations)
-- trace_id comes from groups table, not parameter
SELECT 
    progress_type as type,
    COALESCE(message, 'Progress updated') as message,
    tool_name as tool_name,
    (SELECT trace_id FROM groups WHERE id = group_id LIMIT 1) as trace_id
$$;


