--
-- Name: test_create_test_standard_group_v4(uuid, text, text, text, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_create_test_standard_group_v4(input_rubric_id uuid, group_name text, group_short_name text, group_description text, group_points integer, group_pass_points integer) RETURNS TABLE(standard_group_id uuid, rubric_id uuid, name text, short_name text, description text, points integer, pass_points integer, created_at timestamp with time zone, updated_at timestamp with time zone)
    LANGUAGE sql
    AS $$
    -- NOTE: standard_groups table doesn't have rubric_id column
    -- Standard groups are linked to rubrics via rubric_standard_groups table
    -- This function creates a standard group without rubric link - tests using this may need updating
    WITH new_group AS (
        INSERT INTO standard_groups(name, short_name, description, points, pass_points, tool_call_id)
        SELECT 
            group_name,
            group_short_name,
            group_description,
            group_points,
            group_pass_points,
            (SELECT id FROM calls LIMIT 1)  -- Required foreign key
        RETURNING id AS standard_group_id, name, short_name, description, points, pass_points, created_at, created_at AS updated_at
    )
    SELECT 
        standard_group_id,
        input_rubric_id AS rubric_id,
        name,
        short_name,
        description,
        points,
        pass_points,
        created_at,
        updated_at
    FROM new_group;
$$;


