--
-- Name: test_get_or_create_rubric_v4(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_get_or_create_rubric_v4() RETURNS TABLE(rubric_id uuid, name text, description text, points integer, pass_points integer, active boolean)
    LANGUAGE sql
    AS $$
    WITH existing_rubric AS (
        SELECT id, name, description, points, pass_points, active
        FROM rubrics
        LIMIT 1
    ),
    new_rubric AS (
        INSERT INTO rubrics(name, description, points, pass_points, active)
        SELECT 'Test Rubric', 'Test', 100, 70, true
        WHERE NOT EXISTS (SELECT 1 FROM existing_rubric)
        RETURNING id, name, description, points, pass_points, active
    )
    SELECT id as rubric_id, name, description, points, pass_points, active
    FROM existing_rubric
    UNION ALL
    SELECT id as rubric_id, name, description, points, pass_points, active
    FROM new_rubric
    LIMIT 1;
$$;


--
-- Name: test_get_or_create_scenario_v4(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_get_or_create_scenario_v4() RETURNS TABLE(scenario_id uuid, name text)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_scenario_id uuid;
BEGIN
    -- Try to get existing scenario
    SELECT id INTO v_scenario_id
    FROM scenarios
    LIMIT 1;

    -- If no scenario exists, create one
    IF v_scenario_id IS NULL THEN
        INSERT INTO scenarios(name, active)
        VALUES ('Test Scenario', true)
        RETURNING id INTO v_scenario_id;

        -- Insert self-referencing tree edge
        INSERT INTO scenario_tree(parent_id, child_id, active)
        VALUES (v_scenario_id, v_scenario_id, true);
    END IF;

    -- Return result
    RETURN QUERY
    SELECT 
        s.id as scenario_id,
        s.name
    FROM scenarios s
    WHERE s.id = v_scenario_id;
END;
$$;


--
-- Name: test_get_or_create_test_agent_v4(text, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_get_or_create_test_agent_v4(name text DEFAULT 'Test Agent'::text, description text DEFAULT 'Test Description'::text, model_id uuid DEFAULT NULL::uuid) RETURNS TABLE(agent_id uuid, name text, description text, model_id uuid)
    LANGUAGE sql
    AS $$
    WITH existing_agent AS (
        SELECT id, name, description, model_id
        FROM agents
        WHERE active = true
        LIMIT 1
    ),
    model_to_use AS (
        SELECT COALESCE(test_get_or_create_test_agent_v4.model_id, em.model_id) as id
        FROM existing_agent em
        WHERE test_get_or_create_test_agent_v4.model_id IS NOT NULL OR em.model_id IS NOT NULL
        LIMIT 1
    ),
    new_agent AS (
        INSERT INTO agents(name, description, model_id, active)
        SELECT 
            test_get_or_create_test_agent_v4.name,
            test_get_or_create_test_agent_v4.description,
            COALESCE(mtu.id, (SELECT id FROM models WHERE active = true LIMIT 1)),
            true
        FROM model_to_use mtu
        WHERE NOT EXISTS (SELECT 1 FROM existing_agent)
        RETURNING id, name, description, model_id
    )
    SELECT 
        COALESCE(ea.id, na.id) as agent_id,
        COALESCE(ea.name, na.name) as name,
        COALESCE(ea.description, na.description) as description,
        COALESCE(ea.model_id, na.model_id) as model_id
    FROM existing_agent ea
    FULL OUTER JOIN new_agent na ON true
    WHERE ea.id IS NOT NULL OR na.id IS NOT NULL
    LIMIT 1;
$$;


--
-- Name: test_get_or_create_test_department_v4(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_get_or_create_test_department_v4(title text DEFAULT 'Computer Science'::text, description text DEFAULT 'Test Department Description'::text) RETURNS TABLE(department_id uuid, title text)
    LANGUAGE sql
    AS $$
    WITH existing_dept AS (
        SELECT id, title
        FROM departments
        WHERE title = test_get_or_create_test_department_v4.title
        LIMIT 1
    ),
    new_dept AS (
        INSERT INTO departments(title, description, active)
        SELECT 
            test_get_or_create_test_department_v4.title,
            test_get_or_create_test_department_v4.description,
            true
        WHERE NOT EXISTS (SELECT 1 FROM existing_dept)
        RETURNING id, title
    )
    SELECT 
        COALESCE(ed.id, nd.id) as department_id,
        COALESCE(ed.title, nd.title) as title
    FROM existing_dept ed
    FULL OUTER JOIN new_dept nd ON true
    WHERE ed.id IS NOT NULL OR nd.id IS NOT NULL
    LIMIT 1;
$$;


--
-- Name: test_get_or_create_test_model_v4(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_get_or_create_test_model_v4(name text DEFAULT 'Test Model'::text) RETURNS TABLE(model_id uuid, name text, provider_id uuid)
    LANGUAGE sql
    AS $$
    WITH existing_model AS (
        SELECT id, name, provider_id
        FROM models
        WHERE active = true
        LIMIT 1
    ),
    existing_provider AS (
        SELECT id
        FROM providers
        WHERE active = true
        LIMIT 1
    ),
    new_provider AS (
        INSERT INTO providers(name, description, value, active)
        SELECT 'Test Provider', 'Test Provider Description', 'openai', true
        WHERE NOT EXISTS (SELECT 1 FROM existing_provider)
        RETURNING id
    ),
    provider_to_use AS (
        SELECT COALESCE(ep.id, np.id) as id
        FROM existing_provider ep
        FULL OUTER JOIN new_provider np ON true
        WHERE ep.id IS NOT NULL OR np.id IS NOT NULL
        LIMIT 1
    ),
    new_model AS (
        INSERT INTO models(name, description, value, provider_id, active)
        SELECT 
            test_get_or_create_test_model_v4.name,
            'Test Model Description',
            'gpt-4',
            ptu.id,
            true
        FROM provider_to_use ptu
        WHERE NOT EXISTS (SELECT 1 FROM existing_model)
        RETURNING id, name, provider_id
    )
    SELECT 
        COALESCE(em.id, nm.id) as model_id,
        COALESCE(em.name, nm.name) as name,
        COALESCE(em.provider_id, nm.provider_id) as provider_id
    FROM existing_model em
    FULL OUTER JOIN new_model nm ON true
    WHERE em.id IS NOT NULL OR nm.id IS NOT NULL
    LIMIT 1;
$$;


--
-- Name: test_get_or_create_test_profile_v4(text, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.test_get_or_create_test_profile_v4(email text DEFAULT 'redacted@purdue.edu'::text, role text DEFAULT 'superadmin'::text, first_name text DEFAULT 'Test'::text, last_name text DEFAULT 'User'::text) RETURNS TABLE(profile_id uuid, email text, role text)
    LANGUAGE sql
    AS $$
    WITH existing_profile AS (
        SELECT 
            pe.profile_id,
            pe.email,
            p.role::text
        FROM profile_emails pe
        JOIN profiles p ON p.id = pe.profile_id
        WHERE pe.email = test_get_or_create_test_profile_v4.email
          AND pe.active = true
        LIMIT 1
    ),
    new_profile AS (
        INSERT INTO profiles(first_name, last_name, role, active)
        SELECT 
            test_get_or_create_test_profile_v4.first_name,
            test_get_or_create_test_profile_v4.last_name,
            test_get_or_create_test_profile_v4.role::profile_role,
            true
        WHERE NOT EXISTS (SELECT 1 FROM existing_profile)
        RETURNING id, test_get_or_create_test_profile_v4.role::text as role
    ),
    new_email AS (
        INSERT INTO profile_emails(profile_id, email, is_primary, active)
        SELECT 
            np.id,
            test_get_or_create_test_profile_v4.email,
            true,
            true
        FROM new_profile np
        WHERE NOT EXISTS (SELECT 1 FROM existing_profile)
        RETURNING profile_id, email
    )
    SELECT 
        COALESCE(ep.profile_id, np.id) as profile_id,
        COALESCE(ep.email, ne.email) as email,
        COALESCE(ep.role, np.role) as role
    FROM existing_profile ep
    FULL OUTER JOIN new_profile np ON true
    FULL OUTER JOIN new_email ne ON ne.profile_id = np.id
    WHERE ep.profile_id IS NOT NULL OR np.id IS NOT NULL
    LIMIT 1;
$$;


